var LETTERS_V1_PREFACE={id:"a-word-of-warning",title:"A Word of Warning",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"poetry",lines:[[{t:"italic",v:"Thus says The Lord"}],[{t:"italic",v:"To everyone who hears or"}],[{t:"italic",v:"Looks upon the words of this Book:"}]]},{type:"poetry",lines:[[{t:"italic",v:"If anyone adds to these words,"}],[{t:"italic",v:"I will add to them the punishments"}],[{t:"italic",v:"Written in this Book."}],[{t:"stanza-break"}],[{t:"italic",v:"And if anyone takes anything"}],[{t:"italic",v:"Away from the words in the Book"}],[{t:"italic",v:"Of this prophecy, I will take away"}],[{t:"italic",v:"Their share in The Tree of Life"}],[{t:"italic",v:"And The Holy City, as it is written."},{t:"fn",v:"1"}]]},{type:"poetry",lines:[[{t:"italic",v:"For as I am so shall I be,"}],[{t:"italic",v:"As I have spoken so I speak,"}],[{t:"italic",v:"And that which was written by"}],[{t:"italic",v:"My prophets of old remains standing,"}],[{t:"italic",v:"Even to this day."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"scripture",ref:"Revelation 22:18-19"}},nkjv:{"Revelation 22:18-19":"18. For I testify to everyone who hears the words of the prophecy of this book: If anyone adds to these things, God will add to him the plagues that are written in this book; 19. and if anyone takes away from the words of the book of this prophecy, God shall take away his part from the Book of Life, from the holy city, and from the things which are written in this book."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-word-of-warning",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/a-word-of-warning?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=UGM0FH9k4NA&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=1",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}]},LETTERS_V1=[{id:"chosen-by-god",title:"Chosen by God",date:"8/31/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Many things you must overcome in the years ahead; many things will I show you, many things will I teach you. And though you feel weak and helpless, as a young child struggling to gain his feet, I will strengthen you, for I am with you. For the years draw short, Timothy, and soon all things must come to pass. Therefore be steadfast, My son; strengthen your faith, and I shall make you an immovable stone for My name. For I am your God, and you are one of My chosen sons of the Gentiles, for the Gentiles, living in their midst..."},{t:"italic",v:"Grafted into The Vine, of the branch of Levi, adopted son of Abraham,"},{t:"fn",v:"1"},{t:"italic",v:"says The Lord."}]}],footnotes:{1:{type:"note",text:'Also read: "Grafted In"',url:"https://www.thevolumesoftruth.com/Grafted_In",link:{collection:"Volume Three",letterTitle:"Grafted In"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/chosen-by-god-4",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/v1-001_chosen-by-god?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=j-8yNPMN7cQ&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:1,prevLetter:null,nextLetter:{id:"honor-not-the-day-of-the-dead-honor-god",title:"Honor Not the Day of the Dead... Honor God"}},{id:"honor-not-the-day-of-the-dead-honor-god",title:"Honor Not the Day of the Dead... Honor God",date:"10/6/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, is celebrating Halloween OK?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"In regards to the day in which your land celebrates \u201Cthe Day of the Dead,\u201D those who hear not, speak not, think not nor pray, for all their thoughts have perished with them, I say this: To honor this day is to honor nothing, and is contemptible. And to honor death and darkness is to cast your lot with satan; it is to partake in the works of demons..."},{t:"italic",v:"I am The Light and The Life! Honor Me!"},{t:"text",v:"So again, I say to you, do not do it! In no way make for yourself images of the dead. Do not buy or sell such things, nor decorate your house; carve no image, nor adorn yourself or your children with these symbols. Rather celebrate autumn and its splendor, and give thanks; offer up praises to The Lord your God, for all creation declares My name. Beloved, I created autumn so all may partake of My brushstrokes, and know I am God, and give Me glory. For My splendor is written in the leaves of the trees. It is carried upon the wind, as it moves through the tall grasses. It soars high above on the wings of eagles, yet remains as near as the fragile flower at your feet. Behold, everywhere you look, the hand of God is clearly seen."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, be separate from the world and its evil ways;"}],[{t:"italic",v:"Stand apart from the corrupt traditions of men,"}],[{t:"italic",v:"And delight no more in those things I hate..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written:"}],[{t:"italic",v:"The highway of the upright is to depart from evil;"}],[{t:"italic",v:"And he who watches his step preserves his life"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Proverbs 16:17"}},nkjv:{"Proverbs 16:17":"The highway of the upright is to depart from evil; He who keeps his way preserves his soul."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/honor-not-the-day-of-the-dead-honor-god",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/honor-not-the-day-of-the-dead?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=XvmrBgolWPo&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=3",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"}],num:2,prevLetter:{id:"chosen-by-god",title:"Chosen by God"},nextLetter:{id:"christmas",title:"Christmas"}},{id:"christmas",title:"Christmas",date:"10/7/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy and His Wife, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, what is your will for us regarding Christmas this year?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Timothy and Beloved, I tell you this: Let your hearts guide you, for on them have I written many things, and will continue to do so. Yea, even greater things will I reveal to you in the days to come. Then shall you be changed, from that which is perishable to that which is imperishable, your innermost desire realized."}]},{type:"para",segments:[{t:"text",v:"As for this holiday called Christmas, you must forsake it. For on this day, The Son of Man did not come into the world by way of water and blood; neither shall My people worship Me in this way. Yet of Messiah\u2019s birth, you may indeed remember it with your family, for it was the beginning of your salvation. For where there was once only darkness, behold, a great light has appeared! Therefore, blessed are those who worship with gratitude, giving thanks for the birth of My Son. Even more blessed are those who worship and give thanks for His death and resurrection."}]},{type:"para",segments:[{t:"text",v:"Yet woe to those who associate the name of The Son of God with pagan practices and idolatrous traditions! YOU HAVE SURELY TAKEN THE NAME OF THE LORD IN VAIN! Woe to all who celebrate this holiday called Christmas, for you do dishonor Me by all you say and do! For this season of so-called giving is detestable in My sight! ABOMINATION! IDOLATRY! Woe to all who ignore My warnings and break My Commandments! YOU ARE ALL SLAVES! You have made mammon your master, materialism has bound you in chains, for you want no part with Me as I truly am! Behold, from you My spirit is far removed, for you have surely made yourselves enemies of God! I tell you the truth, the day is coming and is already here, when the quality of each man\u2019s work shall be tried and the faith of every self-proclaimed believer tested! For the Day of The Lord shall surely declare it! Know you not, that to imitate The Messiah is righteousness?! My people, you were to walk in His ways! Yet you have made of Him a mockery! How long shall you cleave to the harlot?! How long shall you walk in her ways?! My people, come out of her, and touch no more the unclean thing!"}]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you the truth, to replace Christ,"}],[{t:"italic",v:"Or to associate His name with sin, is to"}],[{t:"italic",v:"Partake in that which is called antichrist!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And to honor The Messiah with pagan customs and"}],[{t:"italic",v:"Filthy traditions is to take the name of The Lord in vain!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"DESECRATION! BLASPHEMY!"}]]},{type:"para",segments:[{t:"text",v:"I know many in this world celebrate this holiday in ignorance of its origins, yet it is an abomination to Me, pagan practices and idolatrous traditions which I loathe in My zeal! Therefore, woe to those who willfully walk in ignorance! And woe, even three times woe, to those who knowingly place their stamp of approval on these things, doing so in The Messiah\u2019s name; yours shall be a most bitter place, your discipline severe! Woe to all who knowingly lead others into rebellion against The Lord, for the mouth of Sheol is open and ready to receive you! Beloved ones, worship Me as I am and not as you would have Me be! Obey MY voice! Depart from every form of evil and tear down every whitewashed wall of abomination! CHURCHES OF MEN, STOP TWISTING THE SCRIPTURES TO UPHOLD YOUR OWN WAY! Be separate from this world, and no more endorse those things I hate! Again, I say, be separate and come out from among them, and repent! Return to Me, in spirit and in truth, and in the day I stretch out My hand against the inhabitants of the earth, you shall surely be gone from this place, says The Lord."}]},{type:"para",segments:[{t:"text",v:"So then, My beloved servants, share your gifts:"},{t:"italic",v:"Lift up the poor and help the needy, give drink to the thirsty and feed the hungry, share My love and wash each other\u2019s feet."},{t:"text",v:"Yet no longer be a friend of this world, and no more walk in the ways of the churches of men, for they have not known Me."}]},{type:"poetry",lines:[[{t:"italic",v:"Be set apart!"}],[{t:"italic",v:"Rejoice and give thanks!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Honor The Messiah in spirit and in truth,"}],[{t:"italic",v:"And walk closely in His example;"}],[{t:"italic",v:"Testify of Him, from His birth to His passion;"}],[{t:"italic",v:"Glorify His name in all the earth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For HE is the true gift..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"italic",v:"10/7/04"},{t:"bold-italic",v:"From The Lord, Our God and Savior"},{t:"italic",v:"The Word of The Lord Spoken to Timothy For Timothy and His Wife, and For All Those Who Have Ears to Hear Addendum to \u201CChristmas\u201D"}]},{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, what do you say about the modern Christmas?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Though you ask of Me once again, Timothy, concerning this holiday which I hate, this season which the people in your land, even in many lands, mistakenly refer to as Christmas, I will not press down upon you the many cups filled to overflowing with My indignation. For you haven\u2019t the paper or strength of hand to write it. I AM THE LORD."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/christmas-2",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/christmas?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=fJmNtFYP5iI&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=4",videoMusicUrl:"https://www.youtube.com/watch?v=DBFNBzWPEyk&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=5",relatedTopics:[{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Man's Holidays vs. God's Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"}],num:3,prevLetter:{id:"honor-not-the-day-of-the-dead-honor-god",title:"Honor Not the Day of the Dead... Honor God"},nextLetter:{id:"wisdom-regarding-those-who-killed-the-messiah-who-is-called-christ",title:"Wisdom Regarding Those Who Killed The Messiah, Who Is Called Christ"}},{id:"wisdom-regarding-those-who-killed-the-messiah-who-is-called-christ",title:"Wisdom Regarding Those Who Killed The Messiah, Who Is Called Christ",date:"10/16/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Those who say the Jews killed The Messiah speak rightly. For I know all the works of men, and in that day did I harden their hearts to accomplish My purpose. For in the days of Abraham, even unto Moses, did I establish My people as the chosen to give sacrifice for the cleansing of sin..."},{t:"italic",v:"Behold, I gave unto them My Only Begotten Son, The Lamb without spot or blemish, that all written by the prophets should be fulfilled in The Son of Man."},{t:"text",v:"Yet to those who cry,"},{t:"italic",v:"\u201CBut the Romans crucified The Christ, not the Jews,\u201D"},{t:"text",v:"I say this: You lack understanding, and do not know that which was foretold by the prophets and written in the Scriptures of Truth. For the Romans did indeed crucify Him, and His blood is on their hands, even as it was on the hammer which drove the nails. Yet I ask you, are the Romans liken unto the hammer, or he who forged the hammer? Whose guilt is greater, he who holds the hammer, or he who had placed the hammer in his hand? Most assuredly, I say to you, both are guilty! But woe to those who forged the hammer and placed it in his hand! Theirs is the greater sin!"},{t:"italic",v:"For they denied The Holy and Innocent One, reviling Him, and instead asked for the murderer to be set free!"},{t:"fn",v:"1"},{t:"text",v:"THEY KILLED THE AUTHOR OF LIFE!"}]},{type:"para",segments:[{t:"text",v:"Yet those of greater wisdom know"},{t:"italic",v:"all"},{t:"text",v:"are guilty, for all have sinned and fall short of the Glory of God; there is none righteous, no, not one. And for this reason YahuShua The Messiah was sent to die for all men, thereby freeing mankind from the chains which held him captive, loosing him from the bonds which bound him to the punishment of sin, which is death."}]},{type:"poetry",lines:[[{t:"italic",v:"So then as The Messiah was crucified, and died, and is risen,"}],[{t:"italic",v:"So too must you crucify your life of old..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Who you were must perish, along with your sinful ways,"}],[{t:"italic",v:"Then shall you truly be born again..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Revived and restored in The Image of God."}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 27:15-26"}},nkjv:{"Matthew 27:15-26":"15. Now at the feast the governor was accustomed to releasing to the multitude one prisoner whom they wished. 16. And at that time they had a notorious prisoner called Barabbas. 17. Therefore, when they had gathered together, Pilate said to them, \u201CWhom do you want me to release to you? Barabbas, or Jesus who is called Christ?\u201D 18. For he knew that they had handed Him over because of envy. 19. While he was sitting on the judgment seat, his wife sent to him, saying, \u201CHave nothing to do with that just Man, for I have suffered many things today in a dream because of Him.\u201D 20. But the chief priests and elders persuaded the multitudes that they should ask for Barabbas and destroy Jesus. 21. The governor answered and said to them, \u201CWhich of the two do you want me to release to you?\u201D They said, \u201CBarabbas!\u201D 22. Pilate said to them, \u201CWhat then shall I do with Jesus who is called Christ?\u201D They all said to him, \u201CLet Him be crucified!\u201D 23. Then the governor said, \u201CWhy, what evil has He done?\u201D But they cried out all the more, saying, \u201CLet Him be crucified!\u201D 24. When Pilate saw that he could not prevail at all, but rather that a tumult was rising, he took water and washed his hands before the multitude, saying, \u201CI am innocent of the blood of this just Person. You see to it.\u201D 25. And all the people answered and said, \u201CHis blood be on us and on our children.\u201D 26. Then he released Barabbas to them; and when he had scourged Jesus, he delivered Him to be crucified."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/wisdom-regarding-those-who-killed-the-messiah-who-is-called-christ",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/wisdom-regarding-those-who?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=lBsJPZpHVrk&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=6",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:4,prevLetter:{id:"christmas",title:"Christmas"},nextLetter:{id:"humility-and-the-word-of-god",title:"Humility and The Word of God"}},{id:"humility-and-the-word-of-god",title:"Humility and The Word of God",date:"10/17/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"I have bestowed upon you many gifts, and that which was given the twelve shall be yours also. So then, you shall go out and you shall come in. And like the twelve, I shall be with you, and you shall speak on My behalf. Yes, you shall surely testify and give Me glory in the sight and hearing of men; yea, even greater things shall you do. Behold, even as the prophets of old, you shall go out and you shall come in. For I shall rise up within you, and you shall write My words and give a shout, and blow the Trumpet."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus it is not by some new wisdom"}],[{t:"italic",v:"You shall write, but the wisdom of old,"}],[{t:"italic",v:"That which was and is and has always been,"}],[{t:"italic",v:"The same and unchanging,"}],[{t:"italic",v:"The Everlasting Word of God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Established..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even before the foundation of the world..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I AM, and My Word the same."}]]},{type:"para",segments:[{t:"text",v:"Therefore, as blades of grass are beset with dew in the cool of the night, even till the morning, so shall I beset you with My words; each word a glistening drop from Heaven, every letter a shining jewel. Through you shall I set all these crooked paths straight, preparing My way before Me. Indeed, I shall reveal Myself to many, and by this Word, which I shall cause you to write, shall they begin to see Me as I truly am. Yet take care, Timothy, lest your mind betray you, and you unwittingly take My words to yourself. For though I have indeed appointed you a prophet, setting you over nations and over kingdoms, to root out and to pull down, to destroy and to throw down, to build and to plant, never forget your station: You are a servant, of both God and man."},{t:"italic",v:"Behold, you shall be for Me a mouthpiece, through whom I shall make My plans known,"},{t:"fn",v:"1"},{t:"italic",v:"for I do not change."},{t:"fn",v:"2"},{t:"text",v:"Therefore, do not cease from humbling yourself before Me. I am your strength."}]}],footnotes:{1:{type:"scripture",ref:"Amos 3:7"},2:{type:"scripture",ref:"Malachi 3:6"}},nkjv:{"Amos 3:7":"Surely the Lord GOD does nothing, Unless He reveals His secret to His servants the prophets.","Malachi 3:6":"\u201CFor I am the LORD, I do not change; Therefore you are not consumed, O sons of Jacob."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/humility-and-the-word-of-god",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/humility-and-the-word-of-god?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=-IoPHN6zozQ&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:5,prevLetter:{id:"wisdom-regarding-those-who-killed-the-messiah-who-is-called-christ",title:"Wisdom Regarding Those Who Killed The Messiah, Who Is Called Christ"},nextLetter:{id:"god-is-the-fosterer-and-protector-of-those-tossed-away-in-bitter-ignorance",title:"God Is The Fosterer and Protector of Those Tossed Away in Bitter Ignorance"}},{id:"god-is-the-fosterer-and-protector-of-those-tossed-away-in-bitter-ignorance",title:"God Is The Fosterer and Protector of Those Tossed Away in Bitter Ignorance",date:"10/20/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For His Wife, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Timothy asked this question of The Lord, for his wife: Lord, should My wife write a letter about abortion to her friends and family?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Write these words, Timothy, to your wife: Beloved, your aims are both admirable and righteous, and in this you do honor Me. For these things weigh heavily upon My heart also; behold, the cup of the wrath of My fury has come to the full on account of that which I see!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus to these nations and peoples who murder My precious created ones, My very gifts to men and women, I say this:"},{t:"text",v:"You also will I abort! Behold, I shall tear you in pieces and cut your lives short! For as it is written:"},{t:"italic",v:"It would be better for you if a millstone were hung around your neck, and you were drowned in the depths of the sea, than to suffer My wrath over these little ones!"},{t:"fn",v:"1"},{t:"text",v:"Therefore, I call all those whose guilt rises to heaven, to repent with all their heart, to repent in sackcloth and ashes."}]},{type:"para",segments:[{t:"text",v:"So then shine forth, O child of Zion, stand firm. Defend the helpless, speak on the behalf of those who have no speech, uphold the cause of those who are yet unseen. For it is I who formed them, it is I who caused them to be. For I tell you the truth, these little ones know The Kingdom of Heaven already, and will return with The King at the time appointed. For The Kingdom of God belongs to all such as these"},{t:"fn",v:"2"},{t:"text",v:", says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Blessed be the name of The One"}],[{t:"italic",v:"Who is, and was, and is forevermore,"}],[{t:"italic",v:"The Fosterer and Protector of those"}],[{t:"italic",v:"Tossed away in bitter ignorance!"}]]},{type:"para",segments:[{t:"italic",v:"10/20/04"},{t:"bold-italic",v:"From The Lord, Our God and Savior"},{t:"italic",v:"The Word of The Lord Spoken to Timothy For His Wife, and For All Those Who Have Ears to Hear Addendum to \u201CGod Is The Fosterer and Protector of Those Tossed Away in Bitter Ignorance\u201D"}]},{type:"para",segments:[{t:"italic",v:"Timothy asked this question of The Lord, for his wife: Lord, what should My wife include in the letter?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Beloved, do all you have conceived in your heart to do, and make the Commandment known, saying,"},{t:"italic",v:"\u201CYOU SHALL NOT KILL!\u201D"},{t:"fn",v:"3"},{t:"text",v:"Include also the words of The Son of Man concerning the little ones, and how I made them pure and blameless, gifts from God. For I tell you the truth, the day is coming quickly, whether they believe or believe not, when all must stand in judgment and give an account. For LIFE IS, before its very conception, says The Lord."}]}],footnotes:{1:{type:"scripture",ref:"Matthew 18:6"},2:{type:"scripture",ref:"Matthew 19:14"},3:{type:"scripture",ref:"Exodus 20:13"}},nkjv:{"Matthew 18:6":"\u201CWhoever causes one of these little ones who believe in Me to sin, it would be better for him if a millstone were hung around his neck, and he were drowned in the depth of the sea.\u201D","Matthew 19:14":"But Jesus said, \u201CLet the little children come to Me, and do not forbid them; for of such is the kingdom of heaven.\u201D","Exodus 20:13":"\u201CYou shall not murder.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/god-is-the-fosterer-and-protector-of-those-tossed-away-in-bitter-ignorance",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/god-is-the-fosterer-and?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=At9hAYWOspM&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=8",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"}],num:6,prevLetter:{id:"humility-and-the-word-of-god",title:"Humility and The Word of God"},nextLetter:{id:"belong-to-the-church-without-walls",title:"Belong to the Church Without Walls"}},{id:"belong-to-the-church-without-walls",title:"Belong to the Church Without Walls",date:"10/24/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"When those who call of themselves Christian, ask you, \u201CTo which church do you belong?\u201D You shall answer them:"},{t:"italic",v:"\u201CI belong to no church named of men. I belong to The Lord, YahuShua HaMashiach, whom you call Jesus and Christ. And together with all those who remain in His love"},{t:"fn",v:"1"},{t:"italic",v:"and obey His voice"},{t:"fn",v:"2"},{t:"italic",v:"is The Church in which I dwell.\u201D"}]}],footnotes:{1:{type:"scripture",ref:"John 15:10"},2:{type:"scripture",ref:"John 3:36 (CJB)"}},nkjv:{"John 15:10":"If you keep My commandments, you will abide in My love, just as I have kept My Father\u2019s commandments and abide in His love.","John 3:36 (CJB)":"Whoever trusts in the Son has eternal life. But whoever disobeys the Son will not see that life but remains subject to God\u2019s wrath."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/belong-to-the-church-without-walls-5",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/belong-to-the-church-without?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=bL9Lq5PYYN0&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=9",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The True Church",url:"https://answersonlygodcangive.com/Regarding_The_True_Church"}],num:7,prevLetter:{id:"god-is-the-fosterer-and-protector-of-those-tossed-away-in-bitter-ignorance",title:"God Is The Fosterer and Protector of Those Tossed Away in Bitter Ignorance"},nextLetter:{id:"sex",title:"Sex"}},{id:"sex",title:"Sex",date:"10/28/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"When lying together, remember the decrees of God concerning these things of sex and intimacy: You shall not lie with another outside of marriage; even sex before marriage, called fornication, is adultery. Do not think of others while lying with your spouse; this is adultery of the heart. You shall not lie with your wife during her monthly shedding of blood. You shall not behold sexual sin with your eyes, nor partake of any form of pornography, for to do so is to sin with them; this too is adultery. You shall perform no unnatural acts, nor shall you partake in"},{t:"italic",v:"sodomy"},{t:"fn",v:"1"},{t:"text",v:". And no man or woman, in all creation, shall lie with another of their same gender! This is an abomination in the eyes of The Most High God and filled with blasphemy!"}]},{type:"poetry",lines:[[{t:"italic",v:"For I gave unto man woman,"}],[{t:"italic",v:"From his side did I form her,"}],[{t:"italic",v:"And he who was one became two..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, the two became one again"}],[{t:"italic",v:"In marriage, two of one flesh,"}],[{t:"italic",v:"Man and woman"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And I saw that it was very good."}]]}],footnotes:{1:{type:"scripture",ref:"Genesis 19:4-5"},2:{type:"scripture",ref:"Genesis 2:21-24"}},nkjv:{"Genesis 19:4-5":"4. Now before they lay down, the men of the city, the men of Sodom, both old and young, all the people from every quarter, surrounded the house. 5. And they called to Lot and said to him, \u201CWhere are the men who came to you tonight? Bring them out to us that we may know them carnally.\u201D","Genesis 2:21-24":"21. And the LORD God caused a deep sleep to fall on Adam, and he slept; and He took one of his ribs, and closed up the flesh in its place. 22. Then the rib which the LORD God had taken from man He made into a woman, and He brought her to the man. 23. And Adam said: \u201CThis is now bone of my bones And flesh of my flesh; She shall be called Woman, Because she was taken out of Man.\u201D 24. Therefore a man shall leave his father and mother and be joined to his wife, and they shall become one flesh."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/sex-5",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/sex?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=WwAJaWbttlU&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Sex",url:"https://answersonlygodcangive.com/Regarding_Sex"},{label:"Regarding Marriage",url:"https://answersonlygodcangive.com/Regarding_Marriage"},{label:"Regarding Homosexuality",url:"https://answersonlygodcangive.com/Regarding_Homosexuality"}],num:8,prevLetter:{id:"belong-to-the-church-without-walls",title:"Belong to the Church Without Walls"},nextLetter:{id:"what-s-in-a-name",title:"What's In a Name"}},{id:"what-s-in-a-name",title:"What's In a Name",date:"10/29/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, both your earthly father and his namesake are no more. For even your earthly father shall be given a new name, if he so chooses, in the Day of Reckoning. Therefore, from this day onward you shall be called Timothy, he who honors God. And all who walk this path with you should refer to you as such. For you shall number your steps before Me, seeking always to do that which is right and good in My eyes. I AM THE LORD. Yet those who withstand you and persecute you on account of My words, all these hypocrites who have come out to fight against you and slander your name, shall all be made to fall at your feet in the day I send you. Then they will know, I AM THE LORD, and I Myself have loved you. For in that day you shall go out and you shall come in, and bring glory to My name. Yet you ask,"},{t:"italic",v:"\u201CWhat\u2019s in a name? It has no power.\u201D"},{t:"text",v:"Timothy, you speak in ignorance. For The Name, the name above all names, is YAHUWAH."},{t:"italic",v:"And there is only one name under Heaven by which you must be saved."},{t:"fn",v:"1"},{t:"fn",v:"2"},{t:"text",v:"And oh how blessed are those who put their trust in Him."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My name has weight and power!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And in the day I cause My name to resound in all the earth,"}],[{t:"italic",v:"My enemies shall fear and the multitudes shall tremble!"}],[{t:"italic",v:"Lo, many shall be cut to the heart in that day!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet blessed is the man whose name"}],[{t:"italic",v:"Is written in The Book of Life;"},{t:"fn",v:"3"}],[{t:"italic",v:"For he shall inherit everlasting life,"}],[{t:"italic",v:"And his name shall endure forever..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "Death and Deliverance" (first paragraph)',url:"https://www.thevolumesoftruth.com/Death_and_Deliverance#:~:text=For%20they%20have%20called%20upon%20The%20Name%2C%20the%20only%20name%20under%20Heaven%20by%20which%20you%20must%20be%20saved.",link:{collection:"Volume Three",letterTitle:"Death and Deliverance",excerpt:"For they have called upon The Name, the only name under Heaven by which you must be saved."}},2:{type:"note",text:'See: "Death and Deliverance" (last paragraph)',url:"https://www.thevolumesoftruth.com/Death_and_Deliverance#:~:text=Yet%20understand%20this,says%20The%20Lord.",link:{collection:"Volume Three",letterTitle:"Death and Deliverance",excerpt:"Yet understand this: In times past I overlooked the ignorance of the people."}},3:{type:"scripture",ref:"Revelation 3:5"}},nkjv:{"Revelation 3:5":"He who overcomes shall be clothed in white garments, and I will not blot out his name from the Book of Life; but I will confess his name before My Father and before His angels."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/whats-in-a-name-5",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/whats-in-a-name?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=zEATAu2ZEbg&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=11",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Sacred Names",url:"https://answersonlygodcangive.com/Regarding_Sacred_Names"},{label:'The Name of The Lord - "YAHUWAH"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YAHUWAH"}],num:9,prevLetter:{id:"sex",title:"Sex"},nextLetter:{id:"and-he-shall-be-called-i-am",title:"And He Shall Be Called I AM"}},{id:"and-he-shall-be-called-i-am",title:"And He Shall Be Called I AM",date:"10/31/04",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"I am The I AM..."}]},{type:"para",segments:[{t:"text",v:"I am The Lord Your God. I am Immanu El. I am The Lord Your Righteousness. I am The Anointed One. I am The Messiah. I am The Only God and Savior. I am The Holy One of Israel. I am The Glorious One on High. I am The Star Out of Jacob. I am The Everlasting Light of the World. I am The One Who Is and Was and Is to Come. I am The Almighty. I am The One Who Reigns Forever. I am The Kingdom. I am The Power. I am The Glory. I am The Only Lord of Hosts. I am The Source of Life. I am The Creator. I am The Maker of All Things. I am He by Whom All Things Consist. I am The Breath of Life. I am Eternal Life. I am The Passover. I am Your Sacrifice. I am The Lamb of God. I am Your Ransom. I am The Firstfruits of Those Who Have Fallen Asleep. I am The Firstborn from the Dead. I am He Who Died and Is Alive Forevermore. I am The Resurrection and The Life. I am He Who Ascended on High. I am He Who Led Captivity Captive. I am The Bestower of Gifts. I am Your Salvation. I am The Horn of Salvation. I am God\u2019s Salvation, YahuShua. I am The Loving Mercy of God. I am The Gift. I am The Redeemer. I am The Mediator. I am Your Advocate. I am Your High Priest. I am The Keeper of My Saints. I am The Lover of Souls. I am The Song of Your Heart. I am Your Tears of Joy. I am The Nectar of Life. I am He Who Loved You Before the Foundation of the World. I am He Through Whom You Were Made. I am Your Father. I am Your Protector. I am Your Rearguard. I am Your Strength. I am The Guardian of Your Soul. I am The Author; I am also The Finisher. I am The Wisdom. I am The Word of God. I am The Answer You Search For. I am The Truth You Seek. I am The Only Truth, The Truth Absolute. I am The Faithful and True Witness. I am The Sower; I am also The Reaper. I am The Dayspring. I am The Water of Life; I am also Your Bread, The Very Manna from Heaven. I am The Savior. I am The Risen One. I am The Bright and Morning Star. I am The Fulfillment of The Law. I am The Goal at Which The Torah Aims. I am The Fulfillment of All Things. I am The Reward. I am Holy. I am The Mercy Seat; I am also Wrath and Justice. I am He Who Searches the Hearts and Minds. I am The Righteous Judge. I am The Son of Man. I am The Cornerstone. I am The Rock. I am The Tree; I am also The Branch. I am The Son of David. I am The Shepherd. I am The Gate for My Sheep. I am The Master. I am The Good Teacher. I am The Voice of Truth. I am The Day Star Who Arises in the Hearts of Men. I am Your Heart\u2019s Desire. I am The Beloved. I am The Bridegroom. I am The Love That Never Fades. I am The Holy Presence. I am The Spirit. I am The Helper. I am The Counselor. I am The Inspiration. I am The Still Small Voice. I am The Hope. I am The Healer. I am The Sanctuary. I am The Firstborn Over All Creation. I am He Who Sits at The Right Hand of God. I am The Face of God. I am The Image of The Invisible God. I am The Son of God. I am The One Who Has the Seven-fold Spirit of God. I am The Holder of the Book of Life. I am The One Who Has the Key of David. I am He Who Opens Doors No One Can Shut. I am The One Who Holds the Keys of Death and Sheol. I am The Authority. I am The Mighty and Strong One. I am The Strong One of Jacob. I am The Lion of the Tribe of Judah. I am The Warrior of God Who Needs No Weapon. I am The One with the Double-Edged Sword in His Mouth. I am He Who Sits on the White Horse. I am He Who Is Coming on the Clouds. I am He Who Will Shine from the East unto the West. I am He Who Holds the Seven Stars in His Right Hand. I am He Whose Eyes Are Like Flames of Fire. I am He Who Wears the Golden Sash. I am He Who Holds the Iron Scepter. I am King of Kings. I am Lord of Lords. I am The First and The Last. I am Lord Over Heaven and Earth. I am The In All, Be All, of Existence. I am The Meaning of Life. I am The True Vine. I am The Fountain of Living Waters. I am The Restoration of All Things. I am The Prince of Peace. I am The Amen."}]},{type:"para",segments:[{t:"text",v:"I am The Way. I am The Truth. I am The Life."}]},{type:"para",segments:[{t:"text",v:"I am YahuShua HaMashiach. I am for you, and you for Me."}]},{type:"para",segments:[{t:"text",v:"I am The All in All."}]},{type:"para",segments:[{t:"text",v:"I AM."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/and-he-shall-be-called-i-am-5",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/and-he-shall-be-called-i-am?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=MVOupBDuvBw&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=12",videoMusicUrl:"https://www.youtube.com/watch?v=drJFOywutVg&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=5",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"},{label:'"He Who Was and Is and Is to Come"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#He_Who_Was_and_Is_and_Is_to_Come"}],num:10,prevLetter:{id:"what-s-in-a-name",title:"What's In a Name"},nextLetter:{id:"death-and-awakening",title:"Death and Awakening"}},{id:"death-and-awakening",title:"Death and Awakening",date:"11/15/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:[{t:"text",v:"(Regarding the state of the dead"},{t:"fn",v:"1"},{t:"text",v:")"}],blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"All people sleep in death, both those who have done good and those who have done evil. In no way are they among the living, nor are they aware. They know nothing at all, for all their thoughts have perished with them. All remain at rest, until the day I call them to awake; some to the first, the resurrection of life, and many more to the second, the resurrection of judgment. Blessed and holy are those who take part in the first resurrection."},{t:"italic",v:"For over them the second death"},{t:"fn",v:"2"},{t:"italic",v:"has no power, as it is written."},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"italic",v:"You have heard it said:"}],[{t:"italic",v:"To be absent from the body"}],[{t:"italic",v:"Is to be present with The Lord"},{t:"fn",v:"4"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"This saying is true..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For all those who die in Messiah will"}],[{t:"italic",v:"Indeed look upon Him at the Last Day,"},{t:"fn",v:"5"}],[{t:"italic",v:"Yet it will be to them as the blink of an eye..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the dead know not the passage of time,"}],[{t:"italic",v:"Nor do they know they have fallen asleep..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus there is indeed life after death,"}],[{t:"italic",v:"Yet during death there is most certainly not."}]]},{type:"para",segments:[{t:"text",v:"For I tell you the truth, if there is life during death, as it is commonly taught amongst the people, then none truly die. And if all have the victory over death, then all are like The Messiah; thereby making The New Covenant useless and the resurrection of no effect. This teaching is false, denying both the sacrifice of The Messiah and the Word of God. For if none truly die, then The Messiah is no longer the firstfruits of those who have fallen asleep. And if He is not the first to be freed from death and the grave, then The Messiah did not die. And if The Messiah did not die, then the power of sin has the victory and the grave has become your final resting place, leaving you with no hope of salvation. Yet the Scriptures do not lie."},{t:"italic",v:"The wages of sin is death;"},{t:"fn",v:"6"},{t:"text",v:"from the beginning, I declared it! And yet the churches continue to stand divided against themselves, corrupting My Word as they fall in line with satan, deceiving and being deceived, preaching,"},{t:"italic",v:"\u201CYou will not surely die,\u201D"},{t:"fn",v:"7"},{t:"text",v:"teaching that which runs contrary to the Scriptures."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, hear the Word of The Lord, O foolish and deceived generation:"},{t:"text",v:"If as you say, there is no death and all continue on as living spirits, whether it be in Heaven or in hell or in some other place, then you also say there is no God and no Savior who was sent to save you from the penalty of sin, which is death. Where then does that leave you? You are lost, a people without hope, multitudes of deceived people waiting for their own inevitable destruction, a creation wrought in vain! Yet The Messiah did indeed pay the penalty for your sins, even unto death..."},{t:"italic",v:"He is risen, The Firstborn from the dead; by which you are also delivered from death, if you so choose to receive of His life, if you so choose to embrace Him as He truly is!"}]},{type:"poetry",lines:[[{t:"italic",v:"For He alone will stretch out His hand in that day"}],[{t:"italic",v:"And lift His beloved from the grave, in which all must sleep,"}],[{t:"italic",v:"Save those who remain awake at His coming, as it is written"},{t:"fn",v:"8"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, the time is indeed coming, when all"}],[{t:"italic",v:"Who are in the grave will hear His voice and come out..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Those who have done good, to the resurrection of life..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And those who have done evil, to the resurrection of judgment..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"note",text:'See: "Q & A: What is the State of the Dead?"',url:"https://www.thevolumesoftruth.com/The_State_of_the_Dead_and_The_Fate_of_the_Wicked:_The_False_Doctrine_of_Hell_and_Eternal_Torment_Exposed#PART_1_-_Q_.26_A:_What_is_the_State_of_the_Dead.3F",link:{collection:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",letterTitle:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed"}},2:{type:"note",text:'See: "Regarding the Second Death"',url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},3:{type:"scripture",ref:"Revelation 20:6"},4:{type:"scripture",ref:"2 Corinthians 5:8"},5:{type:"scripture",ref:"John 6:40"},6:{type:"scripture",ref:"Romans 6:23"},7:{type:"scripture",ref:"Genesis 3:4"},8:{type:"scripture",ref:"1 Thessalonians 4:16-17",seeAlso:{label:"The Judgment of God Is True and Without Question, Yet the Error of the People Is Great",collection:"Volume Two",letterTitle:"The Judgment of God Is True and Without Question, Yet the Error of the People Is Great"}}},nkjv:{"Revelation 20:6":"Blessed and holy is he who has part in the first resurrection. Over such the second death has no power, but they shall be priests of God and of Christ, and shall reign with Him a thousand years.","2 Corinthians 5:8":"We are confident, yes, well pleased rather to be absent from the body and to be present with the Lord.","John 6:40":"And this is the will of Him who sent Me, that everyone who sees the Son and believes in Him may have everlasting life; and I will raise him up at the last day.\u201D","Romans 6:23":"For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord.","Genesis 3:4":"Then the serpent said to the woman, \u201CYou will not surely die.","1 Thessalonians 4:16-17":"16. For the Lord Himself will descend from heaven with a shout, with the voice of an archangel, and with the trumpet of God. And the dead in Christ will rise first. 17. Then we who are alive and remain shall be caught up together with them in the clouds to meet the Lord in the air. And thus we shall always be with the Lord."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/death-and-awakening-5",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/death-and-awakening?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=T5rAM0Ezk20&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the First and Second Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"}],num:11,prevLetter:{id:"and-he-shall-be-called-i-am",title:"And He Shall Be Called I AM"},nextLetter:{id:"regarding-the-celebration-of-christmas",title:"Regarding the Celebration of Christmas"}},{id:"regarding-the-celebration-of-christmas",title:"Regarding the Celebration of Christmas",date:"11/17/04",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Most assuredly, I say to you, any and all rituals which are rooted in paganism are an abomination in the eyes of God! And all who place My name upon them, or do them by permission in My name, have surely taken the name of The Lord in vain! I know many say they celebrate this holiday in loving memory of My earthly birth, yet on this day I did not come into the world by way of water and blood. For that day and hour remains unknown to you, nor do you understand. For you cast off knowledge, and refuse to honor the appointed times which The Father commanded you to keep holy and remember."},{t:"fn",v:"1"},{t:"italic",v:"Thus My people are indeed destroyed for lack of knowledge, as it is written."},{t:"fn",v:"2"}]},{type:"poetry",lines:[[{t:"italic",v:"How long shall you mar My image before the people?!"}],[{t:"italic",v:"How long shall My name be blasphemed"}],[{t:"italic",v:"Because of you, O churches of men?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"How long shall you commit adultery with the"}],[{t:"italic",v:"Harlot and revel in the idolatries of the pagan?!"}],[{t:"italic",v:"How long shall you remain married to this world"}],[{t:"italic",v:"And all its fornications against God?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Again I tell you, ALL religions, religious rituals"}],[{t:"italic",v:"And celebrations, rooted deeply in paganism,"}],[{t:"italic",v:"Are an abomination in the eyes of The Most High God!"}]]},{type:"para",segments:[{t:"text",v:"Well did My servant Sha\u2019ul (also known as Paul) prophesy of you, saying:"},{t:"italic",v:"In the latter days some will depart from the faith, giving heed to deceiving spirits and doctrines of demons, speaking lies in hypocrisy, having their consciences seared as with a hot iron."},{t:"fn",v:"3"},{t:"text",v:"And well did he prophesy of this generation, saying:"},{t:"italic",v:"Men will be lovers of themselves, lovers of money, boasters, proud blasphemers, disobedient to parents, unthankful, unholy, unloving, unforgiving, slanderers, without self-control, brutal, despisers of good, traitors, headstrong, haughty, lovers of pleasure rather than lovers of God, having a form of godliness but denying the power thereof"},{t:"fn",v:"4"},{t:"italic",v:"."},{t:"text",v:"Therefore, woe to all who celebrate this detestable holiday of men! Woe, I say to you! And three times woe, to all who do so in MY name! Hypocrites! Workers of idolatry! You are a perverse people who do always take the name of The Lord in vain! Yet I hear you saying,"},{t:"italic",v:"\u201CBut we only seek to honor You, Lord, in any and all ways.\u201D"},{t:"text",v:"Yet I ask you, how can we be one if your heart belongs to another?"},{t:"fn",v:"5"},{t:"text",v:"And how does reveling in those things I hate honor Me? I tell you the truth, all who love this world more than Me are not worthy of Me! And all who honor the ways of the harlot dishonor Me and shall share in her judgment! And ALL, who revel in the ways of the pagan, have cast their lot with satan! Or have you never read these Scriptures:"},{t:"italic",v:"You can not drink the cup of The Lord and the cup of demons; you can not partake of The Lord\u2019s table and of the table of demons?!"},{t:"fn",v:"6"}]},{type:"para",segments:[{t:"text",v:"Indeed, what do all these things have to do with Me? Why do you decorate the tree? Is it not beautiful as it is? And why do you decorate your house? A household, which seeks to honor Me, has no need of worldly decorations. For in humility, set apart, shall you shine forth. And why do you give worldly gifts in My name? Am I not The Gift,"},{t:"italic",v:"He who ascended on high, He who led captivity captive and gave gifts to men?"},{t:"fn",v:"7"},{t:"text",v:"Therefore receive of Me, of all I offer, and be separate. For in following My ways do you give gifts to Me and to each other, even to all those around you, for the gifts I bring endure forever. Therefore, again I ask you, what matter these things of the world and men, which shall soon pass away? Yet you say,"},{t:"italic",v:"\u201CAll these things are a metaphor and a testament to You, Lord.\u201D"},{t:"text",v:"Yet I tell you, anything which comes from sin"},{t:"italic",v:"is sin;"},{t:"text",v:"do not do it! Tear down all these whitewashed walls of abomination, and do only as The Word of God instructs! For the season of giving is each and every day, and the season of love is every day, every hour, every minute, every moment of your life lived in Me. So then, share My gifts and withhold not; lift up the poor in spirit and feed the hungry, help the needy and comfort the sick, doing so in My name. Yet do not do as the pagans do, for this is sin. Be completely separate and shun these perverse holidays of men; stop breaking My Commandments! You wish to celebrate My name and My earthly birth, do so; yea, bring glory to My name by your obedience, set apart. You wish to enjoy festivals with your family, do so; I have given you seven."},{t:"fn",v:"8"},{t:"text",v:"And in these seven is wisdom and understanding, the very mind of God, revelation beyond words, the will of God made manifest. Yet no more do as the pagans and false teachers would have you do. Cast off this holiday; throw away your tree and lights, rid your house of all decorations, turn away from these filthy traditions. Honor Me as I truly am, obey the Scriptures, and turn away from the commandments of men."}]},{type:"poetry",lines:[[{t:"italic",v:"Know this: The Salvation Day of Men is four-fold..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It was ordained before the foundation of the world,"}],[{t:"italic",v:"Fulfilled at My birth, finished at My death on the cross,"}],[{t:"italic",v:"And solidified eternally upon My resurrection..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"note",text:'See: "Regarding The Holy Days"',url:"https://www.thevolumesoftruth.com/Regarding_The_Holy_Days",link:{collection:"Regarding The Holy Days",letterTitle:"The Holy Days"}},2:{type:"scripture",ref:"Hosea 4:6"},3:{type:"scripture",ref:"1 Timothy 4:1-2"},4:{type:"scripture",ref:"2 Timothy 3:2-5"},5:{type:"note",text:`See: "Regarding 'Another Messiah'"`,url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},6:{type:"scripture",ref:"1 Corinthians 10:21"},7:{type:"scripture",ref:"Ephesians 4:8"},8:{type:"note",text:'See: "Regarding The Holy Days"',url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"}},nkjv:{"Hosea 4:6":"My people are destroyed for lack of knowledge. Because you have rejected knowledge, I also will reject you from being priest for Me; Because you have forgotten the law of your God, I also will forget your children.","1 Timothy 4:1-2":"1. Now the Spirit expressly says that in latter times some will depart from the faith, giving heed to deceiving spirits and doctrines of demons, 2. speaking lies in hypocrisy, having their own conscience seared with a hot iron,","2 Timothy 3:2-5":"2. For men will be lovers of themselves, lovers of money, boasters, proud, blasphemers, disobedient to parents, unthankful, unholy, 3. unloving, unforgiving, slanderers, without self-control, brutal, despisers of good, 4. traitors, headstrong, haughty, lovers of pleasure rather than lovers of God, 5. having a form of godliness but denying its power. And from such people turn away!","1 Corinthians 10:21":"You cannot drink the cup of the Lord and the cup of demons; you cannot partake of the Lord\u2019s table and of the table of demons.","Ephesians 4:8":"Therefore He says: \u201CWhen He ascended on high, He led captivity captive, And gave gifts to men.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/regarding-the-celebration-of-christmas-5",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/regarding-the-celebration-of?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=b2ttyJPwC-0&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=14",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Man's Holidays vs. God's Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"}],num:12,prevLetter:{id:"death-and-awakening",title:"Death and Awakening"},nextLetter:{id:"duty",title:"Duty"}},{id:"duty",title:"Duty",date:"11/19/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy and His Wife, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Behold, the Spirit of The Lord is upon you. For it is written, and behold, the time has come:"},{t:"italic",v:"In those days I will pour out My spirit, and My sons and daughters will dream dreams and prophesy."},{t:"fn",v:"1"},{t:"text",v:"Therefore give heed to My spirit, and also receive, for that which is revealed is of utmost importance. For I have spoken, and shall continue to speak, and that which I give you shall be written in a book, says The Lord."}]},{type:"para",segments:[{t:"text",v:"Thus I shall speak to you, Timothy, and you shall write My words, and you together with your wife shall place them in My Book. For I have called you to be a prophet, as in the days of old; and you, Beloved, shall be his scribe. Thus you shall receive of the Truth and blow this Trumpet, you shall dream dreams and prophesy. For you are two of one flesh. Therefore as one you shall serve Me, and together you shall accomplish My will. As Baruch served Jeremiah,"},{t:"fn",v:"2"},{t:"text",v:"so shall you, Beloved, serve your husband, handling all affairs unique to your office. And as I called Jeremiah, so have I called you, Timothy."},{t:"italic",v:"From your birth, I set you apart for My purpose; yea, before your formation in the womb, I appointed you a prophet to the nations."},{t:"fn",v:"3"},{t:"italic",v:"And in like manner have I set you over nations and over kingdoms, to root out and to pull down, to destroy and to throw down, to build and to plant."},{t:"fn",v:"4"},{t:"text",v:"Therefore, Beloved, listen to your husband with all attentiveness and humility, for he is the head. You together are of one body, yet Timothy is the head. For he is your husband, and he speaks for Me..."},{t:"italic",v:"Yet I am The Head of all, even over all creation, known and unknown, Lord of Heaven and Earth."},{t:"text",v:"And though he must be separated from you during the time appointed, he will not be alone, I will be with him. And he too shall come to know My dwelling place, going out and coming in, walking always in the fullness of My spirit. And this is the means by which he shall perform My will, accomplishing even all I command him. I AM THE LORD."}]},{type:"poetry",lines:[[{t:"italic",v:"Timothy, I have made you a watchman for My people,"}],[{t:"italic",v:"A witness, of the number, My mouthpiece,"}],[{t:"italic",v:"And through you shall I make My plans known"},{t:"fn",v:"5"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You shall proclaim My words aloud,"}],[{t:"italic",v:"Reprove, rebuke and exhort,"}],[{t:"italic",v:"And convict this generation of its evil ways;"}],[{t:"italic",v:"You shall dream dreams, see visions and prophesy,"}],[{t:"italic",v:"Until the day I send you into the midst of the battle..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Fear not, for greater is He who dwells within you"}],[{t:"italic",v:"Than he who is in the world..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"scripture",ref:"Joel 2:28, Acts 2:17"},2:{type:"scripture",ref:"Jeremiah 36:4"},3:{type:"scripture",ref:"Jeremiah 1:5"},4:{type:"scripture",ref:"Jeremiah 1:10"},5:{type:"scripture",ref:"Amos 3:7 CJB"}},nkjv:{"Joel 2:28, Acts 2:17":"Joel 2:28 \u2014 \u201CAnd it shall come to pass afterward That I will pour out My Spirit on all flesh; Your sons and your daughters shall prophesy, Your old men shall dream dreams, Your young men shall see visions. | Acts 2:17 \u2014 \u2018And it shall come to pass in the last days, says God, That I will pour out of My Spirit on all flesh; Your sons and your daughters shall prophesy, Your young men shall see visions, Your old men shall dream dreams.","Jeremiah 36:4":"Then Jeremiah called Baruch the son of Neriah; and Baruch wrote on a scroll of a book, at the instruction of Jeremiah, all the words of the LORD which He had spoken to him.","Jeremiah 1:5":"\u201CBefore I formed you in the womb I knew you; Before you were born I sanctified you; I ordained you a prophet to the nations.\u201D","Jeremiah 1:10":"See, I have this day set you over the nations and over the kingdoms, To root out and to pull down, To destroy and to throw down, To build and to plant.\u201D","Amos 3:7 CJB":"Surely the Lord GOD does nothing, Unless He reveals His secret to His servants the prophets."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/duty-4",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/duty?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=7brbs7cBqvQ&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=15",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],num:13,prevLetter:{id:"regarding-the-celebration-of-christmas",title:"Regarding the Celebration of Christmas"},nextLetter:{id:"i-shall-correct-and-discipline-all-those-i-love",title:"I Shall Correct and Discipline All Those I Love"}},{id:"i-shall-correct-and-discipline-all-those-i-love",title:"I Shall Correct and Discipline All Those I Love",date:"12/11/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My children, struggle not against the principles of another, nor rebuke them with your own words, nor correct them by your own understanding. Let go of your personal notions of right and wrong, and strive to love others in spite of yourselves, and have compassion for those with whom you disagree. Do not judge them, nor shun them in your heart."},{t:"italic",v:"Rather love those who speak against you, because you obey My Word; bless those who curse you, and pray for those who mistreat you, as it is written."},{t:"fn",v:"1"},{t:"text",v:"Yet have no part with them, nor give them a platform from which to proliferate their sinful ways; remain separate. For they do rebel against their God. Their argument is with Me, though it may seem as though you have become the object of their scorn. For they do always fight against Me, in an effort to justify their sins. For I have written The Law in the hearts of all men; all are able to discern right from wrong. Thus they choose to rebel; they remain in their sins."}]},{type:"poetry",lines:[[{t:"italic",v:"For I have indeed written it,"}],[{t:"italic",v:"Even on tablets of stone and within the heart of man,"}],[{t:"italic",v:"And within the pages of My Book it is made plain;"}],[{t:"italic",v:"Thus they are without excuse..."}]]},{type:"closing",text:"For I am God alone, The Righteous One..."},{type:"poetry",lines:[[{t:"italic",v:"I alone am holy, just and good;"}],[{t:"italic",v:"I alone have divided right from wrong;"}],[{t:"italic",v:"I alone have established The Law and define what is sin..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I expose the darkness and bring all hidden things into the light;"}],[{t:"italic",v:"For I alone sit as Judge, The Only Faithful and True Witness."}]]},{type:"para",segments:[{t:"bold-italic",v:"Therefore let it be known to you, O peoples of the earth, and to all who dwell within the churches of men:"},{t:"text",v:"I must bring My hand against you, I must correct and discipline all those I love. For you have gone astray; behold, from Me you are far removed. And with great malice you do always persecute those I send to you, rejecting the Word given them on account of your pride, persecuting them in word and by deed, stoning some and killing others. Therefore in My jealousy I shall speak, and in the fire of My wrath I shall rebuke you! Behold, My wrath shall come forth and My judgment shall not sleep! For I am coming down to correct, to discipline and to punish, to pour out judgment upon the whole of this wicked generation! Yet those who repent in sincerity and in truth will be delivered, and those who turn from their evil ways will be shown mercy. For I do not change, says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"O you blind leaders of the blind, dumb people who attempt to speak to the deaf, you are lost. You fear I am coming to destroy you. I am not coming to destroy you, but to humble you, that you might be delivered from all this evil which encompasses you round about; I am coming to destroy that which stands against Me, to tear down all man has made!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, again I say to you,"}],[{t:"italic",v:"I shall surely correct and discipline all those I love,"}],[{t:"italic",v:"And upon this most wicked generation"}],[{t:"italic",v:"Shall I pour out judgment..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet as it is written,"}],[{t:"italic",v:"I will do nothing until I have revealed"}],[{t:"italic",v:"My plans to My servants, the prophets"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"closing-fn",segments:[{t:"italic",v:"For I am The Lord, and I do not change."},{t:"fn",v:"3"}]}],footnotes:{1:{type:"scripture",ref:"Matthew 5:44"},2:{type:"scripture",ref:"Amos 3:7"},3:{type:"scripture",ref:"Malachi 3:6"}},nkjv:{"Matthew 5:44":"But I say to you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who spitefully use you and persecute you,","Amos 3:7":"Surely the Lord GOD does nothing, Unless He reveals His secret to His servants the prophets.","Malachi 3:6":"\u201CFor I am the LORD, I do not change; Therefore you are not consumed, O sons of Jacob."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-shall-correct-and-discipline-all-those-i-love-4",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/i-shall-correct-and-discipline?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=uX0dtgHqdHw&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=16",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Take No Part",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Take_No_Part"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Volumes of Truth (Amos 3:7)",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth#Amos_3:7"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:14,prevLetter:{id:"duty",title:"Duty"},nextLetter:{id:"know-that-which-has-been-poured-out-the-word-of-god",title:"Know That Which Has Been Poured Out, The Word of God"}},{id:"know-that-which-has-been-poured-out-the-word-of-god",title:"Know That Which Has Been Poured Out, The Word of God",date:"12/13/04",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"How is it you have not recognized that which comes from The Father? For that which is of the devil is made plain and surrounds you on every side. Therefore the things of God become that much more precious, even as you, My son, are most precious in My sight..."},{t:"italic",v:"Like a gemstone shining in the midst of all this darkness, easily found by the eyes of God, so shall you be in the day you surrender your life, the day you give up this fight and return to Me."},{t:"text",v:"Do you not understand that I have saved you? No, not by your own works, but by My life, which I willingly gave up for you. Therefore, turn to Me wholly and in truth. And no more let the doctrines of men in the churches steal from your trust; nor let their traditions pollute your faith anymore. Be set apart from the ways of this world, and depart from the churches of men. For I alone am your faith, I alone am your completion. Therefore listen, and you will also know, for by the Spirit of God are all things revealed to the chosen. Search your heart, My son, and you will find Me; embrace My words, and you will begin to know Me. For indeed, there are many gifts of the Spirit which I bestow upon all those who love Me, many gifts given to those who are willing to give up everything and follow Me. Thus Timothy is just one among many who hear My voice, one voice in a great chorus growing ever louder, of the number I am sending. Yet to him did I say,"},{t:"italic",v:"\u201CWrite that which I speak, and place it in a book\u201D;"},{t:"text",v:"also commanding him to share that which the Spirit causes him to understand. For the latter is that which My people call inspired of God or inspired in the Spirit; and the former, that which the prophets hear, the voice of The Living God. Therefore listen to Timothy, for he speaks for Me, he hears My voice. Behold, he has sat in My presence and strives to obey all I ask of him. Do not say then, nor conceive any notion within your heart, that he may be deceived by the devil. Or have you never read these Scriptures:"},{t:"italic",v:"Every kingdom divided against itself will surely be brought to ruin, and every house divided against itself will collapse. If satan also is divided against himself, how then will his kingdom stand?"},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"Do men gather grapes of thorns, or figs of thistles?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For a good tree brings forth good fruit,"}],[{t:"italic",v:"But a corrupt tree brings forth evil fruit;"}],[{t:"italic",v:"Neither can a corrupt tree bring forth good fruit..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And every tree that does not bring forth"}],[{t:"italic",v:"Good fruit is hewn down and cast into the fire..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus by their fruits you shall know them."},{t:"fn",v:"2"}]]},{type:"para",segments:[{t:"text",v:"And was I speaking only of the false prophets, or of the true also? Is it not also implied that I speak of their message? And what of all these self-appointed scholars, teachers, pastors, preachers, ministers and priests, who have set themselves up as an authority? What fruit do they bear according to the Scriptures? Come out from among them! No longer embrace their corrupt doctrines, nor take part in their filthy traditions! Stand apart from those who mix the holy with the profane, depart from that which is covered in purple and scarlet, and no more practice that which is an abomination in the eyes of God!"},{t:"fn",v:"3"},{t:"text",v:"For it is the humble, penitent man who hears God, one who is willing to give up his life in this world for My sake. Therefore take My words to heart, and understand: Any man who shares My Word with others is My servant. And any man who hears My voice, in whose hand I have placed the Trumpet, is My prophet. Even all those I send are My apostles. And any who heed these words, and also do them, shall be called a friend of God."}]},{type:"para",segments:[{t:"text",v:"Beloved, this Word, even every Volume to every Letter, is the Word of My glory which I have put forth once again; a testament of My love and sacrifice, the announcement of My coming, a proclamation of truth, revelation of who I really am -"},{t:"italic",v:"the Trumpet Call of God, so all those called and chosen may hear and come to Me in their proper time and season."},{t:"text",v:"Behold, it is also a strong correction for all those who have taken to themselves MY name and MY Word, to pollute it, a plumb line for this wicked generation. For this Word is a waving banner, an ensign to all nations! -"},{t:"italic",v:"A trumpet of alarm and war, the sound of recompense and judgment, which shall soon fall upon every nation!"}]},{type:"poetry",lines:[[{t:"italic",v:"For I AM WHO I AM!\u2026"}]]},{type:"poetry",lines:[[{t:"italic",v:"The Only Begotten of The Father,"}],[{t:"italic",v:"The One True God and Savior,"}],[{t:"italic",v:"The Mashiach!\u2026"}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA-YAHUWAH!"}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 12:25-26"},2:{type:"scripture",ref:"Matthew 7:16-20"},3:{type:"note",text:'See: "Regarding What is an Abomination to The Lord"',url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"}},nkjv:{"Matthew 12:25-26":"25. But Jesus knew their thoughts, and said to them: \u201CEvery kingdom divided against itself is brought to desolation, and every city or house divided against itself will not stand. 26. If Satan casts out Satan, he is divided against himself. How then will his kingdom stand?","Matthew 7:16-20":"16. You will know them by their fruits. Do men gather grapes from thornbushes or figs from thistles? 17. Even so, every good tree bears good fruit, but a bad tree bears bad fruit. 18. A good tree cannot bear bad fruit, nor can a bad tree bear good fruit. 19. Every tree that does not bear good fruit is cut down and thrown into the fire. 20. Therefore by their fruits you will know them."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/know-that-which-has-been-poured-out-the-word-of-god",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/know-that-which-has-been?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=3kFiwwwgIog&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=17",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Discernment",url:"https://answersonlygodcangive.com/Main_Page#Discernment"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Spiritual Gifts",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Gifts"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:'The Name of The Lord - "YAHUSHUA-YAHUWAH"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YAHUSHUA-YAHUWAH"}],num:15,prevLetter:{id:"i-shall-correct-and-discipline-all-those-i-love",title:"I Shall Correct and Discipline All Those I Love"},nextLetter:{id:"run-from-the-forest-and-loose-all-that-binds-you",title:"Run from the Forest and Loose All That Binds You"}},{id:"run-from-the-forest-and-loose-all-that-binds-you",title:"Run from the Forest and Loose All That Binds You",date:"12/23/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Timothy, write as I speak. For the time has come, and is already upon you, when the children of God must be cleansed and set apart for My glory, says The Lord. Yet today the sanctified will be lashed, and the wicked uplifted. And tomorrow evil shall come in, allowed only for a short season, that My people may be tested and the multitudes divided, a sifting of the wheat for the harvest; some to the first, while many others left to the second, with all tares burned in the fire; those on My right to everlasting life, and those on My left to everlasting punishment."},{t:"fn",v:"1"},{t:"text",v:"Even so, amen."}]},{type:"para",segments:[{t:"text",v:"For Salvation had come and has remained in the midst of you, even from the beginning, freely offered to all people since the time of Immanu El on earth. Yet the people refuse to see, nor will they listen; their eyes are blinded, their ears deaf. For the nations have no love for the Truth, for they barter for falsehoods and set up their exchange upon lies. They are lost, wandering aimlessly in a forest without hope, amongst many tall trees of abomination, with darkness and deceit on every side. Yet those who have received eyes to see, see the way ahead clearly and without obstruction, and follow it. And those who have received ears to hear, hear the Truth and obey it. For the way of the upright is well lit, it is not at all hidden, though the men of this world cease not from trying to cover it. Yet the more they strive to push it down, hide it by force and cover it over, the greater will it shine forth..."},{t:"italic",v:"Bursting forth from its hold, filling the entire earth, devouring all darkness in its path and transforming all things in its wake!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the time has come! The Day is very near!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Thief shall enter the house"}],[{t:"italic",v:"And steal away all who are not tied down,"}],[{t:"italic",v:"Fastened, or shackled to the house..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And all those in whom He sees of Himself"}],[{t:"italic",v:"Shall surely be gone from this place!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "Q & A: What is the Fate of the Wicked? (*Verses Often Stumbled Over)"',url:"https://www.thevolumesoftruth.com/The_State_of_the_Dead_and_The_Fate_of_the_Wicked:_The_False_Doctrine_of_Hell_and_Eternal_Torment_Exposed#.28.2AVerses_Often_Stumbled_Over.29",link:{collection:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",letterTitle:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/run-from-the-forest-and-loose-all-that-binds-you",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/run-from-the-forest-and-loose?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=nFPYl8VjZLo&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=18",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:16,prevLetter:{id:"know-that-which-has-been-poured-out-the-word-of-god",title:"Know That Which Has Been Poured Out, The Word of God"},nextLetter:{id:"seek-the-lord-and-he-will-open-the-way",title:"Seek The Lord and He Will Open The Way"}},{id:"seek-the-lord-and-he-will-open-the-way",title:"Seek The Lord and He Will Open The Way",date:"12/25/04",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"It is written:"},{t:"italic",v:"Ask, and it will be given you; seek, and you shall find; knock, and it will be opened to you."},{t:"fn",v:"1"},{t:"text",v:"My son, I am The Answer you search for, I am The Truth you seek. Therefore, he who abides in Me shall reside in the presence of The Almighty, and shall be given knowledge and receive understanding. Thus those who remain void of the Spirit must continually seek Me, and they too shall find Me, for I have written all in My Book. Yet those who read the Word of The Lord must also believe it, or how shall they know Me? For those who truly know Me seek to"},{t:"italic",v:"abide in My love."},{t:"fn",v:"2"},{t:"text",v:"Yet how can one remain in My love, if they do not obey My teaching? For My grace descends upon all who repent in sincerity and in truth, and My spirit dwells within those who keep The Commandments and testify to My glory. Therefore, My son, receive of Me; then will that which you seek become clear. For your heart\u2019s true desire can not be found in the world..."},{t:"italic",v:"Seek God!"}]},{type:"poetry",lines:[[{t:"italic",v:"Again I say to you, search not in the world,"}],[{t:"italic",v:"For there you will not find Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Nor seek Me in the churches of men,"}],[{t:"italic",v:"For there you will not find Me..."}]]},{type:"closing",text:"For I tell you the truth, The Kingdom of God is within you..."},{type:"poetry",lines:[[{t:"italic",v:"And that which is most needful, is it not written for you?"}]]},{type:"para",segments:[{t:"text",v:"Therefore,"},{t:"italic",v:"do not place your trust in any man,"},{t:"fn",v:"3"},{t:"text",v:"nor lean upon man\u2019s invention, for the things of this world deceive you. Beloved, turn away from those who teach as doctrine the commandments of men, and stand apart from all this modern ideology, for it is poison. Close your eyes to all these images on the screen, shut your ears to the noise of this world, and separate yourself from all these mocking voices. For the evil one is, at present, the lord of the air; indeed, every corrupt seed planted within the heart of man is of the evil one. From the beginning he was a liar, and from the beginning he planted seeds of wickedness in My garden, for it is written:"},{t:"italic",v:"There is no truth in him. When he tells a lie, he is only doing what is natural to him, because he is a liar; indeed, he is the father of all lies."},{t:"fn",v:"4"},{t:"text",v:"Therefore, embrace only that which is good and comes down from your Father in Heaven. For God is love, and that which He sends is Spirit and Truth. And by these things shall you be led, even as you in like manner lead those around you, if you so choose to obey My voice and walk in My ways. Yet remember this: Those who boast of their own works are prideful, and seek after the praises of men. Yet those who boast of The Lord\u2019s works, for your sake, are humble, and seek to honor Me; in these pride is far removed. For those who give Me glory honor Me, and those who give thanks without ceasing offer up perfect praise. To the likes of these listen closely, for their desire is righteous and their love true. Behold, they seek The Kingdom of Heaven and My righteousness, and salvation has become their companion."}]},{type:"para",segments:[{t:"text",v:"Therefore, My son, do not worry because you do not have all the answers, nor be upset because you do not fully understand. For The Lord your God is Truth, even as I am The Truth. For all knowledge resides within The Father, even as I am in The Father and He is in Me. Thus I am also The Answer."}]},{type:"poetry",lines:[[{t:"italic",v:"My son, trust in Me, and you shall be set free;"}],[{t:"italic",v:"For it is the humble, penitent man who shall see God;"}],[{t:"italic",v:"Behold, he shall look upon My face,"}],[{t:"italic",v:"As I restore him in My image..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I am the image of The Invisible God,"}],[{t:"italic",v:"The perfect reflection of The Father,"}],[{t:"italic",v:"The face of The Majesty from on high,"}],[{t:"italic",v:"Immanu El..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore open your heart to Me,"}],[{t:"italic",v:"And I shall create you anew..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 7:7"},2:{type:"scripture",ref:"John 15:10"},3:{type:"note",text:'See: "Trust in God Alone"',url:"https://www.thevolumesoftruth.com/Trust_in_God_Alone#:~:text=And%20do%20not,from%20a%20tree.",link:{collection:"A Testament Against The World: The Lord's Rebuke",letterTitle:"Trust in God Alone",excerpt:"And do not put your trust in any man, though he speaks with a clever tongue"}},4:{type:"scripture",ref:"John 8:44"}},nkjv:{"Matthew 7:7":"\u201CAsk, and it will be given to you; seek, and you will find; knock, and it will be opened to you.","John 15:10":"If you keep My commandments, you will abide in My love, just as I have kept My Father\u2019s commandments and abide in His love.","John 8:44":"You are of your father the devil, and the desires of your father you want to do. He was a murderer from the beginning, and does not stand in the truth, because there is no truth in him. When he speaks a lie, he speaks from his own resources, for he is a liar and the father of it."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/seek-the-lord-and-he-will-open-the-way",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/seek-the-lord-and-he-will-open?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=CYTBpnFA1JI&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=19",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:'The Name of The Lord - "Immanu El"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#Immanu_El"}],num:17,prevLetter:{id:"run-from-the-forest-and-loose-all-that-binds-you",title:"Run from the Forest and Loose All That Binds You"},nextLetter:{id:"the-signs-of-the-coming-of-the-son-of-man",title:"The Signs of the Coming of The Son of Man"}},{id:"the-signs-of-the-coming-of-the-son-of-man",title:"The Signs of the Coming of The Son of Man",date:"12/29/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Many great signs have been given to this generation, yet all have went greatly ignored by the multitude. Yet those who are Mine have clearly seen. For those who truly know Me rejoice in the Truth and embrace My correction, and strive always to walk in My ways, glorifying My name without ceasing. For they shine like the sun at noonday, even in the height of summer."}]},{type:"poetry",lines:[[{t:"italic",v:"Yet understand this,"}],[{t:"italic",v:"These signs are but the first of many,"}],[{t:"italic",v:"And shall continue, increasing by measure"}],[{t:"italic",v:"Until the time be fulfilled..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then shall The Son of Man appear,"}],[{t:"italic",v:"Clothed in the brightness of His glory,"}],[{t:"italic",v:"A brilliance which has no equal;"}],[{t:"italic",v:"Even the blind shall see!"}]]},{type:"para",segments:[{t:"text",v:"Behold, I called to the sea, saying,"},{t:"italic",v:"\u201CRise up! Churn, and bring forth a terrible wind! Go ashore, increase in height and make a great noise! Blow like the voice of The Almighty and release a great deluge upon men! Move all things from their places, break apart and destroy! Cause this people to flee in fear, that they may now call upon My name!\u201D"},{t:"text",v:"And still those who dwelt near the shore did not call upon My name in sincerity, nor in truth, nor did they repent of their evil deeds. Behold, three more times did I call the sea to rise up and come ashore, causing that which had lessened to regain strength and return once again. And still the people did not awake, their eyes remained shut, their hearts hard and unyielding. Indeed, the multitudes refuse to give Me glory! And oh how quickly they do always return to their sin, as they seek to fortify their rebellion against God. Therefore the seas shall become angry, the earth shall rumble and quake, and the waves shall continue to crash before the Great and Terrible Day of The Lord! Behold, even the powers of heaven shall be shaken,"},{t:"italic",v:"and the world shall seek to become one, as it is written."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Yet I tell you, there is a sign greater than these. For all creation obeys My voice; from the deepest depths to the highest peaks, to the rocks which lay upon the ground; from the multitudes of insects to the animals of the field and those which fly above; from the waters of the sea to every living creature which dwells within them, great and small; from the winds of heaven to the stars above, all creation obeys the voice of The Almighty. Yet with man it is not so. For the heart of man remains hard and unyielding, and oh how he sets his ways in stone. For in his arrogance, he refuses to listen to the Word of God, nor will he accept My correction. And because of his pride he remains unwilling to heed the call of The Most High. Yet I tell you the truth, that which is made of stone shall break! And that which refuses to be broken shall be crushed beneath the weight of The Cornerstone! Yet that which is laid atop it shall be broken and refashioned, made new. Thus a heart made new in The Lord is the greatest sign of all. For the whole earth is set under My authority, obeying My will without question. Whether upon the land or in the sea, or in the heavens above, all things obey the voice of The Living God, save man. For to him alone did I give the will to choose. And what is life without love? And what is love without the free will to choose love? I tell you the truth, a gift commanded is no gift at all! Yet a gift accepted is where you shall find life, love and salvation."}]},{type:"para",segments:[{t:"italic",v:"Behold, all shall be moved from their places, that the eyes of the prideful might be opened and the ears of the arrogant unstopped, that all might repent and return to Me! Therefore watch! For the time has come for the will of God to be made manifest, for the earth to tremble and quake, to spew its fervent heat! Now is the time for signs in the heavens above and in the earth beneath, for the judgments of God to be poured out, for the wrath of God to fall from Heaven!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, come out from among them,"}],[{t:"italic",v:"And take refuge in Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I am your only shelter,"}],[{t:"italic",v:"Your only sanctuary from the storm..."}],[{t:"stanza-break"}],[{t:"italic",v:"Says The Holy One of Israel."}]]}],footnotes:{1:{type:"note",text:'Also read: "Treason"',url:"https://www.thevolumesoftruth.com/Treason#Treason",link:{collection:"Volume Five",letterTitle:"Treason"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-signs-of-the-coming-of-the-son-of-man",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-signs-of-the-coming-of-the?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=rktIJyyOElY&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=20",videoMusicUrl:"https://www.youtube.com/watch?v=qkTCutjkG1s&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=29",relatedTopics:[{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"The Coming of The Son of Man",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#The_Coming_of_The_Son_of_Man"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the End Sign",url:"https://answersonlygodcangive.com/Regarding_the_End_Sign"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"}],num:18,prevLetter:{id:"seek-the-lord-and-he-will-open-the-way",title:"Seek The Lord and He Will Open The Way"},nextLetter:{id:"make-way-for-the-coming-of-the-lord",title:"Make Way for the Coming of The Lord"}},{id:"make-way-for-the-coming-of-the-lord",title:"Make Way for the Coming of The Lord",date:"12/30/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",noteLine:"(Regarding the Indonesian tsunami)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, hear My words and write, receive My words and have understanding. For My words are truth, a gift for those who give heed, a blessing for those who walk in them, bringing peace to the hearts of all who believe. My son, I know your pain, I feel your anguish. Yet you need not shed tears over these little ones who were swept away, for they have returned home. They dwell in the bosom of their Father, once again. Therefore do not be troubled, be at peace. Trust in My will, though you do not yet fully understand."}]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, many shall fall asleep"}],[{t:"italic",v:"On account of My quaking footsteps..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the Day draws near when I shall tread"}],[{t:"italic",v:"The grapes in the winepress of the wrath of My fury,"}],[{t:"italic",v:"When I shall shake the heavens and the earth,"}],[{t:"italic",v:"When all at rest shall be moved from their places..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the peoples of the earth rest in things they should not;"}],[{t:"italic",v:"They lie down in perverse traditions, and give themselves"}],[{t:"italic",v:"To the abominations of the pagan and the heathen;"}],[{t:"italic",v:"They put their faith in things that can not save."}]]},{type:"para",segments:[{t:"text",v:"Behold, they worship the works of their own hands, as they deny their Creator! They trust in that which is worthless, and in vain they bow down to lifeless statues and pray to graven images! FALSE GODS ABOUND! Yes, they pay homage to idols which can not grant life, neither can they take it away! There is no healing power in them, worthless images which neither speak nor hear! All is vanity and vexation of spirit, doctrines of demons! For all the religions of man are utterly useless!"}]},{type:"para",segments:[{t:"text",v:"Yet the people cry,"},{t:"italic",v:"\u201CDisaster! Death and mourning!\u201D"},{t:"text",v:"Yet I say, do not mourn for the dead, for they only sleep. They abide in darkness for but an instant, for the dead know nothing at all; they know not the passage of time, nor of the seasons."},{t:"fn",v:"1"},{t:"text",v:"They have closed their eyes to this life, yet they shall surely open them again; behold, all shall look upon the face of The Lord their Redeemer, The One who died yet is alive forevermore. Amen. Now look upon those left, look at these who have escaped disaster and death. Their hearts have begun to change, as they cry,"},{t:"italic",v:"\u201CHave compassion!\u201D"},{t:"text",v:"saying within themselves,"},{t:"italic",v:"\u201CWhat is this life of mine filled with all manner of material things and devices, all manner of comforts and pleasures?! None of it matters! Only LIFE is important!\u201D"},{t:"text",v:"And so they cry and lament. Again, I say to you, wail not for those who have passed away, as though you had no hope, nor for the little ones, for they have returned home. For most assuredly, I say to you, by no means does death have the last word."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to the peoples of the earth:"},{t:"text",v:"Wail for yourselves! Wail loudly for those whose hearts have become like stone! Wail for those who have eyes yet refuse to see, for those who have ears yet refuse to hear! Wail! For they know not The Kingdom of God, nor do they seek Him; they have forgotten the place from whence they came, and want no part with Him through whom they were made."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, wake up and pay attention!"}],[{t:"italic",v:"Awaken out of this sleep, be shaken out"}],[{t:"italic",v:"Of this slumber, and call upon My name!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Seek out My will that you may know it;"}],[{t:"italic",v:"Heed the sound of this Trumpet and prepare!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My Kingdom comes, and My will"}],[{t:"italic",v:"Shall be done on earth as in Heaven..."}],[{t:"stanza-break"}],[{t:"italic",v:"Says The Lord God."}]]}],footnotes:{1:{type:"note",text:'See: "Q & A: What is the State of the Dead? (State of the dead)"',url:"https://www.thevolumesoftruth.com/The_State_of_the_Dead_and_The_Fate_of_the_Wicked:_The_False_Doctrine_of_Hell_and_Eternal_Torment_Exposed#.28State_of_the_dead.29",link:{collection:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",letterTitle:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/make-way-for-the-coming-of-the-lord",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/make-way-for-the-coming-of-the?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=jNzQWWuqoAY&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Returned Home",url:"https://answersonlygodcangive.com/Regarding_Children%E2%80%99s_Inheritance_on_Earth_and_in_Heaven#Returned_Home"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:19,prevLetter:{id:"the-signs-of-the-coming-of-the-son-of-man",title:"The Signs of the Coming of The Son of Man"},nextLetter:{id:"to-whom-does-the-kingdom-of-heaven-belong",title:"To Whom Does The Kingdom of Heaven Belong"}},{id:"to-whom-does-the-kingdom-of-heaven-belong",title:"To Whom Does The Kingdom of Heaven Belong",date:"1/2/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Let the truth be known regarding the innocent, My most precious gifts, My beloved little ones. When one of these little ones pass from your sight, grieve not, for they have returned home. Rather grieve for yourselves. For a precious gemstone has been taken; behold, a treasure which has no equal has been hidden before its time."},{t:"fn",v:"1"},{t:"italic",v:"For The Kingdom of Heaven belongs to all such as these."},{t:"fn",v:"2"},{t:"text",v:"Thus these who have come forth from The Kingdom, who remain without blemish, whose lives were cut short, return to Him from whom they came. For the little ones need not sleep in death."},{t:"italic",v:"For the penalty of sin is death,"},{t:"fn",v:"3"},{t:"text",v:"yet they remain in their innocence..."},{t:"italic",v:"And oh how blessed are the pure in heart, for they shall surely behold My face."},{t:"fn",v:"4"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to all who have harmed or killed the little ones, and to all who stand in agreement:"},{t:"italic",v:"It would be better for you if a millstone were hung around your neck, and you were drowned in the depths of the sea, than to suffer My wrath over these little ones!"},{t:"fn",v:"5"},{t:"text",v:"FOR I HAVE SEEN IT! You have mistreated and abused them, you have murdered My gifts! And in so doing have you ripped"},{t:"italic",v:"yourselves"},{t:"text",v:"from The Kingdom of Heaven!..."},{t:"italic",v:"You are cast out! And shall remain outside the gates,"},{t:"fn",v:"6"},{t:"italic",v:"unless you repent wholly and in truth, striving always to make your repentance full!"},{t:"fn",v:"7"}]},{type:"poetry",lines:[[{t:"italic",v:"I tell you the truth, all upon the earth who have"}],[{t:"italic",v:"Gained maturity have become so very poor and desolate..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For once you were wealthy, rich beyond words,"}],[{t:"italic",v:"For then you knew The Kingdom of Heaven as a child;"}],[{t:"italic",v:"Yet now you are grown, your light quickly fading,"}],[{t:"italic",v:"As the ways of this world pull you down to the pit..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore return to Me, humble and penitent;"}],[{t:"italic",v:"Come to Me as a child..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For by no other means shall you pass through"},{t:"fn",v:"8"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "The Truth Absolute"',url:"https://www.thevolumesoftruth.com/The_Truth_Absolute#:~:text=Thus%20the%20little,above%20precious%20stones.",link:{collection:"Volume Three",letterTitle:"The Truth Absolute",excerpt:"Thus the little children shall be My inheritance, and the babes My jewels."}},2:{type:"scripture",ref:"Matthew 19:14"},3:{type:"scripture",ref:"Romans 6:23, Ezekiel 18:4, Ezekiel 18:20"},4:{type:"scripture",ref:"Matthew 5:8"},5:{type:"scripture",ref:"Matthew 18:6"},6:{type:"scripture",ref:"Revelation 22:15"},7:{type:"note",text:'See: "Regarding True Repentance"',url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},8:{type:"scripture",ref:"Matthew 18:3-4"}},nkjv:{"Matthew 19:14":"But Jesus said, \u201CLet the little children come to Me, and do not forbid them; for of such is the kingdom of heaven.\u201D","Romans 6:23, Ezekiel 18:4, Ezekiel 18:20":"Romans 6:23 \u2014 For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord. | Ezekiel 18:4 \u2014 Behold, all souls are Mine; The soul of the father As well as the soul of the son is Mine; The soul who sins shall die. | Ezekiel 18:20 \u2014 The soul who sins shall die. The son shall not bear the guilt of the father, nor the father bear the guilt of the son. The righteousness of the righteous shall be upon himself, and the wickedness of the wicked shall be upon himself.","Matthew 5:8":"Blessed are the pure in heart, For they shall see God.","Matthew 18:6":"\u201CWhoever causes one of these little ones who believe in Me to sin, it would be better for him if a millstone were hung around his neck, and he were drowned in the depth of the sea.\u201D","Revelation 22:15":"But outside are dogs and sorcerers and sexually immoral and murderers and idolaters, and whoever loves and practices a lie.","Matthew 18:3-4":"3. and said, \u201CAssuredly, I say to you, unless you are converted and become as little children, you will by no means enter the kingdom of heaven. 4. Therefore whoever humbles himself as this little child is the greatest in the kingdom of heaven.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/to-whom-does-the-kingdom-of-heaven-belong-5",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/to-whom-does-the-kingdom-of?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=SiYd74d6bBg&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=22",videoMusicUrl:"https://www.youtube.com/watch?v=uXIYXFWpzX8&list=PLE8FlkxQPQkND8PrAIRI5ghd4pMj21-pF&index=1",relatedTopics:[{label:"Regarding Children\u2019s Inheritance on Earth and in Heaven",url:"https://answersonlygodcangive.com/Regarding_Children%E2%80%99s_Inheritance_on_Earth_and_in_Heaven"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"}],num:20,prevLetter:{id:"make-way-for-the-coming-of-the-lord",title:"Make Way for the Coming of The Lord"},nextLetter:{id:"to-he-who-has-understanding-let-him-hear-the-truth-of-the-inheritance-of-sin-and-salvation",title:"To He Who Has Understanding, Let Him Hear the Truth of the Inheritance of Sin and Salvation"}},{id:"to-he-who-has-understanding-let-him-hear-the-truth-of-the-inheritance-of-sin-and-salvation",title:"To He Who Has Understanding, Let Him Hear the Truth of the Inheritance of Sin and Salvation",date:"1/3/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Hear the Word of The Lord, all those who seek to know wisdom and receive understanding, all those who love the Truth, for thus says The Lord:"},{t:"text",v:"I have spoken, and behold, I speak once again, that all who love the little ones may be encouraged and have peace; and so this most wicked generation may know My anger and tremble in fear."}]},{type:"para",segments:[{t:"text",v:"I ask you, what is a child\u2019s inheritance on earth and in Heaven, if the years of their life be few in number and they remain in their innocence? Assuredly, I say to you, they will inherit The Kingdom of Heaven, for The Father holds the pure of heart in the palm of His right hand. For like the firefly which alights upon the tall grass, so are these little ones, precious lights shining among men. Therefore, woe to those who catch them and shut them away! Woe to any who do them harm! AND WOE, EVEN THREE TIMES WOE, TO ALL WHO EXTINGUISH THEIR LIGHT!"},{t:"italic",v:"For behold, I am coming quickly with a shout, with the voice of the archangel and with the trumpet call of God, to remove the light, to take from the earth My own,"},{t:"fn",v:"1"},{t:"text",v:"and this world shall be plunged into darkness! For judgment shall fall from Heaven, covering the face of the earth like a flood! Behold, as a terrible deluge, punishment from on high shall break out against them and wash them away, until every last trace of evil and wickedness is utterly destroyed!"}]},{type:"poetry",lines:[[{t:"italic",v:"And though the little ones may suffer"}],[{t:"italic",v:"At the hands of men in this world,"}],[{t:"italic",v:"I tell you the truth, all arrive at The Father\u2019s house"}],[{t:"italic",v:"In a moment, in the twinkling of an eye..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Where healing is complete and every tear is wiped away..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The ways of the world and men forgotten..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Only love abides, as they look upon"}],[{t:"italic",v:"The face of their Father forever."}]]},{type:"para",segments:[{t:"text",v:"Yet the scholars cry,"},{t:"italic",v:"\u201CWhat of the inheritance of sin, and those born with the burden of sin upon them?\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Listen and have understanding, humble yourselves that you may gain wisdom, and hear the Word of The Lord:"},{t:"text",v:"All people are born as babes from their mother\u2019s womb, into a world of sin. So then, all born by way of water and blood are born"},{t:"italic",v:"into"},{t:"text",v:"sin, not"},{t:"italic",v:"of"},{t:"text",v:"sin. For how can one who comes from The Kingdom of Heaven, created by the hand of God, have sin upon them? Therefore, you do greatly err. For these little ones do not yet know the ways of the world and men;"},{t:"italic",v:"they have not yet eaten from the tree of the knowledge of good and evil."},{t:"fn",v:"2"},{t:"text",v:"They remain in their innocence."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, I ask you, who has blemished My fireflies?"}],[{t:"italic",v:"Who has tarnished their light? What has corrupted My gifts?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"MEN AND THE WORKS OF EVIL IN THIS WORLD!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus these little ones, even these young ones"}],[{t:"italic",v:"Corrupted by men, need not repent,"}],[{t:"italic",v:"For The Son of Man died for them also..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For their cleansing is of that covenant"}],[{t:"italic",v:"Which has remained unspoken and constant,"}],[{t:"italic",v:"In the loving mercy of God, from the beginning..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 Thessalonians 4:16-17"},2:{type:"scripture",ref:"Genesis 2:17"}},nkjv:{"1 Thessalonians 4:16-17":"16. For the Lord Himself will descend from heaven with a shout, with the voice of an archangel, and with the trumpet of God. And the dead in Christ will rise first. 17. Then we who are alive and remain shall be caught up together with them in the clouds to meet the Lord in the air. And thus we shall always be with the Lord.","Genesis 2:17":"but of the tree of the knowledge of good and evil you shall not eat, for in the day that you eat of it you shall surely die.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/to-he-who-has-understanding-let-him-hear-the-truth-of-the-inheritance-of-sin-and-salvation",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/to-he-who-has-understanding?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=wyxblL8gOnU&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=23",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Children\u2019s Inheritance on Earth and in Heaven",url:"https://answersonlygodcangive.com/Regarding_Children%E2%80%99s_Inheritance_on_Earth_and_in_Heaven"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:'The Coming of The Lord - "I Am Coming Quickly"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_Am_Coming_Quickly"}],num:21,prevLetter:{id:"to-whom-does-the-kingdom-of-heaven-belong",title:"To Whom Does The Kingdom of Heaven Belong"},nextLetter:{id:"be-baptized-in-the-living-waters-of-spirit-and-truth",title:"Be Baptized in The Living Waters of Spirit and Truth"}},{id:"be-baptized-in-the-living-waters-of-spirit-and-truth",title:"Be Baptized in The Living Waters of Spirit and Truth",date:"1/13/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, concerning baptism:"},{t:"text",v:"Let My beloved first be baptized in spirit and in truth, filled with the knowledge of The Holy, nourished by the Word of Truth. Let them come to Me in sincere repentance, and receive forgiveness of sins in The Messiah\u2019s name..."},{t:"italic",v:"All burdens lifted, immersed and purified in the Spirit of God."},{t:"text",v:"For The Holy One of Israel is He who baptizes with the Holy Spirit and with fire, and He knows His own."}]},{type:"para",segments:[{t:"text",v:"Therefore, hear and understand: The Water of Life is not of the earth. Rather The Water of Life is that which flows from the body of Messiah. For in Him alone shall one know salvation and receive everlasting life. Therefore be baptized in the knowledge and wisdom of The Beloved. Listen to Him and walk in His ways, and you shall surely be accepted. Tell Me, is the water of the earth able to take away your sins, or cleanse you of your transgressions? Can a river lead you to salvation or a stream call you to repentance? In what waters have you heard The Word of God speak? Thus baptism by water can not save you."}]},{type:"poetry",lines:[[{t:"italic",v:"Rather salvation comes by the hearing of the Gospel,"}],[{t:"italic",v:"And through the confession of the mouth that YahuShua,"}],[{t:"italic",v:"Called Jesus, is Lord, believing HE IS WHO HE IS..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Risen One..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Only Way, The Only Truth, The Only Life..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For only by true repentance, in accord with the heart\u2019s desire"}],[{t:"italic",v:"To be in union with The Messiah, shall one be set free."}]]},{type:"para",segments:[{t:"text",v:"So then go forth, and be baptized in the waters of the earth, if you so desire. Yet remember this: Baptism in and of itself is nothing, unless the heart of the one being immersed has truly been converted. Thus baptism is for a testimony, an exercise in faith for the one who is saved already; or a mere dampening of the clothes of the one who came forth in pretense. For I am The Lord, I search the hearts and minds, and I know whether or not one has truly been converted in their heart."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/be-baptized-in-the-living-waters-of-spirit-and-truth-2",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/be-baptized-in-the-living?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=jYGTqaE38IM&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=24",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Baptism",url:"https://answersonlygodcangive.com/Regarding_Baptism"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"}],num:22,prevLetter:{id:"to-he-who-has-understanding-let-him-hear-the-truth-of-the-inheritance-of-sin-and-salvation",title:"To He Who Has Understanding, Let Him Hear the Truth of the Inheritance of Sin and Salvation"},nextLetter:{id:"god-eternal",title:"God Eternal"}},{id:"god-eternal",title:"God Eternal",date:"1/20/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Behold, the judgments of God shall fall from Heaven; the sun, the moon and the stars shall not give their light; the foundations of the earth shall be shaken, and every high place shall be broken down. For The Lord comes as a thief"},{t:"fn",v:"1"},{t:"text",v:"to steal away His elect, and the judgments of God as a multitude of thunder, to shake the heavens and the earth!"}]},{type:"para",segments:[{t:"text",v:"Yet the multitudes say,"},{t:"italic",v:"\u201CWhat is the said interpretation of The Lord\u2019s judgment? These things are much too terrifying to be true!\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold all creation! Is it not beyond the comprehension of men? Can any man number the galaxies in the heavens or count the stars thereof? And what of the love of The Father, fulfilled through The Son? Is it not also beyond comprehension? Come together and reason, O sons of men. Look upon the works of My hands, and see with new eyes and restored vision, that you may behold the Truth. For all the works of man are here for but a moment, then quickly pass away. And that which remains, shall it not become fuel for the fire in the Day of The Lord\u2019s Anger? And the knowledge of man, is it not foolishness in My eyes, coming to nothing before the light of My Glory? Therefore fear The Lord your God, and accept the truth of who I am. For the fear of The Lord is the beginning of wisdom, and the knowledge of The Holy One is understanding. For I am God alone."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, O sons of men, hear the Word of My mouth and listen closely to My speech:"},{t:"text",v:"If the mighty works of God are broken down into mere parables, and the Word of My power is counted only as figures of speech, or metaphors in need of interpretation, then you are lost, forever consumed by talk and confusion. Yet I say to you, let that which is a parable remain a parable; and let that which is a figure of speech be understood by those who have received the love of the Truth; and let that which is an account strike fear into the hearts of all men. For I do not change. Behold, My Word is truth! And that which requires understanding shall be given to those of a contrite heart and a humble spirit. For those who love Me obey My Commandments, and those who remember My Sabbaths honor Me and shall know Wisdom. Therefore, consider these things carefully. For I have indeed prepared a place for those who seek Me, for those who long to know Me as I truly am, a place for all those accepted in The Beloved, in whom My spirit dwells, The Kingdom without end."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, O peoples of the earth, for the Day of The Lord is at hand:"},{t:"text",v:"Behold, I shall stir up the multitudes, and show wonders in the heavens above and in the earth beneath! There shall be blood and fire and pillars of smoke, and the foundations of the world shall be shaken! For I shall reveal My Glory; behold, every eye shall see! Then all the inhabitants of the earth will know, I AM THE LORD! For as it was in the days of My servant, Moses, when I stretched out My hand against Egypt, with many mighty signs and wonders, so shall it be in the Great and Terrible Day of The Lord! Yet understand this, O most arrogant generation, My judgment on Egypt was but a mere drop of rain, a single crack of thunder, compared with that which I have prepared for this sleeping generation!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore awake, all you sleepers,"}],[{t:"italic",v:"For the time of your slumber has ended;"}],[{t:"italic",v:"Awake, and prepare to meet your God!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Repent, and turn aside from"}],[{t:"italic",v:"All this wickedness you have chosen!"}],[{t:"italic",v:"Turn your back on all these abominations"}],[{t:"italic",v:"You uphold, and embrace The Salvation of God!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I AM, and you are in life because of Me;"}],[{t:"italic",v:"In Me alone is everlasting life;"}],[{t:"italic",v:"Beloved, I AM HE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"There is no other, a just God and a Savior;"}],[{t:"italic",v:"There is none besides Me..."}],[{t:"stanza-break"}],[{t:"italic",v:"God Eternal."}]]}],footnotes:{1:{type:"note",text:'Also read: "...The Coming of The Son of Man"',url:"https://www.thevolumesoftruth.com/As_God_Is_Three_Aspects,_All_as_One,_So_Too_Is_the_Coming_of_The_Son_of_Man#As_God_Is_Three_Aspects.2C_All_as_One.2C_So_Too_Is_the_Coming_of_The_Son_of_Man",link:{collection:"Volume Two",letterTitle:"As God Is Three Aspects, All as One, So Too Is the Coming of The Son of Man"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/god-eternal-4",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/god-eternal?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=aoCJZvPFo_g&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=25",videoMusicUrl:"https://www.youtube.com/watch?v=VIJdHAt16Ak&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=4",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:'The Coming of The Lord - "As a Thief"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#As_a_Thief"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:23,prevLetter:{id:"be-baptized-in-the-living-waters-of-spirit-and-truth",title:"Be Baptized in The Living Waters of Spirit and Truth"},nextLetter:{id:"clothed-with-the-presence-of-god",title:"Clothed with The Presence of God"}},{id:"clothed-with-the-presence-of-god",title:"Clothed with The Presence of God",date:"1/29/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, lift up your head toward Heaven and embrace the prophet\u2019s reward. For you have been chosen to stand up in the face of adversity and speak; to persevere through much persecution, to endure contemptible speech on every side, as you strike down all these abominations in My name. Fear not, for The Lord is your Shepherd; He will be your confidence and keep you safe from harm. Behold, in the day I send you, My presence shall overshadow you, with the glory of The Holy One of Israel shining through you in His strength. Yes, this work is indeed difficult, service wrought with much heartache and pain, evil on every side. For many shall come forth from their hiding places to bar your way, in an attempt to halt your steps and squelch your spirit, even to take away your life. Yet fear not, Timothy. For The Shepherd has complete authority, even over all these ravaging wolves..."},{t:"italic",v:"Behold, He shall scatter them before you in that day! And when it is finished, He shall strike them, and their hearts shall fail them for fear! From the resentful hearer to the outspoken mocker, both those near and those afar off, even to those unseen, ALL shall be made to shudder, ALL shall tremble in fear! For The King shall appear suddenly out of His place, coming forth in power and great glory, and He shall lay all His enemies waste, until every ravaging wolf lies down in death and every brute beast is utterly destroyed! Behold, He shall strike them down in the power of His might, and divide them asunder with the sword of His mouth, and burn up the residue with unquenchable fire!"}]},{type:"para",segments:[{t:"text",v:"My son, even now there are many wolves lurking about, both seen and unseen, who wear the raiment of the sheep they seek to devour. For they are most insidious, ravaging whole flocks from within. Yet you and many more like you shall go out and gather together My lost sheep, and bring them to safety, and they too shall be hidden, even for a time and times and half a time. For those who have ears to hear will heed the sound of this Trumpet in that day, and come forth to drink. Lo, they shall be immersed in springs of living waters, no more blinded by the filthy veil which once covered their heads. And until that day, you also must drink. You must drink deeply and be fully immersed, reborn and remade, abiding in the Holy Place, going out and coming in, until you are fully clothed with the presence of God."}]},{type:"poetry",lines:[[{t:"italic",v:"And behold, your adornments shall be truth and wisdom..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Atop your head, you shall wear the helmet of salvation;"}],[{t:"italic",v:"Upon your brow, the seal of The Living God;"}],[{t:"italic",v:"And around your neck, you shall wear the gemstone..."}]]},{type:"poetry",lines:[[{t:"italic",v:"In your ears, the voice of YAHUWAH shall resonate;"}],[{t:"italic",v:"And in your eyes, a flame of fire, the reflection of"}],[{t:"italic",v:"The Most Holy who goes before you and dwells within you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Over your shoulder, you shall bear the sash of your office;"}],[{t:"italic",v:"And upon your chest, the breastplate of strength,"}],[{t:"italic",v:"Whereon is written the name of The Holy One of Israel;"}],[{t:"italic",v:"And about your waist, the belt of fortitude shall be securely fastened..."}]]},{type:"poetry",lines:[[{t:"italic",v:"In your right hand you shall carry the sword of truth,"}],[{t:"italic",v:"Which is the Word of God, with which you shall"}],[{t:"italic",v:"Strike the nations and cut down your enemies..."}]]},{type:"poetry",lines:[[{t:"italic",v:"In your left hand, the shield of faith, by which"}],[{t:"italic",v:"You shall quell every attack of the evil one..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, My son, look down;"}],[{t:"italic",v:"Your feet rest solidly upon The Rock"}],[{t:"italic",v:"And have been anointed with oil..."}]]},{type:"closing",text:"Says The Lord God."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/clothed-with-the-presence-of-god",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/clothed-with-the-presence-of?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=2wdcU7jIvGo&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=26",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:'The Coming of The Lord - "In Power and Great Glory"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#In_Power_and_Great_Glory"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"}],num:24,prevLetter:{id:"god-eternal",title:"God Eternal"},nextLetter:{id:"remember-the-sabbath-and-your-god-and-he-shall-remember-you",title:"Remember The Sabbath and Your God, and He Shall Remember You"}},{id:"remember-the-sabbath-and-your-god-and-he-shall-remember-you",title:"Remember The Sabbath and Your God, and He Shall Remember You",date:"2/24/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, concerning the Sabbath,"},{t:"italic",v:"the seventh day of each week, Saturday is the day you shall remember and keep holy. Yes, you shall keep it holy and rest. You shall do no work on this day, neither shall your wife or children, nor any guest in your house,"},{t:"fn",v:"1"},{t:"text",v:"save that which is needful for your household. You may also do those things which are good and fruitful in My eyes, according to that which I command you."},{t:"italic",v:"Yet from doing your own pleasure depart and from your own works rest, on the Sabbath day; walk not in your own way, Timothy, but walk with Me in Mine. Rest in Me, and remember. For in this you honor Me and shall surely be blessed."},{t:"fn",v:"2"},{t:"text",v:"Therefore, this is what I command you: You shall be prepared for the Sabbath by sunset on the sixth day, ceasing from all your works as I have commanded you."},{t:"italic",v:"You shall remember and honor the Sabbath;"},{t:"fn",v:"3"},{t:"text",v:"from sunset to sunset, you shall rest and be at peace."},{t:"italic",v:"For the time is coming when none shall have peace, when no one will be able to work."},{t:"fn",v:"4"},{t:"text",v:"Yet you, Timothy, shall work. In the midst of deep darkness you shall serve, and in you shall I shine bright, for I have set you up as a lampstand for My people. And in the day I send you, you shall become a beacon. Therefore, Timothy, cherish the Sabbath. Pray and give worship, offer up thanksgiving in My name. Be refreshed and washed in The Word, renewed in the presence of God. And when others draw near, speak to them also; yea, testify of My Passion on the Sabbath day. Share My Word and My love and blow this Trumpet, for My Kingdom comes. Yes even on the Sabbath, and in the Day of The Lord, shall you walk in the office for which you are called."},{t:"italic",v:"For I am also The Lord of the Sabbath;"},{t:"fn",v:"5"},{t:"italic",v:"behold, I am Lord over all the earth!"},{t:"fn",v:"6"},{t:"text",v:"Then shall the New Day come, and if you are able to receive it, it is the seventh, The Sabbath of The Lord, wherein the whole world shall rest from its evil ways."}]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, many things shall be put to rest"}],[{t:"italic",v:"In The Lord\u2019s Day, even death and the grave;"}],[{t:"italic",v:"Destruction shall have no place,"}],[{t:"italic",v:"And evil shall be far removed..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written:"}],[{t:"italic",v:"They shall not hurt nor destroy in all"}],[{t:"italic",v:"My Holy Mountain, for the earth shall be"}],[{t:"italic",v:"Full of the knowledge of The Lord"}],[{t:"italic",v:"As the waters cover the sea"},{t:"fn",v:"7"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, beloved ones, pray always"}],[{t:"italic",v:"That you are counted worthy"},{t:"fn",v:"8"},{t:"italic",v:"to"}],[{t:"italic",v:"Enter My rest,"},{t:"fn",v:"9"},{t:"italic",v:"that you may abide"}],[{t:"italic",v:"In the presence of The Lord, forever."}]]},{type:"para",segments:[{t:"text",v:"Thus those who remember the Sabbath honor Me, and those who rest on the Sabbath rest in Me, as they look to the Day."},{t:"italic",v:"For I had set the seventh day apart, and sanctified it, from the beginning."},{t:"fn",v:"10"},{t:"text",v:"Thus it has been a sign between Me and My people, even to this day, and so shall it remain forever. For as I spoke to the children of Israel, saying,"},{t:"italic",v:"\u201CSurely My Sabbaths you shall keep, for it is a sign between Me and you throughout your generations, that you may know that I am The Lord who sanctifies you,\u201D"},{t:"fn",v:"11"},{t:"text",v:"so also do I speak to you, even to all who are grafted in."},{t:"italic",v:"For those who obey My Commandments remain in My love,"},{t:"fn",v:"12"},{t:"text",v:"and those who remember My Sabbaths keep My company, for The Holy One of Israel dwells in the midst of them. For I long for My children to be with Me where I am,"},{t:"italic",v:"I am eager to return them to the Garden, that we may once again walk together in the cool of the day."},{t:"fn",v:"13"},{t:"text",v:"Therefore remember the Sabbath, and I shall remember you. Bless the Sabbath, and I shall bless you. Love one another, as I have loved you. Put away your works, look not to the cares of this world, and let go of your worries on the Sabbath day; spare yourselves the weight of all these troubles for just one day. Let all your thoughts dwell upon your God and Savior, and consider; yea, let your mind be filled with wonder and awe over the works of My hands."},{t:"italic",v:"For even The Lord your God, Creator of Heaven and Earth, rested on the seventh day."},{t:"fn",v:"14"},{t:"text",v:"So then bear your cross six days, and let The Lord carry it on the seventh. Rejoice and be merry, for this is My will for you. Then when evening comes, and the sun dips below the horizon, you may once again return to that which you choose to take up, whether it be the plow or the shears. But see that you do not take up your hand in sin, and be wary of those who do. Be separate, and stand apart from those who forsake the Sabbath and push out the hand against My Holy Days"},{t:"fn",v:"15"},{t:"text",v:". For My Sabbaths are holy, a blessing, a time to reflect on those things I have prepared for those who love Me."}]},{type:"para",segments:[{t:"text",v:"Why, O churches of men, do you forsake My Sabbaths and cast away My Holy Days, as though the devil had laid them upon your doorstep?!"},{t:"italic",v:"For My people are those who keep My Commandments"},{t:"fn",v:"16"},{t:"italic",v:"and take pleasure in My Sabbaths. They abide in My love"},{t:"fn",v:"17"},{t:"italic",v:"and have the Testimony, and do not cease from doing those things which are pleasing in My sight."},{t:"fn",v:"18"}]},{type:"poetry",lines:[[{t:"italic",v:"And behold, the Day is coming quickly"}],[{t:"italic",v:"When The Rightful King shall rule..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And His Kingdom shall be a Sabbath,"}],[{t:"italic",v:"Even one thousand years;"}],[{t:"italic",v:"His reign, forever and ever!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The Lord has spoken, and so shall it be:"}]]},{type:"poetry",lines:[[{t:"italic",v:"On earth as in Heaven."},{t:"fn",v:"19"}]]}],footnotes:{1:{type:"scripture",ref:"Exodus 20:8-10"},2:{type:"scripture",ref:"Isaiah 58:13-14"},3:{type:"scripture",ref:"Exodus 20:8"},4:{type:"scripture",ref:"John 9:4"},5:{type:"scripture",ref:"Mark 2:28"},6:{type:"scripture",ref:"Matthew 11:25"},7:{type:"scripture",ref:"Isaiah 11:9"},8:{type:"scripture",ref:"Luke 21:36"},9:{type:"scripture",ref:"Hebrews 4:1"},10:{type:"scripture",ref:"Genesis 2:3"},11:{type:"scripture",ref:"Exodus 31:13"},12:{type:"scripture",ref:"John 15:10"},13:{type:"scripture",ref:"Genesis 3:8"},14:{type:"scripture",ref:"Genesis 2:3"},15:{type:"note",text:"See: Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},16:{type:"scripture",ref:"1 John 2:3-4, 1 John 3:22-24, 1 John 5:2-3, 2 John 1:6, Revelation 12:17, Revelation 14:12, Revelation 22:14"},17:{type:"scripture",ref:"John 15:10"},18:{type:"scripture",ref:"1 John 3:22"},19:{type:"scripture",ref:"Matthew 6:10"}},nkjv:{"Exodus 20:8-10":"8. \u201CRemember the Sabbath day, to keep it holy. 9. Six days you shall labor and do all your work, 10. but the seventh day is the Sabbath of the LORD your God. In it you shall do no work: you, nor your son, nor your daughter, nor your male servant, nor your female servant, nor your cattle, nor your stranger who is within your gates.","Isaiah 58:13-14":"13. \u201CIf you turn away your foot from the Sabbath, From doing your pleasure on My holy day, And call the Sabbath a delight, The holy day of the LORD honorable, And shall honor Him, not doing your own ways, Nor finding your own pleasure, Nor speaking your own words, 14. Then you shall delight yourself in the LORD; And I will cause you to ride on the high hills of the earth, And feed you with the heritage of Jacob your father. The mouth of the LORD has spoken.\u201D","Exodus 20:8":"\u201CRemember the Sabbath day, to keep it holy.","John 9:4":"I must work the works of Him who sent Me while it is day; the night is coming when no one can work.","Mark 2:28":"Therefore the Son of Man is also Lord of the Sabbath.\u201D","Matthew 11:25":"At that time Jesus answered and said, \u201CI thank You, Father, Lord of heaven and earth, that You have hidden these things from the wise and prudent and have revealed them to babes.","Isaiah 11:9":"They shall not hurt nor destroy in all My holy mountain, For the earth shall be full of the knowledge of the LORD As the waters cover the sea.","Luke 21:36":"Watch therefore, and pray always that you may be counted worthy to escape all these things that will come to pass, and to stand before the Son of Man.\u201D","Hebrews 4:1":"Therefore, since a promise remains of entering His rest, let us fear lest any of you seem to have come short of it.","Genesis 2:3":"Then God blessed the seventh day and sanctified it, because in it He rested from all His work which God had created and made.","Exodus 31:13":"\u201CSpeak also to the children of Israel, saying: \u2018Surely My Sabbaths you shall keep, for it is a sign between Me and you throughout your generations, that you may know that I am the LORD who sanctifies you.","John 15:10":"If you keep My commandments, you will abide in My love, just as I have kept My Father\u2019s commandments and abide in His love.","Genesis 3:8":"And they heard the sound of the LORD God walking in the garden in the cool of the day, and Adam and his wife hid themselves from the presence of the LORD God among the trees of the garden.","1 John 2:3-4, 1 John 3:22-24, 1 John 5:2-3, 2 John 1:6, Revelation 12:17, Revelation 14:12, Revelation 22:14":"1 John 2:3-4 \u2014 3. Now by this we know that we know Him, if we keep His commandments. 4. He who says, \u201CI know Him,\u201D and does not keep His commandments, is a liar, and the truth is not in him. | 1 John 3:22-24 \u2014 22. And whatever we ask we receive from Him, because we keep His commandments and do those things that are pleasing in His sight. 23. And this is His commandment: that we should believe on the name of His Son Jesus Christ and love one another, as He gave us commandment. 24. Now he who keeps His commandments abides in Him, and He in him. And by this we know that He abides in us, by the Spirit whom He has given us. | 1 John 5:2-3 \u2014 2. By this we know that we love the children of God, when we love God and keep His commandments. 3. For this is the love of God, that we keep His commandments. And His commandments are not burdensome. | 2 John 1:6 \u2014 This is love, that we walk according to His commandments. This is the commandment, that as you have heard from the beginning, you should walk in it. | Revelation 12:17 \u2014 And the dragon was enraged with the woman, and he went to make war with the rest of her offspring, who keep the commandments of God and have the testimony of Jesus Christ. | Revelation 14:12 \u2014 Here is the patience of the saints; here are those who keep the commandments of God and the faith of Jesus. | Revelation 22:14 \u2014 Blessed are those who do His commandments, that they may have the right to the tree of life, and may enter through the gates into the city.","1 John 3:22":"And whatever we ask we receive from Him, because we keep His commandments and do those things that are pleasing in His sight.","Matthew 6:10":"Your kingdom come. Your will be done On earth as it is in heaven."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/remember-the-sabbath-and-your-god-and-he-shall-remember-you",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/remember-the-sabbath-and-he?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=2xYRmTGpwSo&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=27",videoMusicUrl:"https://www.youtube.com/watch?v=u1LqfVQ8WoU&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=31",relatedTopics:[{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:25,prevLetter:{id:"clothed-with-the-presence-of-god",title:"Clothed with The Presence of God"},nextLetter:{id:"watch",title:"Watch"}},{id:"watch",title:"Watch",date:"3/6/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Peoples of the earth, hear the Word of The Lord your God:"},{t:"text",v:"You are lost, drowning in a deep sea of transgression, sinking in the ever-shifting sands of religion and science. You are stuck in the mire of your iniquities, slowly suffocating, as the fruit of your labor comes full circle to take away your life. For by your own works have you destroyed the garden, on account of your greed have you caused much suffering and death, bringing calamity upon your own heads! Thus because of your great iniquity I have drawn back My hand, and for the multitude of your transgressions the judgment of God has come upon you. Dead generation, foolish children, evil surrounds you on every side! Darkness closes in, yet you remain unmoved! Detestable birds gather and predators come forth to stalk you as prey, yet you see no cause for alarm! Therefore as I live, says The Lord, My flock has become the prey and My children have made themselves meet for the slaughter! For the peoples of the earth have forsaken Me, days without end; they have altogether gone astray! My created ones have removed themselves far from Me, and My own beloved have not returned to Me, but do always seek their own way! And of the shepherds, they did not go out to search for My flock, but have fed themselves! They did not feed My flock, BUT HAVE FED THEMSELVES!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, all you self-appointed shepherds, and give ear, all you wayward flocks, for you have surely broken the yoke and burst the bonds, you have surely forsaken The Lord your God; for thus says The Lord:"},{t:"text",v:"I am against you! Your houses are fallen, and the foundations upon which you have built yourselves up crumble beneath your feet! All is dust and ashes, rubble piled up in heaps! Oh what a bitter thing this is, unending sadness, anguish and pain; My own beloved have departed from Me, My own children have gone far astray! I gave My Son for them, that they may live and not die, I laid Myself upon the altar, yet they want no part with Me as I truly am! Thus they choose death, and with the grave they have made their agreement."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"Tremble, O heavens! Shake, O earth! Let the seas rage and the mountains crumble before the coming of The Lord! Let the whole earth be bowed down before The Holy One of Israel, for My Kingdom comes!..."},{t:"italic",v:"Behold, The Almighty is coming down to you, yes, The Son who wears the full raiment of The Father. For in Him alone does the fullness of God dwell. Thus HE shall pluck you from the fire, HE shall scourge the nations with the Word of His power, and strike the wicked with the sword of His mouth. Yes, HE shall tread the grapes in the winepress of the wrath of My fury, wiping the wicked from existence, destroying all things which sicken His sheep and cause His flocks to go astray; behold, He shall utterly destroy all that offends!"}]},{type:"poetry",lines:[[{t:"italic",v:"My people, The Mashiach is your help and your shield;"}],[{t:"italic",v:"YahuShua, whom you call Jesus and Christ,"}],[{t:"italic",v:"Is The Rock of your Salvation,"}],[{t:"italic",v:"The One who is and was and is to come;"}],[{t:"italic",v:"For The Father and The Son are One..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, embrace Me in My Mercy,"}],[{t:"italic",v:"And receive of Me in My Great Love."}]]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, your Redeemer:"},{t:"text",v:"I am indeed coming down to shake the heavens and the earth, to move all from its place; to bring forth that which was hidden and to reveal that which was misplaced;"},{t:"fn",v:"1"},{t:"text",v:"to open that which was shut and to shut that which was opened. Therefore prepare, My people, for the time has come; yes, today is the day of salvation! Go forth, beloved ones, and set all these crooked paths straight; regain the line, prepare and watch."},{t:"italic",v:"For the leaves of the fig tree are upon its branches; summer is near!"},{t:"fn",v:"2"},{t:"text",v:"Again I say, watch. For The One who ascended is about to descend..."},{t:"italic",v:"And lo, I am come, in the Volume of the Book it is written of Me, to accomplish The Father\u2019s will."},{t:"fn",v:"3"},{t:"text",v:"For I have heard the cries of the oppressed and the groaning of the poor and the needy, I know the plight of the fatherless and the widow. I have tasted their tears, and the heart of the faithful is not hidden from Me."},{t:"italic",v:"Therefore watch"},{t:"fn",v:"4"},{t:"text",v:"and also listen, and be spared, for"},{t:"italic",v:"I am about to give a shout."},{t:"fn",v:"5"},{t:"text",v:"For all that is written in the Book of The Lord, both the former and the latter, comes to pass through Me. Take heed therefore, for assuredly I say to you, it shall in no wise come to pass as a mere metaphor or as a parable conceived of by men. For the time of arrogant assumptions and prideful assertions is over, the time of corrupt knowledge and polluted sermons is at an end."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, The Power from on high is coming"}],[{t:"italic",v:"Forth to reap and to judge the nations,"}],[{t:"italic",v:"To sound the trumpet in the four corners,"}],[{t:"italic",v:"To cause the name of The Lord"}],[{t:"italic",v:"To resound in all the earth..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Bow before The King, therefore;"}],[{t:"italic",v:"Humble yourselves before The Holy One of Israel..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Lay yourselves upon the altar and be broken"}],[{t:"italic",v:"Atop The Stone, and it shall bear you up;"}],[{t:"italic",v:"Yet stand defiant, and you shall be crushed"}],[{t:"italic",v:"Beneath the weight of The Mountain"},{t:"fn",v:"6"},{t:"italic",v:"..."}]]},{type:"closing",text:"For I do not change, says The Lord."}],footnotes:{1:{type:"note",text:'See: "Follow Me"',url:"https://www.thevolumesoftruth.com/Follow_Me#:~:text=They%20lie%20next%20to%20your%20faith%2C%20which%20has%20also%20been%20misplaced.",link:{collection:"Volume Three",letterTitle:"Follow Me",excerpt:"They lie next to your faith, which has also been misplaced."}},2:{type:"scripture",ref:"Matthew 24:32-34"},3:{type:"scripture",ref:"Psalm 40:7-8, Hebrews 10:7 (KJV)"},4:{type:"scripture",ref:"Matthew 24:42, Luke 21:36, Acts 20:31, 1 Thessalonians 5:6"},5:{type:"scripture",ref:"1 Thessalonians 4:16"},6:{type:"scripture",ref:"Matthew 21:44"}},nkjv:{"Matthew 24:32-34":"32. \u201CNow learn this parable from the fig tree: When its branch has already become tender and puts forth leaves, you know that summer is near. 33. So you also, when you see all these things, know that it is near\u2014at the doors! 34. Assuredly, I say to you, this generation will by no means pass away till all these things take place.","Matthew 24:42, Luke 21:36, Acts 20:31, 1 Thessalonians 5:6":"Matthew 24:42 \u2014 Watch therefore, for you do not know what hour your Lord is coming. | Luke 21:36 \u2014 Watch therefore, and pray always that you may be counted worthy to escape all these things that will come to pass, and to stand before the Son of Man.\u201D | Acts 20:31 \u2014 Therefore watch, and remember that for three years I did not cease to warn everyone night and day with tears. | 1 Thessalonians 5:6 \u2014 Therefore let us not sleep, as others do, but let us watch and be sober.","1 Thessalonians 4:16":"For the Lord Himself will descend from heaven with a shout, with the voice of an archangel, and with the trumpet of God. And the dead in Christ will rise first.","Matthew 21:44":"And whoever falls on this stone will be broken; but on whomever it falls, it will grind him to powder.\u201D","Psalm 40:7-8, Hebrews 10:7 (KJV)":"Psalm 40:7-8 \u2014 7. Then I said, \u201CBehold, I come; In the scroll of the book it is written of me. 8. I delight to do Your will, O my God, And Your law is within my heart.\u201D | Hebrews 10:7 (KJV) \u2014 Then said I, Lo, I come (in the volume of the book it is written of me,) to do thy will, O God."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/watch",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/watch?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=f9PgRToHYKI&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=28",videoMusicUrl:"https://www.youtube.com/watch?v=XumpvJfNlI8&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=35",relatedTopics:[{label:"Regarding Pollution and Mankind's Exploitation of the Earth",url:"https://answersonlygodcangive.com/Regarding_Pollution_and_Mankind%27s_Exploitation_of_the_Earth"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"}],num:26,prevLetter:{id:"remember-the-sabbath-and-your-god-and-he-shall-remember-you",title:"Remember The Sabbath and Your God, and He Shall Remember You"},nextLetter:{id:"purify-your-faith",title:"Purify Your Faith"}},{id:"purify-your-faith",title:"Purify Your Faith",date:"3/19/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, how do You feel about \u201Cprayer rugs\u201D with images of Jesus on them?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"This is where blasphemy abides and sin abounds, idolatry covered with purple and scarlet. Therefore, write My words to all who call of themselves Christian, to all those who emulate the harlot, who have not ceased from practicing those things I hate."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"HYPOCRITES! Where are your hearts?! Why do you do these vain and contemptible things?! I tell you the truth, you have surely forgotten Me, nor do you know Me at all! Cease from bringing graven images before Me; your offerings are not accepted!"},{t:"italic",v:"Cease from opening your mouths in vain repetition;"},{t:"fn",v:"1"},{t:"text",v:"your prayers are not heard! Stop teaching detestable doctrine and contemptible tradition! For you have surely blasphemed My name, you have surely caused My people to sin! Day and night you set stones of stumbling at their feet! Year after year, you hew out great blocks of abomination upon which you build your churches, the weight of which you shall bear in the Day of The Lord\u2019s Anger! Churches of men, be ignorant of My ways no longer. Cast from yourselves all these graven images, and no more bring your prayers before Me in this way. Nor pray to those who have fallen asleep;"},{t:"italic",v:"for they are dead, they know nothing at all"},{t:"fn",v:"2"},{t:"text",v:"- YahuShua is The Only Way, The Only Truth, and The Only Life! Again, I say to you, pray no more to those who lie dead in the grave; there is no life in them. For I tell you the truth, you have surely separated yourselves from Me; according to every Commandment you break, according to every jot and tittle you have endeavored to change, are you far removed. For you have become a wholly vain and ignorant people, a people who want no part with Me as I truly am, a wayward flock who ceases not from taking the name of The Lord in vain."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, purify your faith!"}],[{t:"italic",v:"Be cleansed of all this iniquity,"}],[{t:"italic",v:"Turn away from all this impropriety!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Keep The Commandments of God as they are written,"}],[{t:"italic",v:"And not as you would have them be; remain in My love!"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The One alone, whom you shall call Father, is in Heaven;"}],[{t:"italic",v:"And there is but One Mediator between God and man,"}],[{t:"italic",v:"And His name is YahuShua HaMashiach!"}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 6:7"},2:{type:"scripture",ref:"Ecclesiastes 9:5"},3:{type:"scripture",ref:"John 15:10"}},nkjv:{"Matthew 6:7":"And when you pray, do not use vain repetitions as the heathen do. For they think that they will be heard for their many words.","Ecclesiastes 9:5":"For the living know that they will die; But the dead know nothing, And they have no more reward, For the memory of them is forgotten.","John 15:10":"If you keep My commandments, you will abide in My love, just as I have kept My Father\u2019s commandments and abide in His love."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/purify-your-faith",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/purify-your-faith?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=cJOl96P31VU&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prayer",url:"https://answersonlygodcangive.com/Regarding_Prayer"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:'The Name of The Lord - "YahuShua"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YahuShua"}],num:27,prevLetter:{id:"watch",title:"Watch"},nextLetter:{id:"judge-not-others-for-that-by-which-you-judge-is-how-you-shall-be-judged",title:"Judge Not Others, For That By Which You Judge Is How You Shall Be Judged"}},{id:"judge-not-others-for-that-by-which-you-judge-is-how-you-shall-be-judged",title:"Judge Not Others, For That By Which You Judge Is How You Shall Be Judged",date:"3/26/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"O you hypocrites, listen to the voice of The Lord your Redeemer, and repent, says The Lord. For your iniquity is shown upon your vesture, as a garment which has been ripped in two. Shall you judge others by that which you are also guilty?"},{t:"italic",v:"There is one Judge, to whom God has committed all authority, and One only - The Son of Man."},{t:"fn",v:"1"},{t:"text",v:"It is written:"},{t:"italic",v:"Whoever is angry with his brother without a cause shall be in danger of the Judgment."},{t:"fn",v:"2"},{t:"text",v:"For those who hold onto anger retain malice, and are filled with hate; they shall in no wise escape the Day of The Lord. For it is written also, and remains standing:"},{t:"italic",v:"If someone says, \u201CI love God,\u201D yet hates his brother, he is a liar"},{t:"fn",v:"3"},{t:"text",v:"and shall be found as such on the Day of Reckoning. Therefore he who seeks to cast a stone at another, let him first cast it at himself."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Sin is sin. All sin is sin. All have sinned and fall short of the Glory of God. Shall then sin judge sin? No."},{t:"italic",v:"Only The One who is without sin shall be your judge; and behold, He is also The Son of Man."},{t:"fn",v:"4"},{t:"text",v:"Yet you continue to pass judgment on others by the likes of what you know to be true of yourselves, accounting to them those same sins for which you are also guilty. Thus you do greatly err."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore repent, and seek now The Way of The Lord;"}],[{t:"italic",v:"For God is love, and His Mercy endures forever..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore come to Me,"}],[{t:"italic",v:"Come to Me in spirit and in truth,"}],[{t:"italic",v:"And strive to love others as I have loved you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For where there is an absence of love,"}],[{t:"italic",v:"You will find only pain and suffering,"}],[{t:"italic",v:"Hate, and ever-increasing sin;"}],[{t:"italic",v:"And when it is finished, death..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 28:18"},2:{type:"scripture",ref:"Matthew 5:22"},3:{type:"scripture",ref:"1 John 4:20"},4:{type:"scripture",ref:"John 5:27"}},nkjv:{"Matthew 28:18":"And Jesus came and spoke to them, saying, \u201CAll authority has been given to Me in heaven and on earth.","Matthew 5:22":"But I say to you that whoever is angry with his brother without a cause shall be in danger of the judgment. And whoever says to his brother, \u2018Raca!\u2019 shall be in danger of the council. But whoever says, \u2018You fool!\u2019 shall be in danger of hell fire.","1 John 4:20":"If someone says, \u201CI love God,\u201D and hates his brother, he is a liar; for he who does not love his brother whom he has seen, how can he love God whom he has not seen?","John 5:27":"and has given Him authority to execute judgment also, because He is the Son of Man."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/judge-not-others-for-that-by-which-you-judge-is-how-you-shall-be-judged",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/judge-not-others-for-that-by?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=dss14uHB-wQ&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=30",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"},{label:"Regarding Hate",url:"https://answersonlygodcangive.com/God_Speaks_About_Committing_Murder_Within_the_Heart#Hate"},{label:"Regarding Unforgiveness",url:"https://answersonlygodcangive.com/Regarding_Unforgiveness"}],num:28,prevLetter:{id:"purify-your-faith",title:"Purify Your Faith"},nextLetter:{id:"embrace-the-cornerstone-wherein-flows-springs-of-living-water",title:"Embrace The Cornerstone, Wherein Flows Springs of Living Water"}},{id:"embrace-the-cornerstone-wherein-flows-springs-of-living-water",title:"Embrace The Cornerstone, Wherein Flows Springs of Living Water",date:"3/28/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to this generation, the last of these kingdoms of men:"},{t:"text",v:"Why do you kick your foot against The Stone, and shake your fists at Heaven when faced with The Truth? You are like a lost traveler without a home, and like the beast of the field you have no shelter. Thus your wisdom is wind, and your every ambition a fool\u2019s aspiration. Yet in My love, I laid for you an everlasting foundation upon which you were to stand. And in My mercy I constructed high walls, made with the finest stone, to protect you, even from yourselves, engraven stones touched by the finger of God."},{t:"fn",v:"1"},{t:"text",v:"Yet you seek to remove the immovable and hide that which can not be hidden, denying that which is self-evident, as you endeavor to scrape off the writing thereof. Shall you deface The Commandments of God to justify your sins, desecrating The Moral Law to allay your guilt?! The Commandments are a lamp and The Law a light, reproof and instruction, a way of life."},{t:"fn",v:"2"},{t:"text",v:"And shall you now also attempt to hew out The Cornerstone"},{t:"fn",v:"3"},{t:"text",v:"and cast it into the depths of the sea?!"}]},{type:"poetry",lines:[[{t:"italic",v:"O most foolish and deceived generation,"}],[{t:"italic",v:"Can anyone cut out their own heart and live?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And who is able to walk alone in darkness,"}],[{t:"italic",v:"Without a light to guide them?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Who shall uphold them when they stumble"}],[{t:"italic",v:"Or catch them when they fall?"}],[{t:"italic",v:"Who will bind up their wounds?"},{t:"fn",v:"4"},{t:"italic",v:"\u2026"}]]},{type:"poetry",lines:[[{t:"italic",v:"O ignorant and confused generation, deceived peoples,"}],[{t:"italic",v:"The Stone which you seek to cast off is LIFE,"}],[{t:"italic",v:"Your only salvation!"}]]},{type:"para",segments:[{t:"text",v:"Behold, The Stone is The Head of the Corner"},{t:"fn",v:"5"},{t:"text",v:"and shall become a great mountain,"},{t:"fn",v:"6"},{t:"text",v:"breaking the backs of the rebellious and grinding the wicked to powder."},{t:"fn",v:"7"},{t:"text",v:"For its weight is heavy beyond measure; its placement sure, immovable, everlasting. Therefore come and be broken atop this Stone, and it shall bear you up! Yet cast it off or cover it over, in an attempt to hide it from others, and you also shall be hidden; into the pit will you stumble, into the grave shall you fall, covered over in the day of My punishment. Behold, the Day is at hand, My anger is aroused and the fire is kindled!"},{t:"fn",v:"8"},{t:"text",v:"Therefore, I ask you, where will you run and where will you hide, when the bitter rains fall from Heaven and judgment ensues like a mighty flood? For I am coming down to extinguish every fiery dart of the evil one, to put an end to all things which cause My people to sin. For The Salvation of God has come already, and shall return to gather up the light; and behold, He is also coming in power and great glory,"},{t:"fn",v:"9"},{t:"text",v:"to punish the wicked and destroy the evil of heart. For as it is written, so it is and shall be:"},{t:"italic",v:"The Law will proceed from Me, and I will make My justice rest as a light for all peoples. My righteousness is near, My salvation has gone forth, and My arm shall judge the nations."},{t:"fn",v:"10"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, lift up your eyes to the heavens,"}],[{t:"italic",v:"And look upon the earth beneath..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the heavens shall vanish away like smoke,"}],[{t:"italic",v:"The earth will grow old like a garment,"}],[{t:"italic",v:"And those who dwell in it shall"}],[{t:"italic",v:"Pass away in like manner\u2026"}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet My Salvation is forever,"}],[{t:"italic",v:"And My righteousness shall never be abolished"},{t:"fn",v:"11"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Exodus 31:18"},2:{type:"scripture",ref:"Proverbs 6:23"},3:{type:"scripture",ref:"Ephesians 2:20"},4:{type:"scripture",ref:"Psalm 147:3"},5:{type:"scripture",ref:"Matthew 21:42"},6:{type:"scripture",ref:"Daniel 2:35"},7:{type:"scripture",ref:"Matthew 21:44"},8:{type:"scripture",ref:"Luke 12:49"},9:{type:"scripture",ref:"Matthew 24:30"},10:{type:"scripture",ref:"Isaiah 51:4-5"},11:{type:"scripture",ref:"Isaiah 51:6"}},nkjv:{"Exodus 31:18":"And when He had made an end of speaking with him on Mount Sinai, He gave Moses two tablets of the Testimony, tablets of stone, written with the finger of God.","Proverbs 6:23":"For the commandment is a lamp, And the law a light; Reproofs of instruction are the way of life,","Ephesians 2:20":"having been built on the foundation of the apostles and prophets, Jesus Christ Himself being the chief cornerstone,","Psalm 147:3":"He heals the brokenhearted And binds up their wounds.","Matthew 21:42":"Jesus said to them, \u201CHave you never read in the Scriptures: \u2018The stone which the builders rejected Has become the chief cornerstone. This was the LORD\u2019s doing, And it is marvelous in our eyes\u2019?","Daniel 2:35":"Then the iron, the clay, the bronze, the silver, and the gold were crushed together, and became like chaff from the summer threshing floors; the wind carried them away so that no trace of them was found. And the stone that struck the image became a great mountain and filled the whole earth.","Matthew 21:44":"And whoever falls on this stone will be broken; but on whomever it falls, it will grind him to powder.\u201D","Luke 12:49":"\u201CI came to send fire on the earth, and how I wish it were already kindled!","Matthew 24:30":"Then the sign of the Son of Man will appear in heaven, and then all the tribes of the earth will mourn, and they will see the Son of Man coming on the clouds of heaven with power and great glory.","Isaiah 51:4-5":"4. \u201CListen to Me, My people; And give ear to Me, O My nation: For law will proceed from Me, And I will make My justice rest As a light of the peoples. 5. My righteousness is near, My salvation has gone forth, And My arms will judge the peoples; The coastlands will wait upon Me, And on My arm they will trust.","Isaiah 51:6":"Lift up your eyes to the heavens, And look on the earth beneath. For the heavens will vanish away like smoke, The earth will grow old like a garment, And those who dwell in it will die in like manner; But My salvation will be forever, And My righteousness will not be abolished."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/embrace-the-cornerstone-wherein-flows-springs-of-living-water",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/embrace-the-cornerstone?in=the-volumes-of-truth/sets/volume-one",videoVoiceUrl:"https://www.youtube.com/watch?v=1y3kFnVV2fw&list=PLE8FlkxQPQkNhyk7QOplwIcW788ErwTRh&index=31",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:'The Coming of The Lord - "I AM COME"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_AM_COME"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:29,prevLetter:{id:"judge-not-others-for-that-by-which-you-judge-is-how-you-shall-be-judged",title:"Judge Not Others, For That By Which You Judge Is How You Shall Be Judged"},nextLetter:null}],LETTERS=[{id:"the-wide-path",num:1,title:"The Wide Path",date:"3/28/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",metaAddendum:'"Embrace The Cornerstone, Wherein Flows Springs of Living Water"',metaAddendumUrl:"https://www.thevolumesoftruth.com/Embrace_The_Cornerstone,_Wherein_Flows_Springs_of_Living_Water",metaAddendumLink:{collection:"Volume One",letterTitle:"Embrace The Cornerstone, Wherein Flows Springs of Living Water"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-wide-path",videoVoiceUrl:"https://www.youtube.com/watch?v=8Nnw1FjVWC0&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=1",relatedTopics:[{label:"Regarding Destroying the Garden (Earth)",url:"https://answersonlygodcangive.com/Regarding_Destroying_the_Garden_(Earth)"},{label:"Regarding Science",url:"https://answersonlygodcangive.com/Regarding_Science"}],footnotes:{1:{type:"scripture",ref:"Isaiah 13:11"},2:{type:"scripture",ref:"Psalm 2:12"},3:{type:"scripture",ref:"Psalm 113:7 (ASV)"}},nkjv:{"Isaiah 13:11":"\u201CI will punish the world for its evil, and the wicked for their iniquity; I will halt the arrogance of the proud, and will lay low the haughtiness of the terrible.\u201D","Psalm 2:12":"Kiss the Son, lest He be angry, and you perish in the way, when His wrath is kindled but a little. Blessed are all those who put their trust in Him.","Psalm 113:7 (ASV)":"He raiseth up the poor out of the dust, and lifteth up the needy from the dunghill,"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Peoples of the earth, why do you corrupt and pollute My garden?! You have made it as the dunghill! Thus you have signed your own certificate, and with death you are in agreement. And though you walk as if you will live forever, I tell you the truth, you are already dead. For you have surely crossed the threshold; behold, you have reached the point of no return."}]},{type:"para",segments:[{t:"text",v:"Yet in your arrogance, you continue to forsake your Maker and Him who has given you breath, holding fast to the wide path which leads to destruction. Therefore, judgment waits for you on the horizon; calamity and desolations shall increase by measure, as the sun sets upon this age of men."}]},{type:"para",segments:[{t:"bold-italic",v:"Peoples of the earth and all leaders among men, hear the Word of The Lord, for thus says The Lord:"},{t:"text",v:" Your knowledge is useless, all your achievements are in vain, and shall come to nothing in the Day of The Lord\u2019s Anger! For as it is written: "},{t:"italic",v:"I shall surely punish this world for its evil, and the wicked for their iniquity. I will put an end to the arrogance of the proud, and utterly humiliate the haughtiness of the tyrant, the mighty, and the terrible."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"text",v:"Therefore, turn from this"}],[{t:"text",v:"Wicked way you have chosen!"}],[{t:"text",v:"Repent, and kiss The Son,"}],[{t:"text",v:"That you may live and not die!"},{t:"fn",v:"2"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"italic",v:"For I AM HE!..."}],[{t:"stanza-break"}],[{t:"text",v:"He who raises the poor from the dust"}],[{t:"text",v:"And lifts the needy out of the dunghill"},{t:"fn",v:"3"},{t:"text",v:"..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:null,nextLetter:{id:"the-seventh-day",title:"The Seventh Day"}},{id:"the-seventh-day",num:2,title:"The Seventh Day",date:"4/18/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-seventh-day",videoVoiceUrl:"https://www.youtube.com/watch?v=e22voNP_dhs&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=2",videoMusicUrl:"https://www.youtube.com/watch?v=KyRcKB1PnKQ&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=32",relatedTopics:[{label:"The Kingdom",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven#The_Kingdom"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],footnotes:{1:{type:"scripture",ref:"2 Peter 3:8"},2:{type:"scripture",ref:"Genesis 2:2"},3:{type:"scripture",ref:"Revelation 21:4"}},nkjv:{"2 Peter 3:8":"But, beloved, do not forget this one thing, that with the Lord one day is as a thousand years, and a thousand years as one day.","Genesis 2:2":"And on the seventh day God ended His work which He had done, and He rested on the seventh day from all His work which He had done.","Revelation 21:4":"And God will wipe away every tear from their eyes; there shall be no more death, nor sorrow, nor crying. There shall be no more pain, for the former things have passed away."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" As it is written, a day in The Lord is as a thousand years."},{t:"fn",v:"1"},{t:"text",v:" And behold, the seventh day is upon you. For The Lord God created the heavens and the earth, and all therein, in six days, and rested on the seventh."},{t:"fn",v:"2"},{t:"text",v:" And behold, My rest is at the door."}]},{type:"para",segments:[{t:"text",v:"For the sixth day is ending, yet not as the sun sets upon the horizon, but as a woman suffering to bring forth. For she is in great travail, her contractions close together, increasing by measure until the birth is accomplished... "},{t:"italic",v:"Behold, the bride\u2019s Husband shall embrace her and hold her close, and wipe away all her tears. And she shall be comforted as He holds the babe in His right hand; the pain of birth all but forgotten, of which she shall never suffer again, for the old order of things has passed away."},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold The New Day!..."}],[{t:"stanza-break"}],[{t:"text",v:"A day of rest from pain and sorrow, from sin and death,"}],[{t:"text",v:"A day set apart from every kind of evil..."}],[{t:"stanza-break"}],[{t:"italic",v:"Holy..."}],[{t:"stanza-break"}],[{t:"text",v:"The Sabbath..."}],[{t:"text",v:"A day in The Lord lasting one thousand years..."}],[{t:"stanza-break"}],[{t:"italic",v:"Peace."}]]}],prevLetter:{id:"the-wide-path",title:"The Wide Path"},nextLetter:{id:"a-day-in-the-lord",title:"A Day in The Lord"}},{id:"a-day-in-the-lord",num:3,title:"A Day in The Lord",date:"4/28/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-day-in-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=Nx4qmrpZIMQ&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=3",videoMusicUrl:"https://www.youtube.com/watch?v=6FzxcIpAgVw&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=36",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Gathering Up (\u201CRapture\u201D)",url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"}],footnotes:{1:{type:"scripture",ref:"2 Peter 3:8"}},nkjv:{"2 Peter 3:8":"But, beloved, do not forget this one thing, that with the Lord one day is as a thousand years, and a thousand years as one day."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Again, I say to you, a day in The Lord is as a thousand years."},{t:"fn",v:"1"},{t:"text",v:" And there is also a time coming, when a day shall be for a year and a week as seven. Yet the length of the Day of The Lord no one knows, for it remains set within the counsel of My own will. Yet for those who escape, there is a day wherein time has no meaning."}]},{type:"para",segments:[{t:"text",v:"And behold, it shall surely happen, in a moment, in the twinkling of an eye, one shall be taken and the other left. For there shall be two in the world - one discontent, yet filled with joyful expectation; and the other content, yet filled with a great emptiness. The discontent shall be taken, their joy fulfilled; the other left in bitter sorrows, lamentation and great weeping. Yet you need not grieve for those who remain. For they need only humble themselves before Me and repent, and they too shall abide at My right hand."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus declares The Lord:"},{t:"text",v:" I shall indeed rob the world of those who are not of the world, I shall surely steal them away - the first election removed and the pure in heart taken. I AM THE LORD."}]},{type:"poetry",lines:[[{t:"text",v:"Yet the world\u2019s loss shall become gain"}],[{t:"text",v:"For those who receive understanding"}],[{t:"text",v:"And repent, for all those who call upon"}],[{t:"text",v:"The Name in sincerity and in truth..."}],[{t:"stanza-break"}],[{t:"text",v:"Behold, in that day many shall see"}],[{t:"text",v:"The angels of Heaven ascending and"}],[{t:"text",v:"Descending upon The Son of Man..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"the-seventh-day",title:"The Seventh Day"},nextLetter:{id:"i-am-the-passover",title:"I Am The Passover and The Lamb, The New Covenant with Men"}},{id:"i-am-the-passover",num:4,title:"I Am The Passover and The Lamb, The New Covenant with Men",date:"4/18/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-the-passover-and-the-lamb-the-new-covenant-with-men-2",videoVoiceUrl:"https://www.youtube.com/watch?v=SQNOSo5XNLw&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=4",videoMusicUrl:"https://www.youtube.com/watch?v=IB6TJi3Q92Y&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=18",bibleStudies:[{label:"YahuShua\u2026 The Lamb of God: The TRUE Chronology of The Messiah\u2019s Crucifixion and Resurrection",url:"https://www.thevolumesoftruth.com/YahuShua..._The_Lamb_of_God:_The_TRUE_Chronology_of_The_Messiah%E2%80%99s_Crucifixion_and_Resurrection"}],relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding the First and Second Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"}],footnotes:{1:{type:"scripture",ref:"Exodus 12:1-27"},2:{type:"scripture",ref:"John 1:29"},3:{type:"scripture",ref:"Romans 6:23"},4:{type:"scripture",ref:"1 Corinthians 5:7"},5:{type:"scripture",ref:"Hebrews 9:22"},6:{type:"scripture",ref:"John 6:48-58"},7:{type:"scripture",ref:"Luke 22:14-20"},8:{type:"scripture",ref:"Hebrews 2:9"},9:{type:"scripture",ref:"Zechariah 12:10"},10:{type:"scripture",ref:"Colossians 2:16-17"},11:{type:"scripture",ref:"Hebrews 10:1-19"},12:{type:"scripture",ref:"Revelation 1:4, Revelation 1:8, Revelation 11:17"}},nkjv:{"Exodus 12:1-27":"1. Now the LORD spoke to Moses and Aaron in the land of Egypt, saying, 2. \u201CThis month shall be your beginning of months; it shall be the first month of the year to you. 3. Speak to all the congregation of Israel, saying: \u2018On the tenth of this month every man shall take for himself a lamb, according to the house of his father, a lamb for a household. 4. And if the household is too small for the lamb, let him and his neighbor next to his house take it according to the number of the persons; according to each man\u2019s need you shall make your count for the lamb. 5. Your lamb shall be without blemish, a male of the first year. You may take it from the sheep or from the goats. 6. Now you shall keep it until the fourteenth day of the same month. Then the whole assembly of the congregation of Israel shall kill it at twilight. 7. And they shall take some of the blood and put it on the two doorposts and on the lintel of the houses where they eat it. 8. Then they shall eat the flesh on that night; roasted in fire, with unleavened bread and with bitter herbs they shall eat it. 9. Do not eat it raw, nor boiled at all with water, but roasted in fire\u2014its head with its legs and its entrails. 10. You shall let none of it remain until morning, and what remains of it until morning you shall burn with fire. 11. And thus you shall eat it: with a belt on your waist, your sandals on your feet, and your staff in your hand. So you shall eat it in haste. It is the LORD\u2019s Passover. 12. For I will pass through the land of Egypt on that night, and will strike all the firstborn in the land of Egypt, both man and beast; and against all the gods of Egypt I will execute judgment: I am the LORD. 13. Now the blood shall be a sign for you on the houses where you are. And when I see the blood, I will pass over you; and the plague shall not be on you to destroy you when I strike the land of Egypt. 14. So this day shall be to you a memorial; and you shall keep it as a feast to the LORD throughout your generations. You shall keep it as a feast by an everlasting ordinance. 15. Seven days you shall eat unleavened bread. On the first day you shall remove leaven from your houses. For whoever eats leavened bread from the first day until the seventh day, that person shall be cut off from Israel. 16. On the first day there shall be a holy convocation, and on the seventh day there shall be a holy convocation for you. No manner of work shall be done on them; but that which everyone must eat\u2014that only may be prepared by you. 17. So you shall observe the Feast of Unleavened Bread, for on this same day I will have brought your armies out of the land of Egypt. Therefore you shall observe this day throughout your generations as an everlasting ordinance. 18. In the first month, on the fourteenth day of the month at evening, you shall eat unleavened bread, until the twenty-first day of the month at evening. 19. For seven days no leaven shall be found in your houses, since whoever eats what is leavened, that same person shall be cut off from the congregation of Israel, whether he is a stranger or a native of the land. 20. You shall eat nothing leavened; in all your dwellings you shall eat unleavened bread.\u2019 21. Then Moses called for all the elders of Israel and said to them, \u201CPick out and take lambs for yourselves according to your families, and kill the Passover lamb. 22. And you shall take a bunch of hyssop, dip it in the blood that is in the basin, and strike the lintel and the two doorposts with the blood that is in the basin. And none of you shall go out of the door of his house until morning. 23. For the LORD will pass through to strike the Egyptians; and when He sees the blood on the lintel and on the two doorposts, the LORD will pass over the door and not allow the destroyer to come into your houses to strike you. 24. And you shall observe this thing as an ordinance for you and your sons forever. 25. It will come to pass when you come to the land which the LORD will give you, just as He promised, that you shall keep this service. 26. And it shall be, when your children say to you, \u2018What do you mean by this service?\u2019 27. that you shall say, \u2018It is the Passover sacrifice of the LORD, who passed over the houses of the children of Israel in Egypt when He struck the Egyptians and delivered our households.\u2019\u201D So the people bowed their heads and worshiped.","John 1:29":"The next day John saw Jesus coming toward him, and said, \u201CBehold! The Lamb of God who takes away the sin of the world!\u201D","Romans 6:23":"For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord.","1 Corinthians 5:7":"Therefore purge out the old leaven, that you may be a new lump, since you truly are unleavened. For indeed Christ, our Passover, was sacrificed for us.","Hebrews 9:22":"And according to the law almost all things are purified with blood, and without shedding of blood there is no remission.","Hebrews 2:9":"But we see Jesus, who was made a little lower than the angels, for the suffering of death crowned with glory and honor, that He, by the grace of God, might taste death for everyone.","Zechariah 12:10":"\u201CAnd I will pour on the house of David and on the inhabitants of Jerusalem the Spirit of grace and supplication; then they will look on Me whom they pierced. Yes, they will mourn for Him as one mourns for his only son, and grieve for Him as one grieves for a firstborn.","John 6:48-58":"48. I am the bread of life. 49. Your fathers ate the manna in the wilderness, and are dead. 50. This is the bread which comes down from heaven, that one may eat of it and not die. 51. I am the living bread which came down from heaven. If anyone eats of this bread, he will live forever; and the bread that I shall give is My flesh, which I shall give for the life of the world. 52. The Jews therefore quarreled among themselves, saying, \u201CHow can this Man give us His flesh to eat?\u201D 53. Then Jesus said to them, \u201CMost assuredly, I say to you, unless you eat the flesh of the Son of Man and drink His blood, you have no life in you. 54. Whoever eats My flesh and drinks My blood has eternal life, and I will raise him up at the last day. 55. For My flesh is food indeed, and My blood is drink indeed. 56. He who eats My flesh and drinks My blood abides in Me, and I in him. 57. As the living Father sent Me, and I live because of the Father, so he who feeds on Me will live because of Me. 58. This is the bread which came down from heaven\u2014not as your fathers ate the manna, and are dead. He who eats this bread will live forever.\u201D","Luke 22:14-20":"14. When the hour had come, He sat down, and the twelve apostles with Him. 15. Then He said to them, \u201CWith fervent desire I have desired to eat this Passover with you before I suffer; 16. for I say to you, I will no longer eat of it until it is fulfilled in the kingdom of God.\u201D 17. Then He took the cup, and gave thanks, and said, \u201CTake this and divide it among yourselves; 18. for I say to you, I will not drink of the fruit of the vine until the kingdom of God comes.\u201D 19. And He took bread, gave thanks and broke it, and gave it to them, saying, \u201CThis is My body which is given for you; do this in remembrance of Me.\u201D 20. Likewise He also took the cup after supper, saying, \u201CThis cup is the new covenant in My blood, which is shed for you.\u201D","Colossians 2:16-17":"16. So let no one judge you in food or in drink, or regarding a festival or a new moon or sabbaths, 17. which are a shadow of things to come, but the substance is of Christ.","Hebrews 10:1-19":"1. For the law, having a shadow of the good things to come, and not the very image of the things, can never with these same sacrifices, which they offer continually year by year, make those who approach perfect. 2. For then would they not have ceased to be offered? For the worshipers, once purified, would have had no more consciousness of sins. 3. But in those sacrifices there is a reminder of sins every year. 4. For it is not possible that the blood of bulls and goats could take away sins. 5. Therefore, when He came into the world, He said: \u201CSacrifice and offering You did not desire, but a body You have prepared for Me. 6. In burnt offerings and sacrifices for sin You had no pleasure. 7. Then I said, \u2018Behold, I have come\u2014in the volume of the book it is written of Me\u2014to do Your will, O God.\u2019\u201D 8. Previously saying, \u201CSacrifice and offering, burnt offerings, and offerings for sin You did not desire, nor had pleasure in them\u201D (which are offered according to the law), 9. then He said, \u201CBehold, I have come to do Your will, O God.\u201D He takes away the first that He may establish the second. 10. By that will we have been sanctified through the offering of the body of Jesus Christ once for all. 11. And every priest stands ministering daily and offering repeatedly the same sacrifices, which can never take away sins. 12. But this Man, after He had offered one sacrifice for sins forever, sat down at the right hand of God, 13. from that time waiting till His enemies are made His footstool. 14. For by one offering He has perfected forever those who are being sanctified. 15. But the Holy Spirit also witnesses to us; for after He had said before, 16. \u201CThis is the covenant that I will make with them after those days, says the LORD: I will put My laws into their hearts, and in their minds I will write them,\u201D 17. then He adds, \u201CTheir sins and their lawless deeds I will remember no more.\u201D 18. Now where there is remission of these, there is no longer an offering for sin. 19. Therefore, brethren, having boldness to enter the Holiest by the blood of Jesus,","Revelation 1:4, Revelation 1:8, Revelation 11:17":"1:4 \u2014 John, to the seven churches which are in Asia: Grace to you and peace from Him who is and who was and who is to come, and from the seven Spirits who are before His throne. | 1:8 \u2014 \u201CI am the Alpha and the Omega, the Beginning and the End,\u201D says the Lord, \u201Cwho is and who was and who is to come, the Almighty.\u201D | 11:17 \u2014 saying: \u201CWe give You thanks, O Lord God Almighty, the One who is and who was and who is to come, because You have taken Your great power and reigned.\u201D"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Messiah who is called Christ, The Holy One of Israel:"},{t:"text",v:" I am The Lamb of God without spot or blemish, the blood which was shed and placed upon the doorposts,"},{t:"fn",v:"1"},{t:"text",v:" delivering My people from the power of sin,"},{t:"fn",v:"2"},{t:"text",v:" which is death."},{t:"fn",v:"3"},{t:"text",v:" I am The Passover."},{t:"fn",v:"4"}]},{type:"para",segments:[{t:"text",v:"For as it is written in The Law, all things must be purified with blood, and without the shedding of blood there can be no remission."},{t:"fn",v:"5"},{t:"text",v:" Thus no one goes to The Father, unless they receive of Me. Unless they eat My flesh and drink My blood, they have no life in them. For whosoever eats My flesh and drinks My blood has everlasting life, and I will raise them up at the Last Day. For My flesh is food indeed, and My blood is drink indeed. Thus all who eat My flesh and drink My blood live in Me, and I in them."}]},{type:"para",segments:[{t:"text",v:"I am The Living Bread which came down from Heaven! If anyone eats this bread, he will live forever! And the bread that I gave was My flesh, which was given for the life of the world. This I have already told you."},{t:"fn",v:"6"},{t:"text",v:" Therefore keep the Passover in remembrance of Me and My Passion, according to The New Covenant."},{t:"fn",v:"7"},{t:"text",v:" For it is accomplished, and was sealed forevermore upon My resurrection. For The Lamb was slain, My people redeemed in all the earth; and behold, I am risen, crowned with glory and honor, forever and ever."},{t:"fn",v:"8"},{t:"text",v:" Amen."}]},{type:"para",segments:[{t:"text",v:"Therefore, again I say to you, celebrate Passover, yet not as in the days of Moses; nor as the unbelieving in Israel, upon whom the veil remains, for they have yet to look upon Me."},{t:"fn",v:"9"},{t:"text",v:" For the Passover was a signpost, a shadow of glorious things to come."},{t:"fn",v:"10"},{t:"text",v:" Read the writing thereof and have understanding, take its meaning to heart."},{t:"fn",v:"11"},{t:"text",v:" For the Holy Days are revelation, the Plan of the Ages revealed."}]},{type:"poetry",lines:[[{t:"text",v:"Therefore rejoice, My people, for your Redeemer lives!"}],[{t:"text",v:"Death has passed over you!..."}],[{t:"stanza-break"}],[{t:"text",v:"Therefore eat, drink, and give thanks"}],[{t:"text",v:"In remembrance of Me, and I shall also"}],[{t:"text",v:"Remember you in the day I gather My own..."}],[{t:"stanza-break"}],[{t:"text",v:"Then shall you truly know Me,"}],[{t:"text",v:"Just as I have always known you,"}],[{t:"text",v:"Even from the foundation of the world..."}]]},{type:"closing",text:"Says He who is, and was, and is to come,\xA0\xA0YahuShua, The Salvation of God."},{type:"closing-fn",segments:[{t:"fn",v:"12"}]}],prevLetter:{id:"a-day-in-the-lord",title:"A Day in The Lord"},nextLetter:{id:"the-holy-spirit",title:"The Holy Spirit"}},{id:"the-holy-spirit",num:5,title:"The Holy Spirit",date:"4/19/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",preamble:"These questions were asked of The Lord: Lord, should we worship the Holy Spirit? Is the Holy Spirit a person?",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-holy-spirit",videoVoiceUrl:"https://www.youtube.com/watch?v=_jaAUvuDuSA&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=5",bibleStudies:[{label:"The False Doctrine of \u201CThe Trinity\u201D Exposed - The Holy Spirit is Not a Person",url:"https://www.thevolumesoftruth.com/The_False_Doctrine_of_%E2%80%9CThe_Trinity%E2%80%9D_Exposed_-_The_Holy_Spirit_is_Not_a_Person",link:{collection:'The False Doctrine of "The Trinity" Exposed - The Holy Spirit is Not a Person',letterTitle:'The False Doctrine of "The Trinity" Exposed - The Holy Spirit is Not a Person'}}],relatedTopics:[{label:"Regarding The Holy Spirit",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"Regarding The Trinity",url:"https://answersonlygodcangive.com/Regarding_The_Trinity"}],footnotes:{1:{type:"scripture",ref:"2 Timothy 2:15 (KJV)"},2:{type:"scripture",ref:"Psalm 2:7, Hebrews 5:5"},3:{type:"scripture",ref:"John 14:26 (CEB)"},4:{type:"scripture",ref:"John 20:22"},5:{type:"scripture",ref:"1 Corinthians 3:16"}},nkjv:{"2 Timothy 2:15 (KJV)":"Study to shew thyself approved unto God, a workman that needeth not to be ashamed, rightly dividing the word of truth.","Psalm 2:7, Hebrews 5:5":"Psalm 2:7 \u2014 \u201CI will declare the decree: The Lord has said to Me, \u2018You are My Son, today I have begotten You.\u2019\u201D | Hebrews 5:5 \u2014 So also Christ did not glorify Himself to become High Priest, but it was He who said to Him: \u201CYou are My Son, today I have begotten You.\u201D","John 14:26 (CEB)":"The Companion, the Holy Spirit, whom the Father will send in my name, will teach you everything and will remind you of everything I told you.","John 20:22":"And when He had said this, He breathed on them, and said to them, \u201CReceive the Holy Spirit.\u201D","1 Corinthians 3:16":"Do you not know that you are the temple of God and that the Spirit of God dwells in you?"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Beware of the doctrines and traditions of men in the churches. Stumble not over the letter, nor be led astray by perverse interpretations or biased translations, by which the churches of men have marred My Word before the people. "},{t:"italic",v:"Rather study to show yourself approved unto God, a workman that need not be ashamed, rightly dividing the Word of Truth."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"For I ask you, where in the Scriptures of Truth is it written to give praise and worship unto the Spirit? For the Spirit is not a person, nor have I called it by name. For to YahuShua alone did I say, "},{t:"italic",v:"\u201CYou are My Son; today I have begotten You.\u201D"},{t:"fn",v:"2"},{t:"text",v:" Therefore worship God, offering up praises in the name of The Son, and give thanks. For those who believe in The Son, and also seek to obey Him, receive of My spirit. For it is My hand upon you, guiding you in the way in which you should walk, My voice speaking softly from within, reminding you of that which I have taught you,"},{t:"fn",v:"3"},{t:"text",v:" restoring you to righteousness and life. Yet the power of God moving upon the face of the earth is My spirit also, My will made manifest in the world and among men."}]},{type:"para",segments:[{t:"text",v:"Therefore, I ask you, how can one pray to that which he prays through? Shall one pray to the hand of God? Rather pray to your Father in Heaven, in The Son\u2019s name, and through the Spirit we shall be one. For all My servants move, speak and hear Me through My spirit, and only through The Son shall My children come to know Me as I truly am... "},{t:"italic",v:"And oh how blessed are those who know Him, for they love Him and obey His voice, having truly received of Him, even of His spirit, the Spirit of God."}]},{type:"poetry",lines:[[{t:"italic",v:"Indeed holy, holy, holy is The Lord God Almighty..."}],[{t:"stanza-break"}],[{t:"text",v:"One God, invisible and visible, The Father and The Son;"}],[{t:"text",v:"And the Spirit called Holy, because I am holy..."}],[{t:"stanza-break"}],[{t:"text",v:"Therefore, accept My love and receive of My gifts;"}],[{t:"text",v:"For the Spirit is indeed a gift given by The Father,"}],[{t:"text",v:"Received through The Son"},{t:"fn",v:"4"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"text",v:"Call it not a person, call it a blessing;"}],[{t:"text",v:"For blessed are those who have the Spirit of God,"}],[{t:"text",v:"For God dwells within them."},{t:"fn",v:"5"}]]}],prevLetter:{id:"i-am-the-passover",title:"I Am The Passover and The Lamb, The New Covenant with Men"},nextLetter:{id:"bear-much-fruit",title:"Bear Much Fruit, the Harvest Is Near"}},{id:"bear-much-fruit",num:6,title:"Bear Much Fruit, the Harvest Is Near",date:"4/21/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For His Wife, and For All Those Who Have Ears to Hear",preamble:"This question was asked of The Lord, for Timothy\u2019s wife: Lord, should she try to remain friends with those who have separated themselves from her because of Your Word?",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/bear-much-fruit-the-harvest-is-near",videoVoiceUrl:"https://www.youtube.com/watch?v=SCUSQvGx35o&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=6",relatedTopics:[{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Tithing",url:"https://answersonlygodcangive.com/Regarding_Tithing"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],footnotes:{},nkjv:{},blocks:[{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:" Beloved, bear fruit after the kind I have given you, in open and in secret. For what profit is there in sharing with another that which they believe they already have? And how shall one who pushes out the hand receive a gift? Beloved, let the separation stand. For though they say, "},{t:"italic",v:"\u201CWe are full, we are in need of nothing,\u201D"},{t:"text",v:" I tell you the truth, they remain void and desolate."}]},{type:"para",segments:[{t:"text",v:"Therefore, turn aside from those who push out the hand and wag the head. Rather seek out the poor, that I may feed them. Fill the bowls of the hungry, and place the cup in the hands of the thirsty; give them your portion. For My bounty is plentiful, given freely to all who hunger and thirst for righteousness. Beloved, tell them that you were once lost, yet now you are found; that you were once naked, yet now you are clothed in fine linens of white, your filthy rags cast off forever; that you were once hungry and very thirsty, starving in a world of empty promises, lies and vain deceits, yet now you are nourished with The Word of Truth."}]},{type:"para",segments:[{t:"text",v:"Behold, I am The Living Bread which came down from Heaven, The Fountain of Living Waters which sustains My people unto everlasting life! My words never pass away, and My promises stand forever! Therefore eat and be satisfied, drink deeply and be healed, for The Lord\u2019s table is a bounty. And those who eat from My plate are always full, and those who drink from My cup shall never go thirsty. For My cup overflows, bearing fruit in every part of your life, bringing forth love and understanding."}]},{type:"poetry",lines:[[{t:"italic",v:"Oh My beloved, you were once sick, mortally ill;"}],[{t:"text",v:"Yet now you are healed in Me, now you are"}],[{t:"text",v:"Restored because of Me, My body, My bride..."}],[{t:"stanza-break"}],[{t:"text",v:"My precious flower, My pleasant plant, of which"}],[{t:"text",v:"I shall pluck from the earth at the time appointed,"}],[{t:"text",v:"Replanted in the Garden at dawn on the new day..."}],[{t:"stanza-break"}],[{t:"text",v:"Therefore come forth, all My people,"}],[{t:"text",v:"And flourish in the light of The Lord,"}],[{t:"text",v:"And bear much fruit in The Beloved!..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"the-holy-spirit",title:"The Holy Spirit"},nextLetter:{id:"do-this-in-remembrance",title:"Do This in Remembrance of Me"}},{id:"do-this-in-remembrance",num:7,title:"Do This in Remembrance of Me",date:"4/25/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",noteLine:"(Regarding Passover and the Feast of Unleavened Bread)",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/do-this-in-remembrance-of-me",videoVoiceUrl:"https://www.youtube.com/watch?v=_k7yeHHdvYc&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=7",bibleStudies:[{label:"YahuShua\u2026 The Lamb of God: The TRUE Chronology of The Messiah\u2019s Crucifixion and Resurrection",url:"https://www.thevolumesoftruth.com/YahuShua..._The_Lamb_of_God:_The_TRUE_Chronology_of_The_Messiah%E2%80%99s_Crucifixion_and_Resurrection"}],relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],footnotes:{1:{type:"scripture",ref:"Isaiah 58:13"},2:{type:"scripture",ref:"Revelation 22:15"},3:{type:"scripture",ref:"Matthew 3:8"},4:{type:"note",text:"\u201CWomen\u201D in this context refers to the churches of men"},5:{type:"scripture",ref:"Matthew 16:6"},6:{type:"scripture",ref:"Jeremiah 17:10"},7:{type:"scripture",ref:"1 Corinthians 5:7-8"}},nkjv:{"Isaiah 58:13":"\u201CIf you turn away your foot from the Sabbath, from doing your pleasure on My holy day, and call the Sabbath a delight, the holy day of the Lord honorable, and shall honor Him, not doing your own ways, nor finding your own pleasure, nor speaking your own words,\u201D","Revelation 22:15":"But outside are dogs and sorcerers and sexually immoral and murderers and idolaters, and whoever loves and practices a lie.","Matthew 3:8":"Therefore bear fruits worthy of repentance,","Matthew 16:6":"Then Jesus said to them, \u201CTake heed and beware of the leaven of the Pharisees and the Sadducees.\u201D","Jeremiah 17:10":"\u201CI, the Lord, search the heart, I test the mind, even to give every man according to his ways, according to the fruit of his doings.\u201D","1 Corinthians 5:7-8":"7. Therefore purge out the old leaven, that you may be a new lump, since you truly are unleavened. For indeed Christ, our Passover, was sacrificed for us. 8. Therefore let us keep the feast, not with old leaven, nor with the leaven of malice and wickedness, but with the unleavened bread of sincerity and truth."},blocks:[{type:"intro",segments:[{t:"bold-italic",v:"Listen and have understanding, for thus says The Lord your Redeemer:"},{t:"text",v:" Only those who truly believe keep the Passover. To them it is a memorial, a time of reflection and the giving of thanks, a Sabbath."}]},{type:"para",segments:[{t:"text",v:"Therefore, Timothy, do not your own pleasure on the Holy Days or on the Sabbath."},{t:"fn",v:"1"},{t:"text",v:" Rather do that which pleases The Lord your God. Keep the feasts holy, and cause your life to follow suit; unleaven your heart. Discern what is most needful, and when in doubt, ask."}]},{type:"para",segments:[{t:"text",v:"And concerning the rites and ceremonial symbols of the feasts, consider their meaning and rejoice in their fulfillment, for it is accomplished. Do not agonize over the details, nor stumble over the letter. And concerning that which you partake of for the body, it is of little consequence. Rather feast upon that which sustains your soul. Remember Me and My Passion, as I have shown you; offer up thanksgiving, and consider your salvation and The Loving Mercy of God. For the intent of one\u2019s heart speaks volumes more than the offering put forth by their hands."}]},{type:"para",segments:[{t:"text",v:"Yet I tell you the truth, many will there be who enter The Kingdom of Heaven, who did not keep the feasts of The Lord. And many will there be left standing outside the gates, who kept the feasts of The Lord. For those without the gate retain their sin, for they hold fast to malice and have not yet departed from wickedness."},{t:"fn",v:"2"},{t:"text",v:" Yet the hearts of the first election are filled with compassion and a sincere desire to walk in My ways, having called upon My name in sincerity and in truth, as they bring forth new works meet for repentance."},{t:"fn",v:"3"},{t:"text",v:" For where there are righteous works, there are also those who seek to spoil them for the sake of pride and envy. And where there is pure knowledge, there are also those who defile it among women."},{t:"fn",v:"4"},{t:"text",v:" Take heed, therefore, and remember My teaching: "},{t:"italic",v:"Beware of the leaven of the Pharisees and the Sadducees."},{t:"fn",v:"5"},{t:"text",v:" For their like still exists today; only their names and vesture have changed."}]},{type:"poetry",lines:[[{t:"text",v:"Yet the ignorance of the meek is no cause for offense,"}],[{t:"text",v:"Nor shall the error of the humble bring forth rebuke;"}],[{t:"text",v:"For I know the heart and look upon the innermost intentions"},{t:"fn",v:"6"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"text",v:"Therefore keep the feast, not with the old leaven,"}],[{t:"text",v:"Nor with the leaven of malice and wickedness,"}],[{t:"text",v:"But with the unleavened bread of sincerity and truth,"}],[{t:"text",v:"As it is written in accordance with the New Covenant"},{t:"fn",v:"7"},{t:"text",v:"..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"bear-much-fruit",title:"Bear Much Fruit, the Harvest Is Near"},nextLetter:{id:"ensign",title:"Ensign"}},{id:"ensign",num:8,title:"Ensign",date:"5/4/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/ensign",videoVoiceUrl:"https://www.youtube.com/watch?v=ek6TMm9Aoj8&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=8",videoMusicUrl:"https://www.youtube.com/watch?v=2rYNPD0T_m0&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=37",relatedTopics:[{label:"Regarding the End Sign",url:"https://answersonlygodcangive.com/Regarding_the_End_Sign"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],footnotes:{1:{type:"scripture",ref:"Revelation 16:15"},2:{type:"scripture",ref:"Matthew 24:30"},3:{type:"scripture",ref:"Matthew 24:42, Revelation 22:12"},4:{type:"scripture",ref:"John 1:14, Matthew 1:23"},5:{type:"scripture",ref:"Revelation 1:7"}},nkjv:{"Revelation 16:15":"\u201CBehold, I am coming as a thief. Blessed is he who watches, and keeps his garments, lest he walk naked and they see his shame.\u201D","Matthew 24:30":"\u201CThen the sign of the Son of Man will appear in heaven, and then all the tribes of the earth will mourn, and they will see the Son of Man coming on the clouds of heaven with power and great glory.\u201D","Matthew 24:42, Revelation 22:12":"Matthew 24:42 \u2014 \u201CWatch therefore, for you do not know what hour your Lord is coming.\u201D | Revelation 22:12 \u2014 \u201CAnd behold, I am coming quickly, and My reward is with Me, to give to every one according to his work.\u201D","John 1:14, Matthew 1:23":"John 1:14 \u2014 And the Word became flesh and dwelt among us, and we beheld His glory, the glory as of the only begotten of the Father, full of grace and truth. | Matthew 1:23 \u2014 \u201CBehold, the virgin shall be with child, and bear a Son, and they shall call His name Immanuel,\u201D which is translated, \u201CGod with us.\u201D","Revelation 1:7":"Behold, He is coming with clouds, and every eye will see Him, even they who pierced Him. And all the tribes of the earth will mourn because of Him. Even so, Amen."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Behold, the time draws near, when they will not see The Thief come;"},{t:"fn",v:"1"},{t:"text",v:" when the judgments of God shall fall from Heaven, even upon the face of the whole earth; when the sign shall appear and the heavens shall be set ablaze with brilliant light."},{t:"fn",v:"2"},{t:"text",v:" For as The Son of Man was lifted up on a tree in the sight of men, so in like manner shall the sign of The Son of Man be. For that which was the beginning and the end shall also be the end which brings forth the new beginning."}]},{type:"para",segments:[{t:"text",v:"Behold, I shall do a new and wondrous thing! I shall lift up a standard and bring forth a sign, in the sight of all nations! I shall pierce the heavens and bathe the earth in glorious light, and every eye shall see! Yes, even those hidden in caves and shelters shall see and come forth; behold, even the blind shall see! For on that day I shall divide the heavens, and divide them again, and all silence shall flee away!"}]},{type:"para",segments:[{t:"bold-italic",v:"HEAR THE SOUND OF SCORCHING FIRMAMENT! BE AWESTRUCK IN ASTONISHMENT AT THE MULTITUDE OF THUNDER, AND BE HORRIBLY AFRAID!"},{t:"text",v:" For as the sparks of a crackling fire, so shall the sign of The Son of Man be, plus ten thousand million-fold! Says The Lord."}]},{type:"poetry",lines:[[{t:"text",v:"Look up therefore, and keep watch,"}],[{t:"text",v:"For He is coming quickly"},{t:"fn",v:"3"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"italic",v:"Yes, The Word who became flesh, Immanu El"},{t:"fn",v:"4"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"text",v:"Thus as it is written, so shall it be:"}],[{t:"text",v:"He is coming on the clouds and"}],[{t:"text",v:"Every eye shall see Him, even those"}],[{t:"text",v:"Who pierced Him, and all the tribes"}],[{t:"text",v:"Of the earth shall mourn because of Him..."}],[{t:"stanza-break"}],[{t:"italic",v:"Even so, amen."},{t:"fn",v:"5"}]]}],prevLetter:{id:"do-this-in-remembrance",title:"Do This in Remembrance of Me"},nextLetter:{id:"it-is-time",title:"It Is Time... Prepare to Meet Your God"}},{id:"it-is-time",num:9,title:"It Is Time... Prepare to Meet Your God",date:"5/14/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/it-is-time-prepare-to-meet-your-god",videoVoiceUrl:"https://www.youtube.com/watch?v=GEFsMyZttTQ&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=9",relatedTopics:[{label:"Regarding the End Sign",url:"https://answersonlygodcangive.com/Regarding_the_End_Sign"},{label:"\u201CHe Who Was and Is and Is to Come\u201D",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#He_Who_Was_and_Is_and_Is_to_Come"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],footnotes:{1:{type:"scripture",ref:"2 Corinthians 3:13-16"},2:{type:"scripture",ref:"Revelation 1:8"},3:{type:"scripture",ref:"John 1:14, Matthew 1:23"},4:{type:"scripture",ref:"Jeremiah 23:6"},5:{type:"scripture",ref:"John 1:10-11"},6:{type:"scripture",ref:"John 14:10-11"},7:{type:"scripture",ref:"Matthew 24:30"},8:{type:"scripture",ref:"Revelation 6:14"},9:{type:"scripture",ref:"Zechariah 12:10"},10:{type:"scripture",ref:"Isaiah 2:11-12, Isaiah 2:17"},11:{type:"scripture",ref:"Isaiah 2:19, Revelation 6:15-16"},12:{type:"scripture",ref:"Romans 3:13-18"},13:{type:"scripture",ref:"Psalm 21:8-13"}},nkjv:{"Revelation 1:8":"\u201CI am the Alpha and the Omega, the Beginning and the End,\u201D says the Lord, \u201Cwho is and who was and who is to come, the Almighty.\u201D","Jeremiah 23:6":"In His days Judah will be saved, And Israel will dwell safely; Now this is His name by which He will be called: THE LORD OUR RIGHTEOUSNESS.","John 1:10-11":"10. He was in the world, and the world was made through Him, and the world did not know Him. 11. He came to His own, and His own did not receive Him.","Matthew 24:30":"\u201CThen the sign of the Son of Man will appear in heaven, and then all the tribes of the earth will mourn, and they will see the Son of Man coming on the clouds of heaven with power and great glory.\u201D","Revelation 6:14":"Then the sky receded as a scroll when it is rolled up, and every mountain and island was moved out of its place.","Zechariah 12:10":"\u201CAnd I will pour on the house of David and on the inhabitants of Jerusalem the Spirit of grace and supplication; then they will look on Me whom they pierced. Yes, they will mourn for Him as one mourns for his only son, and grieve for Him as one grieves for a firstborn.","Romans 3:13-18":"13. \u201CTheir throat is an open tomb; With their tongues they have practiced deceit\u201D; \u201CThe poison of asps is under their lips\u201D; 14. \u201CWhose mouth is full of cursing and bitterness.\u201D 15. \u201CTheir feet are swift to shed blood; 16. Destruction and misery are in their ways; 17. And the way of peace they have not known.\u201D 18. \u201CThere is no fear of God before their eyes.\u201D","2 Corinthians 3:13-16":"13. unlike Moses, who put a veil over his face so that the children of Israel could not look steadily at the end of what was passing away. 14. But their minds were blinded. For until this day the same veil remains unlifted in the reading of the Old Testament, because the veil is taken away in Christ. 15. But even to this day, when Moses is read, a veil lies on their heart. 16. Nevertheless when one turns to the Lord, the veil is taken away.","John 1:14, Matthew 1:23":"John 1:14 \u2014 And the Word became flesh and dwelt among us, and we beheld His glory, the glory as of the only begotten of the Father, full of grace and truth. | Matthew 1:23 \u2014 \u201CBehold, the virgin shall be with child, and bear a Son, and they shall call His name Immanuel,\u201D which is translated, \u201CGod with us.\u201D","John 14:10-11":"10. Do you not believe that I am in the Father, and the Father in Me? The words that I speak to you I do not speak on My own authority; but the Father who dwells in Me does the works. 11. Believe Me that I am in the Father and the Father in Me, or else believe Me for the sake of the works themselves.","Isaiah 2:11-12, Isaiah 2:17":"Isaiah 2:11 \u2014 The lofty looks of man shall be humbled, the haughtiness of men shall be bowed down, and the LORD alone shall be exalted in that day. | Isaiah 2:12 \u2014 For the day of the LORD of hosts shall come upon everything proud and lofty, upon everything lifted up\u2014and it shall be brought low\u2014 | Isaiah 2:17 \u2014 The loftiness of man shall be bowed down, and the haughtiness of men shall be brought low; the LORD alone will be exalted in that day.","Isaiah 2:19, Revelation 6:15-16":"Isaiah 2:19 \u2014 They shall go into the holes of the rocks, and into the caves of the earth, from the terror of the LORD and the glory of His majesty, when He arises to shake the earth mightily. | Revelation 6:15\u201316 \u2014 And the kings of the earth, the great men, the rich men, the commanders, the mighty men, every slave and every free man, hid themselves in the caves and in the rocks of the mountains, and said to the mountains and rocks, \u201CFall on us and hide us from the face of Him who sits on the throne and from the wrath of the Lamb!\u201D","Psalm 21:8-13":"8. Your hand will find all Your enemies; Your right hand will find those who hate You. 9. You shall make them as a fiery oven in the time of Your anger; the LORD shall swallow them up in His wrath, and the fire shall devour them. 10. Their offspring You shall destroy from the earth, and their descendants from among the sons of men. 11. For they intended evil against You; they devised a plot which they are not able to perform. 12. Therefore You will make them turn their back; You will make ready Your arrows on Your string toward their faces. 13. Be exalted, O LORD, in Your own strength! We will sing and praise Your power."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" My people have turned from Me, they have altogether forsaken The Lord their God, foolish children married to a world awash in vanity and sin. Therefore, the time has come. Behold, the time has come for My name to resound in all the earth, for all who dwell upon the earth to be humbled, to be broken without hand. Indeed, now is the time for all who have ears to hear, to hear and give heed; and for those who refuse, to forbear and rebel against Me."}]},{type:"para",segments:[{t:"text",v:"It is time for My servants to stand up, to receive My words and also do them. It is time to blow the trumpet, to sound the alarm. It is time for My spirit to be poured out, for the hand of The Almighty to stir up the multitudes, for The Word of God to separate and divide the people. It is time for My watchmen to proclaim the acceptable year of The Lord and the Day of Vengeance of The Lord their God. For the ears of the first election are open, and within My prophets I have placed My voice, once again; I have surely put My words in their mouths. For I am The Lord, and I do not change."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, for thus says The Holy One of Israel:"},{t:"text",v:" Awaken, O foolish people! Arise from your beds, and prepare to meet your God! My children, cast away these filthy veils which cover your heads; yes, even you, My people who dwell in Israel, hear the Word of your Messiah."},{t:"fn",v:"1"},{t:"text",v:" For I AM HE, He who was and is and is to come,"},{t:"fn",v:"2"},{t:"text",v:" YAHUSHUA-YAHUWAH, God in the flesh, Immanu El,"},{t:"fn",v:"3"},{t:"text",v:" The Lord your Righteousness."},{t:"fn",v:"4"}]},{type:"para",segments:[{t:"text",v:"For I had come into the world, yet you would not receive Me."},{t:"fn",v:"5"},{t:"text",v:" Behold, I am coming again, and still you deny Me. Therefore hear and understand, and gain wisdom. For The Father has proclaimed My glory from the beginning; even before the house of Israel was My glory put on open display. For I am in The Father, and The Father is in Me, of which My works also testify, the works He sent Me to do, even the cross."},{t:"fn",v:"6"}]},{type:"poetry",lines:[[{t:"text",v:"And now the time has come, behold, the day is near,"}],[{t:"text",v:"When I shall give you yet another sign,"}],[{t:"text",v:"Even the sign of The Son of Man"},{t:"fn",v:"7"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"text",v:"The heavens shall be divided, and divided again,"}],[{t:"text",v:"The glory thereof stretching from the earth to heaven,"}],[{t:"text",v:"And the clouds shall be rolled back like a scroll"},{t:"fn",v:"8"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"text",v:"Behold the brilliance, O earth,"}],[{t:"text",v:"Be bowed down and weep, O sons of men,"}],[{t:"text",v:"For The One whom you pierced is about to appear!"},{t:"fn",v:"9"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"text",v:"Let every eye be opened therefore,"}],[{t:"text",v:"Let all in the earth see, until the fullness"}],[{t:"text",v:"Of the revelation is made complete."}]]},{type:"para",segments:[{t:"text",v:"For all in the earth shall be humbled, and the pride of man shall be broken in that day. For as it is written: "},{t:"italic",v:"The loftiness of man shall be bowed down and the haughtiness of men shall be brought low, the idols shall be utterly abolished, and The Lord alone shall be exalted in that day"},{t:"fn",v:"10"},{t:"italic",v:". And for fear of The Lord, many shall go into the holes of the rocks, and into the caves of the earth, to hide themselves from the terror of The Lord and the glory of His majesty, when He arises to shake the earth mightily!"},{t:"fn",v:"11"},{t:"text",v:" And behold, a great remnant shall emerge, who will not go into the holes of the rocks or into the caves of the earth, to hide themselves from the terror of The Lord or the glory of His majesty, but will stand fast with hands uplifted, singing praises to The Lord their God."}]},{type:"para",segments:[{t:"text",v:"Yet woe to those who shake their fists at Heaven; their destruction draws near. For the hearts of the ungodly produce only wickedness. Their throats are like open graves, their speech is full of deadly deceit. They are practiced liars, and with their tongues they spew all kinds of threats. And like venomous snakes, they conceal poison behind their lips. For their mouths are full of bitterness, and cursing is always upon their breath. They are quick to do harm, and are not afraid to kill. Their ways bring only destruction, misery and death. For the way of peace is foreign to them, and the fear of The Lord they have not known."},{t:"fn",v:"12"}]},{type:"para",segments:[{t:"text",v:"Therefore as it is written of Me, so I am and shall be: "},{t:"italic",v:"My hand shall find all My enemies, My right hand shall overtake those who hate Me! At My appearing I will make them all like a fiery furnace; I shall swallow them up in My anger, and the fire of My wrath shall consume them! I will wipe their descendants from the face of the earth; behold, I shall rid mankind of their posterity! For they intended evil against Me, and devised many schemes, but will be unable to perform them! For My arrows were made ready from the beginning, and when I aim My bow at their faces they shall surely flee! Therefore I shall be exalted in My strength, and My people shall sing Me praises when I put My power on open display! Says The Lord."},{t:"fn",v:"13"}]}],prevLetter:{id:"ensign",title:"Ensign"},nextLetter:{id:"woe-to-the-church",title:"Woe to the Church Called Roman and Catholic"}},{id:"woe-to-the-church",num:10,title:"Woe to the Church Called Roman and Catholic",date:"5/14/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/woe-to-the-church-called-roman-and-catholic-2",videoVoiceUrl:"https://www.youtube.com/watch?v=uyQYfoWv2B8&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=10",relatedTopics:[{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Index of False Doctrines Within the Churches of Men",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],footnotes:{1:{type:"scripture",ref:"Proverbs 2:12-18"},2:{type:"scripture",ref:"Matthew 23:9 (NLT)"},3:{type:"scripture",ref:"Matthew 23:15"},4:{type:"note",text:"Revelation 17",url:"https://www.biblegateway.com/passage/?search=Revelation+17&version=NKJV"},5:{type:"scripture",ref:"Matthew 12:32 (CJB)"},6:{type:"scripture",ref:"Matthew 7:13"},7:{type:"scripture",ref:"1 Timothy 4:7"},8:{type:"scripture",ref:"Jeremiah 7:28, Isaiah 59:14"},9:{type:"note",text:"See: \u201CTrust in God Alone\u201D \u2014 \u201CAnd do not call anyone on earth \u2018father\u2019\u2026\u201D (Matthew 23:9)",url:"https://www.thevolumesoftruth.com/Trust_in_God_Alone#:~:text=And%20do%20not,from%20a%20tree.",link:{collection:"A Testament Against The World: The Lord's Rebuke",letterTitle:"Trust in God Alone",excerpt:"And do not put your trust in any man, though he speaks with a clever tongue"}},10:{type:"scripture",ref:"Matthew 23:27"},11:{type:"scripture",ref:"Matthew 7:19"}},nkjv:{"Proverbs 2:12-18":"12. To deliver you from the way of evil, from the man who speaks perverse things, 13. from those who leave the paths of uprightness to walk in the ways of darkness; 14. who rejoice in doing evil, and delight in the perversity of the wicked; 15. whose ways are crooked, and who are devious in their paths; 16. to deliver you from the immoral woman, from the seductress who flatters with her words, 17. who forsakes the companion of her youth, and forgets the covenant of her God. 18. For her house leads down to death, and her paths to the dead.","Matthew 23:15":"\u201CWoe to you, scribes and Pharisees, hypocrites! For you travel land and sea to win one proselyte, and when he is won, you make him twice as much a son of \u05D2\u05B5\u05D9\u05D0 as yourselves.\u201D","Matthew 12:32 (CJB)":"And whoever says something against the Son of Man will be forgiven; but whoever speaks against the Ruach HaKodesh will not be forgiven, neither in the \u2018olam hazeh nor in the \u2018olam haba.","Matthew 7:13":"\u201CEnter by the narrow gate; for wide is the gate and broad is the way that leads to destruction, and there are many who go in by it.\u201D","Matthew 23:27":"\u201CWoe to you, scribes and Pharisees, hypocrites! For you are like whitewashed tombs which indeed appear beautiful outwardly, but inside are full of dead men\u2019s bones and all uncleanness.\u201D","Matthew 7:19":"\u201CEvery tree that does not bear good fruit is cut down and thrown into the fire.\u201D","Matthew 23:9 (NLT)":"And don\u2019t address anyone here on earth as \u2018Father,\u2019 for only God in heaven is your Father.","1 Timothy 4:7":"But reject profane and old wives\u2019 fables, and exercise yourself toward godliness.","Jeremiah 7:28, Isaiah 59:14":"Jeremiah 7:28 \u2014 \u201CSo you shall say to them, \u2018This is a nation that does not obey the voice of the LORD their God nor receive correction. Truth has perished and has been cut off from their mouth.\u2019\u201D | Isaiah 59:14 \u2014 Justice is turned back, and righteousness stands afar off; for truth is fallen in the street, and equity cannot enter."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Beware, O peoples of the church called Mother. For she is a harlot, a false way, a deceitful house filled with both great and subtle deceptions. Be wary, rouse yourselves from this heavy sleep, and look upon the fruit of your doings. For you have been greatly misled, caught up in a faith which is dead; there is no life in it! For as it was written by My servant, so in like manner I now plead with you: "},{t:"italic",v:"Depart from the way of evil, from the man who speaks perverse things, from those who leave the paths of uprightness to walk in the ways of darkness, who rejoice in doing evil and delight in the perversity of the pagan, whose ways are crooked and who are devious in their paths. Be delivered from the adulterous woman, from the seductress who flatters with her words, who forsakes the husband of her youth and forgets the covenant of her God. For her house is sinking down to death, and all her paths lead to the dead."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord God, The Holy One of Israel, to all who have ears to hear:"},{t:"text",v:" This unholy church of men is a harlot! From the beginning she has been a whore! Yet she would have all believe she is a queen, even the true church and mother. Indeed, she has bore many sons and daughters, daughters who yet bear her likeness; and many sons who shall go to perdition, false fathers"},{t:"fn",v:"2"},{t:"text",v:" and priests, who by their own authority take to themselves proselytes, who they then make twice as fit for destruction as themselves!"},{t:"fn",v:"3"},{t:"text",v:" Behold, deception is hidden within deception, as she continues to build up her sins toward heaven."}]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you a mystery filled with corruption,"}],[{t:"italic",v:"Abuse of power and contemptible ways:"}],[{t:"stanza-break"}],[{t:"text",v:"This church of men is like the woman who rides the beast;"}],[{t:"text",v:"She is clothed with purple and scarlet, enticing the"}],[{t:"text",v:"People to commit fornication with her..."}],[{t:"stanza-break"}],[{t:"text",v:"Yet to her own, she is a queen who sits upon"}],[{t:"text",v:"My throne and has taken to herself My authority,"}],[{t:"text",v:"Perverting My Word and changing My Commandments"}],[{t:"text",v:"As she appoints kings and princes in her own name,"}],[{t:"text",v:"Each with names of blasphemy upon their heads,"}],[{t:"text",v:"So-called holy fathers who shall go into perdition with her..."}],[{t:"stanza-break"}],[{t:"italic",v:"And yet to those against her, she is the beast."}]]},{type:"para",segments:[{t:"text",v:"Yet I tell you the truth, all are deceived. For her power and authority come from the beast, which atop she sits. For she has many names of blasphemy, and all her works are an abomination before The Lord. She is indeed a harlot, and her adulteries are many. Behold, she is also like the great whore who sits upon many waters, who has corrupted the earth with her fornications. And like the false prophet she spews perverse and bitter doctrine, leading many into false worship, even to the committing of fornication with the pagan and the heathen by all her filthy traditions! And like the beast, she has shed the blood of My servants throughout her generations, and has not ceased from opening her mouth to speak great things and blasphemies with a practiced and lying tongue, by which she has deceived many. Therefore, I must take My people out of her! Behold, I shall snatch them from her very breast! For she is also like Babylon, adorning herself with gold and precious stones and pearls, having in her hand a golden cup full of abominations and the filthiness of her fornications."},{t:"fn",v:"4"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God, The Holy One of Israel, to all who have ears to hear:"},{t:"text",v:" Woe, I say to you! Even three times, woe! For the atheist shall have it far better than you, when the wrath of the great and dreadful God has come! For when they seek forgiveness, they shall surely find it. Yet woe to you who blaspheme the Spirit; from you forgiveness has fled away!"},{t:"fn",v:"5"},{t:"text",v:" Behold, destruction waits for you as you continue to tread the wide path!"},{t:"fn",v:"6"}]},{type:"para",segments:[{t:"text",v:"For you believe yourself to be a glorious vine, yet your roots are full of rottenness, a vine of deceit with many tendrils spreading forth abomination! Behold, you see yourself as a sovereign nation, as the mother church, universal, and yet you willingly go into captivity and hold fast in your rebellion! Therefore, I shall make you a desolation and an astonishment, an object of horror and hissing; I shall strip you bare!"}]},{type:"para",segments:[{t:"text",v:"And behold, you shall become an island, a most desolate place amidst the nations. No more shall anyone draw near to you, nor shall any attempt to pass through. For all shall keep their distance for fear of your punishment. Every traveler shall go roundabout, horrified at the smoke of your burning."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:" I have set you apart for judgment! I have separated you out for death, for sorrow and for famine, until the fire of My wrath consumes you! For you have caused My beloved to depart from Me; you have turned them aside from The Way! You have caused them to trust in fables and to put their hope in lies and false visions, in worthless things!"},{t:"fn",v:"7"},{t:"text",v:" The Truth is not in you, and from The Life you are far removed!"},{t:"fn",v:"8"}]},{type:"para",segments:[{t:"text",v:"You have pierced My heart with a hot iron! You have battered and bruised Me, and torn My flesh! My sadness fills the heavens like the unending blackness, My tears cover the earth like the oceans, because of you! My anger wells up within Me like a raging fire, on account of all these you have persecuted and murdered throughout your generations!"}]},{type:"para",segments:[{t:"text",v:"Indeed, the cup of My indignation overflows, on account of all you have done and are about to do, says The Lord. And still I sent to you many in My own name, that you might be saved from yourself. Yet you rejected them all, beating some and killing others, casting them out in your pompous rage. You will not turn, and so The Father has declared your end."}]},{type:"poetry",lines:[[{t:"bold-italic",v:"WOE TO THE CHURCH CALLED MOTHER!"}],[{t:"bold-italic",v:"WOE TO YOU AND YOUR APPOINTED LEADERS!"}],[{t:"bold-italic",v:"WOE TO YOU AND ALL YOUR \u201CHOLY FATHERS\u201D!"},{t:"fn",v:"9"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"bold-italic",v:"WOE TO THE CHURCH CALLED ROMAN AND CATHOLIC!"}],[{t:"bold-italic",v:"WOE TO THE CHURCH FULL OF DEAD MEN\u2019S BONES!"},{t:"fn",v:"10"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"text",v:"For I have prepared a great fire, and behold, it is already kindled,"}],[{t:"text",v:"And you, along with all who cleave to you, shall surely be cast into it!"},{t:"fn",v:"11"},{t:"text",v:"..."}]]},{type:"closing",text:"SAYS THE LORD."}],prevLetter:{id:"it-is-time",title:"It Is Time... Prepare to Meet Your God"},nextLetter:{id:"hearts-changed",title:"Hearts Changed"}},{id:"hearts-changed",num:11,title:"Hearts Changed",date:"7/2/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/hearts-changed-4",videoVoiceUrl:"https://www.youtube.com/watch?v=M6d-k5oUnfo&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=11",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],footnotes:{1:{type:"scripture",ref:"Romans 1:20"},2:{type:"scripture",ref:"Matthew 21:44"},3:{type:"scripture",ref:"John 14:27"},4:{type:"scripture",ref:"Matthew 5:6"}},nkjv:{"Romans 1:20":"For since the creation of the world His invisible attributes are clearly seen, being understood by the things that are made, even His eternal power and Godhead, so that they are without excuse,","Matthew 21:44":"\u201CAnd whoever falls on this stone will be broken; but on whomever it falls, it will grind him to powder.\u201D","John 14:27":"\u201CPeace I leave with you, My peace I give to you; not as the world gives do I give to you. Let not your heart be troubled, neither let it be afraid.\u201D","Matthew 5:6":"\u201CBlessed are those who hunger and thirst for righteousness, for they shall be filled.\u201D"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:" My son, why do you focus on that which others can not see or hear? Rather rejoice, Timothy, for I have given you eyes to see and ears to hear. Behold, all the earth proclaims the glory of The Lord, and the whole of creation testifies to the truth of who I am."},{t:"fn",v:"1"},{t:"text",v:" Yet the truth remains hidden from the multitudes, and the testimony dwells not in the hearts of men."}]},{type:"para",segments:[{t:"text",v:"Timothy, be not downhearted over your loved ones who reject Me and My Word, for they have no understanding. Their hearts remain hard and unyielding, their vision marred and narrow, their minds closed, held captive in a world which rejects God and refuses to accept Me as I truly am. Yet they shall harken in due season, wholeheartedly will they come, once their shells are cracked and they too are broken atop The Stone"},{t:"fn",v:"2"},{t:"text",v:"... "},{t:"italic",v:"A flood of tears washing away every hurt, absolving every sin, bringing peace the kind of which only The Lord can give."},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"text",v:"For that which they have wrought inwardly"}],[{t:"text",v:"Has become a desert of arid sands,"}],[{t:"text",v:"False hope and great iniquity,"}],[{t:"text",v:"A wasteland of scattered stones"}],[{t:"text",v:"Over which they continually stumble..."}],[{t:"stanza-break"}],[{t:"text",v:"Yet I tell you the truth, they shall bring forth"}],[{t:"text",v:"A bounty in their time, as does the desert"}],[{t:"text",v:"After the much needed rains have come..."}],[{t:"stanza-break"}],[{t:"text",v:"For the desolate shall come to realize"}],[{t:"text",v:"Their need, and those who hunger and thirst"}],[{t:"text",v:"For righteousness shall surely receive"},{t:"fn",v:"4"},{t:"text",v:"..."}]]},{type:"closing",text:"I AM THE LORD."}],prevLetter:{id:"woe-to-the-church",title:"Woe to the Church Called Roman and Catholic"},nextLetter:{id:"the-lord-comes-nigh",title:"The Lord Comes Nigh; Make the Way Straight for His Return"}},{id:"the-lord-comes-nigh",num:12,title:"The Lord Comes Nigh; Make the Way Straight for His Return",date:"7/3/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-lord-comes-nigh-make-the-way-straight-for-his-return",videoVoiceUrl:"https://www.youtube.com/watch?v=4r5oSybwqas&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=12",relatedTopics:[{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"}],footnotes:{1:{type:"scripture",ref:"Genesis 35:10"},2:{type:"scripture",ref:"John 3:16"},3:{type:"scripture",ref:"John 1:14"},4:{type:"scripture",ref:"Matthew 1:23"},5:{type:"note",text:"Matthew 3",url:"https://www.biblegateway.com/passage/?search=Matthew+3&version=NKJV"},6:{type:"note",text:"See: \u201CRegarding the 144,000 Witnesses\u201D",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},7:{type:"scripture",ref:"Luke 1:17"},8:{type:"note",text:"Zechariah 6:9-13 \u2014 In Zechariah 6:11, the original Hebrew word for Joshua is Yahushua (\u05D9\u05D4\u05D5\u05E9\u05E2)",url:"https://www.blueletterbible.org/hnv/zec/6/9/"}},nkjv:{"Genesis 35:10":"Also God said to him: \u201CYour name is Jacob; your name shall not be called Jacob anymore, but Israel shall be your name.\u201D So He called his name Israel.","John 3:16":"For God so loved the world that He gave His only begotten Son, that whoever believes in Him should not perish but have everlasting life.","John 1:14":"And the Word became flesh and dwelt among us, and we beheld His glory, the glory as of the only begotten of the Father, full of grace and truth.","Matthew 1:23":"\u201CBehold, the virgin shall be with child, and bear a Son, and they shall call His name Immanuel,\u201D which is translated, \u201CGod with us.\u201D","Luke 1:17":"He will also go before Him in the spirit and power of Elijah, \u2018to turn the hearts of the fathers to the children,\u2019 and the disobedient to the wisdom of the just, to make ready a people prepared for the Lord."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to the peoples of the earth:"},{t:"text",v:" In My right hand is the power to save; and in My left, judgment, which I am about to pour out. For I am The Lord your God, The Only God, The God of Abraham, The God of Isaac, and of Jacob whose name is Israel."},{t:"fn",v:"1"},{t:"text",v:" And behold, I sent My Only Begotten into the world,"},{t:"fn",v:"2"},{t:"text",v:" and The Word became flesh,"},{t:"fn",v:"3"},{t:"text",v:" YahuShua, Immanu El."},{t:"fn",v:"4"}]},{type:"para",segments:[{t:"text",v:"Again, I am sending The Holy One to you. Therefore incline your ears and listen, that you may receive true knowledge. For as it was at the first, so shall it be at the last, for I do not change."}]},{type:"para",segments:[{t:"text",v:"Behold, ahead of The Messiah did I send John the Baptist, the voice of one crying out in the wilderness."},{t:"fn",v:"5"},{t:"text",v:" In John\u2019s hand I had placed the trumpet; and he made the path straight in preparation of The One coming after him, by whom all must be saved. John indeed baptized with water and with the Word given him. And now I am sending 144,000,"},{t:"fn",v:"6"},{t:"text",v:" in the spirit of John and in the power of Elijah,"},{t:"fn",v:"7"},{t:"text",v:" to baptize with the Word of God and fire. For I have placed My words in their mouths, and the Trumpet rests securely in their hands."}]},{type:"para",segments:[{t:"text",v:"Therefore trust these I have sent and am sending, for they are My witnesses; they hear My voice and prepare My way before Me. For My judgments shall fall from Heaven, upon every tribe, tongue, people and nation; My punishments shall rain down hard upon the earth and break the pride of man! Behold, I shall remove all from their places; in My fierce anger I shall drive them out! The cities shall be laid waste and the houses shall be left desolate, for the earth shall become one vast desolation!"}]},{type:"poetry",lines:[[{t:"text",v:"Yet there is sanctuary from this storm,"}],[{t:"text",v:"A way of escape has been provided;"}],[{t:"stanza-break"}],[{t:"text",v:"For He is called Jesus and Christ;"}],[{t:"text",v:"YahuShua"},{t:"fn",v:"8"},{t:"text",v:" HaMashiach is His name!..."}],[{t:"stanza-break"}],[{t:"text",v:"Call upon Him, do not wait!..."}],[{t:"stanza-break"}],[{t:"text",v:"Call upon His name in sincerity and in truth,"}],[{t:"text",v:"And you shall surely be delivered..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"hearts-changed",title:"Hearts Changed"},nextLetter:{id:"the-mark",title:"The Mark"}},{id:"the-mark",num:13,title:"The Mark",date:"7/7/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-mark",videoVoiceUrl:"https://www.youtube.com/watch?v=eNds6FfIcgc&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=13",relatedTopics:[{label:"Regarding the Mark of the Beast",url:"https://answersonlygodcangive.com/Regarding_the_Mark_of_the_Beast"},{label:"Regarding the Antichrist",url:"https://answersonlygodcangive.com/Regarding_the_Antichrist"}],footnotes:{1:{type:"scripture",ref:"Revelation 13:16-17"},2:{type:"scripture",ref:"Revelation 13:16"},3:{type:"scripture",ref:"Revelation 13:17"},4:{type:"scripture",ref:"Amos 3:7"},5:{type:"scripture",ref:"2 Thessalonians 2:3 (NKJV)"},6:{type:"scripture",ref:"Revelation 1:18 (HNV & CEB)"},7:{type:"scripture",ref:"John 8:36"}},nkjv:{"Revelation 13:16-17":"16. He causes all, both small and great, rich and poor, free and slave, to receive a mark on their right hand or on their foreheads, 17. and that no one may buy or sell except one who has the mark or the name of the beast, or the number of his name.","Revelation 13:16":"He causes all, both small and great, rich and poor, free and slave, to receive a mark on their right hand or on their foreheads,","Revelation 13:17":"and that no one may buy or sell except one who has the mark or the name of the beast, or the number of his name.","Amos 3:7":"Surely the Lord GOD does nothing, unless He reveals His secret to His servants the prophets.","2 Thessalonians 2:3 (NKJV)":"Let no one deceive you by any means; for that Day will not come unless the falling away comes first, and the man of sin is revealed, the son of perdition,","Revelation 1:18 (HNV & CEB)":"HNV \u2014 and the Living one. I was dead, and behold, I am alive forevermore. Amein. I have the keys of Death and of She'ol. | CEB \u2014 and the living one. I was dead, but look! Now I'm alive forever and always. I have the keys of Death and the Grave.","John 8:36":"Therefore if the Son makes you free, you shall be free indeed."},blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a brother in Christ: Lord, what is the mark of the beast, in the Bible?"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"bold-italic",v:"[The Lord answered]"},{t:"text",v:" My son, why ask of Me such things? Rather, consider the marks you have taken. Are you clean? Where does your allegiance lie? Is it given to the things of men and to the lusts of this world? Or does it belong to God, longing always to know the deep things of Messiah, whom you call Christ? Therefore, seek first your own salvation; dwell not on outward things of evil. For evil has lost its grip on the redeemed."}]},{type:"para",segments:[{t:"text",v:"Yet for the sake of all those who shall come to read these words, I shall answer you, that they may hear and know and remember: The mark, this mark of the beast, is a choice, a grave error. Yet as of this day, it remains merely an invention of man, a device, a stamp. Yet there is an evil one among men who will gain power and much prestige, who will force everyone \u2014 great and small, rich and poor, free and slave \u2014 to receive a mark in his right hand or on his forehead."},{t:"fn",v:"2"},{t:"text",v:" The technology exists; its production has commenced. Thus that which was created for good shall be used for evil, that the few may gain control over the many, that no one may buy or sell unless they have the mark, that is, the name of the beast or the number of its name, as it is written."},{t:"fn",v:"3"}]},{type:"para",segments:[{t:"text",v:"My son, what you seek concerning the end of the age, I have already given to My servant, John, written in the book called Revelation. And that which was given to John, I now bestow upon My servant, Timothy, that all those who have ears to hear may hear the sound of this Trumpet and escape, for the Day is at hand. For as it is written: "},{t:"italic",v:"The Lord God does nothing without revealing His plans to His servants, the prophets."},{t:"fn",v:"4"}]},{type:"para",segments:[{t:"text",v:"Therefore that which you have considered, and that which you have heard, is true. And oh how modern man glories in his own creations, taking much pride in the inventions of his mind. Look how he revels in the works of his hands. Yet they shall be his undoing, for even now he has brought destruction upon his own head. For in his pride he has opened the door to the evil one, and on account of his great arrogance has he made it possible for the man of perdition"},{t:"fn",v:"5"},{t:"text",v:" to rule over him; by his own works he has condemned himself to death!"}]},{type:"para",segments:[{t:"italic",v:"Why, O peoples of the earth, do you forge shackles and secure them about your feet?! I tell you the truth, you are all captives, slaves to your own evil thoughts and desires! Therefore, forsake all this madness and return to Me! Call upon My name in sincerity and in truth, and you shall truly be free! For I hold all the keys; even over death and Sheol do I have complete authority."},{t:"fn",v:"6"},{t:"italic",v:" For as it is written: If The Son sets you free, you are free indeed!"},{t:"fn",v:"7"},{t:"italic",v:" Says The Lord."}]}],prevLetter:{id:"the-lord-comes-nigh",title:"The Lord Comes Nigh; Make the Way Straight for His Return"},nextLetter:{id:"all-shall-reap",title:"All Shall Reap That Which They Have Sown, Be It of Good or Evil"}},{id:"all-shall-reap",num:14,title:"All Shall Reap That Which They Have Sown, Be It of Good or Evil",date:"7/8/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/all-shall-reap-that-which-they-have-sown-be-it-of-good-or-evil",videoVoiceUrl:"https://www.youtube.com/watch?v=B0gAACKfONk&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=14",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],footnotes:{1:{type:"scripture",ref:"Galatians 6:7"},2:{type:"scripture",ref:"1 Corinthians 3:13-15"},3:{type:"scripture",ref:"Matthew 15:9"}},nkjv:{"Galatians 6:7":"Do not be deceived, God is not mocked; for whatever a man sows, that he will also reap.","1 Corinthians 3:13-15":"13. each one\u2019s work will become clear; for the Day will declare it, because it will be revealed by fire; and the fire will test each one\u2019s work, of what sort it is. 14. If anyone\u2019s work which he has built on it endures, he will receive a reward. 15. If anyone\u2019s work is burned, he will suffer loss; but he himself will be saved, yet so as through fire.","Matthew 15:9":"\u201CAnd in vain they worship Me, teaching as doctrines the commandments of men.\u201D"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord concerning those who have ears yet refuse to hear, who have eyes yet refuse to see:"},{t:"text",v:" Only those with hearts left desolate are filled with contempt. For they have not received the love of the Truth, nor do they accept Me as I truly am. Rather they hide behind corrupt doctrine and filthy tradition, covering themselves with pretense, in an attempt to shield themselves from My correction. With practiced speech and a lying tongue they twist the Scriptures, behold, they rend the Word of God, for the sake of their own pride. For they do not know Me, neither do I live in them. Thus they willingly believe the lies, and seek always to uphold the commandments of men, as they slander those sent to them."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord, to those who dwell in the churches of men and to all their self-appointed leaders:"},{t:"text",v:" Why do you not receive Me?! Indeed you are unable, for you do always push out the hand! Behold, I send to you a mere man, that you might receive of My correction, yet you say he has a demon! You do always fight against Me!"}]},{type:"para",segments:[{t:"text",v:"Behold, this Word is Truth, the very will of The Father made known, the Word of The Lord put forth through His prophets once again. Yet you cry, "},{t:"italic",v:"\u201CFalse!\u201D"},{t:"text",v:" because you find they run contrary to your preconceived notions and beliefs, as though you and your established doctrine were somehow above reproach; all the while setting up walls of falsehood, laying down traps of deceit to bar My way before Me, seeking always to fortify your position, lest I expose your masquerade."}]},{type:"para",segments:[{t:"text",v:"O people of little faith, you are deceived; you have all been turned aside from the Truth! Churches of men, your doctrines are corrupt, your every tradition unclean, born of men and the harlot! She has deceived you, and yet you willingly walk in her ways! Throughout her generations she has deceived the people; in her lust for power she has oppressed them, forcing multitudes to embrace the crooked path! She is a harlot, her ways antichrist, and yet you follow her! Behold, by her own power and authority, of which she appointed to herself, she endeavored to change My Commandments! Yet you nod your head in agreement, yes, you obey her teachings as you forsake My Sabbaths, upholding many of the same false doctrines and perverse traditions I hate!"}]},{type:"poetry",lines:[[{t:"text",v:"Therefore, O churches of men, your discipline"}],[{t:"text",v:"Shall be severe and your abasement terrible!..."}],[{t:"stanza-break"}],[{t:"text",v:"And you, O church of harlots, shall be"}],[{t:"text",v:"Stripped naked and brought to ruin!"}],[{t:"text",v:"Behold, you shall be torn in pieces and left"}],[{t:"text",v:"Utterly desolate, to the astonishment of all people!..."}],[{t:"stanza-break"}],[{t:"italic",v:"For I do not change! Says The Lord."}]]},{type:"para",segments:[{t:"bold-italic",v:"So then listen closely and give ear, all you who call of yourselves Christian, all you who stone My prophets and slander those sent to you, all you who abuse My Word in Scripture and desecrate My Sabbaths; hear the Word of The Lord and give heed, be bowed down, for the mouth of The Living God has spoken:"},{t:"text",v:" ALL YOU SOW, YOU SHALL REAP!"},{t:"fn",v:"1"},{t:"text",v:" Repent, therefore! Again I say, repent, lest you also catch fire as you watch all your works burn in the Day!"},{t:"fn",v:"2"},{t:"text",v:" For My anger is kindled against you, O churches of men! And My wrath grows in its fury, against ALL who lead My people astray!"}]},{type:"poetry",lines:[[{t:"text",v:"Therefore call upon My name, in sincerity and in truth!..."}],[{t:"stanza-break"}],[{t:"text",v:"Beloved ones, embrace Me as I am,"}],[{t:"text",v:"And not as you would have Me be!"}],[{t:"text",v:"Obey MY teaching and turn away"}],[{t:"text",v:"From the commandments of men!"},{t:"fn",v:"3"},{t:"text",v:"..."}],[{t:"stanza-break"}],[{t:"text",v:"For I, alone, am The Way and The Truth,"}],[{t:"text",v:"The Life without end..."}]]},{type:"closing",text:"Says The Lord YahuShua."}],prevLetter:{id:"the-mark",title:"The Mark"},nextLetter:{id:"the-true-baptism",title:"The True Baptism"}},{id:"the-true-baptism",num:15,title:"The True Baptism",date:"7/10/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",addendum:'"Be Baptized in The Living Waters of Spirit and Truth"',addendumUrl:"https://www.thevolumesoftruth.com/Be_Baptized_in_The_Living_Waters_of_Spirit_and_Truth",addendumLink:{collection:"Volume One",letterTitle:"Be Baptized in The Living Waters of Spirit and Truth"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-true-baptism",videoVoiceUrl:"https://www.youtube.com/watch?v=HtUbJbQJwsg&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=15",relatedTopics:[{label:"Regarding Baptism",url:"https://answersonlygodcangive.com/Regarding_Baptism"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"False Doctrines Within the Churches of Men Regarding - Baptism",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"The Coming of The Lord - \u201CI Am Coming Quickly\u201D",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_Am_Coming_Quickly"}],footnotes:{1:{type:"scripture",ref:"2 Timothy 2:15 (KJV)"}},nkjv:{"2 Timothy 2:15 (KJV)":"Study to shew thyself approved unto God, a workman that needeth not to be ashamed, rightly dividing the word of truth."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Be wary of all these men in authority who dwell in the churches of men, be wary and vigilant. For they hold tightly to singleness of doctrine, teaching always that which is built upon the corrupt knowledge and understanding of men, men who refuse to let go of that which was passed down to them by their forefathers, by which they also remain blind. Therefore do not judge according to human standards, nor by that which is put forth by men as doctrine, for they are greatly misled. Rather study to show yourself approved unto God, a workman that need not be ashamed, rightly dividing the Word of Truth."},{t:"fn",v:"1"},{t:"text",v:" For discernment with fear is righteousness."}]},{type:"para",segments:[{t:"text",v:"Beloved ones, embrace the wisdom and knowledge of God, break free from all these corrupt doctrines and filthy traditions held in such high regard. For I ask you, if you dispense the food of God to the hungry, while using your own salt to salt that which has salt in itself, will not the food you offer lose its flavor and become bitter in the mouths of those who came looking to be fed?"}]},{type:"para",segments:[{t:"text",v:"I tell you the truth, many will there be in My Kingdom who received no baptism by water. Rather they had been fully immersed in The Word of God, enveloped in The Son\u2019s sacrifice and love, baptized in the Spirit of Truth. For most assuredly, I say to you, they have their reward. Therefore, do not cast stumbling blocks before the feet of those who love Me. Be one in Messiah, according to that which dwells inwardly in the heart. For true fellowship comes not by words spoken amongst a group of united people, nor by immersion in water. Rather it starts with the heart, and is found in the stillness of My spirit, where My peace mends the broken and My gentle caress gladdens the heart. For all those found at the feet of The Lord are covered with grace, and those who abide in My love are indeed of one accord."}]},{type:"para",segments:[{t:"text",v:"Beloved, where in The Commandments have I written all must be baptized by men to be saved? Baptism is indeed good, if it is a confession poured out from one\u2019s heart in pure belief, an outward act of faith revealing one\u2019s acceptance of their forgiveness in The Messiah. For the water of the earth can only cleanse that which is soiled on the skin. By no means can it cleanse that which is soiled in the spirit; this is reserved for the blood of The Lamb. Again I say to you, baptism by water is nothing, unless one is first washed by The Word, being baptized in the Spirit of Grace and Truth which is received in YahuShua HaMashiach, whom you call Jesus and Christ. For HE is The True Baptism, The Very Water of Life, in which all must be cleansed to receive everlasting life."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore beloved, remember:"}],[{t:"text",v:"The spirit of the Word, and not the letter,"}],[{t:"text",v:"Is the way, the truth and the life..."}],[{t:"stanza-break"}],[{t:"text",v:"For The Messiah is indeed coming quickly,"}],[{t:"text",v:"To baptize all in fire and glory..."}],[{t:"stanza-break"}],[{t:"text",v:"Those of a wicked heart, in fire..."}],[{t:"stanza-break"}],[{t:"text",v:"And those of the Spirit, in glory, forever and ever!"}]]}],prevLetter:{id:"all-shall-reap",title:"All Shall Reap That Which They Have Sown, Be It of Good or Evil"},nextLetter:{id:"all-have-been-purchased",title:"All Have Been Purchased... Yet Few Have Accepted, Few Are Chosen"}},{id:"all-have-been-purchased",num:16,title:"All Have Been Purchased... Yet Few Have Accepted, Few Are Chosen",date:"8/19/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",addendum:'"Grafted In"',addendumUrl:"https://www.thevolumesoftruth.com/Grafted_In",addendumLink:{collection:"Volume Three",letterTitle:"Grafted In"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/all-have-been-purchased-yet-few-have-accepted-few-are-chosen",videoVoiceUrl:"https://www.youtube.com/watch?v=ixPYkoBp8pM&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=16",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Woe to Those Who Come Against God\u2019s Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Regarding Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"},{label:"Regarding Being Born Again",url:"https://answersonlygodcangive.com/Regarding_Being_Born_Again"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],footnotes:{1:{type:"scripture",ref:"Revelation 14:4 (KJV)"},2:{type:"scripture",ref:"Revelation 14:1-4 (NLT)"},3:{type:"scripture",ref:"Revelation 14:1"},4:{type:"scripture",ref:"Matthew 15:18"},5:{type:"note",text:"Also See: John 9:6-7",url:"https://www.biblegateway.com/passage/?search=John+9%3A6-7&version=NKJV"}},nkjv:{"Revelation 14:4 (KJV)":"These are they which were not defiled with women; for they are virgins. These are they which follow the Lamb whithersoever he goeth. These were redeemed from among men, being the firstfruits unto God and to the Lamb.","Revelation 14:1-4 (NLT)":"1. Then I saw the Lamb standing on Mount Zion, and with him were 144,000 who had his name and his Father\u2019s name written on their foreheads. 2. And I heard a sound from heaven like the roar of mighty ocean waves or the rolling of loud thunder. It was like the sound of many harpists playing together. 3. This great choir sang a wonderful new song in front of the throne of God and before the four living beings and the twenty-four elders. No one could learn this song except the 144,000 who had been redeemed from the earth. 4. They have kept themselves as pure as virgins, following the Lamb wherever he goes. They have been purchased from among the people on the earth as a special offering to God and to the Lamb.","Revelation 14:1":"Then I looked, and behold, a Lamb standing on Mount Zion, and with Him one hundred and forty-four thousand, having His Father\u2019s name written on their foreheads.","Matthew 15:18":"But those things which proceed out of the mouth come from the heart, and they defile a man."},blocks:[{type:"intro",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, what does it mean in the Book of Revelation, where it says, \u201CThe 144,000 did not defile themselves with women; they kept themselves pure\u201D?"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:" Rather the 144,000 have been purchased, redeemed and chosen from the earth as a special offering, and are spiritually undefiled, pure as virgins."},{t:"fn",v:"2"},{t:"text",v:" Timothy, you have asked, and I have answered you plainly. Thus I tell you, you are of the number, I have already placed you within their ranks; My seal is upon your forehead."},{t:"fn",v:"3"}]},{type:"para",segments:[{t:"text",v:"Yet those who envy seek to cause doubt, by questioning your worthiness and defilement with women. And because of this, they reject My Word spoken to this generation. Therefore they remain in their sins, for they want no part with Me as I truly am. They have removed themselves far from Me, and seek to draw others away also, that they might feel validated in their unjust cause. Yet who The Lord has cleansed is worthy of His purpose; call him not unworthy or defiled. For that which comes from the heart of man does indeed defile the man,"},{t:"fn",v:"4"},{t:"text",v:" yet that which comes from God is holy."}]},{type:"para",segments:[{t:"text",v:"Therefore fear, all you who point the finger, and humble yourselves, all you who twist My words for your own gain, lest you be found guilty of blaspheming the Holy Spirit. For the defilement which was written, and remains misinterpreted by men, is not defilement with the daughters of men, but defilement with the churches of men, who remain daughters of the church called Mother. For she is a harlot, says The Lord. Thus spiritual purification begins with grace, and is for those whom I have chosen to become virgin in spirit, even a complete cleansing of every aspect of their lives."}]},{type:"poetry",lines:[[{t:"text",v:"All men are defiled, having fallen"}],[{t:"text",v:"Into all manner of diverse temptations;"}],[{t:"text",v:"There is none righteous in all the earth, no, not one..."}],[{t:"stanza-break"}],[{t:"text",v:"Yet all who repent, in sincerity and in truth,"}],[{t:"text",v:"Are cleansed in the blood of The Lamb,"}],[{t:"text",v:"Which is pure and holy..."}],[{t:"stanza-break"}],[{t:"text",v:"Therefore, those whom I have called to be My witnesses"}],[{t:"text",v:"Must become pure in heart and in spirit;"}],[{t:"text",v:"Set apart from the world and the churches of men,"}],[{t:"text",v:"Who cease not from polluting My name"}],[{t:"text",v:"And marring My image before the people."}]]},{type:"para",segments:[{t:"text",v:"Timothy, you have not sat among the prideful, nor have you kept the company of those deceived in the churches of men. You have accepted no doctrine at all. Indeed, you were like clay which had been molded by the world, yet remained unmolded in spirit. Behold, even when you were yet in your mother\u2019s womb, I sanctified you; I ordained you a prophet, a witness for My name, an enemy to all nations. Thus you put no faith in the doctrines of the world, nor did you accept any doctrine taught in the churches of men. As for your body and mind, yes, you did become defiled by sin, of this you were guilty, as are all who have gained maturity. Yet I have taken your sins from you and remember your iniquities no more. Therefore, I ask you, what defilement remains? For what The Lord has cleansed, in the blood of The Lamb, is a new creation \u2014 "},{t:"italic",v:"virgin."}]},{type:"para",segments:[{t:"text",v:"Behold, I am the same yesterday, today, and all tomorrows to come, says The Lord. No contradiction found. Thus all error belongs to men, exploited by the wicked one for his own evil purpose. Therefore, what I have written I have written; it stands. And that which I have written through My servant, John, stands also, though it is greatly misinterpreted, the error of which is compounded by the mistranslations of men."}]},{type:"para",segments:[{t:"text",v:"Yet worse still is the interpretation of My Word by men of intellect and learning, who shroud their arrogance in pretense and hide their error under the guise of established doctrine \u2014 unprofitable servants who lead My people astray. For My Word is for all who truly seek Me and long to know My ways, even to walk in them. Thus My Word can only be accepted and understood by those who have received the love of the Truth, for they abide in Me and My spirit resides within them. For how can one who stands apart from Me know Me? And how can one who teaches his own way walk with Me in Mine?"}]},{type:"para",segments:[{t:"text",v:"Men do not have understanding of the Scriptures in themselves! Rather it is a gift from God, received through the Holy Spirit, given to those who have placed all their trust in The Holy One, embracing Me as I truly am. Or have you never read this Scripture: "},{t:"italic",v:"The fear of The Lord is the beginning of wisdom, and the knowledge of The Holy One is understanding?"},{t:"text",v:" Therefore to those who have received is all revealed, and to those who have not received is all shut away. Shall the darkness understand the light? For only those of The Light, bathed in His glory, shall see; the rest left blinded."}]},{type:"poetry",lines:[[{t:"text",v:"For until one calls on the name of The Messiah,"}],[{t:"text",v:"In sincerity and in truth, by no means shall they receive..."}],[{t:"stanza-break"}],[{t:"text",v:"For He is The One who had placed"}],[{t:"text",v:"The mud upon their eyes to heal them..."}],[{t:"stanza-break"}],[{t:"text",v:"Behold, He is also The Water of Siloam"}],[{t:"text",v:"Which was sent to wash them,"}],[{t:"text",v:"That they might now see..."},{t:"fn",v:"5"}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"the-true-baptism",title:"The True Baptism"},nextLetter:{id:"abortion-murder",title:"Abortion: Murder of the Innocent"}},{id:"abortion-murder",num:17,title:"Abortion: Murder of the Innocent",date:"8/23/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/abortion-murder-of-the-innocent",videoVoiceUrl:"https://www.youtube.com/watch?v=ntxLXO4hlnU&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=16",videoMusicUrl:"https://www.youtube.com/watch?v=8k_itT2KBg0&list=PLSVchFJ22QYKZW4CHtZ43YBxdHUTgS9rv&index=5",relatedTopics:[{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Take No Part",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Take_No_Part"},{label:"Woe to Those Who\u2026",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"}],footnotes:{},nkjv:{},blocks:[{type:"para",segments:[{t:"caps",v:"WOE TO THOSE WHO HARM THE LITTLE ONES! WOE TO THOSE WHO SLAUGHTER MY GIFTS! AND WOE TO ALL WHO STAND IN AGREEMENT!"},{t:"text",v:" Says The Lord. For they are and were created, sculpted delicately in fragile flesh, attached to The Vine before their very conception. For it is the fool who says in her heart, "},{t:"italic",v:"\u201CThere is no God,\u201D"},{t:"text",v:" believing she answers only to herself, as she testifies aloud, saying, "},{t:"italic",v:"\u201CIt is my body, my choice.\u201D"},{t:"text",v:" "},{t:"caps",v:"YOU CHOOSE DEATH!"},{t:"text",v:" Says The Lord. For the child within you is Mine, even as you are Mine also; your body is not your own! "},{t:"caps",v:"ALL BELONG TO THE LORD, ALL ANSWER TO ME!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:" The murder of the innocent leads to the death of the guilty, who carry the innocent within them; take no part in their sin. For all who do wear equally the guilt of the mother, all seek the penalty of death; from the lawmakers to the voters, to the building owner to the workers to the suppliers, and finally to the father, if he does not take a stand to protect the unborn who are without blame. Behold, they have brought the wrath of God upon their nation, upon their state and upon their cities, calamity upon calamity until I have laid them waste!"}]},{type:"poetry",lines:[[{t:"italic",v:"Fierce is My anger, hot is My countenance!"}],[{t:"italic",v:"My little ones perish in all the earth!"}],[{t:"stanza-break"}],[{t:"caps",v:"WHOLE GENERATIONS SLAUGHTERED!"}],[{t:"caps",v:"MULTITUDES OF CHILDREN MURDERED"}],[{t:"caps",v:"DAY AND NIGHT, WITHOUT CEASING!..."}],[{t:"stanza-break"}],[{t:"italic",v:"Therefore have I brought forth and appointed"}],[{t:"italic",v:"Many days of sorrow for THIS generation!..."}],[{t:"stanza-break"}],[{t:"caps",v:"JUDGMENT!..."}],[{t:"stanza-break"}],[{t:"caps",v:"THE GREAT AND TERRIBLE DAY OF THE LORD!"}]]}],prevLetter:{id:"all-have-been-purchased",title:"All Have Been Purchased... Yet Few Have Accepted, Few Are Chosen"},nextLetter:{id:"judgment-of-god",title:"The Judgment of God Is True and Without Question, Yet the Error of the People Is Great"}},{id:"judgment-of-god",num:18,title:"The Judgment of God Is True and Without Question, Yet the Error of the People Is Great",date:"9/3/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-judgment-of-god-is-true-and-without-question-yet-the-error-of-the-people-is-great",videoVoiceUrl:"https://www.youtube.com/watch?v=SRKNsGG5Lrk&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=17",videoVoiceLabel:"Four Part Video Series (with voice over)",relatedTopics:[{label:"Thus Says The Lord Regarding Capital Punishment and Suicide",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Capital_Punishment_and_Suicide"},{label:"God Speaks About Committing Murder Within the Heart",url:"https://answersonlygodcangive.com/God_Speaks_About_Committing_Murder_Within_the_Heart"},{label:"Regarding Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"},{label:"Regarding the Gathering Up (\u201CRapture\u201D)",url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the First and Second Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"}],footnotes:{1:{type:"scripture",ref:"Matthew 10:28 (CJB)"}},nkjv:{"Matthew 10:28 (CJB)":"And do not fear those who kill the body but cannot kill the soul. Rather, fear him who can destroy both soul and body in Gehenna."},blocks:[{type:"intro",segments:[{t:"italic",v:"These questions were asked of The Lord: Lord, is capital punishment OK? Are those who are cremated lost?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" The penalty of sin is death. Thus all who have sinned shall surely die, all shall lie down in death. Yet there is a people who shall not sleep, nor shall they lie down in death; a people who shall be awake at My coming, a people who have received of the divine gift, a people who know Me and in whom I am known, for I see of Myself within them. They shall be lifted up, not preceding those who have fallen asleep in Messiah. This is the first harvest and resurrection. For there is but One Way, One Truth, and One Life; from the beginning, there is but One."}]},{type:"para",segments:[{t:"text",v:"Yet there is one who is cast down, who goes about to and fro in all the earth, perpetuating lies and spreading forth abomination, leading many away from the Truth. From the very beginning, satan was a deceiver and a murderer; he has never been on the side of truth. From the beginning, he has sought to ensnare My people and destroy My nation. For the heart of man is easily swayed, on account of his flesh he becomes entangled. Thus his idolatries are many, and his adulteries have no end."}]},{type:"para",segments:[{t:"text",v:"Behold, hand in hand they march toward their destruction, embracing lies and rejecting Truth, as they parade their transgressions openly in the streets. For the wisdom of the wise has perished, and the knowledge of the prudent has turned to dust. For the people are void, they all have itching ears. As cattle to the slaughter, or as a bird hastens to the snare, they give heed to those of clever words, failing to perceive it will cost them their life. Therefore the mouth of Sheol is open, the pit is dug deep, and the generation of My wrath shall surely be cast into it! Indeed, they shall all walk through the valley, until death comes to claim them and the grave hides them away, says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of My mouth and humble yourselves, O sons and daughters of men, that you may see with new eyes and restored vision:"},{t:"text",v:" If you kill for the sake of justice, though you yourselves remain unjust, have you not transgressed twice in your spirit? Yea three times, you have sinned against The Lord your God. For man knows not the justice of God, nor can he comprehend the judgment of The Most High. "},{t:"caps",v:"YOU SLOTHFUL AND MOST WICKED GENERATION, YOU ARE ALL MURDERERS!"},{t:"text",v:" Even to murder the murderer is murder! You do always transgress! You know nothing of the power of God, nor of My mercy revealed in The Messiah, whom you call Christ, nor are you able to search the hearts of men!"}]},{type:"para",segments:[{t:"text",v:"O foolish and deceived generation, if a man has committed murder and you put him to death, you have placed yourselves in the seat of judgment, making yourselves equal with God! Thus \u201CBLASPHEMY\u201D shall be written upon your heads, and \u201CMURDERER\u201D your new name! Yes punish the man who has committed murder, yet kill him not, lest he turn to Me in sincere repentance, in The Messiah\u2019s name, and be forgiven. Shall you then slaughter the sons of God, piercing the hearts of those made new?!"}]},{type:"para",segments:[{t:"text",v:"O peoples of the earth, how long shall you tread the wide path?! How long shall you walk in the way of Cain and run greedily in the error of Balaam, holding fast in your rebellion as Korah?! For your sins are many; behold, they are increased beyond measure!"}]},{type:"poetry",lines:[[{t:"italic",v:"Shall sin judge sin, and institute"}],[{t:"italic",v:"The punishment before the time?!..."}],[{t:"stanza-break"}],[{t:"italic",v:"Is not My judgment, that of capital punishment,"}],[{t:"italic",v:"For all who have sinned, and annihilation"}],[{t:"italic",v:"For all who refuse to repent?!..."}],[{t:"stanza-break"}],[{t:"italic",v:"Yet I sent My Only Begotten Son"}],[{t:"italic",v:"To suffer your sentences for you;"}],[{t:"italic",v:"Therefore, you do greatly err..."}],[{t:"stanza-break"}],[{t:"italic",v:"Peoples of the earth, where are your hearts?!"}],[{t:"italic",v:"Err on the side of hope and salvation"}],[{t:"italic",v:"In Messiah, where one can not err!"}]]},{type:"para",segments:[{t:"bold-italic",v:"Therefore concerning those who kill the body, yet can not harm the soul, I say this:"},{t:"text",v:" He who murders his brother has committed great evil. Even he who has conceived of murder in his heart is guilty. And those who carry out capital punishment are of the same. For they have put themselves in the judgment seat; behold, they have placed themselves upon My throne! Yet you know not what tomorrow will bring, nor can you look upon the heart of man; even all his thoughts are hidden from you. Thus only I shall make an end of evil. Only I shall destroy the wicked of heart and cast the sons of satan into eternal darkness, into the void of lifeless nothingness. "},{t:"italic",v:"For only The One who grants life can take it away. I AM THE LORD! Or have you forgotten whom you shall fear, The One alone who can destroy both body and soul?"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Behold, the sins of this generation reach unto heaven, a murderous and most wicked people, a great multitude who stand in agreement, a whole generation seeking the penalty of death as they shake their fists at Heaven! Yes, by your own admission you are guilty! Behold, according to your own laws, YOU should be put to death, YOU are the ones who should be sitting in the chair! "},{t:"caps",v:"HYPOCRITES!"},{t:"text",v:" You have destroyed yourselves!"}]},{type:"para",segments:[{t:"caps",v:"FOOLISH GENERATION, YOUR LIFE IS NOT YOUR OWN!"},{t:"text",v:" Apart from Me, there is no wisdom! Apart from The Holy One, there is no life! Apart from The Vine, there are no branches! Behold, the leaves wither and the fruit has been cast down, for the people have no favor with God. Thus every dry branch must be broken off and cast into the fire, all corrupt fruit must be left and tread down. For the temple of God has lost its form; its comeliness has departed, every chamber is empty. For the heart of man is void, his countenance unyielding. Thus the pride of man has become a chasm, both deep and wide, says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord your Redeemer, The Holy One of Israel:"},{t:"text",v:" Tear down the temple of God, and I shall raise it up again! For all who have died but sleep, yet I shall raise them up again. And of those who are Mine, I shall not lose one, for I am The Lord and I shall raise them up again. Even those cremated and those long since turned to dust shall rise. For from the dust you came forth, by My knowledge were you made, and by My breath you became living souls. Can not God raise up children to Abraham, from the very stones, if He so chooses? This I have already told you. Why then, O peoples of the earth, do you rant and rave and wail like the heathen, as one with no hope? Where is your trust? Indeed, you have forgotten your God, and are greatly deceived; you do not know Me, nor will you believe. For if you knew Me, then you would know The Father also, and understand that all things are possible with God."}]},{type:"para",segments:[{t:"text",v:"Therefore, let those who ask in faith receive, and let those who believe have understanding. For the fear of The Lord is indeed the beginning of wisdom. For I have already told you, that neither man nor angel can truly kill another, nor is satan able to raise the dead. Only The One who formed it can raise it up again, and only by the hand of Him who created it shall it be utterly destroyed. Thus if one refuses to be restored in the image of God, which I am, he shall surely perish. He shall be blotted out, his life forfeit. Indeed, it shall be as though he had never been."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore repent, and receive of Me as I am,"}],[{t:"italic",v:"And not as you would have Me be,"}],[{t:"italic",v:"That you may be truly born again..."}],[{t:"stanza-break"}],[{t:"italic",v:"For I am the perfect reflection of The Father,"}],[{t:"italic",v:"The image of The Invisible God..."}],[{t:"stanza-break"}],[{t:"italic",v:"I died, behold, I am risen,"}],[{t:"italic",v:"And by My life are you saved..."}],[{t:"stanza-break"}],[{t:"italic",v:"That you might become the perfect reflection of Me,"}],[{t:"italic",v:"The One alone in whom is everlasting life..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"abortion-murder",title:"Abortion: Murder of the Innocent"},nextLetter:{id:"twice-murdered",title:"Twice Murdered"}},{id:"twice-murdered",num:19,title:"Twice Murdered",date:"9/3/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",metaAddendum:'"The Judgment of God Is True and Without Question, Yet the Error of the People Is Great"',metaAddendumUrl:"https://www.thevolumesoftruth.com/The_Judgment_of_God_Is_True_and_Without_Question,_Yet_the_Error_of_the_People_Is_Great",metaAddendumInternal:"judgment-of-god",noteLine:"(Regarding suicide)",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/twice-murdered-2",videoVoiceUrl:"https://www.youtube.com/watch?v=OIpz19DqZOA&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=21",relatedTopics:[{label:"Thus Says The Lord Regarding Capital Punishment and Suicide",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Capital_Punishment_and_Suicide"},{label:"God Speaks About Committing Murder Within the Heart",url:"https://answersonlygodcangive.com/God_Speaks_About_Committing_Murder_Within_the_Heart"},{label:"Regarding the First and Second Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"}],footnotes:{},nkjv:{},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" I have looked upon those who strike themselves down, upon all who have been ensnared by the devil. For the sin of suicide is very grievous, a sin which only multiplies suffering and increases pain; of which the dead have no knowledge, for there is only silence in the grave."}]},{type:"para",segments:[{t:"text",v:"Therefore, hear and understand: If one heavy-laden with sorrow, with hopelessness and pain, ends their own life, they have indeed sinned. For to kill is to kill, even of one\u2019s self. Yet I tell you the truth, they are twice murdered; slain first in their heart by the devil, then in their body at their own hand. Are they lost? No. For even one dead at their own hand, coerced by the devil, will live again. For I am He who shall call forth both the first and the second."}]},{type:"poetry",lines:[[{t:"italic",v:"For all who have sinned are dead in their sins,"}],[{t:"italic",v:"Yet in Me they are made alive again,"}],[{t:"italic",v:"As many as drink My blood and eat My flesh..."}],[{t:"stanza-break"}],[{t:"italic",v:"For I am The Life Without End,"}],[{t:"italic",v:"The Only Fountain of Living Waters,"}],[{t:"italic",v:"The Bread of God which came down"}],[{t:"italic",v:"From Heaven and gave life to the world..."}],[{t:"stanza-break"}],[{t:"italic",v:"Behold, from the beginning I had overcome all things;"}],[{t:"italic",v:"From the very foundation of the world, I AM HE..."}],[{t:"stanza-break"}],[{t:"italic",v:"The Resurrection and The Life!"}]]}],prevLetter:{id:"judgment-of-god",title:"The Judgment of God Is True and Without Question, Yet the Error of the People Is Great"},nextLetter:{id:"one-truth-one-church",title:"One Truth, One Church, One Body... No Walls"}},{id:"one-truth-one-church",num:20,title:"One Truth, One Church, One Body... No Walls",date:"9/6/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",preamble:"This question was asked of The Lord: Lord, what of the Seventh Day Adventist Church, and their claim to be the true church and remnant?",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/one-truth-one-church-one-body-no-walls",videoVoiceUrl:"https://www.youtube.com/watch?v=WFDwHXyfmxA&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=22",relatedTopics:[{label:"Regarding The True Church",url:"https://answersonlygodcangive.com/Regarding_The_True_Church"},{label:"Regarding the Seventh Day Adventist Church",url:"https://answersonlygodcangive.com/Regarding_the_Seventh_Day_Adventist_Church"}],footnotes:{},nkjv:{},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Again I say to you, My church has no walls, and is called by no other name except the name The Father has given Me. Its members are of one mind and one spirit, of one love, one flock with one Shepherd, a people set apart who keep The Commandments of The Father and remain faithful to The Son, striving always to walk in My ways. For those who truly know Me dwell in Me, and I in them. For they are Mine, even as I am theirs also \u2014 My body, My bride."}]},{type:"para",segments:[{t:"text",v:"Therefore woe to any church of men, who claims to be the true church and remnant. Woe, I say to them. For they have placed themselves in the seat of The Father, and therefore remain under God\u2019s judgment. For none walk according to the Truth, not one accepts Me as I truly am; all have gone astray, teaching as doctrine the commandments of men."}]},{type:"para",segments:[{t:"text",v:"Beloved, no one can come to Me, unless The Father who sent Me draws them to Me. And only those who accept Me as I truly am are of My body, for The Truth resides within them and is revealed by their works. Yes, even these stumble in their walk, for they are but flesh."}]},{type:"poetry",lines:[[{t:"text",v:"Yet I am He who searches the"}],[{t:"text",v:"Hearts and minds, I know My own;"}],[{t:"text",v:"I know whose love is steadfast,"}],[{t:"text",v:"Whose faith is unmoving..."}],[{t:"stanza-break"}],[{t:"text",v:"And this is the True Church"}],[{t:"text",v:"My people long for, the remnant"}],[{t:"text",v:"Which now is and is yet to come..."}],[{t:"stanza-break"}],[{t:"text",v:"For it is not found outwardly in the world,"}],[{t:"text",v:"But inwardly, in the temple of God..."}]]},{type:"closing",text:"I am The Lord."}],prevLetter:{id:"twice-murdered",title:"Twice Murdered"},nextLetter:{id:"three-aspects",title:"As God Is Three Aspects, All as One, So Too Is the Coming of The Son of Man"}},{id:"three-aspects",num:21,title:"As God Is Three Aspects, All as One, So Too Is the Coming of The Son of Man",date:"10/7/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/as-god-is-three-aspects-all-as-one-so-too-is-the-coming-of-the-son-of-man",videoVoiceUrl:"https://www.youtube.com/watch?v=LXARoXzWdKw&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=23",relatedTopics:[{label:"The Coming of The Lord \u2014 \u201CAs a Thief\u201D",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#As_a_Thief"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:"Regarding the Gathering Up (\u201CRapture\u201D)",url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],footnotes:{1:{type:"scripture",ref:"2 Thessalonians 2:8"}},nkjv:{"2 Thessalonians 2:8":"And then the lawless one will be revealed, whom the Lord will consume with the breath of His mouth and destroy with the brightness of His coming."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" If The Son of Man is coming on the clouds of heaven with power and great glory, and every eye shall see Him, how then does He also come as a thief?"}]},{type:"para",segments:[{t:"text",v:"Here is wisdom: The Son of Man comes at a day and hour unknown, to spoil the house of the strong man. And that which belongs to The Lord shall be taken, and that which is of the strong man shall be left. For The Son of Man comes first as spirit poured out on the nations, to call upon His elect. Behold, He shall pass through the multitudes and peer deep into the heart of every vessel, and bundle them together. And on a day which no one knows, at an hour no one can predict, The Son of Man shall come as a thief and steal them away. Then shall the lawless one be revealed, whom The Lord will consume with the breath of His mouth and destroy with the brightness of His coming, as it is written."},{t:"fn",v:"1"},{t:"text",v:" I AM THE LORD."}]}],prevLetter:{id:"one-truth-one-church",title:"One Truth, One Church, One Body... No Walls"},nextLetter:{id:"take-my-people-out",title:"I Will Take My People OUT OF"}},{id:"take-my-people-out",num:22,title:"I Will Take My People OUT OF",date:"10/7/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For the Churches of Men, and For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-will-take-my-people-out-of",videoVoiceUrl:"https://www.youtube.com/watch?v=q58lQRnwXlE&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=24",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Gathering Up (\u201CRapture\u201D)",url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"}],footnotes:{1:{type:"scripture",ref:"Isaiah 2:17 (CJB)"}},nkjv:{"Isaiah 2:17 (CJB)":"The pride of man will be bowed down, the arrogance of men will be humiliated, and when that day comes, ADONAI alone will be exalted."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Churches of men, you do always twist the Scriptures! You cease not from adding to and taking away from the Word of God, as you continue to stand firm upon your own cracked foundations which your forefathers laid! \u2014 Foundation upon foundation throughout your generations, built ever higher according to the pride and vanity of men, an arrogance which has no equal!"}]},{type:"para",segments:[{t:"text",v:"How long shall you contend with Me? How long shall you pervert the Truth? Churches of men, shall I lie to My prophets and give them false testimony?! Or did you think I have ceased from making My plans known, that I have altogether turned back from sending them? Certainly not! For I am The Lord, and I do not change! Therefore, let every cracked foundation crumble and every house fall with a great crash! "},{t:"italic",v:"Let the glory of man be turned backward, until the pride of man is bowed down and the arrogance of man is utterly humiliated! For The Lord alone shall be exalted in that day, as it is written."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Humble yourselves, O churches of arrogance, and pray that you are not left standing upon the earth in bewilderment and tears, in the day I gather up My treasured ones and steal away My elect, those counted worthy to escape all these things which shall soon come to pass, the first to stand in the presence of The Son of Man, the first to be sheltered from My fury. Behold, the angels of Heaven shall ascend and descend upon The Son of Man, until the harvest is made complete."}]},{type:"para",segments:[{t:"text",v:"Therefore, again I say to you, humble yourselves! For pride has blinded your eyes and arrogance has stopped your ears! "},{t:"caps",v:"REPENT!"},{t:"text",v:" And pray double for those YOU have led from the Truth! For you preach and teach in the name of another messiah, a false christ who looks nothing like Me, a molded image which you have shaped to fit your own corrupt doctrines and perverse traditions, polluting My name and My glory as you continue to twist and segregate the Scriptures to your own hurt! Says The Lord."}]},{type:"poetry",lines:[[{t:"text",v:"Therefore, blessed are those who"}],[{t:"text",v:"Come out from among them..."}],[{t:"stanza-break"}],[{t:"text",v:"Blessed are those who obey God rather than men..."}],[{t:"stanza-break"}],[{t:"text",v:"Blessed are those who place their trust"}],[{t:"text",v:"In The Son of God, striving always to walk"}],[{t:"text",v:"In His ways and keep His commandments;"}],[{t:"text",v:"They shall surely be taken out of this place..."}],[{t:"stanza-break"}],[{t:"italic",v:"Yet woe to all those who disobey The Son,"}],[{t:"italic",v:"Woe to all who turn aside from The Way"}],[{t:"italic",v:"And forsake The Commandments,"}],[{t:"italic",v:"For the wrath of God remains upon them."}]]}],prevLetter:{id:"three-aspects",title:"As God Is Three Aspects, All as One, So Too Is the Coming of The Son of Man"},nextLetter:{id:"do-not-be-tempted",title:"Do Not Be Tempted by the World, For Its Ways Lead Only to Blasphemy and Sin"}},{id:"do-not-be-tempted",num:23,title:"Do Not Be Tempted by the World, For Its Ways Lead Only to Blasphemy and Sin",date:"11/25/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",preamble:"This question was asked of The Lord, for several family members: Lord, may we still give gifts to our loved ones, as long as it doesn\u2019t take place on the 25th of December, and if we do not call it Christmas?",addendum:"\u201CObey God\u201D",addendumUrl:"https://www.thevolumesoftruth.com/Obey_God",addendumLink:{collection:"Volume Four",letterTitle:"Obey God"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/do-not-be-tempted-by-the-world-for-its-ways-lead-only-to-blasphemy-and-sin",videoVoiceUrl:"https://www.youtube.com/watch?v=2N7Fky6EfC4&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=25",relatedTopics:[{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Man\u2019s Holidays vs. God\u2019s Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"},{label:"Take No Part",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Take_No_Part"}],footnotes:{1:{type:"scripture",ref:"Ephesians 5:11"},2:{type:"scripture",ref:"2 Corinthians 6:17"},3:{type:"scripture",ref:"Matthew 15:9"},4:{type:"scripture",ref:"John 15:10"},5:{type:"scripture",ref:"2 Corinthians 6:17"},6:{type:"scripture",ref:"Matthew 10:37"},7:{type:"scripture",ref:"James 4:4 (NKJV)"},8:{type:"scripture",ref:"John 4:24"},9:{type:"scripture",ref:"Matthew 16:24"},10:{type:"scripture",ref:"Matthew 21:42"},11:{type:"scripture",ref:"Daniel 2:35"}},nkjv:{"Ephesians 5:11":"And have no fellowship with the unfruitful works of darkness, but rather expose them.","2 Corinthians 6:17":"\u201CCome out from among them and be separate, says the Lord. Do not touch what is unclean, and I will receive you.\u201D","Matthew 15:9":"\u201CAnd in vain they worship Me, teaching as doctrines the commandments of men.\u201D","John 15:10":"\u201CIf you keep My commandments, you will abide in My love, just as I have kept My Father\u2019s commandments and abide in His love.\u201D","Matthew 10:37":"\u201CHe who loves father or mother more than Me is not worthy of Me. And he who loves son or daughter more than Me is not worthy of Me.\u201D","James 4:4 (NKJV)":"Adulterers and adulteresses! Do you not know that friendship with the world is enmity with God? Whoever therefore wants to be a friend of the world makes himself an enemy of God.","John 4:24":"\u201CGod is Spirit, and those who worship Him must worship in spirit and truth.\u201D","Matthew 16:24":"Then Jesus said to His disciples, \u201CIf anyone desires to come after Me, let him deny himself, and take up his cross, and follow Me.\u201D","Matthew 21:42":"Jesus said to them, \u201CHave you never read in the Scriptures: \u2018The stone which the builders rejected has become the chief cornerstone. This was the Lord\u2019s doing, and it is marvelous in our eyes\u2019?\u201D","Daniel 2:35":"Then the iron, the clay, the bronze, the silver, and the gold were crushed together, and became like chaff from the summer threshing floors; the wind carried them away so that no trace of them was found. And the stone that struck the image became a great mountain and filled the whole earth."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord of Heaven and Earth:"},{t:"text",v:" In these things of sin, which are altogether an abomination before The Lord, "},{t:"caps",v:"TAKE NO PART!"},{t:"fn",v:"1"},{t:"text",v:" Make no compromise, nor attempt to go roundabout; be completely separate."},{t:"fn",v:"2"},{t:"text",v:" Turn your back on all these commandments of men"},{t:"fn",v:"3"},{t:"text",v:" which pollute My name and My glory, stop drinking from these polluted fountains! For I hate all these filthy traditions, I loathe the sight of them! They are corrupt, evil works and adulteries, harlotries passed down from generation to generation, idolatries of every kind! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to all those who say they love Me, yet do not remain in My love:"},{t:"fn",v:"4"},{t:"text",v:" Do you really know Me? And if you long to know Me as I truly am, then let go of this world and forsake its evil ways. Come out from among them and be separate; take no part in that which is unclean, and I will receive you."},{t:"fn",v:"5"},{t:"text",v:" Yet I hear you saying, "},{t:"italic",v:"\u201CBut I do these things with a pure heart. The Lord will understand, for I do these things out of love.\u201D"}]},{type:"para",segments:[{t:"text",v:"Yes, all things born of love are good and well-pleasing to The Lord. For I know your hearts, beloved, even to your innermost desires and intentions. Yet those who love Me obey My commands and give heed to the leading of My spirit, for the two are in agreement. It is written: "},{t:"italic",v:"God is love."},{t:"text",v:" And if I am love, then obey Me as I have loved you; remember My decrees and obey My Commandments. Reveal to every onlooker that I am indeed your First Love, and I alone deserve your worship."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Risen One:"},{t:"text",v:" Therefore no more give your love or attention to the things of this world, for they are passing away. Neither shall you love anyone more than Me. Or have you never read these Scriptures: "},{t:"italic",v:"He who loves father or mother more than Me is not worthy of Me; and he who loves son or daughter more than Me is not worthy of Me;"},{t:"fn",v:"6"},{t:"italic",v:" and friendship with the world is enmity with God?"},{t:"fn",v:"7"},{t:"text",v:" Therefore honor Me in spirit and in truth, in accordance with the Scriptures."},{t:"fn",v:"8"},{t:"text",v:" Stand apart from the ways of this world, and cast away those things which pollute My name and My glory; crucify your lives of old and follow Me!"},{t:"fn",v:"9"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved ones, the Scriptures are not malleable;"}],[{t:"italic",v:"The Commandments do not change!..."}],[{t:"stanza-break"}],[{t:"italic",v:"For The Truth is absolute, forever standing on a hill,"}],[{t:"italic",v:"Bright and shining, immovable, unbreakable!..."}],[{t:"stanza-break"}],[{t:"italic",v:"The Everlasting Stone which has become The Head of the Corner,"},{t:"fn",v:"10"}],[{t:"italic",v:"The Great Mountain which fills the whole earth!"},{t:"fn",v:"11"},{t:"text",v:"..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"take-my-people-out",title:"I Will Take My People OUT OF"},nextLetter:{id:"judgment-transgression-word",title:"Judgment, Transgression, and The Word"}},{id:"judgment-transgression-word",num:24,title:"Judgment, Transgression, and The Word",date:"12/1/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/judgment-transgression-and-the-word",videoVoiceUrl:"https://www.youtube.com/watch?v=nB1ei6puQ9I&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=26",videoVoiceLabel:"Two Part Video Series (with voice over)",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Name of The Lord \u2013 \u201CImmanu El\u201D",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#Immanu_El"},{label:"Regarding Pollution and Mankind\u2019s Exploitation of the Earth",url:"https://answersonlygodcangive.com/Regarding_Pollution_and_Mankind%27s_Exploitation_of_the_Earth"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Final Judgment",url:"https://answersonlygodcangive.com/Regarding_the_Final_Judgment"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"}],footnotes:{1:{type:"scripture",ref:"Psalm 50:3-4"},2:{type:"scripture",ref:"Matthew 12:36"}},nkjv:{"Psalm 50:3-4":"3. Our God shall come, and shall not keep silent; a fire shall devour before Him, and it shall be very tempestuous all around Him. 4. He shall call to the heavens from above, and to the earth, that He may judge His people:","Matthew 12:36":"\u201CBut I say to you that for every idle word men may speak, they will give account of it in the day of judgment.\u201D"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" I am The Lord your God, He who stretched out the heavens and laid the foundations of the earth, The Maker of all things. Yes I AM HE, The Creator of Heaven and Earth, The One alone who sits on high, molding and shaping that which I have created by Him who is forever seated at My right hand. The Father and The Son are One."}]},{type:"para",segments:[{t:"text",v:"Behold, even to man did I grant this power, the power to create or to destroy. Yet within man dwells a corrupted spirit. And so he goes out and comes in, corrupting his way before him, leaving mourning in his wake; creating that which brings harm to himself, destroying that which was to sustain him, even to the murdering of the innocent; desecrating that which is pure, polluting the things of God, as he turns his back on his Creator."}]},{type:"para",segments:[{t:"text",v:"Thus I must judge the peoples of the earth; behold, I shall surely testify against them and utter My strong rebuke. For as it is written, so shall it be: "},{t:"italic",v:"I shall come, and I shall not keep silent! A fire shall devour before Me, and a great storm shall rage all around Me! I shall call to the heavens above and to the earth beneath, and judge all people!"},{t:"fn",v:"1"},{t:"italic",v:" Indeed, all shall give an account on that day, even of every idle word."},{t:"fn",v:"2"}]},{type:"para",segments:[{t:"text",v:"Yet let My faithful ones, all who have made a covenant with Me by sacrifice, be gathered to Me, and let them be judged according to the New Covenant; let The Holy Sacrifice stand in their place and speak on their behalf. For only the rejection of The Holy Covenant leads to judgment and death; or the acceptance thereof, from judgment into life. For I am a just God and a Savior; My mercy endures forever, My judgment is righteous, and My justice lasts throughout the generations. Behold, Heaven is My throne, and the earth My footstool, says The Lord."}]},{type:"para",segments:[{t:"text",v:"For I had sent to you My Son, in whom the fullness of God dwells, God in the flesh, Immanu El; a man without sin, blameless, who willingly gave up His life for all who have fallen under judgment, that those who are willing might pass from death to life, from darkness into The Light of Life. For He carried the weight of the world\u2019s sin to the cross, and crucified sin through His suffering; the penalty of sin abolished as He fell asleep, the Victory established for all time upon His rising. Thus He will be your judge at the Last Day, O peoples of the earth, because He is both God and man. Therefore, blessed are all those in whom He sees of Himself. For these have already passed from judgment into life, seated forever at His right hand."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, for thus says The Lord:"},{t:"text",v:" Do not be deceived; let satan gain no foothold. For there is but One God and One Savior, One Deliverer in the Day of Wrath. Again, I say to you, do not be deceived. Satan can not change his visage and become man. He is what he is, and remains who he became to this day. He is heylel, son of the morning, with a heart like the abyss. And those fallen are like him, corrupted by those same things which consume him."}]},{type:"para",segments:[{t:"text",v:"Yet satan has indeed appeared to men, sending them strong delusions, preying upon that which already dwells within them; even imitating Mary, the mother of The Messiah, deceiving those who remain ignorant of the Truth, leading a multitude away into false worship and idolatry. So then satan only imitates the truth, for there is no truth in him. When he tells a lie, he is only doing what comes natural to him, because he is a liar and the father of all lies. Thus he does indeed wear many disguises, and delights in leading My people astray. For by clever words and dark speeches he bears false witness, leading multitudes away into faiths which are dead \u2014 "},{t:"caps",v:"FALSE RELIGIONS! DETESTABLE PRACTICES! ABOMINATIONS!"}]},{type:"para",segments:[{t:"text",v:"YahuShua HaMashiach is The Gift, He is The Only Way; there is salvation in no other, nor any other name under Heaven by which you must be saved. Thus "},{t:"caps",v:"ALL"},{t:"text",v:" religions of this world are an abomination in the eyes of The Most High God! Every one of them pollutes the land and spreads forth like a plague! Behold, even those who bear My name have become like them! Not one worships Me in spirit or in truth, all have gone astray! Corrupt workers, arrogant assemblies, you worship yourselves!"}]},{type:"para",segments:[{t:"text",v:"Yes even you, O churches of men, have corrupted the Word of Truth, and do not cease from polluting My name! You misuse My name and abuse My Word, subverting the people through false doctrine and filthy tradition! You encourage them to forsake My Commandments and ignore My every decree! In the name of The Holy One, you cause My people to sin! By permission, "},{t:"caps",v:"UNDER GRACE,"},{t:"text",v:" you encourage them to transgress The Commandments of God, teaching and preaching to them another messiah, adding to and taking away from My Word to uphold your own way, and all for the sake of unjust gain! Shall I not discipline you for these things?! Shall I not bring down My hand hard upon you?! Shall I not come forth swiftly and wipe "},{t:"caps",v:"ALL"},{t:"text",v:" religions from the face of the earth?!"}]},{type:"para",segments:[{t:"text",v:"Yet true faith has a name, and true religion yields fruit of the same: A bride who obeys the voice of her Husband and walks in His ways, a people worthy to be called by His name. Yet the light has departed from the churches of men, The Word of Truth is hidden from their eyes. All is corrupt and dying, darkness fills the earth."}]},{type:"poetry",lines:[[{t:"text",v:"And so The Word was sent, and came into"}],[{t:"text",v:"The world to seek and to save the lost..."}],[{t:"stanza-break"}],[{t:"text",v:"And behold, He is coming again, to deliver His own,"}],[{t:"text",v:"All those who believe and live by The Word;"}],[{t:"text",v:"And to destroy those who fight against The Word,"}],[{t:"text",v:"For they too are bound by The Word..."}],[{t:"stanza-break"}],[{t:"italic",v:"For The Word stands forever..."}],[{t:"stanza-break"}],[{t:"italic",v:"Immovable and everlasting, unchangeable,"}],[{t:"italic",v:"Having complete authority over all things,"}],[{t:"italic",v:"The light and the dark, the righteous and the wicked..."}],[{t:"stanza-break"}],[{t:"italic",v:"Indeed, the whole universe is set within"}],[{t:"italic",v:"The confines of His will, giving heed to Him"}],[{t:"italic",v:"Who created it, forever and ever..."}]]},{type:"closing",text:"Amen."}],prevLetter:{id:"do-not-be-tempted",title:"Do Not Be Tempted by the World, For Its Ways Lead Only to Blasphemy and Sin"},nextLetter:{id:"heed-the-call",title:"Heed the Call"}},{id:"heed-the-call",num:25,title:"Heed the Call",date:"12/15/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/heed-the-call-2",videoVoiceUrl:"https://www.youtube.com/watch?v=8YOYDjonh4U&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=28",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],footnotes:{},nkjv:{},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" The time approaches quickly, and is already here, when My servant shall speak as never before. And those who have ears to hear will listen and come out. Yet those who hate the sound of this Trumpet will turn and fight against Me. For Timothy shall wield My words like a sword, and many shall be pierced and struck through - some to hope and salvation, and many more to refinement and tears; and still others to condemnation, all those who refuse to repent, those who hold fast in their rebellion to the end. For My words are fire, singeing the forehead of the arrogant, setting the countenance of the prideful ablaze, twin daggers piercing the heart of every hearer."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore hear the Word of The Lord, and heed the call..."}],[{t:"stanza-break"}],[{t:"text",v:"For it is a call to repentance, a shout"}],[{t:"text",v:"And a witness, a proclamation of Truth..."}],[{t:"stanza-break"}],[{t:"text",v:"A trumpet of alarm and war, a declaration"}],[{t:"text",v:"Of judgment, a strong rebuke..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"judgment-transgression-word",title:"Judgment, Transgression, and The Word"},nextLetter:{id:"transgression",title:"Transgression"}},{id:"transgression",num:26,title:"Transgression",date:"12/16/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the modern holidays of men)",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/transgression",videoVoiceUrl:"https://www.youtube.com/watch?v=31b_fZaCgIk&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=29",relatedTopics:[{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Man\u2019s Holidays vs. God\u2019s Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"}],footnotes:{1:{type:"note",text:"See: \u201CGod Speaks Regarding Those Who Take His Name in Vain\u201D",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},2:{type:"scripture",ref:"John 4:24"},3:{type:"scripture",ref:"Joel 2:32"},4:{type:"scripture",ref:"Jeremiah 6:15"},5:{type:"scripture",ref:"Malachi 3:6"},6:{type:"scripture",ref:"John 15:1-2"},7:{type:"scripture",ref:"Matthew 7:19"},8:{type:"scripture",ref:"Revelation 6:16-17"},9:{type:"scripture",ref:"Malachi 3:6"},10:{type:"scripture",ref:"Proverbs 28:9 (NKJV)"},11:{type:"scripture",ref:"Jeremiah 17:10"},12:{type:"scripture",ref:"John 14:6"},13:{type:"note",text:"Also read: \u201CIn Union With The Messiah\u201D",url:"https://www.thevolumesoftruth.com/Words_To_Live_By..._More_Words_of_Wisdom_From_The_Lord,_Our_God_and_Savior#In_Union_With_The_Messiah",link:{collection:"Words To Live By: Part One",letterTitle:"In Union With The Messiah"}}},nkjv:{"John 4:24":"\u201CGod is Spirit, and those who worship Him must worship in spirit and truth.\u201D","Joel 2:32":"And it shall come to pass that whoever calls on the name of the Lord shall be saved. For in Mount Zion and in Jerusalem there shall be deliverance, as the Lord has said, among the remnant whom the Lord calls.","Jeremiah 6:15":"\u201CWere they ashamed when they had committed abomination? No! They were not at all ashamed; nor did they know how to blush. Therefore they shall fall among those who fall; at the time I punish them, they shall be cast down,\u201D says the Lord.","Malachi 3:6":"\u201CFor I am the Lord, I do not change; therefore you are not consumed, O sons of Jacob.\u201D","John 15:1-2":"1. \u201CI am the true vine, and My Father is the vinedresser. 2. Every branch in Me that does not bear fruit He takes away; and every branch that bears fruit He prunes, that it may bear more fruit.\u201D","Matthew 7:19":"\u201CEvery tree that does not bear good fruit is cut down and thrown into the fire.\u201D","Revelation 6:16-17":"16. and said to the mountains and rocks, \u201CFall on us and hide us from the face of Him who sits on the throne and from the wrath of the Lamb! 17. For the great day of His wrath has come, and who is able to stand?\u201D","Proverbs 28:9 (NKJV)":"One who turns away his ear from hearing the law, even his prayer is an abomination.","Jeremiah 17:10":"\u201CI, the Lord, search the heart, I test the mind, even to give every man according to his ways, according to the fruit of his doings.\u201D","John 14:6":"Jesus said to him, \u201CI am the way, the truth, and the life. No one comes to the Father except through Me.\u201D"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:" This world has altogether become a house of harlots, a whole generation who ceases not from committing fornication with the pagan and the heathen, reveling always in those things I hate! - A most perverse generation who desecrates the name of The Messiah, a foolish people who do always take the name of The Lord in vain!"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Behold, all remain shackled to this world, captivated by sin, caught up in the ways of the world and men! Even those within the churches of men will not heed My voice, nor will they receive My correction; choosing rather to mingle honor with dishonor, praise with blasphemy, and purity with sin! Therefore stop breaking My Commandments in The Messiah\u2019s name, O churches of men! You shall not associate His name with sin, nor shall you honor Him with pagan rituals and idolatrous traditions, lest I reject you as I rejected the pagans before you!"}]},{type:"para",segments:[{t:"text",v:"Repent, therefore, and give Me glory; worship Me in spirit and in truth,"},{t:"fn",v:"2"},{t:"text",v:" and call upon The Name! For He alone shall deliver you in the Day of Wrath,"},{t:"fn",v:"3"},{t:"text",v:" if you so choose to embrace Him as He truly is; He being the very same who shall also destroy the wicked and bring terrible judgment upon the rebellious, upon great and small, rich and poor, bond and free, upon all who forsake My Law and push out the hand against the Word of My Commandment! For by Him were you made a vessel unto honor, yet you have all become vessels of dishonor, heaping to yourselves vanities and sin!"}]},{type:"para",segments:[{t:"text",v:"Therefore, because you are not ashamed of all these abominations which you have committed, but walk proudly, you shall be the first to fall among those who fall, at the time I punish this world for its iniquity and cast down the multitudes for their wickedness!"},{t:"fn",v:"4"},{t:"text",v:" For I am The Lord, and I do not change!"},{t:"fn",v:"5"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear My words, all you proud blasphemers, all you modern pharisees who pervert the Truth, for thus says The Lord:"},{t:"text",v:" How long shall you desecrate the name of The Messiah, and set yourselves up as an authority?! Behold, as vines of wickedness you bring forth only bitter fruit, propagating corrupt doctrine and perverse tradition among the people like a plague, doctrines and traditions I hate! YAHUSHUA, whom you call Jesus and Christ, is The True Vine! And only those who bear fruit in accordance with His likeness are His branches. And I shall surely prune every branch which grows from Him, that it may bear even more fruit."},{t:"fn",v:"6"},{t:"text",v:" Yet you say, "},{t:"italic",v:"\u201CHere I am, I also grow from The Vine!\u201D"},{t:"text",v:" You are all liars, a malignancy growing where you should not, dry branches meet to be broken off and cast into the fire!"},{t:"fn",v:"7"}]},{type:"poetry",lines:[[{t:"text",v:"Peoples of the earth, the Wrath of The Lamb is coming!"},{t:"fn",v:"8"}],[{t:"text",v:"Did you think I would stay silent during the time appointed?!"}],[{t:"text",v:"Did you think I would not set the time and declare the season?!..."}],[{t:"stanza-break"}],[{t:"italic",v:"For I am a jealous God and great in power,"}],[{t:"caps",v:"AND I DO NOT CHANGE!"},{t:"fn",v:"9"}]]},{type:"para",segments:[{t:"bold-italic",v:"Thus I shall speak plainly, for you are a most rebellious and hard-hearted people, a most foolish and deceived generation:"},{t:"text",v:" These modern holidays called Christmas, Easter, Halloween and the like, are an abomination in the eyes of The Most High God. Therefore in My jealousy and in the fire of My wrath, I shall destroy all your pagan traditions, and tear apart every perverse holiday of man! Behold, I shall wipe them from the face of the earth on that day, and no more shall you break My Commandments and revel in sin in The Messiah\u2019s name!"}]},{type:"para",segments:[{t:"text",v:"Behold, My countenance is turned against you, O churches of men! For you have blasphemed My name without ceasing, polluting the name of The Messiah days without end! You have placed the commandments of men above The Commandments of God, saying within yourselves, "},{t:"italic",v:"\u201CWe are the only authority among men.\u201D"},{t:"text",v:" How long shall you walk in the ways of the harlot and commit adultery with the pagan?! How long shall you turn your ear away from hearing The Holy Law?! Thus your worship is not accepted, and your prayers are an abomination!"},{t:"fn",v:"10"}]},{type:"para",segments:[{t:"text",v:"Churches of men, stop your vain babbling, for you do always twist the Scriptures of Truth! "},{t:"caps",v:"BE SILENT BEFORE YOUR GOD!"},{t:"text",v:" For your traditions are heresy, and your holidays are proof! Purge all this blasphemy from your lips, therefore, step back from your corrupt teachings, and take an account! "},{t:"caps",v:"HUMBLE YOURSELVES!"},{t:"text",v:" For I am indeed calling you out!"}]},{type:"para",segments:[{t:"text",v:"Know you not, that you have all become as the pagan and the heathen, by which all your holidays have their origins?! "},{t:"caps",v:"ABOMINATION!"},{t:"text",v:" This world has seduced you, and the harlot has led you into temptation! She shall be stripped naked and left desolate in the day of her calamity, broken because of her iniquities, put to death because of her denial of the Truth, crushed beneath the feet of The Holy One of Israel!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord and give heed, for thus declares The Lord:"},{t:"text",v:" One Commandment broken are all Commandments broken. One sin committed in The Messiah\u2019s name are all sins accounted to you. One sin repented in His name, all are forgiven you. For I know your thoughts, My children, even your innermost intentions, and I know whether or not you are fully converted in your hearts."},{t:"fn",v:"11"},{t:"text",v:" And though you may lie to yourselves, and bear false witness in the sight of many witnesses, nothing is hidden from the eyes of God \u2014 every lie exposed, every heart laid bare, in the Day I rise up and judge the earth."}]},{type:"poetry",lines:[[{t:"text",v:"Come to Me, therefore, in sincerity and in truth;"}],[{t:"text",v:"Humble yourselves in The Messiah\u2019s name..."}],[{t:"stanza-break"}],[{t:"text",v:"For He is The True Light, utterly void of darkness,"}],[{t:"text",v:"The Only Way to follow, The Truth Absolute;"}],[{t:"text",v:"By Him alone shall you walk into everlasting life..."}],[{t:"stanza-break"}],[{t:"text",v:"For only those who walk in Him shall find Me,"},{t:"fn",v:"12"}],[{t:"text",v:"And only those in union with Him shall know Me"},{t:"fn",v:"13"},{t:"text",v:"..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"heed-the-call",title:"Heed the Call"},nextLetter:{id:"living-sacrifices",title:"Living Sacrifices"}},{id:"living-sacrifices",num:27,title:"Living Sacrifices",date:"1/8/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/living-sacrifices",videoVoiceUrl:"https://www.youtube.com/watch?v=SNa-YvJMJnY&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=30",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"}],footnotes:{1:{type:"scripture",ref:"Matthew 5:16"},2:{type:"scripture",ref:"Matthew 16:24-26"},3:{type:"scripture",ref:"Matthew 10:37-38"}},nkjv:{"Matthew 5:16":"\u201CLet your light so shine before men, that they may see your good works and glorify your Father in heaven.\u201D","Matthew 16:24-26":"24. Then Jesus said to His disciples, \u201CIf anyone desires to come after Me, let him deny himself, and take up his cross, and follow Me. 25. For whoever desires to save his life will lose it, but whoever loses his life for My sake will find it. 26. For what profit is it to a man if he gains the whole world, and loses his own soul? Or what will a man give in exchange for his soul?\u201D","Matthew 10:37-38":"37. \u201CHe who loves father or mother more than Me is not worthy of Me. And he who loves son or daughter more than Me is not worthy of Me. 38. And he who does not take his cross and follow after Me is not worthy of Me.\u201D"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" My children, do you love Me? Then do as I command you. Grow wise in Me, and live according to My Word, even according to all these Letters I have given you, by which I have set all these crooked paths straight. For My every word is Scripture, My every Letter truth. Be cognizant of My comings and goings. For I have indeed come to live in those who have received of Me, those who obey My voice and embrace Me as I truly am."}]},{type:"para",segments:[{t:"text",v:"Again, I say to you, honor Me first with your ways, then with your mouth. For honor only spoken of is but wind, the veil of the hypocrite who knows not where he is going, having no remorse over where he has been. For how can one who professes to love Me live contrary to Me? Beloved ones, I love you as I love The Father. In the same way, whoever loves Me loves The Father also. I obey The Father in all things, because I love The Father and The Father is in Me. Likewise those who are truly My disciples obey My voice, because they love Me and I live in them."}]},{type:"para",segments:[{t:"text",v:"So then, walk in My ways and be for Me examples, "},{t:"italic",v:"letting your light so shine before men, that they may see your good works and glorify your Father in Heaven, as it is written."},{t:"fn",v:"1"},{t:"text",v:" Beloved ones, show them the Way by your faith and obedience, that they too may come to walk beside Me, even upon the Highway of Holiness, each at their appointed time, each in due season. For I tell you the truth, to walk where The Son of God walks, you must become like Me; crucifying your lives of old, separating yourselves from the bitter enmity which is of this world and the churches of men, living sacrifices who seek to please The Father in all their ways."}]},{type:"para",segments:[{t:"text",v:"For it is written: "},{t:"italic",v:"If anyone desires to come after Me, let him deny himself and take up his cross, and follow Me. For whoever desires to save his life will lose it, but whoever loses his life for My sake will find it. For what profit is it to a man if he gains the whole world, and loses his own soul? Or what will a man give in exchange for his soul?"},{t:"fn",v:"2"},{t:"text",v:" Therefore, those who strive to hold onto their life in this world will lose it, having already become dead men\u2019s bones in a wasteland of many sorrows, leading and following others on the wide path to destruction."}]},{type:"para",segments:[{t:"text",v:"Beloved, what are all these things of this world compared with your life? What is their worth? And what of all these works of man? Are they not passing away? Again I ask you, what is their value? I tell you the truth, "},{t:"italic",v:"whoever loves anything in this world, more than Me, is not worthy of Me."},{t:"fn",v:"3"},{t:"text",v:" For I am The Only Way, The Only Truth and The Only Life. There is nothing apart from Me."}]},{type:"poetry",lines:[[{t:"text",v:"Therefore come and follow Me,"}],[{t:"text",v:"For I am called Jesus The Christ..."}],[{t:"stanza-break"}],[{t:"italic",v:"My name: YahuShua HaMashiach..."}],[{t:"stanza-break"}],[{t:"text",v:"The only name under Heaven"}],[{t:"text",v:"By which you must be saved."}]]}],prevLetter:{id:"transgression",title:"Transgression"},nextLetter:{id:"proclaim-not-hell",title:"Proclaim NOT the Hell of the Churches of Men"}},{id:"proclaim-not-hell",num:28,title:"Proclaim NOT the Hell of the Churches of Men",date:"1/14/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/proclaim-not-the-hell-of-the-churches-of-men-4",videoVoiceUrl:"https://www.youtube.com/watch?v=YA3YSAK_WGM&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=31",bibleStudies:[{label:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",url:"https://www.thevolumesoftruth.com/The_State_of_the_Dead_and_The_Fate_of_the_Wicked:_The_False_Doctrine_of_Hell_and_Eternal_Torment_Exposed",link:{collection:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",letterTitle:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed"}}],relatedTopics:[{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"}],footnotes:{1:{type:"scripture",ref:"Matthew 12:40"},2:{type:"note",text:"See: \u201CFalse Doctrines Within the Churches of Men Regarding (#5 \u201CHell\u201D and Eternal Torment)\u201D",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},3:{type:"note",text:"See: \u201CQ & A: What is the State of the Dead?\u201D",url:"https://www.thevolumesoftruth.com/The_State_of_the_Dead_and_The_Fate_of_the_Wicked:_The_False_Doctrine_of_Hell_and_Eternal_Torment_Exposed#.28.2AVerses_Often_Stumbled_Over.29",link:{collection:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",letterTitle:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed"}},4:{type:"note",text:"See: \u201CRegarding the Second Death\u201D",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},5:{type:"scripture",ref:"Ecclesiastes 9:5"},6:{type:"scripture",ref:"Genesis 3:19, Ecclesiastes 3:20"},7:{type:"scripture",ref:"John 3:36"}},nkjv:{"Matthew 12:40":"\u201CFor as Jonah was three days and three nights in the belly of the great fish, so will the Son of Man be three days and three nights in the heart of the earth.\u201D","Ecclesiastes 9:5":"For the living know that they will die; but the dead know nothing, and they have no more reward, for the memory of them is forgotten.","Genesis 3:19, Ecclesiastes 3:20":"Genesis 3:19 \u2014 \u201CIn the sweat of your face you shall eat bread till you return to the ground, for out of it you were taken; for dust you are, and to dust you shall return.\u201D | Ecclesiastes 3:20 \u2014 All go to one place: all are from the dust, and all return to dust.","John 3:36":"\u201CHe who believes in the Son has everlasting life; and he who does not believe the Son shall not see life, but the wrath of God abides on him.\u201D"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Listen, all you churches of men! Shall I, even I, torment My beloved?! "},{t:"caps",v:"SATAN IS THE TORMENTOR!"},{t:"text",v:" Thus by your own mouths, you have unwittingly called your God, satan! Repent therefore, mend your ways and your doings! Stop profaning My name and desecrating the Glory of My majesty, for you have surely blasphemed The Spirit of Truth!"}]},{type:"para",segments:[{t:"text",v:"Again I say, repent, and have greater understanding of My Mercy, which endures forever. For The Son of Man did indeed sleep in the heart of the earth, His tomb, for three days and three nights,"},{t:"fn",v:"1"},{t:"text",v:" yet by no means did He descend into the evils of man\u2019s imaginings!"},{t:"fn",v:"2"},{t:"text",v:" Become again a child of God, and seek to know Me as I truly am."}]},{type:"para",segments:[{t:"text",v:"Beloved ones, the eternal state of My punishment"},{t:"fn",v:"3"},{t:"text",v:" is the second death,"},{t:"fn",v:"4"},{t:"text",v:" the grave from which one shall never be raised. For they have been cast out, forever separated from God and their part in life. So then those under condemnation are dead. In no way are they part of the living, nor are they living in torment; they know nothing at all."},{t:"fn",v:"5"},{t:"text",v:" Their inheritance is lost, they have been blotted out, broken vessels of dishonor received by the earth once again."},{t:"fn",v:"6"}]},{type:"poetry",lines:[[{t:"text",v:"Thus all those who believe in The Son"}],[{t:"text",v:"And obey His voice shall rise and live..."}],[{t:"stanza-break"}],[{t:"italic",v:"Yet those who hate The Son will not see Life,"}],[{t:"italic",v:"For the wrath of God remains upon them"},{t:"fn",v:"7"},{t:"text",v:"..."}]]},{type:"closing",text:"Says The Lord."}],prevLetter:{id:"living-sacrifices",title:"Living Sacrifices"},nextLetter:{id:"seven-hills",title:"To the Church Who Dwells in the Midst Of and Sits Upon Seven Hills"}},{id:"seven-hills",num:29,title:"To the Church Who Dwells in the Midst Of and Sits Upon Seven Hills",date:"1/31/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",audioUrl:"https://thevolumesoftruth.bandcamp.com/track/to-the-church-who-dwells-in-the-midst-of-and-sits-upon-seven-hills",videoVoiceUrl:"https://www.youtube.com/watch?v=mU3e0s7TZyo&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=33",videoVoiceLabel:"Four Part Video Series (with voice over)",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord_.28Section_One.29"},{label:"Regarding Forgiveness",url:"https://answersonlygodcangive.com/Regarding_Forgiveness"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Index of False Doctrines - The Catholic Church",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding...#More_False_Doctrines_-_The_Catholic_Church"},{label:"The Catholic Church Is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Catholic_Church_Is_an_Abomination_to_The_Lord"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding Crucifying The Messiah in Your Heart",url:"https://answersonlygodcangive.com/Regarding_Crucifying_The_Messiah_in_Your_Heart"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"The ONLY Way, The ONLY Truth, The ONLY Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life#The_ONLY_Way.2C_The_ONLY_Truth.2C_The_ONLY_Life"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"Woe to the Catholic Church",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Catholic_Church"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men_-_Section_One"},{label:"Come Out of Her",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_Her"}],footnotes:{1:{type:"scripture",ref:"Luke 3:23-38"}},nkjv:{"Luke 3:23-38":"23. Now Jesus Himself began His ministry at about thirty years of age, being (as was supposed) the son of Joseph, the son of Heli, 24. the son of Matthat, the son of Levi, the son of Melchi, the son of Janna, the son of Joseph, 25. the son of Mattathiah, the son of Amos, the son of Nahum, the son of Esli, the son of Naggai, 26. the son of Maath, the son of Mattathiah, the son of Semei, the son of Joseph, the son of Judah, 27. the son of Joanna, the son of Rhesa, the son of Zerubbabel, the son of Shealtiel, the son of Neri, 28. the son of Melchi, the son of Addi, the son of Cosam, the son of Elmodam, the son of Er, 29. the son of Jose, the son of Eliezer, the son of Jorim, the son of Matthat, the son of Levi, 30. the son of Simeon, the son of Judah, the son of Joseph, the son of Jonan, the son of Eliakim, 31. the son of Melea, the son of Menan, the son of Mattathah, the son of Nathan, the son of David, 32. the son of Jesse, the son of Obed, the son of Boaz, the son of Salmon, the son of Nahshon, 33. the son of Amminadab, the son of Ram, the son of Hezron, the son of Perez, the son of Judah, 34. the son of Jacob, the son of Isaac, the son of Abraham, the son of Terah, the son of Nahor, 35. the son of Serug, the son of Reu, the son of Peleg, the son of Eber, the son of Shelah, 36. the son of Cainan, the son of Arphaxad, the son of Shem, the son of Noah, the son of Lamech, 37. the son of Methuselah, the son of Enoch, the son of Jared, the son of Mahalalel, the son of Cainan, 38. the son of Enosh, the son of Seth, the son of Adam, the son of God."},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel, The God of Abraham, The God of Isaac, The God of Jacob, The God of all:"},{t:"text",v:" I AM THE I AM, The Only God. I am The All in All, Maker of all that is heaven and earth. I AM. And nothing in all creation exists apart from Me, for even all things have come into being by My voice. For I am YAHUWAH, He who causes to be; even I am He, YAHUSHUA, by whom all things consist."}]},{type:"para",segments:[{t:"text",v:"Yet you, O unholy church of men, have polluted My name! You have departed from The Way, and you have desecrated The Holy Covenant! Behold, you have altogether despised My Word and My Law! For you do always pick the scab and refuse the ointment, a people covered with sores! Thus you shall receive of the curse in full! Says The Lord God. Yes, according to your works, so shall you receive recompense in full, until you are utterly consumed!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, for thus says The Lord, yes I, The Only Lord of Hosts:"},{t:"text",v:" The Word of My mouth speaks, and so it comes to pass. I think, and so it is and shall be. And behold, I curse, and it is cursed. For I cast down the wicked and cause the lofty to fall. I throw down the strongholds of the rebellious and break apart every false foundation. For I AM HE who has punished great kings and brought plagues upon their people. I AM HE who has cast down the mighty and destroyed whole nations. Behold, I abase the pride of the pagan and punish the wickedness of the heathen with death! I break the idols in pieces and cause the graven image to fall on its face! For I am a great king, says The Lord, and My name is to be feared among the nations!"}]},{type:"para",segments:[{t:"text",v:"Yet I am not without mercy, for My promises stand and My Holy Covenant endures forever. Therefore, when one comes to Me in the name of The Son, in sincerity and in truth, they are forgiven, even forever and ever. Amen. For I said, "},{t:"italic",v:"\u201CLet there be a Lamb without spot or blemish, sacrificed for the atonement of sin,\u201D"},{t:"text",v:" and so it was, "},{t:"italic",v:"\u201CAnd let The Lamb be The Son of God, The Holy One of Israel, in whom all the nations of the earth shall be blessed,\u201D"},{t:"text",v:" and so it is, forever and ever! Sing, \u201CHalleluYah!\u201D Let My people cry out, "},{t:"italic",v:"\u201CGod is with us!\u201D"}]},{type:"para",segments:[{t:"text",v:"Yet you have not sung, nor have I heard you cry out in the name of The Holy One of Israel, nor have you given thanks in His holy name! "},{t:"caps",v:"YOU REFUSE TO DRINK FROM MY CUP!"},{t:"text",v:" Instead you pollute it, you defile it, as you pour it upon the ground; coming before Me in the name of those who went before you, of whom you have not known, offering up supplications in the name of the dead; having altogether become as the pagan and the heathen, as those who worshiped the queen of heaven, teaching as doctrine abomination, laying one transgression upon another throughout your generations! Shall I not then require it at your hand?!"}]},{type:"para",segments:[{t:"text",v:"And yet your pomp reaches higher than the mountains, and your false piety extends to the ends of the earth! "},{t:"caps",v:"WOE TO YOU!"},{t:"text",v:" Woe to your sons and daughters! Woe to every disciple who follows you and drinks from the cups of your fornications, taking part in your abominations! "},{t:"caps",v:"WOE TO ALL PEOPLE, WHO HIDE IN THE BOSOM OF THE PRINCE OF DARKNESS!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God, who is and was and is to come, The Almighty:"},{t:"text",v:" As I have spoken, so shall I speak; as I am, so shall I be. Therefore, hear the Word of My mouth and give heed to My speech, and turn from this evil way you uphold, lest I come upon you suddenly and tear you in pieces! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"For among you are wicked men, who like fowlers lie in wait and set traps, that they might catch men. Behold, with practiced speech and a lying tongue they ensnare them, that they might go into captivity together! As a cage full of detestable birds, so are all your houses of worship, O unholy church of men!"}]},{type:"para",segments:[{t:"text",v:"Behold, your leaders have grown fat with deceit, truth has perished among them; it has altogether been cut off from their mouth! For your seers swear falsely, and your leaders do not cease from speaking blasphemies with a practiced and lying tongue, and your appointed kings and bishops rule by their own authority! And oh how your people love to have it so... Yet what will you do in the end?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God, whose throne is set high above the heavens, The Creator of Heaven and Earth:"},{t:"text",v:" As I have spoken, so shall I speak; as I am, so shall I be. Therefore hear the Word of My mouth, and give heed to My speech, and turn from this wicked way you have chosen, lest I come upon you suddenly and tear you in pieces! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"For The Lord God hates abomination, yet vines of wickedness have sprung up, reaching to the ends of the earth. For the fruit of the people is corrupt, their bounty wickedness, producing only rebellion against The Lord! Yet you, O church of harlots, are worse still! For with what can I compare you, and who are you like? You are a whole congregation of sly and deceitful snakes, a vicious den of vipers from which a great hissing has come forth against The Lord and His anointed, a den of thieves who cease not from robbing Me, captive children whose fathers persecuted and murdered those sent to them!"}]},{type:"poetry",lines:[[{t:"italic",v:"Throughout your generations,"}],[{t:"italic",v:"You have been murderers!"}],[{t:"italic",v:"From the beginning, you were scoundrels!..."}],[{t:"stanza-break"}],[{t:"text",v:"Even to this day you persecute My messengers,"}],[{t:"text",v:"And stone those sent to you in word and by deed,"}],[{t:"text",v:"That you might continue to poison your own people!"}],[{t:"text",v:"Behold, your heresies have no end!..."}],[{t:"stanza-break"}],[{t:"caps",v:"SHALL I NOT PUNISH YOU"}],[{t:"caps",v:"FOR THESE THINGS?!..."}],[{t:"stanza-break"}],[{t:"caps",v:"SHALL I NOT AVENGE MYSELF"}],[{t:"caps",v:"UPON A CHURCH SUCH AS THIS?!"}]]},{type:"para",segments:[{t:"text",v:"Yet you say, "},{t:"italic",v:"\u201CWe are sovereign. We are set apart from the nations and sit as queen. We set the times and declare the seasons. See, we have given birth to many kings, and have grown rich beyond measure. Thus our princes shall reign supreme.\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus declares The Sovereign Lord who reigns from Heaven:"},{t:"text",v:" Because you have not shut your mouth from speaking blasphemies, and have not drawn back your hand from all your abominations, to both practice them and to teach them, and because you have endeavored to change The Commandments of The Lord, even to set yourselves up as the standard, declaring your own glory before men, "},{t:"caps",v:"AND BECAUSE YOU HAVE POLLUTED THE HOLY COVENANT BY YOUR EVERY WORD AND DEED,"},{t:"text",v:" so also shall I open My mouth against you, so also shall I stretch out My hand against you, until you are utterly consumed! Declares The Lord. Therefore take up a lamentation on the desolate heights, bring forth a bitter weeping in all the earth! "},{t:"caps",v:"FOR THE LORD HAS REJECTED AND FORSAKEN THE GENERATION OF HIS WRATH!"}]},{type:"para",segments:[{t:"text",v:"O unholy church of men, I take no pleasure in you. You are an abhorrence to Me, your faith is dead, and the fruit of your doings brings forth death, says The Lord. For you do not give heed to My words, nor do you obey My Commandments; My every statute you have torn asunder. You do always reject My Word; from My ways you are far removed."}]},{type:"para",segments:[{t:"text",v:"Behold, you have taken it upon yourselves to change MY Word and MY Commandments, teaching as law the doctrines and traditions of men, which I hate, to the continual blaspheming of My spirit! How long shall I suffer you?! I can not endure all this iniquity! You are perverse, a church overflowing with iniquity, harlotries beyond measure! Your offerings are not accepted, all your supplications are rejected; behold, they are a foul stench in My nostrils, a rancid taste in My mouth! Therefore you must be purged, I must vomit you out!"}]},{type:"poetry",lines:[[{t:"italic",v:"O unholy church of men, mother of all fornications,"}],[{t:"italic",v:"How long shall you tempt The Lord your God?!..."}],[{t:"stanza-break"}],[{t:"italic",v:"How long shall you bring before Me defiled offerings,"}],[{t:"italic",v:"Making supplications in the name of the dead?!..."}],[{t:"stanza-break"}],[{t:"italic",v:"How long shall you deceive yourselves, as you continue"}],[{t:"italic",v:"To place your hope in those who have fallen asleep?!..."}],[{t:"stanza-break"}],[{t:"text",v:"For I tell you the truth, even by all you say and do,"}],[{t:"text",v:"Do you cause your people to sin, even to crucify"}],[{t:"text",v:"Their Savior again and again in their hearts."}]]},{type:"para",segments:[{t:"text",v:"For the people come to you, to you and your appointed \u201Cfathers\u201D, seeking forgiveness, which I said you shall not do. Your appointed fathers are guilty; they remain in their sins! Nor can praying in the name of Mary, using vain repetition, save you, which I said you shall not do. "},{t:"caps",v:"THE SONS OF MEN CAN NOT FORGIVE SINS! MARY IS NOT THE WAY!"}]},{type:"para",segments:[{t:"text",v:"Mary was My beloved servant and vessel, who also was in need of redemption by Him who created her and through whom she was made. Mary sleeps, she is dead, and her sepulcher remains with you to this day."}]},{type:"para",segments:[{t:"text",v:"Is she assured of life in The Kingdom? She is. Because though she bore The Victory, she humbled herself before Him, knowing in herself that The Son she bore first bore her; being both her Son and her Father, her Lord and her God from Heaven; also being her brother, "},{t:"italic",v:"both being children of David and of God in the earthly places."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"I tell you the truth, all have sinned, all have fallen short of glory. There is none righteous, no, not one. Shall you then pray to the vessel, or to The Maker who formed it? And shall you hold the handmaiden of The Lord in high regard, and make for yourselves graven images, though I said this you shall not do? Therefore I tell you plainly, by your own hands you have transgressed The Commandment, and by your own fingers you have sinned against The Lord your God! "},{t:"caps",v:"YEA, BY ALL YOUR DOINGS, YOU HAVE SURELY FORSAKEN AND BETRAYED THE SON OF THE LIVING GOD!"}]},{type:"para",segments:[{t:"text",v:"Behold, even your consciences are defiled, and upon your knees you commit idolatry without ceasing! Did Mary suffer for your iniquities? Did Mary bear your sins on the tree? Was Mary crucified for you? Was Mary raised from the dead, and by her life do you now live? Can anyone in need of redemption redeem another?! Only He, who is completely blameless, may redeem those who have fallen. Therefore if one commits themselves to a faith which is dead, then with the dead they must sleep, having denied The Truth and The Life sent to them, crucified and raised, The Lord your Righteousness, The Only Way."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord God, The Holy One of Israel:"},{t:"text",v:" Stop worshiping the dead! Worship Me by Him who alone is holy, being altogether as The Father, the very same as God. For before the foundation of the world, I AM, with The Christ forever seated at My right hand; The Father and The Son are One. By Him do all things consist, and through Him all was made, even all these worlds."}]},{type:"poetry",lines:[[{t:"caps",v:"HYPOCRITES! WOE TO YOU!..."}],[{t:"stanza-break"}],[{t:"text",v:"Woe to you who testify falsely on My behalf!"}],[{t:"text",v:"Woe to you who teach as doctrine the commandments of men!"}],[{t:"text",v:"Woe to you who pervert the Way of The Lord"}],[{t:"text",v:"Among the people, and profane My holy things!..."}],[{t:"stanza-break"}],[{t:"caps",v:"I DO NOT KNOW YOU, NOR DO YOU"}],[{t:"caps",v:"HAVE ANY PART WITH ME AT ALL!..."}],[{t:"stanza-break"}],[{t:"italic",v:"For the Way of The Lord is set apart and holy, My Law is holy,"}],[{t:"italic",v:"And My Commandments, holy, just and good..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, whose way is in the whirlwind and in the storm, and the clouds are the dust of His feet:"},{t:"text",v:" O unholy church of adulteries, you speak as though you know Me, yet you do not know Me. You have forsaken Me! For you are an estranged woman, who knows not that she is accursed. For the musings of your heart have been evil from your beginnings; from your very foundation your wickedness has not ceased!"}]},{type:"para",segments:[{t:"text",v:"Therefore I will indeed draw near to you for "},{t:"caps",v:"JUDGMENT,"},{t:"text",v:" I will indeed stretch out My hand against you for "},{t:"caps",v:"RECOMPENSE,"},{t:"text",v:" and you shall be torn in pieces! For you have robbed Me, says The Lord, and have not ceased from perverting My way amongst the people! Behold, you continue to pollute My name in all the earth, even to this day!"}]},{type:"para",segments:[{t:"text",v:"Therefore, turn! Says The Lord. Turn aside from this wicked way you uphold, from this evil path you have chosen, and return to Me! Turn aside, and now follow The Shepherd in spirit and in truth, and I also shall return to you. Hear His voice and obey the Word of His mouth, heed His every commandment; turn not to the right hand, nor to the left, but walk in His ways."}]},{type:"para",segments:[{t:"text",v:"Beloved children, I say this once again, so you may be saved: Come out! Come out from among them and be separate! Says The Lord. And no more touch what is unclean, and I will receive you! Cast away the commandments of men, and obey not the word of your forefathers. Turn away from the counsel of your appointed bishops and kings, and shut your ears to the words of your priests and false fathers; fully shun the ways of your founders. For their every doctrine rests upon the sands of abomination, all their ways are corrupt. And no more give reverence to your \u201Choly see\u201D, for this is most contemptible in My sight. Break free from all this insolence before The Lord, and I may yet have mercy upon you."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved children, there is but One Way..."}],[{t:"stanza-break"}],[{t:"italic",v:"YahuShua HaMashiach,"}],[{t:"italic",v:"Yes, He who is called Jesus The Christ,"}],[{t:"italic",v:"He is The Only Way..."}],[{t:"stanza-break"}],[{t:"italic",v:"Therefore follow close behind Him,"}],[{t:"italic",v:"In His very footsteps,"}],[{t:"italic",v:"And you shall surely live and not die..."}]]},{type:"closing",text:"Says The Lord whose dominion is everlasting and whose authority is absolute, The Only Lord God of Hosts, The I AM."}],prevLetter:{id:"proclaim-not-hell",title:"Proclaim NOT the Hell of the Churches of Men"},nextLetterExternal:{url:"https://www.thevolumesoftruth.com/Volume_Three",title:"Volume Three \u2192"}}],LETTERS_V3_PREFACE=null,LETTERS_V3=[{id:"deceptions",title:"Deceptions",date:"2/8/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, what do you say about new age spirituality, psychics, mediums, buddhism and the like?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"All is wickedness, deceptions clothed in falsehoods, presented to the masses under the guise of so-called truth and enlightenment, the wide path leading to destruction. For those who embrace such things cast stumbling stones at their own feet, and those who teach such things teach doctrines of demons, and shall surely fall into the pit. Beware. For these teachings are of the spirit called antichrist; propagated by those sent out by the evil one to disguise and pervert the Truth amongst the people, to deceive the whole world (and if it were possible, even the elect); cunning ones who seek only to steal, kill and destroy, to the devouring of whole nations. For the thoughts and desires of the people are perverse. They practice abomination, and do not retain God in their thoughts. They are consumed by lust, easily devoured by their own evil thoughts and desires."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, again I say to you, beware..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For evil comes in many forms"}],[{t:"italic",v:"And shall only increase by measure,"}],[{t:"italic",v:"Reaching unto new heights in wickedness..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, right has become wrong;"}],[{t:"italic",v:"And wrong has become right,"}],[{t:"italic",v:"And the right of the individual"}],[{t:"italic",v:"Who has become a god unto themselves..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My children have removed"}],[{t:"italic",v:"Themselves far from Me, searching"}],[{t:"italic",v:"In vain for they know not what."}]]},{type:"para",segments:[{t:"text",v:"For I tell you the truth, what they call god is nothing! - Dead works, useless faith, all in all a leading away from The Truth; lies upon lies, deception hidden within deception, both great and subtle, vanity and vexation of spirit; falsehoods passed down from one generation to the next, deceptions built upon the ever-shifting sands of religion, philosophy and science, masquerading as truth! For the evil one does indeed wear many disguises by which he ensnares the people, clever contrivances both subtle and obvious; stones of stumbling, rocks of offense, abominations hidden under the guise of peace and enlightenment, full of self and self-indulgence - DELUSION! Yet the fulfillment they seek through meditation and enlightenment leads only to spiritual starvation and bitter thirst, as they wander aimlessly through a vast desert of lies wherein all dead men\u2019s bones are found, hidden within the mirage of inner peace."}]},{type:"poetry",lines:[[{t:"italic",v:"Peoples of the earth, YahuShua HaMashiach"}],[{t:"italic",v:"Is The Fulfillment of all things,"}],[{t:"italic",v:"The Truth and Understanding you seek,"}],[{t:"italic",v:"The Meaning of Life!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"HE is The Bread which came down"}],[{t:"italic",v:"From Heaven to feed those who hunger,"}],[{t:"italic",v:"The Fountain of Living Waters for those"}],[{t:"italic",v:"Who thirst, The Prince of Peace..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The ONLY Way, The ONLY Truth, The ONLY Life..."}]]},{type:"closing",text:"Says The Lord God."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/deceptions",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/deceptions?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=KywZ7EbtN84&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=1",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Rebukes New Age Spirituality",url:"https://answersonlygodcangive.com/God_Rebukes_New_Age_Spirituality"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"The ONLY Way, The ONLY Truth, The ONLY Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life#The_ONLY_Way.2C_The_ONLY_Truth.2C_The_ONLY_Life"}],num:1,prevLetter:null,nextLetter:{id:"the-sower-has-sown-yet-the-seeds-have-fallen-among-thorns-and-stony-places",title:"The Sower Has Sown, Yet the Seeds Have Fallen Among Thorns and Stony Places"}},{id:"the-sower-has-sown-yet-the-seeds-have-fallen-among-thorns-and-stony-places",title:"The Sower Has Sown, Yet the Seeds Have Fallen Among Thorns and Stony Places",date:"2/9/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding scoffing family members)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"What is done is done, yet need not be. For many remain lost in confusion, hearing the Word of My mouth, yet denying the power thereof."}]},{type:"para",segments:[{t:"text",v:"Therefore, woe to the nay-sayers! Woe, I say to you! For you have failed to discern; indeed, you refuse to understand. For you can not bear to hear the Truth Absolute, nor will you accept Me as I truly am. For you long for that which is malleable, embracing only that which yields to your own perverse desires and expectations. Behold, the Spirit of Truth has departed from you; My hand is removed. Thus you remain lost in the deceptions of this world and the churches of men, leaning always upon your own preconceived notions of what you think the truth is and should be, reconciling within yourself that you know the will of God and the meaning of The Word, as you twist the Scriptures to your own shame. I do not know you! Such arrogant, high-minded children who call of themselves Christian! False servants who cease not from polluting My name and My glory, stomping upon the new faith sprouting in others, persecuting and slandering all those I send! And so it is fulfilled:"},{t:"italic",v:"In stony places has The Word of God been sown, springing forth quickly in the hearts of those whose ears yet hear and whose eyes yet see, yet when the heat of persecution comes, oh how quickly they fall away."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"text",v:"Therefore, woe to the nay-sayers;"}],[{t:"text",v:"Woe to all who lead My people astray!"}]]},{type:"poetry",lines:[[{t:"text",v:"For I am come forth to reap, to gather My own..."}]]},{type:"poetry",lines:[[{t:"text",v:"And to punish those who sow seeds of"}],[{t:"text",v:"Dissension and falsehood in My Garden..."}],[{t:"stanza-break"}],[{t:"text",v:"Says The Lord."}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 13:20-21"}},nkjv:{"Matthew 13:20-21":"20. But he who received the seed on stony places, this is he who hears the word and immediately receives it with joy; 21. yet he has no root in himself, but endures only for a while. For when tribulation or persecution arises because of the word, immediately he stumbles."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-sower-has-sown-yet-the-seeds-have-fallen-among-thorns-and-stony-places",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-sower-has-sown-yet-the?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=i0zbhQkKwVU&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"My Hand is Removed",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets#.22My_Hand_is_Removed.22"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"}],num:2,prevLetter:{id:"deceptions",title:"Deceptions"},nextLetter:{id:"the-last-trump",title:"The Last Trump"}},{id:"the-last-trump",title:"The Last Trump",date:"2/10/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"I AM COME!"},{t:"fn",v:"1"},{t:"text",v:"Says The Lord. Therefore arise and give answer, O peoples of the earth! Who is the face and image of The Invisible God?! Who?! It is He I have sent, The One who is and was and is to come! Behold, He shall wait no longer, for the Day of The Lord is at hand and the time appointed draws near! For The Son of Man shall enter in and gather them together, He shall surely pass through and prepare the harvest - HE SHALL REAP!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, for thus says The Lord:"},{t:"text",v:"My spirit is poured out. My watchmen are called, My prophets sent; they prepare My way before Me. And if you are willing to receive it, they are John and Elijah, My witnesses, even 144,000"},{t:"fn",v:"2"},{t:"text",v:"; and behold, they shall surely baptize with My Word and fire. Who else shall I send?! Who will go for Me?! Who will noise in the four corners and shout from the rooftops?"}]},{type:"poetry",lines:[[{t:"italic",v:"WATCHMEN, stand up and blow the Trumpet!"}],[{t:"italic",v:"For the Great and Terrible Day of The Lord draws near..."}]]},{type:"poetry",lines:[[{t:"italic",v:"PEOPLES OF THE EARTH, repent and be spared!"}],[{t:"italic",v:"For The Thief is about to enter the house and take His spoil;"}],[{t:"italic",v:"Behold, He has entered the hearts of the penitent already,"}],[{t:"italic",v:"And has but to call out, and they shall be snatched away..."}]]},{type:"poetry",lines:[[{t:"italic",v:"CHURCHES OF MEN, let My people go!"}],[{t:"italic",v:"For The Master is coming quickly, and He shall surely"}],[{t:"italic",v:"Purge every temple and tear down every house,"}],[{t:"italic",v:"Which pollutes My name and desecrates"}],[{t:"italic",v:"The glory of My majesty..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore do not wait, beloved ones,"}],[{t:"italic",v:"COME OUT FROM AMONG THEM!"}],[{t:"italic",v:"For the Day of Judgment is at hand."}]]},{type:"para",segments:[{t:"text",v:"Behold, judgment shall rain down from Heaven upon every tribe, tongue and people - RECOMPENSE FOR ALL NATIONS! Calamity upon calamity shall overtake the land, disaster shall reach into every corner, even to the ends of the earth! For who can hide from the face of God revealed in His hot displeasure, burning in the fierceness of His wrath?! Who is able to drink from the cup of My indignation, and live?! For it is written:"},{t:"italic",v:"Unless those days were shortened no flesh would be saved."},{t:"fn",v:"3"},{t:"text",v:"For the heavens shall be set on fire above, and the earth shall become a desolation beneath. Yet whoever calls upon the name of The Lord, in sincerity and in truth, shall be delivered, says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord, to the generation of His wrath:"},{t:"text",v:"I have trumpeted to you, yet you cover your ears. I shall show great signs and wonders, the likes of which have never been seen (indeed many signs are made plain already), yet you shall cover your eyes. Indeed you refuse to repent, neither will you humble yourselves and consider. For your hearts are hard, your countenances unyielding, a vile people who despise The Truth! Therefore judgment is coming quickly, and shall fall hard upon the desolate, the high-minded and the hypocrite - ALL shall be broken; some broken and uplifted, and many broken and condemned. Behold, before the sixth seal is broken, I shall deal to the hard-hearted a glancing blow: One shall be taken, and the other left. For the innocent shall be taken, and the upright in heart shall be hidden, as many as receive My words and also do them. Behold, even those asleep in Messiah shall come forth, and they too shall be gone from this place, for I know My own..."},{t:"italic",v:"The earth shall starve, all light gathered and taken, darkness, thick clouds and darkness, the Great and Terrible Day of The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, for thus declares The Lord:"},{t:"text",v:"Travesty, great travesty is coming and is already here; even the abomination which causes desolation shall be revealed. Atrocities and war shall increase, perversions of every kind shall reach unto new heights in wickedness, as injustice upon injustice is perpetrated in every land, to the rending of the hearts of all people. Thus I have declared the Day"},{t:"fn",v:"4"},{t:"text",v:"and set the hour: JUDGMENT for all who fight against Me! RECOMPENSE for all who harm My little ones or persecute My messengers! REFINEMENT for those who refuse to embrace Me as I truly am!..."},{t:"italic",v:"Yet glory for those who glory in Him who gave His life as a ransom, deliverance for those who obey The Son, sanctuary for the innocent."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore love The Lord your God"}],[{t:"italic",v:"With your whole heart, and find sanctuary"}],[{t:"italic",v:"In The One through whom you were made..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Kiss The Son!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For He alone is The Loving Mercy of God,"}],[{t:"italic",v:"Your only Salvation..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Way, The Truth, The Life."}]]}],footnotes:{1:{type:"note",text:'See: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}},2:{type:"note",text:'See: "Regarding the 144,000 Witnesses"',url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},3:{type:"scripture",ref:"Matthew 24:22"},4:{type:"note",text:'See: "You Have Entered In"',url:"https://www.thevolumesoftruth.com/You_Have_Entered_In#:~:text=thus%20says%20The%20Lord%3A%20You%20have%20entered%20in%3B%20yes%2C%20The%20Day%20is%20here%20and%20ALL%20have%20entered%20in!",link:{collection:"A Testament Against The World: The Lord's Rebuke",letterTitle:"You Have Entered In",excerpt:"You have entered in; yes, The Day is here and ALL have entered in!"}}},nkjv:{"Matthew 24:22":"And unless those days were shortened, no flesh would be saved; but for the elect\u2019s sake those days will be shortened."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-last-trump-4",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-last-trump-full-letter?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=QwBwcB1o1IE&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=2",videoMusicUrl:"https://www.youtube.com/watch?v=is7w_QCLU_8&list=PLSVchFJ22QYKZW4CHtZ43YBxdHUTgS9rv&index=1",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:'"He Who Was and Is and Is to Come"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#He_Who_Was_and_Is_and_Is_to_Come"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"}],num:3,prevLetter:{id:"the-sower-has-sown-yet-the-seeds-have-fallen-among-thorns-and-stony-places",title:"The Sower Has Sown, Yet the Seeds Have Fallen Among Thorns and Stony Places"},nextLetter:{id:"the-mountains-shall-crumble-and-fall-upon-the-desolate",title:"The Mountains Shall Crumble and Fall Upon the Desolate"}},{id:"the-mountains-shall-crumble-and-fall-upon-the-desolate",title:"The Mountains Shall Crumble and Fall Upon the Desolate",date:"2/17/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"I am The God of Jacob, The God of Isaac, The God of Abraham; I am The I AM. I am God alone; there is no other."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord and give heed, for thus says The Lord to this most wicked generation, to the last of these kingdoms of men:"},{t:"text",v:"You are maimed! You have altogether become as one whose ears have been cut off! For you will in no wise hear Me, nor are you able! This world has seduced you, and eagerly do you embrace the seduction! Thus your portion shall be sorrow, and your lot the grave! For the wicked shall lie down in death, and the evil of heart shall be struck down - Broken off! Blotted out!"}]},{type:"para",segments:[{t:"text",v:"Behold, even you, O churches of men, have been seduced! For you do not cease from committing fornication with the harlot! Indeed you have embraced many lovers, lying down in beds of false doctrine, covering yourselves with the filth of the pagan and the heathen, committing many acts of adultery by your traditions, as you continue to indulge in those things which I hate! YOU HAVE CAUSED MY PEOPLE TO SIN! YOU HAVE ALTOGETHER TURNED THEM ASIDE FROM THE TRUTH! For you have preached to them another messiah, a false christ, passed down to you by your forefathers, an idol arrayed in purple and scarlet, which even now you mold to your own likeness, according to your own perverse desires and arrogant assumptions! - Blind guides! Foolish children! YOU ALL SLEEP! Yea, you fold your hands to rest, that you may remain at ease in your slumber! Awake! Free yourselves from the deluge of lies, from this great flood of sin! AWAKE! And go and wash yourselves in the pool of Siloam, yea, immerse yourselves in The Healing Pool of God, which was sent. Beloved, wash yourselves, make yourselves clean, and come out from among them! Be separate from all these commandments of men, from all these false doctrines and filthy traditions, and I will receive you! Yet you refuse Me, nor will you come out. For you want no part with Me as I truly am. Thus you remain under judgment, and the shadow of death covers you. Behold, My own people sin against Me, for they are"},{t:"italic",v:"not"},{t:"text",v:"My people. For they do always testify falsely, as they continue to pervert My name in all the earth. Therefore every lampstand shall be removed from its place, all light gathered and taken; darkness, thick clouds and darkness, cover the face of the earth."}]},{type:"para",segments:[{t:"italic",v:"Beloved children, you have rejected Life! You have turned your backs on Forgiveness! WHY HAVE YOU FORSAKEN ME?! My heart bleeds with sorrow, as I look upon the works of your hands! Anguish grabs hold of Me, as I search your hearts and minds! Deep mourning fills Me, as I stretch out My hand to bring destruction upon you!... Great and bitter sorrows, unending grief, My children have departed from Me."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Holy One of Israel, to this lost and dying generation; thus says He who died and is alive forevermore:"},{t:"text",v:"I am The Only Way by which you shall enter, having ripped the curtain in two; I am The Open Door by which all My beloved shall pass through. Yet you refuse to come to Me, nor will you accept Me as I truly am. How then shall you enter? How then shall you pass through? Behold, I had sent to you My apostles, that you might learn of My ways. I had sent to you My prophets, that you might hear the Word of My mouth and receive of My correction. Indeed throughout your generations, I sent to you many servants, as lambs amongst wolves, yet you persecuted and slandered them all. And still I send more, behold, even a multitude as The Father wills, yet as in all times past you will stone them in word and by deed. Therefore, woe! Woe to the arrogant scoffer and the high-minded hypocrite! Woe to all who take the name of The Lord in vain! All your works shall come to an abrupt end, and that which you spew at My chosen shall return atop your own head! For My prophets are sent and prepare My way before Me, sounding the alarm, trumpeting My strong rebuke. Behold, they shall call all people to repent and warn every nation; yes, they shall give a shout and blow the Trumpet. And whether you will hear or whether you will forbear, they shall surely sing. For it has been appointed to My witnesses to sing a new song, of which only they know and shall be revealed. And behold, they shall sing with a loud voice in concert, to every tribe, tongue, people and nation. And whether the multitudes will hear or forbear, My servants shall surely sing. For the song must be sung and is sung already."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord God, The Only Holy Father, Creator of Heaven and Earth:"},{t:"text",v:"Call upon the name of The Messiah, and listen to those I send. For the time of judgment is at hand, the Day of The Lord draws near. Peoples of the earth, do you not feel My quaking footsteps? Do you not feel the earth tremble? Behold, the mountains shall crumble and fall upon the desolate, every high place shall be broken down. Therefore as it is written:"},{t:"italic",v:"Kiss The Son, lest He be angry and you perish in the way, when His wrath is kindled but a little."},{t:"fn",v:"1"},{t:"text",v:"For most assuredly, I say to you, the fire is already kindled, and on a day you did not look for and at an hour you did not expect, the cup of My fury shall be poured out; behold, it shall be imparted in full!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, blessed are those who call upon the name"}],[{t:"italic",v:"Of The Messiah, in sincerity and in truth,"}],[{t:"italic",v:"For the Spirit of God dwells within them..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Blessed are those who seek refuge in Him,"}],[{t:"italic",v:"For they shall find it..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Blessed are all those who love and"}],[{t:"italic",v:"Obey The Son, for they shall be delivered..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Psalm 2:12"}},nkjv:{"Psalm 2:12":"Kiss the Son, lest He be angry, And you perish in the way, When His wrath is kindled but a little. Blessed are all those who put their trust in Him."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-mountains-shall-crumble-and-fall-upon-the-desolate",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-mountains-shall-crumble?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=GFFWRosk11c&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"}],num:4,prevLetter:{id:"the-last-trump",title:"The Last Trump"},nextLetter:{id:"woe-to-the-captives-of-this-world",title:"Woe to the Captives of This World"}},{id:"woe-to-the-captives-of-this-world",title:"Woe to the Captives of This World",date:"2/24/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Harken to My Word, O house of Jacob, listen to My voice, all you captives of Israel, and let all in the isles receive understanding, for the mouth of The Living God has spoken. Indeed let every tribe, tongue, people and nation hear the Word of The Lord. From those who dwell in the desolate lands, to all those who abide in the fenced cities, to all those who spread forth across the land, even unto the ends of the earth, hear the voice of The Living God..."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"Come out and humble yourselves, O peoples of the earth! Repent of your evil deeds, turn aside from all this iniquity and return to Me! For you have forsaken Me! Days without end you deny My name and shake your fists at Heaven, as you reject The Salvation of God; behold, you spit upon The Name and desecrate My Word, without ceasing! Therefore harken to My voice, says The Lord, for I am come!"},{t:"fn",v:"1"},{t:"text",v:"And behold, judgment shall blaze before Me and great desolation after!..."}]},{type:"para",segments:[{t:"italic",v:"Woe to all who forget God and parade their whoredoms openly in the streets! You shall by no means escape the Day of Wrath when it comes! For I shall deal with you swiftly, even recompense in full, according to the example!"},{t:"fn",v:"2"},{t:"italic",v:"Woe to every high mountain! Woe to every uplifted hill! Woe to all high places, to everything high and lofty! WOE TO ALL WHO SEEK TO EXALT THEMSELVES ABOVE THE MOST HIGH! Woe to the giants of this world and to the mighty oppressor! Woe to all who step on the fingers of the poor and steal from the needy! Woe to all who conspire together in secret, to do My people harm! And woe, even three times woe, to all who harm the little ones and those not yet born from the womb! WOE TO ALL WHO MURDER THE INNOCENT, AND TO ALL WHO STAND IN AGREEMENT! A double portion of wrath is reserved for you!"}]},{type:"para",segments:[{t:"text",v:"For I tell you the truth, not one spring of water flows in purity, not one piece of bread is offered freely or without leaven. All is corrupt, dead men's bones in a wasteland of iniquity and sin. Every table is covered with flies, a feast of abominations is always before their eyes, leaving them void and desolate. For none harken, nor does one truly give heed, for all cry aloud, saying,"},{t:"italic",v:"\u201CCast these shackles from us! Let us alone, for we go our own way! Our knowledge transcends Heaven, our egos reign!\u201D"},{t:"text",v:"Thus they have made their covenant with death, and with the grave they are in agreement."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore take up a lamentation on the"}],[{t:"italic",v:"Desolate heights, for The Lord has rejected"}],[{t:"italic",v:"And forsaken the generation of His wrath!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yea, cry out to The Lord in sincerity and in truth,"}],[{t:"italic",v:"With deep remorse over all you have done,"}],[{t:"italic",v:"And I may yet have mercy upon you."}]]},{type:"para",segments:[{t:"text",v:"Cry out to The Lord your God, for there is no other, fall down at the feet of your Savior, for there is but One, and confess, saying,"},{t:"italic",v:"\u201CWe have done an evil thing, we have committed great iniquity throughout the land! We are desolate, starving and in bitter thirst! Heal us, O Lord! For we have eaten up all the bread, broken every staff, and defecated in the pools of living water from which we were to drink! Surely we are wretched, miserable, poor, blind, deaf and naked!... Save us, O Lord!\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord God, to those near and to those who remain afar off:"},{t:"text",v:"Beloved ones, I have saved you already, having sent The Lamb of God slain from the foundation of the world. He was come into the world, and you would not receive Him..."},{t:"italic",v:"Blessed are those who have received Him; Grace covers them."},{t:"text",v:"Behold, He is coming again, and He have I poured out on every nation, yet you are offended in Him..."},{t:"italic",v:"Blessed are the thirsty who have drunk deeply from His cup; they are filled with His glory."},{t:"text",v:"Behold, He shall call out, He shall surely gather, yet you will neither see nor hear Him..."},{t:"italic",v:"Blessed are those who have eyes to see and ears to hear, for they shall surely be gone from this place."},{t:"text",v:"Yet now the time has come for this generation to drink from another cup; behold, they shall taste of it to the fullest! For it is the chalice of My reckoning, and it shall consume them! Thus as I punished My enemies in all times past, so also shall I stretch out My hand against this most wicked generation. For I am The Lord, and I do not change."}]},{type:"poetry",lines:[[{t:"italic",v:"Even so, blessed are all those who call on the name"}],[{t:"italic",v:"Of The Lord in that day, for as it is written:"}]]},{type:"poetry",lines:[[{t:"italic",v:"It shall come to pass that whoever calls"}],[{t:"italic",v:"On the name of The Lord shall be saved..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For in Mount Zion and in Jerusalem,"}],[{t:"italic",v:"There shall be deliverance among the"}],[{t:"italic",v:"Remnant whom The Lord shall call."},{t:"fn",v:"3"}]]}],footnotes:{1:{type:"note",text:'See: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}},2:{type:"scripture",ref:"2 Peter 2:6, Jude 1:7"},3:{type:"scripture",ref:"Joel 2:32"}},nkjv:{"2 Peter 2:6, Jude 1:7":"2 Peter 2:6 \u2014 and turning the cities of Sodom and Gomorrah into ashes, condemned them to destruction, making them an example to those who afterward would live ungodly; | Jude 1:7 \u2014 as Sodom and Gomorrah, and the cities around them in a similar manner to these, having given themselves over to sexual immorality and gone after strange flesh, are set forth as an example, suffering the vengeance of eternal fire.","Joel 2:32":"And it shall come to pass That whoever calls on the name of the LORD Shall be saved. For in Mount Zion and in Jerusalem there shall be deliverance, As the LORD has said, Among the remnant whom the LORD calls."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/woe-to-the-captives-of-this-world",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/woe-to-the-captives-of-this?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=aFeOa9_3-rI&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=8",videoMusicUrl:"https://www.youtube.com/watch?v=T8bVyz3Tt-o&list=PLSVchFJ22QYKZW4CHtZ43YBxdHUTgS9rv&index=1",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"}],num:5,prevLetter:{id:"the-mountains-shall-crumble-and-fall-upon-the-desolate",title:"The Mountains Shall Crumble and Fall Upon the Desolate"},nextLetter:{id:"the-watchman",title:"The Watchman"}},{id:"the-watchman",title:"The Watchman",date:"3/19/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Abominations swell in the holy lands; great wickedness fills the entire earth! Sins of every kind are committed without ceasing, and perversion is celebrated openly in the streets. Vines of wickedness grow unimpeded, spreading forth iniquity, growing and spreading and putting down roots. Behold, they climb the walls and enter in through the cracks, as they seek new ways to invade every stronghold and break down every barrier."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of My mouth, Timothy, and give heed, for the time has come:"},{t:"text",v:"I have ordained you a prophet to the nations, and you shall be for Me a mouthpiece and a witness, a watchman crying out in the midst of this desolate land, saying,"},{t:"italic",v:"\u201CPrepare the way of The Lord! Set all these crooked paths straight!\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, as an adamant stone"}],[{t:"italic",v:"I have set you against them,"}],[{t:"italic",v:"A rock of offense which can not be broken,"}],[{t:"italic",v:"A stone of stumbling which can not be moved..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, My son, take what I have given you"}],[{t:"italic",v:"And convict this generation of its evil ways;"}],[{t:"italic",v:"Reprove, rebuke, and exhort..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I shall kindle a fire within you,"}],[{t:"italic",v:"And into your ears I shall speak,"}],[{t:"italic",v:"And through you I shall make My plans known"},{t:"fn",v:"1"},{t:"italic",v:"..."}],[{t:"stanza-break"}],[{t:"italic",v:"For I am The Lord, and I do not change."},{t:"fn",v:"2"}]]},{type:"para",segments:[{t:"text",v:"For there are many who claim to know Me, yet do not really know Me. There are many who are wise in their own eyes, yet of My ways they have no knowledge. Yes, there are many who will come out and fight against you, doing so in the name by which I am called among them. They shall slander you, and spit upon you, and seek to do you harm. Indeed, they shall persecute you in word and by deed, saying,"},{t:"italic",v:"\u201CLook at this man! He is unlearned, and yet he speaks to us with authority. Shall he teach us?! How dare he correct us! For we know The Lord and His will and have served Him our whole lives. Is this not one of the prophets, the kind of which The Lord spoke about, who would come speaking and doing miracles, that he might fool even the elect?\u201D"},{t:"text",v:"Yet do not listen to them, Timothy. Do not be turned aside, nor go after them; do not be moved. Give heed to none of their arrogant and dark speeches, listen to not one word that proceeds from their mouths. Be not turned to the right hand, nor to the left, but go straight forward, proclaiming My Word by all manner of speaking and devices. For those who glorify Me in The Messiah\u2019s name, and obey My Commandments, are true; they are by no means false. For My spirit dwells within them, and I Myself have sent them. I AM THE LORD."}]}],footnotes:{1:{type:"scripture",ref:"Amos 3:7"},2:{type:"scripture",ref:"Malachi 3:6"}},nkjv:{"Amos 3:7":"Surely the Lord GOD does nothing, Unless He reveals His secret to His servants the prophets.","Malachi 3:6":"\u201CFor I am the LORD, I do not change; Therefore you are not consumed, O sons of Jacob."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-watchman",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-watchman?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=9HYVSHUqp6w&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=11",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:6,prevLetter:{id:"woe-to-the-captives-of-this-world",title:"Woe to the Captives of This World"},nextLetter:{id:"desolations-are-determined",title:"Desolations Are Determined"}},{id:"desolations-are-determined",title:"Desolations Are Determined",date:"3/19/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel:"},{t:"text",v:"Woe to the kingdoms of this world! Woe to the false religions of this world! The atheist shall have it far better than you, when the wrath of the great and dreadful God has come! Woe to the king of the north! Woe to the kings from the rising of the sun! Woe to the king of Persia and the people of violence! Woe to every nation and people, who say,"},{t:"italic",v:"\u201CCome, let us put an end to Israel as a nation. Let us utterly destroy them, that the name of Israel may be remembered no more!\u201D..."},{t:"text",v:"BEHOLD, I AM AGAINST YOU! Says The Lord God."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, to the king of the north:"},{t:"text",v:"Come and mount up your troops, and take flight. Call upon your agreement with those of the rising sun. Honor your covenant with the people of violence. Cast your devices and launch all your weapons of war. Come against My chosen people and the land promised to their forefathers, forever! COME! Says The Lord. Fulfill the evil desires of your wicked hearts. For you shall fall, and you shall not be found! Says The Lord of Hosts. You shall be a valley of dead and dry bones, buried in the land you came to destroy, for it shall consume you! - Food for the birds, dwelling place of the worm. Therefore come, I say! Come, and leave your spoil and your rotting flesh! For you shall surely stumble, you shall fall, and you shall not be found! And by your falling shall the name of The Lord be glorified in every land, even unto the ends of the earth! For this is but an awakening, and many shall behold it, the mighty and awesome power of The Lord! Behold, the earth shall be shaken, the clouds shall burst! I shall command pestilences to come upon you; they shall cleave to you and drink your blood, and you shall be driven mad. For you shall stumble, you shall fall, and you shall not be found! (Save a sixth part whose hearts I know; they shall return home and be spared.) For in your eagerness to spoil shall you become the spoil, and sustain My people seven days. Swiftly shall I destroy this great multitude who come out to fight against Me, who seek to destroy My people, Israel! For they shall be driven to the ground by fire, by hail, and by thick darkness! FOR STRONG IS THE LORD WHO DEFENDS ISRAEL!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My countenance has changed!"}],[{t:"italic",v:"My face is set hard against you, O enemies of Israel!"}],[{t:"italic",v:"My arm is outstretched and ready for battle!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus that which is written shall be fulfilled,"}],[{t:"italic",v:"And that which is determined shall be done,"}],[{t:"italic",v:"And you shall be left utterly desolate!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then all shall know, I AM THE LORD!"}]]},{type:"para",segments:[{t:"text",v:"Yet understand this, O house of Israel: I do not do this for your sake, but for My holy name\u2019s sake. For My name is profaned among the nations. And you, O Israel, have not obeyed My Word, neither have you walked in The Way I have shown you. For you yet reject The One who I had sent to you, The Holy One who was glorified upon the tree. Thus His blood remains upon you. For you are the children of your fathers, the descendants of those who killed The Author of Life!"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus I have spoken it,"}],[{t:"italic",v:"And it shall surely come to pass..."}]]},{type:"closing",text:"Says The Lord of Power and Glory."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/desolations-are-determined",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/desolations-are-determined?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=69eCl7r4fGU&list=PL5D6C231C451A2F0C&index=4",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:7,prevLetter:{id:"the-watchman",title:"The Watchman"},nextLetter:{id:"you-shall-not-desecrate-the-sabbath",title:"You Shall Not Desecrate the Sabbath"}},{id:"you-shall-not-desecrate-the-sabbath",title:"You Shall Not Desecrate the Sabbath",date:"3/29/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"You shall not desecrate the Sabbath, the seventh day of the week, which I have commanded you to remember and keep holy. For as I had spoken it to My servant Moses, so it is and shall be, even to this day. And as I had spoken it before the congregation, so shall it be done. Yea, with the blowing of the great trumpet, with lightnings and thunderings, did I declare My Law; before the tribes of Israel, and in the presence of angels, did I put My power on open display. Behold, by My own finger was it engravened upon tablets of stone, and by the power of My spirit is it established within the hearts of the penitent."}]},{type:"para",segments:[{t:"text",v:"Yet the churches of men forsake The Law, and the peoples of this world seek to tear down My Commandments! Thus they shall surely die! For transgression of The Law is sin, and the penalty of sin is death. Yet a New Covenant I have sent to you in YahuShua The Messiah, to save you from the penalty of that which you have forsaken. Therefore, you shall live because of Him and set your steps aright, according to that which He upholds and has magnified in Himself, He being the only One who is without sin, having kept every tittle of The Law - blameless. For it is written:"},{t:"italic",v:"It is easier for the heavens and the earth to pass away, than for one tittle of The Law to fail."},{t:"fn",v:"1"},{t:"text",v:"For the spirit of The Law is shown in The Messiah\u2019s vesture, He being the same One who taught you The Law anew, by His example and by His every word and deed. For The Law is fulfilled in The Messiah;"},{t:"italic",v:"indeed, He is the goal at which the Torah aims."},{t:"fn",v:"2"},{t:"text",v:"Thus He is The Lord of The Law"},{t:"italic",v:"and of the Sabbath."},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"italic",v:"So then give answer, O churches of men:"}]]},{type:"poetry",lines:[[{t:"italic",v:"If He is The Lord of the Sabbath,"}],[{t:"italic",v:"Having obeyed My every command,"}],[{t:"italic",v:"Why do you not follow Him?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You say you follow Him and honor Me,"}],[{t:"italic",v:"Yet most assuredly, I say to you, you shall"}],[{t:"italic",v:"All be found liars in the Day of Reckoning!..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"text",v:"And you, O church called Roman and Catholic, how We mourn for you! For you have been judged, and shall be left utterly desolate in the Day of The Lord\u2019s Anger! You say you speak for Me and have The Messiah\u2019s authority, yet I tell you, you have trampled upon the grave of The Resurrected One, making His sacrifice of no effect! WOE TO ALL WHO BLASPHEME THE SPIRIT! Throughout your generations you have not ceased from transgressing The Law by your traditions! Even to this day you embrace every foul and contemptible doctrine, reveling in those things I hate! Behold, you pollute the name of The Messiah by all you say and do, as you lead the people astray! O unholy church of adulteries, mother of all fornications and lies, your destruction draws near! You have become Egypt! LET MY PEOPLE GO! Stop desecrating My Sabbaths! The seventh day is the Sabbath, which I had ordained from the beginning! Cease from your heresies, hold your tongue from your blasphemies, turn back from this wicked way you have chosen, AND REPENT, and I may yet have mercy upon you! For I am The Lord, and I DO NOT CHANGE! Therefore heed My words and bow down, O unholy church of men! Hear the Word of The Lord, and be broken in pieces! For The Holy One is coming quickly and will take from you His own; He shall snatch them from your very breast! And no more shall My children receive nourishment from you! No more shall they be held captive under the veil of your deceptions! The light shall be taken from you, and you shall be left all alone, utterly estranged, on account of your unending adulteries and for the multitude of your whoredoms, which you performed in MY NAME!"}]},{type:"para",segments:[{t:"text",v:"Thus your fate lies with him who is coming, the wicked one who shall lead many into perdition and death. You shall bear him a son, a man who bears the number of his name, his prophet. Yet you will not be alone when desolations come; you and your enemy, Ishmael, shall receive recompense in full. For you both remain children of your father, the devil."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, The Mighty and Strong One"}],[{t:"italic",v:"Shall return and take from the earth"}],[{t:"italic",v:"His own, and great recompense"}],[{t:"italic",v:"Shall be poured out on all nations..."}]]},{type:"poetry",lines:[[{t:"italic",v:"He shall come in power and great glory,"}],[{t:"italic",v:"And Judgment shall sit..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet all who come out from among them,"}],[{t:"italic",v:"And call upon the name of The Holy One of Israel,"}],[{t:"italic",v:"In spirit and in truth, shall be delivered..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Luke 16:17"},2:{type:"scripture",ref:"Romans 10:4 (CJB)"},3:{type:"scripture",ref:"Matthew 12:8"}},nkjv:{"Luke 16:17":"And it is easier for heaven and earth to pass away than for one tittle of the law to fail.","Romans 10:4 (CJB)":"For the goal at which the Torah aims is the Messiah, who offers righteousness to everyone who trusts.","Matthew 12:8":"For the Son of Man is Lord even of the Sabbath.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/you-shall-not-desecrate-the-sabbath",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/you-shall-not-desecrate-the?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=UcYENImQxWs&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=12",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Index of False Doctrines Within the Churches of Men",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"}],num:8,prevLetter:{id:"desolations-are-determined",title:"Desolations Are Determined"},nextLetter:{id:"culmination",title:"Culmination"}},{id:"culmination",title:"Culmination",date:"3/30/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, The God of Israel, The Only Lord of Hosts:"},{t:"text",v:"My anger is aroused and shall not be quenched, until every tall tower is torn down and shaken to dust, and not one fenced city is left standing! In My hot displeasure, I shall turn My hand against the earth, and smite every bird, beast and crawling thing! Every fish shall die, every creature of the sea shall perish, when I strike the waters! I shall not relent nor turn back, until every blade of grass is burned up, and every tree has been stricken and bears neither leaf nor fruit! The earth shall be forsaken for a time and made utterly desolate, with the kingdoms of men left in ruins!"}]},{type:"para",segments:[{t:"text",v:"Therefore gather together, O children of the man of perdition, all you who bear the number of his name; come and gather against My Holy Mountain! Yes, look up and behold the Glory of God wrought in His Mighty and Strong One, The Holy One of Israel, and prepare to meet your end! - Consumed in His glory, cut asunder by the sword of His mouth! For you are accursed in My sight, and there shall be none to deliver! Your bodies shall consume away; your eyes in their sockets, your tongues in your mouths, your flesh from your bones!"},{t:"fn",v:"1"},{t:"text",v:"For thus is the reward of all who come out to fight against Me in that day!... It is finished."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold a new day, the seventh, even one thousand years!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The kingdoms of this world have become"}],[{t:"italic",v:"The Kingdom of God and His Messiah,"}],[{t:"italic",v:"And He shall reign forever and ever!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Zechariah 14:12 (HNV)"}},nkjv:{"Zechariah 14:12 (HNV)":"This will be the plague with which Yahweh will strike all the peoples who have fought against Jerusalem: their flesh will consume away while they stand on their feet, and their eyes will consume away in their sockets, and their tongue will consume away in their mouth."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/culmination",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/culmination?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=7oWn2RuXFes&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Antichrist",url:"https://answersonlygodcangive.com/Regarding_the_Antichrist"},{label:"Regarding the Mark of the Beast",url:"https://answersonlygodcangive.com/Regarding_the_Mark_of_the_Beast"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:9,prevLetter:{id:"you-shall-not-desecrate-the-sabbath",title:"You Shall Not Desecrate the Sabbath"},nextLetter:{id:"the-truth-absolute",title:"The Truth Absolute"}},{id:"the-truth-absolute",title:"The Truth Absolute",date:"4/7/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The God of Israel, Lord of Heaven and Earth, of all that is seen and unseen, known and unknown, The God of all:"},{t:"text",v:"There is One Truth, One Absolute, One Constant in all creation, in whom the fullness of God dwells - YahuShua HaMashiach."}]},{type:"para",segments:[{t:"text",v:"All else is fantasy, great vexation of spirit. For the people are corrupt; by the deceits of their own hearts are they led away. My beloved are misled, they have all gone astray, a whole generation scattered upon the wind. For the ways of men are an abhorrence to Me, their every religion is an abomination. The sins of men are great, and their iniquity increases beyond measure. Behold, they make for themselves molded images, useless things, and by the mouths of wicked men every false way is upheld in vain. For the people have no knowledge, nor do they understand. They are perverse, a most wicked generation, a people who hold out their cup with both hands, that they might fill themselves with abomination. Behold, the broth of abominable things is in their vessels, yet they are eager to drink. They are foolish and can not discern. The works of men are evil, even from their youth. Thus the little children shall be My inheritance, and the babes My jewels. For the innocent come forth as lights shining out of darkness, gifts born from the womb. They are precious; to be cherished is every child in their youth. For the innocent are of more value than gold and silver, prized above precious stones. Therefore, woe to this world and all who dwell in it! WOE TO ALL WHO AFFLICT MY LITTLE ONES! SAYS THE LORD. For I shall strike the earth in My wrath and punish the wicked! I shall strike the earth, and bring swift discipline upon all who lead My people from The Truth! In My great anger, I shall strike them down and bring everlasting punishment upon the evil of heart, for death is reserved for the wicked! - A valley of dead and dry bones, darkness and blackness, a void of lifeless nothingness! Behold, I shall pour out in My anger and destroy in My fury! With eternal fire, I shall take vengeance upon all My enemies, until they are utterly consumed! For thus is the second death prepared for the wicked; thus is the second death, in which the evil of heart shall be consumed: Destruction and annihilation, blotted out!..."},{t:"italic",v:"The death of which the redeemed in Messiah need not fear; for they have passed from death to Life, from despair to Joy, and from judgment to Salvation; bought for a price, purchased in blood, the blood of The Lamb."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore come to Me, My beloved little ones,"}],[{t:"italic",v:"For you know My face!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come forth, O sons and daughters of God,"}],[{t:"italic",v:"For The Lord has redeemed you!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come out, My people,"}],[{t:"italic",v:"For The Holy One of Israel has called you by name!"}]]},{type:"para",segments:[{t:"text",v:"Do not look back, nor hesitate. Turn not the head, nor twist the shoulder. Beloved ones, do not look back! For abomination dwells there, Sodom and Gomorrah! Thus the time of My watchmen has come, the Day of Punishment is made clear. Behold, it waits at the doors and is about to come in, terrible judgment poured out without mixture! - Destruction of the cities! The distress of all nations! WOE TO THE SONS OF MEN! WOE TO THE INHABITANTS OF THE EARTH, FOR NOW SHALL BE YOUR PERPLEXITY! SAYS THE LORD."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord God:"},{t:"text",v:"Great patience and steadfast faith is required. For great and terrible things are coming, days which have no equal. For upon the earth, evil of every kind proliferates unfettered. Iniquity is upheld and righteousness is trampled underfoot. Damnable heresies are taught in the churches, and blasphemy is heard within the synagogues. Temples of false gods litter the face of the earth, and mosques pollute the land like a plague - abomination, blasphemies without end, lies upon lies fed to the masses as truth! Shall I not come forth and destroy?! Shall I not come out swiftly and take vengeance upon My enemies?! Shall I not bring swift destruction upon them, until not one stone is left upon another?! THE DAYS ARE EVIL! The light of the eye has darkened, iniquity fills the heart, and sins of every kind come forth from the people without respite! They do not relent, nor has one truly turned aside! For out of the abundance of the heart the mouth speaks, and those void of the Spirit can not discern. Therefore those with unclean lips prosper, and the desolate kiss them upon the mouth. For this is a most vile generation, a wholly ignorant and deceived people who can not discern, nor will they consider. For they hate the one who rebukes at the gate, and despise the one who speaks a message from God. Shall I not cause the earth to tremble for this?! Shall it not break apart under their feet?! For I shall open the mouth of sheol, and a great multitude shall fall into it. The nations shall mourn, and all those who remain shall be overcome with grief. For from the least, even to the greatest, they have all forsaken The Word of The Lord! Therefore, I call My beloved to choose starvation, to forsake all this worldly food. For only that which comes down from Heaven has life in it, and only those who eat of the manna which I shall give them shall be satisfied; yea, they shall be lifted up, high upon healing wings! For this world is awash in sin, every cup overflows with abomination, every way leads to death. Thus those who take pleasure in unrighteousness shall be cut off, and those who choose evil shall be condemned. And so it begins, the short season of him cast down, when evil reigns in all the earth."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, The Risen One:"},{t:"text",v:"Therefore, I call My beloved ones to be sober and vigilant, because their enemy, the adversary, stalks about like a roaring lion, seeking whom he might devour. Behold, he stalks his prey and grabs hold by that which dwells within their hearts. Therefore, beloved, take every thought captive and resist the devil. Believe not the lies, nor give into fear, nor doubt; be steadfast, immovable, abounding in faith. For I am with you. For as it is written:"},{t:"italic",v:"I am the image of The Invisible God, The Firstborn over all creation. By Me were all things created, both visible and invisible, in the heavens and on earth. Whether thrones or dominions, or principalities or powers, all things that are and were created were created through Me and for Me. I am before all things, and in Me all things consist."},{t:"fn",v:"1"},{t:"text",v:"Therefore, give heed to My words and understand. For as I had spoken to My friends in times past, so now do I also speak to you. For the time has come and is coming and is already here, when all signs and wonders shall be made manifest, when all prophecy shall be fulfilled. Rejoice, for your redemption draws near! And though the time of great sorrows has come in, hold fast, for these days shall be shortened..."},{t:"italic",v:"No more pain, no more tears, no more death, all sorrows passing away, rebirth, a time of refreshing which shall never end."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, remember My words and have peace:"}]]},{type:"poetry",lines:[[{t:"italic",v:"One God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One Son, The Only Way to The Father..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One Truth, One Word, One Messiah, One Spirit;"}],[{t:"italic",v:"One Food, One Bread and One Drink..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One Body..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Of which I am all,"}],[{t:"italic",v:"The All in All..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Amen."}]]}],footnotes:{1:{type:"scripture",ref:"Colossians 1:15-17"}},nkjv:{"Colossians 1:15-17":"15. He is the image of the invisible God, the firstborn over all creation. 16. For by Him all things were created that are in heaven and that are on earth, visible and invisible, whether thrones or dominions or principalities or powers. All things were created through Him and for Him. 17. And He is before all things, and in Him all things consist."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-truth-absolute",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-truth-absolute-full-letter?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=AlF08HwhuMM&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=14",videoMusicUrl:"https://www.youtube.com/watch?v=Cw8BUiL_AqI&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=11",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding Children\u2019s Inheritance on Earth and in Heaven",url:"https://answersonlygodcangive.com/Regarding_Children%E2%80%99s_Inheritance_on_Earth_and_in_Heaven"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Doubt",url:"https://answersonlygodcangive.com/Regarding_Doubt"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],num:10,prevLetter:{id:"culmination",title:"Culmination"},nextLetter:{id:"the-vineyard",title:"The Vineyard"}},{id:"the-vineyard",title:"The Vineyard",date:"4/14/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Peoples of the earth, I had sent to you The Messiah, The Sower of the seeds of salvation. Yet to you, He has become an object of scorn and His words cause for disdain. For you do always contend with Me, a most arrogant and deceived people who revile My Word and reject My Commandments, saying,"},{t:"italic",v:"\u201CI answer to no one, nor to any god. I am who I am, and I go my own way.\u201D"},{t:"text",v:"For truth has perished among you; it has altogether been cut off from your mouth. Therefore are the pleasant fields left desolate, and the peaceful pastures laid waste, for there is no latter rain. For the heart of this generation has turned against Me. Their consciences are defiled as they embrace every evil thought and intention, a base people lost in their own bitterness, who turn justice into wormwood and cast righteousness to the ground."}]},{type:"poetry",lines:[[{t:"italic",v:"My vineyard has produced wild grapes!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, roots of rottenness plunge deep,"}],[{t:"italic",v:"As great vines of wickedness reach"}],[{t:"italic",v:"Unto the ends of the earth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore I must break down the walls,"}],[{t:"italic",v:"And tear out the hedges, and destroy"}],[{t:"italic",v:"All these briers and thorns..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I must tread them down, until nothing remains!..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord to the oppressor, to the haughty, the high-minded and the hypocrite:"},{t:"text",v:"Mankind shall be cast down! I shall throw down the kingdoms of men and bring terrible judgment upon the wicked! The oppressor shall be cut in pieces and the haughty broken, the high-minded abased and the hypocrite put to shame! Thus the prideful shall in no wise escape the Day of The Lord, and the insolent shall be left to wallow in the darkness of their own understanding. For all the children of disobedience must walk through the valley, to the shedding of many tears. For as it is written:"},{t:"italic",v:"There shall be wailing in the public squares, and in every street they shall cry, \u201CWoe is me! Woe is me!\u201D They shall summon the farmer to mourning and call for the skillful lamenters to wail on their behalf. And in all vineyards, there shall be wailing. For I shall surely pass through, says The Lord."},{t:"fn",v:"1"}]}],footnotes:{1:{type:"scripture",ref:"Amos 5:15-17"}},nkjv:{"Amos 5:15-17":"15. Hate evil, love good; Establish justice in the gate. It may be that the LORD God of hosts Will be gracious to the remnant of Joseph. 16. Therefore the LORD God of hosts, the Lord, says this: \u201CThere shall be wailing in all streets, And they shall say in all the highways, \u2018Alas! Alas!\u2019 They shall call the farmer to mourning, And skillful lamenters to wailing. 17. In all vineyards there shall be wailing, For I will pass through you,\u201D Says the LORD."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-vineyard",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-vineyard?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=kH7EmyWPLKg&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=18",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:11,prevLetter:{id:"the-truth-absolute",title:"The Truth Absolute"},nextLetter:{id:"stricken",title:"Stricken"}},{id:"stricken",title:"Stricken",date:"4/17/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"This world is stricken, a corrupt tree which bears only bitter fruit! You have done this, O peoples of the earth! You have done this, O men of power and wealth, all you people of excess! YOU HAVE DONE THIS! For the sake of greed, to fulfill your insatiable appetites and ever-increasing lusts, YOU HAVE DESTROYED THE GARDEN! Therefore cut down the tree and burn the branches! Break apart the stump and pull up the roots!..."},{t:"bold-italic",v:"For thus declares The Lord:"},{t:"text",v:"As you have sown, SO SHALL YOU REAP! And that which you have withheld from the poor and the needy shall be taken from you, and you shall suffer! Behold, even all you have wrought in the earth shall return atop your own heads, for I shall strike you down and lay you waste! - Desolation upon desolation, calamity upon calamity, plagues and famine until you are utterly consumed!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My people are afflicted,"}],[{t:"italic",v:"And My faithful ones are persecuted,"}],[{t:"italic",v:"Imprisoned and put to death!"}],[{t:"italic",v:"My little ones are brought to harm,"}],[{t:"italic",v:"And the innocent are murdered in droves,"}],[{t:"italic",v:"CAST OFF AS REFUSE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore the afflicted shall be"}],[{t:"italic",v:"Given wealth beyond imagining,"}],[{t:"italic",v:"And the meek shall inherit the earth;"}],[{t:"italic",v:"The little ones shall be taken,"}],[{t:"italic",v:"And the innocent shall return home..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And they shall be My sons and daughters,"}],[{t:"italic",v:"Forever, life without end."}]]},{type:"para",segments:[{t:"text",v:"Yet you, O most wicked generation, shall be cut off! I shall cast you out, and you shall remain outside the gates! For I do not know you! Says The Lord... There shall be wailing and gnashing of teeth."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord to the generation of His wrath:"},{t:"text",v:"As a lion springs forth suddenly from its hiding place and lays hold of the prey, so shall I break the neck of this generation and drag it away, until every last remnant of your wickedness is devoured! Behold, you shall be broken without hand, and the wickedness which dwells in the midst of you shall be torn in pieces!... And who among the nations shall deliver you from the mouth of The Lion?! For I am risen up in My anger, I am come forth in My fury! Therefore let every way crack and every foundation crumble; let the earth give way! Let the high places fall with a great crash, and let every false image perish before the great and awesome power of The Lord! See, your wealth has come to nothing, O peoples of the earth. For as it is written:"},{t:"italic",v:"Your wealth shall rot away, your fine clothes shall be eaten by moths, your gold and silver shall become worthless, and shall be for a witness against you in the Day of Wrath, and shall eat your flesh like fire."},{t:"fn",v:"1"},{t:"text",v:"Thus all the treasure, which you have heaped up against the Day, shall bury you. Therefore kneel, kneel before The Lord of Hosts, humble yourselves before The King! Kiss The Son! For in YahuShua alone is your salvation, in Messiah alone is there deliverance in the Day of Wrath, your only escape. For He is The Lamb; behold, He is also The Lion!... Yet you will forsake Him in the name of another."}]},{type:"para",segments:[{t:"text",v:"Did you think, O most wicked generation, the man of perdition could save you from the Day of Wrath?! Did you think you could escape the Day of Judgment, which I pronounced from the beginning?! You are deceived, even as he is deceived!"}]},{type:"poetry",lines:[[{t:"italic",v:"For the reign of evil shall be abolished,"}],[{t:"italic",v:"The wicked stricken and the evil of heart blotted out,"}],[{t:"italic",v:"Extinguished in the lake of My burning heart!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My heart is set ablaze in My anger,"}],[{t:"italic",v:"And My countenance burns like a raging fire;"}],[{t:"italic",v:"My sadness is infinite, the weight of"}],[{t:"italic",v:"Unending sorrow covers Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as I live, says The Lord,"}],[{t:"italic",v:"I take no pleasure in the destruction"}],[{t:"italic",v:"Of the wicked, but call all in the earth"}],[{t:"italic",v:"To repent, to turn from their evil ways..."}],[{t:"stanza-break"}],[{t:"italic",v:"And return to Me."}]]}],footnotes:{1:{type:"scripture",ref:"James 5:2-3"}},nkjv:{"James 5:2-3":"2. Your riches are corrupted, and your garments are moth-eaten. 3. Your gold and silver are corroded, and their corrosion will be a witness against you and will eat your flesh like fire. You have heaped up treasure in the last days."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/stricken",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/stricken-full-letter?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=gpvTkyfsgZc&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=19",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Pollution and Mankind's Exploitation of the Earth",url:"https://answersonlygodcangive.com/Regarding_Pollution_and_Mankind%27s_Exploitation_of_the_Earth"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding Worldly Suffering",url:"https://answersonlygodcangive.com/Regarding_Worldly_Suffering"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Antichrist",url:"https://answersonlygodcangive.com/Regarding_the_Antichrist"}],num:12,prevLetter:{id:"the-vineyard",title:"The Vineyard"},nextLetter:{id:"unleavened",title:"Unleavened"}},{id:"unleavened",title:"Unleavened",date:"4/19/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the Feast of Unleavened Bread)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, The Risen One, your Redeemer:"},{t:"text",v:"I had come to you as a man, clothed in the flesh, humble; My glory set aside, God become man, Immanu El... Living as all have lived in the body, yet not as man lives in the spirit; for I am clean, having no sin in My body, nor in My spirit, having obeyed every command of The Father - blameless."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Behold The Lamb of God without spot or blemish, sent to die for the sins of the world, bearing the full weight of transgression in His own body; the perfect sacrifice, acceptable to God, whereby all men are reconciled to The Father if they so choose to receive of The Free Gift, becoming once again My sons and daughters, free to enter the Garden and My love, from which they shall never again depart."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Risen Lamb:"},{t:"text",v:"Therefore, as I have unleavened all men by My sacrifice, in the same way must those who live in Me crucify their lives daily, bearing their cross after Me. For the first six days of the feast shall be for a physical representation of My command to you:"},{t:"italic",v:"You are forgiven, now go out and sin no more."},{t:"text",v:"Be then separate from the ways of this world and the churches of men, and be for Me a strange and peculiar people who remain in My love, even as I kept The Father\u2019s commands and remain in His love. And the seventh day, it is the consummation of the six gone before, a holy convocation, the cleansing completed, a rest from all works against temptation and the many snares of the evil one. For I am coming quickly, and I shall make a complete end of all iniquity, of all things which lead My people into sin. For I had come at the first to unleaven all men, to heal the hearts of all who receive of Me, to bring peace to the minds of all who believe in Me, to set the captives free - I am The Passover! And now I am returning to make a complete end of all leaven which fills this world; behold, in a week and in the Day shall I accomplish it. Then rest, peace, one thousand years. So then, My children, even all who gather together in My name, have understanding of the Plan of the Ages. In the sixth day, the leaven of sin entered the Garden; and on the seventh, God rested, and blessed the seventh day and sanctified it. Thus here is wisdom:"},{t:"italic",v:"Six days, creation; the seventh, rest, holy. Six days since Adam; the seventh, rest, holy. Six days shall you labor; the seventh, rest, holy. Six days shall you feast; the seventh, rest, holy."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, eat and drink in remembrance of Me;"}],[{t:"italic",v:"Be filled with the glory of The Lord!"}],[{t:"italic",v:"For I died; behold, I am risen!..."}]]},{type:"closing",text:"Says The Amen, The Firstborn from the dead, YahuShua HaMashiach, Lord and Savior of men."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/unleavened",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/unleavened?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=z2pjy0bgeYI&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:13,prevLetter:{id:"stricken",title:"Stricken"},nextLetter:{id:"i-am-risen",title:"I AM RISEN"}},{id:"i-am-risen",title:"I AM RISEN",date:"4/21/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Everlasting who would be man, Immanu El:"},{t:"italic",v:"I was born into the world of the virgin, the chosen vessel by which the salvation of man would come; Growing, Living as all men, yet remaining unspotted from the world, blameless..."}]},{type:"para",segments:[{t:"italic",v:"Born to die, suffering as no man could endure, the healing of many in the blood of sprinkling, Death; My spirit committed to The Father, all things accomplished, the cup of The Father consumed..."}]},{type:"para",segments:[{t:"italic",v:"The grain of wheat, The Holy Seed, has fallen and died, planted in the heart of the earth for three days and three nights. For I gave My life as a ransom for many, even unto death. I have the power to lay down My life, and behold, I have the power to take it up again."}]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE RESURRECTION AND THE LIFE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And all who believe in Me shall not die, but live,"}],[{t:"italic",v:"For I shall raise them up at the Last Day!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"No more tears, no more death, no more pain,"}],[{t:"italic",v:"For the old order of things has passed away;"}],[{t:"italic",v:"All things restored in glory, the glory of everlasting life!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM RISEN! YOUR REDEEMER LIVES!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Says The Holy One of Israel."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-risen",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/i-am-risen?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=na0m8NsQkps&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=22",videoMusicUrl:"https://www.youtube.com/watch?v=ZlQABsbo7sc&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=21",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:'The Name of The Lord - "Immanu El"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#Immanu_El"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding The Resurrection",url:"https://answersonlygodcangive.com/Regarding_The_Resurrection"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:14,prevLetter:{id:"unleavened",title:"Unleavened"},nextLetter:{id:"awake-all-you-churches-of-men",title:"Awake, All You Churches of Men"}},{id:"awake-all-you-churches-of-men",title:"Awake, All You Churches of Men",date:"5/23/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, your Redeemer:"},{t:"text",v:"I AM COME "},{t:"fn",v:"1"},{t:"text",v:" - I have come already and shall also return; I shall gather My elect and come on the clouds of heaven, with power and great glory. Yet you of this world do not believe. Beloved ones, how is it you do not understand My speech? Behold, I proclaim it through your own kindred and countrymen, in a familiar tongue, yet you can not bear to listen; indeed, you refuse to hear! For your hearts remain far from Me, married to a world of unbridled sin, caught up in a deluge of lies, false truths called science and religion which deny My name and steal from My glory! Beloved, I AM THE TRUTH, which was born into the world to testify! Yet you of this world will in no wise hear Me! Yes, even you who dwell in the churches of men reject Me, refusing to accept Me as I truly am! Woe to you, therefore! Woe, I say to you! Woe to all who reject My words and hold fast to the doctrines and traditions of men!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, to all those who call of themselves Christian:"},{t:"text",v:"Beloved, do I live in you? Do you even know My name? For I tell you the truth, you all slumber, you have all fallen asleep. In beds filled with man\u2019s conceit, overlain with purple and scarlet, you have lain down and remain at ease. Behold, upon false foundations of corrupt doctrine and filthy tradition, you build up high walls with untempered mortar - church after church, denomination after denomination, walking always in the commandments of men! YOU HAVE WROUGHT IN VAIN! For I tell you the truth, your every church shall come to nothing - every house devastated, all denominations brought to ruin! For I have not dwelt there!"}]},{type:"poetry",lines:[[{t:"italic",v:"Repent therefore, and tear down all you"}],[{t:"italic",v:"Have built up in My name, for yourselves,"}],[{t:"italic",v:"Of yourselves, to your own glory..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Tear it all down, and begin again in Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Obey My Word as it is written,"}],[{t:"italic",v:"Cast off all you have written,"}],[{t:"italic",v:"And walk no more in the way"}],[{t:"italic",v:"Set forth by the founders..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Break up this fallow ground, and sow"}],[{t:"italic",v:"No more among all these briers and thorns,"}],[{t:"italic",v:"And I may yet receive you, says The Lord."}]]},{type:"para",segments:[{t:"text",v:"Churches of men, hold your lamps up, so I may see your faces. Shine your lamps on your houses, that I may behold your good works, all these grand works you boast of in My name, saying,"},{t:"italic",v:"\u201CLord, Lord, have we not prophesied in Your name, cast out demons in Your name, and done many wonderful works in Your name?\u201D"},{t:"text",v:"Yet most assuredly, I say to you, I do not know you!"},{t:"fn",v:"2"},{t:"text",v:"Your lamps have gone out, and you have nothing at all with which to relight them. Neither are you willing to go out and receive from those I send, for you do always offend. Thus you shall remain in your darkened houses, folding your hands to sleep, until destitution overtakes you and scarcity drives you out. For I have purposed disaster upon every house of worship, until every church is torn down and every denomination is left in ruins. Therefore come out from among them, and embrace The True Light and receive of the pure oil, says The Lord."}]},{type:"para",segments:[{t:"text",v:"Beloved, how long shall I wait for you? How long will you put Me last, as one who is made to wait in an outer room? How long shall you forget My Sabbaths and forsake My Holy Days? How long shall you pollute My name and forsake The Commandments of God, in the name of Grace?! Beloved, follow Me as I am, and not as you would have Me be! Walk in MY ways, and forsake all these commandments of men! For I dwell not in any church made by human hands..."},{t:"italic",v:"I dwell in the hearts of men! I live in those who love Me and obey My commands; I abide with those who continually seek My face and long to know Me as I truly am; I dwell in the temple of God made by HIS hands!"},{t:"text",v:"Therefore again, I call you to repent, to repent in sincerity and in truth; to return to your First Love, to walk in the first works; to embrace The Word of God anew and bring forth works worthy of repentance, that you may truly be born again. For there is only One Way, Only One Truth Absolute, Only One Life without end..."},{t:"italic",v:"I am He, beloved! I AM HE!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore awake, all you churches of men,"}],[{t:"italic",v:"And listen to the sound of this Trumpet..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Be wide awake and very sober, pay close attention,"}],[{t:"italic",v:"For the mouth of The Living God has spoken..."}],[{t:"stanza-break"}],[{t:"italic",v:"Says The Holy One of Israel."}]]}],footnotes:{1:{type:"note",text:'See: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}},2:{type:"scripture",ref:"Matthew 7:22-23"}},nkjv:{"Matthew 7:22-23":"22. Many will say to Me in that day, \u2018Lord, Lord, have we not prophesied in Your name, cast out demons in Your name, and done many wonders in Your name?\u2019 23. And then I will declare to them, \u2018I never knew you; depart from Me, you who practice lawlessness!\u2019"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/awake-all-you-churches-of-men",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/awake-all-you-churches-of-men?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=c56oU-orSaE&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=23",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Index of False Doctrines Within the Churches of Men",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men_-_Section_One"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:15,prevLetter:{id:"i-am-risen",title:"I AM RISEN"},nextLetter:{id:"to-the-church-which-bears-the-name-jehovah",title:"To the Church Which Bears the Name, Jehovah"}},{id:"to-the-church-which-bears-the-name-jehovah",title:"To the Church Which Bears the Name, Jehovah",date:"6/5/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"You have all gone astray, you are lost and void of understanding. Your knowledge is corrupt and shall come to nothing; indeed, all your works shall burn in the Day."},{t:"fn",v:"1"},{t:"text",v:"For you have not known Me, nor will you accept Me as I truly am, having segregated the Scriptures, both adding to and taking away to uphold your own way, polluting My name and My Glory, to the continual blaspheming of the Spirit. Thus you remain desolate, void of the Spirit, listening only to the sound of your own voices - LIES! A multitude of subtle deceptions, knowledge and commandments brought forth by MEN! Men of vanity who seek after human praise, saying,"},{t:"italic",v:"\u201CWe alone are righteous, we alone understand God, and we will fulfill His Word. Are we not His chosen elect, the sent?\u201D"},{t:"text",v:"Hypocrites, shall you speak for The Most High and declare My Word before the people, though I have not sent you?! Modern pharisees, stop speaking, for you do always bear false witness! You proclaim another Messiah, of which your forefathers formed in their own image! DESECRATION! O arrogant church of men, you know nothing yet as you ought to know, nor have you any wisdom at all! For you remain trapped, grievously entangled, caught in your own snare! Put away your pride therefore, that you may see! Cast off all this bitter arrogance, that you may hear! For it is the humble, penitent man who shall know God. And to know The Son is to know The Father, for The Father and The Son are One..."},{t:"italic",v:"For in the beginning was The Word, and The Word was with God and The Word was God; and behold, The Word became flesh and dwelt among you"},{t:"fn",v:"2"},{t:"italic",v:", Immanu El."},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus YahuShua is both Messiah and Lord,"}],[{t:"italic",v:"The ONLY Way, The ONLY Truth, The ONLY Life..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore embrace Him as He truly is,"}],[{t:"italic",v:"And not as you would have Him be;"}],[{t:"italic",v:"Only then will you begin to know Me,"}],[{t:"italic",v:"Only then will you begin to see..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet continue to bear false witness,"}],[{t:"italic",v:"And only by great tribulation"}],[{t:"italic",v:"Shall you come into glory..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 Corinthians 3:11-15"},2:{type:"scripture",ref:"John 1:1, John 1:14"},3:{type:"scripture",ref:'Matthew 1:23 ("God with us")'}},nkjv:{"1 Corinthians 3:11-15":"11. For no other foundation can anyone lay than that which is laid, which is Jesus Christ. 12. Now if anyone builds on this foundation with gold, silver, precious stones, wood, hay, straw, 13. each one\u2019s work will become clear; for the Day will declare it, because it will be revealed by fire; and the fire will test each one\u2019s work, of what sort it is. 14. If anyone\u2019s work which he has built on it endures, he will receive a reward. 15. If anyone\u2019s work is burned, he will suffer loss; but he himself will be saved, yet so as through fire.","John 1:1, John 1:14":"1:1 \u2014 In the beginning was the Word, and the Word was with God, and the Word was God. | 1:14 \u2014 And the Word became flesh and dwelt among us, and we beheld His glory, the glory as of the only begotten of the Father, full of grace and truth.",'Matthew 1:23 ("God with us")':"\u201CBehold, the virgin shall be with child, and bear a Son, and they shall call His name Immanuel,\u201D which is translated, \u201CGod with us.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/to-the-church-which-bears-the-name-jehovah",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/to-the-church-which-bears-the?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=fM5yTwg_RxM&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=24",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Jehovah's Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_Jehovah%27s_Witnesses"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"},{label:'The Name of The Lord - "Immanu El"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#Immanu_El"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Index of False Doctrines Within the Churches of Men",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],num:16,prevLetter:{id:"awake-all-you-churches-of-men",title:"Awake, All You Churches of Men"},nextLetter:{id:"abide-in-the-doctrine-of-the-messiah",title:"Abide in the Doctrine of The Messiah"}},{id:"abide-in-the-doctrine-of-the-messiah",title:"Abide in the Doctrine of The Messiah",date:"6/28/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord's Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have spoken, yet those of hardened hearts refuse to harken to My voice. I have written it with parchment and ink through My prophets, behold, I have etched My words in stone with My own finger,"},{t:"fn",v:"1"},{t:"text",v:"yet who has received My message? Who has obeyed My Word, as it is written? I tell you the truth, only those fully converted in their innermost parts have accepted My message, and only those who truly love Me obey My Word. For they remain in My love and delight in My Commandments, knowing I AM WHO I AM."}]},{type:"para",segments:[{t:"text",v:"So then what of all these smoking firebrands who surround you, who do always rebel against Me in word and by deed? Hypocrites! Shall My children profess to know Me with their lips, and then go and sin before My face in that selfsame hour?! They do continually transgress; neither do they abide in the doctrine of The Messiah. Beloved ones, to abide in the doctrine of The Messiah is not mere proclamation or belief. To abide in His doctrine is to LIVE by His words, a shining example of righteousness, striving always to make your love perfect through obedience, that those close to you, even to the passerby, may see your good works and glorify your Father in Heaven. For it is written:"},{t:"italic",v:"One does not live on bread and water alone, but by every word that comes from the mouth of God."},{t:"fn",v:"2"}]},{type:"poetry",lines:[[{t:"italic",v:"So then do not just give voice and preach,"}],[{t:"italic",v:"But ABIDE in the doctrine of The Messiah..."}]]},{type:"poetry",lines:[[{t:"italic",v:"By example shall you lead them..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Deuteronomy 9:10"},2:{type:"scripture",ref:"Matthew 4:4"}},nkjv:{"Deuteronomy 9:10":"Then the LORD delivered to me two tablets of stone written with the finger of God, and on them were all the words which the LORD had spoken to you on the mountain from the midst of the fire in the day of the assembly.","Matthew 4:4":"But He answered and said, \u201CIt is written, \u2018Man shall not live by bread alone, but by every word that proceeds from the mouth of God.\u2019 \u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/abide-in-the-doctrine-of-the-messiah",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/abide-in-the-doctrine-of-the?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=SDoSNov7cQs&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:17,prevLetter:{id:"to-the-church-which-bears-the-name-jehovah",title:"To the Church Which Bears the Name, Jehovah"},nextLetter:{id:"the-dust-has-been-shaken-off-the-feet-of-god-s-messengers-as-a-testament-against-you-o-churches-of-men",title:"The Dust Has Been Shaken Off the Feet of God\u2019s Messengers as a Testament Against You, O Churches of Men"}},{id:"the-dust-has-been-shaken-off-the-feet-of-god-s-messengers-as-a-testament-against-you-o-churches-of-men",title:"The Dust Has Been Shaken Off the Feet of God\u2019s Messengers as a Testament Against You, O Churches of Men",date:"7/16/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Hear the Word of The Lord, all you insolent children, and give ear, all you desolate houses, for thus says The Lord to those who dwell within the churches of men:"},{t:"text",v:"Shall you come and stand before Me in your temples made by human hands, and say you are delivered, then go in that selfsame hour and pollute My name by all you say and do?! Desecration! Blasphemy!"},{t:"fn",v:"1"},{t:"text",v:"How dare you kneel before Me in repentance, as a show before your brethren, adorning yourselves with pretense! You are not delivered! Your offerings are not accepted, neither will I hear your pleas. For you have surely taken the name of The Lord in vain! For not one of you strives to make your repentance full,"},{t:"fn",v:"2"},{t:"text",v:"nor are you willing to forgive all who have sinned against you."},{t:"fn",v:"3"},{t:"text",v:"Thus your repentance has become unrepentance, and your words wind."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, you quote My Word"}],[{t:"italic",v:"Instant in and out of season,"}],[{t:"italic",v:"Yet not one of you obeys My Word!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As a wife who ceases not from committing"}],[{t:"italic",v:"Adultery, you continue to defile My name"}],[{t:"italic",v:"By your corrupt doctrines and filthy traditions,"}],[{t:"italic",v:"Even to the embracing of all these"}],[{t:"italic",v:"Holidays of men, which I hate!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"STOP BREAKING MY COMMANDMENTS!"},{t:"fn",v:"4"}],[{t:"italic",v:"For they do remain atop your marred heads..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"text",v:"Churches of men, know you not, to worship anything or anyone other than The Father through The Son is false worship?! Know you not, to love any image or material possession more than Me is idol worship?! And to uphold any tradition which stems from idolatry is idolatry?! YOU WORSHIP YOURSELVES! Churches of men, know you not, to speak of Me falsely or to call on My name in unbelief or for a pretense, or to associate My name or The Messiah\u2019s with any doctrine or tradition which I have not decreed, is to take the name of The Lord in vain?! DESECRATION! ANTICHRIST! Churches of men, know you not, the seventh day of the week is the day you shall remember and keep holy, and do no works therein"},{t:"fn",v:"5"},{t:"text",v:"except that which is good and upholds the cause of the fatherless, the widow and the needy?!"},{t:"fn",v:"6"},{t:"text",v:"SUNDAY IS NOT THE SABBATH! SATURDAY YOU SHALL KEEP!"},{t:"fn",v:"7"},{t:"text",v:"For I do NOT change!"},{t:"fn",v:"8"},{t:"text",v:"Nor have I commanded any other day, neither has the thought entered My mind! How long shall you cleave to the harlot?! How long shall you walk in her ways?! Churches of men, shall you continue to dishonor your father and mother, by all you say and do?! UNGRATEFUL HYPOCRITES! Shall you continue to commit murder?! For you hate the one who rebukes at the gate, and despise the one who speaks a message from God."},{t:"fn",v:"9"},{t:"text",v:"Thus in the hating of your brother, you are all guilty of murder in your hearts!"},{t:"fn",v:"10"},{t:"text",v:"Behold, even some of you, who call of yourselves Christian, are in favor of capital punishment. Yet again I say to you, even to murder the murderer is murder!"},{t:"fn",v:"11"},{t:"text",v:"Worse still there are some among you, who are in favor of this so-called right to choose! THEY HAVE CHOSEN DEATH! THEY HAVE SURELY CONDEMNED THEMSELVES! And all who cast their lot with those who murder the innocent shall be left outside The City!"},{t:"fn",v:"12"},{t:"text",v:"I AM THE LORD. Churches of men, shall you continue to commit adultery in your hearts without pause?! Know you not, to even look upon another with lust in your heart is adultery?!"},{t:"fn",v:"13"},{t:"text",v:"Behold, even every doctrine and tradition born of men is adultery against God! How long shall you rob Me and steal from your neighbor, for you do always bear false witness of Me, lying to your neighbor and to yourself! For I tell you the truth, you know neither Me nor My will, nor have you heard My voice at any time! And shall you continue, without ceasing, to covet that which you do not possess?! Be set apart from this world, and come out of the churches of men. Only then will you begin to see, only then shall you receive ears to hear."}]},{type:"poetry",lines:[[{t:"italic",v:"O arrogant generation, how shall"}],[{t:"italic",v:"I humble you that you may be saved?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you the truth, only those who are"}],[{t:"italic",v:"Truly converted in their hearts shall be delivered;"},{t:"fn",v:"14"}],[{t:"italic",v:"Only those who have the Testimony of The Messiah"}],[{t:"italic",v:"AND keep The Commandments"},{t:"fn",v:"15"},{t:"italic",v:"shall escape"},{t:"fn",v:"16"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus I have shaken the dust off the feet of"}],[{t:"italic",v:"My messengers as a testament against you..."},{t:"fn",v:"17"}]]},{type:"poetry",lines:[[{t:"italic",v:"I have set apart My elect..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And of your houses,"}],[{t:"italic",v:"See, I have left them to you desolate"},{t:"fn",v:"18"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Jeremiah 7:8-10"},2:{type:"note",text:'See: "Regarding True Repentance"',url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},3:{type:"scripture",ref:"Matthew 6:15"},4:{type:"scripture",ref:"Exodus 20:3-17"},5:{type:"scripture",ref:"Exodus 20:8-11"},6:{type:"scripture",ref:"Matthew 12:12"},7:{type:"scripture",ref:"Exodus 20:10-11"},8:{type:"scripture",ref:"Malachi 3:6"},9:{type:"scripture",ref:"Amos 5:10"},10:{type:"scripture",ref:"1 John 3:15"},11:{type:"note",text:'See: "The Judgment of God Is True..."',url:"https://www.thevolumesoftruth.com/The_Judgment_of_God_Is_True_and_Without_Question,_Yet_the_Error_of_the_People_Is_Great#:~:text=Even%20to%20murder%20the%20murderer%20is%20murder!",link:{collection:"Volume Two",letterTitle:"The Judgment of God Is True and Without Question, Yet the Error of the People Is Great",excerpt:"Even to murder the murderer is murder!"}},12:{type:"scripture",ref:"Revelation 22:14-15"},13:{type:"scripture",ref:"Matthew 5:28"},14:{type:"scripture",ref:"Psalm 51:6"},15:{type:"scripture",ref:"1 John 2:4, Revelation 14:12, Revelation 22:14"},16:{type:"scripture",ref:"Luke 21:36"},17:{type:"scripture",ref:"Mark 6:11"},18:{type:"scripture",ref:"Matthew 23:37-38"}},nkjv:{"Jeremiah 7:8-10":"8. \u201CBehold, you trust in lying words that cannot profit. 9. Will you steal, murder, commit adultery, swear falsely, burn incense to Baal, and walk after other gods whom you do not know, 10. and then come and stand before Me in this house which is called by My name, and say, \u2018We are delivered to do all these abominations\u2019?","Matthew 6:15":"But if you do not forgive men their trespasses, neither will your Father forgive your trespasses.","Exodus 20:3-17":"3. \u201CYou shall have no other gods before Me. 4. \u201CYou shall not make for yourself a carved image\u2014any likeness of anything that is in heaven above, or that is in the earth beneath, or that is in the water under the earth; 5. you shall not bow down to them nor serve them. For I, the LORD your God, am a jealous God, visiting the iniquity of the fathers upon the children to the third and fourth generations of those who hate Me, 6. but showing mercy to thousands, to those who love Me and keep My commandments. 7. \u201CYou shall not take the name of the LORD your God in vain, for the LORD will not hold him guiltless who takes His name in vain. 8. \u201CRemember the Sabbath day, to keep it holy. 9. Six days you shall labor and do all your work, 10. but the seventh day is the Sabbath of the LORD your God. In it you shall do no work: you, nor your son, nor your daughter, nor your male servant, nor your female servant, nor your cattle, nor your stranger who is within your gates. 11. For in six days the LORD made the heavens and the earth, the sea, and all that is in them, and rested the seventh day. Therefore the LORD blessed the Sabbath day and hallowed it. 12. \u201CHonor your father and your mother, that your days may be long upon the land which the LORD your God is giving you. 13. \u201CYou shall not murder. 14. \u201CYou shall not commit adultery. 15. \u201CYou shall not steal. 16. \u201CYou shall not bear false witness against your neighbor. 17. \u201CYou shall not covet your neighbor\u2019s house; you shall not covet your neighbor\u2019s wife, nor his male servant, nor his female servant, nor his ox, nor his donkey, nor anything that is your neighbor\u2019s.\u201D","Exodus 20:8-11":"8. \u201CRemember the Sabbath day, to keep it holy. 9. Six days you shall labor and do all your work, 10. but the seventh day is the Sabbath of the LORD your God. In it you shall do no work: you, nor your son, nor your daughter, nor your male servant, nor your female servant, nor your cattle, nor your stranger who is within your gates. 11. For in six days the LORD made the heavens and the earth, the sea, and all that is in them, and rested the seventh day. Therefore the LORD blessed the Sabbath day and hallowed it.","Matthew 12:12":"Of how much more value then is a man than a sheep? Therefore it is lawful to do good on the Sabbath.\u201D","Exodus 20:10-11":"10. but the seventh day is the Sabbath of the LORD your God. In it you shall do no work: you, nor your son, nor your daughter, nor your male servant, nor your female servant, nor your cattle, nor your stranger who is within your gates. 11. For in six days the LORD made the heavens and the earth, the sea, and all that is in them, and rested the seventh day. Therefore the LORD blessed the Sabbath day and hallowed it.","Malachi 3:6":"\u201CFor I am the LORD, I do not change; Therefore you are not consumed, O sons of Jacob.","Amos 5:10":"They hate the one who rebukes in the gate, And they abhor the one who speaks uprightly.","1 John 3:15":"Whoever hates his brother is a murderer, and you know that no murderer has eternal life abiding in him.","Revelation 22:14-15":"14. Blessed are those who do His commandments, that they may have the right to the tree of life, and may enter through the gates into the city. 15. But outside are dogs and sorcerers and sexually immoral and murderers and idolaters, and whoever loves and practices a lie.","Matthew 5:28":"But I say to you that whoever looks at a woman to lust for her has already committed adultery with her in his heart.","Psalm 51:6":"Behold, You desire truth in the inward parts, And in the hidden part You will make me to know wisdom.","1 John 2:4, Revelation 14:12, Revelation 22:14":"1 John 2:4 \u2014 He who says, \u201CI know Him,\u201D and does not keep His commandments, is a liar, and the truth is not in him. | Revelation 14:12 \u2014 Here is the patience of the saints; here are those who keep the commandments of God and the faith of Jesus. | Revelation 22:14 \u2014 Blessed are those who do His commandments, that they may have the right to the tree of life, and may enter through the gates into the city.","Luke 21:36":"Watch therefore, and pray always that you may be counted worthy to escape all these things that will come to pass, and to stand before the Son of Man.\u201D","Mark 6:11":"And whoever will not receive you nor hear you, when you depart from there, shake off the dust under your feet as a testimony against them. Assuredly, I say to you, it will be more tolerable for Sodom and Gomorrah in the day of judgment than for that city!\u201D","Matthew 23:37-38":"37. \u201CO Jerusalem, Jerusalem, the one who kills the prophets and stones those who are sent to her! How often I wanted to gather your children together, as a hen gathers her chicks under her wings, but you were not willing! 38. See! Your house is left to you desolate;"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-dust-has-been-shaken-off-the-feet-of-god-s-messengers-as-a-testament-against-you-o-churches-of-men",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/2db7d835-e0dc-4218-80ed-5d6a7c3108bc?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=QZ3jCOba98Q&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=28",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"Index of False Doctrines Within the Churches of Men",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"God Speaks About Honoring Your Father and Your Mother",url:"https://answersonlygodcangive.com/God_Speaks_About_Honoring_Your_Father_and_Your_Mother"},{label:"God Speaks About Committing Murder Within the Heart",url:"https://answersonlygodcangive.com/God_Speaks_About_Committing_Murder_Within_the_Heart"},{label:"Thus Says The Lord Regarding Capital Punishment and Suicide",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Capital_Punishment_and_Suicide"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"God Speaks About Adultery of the Heart",url:"https://answersonlygodcangive.com/God_Speaks_About_Adultery_of_the_Heart"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"God Speaks Regarding Covetousness",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Covetousness"},{label:"Index of False Doctrines Within the Churches of Men",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"}],num:18,prevLetter:{id:"abide-in-the-doctrine-of-the-messiah",title:"Abide in the Doctrine of The Messiah"},nextLetter:{id:"death-and-deliverance",title:"Death and Deliverance"}},{id:"death-and-deliverance",title:"Death and Deliverance",date:"7/27/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The wicked shall surely fall by the word of their own mouth, and by their works shall they stumble into the pit; behold, by their every word and deed have they condemned themselves to death. Yet if these same ones turn from their iniquity, and call upon Me in the name of The Messiah, they shall live and not die; they shall surely be delivered! For they have called upon The Name, the only name under Heaven by which you must be saved. For He is called Jesus and Christ - His name: YAHUSHUA"},{t:"fn",v:"1"},{t:"text",v:"HAMASHIACH, both Lord and Savior of men."}]},{type:"poetry",lines:[[{t:"italic",v:"I tell you the truth, the very moment one has"}],[{t:"italic",v:"A change of heart do they pass from judgment into life..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I know the hearts of men,"}],[{t:"italic",v:"And their thoughts are not at all hidden from Me;"}],[{t:"italic",v:"Behold, I look upon their innermost desires,"}],[{t:"italic",v:"I know every hidden intention..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore when one calls upon Me,"}],[{t:"italic",v:"I know, I see, I hear, regardless of the name"}],[{t:"italic",v:"By which they have come to know Me, says The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For there is but One God and One Savior, and I AM HE."}]]},{type:"para",segments:[{t:"text",v:"Yet understand this: In times past I overlooked the ignorance of the people. Yet now I command all people everywhere to repent in sincerity and in truth."},{t:"fn",v:"2"},{t:"text",v:"In like manner, I have overlooked the ignorance of those who call The Messiah by another name. Yet now I command all who have ears to hear, to call upon His name as it is, was, and has always been, and not as they presume it to be."},{t:"fn",v:"3"},{t:"text",v:"Indeed I am calling all tribes, tongues, peoples and nations to embrace Him as He truly is, and not as the churches of men would have Him be,"},{t:"fn",v:"4"},{t:"text",v:"says The Lord."}]}],footnotes:{1:{type:"scripture",ref:"Zechariah 6:9-13"},2:{type:"scripture",ref:"Acts 17:30"},3:{type:"scripture",ref:"Zephaniah 3:9"},4:{type:"note",text:'See: "Regarding "Another Messiah""',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"}},nkjv:{"Zechariah 6:9-13":`9. The word of the LORD came to me, saying, 10. Take of them of the captivity, even of Heldai, of Toviyah, and of Yedayah; and come the same day, and go into the house of Yoshiyahu the son of Tzefanyah, where they have come from Bavel. 11. Yes, take silver and gold, and make crowns, and set them on the head of Yehoshua the son of Yehotzadak, the Kohen Gadol; 12. and speak to him, saying, 'Thus says the LORD of Hosts, "Behold, the man whose name is the Branch: and he shall grow up out of his place; and he shall build the temple of the LORD; 13. even he shall build the temple of the LORD; and he shall bear the glory, and shall sit and rule on his throne; and he shall be a Kohen on his throne; and the counsel of shalom shall be between them both."' [In Zechariah 6:11, the original Hebrew word for Joshua is Yahushua (\u05D9\u05D4\u05D5\u05E9\u05E2)]`,"Acts 17:30":"Truly, these times of ignorance God overlooked, but now commands all men everywhere to repent,","Zephaniah 3:9":"\u201CFor then I will restore to the peoples a pure language, That they all may call on the name of the LORD, To serve Him with one accord."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/death-and-deliverance",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/death-and-deliverance?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=zKHuPo5BMCQ&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Sacred Names",url:"https://answersonlygodcangive.com/Regarding_Sacred_Names"},{label:'The Name of The Lord - "YahuShua"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YahuShua"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"}],num:19,prevLetter:{id:"the-dust-has-been-shaken-off-the-feet-of-god-s-messengers-as-a-testament-against-you-o-churches-of-men",title:"The Dust Has Been Shaken Off the Feet of God\u2019s Messengers as a Testament Against You, O Churches of Men"},nextLetter:{id:"hallowed-ground",title:"Hallowed Ground"}},{id:"hallowed-ground",title:"Hallowed Ground",date:"8/4/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel:"},{t:"text",v:"As I have commanded it, so shall it be done. As I have spoken it, so shall it come to pass. As I have purposed it, so shall it be accomplished. For My glory, all shall be fulfilled. Thus that which I have spoken by My prophets shall surely be. And though they stumble, they shall by no means fall, for they do continually humble themselves before Me. Therefore, blessed is the man who comes to Me ashamed of his trespasses, whose heart is full of grief on account of his sins, for I am faithful to forgive his sins. Indeed I shall lift him up, and set his feet upon hallowed ground."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Holy One of Israel:"},{t:"text",v:"My servants, remove your sandals from your feet. For wheresoever you come to Me, I am there, and wheresoever you hear the sound of My voice is hallowed ground. For I have come to abide in My temples, to sanctify them, a continual washing. For all men stumble, none having obeyed My voice unto pure righteousness, no, not one. Yet those I am sending have been anointed in My own blood; behold, I have placed My seal upon them. And yes they stumble, for they are but men, yet they do not fall; behold, they shall endure for My name\u2019s sake and bring glory to My name, even to the end of this age."}]},{type:"poetry",lines:[[{t:"italic",v:"For My mercy endures forever..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And those who receive of My Mercy"}],[{t:"italic",v:"Shall likewise endure, forever..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/hallowed-ground-2",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/hallowed-ground?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=uYEzOnUbjNg&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=27",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Being Born Again",url:"https://answersonlygodcangive.com/Regarding_Being_Born_Again"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"}],num:20,prevLetter:{id:"death-and-deliverance",title:"Death and Deliverance"},nextLetter:{id:"chosen-vessels",title:"Chosen Vessels"}},{id:"chosen-vessels",title:"Chosen Vessels",date:"9/4/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"There are many who count themselves worthy, as vessels of honor. Yet they are corrupt, having been filled with all manner of falsehood, bitter doctrine and perverse tradition; men in authority who know not The Truth nor do I reside within them, modern pharisees who in My name feed the masses spoiled food, scraps from which even the dogs turn away, doctrines and traditions I hate, works which shall be burned up in the Day. Therefore I have gathered to Myself a special offering, of the number, empty vessels void of all doctrine taught within the churches of men. And though these have sinned in the body, as all men, they are fully immersed in the Spirit of Truth, enveloped in The Son\u2019s sacrifice, cleansed in the blood of The Lamb..."},{t:"italic",v:"Behold the chosen vessels of The Lord. They are washed and made clean, both in body and spirit, remade, vessels of honor, meet for The Master\u2019s use. Behold, they are filled with the pure water, of which they shall continually pour into the cups of the thirsty. I AM THE LORD."}]},{type:"para",segments:[{t:"text",v:"Yet what of all these other vessels filled with all manner of bitter and foul doctrine? Shall I pour the pure water into these, mixing the pure with the polluted and the clean with the corrupt? Surely not. For they have sat long and unmoving, their contents stagnant and rank, fermenting. Thus when vessels such as these fill the cups of the thirsty, My people become ill, even drunk by the contents. For none are able to perceive the Truth as it really is, nor will they accept it when it comes. They have all become intoxicated, they are all drunk! They are intoxicated with the doctrines of men, they are drunk with the ways of this world! They are corrupt, their works abominable! There is none righteous, no, not one! Therefore every vessel of dishonor shall be broken, all contents purged in the heat of the Great and Terrible Day of The Lord!"}]},{type:"poetry",lines:[[{t:"italic",v:"How easily men give heed"}],[{t:"italic",v:"To the cleansing of the sin of the body,"}],[{t:"italic",v:"Yet oh how they resist the cleansing of the spirit..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For they do always resist the Truth, believing within"}],[{t:"italic",v:"Themselves they are already clean, deceiving themselves..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For this reason I have set apart a special offering, even 144,000,"}],[{t:"italic",v:"My witnesses, who are cleansed and made ready,"}],[{t:"italic",v:"Men of promise who shall go for Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I am The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/chosen-vessels",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/chosen-vessels?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=N2uUeFrG02c&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=28",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"The Ways of Churches of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Ways_of_Churches_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:21,prevLetter:{id:"hallowed-ground",title:"Hallowed Ground"},nextLetter:{id:"blessed-are-those-who-overcome-for-my-name-s-sake",title:"Blessed Are Those Who Overcome for My Name\u2019s Sake"}},{id:"blessed-are-those-who-overcome-for-my-name-s-sake",title:"Blessed Are Those Who Overcome for My Name\u2019s Sake",date:"11/9/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Someone Who Asked if They Can Still Serve The Lord as a Pastor",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant, whom He loves:"},{t:"text",v:"You seek Me, and this is very good. Yet if you wish to please Me, then you must first become My disciple, a devoted servant who walks in My ways."}]},{type:"para",segments:[{t:"text",v:"My son, I have not forsaken you. If you ask of Me forgiveness, I shall surely forgive you, even for all you have done. Yet to continue in those same sins, for which you had sought forgiveness, is most unpleasant in My sight. For by doing so, you have made My forgiveness of no effect. For that which requires forgiveness is the very same from which you must depart, lest your repentance become unrepentance, crucifying Me again and again in your heart."}]},{type:"poetry",lines:[[{t:"italic",v:"For repentance is more than the asking..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It must come from a deep desire to be set free"}],[{t:"italic",v:"In My love, followed by a sincere unyielding"}],[{t:"italic",v:"Commitment to make your love perfect"}],[{t:"italic",v:"Through obedience..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The shedding of the skin of this world,"}],[{t:"italic",v:"The crucifying of your old man with his sinful ways..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The putting on of the new man who is"}],[{t:"italic",v:"Renewed in the knowledge of The Holy One,"}],[{t:"italic",v:"Conforming to the image of Him who created him"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"text",v:"My son, there is none righteous in all the world, no, not one."},{t:"fn",v:"2"},{t:"text",v:"All have sinned and fall short of the Glory of God."},{t:"fn",v:"3"},{t:"text",v:"Behold, even Timothy, a man who I have given to hear My voice, does continually stumble. Yet when he is weak, he becomes strong. For My grace is sufficient for him, and My strength is made perfect in his weakness."},{t:"fn",v:"4"},{t:"text",v:"For he does not cease from coming to Me, laying himself at My feet in repentance, taking full responsibility for his actions, remorseful over those things which yet cause him to stumble, being fully tempted as all men. For I have not yet delivered My people out of temptation; nor has the evil one been bound in the abyss (this time is not yet). Yet from the power of sin, which is death, I have surely delivered you - if you so choose to receive of Me fully, if you so choose to embrace Me as I truly am, if you so choose to remain in My love."},{t:"fn",v:"5"},{t:"text",v:"Therefore you know the answer to your question already, for all is written in the Scriptures of Truth. Shall one, who does that which is an abomination in the eyes of God, serve Me? He may not. For as it is written:"},{t:"italic",v:"No one who actively engages in or passively practices homosexuality shall inherit The Kingdom of God."},{t:"fn",v:"6"},{t:"text",v:"Behold, even all who voice their agreement shall be left outside the gate,"},{t:"fn",v:"7"},{t:"text",v:"says The Lord. Yet if one comes to Me and asks of Me forgiveness, even a continual washing in My own blood, he shall surely have it; even if he comes to Me seven times, or seventy times seven times, he shall be forgiven."},{t:"fn",v:"8"},{t:"text",v:"For I forgive all those who come to Me in sincerity and in truth, and draw near to those of a contrite heart, delivering those of a humble spirit."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, by this then"}],[{t:"italic",v:"Shall our love be made perfect..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You shall abstain from that which is"}],[{t:"italic",v:"Not lawful, and make every effort"}],[{t:"italic",v:"To depart from that which is an"}],[{t:"italic",v:"Abomination in the eyes of God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You must strive to be completely separate"}],[{t:"italic",v:"From that life, presenting your body"}],[{t:"italic",v:"As a living sacrifice to The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Blameless."}]]},{type:"para",segments:[{t:"text",v:"For that which is unnatural is universally known, though the men and women of this world deny it. And that which is against God shall be purged by fire. Even all that offends shall be destroyed and come to a swift end. Therefore, My son, take up your cross and follow Me as I am, and not as you or the churches of men would have Me be. For as it is written:"},{t:"italic",v:"Whoever loves their mother, father, sister, brother, child or close friend, more than Me, is not worthy of Me. And he who does not take up his cross and follow after Me is not worthy of Me. For he who holds onto his life in this world will lose it, yet he who gives up his life for My sake will find it."},{t:"fn",v:"9"},{t:"text",v:"So then, do I call you to serve Me? I do, if you are willing to serve Me in all righteousness, without compromise. Do I then require that you be perfect? No. For there is none perfect, save The Holy One of Israel. Rather I require that you strive to be unto Me a servant of pure heart, of pure intention, a disciple who loves Me with all his heart, understanding and strength, and also loves his neighbor as himself."},{t:"fn",v:"10"},{t:"text",v:"For it is written and remains standing,"},{t:"italic",v:"that one can not be crowned unless they strive lawfully."},{t:"fn",v:"11"}]},{type:"para",segments:[{t:"text",v:"My son, I am the fulfillment of The Law, the very goal at which the Torah aims."},{t:"fn",v:"12"},{t:"text",v:"Thus all those who embrace Me are freed from the curse of The Law, but by no means are they now free to forsake The Law. Rather let The Law be written in your heart, for now you are under grace, and by the power of My own spirit are you now able to keep The Law"},{t:"fn",v:"13"},{t:"text",v:"..."},{t:"italic",v:"Beloved, come to Me and receive! Let Me wash you and make you clean, that you may now arise and walk in My ways."},{t:"text",v:"Therefore again I say to you, serve Me as I am, and not as you would have Me be. Yet turn away unto strange flesh, and I shall also turn away from you, leaving you in the midst of the earth, until you are truly ready to give up your life for My sake."},{t:"fn",v:"14"},{t:"text",v:"My son, come out from among them and be separate,"},{t:"fn",v:"15"},{t:"text",v:"and I shall give you a cool drink of water, for you are yet thirsty. Hear My words and understand. For My words are life for those who walk in them. And if you walk in them, then you are really My disciple,"},{t:"fn",v:"16"},{t:"text",v:"says The Lord."}]}],footnotes:{1:{type:"scripture",ref:"Colossians 3:9-10"},2:{type:"scripture",ref:"Romans 3:10"},3:{type:"scripture",ref:"Romans 3:23"},4:{type:"scripture",ref:"2 Corinthians 12:9"},5:{type:"scripture",ref:"John 15:10"},6:{type:"scripture",ref:"1 Corinthians 6:9-10 (CJB)"},7:{type:"scripture",ref:"Revelation 22:15"},8:{type:"scripture",ref:"Matthew 18:21-22"},9:{type:"scripture",ref:"Matthew 10:37-39"},10:{type:"scripture",ref:"Mark 12:30-31"},11:{type:"scripture",ref:"2 Timothy 2:5 (KJV)"},12:{type:"scripture",ref:"Romans 10:4 (CJB)"},13:{type:"scripture",ref:"1 John 3:24 (NKJV)"},14:{type:"scripture",ref:"Matthew 16:25"},15:{type:"scripture",ref:"2 Corinthians 6:17"},16:{type:"scripture",ref:"John 8:31 (GNT)"}},nkjv:{"Colossians 3:9-10":"9. Do not lie to one another, since you have put off the old man with his deeds, 10. and have put on the new man who is renewed in knowledge according to the image of Him who created him,","1 Corinthians 6:9-10 (CJB)":"9. Don\u2019t you know that unrighteous people will have no share in the Kingdom of God? Don\u2019t delude yourselves \u2014 people who engage in sex before marriage, who worship idols, who engage in sex after marriage with someone other than their spouse, who engage in active or passive homosexuality, 10. who steal, who are greedy, who get drunk, who assail people with contemptuous language, who rob \u2014 none of them will share in the Kingdom of God.","Romans 10:4 (CJB)":"For the goal at which the Torah aims is the Messiah, who offers righteousness to everyone who trusts.","John 8:31 (GNT)":"So Jesus said to those who believed in him, \u201CIf you obey my teaching, you are really my disciples;\u201D","Romans 3:10":"As it is written: \u201CThere is none righteous, no, not one;","Romans 3:23":"for all have sinned and fall short of the glory of God,","2 Corinthians 12:9":"And He said to me, \u201CMy grace is sufficient for you, for My strength is made perfect in weakness.\u201D Therefore most gladly I will rather boast in my infirmities, that the power of Christ may rest upon me.","John 15:10":"If you keep My commandments, you will abide in My love, just as I have kept My Father\u2019s commandments and abide in His love.","Revelation 22:15":"But outside are dogs and sorcerers and sexually immoral and murderers and idolaters, and whoever loves and practices a lie.","Matthew 18:21-22":"21. Then Peter came to Him and said, \u201CLord, how often shall my brother sin against me, and I forgive him? Up to seven times?\u201D 22. Jesus said to him, \u201CI do not say to you, up to seven times, but up to seventy times seven.","Matthew 10:37-39":"37. He who loves father or mother more than Me is not worthy of Me. And he who loves son or daughter more than Me is not worthy of Me. 38. And he who does not take his cross and follow after Me is not worthy of Me. 39. He who finds his life will lose it, and he who loses his life for My sake will find it.","Mark 12:30-31":"30. And you shall love the LORD your God with all your heart, with all your soul, with all your mind, and with all your strength.\u2019 This is the first commandment. 31. And the second, like it, is this: \u2018You shall love your neighbor as yourself.\u2019 There is no other commandment greater than these.\u201D","2 Timothy 2:5 (KJV)":`And if a man also strive for masteries,
yet is he not crowned, except he strive lawfully.`,"1 John 3:24 (NKJV)":"Now he who keeps His commandments abides in Him, and He in him. And by this we know that He abides in us, by the Spirit whom He has given us.","Matthew 16:25":"For whoever desires to save his life will lose it, but whoever loses his life for My sake will find it.","2 Corinthians 6:17":"Therefore \u201CCome out from among them And be separate, says the Lord. Do not touch what is unclean, And I will receive you.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/blessed-are-those-who-overcome-for-my-names-sake",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/blessed-are-those-who-overcome?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=ODqtx5_q71c&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Homosexuality",url:"https://answersonlygodcangive.com/Regarding_Homosexuality"},{label:"Regarding Forgiveness",url:"https://answersonlygodcangive.com/Regarding_Forgiveness"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"}],num:22,prevLetter:{id:"chosen-vessels",title:"Chosen Vessels"},nextLetter:{id:"a-rock-of-offense",title:"A Rock of Offense"}},{id:"a-rock-of-offense",title:"A Rock of Offense",date:"11/12/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, I have sent you out amongst My sheep, as a young shepherd who lacks experience, as one who has little knowledge of My flock. Yet from your birth, I set you apart for My purpose. Yea, before your formation in the womb, I appointed you a prophet to the nations. Thus you shall go for Me and be to My people a light, a beacon shining amidst the darkness of the end of this age, a voice shouting in desolate places calling them out."}]},{type:"poetry",lines:[[{t:"italic",v:"You shall be for Me a witness,"}],[{t:"italic",v:"A rock of offense which I have placed"}],[{t:"italic",v:"At the feet of the rebellious and set"}],[{t:"italic",v:"Against the churches of men,"}],[{t:"italic",v:"Causing them to stumble..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I have put My words in your mouth,"}],[{t:"italic",v:"And by the power of My spirit have I"}],[{t:"italic",v:"Caused you to write all these words..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Each Letter a spear with which I"}],[{t:"italic",v:"Shall pierce the heart of this people,"}],[{t:"italic",v:"Every Volume a sword by which I"}],[{t:"italic",v:"Shall divide them asunder..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A rod and a staff for those who believe..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]},{type:"para",segments:[{t:"text",v:"Timothy, I have made you a watchman for the people. Therefore you shall hear the Word of My mouth, and warn them from Me. Yet their ears are dull, their countenances set and their hearts unyielding. For they are haughty and do always reject the Word of God. Indeed My words have become an object of scorn among them, and in My ways they find no delight. Therefore I shall increase in you seven-fold, and cause this Word to become as a blaring trumpet in the ears of this people, a thorn in the side of this nation which can not be removed, and you shall be perceived as an enemy to all men. Behold, I have set you apart for My glory; an empty vessel of dishonor, of which I have cleansed and filled unto great honor; a man who shall be hated and persecuted by those of this world, yet rejoiced over by angels. For even those who claim to be of My sheepfold shall come to hate you with a profound and bitter hatred, to the casting of many stones in word and by deed. For they have not known Me."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus I have called you out of the world,"}],[{t:"italic",v:"And shall also send you back into the world,"}],[{t:"italic",v:"Even to the churches of men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as it was written of My prophets of old,"}],[{t:"italic",v:"So in like manner have I appointed you:"}]]},{type:"poetry",lines:[[{t:"italic",v:"I have made your face strong against their faces,"}],[{t:"italic",v:"And your forehead strong against their foreheads;"}],[{t:"italic",v:"Like adamant stone, harder than flint,"}],[{t:"italic",v:"I have made your forehead"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I have set you over nations and over kingdoms,"}],[{t:"italic",v:"To root out and to pull down, to destroy"}],[{t:"italic",v:"And to throw down, to build and to plant"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"closing-fn",segments:[{t:"italic",v:"For I am The Lord, and I do not change."},{t:"fn",v:"3"}]}],footnotes:{1:{type:"scripture",ref:"Ezekiel 3:8-9"},2:{type:"scripture",ref:"Jeremiah 1:10"},3:{type:"scripture",ref:"Malachi 3:6"}},nkjv:{"Ezekiel 3:8-9":"8. Behold, I have made your face strong against their faces, and your forehead strong against their foreheads. 9. Like adamant stone, harder than flint, I have made your forehead; do not be afraid of them, nor be dismayed at their looks, though they are a rebellious house.\u201D","Jeremiah 1:10":"See, I have this day set you over the nations and over the kingdoms, To root out and to pull down, To destroy and to throw down, To build and to plant.\u201D","Malachi 3:6":"\u201CFor I am the LORD, I do not change; Therefore you are not consumed, O sons of Jacob."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-rock-of-offense",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/a-rock-of-offense?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=A7crmYL7jOo&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=30",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:23,prevLetter:{id:"blessed-are-those-who-overcome-for-my-name-s-sake",title:"Blessed Are Those Who Overcome for My Name\u2019s Sake"},nextLetter:{id:"follow-me",title:"Follow Me"}},{id:"follow-me",title:"Follow Me",date:"11/12/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, your Teacher:"},{t:"text",v:"God is just in everything. And if The Father\u2019s justice is not partial, then it shall surely come to pass in these latter days, that those who have placed themselves first shall be last, and those who were seen as last shall be first partakers of The Glory. For what shall I do and what shall I say, to all these who call of themselves Christian, to a people who invoke My Word in Scripture, yet in that selfsame hour disobey it? Shall I reward the arrogant for their disobedience and the prideful for their pomp? Shall any who teach as doctrine the commandments of men escape the Day of The Lord? For of My servants I require meekness and fear, rightly dividing the Word of Truth unto the edification of the people - not in justification of themselves, by themselves, to their own glory."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord, to all those who call of themselves Christian:"},{t:"text",v:"Do you really know Me? Have you truly received of Me? And if you have received of Me, how is it you do not abide in Me? Where is the fruit of My spirit, which you say lives in you? I tell you the truth, I have not seen it! And of My gifts, what have you done with them? My lost sheep, where have you laid them? They lie next to your faith, which has also been misplaced."}]},{type:"poetry",lines:[[{t:"italic",v:"Indeed many of you have asked of Me forgiveness,"}],[{t:"italic",v:"And I have washed you in My own blood;"}],[{t:"italic",v:"Are you not then married to Me?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"How is it then that you still play the harlot,"}],[{t:"italic",v:"Returning to those things which are not lawful,"}],[{t:"italic",v:"Taking pleasure in those things I hate?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus as it is written, I will surely"}],[{t:"italic",v:"Correct and discipline all those I love"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I do not change."}]]},{type:"para",segments:[{t:"text",v:"Therefore I have called forth the watchmen, My prophets, of whom you shall know by their fruits and by their sword (the fruits of which the devil can not duplicate - imitate, yes; duplicate, no). Therefore, woe to those who do not embrace their words and ignore their correction. For it would have been better for you if you had never met them, nor heard them, and remained in ignorance. Yet you have heard them. Thus you are bound by their words, a cord which can not be cut. Therefore woe to all those who come against them, for you have lifted up your heel against ME! Says The Lord. Indeed all who stone them in word or by deed shall not be gathered, nor shall they escape. For I shall leave them in the midst of the fire, left unto refinement in the Great and Terrible Day of The Lord. There shall be wailing and gnashing of teeth."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore listen closely"}],[{t:"italic",v:"And take My words to heart,"}],[{t:"italic",v:"All you who call of yourselves Christian:"}],[{t:"italic",v:"I ask you, do you really love Me?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then follow Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved ones, listen closely"}],[{t:"italic",v:"And take My words to heart,"}],[{t:"italic",v:"All you who call of yourselves Christian:"}],[{t:"italic",v:"Do you really love Me?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then obey My Word! Follow Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, listen closely"}],[{t:"italic",v:"And take My words to heart,"}],[{t:"italic",v:"All you who call of yourselves Christian:"}],[{t:"italic",v:"Do you really love Me?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then heed My voice and come out!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"FOLLOW ME!"}]]}],footnotes:{1:{type:"scripture",ref:"Revelation 3:19"}},nkjv:{"Revelation 3:19":"As many as I love, I rebuke and chasten. Therefore be zealous and repent."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/follow-me",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/follow-me?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=Iue6-4nMPRI&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=31",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Woe to Those Who Come Against God's Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:24,prevLetter:{id:"a-rock-of-offense",title:"A Rock of Offense"},nextLetter:{id:"i-am-with-you-always",title:"I Am With You Always"}},{id:"i-am-with-you-always",title:"I Am With You Always",date:"1/5/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the Holy Spirit)",blocks:[{type:"para",segments:[{t:"italic",v:"Question asked by Timothy: Lord, can You help me better understand John 16:13-15?"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, think not in earthly terms, nor consider by human means. Rather know and understand, that which I have poured out is spirit and truth. For the Spirit is not a person, as one separate. Rather it is a gift, a blessing received through The Messiah."},{t:"fn",v:"2"},{t:"text",v:"For as it is written:"},{t:"italic",v:"Streams of life-giving water will pour out from His side."},{t:"fn",v:"3"},{t:"text",v:"Therefore that which you receive is of God and of Messiah, for The Father and The Son are one. Thus the Comforter is of The Son and The Father also."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, your Teacher:"},{t:"text",v:"This is why I said, the Spirit shall not speak of itself as one separate, but shall take of Mine and reveal it to you. For the fullness of The Father dwells in The Son,"},{t:"fn",v:"4"},{t:"text",v:"and that which is The Father\u2019s is The Son\u2019s also. My son, the Spirit and The Messiah are completely one, even as I and The Father are One. For I tell you the truth, all The Father wills is made manifest through Me. Thus the Spirit is given so you may really know Me, and receive strength to walk in My ways. For I am with you always, even to the end of this age."},{t:"fn",v:"5"}]},{type:"poetry",lines:[[{t:"italic",v:"And behold, there is a day coming"}],[{t:"italic",v:"Quickly when you shall be changed,"}],[{t:"italic",v:"And no longer shall I dwell only in you,"}],[{t:"italic",v:"But you shall dwell also in Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then shall you understand"}],[{t:"italic",v:"The fullness of who I am..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written:"}],[{t:"italic",v:"Now you see in a mirror dimly, but then face to face;"}],[{t:"italic",v:"Now you know in part, but then you shall"}],[{t:"italic",v:"Know just as you are also known."},{t:"fn",v:"6"}]]}],footnotes:{1:{type:"scripture",ref:"John 16:13-15 (corrected: \u201CIt\u201D / \u201Cthe Spirit of Truth\u201D)"},2:{type:"scripture",ref:"John 20:22"},3:{type:"scripture",ref:"John 7:37-39 (GNT)"},4:{type:"scripture",ref:"Colossians 1:19"},5:{type:"scripture",ref:"Matthew 28:20"},6:{type:"scripture",ref:"1 Corinthians 13:12"}},nkjv:{"John 16:13-15 (corrected: \u201CIt\u201D / \u201Cthe Spirit of Truth\u201D)":"13. However, when It, the Spirit of Truth, has come, It will guide you into all truth; for It will not speak on Its own authority, but whatever It hears It will speak; and It will tell you things to come. 14. It will glorify Me, for It will take of what is Mine and declare it to you. 15. All things that the Father has are Mine. Therefore I said that It will take of Mine and declare it to you.","John 20:22":"And when He had said this, He breathed on them, and said to them, \u201CReceive the Holy Spirit.","John 7:37-39 (GNT)":"37. On the last and most important day of the festival Jesus stood up and said in a loud voice, \u201CWhoever is thirsty should come to me, and 38. whoever believes in me should drink. As the scripture says, \u2018Streams of life-giving water will pour out from his side.\u2019 39. Jesus said this about the Spirit, which those who believed in him were going to receive. At that time the Spirit had not yet been given, because Jesus had not been raised to glory.\u201D","Colossians 1:19":"For it pleased the Father that in Him all the fullness should dwell,","Matthew 28:20":"teaching them to observe all things that I have commanded you; and lo, I am with you always, even to the end of the age.\u201D Amen.","1 Corinthians 13:12":"For now we see in a mirror, dimly, but then face to face. Now I know in part, but then I shall know just as I also am known."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-with-you-always",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/i-am-with-you-always?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=7-ASr9EEXpg&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=33",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Spirit",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding The Trinity",url:"https://answersonlygodcangive.com/Regarding_The_Trinity"}],num:25,prevLetter:{id:"follow-me",title:"Follow Me"},nextLetter:{id:"rebellion-recompense-reformation",title:"Rebellion, Recompense, Reformation"}},{id:"rebellion-recompense-reformation",title:"Rebellion, Recompense, Reformation",date:"1/22/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord of Hosts:"},{t:"text",v:"I have stretched out My hand to this dying people, I have opened My mouth to speak to this lost and most wicked generation, a people who do always cover their ears and hide their faces, lest they be made to give an account. Indeed, they are wise in their own eyes, and from the Way they have departed. For as it is written:"},{t:"italic",v:"They are wise to do evil, but to do good they have no knowledge."},{t:"fn",v:"1"},{t:"text",v:"Thus all I have purposed to do shall be done, it shall surely come to pass, and you, yes you, O most wicked generation, shall be astonished, horribly afraid! For I shall confound the multitudes, and the people shall be dismayed! Therefore run and hide; conceal yourselves in the clefts of the rocks and hide your faces! For the power of The Lord shall surely be put on open display! For what is this generation to Me? Are you not a people exceedingly great in number, a people whose cities cover the face of the earth like the stars fill the heavens? And though you build and make for yourselves a name, I shall surely throw down! For before Me is a whole generation whose every inclination is evil continually, a most rebellious people who do not cease from fighting against Me! Says The Lord. Not since the days of Noah, when the wickedness of man was great in the earth, have I beheld a generation such as this! - A people who are wise in their own eyes, who parade their whoredoms openly, without restraint, a most vile people whose transgressions increase beyond measure, whose sin reaches unto heaven! Behold, they seek out evil to embrace it, and the grave that they might lie down in it, a so-called modern people who make for themselves laws, that they might practice abomination freely, even to the murdering of the innocent without fear of reprisal! Behold, they run from evil to evil, that they might provoke Me to anger! Yes, they run to and fro in all the earth, committing evil and practicing abomination, for their wickedness has no end! They oppress the poor, and the right of the needy they do not defend! The widows and the fatherless are cast aside, and the meek are trampled underfoot!"}]},{type:"poetry",lines:[[{t:"italic",v:"Day and night you exalt yourselves, O sons of men!"}],[{t:"italic",v:"Every day you walk proudly in your rebellion,"}],[{t:"italic",v:"And every night you practice abomination!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shall you steal, kill and destroy,"}],[{t:"italic",v:"For the sake of your own glory?!"}],[{t:"italic",v:"How long shall you bring forth"}],[{t:"italic",v:"Only works of unrighteousness?!"}],[{t:"italic",v:"How long shall you run greedily for gain,"}],[{t:"italic",v:"Fueled by your never-ending lusts?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YOUR WICKEDNESS OVERFLOWS,"}],[{t:"italic",v:"A PEOPLE WHOSE COVETOUSNESS HAS NO EQUAL!"}]]},{type:"para",segments:[{t:"text",v:"And what is this I see among all these so-called people of faith, among all these multitudes who claim to be a people for My name? Behold, in MY NAME they commit abomination, provoking Me to anger! In MY NAME, they make great spectacles of themselves, as they twist the Scriptures for evil gain! In MY NAME, they teach as doctrine the commandments of men; lawlessness is widely accepted! THEY HAVE SURELY TAKEN THE NAME OF THE LORD IN VAIN! Therefore, I shall turn their glory into shame, I shall make of them a desolation and their people an object of scorn, and they shall bear the reproach of all nations! Behold, I shall break all these unruly branches, for they can in no wise be grafted in! For I am The Lord, and I do not change! Yet in My mercy, I set watchmen over them, saying,"},{t:"italic",v:"\u201CListen to the sound of the trumpet, heed the voice of The Living God, and embrace My correction. For I do not change.\u201D"},{t:"text",v:"But they said,"},{t:"italic",v:"\u201CWe will not listen, nor will we give heed, nor will we embrace The Lord\u2019s correction. For we love our whitewashed palaces, and will never depart from these houses which are called by our name. Yes, we love the sound of our own voices, and we have brought glory to our name.\u201D"},{t:"text",v:"Thus I shall continue to speak. I shall open My mouth in the former manner and speak to this most ungodly generation. Yes, I shall surely make My plans known and warn the people; I shall rebuke them sharply and declare all their wrongdoings, as in the days of old. For I do not change, says The Lord. Did I not speak in times past by the mouths of My servants, the prophets? And was I not also speaking to you, O foolish and deceived generation? Yet they would not give heed to My words, nor would they listen, and so all I had purposed to do to them was fulfilled."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus upon you also will I bring all"}],[{t:"italic",v:"I have spoken by My servants the prophets,"}],[{t:"italic",v:"Both the former and the latter, even to this day..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For you also refuse to give heed to My words,"}],[{t:"italic",v:"Nor will you listen, nor will you turn aside"}],[{t:"italic",v:"From your evil ways, provoking Me to anger!..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"text",v:"And as for you, Timothy, you must proclaim My words, both the former and the latter. You must blow the Trumpet and warn the people. For as I had spoken by My prophet of old, so now do I also speak by you. Therefore prophesy against them, saying..."}]},{type:"para",segments:[{t:"italic",v:"The Lord shall roar from Heaven and thunder from His Holy Mountain; He shall roar mightily against His people! He shall give a shout like the one who treads grapes, and rebuke the inhabitants of the earth! All the people shall hear Him; behold, the sound of His voice shall echo in all the earth! For The Lord has a controversy with the nations; He shall pass judgment on all mankind, and the wicked shall be handed over to the sword. Disaster shall go forth from nation to nation, and a great storm shall be raised up from the uttermost parts of the earth. On that day, the slain of The Lord shall be from one end of the earth to the other. Yet they shall not be lamented, nor gathered, nor buried, but lie as refuse upon the ground. Therefore wail, all you shepherds! Says The Lord. Wallow in the dust and cry aloud, all you leaders among men! For the Days of Brokenness have come upon you, and the Day of Slaughter is about to come in! For I will surely break you; like a clay pot you shall fall and shatter upon the ground! The shepherds shall be unable to flee, and the leaders shall have no escape! Behold, the wailing of the shepherds shall be great, and the cry of the leaders shall resound in every nation! For I shall plunder their pastures and all the peaceable dwellings shall be cut down! Says The Lord in His fierce anger."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, prepare in the desert the way of The Lord!"}],[{t:"italic",v:"Make a straight path in these dry and parched lands,"}],[{t:"italic",v:"For The Holy One of Israel!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Let every valley be exalted,"}],[{t:"italic",v:"And every mountain and hill brought low!"}],[{t:"italic",v:"Let the crooked places be made straight,"}],[{t:"italic",v:"And the rough places smooth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The Glory of The Lord shall be"}],[{t:"italic",v:"Revealed from Heaven, and all"}],[{t:"italic",v:"People shall behold it together!..."}]]},{type:"closing",text:"For I am The Lord, and I do not change."}],footnotes:{1:{type:"scripture",ref:"Jeremiah 4:22"}},nkjv:{"Jeremiah 4:22":"\u201CFor My people are foolish, They have not known Me. They are silly children, And they have no understanding. They are wise to do evil, But to do good they have no knowledge.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/rebellion-recompense-reformation",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/rebellion-recompense?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=MhVny6bjSKU&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=33",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"The Days of Noah Revived",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah#The_Days_of_Noah_Revived"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"God Speaks Regarding Covetousness",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Covetousness"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the Voice of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Voice_of_The_Lord"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:26,prevLetter:{id:"i-am-with-you-always",title:"I Am With You Always"},nextLetter:{id:"grafted-in",title:"Grafted In"}},{id:"grafted-in",title:"Grafted In",date:"2/2/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, why do you beseech The Lord your God in such a manner? Have I not given you your heart\u2019s desire? Stop stifling the Spirit, and break free from doubt. For doubt is your enemy, a clever adversary, a false witness, the work of the evil one in an attempt to bar your way before Me. Therefore cast off the unfruitful works of the devil, and embrace that which I have given you, and you shall surely be established. Let not doubt nor fear rule over you any longer. You need only turn to Me and believe, for all I have spoken shall surely come to pass. And yet you ask of these things written in the book called Revelation, and of the 144,000. Why do you doubt? Have I not said,"},{t:"italic",v:"\u201CYou are chosen, and you shall go for Me\u201D?"},{t:"text",v:"Therefore listen, and also understand: I am no respecter of persons, for all in The Messiah are of one body. So then your appointment is not by lineage nor heritage, but of Messiah. And what of those of the line of Israel who reject The Messiah, shall they go for Me? Surely not. For they are broken off, until such time I choose to graft them in again. And if I choose one such as you, Timothy, whom I have plucked from among the Gentiles and grafted in, are you not then the same as those who remain in the olive tree? Again, only those in union with The Messiah shall go for Me. For if you are adopted into the family of Abraham, then of Abraham you are. If I have grafted you into the branch of Levi, then of the Levites you are and as a Levite you shall serve. And if you grow from The True Vine, and I Myself have pruned you, then you shall indeed bear much fruit in My name. Therefore let no man, nor any doctrine conceived within the churches of men, lead you astray. Do not be swayed, nor doubt, on account of all their lofty assertions, which they falsely call truth. For upon their heads is a veil held fast by the pride and arrogance of men, men in authority who teach and preach in My name, though I have not sent them. For they do always bear false witness, saying,"},{t:"italic",v:"\u201CI see, I see!\u201D"},{t:"text",v:"though they themselves remain blinded. Their knowledge is corrupt, not one has heard the voice of The Living God, nor will they embrace Me as I truly am."}]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written:"}],[{t:"italic",v:"When I swear an oath,"}],[{t:"italic",v:"I swear by Myself,"}],[{t:"italic",v:"For there is none greater"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore who I choose, I choose!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"scripture",ref:"Hebrews 6:13"}},nkjv:{"Hebrews 6:13":"For when God made a promise to Abraham, because He could swear by no one greater, He swore by Himself,"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/grafted-in",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/grafted-in?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=IAV1NV_Vqzs&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=36",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Doubt",url:"https://answersonlygodcangive.com/Regarding_Doubt"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:27,prevLetter:{id:"rebellion-recompense-reformation",title:"Rebellion, Recompense, Reformation"},nextLetter:{id:"born-again",title:"Born Again"}},{id:"born-again",title:"Born Again",date:"2/6/07",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"It is written,"},{t:"italic",v:"that none shall enter The Kingdom of Heaven, unless they are born again. For all are born physically, of human parents, by great travail into a world of sin. So then to enter The Kingdom of Heaven, one must also be born again, of the Spirit,"},{t:"fn",v:"1"},{t:"text",v:"set apart from this world and from all that is sin. My son, you are being born again even now, from the first moment you came to Me in repentance, even to this day. For I am faithful. And yet you ask,"},{t:"italic",v:"\u201CHow can this be?\u201D"},{t:"text",v:"questioning My words spoken to My servant, where I said,"},{t:"italic",v:"\u201CYou must be born again and again.\u201D"},{t:"text",v:"My son, I have spoken, and all I have written through My servant Timothy stands; no contradiction found. Rather it is the understanding of men, which remains lacking. Therefore if one comes to Me in repentance, with sincere remorse over their sins, they shall surely be born again - even again and again, as they strive to make their repentance full."},{t:"fn",v:"2"}]},{type:"para",segments:[{t:"text",v:"Yet I tell you a mystery: It has been appointed to those who are born twice to die once, but by no means shall they die a second time. Yet those who do not come to Me in repentance shall be born once and die twice. Yet there are some among this generation who shall never taste death, having already passed from judgment into life. Thus to My chosen elect, there is a death of the body unto resurrection. Yet for those still living at My return, there is a death of another kind -"},{t:"italic",v:"the crucifying of your old man with his sinful ways, the putting on of the new man who is renewed in the knowledge of the Truth, restored in the image of Him who created him."},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus when one is born into this world,"}],[{t:"italic",v:"The child and the mother suffer the pangs"}],[{t:"italic",v:"Of childbirth, until the birth is complete..."}]]},{type:"poetry",lines:[[{t:"italic",v:"In the same way, those born of the Spirit shall suffer travail;"}],[{t:"italic",v:"For they are not yet separated from their flesh"}],[{t:"italic",v:"Or this world, in which they continually stumble..."}]]},{type:"poetry",lines:[[{t:"italic",v:"So then being born again is the process by which"}],[{t:"italic",v:"You are restored in the image of God,"}],[{t:"italic",v:"A continual washing, until you come into glory."}]]},{type:"para",segments:[{t:"text",v:"My son, I died for the forgiveness of your sins - those of today, yesterday, and those sins of tomorrow. Yet man does continually stumble over his flesh, being tempted in a world filled with sin. And so he must continually come to Me, and even seventy times seven times shall I cleanse him and lift him up. And so to Timothy, I have spoken and said that he must be born again and again, until I present him to The Father clean. This is not rebirth in the Spirit again and again, but rather the process by which Timothy sheds the skin of this world, as he crucifies his old man with his sinful ways and puts on this new man I have given him, in Me and of Me. And so there is one rebirth in the Spirit (the moment one\u2019s heart is irrevocably changed), but many rebirths of man\u2019s spirit, because of his continual sin, fear, doubt and temptation. Therefore as it was with My servant, Sha\u2019ul (also known as Paul), so likewise shall it be with My servants of this day:"},{t:"italic",v:"You must die daily."}]},{type:"para",segments:[{t:"text",v:"And still in another place you ask, concerning those who teach in My name,"},{t:"italic",v:"\u201CWhy must these become, again, children of God?\u201D"},{t:"text",v:"This is not rebirth in the Spirit, but rather a correction and a washing. For these have strayed off the path, though they claim to follow Me. And when one strays off the path and follows after the world, teaching in the churches of men doctrines of demons, I ask you, what father have they chosen and whose child have they become? And so with a firm hand, I will surely correct and discipline all those I love, so they may return to Me and become again children of God. For indeed, small is the gate and narrow is the way into Heaven. And no man who thinks himself righteous may enter, called Christian or otherwise. So then, My son, you are reborn in the Spirit and have embraced the new heart I have given you, but by no means is this birth complete. For you are indeed that fruit which is still ripening, as you have said. In this you have spoken well, by the wisdom I have given you. For as it is written:"},{t:"italic",v:"I am The True Vine, and My Father is The Vinedresser. Every branch in Me that does not bear fruit He takes away; and every branch that bears fruit He prunes, that it may bear even more fruit."},{t:"fn",v:"4"}]},{type:"poetry",lines:[[{t:"italic",v:"My son, you have bore much fruit in My name,"}],[{t:"italic",v:"And shall continue to do so until the day I finish you,"}],[{t:"italic",v:"The day you become completely new..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as a babe is born naked and wrapped in soft linens,"}],[{t:"italic",v:"So also shall My people be reborn -"}],[{t:"italic",v:"Naked, void of the things of this world,"}],[{t:"italic",v:"Clothed in fine linens of white..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the corruptible has put on incorruption,"}],[{t:"italic",v:"And the mortal, immortality, as it is written!"},{t:"fn",v:"5"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 3:3-5"},2:{type:"note",text:'See: "Regarding True Repentance"',url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},3:{type:"scripture",ref:"Colossians 3:9-10"},4:{type:"scripture",ref:"John 15:1-2"},5:{type:"scripture",ref:"1 Corinthians 15:53-54"}},nkjv:{"John 3:3-5":"3. Jesus answered and said to him, \u201CMost assuredly, I say to you, unless one is born again, he cannot see the kingdom of God.\u201D 4. Nicodemus said to Him, \u201CHow can a man be born when he is old? Can he enter a second time into his mother\u2019s womb and be born?\u201D 5. Jesus answered, \u201CMost assuredly, I say to you, unless one is born of water and the Spirit, he cannot enter the kingdom of God.","Colossians 3:9-10":"9. Do not lie to one another, since you have put off the old man with his deeds, 10. and have put on the new man who is renewed in knowledge according to the image of Him who created him,","John 15:1-2":"1. \u201CI am the true vine, and My Father is the vinedresser. 2. Every branch in Me that does not bear fruit He takes away; and every branch that bears fruit He prunes, that it may bear more fruit.","1 Corinthians 15:53-54":"53. For this corruptible must put on incorruption, and this mortal must put on immortality. 54. So when this corruptible has put on incorruption, and this mortal has put on immortality, then shall be brought to pass the saying that is written: \u201CDeath is swallowed up in victory.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/born-again",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/born-again?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=dQQ8C-2YGg0&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=37",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Being Born Again",url:"https://answersonlygodcangive.com/Regarding_Being_Born_Again"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the First and Second Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"},{label:"Regarding Forgiveness",url:"https://answersonlygodcangive.com/Regarding_Forgiveness"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:28,prevLetter:{id:"grafted-in",title:"Grafted In"},nextLetter:{id:"under-god",title:"Under God"}},{id:"under-god",title:"Under God",date:"2/15/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For the United Church of God, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"To the church at The Lord\u2019s right hand, hear the Word of The Lord, for thus says The Lord:"},{t:"text",v:"Many of you remain seated at My right hand, because of your faith and those good works which you have done in accordance with My will. So then call yourself no more \u201CThe United Church of God.\u201D Rather call yourself \u201CThe United Church in YahuShua The Messiah, Under God.\u201D My children, do you sit next to Me on My throne? Or is it My body in which you dwell? The Messiah is The Church, His name is YahuShua, and He is the body in which My children dwell. By Him and through Him are all things, and to Him shall My children flock. He is your Shepherd, and by His shed blood are you made sons and daughters of God. Yes, many of you are of His body and remain seated at His right hand. Therefore continue in the Way I have shown you, resting firmly in The Messiah, being an immovable stone for His name. Turn not to the right hand nor to the left, but continue straight forward, according to the Scriptures and that which I speak to you this day."}]},{type:"poetry",lines:[[{t:"italic",v:"For in your doings I am well pleased..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For you have kept My Commandments"}],[{t:"italic",v:"And remembered My Holy Days,"}],[{t:"italic",v:"And have not departed from My Sabbaths,"}],[{t:"italic",v:"Even the seventh day of each week,"}],[{t:"italic",v:"Which I had commanded My people"}],[{t:"italic",v:"To remember and keep holy..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yes, even to all who are grafted in."}]]},{type:"para",segments:[{t:"text",v:"Indeed, you have sought to be separate from those things I hate, forsaking that which is detestable in My sight, even all these filthy holidays of men which man celebrates in ignorance and sin, to the desecrating of The Messiah\u2019s name. Thus you have not made your members to be members of a harlot. Therefore great shall be your reward in Heaven. For all sin is not equal; only My forgiveness is equal."}]},{type:"para",segments:[{t:"text",v:"Yet remember this, that you may be humbled in your service toward Me: No church named of men is the true church, not one. Rather each member individually, who believes in The Messiah and obeys His voice, in whom His spirit dwells, make up the True Church of His body - no walls, only spirit and truth. Therefore, O church of men, if you seek to strive on toward perfection, hear My words and forbear not. Take to heart all I have given you, and make it not a point of contention; nor pollute your good works with pride, nor use them as a measuring stick by which you count others unworthy. For I alone sit as judge, I alone correct and discipline all those I love. Rather take all I have given you, both in knowledge and understanding, and remain students. Do not cease from studying to show yourself approved unto God, a workman that need not be ashamed, rightly dividing the Word of Truth, as it is written."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"bold-italic",v:"Beloved, heed My words and listen closely to My speech; for thus says The Lord to the church at His right hand, if you do indeed seek to remain at My right hand:"},{t:"text",v:"Forbear not, nor reject My Word spoken to this generation, lest I leave you unto refinement also. For your robes have been made white, washed in the blood of The Lamb. Yet many of your daughters have gone their own way, returning to the ways of this world and the harlot, doing those things which are most unseemly in My sight - forsaking My Sabbaths and embracing those doctrines and traditions I hate, even all these holidays of men which I loathe in My zeal! Therefore be strong, yea, be very strong, and make every effort to turn them back again, lest they be torn in pieces when I stretch out My hand against the harlot and bring calamity upon the churches of men. Again, I say to you, strive toward perfection, yet do not think yourselves above reproach. Embrace My words, obey that which I have spoken to this generation, and you shall surely escape all these things which I am about to do. For as it was in the days of Lot, when I brought him out of the city, so likewise shall I deliver My people in the Day of Wrath. For those in whom The Messiah dwells must be taken out of the way. Then shall I judge the earth and strike the nations. For I do not change. Therefore give heed to My words and embrace My correction, that you may see with greater eyes. Or have you forgotten this truth:"},{t:"italic",v:"No prophecy or scripture is to be interpreted by an individual on their own? For prophecy has never come as a result of human power or by the will of man. Rather those chosen received ears to hear, and by the power of My spirit and according to My will, they became mouthpieces of The Most High God."},{t:"text",v:"For all I speak is Scripture and Truth, a plumb line by which all these crooked paths shall be set straight, says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, hear and understand"}],[{t:"italic",v:"The love and severity of God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For those who forsake Me and trample"}],[{t:"italic",v:"Upon the name of The Holy One of Israel,"}],[{t:"italic",v:"Rejecting Me and My Word, great adversity,"}],[{t:"italic",v:"Refinement in the Day of The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet for those who embrace Me"}],[{t:"italic",v:"And My Word, cleaving to Him"}],[{t:"italic",v:"In whom the fullness of God dwells,"}],[{t:"italic",v:"Escape, sanctuary in the house of The Lord."}]]},{type:"para",segments:[{t:"text",v:"Again I say to you, heed My words and embrace My correction; remain in My love. For you have indeed done many things well, according to My Word in the Scriptures. And only by these things for which you yet lack understanding have you erred. Therefore hear and understand the truth of baptism, of which you hold in such high regard, and be careful that you do not make it a rod or measuring stick by which you judge others; nor make baptism by water more than it was ordained to be, lest you make the cross of The Messiah of no effect. For like circumcision, so is baptism; neither is necessary for salvation. For you need only look to the thief on the cross, and have understanding. For one who had not known baptism by water was assured of salvation, though his sin was great, having confessed before The Messiah with a sincere and penitent heart. And in that same moment he was forgiven, and will enter into paradise at the Last Day, as Messiah had spoken it, saying,"},{t:"italic",v:"\u201CIn truth I speak to you this day"},{t:"bold-italic",v:","},{t:"italic",v:"you shall be with Me in paradise.\u201D"}]},{type:"para",segments:[{t:"text",v:"For as it is written:"},{t:"italic",v:"Many will there be in My Kingdom who received no baptism by water. Rather they had been fully immersed in The Word of God, enveloped in The Son\u2019s sacrifice and love, baptized in the Spirit of Truth. For most assuredly, I say to you, they have their reward. Therefore, do not cast stumbling blocks before the feet of those who love Me. Be one in Messiah, according to that which dwells inwardly in the heart. For true fellowship comes not by words spoken amongst a group of united people, nor by immersion in water. Rather it starts with the heart, and is found in the stillness of My spirit, where My peace mends the broken and My gentle caress gladdens the heart. For all those found at the feet of The Lord are covered with grace, and those who abide in My love are indeed of one accord. Beloved, where in The Commandments have I written all must be baptized by men to be saved? Baptism is indeed good, if it is a confession poured out from one\u2019s heart in pure belief, an outward act of faith revealing one\u2019s acceptance of their forgiveness in The Messiah. For the water of the earth can only cleanse that which is soiled on the skin. By no means can it cleanse that which is soiled in the spirit; this is reserved for the blood of The Lamb. Again I say to you, baptism by water is nothing, unless one is first washed by The Word, being baptized in the Spirit of Grace and Truth which is received in YahuShua HaMashiach, whom you call Jesus and Christ. For HE is The True Baptism, The Very Water of Life, in which all must be cleansed to receive everlasting life."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore beloved, remember:"}],[{t:"italic",v:"The spirit of the Word, and not the letter,"}],[{t:"italic",v:"Is the way, the truth and the life..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The Messiah is indeed coming quickly,"}],[{t:"italic",v:"To baptize all in fire and glory..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Those of a wicked heart, in fire..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And those of the Spirit, in glory, forever and ever!"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"2 Timothy 2:15"},2:{type:"note",text:"See: The True Baptism",url:"https://www.thevolumesoftruth.com/The_True_Baptism#The_True_Baptism",link:{collection:"Volume Two",letterTitle:"The True Baptism"}}},nkjv:{"2 Timothy 2:15":"Be diligent to present yourself approved to God, a worker who does not need to be ashamed, rightly dividing the word of truth."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/under-god",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/under-god?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United Church of God",url:"https://answersonlygodcangive.com/Regarding_the_United_Church_of_God"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Regarding The True Church",url:"https://answersonlygodcangive.com/Regarding_The_True_Church"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding Baptism",url:"https://answersonlygodcangive.com/Regarding_Baptism"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:29,prevLetter:{id:"born-again",title:"Born Again"},nextLetter:{id:"keep-the-passover",title:"Keep The Passover"}},{id:"keep-the-passover",title:"Keep The Passover",date:"3/20/07",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My children, keep the Passover. Keep it according to the New Covenant, in faith and love, and remember. Yet you who call of yourselves Christian do always dishonor Me. Behold, you pollute the glory of My sacrifice with filthy traditions and desecrate My resurrection with pagan practices, forsaking those things which you were to keep holy and remember, nor will you incline the ear. Churches of men, know you not that in these Seven (the Holy Days) is wisdom and understanding, the very mind of God?! Yet you choose vanities on top of vanities, embracing corrupt doctrine and pagan-laced tradition, placing your stamp of approval on them. For you are a most perverse and adulterous generation. Churches of men, I am not of this world, yet you are of this world. Thus only those who obey My voice trust in Me, and only those who embrace Me as I truly am are set apart. For I live in them and they follow Me. You claim you trust in Me and that I live in you, yet not one of you obeys My voice; indeed, you ignore My example and refuse to walk in My ways. For if I truly lived in you, then you would do as I did. Beloved, follow Me! Keep the Passover, honor the Holy Days, and remember the Sabbath. Only then will you begin to see, only then will you understand. For the Holy Days are revelation, every Sabbath a blessing, a sign between Me and you that you may know I am The Lord who sanctifies you."}]},{type:"poetry",lines:[[{t:"italic",v:"And behold, four are fulfilled:"}],[{t:"italic",v:"Salvation assured, sin and death overcome, the Spirit given..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Three are coming quickly:"}],[{t:"italic",v:"Sin destroyed, evil bound, My seat taken, Judgment..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A new day, even one thousand years..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then a short season, consummation..."}]]},{type:"poetry",lines:[[{t:"italic",v:"An everlasting day in The Lord!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Amen, and amen."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/keep-the-passover-2",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/keep-the-passover?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=UHSdSNJvX58&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=38",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:30,prevLetter:{id:"under-god",title:"Under God"},nextLetter:null}],LETTERS_V4_PREFACE=null,LETTERS_V4=[{id:"without-spot-or-blemish",title:"Without Spot or Blemish",date:"6/26/07",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked: Was YahuShua ever ill? It is written: \u201CI was sick and you visited Me.\u201D"},{t:"fn",v:"1"},{t:"italic",v:"It is hard to imagine that He could be scourged and crucified, but never suffered a migraine."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"My son, I came to minister, not to be ministered to. I came to heal the sick, even all who came asking;"},{t:"italic",v:"I bore their infirmities."},{t:"fn",v:"2"},{t:"text",v:"By no means did I, Myself, become sick, for The Father allowed nothing to keep Me from My purpose. I came down to you in the flesh, to live as a man, to be fully tempted as man, yet I did not suffer illness of the body, nor did I sin. For The Father made the body and mind to be one; not to suffer illness, but to abide in health. So as I came from The Father, and The Father is in Me and I am in The Father, so in like manner was My body, incorruptible; the kind of which even Adam was given, and would have kept to this day if he had not transgressed. For he who is without sin has everlasting life; death has no power over him. My son, I carried the infirmities of all those who came to Me in faith. In the same way, I carried their sin though I had no part in sin Myself. I am completely clean, and because of this, all who come to Me in sincerity and in truth are clean also."}]},{type:"poetry",lines:[[{t:"italic",v:"My son, I carried the weight of the world\u2019s sin"}],[{t:"italic",v:"To the cross, and crucified sin through My suffering;"}],[{t:"italic",v:"The penalty of sin abolished as I fell asleep,"}],[{t:"italic",v:"The Victory established for all time upon My rising..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I am and will always be The Perfect Lamb,"}],[{t:"italic",v:"Without spot or blemish, given up for many..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Restoration of All Things..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 25:36"},2:{type:"scripture",ref:"Isaiah 53:4"}},nkjv:{"Matthew 25:36":"I was naked and you clothed Me; I was sick and you visited Me; I was in prison and you came to Me.\u2019","Isaiah 53:4":"Surely He has borne our griefs And carried our sorrows; Yet we esteemed Him stricken, Smitten by God, and afflicted."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/without-spot-or-blemish",videoVoiceUrl:"https://www.youtube.com/watch?v=WD3T_ciIgMM&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=1",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Healing",url:"https://answersonlygodcangive.com/Regarding_Healing"},{label:"Regarding Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"}],num:1,prevLetter:null,nextLetter:{id:"mistranslation-and-misinterpretation-leading-to-great-obscurity-among-many-faces",title:"Mistranslation and Misinterpretation Leading to Great Obscurity among Many Faces"}},{id:"mistranslation-and-misinterpretation-leading-to-great-obscurity-among-many-faces",title:"Mistranslation and Misinterpretation Leading to Great Obscurity among Many Faces",date:"7/25/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Sister in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Regarding Genesis 9:20-27, where Noah drank too much wine, and Ham, his son, saw him naked and uncovered: Some churches and Christians believe and teach that Noah cursed Ham and his son because Ham committed a homosexual act with Noah, while Noah was drunk from the wine. Others believe that Ham had sexual relations with his mother, while Noah was drunk from the wine, and this is why Canaan and Ham were cursed. And still others believe that Ham impregnated his mother, while Noah was drunk from the wine, who later gave birth to Canaan. These same churches use Leviticus as so-called \u201Cevidence\u201D for their beliefs."}]},{type:"para",segments:[{t:"italic",v:"Question asked by Timothy, for a sister in Christ: Lord, are these teachings correct?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved one, hear and understand that which I have spoken through Timothy already. And be very careful that you do not deny My Word, nor add to, nor take away from it. For I am The Lord, and I do not change. And if I do not change, then I shall surely correct and discipline My own; even to the rebuking of all these churches of men, who do always speak in My name without permission, willfully forgetting that no prophecy of Scripture is to be interpreted by an individual on his own. For no prophecy or Scripture has ever come about by the power of man\u2019s will. Rather those chosen were given ears to hear My voice, and by the power of My spirit, according to My will, they shared My message."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Therefore here is truth and wisdom concerning these blasphemies, of which you have accepted: In the days of Noah there was much violence and great perversion upon the face of the earth, and so the wrath of God came upon all the inhabitants of the earth in those days. And none were saved except those counted worthy to escape, those who had walked uprightly before Me, obeying My every word. These, having hearts which were right and good, were spared. Yet I tell you, if even one of these eight souls were not of a right heart, they would have by no means entered the ark. For all appointed to wrath received of wrath and were consumed. Yet these eight lived not as the multitude, but stood apart, choosing rather to trust in My voice and obey My commands, and it was accounted to them as righteousness. So then by no means did these of Noah\u2019s household commit that which is a disgrace to their parents and to themselves, committing that which is altogether worthy of death."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, you see with tainted eyes, through a veil of purple and scarlet;"}],[{t:"italic",v:"Remove this veil, and see with new eyes and restored vision;"}],[{t:"italic",v:"Discern rightly and look upon My words as they are,"}],[{t:"italic",v:"And not as you or the churches would have them be..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My Word is pure, and I am indeed"}],[{t:"italic",v:"A shield to those who put their trust in Me."}]]},{type:"para",segments:[{t:"text",v:"Therefore do not add to My words, lest I rebuke you and you be found a liar, as it is written."},{t:"fn",v:"2"},{t:"text",v:"For only I may add to My Word, yea, an unveiling of the Word\u2019s majesty, both subtle and brilliant, that you may have greater understanding. I alone shall take what man has made crooked, and set it straight once again. For I tell you the truth, the translations of men are greatly erred, which leads to an even greater misinterpretation of My Word by the churches of men, who seek not the Truth as it is but long for that which is malleable, embracing only that which yields to their own perverse desires and expectations. Beloved, hear and understand, and grow wise according to this wisdom I have given you, and no more listen to the churches of men. Be wary of their scholars, and stop your ears from hearing the arrogant speeches of all these men in authority; be wary and vigilant. For they hold tightly to singleness of doctrine, teaching always that which is built upon the corrupt knowledge and vain understanding of men, men who refuse to let go of that which was passed down to them by their forefathers, by which they also remain blind, doctrines and traditions I hate! For they hold onto judgment, seeking always to expose the darkness in men, though they themselves continue to embrace every contemptuous word and deed, perverting My Word and polluting My name before many witnesses. Thus the day is coming and is already here, when all they have wrought in My name shall be tried, it shall surely be tested, and found wanting, declares The Lord."}]},{type:"para",segments:[{t:"text",v:"Beloved, you lack knowledge and have no understanding; you know not the will of The Most High God. Therefore I will speak plainly, that you may discern your error and repent: There is no mention of a forbidden sexual act, nor the \u201Cuncovering of one\u2019s nakedness\u201D as it is ambiguously referred to in certain translations of men. Rather Ham saw his father naked, and then told his brothers, as it is written."},{t:"fn",v:"3"},{t:"text",v:"Thus Noah\u2019s anger was not aroused because of an act worthy of death, but on account of shame. And it was I, by Noah, who cursed Canaan, the father of the Canaanites, according to that which was yet to be. For that which was spoken through Noah was according to prophecy, which later came to be written and was also fulfilled. I AM THE LORD."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore again I say to you,"}],[{t:"italic",v:"Even to all who call of themselves Christian,"}],[{t:"italic",v:"Stop adding to and taking away from My Word,"}],[{t:"italic",v:"To uphold your own perverse way!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"2 Peter 1:20-21"},2:{type:"scripture",ref:"Proverbs 30:6"},3:{type:"scripture",ref:"Genesis 9:22 (CEB)"}},nkjv:{"2 Peter 1:20-21":"20. knowing this first, that no prophecy of Scripture is of any private interpretation, 21. for prophecy never came by the will of man, but holy men of God spoke as they were moved by the Holy Spirit.","Proverbs 30:6":"Do not add to His words, Lest He rebuke you, and you be found a liar.","Genesis 9:22 (CEB)":"Ham, Canaan's father, saw his father naked and told his two brothers who were outside."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/mistranslation-and-misinterpretation-leading-to-great-obscurity-among-many-faces",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Noah, Ham and Canaan (Genesis 9:20-27)",url:"https://answersonlygodcangive.com/Regarding_Noah,_Ham_and_Canaan_(Genesis_9:20-27)"},{label:"Regarding the Days of Noah",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"False Doctrines Within the Churches of Men Regarding...",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],num:2,prevLetter:{id:"without-spot-or-blemish",title:"Without Spot or Blemish"},nextLetter:{id:"the-day-of-astonishment",title:"The Day of Astonishment"}},{id:"the-day-of-astonishment",title:"The Day of Astonishment",date:"11/19/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The time has come and is already here, when all shall be fulfilled; behold, the consummation of all things is at hand! The time has come for the stone to grow very heavy, a yoke upon the necks of all nations. And though many shall gather together seeking to cast it off, they shall be broken in pieces. For they shall stumble, they shall fall, and the weight of their rebellion shall crush them in the day of their calamity, when the foolhardy come out to fight against Me."}]},{type:"poetry",lines:[[{t:"italic",v:"For I shall stretch out My hand against the nations,"}],[{t:"italic",v:"And My strength shall be made fully known..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My name shall resound in all the earth,"}],[{t:"italic",v:"From the uttermost isles even unto the beloved city..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore let the nations be awestruck"}],[{t:"italic",v:"In astonishment at the power of The Lord!"}],[{t:"italic",v:"Let all people be utterly amazed at the mighty works"}],[{t:"italic",v:"Of The Holy One of Israel!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Declares The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-day-of-astonishment",videoVoiceUrl:"https://www.youtube.com/watch?v=njetQWh2Nb0&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:3,prevLetter:{id:"mistranslation-and-misinterpretation-leading-to-great-obscurity-among-many-faces",title:"Mistranslation and Misinterpretation Leading to Great Obscurity among Many Faces"},nextLetter:{id:"integrity-with-all-trust",title:"Integrity with All Trust"}},{id:"integrity-with-all-trust",title:"Integrity with All Trust",date:"4/17/08",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"My son, I have come to live in you, and you have begun to walk in Me; therefore embrace Me fully. For one who loves Me is not ashamed of My ways, neither do they hide what they are doing. How is it then that you hide that which is good and bears fruit in righteousness, and submit to that which is corrupt and bears only bitter fruit, leading to vexation of spirit? Rather as it is written:"},{t:"italic",v:"Let your light so shine before men, that they may see your good works and glorify your Father in Heaven."},{t:"fn",v:"1"},{t:"text",v:"My son, fear not, your beloved will soon awake. Yet for now she remains a stone of stumbling at your feet. Yet you compound the error, by making that which you do seem veiled and sinister in the eyes of the ignorant and arrogant alike. For that done in a corner, or in secret, is not of Me; for that held in secret is akin to a lie. And that which you hide from others, concerning Me and My will, is to deny Me. Know you not, that to love anyone more than Me is to be unworthy of Me? Yet I remain faithful. My son, put dishonesty far from you. For by this you have made your sincere testimony void in the eyes of others, and your good works suspect. Rather be willing to endure persecution for doing what is right, in obedience to God, for this is acceptable with God. Let them speak against you for doing what is right, yet no more give them occasion to speak against you for your wrongdoings; give the adversary no platform at all. My son, hear My words, yet do not act rashly in an attempt to rectify your error; rather in quiet boldness shine forth. Have peace, for I have seen your heart. And that which I see is a sincere hunger and thirst for righteousness - I AM HE. Therefore strive to walk as I walked, and they will see, for every veil is lifted in Me. Be steadfast and forthcoming; make honesty your companion and integrity your close friend."}]},{type:"poetry",lines:[[{t:"italic",v:"Love your enemies, bless those who curse you,"}],[{t:"italic",v:"Do good to those who hate you, and pray for those"}],[{t:"italic",v:"Who spitefully use you and persecute you,"}],[{t:"italic",v:"That you may truly be a son of your"}],[{t:"italic",v:"Father in Heaven, as it is written"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"My son, lead by example, with quiet boldness"}],[{t:"italic",v:"And steadfast trust, and they will begin to see..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 5:16"},2:{type:"scripture",ref:"Matthew 5:44-45"}},nkjv:{"Matthew 5:16":"Let your light so shine before men, that they may see your good works and glorify your Father in heaven.","Matthew 5:44-45":"44. But I say to you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who spitefully use you and persecute you, 45. that you may be sons of your Father in heaven; for He makes His sun rise on the evil and on the good, and sends rain on the just and on the unjust."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/integrity-with-all-trust",videoVoiceUrl:"https://www.youtube.com/watch?v=TuEXiOJrVEo&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=3",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:4,prevLetter:{id:"the-day-of-astonishment",title:"The Day of Astonishment"},nextLetter:{id:"who-is-first",title:"Who Is First"}},{id:"who-is-first",title:"Who Is First",date:"5/24/08",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For His Brothers in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My beloved sons, whom I have also called friends, trust in Me. Stop denying My name, and cease from covering over My doings. For I have indeed called you, yet you have kept secret that which I said to show before all, and quieted that which I commanded be trumpeted loudly. Therefore give heed to My voice, embrace the leading of My spirit, and do those things which are right and good in My eyes; proclaim the Truth, speak it aloud, and no more hide what you are doing. For though you say,"},{t:"italic",v:"\u201CI shall keep the peace,\u201D"},{t:"text",v:"there is no peace. And though within your heart, you have said,"},{t:"italic",v:"\u201CI shall serve in secret,\u201D"},{t:"text",v:"I tell you the truth, you have surely denied Me. Therefore let your \u2018Yes\u2019 be \u2018Yes,\u2019 and your \u2018No,\u2019 \u2018No,\u2019 as it is written."},{t:"fn",v:"1"},{t:"text",v:"Therefore gird up your loins like men, and serve Me in sincerity and in truth, or serve Me not. For it is far better to do nothing, than to deny Me by concealed works and dark speeches. Nor shall you attempt to justify yourselves by false and erred parables, which you did not receive from Me. For you deal not with children, nor with those who feign ignorance, but with those of your own household, of which you were to be the head. Thus you are to blame. For by your actions you have added to their quandary, when instead you should have quickly set all these crooked paths straight. For it is written:"},{t:"italic",v:"Whoever confesses Me before men, him I will also confess before My Father who is in Heaven. But whoever denies Me before men, him I will also deny before My Father who is in Heaven. Do not think that I came to bring peace on earth; I did not come to bring peace but a sword. For I have come to set a man against his father, a daughter against her mother, and a daughter-in-law against her mother-in-law; and a man\u2019s enemies will be those of his own household. For he who loves father or mother, more than Me, is not worthy of Me. And he who loves son or daughter, more than Me, is not worthy of Me. And he who does not take his cross and follow after Me is not worthy of Me. He who finds his life will lose it, and he who loses his life for My sake will find it."},{t:"fn",v:"2"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus that which I had spoken"}],[{t:"italic",v:"To My servant, Kefa, I say also to you:"}],[{t:"italic",v:"Do you love Me more than these?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then feed My sheep, and take care of My lambs..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 5:37"},2:{type:"scripture",ref:"Matthew 10:32-39"}},nkjv:{"Matthew 5:37":"But let your \u2018Yes\u2019 be \u2018Yes,\u2019 and your \u2018No,\u2019 \u2018No.\u2019 For whatever is more than these is from the evil one.","Matthew 10:32-39":"32. \u201CTherefore whoever confesses Me before men, him I will also confess before My Father who is in heaven. 33. But whoever denies Me before men, him I will also deny before My Father who is in heaven. 34. \u201CDo not think that I came to bring peace on earth. I did not come to bring peace but a sword. 35. For I have come to \u2018set a man against his father, a daughter against her mother, and a daughter-in-law against her mother-in-law\u2019; 36. and \u2018a man\u2019s enemies will be those of his own household.\u2019 37. He who loves father or mother more than Me is not worthy of Me. And he who loves son or daughter more than Me is not worthy of Me. 38. And he who does not take his cross and follow after Me is not worthy of Me. 39. He who finds his life will lose it, and he who loses his life for My sake will find it."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/who-is-first",videoVoiceUrl:"https://www.youtube.com/watch?v=W8bl1ZTJ8g0&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=4",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:5,prevLetter:{id:"integrity-with-all-trust",title:"Integrity with All Trust"},nextLetter:{id:"the-cups-of-the-thirsty",title:"The Cups of the Thirsty"}},{id:"the-cups-of-the-thirsty",title:"The Cups of the Thirsty",date:"9/29/08",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I am come,"},{t:"fn",v:"1"},{t:"text",v:" I dwell with My people. And behold, I shall also return and gather My own - some before, and many more after."}]},{type:"para",segments:[{t:"text",v:"Therefore thus says The Lord to His servants: Those of you who have received My Word must walk in it. And those of you who have not received must depart for a time. Yet you also shall receive when your time comes. For The Father will make it possible for you to do so. Therefore to those of you who remain, I say this: Come and drink fully of that which is sweet. Come and drink also of that which you perceive to be bitter and very hard to swallow. Ingest it fully, for it too shall become sweet when understanding comes."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved ones, receive of Me and"}],[{t:"italic",v:"Partake of My words; take your fill!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then go out and share it with all"}],[{t:"italic",v:"Those held captive in this world;"}],[{t:"italic",v:"Fill the cups of the thirsty..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And oh how blessed are those who receive,"}],[{t:"italic",v:"For they shall surely be delivered."}]]},{type:"para",segments:[{t:"text",v:"Yet concerning those who refuse to drink, those who hold up the hand and shoot out the lip, pour it out upon the ground in front of them. For again I say to you:"},{t:"italic",v:"Whoever receives My message receives Me, and I sanctify them. Yet whoever does not receive My message is against Me; and he who does not gather with Me scatters abroad..."},{t:"text",v:"They shall not escape! Yet take hope, beloved ones, for even among this most arrogant and high-minded generation, there is a remnant of whom I know. For in this also is the glory of God revealed. For that poured out as a testament against them does indeed contain wrath, yet from wrath shall also come forth repentance and deliverance among the remnant whom The Lord shall call."}]}],footnotes:{1:{type:"note",text:'Also read: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-cups-of-the-thirsty",videoVoiceUrl:"https://www.youtube.com/watch?v=iDpnedHwxZM&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:6,prevLetter:{id:"who-is-first",title:"Who Is First"},nextLetter:{id:"awaken-partake-of-the-living-bread",title:"Awaken... Partake of The Living Bread"}},{id:"awaken-partake-of-the-living-bread",title:"Awaken... Partake of The Living Bread",date:"4/6/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord YahuShua:"},{t:"text",v:"There are none here who have come into perfection, a finishing of that which I Myself have planted within you and watered..."}]},{type:"para",segments:[{t:"text",v:"Therefore, understand the Word of My mouth and that which is set before you, even upon each of your plates: I have bore you, even twice have you come forth; first by water and blood in the flesh, and a second time in the Spirit, yea even a third time when you shall come into glory. And behold, that which is first sown in your hearts is The Living Word. And that which grows from Me bears fruit, according to the food and drink I provide, the written Word. Therefore both are necessary, yet one must be first."}]},{type:"poetry",lines:[[{t:"italic",v:"Yet understand this:"}],[{t:"italic",v:"One who is awakened can not remain so,"}],[{t:"italic",v:"Unless they receive of Me and also"}],[{t:"italic",v:"Eat of that which I provide..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore abide in Me,"}],[{t:"italic",v:"And partake daily of My supper..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/awaken-partake-of-the-living-bread-3",videoVoiceUrl:"https://www.youtube.com/watch?v=n6HZ_4TFScE&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=6",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Being Born Again",url:"https://answersonlygodcangive.com/Regarding_Being_Born_Again"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:7,prevLetter:{id:"the-cups-of-the-thirsty",title:"The Cups of the Thirsty"},nextLetter:{id:"from-betrayal-to-victory",title:"From Betrayal to Victory"}},{id:"from-betrayal-to-victory",title:"From Betrayal to Victory",date:"6/2/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Timothy, this question of Judas has come up before Me once again. Therefore because you have humbled yourself before Me, sincerely seeking to know the truth of the matter, even if it meant your own correction, not at all doubting the Scriptures of Truth or My Word in the Volumes, I will answer you, and for the sake of those who seek to know Me as I truly am. So then let all those who have ears to hear, hear and gain wisdom."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"Before you in the Scriptures of Truth you see the man called Judas, who by receiving the bribe betrayed The Son of Man. Yet afterward, out of extreme remorse, he took the money (the price for which I had been weighed) and cast it down at the feet of the guilty. Therefore Judas could not buy a field with the money he did not have, nor did it enter his mind. Rather those of evil and hardened hearts bought the field to bury those who they saw as unworthy, whereby a sign was also given and fulfilled by Judas, written in his own blood; and so it remains to this day, the desolate Field of Blood. Therefore, again I say to you, stumble not over the letter, nor be confused by gossip; nor let perverse interpretations and biased translations lead you astray, by which the churches of men have marred My Word and My Glory before the people. Stop judging by human standards! Discern by right standards, according to My love and the knowledge you have received in Me; see with greater eyes! For I tell you the truth, Judas shall be with Me in paradise."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved ones, I forgive all who return to Me;"}],[{t:"italic",v:"Even the one in ninety-nine who goes astray,"}],[{t:"italic",v:"Even the one among twelve who betrays Me..."}]]},{type:"closing",text:"For I am The Lord..."},{type:"poetry",lines:[[{t:"italic",v:"And of all those The Father"}],[{t:"italic",v:"Has given Me, I shall not lose one."}]]},{type:"para",segments:[{t:"text",v:"And though Judas was indeed lost according to the flesh, he was not lost according to the spirit. For he repented in sincerity and in truth, confessing his sin with extreme remorse. And though he died before Me, his sins I bore also, crucifying them upon the tree."}]},{type:"para",segments:[{t:"text",v:"Therefore awake and give answer, all you who call of yourselves Christian: Who among you has not gone astray? Who among you has not betrayed Me? Who among you has not sinned? Who among you has not denied The Son of The Living God?! Therefore, again I say to you, all those who repent in My name, with sincere remorse in their hearts, are saved. For I am The One who makes it possible for them to do so."}]},{type:"poetry",lines:[[{t:"italic",v:"And though some have fallen asleep in death,"}],[{t:"italic",v:"And others are slain, even by their own hand,"}],[{t:"italic",v:"I ask you, shall death have the last word?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"BY NO MEANS! For I shall raise them up at the Last Day!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I have granted them the victory, even as I am The Victory,"}],[{t:"italic",v:"Being the Firstfruits from death..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even as those given Me shall likewise be first"}],[{t:"italic",v:"When the shout is made..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/from-betrayal-to-victory",videoVoiceUrl:"https://www.youtube.com/watch?v=kVN4y7uza1A&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Judas Iscariot",url:"https://answersonlygodcangive.com/Regarding_Judas_Iscariot"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Forgiveness",url:"https://answersonlygodcangive.com/Regarding_Forgiveness"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"}],num:8,prevLetter:{id:"awaken-partake-of-the-living-bread",title:"Awaken... Partake of The Living Bread"},nextLetter:{id:"hold-fast-and-do-not-waver",title:"Hold Fast and Do Not Waver"}},{id:"hold-fast-and-do-not-waver",title:"Hold Fast and Do Not Waver",date:"6/25/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"Beloved, prepare your hearts and do not abandon hope. Though much death draws near and the pain of death increases in every corner, though heavy sorrows overtake the land and tears fill your eyes, hold fast; embrace Me fully and do not waver. Beloved, receive My words and also do them, obey all My commands, for I am with you. For those who love Me obey My voice and walk in My ways. They recognize those I send and the Word given them. Yes, these are they who keep The Commandments of God and testify of My glory without ceasing, and their testimony is true. Thus at the appointed time I will surely gather them to Myself, some before and many more after, for I know My own. Beloved, I know when each will come to Me, I know every trial and tribulation. Therefore, again I say to you, call on My name in this time of darkness, in this time of great calamity and fear. Hold fast through all these tears, endure in these times of trouble."}]},{type:"poetry",lines:[[{t:"italic",v:"Fear not, for I have overcome the world;"}],[{t:"italic",v:"I hold the keys of death and Sheol,"}],[{t:"italic",v:"And The Book of Life is held"}],[{t:"italic",v:"Securely in My right hand..."}]]},{type:"poetry",lines:[[{t:"italic",v:"No one can steal you from My love;"}],[{t:"italic",v:"No one can pluck you from My hand;"}],[{t:"italic",v:"No one can break off what I have grafted in..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For that which I revealed to My servant is true:"}],[{t:"italic",v:"I know you as you are and as you will be,"}],[{t:"italic",v:"With Me where I am..."}]]},{type:"closing",text:"Says The Lord YahuShua."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/hold-fast-and-do-not-waver",videoVoiceUrl:"https://www.youtube.com/watch?v=KdXTzVr4Agc&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=8",videoMusicUrl:"https://www.youtube.com/watch?v=2JUP7XkXJJA&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=31",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Patience",url:"https://answersonlygodcangive.com/Regarding_Patience"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:9,prevLetter:{id:"from-betrayal-to-victory",title:"From Betrayal to Victory"},nextLetter:{id:"evil-blotted-out-righteousness-reigns",title:"Evil Blotted Out, Righteousness Reigns"}},{id:"evil-blotted-out-righteousness-reigns",title:"Evil Blotted Out, Righteousness Reigns",date:"7/20/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the false doctrine of hell and eternal torment)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"When My will is fulfilled to the last, and the wicked become ashes under the soles of your feet, indeed when all things are completed, satan shall be no more. Or do you also see with tainted eyes and blurred vision, as those within the churches of men? For the veil remains and is held fast atop their heads; behold, their lies do not cease! For the churches of men do always bear false witness of Me; they think I have altogether become like them! Thus I will rebuke them, and list all My charges against them. Therefore consider and pray. Seek My face with a fervent desire to know Me as I truly am, that you may worship Me in spirit and in truth."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear My words and gain wisdom, for thus says The Lord:"},{t:"text",v:"If in My Word, as it was written in the beginning by My chosen people, there was no trace of this doctrine of hell and eternal torment, as it is commonly spoken of amongst the churches of men, how has it now come to be in the New Covenant Scriptures? Again, I say to you, consider and pray, and seek My face by Him who alone is the image of The Invisible God. For only through The Son shall the true nature of The Father be revealed. Beloved ones, be wise and vigilant; do not be deceived. For as it is written:"},{t:"italic",v:"From the very beginning satan was a murderer and has never been on the side of truth, because there is no truth in him. When he tells a lie, he is only doing what is natural to him, because he is a liar and the father of all lies."},{t:"fn",v:"1"},{t:"text",v:"Thus from the beginning he sought to ensnare My people, saying,"},{t:"italic",v:"\u201CYou will not surely die.\u201D"},{t:"fn",v:"2"},{t:"text",v:"And still to this day, the lie is widely spoken of and accepted, even fiercely defended by the churches of men for the sake of pride. For they uphold the lie, teaching that whether one believes and accepts The Son, or whether one forbears and rejects The Life, all have eternal life in Heaven or in hell - BELIEVE THEM NOT! See with greater eyes, for I do not change! I do not grant eternal life to the wicked, in any form, nor shall the evil of heart see everlasting life. Their existence shall be taken from them, they shall surely be blotted out. Again, I say to you, those under condemnation are dead. In no way are they part of the living, nor are they living in torment; they know nothing at all. For the churches of men are foolish, and their leaders teach doctrines of devils. Therefore come out from among them, and be separate from all these corrupt doctrines and perverse traditions. For as it is written:"},{t:"italic",v:"Do not be conformed to this world, but be transformed by the renewing of your mind in The Beloved, that you may prove what is good and acceptable before God, according to His will, which is perfect."},{t:"fn",v:"3"},{t:"text",v:"I AM THE LORD."}]}],footnotes:{1:{type:"scripture",ref:"John 8:44"},2:{type:"scripture",ref:"Genesis 3:4"},3:{type:"scripture",ref:"Romans 12:2"}},nkjv:{"John 8:44":"You are of your father the devil, and the desires of your father you want to do. He was a murderer from the beginning, and does not stand in the truth, because there is no truth in him. When he speaks a lie, he speaks from his own resources, for he is a liar and the father of it.","Genesis 3:4":"Then the serpent said to the woman, \u201CYou will not surely die.","Romans 12:2":"And do not be conformed to this world, but be transformed by the renewing of your mind, that you may prove what is that good and acceptable and perfect will of God."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/evil-blotted-out-righteousness-reigns",videoVoiceUrl:"https://www.youtube.com/watch?v=oI5kOjrZ6qo&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=9",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"}],num:10,prevLetter:{id:"hold-fast-and-do-not-waver",title:"Hold Fast and Do Not Waver"},nextLetter:{id:"i-search-the-hearts-and-minds",title:"I Search the Hearts and Minds"}},{id:"i-search-the-hearts-and-minds",title:"I Search the Hearts and Minds",date:"7/27/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Sister in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a sister in Christ: Lord, are You coming only for those who are looking for You?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord YahuShua:"},{t:"text",v:"Your question is answered in this: I know My own. Thus I am coming for those who are Mine, all those in whom I see of Myself and for the little ones who remain in their innocence, for all who remain blameless. For those who have received of Me look always to The Blessed Hope, their hearts filled with joyful expectation. For they have been awakened to the Truth, and long to know Me as I truly am. Yet there are many who say they love Me, yet do not walk in My ways. For they do always resist the Truth, persecuting and slandering all those I send."},{t:"italic",v:"Thus these shall suffer great loss, yet they too shall be delivered - yet so as through fire, as it is written."},{t:"fn",v:"1"},{t:"text",v:"For those who hold fast to the veil refuse to discern, nor will they receive correction. They have altogether gone astray and remain at ease in their slumber. Indeed their own arrogance has deceived them, and on account of their pride they are held captive, bound with cords of man-made doctrine, ensnared by filthy tradition, walking always in the commandments of men. Thus they must be left to refinement, a great humbling in the Day of The Lord. Yet even amongst the churches of men there is a hidden treasure, a select few who shall escape, a humble penitent people whose hearts speak true, in spite of their error."}]},{type:"closing",text:"For I am The Lord..."},{type:"poetry",lines:[[{t:"italic",v:"I alone search the hearts and minds..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And whether they be of the first"}],[{t:"italic",v:"Or of the second, I know My own."}]]}],footnotes:{1:{type:"scripture",ref:"1 Corinthians 3:15"}},nkjv:{"1 Corinthians 3:15":"If anyone\u2019s work is burned, he will suffer loss; but he himself will be saved, yet so as through fire."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-search-the-hearts-and-minds",videoVoiceUrl:"https://www.youtube.com/watch?v=DnGlA0jt48E&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding The Ascension and The Blessed Hope",url:"https://answersonlygodcangive.com/Regarding_The_Ascension_and_The_Blessed_Hope"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:11,prevLetter:{id:"evil-blotted-out-righteousness-reigns",title:"Evil Blotted Out, Righteousness Reigns"},nextLetter:{id:"feed-my-sheep",title:"Feed My Sheep"}},{id:"feed-my-sheep",title:"Feed My Sheep",date:"7/30/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a brother in Christ: Lord, how is he to satisfy the scrutiny of a scoffer, who says that the Letters contradict Scripture, saying, \u201CMy children\u201D in the Letter \u201C Transgression \u201D to those that altogether forsake The Lord YahuShua, before they have repented to become \u201Cchildren of God\u201D?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My son, answer not the obstinate, nor strive with those who reject My Word out of hand, nor give answer to those who seek to tear down My words. For by doing so you have agreed that their point is valid, though you argue. Is My Word in need of human power or wisdom to uphold it? That which proceeds from My mouth at present is foremost, and shall not be put second to My Word spoken aforetime. Neither is one a foundation for the other, as though the Word proceeding from My own mouth is in need of anything to uphold it; nor is any other witness required to prove My Word as My own, when I Myself have spoken it. What I speak, I speak by Myself; and that which I have sworn in My wrath, I swear by Myself - IT STANDS! And you, O most arrogant and deceitful generation, shall live by it! Says The Lord. And if you forbear and reject My words, and refuse to heed My correction, you shall come to know the power of The Lord in the Day of Wrath, for you shall surely be left in the midst of it. Behold, I shall stretch out My hand in My anger, and the whole world shall fall under the shadow of My judgment. Then you will know, I AM THE LORD, and it was indeed I who had spoken it!"}]},{type:"para",segments:[{t:"text",v:"Therefore, My son, I shall answer you simply, to keep your foot from stumbling. (Yet of the scoffers, let them stumble until the time be changed.) Who among all these created ones, whether on the earth or under the earth or those in Heaven, who of these are not My children? And who among these, at present, is blotted out? And who among men has done right? Answer if you know. There is none righteous in all the earth, no, not one. For I tell you a mystery: If all being alive in the flesh are dead, then how is it you remain alive? (I speak not of salvation in The Messiah, but of those with breath.) For all remain in The Father, all are attached to The Vine, unless they are broken off and cast into the fire."}]},{type:"poetry",lines:[[{t:"italic",v:"So then ALL people are My children..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet among My children, only those who fully embrace"}],[{t:"italic",v:"The Son of Salvation and obey His voice"}],[{t:"italic",v:"Are given the right to be called children of God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Receiving their inheritance according"}],[{t:"italic",v:"To the seed of which they have become"}],[{t:"italic",v:"And now are, grafted into My olive tree."}]]},{type:"para",segments:[{t:"text",v:"Therefore, again I tell you, the time has come and the day is near, when the harvest shall be gathered together, the bundles tied and set in their places. And all who reject The Life will no more be My children, they shall cease. They shall be broken off and thrown into the fire, and like dry branches they will be burned up, utterly consumed. And of those who remain in The Vine and bear fruit, these shall receive life anew, even life everlasting."}]},{type:"para",segments:[{t:"text",v:"So then, My son, you have searched the Scriptures and have seen, yet only dimly. And of the scoffers, they remain blind, not at all willing to go and wash their faces, that their eyes might be opened. Nor do they seek Me in truth according to the Spirit, which can only be received in Messiah; He is not in them. Thus the mud remains, the scales have yet to fall from their eyes."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore stay separate from those"}],[{t:"italic",v:"Who shoot out the lip, from all who reject"}],[{t:"italic",v:"This Word and slander My messengers..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Rather feed those who come"}],[{t:"italic",v:"Seeking bread in sincerity and in truth,"}],[{t:"italic",v:"Those who seek to know Me as I truly am,"}],[{t:"italic",v:"Those who carry Messiah within them..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Feed MY sheep, says The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/feed-my-sheep",videoVoiceUrl:"https://www.youtube.com/watch?v=g5q0DyMZyuU&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=11",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"}],num:12,prevLetter:{id:"i-search-the-hearts-and-minds",title:"I Search the Hearts and Minds"},nextLetter:{id:"wholly-of-the-lord",title:"Wholly of The Lord"}},{id:"wholly-of-the-lord",title:"Wholly of The Lord",date:"10/28/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy During Men\u2019s Fellowship",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"My sons, who you are at home reveals the person you remain. Therefore, do not be as the hypocrite who has two faces. For I see all your doings, I know your hearts. Thus the servant I call must be wholly of The Lord, at all times and in every season - one who serves Me in open and in secret, one who keeps The Lord close to his heart and present in all his thoughts, seeking always to please Me. Whether he is seen by men or hidden from their eyes, whether he is at home or in a public place, whether he is trumpeting My Word openly in the streets or has entered into his closet in quiet supplication, I tell you the truth, I have seen it. For I know all his comings and goings, and his thoughts are not at all hidden from Me."}]},{type:"poetry",lines:[[{t:"italic",v:"Again, I tell you, who you are at home is who you are..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For by a man\u2019s actions is his heart revealed,"}],[{t:"italic",v:"And by his mouth is he defined before others..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore honor Me first at home,"}],[{t:"italic",v:"Among your beloved, as I have taught you;"}],[{t:"italic",v:"Then go out and testify..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My every word is Scripture,"}],[{t:"italic",v:"My every Letter truth."}]]},{type:"para",segments:[{t:"text",v:"My sons, speak My name aloud and reveal My glory to the world. Share My words with your kindred, and trumpet My strong rebuke against your nation, sounding the alarm among your countrymen; be bold in word and by deed. Yet again I tell you, do not be as the hypocrite, who honors Me with his lips though his heart remains far from Me. For his actions testify against him, and that which he does in secret reveals the corrupt fruit of the same. Therefore let My servants be given fully to their task, let them serve Me without distraction. Let each man first order his steps before Me in righteousness, setting his own house in order, then shall he be meet for The Master\u2019s use, prepared for every good work. And if My servant does indeed strive to keep his way straight, endeavoring also to set his household in order, taking a stand, he shall surely receive his reward. Yet if his spouse refuses to give heed and attempts to bar his way, let her depart, and let My servant proceed with his task; let him go forth in the name of The Lord. For all who seek to bar My way before Me shall be left desolate, and all who fight against Me and slander My messengers shall suffer many tears, even to the rebellious children. (Yet not the young ones, for they are Mine.) I AM THE LORD."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/wholly-of-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=mkHbngRzd7g&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=12",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:13,prevLetter:{id:"feed-my-sheep",title:"Feed My Sheep"},nextLetter:{id:"the-innocent-are-mine",title:"The Innocent Are Mine"}},{id:"the-innocent-are-mine",title:"The Innocent Are Mine",date:"11/19/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding a video which showed children being \u201Cslain in the spirit\u201D at a church assembly)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"How long must I speak to that which is obvious, little flock? Must My servant be drawn away continually to feed you, as though you were yet babes? How is it you still question, though within your heart the truth of the matter is made known by the Spirit, which cries,"},{t:"italic",v:"\u201CFalse!\u201D?"},{t:"text",v:"When will you open your eyes and see? When will you lay yourselves down and hear? When will you empty yourselves, that you may truly discern?"}]},{type:"para",segments:[{t:"text",v:"Therefore because your eyes are slow in seeing and your ears dull of hearing, your mind congested with the many deceits of this world, this is what The Lord your God says: WOE TO THOSE WHO LEAD MY LAMBS ASTRAY! WOE, I SAY TO THEM! Woe to all who feed lies to the little ones and cause them to sin! For as it is written:"},{t:"italic",v:"It would be better for them if a millstone were hung around their neck, and they were drowned in the depths of the sea, than to suffer My wrath over these little ones!"},{t:"fn",v:"1"},{t:"text",v:"Therefore woe to those who uphold perverse and bitter doctrine; your discipline shall be most severe! Woe to those who pollute My name, in word and by deed; for you have brought shame upon your own heads, and disgrace to all your houses which you call by My name! Woe to all who take advantage of the ignorant and pollute the minds of the innocent! WOE TO ALL WHO HARM MY LITTLE ONES! For I shall stretch out My hand against you; indeed, a double portion of wrath is reserved for you! Behold, I shall stretch out My hand and bring harm upon the wicked, and strike those who slaughter the innocent, until I have destroyed them in all the earth! For My wrath remains upon all who have taken part, upon all who voice their agreement! And yes double, even double again, upon all who murder My precious gifts! Declares The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, beloved, turn away from the churches of men"}],[{t:"italic",v:"And take a stand against the wickedness of this world,"}],[{t:"italic",v:"And no more give any credence to that"}],[{t:"italic",v:"Which you behold on the screen..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Rather fall down and pray, wail and bring forth"}],[{t:"italic",v:"Many tears, on behalf of those perishing..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet of the little ones you need not pray, nor make intercession;"}],[{t:"italic",v:"For they are Mine, and I shall surely hide them away..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 18:6-7"}},nkjv:{"Matthew 18:6-7":"6. \u201CWhoever causes one of these little ones who believe in Me to sin, it would be better for him if a millstone were hung around his neck, and he were drowned in the depth of the sea. 7. Woe to the world because of offenses! For offenses must come, but woe to that man by whom the offense comes!"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-innocent-are-mine",videoVoiceUrl:"https://www.youtube.com/watch?v=oVetX4O62tw&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding The Holy Spirit",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding Children\u2019s Inheritance on Earth and in Heaven",url:"https://answersonlygodcangive.com/Regarding_Children%E2%80%99s_Inheritance_on_Earth_and_in_Heaven"}],num:14,prevLetter:{id:"wholly-of-the-lord",title:"Wholly of The Lord"},nextLetter:{id:"come-to-me-no-more-time-to-tarry",title:"Come to Me; No More Time to Tarry"}},{id:"come-to-me-no-more-time-to-tarry",title:"Come to Me; No More Time to Tarry",date:"12/17/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy During an Online Fellowship",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved, how long shall you tarry? How long shall you remain unmoved? How long shall you fail to raise your voices? What is it you wait for? Have I not drawn you to the sound of this Trumpet? Have not I, even I, pierced your hardened hearts with these words? Have I not blessed you with a multitude of words in your hearing? Behold, I have placed My Word in front of you; indeed every Letter is within your reach. Beloved, take your fill! Stop listening to the adversary! Stop judging My Word! For one who is a judge has ceased from being a hearer, and has also cut themselves off from being a doer, leaving them desolate. Beloved, each minute you withhold does your faith weaken, each second you hesitate does your trust break. Therefore come to Me quickly, and sup with Me at My table. And when you have taken your fill, stand up and blow the Trumpet; go and tell your neighbors. And when they refuse to hear, go into the streets and tell the stranger. And when they turn away, go and seek out the homeless, the fatherless and the widow. Beloved, share My Word! Tell them of My sacrifice, and of The Glory which is and was and shall soon return, and is also coming quickly in power and great glory. Place My Letters in the hands of all who are willing to receive them, doing so in My name. And to the rest, let it be to them as a trumpet of alarm and war, a declaration of judgment, a stern warning, a strong rebuke. Beloved, I have spoken, and behold I am speaking again. For I am The Lord, and I do not change. Therefore no longer be confused on account of your flesh, nor let your minds deceive you. For you have One Master; I AM HE. Come to Me in sincerity and in truth, humble yourselves and cast off all this worldly knowledge, that you may see Me as I truly am. For I tell you plainly, Timothy is My prophet, yet you must look past him. Look past him, beloved, and tell Me what you see? Tell Me, who is there?"}]},{type:"para",segments:[{t:"italic",v:"[Fellowship Participants]"},{t:"text",v:"YahuShua! You, Lord."}]},{type:"para",segments:[{t:"italic",v:"[YahuShua]"},{t:"text",v:"You have answered well. And if I am there, and you have recognized both Me and My Word, then where must I be also? For the one who I have given to hear My voice shall indeed prophesy. And those who have eyes to see will recognize My words, and those who have ears to hear shall surely receive them. Yet only those who truly love Me will obey My voice and walk in that which is given. Yet for one to know Me as I truly am, they must receive of My spirit and embrace Me fully, whereby they shall see with new eyes and restored vision. Therefore I ask you once again, do you really love Me?"}]},{type:"para",segments:[{t:"italic",v:"[Fellowship Participants]"},{t:"text",v:"Yes, Lord."}]},{type:"para",segments:[{t:"italic",v:"[YahuShua]"},{t:"text",v:"Then make Me your treasure! For you are Mine already, even as I had set you apart for My glory from the beginning. Therefore, again I ask you, do you really know Me? For I have always known you; even from the beginning you were Mine. And if you have always been Mine, then come to Me as you are, and withhold not; embrace Me fully, that I may reign in your hearts. Ask no more in doubt, nor seek Me in passing; ask as one dying of thirst, as one who is starving in this world, as one with few breaths left, suffocating in this world of sin. Ask, and be broken atop this Stone - It is time!"}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/come-to-me-no-more-time-to-tarry",videoVoiceUrl:"https://www.youtube.com/watch?v=6oZUP5zfNuk&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=14",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:'The Coming of The Lord - "I AM COME"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_AM_COME"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Doubt",url:"https://answersonlygodcangive.com/Regarding_Doubt"}],num:15,prevLetter:{id:"the-innocent-are-mine",title:"The Innocent Are Mine"},nextLetter:{id:"i-did-not-come-to-bring-peace-but-a-sword",title:"I Did Not Come to Bring Peace, But a Sword"}},{id:"i-did-not-come-to-bring-peace-but-a-sword",title:"I Did Not Come to Bring Peace, But a Sword",date:"12/17/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy During an Online Fellowship",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked: What does it mean when The Lord says to stop judging His Word?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved, the time of testing this Word has passed, yet you test Me still. How is it you have yet to discern? For I have indeed opened My mouth to speak, and through My prophet I have spoken to this generation, for I shall surely set all these crooked paths straight. And behold, My every word convicts, bringing all who hear My words into subjection, for My every word is law. Thus it has also become your judge, testing the quality of your works, revealing the strength of your trust and that upon which you have built your faith. Yet you sit still, pushing out the hand when My words oppose your will, holding fast when My commands shake up the status quo to which you have grown accustomed. I have already told you, that only those who fully embrace Me and obey My voice are given the right to be called children of God. And only those who receive the love of the Truth are set free. Yet you judge My Word and seek always to find fault with My prophet, that you might somehow be loosed from these bonds, as though the Way of The Lord was akin to shackles and chains. Beloved ones, whoever commits sin is a slave of sin. And a slave does not abide in the house forever, but only the children abide forever."},{t:"italic",v:"Therefore if The Son sets you free, you are free indeed, as it is written."},{t:"fn",v:"1"},{t:"text",v:"It is written also:"},{t:"italic",v:"Do not speak evil of one another. For whoever speaks evil of a brother, or judges a brother, speaks evil of The Law and judges The Law. But if you judge The Law, you are not a doer of what The Law says, but a judge."},{t:"fn",v:"2"},{t:"text",v:"Thus in the same way, one who speaks evil of My messenger and judges My prophet speaks evil of Me and judges the Word. And one who judges the Word will by no means obey it, but have set themselves up as an authority, a judge, held captive by their own evil thoughts. Again, one who refuses My messenger can by no means receive My message, and one who judges him has blinded themselves to the Truth. For there is none righteous, no, not one. Yet The One who sent the message is true. Thus the one who delivers My Word must also be its recipient, or how shall I send him? And all those who judge can do nothing and shall receive nothing; even that which they have shall be taken away. Therefore what I have written stays written, and what I have spoken stands."}]},{type:"poetry",lines:[[{t:"italic",v:"For the time of choosing has come, all shall be sifted;"}],[{t:"italic",v:"Even by this Word shall it be accomplished, a great division!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written:"}],[{t:"italic",v:"I did not come to bring peace, but a sword"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 8:36"},2:{type:"scripture",ref:"James 4:11"},3:{type:"scripture",ref:"Matthew 10:34"}},nkjv:{"John 8:36":"Therefore if the Son makes you free, you shall be free indeed.","James 4:11":"Do not speak evil of one another, brethren. He who speaks evil of a brother and judges his brother, speaks evil of the law and judges the law. But if you judge the law, you are not a doer of the law but a judge.","Matthew 10:34":"\u201CDo not think that I came to bring peace on earth. I did not come to bring peace but a sword."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-did-not-come-to-bring-peace-but-a-sword",videoVoiceUrl:"https://www.youtube.com/watch?v=6MAKfupxIPg&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=15",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Setting All These Crooked Paths Straight",url:"https://answersonlygodcangive.com/Main_Page#Setting_All_These_Crooked_Paths_Straight"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],num:16,prevLetter:{id:"come-to-me-no-more-time-to-tarry",title:"Come to Me; No More Time to Tarry"},nextLetter:{id:"discernment",title:"Discernment"}},{id:"discernment",title:"Discernment",date:"1/5/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"",forLine:"For Someone Who Claims the Apostle Paul Was False",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Holy One of Israel:"},{t:"text",v:"Have I not spoken to the discernment of spirits and prophets already, saying,"},{t:"italic",v:"\u201CYou will know them by their fruits\u201D?"},{t:"text",v:"Is it not written:"},{t:"italic",v:"Blessed is he who comes in the name of The Lord"},{t:"fn",v:"1"},{t:"italic",v:", and how beautiful are the feet of those who preach the Gospel of Peace, who bring glad tidings of good things?"},{t:"fn",v:"2"},{t:"text",v:"Yet you have failed to see. For the scales removed from the eyes of My servant Sha\u2019ul (also known as Paul) remain upon you. How is it you do not recognize My servants? How is it you have failed to see past the doctrines of men within the churches? For they do always twist the Scriptures, misusing and abusing My Word to uphold their own way, forsaking The Holy Law by permission in MY name. Thus you also lack understanding. For the shadow of the veil which covers them has fallen upon you. For those who know Me know those I send. And those in whom I dwell receive My words with gladness, whether spoken into the ears of My prophets or placed within the hearts of My apostles. Thus I shall speak plainly, that you may know the folly of your speech: Sha\u2019ul, My apostle and prophet, whom I appointed and sent, kept The Commandments of God and ceased not from proclaiming My name in truth. Even unto death, he did not cease from testifying to the truth of who I am. For it is written:"},{t:"italic",v:"The people of God are those who keep The Commandments and have the Testimony of YahuShua The Messiah."},{t:"fn",v:"3"},{t:"text",v:"And their testimony is true. Therefore, again I say to you, let not the churches of men deceive you, nor let any self-appointed teacher, pastor, preacher, minister or priest lead you astray. For they do greatly err."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord, to all who have eyes to see and ears to hear:"},{t:"text",v:"Who among you has committed no murder, whether in heart or in action? Who among you has committed no adultery, whether in heart or in action? Who among you, O peoples of the earth, has committed no sin?! Behold, all have fallen short of the Glory of God, all have failed utterly in their attempts to gain righteousness; even the works of the most righteous among you are but filthy rags before Me. And for this reason did I come into the world, manifest in the flesh, to bear the full weight of the sin of this world - Immanu El."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore get wisdom, get understanding,"}],[{t:"italic",v:"And seek My face in sincerity and in truth..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Humble yourselves, that you may receive true knowledge,"}],[{t:"italic",v:"That you may come to know Me as I truly am..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Psalms 118:26, Matthew 23:39"},2:{type:"scripture",ref:"Isaiah 52:7, Romans 10:15"},3:{type:"scripture",ref:"Revelation 14:12"}},nkjv:{"Psalms 118:26, Matthew 23:39":"Psalms 118:26 \u2014 Blessed is he who comes in the name of the LORD! We have blessed you from the house of the LORD. | Matthew 23:39 \u2014 for I say to you, you shall see Me no more till you say, \u2018Blessed is He who comes in the name of the LORD!\u2019 \u201D","Isaiah 52:7, Romans 10:15":"Isaiah 52:7 \u2014 How beautiful upon the mountains Are the feet of him who brings good news, Who proclaims peace, Who brings glad tidings of good things, Who proclaims salvation, Who says to Zion, \u201CYour God reigns!\u201D | Romans 10:15 \u2014 And how shall they preach unless they are sent? As it is written: \u201CHow beautiful are the feet of those who preach the gospel of peace, Who bring glad tidings of good things!\u201D","Revelation 14:12":"Here is the patience of the saints; here are those who keep the commandments of God and the faith of Jesus."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/discernment",videoVoiceUrl:"https://www.youtube.com/watch?v=9zp-ONYIO4I&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=16",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Apostle Paul",url:"https://answersonlygodcangive.com/Regarding_the_Apostle_Paul"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:'The Name of The Lord - "Immanu El"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#Immanu_El"}],num:17,prevLetter:{id:"i-did-not-come-to-bring-peace-but-a-sword",title:"I Did Not Come to Bring Peace, But a Sword"},nextLetter:{id:"choose-me",title:"Choose Me"}},{id:"choose-me",title:"Choose Me",date:"1/7/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved ones, I am The Answer you search for, The Truth you seek - The Only Way, The Only Truth, The Only Life. Apart from Me there is nothing of any value; apart from Me there is no life. Therefore who you choose, not what you choose, is the answer. For who you choose defines what you do. And whosoever chooses another, and not Me in truth, has chosen themselves, and has done according to their own will."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus those who embrace My words"}],[{t:"italic",v:"Have taken the first steps in the"}],[{t:"italic",v:"Knowledge of how to truly abide in Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, those who have written"}],[{t:"italic",v:"This wisdom upon their heart"}],[{t:"italic",v:"Have already crossed the threshold..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/choose-me-2",videoVoiceUrl:"https://www.youtube.com/watch?v=Jwow16_TftQ&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=17",videoMusicUrl:"https://www.youtube.com/watch?v=l_8Uw_I2K_s&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=28",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"}],num:18,prevLetter:{id:"discernment",title:"Discernment"},nextLetter:{id:"obey-god",title:"Obey God"}},{id:"obey-god",title:"Obey God",date:"2/4/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, by putting You first, and refusing to take part in the modern holidays of men, are we dishonoring our parents and family who say we should take part?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord YahuShua:"},{t:"text",v:"Beloved, a sincere desire to be free from the iniquity of this world is good and well-pleasing to The Lord. For one who truly loves Me seeks to please Me. And those in whom I dwell will run from these holidays of men, which I hate, despising them. Yet one who remains in disagreement with My Word in the Volumes can in no wise be gathered, for they have denied Me. And any who reject My Word, in favor of the doctrines and traditions of men, embrace that which runs contrary to Me. For I tell you the truth, anyone who refuses, disagrees with, or speaks against My Letters or My prophet has rejected Me in favor of their own way. Pride has ensnared them, and arrogance has become their close friend. Behold, they have embraced the world and its evil ways, and seek not the approval of their Father in Heaven, but of men. And all who seek the approval of men must walk through the valley with them; and all who remain friends of the world have made themselves enemies of God, as it is written."},{t:"fn",v:"1"},{t:"text",v:"Therefore all lovers of the world shall surely be left in it; they shall not escape! For assuredly, I say to you, this world shall be shaken and the glory of men shall be broken down! And in like manner shall all those left in the world be humbled, severely abased - many broken and uplifted, and many more broken and condemned, says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore concerning these holidays"}],[{t:"italic",v:"Of men, which I hate..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Let all those who have received"}],[{t:"italic",v:"The love of the Truth depart from them;"}],[{t:"italic",v:"Let the division be made clear"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And let those who say they know Me,"}],[{t:"italic",v:"Yet make no effort to pick up their"}],[{t:"italic",v:"Cross and follow Me,"},{t:"fn",v:"3"},{t:"italic",v:"bear the weight"}],[{t:"italic",v:"Of their burden in the Day of The Lord."}]]},{type:"para",segments:[{t:"text",v:"Therefore, concerning the question of breaking one Commandment in favor of another, the answer is this: I AM FIRST, of which The Commandments also testify. For those who truly love Me seek to obey My voice, and those who obey My voice have also fulfilled The Moral Law. For I am, and have always been the goal at which the Torah aims."},{t:"fn",v:"4"},{t:"text",v:"And all those in whose heart I am foremost serve Me without constraint, seeking always to place Me first, above all else. For these walk in My ways, doing those same things I did. They do not add to the Word which I have commanded them, nor do they take away from it. Behold, they keep The Commandments of God, as He commanded them and as they are written, and not as the churches of men would have them be."},{t:"fn",v:"5"},{t:"text",v:"Thus those who say no to sin, and stay separate from that which is an abomination in the eyes of God,"},{t:"fn",v:"6"},{t:"text",v:"have broken no Commandment. So then to honor any parent who transgresses The Law, by taking part in these perverse holidays of men, is to transgress The Law. Yet by honoring Me in truth, obeying the Word of The Lord, one can by no means transgress The Law. Therefore those who ask,"},{t:"italic",v:"\u201CWould you break one Commandment to obey another?\u201D"},{t:"text",v:"speak without knowledge, having also failed to recognize the lie hidden within. For those who ask such questions have given heed to the subtle deceptions of the evil one, by which they are also led, seeing contradictions where none exist."}]},{type:"poetry",lines:[[{t:"italic",v:"Again I say to you, who you"}],[{t:"italic",v:"Choose defines what you do..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And whosoever chooses another"}],[{t:"italic",v:"And not Me in truth has chosen themselves,"}],[{t:"italic",v:"And has done according to their own will"},{t:"fn",v:"7"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet to disobey God is sin..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore call on My name and make"}],[{t:"italic",v:"Your repentance full,"},{t:"fn",v:"8"},{t:"italic",v:"by departing"}],[{t:"italic",v:"From those things which are not lawful,"}],[{t:"italic",v:"Standing apart from those things I hate,"}],[{t:"italic",v:"And you shall surely be delivered..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"italic",v:"2/4/10"},{t:"bold-italic",v:"From YahuShua HaMashiach, Our Lord and Savior"},{t:"italic",v:"The Word of The Lord Spoken to Timothy For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My sons and daughters, you have yet to understand My Word and My will, concerning these things which I hate. When a parent says to their child,"},{t:"italic",v:"\u201CObey me,\u201D"},{t:"text",v:"yet their request leads their child into sin, the child who has received knowledge of My ways must choose to walk in them. For by refusing to obey their parents in that which causes them to sin, they have not dishonored their parents, but have obeyed the Word of The Lord, doing that which is right and good in My eyes, revealing that which is most needful. Beloved, this is where you have erred. For you still listen to the whisperings of the evil one; listen not to his subtle and dark speeches!"}]},{type:"para",segments:[{t:"italic",v:"[Timothy]"},{t:"text",v:"Brothers and sisters, satan would have us believe that even while we are obeying God it is still possible to sin, and that placing God\u2019s will over our parent\u2019s will will cause us to break the Fifth Commandment! Do not be ensnared! Obey God!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved, awake! For I tell you the truth, you have yet to come into the full knowledge of who I truly am; nor do you understand My ways, neither are you willing to walk in them. Learn to see with new eyes and restored vision, and no longer be constrained by doubt, nor let fear hold you captive. For knowledge of Me is understanding,"},{t:"fn",v:"9"},{t:"text",v:"and My spirit brings forth new awareness in those who have truly received,"},{t:"fn",v:"10"},{t:"text",v:"whereby satan\u2019s power is easily broken. Be fully awake, therefore, and no longer give heed to the corrupt teachings of men or the churches."},{t:"fn",v:"11"},{t:"text",v:"Beloved, by disobeying a parent in regards to these modern holidays of men, you have testified to them by your refusal. And by your actions you have shown them a better way, magnifying that which is first. Thus in righteousness you have blessed them by your example. Where then is the dishonor? Again, I say to you, one who chooses Me and performs My will does not sin. Therefore, obey your parents and honor them in all things, save that which causes you to disobey the Word of God; honor NO request from one who chooses sin, asking you to be a partaker with them. For all who know and understand the origins of these holidays of men, and do not take a stand against them, have shown themselves to be in agreement with those who sin against Me. And all those who compromise or make concessions dishonor Me and have no love for God in their hearts."},{t:"fn",v:"12"}]},{type:"poetry",lines:[[{t:"italic",v:"Be My examples, therefore..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come out from among them and be separate;"}],[{t:"italic",v:"Do not touch what is unclean and I will"}],[{t:"italic",v:"Receive you, as it is written"},{t:"fn",v:"13"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Obey My voice and walk in My ways,"}],[{t:"italic",v:"Revealing to every onlooker that I am indeed first..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The greatest of all loves."}]]}],footnotes:{1:{type:"scripture",ref:"James 4:4"},2:{type:"scripture",ref:"Matthew 10:34-36"},3:{type:"scripture",ref:"Matthew 16:24"},4:{type:"scripture",ref:"Romans 10:4 (CJB)"},5:{type:"scripture",ref:"Deuteronomy 4:2"},6:{type:"scripture",ref:"2 Corinthians 6:17"},7:{type:"note",text:'See: "Choose Me"',url:"https://www.thevolumesoftruth.com/Choose_Me#:~:text=who%20you%20choose%2C%20not%20what%20you%20choose%2C%20is%20the%20answer.%20For%20who%20you%20choose%20defines%20what%20you%20do.%20And%20whosoever%20chooses%20another%2C%20and%20not%20Me%20in%20truth%2C%20has%20chosen%20themselves%2C%20and%20has%20done%20according%20to%20their%20own%20will.",link:{collection:"Volume Four",letterTitle:"Choose Me",excerpt:"who you choose, not what you choose, is the answer. For who you choose defines what you do. And whosoever chooses another, and not Me in truth, has chosen themselves, and has done according to their own will."}},8:{type:"note",text:'See: "Regarding True Repentance"',url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},9:{type:"scripture",ref:"Proverbs 9:10"},10:{type:"scripture",ref:"John 14:26 (CEB)"},11:{type:"scripture",ref:"Acts 5:29, Matthew 15:9"},12:{type:"scripture",ref:"John 5:42-44"},13:{type:"scripture",ref:"2 Corinthians 6:17"}},nkjv:{"James 4:4":"Adulterers and adulteresses! Do you not know that friendship with the world is enmity with God? Whoever therefore wants to be a friend of the world makes himself an enemy of God.","Matthew 10:34-36":"34. \u201CDo not think that I came to bring peace on earth. I did not come to bring peace but a sword. 35. For I have come to \u2018set a man against his father, a daughter against her mother, and a daughter-in-law against her mother-in-law\u2019; 36. and \u2018a man\u2019s enemies will be those of his own household.\u2019","Matthew 16:24":"Then Jesus said to His disciples, \u201CIf anyone desires to come after Me, let him deny himself, and take up his cross, and follow Me.","Romans 10:4 (CJB)":"For the goal at which the Torah aims is the Messiah, who offers righteousness to everyone who trusts.","Deuteronomy 4:2":"You shall not add to the word which I command you, nor take from it, that you may keep the commandments of the LORD your God which I command you.","2 Corinthians 6:17":"Therefore \u201CCome out from among them And be separate, says the Lord. Do not touch what is unclean, And I will receive you.\u201D","Proverbs 9:10":"\u201CThe fear of the LORD is the beginning of wisdom, And the knowledge of the Holy One is understanding.","Acts 5:29, Matthew 15:9":"Acts 5:29 \u2014 But Peter and the other apostles answered and said: \u201CWe ought to obey God rather than men. | Matthew 15:9 \u2014 And in vain they worship Me, Teaching as doctrines the commandments of men.\u2019 \u201D","John 5:42-44":"42. But I know you, that you do not have the love of God in you. 43. I have come in My Father\u2019s name, and you do not receive Me; if another comes in his own name, him you will receive. 44. How can you believe, who receive honor from one another, and do not seek the honor that comes from the only God?","John 14:26 (CEB)":"The Companion, the Holy Spirit, whom the Father will send in my name, will teach you everything and will remind you of everything I told you."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/obey-god-4",videoVoiceUrl:"https://www.youtube.com/watch?v=HrgXb9YSwHI&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=18",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Doubt",url:"https://answersonlygodcangive.com/Regarding_Doubt"},{label:"Man's Holidays vs. God's Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"}],num:19,prevLetter:{id:"choose-me",title:"Choose Me"},nextLetter:{id:"walking-in-the-footsteps-of-the-messiah-s-passion",title:"Walking in the Footsteps of The Messiah\u2019s Passion"}},{id:"walking-in-the-footsteps-of-the-messiah-s-passion",title:"Walking in the Footsteps of The Messiah\u2019s Passion",date:"2/10/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding the Feasts of The Lord)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to those who believe, to those who have ears to hear, eyes to see, and a heart which longs to know Me as I truly am:"},{t:"text",v:"Three are fulfilled, one is, and three are to come, coming quickly. Of the three fulfilled, you shall remember and honor them according to how I command you. The dates and times, the new moons and seasons, are not the focus; rather, YahuShua is the focus. For the significance of these Holy Days is found in their meaning and revealed by their order, even as all find their fulfillment in The Messiah and their completion in the coming of The Lord. Thus you shall not keep My Holy Days as the world, nor as those held captive in the churches of men, nor shall you follow the futile traditions of the Jews. For those who deny The Son deny The Father also; their worship is in vain. For the Jews reject The Son of Salvation, and the churches of men pollute His name and corrupt His image without ceasing. For they do always follow the dictates of their own hearts, and in their stubbornness they hold fast to religion, embracing the commandments of men, walking in every perverse doctrine and tradition thereof, which I hate! Therefore you shall set yourselves apart from them, and do all I command you: You shall honor the Passover a week before the time, beginning Tuesday at sundown. You shall walk in the footsteps of Messiah, and remember, blessing His name and giving thanks according to each day He fulfilled in His Passion. Four holy convocations, plus one, shall be kept."}]},{type:"poetry",lines:[[{t:"italic",v:"As The Messiah kept The Passover,"}],[{t:"italic",v:"So shall you in like manner keep The Passover..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As He was afflicted, you shall fast..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As He slept in the tomb, you shall mourn..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And as He rose from the grave,"}],[{t:"italic",v:"You shall rejoice and sing praises..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, you shall complete the week with joy and feasting..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then later shall you remember The Bridegroom being taken from you,"}],[{t:"italic",v:"And rejoice in the Blessed Hope of His soon return."}]]},{type:"para",segments:[{t:"text",v:"In this way will you begin to partake of the hidden manna, and your hearts shall be glad, causing you to see with greater eyes; your understanding of the Glory brightening as you enter into a more profound knowledge of the salvation of God, which is accomplished and fulfilled in The Son of Man. For the Holy Days are revelation, revealing hidden things kept secret since the world began - signposts of things to come, a foretaste of The Kingdom, a glimpse into the Glory of God even as the Scriptures, unfolding and coming to light as the will of God is manifest."}]},{type:"para",segments:[{t:"text",v:"And though you are counted as last partakers by the Jews, and scorned by those who dwell in the churches of men, I tell you, you shall be first partakers. For I have set you apart as an example, and by these things shall you bear witness of My comings and goings. For I am The Lord, and I shall surely follow the counsel of My own will. For I do not receive counsel from men, nor shall I follow the line which they have stretched out for Me, that I might adhere to their rules or meet their expectations; rather I do that which is right and good in My own eyes. Therefore those who diligently seek to know The Father must abide in The Son, and obey His voice - living testaments to those without knowledge, an ensign to all nations, soon taken up, first partakers of the Glory."}]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, many who are counted as first will be last,"}],[{t:"italic",v:"And many who are counted as last shall be first..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For those mocked and persecuted"}],[{t:"italic",v:"For My name\u2019s sake must be first..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even as those who are mocked and persecuted"}],[{t:"italic",v:"Because of this Word shall be first also..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/walking-in-the-footsteps-of-the-messiahs-passion",videoVoiceUrl:"https://www.youtube.com/watch?v=4McEeRHG1wc&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=20",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#The_Coming_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:20,prevLetter:{id:"obey-god",title:"Obey God"},nextLetter:{id:"wisdom",title:"Wisdom"}},{id:"wisdom",title:"Wisdom",date:"4/26/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"True wisdom is not of man, nor is it found in the earth, but from above - heavenly, holy. For that created was created according to the wisdom of Him who created it and by whom all things consist, knowing their form from the beginning."},{t:"italic",v:"Therefore the fear of The Lord is indeed the beginning of wisdom, and the knowledge of The Holy One is understanding, as it is written."},{t:"fn",v:"1"},{t:"text",v:"Yet in vain men continue to seek out wisdom, yet never find it; they search for knowledge, yet it remains just outside their reach. For apart from Me there is no knowledge, apart from Me all understanding passes away. For I AM HE, The Only Fountain from which flows all wisdom and knowledge, The Source of all things. For I am He who spoke into the dark which was upon the face of the deep; behold, I am He who divided the light from the darkness. Thus all things conform to the line which I have set. For My will is a rock which can never be moved, the confines in which all creation exists. And behold, the earth abides forever, and everything in it gives heed to the will of The Most High God, having come forth by the Word of My power. Thus that which has been corrupted shall be purified, and that which has become crooked shall once again be made straight, restored to the form in which I created it, according to that same wisdom by which it was made at the first - from Glory to Glory, by Grace of Grace, says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"So then all who receive of Me grow wise,"}],[{t:"italic",v:"Receiving of that which is pure,"}],[{t:"italic",v:"Learning to walk in that which is eternal..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As one being led along a mountain stream of living waters,"}],[{t:"italic",v:"Filled with a fervent desire to seek out its source..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Drinking from it along the way,"}],[{t:"italic",v:"Gaining strength in weakness,"}],[{t:"italic",v:"Leaving all behind in their holy pursuit."}]]},{type:"para",segments:[{t:"text",v:"Yet with the ungodly, it is not so. For the ungodly man proclaims the wisdom of the world, seeking always to lay hold on it, to make it his own. Thus he shall indeed gain the world, yet shall be left wanting, when all he has built up for the sake of his own glory comes crashing down. For all who remain married to this world shall surely share in its end. For the wisdom of man is like him - grass of the field, here today and tomorrow thrown into the fire. And thus shall the wisdom and glory of man be destroyed together, along with that which had sprung up from beneath - lies, ever-growing deceptions, leading him away from The Truth and The Life. For like lost sheep all have gone astray; there are none who know, not one who truly understands. They run to and fro in all the earth, neither seeing nor believing, grasping always at particles of dust blowing in the wind; worldly men sinking into the mire of their own ways, meet for death; a whole generation of dying children suffocating in the ever-shifting sands of religion, philosophy and science, falsely called truth and wisdom, built upon the corrupt knowledge of man, all of which shall be burned up in the Day."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore here is wisdom, the only knowledge"}],[{t:"italic",v:"Which endures forever, true understanding:"}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And you are in life because of Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And all that is, even all these worlds"}],[{t:"italic",v:"To every star you see in the heavens,"}],[{t:"italic",v:"Was made according to the wisdom"}],[{t:"italic",v:"Of The Father, brought forth and established"}],[{t:"italic",v:"Through The Son, by whom all things consist..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I AM, and have always been,"}],[{t:"italic",v:"The Way and The Life, The Salvation of God,"}],[{t:"italic",v:"The Only Truth from which all understanding flows..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA-YAHUWAH."}]]}],footnotes:{1:{type:"scripture",ref:"Proverbs 9:10"}},nkjv:{"Proverbs 9:10":"\u201CThe fear of the LORD is the beginning of wisdom, And the knowledge of the Holy One is understanding."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/wisdom",videoVoiceUrl:"https://www.youtube.com/watch?v=Q04sPRb7m00&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=21",videoMusicUrl:"https://www.youtube.com/watch?v=YU3D02_2lEc&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=9",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"}],num:21,prevLetter:{id:"walking-in-the-footsteps-of-the-messiah-s-passion",title:"Walking in the Footsteps of The Messiah\u2019s Passion"},nextLetter:{id:"workers-in-the-field-of-the-lord-s-harvest",title:"Workers in the Field of The Lord\u2019s Harvest"}},{id:"workers-in-the-field-of-the-lord-s-harvest",title:"Workers in the Field of The Lord\u2019s Harvest",date:"5/15/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy\u2019s Wife, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, I have sent into My vineyard husbandmen, and one who is to be as a chief husbandman. And all those who are sent are of the same. Even all who seek Me in sincerity and in truth shall serve in like manner."}]},{type:"para",segments:[{t:"text",v:"Behold, The Lord over the harvest has sent out a call to every tribe, tongue, people and nation, calling them out, that they might come and work in His field. Yet the laborers are few. For though many labor, few heed the call. They serve another master, seeking always after the praises of men. And behold, they have grown fat, they are swelled with pride; they have enlarged themselves and acquired much gain. Yet what they produce remains altogether wanting - bitter wine, fit for neither man nor beast, but only to be cast out. Thus they hate the smaller vineyards and the laborers thereof. For in the small vineyards the early and latter rains are abundant and are received in due season, the quality of the wine produced greater, its value beyond compare."}]},{type:"para",segments:[{t:"text",v:"Beloved, you and your husband are of the small in number, the lowly vineyard, where the wine is superior and the latter rains abundant. For your husband has been appointed as a chief husbandman over this field and all its laborers. For he listens to Me, and delivers My commands; by him I make My plans known. And you transcribe what he receives, that it may be delivered in due season, to those who have drawn near and to those who remain afar off. Therefore the one who The Master appoints, as both servant and chief husbandman, enters not the field, but stands outside relaying The Master\u2019s orders, with his helper beside him. And if the laborers hate the chief husbandman, have not evil thoughts entered their hearts, by which they have also judged falsely? For those who hate My messengers hate Me, for I have sent them. Therefore all who harbor evil thoughts shall be sent away, and many shall be left desolate. Indeed all flocks shall be tested, every congregation sifted, no matter their number - whether great or small, bond or free, rich or poor. There shall be weeping and gnashing of teeth."}]},{type:"poetry",lines:[[{t:"italic",v:"Again, I say to you,"}],[{t:"italic",v:"The first harvest shall be lowly, of the lowly;"}],[{t:"italic",v:"And the second plenteous, of the refined and penitent..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For many are called, yet few are chosen."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/workers-in-the-field-of-the-lords-harvest",videoVoiceUrl:"https://www.youtube.com/watch?v=UBe2l_vtEYg&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=22",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"I Am Calling You Out",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:22,prevLetter:{id:"wisdom",title:"Wisdom"},nextLetter:{id:"spoils-of-war",title:"Spoils of War"}},{id:"spoils-of-war",title:"Spoils of War",date:"5/29/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, what do You say regarding those who take it upon themselves to be \u201Cspiritual warriors,\u201D rebuking demons in the name of Jesus?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"YahuShua is My name. Therefore hear My words, O ignorant and vain generation, for you know nothing yet as you ought to know. For one who endeavors to gain advantage over that which they know nothing about shall surely be ensnared by it. Yet there are those who are chosen by The Father, in whom My spirit dwells, who may rebuke demons in My name, but only those to whom it is given. And this is not of their own authority, but MY authority. For as it is written:"},{t:"italic",v:"No one can have anything unless God gives it,"},{t:"fn",v:"1"},{t:"italic",v:"and apart from Me one can do nothing."},{t:"fn",v:"2"},{t:"text",v:"For I have already told you:"},{t:"italic",v:"Those who seek to understand the dark will soon find themselves trapped in the midst of it, unable to break free. Yet those who seek The Light will find it, and I will show them The Way; in these darkness has no foothold."},{t:"fn",v:"3"},{t:"text",v:"For people who practice such offenses walk in pride, knowing neither Me nor My will. And any who seek to do battle with evil spirits, apart from Me, will fail and be severely harmed."},{t:"fn",v:"4"},{t:"text",v:"For I am The Only Lord of Hosts. I am Lord over Heaven and Earth, over good and evil; ALL are subject to My will, even to My every word. For where I am, there is no darkness at all. What then is man? He is but flesh, his power of no use at all. And in his pride he seeks glory for himself, a false valor. And so he continually turns to his own devices, deceiving himself, thinking he stands though he has fallen. Foolhardy, he rushes into battle where he suffers injury after injury, ignoring his wounds, wounds which remain unhealed, infecting the whole of the body. Yet he continues on in his arrogance, his pride driving him forward, unable to see that he is cast down, saying within himself, \u201CLook at my accomplishments, look upon all I have done!\u201D And all the while satan laughs, saying,"},{t:"italic",v:"\u201CBehold my acolytes; see how these men of battle have become like me.\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"Sons and daughters of men, you are no warriors..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You are casualties, spoils of a war"}],[{t:"italic",v:"Which was won from the foundation"}],[{t:"italic",v:"Of the world, of which I was also slain..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I alone bear the scars of battle..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Lo, I bear them in My hands and My feet,"}],[{t:"italic",v:"Upon My back and in My side, wounds which I"}],[{t:"italic",v:"Received in the house of My friends..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 3:27 (GNT)"},2:{type:"scripture",ref:"John 15:5"},3:{type:"note",text:'See: "Seek The Light Only"',url:"https://www.thevolumesoftruth.com/Seek_The_Light_Only#:~:text=Therefore%20those%20who,Says%20The%20Lord.",link:{collection:"Letters to The Lord's Little Flock",letterTitle:"Seek The Light Only",excerpt:"Therefore those who seek to understand the dark"}},4:{type:"scripture",ref:"Acts 19:13-16"}},nkjv:{"John 3:27 (GNT)":"John answered, \u201CNo one can have anything unless God gives it.\u201D","John 15:5":"\u201CI am the vine, you are the branches. He who abides in Me, and I in him, bears much fruit; for without Me you can do nothing.","Acts 19:13-16":"13. Then some of the itinerant Jewish exorcists took it upon themselves to call the name of the Lord Jesus over those who had evil spirits, saying, \u201CWe exorcise you by the Jesus whom Paul preaches.\u201D 14. Also there were seven sons of Sceva, a Jewish chief priest, who did so. 15. And the evil spirit answered and said, \u201CJesus I know, and Paul I know; but who are you?\u201D 16. Then the man in whom the evil spirit was leaped on them, overpowered them, and prevailed against them, so that they fled out of that house naked and wounded."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/spoils-of-war",videoVoiceUrl:"https://www.youtube.com/watch?v=Dh0lJ1oZCuY&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=23",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Spiritual Warfare",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Warfare"},{label:"Regarding Demons",url:"https://answersonlygodcangive.com/Regarding_Demons"},{label:"Regarding Demons (Bible)",url:"https://trumpetcallofgodonline.com/index.php5?title=Regarding_Demons"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:23,prevLetter:{id:"workers-in-the-field-of-the-lord-s-harvest",title:"Workers in the Field of The Lord\u2019s Harvest"},nextLetter:{id:"fasting",title:"Fasting"}},{id:"fasting",title:"Fasting",date:"6/5/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Sister in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a sister in Christ: Lord, should we fast on the behalf of others?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Have not My servants fasted in your presence?"},{t:"fn",v:"1"},{t:"text",v:"Yet you have not discerned. For whatsoever one does with love, with compassion, with empathy, or with concern for their fellow man, is well and good in My eyes. Even to afflict one\u2019s soul on the behalf of another, in My name, is righteousness. For this is true love. Therefore fast if you are so moved, and do so according to your faith, that it may be strengthened. Yet do not take up a fast for the dead, forsaking The Promise. For this is contemptible in My sight and bears only bitter fruit. Neither shall you fast as a recompense for sin. For this is to deny The Holy Sacrifice, the forgiveness of sins. Therefore the one who fasts in remembrance of Me is wise, and the one who draws close to Me, placing Me above all else, will have peace. For they have chosen to forsake their flesh, that they might be filled with grace and satisfied with truth."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus that which I had spoken"}],[{t:"italic",v:"In the wilderness is the very same"}],[{t:"italic",v:"By which you shall live,"},{t:"fn",v:"2"},{t:"italic",v:"as you seek"}],[{t:"italic",v:"To do the will of your Father in Heaven"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved children, I am enough!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I am The Only Bread which satisfies,"}],[{t:"italic",v:"The Very Manna which came down from Heaven,"}],[{t:"italic",v:"The One alone in whom is eternal life..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Only Way, The Only Truth, The Only Life..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "For a Testimony and as a Lamentation"',url:"https://www.thevolumesoftruth.com/For_a_Testimony_and_as_a_Lamentation#For_a_Testimony_and_as_a_Lamentation",link:{collection:"Letters to The Lord's Little Flock",letterTitle:"For a Testimony and as a Lamentation"}},2:{type:"scripture",ref:"Matthew 4:4"},3:{type:"scripture",ref:"John 4:34"}},nkjv:{"Matthew 4:4":"But He answered and said, \u201CIt is written, \u2018Man shall not live by bread alone, but by every word that proceeds from the mouth of God.\u2019 \u201D","John 4:34":"Jesus said to them, \u201CMy food is to do the will of Him who sent Me, and to finish His work."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/fasting",videoVoiceUrl:"https://www.youtube.com/watch?v=siNIoPK2qs0&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=24",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Fasting",url:"https://answersonlygodcangive.com/Regarding_Fasting"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:24,prevLetter:{id:"spoils-of-war",title:"Spoils of War"},nextLetter:{id:"the-ill-favored-of-the-flock",title:"The Ill-Favored of the Flock"}},{id:"the-ill-favored-of-the-flock",title:"The Ill-Favored of the Flock",date:"6/5/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a brother in Christ: Lord, how do I pray for those who blaspheme Your Word and persecute Your servants? How do I pray double for them? What does that mean?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Where does a shepherd spend his time, and which of his sheep require the most attention? Therefore pray in like manner. For indeed the ill of the flock require the most attention, and the one in ninety-nine who has gone astray shall by no means be forsaken. And though there are many who stand inside locked gates, while you stand outside, do you not remain all of one fold? And when I have freed them, will you not all rejoice together?"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore treat them as such,"}],[{t:"italic",v:"And pray for them, even double,"}],[{t:"italic",v:"And it shall be well with you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For those who arrive last shall be"}],[{t:"italic",v:"Embraced by those who had arrived first..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore let your heart remember,"}],[{t:"italic",v:"As you look to the day..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-ill-favored-of-the-flock-4",videoVoiceUrl:"https://www.youtube.com/watch?v=JxifswRYNpg&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=26",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prayer",url:"https://answersonlygodcangive.com/Regarding_Prayer"}],num:25,prevLetter:{id:"fasting",title:"Fasting"},nextLetter:{id:"that-which-is-not-of-me-is-against-me-and-comes-from-the-evil-one-says-the-lord",title:"That Which Is Not of Me Is against Me, and Comes from the Evil One, Says The Lord"}},{id:"that-which-is-not-of-me-is-against-me-and-comes-from-the-evil-one-says-the-lord",title:"That Which Is Not of Me Is against Me, and Comes from the Evil One, Says The Lord",date:"6/9/10",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For a Sister and Brother in Christ, and For All Those Who Have Ears to Hear",noteLine:"(Regarding the doctrine of hell and eternal torment, as taught in the churches of men)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, He who is holy, He who is true:"},{t:"text",v:"Have I not made the matter known? Beloved ones, how is it you have yet to discern? Tell Me, in this doctrine of hell and eternal torment, as taught by those who call of themselves Christian, what fruit is displayed? - Love? Joy? Peace? Patience? Kindness? Gentleness? Goodness? Mercy?! So then if it bears no fruit, according to My own spirit, then from what spirit must this doctrine come, and upon what foundation is it built? For I have already told you, whosoever believes in The Son shall abide forever, and whosoever has not The Son shall perish and not see life. Therefore you do greatly err."}]},{type:"para",segments:[{t:"text",v:"Behold, I shall speak plainly, so those who have ears to hear may hear and draw close, and so those who refuse to hear may forbear and depart: ANYONE who holds fast to the false doctrine of hell and eternal torment, as taught in the churches of men, DO NOT KNOW ME! Nor have they embraced Me in truth, nor does My spirit dwell within them; I do not know them! Thus refinement shall be their portion, and abasement their due reward, in the Great and Dreadful Day of The Lord! For by strong rebuke I must correct them, and with an outstretched hand shall I bring swift discipline upon them! For they have surely blasphemed My name, even on the highest order! Therefore, beloved ones, hear My words and also understand: You must forsake this doctrine, for it is most perverse. You must withdraw yourself from all who teach this doctrine or seek to uphold it in any way. For it is written:"},{t:"italic",v:"You can not drink the cup of The Lord and the cup of demons; you can not partake of The Lord\u2019s table and of the table of demons."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore come out from among them, and be separate..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come to Me and embrace Me as I truly am,"}],[{t:"italic",v:"And I also shall embrace you, setting you apart"}],[{t:"italic",v:"From all these who have deceived you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then shall that which was brought forth"}],[{t:"italic",v:"From a lie, as a veil of darkness to cover"}],[{t:"italic",v:"The heads of My people, be destroyed in the light"}],[{t:"italic",v:"Of pure understanding and undefiled wisdom,"}],[{t:"italic",v:"Crushed beneath the weight of The Truth, which I am..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Says He who is faithful, He who is true."}]]}],footnotes:{1:{type:"scripture",ref:"1 Corinthians 10:21"}},nkjv:{"1 Corinthians 10:21":"You cannot drink the cup of the Lord and the cup of demons; you cannot partake of the Lord\u2019s table and of the table of demons."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/that-which-is-not-of-me-is-against-me-and-comes-from-the-evil-one-says-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=X7gkkZw7W64&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=26",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"}],num:26,prevLetter:{id:"the-ill-favored-of-the-flock",title:"The Ill-Favored of the Flock"},nextLetter:{id:"be-instant-in-and-out-of-season",title:"Be Instant In and Out of Season"}},{id:"be-instant-in-and-out-of-season",title:"Be Instant In and Out of Season",date:"6/10/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding unbelieving family members)",blocks:[{type:"para",segments:[{t:"text",v:"My sons and daughters, what is trust with abandonment? What is obedience without expectation? Is not your reasonable service love without condition? Yet I tell you the truth, trust is more than letting go. For it remains standing that it must also be shown in your obedience and by your example, and by your willingness to never deny My name, no matter the time or the season. Beloved, place your loved ones in My hands, as I have said, for at no time were they forsaken. For I am the gate for all My sheep, and they also will hear My voice in the day they are humbled, the day their hearts crack and their pride crumbles..."},{t:"italic",v:"And oh what a cry shall be heard, oh what wailing shall come forth."},{t:"text",v:"Yet are you not also My hands and My feet, My voice, a testimony and a lamentation bearing witness of Me? Therefore, again I say to you, do not deny My name to please others or because of fear. Make no effort to keep the peace for their sakes. Rather as it is written:"},{t:"italic",v:"Proclaim My words; be instant in and out of season. Reprove, rebuke and exhort, with all long-suffering, according to that which I have shown you."},{t:"fn",v:"1"},{t:"text",v:"For one who truly loves Me speaks about Me, and remains faithful at all times and in every season. And one who places Me above all else has shown their loved ones who is first, and what faithfulness truly is. For there is no true love apart from Me; nor can one remain faithful unless they have received of Me."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore to speak of Me in the"}],[{t:"italic",v:"Company of others is to love them..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And to deny Me in the company"}],[{t:"italic",v:"Of others is to hate them,"}],[{t:"italic",v:"Whereby you have also revealed that"}],[{t:"italic",v:"Your comfort is of more importance than"}],[{t:"italic",v:"The Truth, and keeping the peace"}],[{t:"italic",v:"More important than their lives..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"2 Timothy 4:2"}},nkjv:{"2 Timothy 4:2":"Preach the word! Be ready in season and out of season. Convince, rebuke, exhort, with all longsuffering and teaching."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/be-instant-in-and-out-of-season",videoVoiceUrl:"https://www.youtube.com/watch?v=BMcKx_w-z1k&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=27",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:27,prevLetter:{id:"that-which-is-not-of-me-is-against-me-and-comes-from-the-evil-one-says-the-lord",title:"That Which Is Not of Me Is against Me, and Comes from the Evil One, Says The Lord"},nextLetter:{id:"a-faithful-witness",title:"A Faithful Witness"}},{id:"a-faithful-witness",title:"A Faithful Witness",date:"6/21/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved, hear Me, says The Lord. Understand love and know mercy, then go and do justly as you walk humbly with your God, sharing all I have given you with everyone you meet. For again I say to you:"},{t:"italic",v:"This Word, even every Volume to every Letter, is the Word of My glory which I have put forth once again; a testament of My love and sacrifice, the announcement of My coming, a proclamation of truth, revelation of who I really am - the Trumpet Call of God, so all those called and chosen may hear and come to Me in their proper time and season."},{t:"text",v:"And if they turn away or fight against you, pray for them. For they know not the valley in which they tread, nor do they understand they are walking into death; for they have yet to grasp the full weight of their error. Thus those who rebel against Me, and speak evil of you because of Me, shall surely receive of My strong rebuke - judgment at the time appointed. Therefore, warn them from Me. And in doing so shall you understand love and know mercy, and do justly. For this is to love your enemies, to bless those who curse you, and to do good to those who hate you."}]},{type:"poetry",lines:[[{t:"italic",v:"My sons and daughters, it is time"}],[{t:"italic",v:"To love your neighbor as yourself..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For only a wicked man would neglect"}],[{t:"italic",v:"His own people, only an evil man would fail"}],[{t:"italic",v:"To warn his neighbor, and only a sluggard"}],[{t:"italic",v:"Would sleep while holding the trumpet..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Only a man meet for death would fail"}],[{t:"italic",v:"To warn the people, when the sword"}],[{t:"italic",v:"Is about to overtake the land..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-faithful-witness",videoVoiceUrl:"https://www.youtube.com/watch?v=k9YbnjePdjk&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=28",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:28,prevLetter:{id:"be-instant-in-and-out-of-season",title:"Be Instant In and Out of Season"},nextLetter:{id:"foremost",title:"Foremost"}},{id:"foremost",title:"Foremost",date:"7/19/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Sister in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"The following was brought before The Lord, for a sister in Christ. She said, \u201CI have been thinking of plastering the sides of my truck with something like, \u2018Adoption is the Loving Option\u2019. I have not heard either \u2018Yes,\u2019 or \u2018No\u2019. The reason I am asking you to ask The Lord is that I do not want to take away from what is already on the back tailgate of my truck (the TrumpetCallofGodOnline.com website sign).\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Do not detract from it; let it stand alone. For My Word is fire, My every Letter purges the dross. Behold, by these Volumes shall I set all these crooked paths straight. For I am The Lord, and I do not change. Therefore, let the Trumpet be blown loudly! Let the call to repentance go out and the announcement be made! For I have lifted up an ensign to all nations, I have set up a standard for this sleeping generation, a bright and shining lamppost for My people, a light, the glory of which shall not be diminished, but shall only increase by measure. For that which must be first is first, and that which I have spoken to this generation is set above all else, even above the atrocities of men. Behold, it shall surely crush them in the Day of The Lord\u2019s Anger."}]},{type:"para",segments:[{t:"text",v:"Beloved, the little ones have always been Mine, and are with Me where I am. Therefore sound the Trumpet to those who are walking into death, to those who tread the wide path, for their destruction draws near. For they have not turned aside from their evildoings, nor do they look back. Behold, they continue on, pressing forward by unjust gain, stepping upon the necks of the poor, breaking the backs of the needy, as they slaughter the innocent in droves. Thus My anger is aroused against the generation of My wrath, My fury is come forth like fire, and shall burn; behold, it shall not be quenched, until every form of wickedness is utterly consumed!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, again I say to you,"}],[{t:"italic",v:"Trumpet My words loudly by all"}],[{t:"italic",v:"Manner of speaking and devices..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Warn them from Me..."}]]},{type:"closing",text:"Says The Lord, The One who sees, The One who knows."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/foremost",videoVoiceUrl:"https://www.youtube.com/watch?v=OzMAizj97G4&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"About The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding Children\u2019s Inheritance on Earth and in Heaven",url:"https://answersonlygodcangive.com/Regarding_Children%E2%80%99s_Inheritance_on_Earth_and_in_Heaven"}],num:29,prevLetter:{id:"a-faithful-witness",title:"A Faithful Witness"},nextLetter:null}],LETTERS_V5_PREFACE=null,LETTERS_V5=[{id:"a-bruised-reed-swaying-in-the-wind",title:"A Bruised Reed Swaying in the Wind",date:"8/5/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"One who sits upon the fence between two houses can not enter either one..."}]},{type:"para",segments:[{t:"text",v:"My son, I have spoken to you many times, and still you deny Me. Even now you rebel against Me, as you reject this Word spoken through My prophet. For I have indeed spoken it, yet I hear no \u2018Amen.\u2019 Behold, it is written in the Scriptures of Truth, and still you remain sitting upon the fence, with one foot planted securely in the pastures of men and the other dangling in the wind. When you called to Me, did I not answer? And when you reached out to Me, did I not extend My hand? Yet you turn from Me, rejecting this Word, drawing back from My hand, refusing to be replanted. Thus between us a gulf widens on account of that from which you refuse to depart, on account of that which you hold on to so tightly - Let go, My son! Let go! There is no argument, no debate! Obey NOT the commandments of men! For I tell you the truth, to choose the doctrines of men is to deny Me, and to uphold their traditions is to fight against Me! I AM THE LORD! Thus before you I have placed an open door. Yet one may only pass through by coming to Me empty, free of the corrupt doctrines of men, standing apart from all their filthy traditions, which I hate. My son, I shall speak plainly, for your sake, once again: NO ONE who upholds any part of the doctrine of hell and eternal torment, as taught in the churches of men, shall escape the Day of The Lord. For whether one holds to it in part or as a whole, they have surely blasphemed My name, even on the highest order. Therefore I call you to repent, and to come out of the churches of men, to be separate. Only then will you begin to know Me, only then will you see Me as I truly am. Yet if you will not come out, nor be separate, most assuredly, I say to you, I shall leave you to refinement in the Great and Terrible Day of The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written:"}],[{t:"italic",v:"I shall not lose one The Father has given Me"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet I shall surely refine them,"}],[{t:"italic",v:"I must purge all who are left,"}],[{t:"italic",v:"And by great tribulation shall they come into glory..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I will turn My hand against them,"}],[{t:"italic",v:"And thoroughly purge away their dross"}],[{t:"italic",v:"And take away all their alloy"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 6:39 (NLT)"},2:{type:"scripture",ref:"Isaiah 1:25 (NKJV)"}},nkjv:{"John 6:39 (NLT)":"And this is the will of God, that I should not lose even one of all those he has given me, but that I should raise them up at the last day.","Isaiah 1:25 (NKJV)":"I will turn My hand against you, And thoroughly purge away your dross, And take away all your alloy."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-bruised-reed-swaying-in-the-wind",videoVoiceUrl:"https://www.youtube.com/watch?v=88-Xb5DOCT0&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=1",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men_-_Section_One"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:1,prevLetter:null,nextLetter:{id:"in-spirit-and-in-truth",title:"In Spirit and in Truth"}},{id:"in-spirit-and-in-truth",title:"In Spirit and in Truth",date:"8/5/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Holy One of Israel:"},{t:"text",v:"What is the knowledge of man? Is it not a stone of stumbling? And the pride of man, a rock of offense? How then shall the blind see or the deaf hear, unless I heal them? Or how shall one grab hold of the line, unless it is first placed within their reach?"}]},{type:"para",segments:[{t:"text",v:"Yet all those who call of themselves Christian seek out knowledge, only to proclaim their own glory before men. Indeed, they proclaim falsely that they know the Way, though they remain lost in their own deceptions. For as it is written:"},{t:"italic",v:"My people are foolish and have no understanding; they are skilled at doing evil, but of doing good they have no knowledge;"},{t:"fn",v:"1"},{t:"italic",v:"they refuse to obey the voice of The Living God, nor will they receive correction. Behold, truth has perished among them; it has altogether been cut off from their mouths!"},{t:"fn",v:"2"},{t:"text",v:"Yet My servants are wise. They fear The Lord, and wait upon Me with all patience and faith, doubting nothing, humble servants who study My Word,"},{t:"fn",v:"3"},{t:"text",v:"knowing I am The Author and The Finisher thereof. When they wake and when they lie down, I am there; I am their life, and they are My joy, says The Lord. Therefore when My servants come to an impasse in My Word, according to their own understanding, what is their reaction? They continue on, without hindrance or doubt. For their relationship with The Author is intimate, their trust without reservation. Thus they remain at peace, and wait upon The Lord for the light of understanding, knowing in their heart every word is true, ready to receive the spirit of the Word, stumbling not over its letter. And until My people are established firmly upon this premise, they will remain daunted, striving to see but never fully understanding, straining to hear but remaining dull of hearing."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus for My wise and faithful servants,"}],[{t:"italic",v:"All barriers are removed..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For their peace is in the knowing,"}],[{t:"italic",v:"I AM WHO I AM, though they yet"}],[{t:"italic",v:"Stand at the beginning, unable to see the end..."}]]},{type:"poetry",lines:[[{t:"italic",v:"An heir of all I will reveal to them"}],[{t:"italic",v:"When the fullness of time has come in..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Jeremiah 4:22"},2:{type:"scripture",ref:"Jeremiah 7:28"},3:{type:"scripture",ref:"2 Timothy 2:15 (KJV)"}},nkjv:{"Jeremiah 4:22":"\u201CFor My people are foolish, They have not known Me. They are silly children, And they have no understanding. They are wise to do evil, But to do good they have no knowledge.\u201D","Jeremiah 7:28":"\u201CSo you shall say to them, \u2018This is a nation that does not obey the voice of the LORD their God nor receive correction. Truth has perished and has been cut off from their mouth.","2 Timothy 2:15 (KJV)":"Study to shew thyself approved unto God, a workman that needeth not to be ashamed, rightly dividing the word of truth."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/in-spirit-and-in-truth",videoVoiceUrl:"https://www.youtube.com/watch?v=Wq7wiv0OMw8&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Patience",url:"https://answersonlygodcangive.com/Regarding_Patience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Doubt",url:"https://answersonlygodcangive.com/Regarding_Doubt"},{label:"Discernment",url:"https://answersonlygodcangive.com/Main_Page#Discernment"}],num:2,prevLetter:{id:"a-bruised-reed-swaying-in-the-wind",title:"A Bruised Reed Swaying in the Wind"},nextLetter:{id:"the-measuring-line",title:"The Measuring Line"}},{id:"the-measuring-line",title:"The Measuring Line",date:"8/23/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved ones, you have sought Me; in this you have done well. Yet the fullness of My love you have yet to understand. For you have only tasted, having taken but a single sip from the cup of My glory. Indeed in your mind\u2019s eye you have seen, but only dimly, a passing glimpse of The Majesty from on high..."},{t:"italic",v:"Therefore I ask you to take a leap! - A leap of understanding, a leap of faith, of steadfast trust! A wondrous leap wherein one lands solidly in My love, wherein peace flows beyond understanding and knowledge of The Holy One is made complete!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear My words, and have understanding:"},{t:"text",v:"Those who sit at My table, also having one who speaks for Me in their midst, shall be tried by a greater line than their fellows - a measuring line over which many shall stumble and from which many shall flee; a plumb line which the churches hate and the world seeks to destroy, the line by which all is measured, by which right is separated from wrong; the line which I established from the beginning, unchanged, even from the foundation of the world. Beloved ones, I tell you the truth, the people of this world do not know Me. Therefore I have come close, to unstop the ears of all who long to hear My voice and obey it; I have drawn near, to open the eyes of all who desire to look upon My face and partake of My glory; and behold, I have poured out My spirit to restore the hearts of the penitent, to breathe new life into all those who embrace My words and seek to remain in My love."}]},{type:"poetry",lines:[[{t:"italic",v:"For I am come,"}],[{t:"italic",v:"And have come already;"}],[{t:"italic",v:"And behold, I shall also"}],[{t:"italic",v:"Return and reveal My glory..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I have not departed from My people,"}],[{t:"italic",v:"For My spirit dwells in My own..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet all must be broken..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Some broken before the time,"}],[{t:"italic",v:"And many more after..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-measuring-line",videoVoiceUrl:"https://www.youtube.com/watch?v=ddSA4Sb9Ncw&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=3",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:'The Coming of The Lord - "I AM COME"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_AM_COME"}],num:3,prevLetter:{id:"in-spirit-and-in-truth",title:"In Spirit and in Truth"},nextLetter:{id:"breaking-through-the-lines",title:"Breaking Through the Lines"}},{id:"breaking-through-the-lines",title:"Breaking Through the Lines",date:"8/23/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved ones, come to Me, and I shall give you rest. Be drawn to Me, that I may lift you up. For I tell you the truth, My wrath is coming. Behold, My anger is aroused, My fierce jealousy burns like a raging fire and is about to come to the full. Yet do not waver, but understand. For My wrath is required, and the foundation of My anger rests solidly upon My jealousy, by which My unending sorrow is also revealed. For My wrath is born of sorrow, and My anger bursts forth as a husband jealous over his bride, My fury as a father protecting his children, as one mighty in battle breaking through the lines - recompense upon ALL who offend, upon ALL who have harmed My beloved! Vengeance upon ALL who have slain My little ones, upon ALL who took part in the murder of the innocent! For the people have forsaken Me, and those within the churches of men refuse to accept Me as I am, nor do they seek to understand. And when I warn them of My wrath or speak of My anger, they do always turn to Me a deaf ear. For they can not bear to listen; indeed, they refuse to understand! Behold, they hate the sound of My voice, and will not give heed to My correction, persecuting all those I send! Beloved, they no longer recognize Me, and want no part with Me as I truly am."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore My wrath shall come upon them"}],[{t:"italic",v:"On a day they did not look for,"}],[{t:"italic",v:"And My anger at an hour they did not expect..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, upon the whole world shall I"}],[{t:"italic",v:"Pour out judgment on that day!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/breaking-through-the-lines",videoVoiceUrl:"https://www.youtube.com/watch?v=RMwiPQskjIA&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=4",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"}],num:4,prevLetter:{id:"the-measuring-line",title:"The Measuring Line"},nextLetter:{id:"judgment-and-mercy",title:"Judgment and Mercy"}},{id:"judgment-and-mercy",title:"Judgment and Mercy",date:"8/28/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears To Hear",noteLine:"(Regarding the judgment of those who are raised at the end of the thousand years)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"In the Consummation, all judged according to their works shall surely die. Yet in that day, if one calls upon the name of Salvation, in true repentance, with sincere remorse in their heart, they will not be judged; behold, they shall pass from judgment into life. For I look upon the heart, I discern the thoughts and judge the innermost intentions; nothing is hidden before Me. Therefore when the multitudes are judged, they will indeed be judged according to their works. For the books shall be opened and their works will be made known, even every idle word, and they shall be condemned. Yet again I say to you, those who call upon the name of The Holy One of Israel in sincerity and in truth, humbling themselves before Him, taking full responsibility for their works, confessing their sin, shall receive mercy. For YahuShua and"},{t:"italic",v:"His"},{t:"text",v:"works now stand in their place, interceding on their behalf. For The Gift is never-ending, and all who come to Me will I in no wise turn away."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, My son, trust in My glory,"}],[{t:"italic",v:"And seek no more to understand"}],[{t:"italic",v:"My Word according to the letter,"}],[{t:"italic",v:"Nor grab hold of it as though"}],[{t:"italic",v:"It can be fully grasped by any man..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Rather seek to know Me as I am..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For from this knowledge alone"}],[{t:"italic",v:"Does all understanding flow"}],[{t:"italic",v:"Into the hearts of My beloved,"}],[{t:"italic",v:"And they shall have peace..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/judgment-and-mercy-6",videoVoiceUrl:"https://www.youtube.com/watch?v=TixxJ6E7o3s&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Final Judgment",url:"https://answersonlygodcangive.com/Regarding_the_Final_Judgment"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Discernment",url:"https://answersonlygodcangive.com/Main_Page#Discernment"}],num:5,prevLetter:{id:"breaking-through-the-lines",title:"Breaking Through the Lines"},nextLetter:{id:"those-who-are-mine-shall-never-be-cast-off",title:"Those Who Are Mine Shall Never Be Cast Off"}},{id:"those-who-are-mine-shall-never-be-cast-off",title:"Those Who Are Mine Shall Never Be Cast Off",date:"9/16/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Regarding Matthew 19:28: So YahuShua said to them, \u201CAssuredly I say to you, that in the regeneration, when The Son of Man sits on the throne of His glory, you who have followed Me will also sit on twelve thrones, judging the twelve tribes of Israel\u201D... A brother in Christ asked if Judas would be one of those twelve."}]},{type:"para",segments:[{t:"italic",v:"[YahuShua answered]"},{t:"text",v:"My son, you consider things deeply, pondering that which others often overlook. Thus because of your zealousness you are called, should you choose to embrace your calling fully, receiving temperance unto peace according to the Spirit of Truth. Yet what of another who has been called in like manner, who refuses to walk according to My will and purpose? Shall he continue in his office, though his heart testifies against him, with his actions bearing fruit of the same? My son, he shall not; his calling shall be given to another."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, hear and understand the loving mercies"}],[{t:"italic",v:"Of God fulfilled in Me, even of those bitter tears"}],[{t:"italic",v:"Which I have shed over all these who deny Me,"}],[{t:"italic",v:"Over all these who betray Me by all they say and do:"}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, in My anger I have indeed cast them out,"}],[{t:"italic",v:"Appointing others to run in their stead..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet I tell you the truth, though they now"}],[{t:"italic",v:"Abide as one sitting along the wayside,"}],[{t:"italic",v:"They are in no wise broken off..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For our bond is love, and any bond"}],[{t:"italic",v:"Forged in My love can never be broken."}]]},{type:"para",segments:[{t:"text",v:"Behold, even amongst this little flock have I received many kisses after the kind of My son, Judas. Yet I tell you the truth, I have never lost one who is Mine; I am in love with My own. And though their thoughts betray them, having given heed to many lies and deceptions from within and without, I know My own, and I will never turn away anyone who returns to Me. Therefore, again I say to you, Judas shall be with Me in paradise. For he repented in sincerity and in truth, with extreme remorse. And though the weight of sin can be very heavy, and remorse over betrayal can slay your heart, even to the point of death, My love is greater still. Thus upon these twelve thrones, of which you have considered yet do not fully comprehend, will My twelve apostles sit, judging the twelve tribes of Israel. Yet Judas shall not be among them. Yet he shall indeed be there, even close at hand, and he shall be at peace, having spent many days wailing upon My bosom in the house of The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/those-who-are-mine-shall-never-be-cast-off",videoVoiceUrl:"https://www.youtube.com/watch?v=K_3iR9TWHIU&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=6",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Judas Iscariot",url:"https://answersonlygodcangive.com/Regarding_Judas_Iscariot"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Forgiveness",url:"https://answersonlygodcangive.com/Regarding_Forgiveness"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"}],num:6,prevLetter:{id:"judgment-and-mercy",title:"Judgment and Mercy"},nextLetter:{id:"my-witnesses-in-the-day",title:"My Witnesses in the Day"}},{id:"my-witnesses-in-the-day",title:"My Witnesses in the Day",date:"9/29/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Look upon My witnesses, for they prepare My way before Me. And behold, the day is coming quickly when I shall also go before them, dwell within them, and be their rearguard. For as the angels which I had placed at the east of the Garden of Eden, and the flaming sword which turned in every direction to guard the way to the Tree of Life,"},{t:"fn",v:"1"},{t:"text",v:"so in like manner shall I guard My witnesses in the Day of Battle. For I had sent My angels to block the way to the Tree of Life. Yet in the Day of The Lord, My servants shall eat from it freely, even as they shall also be its branches, partaking of its fullness, even the strength of the root. And if My servants partake of The Tree of Life, and the fullness of The tree dwells within them, then who shall be able to approach them, to do them harm by any means?"}]},{type:"poetry",lines:[[{t:"italic",v:"For I shall put My words in their mouths..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And set them over nations and over kingdoms,"}],[{t:"italic",v:"To root out and to pull down,"}],[{t:"italic",v:"To destroy and to throw down,"}],[{t:"italic",v:"To build and to plant..."}]]},{type:"closing",text:"For I am The Lord, and I do not change."}],footnotes:{1:{type:"scripture",ref:"Genesis 3:24"}},nkjv:{"Genesis 3:24":"So He drove out the man; and He placed cherubim at the east of the garden of Eden, and a flaming sword which turned every way, to guard the way to the tree of life."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/my-witnesses-in-the-day",videoVoiceUrl:"https://www.youtube.com/watch?v=Uaw6ObMJ-Vo&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:7,prevLetter:{id:"those-who-are-mine-shall-never-be-cast-off",title:"Those Who Are Mine Shall Never Be Cast Off"},nextLetter:{id:"death-unto-life",title:"Death unto Life"}},{id:"death-unto-life",title:"Death unto Life",date:"10/11/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved ones, there is indeed a death in which I am well pleased, and another which greatly pains My heart. For a great multitude shall be left in the Refiner\u2019s Fire, and all shall suffer the pains of death - for some, death unto life; and others, death into darkness. And yet still others have been appointed to be taken through. These shall be for Me a remnant. Behold, I shall be their covering, hiding them from all who puff at them, a strong shield protecting them from all their enemies, a high wall which can not be broken down. They shall endure. For these are reserved for glory, to bring Me great glory in all the earth. Yes, these are they who shall suffer as you must suffer, the same death of which you seek and shall surely be fulfilled, when I finish you -"},{t:"italic",v:"the shedding of the skin of this world, the crucifying of your old man with his sinful ways, the putting on of the new man who is renewed in the knowledge of The Truth, restored in the image of Him who created him."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"For those who come into the world by way"}],[{t:"italic",v:"Of water and blood were born from Life into life;"}],[{t:"italic",v:"Yet to return to My kingdom, one must"}],[{t:"italic",v:"Be reborn from death unto Life..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And though My will seems to be hidden"}],[{t:"italic",v:"From your eyes, it is not at all hidden;"}],[{t:"italic",v:"For I have proclaimed it openly from the beginning;"}],[{t:"italic",v:"I have not ceased from making My plans known..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet from those who refuse Me, it is indeed hidden,"}],[{t:"italic",v:"Though it passes before their eyes even now..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Colossians 3:9-10"}},nkjv:{"Colossians 3:9-10":"9. Do not lie to one another, since you have put off the old man with his deeds, 10. and have put on the new man who is renewed in knowledge according to the image of Him who created him,"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/death-unto-life",videoVoiceUrl:"https://www.youtube.com/watch?v=q13aYqcQ7_k&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=8",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Being Born Again",url:"https://answersonlygodcangive.com/Regarding_Being_Born_Again"}],num:8,prevLetter:{id:"my-witnesses-in-the-day",title:"My Witnesses in the Day"},nextLetter:{id:"pure-and-undefiled-faith",title:"Pure and Undefiled Faith"}},{id:"pure-and-undefiled-faith",title:"Pure and Undefiled Faith",date:"10/14/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved ones, before you depart My table, consider this: Where did your faith come from, and by what means was it authored? Be not quick to answer, but consider. For I tell you the truth, I am not the author of your faith, nor did your faith begin with Me. For I did not come forth to increase the faith you already have, nor have I spoken through all these Letters to affirm that which you have already accepted; no, I have come to tear down and to supplant. Beloved, I am calling you out of that to which you have grown accustomed, to be separate from that which has until now been the author of your faith. For some of you your faith began in the churches of men, and for others it was molded and shaped by the world, yet for most it was a combination of the two. Therefore I call you to see with greater eyes, with eyes like Mine. For I tell you the truth, your faith is against Me, even as the churches of men and this world are against Me, polluting My name and My glory without ceasing. For it is written:"},{t:"italic",v:"Friendship with the world is enmity with God; whoever therefore wants to be a friend of the world makes himself an enemy of God."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Therefore, I have poured out My spirit on all flesh in these last days, and by My prophet I have spoken; even by a multitude of words I have declared it. And thus I say it to you, once again:"},{t:"italic",v:"I shall tear down, uproot and destroy, supplant, until I have set all these crooked paths straight."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus I have called My people out, that they might"}],[{t:"italic",v:"Come out from among them and be separate..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A people set apart for My name,"}],[{t:"italic",v:"A people who keep The Commandments"}],[{t:"italic",v:"And cease not from testifying to My glory,"}],[{t:"italic",v:"A people of pure and undefiled faith..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A people joined unto ME..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"James 4:4"}},nkjv:{"James 4:4":"Adulterers and adulteresses! Do you not know that friendship with the world is enmity with God? Whoever therefore wants to be a friend of the world makes himself an enemy of God."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/pure-and-undefiled-faith",videoVoiceUrl:"https://www.youtube.com/watch?v=HZD-y6e6hek&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=9",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Setting All These Crooked Paths Straight",url:"https://answersonlygodcangive.com/Main_Page#Setting_All_These_Crooked_Paths_Straight"},{label:"I Am Calling You Out",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out"}],num:9,prevLetter:{id:"death-unto-life",title:"Death unto Life"},nextLetter:{id:"women-in-mourning",title:"Women in Mourning"}},{id:"women-in-mourning",title:"Women in Mourning",date:"10/19/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have stretched out My hands all day long to a stubborn people, who walk in a way that is not good; a people who do not obey My voice, nor will they incline the ear, but do always follow the counsels and dictates of their own evil hearts; a most rebellious generation who provoke Me to anger continually to My face! For they seek always a way to retain their corrupt riches, a way to hide their shame, as they uplift themselves to new heights in vanity - false glory! Yea they build great and lavish houses, setting each one upon the shifting sands of man-made religion, perverse tradition and the corrupt doctrines of men; behold, even their steeples seek to pierce Heaven!..."},{t:"italic",v:"Woe, therefore, to this adulterous people! Woe to all these women dressed in fine apparel! They are all as strangers to Me! For they worship another god, and within their churches they teach the people of another messiah, one which they themselves have created! THESE ARE NOT OF MY BODY! THEY LOOK NOTHING LIKE ME!"},{t:"text",v:"Behold, the churches have removed themselves far from Me! For they have played the harlot, and cleave to the breast of another! Tears, great anguish fills My heart! The stripes which I bore for them remain, yet they continue to bruise Me and persecute My body while mocking Me, spitting in My face on account of My words, continuing in their unjust cause, that they might silence My messengers and shut My mouth from speaking! For the sake of envy they stone My Bride, and are quick to pass judgment upon the lowly, turning their backs on those who come seeking bread! Behold, they pollute the name of God without ceasing, even the name The Father gave Me (the name We share), refusing to embrace Me as I truly am! Lo, even the least of their brethren are made to conform to their image, as they continue to heap up offenses one atop another throughout their generations! And those who depart their company, or bring forth a just complaint, are judged swiftly and very harshly, slandered and cast out. For they say within themselves,"},{t:"italic",v:"\u201CI answer to no one; I am free from The Law, and am in need of nothing. This is my house, and to IT am I married. I will follow the traditions of my fathers, and no one will turn me aside. For I am a bride-in-waiting, and will never be a widow!\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore I am coming down, and MY bride shall be taken,"}],[{t:"italic",v:"My every treasure gone from this place..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And so it shall come to pass, the \u201Cbride-in-waiting\u201D"}],[{t:"italic",v:"Shall indeed become the widow;"}],[{t:"italic",v:"For the husband which she had formed"}],[{t:"italic",v:"In her own image shall die on that day..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, only women in mourning shall remain..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/women-in-mourning",videoVoiceUrl:"https://www.youtube.com/watch?v=DQsuK6oP20E&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:10,prevLetter:{id:"pure-and-undefiled-faith",title:"Pure and Undefiled Faith"},nextLetter:{id:"trees-of-the-field",title:"Trees of the Field"}},{id:"trees-of-the-field",title:"Trees of the Field",date:"10/28/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy, During Men\u2019s Fellowship",forLine:"For The Lord\u2019s Watchmen, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My sons, what is a dry tree to he who holds the axe? Yet when the winds pass through and catch the man sleeping, is he not easily crushed by the weight of the tree?"}]},{type:"para",segments:[{t:"text",v:"Indeed, what is this forest full of tall trees before Me, standing so tall with roots deeply embedded in the world, blocking always the warmth of the sun at eventide, casting long shadows under which the wicked flock? Are they not soon left cold, standing in darkness? Are they not as those who seek shelter under a tree when the rains descend and the thunder crashes, who meet a quick end when lightning strikes?..."},{t:"italic",v:"So is this people before Me, a most wicked and foolish generation, multitudes of slothful people seeking always the tall tree, taking shelter under branches which have grown far and wide, standing fast in the cold darkness of its shadow, oblivious to the setting of the sun upon this age of men!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore I am come to cut down every tree,"}],[{t:"italic",v:"Which grows where I have not planted;"}],[{t:"italic",v:"Behold, I shall level entire forests!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I have called forth My witnesses, men of promise,"}],[{t:"italic",v:"Who I shall set over nations and over kingdoms,"}],[{t:"italic",v:"To root out and to pull down, to destroy"}],[{t:"italic",v:"And to throw down, to build and to plant..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And no one shall be able to subdue them, by any means!"}]]},{type:"para",segments:[{t:"text",v:"Yet you ask within yourselves,"},{t:"italic",v:"\u201CHow can this be?\u201D"},{t:"text",v:"My sons, My ways are not human ways, My thoughts not human thoughts. Here is wisdom: If a man can not be overcome by any means, what is he to other men? And if a man can not be moved from his place, not one inch to the left nor to the right, what has he become compared with other men? And what of a man, My servant, who is one with The Messiah? Is he not an island which no one can reach, save I make it possible for them to do so? Consider the squirrel and its ways. Does it not live among the trees, running up and down with ease, leaping from branch to branch with skill and grace, perfectly designed for its abode and purpose? So shall My watchmen be in the Day of The Lord; prepared according to their task, established according to the Word of My mouth, filled according to their service, remade according to My purpose. I AM THE LORD. Therefore, again I say to you, all those who seek sanctuary under any tree which grows contrary to Me shall be struck down; indeed all who take refuge in these man-made houses, whose doctrines and traditions I hate, shall be crushed beneath the weight of their fallen riches. Yet all who seek sanctuary in The Messiah, all who sought refuge under the shadow of His healing wings, shall escape. Yet those plucked up and replanted shall be set as a high wall against the world, a strong tower standing firm in the midst of great and mighty men, fixed pillars which can not be moved nor broken down, men of valor in whom My spirit dwells like fire, says The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/trees-of-the-field",videoVoiceUrl:"https://www.youtube.com/watch?v=auArYPQkAws&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=11",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:11,prevLetter:{id:"women-in-mourning",title:"Women in Mourning"},nextLetter:{id:"blessed-by-the-word-of-god",title:"Blessed by The Word of God"}},{id:"blessed-by-the-word-of-god",title:"Blessed by The Word of God",date:"11/18/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Who is a wise and faithful servant? Is he not one who receives the blessings of his Father without constraint, one who embraces My speech, whether soft or hard, even of that which I have spoken to another? A servant such as this is wise indeed."},{t:"italic",v:"For he knows that every good gift and every perfect gift is from above, and comes down from The Father of Lights, with whom there is no variation or shadow of turning, as it is written."},{t:"fn",v:"1"},{t:"text",v:"Beloved ones, if I am He who reigns in your heart, The One of whom you testify is love and mercy, The One alone who knows all things, why do you resist My correction and seek only to embrace that which is soft? If I speak, and My words carry My spirit, put no difference between them. For everything which comes from the mouth of The Lord your God is a blessing for all - a song for all those who have ears to hear, a vision to all who have eyes to see My splendor, painted by the Word of My glory, an overflowing fountain inside those whose hearts are wide open."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, it is time for you to truly believe without seeing,"}],[{t:"italic",v:"To obey My voice, whether soft or hard..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It is time for you to follow your heart,"}],[{t:"italic",v:"And no more bow to the demands of your mind..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It is time for you to embrace Me as I truly am..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"James 1:17"}},nkjv:{"James 1:17":"Every good gift and every perfect gift is from above, and comes down from the Father of lights, with whom there is no variation or shadow of turning."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/blessed-by-the-word-of-god-6",videoVoiceUrl:"https://www.youtube.com/watch?v=cYYPy2AnQEc&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=12",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:12,prevLetter:{id:"trees-of-the-field",title:"Trees of the Field"},nextLetter:{id:"mindful",title:"Mindful"}},{id:"mindful",title:"Mindful",date:"11/30/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"What is a son who is mindful of his father\u2019s ways, who pays close attention to his every word? Or a servant, who seeks only to serve his master? Or a faithful bride, who seeks always to please her husband in all her ways, whether he is near or far, in her presence or soon returning? Beloved ones, be mindful of these things and grow in wisdom, abide in trust and do not waver; be at peace. For I am indeed coming quickly, and My reward is with Me. And behold, I am also coming to repay the nations, for all their forsaking of Me. Therefore sing for Me, beloved, stand up and blow the Trumpet. For the day is coming quickly, and is already here, when I shall place My voice within My servants, and together we shall speak as one. Therefore do not draw back, but lean forward, cup your ears and listen to the sound of My voice; be attentive and wide awake. For the time has come for Me to claim My own, to call them out and gather them together. Therefore search your hearts and know Me, embrace Me as I truly am. Beloved, stop looking forward, as though I am afar off. Cease from looking backward, as though I am somehow beyond your reach - Look, here I am! See no more through the eyes of man, for flesh and blood deceive you. And by NO means am I that which men in authority have spoken concerning Me; the \u201CJesus\u201D of the churches of men looks nothing like Me!"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, wipe your eyes, and see!"}],[{t:"italic",v:"Unstop your ears, and hear!"}],[{t:"italic",v:"Open your hearts, and know, I AM HE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Only Begotten of The Father,"}],[{t:"italic",v:"The One True God and Savior, The Mashiach,"}],[{t:"italic",v:"YAHUSHUA-YAHUWAH..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Immanu El!"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/mindful",videoVoiceUrl:"https://www.youtube.com/watch?v=QEOqseKkVSA&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:'The Coming of The Lord - "I Am Coming Quickly"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_Am_Coming_Quickly"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"}],num:13,prevLetter:{id:"blessed-by-the-word-of-god",title:"Blessed by The Word of God"},nextLetter:{id:"do-not-look-back-escape-to-the-fathers-house",title:"Do Not Look Back; Escape to The Fathers House"}},{id:"do-not-look-back-escape-to-the-fathers-house",title:"Do Not Look Back; Escape to The Fathers House",date:"12/7/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:" Learn the lesson of Lot and his wife. It is simple, yet speaks to that which is to come and must be. For those who I have called out of a place shall in no wise return to it, nor shall they look back. They shall continue on toward safety, with their eyes fixed upon The Goal, walking always in line with the Spirit - praying without ceasing, giving heed to My leading, listening for My voice."}]},{type:"para",segments:[{t:"text",v:"Yet there shall be many who will seek to flee the coming wrath, yet shall by no means escape it, for this world is condemned. Behold, many shall stop to look back, and their hearts shall fail them for fear, on account of that which is coming to pass before their eyes. For I have purposed and will not relent, I will not turn back - "},{t:"italic",v:"CALAMITY upon the cities of men! Upon every city in every land, of every tribe, tongue, people and nation! CALAMITY upon the churches of men and every religion of man! Upon every denomination and religion in every land, of every tribe, tongue, people and nation! Not one polluted sanctuary shall stand before My face, anymore! For I am a jealous God, and I will not share My glory!"},{t:"text",v:" Declares The Lord."}]},{type:"poetry",lines:[[{t:"text",v:"For there is but One Sanctuary"}],[{t:"text",v:"In which My people are to take refuge,"}],[{t:"text",v:"One Shelter from the heat of the Day..."}],[{t:"stanza-break"}],[{t:"text",v:"Blessed, therefore, are all those who embrace Him fully"}],[{t:"text",v:"And strive always to walk in His ways..."}],[{t:"stanza-break"}],[{t:"text",v:"They shall be hidden under the shadow"}],[{t:"text",v:"Of His healing wings, high and lifted up..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/do-not-look-back-escape-to-the-father-s-house",videoVoiceUrl:"https://www.youtube.com/watch?v=bAvIZkq3LbQ&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=14",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/Regarding_The_Messiah"}],num:14,prevLetter:{id:"mindful",title:"Mindful"},nextLetter:{id:"tear-down-every-whitewashed-wall-of-abomination",title:"Tear Down Every Whitewashed Wall of Abomination"}},{id:"tear-down-every-whitewashed-wall-of-abomination",title:"Tear Down Every Whitewashed Wall of Abomination",date:"12/9/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Those in Men\u2019s Fellowship, and For All Those Who Have Ears to Hear",noteLine:"(Regarding the conflict which arises between those who keep the holidays of men and those who obey the Word of The Lord)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Purification of faith starts with the temple in which I dwell,"},{t:"fn",v:"1"},{t:"text",v:"and ends with the house in which My servants dwell. For the Day approaches quickly wherein My witnesses"},{t:"fn",v:"2"},{t:"text",v:"shall wield a staff and a sword; a staff to break, and a sword to cut and strike through. And wheresoever I send them, in where an idol is found, I shall cause a fire to well up within their hearts and they shall strike with ferocity, breaking every idol in pieces, cutting down every tree of abomination which stands against Me, piercing the heart of every man who upholds that which pollutes My name and My glory, whether he blasphemes in word or by deed. Behold, EVERY form of idolatry shall be utterly destroyed in that day! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"My sons, you fear a war which is waged already, a battle that has already come. And though I have said that I require peace in the houses of My servants, there can be no peace while abominations stand. Therefore, if peace is taken from a house in the name of righteousness, to rectify that which has polluted My name and My glory, this is acceptable with Me. For you have shown yourselves worthy of Me"},{t:"fn",v:"3"},{t:"text",v:"... Or have you forgotten the sword I bring?"},{t:"fn",v:"4"}]},{type:"poetry",lines:[[{t:"italic",v:"Yet My words are only for those who believe,"},{t:"fn",v:"5"}],[{t:"italic",v:"For those willing to set all these crooked paths straight..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Those who love Me more than these..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 Corinthians 3:16"},2:{type:"note",text:'See: "Regarding the 144,000 Witnesses"',url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},3:{type:"scripture",ref:"Matthew 10:37-38"},4:{type:"scripture",ref:"Matthew 10:34-36"},5:{type:"scripture",ref:"1 Corinthians 14:22"}},nkjv:{"1 Corinthians 3:16":"Do you not know that you are the temple of God and that the Spirit of God dwells in you?","Matthew 10:37-38":"37. He who loves father or mother more than Me is not worthy of Me. And he who loves son or daughter more than Me is not worthy of Me. 38. And he who does not take his cross and follow after Me is not worthy of Me.","Matthew 10:34-36":"34. \u201CDo not think that I came to bring peace on earth. I did not come to bring peace but a sword. 35. For I have come to \u2018set a man against his father, a daughter against her mother, and a daughter-in-law against her mother-in-law\u2019; 36. and \u2018a man\u2019s enemies will be those of his own household.\u2019","1 Corinthians 14:22":"Therefore tongues are for a sign, not to those who believe but to unbelievers; but prophesying is not for unbelievers but for those who believe."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/tear-down-every-whitewashed-wall-of-abomination-6",videoVoiceUrl:"https://www.youtube.com/watch?v=Bc1Bth495AM&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=15",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Man's Holidays vs. God's Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"}],num:15,prevLetter:{id:"do-not-look-back-escape-to-the-fathers-house",title:"Do Not Look Back; Escape to The Fathers House"},nextLetter:{id:"most-needful",title:"Most Needful"}},{id:"most-needful",title:"Most Needful",date:"12/11/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Sister in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"A sister in Christ asked a question regarding the blood red moons of the past occurring on Holy Days and coinciding with significant events in Israel, and future blood red moons occurring on Holy Days, and what the connection might be."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved, why do you seek after signs and search elsewhere for proof?"},{t:"italic",v:"Since the creation of the world My invisible attributes, both My eternal power and My divine nature, have been clearly seen, readily perceived by those I have made, leaving them without excuse, as it is written."},{t:"fn",v:"1"},{t:"text",v:"Even so, there will indeed be many signs. And those who have eyes to see will look upon them and acknowledge Me, and those who have received wisdom shall understand. Yet I ask you, what is most needful and which is the greatest sign of all? And what of all these Letters I have put forth, are they not a sign in and of themselves? Or is your faith still in need of supports to prop it up, due to your lack of trust and a heart which remains unwilling? For I have indeed lifted up My voice to this lost and dying generation, I have spoken plainly to My people, yet few have ears to hear, few stop and pay attention."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus only those who seek that which is first,"}],[{t:"italic",v:"Who fill themselves up with that which is most needful,"}],[{t:"italic",v:"Will finish the day with strength enough to face tomorrow..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore seek Me out at every opportunity,"}],[{t:"italic",v:"Whether for a moment or for the hour,"}],[{t:"italic",v:"That you may be renewed in My presence,"}],[{t:"italic",v:"Looking always to The Blessed Hope,"}],[{t:"italic",v:"Having tasted of it while in waiting..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Romans 1:20 (NAS)"}},nkjv:{"Romans 1:20 (NAS)":"For since the creation of the world His invisible attributes, that is, His eternal power and divine nature, have been clearly perceived, being understood by what has been made, so that they are without excuse."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/most-needful",videoVoiceUrl:"https://www.youtube.com/watch?v=Kz0LdWSyT94&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=16",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Prayer",url:"https://answersonlygodcangive.com/Regarding_Prayer"},{label:"Regarding The Ascension and The Blessed Hope",url:"https://answersonlygodcangive.com/Regarding_The_Ascension_and_The_Blessed_Hope"}],num:16,prevLetter:{id:"tear-down-every-whitewashed-wall-of-abomination",title:"Tear Down Every Whitewashed Wall of Abomination"},nextLetter:{id:"deplorable-traditions",title:"Deplorable Traditions"}},{id:"deplorable-traditions",title:"Deplorable Traditions",date:"12/15/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the holidays of men)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"All these things which these modern people do in My name, though they be called Christian or otherwise, I DO HATE! I loathe the sight of them! - Dead works! Abominations! Deplorable traditions, in where they have despised both Me and My Word! Behold, even the churches of men pollute My name and My glory. Day after day, they twist the Scriptures and tread upon My Holy Law, in an effort to uphold their own way. Behold, from house to house they pollute the name of The Messiah, desecrating The Glory of My majesty, as they attempt to place the name of The Holy One upon their perverse traditions! Reason has altogether departed from them, the truth is cast down, and righteousness has perished!"},{t:"fn",v:"1"},{t:"text",v:"For not one is willing to embrace Me as I truly am!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to the churches of men:"},{t:"text",v:"Your worship is in vain! Your offerings are not accepted! Behold, even your prayers are an abomination! For you do always turn your ear away from hearing The Holy Law"},{t:"fn",v:"2"},{t:"text",v:", and have not ceased from practicing those things I hate! Modern Pharisees! Arrogant children! Behold, you have made for yourselves a graven image, an intricately woven tapestry of man-made doctrine and idolatrous tradition, interlacing sin with sin, all in the name of your \u201CJesus,\u201D another messiah which you have created in your own image!"},{t:"fn",v:"3"},{t:"text",v:"Desecration! Blasphemy! YOU KNOW NEITHER ME, NOR MY WORD!"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus I call all those who desire to serve Me"}],[{t:"italic",v:"In truth and righteousness, to tear down"}],[{t:"italic",v:"Every whitewashed wall of abomination!"},{t:"fn",v:"4"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For this is not a light matter with Me,"}],[{t:"italic",v:"But carries great weight, filling the cup of"}],[{t:"italic",v:"My indignation throughout your generations!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, I shall surely pour out!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until My wrath is satisfied and My anger has abated,"}],[{t:"italic",v:"Until the whole breadth of the whole earth"}],[{t:"italic",v:"Is cleansed in the heat of My fury!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Jeremiah 7:28"},2:{type:"scripture",ref:"Proverbs 28:9"},3:{type:"note",text:'See: "Regarding "Another Messiah""',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},4:{type:"note",text:'Also read: "Tear Down Every Whitewashed Wall of Abomination"',url:"https://www.thevolumesoftruth.com/Tear_Down_Every_Whitewashed_Wall_of_Abomination#Tear_Down_Every_Whitewashed_Wall_of_Abomination",link:{collection:"Volume Five",letterTitle:"Tear Down Every Whitewashed Wall of Abomination"}}},nkjv:{"Jeremiah 7:28":"\u201CSo you shall say to them, \u2018This is a nation that does not obey the voice of the LORD their God nor receive correction. Truth has perished and has been cut off from their mouth.","Proverbs 28:9":"One who turns away his ear from hearing the law, Even his prayer is an abomination."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/deplorable-traditions-6",videoVoiceUrl:"https://www.youtube.com/watch?v=-5vr9cmmG4w&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=17",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:'"In My Name"',url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#.22In_My_Name.22"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord_.28Section_One.29"},{label:"The Prayers of Those Who Forsake The Law Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Prayers_of_Those_Who_Forsake_The_Law_Are_an_Abomination_to_The_Lord"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_%22Another_Messiah%22"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Man's Holidays vs. God's Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"}],num:17,prevLetter:{id:"most-needful",title:"Most Needful"},nextLetter:{id:"as-it-was-in-the-days-of-noah-so-shall-the-coming-of-the-son-of-man-be",title:"As It Was in the Days of Noah, So Shall the Coming of The Son of Man Be"}},{id:"as-it-was-in-the-days-of-noah-so-shall-the-coming-of-the-son-of-man-be",title:"As It Was in the Days of Noah, So Shall the Coming of The Son of Man Be",date:"12/21/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The words of scoffers come forth from a hard and troubled heart, from a place void of understanding. Their words are like chaff, their every lofty assertion dust carried away by the wind. As a ship tossed about by rough seas, so is the plight of the ungodly; in a dark sea of confusion, they attempt to sail against every wind of doctrine which opposes them. Yet all their toil is in vain. For I am The Only Truth, I am God alone! And behold, all I have spoken is established and shall be; My Word yields to no man. For I tell you the truth, the coming of The Lord is a terror to all who say they know Me, yet do not really know Me, a terror to all who deny Me and to all who offend. Therefore let the feet of the desolate stumble, and the ways of the ungodly return atop their own head - JUDGMENT for the rebellious! PUNISHMENT for the wicked! CALAMITY upon all nations who offend!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore as it was in the days of My servant Noah,"}],[{t:"italic",v:"So shall it be with My faithful servants of this day also;"}],[{t:"italic",v:"And as it was then, so shall it be in the Day of The Lord\u2019s Anger..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The door shall be shut!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And upon the earth shall I rain down judgment,"}],[{t:"italic",v:"And bring up horrible calamity from beneath;"}],[{t:"italic",v:"The storehouses shall be opened and My wrath shall overflow..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until I have covered the face of the whole earth in My vengeance,"}],[{t:"italic",v:"Until I have wiped away all that offends,"}],[{t:"italic",v:"Until I have utterly destroyed the kingdoms of men"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord Most High, He who comes With justice and recompense for all nations."}],footnotes:{1:{type:"note",text:'See: "a flood of judgment"',url:"https://www.thevolumesoftruth.com/Vengeance_Is_Mine,_I_Shall_Repay#:~:text=Behold%2C%20in%20the,GOD%20OF%20ISRAEL...",link:{collection:"Volume Seven",letterTitle:"Vengeance Is Mine, I Shall Repay",excerpt:"Behold, in the heat of My indignation, I shall surely cleanse the face of the earth"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/as-it-was-in-the-days-of-noah-so-shall-the-coming-of-the-son-of-man-be",videoVoiceUrl:"https://www.youtube.com/watch?v=Gyx4lyZGjiY&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=18",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding the Days of Noah",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#The_Coming_of_The_Lord"}],num:18,prevLetter:{id:"deplorable-traditions",title:"Deplorable Traditions"},nextLetter:{id:"treasuries-of-wrath-and-mercy",title:"Treasuries of Wrath and Mercy"}},{id:"treasuries-of-wrath-and-mercy",title:"Treasuries of Wrath and Mercy",date:"1/3/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Behold, the time has come for wrath and recompense, for the anger of The Lord to be put on open display..."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to His servants:"},{t:"text",v:"Beloved ones, the time of ignorance has passed. Therefore blow this Trumpet, making use of every platform at your disposal; shout My words from the rooftops and cause an uproar, trumpet My wrath and reveal My anger; draw back from no man. Indeed serve My words hot, and let their palates be set ablaze by My fierce rebuke. Show this most wicked generation no mercy in your speech, make no concessions, for My Word yields to no man. For My words are poured out like rain, and My voice shakes the house like thunder, My every word a hailstone released from the treasury of hail, which I have reserved for the Time of Trouble. Behold, My wrath is a consuming fire, a mighty earthquake, encompassing the breadth of the whole earth!"}]},{type:"para",segments:[{t:"text",v:"Yet I ask you, what is the treasury of My mercy reserved for those who repent? And what are the depths of My compassion for the little ones who suffer at the hands of men in this world? Does not My anger burn hot against all those who forsake or do harm to My little ones?! For as it is written:"},{t:"italic",v:"It would be better for them if a millstone were hung around their neck, and they were drowned in the depths of the sea, than to suffer My wrath over these little ones!"},{t:"fn",v:"1"},{t:"text",v:"Thus in these words alone shall mercy be found, in these words alone is there hope and salvation for the penitent:"},{t:"italic",v:"\u201CREPENT! And turn from your evil ways,\u201D"},{t:"text",v:"and all such similar words, which I have spoken and shall continue to speak, says The Lord."}]}],footnotes:{1:{type:"scripture",ref:"Matthew 18:6-7"}},nkjv:{"Matthew 18:6-7":"6. \u201CWhoever causes one of these little ones who believe in Me to sin, it would be better for him if a millstone were hung around his neck, and he were drowned in the depth of the sea. 7. Woe to the world because of offenses! For offenses must come, but woe to that man by whom the offense comes!"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/treasuries-of-wrath-and-mercy",videoVoiceUrl:"https://www.youtube.com/watch?v=ma1o7EMh5PE&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=19",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"}],num:19,prevLetter:{id:"as-it-was-in-the-days-of-noah-so-shall-the-coming-of-the-son-of-man-be",title:"As It Was in the Days of Noah, So Shall the Coming of The Son of Man Be"},nextLetter:{id:"a-shout-and-a-trumpet",title:"A Shout and a Trumpet"}},{id:"a-shout-and-a-trumpet",title:"A Shout and a Trumpet",date:"1/6/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"A brother in Christ asked: Is it OK to tell people The Lord is returning this year to gather, or is this date-setting?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Have I not spoken to this already?"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Therefore before I gather, say to them:"},{t:"italic",v:"\u201CBehold, The Bridegroom is coming! Go out to meet Him!\u201D"}]},{type:"para",segments:[{t:"text",v:"And after, say to them:"},{t:"italic",v:"\u201CI am a voice crying out in the midst of desolations and strong judgment, shouting the name of glory and pure righteousness, a trumpet of God until the end - MAKE WAY FOR THE COMING OF THE LORD!\u201D"}]}],footnotes:{1:{type:"scripture",ref:"Matthew 24:36,42"}},nkjv:{"Matthew 24:36,42":"24:36 \u2014 \u201CBut of that day and hour no one knows, not even the angels of heaven, but My Father only. | 24:42 \u2014 Watch therefore, for you do not know what hour your Lord is coming."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-shout-and-a-trumpet",videoVoiceUrl:"https://www.youtube.com/watch?v=HPVUVvssKfA&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=20",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:20,prevLetter:{id:"treasuries-of-wrath-and-mercy",title:"Treasuries of Wrath and Mercy"},nextLetter:{id:"false-miracles-and-lies-deceived-and-ignorant-people",title:"False Miracles and Lies, Deceived and Ignorant People"}},{id:"false-miracles-and-lies-deceived-and-ignorant-people",title:"False Miracles and Lies, Deceived and Ignorant People",date:"1/24/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding modern reports of people being raised from the dead and coming back from death)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"No man shall raise the dead, save I live in that man. And no account of one raising the dead in My name is true, save it was given them by Me to do so. Or have you never read this Scripture:"},{t:"italic",v:"It is I who has done it?"},{t:"text",v:"For I have indeed raised the dead through My servants in times past, and I shall do so again, yet this time is not yet. In that day My witnesses shall go out ahead of Me, preparing My way before Me, and by signs such as this shall My coming glory be revealed. For through them I shall indeed perform many signs and wonders, in the sight of many witnesses, to the glory of My name. Yet no man or woman in all the earth shall do these things, save those I send. Therefore believe no report of one returning from death, speaking false tales. For as it is written:"},{t:"italic",v:"The dead know nothing at all,"},{t:"fn",v:"1"},{t:"italic",v:"for all their thoughts have perished with them."},{t:"fn",v:"2"},{t:"text",v:"For satan shall indeed deceive many; and as it is written:"},{t:"italic",v:"False messiahs and false prophets will rise and show great signs and wonders, to deceive, if possible, even the elect."},{t:"fn",v:"3"},{t:"text",v:"Yet I tell you the truth, all is a lie, a very clever, well-planned deception; no miracle is found - only illusion and misdirection, accompanied by propaganda and dark sentences, great delusion to the darkness of many faces."}]},{type:"poetry",lines:[[{t:"italic",v:"For there is but One in whom"}],[{t:"italic",v:"The fullness of God dwells..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One alone who has the power to"}],[{t:"italic",v:"Revive the dead and destroy the wicked..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One alone who holds all the keys,"}],[{t:"italic",v:"Even over death and Sheol"},{t:"fn",v:"4"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM HE!"}]]}],footnotes:{1:{type:"scripture",ref:"Ecclesiastes 9:5"},2:{type:"scripture",ref:"Psalm 146:4 (NAS)"},3:{type:"scripture",ref:"Matthew 24:24"},4:{type:"scripture",ref:"Revelation 1:18 (HNV)"}},nkjv:{"Ecclesiastes 9:5":"For the living know that they will die; But the dead know nothing, And they have no more reward, For the memory of them is forgotten.","Psalm 146:4 (NAS)":"His spirit departs, he returns to the earth; On that very day his plans perish.","Matthew 24:24":"For false christs and false prophets will rise and show great signs and wonders to deceive, if possible, even the elect.","Revelation 1:18 (HNV)":"and the Living one. I was dead, and behold, I am alive forever and ever. Amen. I have the keys of Death and of Hades."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/false-miracles-and-lies-deceived-and-ignorant-people",videoVoiceUrl:"https://www.youtube.com/watch?v=7f8mslxM5Sg&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:21,prevLetter:{id:"a-shout-and-a-trumpet",title:"A Shout and a Trumpet"},nextLetter:{id:"sons-of-the-devil",title:"Sons of the Devil"}},{id:"sons-of-the-devil",title:"Sons of the Devil",date:"1/28/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding those who say The Volumes of Truth are from the devil, who cite the Letters regarding Judas as proof)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"That which glorifies Me can have only one source. And that which denies My sacrifice, as though it were not enough, steals from My glory, and this also has one source. For all who deny Me and steal from My sacrifice, to pollute it, have become sons of their father, the devil. And all who reject My words spoken to this generation reject Me, and shall by no means escape the Day of The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/sons-of-the-devil",videoVoiceUrl:"https://www.youtube.com/watch?v=WKzYveFb9Do&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=22",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Judas Iscariot",url:"https://answersonlygodcangive.com/Regarding_Judas_Iscariot"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:22,prevLetter:{id:"false-miracles-and-lies-deceived-and-ignorant-people",title:"False Miracles and Lies, Deceived and Ignorant People"},nextLetter:{id:"prophets-hananiah",title:"Prophets Hananiah"}},{id:"prophets-hananiah",title:"Prophets Hananiah",date:"1/29/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding modern false prophets)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The false prophets gather, and the deceitful teachers increase in number like a plague; a great company who pollute My holy name in one accord, to the blaspheming of the Spirit; an ever-increasing multitude of self-appointed apostles, prophets and teachers, whose every word I despise in My zeal!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold the prophets Hananiah!"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And of his reward, they are fully worthy!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Jeremiah 28:15-17"}},nkjv:{"Jeremiah 28:15-17":"15. Then the prophet Jeremiah said to Hananiah the prophet, \u201CHear now, Hananiah, the LORD has not sent you, but you make this people trust in a lie. 16. Therefore thus says the LORD: \u2018Behold, I will cast you from the face of the earth. This year you shall die, because you have taught rebellion against the LORD.\u2019 \u201D 17. So Hananiah the prophet died the same year in the seventh month."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/prophets-hananiah",videoVoiceUrl:"https://www.youtube.com/watch?v=3lbonmQZvh0&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=23",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"}],num:23,prevLetter:{id:"sons-of-the-devil",title:"Sons of the Devil"},nextLetter:{id:"i-am-come",title:"I AM COME"}},{id:"i-am-come",title:"I AM COME",date:"2/4/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My sons and daughters, have you not discerned? How is it you have yet to consider, to see with greater eyes? Beloved, let go of your preconceived notions and biased beliefs, put away all your self-serving expectations, and humble yourselves, that your understanding may be set free."}]},{type:"para",segments:[{t:"text",v:"Therefore hear now, and consider these three words: I AM COME. Consider the whole of prophecy, and bow down; consider all My words, from the foundation of the world even to this day, and be greatly humbled; consider the vastness of My Glory and offer up perfect praise! Beloved, as I AM, so also is My Word. And so I have spoken this one phrase in your hearing, even many times. Yet not one has truly discerned, not one among you has truly considered the scope of its meaning. For the whole of Scripture speaks to one end, the glory of The Holy One, He who is and was and is to come. And as the glory of The Messiah is fulfilled in this: One Way, One Truth and One Life, even the whole of The Scriptures in One, so in like manner have I revealed it to you, once again."}]},{type:"poetry",lines:[[{t:"italic",v:"For the fulfillment of all things"}],[{t:"italic",v:"Has come, and is revealed in this:"}],[{t:"stanza-break"}],[{t:"italic",v:"I AM COME."}],[{t:"stanza-break"}],[{t:"italic",v:"The One who was has come;"}],[{t:"italic",v:"The One who is, is come;"}],[{t:"italic",v:"The One who is to come is coming"}],[{t:"italic",v:"Quickly to fulfill and complete."}]]},{type:"poetry",lines:[[{t:"italic",v:"HISTORY HAS AN END."}]]},{type:"poetry",lines:[[{t:"italic",v:"And His name is The Great I AM,"}],[{t:"italic",v:"The Holy One of Israel..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA-YAHUWAH..."}]]},{type:"poetry",lines:[[{t:"italic",v:"IMMANU EL!"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-come",videoVoiceUrl:"https://www.youtube.com/watch?v=FgwxrBnoKzI&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=24",videoMusicUrl:"https://www.youtube.com/watch?v=DAZ4DhXMCwY&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=8",relatedTopics:[{label:'The Coming of The Lord - "I AM COME"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_AM_COME"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Discernment",url:"https://answersonlygodcangive.com/Main_Page#Discernment"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"}],num:24,prevLetter:{id:"prophets-hananiah",title:"Prophets Hananiah"},nextLetter:{id:"pride-goes-before-a-fall",title:"Pride Goes Before a Fall"}},{id:"pride-goes-before-a-fall",title:"Pride Goes Before a Fall",date:"2/8/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding a brother in Christ who fell away)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Why do you wane in the heat of persecution, little flock? And how is it you are taken aback, when one is led away from the Truth, while walking in disobedience? Has not the pride of man revealed such things? Where is your trust? Or have you forgotten the knowledge of The Holy, by which I have opened your understanding, and My glory which is put on open display? Little flock, your brother remains My son, and I shall indeed go out after him, severely punishing all who lead My people astray, even with sickness and death. Did I not offer your brother his calling and give him much correction, as any good father should? Yet My sons are grown, and they must choose to obey. And what shall I do when My sons choose to go their own way, running far from Me, squandering that which I had given them?"},{t:"fn",v:"1"},{t:"text",v:"Beloved, I shall surely let them go, I shall let them run far away; I shall let them do all they have purposed in their hearts to do, until they can run no further, until the bitterness of deceit wears them out and their pride weighs heavily upon them, and they fall hard upon the ground. Then shall they stop and consider, turning back to look, and there will I be, waiting."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear and understand, beloved:"},{t:"text",v:"The moment pride enters a man, the moment he stands in front of Me, to look elsewhere, is the same moment My hand is removed. For I have shown you, My servants, what is good and that which I require:"},{t:"italic",v:"That you should do justly, love mercy, and walk humbly with your God."},{t:"fn",v:"2"},{t:"text",v:"Yet how can one behold My face while looking elsewhere, seeking glory for themselves? And how can one who has stepped in front of Me walk in My footsteps? Beloved, how shall one who runs away from Me, to tread another path, take My hand?"}]},{type:"poetry",lines:[[{t:"italic",v:"And so they must first be greatly humbled,"}],[{t:"italic",v:"They must fall hard upon the ground..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until the revelation of their error comes"}],[{t:"italic",v:"Full circle, until they are truly ready"}],[{t:"italic",v:"To give up their life for My sake"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Luke 15:11-32"},2:{type:"scripture",ref:"Micah 6:8"},3:{type:"scripture",ref:"Matthew 16:25"}},nkjv:{"Luke 15:11-32":"11. Then He said: \u201CA certain man had two sons. 12. And the younger of them said to his father, \u2018Father, give me the portion of goods that falls to me.\u2019 So he divided to them his livelihood. 13. And not many days after, the younger son gathered all together, journeyed to a far country, and there wasted his possessions with prodigal living. 14. But when he had spent all, there arose a severe famine in that land, and he began to be in want. 15. Then he went and joined himself to a citizen of that country, and he sent him into his fields to feed swine. 16. And he would gladly have filled his stomach with the pods that the swine ate, and no one gave him anything. 17. \u201CBut when he came to himself, he said, \u2018How many of my father\u2019s hired servants have bread enough and to spare, and I perish with hunger! 18. I will arise and go to my father, and will say to him, \u201CFather, I have sinned against heaven and before you, 19. and I am no longer worthy to be called your son. Make me like one of your hired servants.\u201D \u2019 20. \u201CAnd he arose and came to his father. But when he was still a great way off, his father saw him and had compassion, and ran and fell on his neck and kissed him. 21. And the son said to him, \u2018Father, I have sinned against heaven and in your sight, and am no longer worthy to be called your son.\u2019 22. \u201CBut the father said to his servants, \u2018Bring out the best robe and put it on him, and put a ring on his hand and sandals on his feet. 23. And bring the fatted calf here and kill it, and let us eat and be merry; 24. for this my son was dead and is alive again; he was lost and is found.\u2019 And they began to be merry. 25. \u201CNow his older son was in the field. And as he came and drew near to the house, he heard music and dancing. 26. So he called one of the servants and asked what these things meant. 27. And he said to him, \u2018Your brother has come, and because he has received him safe and sound, your father has killed the fatted calf.\u2019 28. \u201CBut he was angry and would not go in. Therefore his father came out and pleaded with him. 29. So he answered and said to his father, \u2018Lo, these many years I have been serving you; I never transgressed your commandment at any time; and yet you never gave me a young goat, that I might make merry with my friends. 30. But as soon as this son of yours came, who has devoured your livelihood with harlots, you killed the fatted calf for him.\u2019 31. \u201CAnd he said to him, \u2018Son, you are always with me, and all that I have is yours. 32. It was right that we should make merry and be glad, for your brother was dead and is alive again, and was lost and is found.\u2019 \u201D","Micah 6:8":"He has shown you, O man, what is good; And what does the LORD require of you But to do justly, To love mercy, And to walk humbly with your God?","Matthew 16:25":"For whoever desires to save his life will lose it, but whoever loses his life for My sake will find it."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/pride-goes-before-a-fall",videoVoiceUrl:"https://www.youtube.com/watch?v=gl0hcoJs2qw&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:25,prevLetter:{id:"i-am-come",title:"I AM COME"},nextLetter:{id:"those-who-walk-in-my-ways-walk-in-the-light-yet-those-who-forsake-the-way-of-the-lord-abide-in-darkness-already",title:"Those Who Walk in My Ways Walk in The Light, Yet Those Who Forsake The Way of The Lord Abide in Darkness Already"}},{id:"those-who-walk-in-my-ways-walk-in-the-light-yet-those-who-forsake-the-way-of-the-lord-abide-in-darkness-already",title:"Those Who Walk in My Ways Walk in The Light, Yet Those Who Forsake The Way of The Lord Abide in Darkness Already",date:"2/9/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"A fellowship participant asked: Will you all pray for a sister in Christ? She is going through hard times, and is convinced that God is trying to kill her, or something along those lines."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I know all My sheep. And though they wander and betray their own hearts, I do not punish them; they punish themselves. Therefore, woe to all who lay blame at the feet of The Lord! I do not stalk My sheep, as though they were prey! Yet I do go out after them, leaving the ninety-nine to seek out the one who has gone astray."},{t:"fn",v:"1"},{t:"text",v:"And those who know My voice come running."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, let no one pollute My love anymore!"}],[{t:"italic",v:"Nor let the remarks of the wayward enter in..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Turn to God!"}]]},{type:"poetry",lines:[[{t:"italic",v:"And seek to know My ways,"}],[{t:"italic",v:"That you may walk in them..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For in doing so shall you come"}],[{t:"italic",v:"To know Me as I truly am..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The Father and The Son are One."}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 18:12"}},nkjv:{"Matthew 18:12":"\u201CWhat do you think? If a man has a hundred sheep, and one of them goes astray, does he not leave the ninety-nine and go to the mountains to seek the one that is straying?"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/those-who-walk-in-my-ways-walk-in-the-light-yet-those-who-forsake-the-way-of-the-lord-abide-in-darkness-already",videoVoiceUrl:"https://www.youtube.com/watch?v=9yXJUxyPLpw&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=26",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:26,prevLetter:{id:"pride-goes-before-a-fall",title:"Pride Goes Before a Fall"},nextLetter:{id:"i-am-he",title:"I AM HE"}},{id:"i-am-he",title:"I AM HE",date:"2/17/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My sons and daughters, from the beginning, I AM WHO I AM and shall be. Even to the end, I AM HE. From everlasting to everlasting, I AM. In this shall you find rest and know peace, says The Lord."}]},{type:"para",segments:[{t:"text",v:"Therefore no longer bind yourselves to what you see, nor concern yourselves with the things of this world and its evil ways. Free yourselves by the knowledge I have given you, by the understanding that I AM WHO I AM, freedom in the knowing I AM HE. Beloved ones, I have defeated the world, I have overcome your sins; death is put to death because of Me. Behold, I am risen, death is turned backward - only life is and shall be. Lo, I have defeated you also, if you would only surrender your life. For I gave up My life in place of yours, so you may receive of My life. Therefore, I ask you, how long will you withhold? How long will you wait before you let go? When will you fly? When will you believe? Believe, and you shall also know! For I have already told you, peace is in the knowing that I AM WHO I AM, and you are in life because of Me. Beloved, you were made for Me, created for love\u2019s purpose. I created you in My image, and gave you My breath, My life. Therefore, this is life: I AM HE!..."},{t:"italic",v:"Beloved, you worry, yet I AM HE. You weep, yet I AM HE. You stumble, yet I AM HE. Your hearts tear and break over all these sorrows, yet I AM HE. You struggle and are in turmoil, you feel lost, yet I AM HE. You grasp at the wind and have no understanding, yet I AM HE. You are persecuted by those you love, yet I AM HE. The world hates you, yet I AM HE. Everything you have is passing away, yet I AM HE. Death comes to take you into darkness, yet I AM HE!"}]},{type:"poetry",lines:[[{t:"italic",v:"Do you not understand?! I AM ENOUGH! -"}],[{t:"italic",v:"The One who sees, The One who knows..."}]]},{type:"poetry",lines:[[{t:"italic",v:"No matter the time or the season,"}],[{t:"italic",v:"In every moment of your life, I AM HE!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-he",videoVoiceUrl:"https://www.youtube.com/watch?v=jAXwrnm0-kI&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=27",videoMusicUrl:"https://www.youtube.com/watch?v=PLeBXHVZFT4&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=14",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:27,prevLetter:{id:"those-who-walk-in-my-ways-walk-in-the-light-yet-those-who-forsake-the-way-of-the-lord-abide-in-darkness-already",title:"Those Who Walk in My Ways Walk in The Light, Yet Those Who Forsake The Way of The Lord Abide in Darkness Already"},nextLetter:{id:"brought-to-a-close",title:"Brought to a Close"}},{id:"brought-to-a-close",title:"Brought to a Close",date:"3/2/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved little flock, it is time for you to choose. It is time for your trust to be tried and your faith tested, to reveal of what sort it truly is."}]},{type:"para",segments:[{t:"text",v:"Thus I am bringing this table to a close. For you did not seek My face when I called to you. And when I gave you correction, you turned to Me a deaf ear. And of My servants, these also you refused to hear. Therefore because you have refused Me, and because you have found fault with My servants, as you continually speak one against the other, wherein pride and judgment grabs hold and forgiveness flees away, this table is brought to a close. And because some of you refuse to be separate from those who have hated both Me and My Word, who also speak evil of My servants, this table is brought to a close. And because some of you refuse to reach out the hand and give to those in need, and still others do so begrudgingly, this table is brought to a close. Beloved, those seated at My table are given much, and ALL I have spoken is required of them. Thus some of you have treated My table with contempt, while still others have likened My table unto the churches of men, whose ways are an abhorrence to Me, whose doctrines and traditions I hate! And worse still, some of you have built your faith upon My servants, using this table to prop up that which remains altogether lacking within you. I will not share My glory! Nor is there any other stone upon which one shall be broken, nor any other foundation upon which one shall stand. Therefore, this table is brought to a close."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, it is time to choose, to make your decision..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It is time to bring your hearts forward, and be healed,"}],[{t:"italic",v:"To make your repentance full; "},{t:"fn",v:"1"},{t:"italic",v:""}],[{t:"italic",v:"Or to My bitter sadness, fall away,"}],[{t:"italic",v:"And return to the world and its evil ways..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It is time to fall into Me unreservedly;"}],[{t:"italic",v:"Or to depart, and walk through dry places..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'Also read: "True Repentance"',url:"https://www.thevolumesoftruth.com/True_Repentance",link:{collection:"Letters to The Lord's Little Flock",letterTitle:"True Repentance"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/brought-to-a-close",videoVoiceUrl:"https://www.youtube.com/watch?v=oXO3hMOkAiQ&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=28",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding Unforgiveness",url:"https://answersonlygodcangive.com/Regarding_Unforgiveness"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"}],num:28,prevLetter:{id:"i-am-he",title:"I AM HE"},nextLetter:{id:"treason",title:"Treason"}},{id:"treason",title:"Treason",date:"3/7/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"The kingdoms of men shall raise themselves up, though night has fallen; behold, out of deep darkness, the kingdoms of men shall rise and make themselves one by treason; by many deceits and false promises, by vanities and vain flatteries, by the heaping up of lies, shall they come together as one. They shall raise themselves up, boasting unity and peace, and safety from the hand of The Almighty, until their loftiness flies high above all kingdoms, from those of ancient times even to this day..."}]},{type:"para",segments:[{t:"italic",v:"YET THERE SHALL BE NO PEACE! Says The Lord. For I shall bring calamity in waves! Behold, the weight of My punishment shall increase by measure, bringing forth destruction without respite! Escape shall flee away, safety shall become a distant memory and no shelter shall be found, forcing the rebellious into the rocks, the mighty into the clefts of the rocks, and the kings of the earth into the caves of the mountains! From the least to the greatest, they shall all seek to hide themselves from the face of Him who sits on the throne and from the wrath of The Lamb!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the unity of the nations shall be eaten up,"}],[{t:"italic",v:"As the caterpillar devours the newly sprouted vine,"}],[{t:"italic",v:"As the worms beneath the ground eat up the roots!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"All shall wither, until the fire comes"}],[{t:"italic",v:"To set the whole field ablaze!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"By a spark and by a flame of fire,"}],[{t:"italic",v:"By a strike from roiling clouds,"}],[{t:"italic",v:"Shall the fire be kindled by My own hand!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/treason-5",videoVoiceUrl:"https://www.youtube.com/watch?v=QwUtdWO55oE&list=PLE8FlkxQPQkNIgyNvi80ZOJtvD5LuxQ3J&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:29,prevLetter:{id:"brought-to-a-close",title:"Brought to a Close"},nextLetter:null}],LETTERS_V6_PREFACE=null,LETTERS_V6=[{id:"pangs",title:"Pangs",date:"3/14/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"What is the high branch of the palm tree to that of the weeping willow? For they know not each other\u2019s place. Each bears seed after its own kind, yet the ground beneath remains unyielding. And without the rain, the leaf fades and the seed flees back into the dust of the ground, unable to rise again. Therefore are they cut down as the cedars; they are broken and they are toppled when calamity comes to claim them, washed away. And who will mourn their passing or search out their seed, that they might be revived in another place?"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, O peoples of the earth; stop and consider and be broken in pieces:"},{t:"text",v:"For as I have spoken, so I speak; as I have done, so shall it be again. And though you make an uproar, and band together and make for yourselves a name, you shall surely be broken in pieces! Yes arm yourselves, prepare and come out, stand up and fight, yet you will surely be broken in pieces! For I am The Lord, and I do not change!"}]},{type:"para",segments:[{t:"italic",v:"Behold, a mournful cry is heard in the midst of every nation, bitter weeping comes forth from the coastlands, and the sound of gnashing teeth breaks out in every corner. For the Day of The Lord has come! For the peoples of the earth have forgotten Me, the nations have forsaken Me, and My own people hate the sound of My voice; indeed they refuse to walk in My ways, neither will they receive correction! Therefore the pangs must increase, the bearing down must come quickly, lest the seed be lost and the child fail to come forth. For if I do not bring forth, says The Lord, the child shall surely die before seeing the light of day... It is time."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/pangs-7",videoVoiceUrl:"https://www.youtube.com/watch?v=05ZsxUAvIWo&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=1",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:1,prevLetter:null,nextLetter:{id:"reasonable-service",title:"Reasonable Service"}},{id:"reasonable-service",title:"Reasonable Service",date:"3/25/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Blessed is that servant of Mine who seeks out the poor, whose heart is eager to help the needy, for they know My ways and seek to please Me. Blessed also is My servant who gives out of the abundance they have received, for they walk in My ways. Yet most blessed is My servant who gives from their lack, for they do justly, love mercy, and walk humbly with their God; indeed, they have understood. Yet woe to those who ignore the poor and draw back their hand from the needy, while they sit at ease in their abundance. For destitution is coming, and shall be born out of great desolation, in the day I take away their abundance and leave their houses desolate. Woe also to those who say they are My servants, yet refuse to help those in need, for only tears and sorrow await them. And woe to those who fail to give even the smallest amount, claiming they are in lack, for they have no trust, having learned nothing from the poor widow."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Little flock, have you learned nothing from My Word? Have you so quickly forgotten My Letters, in where I have taught you the way in which you should walk? Indeed, who you choose defines what you do, as I have already told you."},{t:"fn",v:"2"},{t:"text",v:"And who are the poor and the needy? How have you treated them, while entreating Me? Do not lie to yourselves, beloved ones. Every one of you who sit at this table want for nothing. Shall you mince words over a dollar, while others sit upon the ground seeking to draw water from a pit? Shall you covet five dollars or even ten as you drive about in your automobiles, while your brothers and sisters abroad willingly walk miles to preach My Word, with joy, even to their dying breath? And still some of you sit at ease in your padded chairs, punching the keys, saying within yourselves,"},{t:"italic",v:"\u201CI am delivered.\u201D"},{t:"text",v:"You are not delivered! From the power of sin, yes, My children, I have delivered you, yet some of you remain married to this world. And those who remain married to another, even to themselves, can by no means be joined unto Me, lest adultery be brought into the house of The Lord. Beloved ones, you are My treasure. Yet some of you count yourselves as first, having loved another more than Me; therefore you must be last. For I search the hearts and minds. And that discipline reserved for the churches of men, is it not also for you, even to a greater degree? Or have you forgotten this Scripture:"},{t:"italic",v:"For everyone to whom much is given, from him much will be required; and to whom much has been committed, of him they will ask the more?"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore choose, make your decision..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It is time..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Mark 12:41-44"},2:{type:"note",text:'See: "Choose Me"',url:"https://www.thevolumesoftruth.com/Choose_Me#:~:text=For%20who%20you%20choose%20defines%20what%20you%20do.",link:{collection:"Volume Four",letterTitle:"Choose Me",excerpt:"For who you choose defines what you do."}}},nkjv:{"Mark 12:41-44":"41. Now Jesus sat opposite the treasury and saw how the people put money into the treasury. And many who were rich put in much. 42. Then one poor widow came and threw in two mites, which make a quadrans. 43. So He called His disciples to Himself and said to them, \u201CAssuredly, I say to you that this poor widow has put in more than all those who have given to the treasury; 44. for they all put in out of their abundance, but she out of her poverty put in all that she had, her whole livelihood.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/reasonable-service-6",videoVoiceUrl:"https://www.youtube.com/watch?v=TRX2dp5X1Ts&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Tithing",url:"https://answersonlygodcangive.com/Regarding_Tithing"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"God Speaks Regarding Covetousness",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Covetousness"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"}],num:2,prevLetter:{id:"pangs",title:"Pangs"},nextLetter:{id:"deliverance",title:"Deliverance"}},{id:"deliverance",title:"Deliverance",date:"4/11/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"poetry",lines:[[{t:"italic",v:"Therefore, My people, call upon the name"}],[{t:"italic",v:"Of The Lord in your darkest hour!..."}],[{t:"stanza-break"}],[{t:"italic",v:"For it is time for the name of mercy and pure righteousness to be glorified!"}],[{t:"italic",v:"It is time for God\u2019s Salvation to be revealed to the first election,"}],[{t:"italic",v:"For the supplications of His people to be fulfilled to the fullest!..."}],[{t:"stanza-break"}],[{t:"italic",v:"LET THEM BE DELIVERED!..."}],[{t:"stanza-break"}],[{t:"italic",v:"Says The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/deliverance-5",videoVoiceUrl:"https://www.youtube.com/watch?v=f1GiDwV4LsU&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=3",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:3,prevLetter:{id:"reasonable-service",title:"Reasonable Service"},nextLetter:{id:"join-not-in-the-error-of-the-people",title:"Join Not in the Error of the People"}},{id:"join-not-in-the-error-of-the-people",title:"Join Not in the Error of the People",date:"4/22/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding Easter)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord YahuShua:"},{t:"text",v:"Those who knowingly celebrate Easter and its deplorable traditions hate My resurrection. Therefore, join not in the error of the people; have no part in their sin. For those who refuse My correction are foolish and must walk through dry places, and those who refuse to repent have secured their place in the valley of death. For the pride of man is a heavy stone, which increases by weight each day it remains unbroken."}]},{type:"poetry",lines:[[{t:"italic",v:"Join NOT in the error of the people;"}],[{t:"italic",v:"Have NO part in their sin!..."}],[{t:"stanza-break"}],[{t:"text",v:"Says The One who sees,"}],[{t:"text",v:"The One who knows."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/join-not-in-the-error-of-the-people",videoVoiceUrl:"https://www.youtube.com/watch?v=J5WcTujU_kU&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=4",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Man's Holidays vs. God's Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"},{label:"Take No Part",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Take_No_Part"}],num:4,prevLetter:{id:"deliverance",title:"Deliverance"},nextLetter:{id:"subject-to-no-man",title:"Subject to No Man"}},{id:"subject-to-no-man",title:"Subject to No Man",date:"4/29/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding self-appointed apostles, prophets and teachers)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Is My Word in need of confirmation by those who say they know Me, yet do not really know Me? Is the Word of My mouth subject to men, whose understanding remains altogether lacking, whose knowledge is corrupt and whose power is of no use at all? Shall My words be made subject to the approval of any self-appointed apostle, prophet or teacher? Shall flesh usurp the things of God? Can mortal man ascend above the throne of The Eternal? Shall the created rule over The Creator, or the corrupt sit as judge over The Holy? Shall any attempt to occupy My throne and not be cast down?! For I tell you the truth, ALL flesh shall be humbled in the Day of The Lord; the whole world shall be bowed down! For all creation is subject to The Word of God, every living creature is put into subjection to The Almighty! Nothing in the earth beneath, or in the heavens above, shall usurp the will of The Most High! Therefore, I ask you, do My servants seek glory for themselves? Have they so highly esteemed themselves, as to name themselves according to the gift? Are they so skilled in knowledge and cleverness of speech, that they may now appoint themselves to a certain office, without first being called? The gift is Mine! And I bestow it upon whomever I wish, whenever I choose! For I call My servants out from among them, I appoint every office, and I Myself number their steps before them. For My gifts are given through The Spirit, and must also be received in Me. They are in no wise open to claim, nor shall anyone on earth assign them. For only those in union with The Messiah are able to walk in them."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus the highly esteemed shall be abandoned,"}],[{t:"italic",v:"And the self-appointed severely abased..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Left to walk through the valley in the"}],[{t:"italic",v:"Great and Terrible Day of The Lord,"}],[{t:"italic",v:"Until death comes to claim them..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Declares The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/subject-to-no-man",videoVoiceUrl:"https://www.youtube.com/watch?v=7tkh9eyESGE&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Spiritual Gifts",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Gifts"}],num:5,prevLetter:{id:"join-not-in-the-error-of-the-people",title:"Join Not in the Error of the People"},nextLetter:{id:"a-blemish-and-a-stain",title:"A Blemish and a Stain"}},{id:"a-blemish-and-a-stain",title:"A Blemish and a Stain",date:"5/6/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, the corrupt doctrines of the churches of men have crept into every corner; near and far, the doctrine of hell and eternal torment is embraced by the people. Yet I tell you the truth, this doctrine is a loathsome spot on every garment worn in the name of truth! A detestable wrinkle within the tapestry of My glory! A horrible interwoven thread by which those who call of themselves Christian pollute My name and mar My image before the people, propagating that which came forth from the mouth of the dragon! THIS DOCTRINE IS EVIL! And must be opposed by all who have received the love of the Truth. For I have indeed spoken to this generation, even as I have spoken in all times past. For I AM THE LORD, The Light in whom there is no darkness at all."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-blemish-and-a-stain",videoVoiceUrl:"https://www.youtube.com/watch?v=NkQ_Y6argXs&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=6",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"False Doctrines Within the Churches of Men Regarding...",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],num:6,prevLetter:{id:"subject-to-no-man",title:"Subject to No Man"},nextLetter:{id:"gathered",title:"Gathered"}},{id:"gathered",title:"Gathered",date:"5/25/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"The day has come, says The Lord, even as I had spoken it to My servant, that it should indeed come. For the heart of man is hard and unyielding, the state of man grievous. Injustice and atrocity increase, evil spreads forth across the land unimpeded. Lo, evil men in authority worship and serve the gods of the earth and bring harm upon My anointed; the outcry is very great. And because of this, the love of My servants is withheld and the hand of My elect is prevented from reaching out, locked doors at every turn."}]},{type:"para",segments:[{t:"text",v:"Yet I tell you, rejoice! For the hand of The Lord is not prevented by any means, the arm of The Lord is in no way shortened! For the name of The Lord shall be exalted, the name of The Lord shall be spoken aloud, and all in the earth shall tremble!..."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the Glory of God breaks through the clouds,"}],[{t:"italic",v:"A mighty trumpet blast sounds in all the earth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"From the heights of the mountains to the deepest depths,"}],[{t:"italic",v:"Life bursts forth in the bodies of the dead!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, a loud voice is heard from Heaven:"}],[{t:"italic",v:"\u201CEARTH, GIVE UP YOUR DEAD!"}],[{t:"italic",v:"BRIDE OF THE BLESSED, COME UP HERE!\u201D"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/gathered",videoVoiceUrl:"https://www.youtube.com/watch?v=YO15kvvWBfo&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:7,prevLetter:{id:"a-blemish-and-a-stain",title:"A Blemish and a Stain"},nextLetter:{id:"delight-in-the-ways-of-the-lord",title:"Delight in the Ways of The Lord"}},{id:"delight-in-the-ways-of-the-lord",title:"Delight in the Ways of The Lord",date:"5/30/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have bestowed many gifts upon this generation, and lo, the small of My flock have received knowledge and revelation beyond compare. Yet I ask you, who has truly received? Who has been humbled by My words and given thanks? Who among all these scattered flocks has taken joy in My gifts? Beloved, who among this great multitude seeks out My will, to know it? And who, among all these so-called believers, takes pleasure in My Law, saying,"},{t:"italic",v:"\u201CI delight to do Your will, O God, for Your Law is written in my heart\u201D?"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Yet My people remain foolish, and this little flock envious. For I tell you the truth: Unrighteous jealousy is the companion of fools. For those who envy also grab hold of jealousy, walking hand in hand with covetousness. Beloved, there is but One who sees, One who knows, only One who searches the hearts and minds - I AM HE. How is it then that My people sit in judgment, judging My Word and My will, resisting My ways as they look upon others with contempt? Shall you also seek to ascend above The Most High?! Shall"},{t:"italic",v:"you"},{t:"text",v:"sit upon My throne?! For I tell you the truth, each time you sit in judgment and question My ways, you walk in satan\u2019s aspirations; you follow in his footsteps!"},{t:"fn",v:"2"},{t:"text",v:"And when I bless another, why do you not take joy in it? And when I correct you, why do you resist and question My ways? Am I not The Lord? Do I not give to each according to their faith, according to that which I see in their heart? Why do you in your arrogance set a line for Me to follow, or think within yourselves there must be a better way? And how is it you continually compare yourselves amongst yourselves, knowing this is unwise?"},{t:"fn",v:"3"},{t:"text",v:"Beloved, I have prepared a place for you! Therefore offer up thanksgiving, and cease from your complaints. Forgive and bless, let go and obey, love one another and wash each other\u2019s feet. Take joy in all I do, especially in that which I bestow upon another. And when I feed you, eat from your own plate and give thanks. Little flock, it is the last hour, yet many of you have stepped backward. Let it be known to you: One who treads the path, going up and down, stepping on and off at their convenience, treads not the path, but is like one who treads water. By no means shall they be able to keep their head above water, nor shall their strength deliver them in the Day of Troubles."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore heed My words, and also do them;"}],[{t:"italic",v:"Be wise in your dealings with Me,"}],[{t:"italic",v:"Humble yourselves and remember..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Blessed are those who run to Me,"}],[{t:"italic",v:"For they shall be blessed in My presence;"}],[{t:"italic",v:"Even more blessed are those who run to Me,"}],[{t:"italic",v:"Then obey My Word, for their blessing"}],[{t:"italic",v:"Is complete and they are at peace..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Deliverance they shall surely know..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Psalm 40:8 (ESV)"},2:{type:"scripture",ref:"Isaiah 14:12-15"},3:{type:"scripture",ref:"2 Corinthians 10:12"}},nkjv:{"Psalm 40:8 (ESV)":"I delight to do your will, O my God; your law is within my heart.","Isaiah 14:12-15":"12. \u201CHow you are fallen from heaven, O Lucifer, son of the morning! How you are cut down to the ground, You who weakened the nations! 13. For you have said in your heart: \u2018I will ascend into heaven, I will exalt my throne above the stars of God; I will also sit on the mount of the congregation On the farthest sides of the north; 14. I will ascend above the heights of the clouds, I will be like the Most High.\u2019 15. Yet you shall be brought down to Sheol, To the lowest depths of the Pit.","2 Corinthians 10:12":"For we dare not class ourselves or compare ourselves with those who commend themselves. But they, measuring themselves by themselves, and comparing themselves among themselves, are not wise."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/delight-in-the-ways-of-the-lord-6",videoVoiceUrl:"https://www.youtube.com/watch?v=k5PiumDQhjA&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=8",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks Regarding Covetousness",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Covetousness"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:8,prevLetter:{id:"gathered",title:"Gathered"},nextLetter:{id:"i-have-taken-to-myself-a-prophet",title:"I Have Taken to Myself a Prophet"}},{id:"i-have-taken-to-myself-a-prophet",title:"I Have Taken to Myself a Prophet",date:"6/2/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"I am The Lord your God, and I have spoken by My servant, and behold, in him shall I increase. I shall be with him as I was with My servant, Moses. I shall speak with him face to face, and he shall go out and come in. I shall be with him like the pillar of the cloud by day, and as the pillar of fire by night. Behold, The Authority from on high shall dwell with men, and The Lord your God shall heed the voice of a man in that day. Yet the people say,"},{t:"italic",v:"\u201CWhat man is this who exalts himself by his own words, and speaks with the authority of God?\u201D"},{t:"text",v:"And thus they shall surely deny Me and persecute him. Hate shall well up within their hearts, and they shall seek to destroy him. Yet The Word of God shall speak, and the signs of The Almighty shall testify on his behalf. Behold, the cloud of The Almighty shall hide him, and fire shall fall from Heaven and consume his enemies round about, as in the days of old, says The Lord. And though you yet resist My words, My Word shall speak and My judgments shall shout. For I have taken to Myself a prophet, and he shall go for Me. He shall prepare My way before Me, even as I have prepared his way before him. He is not holy, nor righteous; he is but a man, a man after My own heart. And though he stumbles as all men and fear grabs hold of him, for he is but flesh, I tell you the truth, I have surely purchased him from among men as part of the special offering. "},{t:"fn",v:"1"},{t:"text",v:" I AM THE LORD."}]},{type:"para",segments:[{t:"text",v:"Therefore, again I say to you, Timothy is My prophet, and through him have I made My plans known. For I do not change. Thus he shall go for Me, and a number like him, and they shall declare My judgments and warn the people. For the Day of The Lord is here, and the Great and Dreadful Day is about to begin, declares The Lord."}]}],footnotes:{1:{type:"scripture",ref:"Psalm 50:7"}},nkjv:{"Psalm 50:7":'"Hear, O My people, and I will speak, O Israel, and I will testify against you; I am God, your God!"'},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-have-taken-to-myself-a-prophet-5",videoVoiceUrl:"https://www.youtube.com/watch?v=sCxwwNACRaA&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=9",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Amos 3:7 in The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth#Amos_3:7"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:9,prevLetter:{id:"delight-in-the-ways-of-the-lord",title:"Delight in the Ways of The Lord"},nextLetter:{id:"pentecost",title:"Pentecost"}},{id:"pentecost",title:"Pentecost",date:"6/6/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Little flock, hear and understand the will and discipline of The Lord Most High. For I tell you the truth, Pentecost has been fulfilled; behold, it has passed them by unawares. Yet for some it remains, and shall also continue until the time. For many are called, yet few are chosen. Therefore have compassion and pray for them, beloved. For in the same way, you also looked to the time and waited for My words, yet they did not come. And some of you took it upon yourselves to run ahead, impatient, lacking trust, while still others waited patiently; yet all were unaware of My will, save one."}]},{type:"para",segments:[{t:"text",v:"Beloved, here is wisdom: The penitent wait and bow down in thanksgiving. Yet the arrogant and false righteous stand up proudly, declaring their deliverance, a deliverance which has already passed and shall not come. For My hand is removed and My spirit taken. For only those in whom I see of Myself shall escape, and only those caught in My embrace shall fly away. Thus as you were made to wait, so shall these within the churches of men wait. For they wait for a sound they no longer recognize, for a call to which they have shut their ears, for a shout from Him whom they have not known, a voice they have altogether rejected. For how can one who rejects My voice heed the call? And how can one who turns away from Me, embrace Me when the shout is made? For they have surely joined themselves to another, they embrace another messiah, a false christ, who looks nothing like Me. Therefore they shall surely pass through the fire, for by no other means shall they be saved."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"This then is what I command you, little flock:"}],[{t:"italic",v:"Have compassion, and pray for your brothers and sisters"}],[{t:"italic",v:"In the churches of men and for the unbelieving of Israel;"}],[{t:"italic",v:"For they must endure much for the sake of My name..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And though the day has passed, lo it has ceased"}],[{t:"italic",v:"For many, it has not altogether passed away..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My spirit remains with the first election,"}],[{t:"italic",v:"And shall be restored to the penitent after..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 Corinthians 3:11 (HNV)"}},nkjv:{"1 Corinthians 3:11 (HNV)":"For no one can lay any other foundation than that which has been laid, which is Jesus Christ."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/pentecost-3",videoVoiceUrl:"https://www.youtube.com/watch?v=QRVuknMEXRg&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding The Holy Spirit",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"}],num:10,prevLetter:{id:"i-have-taken-to-myself-a-prophet",title:"I Have Taken to Myself a Prophet"},nextLetter:{id:"in-the-bosom-of-the-father",title:"In The Bosom of The Father"}},{id:"in-the-bosom-of-the-father",title:"In The Bosom of The Father",date:"6/28/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Timothy, ask of Me any question, and I shall answer in accordance with your understanding. For that which can not be explained in human terms shall be shown you, and that which you do not understand shall be given you, and you shall understand. For there are languages which use no speech, and communication which comes by sight, even by touch, yet what I shall give you surpasses all of these..."}]},{type:"poetry",lines:[[{t:"italic",v:"For there is a place..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A place beyond space and time, where eternity dwells and life has no end,"}],[{t:"italic",v:"Where light takes its form and goodness is revealed,"}],[{t:"italic",v:"Where the eyes of the redeemed may look upon the Glory of God and see His face,"}],[{t:"italic",v:"Where Heaven meets the earth and The Eternal dwells with men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A place where Everlasting Love can be embraced and healing flows like a gentle stream,"}],[{t:"italic",v:"A place where time has no meaning and the stars flee away,"}],[{t:"italic",v:"Where the brightness is excellent and the warmth thereof very soothing..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A place where joy comes by knowledge with pure understanding,"}],[{t:"italic",v:"Where fulfillment comes by a strong embrace, and love\u2019s completion"}],[{t:"italic",v:"Is met with great satisfaction through many tears"}],[{t:"italic",v:"Flowing down the cheeks of the forever young;"}],[{t:"italic",v:"A place where understanding bursts forth in realization,"}],[{t:"italic",v:"Revelation beyond words!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A place where the hearts of the chosen are revealed,"}],[{t:"italic",v:"Behold, they are uncovered, revealing their true form;"}],[{t:"italic",v:"The image in which I created them, restored..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A simple quiet place, set apart..."}]]},{type:"poetry",lines:[[{t:"italic",v:"In the arms of The King."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/in-the-bosom-of-the-father",videoVoiceUrl:"https://www.youtube.com/watch?v=adtHFdY4tlw&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=11",videoMusicUrl:"https://www.youtube.com/watch?v=JJQihlFLgfw&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=44",relatedTopics:[{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:11,prevLetter:{id:"pentecost",title:"Pentecost"},nextLetter:{id:"the-one-worthy-of-all-praise",title:"The One Worthy of All Praise"}},{id:"the-one-worthy-of-all-praise",title:"The One Worthy of All Praise",date:"7/1/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel:"},{t:"text",v:"The Days of Noah are here, the Day of The Lord has come in; and behold, the Great and Dreadful Day is very near!..."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, O peoples of the earth, and gain wisdom:"},{t:"text",v:"Are not the mountains risen up at the Word of My mouth? Do not the highest peaks break through the clouds at My command? Are not the depths carved out by My knowledge, and the seas filled according to My will? Who causes the clouds to gather together and bring forth rain? Who calls forth the wind from its place and stirs up the hurricane? Who speaks to the horrible mountain, causing it to burst forth, to spew its fervent heat? It is I who has done it, The One who formed it, The One who causes to be! My children, look upon the stars, upon the whole of the heavens, consider the vastness thereof, and know:"},{t:"italic",v:"YAH has spoken it into being, YAHUWAH caused it to be!"},{t:"text",v:"Behold, I have spread out life like a blanket, and caused it to multiply in all the earth; life fills every corner! And still mankind seeks out its beginnings and longs to know its source, asking in vain,"},{t:"italic",v:"\u201CWhere did I come from, and why are we here? From what source did all this life come, and how did it get here? What is the beginning, and how will it end?\u201D"},{t:"text",v:"Blind and hard-hearted generation, deceived and ignorant peoples, foolish children, LIFE HAS A NAME! The Beginning and The End has walked among you! The Source and The Reason is here, and shall also come in great power and glory! From Him did you come forth, and to Him must you return, all you, His beloved. Behold, His names are many and wonderful!"},{t:"fn",v:"1"},{t:"text",v:"That which He is has no end, for as I AM so also is He! The Father and The Son are one, and our name, one - YAHUSHUA-YAHUWAH!"}]},{type:"poetry",lines:[[{t:"italic",v:"In the beginning was The Word, and The Word"}],[{t:"italic",v:"Was with God, and The Word was God;"}],[{t:"italic",v:"The same was in the beginning with God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Through Him all things came into being,"}],[{t:"italic",v:"And nothing in all creation was made apart from Him..."}]]},{type:"poetry",lines:[[{t:"italic",v:"In Him was life, and The Life was the light of men;"}],[{t:"italic",v:"The Light shines in the darkness,"}],[{t:"italic",v:"And the darkness shall not overcome it"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, The Word became flesh"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Immanu El!"},{t:"fn",v:"4"}]]}],footnotes:{1:{type:"note",text:'See: "And He Shall Be Called I AM"',url:"https://www.thevolumesoftruth.com/And_He_Shall_Be_Called_I_AM",link:{collection:"Volume One",letterTitle:"And He Shall Be Called I AM"}},2:{type:"scripture",ref:"John 1:1-5"},3:{type:"scripture",ref:"John 1:14"},4:{type:"scripture",ref:"(which means \u201CGod with us\u201D) - Matthew 1:23"}},nkjv:{"John 1:1-5":"1. In the beginning was the Word, and the Word was with God, and the Word was God. 2. He was in the beginning with God. 3. All things were made through Him, and without Him nothing was made that was made. 4. In Him was life, and the life was the light of men. 5. And the light shines in the darkness, and the darkness did not comprehend it.","John 1:14":"And the Word became flesh and dwelt among us, and we beheld His glory, the glory as of the only begotten of the Father, full of grace and truth.","(which means \u201CGod with us\u201D) - Matthew 1:23":"\u201CBehold, the virgin shall be with child, and bear a Son, and they shall call His name Immanuel,\u201D which is translated, \u201CGod with us.\u201D (Matthew 1:23)"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-one-worthy-of-all-praise",videoVoiceUrl:"https://www.youtube.com/watch?v=3cBRmRcC2Lw&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=12",videoMusicUrl:"https://www.youtube.com/watch?v=YGSGTBffsK0&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=7",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:'The Coming of The Lord - "In Power and Great Glory"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#In_Power_and_Great_Glory"}],num:12,prevLetter:{id:"in-the-bosom-of-the-father",title:"In The Bosom of The Father"},nextLetter:{id:"freedom-comes-by-sacrifice",title:"Freedom Comes By Sacrifice"}},{id:"freedom-comes-by-sacrifice",title:"Freedom Comes By Sacrifice",date:"7/25/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have called to the scoffer and to the wicked alike, that they might come forward and declare their evil thoughts, that they might come forth from their hiding places and walk openly in their rebellion. And thus they have answered, they have surely come out."}]},{type:"para",segments:[{t:"text",v:"Yet of the Called, they have not come out. Indeed, few have rushed forward to embrace Me, few have come to Me without condition. Behold, I called to them, even to the great outpouring of My spirit; in page after page, I wrote to them, offering them many gifts; yea, with arms outstretched, I sought to uphold them and guide them. Yet they refused My voice and drew back the hand, turning to Me the back, for they want no part with Me as I truly am. And of My prophet, they have treated him as Micaiah. For the thoughts of their hearts do always betray them, and by their actions have they shown themselves to be in agreement with the insolent king."},{t:"fn",v:"1"},{t:"text",v:"My children have forsaken Me! Not one truly seeks to remain in My love! They have all become unprofitable servants; there is none who does good, no, not one! And when I send to them a prophet, they despise him on account of his words, which are not his own, treating My words as binding cords about their hands and their feet! For they do always dishonor Me, and within their hearts they cease not from their complaint!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore that from which they seek"}],[{t:"italic",v:"To be loosed shall bind them in the Day,"}],[{t:"italic",v:"Until they willingly place themselves upon the altar..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Wherein freedom comes by sacrifice,"}],[{t:"italic",v:"And true understanding by letting go..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:"1 Kings 22"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/freedom-comes-by-sacrifice-6",videoVoiceUrl:"https://www.youtube.com/watch?v=IaO5eVi_ut0&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"}],num:13,prevLetter:{id:"the-one-worthy-of-all-praise",title:"The One Worthy of All Praise"},nextLetter:{id:"god-of-the-living",title:"God of the Living"}},{id:"god-of-the-living",title:"God of the Living",date:"7/28/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Who shall praise Me from the pit? What song is heard from the grave? Shall rotting flesh stand up and praise The God of Israel? Shall those turned to dust give Me glory? Thus I tell you a mystery, behold, I speak to you a wonder: There is a people who sleep and a flesh which has no life in it, there are many who have been lost to the depths, a great multitude who have returned to the dust of the earth and can not be found, yet The Lord God knows their names and their dwelling places. Not one has passed from My sight, not one has been given up to the void. For I am God of the living, The One alone worthy of all praise! I am not God of the dead, but of the living!"},{t:"fn",v:"1"},{t:"text",v:"For the dead have no ruler. There is no life in them; even all their thoughts have perished with them."},{t:"fn",v:"2"},{t:"text",v:"No voice is heard from the grave; only complete and utter silence dwells there"},{t:"fn",v:"3"},{t:"text",v:"- darkness without time."},{t:"fn",v:"4"},{t:"text",v:"For from the dust I created them, and to the dust they return. By My breath they were made alive, and without My breath they fall asleep."},{t:"fn",v:"5"},{t:"text",v:"In the image of The Son were My beloved created,"},{t:"fn",v:"6"},{t:"text",v:"and in His likeness shall they be restored."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the day and hour is close at hand,"}],[{t:"italic",v:"Yea it is very near, when the dead in Messiah"}],[{t:"italic",v:"Shall arise and the sleepers shall awake,"}],[{t:"italic",v:"When the rotting corpses are revived"}],[{t:"italic",v:"And the dust gathers together once again..."}]]},{type:"poetry",lines:[[{t:"italic",v:"From one end of the earth to the other,"}],[{t:"italic",v:"Even from the deepest depths, shall My people"}],[{t:"italic",v:"Rise up and give Me glory!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore let the children of Israel prepare,"}],[{t:"italic",v:"Let everyone joined to Messiah step forward"}],[{t:"italic",v:"And claim their inheritance..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I have but to call out your name!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Says The Holy One of Israel."}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 22:32, Mark 12:27"},2:{type:"scripture",ref:"Psalm 146:4 (NAS)"},3:{type:"scripture",ref:"Psalm 31:17, Psalm 115:17"},4:{type:"note",text:'See: "they know not the passage of time"',url:"https://www.thevolumesoftruth.com/Make_Way_for_the_Coming_of_The_Lord#:~:text=Yet%20I%20say%2C%20do%20not%20mourn%20for%20the%20dead%2C%20for%20they%20only%20sleep.%20They%20abide%20in%20darkness%20for%20but%20an%20instant%2C%20for%20the%20dead%20know%20nothing%20at%20all%3B%20they%20know%20not%20the%20passage%20of%20time%2C%20nor%20of%20the%20seasons.",link:{collection:"Volume One",letterTitle:"Make Way for the Coming of The Lord",excerpt:"Yet I say, do not mourn for the dead, for they only sleep. They abide in darkness for but an instant, for the dead know nothing at all; they know not the passage of time, nor of the seasons."}},5:{type:"scripture",ref:"Genesis 2:7, Psalm 104:29"},6:{type:"scripture",ref:"Genesis 1:26-27"}},nkjv:{"Matthew 22:32, Mark 12:27":"Matthew 22:32 \u2014 \u2018I am the God of Abraham, the God of Isaac, and the God of Jacob\u2019? God is not the God of the dead, but of the living.\u201D | Mark 12:27 \u2014 He is not the God of the dead, but the God of the living. You are therefore greatly mistaken.\u201D","Psalm 146:4 (NAS)":"His spirit departs, he returns to the earth; On that very day his plans perish.","Psalm 31:17, Psalm 115:17":"31:17 \u2014 Do not let me be ashamed, O LORD, for I have called upon You; Let the wicked be ashamed; Let them be silent in the grave. | 115:17 \u2014 The dead do not praise the LORD, Nor any who go down into silence.","Genesis 2:7, Psalm 104:29":"Genesis 2:7 \u2014 And the LORD God formed man of the dust of the ground, and breathed into his nostrils the breath of life; and man became a living being. | Psalm 104:29 \u2014 You hide Your face, they are troubled; You take away their breath, they die and return to their dust.","Genesis 1:26-27":"26. Then God said, \u201CLet Us make man in Our image, according to Our likeness; let them have dominion over the fish of the sea, over the birds of the air, and over the cattle, over all the earth and over every creeping thing that creeps on the earth.\u201D 27. So God created man in His own image; in the image of God He created him; male and female He created them."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/god-of-the-living",videoVoiceUrl:"https://www.youtube.com/watch?v=YmWSzhtCz5s&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=14",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},{label:"Regarding the First and Second Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"}],num:14,prevLetter:{id:"freedom-comes-by-sacrifice",title:"Freedom Comes By Sacrifice"},nextLetter:{id:"walking-through-the-valley",title:"Walking through the Valley"}},{id:"walking-through-the-valley",title:"Walking through the Valley",date:"7/28/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My sons and daughters, hear now this parable, that you may gain wisdom and have understanding of that which I am about to do, of that which must be: I have a great vineyard, with many grapes. I have provided both the early and latter rain and tended every vine, pruning them with sure hands and delicate fingers. Yet many wither, while others fail to produce, and still others are slow to ripen. Beloved, I have waited patiently and tended My vineyard, doing all that was necessary to produce a fair crop, and now it is time for harvest. Yet I tell you plainly, it shall be a very lowly crop, a very small harvest, for few have ripened to maturity. Thus they must be left to ripen in their season. And though the winds shall be harsh and the rains rare, behold, even all manner of plagues shall come, I must not gather them until their due season, says The Lord."}]},{type:"para",segments:[{t:"text",v:"Thus I shall quiet My voice among you, little flock, and speak to you no more in this manner. For My prophet must be cut off from among you for a time. And though you endeavor to loosen these bonds, I will not forsake you utterly, I am with you still. Though I pull back My hand, I will not forsake you; and though you have yet to truly harken to My voice, I am with you still. Behold, in your time of need, when calamity and great devastation is on every side, I will be there, I will not forsake you utterly. For I have left a multitude of words to guide you, and many husbandmen to point the way. You will not be alone in the valley."}]},{type:"poetry",lines:[[{t:"italic",v:"Trust in My ways therefore,"}],[{t:"italic",v:"Embrace My correction,"}],[{t:"italic",v:"And do not turn away from My discipline..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written:"}],[{t:"italic",v:"As many as I love, I rebuke and chasten"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Revelation 3:19"}},nkjv:{"Revelation 3:19":"As many as I love, I rebuke and chasten. Therefore be zealous and repent."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/walking-through-the-valley-6",videoVoiceUrl:"https://www.youtube.com/watch?v=HC7Rms8IwqE&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=15",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Parables",url:"https://answersonlygodcangive.com/Parables"}],num:15,prevLetter:{id:"god-of-the-living",title:"God of the Living"},nextLetter:{id:"the-harvest-is-separated-all-bundles-set-in-their-places",title:"The Harvest Is Separated, All Bundles Set in Their Places"}},{id:"the-harvest-is-separated-all-bundles-set-in-their-places",title:"The Harvest Is Separated, All Bundles Set in Their Places",date:"8/1/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"By My prophets have I made My plans known. Yet that which I am about to do is done already, and shall be. And that which I have spoken from the beginning, even to this day, is true. For the will of God can not be broken, even as The Scriptures. And if My every word is Scripture, then how shall even one word fail? Yet My people fall away, and My little flock grows smaller still. For they seek to loosen these bonds in an attempt to flee this bundle. For the Way of The Lord is not known among them, and My words have ceased from being a blessing. And so they flee back into the world in an attempt to escape, as in all times past, for they have no root. Yet I tell you the truth, none shall escape their bundle. For all bundles lie in the field already, each one tied securely and set in its place. Therefore as one attempts to flee this bundle, the truth of the matter is made plain. For they have not departed at all, but remain in the bundle in which I had placed them at the first. I AM THE LORD."}]},{type:"para",segments:[{t:"text",v:"Beloved ones, I search the hearts and minds, even the innermost thoughts I know; even from the foundation of the world did I know each one of you, setting you in your place from the beginning. Yet some will say,"},{t:"italic",v:"\u201CWhat of free will and our right to choose?\u201D"},{t:"text",v:"To these I say: You have chosen, and the will of your heart has spoken, and thus were you bundled and prepared. For I know My own."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus the Bride is chosen;"}],[{t:"italic",v:"My blood runs through her veins,"}],[{t:"italic",v:"My image is shown upon her face..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the light of My coming is reflected"}],[{t:"italic",v:"In her eyes, for I have captured her gaze,"}],[{t:"italic",v:"And she will by no means look away"}],[{t:"italic",v:"Or seek after another..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore some are plucked from"}],[{t:"italic",v:"The world already, and shall also be taken;"}],[{t:"italic",v:"They shall surely be gone from this place!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-harvest-is-separated-all-bundles-set-in-their-places",videoVoiceUrl:"https://www.youtube.com/watch?v=949oVWIO10U&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=16",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Amos 3:7",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth#Amos_3:7"},{label:"The True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#The_True_Bride"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:16,prevLetter:{id:"walking-through-the-valley",title:"Walking through the Valley"},nextLetter:{id:"a-just-god-and-a-savior",title:"A Just God and A Savior"}},{id:"a-just-god-and-a-savior",title:"A Just God and A Savior",date:"8/20/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"My people do greatly err, for they believe that I have altogether become like them! Yet I am HOLY, and My words TRUE. For as it is written:"},{t:"italic",v:"My thoughts are not your thoughts, neither are your ways My ways. For as the heavens are higher than the earth, so are My ways higher than your ways and My thoughts than your thoughts."},{t:"fn",v:"1"},{t:"text",v:"When I consider, all creation is before Me; from the most minute detail to the greatest, nothing is hidden from My eyes; behold, the whole universe abides within My understanding. For I am LORD and GOD, Creator of Heaven and Earth."}]},{type:"para",segments:[{t:"text",v:"How is it then, I have become unjust in your eyes? Shall My ways be questioned by you?! Are you upset because I speak to the few in the same manner I spoke to My people, Israel, in the wilderness? And who is Israel? Is he a home-born slave in your eyes?! For I tell you the truth, those of My Olive Tree are free. Only those who have gone astray are slaves, and only those who seek to uphold their own way remain bound. For you can only serve one master. Or have you forgotten My words and the Way which was set before you? Therefore I shall treat the one, who has knowledge of the Way and pollutes it, as the multitudes who forsake it. For those who have seen must now walk in that which I have revealed. And if they refuse, then by their own choice have they chosen to walk through the valley, until they are broken - atop or beneath, all shall be broken. For I am The Lord, and I do not change!"}]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you the truth, all paths lead"}],[{t:"italic",v:"To the foot of My throne, all must stand"}],[{t:"italic",v:"Before the judgment seat of Mashiach..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For there is no other God besides Me;"}],[{t:"italic",v:"A just God and a Savior,"}],[{t:"italic",v:"There is none besides Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus those who receive of Me are made worthy,"}],[{t:"italic",v:"And shall walk with Me forever;"}],[{t:"italic",v:"And those who remain void and reject"}],[{t:"italic",v:"My gifts shall cease, broken off forever..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Isaiah 55:8-9"}},nkjv:{"Isaiah 55:8-9":"8. \u201CFor My thoughts are not your thoughts, Nor are your ways My ways,\u201D says the LORD. 9. \u201CFor as the heavens are higher than the earth, So are My ways higher than your ways, And My thoughts than your thoughts."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-just-god-and-a-savior",videoVoiceUrl:"https://www.youtube.com/watch?v=nR8-XB9WlPw&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=17",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:17,prevLetter:{id:"the-harvest-is-separated-all-bundles-set-in-their-places",title:"The Harvest Is Separated, All Bundles Set in Their Places"},nextLetter:{id:"what-is-man",title:"What Is Man"}},{id:"what-is-man",title:"What Is Man",date:"8/29/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved, upon what foundation does the love of God rest? With what thread is the Word of The Lord woven? Can any man know the mind of God? Can flesh touch The Holy? Tell Me, if you know. And what is man, that he should be created in My image, the image of The Son of Man? For within man is My breath; I gave him life. He was made through Me and for Me; I caused him to be. It was My own blood which was shed for him, My own life which was poured out, even unto death. Therefore all those who come to Me and drink shall be made new; whether awake or sleeping, all My beloved shall arise and live. For I AM HE, The Resurrection and The Life. Thus there is indeed a focal point of creation, of which I am always mindful, a reason I created the heavens and the earth and everything in them -"},{t:"italic",v:"It is mankind."},{t:"text",v:"Yet man does not yet understand what he is, nor can he comprehend what he shall be. For I have made man in My own image, that in the fullness of time he would come to dwell in Me and I in him, being at all times with Me where I am. In that day he will become like Me, for he shall see Me as I truly am."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore prepare your hearts, beloved ones..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Keep your eyes fixed upon Me, obey My voice,"}],[{t:"italic",v:"And heed the sound of this Trumpet..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the Day of The Lord has come,"}],[{t:"italic",v:"Behold, ALL have entered in..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 John 3:2"}},nkjv:{"1 John 3:2":"Beloved, now we are children of God; and it has not yet been revealed what we shall be, but we know that when He is revealed, we shall be like Him, for we shall see Him as He is."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/what-is-man-6",videoVoiceUrl:"https://www.youtube.com/watch?v=AFzeRHvbDC4&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=18",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:18,prevLetter:{id:"a-just-god-and-a-savior",title:"A Just God and A Savior"},nextLetter:{id:"desperation",title:"Desperation"}},{id:"desperation",title:"Desperation",date:"8/30/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the United States)",blocks:[{type:"para",segments:[{t:"text",v:"Beloved, the time is short. And though your nation is in desperate need, it has yet to reveal its weakness for fear of its enemies. Yet it will not be able to hide the truth from the world much longer, for everything is about to change. And that which is held together by the weakest of threads shall break, and new alliances shall be formed out of desperation, and ALL shall fear, says The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/desperation",videoVoiceUrl:"https://www.youtube.com/watch?v=-zvKSnz1oQ0&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=19",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"}],num:19,prevLetter:{id:"what-is-man",title:"What Is Man"},nextLetter:{id:"narrow-vision",title:"Narrow Vision"}},{id:"narrow-vision",title:"Narrow Vision",date:"10/25/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"I called to you, yet not one truly heeds the call. I revealed a need, yet who has stepped forward to uphold My cause? Behold, I poured out My spirit, and still you remain unmoved. Therefore this little flock is disbanded, even now you are dispersed, for in you I am sorely displeased. For I said that your faith was not to stand upon anything apart from Me, yet you fixed beams and set up supports, in an effort to uphold your own expectations. Behold, you built upon your own arrogant assumptions and private interpretations, and I knocked you down, breaking apart every pillar which you had erected falsely in My name. And still you speak deceits within your hearts, saying,"},{t:"italic",v:"\u201CWhere is the promise of His coming? The year draws to a close and no one is gathered\u201D"},{t:"fn",v:"1"},{t:"text",v:"- Faithless servants! Blind children! Not one word I have spoken shall by any means pass away, nor shall one word of My prophets fall to the ground! Indeed ALL shall serve My purpose, and come to pass according to MY will. For as it is written:"},{t:"italic",v:"The vision is yet for the appointed time, it hastens, and in the end it will speak; behold, it shall testify loudly. And though it tarries, wait for it, for it shall surely come, it will not tarry."},{t:"fn",v:"2"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, stop looking upon My words"}],[{t:"italic",v:"With tainted eyes and narrow vision;"}],[{t:"italic",v:"Stop staring at My messengers;"}],[{t:"italic",v:"Look past them and see with greater eyes..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you the truth,"}],[{t:"italic",v:"Your expectations shall never be met,"}],[{t:"italic",v:"Your assumptions shall fall short,"}],[{t:"italic",v:"And your every private interpretation shall fail..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet I remain faithful, and My Word true..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"2 Peter 3:3-4"},2:{type:"scripture",ref:"Habakkuk 2:3"}},nkjv:{"2 Peter 3:3-4":"3. knowing this first: that scoffers will come in the last days, walking according to their own lusts, 4. and saying, \u201CWhere is the promise of His coming? For since the fathers fell asleep, all things continue as they were from the beginning of creation.\u201D","Habakkuk 2:3":"For the vision is yet for an appointed time; But at the end it will speak, and it will not lie. Though it tarries, wait for it; Because it will surely come, It will not tarry."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/narrow-vision",videoVoiceUrl:"https://www.youtube.com/watch?v=17WYFS6v8sM&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=20",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"}],num:20,prevLetter:{id:"desperation",title:"Desperation"},nextLetter:{id:"full-circle",title:"Full Circle"}},{id:"full-circle",title:"Full Circle",date:"11/9/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"I have called the winds of heaven to blow upon the earth. I have stirred them up, that they may go forth and gnarl the branches, that they may blow hard against the multitudes and break down the walls - Let every tree topple and break the necks of the wicked! Let every wall come down with a great crash! Behold, the anger of The Lord shall increase by measure, until every foundation is broken up from beneath, until the face of the earth is once again without form! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"Thus I have spoken, and who is able to restrain themselves from repeating My every word? Who will not prophesy, when the voice of The Almighty has entered his ear? For I tell you plainly, the day is coming and is already here, when I shall speak into the air and the voice of YAHUWAH shall thunder, reaching even to the ends of the earth! Yet I ask you, how does a prophet hear and by what means is he revealed? Remember My words:"},{t:"italic",v:"If there be a prophet among you, I, The Lord, shall make Myself known to him in a vision; I shall speak to him in a dream; even plainly I shall speak with him, not in mysterious sayings. For he has seen the form of The Lord and has sat in My presence, and knows that which is beyond words, and before him men shall fear."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord, to all those who have ears to hear:"},{t:"text",v:"Wait upon Me, with all trust and fear; stand steadfast and be patient. Accept My words, as I have spoken them and as they are written;"},{t:"italic",v:"do not add to My words, nor take from them."},{t:"fn",v:"2"},{t:"italic",v:"Neither form for yourselves any private interpretation"},{t:"fn",v:"3"},{t:"italic",v:";"},{t:"text",v:"only give heed to My words and also do them, and prepare."}]},{type:"poetry",lines:[[{t:"italic",v:"For My words are indeed that light"}],[{t:"italic",v:"Which shines in a dark place,"}],[{t:"italic",v:"A lamp and a beacon,"}],[{t:"italic",v:"Preparing My way before Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until the new day dawns and The Morning Star rises,"}],[{t:"italic",v:"Filling the hearts of My chosen as they enter in..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Numbers 12:6-8"},2:{type:"note",text:'See: "You Shall Not Add to nor Take Away"',url:"https://www.thevolumesoftruth.com/The_False_Doctrine_of_%E2%80%9CThe_Trinity%E2%80%9D_Exposed_-_The_Holy_Spirit_is_Not_a_Person#You_Shall_Not_Add_to_nor_Take_Away"},3:{type:"scripture",ref:"2 Peter 1:20-21"}},nkjv:{"Numbers 12:6-8":"6. Then He said, \u201CHear now My words: If there is a prophet among you, I, the LORD, make Myself known to him in a vision; I speak to him in a dream. 7. Not so with My servant Moses; He is faithful in all My house. 8. I speak with him face to face, Even plainly, and not in dark sayings; And he sees the form of the LORD. Why then were you not afraid To speak against My servant Moses?\u201D","2 Peter 1:20-21":"20. knowing this first, that no prophecy of Scripture is of any private interpretation, 21. for prophecy never came by the will of man, but holy men of God spoke as they were moved by the Holy Spirit."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/full-circle",videoVoiceUrl:"https://www.youtube.com/watch?v=J5Cjn22gijA&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],num:21,prevLetter:{id:"narrow-vision",title:"Narrow Vision"},nextLetter:{id:"blessed-hope",title:"Blessed Hope"}},{id:"blessed-hope",title:"Blessed Hope",date:"11/19/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"There are many gathered together, of one heart and one mind; there are many scattered abroad, with faces turned by the wind, with chapped cheeks and red faces; there are many who have embraced him whose heel is lifted up against Me."}]},{type:"para",segments:[{t:"text",v:"What are all these tears?! - Flowing streams without hope, torrents with no outlet, flooding sorrows drowning every hope and killing every good intention! What is this leaning upon God\u2019s people, oppressing them, crushing them?! Who are all these who spit in My eyes and lay stripes upon My back?! Are not My people delivered?! And still the voice of the multitude says,"},{t:"italic",v:"\u201CThere is no hope in God.\u201D"},{t:"text",v:"Dark counsel is increased! Concealed truth devastates the ignorant, while men in authority step upon the fingers of the innocent! How long shall dark counsel prevail?! Shall veiled intentions come upon My people, to do great harm in an instant?! Shall the nations lie down in death, for lack of remorse?! For I see no sincere repentance, nor has one truly turned about. How long shall the multitudes swear by things made, and place their trust in the works of man?! For the desolate know not the things of God, nor is darkness able to understand; yea, the wicked gnash upon their teeth, the whole body convulses in the wake of mourning, for there is no rest."}]},{type:"poetry",lines:[[{t:"italic",v:"Yet My hand caresses the cheeks of the hopeless,"}],[{t:"italic",v:"As we watch the dawning of the day together..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the strength of My arm uplifts the downtrodden,"}],[{t:"italic",v:"My strong embrace heals the sorrowful,"}],[{t:"italic",v:"Every beat of My heart revives the dead,"}],[{t:"italic",v:"And the sound of My voice frees every captive..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the power of My love hides them away!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/blessed-hope",videoVoiceUrl:"https://www.youtube.com/watch?v=DwqXllU0bM8&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=22",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:22,prevLetter:{id:"full-circle",title:"Full Circle"},nextLetter:{id:"mouthpieces-of-the-most-high-god",title:"Mouthpieces of The Most High God"}},{id:"mouthpieces-of-the-most-high-god",title:"Mouthpieces of The Most High God",date:"2/19/12",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For the Sons of Promise, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"To every prophet who went before was there a time of service, a time of great works done in the Spirit, according to My will. And thus shall it be for you also, if you remain faithful. For I have prepared the number, men of My choosing, a special offering who shall be set apart."},{t:"fn",v:"1"},{t:"text",v:"Behold, I have drawn you out, separating you from amongst those who remain married to this world, even as I have done with every prophet and man of God who went before you, each at their appointed time, each in their due season. Therefore let the Sons of Promise arise and take a stand, for the time has come! Let those chosen be established, the number fulfilled! For as it is written:"},{t:"italic",v:"I shall dwell in My witnesses like a flame of fire, and well up in My servants like a boiling pool."},{t:"fn",v:"2"},{t:"text",v:"And they shall prophesy and declare My judgments against the churches and upon every religion of man, against the nations and upon all the cities of men."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My words shall increase by measure,"}],[{t:"italic",v:"And pass through the multitudes like fire!..."}],[{t:"stanza-break"}],[{t:"italic",v:"Each word a flame which can not be quenched!"}],[{t:"italic",v:"Every diatribe a relentless fire breaking through"}],[{t:"italic",v:"The lines, surmounting every obstacle,"}],[{t:"italic",v:"Crossing every border, inundating every land!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And the pride of man shall be bowed down,"}],[{t:"italic",v:"And the arrogance of man utterly humiliated!"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "Regarding the 144,000 Witnesses"',url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},2:{type:"note",text:'See: "Proclaim The Name of The Lord"',url:"https://www.thevolumesoftruth.com/Proclaim_The_Name_of_The_Lord#:~:text=For%20the%20day%20is%20coming%2C%20and%20behold%20it%20is%20already%20here%2C%20when%20I%20shall%20dwell%20in%20My%20witnesses%20like%20a%20flame%20of%20fire%2C%20and%20well%20up%20in%20My%20servants%20like%20a%20boiling%20pool%2C",link:{collection:"Volume Seven",letterTitle:"Proclaim The Name of The Lord",excerpt:"For the day is coming, and behold it is already here, when I shall dwell in My witnesses like a flame of fire, and well up in My servants like a boiling pool,"}},3:{type:"scripture",ref:"Isaiah 2:17 (CJB)"}},nkjv:{"Isaiah 2:17 (CJB)":"The pride of man will be bowed down, the arrogance of men will be humiliated, and when that day comes, Adonai alone will be exalted."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/mouthpieces-of-the-most-high-god",videoVoiceUrl:"https://www.youtube.com/watch?v=lSmsPPgC168&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=23",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"My Word Is Fire",url:"https://answersonlygodcangive.com/Main_Page#My_Word_Is_Fire"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:23,prevLetter:{id:"blessed-hope",title:"Blessed Hope"},nextLetter:{id:"madness",title:"Madness"}},{id:"madness",title:"Madness",date:"3/25/12",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My people believe I have altogether gone silent, that I have shut My mouth from speaking through My prophets (for they are not My people). Behold, every false doctrine is strictly upheld, every filthy tradition fiercely defended, as the pride of the people escalates beyond reason; the lies do not cease!"},{t:"italic",v:"Thus the churches of men provide My people with security in false hope, and put forth divinations of peace and safety, preaching prosperity in monologues of false praise and fake passion, abusing My name and misusing My Word, twisting it to uphold their own corrupt foundation, all in the name of unrighteous gain, as it is written. "},{t:"fn",v:"1"},{t:"text",v:"Look how all these leaders in the churches assert their own authority, yet remain void of the Spirit! Look how they proclaim My name, yet fail to recognize Me! And look how all these unbelieving Jews and orthodox rabbis do the very same. Look how My words pass before the eyes of the ignorant Christian, and enter into the ears of the arrogant, self-proclaimed believer, who then turn and fight against Me! Look how they in one accord persecute and slander those I send, and all this in the name of doing God a service! Look, how in one breath and in one moment, they recognize The Author of these Letters, and then turn and strike Me upon the mouth, blaspheming My words and desecrating My gifts!..."}]},{type:"poetry",lines:[[{t:"italic",v:"WHAT MADNESS IS THIS?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"WHAT IS THIS WHICH FILLS MY PEOPLE?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Answer, if you know."}]]}],footnotes:{1:{type:"scripture",ref:"2 Peter 2:3"}},nkjv:{"2 Peter 2:3":"By covetousness they will exploit you with deceptive words; for a long time their judgment has not been idle, and their destruction does not slumber."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/madness",videoVoiceUrl:"https://www.youtube.com/watch?v=K5vmdrQuUdk&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=24",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:24,prevLetter:{id:"mouthpieces-of-the-most-high-god",title:"Mouthpieces of The Most High God"},nextLetter:{id:"a-perverse-nation",title:"A Perverse Nation"}},{id:"a-perverse-nation",title:"A Perverse Nation",date:"7/4/12",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Is the U.S.A. still a \u201CGod-fearing\u201D nation?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Many yet fear Me, even the wicked deep within, yet very few have any love for God in their hearts. For this nation is most perverse, a nation which loves abomination and from righteousness is far removed - Thus I have spit them out! Behold, even the earth shall vomit them out! For they have greatly defiled the land, a multitude of dry branches, broken off, which shall by no means be grafted in again until they fall hard upon their faces, crying out,"},{t:"italic",v:"\u201CBlessed is He who comes in the name of The Lord!\u201D"},{t:"text",v:"Behold, this nation plants seeds of perversion without ceasing! They cultivate abominations and reap sin all day long, and into the night they revel in all their uncleanness! And when I look down upon this nation, I see Sodom bursting forth and Gomorrah overtaking the land! And when I peer deeper still, I see one nation in agreement, a people in love with themselves, a nation which loves its harlotries more than God! - An adulterous people! A most wicked generation! BEHOLD, A WHOLE NATION OF MURDERERS IS BEFORE MY EYES! Therefore I am come down to tread, until every wicked person is crushed beneath My feet and every evil man in authority dies a grievous death in this land!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I shall purge this"}],[{t:"italic",v:"Great and awful vineyard;"}],[{t:"italic",v:"I shall uproot and destroy!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until that which was lost is found,"}],[{t:"italic",v:"And that which was hidden is"}],[{t:"italic",v:"Brought into the open..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until that which I have"}],[{t:"italic",v:"Searched for is seen, once again..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Declares The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-perverse-nation-3",videoVoiceUrl:"https://www.youtube.com/watch?v=oRR7Btavp1s&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:25,prevLetter:{id:"madness",title:"Madness"},nextLetter:{id:"the-parable-of-the-aged-shepherd",title:"The Parable of The Aged Shepherd"}},{id:"the-parable-of-the-aged-shepherd",title:"The Parable of The Aged Shepherd",date:"7/14/12",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"There was a man, an old man full of years, who grew up tending sheep. And to this day he tends them still, arising early each day; even going out in the middle of the night when required, whether due to wolves or approaching bad weather. He tends his sheep, for he knows no other trade, and enjoys doing so. The shepherd has no family, nor children of his own. The sheep are his family, and he cares for them as such."}]},{type:"para",segments:[{t:"text",v:"One day a man came to him while he was out in the field, and offered to buy all the sheep for a good price, and said,"},{t:"italic",v:"\u201CYou are old and look very tired; let me take this flock off your hands. Then you can take the money and retire, and relax and enjoy life.\u201D"},{t:"text",v:"The aged shepherd paused and considered for a moment, and looked up at the man with a smile, and said with conviction,"},{t:"italic",v:"\u201CI am retired; I haven\u2019t had to work a day my whole life.\u201D"},{t:"text",v:"The man was puzzled by this, and said,"},{t:"italic",v:"\u201CBut you have been tending sheep your whole life, and caring for their lambs since you were a boy!\u201D"},{t:"text",v:"As the aged shepherd\u2019s mind drifted back across the years, he sighed contentedly, and answered,"},{t:"italic",v:"\u201CRight. I have indeed been very blessed in my life.\u201D"}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-parable-of-the-aged-shepherd-3",videoVoiceUrl:"https://www.youtube.com/watch?v=jnobZW3EVYQ&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=26",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Parables",url:"https://answersonlygodcangive.com/Parables"}],num:26,prevLetter:{id:"a-perverse-nation",title:"A Perverse Nation"},nextLetter:{id:"the-pomp-of-the-nations-shall-cease",title:"The Pomp of the Nations Shall Cease"}},{id:"the-pomp-of-the-nations-shall-cease",title:"The Pomp of the Nations Shall Cease",date:"7/27/12",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked: What does The Lord think about the Olympics, and professional sports in general?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"It is an abhorrence to Me. For the athletes, who, for a pretense, give thanks in My name, do always offend. For they have surely taken the name of The Lord in vain. For what part do I have in their achievements? What part do I have in their vanity? In their sin?! And look upon these monstrosities, which man has built for the sake of greed. Look upon the vanity and pomp of all these deceitful nations, and tell Me, what do you see? They enlarge themselves, while the needy are made to live in obscurity; behold they flaunt freedom, yet oppress their own people from birth to the grave! Not one does good - NOT ONE! All have gone the way of Sodom, every one of them follows in the way of Cain! And all, from the least to the greatest, have blasphemed My holy name!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore as I have spoken, I declare it once again:"}]]},{type:"poetry",lines:[[{t:"italic",v:"Let the glory of man be turned backward,"}],[{t:"italic",v:"Let every countenance fall and every heart fail,"}],[{t:"italic",v:"Until the pride of man is bowed down"}],[{t:"italic",v:"And the arrogance of man is utterly humiliated!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Declares The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-pomp-of-the-nations-shall-cease",videoVoiceUrl:"https://www.youtube.com/watch?v=CCCM0MkTrH0&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=27",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Olympics",url:"https://answersonlygodcangive.com/Regarding_the_Olympics"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"}],num:27,prevLetter:{id:"the-parable-of-the-aged-shepherd",title:"The Parable of The Aged Shepherd"},nextLetter:{id:"a-heavy-stone-a-bitter-burden",title:"A Heavy Stone, a Bitter Burden"}},{id:"a-heavy-stone-a-bitter-burden",title:"A Heavy Stone, a Bitter Burden",date:"10/16/12",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The walls of Jerusalem are fallen! The high walls crumble and are broken down! The people are given into the hands of their enemies, those who murder without cause! Blood fills the streets as the women wail over the dead, pouring out drink offerings upon the ground! My people are taken captive, and those who walk free are surrounded on every side, with no place to flee! By two and by three, the enemies enter in through the cracks; in droves they gather outside the city, that they might break down the gates!..."},{t:"italic",v:"Jerusalem, O Jerusalem, why have you forsaken Me?!"},{t:"text",v:"Even to this day, O Israel, you have not ceased from walking in the ways of your forefathers, stoning My prophets in word and by deed, seeking always to kill or imprison those sent to you. Have I not gathered you with a mighty hand from among the nations, restoring you to your own land, even granting you great increase? Yet you do not embrace Me, for you yet push out the hand against My Holy One; you refuse to drink from His cup."}]},{type:"poetry",lines:[[{t:"italic",v:"How long shall you seek to murder your King?!"}],[{t:"italic",v:"How long will you deny The Way I have set before you?!"}],[{t:"italic",v:"How long shall you blaspheme The Truth,"}],[{t:"italic",v:"Which I sent into the world to testify?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YOU HAVE FORSAKEN LIFE!"}],[{t:"italic",v:"You refuse the blood I poured out for you!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"O Jerusalem, Jerusalem, how long will you"}],[{t:"italic",v:"Let His blood drip from your fingers?!"}]]},{type:"para",segments:[{t:"text",v:"WASH YOURSELVES! MAKE YOURSELVES CLEAN! For I tell you the truth, the stain of your guilt remains, as you pass it from one generation to the next! Thus YOU fulfill the curse by which your forefathers had cursed themselves! YOU freed the murderer and condemned The Innocent! YOU murdered The Author of Life and hung your Salvation upon a tree, piercing His hands and His feet! Behold, even those who dwell among you, who are called Christian, do pollute My name and crucify Me again and again in their hearts, by all they say and do; a very perverse people, a corrupt religion which looks nothing like Me; churches of men who worship themselves and their own ideals as they proclaim a christ, an idol, which they have formed in their own image, continually reshaping it to meet their own expectations, that they might uphold their own traditions, which I hate!..."},{t:"italic",v:"Jerusalem, O Jerusalem, why have you forsaken Me?!"},{t:"text",v:"Your enemies dwell at the gates and have entered the city! Behold, they dwell upon the mount desecrating the land, bowing down five times per day to their god, a false image, a very grave error, for he is no god; a religion built upon the works of the evil one, acolytes who walk in his footsteps, bearing fruit according to his likeness; multitudes of deceived peoples, a whole nation of evil workers practicing that which satan delights in!..."},{t:"italic",v:"O sons of perdition, you have no place in My Holy Mountain! For you shall be utterly destroyed, when it falls hard upon you! You shall be wiped from off the land, your every temple torn down and burned with fire! I shall bring upon you a great slaughter! From city to city death shall pursue you, and fire shall lick at your heels as you attempt to flee! Says The Lord God of Israel."},{t:"text",v:"And when the day comes, yea it has come and is here, O house of Israel, when your enemies band together and come out to fight against you with numbers beyond compare, a great multitude; every man fitted with weapons of death and slaughter, an astounding company with many machines of war, a terrible army the likes of which has never been seen..."},{t:"italic",v:"Jerusalem, O Jerusalem, shall I also forsake you, and leave you to the slaughter?! Shall I now turn My back on you, and leave you to annihilation?! O Israel, shall I let you burn in the fire?!"},{t:"text",v:"Shall I leave Jacob to be plowed like a field? Have I gathered you together in one place, only to let you be overcome by your enemies round about? For you have indeed sinned against Me and you forsake Me still. Thus I tell you plainly, behold I speak it to you once again, though you have no ears to hear - I AM THE LORD. And I have dealt with you for My own name\u2019s sake, and not according to your wicked ways, nor according to your corrupt doings, O house of Israel. Therefore, with the backward swipe of My hand shall I scatter those who have drawn near to destroy you, and with the blast of My nostrils shall all their wings be broken off! My footsteps shall shake the earth and bring destruction upon all their devices! The heat of My anger shall come up into My face, causing a terrible fire to consume them! My voice shall speak into the air, and many shall be driven mad! Behold, in My jealousy and in the fire of My wrath I shall speak, and brother shall turn against brother, and nature shall rise up and fight against them! For is this not the day spoken of by My prophets of old? Is this not the day I declared from the beginning, that it would come? Is this not the day I rise up and defend My people Israel, and cause My name to resound in all the earth?"}]},{type:"para",segments:[{t:"text",v:"Go now and read what has been written, read what the mouth of The Living God has spoken concerning all these things, and now read also that which I have spoken through My prophet of this day, and tremble in fear."}]},{type:"poetry",lines:[[{t:"italic",v:"For indeed, Jerusalem has become"}],[{t:"italic",v:"A heavy stone upon the necks of all nations,"}],[{t:"italic",v:"Even as it weighs heavily upon Mine also..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus as I have spoken it, so shall it be:"}],[{t:"italic",v:"All who seek to cast off this stone"}],[{t:"italic",v:"Shall surely be cut in pieces..."}]]},{type:"closing",text:"Says The Lord God of Hosts."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-heavy-stone-a-bitter-burden",videoVoiceUrl:"https://www.youtube.com/watch?v=a6PEVCUs6bI&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=28",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:28,prevLetter:{id:"the-pomp-of-the-nations-shall-cease",title:"The Pomp of the Nations Shall Cease"},nextLetter:{id:"without-condition",title:"Without Condition"}},{id:"without-condition",title:"Without Condition",date:"1/27/12",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy, During Men\u2019s Fellowship",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My sons, listen closely as I speak to you this parable: There were three men who devoted their lives to God, three men who sought to serve The Lord their God in righteousness. The first went out feeding the poor and the hungry, doing all he could for the needy, as he was able. The second gave everything he had to those who asked, with no thought to himself, until the day came when he had nothing more to give and he too had to ask. Yet the third did not go out, nor did he give to all who asked, but bowed down each day seeking the will of God, wanting always to walk in the ways of The Lord. Years passed by, and the three men continued in their walks, serving God each day as they were able. Then the day came when each was presented with a new choice, one which they had not faced before. To the first, The Lord sent a prophet, saying,"},{t:"italic",v:"\u201CThus says The Lord: Draw back now your hand from the needy, and no more go out to feed the poor and the hungry round about, but obey the Word of My mouth and sound the trumpet.\u201D"},{t:"text",v:"But he refused and went away in unbelief, appalled by the Word he had heard by the mouth of the prophet. The second man was faced with a similar choice; to him God sent the Word of The Lord in a book. Yet because it was not found in his Bible, the man immediately rejected it and went his way in unbelief, appalled by the Word which had been given him in the name of The Lord. And to the third, The Lord Himself said,"},{t:"italic",v:"\u201CMy son, the time has come for you to give up all you hold most dear, to give up your life for My purpose, to serve without constraint... To be greatly hated and persecuted for My name\u2019s sake.\u201D"},{t:"text",v:"And with tears streaming, the servant said,"},{t:"italic",v:"\u201CYes, Lord.\u201D"}]},{type:"para",segments:[{t:"text",v:"Therefore, My sons, I ask you, of these three men, which one was truly devoted to Me, though all did good and fruitful works? For indeed many are called, yet few are chosen, few have ears to hear. Thus learning the lesson of obedience is far greater than witnessing a prophecy come to pass, or receiving healing by a miracle. For obedience is born of love. For those who have no trust seek after signs, and those who remain in unbelief wait for miracles. And those whose requests are met, while in unbelief, will soon demand them. And those who receive a sign, yet have no trust, will only expect the more."}]},{type:"poetry",lines:[[{t:"italic",v:"Yet only those who love Me,"}],[{t:"italic",v:"Without condition, will remain faithful..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And only those who truly know Me"}],[{t:"italic",v:"Will endure in times of trouble..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/without-condition",videoVoiceUrl:"https://www.youtube.com/watch?v=G98JFed6ugY&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Parables",url:"https://answersonlygodcangive.com/Parables"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:29,prevLetter:{id:"a-heavy-stone-a-bitter-burden",title:"A Heavy Stone, a Bitter Burden"},nextLetter:{id:"fulfilled",title:"Fulfilled"}},{id:"fulfilled",title:"Fulfilled",date:"12/27/12",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, the time has come. It is time for great things to be shown in the heavens above and upon the earth beneath, for the flood gates to be opened and the storehouses emptied, for all that is hidden to be uncovered and that which slumbers to be awakened. For it is written:"},{t:"italic",v:"It shall come to pass in the last days, says The Lord, that I will pour out My spirit on all flesh, and your sons and your daughters shall prophesy, your old men shall dream dreams, your young men shall see visions. Also on My menservants and on My maidservants, I will pour out My spirit in those days. And I will show wonders in the heavens above and in the earth beneath, blood and fire and pillars of smoke. The sun shall be turned into darkness and the moon into blood, at the coming of the Great and Terrible Day of The Lord. And it shall come to pass that whoever calls on the name of The Lord shall be saved. For in Mount Zion and in Jerusalem there shall be deliverance, among the remnant whom The Lord shall call."},{t:"fn",v:"1"},{t:"text",v:"I tell you the truth, this Scripture is fulfilled, even now, as you read these words, and is also to come."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, listen to the sound of My voice..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Give heed to My speech, embrace My Word"}],[{t:"italic",v:"Spoken to this generation, and repent..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved ones, find solace in My words"}],[{t:"italic",v:"And have peace, whether brought to remembrance"}],[{t:"italic",v:"By My spirit or read upon the pages of My Book..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I am come."},{t:"fn",v:"2"}]]}],footnotes:{1:{type:"scripture",ref:"Acts 2:17-21, Joel 2:28-32"},2:{type:"note",text:'Also read: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME#I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}}},nkjv:{"Acts 2:17-21, Joel 2:28-32":"Acts 2:17-21 \u2014 17. \u2018And it shall come to pass in the last days, says God, That I will pour out of My Spirit on all flesh; Your sons and your daughters shall prophesy, Your young men shall see visions, Your old men shall dream dreams. 18. And on My menservants and on My maidservants I will pour out My Spirit in those days; And they shall prophesy. 19. I will show wonders in heaven above And signs in the earth beneath: Blood and fire and vapor of smoke. 20. The sun shall be turned into darkness, And the moon into blood, Before the coming of the great and awesome day of the LORD. 21. And it shall come to pass That whoever calls on the name of the LORD Shall be saved.\u2019 | Joel 2:28-32 \u2014 28. \u201CAnd it shall come to pass afterward That I will pour out My Spirit on all flesh; Your sons and your daughters shall prophesy, Your old men shall dream dreams, Your young men shall see visions. 29. And also on My menservants and on My maidservants I will pour out My Spirit in those days. 30. \u201CAnd I will show wonders in the heavens and in the earth: Blood and fire and pillars of smoke. 31. The sun shall be turned into darkness, And the moon into blood, Before the coming of the great and awesome day of the LORD. 32. And it shall come to pass That whoever calls on the name of the LORD Shall be saved. For in Mount Zion and in Jerusalem there shall be deliverance, As the LORD has said, Among the remnant whom the LORD calls."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/fulfilled-2",videoVoiceUrl:"https://www.youtube.com/watch?v=g9mxQujxzTI&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=30",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],num:30,prevLetter:{id:"without-condition",title:"Without Condition"},nextLetter:{id:"desolations",title:"Desolations"}},{id:"desolations",title:"Desolations",date:"1/31/13",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, the waves of the sea shall be risen up in the day of My anger, and they shall crash upon the shore and ravage the banks. The waters shall be very tumultuous, and with an awful noise they shall break down the barriers and pass through, reaching far and wide. For I shall strike the westernmost parts, causing the hidden foundations to rise up suddenly, and with great violence shall they be thrust upward from beneath. And the people shall be greatly astonished on account of the waters and due to the devastation. Behold, the day is coming and is very near, when I shall utterly devastate the coastlands and bring forth judgment, even upon the whole of this great and mighty nation. For they have not ceased from upholding their abominations, nor have they turned back from their ever-increasing perversions, nor have they put a stop to the slaughter of the innocent. Yes, they continue in their evil ways, passing laws and allowing even all things which I said they shall not do, provoking Me to anger! Therefore, I shall indeed stretch out My hand against them, and bring upon them desolations of every kind, until My wrath is satisfied and My anger has abated, says The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/desolations-4",videoVoiceUrl:"https://www.youtube.com/watch?v=bztvxWi0JRA&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=31",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"}],num:31,prevLetter:{id:"fulfilled",title:"Fulfilled"},nextLetter:null}],LETTERS_V7_PREFACE={id:"the-indignation-of-the-lord",title:"The Indignation of The Lord",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"poetry",lines:[[{t:"text",v:"No more shall I withhold My hand,"}],[{t:"text",v:"Nor stay silent, no more shall I wait;"}],[{t:"text",v:"The day is done, and the sun is setting upon this age of men."}]]},{type:"poetry",lines:[[{t:"text",v:"For My anger is kindled and burns in the heat of My wrath;"}],[{t:"text",v:"My indignation has come to the full and must be poured out!"}],[{t:"stanza-break"}],[{t:"text",v:"Like a dark storm building upon the horizon"}],[{t:"text",v:"Brings foreboding, as a great torrent inundates"}],[{t:"text",v:"A city and running waters quickly overtake a town,"}],[{t:"text",v:"Like fierce waves beat back the shore or a raging sea"}],[{t:"text",v:"Capsizes a ship, as the power of the great"}],[{t:"text",v:"Whirlwind causes widespread devastation,"}],[{t:"text",v:"So shall the indignation of The Lord be!..."}],[{t:"stanza-break"}],[{t:"text",v:"Says The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-indignation-of-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=nGRiuBZOybQ&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=1",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],isPreface:!0},LETTERS_V7=[{id:"to-the-nation-once-called-of-itself-under-god",title:"To the Nation Once Called of Itself \u201CUnder God\u201D",date:"3/28/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, doubt not yourself, nor My words which I shall speak to you this day. For you are delivered out of the hand of the oppressor, even of all he shall send against you. For you are My prophet, and you shall endure; even by the power of My own right hand shall I prosper you. Yea, you shall grow strong and proclaim My Word to those who are near and to those afar off. You shall speak to the believer and unbeliever alike, and declare My judgments against the wicked and your enemy, Ishmael; even against your own nation and the churches of men shall you trumpet My strong rebuke. For your nation has gone the way of the wicked and the heathen, and the churches of men do not cease from polluting My name. Behold, even Sodom and Gomorrah are revived and thrive before My face, within your nation\u2019s borders. Yet I withhold My hand for the sake of the elect, for they must shortly be taken out of the way."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, O mighty and perverse nation, for thus says The Lord:"},{t:"text",v:"I AM AGAINST YOU! Yes, I am against you, O nation of harlots! For I had made you strong and gave you blessings beyond compare, yet you turn your face from Me, and blaspheme the name of The One who bought you in His own blood! -"},{t:"italic",v:"Beaten, scourged and mocked, crucified, pierced for your transgressions!"},{t:"text",v:"Yet you turn your back on Him and use His name as a cursing! DESECRATION! BLASPHEMY! Therefore you, O nation not desired, are given into the hands of your enemies, and they shall kill you and burn you with fire and tear down your tall towers! Yet you shall raise your hand in great anger and haste, and repay them double! Says The Lord of Hosts. For as you are given up, so shall they be given into your hand for retribution; even double shall you afflict them, even double shall they receive at your hand! Behold, you shall be swift and very terrible in your vengeance! You shall come upon them like a dark storm, and as a great whirlwind you shall tear them in pieces! Yet the end is not yet. For there are those among you who I know and in whom I see of Myself; these must be taken out of the way. Then you shall fall, O mighty nation, and great shall be your fall! For then shall arise one whom you shall fear. And all who feared you shall fear him. And those who served you, you shall serve. And you will not be satisfied, you will grumble and not sit still, but in false hope you shall rise up and meet your end, plucked up and put underfoot by the lawless one, he who is full of wickedness and lying, says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Churches of men, you also refuse to listen, nor will you give heed to My correction; therefore hear the Word of The Lord, for thus says The Lord:"},{t:"text",v:"You have all gone out of the way! You have corrupted My Word for your own glory! Pride has become your master and greed has entered your houses, houses which bear MY name! DESECRATION! BLASPHEMY! I dwell not in any church made by human hands; I dwell in the temples made by My own hands! O churches of arrogance, how shall I gather you when you resist all correction and follow after the vain babblings of men in authority, heaping to yourselves teachers, wolves in sheep\u2019s clothing, saying the Word of God is the way to riches and material things?! Woe, I say to you who follow these acolytes of satan! False teachers! Soothsayers! Desolations are coming and great want! How then shall all these silver coins and paper, houses made of brick and wood, save you?! The riches of men shall be taken from them in a day! What then shall you stand upon, O men of vanities and vain deceits? Where shall you hide?! Churches of men, cast out these leaders who speak as doves and teach doctrines of devils! My children, wash your robes and purify your houses, for The Holy One comes nigh! Be not left in bitter sorrows, abased in the Great and Terrible Day of The Lord! Cast away these false doctrines and filthy traditions; stop committing fornication with the harlot! Repent therefore, and come out of her! Take not one of her corrupt doctrines to yourself, stand apart from her traditions, for they are most perverse! For I tell you the truth, you all remain like her! Says The Lord. From the least to the greatest, you all pollute My name by your traditions and profane My Word by your doctrines! Behold, you have agreed together to forsake My Law and forget My Sabbaths, justifying your transgression in the name of Grace, upholding your sin by permission in the name of The Messiah, whom you call Christ! DESECRATION! GREAT BLASPHEMY! You follow another messiah, a false christ, a molded image, which your forefathers created and you continue to mold to this day! Return to Me, therefore, and seek your Savior in truth, that you may now embrace Him as He truly is! For YahuShua, yes He whom you call Jesus, is your only Sanctuary from the storm. To Him alone shall you flock, His flesh shall you eat, His blood shall you drink. Walk in HIS ways as they are, and not as you would have them be. Put away all your holidays, and no more worship Me in that way,"},{t:"fn",v:"1"},{t:"text",v:"for it is most perverse. Seek now the way of true righteousness, and obey all My commands; set all these crooked paths straight, and you may yet escape all these things which are about to come upon you."}]},{type:"poetry",lines:[[{t:"italic",v:"TURN TO GOD!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Turn to Me as I am, and not as you would have Me be!"}],[{t:"italic",v:"For The Holy One comes quickly to deliver His own!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, you shall see the angels of Heaven"}],[{t:"italic",v:"Ascending and descending upon The Son of Man;"},{t:"fn",v:"2"}],[{t:"italic",v:"The sleepers shall awake, and you who are yet awake,"}],[{t:"italic",v:"Having been fully awakened to Him, shall be caught up"}],[{t:"italic",v:"With them to meet The Lord in the air, as it is written;"}],[{t:"italic",v:"And forever shall you be with The Lord..."},{t:"fn",v:"3"}]]},{type:"poetry",lines:[[{t:"italic",v:"Purify your faith! Purify your worship! Purify your houses!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Do it now! Says The Lord God, Creator of Heaven and Earth."}]]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Holy One of Israel:"},{t:"text",v:"I have come not to make peace, but war, even war in My members - a great division,"},{t:"fn",v:"4"},{t:"text",v:"the scourging of nations, the wrath of God! For the fulfillment of all that is written is at hand, and shall progress quickly. Yet for the sake of the elect, it shall be cut short. Beloved of My heart, be not troubled nor weep, for these things must be. Then the end shall come, and I shall reveal My glory. Behold, I shall cleanse the sanctuary and restore the garden, and you shall learn war no more"},{t:"fn",v:"5"},{t:"text",v:"- NO MORE! Says The Lord. For I died; behold, I am risen! And so as I died, sin has also died in those who love Me. And that which leads My people into sin shall also be destroyed, ground to dust beneath My feet, carried away upon the winds of restoration, which I am..."},{t:"italic",v:"Behold, The Morning Star is risen, the universe is filled with His glory! And that glory shall abide with men, even in them and among them! I shall be a Father unto them, and they shall be My beloved children, forever! Lo, a return to innocence, paradise lost is paradise found, a return to the garden - the universe, your playground."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus I have spoken, so shall it be:"}]]},{type:"poetry",lines:[[{t:"italic",v:"The mystery of God revealed,"}],[{t:"italic",v:"The counting of days no more..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Forever young in the presence of"}],[{t:"italic",v:"Your Shepherd, your Redeemer, your Father,"}],[{t:"italic",v:"Your Brother, your Most Beloved Friend..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The fulfillment of all things"}],[{t:"italic",v:"For which your hearts have groaned..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE MEANING OF LIFE!"}],[{t:"italic",v:"And all who live in Me, and I in them, will live forever!"}]]}],footnotes:{1:{type:"scripture",ref:"Deuteronomy 12:31"},2:{type:"scripture",ref:"John 1:51"},3:{type:"scripture",ref:"1 Thessalonians 4:17"},4:{type:"scripture",ref:"Luke 12:51"},5:{type:"scripture",ref:"Isaiah 2:4"}},nkjv:{"Deuteronomy 12:31":"You shall not worship the LORD your God in that way; for every abomination to the LORD which He hates they have done to their gods; for they burn even their sons and daughters in the fire to their gods.","John 1:51":"And He said to him, \u201CMost assuredly, I say to you, hereafter you shall see heaven open, and the angels of God ascending and descending upon the Son of Man.\u201D","1 Thessalonians 4:17":"Then we who are alive and remain shall be caught up together with them in the clouds to meet the Lord in the air. And thus we shall always be with the Lord.","Luke 12:51":"Do you suppose that I came to give peace on earth? I tell you, not at all, but rather division.","Isaiah 2:4":"He shall judge between the nations, And rebuke many people; They shall beat their swords into plowshares, And their spears into pruning hooks; Nation shall not lift up sword against nation, Neither shall they learn war anymore."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/to-the-nation-once-called-of-itself-under-god-2",videoVoiceUrl:"https://www.youtube.com/watch?v=0JiFP1xP6zg&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord_.28Section_One.29"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Antichrist",url:"https://answersonlygodcangive.com/Regarding_the_Antichrist"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men_-_Section_One"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord_.28Section_One.29"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#The_Coming_of_The_Lord"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:1,prevLetter:null,nextLetter:{id:"punishment",title:"Punishment"}},{id:"punishment",title:"Punishment",date:"5/2/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Come forth, O acolytes of satan, all you wicked vipers who shake your fists at Heaven and spit at The King! Come and hiss at My chosen, that I may strike you down! For from the dust had I formed you, and to the dust shall you return!"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"For thus is the eternal state of My punishment, thus is the punishment you shall receive at My own hand:"},{t:"italic",v:"Destruction in the lake that burns, consumed in an instant, gone from My presence forever!"},{t:"text",v:"Darkness, outer darkness, nothingness is your reward! And you shall never even know you had received it or received it not! You shall know NOTHING, nor shall you have ANY part in life! It is taken from you, and shall never again be granted to you; your inheritance lost, your existence blotted out!"}]},{type:"poetry",lines:[[{t:"italic",v:"THIS, O perverse generation,"}],[{t:"italic",v:"Is the eternal state of My punishment;"},{t:"fn",v:"2"}],[{t:"italic",v:"For the lake of My burning heart is"}],[{t:"italic",v:"Judgment and not life, a consuming fire!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THEREFORE TURN! SAYS THE LORD..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Depart from your wicked ways,"}],[{t:"italic",v:"Heed the Call and take warning,"},{t:"fn",v:"3"}]]},{type:"poetry",lines:[[{t:"italic",v:"And REPENT!"}]]}],footnotes:{1:{type:"scripture",ref:"Genesis 3:19"},2:{type:"note",text:'See: "PART 2 - Q & A: What is the Fate of the Wicked?"',url:"https://www.thevolumesoftruth.com/The_State_of_the_Dead_and_The_Fate_of_the_Wicked:_The_False_Doctrine_of_Hell_and_Eternal_Torment_Exposed#PART_2_-_Q_.26_A:_What_is_the_Fate_of_the_Wicked.3F",link:{collection:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",letterTitle:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed"}},3:{type:"scripture",ref:"Ezekiel 33:4-5"}},nkjv:{"Genesis 3:19":"In the sweat of your face you shall eat bread Till you return to the ground, For out of it you were taken; For dust you are, And to dust you shall return.","Ezekiel 33:4-5":"4. then whoever hears the sound of the trumpet and does not take warning, if the sword comes and takes him away, his blood shall be on his own head. 5. He heard the sound of the trumpet, but did not take warning; his blood shall be upon himself. But he who takes warning will save his life."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/punishment-2",videoVoiceUrl:"https://www.youtube.com/watch?v=vZdfDZXk2WE&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"}],num:2,prevLetter:{id:"to-the-nation-once-called-of-itself-under-god",title:"To the Nation Once Called of Itself \u201CUnder God\u201D"},nextLetter:{id:"to-all-those-who-speak-against-the-word-of-the-lord-given-to-timothy",title:"To All Those Who Speak Against the Word of The Lord Given to Timothy"}},{id:"to-all-those-who-speak-against-the-word-of-the-lord-given-to-timothy",title:"To All Those Who Speak Against the Word of The Lord Given to Timothy",date:"5/21/07",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to all those who reject My words and persecute My messengers, and then have the gall to call themselves My servants:"},{t:"text",v:"You have gone out of the way, thinking you stand! YOU DO NOT STAND! For you have stood against Me, rejecting My Word which I have spoken through My prophet! THIS IS NOT TO STAND! Thus you shall be brought very low; you shall not be gathered, neither will I hear your pleas. For you have forsaken Me in favor of your own way! YOU HAVE SURELY BETRAYED THE SON OF THE LIVING GOD! Behold, in open and in secret, you slander My name and pervert My way before Me! Sons and daughters of men, did you think I would stay silent?! My prophets speak, My watchmen blow the trumpet, and My servants prepare My way before Me. Yet you cover your ears and hide your faces, saying within yourselves,"},{t:"italic",v:"\u201CI already hear and will not heed any trumpet, other than that which I have made or was put in my hand by man and not God. For I alone am righteous, and these with me know God\u2019s will, and WE shall teach others. And we will by no means listen to these sent. We shall stone them in word and by deed, and cast ALL their cords from us, saying, \u2018You shall no more speak in The Lord\u2019s name!\u2019\u201D"},{t:"text",v:"Yet I ask you, WHO have you reproached and blasphemed?! Against WHOM have you raised your voice and haughtily lifted up your eyes?! IT IS I, EVEN I, THE HOLY ONE OF ISRAEL AGAINST WHOM YOU SPEAK! Therefore it is fulfilled, and shall come to pass: Many who call of themselves Christian shall come forth in the day of their humiliation, saying,"},{t:"italic",v:"\u201CLord, Lord, have we not prophesied in Your name, cast out demons in Your name, and done many wonderful works in Your name?\u201D And I will declare to them, \u201CI never knew you.\u201D"},{t:"fn",v:"1"},{t:"text",v:"For if you truly knew Me, and I lived in you, then you would recognize those I send and the Word given them. Yet you forbear, resting always upon beds of false doctrine, the doctrines of men! Therefore you shall not be gathered, for I do not see of Myself in you. And though you speak My words instant in and out of season, you open your mouths in vain. For you do always add to and take away from My words, in an effort to uphold your own way. Know you not, that which is of God has salt in itself and in no wise needs seasoning?"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore get wisdom, get understanding, and repent!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Do not forget, nor turn away from the"}],[{t:"italic",v:"Words of My mouth, but heed the sound"}],[{t:"italic",v:"Of this Trumpet, that you may escape"}],[{t:"italic",v:"All these things which I am about to do..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Forbear, and you shall surely endure refinement"}],[{t:"italic",v:"In the Day of The Lord, and only by great"}],[{t:"italic",v:"Tribulation shall you come into glory."}]]},{type:"para",segments:[{t:"text",v:"For I am The Lord, and I shall surely correct and discipline all those I love; yes, even all who have been led astray and teach others in like manner, all in all a leading away from the Truth as I Myself have spoken it and how it was meant to be received. For you know not the mind of God, nor have you heard My voice, neither will you listen, says The Lord. Therefore, come out from among them and be separate; be joined unto Me! Look past My prophet, and see with greater eyes! For your ego has crippled you, and your corrupt knowledge has caused you to blaspheme My words! Therefore, again I say, REPENT! Call upon My name in spirit and in truth, with all humility, that you may receive true understanding! Depart from all these vanities! Stop desecrating My Word in the Scriptures of Truth, for your own glory! Humility and steadfast faith is what I require; disciples who obey My teaching, striving always to walk in My ways; servants who keep The Commandments as they are written and not as you would have them be; vessels who carry Me within them and do not cease from testifying to the truth of who I am, by all they say and do. Beloved ones, you can not serve both God and men! For all these men in authority, within the churches of men, are perverse in their segregation of My Word! For as it is written:"},{t:"italic",v:"They profess to know God, but in works they deny Me, being abominable, disobedient, and disqualified for every good work."},{t:"fn",v:"2"},{t:"text",v:"For you have divided My Word, O churches of men, yes, you have divided it, and it shall slay you! For the day is coming when you shall be struck to the heart and you shall wail, when again this same one, against whom you have brought all manner of false accusations, comes to you in the Day of Sorrows, saying,"},{t:"italic",v:"\u201CThus says The Lord,\u201D"},{t:"text",v:"and you realize that all you have done has been found wanting."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore again, I call you to repent, to turn aside"}],[{t:"italic",v:"From this corrupt way you have chosen,"}],[{t:"italic",v:"To come out of the churches of men!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"That I, Myself, may once again place your feet"}],[{t:"italic",v:"Back on the path of truth and righteousness..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as I am, so shall I be;"}],[{t:"italic",v:"As I have spoken, so I speak..."}]]},{type:"closing",text:"For I am The Lord, and I DO NOT CHANGE."}],footnotes:{1:{type:"scripture",ref:"Matthew 7:22-23"},2:{type:"scripture",ref:"Titus 1:16"}},nkjv:{"Matthew 7:22-23":"22. Many will say to Me in that day, \u2018Lord, Lord, have we not prophesied in Your name, cast out demons in Your name, and done many wonders in Your name?\u2019 23. And then I will declare to them, \u2018I never knew you; depart from Me, you who practice lawlessness!\u2019","Titus 1:16":"They profess to know God, but in works they deny Him, being abominable, disobedient, and disqualified for every good work."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/to-all-those-who-speak-against-the-word-of-the-lord-given-to-timothy-2",videoVoiceUrl:"https://www.youtube.com/watch?v=iTYKXIIFT4U&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=4",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men_-_Section_One"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"False Doctrines Within the Churches of Men Regarding...",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],num:3,prevLetter:{id:"punishment",title:"Punishment"},nextLetter:{id:"salvation-is-given-and-must-be-received-once-received-forever-shall-it-belong-to-the-redeemed",title:"Salvation Is Given and Must Be Received; Once Received, Forever Shall It Belong to the Redeemed"}},{id:"salvation-is-given-and-must-be-received-once-received-forever-shall-it-belong-to-the-redeemed",title:"Salvation Is Given and Must Be Received; Once Received, Forever Shall It Belong to the Redeemed",date:"6/19/07",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a brother in Christ: Lord, can our salvation be lost?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Timothy, write as I speak; hear My words and give Me glory. For in My Word is glory, even the Truth, of which no man shall change. For if any man attempts to change that which I have spoken for his own glory, or in the serving of the evil one, even that man shall I destroy, says The Lord."}]},{type:"para",segments:[{t:"text",v:"So then, you have come before Me asking on your brother\u2019s behalf, though he asks in the testing of you; yet not according to the Truth or that written in the Scriptures, but according to the doctrines of men, of which he has already accepted. Yet I will speak for the sake of your asking, and for the edification of him you call brother. For he is My son also, though he does not yet believe you are who you claim to be. And for this reason I have commanded you to write My words, so for surety all may know and understand, that salvation gained is assured. For it is not by gain you have received it, rather it is by grace, The Gift of The Father..."},{t:"italic",v:"Ransomed through the blood of The Son."},{t:"text",v:"Therefore, concerning all these The Father has given Me, I shall not lose one. For those who come to Me are drawn to Me by The Father, and shall in no wise be cast out."}]},{type:"para",segments:[{t:"text",v:"Yet there are those among you who say it is written by the prophet, that when the righteous turn from their righteousness and commit iniquity, The Father will in turn remember their righteous deeds no more, and because of their unfaithfulness they shall surely die. This saying is true, and was spoken by the prophets of old according to The Old Covenant, and should indeed be taken to heart. Yet understand this, all you haughty scholars and prideful teachers, even all you who call of yourselves Christian who make arrogant assertions without knowledge, you lack trust and have no understanding! Nor do you know your God, nor that covenant written in My own blood, which is The New and Everlasting Covenant. For I died; behold, I am risen! I am alive forevermore! Amen! And as I live, so shall the penitent man live. Even if he should turn and stumble, his salvation is in no wise lost to him. For he has an Advocate with The Father, One who stands in his place, having already paid the full price for his transgression; behold, his sin is remembered no more, cast into a dark sea of forgetfulness!..."},{t:"italic",v:"And oh how blessed are those who strive always to make their repentance full, "},{t:"fn",v:"1"},{t:"italic",v:" says The Lord."},{t:"text",v:"Yet there are many who call of themselves Christian, who say,"},{t:"italic",v:"\u201CIf a man turn from The Lord and commit wickedness, even this same man has lost his salvation and shall suffer in the fires of hell.\u201D"},{t:"text",v:"Again, I say to you, you know neither Me nor My Father who is in Heaven! For if you knew Him, and had truly accepted Me and My Word, then I would live in you. And if I truly lived in you, you would understand God\u2019s mercy which endures forever..."},{t:"italic",v:"I am that mercy, who lives forever to intercede on your behalf!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, O arrogant generation, you do greatly err;"}],[{t:"italic",v:"For upon this one truth is The Kingdom"}],[{t:"italic",v:"Built and everlasting life established:"}]]},{type:"poetry",lines:[[{t:"italic",v:"Salvation received in Me is forever, as I am forever and unchanging..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I have already told you, this is a cord which can not be broken."}],[{t:"italic",v:"It is made of the finest thread and the strongest steel,"}],[{t:"italic",v:"And in no wise shall death prevail."}]]},{type:"para",segments:[{t:"text",v:"And by no means shall one be cast into hell, to suffer day and night without end. This teaching is FALSE, myth, borrowed from the deceiver who upon all pagan religion was built. Sons of men, know you not what the Scriptures say, that whosoever believes in The Son abides forever, and whoever has not The Son shall perish and not see life? How then shall one say that whether one believes or believes not, both have eternal life? This teaching among the churches is of the church called Mother, and is of her father the devil, of which she continually emulates, seeking after her own glory which she claims she had received from Me..."},{t:"italic",v:"She shall be torn in pieces!"}]},{type:"para",segments:[{t:"text",v:"Behold, the day is coming and is already here, when this world shall be judged; yes, it has come and is yet coming. Yet there are those among you, of whom I love, who say they love Me yet do not obey My voice, nor will they listen. For they do adhere closely to the doctrines and traditions of men, even to all their holidays which are perverse in My sight, mixing that which is holy with the profane, as a harlot perverting her way among many lovers. So then behold the Day, where all those who come to Me in truth, being fully converted in their hearts, who also obey My voice and keep The Commandments, shall be taken; behold, they shall surely be gone from this place! Yet to the rest, though they have called on My name (the name by which I am known among them), with raised hands and many supplications, even unto vain babblings, they shall surely be left. For I have looked upon them, I have peered deep within, and I know they are not truly converted in their hearts; neither will they harken to My voice, nor will they give heed to My Commandments. For they do always dishonor Me, as they pervert My name among the people by all they say and do. Yes, even these, who call of themselves Christian, shall be left in the midst of thick clouds and darkness on that day. For it is a day of refinement and tears, a day of heavy sorrows and bitter weeping. Therefore, I ask you, have these lost their salvation? Had they truly received? Do I live in them? For all who truly receive of Me know Me, and I live in them. And if I live in them, then in no wise will these turn away. For one who abides in My love shall never leave it. For they have tasted of the divine gift and have looked upon My glory. They will not depart from Me, but rest securely at My right hand. These are My sheep, the tame of My flock; they call out and I do hear them, even as I had called to them and they did hear. All My sheep hear My voice and know the sound of My voice, and seek to follow Me wheresoever I lead them. Yet there are many scattered sheep who remain wild, who have also been given Me of My Father; these I must bring also. Lo, they shall be tried in the furnace, refined by fire unto pure white stones, of which all shall be given new names. They shall come to Me by great tribulation and shall be made white in My own blood, bringing glory to My name, even the name of The Father who is in Heaven, the name We share. And they shall all become one flock, with one Shepherd. Behold, I shall be their God, and they shall be My people, forever! Says The Lord. For Salvation has come and shall in no wise depart from My people. For that which was corrupted is made new in Me, and will soon be refashioned of that which is incorruptible. For all who come to Me in sincerity and in truth are saved, having been saved from the beginning. And all those who say they know Me, then turn away, never really knew Me, nor had they truly come to Me, having spoken in vain. Thus by the heart is one judged, of which I know, for nothing is hidden before Me. I made you and know you, having always known you; even those who will yet come to Me, I see and know. For I see you as you are and will be, with Me where I am. Thus salvation can not be lost, once given, for it is only given to those who will receive. For those written in My Book were written there from the foundation of the world, of which I was also slain..."},{t:"italic",v:"Behold, I am risen! For I AM, and LIFE IS because of Me!"},{t:"text",v:"So then that atoned for by My blood is far-reaching, even across all boundaries, life and death, time and space. For even those before Me were after Me, and knew The Father, who knowing Him knew and saw the time of My coming, having repented before The Father in His name, which is also My name, the name We shared before the world was made."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, understand Glory and the power of the cross,"}],[{t:"italic",v:"By which I have sprinkled all nations, all peoples and all men:"}]]},{type:"poetry",lines:[[{t:"italic",v:"Only one\u2019s complete rejection of this Truth,"}],[{t:"italic",v:"In the hating of My name, keeps them from Salvation and Life,"}],[{t:"italic",v:"Of which I offer them in rivers of living water mixed with My own blood,"}],[{t:"italic",v:"Which is poured out from My side, of which all must drink,"}],[{t:"italic",v:"Even to the eating of My flesh to have life, life without end..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And so the day is coming and is already here, when all shall know"}],[{t:"italic",v:"God and the power of The Messiah, when all shall sit before My throne;"}],[{t:"italic",v:"Some to My right hand, and some to My left; even so, amen..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, let it be done and come to pass according"}],[{t:"italic",v:"To how it is and was written; behold, even by"}],[{t:"italic",v:"My own hand shall all things be fulfilled..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come to Me, therefore! Come to Me in spirit and in truth!"}],[{t:"italic",v:"Beloved, gather around, and let Me heal you and sanctify you!"}]]},{type:"poetry",lines:[[{t:"italic",v:"Your salvation is assured!"}]]}],footnotes:{1:{type:"note",text:'Also read: "True Repentance"',url:"https://www.thevolumesoftruth.com/True_Repentance",link:{collection:"Letters to The Lord's Little Flock",letterTitle:"True Repentance"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/salvation-is-given-and-must-be-received-once-received-forever-shall-it-belong-to-the-redeemed",videoVoiceUrl:"https://www.youtube.com/watch?v=MVrOnwRLufE&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=3",videoMusicUrl:"https://www.youtube.com/watch?v=Yoq62SWaYN0&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=22",relatedTopics:[{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"False Doctrines Within the Churches of Men Regarding...",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],num:4,prevLetter:{id:"to-all-those-who-speak-against-the-word-of-the-lord-given-to-timothy",title:"To All Those Who Speak Against the Word of The Lord Given to Timothy"},nextLetter:{id:"the-lord-has-spoken-and-will-not-repent-heed-his-words-and-give-him-glory",title:"The Lord Has Spoken and Will Not Repent; Heed His Words and Give Him Glory"}},{id:"the-lord-has-spoken-and-will-not-repent-heed-his-words-and-give-him-glory",title:"The Lord Has Spoken and Will Not Repent; Heed His Words and Give Him Glory",date:"7/17/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, look upon these who have caused you such great distress and heartache, all these who have spoken against you in harsh tones, with anger, reproach, contempt and backbitings, in the name of envy and pride, and tell Me, against whom have these spoken and with whom do they contend? Against whom have these gathered? They do rebel against The Lord their God, for they can not bear to hear the Truth Absolute! They long for that which is malleable, embracing only that which yields to their own perverse desires and expectations. Therefore take not one word to yourself, Timothy, not one. Rather pray for them. For though they are learned, they have become as the unlearned. They know not the things of God, nor do they abide in The Messiah, neither does He live in them. They have turned their faces from Me, shining their false light before men, according to those same corrupt doctrines and filthy traditions passed down to them by their forefathers. How is it then, that you contend with them in the same manner they contend with you? Have you written all these Letters? Have you done all these things by your own commandment? Have you taught or planted even one seed of truth, according to your own understanding or knowledge? Vanity, Timothy, vanity! Taking all these accusations and backbitings to yourself is great arrogance, the seeds of pride and vanity! For in the defending of yourself, you have taken all I have given you and made it your own unwittingly. This is MY Word, MY understanding, and MY knowledge, My own spirit through which you have received all these things. Therefore step down from My throne and humble yourself, and repent! Or have you so quickly forgotten that vengeance is Mine, I shall repay? Thus all those who say they know Me, then turn and strike Me upon the mouth, never knew Me. And all who call of themselves Christian and Jew, who do not cease from fighting against Me, shall surely be rebuked and chastened. For I correct and discipline all those I love, even as I have done with you. Yet understand this also: All who refuse to give heed to My words, and cast stones at My prophets by every contemptuous word and deed, in open and in secret, shall by no means escape the Day of The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Shall I reward them based solely upon their proclamation of faith in My name?!"}],[{t:"italic",v:"Shall the Jew who rejects Messiah be gathered, simply because"}],[{t:"italic",v:"He is an adherent of Judaism or a descendant of Israel?"}],[{t:"italic",v:"Shall the Christian escape because they have repented in My name,"}],[{t:"italic",v:"Though they make no effort to make their repentance full?"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shall any, who pollute My name and pervert My Word in Scripture, be delivered?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I search the hearts and minds, even to the innermost,"}],[{t:"italic",v:"And I know whether or not you have been truly"}],[{t:"italic",v:"Converted in your hearts, O faithless generation!"}]]},{type:"para",segments:[{t:"text",v:"So then all these who speak presumptuously in My name, who seem oh so righteous before men, can not cover over their heart\u2019s true intent with elevated words and prepared speeches, or by the quoting of Scripture. Rather that done and that spoken, whether in truth or for a pretense, was first born in the heart, in accordance with one\u2019s innermost thoughts and intentions. Yet as it is written:"},{t:"italic",v:"There is nothing concealed which will not be exposed, nor anything hidden which shall not be revealed and brought into the light of day;"},{t:"fn",v:"2"},{t:"text",v:"all will be made known. Therefore, Timothy, fear none of these who persecute you, nor strive over words with them, for they are but flesh. They have ears, yet refuse to hear; they have eyes, yet refuse to see; they want no part with Me as I truly am. Thus when even one word of My correction is spoken against them, they do quickly plug their ears and cover their faces, lest they should be found guilty of teaching heresies and blasphemies before God, in the name of The Son. Again, shall I reward them for these things? Shall I deliver them, though they have learned nothing of the Truth as it was meant to be received, preached, and lived in, abiding wholly in the doctrine of The Messiah, whose disciples they claim to be though they do not follow Him?! Behold, they carry no cross at all, refusing to pick it up for its weight! Neither do they ask for strength, but do always turn aside after satan!"}]},{type:"para",segments:[{t:"text",v:"Timothy, I have given you a sword, not a handcart. Therefore trust in Me, and use what I have given you. For My sickle is poised and ready for reaping, yet the harvest must first be prepared and separated. You are sent as a teacher and prophet to those of a humble heart who do always seek My face, and as a watchman and soldier to those who continually resist My Word and blaspheme My spirit."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the hearts of both the seeker and the obstinate"}],[{t:"italic",v:"Shall be pierced, and the wicked struck through..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The Lord your God is no respecter of persons, neither do I change;"}],[{t:"italic",v:"For I AM, and forever shall I be, the same and unchanging..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus I have spoken and shall not repent;"}],[{t:"italic",v:"Therefore heed My words and give Me glory!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you the truth, all shall come to pass and be fulfilled,"}],[{t:"italic",v:"Even before the eyes of THIS generation!"}]]},{type:"poetry",lines:[[{t:"italic",v:"Then you shall know, I AM THE LORD,"}],[{t:"italic",v:"And a prophet had been among you."}]]}],footnotes:{1:{type:"note",text:'See: "Regarding True Repentance"',url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},2:{type:"scripture",ref:"Luke 8:17"}},nkjv:{"Luke 8:17":"For nothing is secret that will not be revealed, nor anything hidden that will not be known and come to light."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-lord-has-spoken-and-will-not-repent-heed-his-words-and-give-him-glory",videoVoiceUrl:"https://www.youtube.com/watch?v=cYODnpbf2DM&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=4",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"}],num:5,prevLetter:{id:"salvation-is-given-and-must-be-received-once-received-forever-shall-it-belong-to-the-redeemed",title:"Salvation Is Given and Must Be Received; Once Received, Forever Shall It Belong to the Redeemed"},nextLetter:{id:"the-prophets-are-sent-out-true-and-false-the-high-minded-abased-the-lowly-uplifted-the-great-and-terrible-day-of-the-lord-is-near-and-who-shall-stand",title:"The Prophets Are Sent Out, True and False; the High-Minded Abased, the Lowly Uplifted... The Great and Terrible Day of The Lord Is Near, and Who Shall Stand"}},{id:"the-prophets-are-sent-out-true-and-false-the-high-minded-abased-the-lowly-uplifted-the-great-and-terrible-day-of-the-lord-is-near-and-who-shall-stand",title:"The Prophets Are Sent Out, True and False; the High-Minded Abased, the Lowly Uplifted... The Great and Terrible Day of The Lord Is Near, and Who Shall Stand",date:"9/29/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"I am The Lord your God who brought His people out of Egypt. I am The Lord God of Heaven and Earth. I am THE GOD; there is none besides Me. Behold, I came down to you in the flesh, and many beheld My face in The Redeemer. And now I am come again, "},{t:"fn",v:"1"},{t:"text",v:" even to the outpouring of My spirit on all flesh."}]},{type:"para",segments:[{t:"text",v:"Yet you of this world will not receive Me! Therefore I am sending out many in My own name, in the spirit and power of Elijah, to prepare My way before Me. Yet you shall persecute them, and they shall be despised by all nations. Behold, a great hissing shall arise even among My own people, and many mocking voices shall come forth from among those who call of themselves Christian and Jew. Even from among the devout of Israel shall many step forward to stone them in word and by deed, for they do always walk in the ways of their forefathers. Yet undaunted shall My witnesses in turn speak louder, with the power of The Lord in their nostrils! - A whirlwind of words and proclamations, miraculous signs and wonders, all in the name of YahuShua The Messiah, to the astonishment of the people! They shall blow the Trumpet and call upon the name of The Lord, in judgment and sanctification alike, yet they shall not raise a hand against another in violence. For theirs is the war of words, and strong shall the word of their mouth be. For as it was in the days of Noah, so shall the coming of The Son of Man be; as it was in Egypt, so shall it be in the Day of Preparation:"},{t:"italic",v:"A time of judgment and wrath, plus one hundred fold."},{t:"text",v:"As it was in all days past when I sent out My prophets, showing mighty signs and wonders, so shall it be at this time also. Beware, for the evil one shall attempt the same. Yet believe not these prophets, nor listen to their subtle and dark speeches. Neither believe your eyes, though you behold their false signs and wonders - trickery, dark sentences, the power of the pit, deceptions clothed in falsehoods with a veneer of light and truth."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore have understanding and seek wisdom,"}],[{t:"italic",v:"Know who I have sent and who I am sending..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The prophets, My witnesses, 144,000,"}],[{t:"italic",v:"Who cease not from glorifying My name day and night..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Gifts and wonders without price,"}],[{t:"italic",v:"All in the name of The One True God"}],[{t:"italic",v:"And YahuShua The Messiah, The Risen One."}]]},{type:"para",segments:[{t:"text",v:"Therefore, My people, unless His name be called out in truth, by no means shall one tittle come to pass or be accounted as true. Turn your back on all who say,"},{t:"italic",v:"\u201CPeace, peace,\u201D"},{t:"text",v:"when there is no peace! And run from those who say,"},{t:"italic",v:"\u201CThere are no more prophets of God,\u201D"},{t:"text",v:"as they subvert whole households, teaching things which they ought not for the sake of dishonest gain! Run, I say, and do not look back! Be wary and vigilant. And to all those who dwell in the churches of men, I say this:"},{t:"italic",v:"Pray, and open not your mouths; pray and be quiet, and open not your mouths; pray and give heed, for the mouth of The Living God has spoken."},{t:"text",v:"Discern the spirit of those I am sending, and listen to those I have sent already. Speak not one word against them, not in open, nor in secret. Speak not one word against them, for you speak against Me; I have sent them! Behold, they carry nothing of their own, they have taken nothing with them. For I have put My words in their mouths, My trumpet has been placed in their hands, and by the power of My own spirit shall I establish them; it is I who overshadows them. These are they who are not defiled by the corrupt doctrines and filthy traditions of the churches of men. Indeed, they stand apart from every religion, and remain spiritually undefiled, men of valor bought for a price, set apart for My purpose. Thus they shall take of Mine, and through the power of My spirit show it to you. For that which is Mine is The Son\u2019s also. And that which is His He shall share with those who walk in union with Him, that I may be glorified in Him and He in them."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to the churches of men and to all who lead them:"},{t:"text",v:"You shall stay silent and open not your mouths. And you shall give heed to My every decree, and now strive to obey ALL My Commandments. Yet forbear and speak, and I Myself shall come against you, on a day you did not look for and at an hour you did not expect, striking you dumb, leaving you mute for a whole season, abased in the sight of many witnesses! Thus those who were full shall be left empty, so they may be truly filled up, and those who were thought of as first shall be last. Yet those who were forsaken as last shall be first partakers of The Glory. And those without knowledge shall be given great knowledge, for Love has saved them. Yet those who had attained great knowledge shall be brought down to shame, so they too may be glorified in My presence, for Love has saved them."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore let it be written and understood,"}],[{t:"italic",v:"For it shall surely come to pass:"}]]},{type:"poetry",lines:[[{t:"italic",v:"Nothing, nothing in all creation,"}],[{t:"italic",v:"Can usurp the will of The Most High God!"}],[{t:"italic",v:"Nor shall any run out ahead of Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"MY will shall be done on earth as it is in Heaven,"}],[{t:"italic",v:"For it is purposed and can not be moved,"}],[{t:"italic",v:"Having been written in everlasting stone"}],[{t:"italic",v:"From the very foundation of the world..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"note",text:'Also read: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-prophets-are-sent-out-true-and-false-the-high-minded-abased-the-lowly-uplifted-the-great-and-terrible-day-of-the-lord-is-near-and-who-shall-stand",videoVoiceUrl:"https://www.youtube.com/watch?v=jdkVq-A4JV4&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"The Coming of The Son of Man",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#The_Coming_of_The_Son_of_Man"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:6,prevLetter:{id:"the-lord-has-spoken-and-will-not-repent-heed-his-words-and-give-him-glory",title:"The Lord Has Spoken and Will Not Repent; Heed His Words and Give Him Glory"},nextLetter:{id:"a-day-of-thick-clouds-and-darkness-bitter-sorrows-the-day-of-deliverance-and-judgment-the-day-of-the-lord",title:"A Day of Thick Clouds and Darkness, Bitter Sorrows... The Day of Deliverance and Judgment, The Day of The Lord"}},{id:"a-day-of-thick-clouds-and-darkness-bitter-sorrows-the-day-of-deliverance-and-judgment-the-day-of-the-lord",title:"A Day of Thick Clouds and Darkness, Bitter Sorrows... The Day of Deliverance and Judgment, The Day of The Lord",date:"10/20/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Hear the Word of The Lord your God, all peoples and nations; hear Me and give heed:"},{t:"text",v:"I am The Lord your God, The Creator of Heaven and Earth, of all things seen and unseen, known and unknown. Therefore run not to the left hand, nor to the right, eyes straight forward. For there I am upon My throne. All judgment and principalities are given into My hand; all is Mine. Yes, all you have is Mine, for everything you have I have given you, even to the cattle on a thousand hills. Every living creature is Mine. Every tribe, tongue and nation is Mine. All peoples are given into My hand, says The Lord God of Hosts. Behold, the whole earth and everything in it is Mine. Even every star and planet you see in the heavens, and those not yet discovered, even all of these are Mine. For I have created all things, and through My Son they are and were created. And all that is Mine, I have given to Him. Kneel therefore, bow down and give Him glory! For your life is but a glimmer, a mere drop of rain soon swallowed up by the earth, seen of no more; serving as nourishment for that which grows upon it, which is also soon withered and turned to dust once again; dust to dust, ashes to ashes, a flame brought forth, soon extinguished - so likewise are all those of the flesh. All flesh is given into His hand; whether from death unto life eternal, or from life unto death eternal, all is given into His hand. For you are and were created in fragile flesh, beautifully crafted by the hand of your Father, having been made alive in The Son. In His image you are and were created, in love I created you, placing you in the garden to My own joy..."},{t:"italic",v:"My own beloved who have received of My breath, created by The Father, made for The Son."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved little ones, you are Mine,"}],[{t:"italic",v:"And I have given you to My Son;"}],[{t:"italic",v:"For all I have is His, and all He has is Mine..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And so that which I have created must now return to Me,"}],[{t:"italic",v:"For I call you back, and I will receive you to Myself once again..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore come to Me, return to My love,"}],[{t:"italic",v:"Abide in My mercy and know Me; live in My Son!"}],[{t:"italic",v:"And I, even I, shall be your God, and you shall be My people..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Six days ending, the seventh at the door, wherein you shall find rest;"}],[{t:"italic",v:"Behold, even I shall rest with you, for one day in The Lord."}]]},{type:"para",segments:[{t:"text",v:"Therefore, come now and share in My joy, abide in My love, enter into My rest. For The Way is provided, The Lamb sacrificed, My own beating heart stilled in death, My own blood poured out so you may return to Me. Beloved, the curtain is torn! The way is open! Approach and draw near to Me, hear Me calling! For The Ladder of Heaven is joined to earth, glorified and named above all names! Call out, My children, call on His name, and seek to know Him as He truly is, and you shall be lifted up to glory! For all those who truly know Him know Me also, for The Father and The Son are One, YAHUSHUA-YAHUWAH! Beloved, He ALONE is The Way and The Ladder; be joined unto Him, be united with Me!..."},{t:"italic",v:"Glory to Glory, by Grace of Grace, Immanu El!"}]},{type:"para",segments:[{t:"text",v:"Yet I hear the cries of this wicked age, says The Lord. I have looked upon all these atrocities committed by man. I have seen how he murders the innocent without cause, how he oppresses the poor and the needy and cares not for the widow or the fatherless. I have beheld the hearts of all men. I know every thought and every intention; I am aware of all his plans, of every evil scheme he devises against his neighbor. Thus I have declared the day and appointed the season..."},{t:"italic",v:"A day of darkness and gloominess, a day of clouds and thick darkness, bitter sorrows and great fear, days of judgment! RECOMPENSE FOR ALL NATIONS! The Great and Dreadful Day of The Lord, the Day of Slaughter, great sorrow and bitter tears!..."},{t:"text",v:"It is finished."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"No more shall I withhold My hand, nor stay silent, no more shall I wait. The day is done, and the sun is setting upon this age of men. For My anger is kindled and burns in the heat of My wrath; My indignation has come to the full and must be poured out!..."},{t:"italic",v:"Like a dark storm building upon the horizon brings foreboding, as a great torrent inundates a city and running waters quickly overtake a town, like fierce waves beat back the shore or a raging sea capsizes a ship, as the power of the great whirlwind causes widespread devastation, so shall the indignation of The Lord be!"},{t:"text",v:"Behold, I had given mankind dominion over that which is Mine, even over all My good earth and every living thing upon it, and this is how My own children repay Me?! WITH SORROWS?! What do you mean by this, O sons of men?! Where are your hearts?! For you have endeavored to rip My image from your chests, as you cast away every blessing with which I had blessed you, feeding it to the dogs! Behold, even the pearl, of which you were to cherish, have you taken and smashed upon the rocks, shattering all hope, breaking My heart in pieces! O sons of men, what do you mean by this?! Why now do you go out to pervert your ways, as one with no heart and no mind at all?! For that which I behold in your hearts is evil upon evil, darkness, veiled darkness and vain deceits! Even now, you devise plans to utterly destroy yourselves! Sons of men, what do you mean by these things?! How is it I bless you, and you return evil for good and death for life, even to the destroying of all things holy, even to the innocent, MURDERING MY LITTLE ONES WHILE STILL IN THE WOMB?! Have you no love in your hearts at all?! Have you no compassion for these I have given you?! DEAD GENERATION! MULTITUDES OF CONDEMNED AND DYING PEOPLES!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear Me, you wayward and most wicked generation:"},{t:"text",v:"Call on your men in authority, bring out your riches, bow down and call upon your idols! Call upon your gods and possessions to save you, if they are able! Bring out your weapons of war, encompass the holy city round about, and seek to fulfill every evil desire of your black hearts; yes, come out and beat upon your chests and shake your fists at Heaven! The kingdoms of men are finished! Judgment reigns and it shall fall hard upon your backs, until every last one of you is broken or blotted out! Says The Lord God."}]},{type:"para",segments:[{t:"italic",v:"Children, I had sent to you Grace! Oh most beloved of My heart, My created ones, I am your own Father! Even I have loved you, sacrificing My own Son, spilling My own blood which runs in His veins! I LAID MYSELF UPON THE ALTAR! Sorrows, most bitter sorrows, such enmity and tears! Your Shepherd weeps for you! I take no pleasure at all in your destruction! Yet you choose death, you choose death! OH BELOVED, YOU CHOOSE DEATH! Estranged children, you are far from Me, returning to Me hate though I Myself have loved you. Little children, return to Me that I may heal you! Receive of Me and partake of My supper; receive of this bread I have broken for you, drink of this wine I have poured out for you! STOP BREAKING MY HEART!"},{t:"text",v:"Tears, bitter and deep sorrows, wailing in all the earth. The day is far spent, night is here; all lampstands removed from their places, all candlesticks put out, all light gathered and taken; darkness, thick darkness spreads forth across the land. Behold, you are undone and given up to judgment. For only those who receive of grace shall abide in it, and only those who are accepted shall be taken; the rest left to dwell in judgment, choosing not to escape from underneath its shadow. For it has fallen and shall be very heavy, a weight which can not be moved, a weight awash in tears and blood and much death, a burden of heavy sorrows..."},{t:"italic",v:"Reap, O Son of Man, reap! Lay the axe to the trees, level the forest and burn the branches! Uproot and destroy and judge the earth; judge and destroy! Refine and uplift until the Day is done, says The Lord God."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord, yes I, The Everlasting who is from everlasting to everlasting; I AM:"},{t:"text",v:"Repent, and give Me glory! Embrace and kiss The Holy One of Israel! His name is YahuShua HaMashiach, King of kings, Lord of lords, My Son in whom I am well pleased. Listen to Him! Eat of His body and drink of His blood!"}]},{type:"poetry",lines:[[{t:"italic",v:"My children, give up this life and depart from all"}],[{t:"italic",v:"This sin, forsake this world and now walk in MY ways,"}],[{t:"italic",v:"And you shall surely escape all these things, lifted up to glory!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"From Glory to Glory, from Grace to Grace..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Life without end."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-day-of-thick-clouds-and-darkness-bitter-sorrows-the-day-of-deliverance-and-judgment-the-day-of-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=_FTyBmV_9_E&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=12",videoMusicUrl:"https://www.youtube.com/watch?v=kp3c14gy-wU&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=40",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"},{label:"Crucified for Our Transgressions",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion#Crucified_for_Our_Transgressions"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:7,prevLetter:{id:"the-prophets-are-sent-out-true-and-false-the-high-minded-abased-the-lowly-uplifted-the-great-and-terrible-day-of-the-lord-is-near-and-who-shall-stand",title:"The Prophets Are Sent Out, True and False; the High-Minded Abased, the Lowly Uplifted... The Great and Terrible Day of The Lord Is Near, and Who Shall Stand"},nextLetter:{id:"israel-is-mine",title:"Israel Is Mine"}},{id:"israel-is-mine",title:"Israel Is Mine",date:"11/1/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Weep, O nations! Cry, all peoples! For I have lifted up My voice and set My face against you! O mighty and perverse nations, you shall be forsaken and left utterly desolate, IN RUINS! Says The Lord. No more shall you contend with Me in your uplifting, in your upholding, of all this wickedness! YOU HAVE FORSAKEN ME!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, even My own people go the way"}],[{t:"italic",v:"Of the ungodly, following after those void"}],[{t:"italic",v:"Of the Spirit, married to this world!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet I shall save them out of all their troubles;"}],[{t:"italic",v:"For My own name\u2019s sake will I do it..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the sake of Judah, I shall cover them;"}],[{t:"italic",v:"For the sake of Jacob, I shall hold them in safety;"}],[{t:"italic",v:"And for the sake of David, My servant, I shall"}],[{t:"italic",v:"Shelter them under the shadow of My wings..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/israel-is-mine-3",videoVoiceUrl:"https://www.youtube.com/watch?v=0gq9qzmX6jg&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=8",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"}],num:8,prevLetter:{id:"a-day-of-thick-clouds-and-darkness-bitter-sorrows-the-day-of-deliverance-and-judgment-the-day-of-the-lord",title:"A Day of Thick Clouds and Darkness, Bitter Sorrows... The Day of Deliverance and Judgment, The Day of The Lord"},nextLetter:{id:"recompense",title:"Recompense"}},{id:"recompense",title:"Recompense",date:"11/28/07",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"The Day has come, it is here, it has come! Says The Lord God. I shall repay! Your nation is given up and will be left in ruins, for all its forsaking of Me! For the roof is heavily weighted, all its pillars are cracked and can no longer bear the weight of their burden. Behold, the wind shall blow, the fire shall burn, and all these riches shall be consumed! A swift storm shall come upon you, and you shall not know from where it comes. For it is already upon you, and is yet coming. It shall reach across the oceans, it shall be swift and catch you unawares, it is building and grows in its fury; it builds and has come. And this shall be its consequence upon you, thus shall it bring forth against you:"},{t:"italic",v:"Confusion, a swirling wind! Water, a flood of fear! Destruction, collapse of all your foundations! Behold, even the earth shall rise up against you, and nature shall fight against you, O perverse and mighty nation!"},{t:"text",v:"And when three times pass, it shall be accomplished, it shall surely come to pass, the elect shall be gathered, all those in whom I see of Myself, My own reflection shown within the eyes of the first redeemed from the earth. For in a moment, in the twinkling of an eye, they shall climb The Ladder and lie down and rest for a short season, even in the place I have prepared for them. They shall rest and give worship, until the Day is done and it is finished. Then shall they arise and descend with The King. And as the lightning flashes out of the east, and fills the sky even unto the west, so shall the coming of The Son of Man be."}]},{type:"para",segments:[{t:"text",v:"For your leaders have cast their lot with the Ishmaelites in the dividing of MY land, even of the children\u2019s inheritance I had given to their forefathers forever..."},{t:"italic",v:"And so I shall divide them! With calamity, with famine, and with destitution!"},{t:"text",v:"Yet they will turn, and anger shall swell in their faces over much betrayal, causing them to repent of that which they had promised. And they will again stand with the children of Abraham, until three days pass over. Then shall they be given into the hand of him called the horn of satan, their name dissolved, becoming one of the ten for one hour; then plucked up and broken, during which time The Lord shall bring forth of them a great harvest, a great and mighty harvest, a great multitude, a refined and strong people for My name!..."},{t:"italic",v:"Then the end will come; The King shall reign, and that accomplished shall be finished, it shall be completed... Peace... One thousand years."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/recompense",videoVoiceUrl:"https://www.youtube.com/watch?v=jhS2mMDVTvk&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=9",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"The Coming of The Son of Man",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#The_Coming_of_The_Son_of_Man"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:9,prevLetter:{id:"israel-is-mine",title:"Israel Is Mine"},nextLetter:{id:"thus-says-the-lord-to-the-united-states-and-to-all-the-churches-of-men-which-dwell-within-its-borders",title:"Thus Says The Lord to the United States, and to All the Churches of Men Which Dwell Within Its Borders"}},{id:"thus-says-the-lord-to-the-united-states-and-to-all-the-churches-of-men-which-dwell-within-its-borders",title:"Thus Says The Lord to the United States, and to All the Churches of Men Which Dwell Within Its Borders",date:"11/28/07",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"O nation, once called of itself \u201CUnder God,\u201D you have raised yourselves above Me, saying within yourselves,"},{t:"italic",v:"\u201CWe are not under God, nor do we serve any god. Right is wrong, and wrong is right and the right of the individual who has become a god unto himself.\u201D"},{t:"text",v:"Therefore, because you have spoken in such a manner, you shall surely come to know God; you shall come to know Me in My anger! And I shall show you what is right, and I, even I shall cause you to discern, and you shall choose! For the sword has come, and under God shall you be placed once again! Yet not as at the first when you blessed My name, no, not as at the first, but in subjection, in retribution, in the shadow of My judgment! - Under God, My footstool! Then you will know, I AM THE LORD!"}]},{type:"poetry",lines:[[{t:"italic",v:"O mighty and perverse nation, cease from"}],[{t:"italic",v:"Your adulteries and return to Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I had blessed you, I had bestowed upon"}],[{t:"italic",v:"You great abundance, yet you have perverted"}],[{t:"italic",v:"Your way, desecrating all I have given you,"}],[{t:"italic",v:"Hardening your hearts, forsaking the poor,"}],[{t:"italic",v:"Turning your faces away from the afflicted!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You have become a harlot, an adulterous woman"}],[{t:"italic",v:"Who perverts her way among many lovers!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Return to Me! Says The Lord."}]]},{type:"para",segments:[{t:"text",v:"Sons of men, look at what you have done! Look upon all you have wrought in My name! Behold, even My own people have turned from Me and pervert their way among many witnesses, misusing My Word to their own glory, uplifting and exalting themselves as they segregate the Scriptures to uphold their own corrupt doctrines and filthy traditions; a great perversion of speech among these who call of themselves Christian, who do not cease from polluting My name day and night!"}]},{type:"para",segments:[{t:"bold-italic",v:"Churches of men, built up and named among yourselves, by yourselves, to your own glory, hear the Word of The Lord:"},{t:"text",v:"You are cast off as an abominable seed, sprouting and growing where I, Myself, have not planted you! Indeed, you have become as the vine of the earth which spreads forth across the land, making it desolate, growing and spreading and putting down roots! O abominable vine, you grow in the sand and shall be left desolate, undone, having received neither the early nor latter rain! Churches of men, your land and nation stinks, a foul stench has come up into My nostrils! Yet there you sit upon your thrones of pride, saying,"},{t:"italic",v:"\u201CWe alone are righteous. We alone serve God and shall be sheltered in the Day of The Lord.\u201D"},{t:"text",v:"WOE TO YOU, O CHURCHES OF MEN! Hypocrites! Arrogant assemblies! As you have divided yourselves, so shall I divide you in judgment! As sheep from the goats, so shall you be divided! I shall sift you and stir you up, and you shall be severely shaken, until your walls crumble and all you have built comes crashing down! Behold, no partition shall be left standing; all this enmity shall be stripped away! No more shall you come before Me arrayed in purple and scarlet robes, touting your expensive garments and shining ornaments, jingling as you go; your visage is detestable to Me! Your shepherds teach lies, your diviners of peace and prosperity, divinations from their own imaginations brought forth from their corrupted hearts! Yet oh how you love to have it so! Shall I not correct and discipline you for these things?! Shall I not set all these crooked paths straight?! Churches of men, why do you sit still, growing fat, consuming all these doctrines made by human hands?! Stand up or bow down! Shout to your nation or bow down! Fall on your faces! Says The Lord. Rend your clothes, howl and wail! Put on sackcloth, cover your heads with dust and ashes, and take up a lamentation! Sound the Trumpet to your kindred and countrymen! Stop hiding in your houses you call by My name; I do not dwell there! Come out, come out from among them, AND REPENT! Churches of men, you were to be an example, preparing My way before Me, a beacon on a hill, watchmen blowing the trumpet. Yet what do I see?! THE WORKS OF THE FLESH!"},{t:"fn",v:"1"},{t:"text",v:"For as it is written:"},{t:"italic",v:"You are neither cold nor hot. Oh how I wish you were one or the other! Therefore, because you have become as lukewarm water, even now becoming stagnant and rank, I shall vomit you out!"},{t:"fn",v:"2"}]},{type:"para",segments:[{t:"text",v:"Yet from among you I have already taken many, even a multitude who stand without, and these I have anointed and set in their places. They have received of Me and grow vigorously from The Vine, having been pruned and watered by My own hand. These shall burn bright, for they burn from within, having My own fire within them; behold, I shall stoke them and they shall burn brighter still, and they shall go for Me. They shall blow the Trumpet and sound the alarm, and serve you My fierce rebuke; behold, they shall serve it to you hot, and you shall be burned."}]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you the truth,"}],[{t:"italic",v:"If I do not correct and discipline you,"}],[{t:"italic",v:"You shall never enter My rest..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Galatians 5:19-21"},2:{type:"scripture",ref:"Revelation 3:15-16"}},nkjv:{"Galatians 5:19-21":"19. Now the works of the flesh are evident, which are: adultery, fornication, uncleanness, lewdness, 20. idolatry, sorcery, hatred, contentions, jealousies, outbursts of wrath, selfish ambitions, dissensions, heresies, 21. envy, murders, drunkenness, revelries, and the like; of which I tell you beforehand, just as I also told you in time past, that those who practice such things will not inherit the kingdom of God.","Revelation 3:15-16":"15. \u201CI know your works, that you are neither cold nor hot. I could wish you were cold or hot. 16. So then, because you are lukewarm, and neither cold nor hot, I will vomit you out of My mouth."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/thus-says-the-lord-to-the-united-states-and-to-all-the-churches-of-men-which-dwell-within-its-borders-2",videoVoiceUrl:"https://www.youtube.com/watch?v=A7jEAtx2JJQ&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to the United States",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_United_States"},{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord_.28Section_One.29"},{label:"Woe to the Churches of Men",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Churches_of_Men"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"The Ways of Churches of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Ways_of_Churches_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men_-_Section_One"}],num:10,prevLetter:{id:"recompense",title:"Recompense"},nextLetter:{id:"grace-and-the-law",title:"Grace and The Law"}},{id:"grace-and-the-law",title:"Grace and The Law",date:"2/5/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For His Brothers In Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My sons, I have sent Timothy on this wise: He is as one born out of due time, whom I have called into service by My own voice, for My own purpose, whereby his faith would come to grow vigorously from The Vine, according to that same end for which I have appointed him and shall surely be fulfilled, says The Lord. Therefore listen to him and help him, even as he shall also help you. For as he is My husbandman set over this present vineyard, so also am I sending him into the vineyard which shall be left unprotected during the storm, to gather in the many grapes which had not yet ripened before the time. For they have become entangled amongst all these briers and thorns. Look how man and the evils of this world have polluted My vineyard! Look how they have built up thick walls with untempered mortar, many high walls ready to topple. Yet they continue to stand, held up by human hands, supported from beneath by all these vain and ignorant builders who were deceived by their forefathers, even satan. Look how they continue to uphold them, blocking The Way before them. For they falsely believe it to be a shelter built upon a solid foundation. Yet I tell you the truth, it is the makings of their separation from Me, a way to hide that which has become unseemly in My sight, an attempt to avoid all accountability, perceiving not that it has become their prison. My sons, listen and so do. For you are also set over this present vineyard as husbandmen, even as friends of The Bridegroom. Go out into the streets, therefore, and call the guests to the wedding by all manner of speaking and devices, as many as are willing. Yet Timothy is sent to tear down these walls built up by men of pride, to break apart all these false foundations which they have laid in their vanity, all these arrogant teachers who have forsaken Me and My Law. For these men, these deceptive builders, seek to tear down My Law, even in the name of Grace! DESECRATION! BLASPHEMY! For those who preach grace in place of The Law do not know Me, neither do I dwell in them. For this is that same wall, which they have built in an attempt to bar the way of those who preach The Law, that they might avoid all accountability and keep their freedom..."},{t:"italic",v:"Freedom to sin by permission IN MY NAME, whereby they have also made ME the author of sin!"},{t:"text",v:"For they forsake The Moral Law of The Father, by permission in MY name, profaning My name, having altogether polluted that which I have offered them, having never received of Me nor known Me at all. Thus that which they have built up as a hedge against The Law has become their prison, says The Lord. Never underestimate the schemes of the adversary, My sons. For you are indeed saved by Grace, and were condemned because of your transgression under The Law. In this you have spoken well, and progress quickly toward perfection. And so I have spoken by My servant, Timothy, even in all these Letters, that your faith might be brought to its completion. Therefore, hear and understand: Salvation can in no wise depart from you, once received."},{t:"fn",v:"1"},{t:"text",v:"Therefore, seek to please The Father AND keep The Law. For how can one, who walks in Me by grace, also walk in that which had condemned them? Shall My people reach toward Heaven with their hands, while their feet continue to tread the wide path which leads to destruction? And how shall one who loves Me take My hand and walk beside Me, with one foot on the good ground and the other in the grave? Therefore, knowledge must increase and sin decrease, to enter The Kingdom of Heaven. For one who is under grace bears fruit of the same, and The One who kept The Law of The Father revealed that grace by works."}]},{type:"para",segments:[{t:"text",v:"Beloved sons, I am in The Father and He is in Me, and We are in you. And if I am in you, seek to please The Father in the same way I did. For if you seek to follow Me in truth, bearing your cross after Me, fearing not its weight but rather embracing it, you will surely become that example for which you are called."}]},{type:"poetry",lines:[[{t:"italic",v:"So then, grace is first and everlasting..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then comes works, the first works done in faith,"}],[{t:"italic",v:"Even the firstfruits bore in your lives..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Which is to love The Father and one another,"}],[{t:"italic",v:"By keeping The Law..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "Salvation Is Given and Must Be Received; Once Received, Forever Shall It Belong to the Redeemed"',link:{collection:"Volume Seven",letterTitle:"Salvation Is Given and Must Be Received; Once Received, Forever Shall It Belong to the Redeemed"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/grace-and-the-law",videoVoiceUrl:"https://www.youtube.com/watch?v=-qX8JfSmTNA&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:11,prevLetter:{id:"thus-says-the-lord-to-the-united-states-and-to-all-the-churches-of-men-which-dwell-within-its-borders",title:"Thus Says The Lord to the United States, and to All the Churches of Men Which Dwell Within Its Borders"},nextLetter:{id:"you-shall-not-use-grace-as-a-sword-by-which-you-attempt-to-slay-the-moral-law",title:"You Shall Not Use Grace as a Sword, By Which You Attempt to Slay The Moral Law"}},{id:"you-shall-not-use-grace-as-a-sword-by-which-you-attempt-to-slay-the-moral-law",title:"You Shall Not Use Grace as a Sword, By Which You Attempt to Slay The Moral Law",date:"2/15/08",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Say no more,"},{t:"italic",v:"\u201CGrace versus The Law.\u201D"},{t:"text",v:"Say rather,"},{t:"italic",v:"\u201CGrace AND The Law.\u201D"},{t:"text",v:"For Grace is the fulfillment of The Law. And where there is an absence of grace, there is lawlessness. Therefore, keeping The Law is a reflection of My own spirit in you. For anyone who says,"},{t:"italic",v:"\u201CI am in The Lord and He is in Me,\u201D"},{t:"text",v:"while forsaking The Law, is a liar, and will be found as such in the Day of Reckoning. For I AM WHO I AM, the same and unchanging, nor do I stand divided against Myself. Yet My children do continually use My name and that gift given them as a sword by which they attempt to justify their sins, which I hate! Desecration!"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus until the Day be fulfilled,"}],[{t:"italic",v:"Let those who do wickedly continue therein,"}],[{t:"italic",v:"And let those who seek righteousness walk therein,"}],[{t:"italic",v:"Until the harvest is complete..."}]]},{type:"poetry",lines:[[{t:"italic",v:"But oh how blessed are those who have"}],[{t:"italic",v:"Received of Grace, and seek to please The Father"}],[{t:"italic",v:"By obeying His Law, and teach men so..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Grace AND The Law."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/you-shall-not-use-grace-as-a-sword-by-which-you-attempt-to-slay-the-moral-law",videoVoiceUrl:"https://www.youtube.com/watch?v=joSFPGst0XI&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=11",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"}],num:12,prevLetter:{id:"grace-and-the-law",title:"Grace and The Law"},nextLetter:{id:"god-s-will",title:"God\u2019s Will"}},{id:"god-s-will",title:"God\u2019s Will",date:"3/7/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to the United States:"},{t:"text",v:"Obama shall lead you. And by him shall My will and judgment against your nation be fulfilled, for all its forsaking of Me and My Israel."}]},{type:"para",segments:[{t:"text",v:"And so I have brought from among your enemy even one from Ishmael, to rule over you for a time and a season, foreordained, until that foretold is accomplished and the king of fierce countenance rules. Then by that deception conceived of by your enemy and this transgressor, him being full of lofty and elevated words, lies and dark speeches sold as hope, will it return against him ten-fold of the same, by him called Perdition."}]},{type:"para",segments:[{t:"text",v:"Yet remember this: Nothing exists outside of Me, says The Lord; neither does anything continue outside My will. For even the evil of this present world is set within the confines of My will. For evil acts and brings forth of its own, yet is unaware that nothing is hidden before Me; neither has anything come to pass, nor will be, that I have not already beheld. And this, O arrogant and deceived generation, is why I said,"},{t:"italic",v:"\u201CAll was written and completed, even before the foundation of the world.\u201D"}]},{type:"closing",text:"For I am God, THE GOD!..."},{type:"poetry",lines:[[{t:"italic",v:"The God of Abraham, The God of Isaac,"}],[{t:"italic",v:"The God of Jacob, The God of all!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even of all that is known and unknown,"}],[{t:"italic",v:"The Creator of all things..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Everlasting, who is from"}],[{t:"italic",v:"Everlasting to everlasting..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/gods-will",videoVoiceUrl:"https://www.youtube.com/watch?v=eMuW7OlJwEQ&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=12",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Regarding the Antichrist",url:"https://answersonlygodcangive.com/Regarding_the_Antichrist"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:13,prevLetter:{id:"you-shall-not-use-grace-as-a-sword-by-which-you-attempt-to-slay-the-moral-law",title:"You Shall Not Use Grace as a Sword, By Which You Attempt to Slay The Moral Law"},nextLetter:{id:"thus-says-the-lord-by-the-spirit-of-truth-obey-the-commandments",title:"Thus Says The Lord, by The Spirit of Truth: Obey The Commandments"}},{id:"thus-says-the-lord-by-the-spirit-of-truth-obey-the-commandments",title:"Thus Says The Lord, by The Spirit of Truth: Obey The Commandments",date:"3/22/08",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy, For All Those Who Have Ears to Hear",forLine:"",blocks:[{type:"para",segments:[{t:"text",v:"Timothy, what is their false testimony to you? What part do you have with them? Is not the truth of the matter made plain in the Scriptures of Truth? Have I not already set all these crooked paths straight in these many Letters, which are of the same? Thus as it is written, so it has come to pass:"},{t:"italic",v:"In the latter days some will depart from the faith, giving heed to deceiving spirits and doctrines of demons, speaking lies in hypocrisy,"},{t:"fn",v:"1"},{t:"italic",v:"having never received the love of the Truth,"},{t:"fn",v:"2"},{t:"italic",v:"says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, this is how you"}],[{t:"italic",v:"Shall know the children of God:"}]]},{type:"poetry",lines:[[{t:"italic",v:"They keep The Commandments and"}],[{t:"italic",v:"Have the Testimony of YahuShua The Messiah,"}],[{t:"italic",v:"Who is called Jesus and Christ."},{t:"fn",v:"3"}]]},{type:"para",segments:[{t:"text",v:"For if one comes and has the Testimony, yet seeks not to keep The Commandments of God, he is a liar and shall be found as such in the Day of The Lord. And if one comes, saying,"},{t:"italic",v:"\u201CKeep The Commandments,\u201D"},{t:"text",v:"yet has not the Testimony of YahuShua The Messiah, this one also shall be found a liar."},{t:"fn",v:"4"},{t:"text",v:"For it is written:"},{t:"italic",v:"If anyone builds on this foundation with gold, silver, precious stones, wood, hay or straw, each one\u2019s work will be made clear, for the Day will surely declare it. For it will be revealed by fire, and the fire will test the quality of each one\u2019s work, to reveal of what sort it truly is. And if anyone\u2019s work endures, he will receive a reward. Yet if anyone\u2019s work is burned up, he will suffer great loss."},{t:"fn",v:"5"},{t:"text",v:"It is written also, and remains standing:"},{t:"italic",v:"Many will say to Me in that day, \u201CLord, Lord, have we not prophesied in Your name, cast out demons in Your name, and done many wonders in Your name?\u201D Yet I will declare to them, \u201CI never knew you; depart from Me, you who practice lawlessness!\u201D"},{t:"fn",v:"6"},{t:"text",v:"For the time will pass and the door shall be shut, and they shall all be left standing outside, where they shall then look upon all they had built up in their arrogance, and consider that which they had defended for the sake of their pride, even every corrupt doctrine and filthy tradition they upheld in their vanity, as it crumbles and is burned up before their eyes."}]},{type:"para",segments:[{t:"text",v:"Yet The Lord is not without mercy; they shall keep their life, yet as one escaping through fire,"},{t:"fn",v:"7"},{t:"text",v:"says The Lord."}]}],footnotes:{1:{type:"scripture",ref:"1 Timothy 4:1-2"},2:{type:"scripture",ref:"2 Thessalonians 2:10"},3:{type:"scripture",ref:"Revelation 12:17, Revelation 14:12"},4:{type:"scripture",ref:"1 John 2:4"},5:{type:"scripture",ref:"1 Corinthians 3:11-15"},6:{type:"scripture",ref:"Matthew 7:23 (NKJV)"},7:{type:"scripture",ref:"1 Corinthians 3:15"}},nkjv:{"1 Timothy 4:1-2":"1. Now the Spirit expressly says that in latter times some will depart from the faith, giving heed to deceiving spirits and doctrines of demons, 2. speaking lies in hypocrisy, having their own conscience seared with a hot iron,","2 Thessalonians 2:10":"and with all unrighteous deception among those who perish, because they did not receive the love of the truth, that they might be saved.","Revelation 12:17, Revelation 14:12":"12:17 \u2014 And the dragon was enraged with the woman, and he went to make war with the rest of her offspring, who keep the commandments of God and have the testimony of Jesus Christ. | 14:12 \u2014 Here is the patience of the saints; here are those who keep the commandments of God and the faith of Jesus.","1 John 2:4":"He who says, \u201CI know Him,\u201D and does not keep His commandments, is a liar, and the truth is not in him.","1 Corinthians 3:11-15":"11. For no other foundation can anyone lay than that which is laid, which is Jesus Christ. 12. Now if anyone builds on this foundation with gold, silver, precious stones, wood, hay, straw, 13. each one\u2019s work will become clear; for the Day will declare it, because it will be revealed by fire; and the fire will test each one\u2019s work, of what sort it is. 14. If anyone\u2019s work which he has built on it endures, he will receive a reward. 15. If anyone\u2019s work is burned, he will suffer loss; but he himself will be saved, yet so as through fire.","Matthew 7:23 (NKJV)":"And then I will declare to them, \u2018I never knew you; depart from Me, you who practice lawlessness!\u2019","1 Corinthians 3:15":"If anyone\u2019s work is burned, he will suffer loss; but he himself will be saved, yet so as through fire."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/thus-says-the-lord-by-the-spirit-of-truth-obey-the-commandments",videoVoiceUrl:"https://www.youtube.com/watch?v=AZyC6tZ29g4&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:14,prevLetter:{id:"god-s-will",title:"God\u2019s Will"},nextLetter:{id:"the-voice-of-truth",title:"The Voice of Truth"}},{id:"the-voice-of-truth",title:"The Voice of Truth",date:"4/22/08",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a brother in Christ: Lord, what does Your voice sound like?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered] To My son, and to all those who have received ears to hear, My own beloved within whom I see of Myself..."}]},{type:"para",segments:[{t:"italic",v:"Beloved, listen, and hear and know the love of a father, even of your Father in Heaven, whose voice you have heard and will soon come to know... Beloved, come and be filled with the joy of The Lord, which never fades, nor does it slumber, nor will it ever pass away; a flood of joy flowing into the innermost parts of your being, cascading through your spirit, reaching deep into that hidden place known only to The Lord; a place crafted by My own fingertips, delicately fashioned so those of the flesh may know Me, unlocked and opened by the trusting in and the knowledge of The Greatest of All Loves... A love which surpasses time and space, life and death, a place of perfect peace, yea inside pure and undefiled love; love of such a kind, cleansing every part seen and unseen, known and unknown; the love of such power and majesty, even that which has been corrupted is restored in the image of God... From grace to Grace, from light to The Light... My glory shown in you and through you, bright and shining, a flame brought forth from My own glory, shared with My beloved forever; a flame which can never be put out, nor can it flicker, nor shall it be covered over again, for where I am there is no darkness at all!"}]},{type:"para",segments:[{t:"italic",v:"Beloved, you are never alone! Here I am, with you and in you!... The blood in your veins, of which you have drank and accepted, the very salt in your tears, healing tears brought forth from a sincere and contrite heart, manifest in the eyes of the redeemed. Oh My beloved, let Me wipe them away, even every one, numbering them, accounting them unto love\u2019s purpose; even as that which was poured out from My side, which must be received in Me and from Me, even as Eve was given to Adam... And so it is with My bride, both taken and given and received, and brought forth of the same. Beloved, I am The Fulfillment of All Things! In My arms heaven and earth pass away; only perfect fulfillment remains!... You and I united, love\u2019s completion; your image, Mine, Father and son; The Father\u2019s joy accomplished. I have loved you all your life, even from the foundation of the world. Even upon the cross, I knew you and loved you, remembering you in My Kingdom. Beloved, those with Me have never departed; at no time have I ever lost one The Father has given Me. Beloved, here is wisdom surpassing human knowledge: Satan has no power at all! Nor has he changed even one tittle of that written according to The Father\u2019s will. For those who have eternal life were known to Me from the very foundation of the world, and those written in My Book were written there from the beginning. Is The Lord\u2019s hand shortened at all, that He can not save?! Is My ear dulled, that I can not hear?!"},{t:"text",v:"My son, I speak to all My sheep, yet they have forgotten how to listen. And so I have taken from among you one who was ignorant, void of all doctrine and teaching, and spoke to him these words,"},{t:"italic",v:"\u201CTimothy, read My Word.\u201D"},{t:"text",v:"And from that moment on has he heard My voice. And what of My voice, you ask... Its sound, its tone, its passion? This is what I say to you:"},{t:"italic",v:"Listen, and you shall also know... How does water taste to the man lost in the desert, dying of thirst? How does food taste to the starving? How does love feel to the desolate? How does the warmth of a fire feel to those coming in from the cold? How does the caress of your beloved feel after many days apart? How does a father look upon his newborn child?... How can one describe the sound of love which surpasses knowledge, the sound of what My love is? Can you hold the infinite in your hand?!"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, this is what My voice"}],[{t:"italic",v:"Sounds like to those who love Me:"}],[{t:"stanza-break"}],[{t:"italic",v:"A still small voice."}],[{t:"stanza-break"}],[{t:"italic",v:"And to the rest:"}],[{t:"stanza-break"}],[{t:"italic",v:"The sound of rushing waters,"}],[{t:"italic",v:"Lightnings and thunderings of fury and fiery anger,"}],[{t:"italic",v:"With deep and infinite sorrow, bitter anguish!..."}],[{t:"stanza-break"}],[{t:"italic",v:"Love."}],[{t:"stanza-break"}],[{t:"italic",v:"The Voice of Truth."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-voice-of-truth-3",videoVoiceUrl:"https://www.youtube.com/watch?v=_ZNlvbiAvSY&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=14",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Voice of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Voice_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:15,prevLetter:{id:"thus-says-the-lord-by-the-spirit-of-truth-obey-the-commandments",title:"Thus Says The Lord, by The Spirit of Truth: Obey The Commandments"},nextLetter:{id:"let-all-in-the-earth-be-brought-into-deep-and-profound-silence",title:"Let All in the Earth Be Brought into Deep and Profound Silence"}},{id:"let-all-in-the-earth-be-brought-into-deep-and-profound-silence",title:"Let All in the Earth Be Brought into Deep and Profound Silence",date:"4/24/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding allowing comments of scoffers or debating with mockers)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, to all those who blow this Trumpet:"},{t:"text",v:"I will not share My glory, nor shall any who speak against Me be given a voice! Neither shall any who hate the sound of this Trumpet, or speak against My Word in these Letters, be given any voice at all! Behold, the day is at hand when they shall all be struck dumb, the day I put them to shame and leave them desolate, the day they shall be left utterly astounded! For My Word stands and can not be moved; whether they hear or whether they forbear, it stands! Yet this is but the beginning. Soon all shall be brought to fruition, soon all shall be brought forth and completed, for the time has come."},{t:"italic",v:"Therefore, let those who do wickedly continue therein, and let those who seek righteousness walk therein."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Yet I tell you this, My servants, when it is within your power to silence the scoffers, do so. Give no voice to the mocker, nor to the evil of heart, for to do so is to enable satan. Know you not what the Scriptures say? -"},{t:"italic",v:"If anyone comes to you and does not hold to this teaching, or upholds any other doctrine, do not receive him or welcome him in."},{t:"fn",v:"2"},{t:"text",v:"Neither give him place nor part in that reserved for The Lord and His Proclamation. For this would be to give him a platform from which to perpetuate his evil ways. I tell you the truth, to allow the comments of scoffers and mockers is to welcome them in. Rather let them shout their controversy before The Lord, let their outcry enter into the ears of The Lord of Hosts. For I alone shall repay, I alone shall bring forth judgment and institute the punishment. And if they choose to stand defiant until the end, beating upon their chests, shaking their fists at Heaven, I will destroy them! Says The Lord."},{t:"italic",v:"For the Word of God is living and powerful; sharper than any double-edged sword, piercing to where the soul meets the spirit, cutting through to where the joint meets the bone, even to the marrow; a discerner of the thoughts, a judge of the innermost intentions!"},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, let all who behold My words look upon"}],[{t:"italic",v:"Them as an ensign, as a waving banner brought forth"}],[{t:"italic",v:"And set up for this wayward generation, even as a trumpet"}],[{t:"italic",v:"And alarm blowing continually upon the wall;"}],[{t:"italic",v:"Let its sound rush through the streets of the cities!"}],[{t:"italic",v:"Let its noise be carried into the wilderness,"}],[{t:"italic",v:"Even to the outermost isles!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And let all those who have ears to hear listen,"}],[{t:"italic",v:"And be silent before their God, and pray..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, let all in the earth partake of My Word"}],[{t:"text",v:"And be brought into deep and profound silence..."}],[{t:"stanza-break"}],[{t:"text",v:"And consider..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Revelation 22:11"},2:{type:"scripture",ref:"2 John 1:10-11"},3:{type:"scripture",ref:"Hebrews 4:12"}},nkjv:{"Revelation 22:11":"He who is unjust, let him be unjust still; he who is filthy, let him be filthy still; he who is righteous, let him be righteous still; he who is holy, let him be holy still.\u201D","2 John 1:10-11":"10. If anyone comes to you and does not bring this doctrine, do not receive him into your house nor greet him; 11. for he who greets him shares in his evil deeds.","Hebrews 4:12":"For the word of God is living and powerful, and sharper than any two-edged sword, piercing even to the division of soul and spirit, and of joints and marrow, and is a discerner of the thoughts and intents of the heart."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/let-all-in-the-earth-be-brought-into-deep-and-profound-silence",videoVoiceUrl:"https://www.youtube.com/watch?v=JaIQZg6yVo8&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=15",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"More Related Topics",url:"https://answersonlygodcangive.com/index.php?search=%224%2F24%2F08%22&title=Special%3ASearch&go=Go"}],num:16,prevLetter:{id:"the-voice-of-truth",title:"The Voice of Truth"},nextLetter:{id:"thus-says-the-lord-against-the-united-states-you-have-hastened-the-day",title:"Thus Says The Lord against the United States: You Have Hastened the Day"}},{id:"thus-says-the-lord-against-the-united-states-you-have-hastened-the-day",title:"Thus Says The Lord against the United States: You Have Hastened the Day",date:"5/21/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God, The God of Israel, The God of all:"},{t:"text",v:"Woe to you, O mighty and perverse nation! For you stand united and proud, UNITED IN TRANSGRESSION! Woe to you! WOE TO YOU! Says The Lord. For your travail has come! Behold, I shall divide you and bring you very low! For I have called to you, yet you have not answered! I have spoken to you, even arising early and sending My servants, the prophets, yet you turn to Me a deaf ear!"}]},{type:"para",segments:[{t:"text",v:"Behold, your Savior does continually call to you, yet you want no part with Him! Sorrows, bitter sorrows, many tears! I take no pleasure at all in your destruction! Says The Lord. Yet you have not answered, neither have you repented of all these abominations, neither will you turn aside! Yet you run, yes you run, running headlong toward your destruction, while shaking your fists at Heaven!"}]},{type:"para",segments:[{t:"text",v:"Therefore, listen and understand: I MYSELF HAVE SEEN IT! It is not covered, it is not at all hidden! - A parading of your whoredoms, vanities, greed and licentiousness, AND MURDER! Even to the destroying of the innocent, without remorse! Man with man, woman to woman, to the polluting of marriage of which I had sanctified in My own name, the defiling of flesh, even of this temple I have given you! ABOMINATION!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, Sodom and Gomorrah"},{t:"fn",v:"1"},{t:"italic",v:"are revived and"}],[{t:"italic",v:"Thrive before your face,"},{t:"fn",v:"2"},{t:"italic",v:"yet you stand up in"}],[{t:"italic",v:"Agreement and clap your hands!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Sin and violence spread forth in every direction,"}],[{t:"italic",v:"Overflowing your nation as a flood, yet you remain"}],[{t:"italic",v:"Unmoved, having no regard for your neighbor!..."},{t:"fn",v:"3"}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, you have hastened the Day!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You have surely aroused Me to anger!"}]]},{type:"para",segments:[{t:"text",v:"Did you think you had received, being blessed in this land, of yourselves?! Behold, it was I, even I who had done it, even according to the desire of your forefathers who came seeking to build a nation of freedom, building it upon My Word and My foundations written in the Scriptures of Truth, resting solidly upon My Law, the bedrock by which all shall govern themselves. Yet you turned, and desecrated and corrupted My name for your own glory, taking that which is Mine and calling it your own!"}]},{type:"para",segments:[{t:"text",v:"Sons of men, of this nation once called of itself \u201COne Nation Under God,\u201D I DO NOT KNOW YOU! Neither do any of these churches, built up and named of men, seek My face in truth; nor do they walk in My ways, even to the utter forsaking of My Law! Thus I have declared My judgment and will also bring it to pass, I have purposed it and will also do it, for all your forsaking of Me and My Law."}]},{type:"para",segments:[{t:"text",v:"Behold, I had written it upon your hearts, yet you have scraped off the writing, leaving you broken and desolate, scarred and void of the Spirit. For whosoever comes speaking against My Word, or against My prophets, shall be left utterly desolate. Even from those who cast stones at them, in open or in secret, have I removed My hand already."}]},{type:"para",segments:[{t:"italic",v:"Oh My children, oh My beloved children, you have turned from Me and cast your lot with satan; from My glory you are far removed! Oh My sleeping children, awaken from this darkness and open your eyes! For there is but One Way before you, only One Escape from all these things wrought in My fury; Only One Highway to travel, Only One Path to tread, Only One Ladder to Heaven! Even from the foundation of the world, there has been but One: One Way, One Truth and One Life!"},{t:"fn",v:"4"},{t:"italic",v:"CALL ON HIS NAME!"},{t:"text",v:"For He is called Jesus The Christ, Yeshua The Messiah; His name, YahuShua HaMashiach, the only name under Heaven by which you must be saved."},{t:"fn",v:"5"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the Day has come, even ten days of sorrow,"}],[{t:"italic",v:"Of great wailing and gnashing of teeth..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Bitter tears..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THE DAY OF THE LORD."}]]}],footnotes:{1:{type:"scripture",ref:"Genesis 18:20-33, Genesis 19:1-25"},2:{type:"note",text:'See: "Regarding Sodom and Gomorrah Revived"',url:"https://www.answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},3:{type:"scripture",ref:"Leviticus 19:18"},4:{type:"scripture",ref:"John 14:6 (CJB)"},5:{type:"scripture",ref:"Acts 4:12 (CJB)"}},nkjv:{"Genesis 18:20-33, Genesis 19:1-25":"18:20-33 \u2014 20. And the LORD said, \u201CBecause the outcry against Sodom and Gomorrah is great, and because their sin is very grave, 21. I will go down now and see whether they have done altogether according to the outcry against it that has come to Me; and if not, I will know.\u201D 22. Then the men turned away from there and went toward Sodom, but Abraham still stood before the LORD. 23. And Abraham came near and said, \u201CWould You also destroy the righteous with the wicked? 24. Suppose there were fifty righteous within the city; would You also destroy the place and not spare it for the fifty righteous that were in it? 25. Far be it from You to do such a thing as this, to slay the righteous with the wicked, so that the righteous should be as the wicked; far be it from You! Shall not the Judge of all the earth do right?\u201D 26. So the LORD said, \u201CIf I find in Sodom fifty righteous within the city, then I will spare all the place for their sakes.\u201D 27. Then Abraham answered and said, \u201CIndeed now, I who am but dust and ashes have taken it upon myself to speak to the Lord: 28. Suppose there were five less than the fifty righteous; would You destroy all of the city for lack of five?\u201D So He said, \u201CIf I find there forty-five, I will not destroy it.\u201D 29. And he spoke to Him yet again and said, \u201CSuppose there should be forty found there?\u201D So He said, \u201CI will not do it for the sake of forty.\u201D 30. Then he said, \u201CLet not the Lord be angry, and I will speak: Suppose thirty should be found there?\u201D So He said, \u201CI will not do it if I find thirty there.\u201D 31. And he said, \u201CIndeed now, I have taken it upon myself to speak to the Lord: Suppose twenty should be found there?\u201D So He said, \u201CI will not destroy it for the sake of twenty.\u201D 32. Then he said, \u201CLet not the Lord be angry, and I will speak but once more: Suppose ten should be found there?\u201D And He said, \u201CI will not destroy it for the sake of ten.\u201D 33. So the LORD went His way as soon as He had finished speaking with Abraham; and Abraham returned to his place. | 19:1-25 \u2014 1. Now the two angels came to Sodom in the evening, and Lot was sitting in the gate of Sodom. When Lot saw them, he rose to meet them, and he bowed himself with his face toward the ground. 2. And he said, \u201CHere now, my lords, please turn in to your servant\u2019s house and spend the night, and wash your feet; then you may rise early and go on your way.\u201D And they said, \u201CNo, but we will spend the night in the open square.\u201D 3. But he insisted strongly; so they turned in to him and entered his house. Then he made them a feast, and baked unleavened bread, and they ate. 4. Now before they lay down, the men of the city, the men of Sodom, both old and young, all the people from every quarter, surrounded the house. 5. And they called to Lot and said to him, \u201CWhere are the men who came to you tonight? Bring them out to us that we may know them carnally.\u201D 6. So Lot went out to them through the doorway, shut the door behind him, 7. and said, \u201CPlease, my brethren, do not do so wickedly! 8. See now, I have two daughters who have not known a man; please, let me bring them out to you, and you may do to them as you wish; only do nothing to these men, since this is the reason they have come under the shadow of my roof.\u201D 9. And they said, \u201CStand back!\u201D Then they said, \u201CThis one came in to stay here, and he keeps acting as a judge; now we will deal worse with you than with them.\u201D So they pressed hard against the man Lot, and came near to break down the door. 10. But the men reached out their hands and pulled Lot into the house with them, and shut the door. 11. And they struck the men who were at the doorway of the house with blindness, both small and great, so that they became weary trying to find the door. 12. Then the men said to Lot, \u201CHave you anyone else here? Son-in-law, your sons, your daughters, and whomever you have in the city\u2014 take them out of this place! 13. For we will destroy this place, because the outcry against them has grown great before the face of the LORD, and the LORD has sent us to destroy it.\u201D 14. So Lot went out and spoke to his sons-in-law, who had married his daughters, and said, \u201CGet up, get out of this place; for the LORD will destroy this city!\u201D But to his sons-in-law he seemed to be joking. 15. When the morning dawned, the angels urged Lot to hurry, saying, \u201CArise, take your wife and your two daughters who are here, lest you be consumed in the punishment of the city.\u201D 16. And while he lingered, the men took hold of his hand, his wife\u2019s hand, and the hands of his two daughters, the LORD being merciful to him, and they brought him out and set him outside the city. 17. So it came to pass, when they had brought them outside, that he said, \u201CEscape for your life! Do not look behind you nor stay anywhere in the plain. Escape to the mountains, lest you be destroyed.\u201D 18. Then Lot said to them, \u201CPlease, no, my lords! 19. Indeed now, your servant has found favor in your sight, and you have increased your mercy which you have shown me by saving my life; but I cannot escape to the mountains, lest some evil overtake me and I die. 20. See now, this city is near enough to flee to, and it is a little one; please let me escape there (is it not a little one?) and my soul shall live.\u201D 21. And he said to him, \u201CSee, I have favored you concerning this thing also, in that I will not overthrow this city for which you have spoken. 22. Hurry, escape there. For I cannot do anything until you arrive there.\u201D Therefore the name of the city was called Zoar. 23. The sun had risen upon the earth when Lot entered Zoar. 24. Then the LORD rained brimstone and fire on Sodom and Gomorrah, from the LORD out of the heavens. 25. So He overthrew those cities, all the plain, all the inhabitants of the cities, and what grew on the ground.","Leviticus 19:18":"You shall not take vengeance, nor bear any grudge against the children of your people, but you shall love your neighbor as yourself: I am the LORD.","John 14:6 (CJB)":"I AM the Way \u2014 and the Truth and the Life; no one comes to the Father except through me.","Acts 4:12 (CJB)":"There is salvation in no one else! For there is no other name under heaven given to mankind by whom we must be saved!"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/thus-says-the-lord-against-the-united-states-you-have-hastened-the-day",videoVoiceUrl:"https://www.youtube.com/watch?v=ujYi3sLzoTA&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=16",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding Homosexuality",url:"https://answersonlygodcangive.com/Regarding_Homosexuality"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"},{label:'The Name of The Lord - "YahuShua"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YahuShua"}],num:17,prevLetter:{id:"let-all-in-the-earth-be-brought-into-deep-and-profound-silence",title:"Let All in the Earth Be Brought into Deep and Profound Silence"},nextLetter:{id:"shout-his-name",title:"Shout His Name"}},{id:"shout-his-name",title:"Shout His Name",date:"6/19/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Whom shall I send? Who will go for Me? There is no more time to tarry. The day is far spent, and the sun is setting upon this age of men."}]},{type:"para",segments:[{t:"text",v:"Husbandmen, go out and gather. For the wheat is already bundled, and who is able to loose it? Neither man nor beast is able; behold, nothing in all creation is able to separate that which The Lord has bound together. Therefore, My sons, go out and gather up the remnant, even every last grain which has fallen to the ground. Gather it up quickly before the storm comes, where the winds shall blow, the hail shall beat down, and the rains shall overflow, erode and wash away. Behold, the field shall be left in ruins, in much disarray, unrecognizable to those who look upon it. And what of that which is left? Will not the birds of the air come and consume, and the beasts of the field devour, until nothing of the crop remains? For the time has indeed come for The Lord to stretch out His hand against the wicked, for The God of Heaven to visit the earth. Behold, I shall visit in My wrath and come like a storm! And as a great whirlwind of fire, I shall consume all this wickedness from the face of the earth! For the nations have raged against Me, and the people refuse to give glory to My name. Yet of sin, this they uphold! Thus they shall perish with much shouting, when I cause the earth to rise up and fight against them, until deep and heavy silence covers them and their wickedness is no more before My face! Behold, even in these lands, you call California and Nevada, shall it begin. For they have become as a great river, A RIVER OF SIN, an unending source of abominations, murder and licentiousness! Even that which Sodom and Gomorrah had done pales compared with that brought forth of them!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, My servants,"}],[{t:"italic",v:"BLOW THIS TRUMPET!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shout to the masses, by all"}],[{t:"italic",v:"Manner of speaking and devices!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For you hold The Key to Salvation in your hearts,"}],[{t:"italic",v:"And there He is within your understanding..."}]]},{type:"poetry",lines:[[{t:"italic",v:"SHOUT HIS NAME!"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/shout-his-name",videoVoiceUrl:"https://www.youtube.com/watch?v=HLyOkilffpQ&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=18",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:18,prevLetter:{id:"thus-says-the-lord-against-the-united-states-you-have-hastened-the-day",title:"Thus Says The Lord against the United States: You Have Hastened the Day"},nextLetter:{id:"woe-to-the-megachurches-of-men",title:"Woe to the Megachurches of Men"}},{id:"woe-to-the-megachurches-of-men",title:"Woe to the Megachurches of Men",date:"6/26/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, what do you think of Todd Bentley and all these megachurches?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"No more shall My people call out My name, and then run after men in authority, seeking after the vain glory wrought within the churches of men! No more shall they run greedily after vain glory, or heap up vanities to themselves, in MY name! For they have done a detestable thing in My sight! Lo, I have beheld their hearts, and within them I have seen their vanity, vanities on top of vanities and many vain deceits!..."},{t:"italic",v:"Woe to the churches of men who seek after vain glories, and build themselves up by vanity and greed! Woe to them! For they shall be the first to be thrown down! They shall be brought down to the ground, they shall no more stand!"},{t:"text",v:"Look, My sons and daughters, look at all these detestable things wrought within the churches of men, and tell Me, what do you see? What do you see, beloved? What have they done to My name?!..."},{t:"italic",v:"Woe to these people of excess! Woe to all these churches of men, who pollute My name and steal from My glory! For they build great churches of brick and wood, magnificent buildings of concrete and steel, yet the poor cry at the doors!"}]},{type:"poetry",lines:[[{t:"italic",v:"Yes, they build great and extravagant houses,"}],[{t:"italic",v:"They amplify their voices like the wind,"}],[{t:"italic",v:"Yet the cause of the widow and"}],[{t:"italic",v:"The fatherless goes unheard!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shall I not recompense them for all these things?!"}],[{t:"italic",v:"Shall I not abase all these self-appointed leaders,"}],[{t:"italic",v:"These charlatans, in front of many witnesses?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shall I not come upon them quickly"}],[{t:"italic",v:"And strip them of all their clothes,"}],[{t:"italic",v:"Leaving them naked and desolate?!"}]]},{type:"para",segments:[{t:"text",v:"Behold, I shall be terrible to them, yes, I shall be a terror unto them, when I sweep across the land and destroy all these houses which bear My name! For My anger is kindled, and My face is set hard against them! No more shall they seduce My bride and rape My daughters! No more shall they cause My children to sin! FOR I, MYSELF, HAVE SEEN IT! My sons and daughters, listen to My voice and give heed to My spirit. For I tell you the truth, if these great and extravagant churches were to call for the Holy Spirit in truth, and I did send it in the fullness of My strength, none would stand, all would fall down. Thus I did not send it, nor has My presence been among them, for I do not know them. All is vanity and vain glory, corruption by flattery, filthy pretense for evil gain. For in My presence all fall down and give Me glory; from the righteous to the wicked, all shall fall down and give Me glory. For who can stand before The Lord Most High? Who?! Not this man! For he has lifted up his head, and taken it upon himself to speak in My name, though I have not sent him. Therefore I shall surely humble him, and he shall be severely abased in the sight of many witnesses. For I alone uplift, and I alone abase, says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The light has gone out of the churches of men, and My hand is removed. Therefore what remains, and what spirit dwells there? Deceptions clothed in falsehoods, whitewashed and covered over in purple and scarlet, doctrines of demons! Therefore prepare, all you who remain in My love,"},{t:"fn",v:"1"},{t:"text",v:"for the time is at hand; the Trumpet is blowing and the warning is sent down. Yet those in your land cover their ears and will not listen; indeed, they hate the sound of this Trumpet and refuse to give heed! Thus I shall be terrible to them, and nature shall rise up in its fury and fight against them! Yet The Lord is not without mercy, for all these things are but a call to awake. For your land and its people sleep; behold, they lie down in beds of wickedness, embracing sins of every kind. And those among the churches slumber also, with all these self-appointed prophets, pastors and preachers lulling them to sleep, though the storm rages. Behold, sin inundates the streets and alleyways, even to the broadways, a great deluge of wickedness; the surge of which has come and shall not be turned back, until its pinnacle is reached and that written is accomplished. And behold, the eyes of many shall be opened in that day, and they shall see. Yes, they shall call out and choose Righteousness, and I Myself will save them out of all their troubles; I shall surely deliver them from the mouth of the dragon."},{t:"fn",v:"2"},{t:"text",v:"Then they will know, I AM THE LORD."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, My servants, again I say to you,"}],[{t:"italic",v:"Turn away from this world and prepare!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Call out to your beloved"}],[{t:"italic",v:"And speak to them My name,"}],[{t:"italic",v:"Give a shout to your kindred and countrymen;"}],[{t:"italic",v:"Blow the Trumpet and sound the alarm!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the Days of Sorrow are here"}],[{t:"italic",v:"And the Day of The Lord is upon you;"}],[{t:"italic",v:"Behold, it waits at the door"}],[{t:"italic",v:"And is about to come in..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 15:10 (CEB)"},2:{type:"scripture",ref:"Revelation 12:13-16"}},nkjv:{"John 15:10 (CEB)":"If you keep my commandments, you will remain in my love, just as I kept my Father\u2019s commandments and remain in his love.","Revelation 12:13-16":"13. Now when the dragon saw that he had been cast to the earth, he persecuted the woman who gave birth to the male Child. 14. But the woman was given two wings of a great eagle, that she might fly into the wilderness to her place, where she is nourished for a time and times and half a time, from the presence of the serpent. 15. So the serpent spewed water out of his mouth like a flood after the woman, that he might cause her to be carried away by the flood. 16. But the earth helped the woman, and the earth opened its mouth and swallowed up the flood which the dragon had spewed out of his mouth."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/woe-to-the-megachurches-of-men",videoVoiceUrl:"https://www.youtube.com/watch?v=7rOzvjmtbYA&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=24",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Woe to Those Who Walk in Pretense",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Walk_in_Pretense"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:'"My Hand is Removed from the Churches of Men"',url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets#.22My_Hand_is_Removed_from_the_Churches_of_Men.22"},{label:"Woe to the Churches of Men",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Churches_of_Men"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"Woe to Those Who Bear False Witness in The Lord\u2019s Name",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Bear_False_Witness_in_The_Lord.E2.80.99s_Name"},{label:"False Doctrines Within the Churches (Index)",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:'The Volumes of Truth ("the Trumpet")',url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:19,prevLetter:{id:"shout-his-name",title:"Shout His Name"},nextLetter:{id:"woe-to-those-who-bear-false-witness-in-the-lord-s-name-saying-hear-the-word-of-the-lord-when-the-lord-has-not-spoken-it",title:"Woe to Those Who Bear False Witness in The Lord\u2019s Name, Saying, \u201CHear the Word of The Lord\u201D, When The Lord Has Not Spoken It"}},{id:"woe-to-those-who-bear-false-witness-in-the-lord-s-name-saying-hear-the-word-of-the-lord-when-the-lord-has-not-spoken-it",title:"Woe to Those Who Bear False Witness in The Lord\u2019s Name, Saying, \u201CHear the Word of The Lord\u201D, When The Lord Has Not Spoken It",date:"11/9/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy, For All Those Who Have Ears to Hear",forLine:"",noteLine:"(Regarding a false prophetess, who claims she receives the Word of The Lord)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God, yes I, YAHUWAH, The God of Israel:"},{t:"text",v:"I DO NOT KNOW HER! Neither have I sent her, nor has she at anytime heard the Word of The Lord! Therefore this prophet, even all prophets who speak in My name, saying,"},{t:"italic",v:"\u201CThus says The Lord,\u201D"},{t:"text",v:"when I have NOT spoken it, neither did it come forth from My mouth, even these prophets shall be brought to utter ruin! Behold, all their houses shall become as the dung hill, piles of refuse, in the Day of The Lord\u2019s Anger! For of such are all their words before Me, of such is the value I have assigned to all their lofty assertions! I AM THE LORD! Therefore, let them never again speak in My name, saying,"},{t:"italic",v:"\u201CCome and hear the word The Lord speaks,\u201D"},{t:"text",v:"when I have NOT spoken it! Let all these self-appointed prophets stay silent, let them be quiet and open not their mouths, lest I strike them down for all their false-witnessing!"}]},{type:"poetry",lines:[[{t:"italic",v:"Yet let the chosen trumpet MY Word loudly!"}],[{t:"italic",v:"Let them shout it from the rooftops and spread"}],[{t:"italic",v:"My Word abroad, by all manner of speaking and devices!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I Myself have sent them!"}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/woe-to-those-who-bear-false-witness-in-the-lord-s-name-saying-hear-the-word-of-the-lord-when-the-lord-has-not-spoken-it",videoVoiceUrl:"https://www.youtube.com/watch?v=Kghl4HIk2c4&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=19",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"}],num:20,prevLetter:{id:"woe-to-the-megachurches-of-men",title:"Woe to the Megachurches of Men"},nextLetter:{id:"repent",title:"REPENT"}},{id:"repent",title:"REPENT",date:"1/18/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel, The God of all:"},{t:"text",v:"I am come!"},{t:"fn",v:"1"},{t:"text",v:"And I shall visit upon this generation great recompense for all their adulteries against God! For all their murders and oppression, I shall lay them waste! Yet first I shall remove My hand,"},{t:"fn",v:"2"},{t:"text",v:"and evil shall reign, and according to all this generation has sown SO SHALL THEY REAP! Therefore fall down, all you wicked! Be cast down, all you high-minded! Grovel at the feet of your Creator, you double-minded hypocrites! For the sow knows her place and wallows in it, yet this generation knows no bounds! Your sin proliferates as the pestilence and spreads forth as the plague, and oh how you, O modern peoples of this wicked age, love to have it so! Shall I not repay?! Did you think it was hidden from My eyes?! Did you think I, even I, The Creator of Heaven and Earth, would not come down and make a swift end?! O foolish and deceived generation, I had sent to you Grace, yet you turn and spit at The King! And what shall I say to a people, the likes of which even those of Sodom and Gomorrah would have fled from, saying,"},{t:"italic",v:"\u201CThis people and its ways are a terror unto us. Let us go into silence, and suffer not to know The Lord\u2019s anger over that which a people such as this have committed. For our sins were great, and we received the due reward for our iniquities, yet these people have come out to fight against The King!\u201D"},{t:"text",v:"Yet I know your thoughts and I have heard your voices, O most wicked generation. Even now, I hear you saying within yourselves,"},{t:"italic",v:"\u201CIn what way have we sinned against The Lord? And by what means did we become worthy of all this punishment? Who is our king, and what king is appointed over us?!\u201D..."},{t:"text",v:"O most wicked and arrogant generation, there is a King who reigns and shall come, yet He remains hidden from your eyes."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord your God, of whom you have forsaken and not known, choosing rather to strike Me from all remembrance, that you may be loosed from all accountability:"},{t:"text",v:"Behold, there is another king, and he shall rule over you. He shall be fierce, and his countenance shall be like no other man, a man skilled in intrigue who serves the prince and the power of the air."},{t:"fn",v:"3"},{t:"text",v:"Yet to you he will be as a savior, a man of action. He shall reign in the earth for a short season, and many shall flock to him and bow down, even to the bearing of the mark and the number of his name upon their foreheads or right hands."},{t:"fn",v:"4"},{t:"text",v:"For you have all become as goats meet for the slaughter. You have chosen vanities and do always revel in your uncleanness, pursuing all the lusts thereof. Behold, the whole world is defiled, awash in iniquity, overflowing with abomination! And so I give to you a king, one who shall woo you and bring in the slaughter. And you, together with him, shall drink of the wine of the wrath of My fury. Then you will know, I AM THE LORD."}]},{type:"poetry",lines:[[{t:"italic",v:"My people, today is the day!..."}]]},{type:"poetry",lines:[[{t:"text",v:"Call upon the name of The Lord,"}],[{t:"text",v:"By Him whose name is one with The Father\u2019s..."}]]},{type:"poetry",lines:[[{t:"italic",v:"AND REPENT!"}]]},{type:"poetry",lines:[[{t:"text",v:"Drink from this cup, which I have poured out for you!"}],[{t:"text",v:"Embrace this Word, which I have spoken to you!..."}]]},{type:"poetry",lines:[[{t:"text",v:"Return to Me in sincerity and in truth,"}],[{t:"text",v:"That I may gather you, that I may shelter you"}],[{t:"text",v:"Under the shadow of My healing wings!"},{t:"fn",v:"5"},{t:"text",v:"..."}]]},{type:"poetry",lines:[[{t:"text",v:"For The Lord Omnipotent reigns,"}],[{t:"text",v:"And has spoken to this generation, saying..."}]]},{type:"poetry",lines:[[{t:"italic",v:"REPENT!"}]]}],footnotes:{1:{type:"note",text:'Also read: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME#I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}},2:{type:"note",text:'Also read: "The One Who Stays, Lets"',url:"https://www.thevolumesoftruth.com/The_One_Who_Stays,_Lets#The_One_Who_Stays.2C_Lets",link:{collection:"Volume Seven",letterTitle:"The One Who Stays, Lets"}},3:{type:"scripture",ref:"Daniel 8:23-24 (KJV)"},4:{type:"scripture",ref:"Revelation 13:16"},5:{type:"scripture",ref:"Psalm 17:8, Psalm 57:1"}},nkjv:{"Daniel 8:23-24 (KJV)":"23. And in the latter time of their kingdom, when the transgressors are come to the full, a king of fierce countenance, and understanding dark sentences, shall stand up. 24. And his power shall be mighty, but not by his own power: and he shall destroy wonderfully, and shall prosper, and practise, and shall destroy the mighty and the holy people.","Revelation 13:16":"He causes all, both small and great, rich and poor, free and slave, to receive a mark on their right hand or on their foreheads,","Psalm 17:8, Psalm 57:1":"17:8 \u2014 Keep me as the apple of Your eye; Hide me under the shadow of Your wings, | 57:1 \u2014 To the Chief Musician. Set to \u201CDo Not Destroy.\u201D A Michtam of David when he fled from Saul into the cave. Be merciful to me, O God, be merciful to me! For my soul trusts in You; And in the shadow of Your wings I will make my refuge, Until these calamities have passed by."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/repent-2",videoVoiceUrl:"https://www.youtube.com/watch?v=f8P8JaODq04&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=20",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Regarding the Antichrist",url:"https://answersonlygodcangive.com/Regarding_the_Antichrist"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:21,prevLetter:{id:"woe-to-those-who-bear-false-witness-in-the-lord-s-name-saying-hear-the-word-of-the-lord-when-the-lord-has-not-spoken-it",title:"Woe to Those Who Bear False Witness in The Lord\u2019s Name, Saying, \u201CHear the Word of The Lord\u201D, When The Lord Has Not Spoken It"},nextLetter:{id:"recompense-wrath-and-glory",title:"Recompense, Wrath and Glory"}},{id:"recompense-wrath-and-glory",title:"Recompense, Wrath and Glory",date:"2/11/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to the United States and to this wicked generation of modern peoples; hear the Word of The Lord your God, The God of Israel, The God of all, for there is no other:"},{t:"text",v:"You are walking into death, dead men\u2019s bones lost in a sea of sin, a dark ocean of transgression! You have forgotten Me days without end! Thus must I also forget you in the Day of Harvest! Yet of your evil deeds, even all this wickedness of which you are guilty, I shall remember! Behold, I shall bring it to the forefront, that all who walk in it may receive of My punishment! Then you shall know, there is a God in Heaven who reigns and judges the earth! And who is this who is given a voice? And what man is this, who has brought all these nations into subjection? O heylel, you shall be brought down to Sheol, and to the sides of the pit shall you be cast! For you are brought low, even to the uttermost depths shall you go! Behold, you shall bow at the feet of The King, The Holy One of God! You shall hear His voice, and be brought down! Even all those with you, all these mighty and proud men, this great multitude, this numerous company which you have assembled, shall be struck down! Behold, every last one of them shall be slain by the sword of His mouth, being consumed in the brightness of His coming!..."},{t:"italic",v:"Behold The King! For He is The King of Glory, The King of Great Power and Glory, The King of Righteousness! The Lamb! THE LION!"},{t:"text",v:"Behold, He is coming! There is no more time to tarry, The Thief comes! He shall pass through, He shall gather His own, the earth plunged into darkness! And you, O most deceitful and wicked generation, even all of you with your proud looks and outstretched necks, shall wail and gnash your teeth in that day! Oh such a cry shall be heard, the likes of which has not been since Ramah, nor known since the day I stretched out My hand against Egypt!..."},{t:"italic",v:"Great wailing and gnashing of teeth, great and bitter tears, and fear; paling of faces, darkness, all light gathered and taken."},{t:"text",v:"Therefore weep and howl for your miseries, lament and howl, O peoples of the earth! Scatter in fear, run and hide your faces and take refuge in the rocks! RUN AND HIDE! Says The Lord God Almighty. For I am awakened out of My place; you have aroused Me to anger! For the Day has come, yes it is here, and the Day of Wrath is very near!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the days of sorrow overflow and shall drown you in tears!"}],[{t:"italic",v:"Blood fills the earth and reaches unto Heaven!"}],[{t:"italic",v:"Even before My throne do I hear the cries of every unborn child,"}],[{t:"italic",v:"Of which you have slain before My eyes, without remorse!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"MURDERERS! EVIL AND MOST WICKED GENERATION!"}],[{t:"italic",v:"VENGEANCE HAS COME, IT IS HERE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And I, even I, The Creator of Heaven and Earth, shall surely repay!"}]]},{type:"para",segments:[{t:"text",v:"Recompense in full shall be delivered at My hand, for you have forsaken Me! You have killed the innocent! LO, YOU HAVE MURDERED AND TORN THE FLESH OF THE LITTLE ONES! Even now, your leader, in whom you have placed all your trust, betrays you, bringing My wrath upon your nation, even upon every nation which has followed in your footsteps! You are undone! And as you have done to all these innocent, so shall it be done unto you! Even double shall you receive at My hand! Behold, I am moved from My place! I AM MOVED TO WRATH! And if it was not for the sake of My servant, Noah, and all these in whom I see of Myself, I would have drowned your nation in the depths of the sea long ago, wiping away every trace of your existence! Yet for the sake of the elect, I have withheld My hand and yet withhold My vengeance. Yet against your nation, I have already brought forth and purposed ruin."}]},{type:"para",segments:[{t:"text",v:"Peoples of the earth, I had sent to you Grace! I revealed My Mercy and the knowledge of Salvation, I gave you The Word of God; behold, He has walked among you! Yet what do I hear, and what is this upon your lips, O perverse and fallen nation? - His name, HIS NAME AS A CURSING! Therefore, I am come out to strike you down, to cast every stronghold of satan into deep and profound silence! Be greatly astonished, therefore! Be awestruck at that which The Lord your God brings! Crumble in fear, break under the weight of My wrath; let all nations and peoples lie down! None shall stand, all shall fall down; every pillar which stood so tall, every tower which remained unmoving, every giant who robbed and persecuted the poor and the needy in the name of gain!"},{t:"italic",v:"For behold, you have sown in the wind; thus you shall reap the whirlwind!"},{t:"fn",v:"1"},{t:"text",v:"For all your doings are but chaff, and your knowledge, which you call great and vast, shall be stripped away! Lo, it shall burn, ashes beneath the feet of My messengers!"}]},{type:"poetry",lines:[[{t:"italic",v:"Sons and daughters of men, REPENT, and give Me glory!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Kiss The Son, and humble yourselves at the feet"}],[{t:"italic",v:"Of The King, The One who is and was"}],[{t:"italic",v:"And is to come, The Almighty!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For He shall roar from on high, and utter"}],[{t:"italic",v:"His voice from His holy habitation;"}],[{t:"italic",v:"He shall roar mightily against His fold!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"He shall give a shout as those who"}],[{t:"italic",v:"Tread grapes, against all the inhabitants"}],[{t:"italic",v:"Of the earth, as it is written!"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet those who call upon The Name in"}],[{t:"italic",v:"Sincere remorse, with many tears, shall be as brands"}],[{t:"italic",v:"Plucked out of the fire, and those who come out"}],[{t:"italic",v:"From among them shall be delivered..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Hosea 8:7"},2:{type:"scripture",ref:"Jeremiah 25:30"}},nkjv:{"Hosea 8:7":"\u201CThey sow the wind, And reap the whirlwind. The stalk has no bud; It shall never produce meal. If it should produce, Aliens would swallow it up.","Jeremiah 25:30":"\u201CTherefore prophesy against them all these words, and say to them: \u2018The LORD will roar from on high, And utter His voice from His holy habitation; He will roar mightily against His fold. He will give a shout, as those who tread the grapes, Against all the inhabitants of the earth."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/recompense-wrath-and-glory",videoVoiceUrl:"https://www.youtube.com/watch?v=7F1zslK1PWo&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:'"He Who Was and Is and Is to Come"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#He_Who_Was_and_Is_and_Is_to_Come"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:22,prevLetter:{id:"repent",title:"REPENT"},nextLetter:{id:"thus-says-the-lord-against-las-vegas",title:"Thus Says The Lord against Las Vegas"}},{id:"thus-says-the-lord-against-las-vegas",title:"Thus Says The Lord against Las Vegas",date:"3/5/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Hear the Word of The Lord, for thus declares The Lord:"},{t:"text",v:"Las Vegas shall receive recompense in full, even the full cup of My hot displeasure. For the slate shall be wiped clean, and they shall perish with much shouting. Behold, not even the sidewalks shall remain, when deep and profound silence covers them and the earth hides them away."}]},{type:"poetry",lines:[[{t:"italic",v:"For behold, this people and this city called Sin"}],[{t:"italic",v:"Shall be no more before My face,"}],[{t:"italic",v:"From that day onward and forever..."}]]},{type:"poetry",lines:[[{t:"italic",v:"FORGOTTEN AND BLOTTED OUT!..."}]]},{type:"closing",text:"Says The Lord God of Power and Glory; The Lord of Hosts is My name, The God of Israel."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/thus-says-the-lord-against-las-vegas",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:23,prevLetter:{id:"recompense-wrath-and-glory",title:"Recompense, Wrath and Glory"},nextLetter:{id:"thus-says-the-lord-to-the-churches-of-men-and-to-all-their-self-appointed-apostles-prophets-and-preachers",title:"Thus Says The Lord to the Churches of Men, and to All Their Self-Appointed Apostles, Prophets and Preachers"}},{id:"thus-says-the-lord-to-the-churches-of-men-and-to-all-their-self-appointed-apostles-prophets-and-preachers",title:"Thus Says The Lord to the Churches of Men, and to All Their Self-Appointed Apostles, Prophets and Preachers",date:"7/16/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The error of the churches is great! Behold, their every tradition has come up before Me as an awful stench in My nostrils, and their every doctrine assaults My ears with a terrible sound! For they have taken the things of God and corrupted them for evil gain! -"},{t:"italic",v:"Prepared speeches, lawless sermons, heresies against God and The Way!"},{t:"text",v:"By clever words and false hope built upon the promise of riches, they lead My people astray. Behold, they corrupt their own congregations by flattery, and because of covetousness the people are easily swayed..."},{t:"italic",v:"Oh the vanity and pride of men, who do continually seek after vain glory, saying within themselves, \u201CLook at all I have done. See how I have come to speak for The Most High. See how I have become like Him!\u201D"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"ALL self-appointed apostles, prophets, and preachers shall be brought to utter ruin! And lo, destruction comes swiftly, a weight which you have brought upon your own heads! For I am coming quickly in judgment, I am coming down with great recompense, and I shall surely repay! Behold, I shall strike you down, and you shall collapse where you stand; even as that which you have built up in your greed, for the sake of your own glory, falls with a great crash!"},{t:"fn",v:"2"},{t:"text",v:"Shall one become a prophet by human means?! Is the voice of The Almighty something that can be claimed?! Can the gifts of My spirit be attained by human power, and am I now made subject to the wiles of men?! You have all prophesied lies before Me, you speak that which is born from the deceit of your own hearts! -"},{t:"italic",v:"A very foolish endeavor, a vain thing, a fatal error!"},{t:"text",v:"For you have taken the things of God in hand, and twisted them, for your own gain!"},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"italic",v:"Shall you attempt to steal from My glory, and then parade"}],[{t:"italic",v:"Yourself before the people as though you were sent by God?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I HAVE NOT SENT YOU!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shut your mouths and be quiet, open not your mouths"}],[{t:"italic",v:"And speak no more in My name, lest I tear you"}],[{t:"italic",v:"In pieces and there be none to deliver!"},{t:"fn",v:"4"}],[{t:"italic",v:"For I tell you the truth, My judgment is not idle"}],[{t:"italic",v:"And your destruction does not sleep!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore fall hard upon your faces, AND REPENT,"}],[{t:"italic",v:"And I may yet have mercy upon you, says The Lord God."}]]},{type:"para",segments:[{t:"text",v:"For I have beheld your form, yes, I have looked upon your visage, and I have seen your fine clothes and all your luxuriously-crafted apparel, all these expensive ornaments with which you adorn yourselves. I know all your delusions of grandeur, and how you lead My people astray by false divinations, brought forth from your own corrupted hearts. Therefore your portraits shall be broken, your church buildings shall be thrown down, and your every pulpit swept away, in the day I strip you naked and leave you desolate! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, all you who call of yourselves Christian, for thus declares The Lord:"},{t:"text",v:"No prophet or man of God, of whom I have chosen and sent, shall by any means receive payment for his services, nor shall he accept a gift; no man shall profit from My Word! Freely he has received, freely he shall give. Nor shall he allow any form of praise or glory to be added to his account; rather, he shall correct them sharply. I AM THE LORD. Thus all you teachers, pastors, preachers, ministers and priests, who receive tithes and welcome praise from the people, shall be held accountable; behold, it shall be required of you in the Day. Shall you take profit for that which I have offered as a free gift? Shall you raise yourselves up by false glory, and abuse My Word for selfish gain? Yes, there is indeed profit in it, according to the wealth of grace and salvation which abounds in love, granting an abundance of eternal wealth, which is life in My presence and My joy forevermore, for all those who receive My Word and also walk in it. Yet those who use My Word to profit by monetary means shall be cast out and shall remain in the valley, walking through thick darkness until death comes to claim them, says The Lord."}]},{type:"para",segments:[{t:"text",v:"Therefore, let it be stated and set forth this day in the hearing of the people, whether they will hear or whether they will forbear, for it shall be done and come to pass as I have spoken it, even as I proclaim it now:"},{t:"italic",v:"No man in authority, whether a self-appointed apostle, prophet, teacher, pastor, preacher, minister or priest, as they are called among men, who also forsake The Moral Law in the name of The Messiah, to make Him the author of sin, shall escape the Day of The Lord!"},{t:"text",v:"For the saints of The Most High are those who keep My Commandments and remember My Sabbaths, and carry The Messiah within them, even unto pure testimony in His name, in word and by deed."},{t:"fn",v:"5"},{t:"text",v:"Again, I tell you, no leader amongst the churches of men who forsakes the Sabbath, of which I Myself had sanctified from the beginning,"},{t:"fn",v:"6"},{t:"text",v:"which is and has always been and shall always be the seventh day,"},{t:"fn",v:"7"},{t:"text",v:"shall escape the Day of The Lord! And no leader amongst the churches who embraces all these holidays of men,"},{t:"fn",v:"8"},{t:"text",v:"which I hate, shall by any means escape the Day of The Lord! Remember My Holy Days, for in them shall you begin to know the mind of God and the glory of My salvation in Messiah. And NO leader amongst the churches of men, who teaches the doctrine of hell and eternal torment,"},{t:"fn",v:"9"},{t:"text",v:"shall by any means be gathered! Neither shall any who embrace this teaching escape! For I do not know them, neither do I abide in them. And NOT ONE who comes speaking against this Word or My messengers, to stone them in word and by deed, to slander them, to spit upon them, to strike them down, or to bring even one railing accusation against them, whether it be in open or in secret, shall by any means escape the Day of The Lord\u2019s Fury! For I tell you the truth, neither age nor gender shall deliver them. For The Lord your God is no respecter of persons;"},{t:"fn",v:"10"},{t:"text",v:"I know your hearts!"},{t:"fn",v:"11"},{t:"text",v:"For as I am, says The Lord, so shall I be. And as I have always done, so shall I perform it again, even amongst this modern generation of perverse and deceitful peoples. For indeed, the fear of YAHUWAH is the beginning of wisdom, and knowledge of The Holy One is understanding."},{t:"fn",v:"12"},{t:"text",v:"Therefore abide in Him, and you have Me also. Yet abide in the world, and you shall also reap the world\u2019s reward:"},{t:"italic",v:"Judgment and punishment in the Great and Terrible Day of The Lord."},{t:"text",v:"Therefore, My children, unless you call upon the name of The Messiah in truth, with sincere remorse in your hearts, as one broken atop The Stone,"},{t:"fn",v:"13"},{t:"text",v:"you shall by no means escape."}]},{type:"poetry",lines:[[{t:"italic",v:"Again I say to you, REPENT, and run to your Savior in truth!"}],[{t:"italic",v:"Embrace Him as He truly is, and not as you would have Him be!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Flee all these churches of men, turn your backs on all their"}],[{t:"italic",v:"Self-appointed apostles, prophets and preachers, and run!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Run to YahuShua, whom you call Christ and Jesus!"}],[{t:"italic",v:"For He alone is your hope and your shield,"},{t:"fn",v:"14"},{t:"italic",v:"your only escape..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Isaiah 14:13-14"},2:{type:"scripture",ref:"Matthew 7:26-27"},3:{type:"scripture",ref:"Psalm 56:5, 2 Peter 3:16 (NKJV)"},4:{type:"scripture",ref:"Psalm 50:22"},5:{type:"scripture",ref:"Revelation 12:17, Revelation 14:12"},6:{type:"scripture",ref:"Genesis 2:3"},7:{type:"scripture",ref:"Exodus 16:26, Exodus 16:30, Exodus 20:10-11, Exodus 23:12"},8:{type:"note",text:'See: "Thus Says The Lord Regarding the Holidays of Men"',url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},9:{type:"note",text:'See: "The False Doctrine of Hell and Eternal Torment Exposed"',url:"https://www.thevolumesoftruth.com/The_State_of_the_Dead_and_The_Fate_of_the_Wicked:_The_False_Doctrine_of_Hell_and_Eternal_Torment_Exposed",link:{collection:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",letterTitle:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed"}},10:{type:"scripture",ref:"Ephesians 6:9"},11:{type:"scripture",ref:"Jeremiah 17:10"},12:{type:"scripture",ref:"Proverbs 9:10"},13:{type:"scripture",ref:"Matthew 21:44"},14:{type:"scripture",ref:"Psalm 119:114"}},nkjv:{"Isaiah 14:13-14":"13. For you have said in your heart: \u2018I will ascend into heaven, I will exalt my throne above the stars of God; I will also sit on the mount of the congregation On the farthest sides of the north; 14. I will ascend above the heights of the clouds, I will be like the Most High.\u2019","Matthew 7:26-27":"26. \u201CBut everyone who hears these sayings of Mine, and does not do them, will be like a foolish man who built his house on the sand: 27. and the rain descended, the floods came, and the winds blew and beat on that house; and it fell. And great was its fall.\u201D","Psalm 56:5, 2 Peter 3:16 (NKJV)":"Psalm 56:5 \u2014 All day they twist my words; All their thoughts are against me for evil. | 2 Peter 3:16 \u2014 as also in all his epistles, speaking in them of these things, in which are some things hard to understand, which untaught and unstable people twist to their own destruction, as they do also the rest of the Scriptures.","Psalm 50:22":"\u201CNow consider this, you who forget God, Lest I tear you in pieces, And there be none to deliver:","Revelation 12:17, Revelation 14:12":"12:17 \u2014 And the dragon was enraged with the woman, and he went to make war with the rest of her offspring, who keep the commandments of God and have the testimony of Jesus Christ. | 14:12 \u2014 Here is the patience of the saints; here are those who keep the commandments of God and the faith of Jesus.","Genesis 2:3":"Then God blessed the seventh day and sanctified it, because in it He rested from all His work which God had created and made.","Exodus 16:26, Exodus 16:30, Exodus 20:10-11, Exodus 23:12":"16:26 \u2014 Six days you shall gather it, but on the seventh day, the Sabbath, there will be none.\u201D | 16:30 \u2014 So the people rested on the seventh day. | 20:10-11 \u2014 10. but the seventh day is the Sabbath of the LORD your God. In it you shall do no work: you, nor your son, nor your daughter, nor your male servant, nor your female servant, nor your cattle, nor your stranger who is within your gates. 11. For in six days the LORD made the heavens and the earth, the sea, and all that is in them, and rested the seventh day. Therefore the LORD blessed the Sabbath day and hallowed it. | 23:12 \u2014 Six days you shall do your work, and on the seventh day you shall rest, that your ox and your donkey may rest, and the son of your female servant and the stranger may be refreshed.","Ephesians 6:9":"And you, masters, do the same things to them, giving up threatening, knowing that your own Master also is in heaven, and there is no partiality with Him.","Jeremiah 17:10":"I, the LORD, search the heart, I test the mind, Even to give every man according to his ways, According to the fruit of his doings.","Proverbs 9:10":"\u201CThe fear of the LORD is the beginning of wisdom, And the knowledge of the Holy One is understanding.","Matthew 21:44":"And whoever falls on this stone will be broken; but on whomever it falls, it will grind him to powder.\u201D","Psalm 119:114":"You are my hiding place and my shield; I hope in Your word."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/thus-says-the-lord-to-the-churches-of-men-and-to-all-their-self-appointed-apostles-prophets-and-preachers-3",videoVoiceUrl:"https://www.youtube.com/watch?v=LXfs3i49_VU&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=27",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Woe to the Churches of Men",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Churches_of_Men"},{label:"False Doctrines Within the Churches (Index)",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Woe to Those Who Bear False Witness in The Lord\u2019s Name",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Bear_False_Witness_in_The_Lord.E2.80.99s_Name"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Regarding Spiritual Gifts",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Gifts"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"Woe to Those Who Walk in Pretense",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Walk_in_Pretense"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Tithing",url:"https://answersonlygodcangive.com/Regarding_Tithing"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Woe to Those Who Come Against God's Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men_-_Section_One"}],num:24,prevLetter:{id:"thus-says-the-lord-against-las-vegas",title:"Thus Says The Lord against Las Vegas"},nextLetter:{id:"who-among-you-o-israel-and-among-you-o-olive-branches-has-fasted-unto-me-says-the-lord-god",title:"Who Among You, O Israel, and Among You, O Olive Branches, Has Fasted Unto Me?! Says The Lord God"}},{id:"who-among-you-o-israel-and-among-you-o-olive-branches-has-fasted-unto-me-says-the-lord-god",title:"Who Among You, O Israel, and Among You, O Olive Branches, Has Fasted Unto Me?! Says The Lord God",date:"7/27/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy, For All Those Who Have Ears to Hear",forLine:"",noteLine:"(Regarding believers in Messiah taking part in a Jewish fast during the month of Av)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord your God, The God of Israel, The God of all, He who searches the hearts and minds, even to the innermost thoughts and intentions:"},{t:"fn",v:"1"},{t:"text",v:"I alone see the heart of man, and I alone test the quality of each man\u2019s work, to reveal of what sort it truly is."},{t:"fn",v:"2"},{t:"text",v:"Therefore, I ask you, shall you seek to do as those who have rejected The Messiah, as those who have forsaken Me and remain void of the Spirit?! I tell you the truth, their fasts and offerings are not accepted, their sacrifices I hate! Shall My own people, who are not My people, come before Me in My name to fast for the dead?! Shall they call on My name, while at the same time rejecting The Son of Salvation?! Lo, they will indeed come, yet I will turn to them the back! For they have no voice before Me; they remain broken off! Says The Lord. And what of you, beloved, where do you stand? And where have I placed you, according to your acceptance of The Messiah? Answer, if you know. For indeed it has come to pass, even since the day I dwelt among them in the flesh, behold, they were broken off that you might be grafted in. For out of unbelief they have been forsaken for a time. Yet the day has come and is nearly upon them, when they will be grafted in again, for I am able to graft them in again."},{t:"fn",v:"3"},{t:"text",v:"Yet of that day, it has not yet fully come. And so I ask you, why do you now endeavor to take part in the futile customs of the unbeliever? How is it you seek to seat yourself among those who lack knowledge and forsake understanding? Their fasts are in vain! They are not accepted! Yet I ask you, all you who have not denied Me, who also believe this Word, why do My servants fast on the Sabbath as I have commanded them?"},{t:"fn",v:"4"},{t:"text",v:"And of you who I did not command, why do you also take part? (Yes, you too shall fast, indeed, I will require it of you. Yet only those who present themselves before Me in sincere devotion, as one swallowed up in much sorrow over the absence of The Bridegroom,"},{t:"fn",v:"5"},{t:"text",v:"and over all this death which has come and is coming and shall fill the world with tears and blood, shall be accepted.)"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, over this you shall fast, over this you shall wail:"}]]},{type:"poetry",lines:[[{t:"italic",v:"All these crying children, all these hardened hearts,"}],[{t:"italic",v:"All this death and murder, all this injustice and godlessness..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Tears as a river, tears and blood and much wailing,"}],[{t:"italic",v:"Great evil and the slaughter of the innocent..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"text",v:"Yet those of Israel go out to cry over all their dead, and fast because of all this punishment I have allowed to overtake them. Yet I hear no repentance! I hear no wailing at all over their forsaking of The Holy One who poured out His life for them, nor over that which their fathers had done to Him, the sin of which remains atop their marred heads!"},{t:"fn",v:"6"},{t:"text",v:"Enmity, such bitter tears! My own people, who were the apple of My eye, forsake Me still! Therefore, take no part in their festivals! Take no part in their wailing over the dead, as though I am not able at this very moment to call them forth from their graves and from their tombs, to raise them ALL from the dust of the earth once again!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, to all those of Israel who have drunk from My cup and eaten of My bread, all who remain grafted in; hear the Word of The Lord your God, yes I, YAHUWAH, The God of your fathers, The God of all:"},{t:"text",v:"Be not offended in My words, nor wag the head at My speech, nor push out the hand against My words in these Letters. For your eyes have seen and your ears have heard, and within your hearts you have understood the grace of Him who was crucified upon the tree. Again, I say, wag not your head. Rather that which honors Messiah, do. And that which I have decreed as a perpetual ordinance,"},{t:"fn",v:"7"},{t:"text",v:"continue therein, according to The Messiah YahuShua being the goal and fulfillment thereof, for He is worthy. And in so doing, do you also become worthy because of Him. And that which you do in remembrance of Him, to bring glory to His name, honors Me; even as that which you offer up in thanksgiving, in His name, glorifies Me. For I AM HE, YAHUWAH, The One who reigns and causes to be, The One who is and has always been, The Eternal God, The Everlasting who is from everlasting to everlasting; I AM."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore if you fast, fast as one who longs for the"}],[{t:"italic",v:"Return of The Bridegroom, even as a sign to those"}],[{t:"italic",v:"Who are near and to those who are afar off..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And beloved, fast for those perishing, for those"}],[{t:"italic",v:"Who are about to receive of My Judgment,"}],[{t:"italic",v:"Which is stored up and must be poured out;"}],[{t:"italic",v:"Fast and lament and pray that they repent before the time..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And fast also for those who at present"}],[{t:"italic",v:"Remain broken off,"},{t:"fn",v:"8"},{t:"italic",v:"yes, beloved, pray for"}],[{t:"italic",v:"Repentance in Israel, for a great awakening,"}],[{t:"italic",v:"That all come to accept Me as I truly am,"}],[{t:"italic",v:"That all be broken atop The Stone,"},{t:"fn",v:"9"}],[{t:"italic",v:"Before calamity and judgment overtake this world..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the time has come, says The Lord."}]]}],footnotes:{1:{type:"scripture",ref:"Jeremiah 17:10"},2:{type:"scripture",ref:"1 Corinthians 3:12-13"},3:{type:"scripture",ref:"Romans 11:19-24"},4:{type:"note",text:'See: "For a Testimony and as a Lamentation"',url:"https://www.thevolumesoftruth.com/For_a_Testimony_and_as_a_Lamentation#For_a_Testimony_and_as_a_Lamentation",link:{collection:"Letters to The Lord's Little Flock",letterTitle:"For a Testimony and as a Lamentation"}},5:{type:"scripture",ref:"Mark 2:20"},6:{type:"scripture",ref:"Matthew 27:25"},7:{type:"note",text:"Leviticus 23"},8:{type:"scripture",ref:"Romans 11:20"},9:{type:"scripture",ref:"Luke 20:18"}},nkjv:{"Jeremiah 17:10":"I, the LORD, search the heart, I test the mind, Even to give every man according to his ways, According to the fruit of his doings.","1 Corinthians 3:12-13":"12. Now if anyone builds on this foundation with gold, silver, precious stones, wood, hay, straw, 13. each one\u2019s work will become clear; for the Day will declare it, because it will be revealed by fire; and the fire will test each one\u2019s work, of what sort it is.","Romans 11:19-24":"19. You will say then, \u201CBranches were broken off that I might be grafted in.\u201D 20. Well said. Because of unbelief they were broken off, and you stand by faith. Do not be haughty, but fear. 21. For if God did not spare the natural branches, He may not spare you either. 22. Therefore consider the goodness and severity of God: on those who fell, severity; but toward you, goodness, if you continue in His goodness. Otherwise you also will be cut off. 23. And they also, if they do not continue in unbelief, will be grafted in, for God is able to graft them in again. 24. For if you were cut out of the olive tree which is wild by nature, and were grafted contrary to nature into a cultivated olive tree, how much more will these, who are natural branches, be grafted into their own olive tree?","Mark 2:20":"But the days will come when the bridegroom will be taken away from them, and then they will fast in those days.","Matthew 27:25":"And all the people answered and said, \u201CHis blood be on us and on our children.\u201D","Romans 11:20":"Well said. Because of unbelief they were broken off, and you stand by faith. Do not be haughty, but fear.","Luke 20:18":"Whoever falls on that stone will be broken; but on whomever it falls, it will grind him to powder.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/who-among-you-o-israel-and-among-you-o-olive-branches-has-fasted-unto-me-says-the-lord-god",videoVoiceUrl:"https://www.youtube.com/watch?v=iFKed6ZA82Y&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=27",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Fasting",url:"https://answersonlygodcangive.com/Regarding_Fasting"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Take No Part",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Take_No_Part"},{label:"Regarding the First and Second Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:25,prevLetter:{id:"thus-says-the-lord-to-the-churches-of-men-and-to-all-their-self-appointed-apostles-prophets-and-preachers",title:"Thus Says The Lord to the Churches of Men, and to All Their Self-Appointed Apostles, Prophets and Preachers"},nextLetter:{id:"sons-of-the-kingdom-witnesses-in-the-day",title:"Sons of The Kingdom, Witnesses in the Day"}},{id:"sons-of-the-kingdom-witnesses-in-the-day",title:"Sons of The Kingdom, Witnesses in the Day",date:"8/19/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Shall Be Sent In the Day",blocks:[{type:"para",segments:[{t:"text",v:"My sons, this is but the beginning, says The Lord. For when the day comes, no more will you draw back in fear, no more will you stumble backward. Behold, you shall rush forward, and I shall be established in you, and we shall be one. And from your mouths shall proceed lightnings and thunderings, of which no one will be able to withstand. For quick and powerful is the Word of The Lord Most High. Behold, you will hear, and at once you shall speak; as God you shall speak to them!"},{t:"fn",v:"1"},{t:"text",v:"Yes, you shall open your mouths to speak, and at the first word proceeding from your lips they shall all be pushed backward! For as the mighty whirlwind uproots and destroys, tearing all in its path to pieces, so also shall the words of My witnesses be -"},{t:"italic",v:"A strong wind to break the branches, a swirling wind to topple the trees, until every root is laid bare and every foundation is swept clean!"},{t:"text",v:"Then shall a deep burning arise within the fallen, and they shall stand up with renewed vigor and come against you in haste, with great violence and hate. Yet all they bring forth against you shall be turned back upon their own heads. And in the midst of their rage they shall be assaulted, as one who has stumbled upon a hornet\u2019s nest, scattering them in fear. For I AM GOD, and My Word never returns void. Behold, My Word shall go out, and the harvest shall come in; the rest left to the fire, to the singeing of all these hardened foreheads! Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My witnesses shall speak"}],[{t:"italic",v:"My name in power and perform many signs..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And upon the lips of My elect it shall"}],[{t:"italic",v:"Be for a song, as in the days of old;"}],[{t:"italic",v:"And among My saints, it shall be murmured softly in prayer,"}],[{t:"italic",v:"Offered up continually as a sweet-smelling savor..."}]]},{type:"closing",text:"For I am The Lord, and there is no other; A just God and a Savior, there is none besides Me..."},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA-YAHUWAH."}]]}],footnotes:{1:{type:"scripture",ref:"Exodus 7:1-2"}},nkjv:{"Exodus 7:1-2":"1. So the LORD said to Moses: \u201CSee, I have made you as God to Pharaoh, and Aaron your brother shall be your prophet. 2. You shall speak all that I command you. And Aaron your brother shall tell Pharaoh to send the children of Israel out of his land."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/sons-of-the-kingdom-witnesses-in-the-day",videoVoiceUrl:"https://www.youtube.com/watch?v=ksAi-VyqFcU&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=24",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:'The Name of The Lord - "YAHUSHUA-YAHUWAH"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YAHUSHUA-YAHUWAH"}],num:26,prevLetter:{id:"who-among-you-o-israel-and-among-you-o-olive-branches-has-fasted-unto-me-says-the-lord-god",title:"Who Among You, O Israel, and Among You, O Olive Branches, Has Fasted Unto Me?! Says The Lord God"},nextLetter:{id:"the-lord-has-purposed",title:"The Lord Has Purposed"}},{id:"the-lord-has-purposed",title:"The Lord Has Purposed",date:"8/20/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, The Lord God has purposed, and who can annul it?! My sons and daughters, I have purposed, and I shall also bring it to pass before the eyes of"},{t:"italic",v:"this"},{t:"text",v:"generation! Yes I, even I, The Lord God of Heaven and Earth have purposed and brought it forth; behold, I have announced it in a loud voice and set it before the people; The Lord\u2019s Proclamation is sent down!"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus that which I have purposed is set"}],[{t:"italic",v:"In its place, prepared and made ready..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, that which I speak"}],[{t:"italic",v:"A second time is established..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And that which I have decreed"}],[{t:"italic",v:"A third time can never be moved..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-lord-has-purposed-3",videoVoiceUrl:"https://www.youtube.com/watch?v=BK05m6_LIzk&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],num:27,prevLetter:{id:"sons-of-the-kingdom-witnesses-in-the-day",title:"Sons of The Kingdom, Witnesses in the Day"},nextLetter:{id:"churches-of-men-hear-the-word-of-the-lord",title:"Churches of Men, Hear The Word of The Lord"}},{id:"churches-of-men-hear-the-word-of-the-lord",title:"Churches of Men, Hear The Word of The Lord",date:"9/9/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have spoken to those who call of themselves Christian, yet they have not discerned. I have written to them by the pen of My prophets, yet they have not perceived. Indeed, they refuse to accept Me as I truly am. For within their churches they worship another god, they teach the people of another messiah, one who looks nothing like Me! Lo, they seek after the doctrines and traditions of men, which I hate; they embrace them without thought or consideration; behold, they uphold them in MY name! DESECRATION! BLASPHEMY! The whole body is sick, its members wane, for they are covered with the filth of the pagan and dwell gladly in their uncleanness!"}]},{type:"poetry",lines:[[{t:"italic",v:"For behold, the mother went forth and"}],[{t:"italic",v:"Played the harlot; yes, she played the harlot"}],[{t:"italic",v:"And reveled in her fornications with the heathen;"}],[{t:"italic",v:"She married among the pagans and laid"}],[{t:"italic",v:"Down with them in her wickedness..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, she gave birth by her father,"}],[{t:"italic",v:"And brought forth many daughters..."}]]},{type:"poetry",lines:[[{t:"italic",v:"In sin she brought forth! In great wickedness"}],[{t:"italic",v:"She proliferated all her adulteries"}],[{t:"italic",v:"Against both God and man!"}]]},{type:"para",segments:[{t:"text",v:"She has altogether forsaken Me! Says The Lord. For she does always reject the Spirit of Truth, and will not listen to the counsel of The Holy One of Israel. For she has solidified her way before her, and will not be turned aside! Behold, she is altogether like one who has committed treason, a self-appointed queen who has endeavored to seat herself upon My throne, deceiving the people, taking much delight in her authority! Behold, like the jackals of the wilderness, which tear the flesh and drag away the carcass, so has she torn the heart of this people; they are far removed! For they are made to dwell in darkness with her, as they lie down with the dead. Behold, even as the sow devours without reservation, wallowing in its own filth, taking much pleasure in all its uncleanness, so in like manner does she! Yet the sow knows its place, and acts according to the manner in which it was created. Yet it is not so among those who walk in her ways. Behold, even those who rebelled against her, who proclaim they are set apart from her, remain like her, practicing those same things which I said they shall not do! And though they say,"},{t:"italic",v:"\u201CWe are not daughters,\u201D"},{t:"text",v:"daughters they remain."},{t:"italic",v:"Thus the harlot shall be torn in pieces! Her flesh shall be eaten, and she shall be burned with fire, as it is written!"},{t:"fn",v:"1"},{t:"text",v:"And all her daughters, yes, all you churches of men, shall be severely abased! Even a great purging shall come forth from within the midst of you; behold, you shall be stripped naked and left desolate in the Great and Terrible Day of The Lord!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear Me, all you foolish leaders who dwell amongst the churches of men, hear the Word of The Lord your God:"},{t:"text",v:"Yes, you shall surely be left desolate and stripped naked of all your clothes! And no more shall you spew all this perverse doctrine or revel in all these filthy traditions before My face! Behold, your adulteries shall be uncovered, O churches of men, and you shall cry out in the streets! And with tears streaming, you shall fall and be made to sit upon the ground, until you once again stand up with pure testimony and right understanding, proclaiming My name in truth, honoring My Commandments and keeping My Sabbaths, and no more adding to nor taking away from the Word which I have commanded you."},{t:"fn",v:"2"},{t:"text",v:"In that day, the multitudes shall lie down in death, and many of you shall fall asleep. Yet I shall come for you, and lift you up, and give you robes of white. Yes, you shall die, even at the hands of men, yet you shall be lifted up to glory."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore purge yourselves, and cease from all this awful spewing!"}],[{t:"italic",v:"Wash yourselves, make yourselves clean, AND REPENT; return to Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, come to Me empty, that you may receive true knowledge;"}],[{t:"italic",v:"Come out from among them and embrace your Savior in truth;"}],[{t:"italic",v:"Be delivered from all this darkness!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Turn away from the commandments of men;"}],[{t:"italic",v:"Stand apart from those who call evil good and good evil,"}],[{t:"italic",v:"Who put darkness for light and light for darkness,"}],[{t:"italic",v:"Who put bitter for sweet and sweet for bitter,"},{t:"fn",v:"3"}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"text",v:"O churches of men, how long shall I suffer you?! How long will you devour corrupt fruit and consume bitter doctrine, and then in turn serve it to My children?! For from the grapes which bring forth wrath do you produce wine, and from the fruit of wild grapevines do you drink, leaving your mouths dry and your palates bitter. Cast it out! For as it is written:"},{t:"italic",v:"You can not drink from the cup of The Lord and from the cup of demons!"},{t:"fn",v:"4"},{t:"italic",v:"You can not partake of The Lord\u2019s table and of the table of demons! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"Yet I hear you saying,"},{t:"italic",v:"\u201CWe do not sup with demons, nor do we drink from their cup. And we have never served rotten food!\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"My anger is kindled against you, O churches of men! My discipline is prepared and made ready and shall be most severe, on account of all this blasphemy I have heard from your lips, and because of all these heresies of which you have readily accepted from all these haughty scholars, teachers, pastors, preachers, ministers and priests, who have set themselves up as an authority, who as the Pharisees of old have lifted up their heel against Me! CHURCH LEADERS, LET MY PEOPLE GO! No more feed them, for I alone shall feed them! Let them go, so I may purge them and make them clean! LET THEM GO! Let My children come out and worship Me in a place set apart. For they are My treasure and I shall surely steal them away, even all in whom I see of Myself, those who have received of Me in sincerity and in truth, humble and penitent, with a new heart and a contrite spirit. Indeed, from the beginning I have set up prophets and exalted My servants in accordance with My will, yet who among these did I not first abase? Can any man be humbled without first being brought low? And who among you, who wears a crown, shall not have it struck from his head? Shall not his pompous robes and fine apparel also be stripped from him, even in the sight of many witnesses? For there is but One who wears the crown, only One who shares it with the worthy. Yet among the churches I hear only a hissing at this Word, though it has proceeded from My own mouth! Therefore, know this and also understand, O foolish and slothful people:"},{t:"italic",v:"Though you forbear, I will continue to speak; and though you push out the hand and wag the head, I shall cause this Word to cleave to you; and behold, the more you struggle and fight against it, the more burdensome shall it become, pressing hard upon your chest, entering in, even to the piercing of your heart."}]},{type:"poetry",lines:[[{t:"italic",v:"For you, O rebellious children, have indeed grown very fat,"}],[{t:"italic",v:"Having engorged yourselves as the sluggard, even as"}],[{t:"italic",v:"The rich man who sits at his own table to be a glutton;"}],[{t:"italic",v:"For he partakes only of that which is pleasing"}],[{t:"italic",v:"In his own eyes and seasoned by his hire..."}]]},{type:"poetry",lines:[[{t:"italic",v:"So also do you, O churches of men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For you seek after every seductive and deceiving"}],[{t:"italic",v:"Spirit to satisfy your itching ears, embracing only"}],[{t:"italic",v:"That which you perceive frees you from all accountability,"}],[{t:"italic",v:"That you may continue to walk in the deceits of your flesh,"}],[{t:"italic",v:"As you seek to fulfill every hidden lust of your corrupted hearts..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus you do always push out the hand against the Truth,"}],[{t:"italic",v:"Hating that which brings conviction, resisting the purging of your souls."}]]},{type:"para",segments:[{t:"text",v:"Churches of men, what god is this you serve?! What savior is this you testify of?! Behold, he has become unrecognizable to Me, an idol which you have made, a corrupt image which you have established upon the doctrines and traditions of men, which run contrary to Me and My Word! Yes, it is MY Word which you have polluted, mistranslated and misinterpreted, according to the vain deceits of men in authority, whose hearts are perverse, overflowing with pride, puffed up and full of vanity! Says The Lord. Churches of men, you have endeavored to recreate Me in your own image! Cry out to The Potter, therefore, for you are but clay! And no more speak as though you are in any way able to mold Him! For I tell you the truth, you have all become as a disgusting lump in His body! And that which you speak has become like a sore and a sickness which exudes a foul stench, a detestable odor which ceases not from coming up before My face! For you have altogether become as the pagan and the heathen among whom you dwell, a rotten stalk of wheat in a valley of tares, where the latter rain has ceased and the sun narrowly breaks through the clouds. For you are a people who gather together in The Messiah\u2019s name (whom you call Christ), yet your visage has become altogether as that of the world, a people who take the name of The Lord in vain continually by your corrupt doctrines and filthy traditions, even by all your holidays, which I hate! Therefore your prayers are not heard"},{t:"fn",v:"5"},{t:"text",v:", your worship is not accepted; My face is turned from you, and My hand is removed. For you continue to practice those things which I said you shall not do and forsake that which I commanded be done, dishonoring that which was to be held in high esteem and forgetting that which I called you to remember. Thus you have turned to Me the back and not the front, and at My Word you hiss and wag the head, arousing Me to anger. Churches of men, why do you embrace wrath?! Indeed, it is as though you have fallen in love with judgment! For you do always practice that which I said you shall not do, marrying yourselves to those doctrines and traditions which are against Me, even to all these pagan-laced holidays and festivals, which I hate! Furthermore, you pollute My name and the glory of The Holy One by this one doctrine which I despise in My zeal, the false and most perverse doctrine called hell and eternal torment,"},{t:"fn",v:"6"},{t:"text",v:"as spoken of and taught in the churches of men! Yet you embrace it, yea, you grab hold of it and make it your own, upholding satan\u2019s cause! Woe, My people! Woe, I say to you! For those who love wrath shall surely receive of it, and those who seek torment for another shall partake of it in the Day of The Lord! Behold, even now it is yours! For My hand is removed from all who uphold this doctrine or speak against this Word. Lo, as an unarmed man overtaken suddenly by a band of thieves, left bruised and broken, so shall it be in the Day of The Lord, for all who reject this Word and heed not the sound of this Trumpet. Therefore, as it is written:"},{t:"italic",v:"Watch and pray always that you may be counted worthy to escape all these things."},{t:"fn",v:"7"},{t:"text",v:"For the time has come, behold, the Day is here, it waits at the doors, and soon the whole world shall fall under the shadow of My judgment."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, come out from among them and prepare to meet your God!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Bow down and be purged and no more stand defiant;"}],[{t:"italic",v:"Seek no longer to uphold your own way, but come to Me naked;"}],[{t:"italic",v:"Kneel before your Redeemer and bear your hearts before Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved ones, receive of The Pure Water and drink deeply,"}],[{t:"italic",v:"Yea, immerse yourselves and be cleansed, set free!"}]]},{type:"para",segments:[{t:"text",v:"For The Lord your God has a Holy One; He is The Head of the body, The True Sanctuary, The Only Life Without End! Say no more there is another way into eternal life, nor say those who reject His life live also, though it be in torment. For there is but ONE WAY, ONE TRUTH and ONE LIFE..."},{t:"italic",v:"Behold, He is a strong tower, a fortified city in the day of battle, an all-encompassing fire; The Mighty and Strong One whose rod is made of iron, The Law-Giver; The Source of Life by which all things consist,"},{t:"fn",v:"8"},{t:"italic",v:"your Carpenter and Redeemer, The Salvation of God! My people, wait upon The Lord with meekness and fear, with unwavering trust, wait for Him! For He is The Fountain of Living Waters for all who thirst, a fruitful vine for the hungry, a wealth of riches for all those who come to Me empty."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, beloved, give Him glory!"}],[{t:"italic",v:"Lift up your voices with everlasting praise!"}],[{t:"italic",v:"Bring thanksgiving to the altar,"}],[{t:"italic",v:"And offer up your hearts before Him!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shout His name to the heavens,"}],[{t:"italic",v:"For He is The Lord your Righteousness!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA HAMASHIACH!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"IMMANU EL!"}]]}],footnotes:{1:{type:"scripture",ref:"Revelation 17:16"},2:{type:"scripture",ref:"Deuteronomy 4:2, Deuteronomy 12:32 (NKJV)"},3:{type:"scripture",ref:"Isaiah 5:20"},4:{type:"scripture",ref:"1 Corinthians 10:21"},5:{type:"scripture",ref:"Proverbs 28:9"},6:{type:"note",text:'See: "The False Doctrine of Hell and Eternal Torment Exposed"',url:"https://www.thevolumesoftruth.com/The_State_of_the_Dead_and_The_Fate_of_the_Wicked:_The_False_Doctrine_of_Hell_and_Eternal_Torment_Exposed",link:{collection:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed",letterTitle:"The State of the Dead and The Fate of the Wicked: The False Doctrine of Hell and Eternal Torment Exposed"}},7:{type:"scripture",ref:"Luke 21:36"},8:{type:"scripture",ref:"Colossians 1:16-17"}},nkjv:{"Revelation 17:16":"And the ten horns which you saw on the beast, these will hate the harlot, make her desolate and naked, eat her flesh and burn her with fire.","Deuteronomy 4:2, Deuteronomy 12:32 (NKJV)":"4:2 \u2014 You shall not add to the word which I command you, nor take from it, that you may keep the commandments of the LORD your God which I command you. | 12:32 \u2014 \u201CWhatever I command you, be careful to observe it; you shall not add to it nor take away from it.","Isaiah 5:20":"Woe to those who call evil good, and good evil; Who put darkness for light, and light for darkness; Who put bitter for sweet, and sweet for bitter!","1 Corinthians 10:21":"You cannot drink the cup of the Lord and the cup of demons; you cannot partake of the Lord\u2019s table and of the table of demons.","Proverbs 28:9":"One who turns away his ear from hearing the law, Even his prayer is an abomination.","Luke 21:36":"Watch therefore, and pray always that you may be counted worthy to escape all these things that will come to pass, and to stand before the Son of Man.\u201D","Colossians 1:16-17":"16. For by Him all things were created that are in heaven and that are on earth, visible and invisible, whether thrones or dominions or principalities or powers. All things were created through Him and for Him. 17. And He is before all things, and in Him all things consist."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/churches-of-men-hear-the-word-of-the-lord-3",videoVoiceUrl:"https://www.youtube.com/watch?v=mRhENOVppJo&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"I Am Calling You Out",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"False Doctrines Within the Churches of Men Regarding...",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],num:28,prevLetter:{id:"the-lord-has-purposed",title:"The Lord Has Purposed"},nextLetter:{id:"roaring-lions",title:"Roaring Lions"}},{id:"roaring-lions",title:"Roaring Lions",date:"9/20/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, I reveal to you a mystery concerning these I have chosen, of whom I am also sending, these who must remain and gather together the second harvest, My witnesses who shall shout The Lord\u2019s Proclamation. These shall be left, according to the perception of men who remain upon the earth in that day, yet taken according to those who are changed and come to know My dwelling place. For such is the way and power of The Lord, for those who come to live in Me and move within My spirit. Yet how can they be both left and taken, you ask. I tell you the truth, they shall be even as a rose in full bloom, both uprooted and replanted in one swift stroke. For those whom I have chosen, who are of the special offering, must be changed, or how shall I send them and how shall they go for Me? By what means shall they endure, when death stalks them as the prey? For as it is written:"},{t:"italic",v:"Unless those days were shortened, no flesh would be saved."},{t:"fn",v:"1"},{t:"text",v:"Behold, they shall move through the multitude unhindered, both seen and unseen, heard and rejected. They shall be as vinedressers in My vineyard, men of promise until the time, husbandmen in the Great and Terrible Day of The Lord. Yet they shall by no means be given up as lambs to the slaughter, for they shall all be mighty men! They shall roar like young lions; behold, with a resounding roar I shall speak through them! And they shall make a great noise, even in the midst of this most ungodly generation! - A terrible sound assaulting the ears of this wicked multitude who hate My name and My coming, a loud shout, a blaring trumpet, breaking down the walls, leaving them desolate!"},{t:"fn",v:"2"},{t:"text",v:"Yet to the wild wheat, the broken and refined wheat, those ripe for the second harvest, to them My witnesses shall be as a welcomed rain in the midst of a ten-year drought, a shelter from the heat at the height of summer, even as singing doves set on a high branch beckoning all who hear to spy them out."}]},{type:"poetry",lines:[[{t:"italic",v:"Yes these, My chosen, shall be left in the"}],[{t:"italic",v:"Day of The Lord as beacons, to guide those"}],[{t:"italic",v:"Who yet grovel in the dark, seeking respite;"}],[{t:"italic",v:"A strong arm to lean upon for those who yet lack a foothold,"}],[{t:"italic",v:"Servants who see clearly though night has fallen..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, beloved, trust in My ways;"}],[{t:"italic",v:"Run not ahead, nor lag behind;"}],[{t:"italic",v:"Take My hand and embrace Me tightly..."}]]},{type:"poetry",lines:[[{t:"text",v:"For the time has come..."}],[{t:"stanza-break"}],[{t:"text",v:"Says The Lord."}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 24:22"},2:{type:"scripture",ref:"Isaiah 5:28-30"}},nkjv:{"Matthew 24:22":"And unless those days were shortened, no flesh would be saved; but for the elect\u2019s sake those days will be shortened.","Isaiah 5:28-30":"28. Whose arrows are sharp, And all their bows bent; Their horses\u2019 hooves will seem like flint, And their wheels like a whirlwind. 29. Their roaring will be like a lion, They will roar like young lions; Yes, they will roar And lay hold of the prey; They will carry it away safely, And no one will deliver. 30. In that day they will roar against them Like the roaring of the sea. And if one looks to the land, Behold, darkness and sorrow; And the light is darkened by the clouds."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/roaring-lions",videoVoiceUrl:"https://www.youtube.com/watch?v=j_xy4OJpook&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=26",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:29,prevLetter:{id:"churches-of-men-hear-the-word-of-the-lord",title:"Churches of Men, Hear The Word of The Lord"},nextLetter:{id:"as-i-am-so-shall-it-be-with-those-i-am-sending-the-mystery-of-god-revealed-to-the-chosen",title:"As I Am, So Shall It Be with Those I Am Sending... The Mystery of God Revealed to the Chosen"}},{id:"as-i-am-so-shall-it-be-with-those-i-am-sending-the-mystery-of-god-revealed-to-the-chosen",title:"As I Am, So Shall It Be with Those I Am Sending... The Mystery of God Revealed to the Chosen",date:"10/1/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy, During Men\u2019s Online Fellowship",forLine:"For All Those Who Have Ears to Hear (Regarding the Book of Ezekiel, Chapter One)",blocks:[{type:"para",segments:[{t:"text",v:"My sons, before you in My Book is My glory revealed, says The Lord. Yet few are able to receive it, nor are they able to comprehend it..."},{t:"italic",v:"Behold the aspects of God, that which is and was and shall be, manifest in Himself and of Himself, both that symbolized and that which I AM."},{t:"text",v:"For I tell you the truth, you have attempted to see My likeness in your imagination upon the reading of this Word, yet you have perceived only slightly. For indeed My likeness was revealed to My servant of old, in a vision and by the hearing, yet this is not the visage of The Lord as it truly is, nor can anyone look upon The Father and live. Thus through many figures of speech, and symbolic signs and gestures, has the likeness of The Lord come to be written in a book."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore hear My words, and pray"}],[{t:"italic",v:"Also that you receive understanding..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The wheel within the wheel is that"}],[{t:"italic",v:"Which is and was and is to come,"}],[{t:"italic",v:"The Almighty, The Father and The Son,"}],[{t:"italic",v:"The Everlasting who has neither beginning nor end."}]]},{type:"para",segments:[{t:"text",v:"As is The Father, so too is The Son, and the will of God the same. For The Word of God speaks, and it is done. The Spirit of The Lord moves and it is made manifest, never turning to the left hand nor to the right, but going always straight forward. For the will of The Lord is and shall be, and is already, and has always been; even as The Power of God moved upon the face of the deep, and that which had no form was formed and came to be. For I am before all things, and in Me all things consist, as it is written"},{t:"fn",v:"1"},{t:"text",v:", even as this testimony speaks to the truth of who I am:"},{t:"italic",v:"In the beginning was The Word, and The Word was with God and The Word was God. The same was in the beginning with God. Through Him all things came into being, and nothing in all creation was made apart from Him. In Him was life, and The Life was the light of men. The Light shines in the darkness, and the darkness shall not overcome it"},{t:"fn",v:"2"},{t:"italic",v:"... Behold, The Word became flesh"},{t:"fn",v:"3"},{t:"italic",v:", Immanu El!"},{t:"fn",v:"4"}]},{type:"para",segments:[{t:"italic",v:"My sons, listen and have understanding:"},{t:"text",v:"I AM. I think, and it is manifest; I purpose, and it is established; I speak, and it comes to pass. I AM THE LORD. All living things have breath"},{t:"italic",v:"in"},{t:"text",v:"Me, and those created as living souls receive breath"},{t:"italic",v:"from"},{t:"text",v:"Me. And so shall it be in the Day of The Lord, with those I am sending. Yet they shall not receive of My breath as at the first, but shall receive of Me anew, even of My fullness, as I cause the new song to fill their hearts. And they shall move within My spirit and dwell within My being, in union with The Messiah, always in the presence of The Lord. And when I send them, I shall go out ahead of them. And they shall not turn when they go, but they shall go straight forward, following Me wheresoever I go. And where I am they shall be also. And in the same way, wheresoever they go, I shall be already, and never again shall we be apart."}]},{type:"para",segments:[{t:"text",v:"My sons, though these things are very hard at present to understand, they shall surely be. For when the day comes, and you come to know Me as I truly am, then that which is hard to discern will be understood, and that which is a mystery shall be no more a mystery, but shall be made plain, even self-evident. For I will be fully established in you, and you in Me, even as I am in The Father and He is in Me."}]},{type:"poetry",lines:[[{t:"italic",v:"Trust therefore, and wait with all patience"}],[{t:"italic",v:"In faith, until your reward comes..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I AM HE, beloved ones, I AM HE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Desire of Ages! The Amen!"}]]}],footnotes:{1:{type:"scripture",ref:"Colossians 1:16-17"},2:{type:"scripture",ref:"John 1:1-5"},3:{type:"scripture",ref:"John 1:14"},4:{type:"scripture",ref:"(which means \u201CGod with us\u201D) - Matthew 1:23"}},nkjv:{"Colossians 1:16-17":"16. For by Him all things were created that are in heaven and that are on earth, visible and invisible, whether thrones or dominions or principalities or powers. All things were created through Him and for Him. 17. And He is before all things, and in Him all things consist.","John 1:1-5":"1. In the beginning was the Word, and the Word was with God, and the Word was God. 2. He was in the beginning with God. 3. All things were made through Him, and without Him nothing was made that was made. 4. In Him was life, and the life was the light of men. 5. And the light shines in the darkness, and the darkness did not comprehend it.","John 1:14":"And the Word became flesh and dwelt among us, and we beheld His glory, the glory as of the only begotten of the Father, full of grace and truth.","(which means \u201CGod with us\u201D) - Matthew 1:23":"\u201CBehold, the virgin shall be with child, and bear a Son, and they shall call His name Immanuel,\u201D which is translated, \u201CGod with us.\u201D (Matthew 1:23)"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/as-i-am-so-shall-it-be-with-those-i-am-sending-the-mystery-of-god-revealed-to-the-chosen",videoVoiceUrl:"https://www.youtube.com/watch?v=uVaosY1xm0s&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=27",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Book of Ezekiel",url:"https://answersonlygodcangive.com/Regarding_the_Book_of_Ezekiel"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:'The Name of The Lord - "Immanu El"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#Immanu_El"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:30,prevLetter:{id:"roaring-lions",title:"Roaring Lions"},nextLetter:{id:"the-fatherless-widow",title:"The Fatherless Widow"}},{id:"the-fatherless-widow",title:"The Fatherless Widow",date:"10/8/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy, For All Those Who Have Ears to Hear",forLine:"",noteLine:"(Regarding the churches of men and their rejection of this Word)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My sons and daughters, take this knowledge you have received in Me, and discern. Anoint your eyes with this salve I have given you, and now see. Come to see with My eyes; see, beloved! See with your hearts and quiet your minds, that you may understand. Yes, let your hearts be troubled, let the tears flow, and wail over your brothers and sisters in the churches. Wail, be broken in pieces on their behalf, that you may know what My love is, that your hearts may come to beat in sync with Mine. For they have departed from Me! Beloved, I do not know them! Such sorrow and bitter tears, I do not know them! Great enmity has come up between us! For they remain lovers of the world, ensnared by the things of this world and men! Beloved, they have forsaken Me! Behold, they have turned to Me the back and not the front! For I have reached out My hand to them, yet they turn away, refusing Me, seeing only cords of which they despise and endeavor to cut. Beloved, they have hated the sound of My voice, and do always hold out the hand against the leading of My spirit! Such sorrow, such enmity and tears, I weep for them! Beloved, I have counted their tears also, in number very few, for My tears they have not known. How then shall I heal them? How then shall they receive ears to hear? For their hearts remain cold, without feeling, unyielding to the call of God, a hard and proud people who bear false witness in My name without ceasing. They retain no love for God in their hearts, nor do they love their neighbor, even to the forsaking of the poor and the needy. And of the cause of the widow and the fatherless, they care not, nor do they contend on their behalf, unwilling to lift even one finger to aid them."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"I am come to make them poor, to leave them desolate. Even now they are in severe lack and remain void of the Spirit, and know it not. And behold, the day is coming and draws very near, when they shall be in need and no one will come to aid them. For I am no more their Father, and they are no more My people, says The Lord. For they have played the harlot; indeed, they have rebelled against Me, and have played the harlot with many lovers!"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus those who were to be the bride shall become the widow;"}],[{t:"italic",v:"She shall altogether become as one who mourns the loss of her husband,"}],[{t:"italic",v:"As one who seeks after her beloved, yet he can not be found..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And so shall it remain until her day comes and is fulfilled,"}],[{t:"italic",v:"When she once again cries out in the streets,"}],[{t:"italic",v:"\u201CBlessed is He who comes in the name of The Lord!\u201D"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-fatherless-widow-3",videoVoiceUrl:"https://www.youtube.com/watch?v=COfWf0XLuwE&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=40",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"The One Who Stays, Lets",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:31,prevLetter:{id:"as-i-am-so-shall-it-be-with-those-i-am-sending-the-mystery-of-god-revealed-to-the-chosen",title:"As I Am, So Shall It Be with Those I Am Sending... The Mystery of God Revealed to the Chosen"},nextLetter:{id:"the-word-of-my-mouth",title:"The Word of My Mouth"}},{id:"the-word-of-my-mouth",title:"The Word of My Mouth",date:"11/3/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Behold, My words shall never pass away, for as I am so also is My Word. For it proceeds from Me, being manifest by He Who Is True, also being called The Word... Living... Always feeding His flock the Word which is written for their nourishment, which is to be received through that part of Himself which is also in Me, the Spirit called Holy, which speaks to the truth of who I am, glorifying Him who I sent to you who bears My name and reveals My glory in Himself, even as I am glorified through Him, His glory being the same I own. For We are One from the beginning, yet manifest as two in the earth, so those whom I have chosen may know Me and come to Me and receive life. For I am The Lord, and I do not change."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"My son, there are some among you who have endeavored to seat themselves at My table, who yet resist My Word in the Volumes. They long to hear My Word, but at the same time refuse it. For they can not bear to hear the truth of My words spoken to this generation, lest they feel conviction deep within. For as it is written, so it is, even to this day:"},{t:"italic",v:"They come to you as people do. They sit before you as though they were My people, and they hear your words, but they do not act upon them. For with their mouths they speak flatteries and for a pretense show much love, yet their hearts pursue their own way. Indeed, you are as a lovely song to them, one who has a pleasant voice and can play well on an instrument. For they hear your words, but they will not do them!"},{t:"fn",v:"1"},{t:"text",v:"Yet My people shall live by faith, and walk in that which was given them already. For those who truly know Me pay close attention to My every word, and also give ear and obey that which I speak presently, giving heed to that which is at hand and given to this generation. Yet that which I speak at present must be put first. Thus that which is contained in the Volumes of Truth is foremost, and must be brought to the forefront for all to behold. Not that this Word is at all superior; neither shall it be considered inferior to My Word found in the Scriptures of Truth. For My Word is My Word; all I speak is Scripture and Truth. And that which I speak in the hearing of My prophets is written and put forth for the generation in which it is to be received, foremost, whether they will hear or whether they will forbear. And as it was in all times past, when I spoke by My servants, the prophets, and they in turn both wrote and spoke My words aloud, saying,"},{t:"italic",v:"\u201CThus says The Lord,\u201D"},{t:"text",v:"so it is at this time also, even during the end of this age which is upon you. Again, I say to you, that which proceeds from My mouth at present is foremost, and shall not be put second to My Word spoken aforetime. Neither is one a foundation for the other, as though the Word proceeding from My own mouth is in need of anything to uphold it; nor is any other witness required to prove My Word as My own, when I Myself have spoken it..."},{t:"italic",v:"MY WORD STANDS! Therefore, let My present Word be shown to be in full agreement with My former Word. For it is indeed in perfect agreement with My Word as it was, yet runs straight in comparison with that which men have made crooked."}]},{type:"para",segments:[{t:"text",v:"Here is wisdom few have considered, nor have they understood: If one who confesses Me lacks discernment, on account of ears which remain dull of hearing and eyes which remain dim in seeing, let them test My Word by My Word only. For any who test outside My Word, according to the words or doctrines of men, shall fail and be found in contempt before The Lord. For I alone sit as judge. Indeed, they have failed to see that My Word in the Volumes of Truth, also being called the Letters, is the rod by which the translations of men are to be tested, a light which shines upon the doctrines of men to expose them, revealing them to be blasphemies and heresies before God, all of which shall burn up in the Day, when the fire comes to test the quality of each man\u2019s work."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, if one professing faith be wise,"}],[{t:"italic",v:"He shall humble himself before Me,"}],[{t:"italic",v:"Calling upon the name of The Holy One"}],[{t:"italic",v:"For knowledge, in where all understanding"}],[{t:"italic",v:"Flows to the truly contrite and penitent,"}],[{t:"italic",v:"Flowing in pure testimony, free from corruption..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And by this only shall one be wise in the reading,"}],[{t:"italic",v:"Comparing that which was given with that"}],[{t:"italic",v:"Which is put forth once again, discerning"}],[{t:"italic",v:"The Source and The Author to be the same..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One Word, One Book,"}],[{t:"italic",v:"One on-going Testament to My glory;"}],[{t:"italic",v:"By no means shall it be divided into three!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Ezekiel 33:31-33"}},nkjv:{"Ezekiel 33:31-33":"31. So they come to you as people do, they sit before you as My people, and they hear your words, but they do not do them; for with their mouth they show much love, but their hearts pursue their own gain. 32. Indeed you are to them as a very lovely song of one who has a pleasant voice and can play well on an instrument; for they hear your words, but they do not do them. 33. And when this comes to pass\u2014surely it will come\u2014then they will know that a prophet has been among them.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-word-of-my-mouth",videoVoiceUrl:"https://www.youtube.com/watch?v=1Eu7udI0eCE&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Holy Spirit",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Woe to Those Who Walk in Pretense",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Walk_in_Pretense"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"About The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Discernment",url:"https://answersonlygodcangive.com/Main_Page#Discernment"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:32,prevLetter:{id:"the-fatherless-widow",title:"The Fatherless Widow"},nextLetter:{id:"warn-them-from-me-says-the-lord",title:"Warn Them from Me, Says The Lord"}},{id:"warn-them-from-me-says-the-lord",title:"Warn Them from Me, Says The Lord",date:"11/3/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the churches of men)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants, those who are being sent into battle, My shepherds whom I have set up and shall surely establish, those who shall shepherd the wild of My flock and prepare My way before Me:"},{t:"text",v:"My sons, correct them sharply and warn them from Me; let the division be made clear. For as I am, says The Lord God, so shall I be and have always been. I can not be moved, and neither shall those in whom I come to dwell fully. I AM THE LORD. Therefore, warn them from Me. For all who hate My Letters and despise My Word written in these Volumes, who also refuse My correction, contend not with men but with The Lord their God, even to the polluting of My name as they walk together in arrogant accord. For in the name of pride they do closely adhere to every perverse tradition of their forefathers, as they follow after every deceitful wind of doctrine which tickles their ears, which I hate! Their works are detestable to Me, I loathe the sight of them! I can bear the ways of this people no longer, nor will I hear them anymore!"}]},{type:"poetry",lines:[[{t:"italic",v:"Again I say, warn them from Me;"}],[{t:"italic",v:"Whether they will hear or whether they"}],[{t:"italic",v:"Will forbear, make My Word known;"}],[{t:"italic",v:"Strike quickly with the sword I have given you!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the Word of God is indeed quick and powerful"}],[{t:"italic",v:"And very sharp, and by it shall the multitudes be divided!"}]]},{type:"para",segments:[{t:"text",v:"Behold, they have divided themselves already, according to that which dwells within their hearts. For they have cast their lot with men and the deceiver, refusing My correction and those truths which are self-evident in the eyes of all who know Me and in whom I dwell. Therefore, I will no more listen to all these controversies brought forth from the lips of those who call of themselves Christian, who dwell in the midst of all these worldly churches of men, whose doctrines and traditions I hate. No more will I allow their perverse disputings to continue, for they do always fight against Me! I shall turn to them the back, and not the front; I shall hide My face from them, for I do not know them! - Lawless people, purveyors of lies, false witnesses who cease not from polluting My name and My glory! Therefore they shall be left desolate, standing alone in the place they said they would never be, refinement and the Day of The Lord..."},{t:"italic",v:"A day of abasement and great humbling, a day of bewilderment and many tears, the day of heavy sorrows and gnashing of teeth."},{t:"text",v:"For I must give correction and impart judgment, or how shall I gather them? Thus brokenness shall become their companion in the Day of The Lord\u2019s Anger. For My anger shall not be turned away, until they say,"},{t:"italic",v:"\u201CBlessed are the feet of those whom The Lord sends, for they have received a message from God. We will give heed to their speech and pay close attention to their every proclamation. We repent, O Lord, in dust and ashes.\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"I am The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And though I bruise, I will surely heal;"}],[{t:"italic",v:"And though I pour out strong judgment,"}],[{t:"italic",v:"I will also show mercy..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For all appointed to captivity shall go into captivity,"}],[{t:"italic",v:"Yet I will deliver them, even all who call on the"}],[{t:"italic",v:"Name of The Lord in that day..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And though many will be brought low,"}],[{t:"italic",v:"Even down to the depths of darkness and despair,"}],[{t:"italic",v:"Behold, from the depths I shall raise them up,"}],[{t:"italic",v:"Even high above the heavens!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even from the ashes shall I bring them forth,"}],[{t:"italic",v:"And they shall give Me perfect praise in the"}],[{t:"italic",v:"Tabernacle of My glory!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And so it is fulfilled, and shall also come to pass:"}],[{t:"italic",v:"The first shall be last, and the last shall be first partakers of the glory;"}],[{t:"italic",v:"Yet all will be saved according to the number The Lord shall call."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/warn-them-from-me-says-the-lord-4",videoVoiceUrl:"https://www.youtube.com/watch?v=g0jM1ShS_LE&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=30",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"About The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:33,prevLetter:{id:"the-word-of-my-mouth",title:"The Word of My Mouth"},nextLetter:{id:"i-can-wait-no-longer",title:"I Can Wait No Longer"}},{id:"i-can-wait-no-longer",title:"I Can Wait No Longer",date:"11/10/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Behold, I shall come in an instant! In a moment, I shall reach down and take My spoil!"},{t:"fn",v:"1"},{t:"italic",v:"Says The Lord. Therefore, let the remnant of Israel be found waiting with eager hands, and let those grafted into My olive tree bear summer fruit! Let the sprigs sprout quickly, and let not the seedlings be withered; let not the noonday sun wilt or scorch any of My pleasant plants! Be moved from your places, oh My people, and be hidden! Be exalted, oh My beautiful ones, and find sanctuary in the tabernacle of My mercy! Be sheltered from all this burning heat, until the indignation passes by and The Majesty comes!"}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"I can no more endure all this iniquity! I can no more tolerate all these abominations which proliferate throughout the land! This generation is a trouble to Me, I am weary of bearing them! No more shall all this wickedness go unpunished, no more shall all these abominations stand! For I shall surely rid Myself of My adversaries and take vengeance upon all My enemies! Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"I CAN WAIT NO LONGER!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the cries of the oppressed and of the hungry"}],[{t:"italic",v:"And of every starving child have reached deep"}],[{t:"italic",v:"Into the ears of The Lord of Hosts!"}],[{t:"italic",v:"For My beloved are murdered in every corner,"}],[{t:"italic",v:"And My servants are persecuted from city to city!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"BEHOLD, THE UNBORN ARE TORN IN PIECES!"}],[{t:"italic",v:"THEY ARE BROKEN AND MURDERED BEFORE MY EYES!"}]]},{type:"para",segments:[{t:"text",v:"Shall I not repay?! Says The Lord. Shall I not come down and make a swift end?! Shall I not deliver recompense in full?! Says The Almighty. Yet you, O most wicked and foolish generation, do not fear Me! And you, who say you are My people, refuse to believe! For you do always push out the hand against My messengers, and draw back from those I send. Behold, you say you are My people, yet you cover your ears when I speak and hide your faces when I pass by! Yet the time has come! And though you yet resist My voice, and turn away your ears from hearing, My wrath shall speak on My behalf and My power shall testify to My glory! Behold, the dark clouds gather, the lightning flashes on the horizon, yet no one seeks shelter, not one abides in safety, nor does the sound of thunder make them afraid. For they are a foolish people, a most arrogant generation, a corrupt people heavy-laden with sin; a people who make many lofty assertions without knowledge, a wholly ignorant people who reject the knowledge of God, yet embrace every corrupt theory created by men of science, a people who know not their right hand from their left! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"And what of all these houses called by My name, all these arrogant assemblies, these numerous denominations amongst the churches of men? Have any of these brought forth an offering worthy of acceptance, an offering of tears in sincere repentance, laying themselves upon the altar?"},{t:"fn",v:"2"},{t:"text",v:"Who among all these has offered up prayers and supplications for the afflicted? Who has come before Me on behalf of the unborn? WHERE IS THE OUTCRY?! My eyes have not seen it, neither have My ears heard it! Nor have I seen any amongst all these churches of excess strip themselves of all their fine apparel, that they may clothe another! Nor have they bent down the knee, nor offered the hand to even one of these I sent to them asking! Evil and wicked generation, brood of vipers, I have sent to you many witnesses! Even the poor and needy testify on My behalf, yet you remain unmoved! BLIND AND DEAF CHILDREN! SLOTHFUL SERVANTS! Therefore, let it be known to you:"},{t:"italic",v:"You have been weighed, O churches of men, and you, O nation not desired, you have been judged, AND YOU HAVE ALL BEEN FOUND WANTING! Your kingdom is finished, and your houses shall be left to you desolate! And of your gates, they shall be left wide open, and your enemies shall come in and take their spoil! Says The Lord."},{t:"text",v:"Churches of men, I had given you time to reveal your faith by works,"},{t:"fn",v:"3"},{t:"text",v:"to show yourselves worthy of Me,"},{t:"fn",v:"4"},{t:"text",v:"that I live in you and that you know Me, yet what is this I see?! - A stiff arm and an outstretched neck, a face full of haughty and high looks, a mouth teaching blasphemies and lies in MY name! Thus I shall surely leave you desolate, all your lampstands removed and taken,"},{t:"fn",v:"5"},{t:"text",v:"all your candlesticks put out and toppled!..."},{t:"italic",v:"You are estranged! I do not know you!"},{t:"fn",v:"6"},{t:"italic",v:"Tears, many tears, deep and heavy sorrows, for she who would be My bride is not My bride! She has departed from Me and lusts after others! She remains a harlot, and so I leave her to her own devices with six months to repent."},{t:"fn",v:"7"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus the true bride is chosen;"}],[{t:"italic",v:"She has been called out and shall be lifted up!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I will come for her and she will be taken,"}],[{t:"italic",v:"Caught up to My Father\u2019s house for one week"}],[{t:"italic",v:"In The Lord, and we shall be together forever..."}]]},{type:"poetry",lines:[[{t:"italic",v:"All tears wiped away..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even every tear she shed on the behalf of others;"}],[{t:"italic",v:"Every tear she shed for the afflicted and the unborn;"}],[{t:"italic",v:"Every tear she shed over all this evil,"}],[{t:"italic",v:"On account of all this oppression and death..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even every tear she shed in repentance,"}],[{t:"italic",v:"In seeking after her Bridegroom..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 Corinthians 15:51-52"},2:{type:"scripture",ref:"Luke 20:18"},3:{type:"scripture",ref:"James 2:17-20"},4:{type:"scripture",ref:"Matthew 10:37-38"},5:{type:"scripture",ref:"Revelation 2:5"},6:{type:"scripture",ref:"Matthew 7:22-23 (NKJV)"},7:{type:"note",text:'See: "I Shall Remove My Hand and My Spirit Shall Be Withdrawn..."',url:"https://www.thevolumesoftruth.com/I_Shall_Remove_My_Hand_and_My_Spirit_Shall_Be_Withdrawn..._And_That_Purposed_from_the_Beginning_Shall_Be_Done,_It_Shall_Be_Accomplished_Swiftly",link:{collection:"Volume Seven",letterTitle:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"}}},nkjv:{"1 Corinthians 15:51-52":"51. Behold, I tell you a mystery: We shall not all sleep, but we shall all be changed\u2014 52. in a moment, in the twinkling of an eye, at the last trumpet. For the trumpet will sound, and the dead will be raised incorruptible, and we shall be changed.","Luke 20:18":"Whoever falls on that stone will be broken; but on whomever it falls, it will grind him to powder.\u201D","James 2:17-20":"17. Thus also faith by itself, if it does not have works, is dead. 18. But someone will say, \u201CYou have faith, and I have works.\u201D Show me your faith without your works, and I will show you my faith by my works. 19. You believe that there is one God. You do well. Even the demons believe\u2014and tremble! 20. But do you want to know, O foolish man, that faith without works is dead?","Matthew 10:37-38":"37. He who loves father or mother more than Me is not worthy of Me. And he who loves son or daughter more than Me is not worthy of Me. 38. And he who does not take his cross and follow after Me is not worthy of Me.","Revelation 2:5":"Remember therefore from where you have fallen; repent and do the first works, or else I will come to you quickly and remove your lampstand from its place\u2014unless you repent.","Matthew 7:22-23 (NKJV)":"22. Many will say to Me in that day, \u2018Lord, Lord, have we not prophesied in Your name, cast out demons in Your name, and done many wonders in Your name?\u2019 23. And then I will declare to them, \u2018I never knew you; depart from Me, you who practice lawlessness!\u2019"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-can-wait-no-longer-3",videoVoiceUrl:"https://www.youtube.com/watch?v=N1X3O7VtIx0&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=31",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"The True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#Section_2_-_The_True_Bride"}],num:34,prevLetter:{id:"warn-them-from-me-says-the-lord",title:"Warn Them from Me, Says The Lord"},nextLetter:{id:"establish-my-way-before-me-says-the-lord",title:"Establish My Way Before Me, Says The Lord"}},{id:"establish-my-way-before-me-says-the-lord",title:"Establish My Way Before Me, Says The Lord",date:"12/25/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Peoples of the earth, do you know Me? Do you really know who I am? I am Elohim. YAHUSHUA-YAHUWAH is My name, both God and Savior. For in The Son does the fullness of The Father dwell."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Yet you of this earth have not known Me! Behold, I have spoken to you plainly, using few figures of speech, yet you do not know Me! From the beginning, even to this day, I have declared My glory through all My servants, the prophets, and still you refuse to embrace Me as I truly am! Behold, the peoples of the earth pollute My name, and the nations take counsel together to strike Me from remembrance! Therefore, ALL shall come to know Me in My anger! Every tribe, tongue, and people shall behold My hand against the nations, until all those who blaspheme are bowed down, until every jaw is clamped shut and every tongue cleaves to the roof of the mouth! For I am come out of My sanctuary, to astound the nations, to judge and to pour out judgment, to repay and take vengeance upon My enemies, to make an end! Yet I ask you, who among the nations fears Me? Who among this modern generation, among all these multitudes of perverse and vile people, revere My name? Who, among this great multitude, trembles in fear at the coming of The Lord?! And who among the mighty shall be able to stand, when the wrath of God is revealed from Heaven?! Therefore repent, and establish My way before Me, says The Lord God, and I shall also establish you! For I am The Lord, and I shall establish justice in all the earth! Why, O peoples of the earth, do you stand proud? Why do you set your faces like stone, and resolve in your hearts to fight against Me? Behold, I have set My face against YOU, and resolve in My heart to abase you, until the pride of man is bowed down and the arrogance of man is utterly humiliated, as it is written!"},{t:"fn",v:"2"},{t:"text",v:"Be bowed down therefore, O most wicked generation! Humble yourselves and repent, and seek now The Righteousness of The Lord, that you may live and not die!"}]},{type:"poetry",lines:[[{t:"italic",v:"Peoples of the earth, how long shall you court death and desire abomination?!"}],[{t:"italic",v:"Your hearts are full of adultery; you cease not from lying down with sin!"}],[{t:"italic",v:"Behold, you have joined yourselves to the grave and"}],[{t:"italic",v:"With death you have made your agreement!"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Foolish people, see now the Word of The Lord,"}],[{t:"italic",v:"Open your ears and listen to the voice of The Lord your God,"}],[{t:"italic",v:"And establish My way before Me, that you may live and not die..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For there is no other God besides Me;"}],[{t:"italic",v:"A just God and a Savior, there is none besides Me"},{t:"fn",v:"4"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Colossians 1:19"},2:{type:"scripture",ref:"Isaiah 2:17"},3:{type:"scripture",ref:"Isaiah 28:15"},4:{type:"scripture",ref:"Isaiah 45:21"}},nkjv:{"Colossians 1:19":"For it pleased the Father that in Him all the fullness should dwell,","Isaiah 2:17":"The loftiness of man shall be bowed down, And the haughtiness of men shall be brought low; The LORD alone will be exalted in that day,","Isaiah 28:15":"Because you have said, \u201CWe have made a covenant with death, And with Sheol we are in agreement. When the overflowing scourge passes through, It will not come to us, For we have made lies our refuge, And under falsehood we have hidden ourselves.\u201D","Isaiah 45:21":"Tell and bring forth your case; Yes, let them take counsel together. Who has declared this from ancient time? Who has told it from that time? Have not I, the LORD? And there is no other God besides Me, A just God and a Savior; There is none besides Me."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/establish-my-way-before-me-says-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=Zb0QVkFdwq0&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=31",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:'The Name of The Lord - "YAHUSHUA-YAHUWAH"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YAHUSHUA-YAHUWAH"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"The Pride of Man Shall Be Bowed Down",url:"https://answersonlygodcangive.com/Regarding_Pride#The_Pride_of_Man_Shall_Be_Bowed_Down"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:35,prevLetter:{id:"i-can-wait-no-longer",title:"I Can Wait No Longer"},nextLetter:{id:"i-am-come-out-of-my-sanctuary",title:"I Am Come Out of My Sanctuary"}},{id:"i-am-come-out-of-my-sanctuary",title:"I Am Come Out of My Sanctuary",date:"12/25/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, The Creator of Heaven and Earth, YAHUWAH, The One and Only True God, The God of Israel, The Only Lord of Hosts:"},{t:"text",v:"Peoples of the earth, come forth from your hiding places and call upon your gods! Call upon your leaders and beg your generals to set their armies in battle array! See if they are in anywise able to deliver you out of My hand, or hide you from the face of Him who sits on the throne! For I am come out to punish the wicked and cast down the mighty! Behold, I shall avenge Myself upon all My adversaries! For they have loved transgression and do always run greedily for gain, with no thought to others! The Way of The Lord they have put far from them, The Truth is gone from their hearts, and of The Life they want no part! The light of their eyes is darkened; they are filled with darkness! Their hearts are full of violence, and with their mouths they cease not from practicing deceit! Thus the wicked have no home, neither does the evil-doer have any place in all My Holy Mountain! From the earth and from The Holy City, they are cut off!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, I am indeed come out to judge the nations!"}],[{t:"italic",v:"I am indeed come forth to pass judgment"}],[{t:"italic",v:"Upon the peoples of the earth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For they have bound themselves together,"}],[{t:"italic",v:"And in one accord they stand defiant"}],[{t:"italic",v:"Against The Holy One of Israel!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus I shall cut them down in their loftiness"}],[{t:"italic",v:"And crush them at the height of their rebellion,"}],[{t:"italic",v:"Breaking off every branch, drying up"}],[{t:"italic",v:"Every root, until there is no trace"}],[{t:"italic",v:"And the land is left utterly desolate!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And it shall be as though they had never been..."}]]},{type:"closing",text:"Says The Lord God."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-come-out-of-my-sanctuary",videoVoiceUrl:"https://www.youtube.com/watch?v=aJturyakFqo&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=32",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:36,prevLetter:{id:"establish-my-way-before-me-says-the-lord",title:"Establish My Way Before Me, Says The Lord"},nextLetter:{id:"i-am-moved-to-wrath",title:"I Am Moved to Wrath"}},{id:"i-am-moved-to-wrath",title:"I Am Moved to Wrath",date:"12/25/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I am moved to wrath, My cup overflows, for great is the indignation of The Lord! I am come out to tread upon the gods of the earth, to destroy every stronghold, to break apart every dwelling place of idols! Behold, even against the churches of men shall I stretch out My hand, and My discipline shall be very severe! And behold, great collapse shall ensue, even from one end of the earth to the other, for their wickedness shall be exposed and their shame made plain! For the threshing of The Lord comes forth to separate and to divide asunder, to cleanse and to wipe away! Then shall The Foundation Stone be uncovered! And no more shall it be hidden by men or covered over with corrupt doctrine and filthy tradition! No more shall all this purple and scarlet hide the truth of who I am, nor shall this false image stand in My place, anymore! Neither shall all these men of vanities block My way before Me, anymore! For I am a jealous God, and I will not share My glory!"}]},{type:"para",segments:[{t:"text",v:"Behold, the anger of The Lord shall burst forth to the conquering of nations, to the punishing of great kings, to the slaughter of mighty men, to the utter destruction of every false god, to the smashing of every idol!..."}]},{type:"para",segments:[{t:"text",v:"TO THE KINGS OF THE EAST, AND EVERY IDOL!..."}]},{type:"para",segments:[{t:"text",v:"TO THE KINGS OF THE SOUTH, AND EVERY IDOL!..."}]},{type:"para",segments:[{t:"text",v:"TO THE KINGS OF THE WEST, EVEN OF ALL THEIR MATERIAL POSSESSIONS AND EVERY IDOL, UNTIL I HAVE BROUGHT THEM TO UTTER RUIN!..."}]},{type:"para",segments:[{t:"text",v:"AND TO THE KINGS AND CHIEF PRINCES WHO SURROUND MY PEOPLE, TO EVERY TEMPLE OF ALLAH AND EVERY IDOL! Behold, I shall murder the god of the sons of Ishmael before their eyes, and he shall die in that day, for he is no god! Neither can he save or deliver any out of My hand! For I shall cover his prophet with shame, and cause his name to become as an awful spewing among the nations, a byword and a hissing in all the earth!..."}]},{type:"para",segments:[{t:"text",v:"AND WHEN THE DAYS ARE ACCOMPLISHED, I SHALL BRING MY HAND AGAINST THE KINGS OF THE NORTH, AND EVERY IDOL! I shall tear them in pieces and cast down their ruler, covering their cities with darkness and their people with sores! Wailing and gnashing of teeth shall be heard without ceasing, until I have made a full end! Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"FOR THE LORD GOD HAS PURPOSED,"}],[{t:"italic",v:"AND WHO CAN ANNUL IT?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the first of the vessels is tipped"}],[{t:"italic",v:"And shall shortly be overturned,"}],[{t:"italic",v:"Its contents rushing forth like a flood!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My countenance is changed,"}],[{t:"italic",v:"My anger is come to the full"}],[{t:"italic",v:"And fills My face like fire!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus the time of The Great Recompense"}],[{t:"italic",v:"Has come, and can not be turned back!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"VENGEANCE IS MINE! SAYS THE LORD."}],[{t:"italic",v:"AND I SHALL SURELY REPAY!"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-moved-to-wrath",videoVoiceUrl:"https://www.youtube.com/watch?v=tsb8NMYi_kw&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=33",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:37,prevLetter:{id:"i-am-come-out-of-my-sanctuary",title:"I Am Come Out of My Sanctuary"},nextLetter:{id:"blood",title:"BLOOD"}},{id:"blood",title:"BLOOD",date:"12/25/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Behold, the earth swells with abominations. The cities of men are filled with darkness and overflow with every kind of evil. Every foul and wretched sin is widely accepted, as the multitudes band together with one voice, reaching new heights in wickedness. Across land and sea, iniquity spreads forth like a plague; even in the wide open spaces, behold, it is there, carried upon prevailing winds to every corner."}]},{type:"para",segments:[{t:"text",v:"O most wicked generation, you have raised up Sodom from the dust, and brought forth Gomorrah from the ashes, having learned nothing from the example!"},{t:"fn",v:"1"},{t:"text",v:"Behold, the days of Noah are revived before My face! Thus the days of calamity and many sorrows have come in."}]},{type:"poetry",lines:[[{t:"italic",v:"Peoples of the earth, your evils are"}],[{t:"italic",v:"Not hidden, nor does your wickedness sleep!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the cause of the oppressed has come up before Me,"}],[{t:"italic",v:"And the cries of the innocent fill My chambers!"}],[{t:"italic",v:"Even the sound of every unborn child, which you have murdered,"}],[{t:"italic",v:"Has entered into the ears of The Lord of Hosts!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Murder fills every corner, blood flows"}],[{t:"italic",v:"In the streets, and the lewd gladly walk in it!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus by all your doings have you brought"}],[{t:"italic",v:"Blood upon your own heads!..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus declares The Lord to the generation of His wrath:"},{t:"text",v:"From the blood of righteous Abel to the blood of every unborn child, even to every person murdered in innocent blood from the beginning unto this day, have I laid upon this generation!"}]},{type:"para",segments:[{t:"text",v:"For I had spoken, yet you would not hear! It was written, yet you rejected My Word! I poured out My spirit, yet you refused to drink! And now, even as in all times past, you come against My servants, the prophets! Behold, even the churches of men join in your error and remain on your part! For they have not discerned, neither will they receive correction, blind leaders of the blind who cast their lot with this world and the deceiver! THEREFORE, BLOOD! Blood shall be your drink, and suffering your meat! Blood and suffering shall fill every corner, for this is your due reward, seeing as how you do revel in it! Behold, you show no concern over the affliction of others, and care not for the poor and the needy! The cause of the widow and the fatherless is all but forgotten among you, and over the slaying of the innocent rarely a tear is shed! Your murders have not ceased, they only increase by measure! Nor have your leaders sought to put an end to all this injustice, nor has the outcry of the suffering entered your ears, nor has the scale of these atrocities penetrated your stony hearts, whereby you should have been moved by it! THEREFORE, BLOOD! Blood shall fill the rivers and springs of water, and the sea shall become as the blood of a dead man! The mountains shall drip with the blood of the slain, and the hills shall flow with the blood of My enemies; multitudes of dead bodies shall litter the ground!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the hand of The Invisible God"}],[{t:"italic",v:"Of your forefathers shall be felt!"}],[{t:"italic",v:"The presence of The Holy One of Israel"}],[{t:"italic",v:"Shall cause all in the earth to tremble!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The mountains shall be thrown down, the steep"}],[{t:"italic",v:"Places shall fall, and every wall shall fall to the ground!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, at the sound of My voice all creation shall bow down!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the time has come for The Ancient of Days"}],[{t:"italic",v:"To stand up and judge the peoples of the earth,"}],[{t:"italic",v:"For The Everlasting to stretch out His arm"}],[{t:"italic",v:"And pour out judgment upon the nations!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"2 Peter 2:6, Jude 1:7"}},nkjv:{"2 Peter 2:6, Jude 1:7":"2 Peter 2:6 \u2014 and turning the cities of Sodom and Gomorrah into ashes, condemned them to destruction, making them an example to those who afterward would live ungodly; | Jude 1:7 \u2014 as Sodom and Gomorrah, and the cities around them in a similar manner to these, having given themselves over to sexual immorality and gone after strange flesh, are set forth as an example, suffering the vengeance of eternal fire."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/blood",videoVoiceUrl:"https://www.youtube.com/watch?v=pIeWaPYjDqs&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=34",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Regarding the Days of Noah",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:38,prevLetter:{id:"i-am-moved-to-wrath",title:"I Am Moved to Wrath"},nextLetter:{id:"enemies-of-israel-come-forth",title:"Enemies of Israel, Come Forth"}},{id:"enemies-of-israel-come-forth",title:"Enemies of Israel, Come Forth",date:"12/31/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel:"},{t:"text",v:"The time has come, behold, the day appointed draws near, when I shall rise up and defend My people, Israel. I shall stretch out My hand and deliver them, even all who dwell in the land of Israel, the land which I had promised to Abraham and have given to the seed of Jacob, forever."}]},{type:"para",segments:[{t:"text",v:"Yet let it be known to you, O house of Israel, and let all nations understand, for My own name\u2019s sake shall I do it. For it is time to reveal My hand to the peoples of the earth, it is time for the name of The Lord your God to be made known, for My name to resound in all the earth! Then you will know, I AM THE LORD, and I have dealt with you for My own name\u2019s sake, and not according to your wicked ways, nor according to your corrupt doings, says The Lord God. Therefore, let the atheist consider and weep for his soul, let his intellect fail him and his heart melt like wax before the fire, for it is time! Yea, let all My enemies fear, let all in the earth tremble! For I am coming down to take vengeance upon My adversaries, and to repay all who lift up their heel against Me! For the enemies of Israel gather, evil thoughts have entered their hearts. And behold, as in the days of Moses when I hardened the heart of Pharaoh, so also have I hardened the hearts of those who seek to destroy Israel."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to the enemies of Israel:"},{t:"text",v:"COME FORTH! Yes, gather yourselves together and come forth! Make your pact and come out, ascend! Come like a storm, cover the land like a cloud, you and all your armies with you! COME OUT AND FIGHT AGAINST ME, THAT I MAY CUT YOU DOWN!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My fury shall show in My face!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And I shall strike you in My jealousy and cut you down"}],[{t:"italic",v:"In the fire of My wrath, as blighted wheat before the scythe,"}],[{t:"italic",v:"As a diseased sheaf left standing in an open field,"}],[{t:"italic",v:"Set as stubble before the fire!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I shall make of you a spectacle,"}],[{t:"italic",v:"And you shall be for a sign to all nations!"}],[{t:"italic",v:"For the time has come and I am eager to perform My will!..."}]]},{type:"closing",text:"Says The Lord, The One and Only True God, The Holy One of Israel."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/enemies-of-israel-come-forth-3",videoVoiceUrl:"https://www.youtube.com/watch?v=iR7u8PS9ayE&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=35",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:39,prevLetter:{id:"blood",title:"BLOOD"},nextLetter:{id:"the-world-shall-be-shaken",title:"The World Shall Be Shaken"}},{id:"the-world-shall-be-shaken",title:"The World Shall Be Shaken",date:"1/10/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"The earth is filled with violence, the whole world is corrupt! Madness has overcome the people, transgression is uplifted, and abominations of every kind are widely accepted; great wickedness proliferates throughout every tribe, tongue, people and nation unimpeded! Thus the earth is forsaken for a time, wherein I have turned to it My back. And so shall it remain, until the Great Day comes when I shall move swiftly against it. Behold, My countenance is changed, and I shall surely turn My face toward it once again. Yet not for good, but for great calamity! For My anger is kindled, and My face is set hard against the peoples of the earth! Behold, even this year shall many feel the strength of The Lord building quickly in His anger, and this world shall be shaken! For the heart of man has waxed cold, his wickedness proliferates beyond compare! Therefore I shall strike down My enemies in My fury, and the whole world shall tremble! Behold, the hearts of all people shall melt in that day, with every countenance falling, their innards quaking, their knees buckling for fear!"}]},{type:"poetry",lines:[[{t:"italic",v:"And until this time and after,"}],[{t:"italic",v:"The earth shall tremble and shake,"}],[{t:"italic",v:"And bring forth calamity upon calamity,"}],[{t:"italic",v:"And famine and pestilence of every kind..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For all this is but the beginning of sorrows..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The first contractions of an expectant mother"}],[{t:"italic",v:"Suffering to bring forth..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-world-shall-be-shaken",videoVoiceUrl:"https://www.youtube.com/watch?v=Xe_r7cI_BCg&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=36",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Days of Noah Revived",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah#The_Days_of_Noah_Revived"},{label:"The One Who Stays, Lets",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets#The_One_Who_Stays.2C_Lets"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"}],num:40,prevLetter:{id:"enemies-of-israel-come-forth",title:"Enemies of Israel, Come Forth"},nextLetter:{id:"i-shall-bring-my-hand-against-all-nations-who-have-forsaken-me",title:"I Shall Bring My Hand Against ALL Nations Who Have Forsaken Me"}},{id:"i-shall-bring-my-hand-against-all-nations-who-have-forsaken-me",title:"I Shall Bring My Hand Against ALL Nations Who Have Forsaken Me",date:"1/14/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, was the earthquake in Haiti part of Your judgment?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"From Haiti also have I removed My hand. For the multitude of their idols have I turned My face from them, and because of all their evil deeds have I forsaken them in My anger, says The Lord. Yet grieve not over all these dead, for by no means does death have the last word. Rather wail and pray for those who remain. Wail on behalf of those who refuse Me, and double for those who continue to rebel against Me, says The Lord. For they shall suffer the full weight of My wrath upon the nations."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, O peoples of the earth; awake and behold the signs, for The Lord God testifies against you:"},{t:"text",v:"I am The Lord and I have purposed, and I shall bring My hand against ALL nations who have forsaken Me! For the nations of the earth parade their whoredoms before Me continually! Greedily do they heap to themselves perversions of every kind, eagerly do they run to commit every sin I hate, practicing abomination to their own hurt! Behold, they celebrate their filthiness at noonday, and at night they revel in all their uncleanness! Peoples of the earth, how long shall you tempt The Lord your God?! For I can no longer bear the sight of you! Behold, I have given you many days to repent, yet you only increase in your rebellion against Me, putting evil for good and good for evil, darkness for light and light for darkness, making for yourselves laws that you might continue in all your fornications and walk proudly in your abominations! WICKEDNESS OVERFLOWS! It is not at all hidden!"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus in My bitterness I have forsaken you for a time,"}],[{t:"italic",v:"In My disgust I have turned to you the back, until the day"}],[{t:"italic",v:"My anger is revealed and My power is put on open display..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the Day of Recompense draws near,"}],[{t:"italic",v:"And shall continue until the consummation..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The day I take vengeance upon My enemies and repay"}],[{t:"italic",v:"The nations for all their forsaking of Me, the day I stretch"}],[{t:"italic",v:"Out My hand against the inhabitants of the earth..."}]]},{type:"closing",text:"Says The Lord God."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-shall-bring-my-hand-against-all-nations-who-have-forsaken-me",videoVoiceUrl:"https://www.youtube.com/watch?v=z8ZFEJfJHxg&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=37",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The One Who Stays, Lets",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:41,prevLetter:{id:"the-world-shall-be-shaken",title:"The World Shall Be Shaken"},nextLetter:{id:"the-voice-of-the-almighty-god",title:"The Voice of The Almighty God"}},{id:"the-voice-of-the-almighty-god",title:"The Voice of The Almighty God",date:"1/21/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Timothy, hear My words and have understanding, receive of Me and find peace. For that which I now share with you shall answer your concerns and open your understanding, and you shall have peace, says The Lord."}]},{type:"para",segments:[{t:"text",v:"For I will, and it is done; I speak, and it is heard. Yea, My voice resounds in all the earth, yet few have ears to hear. And though My voice is made known, even in all the world, still the people refuse to hear; indeed, they hate the sound of My voice! Yet you, Timothy, have embraced My voice, and your ears I have opened. Thus when I speak, you hear and also write and blow the Trumpet; so also is My voice carried upon the four winds of heaven, broadcast in every corner, entering into every ear. Yet as it is written:"},{t:"italic",v:"The heart of this people has waxed gross, their ears are dull of hearing and their eyes they have shut, lest at any time they should see with their eyes and hear with their ears and understand with their heart and be fully converted, and I should heal them."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Therefore, listen and have understanding: The Day is upon you, wherein I shall gather up My sheep and every lamb; even those asleep shall be lifted up, and the first harvest shall be accomplished in an instant. And though this Trumpet has reached in number many ten thousands, even now according to these millions, you will have only reached a very few when compared with the whole of the population of the earth, before the first harvest has commenced and is finished. For I tell you a mystery, which is now made known: I am The Lord, and My voice a consuming fire, the sound of which carries to the farthest reaches of the universe. Therefore that which I speak to you has already gone out into the world, even into every ear. Thus that which I command you to trumpet is an echo of My Word spoken to this generation, so those who have heard and receive My Word, who also heed My calling, may seek out its sound to be blessed in it, for further edification, as a continual song drawing them to its Source. Yet most refuse to hear, clasping their hands over their ears; rather embracing this world and its seductive song, which leads quickly down the wide path to destruction. For to the dull of hearing and to the wicked of heart, whose tongues testify to their own demise, whose ears are attuned to evil, their thoughts and musings contemptible, My Letters and My Word in the Scriptures of Truth have become a stern warning, an unrelenting siren blowing continually on the wall which ceases not from tormenting their corrupted souls; as fire upon their skin, as sand in their eyes, as burning wax dripping into their ears. Therefore, Timothy, those who hear Me will also hear you, and those who refuse Me will also refuse you. And those who love Me will also love you, and those who hate Me will also hate you. And those who seek out this Trumpet, loving its sound, will help you. And those who forbear will fight against you..."},{t:"italic",v:"And so I shall increase the sound of My voice seven times, even as Jericho, until all things break and all are broken; many broken unto death, ground to dust beneath The Stone which shall be placed in Zion, for The Stone shall become a great mountain filling the whole earth; while still others, My hidden treasure, My battered and bruised sheep, the wild of My flock, are broken and come to rest solidly atop this same Stone, The Rock of My Enduring Promise."}]},{type:"para",segments:[{t:"text",v:"Behold, My Word has went forth and sounds in all the earth, resounding through My body, by mouth and by trumpet. For I am The Lord, and I do not change; as I am, so shall I be and have always been; even from everlasting to everlasting, I AM. Therefore, I have spoken it and shall say it again before this perverse and wicked generation, though they can in no wise bear to hear it: I AM COME!"},{t:"fn",v:"2"},{t:"text",v:"THE TIME IS HERE! And behold I, The Lord your God, will do nothing until I have revealed My plans to My servants, the prophets."},{t:"fn",v:"3"},{t:"text",v:"And this I have done."}]},{type:"para",segments:[{t:"text",v:"Give Me glory! Kiss The Son! For darkness is overhead and great turmoil has come upon this generation, the likes of which no generation before has ever seen, the Great and Terrible Day of The Lord! Woe to the inhabitants of the earth! For The Lord your God is coming down to you in judgment and for great ruin, FOR CALAMITY! Behold, I am coming out of My sanctuary to destroy, until there is no sin left upon the earth, until all things have bowed down before Me, to give Me glory! And to those who kiss The Son, to them I shall be God, very close at hand; even they shall rest upon My bosom"},{t:"fn",v:"4"},{t:"text",v:". Yet to those who forsake Me, who do always rebel against Me and curse My name and The Messiah, to them also shall I be God, very close at hand -"},{t:"italic",v:"The God of vengeance and recompense! The God of judgment and justice!"},{t:"text",v:"Behold, I shall be The God of horror and dreadful signs to them and their idols, the destroyer of all their temples, The One who reigns in Israel who breaks apart all their false foundations, The King, The Mighty and Strong One who smashes in pieces and wipes away even all they hold sacred! IT SHALL BE BROKEN IN PIECES! Behold I, even I, shall murder every god of the pagans and of the Gentiles, for they are no gods! Even the god of the sons of Ishmael shall die in that day, for he is no god! HE LOOKS NOTHING LIKE ME!"}]},{type:"poetry",lines:[[{t:"italic",v:"Then they will know, I AM THE LORD,"}],[{t:"italic",v:"For there is no other and none like Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The One True God, THE ONLY GOD,"}],[{t:"italic",v:"Whose fury has come in His burning jealousy;"}],[{t:"italic",v:"Elohim, YAHUWAH, also being your only"}],[{t:"italic",v:"Salvation and escape; behold, all shall know"}],[{t:"italic",v:"Me and see My face, YAHUSHUA..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Bow therefore, and give glory to My name!"}],[{t:"italic",v:"For it is time! Return to Me!"}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 13:15 (KJV)"},2:{type:"note",text:'Also read: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME#I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}},3:{type:"scripture",ref:"Amos 3:7 (NLT)"},4:{type:"note",text:'Also read: "In The Bosom of The Father"',url:"https://www.thevolumesoftruth.com/In_The_Bosom_of_The_Father",link:{collection:"Volume Six",letterTitle:"In The Bosom of The Father"}}},nkjv:{"Matthew 13:15 (KJV)":"For this people\u2019s heart is waxed gross, and their ears are dull of hearing, and their eyes they have closed; lest at any time they should see with their eyes, and hear with their ears, and should understand with their heart, and should be converted, and I should heal them.","Amos 3:7 (NLT)":"Indeed, the Sovereign Lord never does anything until he reveals his plans to his servants the prophets."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-voice-of-the-almighty-god",videoVoiceUrl:"https://www.youtube.com/watch?v=K16tpN0bcPw&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=38",videoMusicUrl:"https://www.youtube.com/watch?v=6EZ_DrhadM8&list=PLSVchFJ22QYKZW4CHtZ43YBxdHUTgS9rv&index=1",relatedTopics:[{label:"Regarding the Voice of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Voice_of_The_Lord"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"The Trumpet Call of God",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth#The_Trumpet_Call_of_God"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:42,prevLetter:{id:"i-shall-bring-my-hand-against-all-nations-who-have-forsaken-me",title:"I Shall Bring My Hand Against ALL Nations Who Have Forsaken Me"},nextLetter:{id:"i-alone-sit-as-judge-says-the-lord",title:"I Alone Sit as Judge, Says The Lord"}},{id:"i-alone-sit-as-judge-says-the-lord",title:"I Alone Sit as Judge, Says The Lord",date:"4/2/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Nothing coming from the mouth of those who scoff and shoot out the lip against The Lord\u2019s anointed, whether they be a friend or an enemy, a spouse or a relative, a neighbor or a stranger, a scholar or a teacher, a pastor or a self-appointed prophet or preacher, shall be accounted as true. Neither shall any weight be given to their arguments; it is wind. Therefore, let them bring their controversies before ME, if they have no fear of God in their hearts, or let it be cast upon the dunghill. For this is the weight which their words carry in My eyes, and this is the value I have assigned to their assertions. For I am The Only Judge, says The Lord. Thus those who endeavor to sit upon My throne shall be cast down! For any who cast judgment or condemn another have no forgiveness in their heart. They have departed from love, behold, pride has become their master, as they continue to ridicule, slander, and persecute My servants with a heart full of unbridled arrogance..."},{t:"italic",v:"They shall surely be cast down! They shall be severely abased in the Day of The Lord\u2019s Anger, with their every word falling to the ground, their every arrogant assertion shattering at the feet of My messengers! Says The Lord God."}]},{type:"poetry",lines:[[{t:"italic",v:"For I alone sit as judge, and the earth, it is My footstool;"}],[{t:"italic",v:"The whole universe is subject to My every word..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I am He who causes to be,"}],[{t:"italic",v:"YAHUWAH, The Everlasting..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The One and Only True God,"}],[{t:"italic",v:"He whose will is made manifest and shall be,"}],[{t:"italic",v:"The Only Lord of Hosts."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-alone-sit-as-judge-says-the-lord-2",videoVoiceUrl:"https://www.youtube.com/watch?v=EmdrevSJB1A&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=39",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:43,prevLetter:{id:"the-voice-of-the-almighty-god",title:"The Voice of The Almighty God"},nextLetter:{id:"lost-sheep",title:"Lost Sheep"}},{id:"lost-sheep",title:"Lost Sheep",date:"4/8/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"",forLine:"For All Those Who Call of Themselves Christian",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord of Heaven and Earth:"},{t:"text",v:"I have seen and I have heard, and no more shall I allow all this iniquity to thrive before My face! No more shall I allow all these abominations to proliferate throughout the earth!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord your Redeemer, He who weeps for you; behold, with many tears I speak to you:"},{t:"text",v:"Oh My beloved lost sheep, you have wandered far from Me, you have gone astray! Why, beloved?! Why have you forsaken Me?! You were to be My treasure! Oh how I weep for you; yes, I weep for you, beloved! Turn aside and return to Me, for I call to you still! Where are you, beloved? You are lost, chasing after every unclean thing in a world which seeks only to consume you! Come home! COME HOME, MY BELOVED ONES! There is no more time to tarry! For the time has come for The Father\u2019s indignation to be poured out, and all the children of disobedience shall come to know it! Yes, all these insolent and rebellious peoples shall surely drink of it! Yet here I am, beloved! Look up, My children, and give Me glory! Repent in dust and ashes, wail and lament loudly! CRY OUT! For there is but One Salvation, only one name under Heaven by which you must be saved, One God and One Savior, only One who can fulfill your heart\u2019s innermost desire..."},{t:"italic",v:"I am He, beloved! I AM HE! YahuShua is My name!"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, come out from among them and be joined unto ME!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Be sheltered from all these troubles which are coming"}],[{t:"italic",v:"And are already here; be spared from all these things"}],[{t:"italic",v:"Which I am about to pour out upon this generation!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Now is the accepted time! Today is the day of salvation!"}],[{t:"italic",v:"Escape to The Father\u2019s house!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus have I spoken it and so shall it be,"}],[{t:"italic",v:"For I swear by Myself, says The Lord, it has begun."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/lost-sheep",videoVoiceUrl:"https://www.youtube.com/watch?v=rsi0RflcFZo&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=41",videoMusicUrl:"https://www.youtube.com/watch?v=B7bBqBCg5Ak&list=PLE8FlkxQPQkOKqEMycTZOwj2BAyqj6HwU&index=2",relatedTopics:[{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Gathering Up (Rapture)",url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:44,prevLetter:{id:"i-alone-sit-as-judge-says-the-lord",title:"I Alone Sit as Judge, Says The Lord"},nextLetter:{id:"my-word-has-gone-forth-yet-who-has-embraced-it-who-has-cupped-their-ears-to-listen-says-the-lord",title:"My Word Has Gone Forth, Yet Who Has Embraced It?... Who Has Cupped Their Ears to Listen?! Says The Lord"}},{id:"my-word-has-gone-forth-yet-who-has-embraced-it-who-has-cupped-their-ears-to-listen-says-the-lord",title:"My Word Has Gone Forth, Yet Who Has Embraced It?... Who Has Cupped Their Ears to Listen?! Says The Lord",date:"4/18/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"If you embrace the Scriptures of Truth, yet reject My Word in these Volumes, you deny the Word of The Lord. And if you embrace My Letters, yet reject the Bible, you deny the Word of The Lord. For I am The Author and Finisher thereof. Is this not how it has always been, even toward every prophet which was sent, even to YahuShua, whom you call Jesus, who was and is and shall always be The Prophet and Deliverer, The Mashiach? For the people to whom the prophets were sent did indeed have a form of godliness, yet denied the power thereof, saying within themselves, even one to the other,"},{t:"italic",v:"\u201CWe believe the Torah, yet we will reject these sent to us. Yes, we shall stone them in word and by deed, and cast all their cords from us,\u201D"},{t:"text",v:"though it was I Myself who had sent to them the prophets, even The Messiah who is called Christ."}]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, there is nothing new under the sun..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as My people refused Me in all times past,"}],[{t:"italic",v:"With a stiff arm and an outstretched neck,"}],[{t:"italic",v:"With their foreheads hardened and their"}],[{t:"italic",v:"Hearts calloused, so it is even to this day..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For those who dwell in the churches of men"}],[{t:"italic",v:"Are rebellious, and the devout of Israel remain"}],[{t:"italic",v:"Blind, an insolent and deceived people, a most"}],[{t:"italic",v:"Stubborn and high-minded generation!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Houses full of blind guides who speak to the deaf,"}],[{t:"italic",v:"Endeavoring to teach the dumb the songs of men..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/my-word-has-gone-forth-yet-who-has-embraced-it-who-has-cupped-their-ears-to-listen-says-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=vV8_5d7af7c&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=42",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:45,prevLetter:{id:"lost-sheep",title:"Lost Sheep"},nextLetter:{id:"thus-declares-the-lord-against-the-nation-once-called-of-itself-under-god",title:"Thus Declares The Lord Against the Nation Once Called of Itself \u201CUnder God\u201D"}},{id:"thus-declares-the-lord-against-the-nation-once-called-of-itself-under-god",title:"Thus Declares The Lord Against the Nation Once Called of Itself \u201CUnder God\u201D",date:"4/19/10",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My sons, have you seen all these abominations wrought in your land?! Have you seen how they pollute My name, day and night without ceasing, how they parade their adulteries continually before My face?! Behold, the sins of this people are very great, sins of every kind, iniquity beyond measure! Therefore prophesy, lift up your voices and prophesy against this nation, and say to this wicked people..."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I AM AGAINST YOU! Behold, I have set My face against you for harm and not for good! For you have become a nation of harlots, a perverse and lawless people who uphold abomination and cast righteousness to the ground! Thus the Day has come, and ALL shall enter in! And upon this nation, once called of itself \u201CUnder God,\u201D shall come ruin, even calamity upon calamity, disasters of every kind! Behold, I am calling the earth to rise up and fight against you, O proud and arrogant people! For you are a very adulterous people, a wayward generation who have removed themselves far from Me, a people who walk in the ways of the pagan and delight in the ways of the heathen, a whole nation which lifts up its heel against Me! -"},{t:"italic",v:"A nation which murders the innocent! A nation which casts the widow and the elderly aside in their affliction, and forgets the needs of the fatherless! A nation which does not uphold the cause of the poor and the needy! A nation which oppresses the alien and does not aid the stranger in their time of need! A hard-hearted generation, a very rebellious people, who reject both Me and My Word!"},{t:"text",v:"Therefore you shall become the afflicted, and I shall leave you fatherless in your time of need! Behold, I have turned to you the back; from you I am far removed! Says The Lord. Yes, I shall surely leave you poor and naked, oppressed, with no one to uphold you or listen to your cause, lost, a stranger wandering in desolate lands. For My anger is kindled against you! Behold, the heat of My indignation has come up into My face, and shall burn as a raging fire in the day I repay you for all your evil deeds! Declares The Lord. For I have seen your wickedness, and I have looked upon the deceit of your heart, O fallen nation! Therefore I am coming down to break this people, to severely humble this great nation! For the wicked have become a sore, an awful sickness spreading forth across the land, a disease which I shall command the earth to cleanse, until all this wickedness is consumed! Says The Lord God."}]},{type:"para",segments:[{t:"text",v:"Yet I shall not make a total end. For I shall clothe all who come to Me in sincere repentance with fine robes; I shall feed the poor in spirit, wipe the tears of the remorseful, and uphold the broken; I shall shelter the penitent and give grace to the humble, and the pure in heart shall behold My face. Indeed, all who wash My feet with their tears shall be comforted for one week in the house of The Lord, says The Holy One of Israel."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/thus-declares-the-lord-against-the-nation-once-called-of-itself-under-god",videoVoiceUrl:"https://www.youtube.com/watch?v=A7DCLWYWCrk&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=43",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"}],num:46,prevLetter:{id:"my-word-has-gone-forth-yet-who-has-embraced-it-who-has-cupped-their-ears-to-listen-says-the-lord",title:"My Word Has Gone Forth, Yet Who Has Embraced It?... Who Has Cupped Their Ears to Listen?! Says The Lord"},nextLetter:{id:"the-one-who-stays-lets",title:"The One Who Stays, Lets"}},{id:"the-one-who-stays-lets",title:"The One Who Stays, Lets",date:"4/26/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, I am come to take My own, to plunge this world into darkness. Even with a heavy heart, it must be. For My heart is torn, My wounds remain, and My heart bleeds still. Yet the people of this world refuse to drink from My cup, nor will they accept that which I have poured out for them. Behold, even those who say they know Me do not really know Me, nor do they follow Me; indeed, they refuse to accept Me as I truly am. Thus I have given them many days to repent, many days to turn aside and return to Me. Yet they will not come, nor will they heed the call."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore I declare it to you plainly,"}],[{t:"italic",v:"O peoples of the earth,"}],[{t:"italic",v:"Yes, even to you, O churches of men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I shall draw back My hand,"}],[{t:"italic",v:"And My spirit, of which I have poured"}],[{t:"italic",v:"Out on all flesh, shall return to Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, The One who stays..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Lets."},{t:"fn",v:"1"}]]}],footnotes:{1:{type:"scripture",ref:"2 Thessalonians 2:6-7 (KJV)"}},nkjv:{"2 Thessalonians 2:6-7 (KJV)":"6. And now ye know what withholdeth that he might be revealed in his time. 7. For the mystery of iniquity doth already work: only he who now letteth will let, until he be taken out of the way."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-one-who-stays-lets-4",videoVoiceUrl:"https://www.youtube.com/watch?v=uKj81MS5Fmc&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=44",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The One Who Stays, Lets",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets"}],num:47,prevLetter:{id:"thus-declares-the-lord-against-the-nation-once-called-of-itself-under-god",title:"Thus Declares The Lord Against the Nation Once Called of Itself \u201CUnder God\u201D"},nextLetter:{id:"blow-the-trumpet-sound-the-alarm",title:"Blow the Trumpet, Sound the Alarm"}},{id:"blow-the-trumpet-sound-the-alarm",title:"Blow the Trumpet, Sound the Alarm",date:"4/28/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Watchmen, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to those who are faithful and hold fast to the line..."},{t:"italic",v:"To those whose hearts remain close to The Holy Covenant, whose minds are set upon The Goal; those whose thoughts grab hold of the vision with countenances unchanged, adamant stones who can not be moved from My purpose, rocks of offense set in the midst of this most rebellious generation; servants who remain in My love,"},{t:"fn",v:"1"},{t:"italic",v:"who long for justice to run down like water and for righteousness to flow like a mighty stream,"},{t:"fn",v:"2"},{t:"italic",v:"for the zeal of The Lord of Hosts dwells within them..."}]},{type:"para",segments:[{t:"text",v:"My sons, in the midst of you I have placed a measuring line. Even amidst many stones of stumbling have I stretched it out, that you may follow it, that you may go straight forward. And though you yet stumble, I have indeed stretched it out before you, lest you should fall and be unable to rise up again. For the weight of this revelation is indeed very heavy and shall be met with much resistance. Persecution and slander shall come forth to bar your way, many voices condemning you for your actions, many accusations brought forth falsely on account of My words. Lo, it has come forth already, and shall continue and increase by measure. Yet do not be at all dismayed by this people, nor be taken aback by their words; do not listen to their slander. And when they draw close to abuse you in word or by deed, do not turn and run. For I shall be with you and dwell in you like a flame of fire. Behold, I shall make you as a fortified city, with high and thick walls, built with strong and tempered mortar, which no man can scale nor shall the enemy break through. For no weapon forged against Me shall by any means prosper. I AM THE LORD. Therefore, My sons, hear the Word of My mouth and so do; heed all My commands and do not hesitate when the decree is sent down. Go forth in My name and do not relent, nor be turned aside, for the mouth of The Living God has spoken! Trumpet My fierce rebuke and make My indignation known, without ceasing!"}]},{type:"poetry",lines:[[{t:"italic",v:"Share My words and declare My wrath"}],[{t:"italic",v:"In every corner of your reach, by all manner"}],[{t:"italic",v:"Of speaking and devices!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Speak My words aloud, and blow the Trumpet"}],[{t:"italic",v:"Against this nation and against the churches of men!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yea, sound to the four corners,"}],[{t:"italic",v:"Blow the Trumpet in all the earth!..."}]]},{type:"closing",text:"Says The Lord God."},{type:"para",segments:[{t:"text",v:"My watchmen, pick up the Trumpet and turn toward the churches of men and declare the Word of My mouth, that the sound of My voice may humble them. Yet if they will by no means be humbled upon hearing the Word of The Lord, behold, on a day they do not know and at an hour they do not expect, I will come forth from My place and strip them naked and pour out all their riches upon the ground. Lo, I will sift them and bring forth a remnant, even from the midst of them, and they shall be left all alone in bewilderment and tears. Therefore, again I say to you, blow the Trumpet, My sons. For the time of The Lord\u2019s Rebuke has come and the warning must be given. Go, hesitate not! Go forth and make enemies of all peoples and nations! Cause a great division,"},{t:"fn",v:"3"},{t:"text",v:"even within the churches of men! For I have not come forth to give them peace, that they may sit at ease in all their fornications, or to sit idly by as iniquity overtakes them; no, I have not come forth to make peace, but war, a great division!"}]},{type:"poetry",lines:[[{t:"italic",v:"For this is the sword I bring,"},{t:"fn",v:"4"}],[{t:"italic",v:"Even to the slaying of every heart,"}],[{t:"italic",v:"To the breaking up of every false foundation..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I am come forth to divide asunder,"}],[{t:"italic",v:"To cut in pieces, until all this enmity is torn down..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 15:10 (CEB)"},2:{type:"scripture",ref:"Amos 5:24 (NKJV)"},3:{type:"scripture",ref:"Luke 12:51"},4:{type:"scripture",ref:"Matthew 10:34"}},nkjv:{"John 15:10 (CEB)":"If you keep my commandments, you will remain in my love, just as I kept my Father\u2019s commandments and remain in his love.","Amos 5:24 (NKJV)":"But let justice run down like water, And righteousness like a mighty stream.","Luke 12:51":"Do you suppose that I came to give peace on earth? I tell you, not at all, but rather division.","Matthew 10:34":"\u201CDo not think that I came to bring peace on earth. I did not come to bring peace but a sword."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/blow-the-trumpet-sound-the-alarm",videoVoiceUrl:"https://www.youtube.com/watch?v=i4g1ljQUt7A&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=45",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"About The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:48,prevLetter:{id:"the-one-who-stays-lets",title:"The One Who Stays, Lets"},nextLetter:{id:"the-holy-one-of-israel-is-coming-down",title:"The Holy One of Israel Is Coming Down"}},{id:"the-holy-one-of-israel-is-coming-down",title:"The Holy One of Israel Is Coming Down",date:"4/28/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Hear the Word of The Lord, all you arrogant churches of men; hear the Word of My mouth, O awful generation, for thus declares The Lord:"},{t:"text",v:"This is My Word, and behold, I have surely set before you My prophets. They hear My voice, and My spirit increases rapidly within them; My voice grows ever louder. Behold, My presence shall be with them as a mighty terrible one"},{t:"fn",v:"1"},{t:"text",v:"in the day I send them, My spirit fully established in them like a fire which can not be quenched..."},{t:"italic",v:"Woe, therefore, to ALL who come against them, says The Lord, for I am coming down!"},{t:"text",v:"Peoples of the earth, I am coming down to you, with My left arm outstretched to judge and to punish, and with My right arm bent to save and deliver! It is time! The day is far spent, the hour is coming to a close! Behold, the whole earth shall be shaken by My presence! Every man shall tremble in his place, with his heart thundering in his chest, because of the fury of The Lord which has come forth to punish the nations, because of the judgments of The Most High raining down from Heaven! Look now and see, open your ears and hear, for though you are yet dull of hearing, the vision shall surely speak. And though your eyes remain covered with purple and scarlet, it shall be made clear. And though it seems to tarry, due to the darkness of your understanding, it will not tarry, it shall surely come..."},{t:"italic",v:"Behold, I am coming quickly! Yes, behold the Day, O foolish generation, and look! The Day of The Lord is here! Behold, it is at the door and is about to come in! Therefore repent, and call upon The Name!"}]},{type:"poetry",lines:[[{t:"italic",v:"Peoples of the earth, cry out, and call upon the name of Mercy!"}],[{t:"italic",v:"Call upon the only name under Heaven by which you must be saved;"}],[{t:"italic",v:"My children, call out His name if you know it!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Call upon the name of pure righteousness, of majesty and saving grace;"}],[{t:"italic",v:"Yes, cry out to Him, saying, \u201CGrace! Grace!\u201D..."}]]},{type:"poetry",lines:[[{t:"italic",v:"My people, speak His name aloud in repentance,"}],[{t:"italic",v:"Offer up your tears, confess your sin!"}],[{t:"italic",v:"Do it quickly, before the door is shut!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Jeremiah 20:11 (KJV)"}},nkjv:{"Jeremiah 20:11 (KJV)":`But the LORD
is with me as a mighty terrible one: therefore my persecutors shall stumble, and they shall not prevail: they shall be greatly ashamed; for they shall not prosper:
their everlasting confusion shall never be forgotten.`},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-holy-one-of-israel-is-coming-down",videoVoiceUrl:"https://www.youtube.com/watch?v=A7DPLvy4H8Q&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=46",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:'The Coming of The Lord - "I Am Coming Quickly"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_Am_Coming_Quickly"}],num:49,prevLetter:{id:"blow-the-trumpet-sound-the-alarm",title:"Blow the Trumpet, Sound the Alarm"},nextLetter:{id:"the-lord-gives-behold-the-lord-also-takes-away",title:"The Lord Gives; Behold, The Lord Also Takes Away"}},{id:"the-lord-gives-behold-the-lord-also-takes-away",title:"The Lord Gives; Behold, The Lord Also Takes Away",date:"5/14/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have spoken to you many times, O peoples of the earth. Behold, I have sent out My messengers before My face, rising up early and sending them. They have gone out in the name of The Holy One of Israel, your Redeemer, trumpeting My Word by all manner of speaking and devices. For I do not change, says The Lord."}]},{type:"para",segments:[{t:"text",v:"Yet you, O vile generation, have turned to Me the back, hiding your faces, refusing to be healed! For in secret you commit adultery against The Lord, and in open you practice abomination, that you might arouse Me to anger! Indeed you profane My name, and do not cease from polluting it, a most rebellious people who tread upon My Commandments and will not be turned aside from iniquity! Behold, righteousness has fled away and holiness is forgotten, as My own people desecrate My Word for evil gain, unruly children who forsake My Law in My own name, multitudes of ill-favored sheep!..."},{t:"italic",v:"Therefore, behold the generation of My wrath, a people not desired, a whole generation of evil workers who destroy the garden and leave the land desolate! Their appetites are insatiable, their lusts unabated, a people without conscience, consumed by greed!"},{t:"text",v:"PEOPLES OF THE EARTH, YOU ARE NO CARETAKERS! Says The Lord. Behold, the husbandmen have all gone astray, every servant to his own way! The caretakers sleep in the dust, only dry roots remain! Therefore, I shall lay every vineyard waste and render every pleasant field useless! For there are none who cleave to Me, not one who truly knows Me, no one holds a listening ear. For who has longed to know My way, that they might walk in it? Who cries out in sincerity, saying,"},{t:"italic",v:"\u201CHere I am, send me\u201D?"},{t:"text",v:"Why do My people rend their clothes while their hearts remain hard and unyielding, growing cold? My people, rend your hearts and not your garments, bare yourselves before Me and be broken! For I tell you the truth, you are fallen! From a great height you have been cast down; My spirit is far removed! And still you stand proud, saying,"},{t:"italic",v:"\u201CAre we not wise in our own eyes and highly exalted? Do we not stand firm upon our own false foundations, for the sake of pride and vanity? Are we not a lavishly-adorned bride, who wears the poor for ornaments and the destitute for clothes?\u201D"},{t:"text",v:"Therefore, because you are haughty and your works pretentious, walking always in covetousness as a pair of shoes, I tell you plainly, you are not My bride! For none seek My righteousness as it truly is, none prepare My way before Me! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"Behold, the peoples of the earth have become as a swarm of devouring locusts which consume every green thing, a forest of fallen trees broken and dying, a desolate valley where the rains have ceased and the grass is tread down! Yet there is no seed left in you! How then shall you arise?! Peoples of the earth, you have destroyed yourselves, you have taken your own lives! Even now you are gasping for breath, your strength all but gone from you as your life flees away! Behold, death is at the door and is about to come in! Says The Lord. Behold, by the works of your own hands, O foolish generation, are you held captive, prisoners of sin, workers of great iniquity who embrace every perverse way!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold the final generation, the last of the kingdoms of men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A most arrogant and wicked generation!"}],[{t:"italic",v:"A people who exalt themselves above their Creator"}],[{t:"italic",v:"And cast off My gifts, destroying that which I created for them!"}],[{t:"italic",v:"AN ABOMINABLE PEOPLE WHO DESTROY"}],[{t:"italic",v:"LIFE WHILE STILL IN THE WOMB!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"This is MY earth, of which you have polluted,"}],[{t:"italic",v:"MY precious lambs, which you have slaughtered!"}]]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, because you have made yourselves enemies of God, and speak as though you were God, THUS SAYS THE LORD:"},{t:"text",v:"I am come to cut down the generation of My wrath, to strike the nations in My hot displeasure! Behold, I shall cause nature to rise up and fight against you, and the earth shall become your enemy, from which there shall be no defense nor hiding place! Behold, perplexity and great fear shall overtake you, and you shall be unable to move, astonished at those things coming to pass upon the earth and in the heavens! For My anger is kindled against you and shall come forth like fire! For The Lord God of Hosts has purposed destruction upon the earth and upon all the cities of men! Behold, wrath overflows My cup and shall proceed like a flood, and you shall all bow down to the slaughter! From the beginning My plans were written and made known. Yet when I called to you, you would not answer! And when I spoke to you, you refused to hear, but continued to do evil in My sight, choosing always those things I hate, casting your lot with the deceiver, holding your heads high as you joined the ranks of the rebellious! EVIL WORKERS! REPROBATE CHILDREN!..."},{t:"italic",v:"Therefore, woe to the peoples of the earth! For The Almighty is coming down to you in the fierceness of His wrath! In haste He shall deliver His people, and with great anger He shall pour out judgment upon the inhabitants of the earth!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, all you sons of perdition, kings, rulers and leaders among men:"},{t:"text",v:"LET MY PEOPLE GO! For this is MY field and this is MY harvest, MY earth and MY people! For I shall command the earth, and My people shall be brought forth; even Sheol shall give up the dead! Behold, the command shall go forth and the trumpet shall sound, and it shall be done! Lo, it shall surely be accomplished, even in the sight of all nations! Says The Lord. Behold, night has fallen and great wrath is about to ensue, yet even you, O churches of men, have failed to hear, neither will you listen; nor will you give heed to these words which I have spoken in all these Letters, nor have you considered the number of these Volumes which I have set before you."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to the churches of men:"},{t:"text",v:"The day is indeed coming, of which you are unaware, and the hour for which you are unprepared approaches quickly. For you are no watchmen. For I shall surely leave you desolate, in darkness and bitter weeping; I shall devastate all your lavish houses, until every harlot is made to sit upon the ground."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore I tell you plainly, night has indeed fallen"}],[{t:"italic",v:"And thick darkness is about to come in..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Wherein the lukewarm shall be spit out and the"}],[{t:"italic",v:"Blind shall be left to walk through dry places,"}],[{t:"italic",v:"The deaf will be made to dwell in darkness"}],[{t:"italic",v:"And the forgetful hearer shall be confounded,"}],[{t:"italic",v:"And the widow"},{t:"fn",v:"1"},{t:"fn",v:"2"},{t:"italic",v:"shall wail upon her bed..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I shall surely leave you desolate..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "Women in Mourning"',url:"https://www.thevolumesoftruth.com/Women_in_Mourning#Women_in_Mourning",link:{collection:"Volume Five",letterTitle:"Women in Mourning"}},2:{type:"note",text:'See: "The Fatherless Widow"',url:"https://www.thevolumesoftruth.com/The_Fatherless_Widow#:~:text=Thus%20those%20who,of%20The%20Lord!",link:{collection:"Volume Seven",letterTitle:"The Fatherless Widow",excerpt:"Thus those who were to be the bride shall become the widow"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-lord-gives-behold-the-lord-also-takes-away-3",videoVoiceUrl:"https://www.youtube.com/watch?v=1azWV6HFzfs&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=49",videoMusicUrl:"https://www.youtube.com/watch?v=509JF_t-jXE",relatedTopics:[{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Pollution and Mankind's Exploitation of the Earth",url:"https://answersonlygodcangive.com/Regarding_Pollution_and_Mankind%27s_Exploitation_of_the_Earth"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"God Speaks Regarding Covetousness",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Covetousness"},{label:"The True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#Section_2_-_The_True_Bride"},{label:"The One Who Stays, Lets",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"}],num:50,prevLetter:{id:"the-holy-one-of-israel-is-coming-down",title:"The Holy One of Israel Is Coming Down"},nextLetter:{id:"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly",title:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"}},{id:"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly",title:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly",date:"5/19/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a sister in Christ: Lord, is this really the last Pentecost?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Beloved, I have poured out My spirit on all flesh, even as I was poured out for you from the beginning. Yet no one comes to drink, not one is willing to receive of Me as I truly am. I have brought forth the rains in their due season, both the former and the latter, and still the crop wanes and bears only bitter fruit. Behold, the voice of The Lord your God has spoken, yet few have ears to hear, few are willing to open their heart and truly listen. I tell you the truth, before Me stands a very proud people, multitudes of foolish children who can not discern their right hand from their left. Their knowledge is corrupt; all their thoughts and musings only serve to uphold their vile nature. For they do not retain God in their thoughts, and from The Holy they are far removed."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"The churches of men are perverse, their ways corrupt, a wholly ignorant and vain people, multitudes of deceived children, a people who were to prepare My way before Me! Yet they have chosen another way, twisting and segregating the Scriptures, both adding to and taking away, that they may continue to uphold their own corrupt doctrines and filthy traditions, which I hate! Therefore, woe to those who dwell in the churches of men! Woe to all who walk in their ways! HYPOCRITES! And of the hypocrite\u2019s portion they shall surely receive, unless they repent and return to Me wholly and in truth! Says The Lord. For I tell you the truth, behold, I declare it to you plainly, if I were to come down and speak in the former manner, every one of these churches of men would bar My way before Me; even every one of them would cast Me out and seek to have Me arrested! Yet I have indeed passed through the midst of them, and though they have not seen Me, as I live, says The Lord, they have surely rejected Me!"}]},{type:"poetry",lines:[[{t:"italic",v:"I have poured out My spirit, yet they refuse to drink!"}],[{t:"italic",v:"I have spoken to them, yet they shut their ears to My voice!"}],[{t:"italic",v:"I have sent My messengers to them, yet they cast them out"}],[{t:"italic",v:"With great anger and violence, persecuting and slandering them!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, even the least of these, My servants, have been"}],[{t:"italic",v:"Mistreated by these so-called people of faith!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THEY HAVE SURELY HATED ME!"}]]},{type:"para",segments:[{t:"text",v:"It is written:"},{t:"italic",v:"The heart of this people has waxed gross, their ears are very dull of hearing and their eyes they have shut, lest at any time they should see with their eyes and hear with their ears and understand with their heart, and be fully converted, and I should heal them."},{t:"fn",v:"1"},{t:"text",v:"Yet they have not returned to Me, nor will they repent. How then shall I heal them? For only those who know they are sick seek out The Physician. Yet those who perceive themselves as well will in no wise come to Me. Indeed they remain seated firmly in the darkness of their own understanding, resting upon their laurels by which they highly esteem themselves, as they for a pretense worship another messiah. For one who peers through stained glass can not behold his own image, nor is he able to see those inside clearly. For he sees only an outline, a blur of color obscuring his vision. And those on the inside who peer outward remain blinded, able to perceive only a shadow of what truly is, holding up the hand against the brightness, for fear of the noonday sun which is about to come in."},{t:"fn",v:"2"},{t:"text",v:" Thus they prefer the light filtered and the brilliance masked, by means of all this painted glass. What then shall a people such as this do when night has fallen? Thus the churches of men do always take the name of The Lord in vain, by all they say and do. From the least even unto the greatest, they pollute My name, even to the continual blaspheming of the Spirit. Therefore I shall indeed remove My hand, and My spirit shall return to Me. Behold, from every individual who refuses to give heed to My voice and embrace My correction has it departed already. Yet let all those who remain in My love understand and have peace. For though My spirit departs from the multitudes and the ensuing darkness be thick, though wickedness overflows and every man of pride who being wise in his own eyes is left confounded, I shall not make a total end. For My hand shall remain with the faithful, and My strength shall be revealed in My anointed. Behold, My spirit shall well up within the hearts of the penitent and come upon My chosen as a welcomed rain, and they shall be greatly increased, shining ever brighter, even amidst thick clouds and darkness."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold The Lord\u2019s purpose, for it shall surely"}],[{t:"italic",v:"Be accomplished, it shall surely be done:"}]]},{type:"poetry",lines:[[{t:"italic",v:"From My left hand, judgment shall be poured out"}],[{t:"italic",v:"Upon the desolate, the high-minded and the hypocrite..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet under the shadow of My right hand,"}],[{t:"italic",v:"The humble shall be hidden..."}]]},{type:"closing",text:"For I am The Lord, and I do not change."}],footnotes:{1:{type:"scripture",ref:"Matthew 13:15 (KJV)"},2:{type:"note",text:'See: "THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL"',url:"https://www.thevolumesoftruth.com/THE_CUP_OF_THE_WRATH_OF_MY_FURY_IS_COME_TO_THE_FULL",link:{collection:"A Testament Against The World: The Lord's Rebuke",letterTitle:"THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL"}}},nkjv:{"Matthew 13:15 (KJV)":`For this people\u2019s heart is waxed gross, and
their ears are dull of hearing, and their eyes they have closed; lest at any time they should see with
their eyes, and hear with
their ears, and should understand with
their
 heart, and should be converted, and I should heal them.`},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly",videoVoiceUrl:"https://www.youtube.com/watch?v=PUowi1iW1iA&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=49",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"*Even More Related Topics",url:"https://answersonlygodcangive.com/index.php?search=%225%2F19%2F10%22&title=Special%3ASearch&go=Go"}],num:51,prevLetter:{id:"the-lord-gives-behold-the-lord-also-takes-away",title:"The Lord Gives; Behold, The Lord Also Takes Away"},nextLetter:{id:"the-sword-comes",title:"The Sword Comes"}},{id:"the-sword-comes",title:"The Sword Comes",date:"5/23/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, The Lord has purposed, and that which I have purposed to do is established; the first of many called, their number accomplished, it is done. Thus there shall now be a great emptiness across the land. And among the churches, a void, a dullness of understanding, a great emptiness, with the way ahead unsure for those who have not known Me. For they have refused to accept Me as I truly am. Yet those who come out from among them shall have their eyes opened and their understanding brightened. For their hearts have longed for Me, their hearts I have known. Therefore, My servants, blow the Trumpet against your nation and the rulers of this world, sound the alarm and warn the people, for My hand is removed. Behold, that which restrains is taken out of the way, and He who withholds lets. Again, I say to you, warn them from Me! For the sword shall soon come upon your nation, even upon the whole of this world, to the distress of all nations! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I am come out of My sanctuary, and the arm of The Lord shall be revealed! The anger of The Lord shall be made fully known, and great and mighty nations shall be brought down! And woe to those who come against My people, Jacob! Woe to all who come out to destroy Israel! You shall come to know the power of The Lord in His anger! In the strength of My hot displeasure shall you be brought down! Behold, you shall lick the dust, all your mighty men of battle strewn about, all your devices coming to rest in ruinous heaps, littering the open fields! For The Lord has spoken, and so shall it be and come to pass in the sight of all nations!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, all you multitudes, listen and heed this warning, all you deceitful peoples of the earth:"},{t:"text",v:"Your labor pains shall be dire, and shall increase quickly; much wailing shall be heard! Behold, the birth shall be accomplished through much suffering, with no respite, lasting seven days."}]},{type:"poetry",lines:[[{t:"italic",v:"Yet it shall come to pass, that whosoever calls upon the name"}],[{t:"italic",v:"Of The Lord in that day and at that time shall be saved, as it is written"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the first harvest shall indeed be lowly, of the lowly and of the innocent;"}],[{t:"italic",v:"And the second plenteous, of the refined and penitent..."}]]},{type:"closing",text:"Says The Lord God, Creator of Heaven and Earth; The Lord of Hosts is My name."}],footnotes:{1:{type:"scripture",ref:"Joel 2:32"}},nkjv:{"Joel 2:32":"And it shall come to pass That whoever calls on the name of the LORD Shall be saved. For in Mount Zion and in Jerusalem there shall be deliverance, As the LORD has said, Among the remnant whom the LORD calls."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-sword-comes",videoVoiceUrl:"https://www.youtube.com/watch?v=YWI_rcN-AL8&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=49",videoMusicUrl:"https://www.youtube.com/watch?v=SdC4i8aNE4Q&list=PLSVchFJ22QYKZW4CHtZ43YBxdHUTgS9rv&index=3",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"}],num:52,prevLetter:{id:"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly",title:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"},nextLetter:{id:"a-day-of-slaughter",title:"A Day of Slaughter"}},{id:"a-day-of-slaughter",title:"A Day of Slaughter",date:"5/31/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel:"},{t:"text",v:"I have seen the pride of men, and how hate builds within their hearts. For My hand is removed. And who is able to withhold them? Who is able to turn them back, once their minds are set? Behold, they shall come as a whirlwind, as a flood to cover the land; with a sound like raging waters shall they come forth from their places. And the earth shall tremble, the ground shall shake beneath the multitude of their devices. Their intentions are not hidden, and that which they do in secret is always before My face. For that which is conceived of in the hearts of men is known to Me; indeed, everything whispered in secret enters into My ears. Behold, an evil plan has come into their hearts. For they plot an evil thing, saying,"},{t:"italic",v:"\u201CThe God of Israel sleeps, and will not arise to defend His people; The Holy One of Israel will not see it. Therefore let us go up and fight against the people of Jacob, and murder the inhabitants of Judah, and wipe Israel from all remembrance; let their name die with them! Yes, let us go swiftly and many peoples with us, to destroy them, that we may cast their name out of the earth forever!\u201D"},{t:"text",v:"THEREFORE COME! SAYS THE LORD; COME FORTH! For by the blood of your fathers and by the blood of your sons, and by the blood of all your great and proud men, shall I be glorified in the sight of many nations! Behold, you shall fall upon the mountains of Israel, a feast for the birds, a dwelling place of the worm, and in the open fields shall you leave your spoil! For I have prepared a valley, your resting place! THEREFORE COME FORTH, ALL YOU LOATHFUL NATIONS! Bring your multitudes with you, all your mighty men of battle! Come up for the Day of Slaughter! Says The Lord God Almighty. For My anger has come up into My face and My hand is raised for battle! I am poised in My strength, ready to strike you down with a great vengeance! THEREFORE COME, O MIGHTY MEN! Come down from the north as the whirlwind and fight against Me, says The Lord, and bring the fullness of Ishmael with you! GATHER TOGETHER AND COME! Bring forth the weapons from the storehouses, from Asia to the kings of the south! COME FORTH! For The Lord God of Israel has prepared a great slaughter!"}]},{type:"poetry",lines:[[{t:"italic",v:"ENEMIES OF ISRAEL,"}],[{t:"italic",v:"I CALL YOU OUT! COME FORTH!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For indeed, the world has turned a deaf ear and many"}],[{t:"italic",v:"Nations are in agreement, and not one will prevent you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THEREFORE, COME FORTH!"}],[{t:"italic",v:"COME OUT AND FIGHT AGAINST ME!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"IT IS TIME!"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-day-of-slaughter-3",videoVoiceUrl:"https://www.youtube.com/watch?v=DokYDr_56tE&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=50",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Woe to Those Who Come Against Israel",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_Israel"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:53,prevLetter:{id:"the-sword-comes",title:"The Sword Comes"},nextLetter:{id:"i-will-defend-my-people-israel",title:"I Will Defend My People, Israel"}},{id:"i-will-defend-my-people-israel",title:"I Will Defend My People, Israel",date:"5/31/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"I will defend My people, Israel, and take vengeance upon My enemies. For My own name\u2019s sake will I do it, and for the sake of My servant, David, shall it be done. And thereafter shall My witnesses be sent into battle. For I have only just begun to speak, I have only just begun to reveal My hot displeasure, to put My power on open display, says The Lord of Hosts. Yet if it were not for the sake of a remnant among those yet to be called, and for the sake of My name in Israel, that it may be glorified, I would have destroyed the enemies of Israel already, wiping them from the face of the earth. Thus I have withheld My hand, and have not yet taken vengeance upon My enemies; yet I shall not withhold My hand forever, neither shall My wrath tarry. Behold, I shall lift up an ensign to all nations! It shall be forged with fire and painted with the blood of mighty men, and many ten thousands shall fall in one day! For I shall come out mightily against them, very dreadful in battle, and with terrible destruction I shall strike all who come out to fight against Me, and all in the earth shall tremble! Then they will know, I AM THE LORD, when I have magnified Myself in the land of Israel!"}]},{type:"para",segments:[{t:"italic",v:"For I was there when My people were slaughtered, I was with each one as they breathed their last. I was with them in their torment, I shared in their agony, I endured their pain and their anguish I knew... We did weep together! Indeed, I had handed them over and scattered them amongst the nations, and this at their own request. For their forefathers had sworn it,"},{t:"fn",v:"1"},{t:"italic",v:"and throughout their generations they have upheld it. Therefore was My anger kindled against them; thus did I drive them out and scatter them amongst the nations... Bitter enmity, great sadness. Yet I did not hold onto My anger forever, and My love never departed; neither did I forsake them in their trials. Behold, I was there at the end of their tribulations, for they did behold My face as they fell asleep... And now the time has come, the time of vengeance is very near, I shall surely repay! Says YAHUWAH, The One and Only True God, The God of Israel."}]}],footnotes:{1:{type:"scripture",ref:"Matthew 27:25"}},nkjv:{"Matthew 27:25":"And all the people answered and said, \u201CHis blood be on us and on our children.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-will-defend-my-people-israel",videoVoiceUrl:"https://www.youtube.com/watch?v=wyj3QjjbmBE&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=51",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:54,prevLetter:{id:"a-day-of-slaughter",title:"A Day of Slaughter"},nextLetter:{id:"vengeance-is-mine-i-shall-repay",title:"Vengeance Is Mine, I Shall Repay"}},{id:"vengeance-is-mine-i-shall-repay",title:"Vengeance Is Mine, I Shall Repay",date:"6/7/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My sons and daughters, do you believe I AM WHO I AM? Do you know I am with you? Hold fast therefore, for The Lord of Heaven and Earth is about to do an awesome and terrible thing, a wonder, an astonishment! Behold, the peoples of the earth shall be made to shudder, their hearts shall fail them for fear, their minds shall be cast into confusion over those things coming to pass before their eyes! For the terror of The Lord shall overtake them, and ALL shall fear!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, O peoples of the earth:"},{t:"text",v:"I AM COMING DOWN! And as a darkening sky brings foreboding, and roiling clouds bring forth lightning and thunder shakes the earth, so also shall it be in the Day of The Lord!"}]},{type:"poetry",lines:[[{t:"italic",v:"As the mighty whirlwind drops down"}],[{t:"italic",v:"Suddenly out of the midst of the storm,"}],[{t:"italic",v:"Bringing great destruction upon all in its path,"}],[{t:"italic",v:"So also shall it be in the Day of The Lord\u2019s Anger!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"SWIFT DESTRUCTION FROM ON HIGH"}],[{t:"italic",v:"UPON ALL MY ENEMIES!..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Mighty One of Jacob:"},{t:"text",v:"Behold, I shall make My presence felt in the land of Israel! The heavens shall shake, and a great trembling shall come up from beneath! The sun shall be darkened, and fire shall fall from heaven upon My enemies, and with great hailstones shall I strike them in My anger! In My fury I shall cast them down and tear all their companies in pieces! - Heaps of wreckage! Multitudes of broken bodies littering the open fields! I shall put a halt to all their weapons of war! Behold, I shall bring upon them a flooding rain, a great deluge, and they shall sink deep into the mire, unable to gain any ground or foothold! Their armies shall be driven backward, bold soldiers shall cower in fear and mighty men shall flee, before the might of The Holy One of Israel! And that over which men were given dominion shall rise up and have dominion over them! Says The Lord God. Behold, every mighty man and proud soldier who sets foot in the land of Israel, to kill and to take spoil, shall be overcome with madness! - Brother against brother, nation against nation, every man striking his neighbor on the chest! Behold, I shall splatter the mountains of Israel, and the hills shall drip down with blood! I shall litter the open fields with your dead bodies, and the stink of your rotting corpses shall fill the air and inundate the valleys, the smoke of your burning ascending high into the heavens as a testament against you, O enemies of Israel! For all your plans are uncovered, your loathsome hearts are laid bare and shall fail you for fear! For I shall cause your hate to eat your flesh like fire, as you watch all your plans return atop your own heads! And that by which you came to spoil shall become the spoil, and with the destruction you conceived so shall you be destroyed! And behold, YOU shall become a most loathsome sight in the eyes of all nations, an astonishment and a terror to all who look upon you! For as it is written:"},{t:"italic",v:"I will bring judgment upon My enemies with pestilence and bloodshed; I will magnify Myself in the land of Israel and show My greatness; My holiness shall be revealed and My presence made known, in the sight of all nations!"},{t:"fn",v:"1"},{t:"text",v:"Thus those who bore the sword in agreement shall fall upon it, and those who came forth in great numbers shall be overrun! Says The Lord. Yet think not that I do this according to the righteousness of the people in the land of Israel, for they too have forgotten Me and walk not in The Way of The Lord, rejecting My Salvation still. Therefore hear Me, for I declare it to every tribe, tongue, people and nation: FOR MY OWN NAME\u2019S SAKE SHALL I DO IT! For the name of The King, who comes quickly to gather, shall it be done. And for the sake of My beloved servants, from Noah to David, shall I remember My promises. Then all will know, I AM THE LORD..."},{t:"italic",v:"He who sets up kingdoms and brings them to ruin, He who set the foundations of the earth and covered them with beauty, He who also set the stars in their places and caused the galaxies to take their form, He to whom all creation bows down! He whose power is limitless and by whose wisdom all things were brought forth, whose authority is absolute, The God who reigns in Israel, He who was and is and is to come, The Almighty!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore thus says The Lord to the peoples of the earth:"},{t:"text",v:"Have you come so far in your self-proclaimed glory, that you now believe you have done it, and by your own strength you stand?! How long shall you put forth theories as fact and make confident assertions without knowledge?! Tell Me, are you in anywise able to understand the beginning and the end?! Foolish and deceived peoples, most arrogant generation, you know nothing yet as you ought to know, nor do you seek after true knowledge! Thus wisdom remains hidden from your eyes. For I tell you the truth, you have covered yourselves in darkness, in ignorance you have brought forth, and with great arrogance you have pushed ahead! And for the sake of greed you have brought yourselves to the brink! For you wear pride as a cloak and arrogance as a veil! Therefore revelation is far removed and the light of understanding remains hidden from you, leaving you blind and desolate, unable to discern the truth of who I am! O blind and foolish generation, hard-hearted peoples, have you never read, from the beginning it was I who had done it and to the end I AM HE?!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, hear the Word of The Lord and consider, humble yourselves and repent, for the time has come:"},{t:"text",v:"In the days of Noah, was I not more than a little displeased, My anger coming up into My face over that which men had wrought upon the earth? And in My hot displeasure, did I not cover the earth with waters from above and open the storehouses from beneath, drowning the whole world in My bitter tears? Behold, mankind has brought Me to this place once again, because of the multitude of sin which spreads forth across the land unimpeded, because of the multitude of tears and wailing which has entered My ears; behold, the outcry is very great! And because of the multitudes of slain, and because of the silent screams of every unborn child whom you have murdered while still in the womb, O most wicked generation!"}]},{type:"poetry",lines:[[{t:"italic",v:"PEOPLES OF THE EARTH,"}],[{t:"italic",v:"YOUR WORKS ARE REPREHENSIBLE!"}],[{t:"italic",v:"I AM APPALLED BY WHAT I SEE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"This generation is evil, says The Lord,"}],[{t:"italic",v:"Wicked beyond compare, and great is the"}],[{t:"italic",v:"Innocent blood which remains on your hands!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus bitter sadness fills My heart and anguish grabs hold of Me,"}],[{t:"italic",v:"My anger builds and My fury rises up within Me,"}],[{t:"italic",v:"As I set My face to destroy and to wipe away,"}],[{t:"italic",v:"To cleanse the face of the earth once again;"}],[{t:"italic",v:"All wickedness into the fire, every last"}],[{t:"italic",v:"Vestige of man\u2019s invention wiped away!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Cry out therefore, wail loudly and lament,"}],[{t:"italic",v:"For the wicked shall not go unpunished!"}],[{t:"italic",v:"Behold, the time of recompense is here!"}]]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"NO MORE shall My enemies fight against Me without retribution! NO MORE shall the transgressions of the nations continue without judgment; their wickedness shall not go unpunished! For I shall stretch out My hand against them, until all their abominations cease, until the nations fall with a great crash and the pride of the people comes to an end! For My name alone shall be exalted in all the earth, and no more shall it be blasphemed among the nations! Says The Lord God. No more shall the enemies of Israel seek to cast off My people, Jacob, for My Name is there! And no more shall any who dwell upon the earth spit upon the name of The King, nor pollute His Word among the people, anymore! Neither shall Gentile, nor Jew, nor any among those who claim to be grafted in, who reject My Salvation or forsake My Commandments, continue on without strong rebuke and swift discipline! I AM THE LORD! Therefore I have indeed set My face to destroy, to break apart and to strip away, until every cracked foundation is exposed and every corrupt house which stands so high and lofty is struck and collapses upon the desolate, until every nation is left in ruins and the whole land is laid waste. For in their loftiness they built high, with no solid foundation beneath them. Thus the weight of their accomplishments shall crush them, until only dust and ashes remain. For I am a great King, says The Lord, The Only God of power and glory who holds infinite might, whose anger is righteous, whose judgment is true and whose justice shall be swift! Behold, in the heat of My indignation, I shall surely cleanse the face of the earth and wipe the slate clean! Says The Lord. Yet I have not forgotten My promises, nor the covenants I made with My people. Therefore, for the sake of My people and because of My promises, I yet withhold the full weight of My judgment and the power of My wrath; nor shall I flood the face of the earth in My anger, nor drown the nations in the depths of My sorrow."}]},{type:"poetry",lines:[[{t:"italic",v:"For that which I pour out shall not"}],[{t:"italic",v:"Be a flood of water which covers,"}],[{t:"italic",v:"But a flood of judgment to destroy,"}],[{t:"italic",v:"Until the pride of man is bowed down and"}],[{t:"italic",v:"The arrogance of man is utterly humiliated..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Says He who overthrew Sodom and destroyed Gomorrah,"}],[{t:"italic",v:"And punished Egypt with terrible plagues..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUWAH, The Creator of Heaven and Earth,"}],[{t:"italic",v:"THE GOD OF ISRAEL..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet I shall not make a total end,"}],[{t:"italic",v:"Until every last grain of wheat has been gathered"}],[{t:"italic",v:"And every last one of the Called is delivered..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Ezekiel 38:22-23"}},nkjv:{"Ezekiel 38:22-23":"22. And I will bring him to judgment with pestilence and bloodshed; I will rain down on him, on his troops, and on the many peoples who are with him, flooding rain, great hailstones, fire, and brimstone. 23. Thus I will magnify Myself and sanctify Myself, and I will be known in the eyes of many nations. Then they shall know that I am the LORD.\u201D \u2019"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/vengeance-is-mine-i-shall-repay",videoVoiceUrl:"https://www.youtube.com/watch?v=ueM3_LeoQUU&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=52",videoMusicUrl:"https://www.youtube.com/watch?v=TCt1bJYNLB0&list=PLSVchFJ22QYKZW4CHtZ43YBxdHUTgS9rv&index=4",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding the Days of Noah",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"}],num:55,prevLetter:{id:"i-will-defend-my-people-israel",title:"I Will Defend My People, Israel"},nextLetter:{id:"the-diviners-divine-false-visions-the-prophets-prophesy-lies-and-every-dreamer-shares-deceptive-dreams-brought-forth-from-their-own-imagination",title:"The Diviners Divine False Visions, the Prophets Prophesy Lies, and Every Dreamer Shares Deceptive Dreams Brought Forth from Their Own Imagination"}},{id:"the-diviners-divine-false-visions-the-prophets-prophesy-lies-and-every-dreamer-shares-deceptive-dreams-brought-forth-from-their-own-imagination",title:"The Diviners Divine False Visions, the Prophets Prophesy Lies, and Every Dreamer Shares Deceptive Dreams Brought Forth from Their Own Imagination",date:"6/12/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to all diviners, false prophets and dreamers of dreams, even to all who speak falsely in My name, sharing false visions of hell and torment:"},{t:"text",v:"You shall by no means escape the Day of The Lord\u2019s Anger when it comes! For you have caused My people to err, you have led them astray with lies, by many dark speeches! By your false visions have you caused them to stumble into darkness! - Deceptive dreams and delusions brought forth from your own imaginations, all in all doctrines of demons which blaspheme My name and desecrate the truth of who I am! Yet are you ashamed of all these abominations, which you have propagated before the people? No! You are not ashamed, nor do you know how to blush! Therefore you shall be the first to fall among those who fall! Behold, in the time of your punishment you shall surely be cast down! Says The Lord. For wrath has indeed entered My heart, and My anger is increased on your account. Yet MY anger is true, and MY judgment righteous. For that which I see is the whole truth; nothing is hidden from My eyes. Indeed, I know the hearts of both those who deceive and those being deceived. I AM THE LORD."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord God:"},{t:"text",v:"Be struck down, all you deceivers! Even every one, from the deceiver to those perpetuating these deceptions, shall be struck atop their heads! Yet let not those being deceived perish; rather let them be humbled in the Day of The Lord. For the discipline of The Lord shall teach them, and My stern correction shall open their eyes in the Day of Darkness. For The Holy One of Israel is great in power and mighty to save, bursting all bonds asunder, breaking every chain which holds My people captive. Then they will know, I AM THE LORD, and they shall turn away from all these perverse doctrines and reject all these evil fables. For in that day they shall come to see Me as I truly am, declares The Lord. Yet look upon all these who continue to perpetuate these corrupt doctrines and false visions; behold, My name is greatly blasphemed among the nations because of them! It is polluted in every corner where this doctrine of hell and everlasting torment is upheld by the pride and arrogance of men!..."},{t:"italic",v:"MODERN PHARISEES! From the overbearing church leader to the sanctimonious priest, from the high-minded scholar to the braggart preacher, from the self-righteous pastor to the arrogant minister, before Me stands a whole multitude of deceived teachers who know neither Me nor My Word!"},{t:"text",v:"And now they have taken up the sword against Me, even Me, The One True God and Savior! For with cunning words and clever speeches they cast down My words before the people, as they seek to bring harm against My anointed! They cease not from persecuting My messengers, as they seek always a way to slay My prophets!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"Their arms shall be broken in their malice, and their wrists bent backward in their jealousy, as I strike them hard upon the mouth! And upon the sword which they have raised against Me shall they fall! FOR I AM YAHUWAH, AND MY NAME IS TO BE GREATLY FEARED!"}]},{type:"para",segments:[{t:"text",v:"Behold, the veil remains fastened securely atop their heads, and the darkness of their shame covers them, for they have no understanding! For they love to condemn their enemies and take much pleasure in passing judgment against their neighbor! For their hearts are full of hate and the spirit of Cain rules over them! - A most foolish and ignorant generation, multitudes of prideful people who refuse knowledge and reject correction, a people of wrath! I DO NOT KNOW THEM! Neither has The Holy One entered in! Shall I not repay?! Behold, I shall surely require it of them! For they have robbed Me! Says The Lord. Is it a light thing to The Lord, that they have went out polluting My name as they attempt to cast a shadow over My glory?! Is it a small thing to Me, that My sheep are led into the wilderness by all these self-appointed shepherds, by all these false prophets and diviners, all these so-called dreamers of dreams, leaving them lost and without understanding, with no lamp to guide them?! Shall I leave My children to die in this darkness, trapped by all these tall trees?! Shall I leave them as prey for the wolves of the wilderness, afar off, separated from God, destitute of daily food?! Behold, I shall feed them! Even I, Myself, shall give them food and drink! Says The Lord. And lo, they shall be set free to serve in My name, once again. Oh yes, they shall serve Me in truth and righteousness and keep My Commandments, as they testify to The Salvation of God anew. Yet the self-appointed shepherds shall fall, left to starve for a whole season, the dreamers of dreams shall be put to shame, and the breath of every diviner taken; the false prophets shall all lie down in the grave! Yes, every false prophet and diviner who continues to speak lies in My name shall surely die! They shall not be lifted up, nor shall they pollute My name or attempt to steal from My glory, anymore! For fierce is My anger against them, and thus shall I pour out My indignation upon them! Says The Lord of Hosts."}]},{type:"poetry",lines:[[{t:"italic",v:"I am The Lord, and My ways are not human ways,"}],[{t:"italic",v:"For My mercy endures forever and My anger has an end..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus those who highly esteem themselves shall be"}],[{t:"italic",v:"Broken in pieces, and those who profess themselves"}],[{t:"italic",v:"To be wise shall be made the fool..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, the self-appointed shall fall hard upon their faces,"}],[{t:"italic",v:"Severely abased, for by no other means shall"}],[{t:"italic",v:"They be brought into perfection..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-diviners-divine-false-visions-the-prophets-prophesy-lies-and-every-dreamer-shares-deceptive-dreams-brought-forth-from-their-own-imagination",videoVoiceUrl:"https://www.youtube.com/watch?v=LNSOCsIKOW8&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=64",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"The Doctrine of Hell and Eternal Torment Is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Doctrine_of_Hell_and_Eternal_Torment_Is_an_Abomination_to_The_Lord"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"Woe to Those Who Bear False Witness in The Lord\u2019s Name",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Bear_False_Witness_in_The_Lord.E2.80.99s_Name"},{label:"False Doctrines Within the Churches (Index)",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],num:56,prevLetter:{id:"vengeance-is-mine-i-shall-repay",title:"Vengeance Is Mine, I Shall Repay"},nextLetter:{id:"churches-of-men-you-have-robbed-me-says-the-lord",title:"Churches of Men, You Have Robbed Me! Says The Lord"}},{id:"churches-of-men-you-have-robbed-me-says-the-lord",title:"Churches of Men, You Have Robbed Me! Says The Lord",date:"6/15/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy, For All Those Who Have Ears to Hear",forLine:"",noteLine:"(Regarding a large statue of Jesus which was struck by lightning and burned down)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord concerning that which is obvious, a warning made plain, which shall go greatly unheeded by those with veiled heads:"},{t:"text",v:"This is but the first of many things, of which men in the churches have built up in their pride, which shall be struck! For they build themselves up for a show, a false goodness, foolish servants who forsake the poor and the needy in favor of the praises of men! FALSE GLORY! Says The Lord in His jealousy. For their works are perverse in My sight, and their words contemptible! Therefore, because they have robbed Me, I will also rob them; I will tear them in pieces, breaking off all their dead members! Behold, I shall cause their man-made foundations to collapse beneath their feet, and all shall be brought down to the ground! Not one wall shall be left standing! Thus shall they become as those whom they have forsaken. And they shall no more preach from their finely-crafted pulpits, standing tall amongst all their expensive ornaments, broadcasting lies with all their purchased devices. FOR I AM THE LORD, and I will not share My glory; neither will I allow My name to be polluted anymore!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold these great churches of men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Look upon all their riches, see how they have enlarged themselves;"}],[{t:"italic",v:"Look how they have accomplished such great gain in the world..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet I tell you the truth, upon them calamity shall come suddenly,"}],[{t:"italic",v:"And their destitution shall be severe, and in their poverty"}],[{t:"italic",v:"They shall consider and cry many tears..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For in that day they shall become"}],[{t:"italic",v:"The offscouring among many nations..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/churches-of-men-you-have-robbed-me-says-the-lord-3",videoVoiceUrl:"https://www.youtube.com/watch?v=4jOEVRJ0nPA&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=54",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Woe to Those Who Walk in Pretense",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Walk_in_Pretense"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:57,prevLetter:{id:"the-diviners-divine-false-visions-the-prophets-prophesy-lies-and-every-dreamer-shares-deceptive-dreams-brought-forth-from-their-own-imagination",title:"The Diviners Divine False Visions, the Prophets Prophesy Lies, and Every Dreamer Shares Deceptive Dreams Brought Forth from Their Own Imagination"},nextLetter:{id:"the-alarm-of-war",title:"The Alarm of War"}},{id:"the-alarm-of-war",title:"The Alarm of War",date:"7/5/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God in a loud voice:"},{t:"text",v:"The Day has come, yes, it is here! It waits at the doors and is about to come in! And behold, the Great Day approaches and draws near!"}]},{type:"para",segments:[{t:"text",v:"Therefore hear the Word of The Lord, for thus says The Lord to the inhabitants of the earth, to every tribe, tongue, people and nation: Bring forth everything you have from the storehouses and come out to the field for battle! Run quickly, and seek out your gods! Hurry, bow down and plead with your idols, and see if they have the power to save you from the wrath of God! Yes hurry now, O peoples of the earth, go hastily and prepare for war, and see if you are in anywise able to deliver yourselves from the judgments of The Most High! For I am a Great King! Says The Lord. I am God alone, He who is set apart and holy, set apart in power and great glory! The God of Justice is My name, YAHUWAH, He who causes to be! There is no other, for I am God alone, God Eternal!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, O most perverse and deceitful generation, for thus says The Lord:"},{t:"text",v:"Lie not to yourselves; cease from all these deceptions which you have propagated in all the earth! For My Word is law and shall by NO means pass away, nor shall even one tittle fall to the ground! Nor shall the words of My prophets fail, for I have sent them! Therefore touch not My prophets, nor seek to do them any harm, lest your every evil thought and intention be returned atop your own head, and that which you have done against The Lord your God is repaid ten-fold into your bosom! Thus every stone you cast at My servants, in word or by deed, is stored up, and shall be released on a day you did not look for and at an hour you did not expect as a testament against you! And those who seek to murder My chosen shall die by My hand; indeed, all who rush forward to kill My prophets shall be struck down where they stand! For strong is The Lord, and powerful is the sword which proceeds from My mouth!"}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"Behold, My prophets speak and trumpet My warning to the masses, by all manner of speaking and devices, and My messengers deliver My strong rebuke. Yet few have ears to hear, few are willing to listen, for they hide their faces and stiffen their necks. Yea, they push out the lip and turn their backs on My anointed, while mocking Me! Behold, even within the churches of men are the people held captive, fastened to their own doctrines, bound by their own traditions, which I hate! Yes, many who claim to be grafted in hide behind white-washed walls of abomination, choosing to remain within all these detestable gates, rejecting the Word of God! For not one of them has received of Me, not one has been baptized in the Spirit of Truth! Therefore I ask you, who has given heed to the voice of The Lord their God? Who has come out to meet Me? Behold, the lowly have come out, the poor in spirit have come forth, the broken have sought Me and the faithful uphold My cause. Yes, these who carry The Messiah within them have come forward to partake of My supper, and do follow The Lamb wheresoever He leads them. And behold, the day is near when He shall call out to His beloved, and all those who have ears to hear will be lifted up; they shall surely be gone from this place!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, O deceived nations, give ear, all you arrogant peoples who cover the face of the earth, for thus says The Lord:"},{t:"text",v:"Most assuredly, I say to you, I am indeed coming forth to execute vengeance! I am indeed coming down to repay! Behold, I have reserved a double portion of wrath for every nation which condones the slaying of the innocent, and a double portion for all who stand in agreement! Yes, I shall pour out double, even double again, upon all who murder My little ones! And behold, I shall pour out terrible judgment upon every nation who persecutes Me and My body! TOUCH NOT MY BRIDE! For as it is written of Me, so I am:"},{t:"italic",v:"I am jealous, and will avenge Myself upon My enemies; I will avenge, for I am furious! Behold, I will take vengeance on My adversaries and pour out wrath reserved for My enemies! And though I am indeed slow to anger, I will not leave the guilty unpunished! For I am great in power! My path is in the whirlwind and in the storm, and the clouds are the dust of My feet! The mountains quake before Me and the hills melt, the earth heaves at My presence! I AM THE LORD!"},{t:"fn",v:"1"},{t:"text",v:"Therefore, who shall stand before Me? Who can endure the fierceness of My wrath? For My anger is aroused, and will not be turned away; it shall surely be fulfilled before the eyes of"},{t:"italic",v:"this"},{t:"text",v:"generation. Then they will know, I AM THE LORD, He who comes forth to repay the nations, He who has come out of His sanctuary to judge the earth, to deliver His people and defend His prophets! Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, let all nations tremble!"}],[{t:"italic",v:"Let all peoples fear The Lord!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Let the terror of The Lord overwhelm the"}],[{t:"italic",v:"Hearts of the wicked, and come swiftly upon"}],[{t:"italic",v:"The heads of the defiant! Let every countenance"}],[{t:"italic",v:"Fall and every knee buckle for fear!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Let all peoples be awestruck in astonishment"}],[{t:"italic",v:"At the power of The Lord in His anger!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the cup of My indignation overflows,"}],[{t:"italic",v:"And that stored up breaks forth from its hold;"}],[{t:"italic",v:"From the depths of My sorrow to the agony"}],[{t:"italic",v:"Of My heart, My anger rises up inside Me,"}],[{t:"italic",v:"Filling Heaven with My tears!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A hard rain upon the nations..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Nahum 1:2-5"}},nkjv:{"Nahum 1:2-5":"2. God is jealous, and the LORD avenges; The LORD avenges and is furious. The LORD will take vengeance on His adversaries, And He reserves wrath for His enemies; 3. The LORD is slow to anger and great in power, And will not at all acquit the wicked. The LORD has His way In the whirlwind and in the storm, And the clouds are the dust of His feet. 4. He rebukes the sea and makes it dry, And dries up all the rivers. Bashan and Carmel wither, And the flower of Lebanon wilts. 5. The mountains quake before Him, The hills melt, And the earth heaves at His presence, Yes, the world and all who dwell in it."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-alarm-of-war-3",videoVoiceUrl:"https://www.youtube.com/watch?v=oJ7Gl22jsxM&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=54",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:'The Name of The Lord - "YAHUWAH"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YAHUWAH"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Woe to Those Who Come Against God's Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."}],num:58,prevLetter:{id:"churches-of-men-you-have-robbed-me-says-the-lord",title:"Churches of Men, You Have Robbed Me! Says The Lord"},nextLetter:{id:"depart-from-me",title:"Depart from Me"}},{id:"depart-from-me",title:"Depart from Me",date:"7/6/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My people have forsaken Me! The churches of men have departed from Me! They have gone astray, they have been drawn far asunder, polluting My name without ceasing! Behold, even those among the Called of Israel have turned from Me and cover their ears! Therefore must I also forsake them when the trumpet sounds, turning My face from them when the shout is made. Behold, I have sent My messengers to every land, one from every nation, each being sent to the people of their own land, even from the midst of them. Yet I hear no answer, no wailing has entered My ears, not one has come out in mourning; I hear no repentance at all! Only filthiness comes forth, corrupt doctrines and detestable traditions polluting My name and The Messiah\u2019s, great perversions of speech to uphold their own way, desecration as has never been seen! And though they do indeed have a form of godliness, they continually deny the power thereof! The churches of men are unclean, every synagogue is void and desolate; My people have forgotten Me, neither do I dwell among them; My spirit is far removed! Therefore the desolate shall receive the reward of their error, and the heathen the penalty of their idolatries! Behold, the churches of men shall also receive - RECOMPENSE, for every act of adultery which they have committed before My face! Yes, according to every filthy act, which they have performed in MY name, shall it be accounted to them! Dissolute children, why do you rend the heart of God and fill The Holy One with tears and heavy sorrows?! Am I not your God?! Did I not purchase you at a great price?! When did I withhold My heart from you?! At what moment did I turn back or stop to consider if you would receive Me, when I delivered Myself up for you, pouring out My love in rivers of blood?!"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, I poured out My life so you may"}],[{t:"italic",v:"Partake of Me fully, that you may receive of My life!"}],[{t:"italic",v:"Yet you want no part with Me as I truly am!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, with great heaviness of heart"}],[{t:"italic",v:"I declare to you, I am no more your God,"}],[{t:"italic",v:"And you have ceased from being My people..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The True Salvation, which is revealed in Me,"}],[{t:"italic",v:"Remains hidden from your eyes."}]]},{type:"para",segments:[{t:"text",v:"Did you think The Most High was subject to your conditions?! Did you think The Holy One of Israel could be transformed into an image more to your liking?! Did you presume, in your arrogance, to think the ways of The Lord God Almighty were subject to men?! And are My prophets now subject to you?! Foolish people, wicked and slothful generation, you know neither Me nor My Word! For the ways of The Beloved you have not known, and His glory remains hidden from you! And though His grace is shed abroad, it remains far from you; neither have I beheld His form among you. Therefore have you come out to fight against Me in your pride! And with a mouth of arrogance you speak blasphemies before My face, day and night, standing fast in your bitter ignorance! And so I have called for a witness against you, says The Lord of Power and Glory, He who was and is and shall be, The Everlasting, who is from everlasting to everlasting. Amen."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord whose name is one, to His people who are not His people; thus is the witness which I declare against you, which I speak by Myself, of Myself, in My own name:"},{t:"text",v:"I never knew you! Depart from Me! Depart, all you workers of hypocrisy and lawlessness! Depart into the furnace, into refinement and death, the Great and Terrible Day of The Lord! For the lake of My burning heart is a consuming fire, and in the heat of My jealousy I shall purify My people seven times, until only that which bears My likeness remains; the refined lifted up, the wicked consumed, destruction of every kind of evil! For I am The Lord who was and is, even from the beginning, and to the end and forever after I remain."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, thus declares The Lord to all peoples of the earth:"}]]},{type:"poetry",lines:[[{t:"italic",v:"There shall not be another generation which shall"}],[{t:"italic",v:"Grow up out of the kingdoms of men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the kingdoms of men are finished, never to rise again."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/depart-from-me-2",videoVoiceUrl:"https://www.youtube.com/watch?v=0r9s-HDbd0k&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=56",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:59,prevLetter:{id:"the-alarm-of-war",title:"The Alarm of War"},nextLetter:{id:"captive-children-a-lamentation",title:"Captive Children (a Lamentation)"}},{id:"captive-children-a-lamentation",title:"Captive Children (a Lamentation)",date:"7/12/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Holy One, your Redeemer:"},{t:"italic",v:"Beloved, My treasure, My most beloved ones, here I am! Hear Me! I am poured out like wax before the fire; like a candle, I am dripping with tears! Yet you have not come to Me! My love was poured out, My spirit fell like rain upon the nations... Tears and great mourning... I poured Myself out to heal the nations! Blood and tears, pools of blood, the agony of My passion, My love put on open display! Yet who is healed in My love? Where is the harvest among the nations, according to the latter rain? It withers, blighted wheat waning in the heat of the noonday sun, planted in the hard and cracked ground, revealing the broken roots thereof; the rains have ceased and are withheld from the land, the hand of The Holy One removed. Captive children, held fast by the pride and arrogance of men whose hearts remain far from Me, shackled to a world of bitter enmity against God and His Messiah, refusing My Letters of Love, stopping your ears to My voice... Weeping and many tears... I had set you free! Behold, I have freely given! I have not ceased from calling to you through My spirit and by the pen of My prophets, yet you will not listen, nor will you give heed! Even you, O churches of men, will in no wise hear Me, nor are you able! - Arrogant assemblies! DEAF CHILDREN!"}]},{type:"poetry",lines:[[{t:"italic",v:"Bitter children, amiss in your dealings with Me,"}],[{t:"italic",v:"I love you, yet you refuse Me still"}],[{t:"italic",v:"In favor of your own way!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Peoples of this world, and all pastors"}],[{t:"italic",v:"And teachers and leaders among men,"}],[{t:"italic",v:"You are forsaken, given up to the fire..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The fires of My own correction,"}],[{t:"italic",v:"The harsh discipline of The Father,"}],[{t:"italic",v:"The day of refinement and tears."}]]},{type:"para",segments:[{t:"italic",v:"I love you, yet you have not known Me; neither do I see of Myself in you... Our hearts torn. For I see your hearts, beloved, I see and know. Behold, I have searched, and have not found even one tittle of that which is of Me! Cry out, therefore! Call out to your Savior! Call upon your Maker in My name! DIE TO YOURSELVES! Forsake this world and run to Me through the fire, and I shall abide with you in the heat of its burning, until that which must be done is finished and you emerge purified. Humble yourselves! Cast yourselves down! I am your Father! I LOVE YOU! Yet you have departed from Me, wasting your inheritance in a world of unbridled sin, a world which even now hates you, a world which you have loved more than Me, even yourselves! And so I have written to you page after page by the pen of My prophets, shouting to you by all manner of speaking and devices, calling to you across the ages, speaking to THIS generation with many tears and much sorrow, warning you of My wrath which must come and is now here and shall quickly overtake this world. And still you push out the hand! Do you not understand?! I have seen it; nothing escapes My eye! Churches of men, I have seen it! Modern Pharisees, you fight against Me! You fight against The God of your fathers, The One and Only True God! And whatsoever you do to even one of these I have sent to you, whether in word or by deed, you have done it to Me!... Yet I love you still... My heart is torn, a rent which widens, a rent which you have made! Why do you tear yourselves from Me?! For apart from Me, you can do nothing! Apart from Me is darkness, thick darkness and death!"}]},{type:"para",segments:[{t:"text",v:"The time has passed, beloved ones; My bride is chosen and the first election is made; the bundles are prepared and set in their places. Therefore I tell you, when you look for Me in the Day, look no more to yourselves, nor in man-made churches; behold, they shall all be torn down! For in them I have not dwelled... I dwell in the hearts of men! And when darkness has fallen and your tears well up, a bitter rain brought forth from a heart severely broken, from a spirit crushed by the weight of realization, run and seek out My beacons, My witnesses. For they shall lead you through the fire, and I shall abide with you, accompanying you on your journey..."},{t:"italic",v:"A journey of service and great hardship, of many tears and great sorrows, suffering on every side; a journey of love and hope in the midst of great adversity, the end of which shall bring a great multitude into My love, with every servant washing the feet of his neighbor until death comes and sets you free; caught up into My love, healed in an instant, refashioned in glory, remade in My image, partaking of My life fully."}]},{type:"poetry",lines:[[{t:"italic",v:"For as many as I love, I rebuke and chasten,"}],[{t:"italic",v:"Bringing forth much thanksgiving"}],[{t:"italic",v:"To the praise of My glory..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As it is written, so shall it be done..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore trust in My ways,"}],[{t:"italic",v:"For I am The King alone;"}],[{t:"italic",v:"Apart from Me, there is nothing at all."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/captive-children-a-lamentation-3",videoVoiceUrl:"https://www.youtube.com/watch?v=U8qbVRJ0SXI&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=57",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:'"My Hand is Removed"',url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets#.22My_Hand_is_Removed.22"}],num:60,prevLetter:{id:"depart-from-me",title:"Depart from Me"},nextLetter:{id:"proclaim-the-name-of-the-lord",title:"Proclaim The Name of The Lord"}},{id:"proclaim-the-name-of-the-lord",title:"Proclaim The Name of The Lord",date:"7/24/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"I have indeed spoken by My servant, I have indeed spread My words abroad, placing them before the eyes of this most wicked and unbelieving generation. Therefore, My sons, speak My name aloud, yea shout My name to the ends of the earth, for I have surely revealed it! Behold, I have placed My name on a hill, a waving banner in the sight of all nations! Therefore, let My people lift up My name and make mention of My glory, at all times and in every season! My people, speak My name aloud, yet speak nothing apart from Me; speak only that which I Myself have given you. Freely you have received in My name, freely give."},{t:"fn",v:"1"},{t:"text",v:"For when I speak, I speak in My own name; and when I swear, I swear by Myself. And you, My beacons, have the name of The Holy One written in your hearts, having also been sealed with the name of The Living God upon your foreheads; behold, the name of Mashiach shall be emblazoned upon your chests. Why then do you withhold? How is it you keep quiet? Honor My name wholly and in truth; speak My name aloud and withhold not. Proclaim the truth of who I am, and warn the people of that which I am about to do. For I am The Only God, a just God and a Savior. Therefore, again I say to you, shout My name aloud and withhold not! Call all in the earth to repent! For The Lord your God is a consuming fire, setting the course of this world ablaze in My glory, restoring all things in the brightness of My coming and by the Word of My power."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My name alone stands throughout"}],[{t:"italic",v:"The generations, a perpetual covering for My people,"}],[{t:"italic",v:"A secure place of shelter for all those who seek My face,"}],[{t:"italic",v:"A tower of strength for all who take refuge in Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"From everlasting, I AM, and to everlasting shall I be,"}],[{t:"italic",v:"The same and unchanging, even as My name..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I AM WHO I AM, YAHUWAH, The One who causes to be..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA, He by whom all things consist and have life."}]]},{type:"para",segments:[{t:"text",v:"Thus My name is one, even as The Father and The Son are one, a just God and a Savior - ONE. Therefore when My beloved seek Me out, or call upon Me in another language, it is acceptable with Me, for there is but One God and One Savior..."},{t:"italic",v:"I know My own."},{t:"text",v:"For I alone search the hearts and minds, and whether one calls upon Me in this language or in the tongue of another, I listen, I see, I know."},{t:"fn",v:"2"},{t:"text",v:"Yet as it is written,"},{t:"italic",v:"there is indeed a day coming when I shall restore to the nations a pure language, that all My people may call upon the name of The Lord in one accord, to serve Me as one people set apart for My name."},{t:"fn",v:"3"},{t:"text",v:"Yet this day is not yet, says The Lord. Therefore, listen not to all these self-proclaimed teachers! Shut your ears to all these self-appointed pastors, preachers, ministers and priests, who pollute My name and My glory! Turn away from all these arrogant men in authority; do not give heed to any of their clever and dark speeches! Glorify MY name and withhold not! For there are many who say,"},{t:"italic",v:"\u201CHush, speak not the name of The Lord aloud. For who can know His name or speak it aloud, without error?\u201D"},{t:"text",v:"And yet others assert that only by a certain name which they have chosen, or by a certain tradition which they uphold, can one be saved. Indeed, there are many who have given heed to the devil\u2019s purpose. Even now it is apparent, manifest in the world by people who hide My name under false pretense, and desecrate My name by detestable doctrine and perverse tradition, people who take the name of The Lord in vain without ceasing by all they say and do, sins far greater than those who without knowledge use My name as a cursing. Yet greater still is the sin of those who curse others in My name, endeavoring to place a curse upon another in the name of The Lord. Woe, I say to them! Woe! Even three times, woe! Says The Lord."},{t:"italic",v:"For these are wells without water, clouds carried by a tempest for whom is reserved the blackness of darkness forever, as it is written!"},{t:"fn",v:"4"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The whole world is awash in blasphemy and sin, perversion fills every corner! For all these people of faith, as they are called among men, desecrate My name by man-made doctrine and pollute My name by pagan tradition; harlotries abound! Come out from among them therefore, and be separate! Touch no more that which is unclean, and I will receive you! Be separate from this world and its evil ways! Be plucked up and freed from all these vain religions of men, from all these who uphold reprehensible doctrine and deplorable tradition, polluting My way before Me! For they are greatly misled, pleasers of men and this world, antichrist. Therefore, My servants, sing praises to My name without ceasing! Bless My name in the company of angels, shout My name aloud! Yea, proclaim the name of The Lord in the ear of every mocker, in the face of every adversary, in open and in secret! Speak forth My name in power, and withhold not! Speak My name aloud for the sake of those dying in this world! Speak My name as it is, and also in the tongue of the hearer, so they may hear and understand and know, I AM HE! -"},{t:"italic",v:"He who was and is and is to come, The Almighty! God in the flesh, YahuShua, Immanu El!"},{t:"text",v:"And when you find yourself under attack by a flock of detestable birds, surrounded on every side, wield My name as a sword and doubt not, and it will surely find its mark. For the day is coming, and behold it is already here, when I shall dwell in My witnesses like a flame of fire, and well up in My servants like a boiling pool, when all flocks shall be scattered and the wicked of the flock purged. For I shall strike down many ten thousands in My anger, slaying a great multitude with the sword of My mouth! Behold, I shall cut down My adversaries and lay whole armies waste! For the name of The Lord of Hosts is a broadsword, and My every word a freshly sharpened blade! For in My name is great power, and at the sound of My name all darkness flees away! For as a razor removes the stubble, and fervent heat burns away the dross, so shall My name purge the waste places and cleanse the polluted cities, until all these squawking birds are brought down into silence and every tall tower is toppled and left in ruins, until Babel is utterly destroyed and every last vestige of man\u2019s invention is wiped from the face of the earth! Says The Lord God."}]},{type:"para",segments:[{t:"text",v:"Then shall The Son of Righteousness rise up with healing in His wings, and you, My precious beloved, shall go out leaping like calves released from the stall! The King, Himself, shall cultivate the ground in that day, with streams of living waters breaking out behind Him! Behold, new life shall fill every corner, and the desolate places shall be restored! Whole forests shall burst forth from the ground, with every kind of tree and flowering plant, every kind of grass and fern reappearing, and every living creature leaping up from the dust of the earth, once again! Behold, The Lord\u2019s peace shall be there! And nothing under the sun shall destroy, nor shall anything be given to destruction, in all My holy mountain! For there shall be no predator, nor shall any prey be found, neither shall the strong slay the weak. For as it is written:"},{t:"italic",v:"The wolf and the lamb shall feed together, the lion shall eat straw like the ox, and dust shall be the serpent\u2019s food."},{t:"fn",v:"5"},{t:"text",v:"All shall dwell in safety, with every living creature dwelling at peace with its neighbor. Behold, in that day everlasting righteousness shall reign in all the earth! For The King shall stand up, and all creation shall bow down! And He shall look upon the joy of His heart with gladness, and the blessing shall be fulfilled:"},{t:"italic",v:"He shall bless them and keep them, and make His face to shine upon them; He shall be gracious to them, and lift up His countenance upon them, and grant them peace."},{t:"fn",v:"6"}]},{type:"poetry",lines:[[{t:"italic",v:"And thus shall My name be placed upon the children of Israel,"}],[{t:"italic",v:"Even upon all who have been grafted in, and they shall be blessed..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yea, they shall be exceedingly glad,"}],[{t:"italic",v:"Dwelling in the presence of The Lord, forever!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the multitudes shall break forth into singing!"}],[{t:"italic",v:"For The Glory of The Lord shall be alive in their hearts,"}],[{t:"italic",v:"The seal of The Living God shall be upon their foreheads,"}],[{t:"italic",v:"The Way of The Lord shall dwell in their limbs,"}],[{t:"italic",v:"And unending praise shall be upon their lips!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"All their doings shall bear fruit in righteousness,"}],[{t:"italic",v:"For The Law shall be written there, even in their innermost parts!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, The King of Peace shall overflow,"}],[{t:"italic",v:"And His people shall be satisfied and have rest, our joy complete..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, blessed are all those who seek forgiveness"}],[{t:"italic",v:"In YahuShua HaMashiach, and also receive;"}],[{t:"italic",v:"For in His name shall all find freedom,"}],[{t:"italic",v:"Solace under the shadow of His healing wings..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Life without end..."}]]},{type:"closing",text:"Says The Lord God."}],footnotes:{1:{type:"scripture",ref:"Matthew 10:8"},2:{type:"note",text:`\u201CYet understand this: In times past I overlooked the ignorance of the people. Yet now I command all people everywhere to repent in sincerity and in truth.[A] In like manner, I have overlooked the ignorance of those who call The Messiah by another name. Yet now I command all who have ears to hear, to call upon His name as it is, was, and has always been, and not as they presume it to be.[B] Indeed I am calling all tribes, tongues, peoples and nations to embrace Him as He truly is, and not as the churches of men would have Him be, says The Lord.\u201D (From \u201CDeath and Deliverance\u201D)

A. Acts 17:30 \u2014 \u201CTruly, these times of ignorance God overlooked, but now commands all men everywhere to repent,\u201D
B. Zephaniah 3:9 \u2014 \u201CFor then I will restore to the peoples a pure language, That they all may call on the name of the LORD, To serve Him with one accord.\u201D`},3:{type:"scripture",ref:"Zephaniah 3:9"},4:{type:"scripture",ref:"2 Peter 2:17"},5:{type:"scripture",ref:"Isaiah 65:25"},6:{type:"scripture",ref:"Numbers 6:24-26"}},nkjv:{"Matthew 10:8":"Heal the sick, cleanse the lepers, raise the dead, cast out demons. Freely you have received, freely give.","Zephaniah 3:9":"\u201CFor then I will restore to the peoples a pure language, That they all may call on the name of the LORD, To serve Him with one accord.","2 Peter 2:17":"These are wells without water, clouds carried by a tempest, for whom is reserved the blackness of darkness forever.","Isaiah 65:25":"The wolf and the lamb shall feed together, The lion shall eat straw like the ox, And dust shall be the serpent\u2019s food. They shall not hurt nor destroy in all My holy mountain,\u201D Says the LORD.","Numbers 6:24-26":"24. \u201CThe LORD bless you and keep you; 25. The LORD make His face shine upon you, And be gracious to you; 26. The LORD lift up His countenance upon you, And give you peace.\u201D \u2019"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/proclaim-the-name-of-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=Mwj7qios1AA&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=74",videoMusicUrl:"https://www.youtube.com/watch?v=WTZumHMDEsU&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=41",relatedTopics:[{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord_.28Section_One.29"},{label:"Regarding Sacred Names",url:"https://answersonlygodcangive.com/Regarding_Sacred_Names"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:'"He Who Was and Is and Is to Come"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#He_Who_Was_and_Is_and_Is_to_Come"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:61,prevLetter:{id:"captive-children-a-lamentation",title:"Captive Children (a Lamentation)"},nextLetter:{id:"my-word-is-fire",title:"My Word Is Fire"}},{id:"my-word-is-fire",title:"My Word Is Fire",date:"8/6/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Hosts:"},{t:"text",v:"Behold, I had purified My servant, Israel, and in My zeal I purged Jacob, leaving his descendants to wander in desolate lands forty years, that I might make them a kingdom of priests, a holy nation, a people set apart for My name. For I am God alone, The Only Lord of Hosts; there is none besides Me. Therefore, from the beginning I laid the foundations, and from the beginning was the Day of The Lord prepared, that My power may be revealed in My judgments and My glory in My zeal, that all in the earth may know and remember, I AM THE LORD. For behold, at My strong rebuke was the mighty king cast down. And with the backward swipe of My hand the increase of Egypt was laid waste, consumed by all manner of pestilence and plague. For in My anger I greatly afflicted the people in the land of Egypt, even to the firstborn of man and beast, which I killed with death. Yet Israel, My inheritance, remained untouched by My hand, nor did I allow them to be harmed in My judgment, though My wrath covered all of Egypt and pestilence and plague inundated the land. Lo, even death passed over them when I saw the blood upon their doorposts. Thus by the power of My own right hand I delivered them, and by the strength of My arm did I bring them out. And when their enemies pursued them, I rose up and fought for My people, Israel. Behold, by the breath of My nostrils I opened a way for them in the midst of the sea, and they escaped, crossing over dry-shod, while the waters stood roiling on the right and on the left. And when I had brought them through to safety, I looked down upon the army of the Egyptians and greatly troubled them; behold, I covered them in My anger, and crushed them under the weight of the sea. Thus the slaughter was very great, causing all who heard of it to tremble. Behold, I caused My name to resound throughout the generations on that day, that all nations may fear The Lord and know, there is no other god besides Me."}]},{type:"para",segments:[{t:"text",v:"Yet how did My people repay Me?! With grief! Yea, with a multitude of complaints they troubled Me, until I was sorely displeased! Behold, ten times they tempted The Lord their God, though I had shown them My glory by many mighty signs and wonders in the land of Egypt and in the wilderness! Therefore, because they rejected Me and refused to give heed to My voice, I stretched out My hand against them. Yes, many were cut off from the earth and from their people, among the generation who had provoked Me to anger. And not one entered into their inheritance save those whose hearts held fast to the promise, whose countenances did not waver. For they were of a different spirit and had shown themselves fully worthy; neither did they cease from giving Me glory, offering up praise and thanksgiving in My name, at all times and in every season. Therefore, only two sons of Israel entered the promised land, of the generation who had provoked Me to anger; only two were chosen to lead the generation which came after. For I am The Lord God of Israel, The Only God, He who is great in power and clothed with eternal glory! I CHANGE NOT! Even from generation to generation, I AM THE LORD."}]},{type:"para",segments:[{t:"text",v:"Therefore I ask you, what is this I see amongst My flocks, yes, even among you, the small of My flock? Pretense upon pretense, hidden agendas and darkness of faces"},{t:"fn",v:"1"},{t:"text",v:", many ill sheep looking to tread the line, forsaking My ways when they become inconvenient, fleeing in heart and mind when the heat of My face is revealed; a most wayward people, foolish children who know not My ways, turning their face always from My correction! And what is this I hear amongst the churches of men? What is this I behold in the hearts of many, even within the hearts of some in this little flock?! Grumbling and secret complaints! Behold, My own beloved have reproached Me, saying,"},{t:"italic",v:"\u201CSpeak not the Word of The Lord in the fierceness of His wrath, nor in truths which are absolute; remove from us all these sharp words. Speak to us smooth words, prophesy to us deceits. Let us be at peace in our ignorance, and take solace in the darkness of our understanding. Let all accountability be far removed, that we may go our own way.\u201D"},{t:"text",v:"Therefore am I risen up in My hot displeasure, therefore have I opened My mouth to speak, until every heart is brought forward, until every evil thought and hidden intention is revealed and brought into the light, until ALL is put on open display! For those who say they are My people are not My people! They have surely rejected Me, says The Lord, hating both Me and My Word! Yet I have indeed bestowed upon this generation a multitude of gifts, a great number of words, words of warning and unsurpassed wisdom, words of exaltation and correction, calling all in the earth to repent. Lo, I have expounded many words of unending love, with great passion, revealing My Mercy which endures forever. Behold, I have proclaimed the way of salvation, time and time again, and He whose name is The Salvation of God! Yes, I have blown the trumpet and called forth My watchmen, I have struck the gates and rattled the doors, I have shaken the foundations of the earth! And still the people hold fast, clutching the pillars and shoring up the doors against Me! Yet from the beginning I established the line, a narrow way which I had placed in the midst of My people, Israel. And in My mercy, I revealed The Way in which My people should walk. Behold, even now I have placed a plumb line in the midst of all people, setting all these crooked paths straight. For I am The Lord, and I do not change."}]},{type:"poetry",lines:[[{t:"italic",v:"Or do you still think that I have come forth to"}],[{t:"italic",v:"Bring peace on earth? No, not peace, but great division!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I have come forth to correct and discipline, to rebuke"}],[{t:"italic",v:"And pass judgment, to make war and divide the spoils!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"FOR MY WORD IS FIRE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Stoking the flames of the elect and searing the consciences"}],[{t:"italic",v:"Of the lukewarm, setting the hearts of the wicked"}],[{t:"italic",v:"Ablaze with anger and causing the indignation"}],[{t:"italic",v:"Of the rebellious to rise up against Me, that I may"}],[{t:"italic",v:"Divide all people asunder and allot them their portions!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to all people:"},{t:"text",v:"You shall be undone, and all who rebel against Me shall be torn in pieces! And you, even you who are called Christian, you also shall be tried! For as silver purified in the furnace seven times, so shall I purify you until I have burned away the dross, until you also become a holy people set apart for My name, grafted in. For I must refine My people and separate My flocks, as a shepherd separates the sheep from the goats, as the hired man calls them out from amongst them. For I am The Shepherd, and in My servants I shall surely dwell. Yet you refuse to come out, therefore you shall surely endure the consequence of your error. For you continue to hold fast in your pride, and sit still on account of your arrogance, saying,"},{t:"italic",v:"\u201CThis is my house, and these are my people by which I am called; I will not come out! For we alone are righteous, and we together will not give heed to any trumpet. We will reject every call to come out, we will refuse all messengers sent to us by God, lest He expose our guilt and uncover our shame. For only those who come in their own names, and bear the marks of our affiliation, will be embraced. And only those who bring us food, according to our own palates, will be accepted. Let us alone!\u201D"},{t:"text",v:"Has The Lord\u2019s table become contemptible in your eyes?! Has The Way of God become unrecognizable to you?! How is it My voice has become altogether foreign to you, O churches of men?!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to the churches of men:"},{t:"text",v:"Because you have spoken in such a manner, with your hearts revealing the same, and because you have pushed out the hand against the cleansing of The Lord, choosing rather to revel in all your uncleanness, you are given up and shall be purged by fire, refinement in the Day of The Lord! For The Lord your God is a consuming fire, My every word a purifying flame! The presence of The Lord is an oppressive storm, which abases the proud and causes the high-minded to flee! And that which I have spoken to this generation, is it not a sword by which I shall strike to the heart of this people?! For I shall surely set all these crooked paths straight and burn away the dross!"}]},{type:"poetry",lines:[[{t:"italic",v:"Yet for those who trust in Me and in whom My spirit"}],[{t:"italic",v:"Dwells, My words are like a strong tower set in the midst"}],[{t:"italic",v:"Of battle, which can in no wise be broken down..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A great trumpet blowing upon the hill outside"}],[{t:"italic",v:"The city, echoing throughout the waste places;"}],[{t:"italic",v:"A waving banner for this generation, a bright light,"}],[{t:"italic",v:"A beacon shining in the midst of this present darkness..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A rod of justice for the oppressed and the persecuted,"}],[{t:"italic",v:"A loosening of the chains, the breaking apart of every shackle!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Freedom for those who love Me, deliverance for those"}],[{t:"italic",v:"Who understand, strength for the weak, grace to the humble..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Manna to nourish the penitent..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'Also read: "Darkness of Faces"',url:"https://trumpetcallofgodonline.com/index.php5?title=Darkness_of_Faces"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/my-word-is-fire-3",videoVoiceUrl:"https://www.youtube.com/watch?v=SmA0fi9LrMo&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=59",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:62,prevLetter:{id:"proclaim-the-name-of-the-lord",title:"Proclaim The Name of The Lord"},nextLetter:{id:"dividing-the-spoils",title:"Dividing the Spoils"}},{id:"dividing-the-spoils",title:"Dividing the Spoils",date:"8/6/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the churches of men)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Hear the Word of The Lord, for thus declares The Lord:"},{t:"text",v:"All those who depart the churches of men shall come and sit at My table. And those who remain unmoving, holding fast, resting proudly upon their laurels, shall receive the recompense of their error. For their fate shall be even as the house in which they have placed all their trust, a house which is already condemned. For I am The Lord alone, and I will not share My glory; nor shall any corrupt house stand, though man has endeavored to place My name there..."},{t:"italic",v:"No more shall My name be polluted because of you, O churches of men!"},{t:"fn",v:"1"},{t:"italic",v:" No more shall the name of The Son of Salvation be perverted before the multitude, because of you, O house of harlots!"},{t:"fn",v:"2"},{t:"italic",v:" For you have surely committed adultery by your doctrines,"},{t:"fn",v:"3"},{t:"italic",v:" and have played the harlot by your traditions,"},{t:"fn",v:"4"},{t:"italic",v:" welcoming in many lovers!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, I am coming down to you,"}],[{t:"italic",v:"To purge and to divide the spoils!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I shall tear down,"}],[{t:"italic",v:"Uproot and destroy, supplant,"}],[{t:"italic",v:"Until I have set all these crooked paths straight!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'Also read: "Regarding the Churches of Men"',url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},2:{type:"note",text:'Also read: "Regarding the Catholic Church"',url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},3:{type:"note",text:'Also read: "False Doctrines Within the Churches of Men Regarding..."',url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},4:{type:"note",text:'Also read: "Regarding the Holidays of Men"',url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/dividing-the-spoils",videoVoiceUrl:"https://www.youtube.com/watch?v=ZaB43R3sxyo&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=62",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"Index of False Doctrines Within the Churches of Men",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"}],num:63,prevLetter:{id:"my-word-is-fire",title:"My Word Is Fire"},nextLetter:{id:"i-am-calling-you-out-part-1",title:"I Am Calling You Out! (Part 1)"}},{id:"i-am-calling-you-out-part-1",title:"I Am Calling You Out! (Part 1)",date:"8/19/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Beloved children, I am calling you out. From the midst of your countrymen, from the midst of your peers and kindred, even from the midst of all these churches of men, I am calling you out, that you may be separate, that you may be set apart in truth, a lowly people who wait upon The Lord with joy and trembling. Yet My people will not come out, nor will they stay separate. For they do not hate the company of evildoers, and at the table of the wicked they sit at ease. Yet The Lord your God has shown you the Way. Even I have provided this lamp for your feet, lest you should stumble and fall into a pit. For thick clouds gather, darkness descends and covers the earth, yet you will not believe."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus in My mercy,"}],[{t:"italic",v:"I have placed a beacon in the midst"}],[{t:"italic",v:"Of this desolate land, a light which shall"}],[{t:"italic",v:"Reach even unto the ends of the earth..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I have forged a silver trumpet,"}],[{t:"italic",v:"And placed it in the hands of My watchman..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the flames of My people flicker,"}],[{t:"italic",v:"And the winds of deception do not cease."}]]},{type:"para",segments:[{t:"text",v:"BEHOLD, WICKEDNESS INCREASES BY MEASURE! And oh how the people love to have it so! For they all have itching ears! They give heed to every wind of doctrine, and hold fast to every false expectation and arrogant assumption! They are continually led away; none have truly discerned, nor are they able!..."},{t:"italic",v:"Oh sadness, bitter sorrow, My beloved has forsaken Me! She cleaves to the breast of another, and has not known Me! Therefore do My tears flow down, My face is wet with grief! For I had called out to her, yet I heard no answer! I lifted up My voice, yet she did not come out to meet Me! Behold, in My zeal I stretched out My arms to embrace her, yet she refused Me!"},{t:"text",v:"My people, the trumpet is blown, the call has went out, yet few have assembled before the tent of meeting. For there are many who claim to know Me, there are many who say they are My servants, a great multitude who claim they are My people, yet they are not My people! For they do not observe justice, neither do they seek to do what is right. For I have surely looked upon them, I have set My gaze upon all who call upon My name, I have searched and I have passed through. I know the thoughts of My people, and the hearts of My elect are known to Me. For I am The Lord, very close at hand. Thus I shall purge My people and set apart My elect; I shall surely sift and separate the harvest, and cause a great division in all the earth! For I am The Lord, and I DO NOT CHANGE."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to all those who have ears to hear:"},{t:"text",v:"Beloved, stand apart from this world in word and by deed. Take your every thought captive that you may be fully set apart. Reveal your love for Me by all you say and do; put your love on open display. Rest in Me on the Sabbath Day and receive My blessing; honor My Holy Days and remember, that you may also understand; hold fast to The Holy Covenant, and no longer depart from the Word of My Commandment. Yet among you, I see some who do not turn their foot away from doing their own pleasure on the Sabbath, the day which I made for you, the day I commanded you to remember and keep holy. Beloved ones, did I not sanctify the seventh day from the beginning? Did I not write The Commandment by My own finger? Is it not a sign between Me and you, that you may know that I am The Lord who sanctifies you? Yet the churches of men forsake My Commandments, and do not honor My Holy Days. Thus those who forsake My Sabbaths have revealed who is first; let them walk through the valley! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My people lack knowledge and have no understanding; they shut their eyes and can not discern; their ears grow dull and they have forgotten how to listen. For they do always turn away from that which is most needful as they judge falsely, failing to do that which is right and good in My eyes. Behold, upon a cracked reed they have placed all their trust; they lean heavily upon a way which is not good! Therefore I shall break up their fallow ground, and cause their reed to splinter beneath them, and they too shall be pierced! Says The Lord..."},{t:"italic",v:"Beloved, My eyes are full of tears, My heart heavy with grief! The cry of mourning is heard at noonday, great wailing breaks forth in all the earth! For the wound of this people is grievous, their affliction most severe! Yet who shall plead their cause in the Day of Calamity?! Who shall bind up the wound?! For they have surely rejected Me!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord God:"},{t:"text",v:"I have set My face against the generation of My wrath! For the people have made lies their refuge, and under falsehood they have endeavored to hide themselves! Behold, they have made a covenant with death, and with the grave they are in agreement! Yet it shall not stand! For in the midst of unparalleled calamity I shall hear, and from the midst of terrible judgment My arm shall surely deliver, even a great remnant of whom The Lord shall call."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His little flock:"},{t:"text",v:"I call you to consider, to consider deeply, to see with greater eyes. For I have blessed you in a way few have regarded, nor have any seen the like since My apostles walked with Me in Israel. Indeed, I have opened My mouth and spoken to this generation through My prophets, I have revealed secrets and made My plans known. For I do not change, says The Lord. Yet who has truly considered, and who is able to comprehend? For My people walk about as one heavy with sleep, as one caught up in the midst of a dream, unable to perceive whether they are awake or sleeping. My people are dull, they are heavy with sleep, yet I shall surely awaken them! For I shall cause the hearts of My beloved to skip a beat, and the hearts of the multitude shall thunder in their chests! For as it was with My prophet of old, to whom I said,"},{t:"italic",v:"\u201CGo out, and stand on the mountain before The Lord,\u201D"},{t:"text",v:"so shall it be with the people of this generation! For I shall pass through, and a great and terrible wind shall tear into the mountains, and the rocks shall be broken in pieces! Behold, a great earthquake shall ensue, and fire shall break out in all the earth, and this generation shall be humbled!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, woe to those who"}],[{t:"italic",v:"Do not give heed to My words"}],[{t:"italic",v:"And mock this Trumpet!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Woe to those who turn away"}],[{t:"italic",v:"From My voice and shut their ears"}],[{t:"italic",v:"To the quiet utterings of My spirit!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"WOE TO ALL WHO REFUSE TO COME OUT!"}]]},{type:"para",segments:[{t:"text",v:"Oh My beloved, why do you not love Me? How is it you take no pleasure in My Sabbaths, and turn your face from My Holy Days? Beloved, am I not married unto you? Have I not prepared your way before you, that you may come to Me unhindered? Have I not prepared a place for you, that you may be with Me where I am? Beloved, you are My heart\u2019s desire! Yet when I look upon you I see only lukewarm children, lamps with no oil, flowers of the field quickly fading. Beloved, before you came forth from the womb you were Mine, and in your youth I knew you; even in your early years, you remembered Me and knew My face. Yet now you hide your face from Me; under the darkness of the veil your countenance is concealed. For your heart is far removed, and the Way of The Lord you have forgotten..."},{t:"italic",v:"Beloved, when I look into your eyes, I do not see of Myself, My glory has departed! Oh what sadness, bitter grief, the beautiful ones have all gone away, darkness covers the face of the earth!"},{t:"text",v:"How long shall My people treat Me as one who is made to stand afar off, as one who must wait in an outer room? How then shall the dull of hearing hear My voice and the weak clasp the hem of My robe? Beloved, you have lost your grasp, yet are unaware! Your feet have become entangled amongst briers and thorns, yet you have made no effort to loose them! For who can endure the Day of The Lord? Who is able to stand in the Day of Judgment? Who, in all the earth, is able to pass through the fiery furnace unharmed?!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, little flock, perk up your ears and listen, all you who call on My name, for the mouth of The Lord has spoken:"},{t:"text",v:"Behold, there is a day coming quickly, a day and hour which remains unknown to you, in which I will call you to stop what you are doing that you may come out and worship Me. I will call you to keep this day holy, and you shall do no work, and it shall be to you a Sabbath. And lo, it shall also be fulfilled a second time, says The Lord. On this day, I will call to you through My prophet, and you will come out and worship Me, each in your own house, set apart, with your beloved set apart. And in each household shall it be decided, it shall surely be revealed:"},{t:"italic",v:"Who among you loves Me more than these, more than themselves, more than this world."},{t:"text",v:"Yet those who fail to come to Me without condition, even all those who refuse to come out, their ears shall grow dull and they shall be unable to hear, neither shall they escape. For I am The Lord, and this is My will: That one whose flame burns hot, whose love for Me runs deep, now display their love for Me openly. And that one who is neither cold nor hot depart from Me, until the time comes and is fulfilled, that by great distress their flame is stoked and becomes a great fire, glaring in the eyes of the passerby, shining in the midst of the cold dark night. For I search the heart, says The Lord, I alone know the mind. The thoughts of My beloved are known to Me, and the plans of the wicked are not hidden from Me. Behold, I look upon the innermost thoughts, I am aware of every hidden intention. For I am The Lord, He who separated the light from the darkness; from the beginning, I am He who formed it and brought it into the light. Thus pretense is not at all becoming of a servant of The Lord; neither is the world a garment which My elect shall wear..."},{t:"italic",v:"Beloved, strip yourselves naked, cast off these filthy robes! Wash yourselves, make yourselves clean! Turn away from this world, and come to Me! Lay yourselves upon the altar and become a living sacrifice to The Lord, the planting of The Lord, My pleasant plants set in the midst of My vineyard, My beautiful ones grafted in."},{t:"text",v:"Yet My beloved are held captive and seek not the way of escape. Indeed, those within the churches of men say,"},{t:"italic",v:"\u201CWe are delivered!\u201D"},{t:"text",v:"Yet they are NOT delivered! For they have no knowledge, nor will they receive correction; they cleave to a false way and worship a graven image. They are battered and they are bruised, yet they do not come to Me that I may heal them! Behold, they are like the swift dromedary, who runs to and fro in the desert. Who can control her when she is in heat? Indeed My people appear docile, yet they can not be tamed, neither will they sit still! For My children are stubborn and will not lay down; they refuse to be broken! They are strangers, yes, they are strangers and go after them! They love the voice of strangers and embrace strange doctrine! They cleave to foreign traditions and practice abomination in MY name! For they have not known Me! Says The Lord. How long shall My beloved wander in desolate places?! How long shall they strip the fruitful field bare and pollute the springs of living water?! The innocent are destroyed, and the earth is forsaken! The cities of men are a harbor for every foul and detestable bird, a nest for every kind of evil; behold, great wickedness dwells there! Therefore the earth shall rise up against the sons of men, and nature shall break forth in its fury and fight against them, until all in the earth grow weary and the heart of this people is torn! - A rent which is deep, a rent made wide. Behold, the earth shall shake and rumble from beneath, the cities shall break apart and the towers shall be toppled, and the glory of man shall be utterly devastated! The blood of the innocent shall cry out from the ground, every atrocity of man shall be remembered, when The Lord God strikes the earth with plague and famine and the waters turn to blood! For the generation of My wrath shall be shaken, the generation of My fury shall be broken without hand! Behold, the storm is already overhead, the whirlwind breaks forth from the midst of the clouds! SEEK SHELTER! For I have set My face against you, O sons of men, and with a strong hand and an outstretched arm I shall surely punish the inhabitants of the earth!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Holy One of Israel:"},{t:"text",v:"Beloved, I have spoken to you firmly, and with a stern voice I have declared the controversy of The Lord; with a multitude of words and unending mercy, I have spoken and shall continue to speak. For I am The Lord, and I do not change. I do what is right, I alone know what is most needful. Thus I have called for a right heart within My servants, for My people to walk in My ways without reservation. Yet no pure works follow. Yes, I have called for works befitting a servant of The Lord. Yet the works of My people last only for a moment, then quickly pass away; works done out of obligation, works without trust, fruitless endeavors performed for the sake of pretense, in a vain effort to keep the door open. For My people have not known Me, neither do they have any love for God in their hearts; self-preservation is their only concern! BELOVED, AWAKE! Awake from your slumber! Awaken your hearts to The Majesty on High! Embrace the full revelation of WHO I AM, of all I have done! For the Word of The Lord flows like water, My love runs pure! Therefore embrace My words and receive of My love, that you may be filled with My spirit, to the bearing of much fruit in The Beloved!"}]},{type:"para",segments:[{t:"text",v:"Therefore hear and understand, receive of this Word and write this wisdom in your hearts. For upon these words does all life, all knowledge and all truth rest, even by which all things consist:"},{t:"italic",v:"I am The Way, The Truth, and The Life."},{t:"text",v:"And this is pure, undefiled love, the only means by which The Law of The Father may be fulfilled:"},{t:"italic",v:"You shall love The Lord your God with ALL your heart, with ALL your mind, with ALL your soul and with ALL your strength; and yes, beloved, you shall love your neighbor as yourself. For this is to walk in Me, this is to abide in Me, the only true religion in which is life."},{t:"text",v:"For apart from this is only enmity and rebellion against God, the ways of the world and the evil one, darkness of faces"},{t:"fn",v:"1"},{t:"text",v:", bringing forth much pain and death, a multitude of tears and sorrow. Beloved, it is time that My servants learn to walk in My strength, for the day is far spent. It is time for those I am sending to drink deeply from My cup and embrace Me fully, that My grace may cover them as they prepare My way before Me. Yet let all others fall away. Let the obstinate depart and the lukewarm pass to the wayside, until that which was planted at the first takes root, and that which was sown in the dry and cracked ground is watered once again. For I am coming quickly, and I will surely call out, and the first of many shall be gone from this place..."},{t:"italic",v:"Behold, I shall reveal My glory and the power of My strength, and the Word of The Lord shall speak! Desolations shall continue until the Consummation, and the hidden treasure shall appear out of the ground when I arise and shake the earth mightily! For as the shaking of an olive tree, or grape gleanings after the harvest, so shall I gather the remnant in the day of grief and bitter sorrow."}]},{type:"closing",text:"For I am The Lord..."},{type:"poetry",lines:[[{t:"italic",v:"I know what is most needful, I alone do what is right..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And though I afflict, I will also heal;"}],[{t:"italic",v:"And though I strike the people in My wrath,"}],[{t:"italic",v:"I will also bind up their wounds..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I shall bring the kingdoms of men to utter ruin,"}],[{t:"italic",v:"And make the face of the earth a desolation;"}],[{t:"italic",v:"For I AM HE who shall create new heavens"}],[{t:"italic",v:"And a new earth, in which justice shall run down"}],[{t:"italic",v:"Like water and righteousness like an ever-flowing stream..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as I have spoken, so I speak;"}],[{t:"italic",v:"As I am, so shall I be..."}]]},{type:"closing",text:"Says The King of Power and Glory, The Only Lord of Hosts, The Holy One of Israel."}],footnotes:{1:{type:"note",text:'Also read: "Darkness of Faces"',url:"https://trumpetcallofgodonline.com/index.php5?title=Darkness_of_Faces"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-calling-you-out-part-one",videoVoiceUrl:"https://www.youtube.com/watch?v=WRe6qWXPi5U&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=60",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"I Am Calling You Out",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:"Regarding Pollution and Mankind's Exploitation of the Earth",url:"https://answersonlygodcangive.com/Regarding_Pollution_and_Mankind%27s_Exploitation_of_the_Earth"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding The Holy Spirit",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"},{label:"Regarding the End Sign",url:"https://answersonlygodcangive.com/Regarding_the_End_Sign"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding The First Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:64,prevLetter:{id:"dividing-the-spoils",title:"Dividing the Spoils"},nextLetter:{id:"i-am-calling-you-out-part-2-come-out-of-the-churches-of-men-and-i-will-receive-you-says-the-lord",title:"I Am Calling You Out! (Part 2)... Come Out of the Churches of Men and I Will Receive You! Says The Lord"}},{id:"i-am-calling-you-out-part-2-come-out-of-the-churches-of-men-and-i-will-receive-you-says-the-lord",title:"I Am Calling You Out! (Part 2)... Come Out of the Churches of Men and I Will Receive You! Says The Lord",date:"10/7/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Hear the Word of The Lord; thus says The Lord:"},{t:"text",v:"Prepare your hearts, My people, yea cup your ears and listen, all you who call of yourselves Christian. Pay close attention and heed My words, for it is I, your Redeemer, who speaks. And behold, I shall indeed open My mouth once again, and the sound of the final trumpet before the time shall be heard; the line set, the division established, the last of My bride called forth, says The Lord. Yet what of all these who have not given heed to the sound of My voice, who do always turn away from My commands? What of all these who stiffen their necks and refuse to come out of the churches of men, people who hold fast in their pride, arrogant assemblies who have altogether forsaken The Lord their God? THEY SHALL SURELY DIE! Yet all those who call upon the name of The Lord in that day, in truth, with sincere remorse, shall be delivered, yet so as through fire. For I tell you the truth, there is indeed a death of a man unto death, and a death of a man unto life. Yet he who willingly forsakes his life in this world, for My sake, has already passed from judgment into life. Therefore I, even I, The Lord God of Heaven and Earth, am calling you out! I am calling you to come out from amongst them and to be separate; that you no longer be given to the fornications of the churches of men, nor be caught up in the filth of the pagan; that you cease from committing adultery with all these strange men of unclean lips, who dwell amongst a people of unclean lips, who cease not from polluting My name and My glory! Yet you will not come out, nor will you abandon this other way you have chosen! For you do always hold out the hand against the cleansing of the Spirit, you do always reject The Word of The Lord!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, because you have a harlot\u2019s forehead and refuse to be ashamed, and because you have altogether hardened your hearts against Me, hear the Word of My mouth and consider the indignation of The Lord:"},{t:"text",v:"I AM AGAINST YOU, O CHURCHES OF MEN! YES, EVEN I AM AGAINST YOU! I am against your leaders and your elders! I am against your congregations and your guest speakers! I am against your corrupt doctrines and your perverse traditions! I AM AGAINST YOU! Says The Lord. And of your forefathers, they shall surely answer for their subrogation of Me and My Word in the day they are called forth from the pit, when they stand up in their graves to give an account of their every word and deed which they performed in My name, to pollute it! Yet upon this generation, who say,"},{t:"italic",v:"\u201CWe are wide awake. Our eyes see, our ears hear, and our mouths speak the only truth,\u201D"},{t:"text",v:"I have already brought forth and purposed ruin. Yes, upon this generation and upon the churches of men, I have purposed great ruin! I have prepared destruction, and shall bring forth calamity upon all these houses which bear My name without permission! For I shall strip away every roof under which you have endeavored to take sanctuary, and break down every wall behind which you attempted to fortify your position! For you have surely rebelled against Me, desecrating the truth of who I am, all for the sake of your unjust cause! Behold, My judgment is declared already, and shall come, and on a day you do not expect and at an hour you did not look for, disaster shall break out suddenly against you! Behold, it shall overtake you in a moment, and in the twinkling of an eye the multitudes shall be undone! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"Churches of men, remove yourselves from My throne! Stop recreating Me in your own image! Draw back your hand from this other \u201CJesus\u201D you uphold! LET EVERY GRAVEN IMAGE FALL! LET EVERY IDOL SHATTER IN PIECES! Or did you think My eyes were shut to your transgressions? Did you think I would not see it?! And did you think I had turned away My ear from listening, and would not hear it?! FOR YOU HAVE SURELY SINNED AGAINST ME, O CHURCHES OF MEN! Therefore, I shall purge you and stir you up, I shall discipline you and wear you out! From the least of these houses to the greatest, I shall shake your every foundation, until every pillar which you have erected in your arrogance, to bring glory to your vanity, crumbles and comes crashing down, breaking in pieces before your eyes! FOR I AM THE LORD, AND I WILL NOT SHARE MY GLORY! Therefore let no man speak in the name of The Lord, unless I Myself have sent him! Unless I Myself have appointed him to speak, let him be quiet and open not his mouth! Lie not to yourselves, O pastors and preachers and leaders among men, for I know who I have sent and who I am sending! Lie not to yourselves, nor let any congregation attempt to place My name upon their blasphemies, as a cover to hide their adulteries, as they put The Holy One of Israel to an open shame! For I am The Lord, yes, I am He, AND I HAVE SEEN IT! For you have surely betrayed Me, O churches of men! You have altogether become as one who has committed treason! You are no bride; neither is there a woman of virtue among you! Behold, you are all harlots, daughters of fornication, women who demand payment for their services, heavy-laden women filled with iniquity, prisoners held captive by their own corrupt doctrines, chained by their own filthy traditions! - Doctrines and traditions at which the pagans laugh, jeering and laughing on account of that which you have borrowed from them, mixing the holy with the unholy, the clean with the unclean, and that which is to be held in great reverence with that which is contemptible, doctrines and traditions which I hate!"}]},{type:"poetry",lines:[[{t:"italic",v:"CHURCHES OF MEN, YOU ARE UNCLEAN!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus all you have built up for yourselves, of yourselves,"}],[{t:"italic",v:"To your own glory, has become meet for disaster,"}],[{t:"italic",v:"Destruction which comes quickly!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The Lord your God has spoken it, and so shall it be!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THEREFORE, COME OUT!"}]]},{type:"para",segments:[{t:"text",v:"Behold, even I shall speak it plainly once again, so you may escape:"},{t:"italic",v:"Sons and daughters of men, come out of the churches and be joined unto Me! For I am your only sanctuary, says The Lord."},{t:"text",v:"Yes I, your Redeemer, am calling you to come out of the churches of men, to be separate, and to no more worship Me in that way! - To no more touch the unclean thing! To no more let hypocrisy enter your ears! To no more sit in the company of those who pollute My name and lean upon their own understanding, who trust in their own righteousness as they sit upon self-made thrones of pride, a perverse and high-minded people who rest upon their own laurels by which they highly esteem themselves, seeking always the praise and glory of men. MY PEOPLE, COME OUT FROM AMONGST THEM! Run from all these who reject this Word and push out the hand against My messengers, who hold fast to all these doctrines of men, which I hate! Depart quickly from all these rebellious houses, who refuse correction and shut their eyes to truth! For they do always stop their ears from hearing the voice of The Lord their God, choosing rather to persecute and slander those I have sent to them! Behold, I have become as an idol to them, which they have formed in their own image! DESECRATION! GREAT BLASPHEMY! Therefore, because you have made for yourselves idols, many graven images, and because you have committed adultery as a wayward harlot, allowing men with suave tongues and clever lips to have their way with you, to be lords over you, men in authority who do always fight against Me in word and by deed, even to the persecuting of My messengers..."},{t:"italic",v:"Therefore, thus says The Lord: As you have become, and according to that for which you stand, so shall you be treated."}]},{type:"para",segments:[{t:"text",v:"Churches of men, you do continually crucify Me by all you say and do! Again and again, you put The Author of Life to an open shame, marring My image by your detestable doctrines, spitting upon Me by all your contemptible traditions, molding Me and shaping Me according to the dictates of your own evil hearts! Satan has deceived you and to his desires have you given heed, his lies have you propagated! He has never been on the side of truth, because there is no truth in him! Indeed, he is the father of all lies, and you have welcomed him in! Thus this generation does always disobey the voice of The Lord their God, nor will they receive of His correction! Truth has altogether perished among them; behold, it has been cut off from their mouths! Churches of men, shall you forsake The Commandments of God by permission in MY name, then turn to your brother and say,"},{t:"italic",v:"\u201CWe are delivered to do all these things,\u201D"},{t:"text",v:"making Me the author of your sins?! TOUCH NOT THE COMMANDMENT! DRAW BACK YOUR HAND FROM DESECRATING THE HOLY LAW! For that written by the finger of God was etched in everlasting stone and forged with eternal fire! Therefore woe to any man who attempts to alter the writing thereof, or render The Law of no effect! For death waits at the door, and the mouth of sheol is wide open, ready to receive him!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"I HAVE BROUGHT CHARGES AGAINST YOU, O CHURCHES OF MEN! And My judgment shall be swift, your discipline severe, and you shall all be broken in the day of your ruin! Indeed, judgment must begin at the temple of God, of which each one of you were to be. Thus it has been decreed and must be, it has commenced. Behold, the call has gone out and shall continue, until the first separation is made complete. Then shall that which I have purposed upon your houses immediately follow. Indeed, it has come forth already to shake you and to stir you up, that you might be moved from your places and come out, that you might fall hard upon your faces and repent. Oh My people, why do you stand defiant?! Why do you stiffen your necks and furrow your brows?! How is it you say you are My people, yet continue to shoot out the lip and shake the head, tempting The Lord your God?! For I tell you the truth, it shall by no means be finished, until every last one of your detestable sanctuaries is torn down and you are broken, until the loftiness of men is left in tatters and the rebellious are utterly devastated! For in that day, I shall surely turn My face against the earth and every inhabitant! Says The Lord. Behold, in that day I shall come down and murder every god of the Gentiles, to which they have prepared offerings and made sacrifices, to which they have prayed and bowed down, to which they have worshiped in vain! Even the god of the sons of Ishmael shall die in that day, for he is not God! HE LOOKS NOTHING LIKE ME! He is a facade of the devil, an elaborate deception of satan whose heart is wroth, whose ways are a never-ending offense! For at his heart he declares,"},{t:"italic",v:"\u201CI will profane the name of The Lord, and pollute the majesty of His being. Behold, I shall cause the nations to worship me and harken to my words; yea, I shall deceive the whole world. And who shall deliver them from my power, or from the many snares which I have set for them? And behold, men shall hate The God of Israel and loathe His chosen people. Yes, they shall gather unto me and to my servant, and we together shall build a great army. And darkness shall prevail rather than light, and The King who was and is and is to come shall be defeated.\u201D"},{t:"text",v:"BEHOLD, I AM AGAINST YOU, SATAN! SAYS THE LORD GOD. EVEN I, YAHUWAH, THE FATHER OF ALL NATIONS, AM AGAINST YOU! Thus you shall surely be brought down to shame! And as the beast of the field treads down the tall grass, so shall My people tread upon you! For of such are all your plans before Me, of such are all these false gods before Me - Dry grass! Here today and tomorrow thrown into the fire! I AM THE LORD! Behold, as I have purposed, so shall it be done. And that which I allow shall be also, yet only for a short season. For in that day and at that time, the name of The Lord of Hosts shall cause the whole world to shudder, and the sound of the voice of The Holy One shall slay many mighty and strong nations!..."},{t:"italic",v:"A great multitude of slain, driven through by the sword of His mouth, many ten thousands consumed and destroyed in the brightness of His coming, destruction from The Almighty! Says The Lord God."},{t:"text",v:"And oh how the earth shall groan in that day, for the whole earth shall heave and cast off the wickedness of men. The land shall shake violently and break apart, destroying all mankind has made. And behold, consuming fire shall come down from heaven, and cleanse the face of the whole earth, says The Lord. Then The Glory of The Lord shall come to rest upon the mountains of Israel. And behold, every valley shall be exalted, and every mountain and hill brought low; the crooked places shall be made straight, and the rough places smooth. For I am The Lord..."},{t:"italic",v:"Yes, I AM HE, He who secured the victory from the very foundation of the world, and pronounced Judgment before men came to dwell upon the earth; yes, I AM HE who has declared the end from the beginning, The Holy One who was and is and is to come, The Almighty, The Lord of all, The Creator of Heaven and Earth; even from everlasting to everlasting, I AM HE."}]},{type:"para",segments:[{t:"text",v:"Therefore, I ask you, who are all these who have opened their mouths foolishly, to reproach The Living God?! And who are all these who display a form of godliness, yet deny the power thereof?! What part do I have with all these houses, which are called by My name? And what part do I have with all these churches of men, who do always take the name of The Lord in vain by all they say and do?! I TELL YOU THE TRUTH, YOU ARE ALL AS FOREIGNERS TO ME! IMMANU EL HAS PASSED YOU BY! For I had poured out My spirit upon you, that you might be bathed in the light of My coming; behold, upon all flesh did I pour it out! Yet you would not receive of Me, nor would you come out. Instead you turned away from My leading, and shut the door when I came knocking. For you do always resist the Voice of Truth and refuse correction! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Churches of men, you have surely played the harlot, even as your mother has played the harlot, reveling in her fornications! From the beginning she has been a whore and played the harlot, receiving into herself many lovers! She has never been on the side of truth; deceits are found always in her mouth! Even those who came out of her, to point the finger, became like her! For there is nothing new under the sun, for the heart of man remains deceitful and wicked! And in his unending quest for power he grows ever more corrupt, as he strives always to enhance his self-perceived glory, that he might fulfill his ever-increasing lusts! Yet I tell you the truth, the reformers are cast down! Every one of them sleeps; in the pit they have all lain down. O great and lofty churches of men, you have enlarged yourselves! Your pomp reaches unto new heights, higher than your tallest steeple, by which you seek to pierce Heaven! Therefore, I shall surely cast you down; even all of you shall be made to sit upon the ground! For you do always resist My voice, and in your arrogance you reject My words, believing yourselves to be above reproach, deep-seated pride which chokes My Word and is quick to blaspheme My spirit! BEHOLD, YOU HAVE SURELY REPROACHED ME! Says The Lord. You have slandered My servants, and bore false witness in My name against Me and My messengers! For you say,"},{t:"italic",v:"\u201CSurely they have a demon! Yes, they have given heed to deceiving spirits, for God would never speak in such a manner!\u201D"},{t:"text",v:"Yet I tell you the truth, it is you who has given heed, it is you who has been greatly deceived! Therefore are My servants slain and My people given up to the blade. Yet you persist, and say,"},{t:"italic",v:"\u201CWE serve The Lord, WE are God\u2019s servants.\u201D"},{t:"text",v:"YOU HAVE SURELY SWORN FALSELY! For as I live, says The Lord, you have all spoken lies before Me! Thus as it was written of My people, Israel, so it is even unto this day with you:"},{t:"italic",v:"For you have grown fat, you are sleek. Yes, your deeds surpass those of the wicked. You do not plead the cause, the cause of the fatherless, yet you prosper, and the right of the needy you do not defend"},{t:"fn",v:"1"},{t:"italic",v:"..."},{t:"text",v:"Thus you are given up to the slaughter! Yes, you have all grown rich, very fat; you are swollen with pride! Your houses have become enlarged, spreading far and wide! Therefore every lofty house must be brought down, and every great and lavish church must be left in ruins! Behold, I shall tear you in pieces! Says The Lord. And in the day of My anger, I shall not withhold, for you have surely robbed Me! You have surely cast My people down, accounting them as spoils! Unfruitful servants, shall I not repay?! Shall I not punish you for all these things?!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I had caused My name to resound amongst"}],[{t:"italic",v:"The Gentiles, and among those in far nations"}],[{t:"italic",v:"The Holy One has had renown, yet what is this"}],[{t:"italic",v:"I see gathering strength throughout this generation?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Perversions of every kind celebrated openly in the streets!"}],[{t:"italic",v:"Multitudes who dwell gladly in the midst of Sodom"}],[{t:"italic",v:"And walk at ease amongst the people of Gomorrah!"}],[{t:"italic",v:"Behold, wayward nations cover the earth,"}],[{t:"italic",v:"And every church goes its own way!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore do you stand in judgment,"}],[{t:"italic",v:"O most perverse and deceitful generation!"}],[{t:"italic",v:"Therefore do I leave you to walk through"}],[{t:"italic",v:"The valley, O churches of men!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"FOR YOU HAVE ALL FORSAKEN ME!"}]]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, I have judged already, and am come to pass judgment. For I had called to you, O churches of men, saying,"},{t:"italic",v:"\u201CCome out and be separate,\u201D"},{t:"text",v:"yet you refused Me. As an obstinate child flailing in the midst of a tantrum, so have you refused to obey My voice, neither will you listen. Indeed, you are altogether unable to receive correction. Even as a stubborn ox which sits upon the ground and can not be moved, so are you amongst the churches of men, bullheaded and unmoving. Therefore, I will release you into the open field, and break up your fallow ground. And of all your finely crafted houses, they shall have no place, for only waste places shall be found..."},{t:"italic",v:"Where there was once laughter, behold, only wailing shall be heard; where there was once great riches, behold, only destitution shall remain; and where great teachers once stood, preaching loudly in My name, polluting it, behold, the sound of a great crash! ABASEMENT! Then silent lamentation, as all your works are burned up in the fire, declares The Lord."},{t:"text",v:"And now you raise your voices against Me once again, with renewed fervor, because of this Word. Thus I shall indeed punish you for all these things, I shall indeed stretch out My hand and break your pride. For as the firm hand of a father humbles a haughty daughter and disciplines an unruly son "},{t:"fn",v:"3"},{t:"text",v:" , so shall I deal with you, O churches of men. For you have surely forsaken Me! Says The Lord. Beloved, you have forgotten your God, and The Holy One, your Redeemer, has become unrecognizable to you! How then shall you escape?! How then shall you be delivered from all this death, which encompasses you round about? How then shall you hide from the destruction which comes quickly from on high, drawing ever closer to take away your life? For your ways and your teachings do always contradict sound doctrine. Indeed, your doctrines and traditions profane My holy name, as you further defile yourselves through your acceptance of pagan practices and myths, which have been passed down to you by your forefathers, men who were corrupters and given to corruption, false servants who committed adultery with the pagans and did not wholly separate themselves from the many harlotries of the Catholic Church..."},{t:"italic",v:"I tell you the truth, she shall be torn in pieces!"},{t:"text",v:"And yet all you churches of men remain like her, teaching always as doctrine the commandments of men, which has altogether turned you from The Truth. For you profess to know Me, yet by your works you deny Me, being disobedient, abominable, disqualified for every good work. Thus, as it was written of those who rebelled against Me at the first, so it remains concerning you at the last:"},{t:"italic",v:"Your mouths must be stopped. For you have subverted whole households, teaching things which you ought not, for the sake of dishonest gain."},{t:"fn",v:"2"},{t:"text",v:"For I tell you the truth, you have surely blasphemed the Spirit of God! Says The Lord. Thus I shall rebuke you sharply for your sins, by which you have rebelled against Me! I shall correct and discipline you for the multitude of your transgressions, by which you have robbed Me! For I have seen in your hearts malice and how you seek to hold others captive, how you hold their sins over their heads and cast judgment, as though it were a hook. Therefore do your sins remain! Therefore must your discipline be severe! For if I do not punish you for your iniquities, if I do not tear down all your houses and make you very poor and desolate, you can in no wise be joined unto Me, declares The Lord. For I have not forgotten you, nor will I forsake you utterly as the wicked. I will remember you, for I have known you; no, not as you are, but as you will be, when I have broken your pride and brought your haughtiness to the ground, in the day I rob you of all your riches, says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, I shall surely establish the line. And all on this side of the line shall be taken. And all on that side shall by no means escape, except through fire and tumult, until pure testimony flows from their lips and death comes to set them free; even as those who at present hold fast to the Testimony of YahuShua HaMashiach, and also keep The Commandments of God, have given up their lives for My sake. Thus all those who repent shall set themselves apart in that day, and they will keep that which they had forsaken. Yes, they shall honor The Law of The Father, which they had forsaken in My name. Yes, in that day they shall come to testify of Me as I really am! NO MORE shall they pollute My name or the glory of My majesty, in their own names! NO MORE shall they judge their neighbor harshly, with impudent hearts! NO MORE shall they mar My image among the people, by all these detestable doctrines and traditions! Yes, My beloved, you shall be made new, and all that you were shall pass away in that day. Your vain worship shall cease, and all wickedness shall be purged from the midst of you. And you shall be for Me a testimony and a witness, a great remnant who shall be given a new voice. For I shall put a new song in your mouths and cause your lips to burst forth with praise, even unto pure testimony in My name. And you shall lift up your voices boldly, causing the song to be heard throughout the city, until you fall asleep. Fear not, for though you die, you shall not sleep at all. For you shall be with Me in an instant, in the twinkling of an eye, in the day you give up your life..."},{t:"italic",v:"Having ceased from loving your life in this world, as one who in vain grasps at the wind, keeping it rather unto eternal life, the day your love is made perfect in The Beloved, the day you find solace upon the bosom of your Savior, The One who consoles your heart and wipes away all your tears."},{t:"text",v:"Therefore, I am sending out this last Trumpet before the time, increasing its sound, a final trumpet blast to warn the people, echoing in all the earth until the consummation. For behold, the Day of The Lord is about to overtake you, and the Great and Terrible Day is very near and shall overcome you, says The Lord. Behold, the judgments of God shall rain down from Heaven upon all who offend! For the wine of God\u2019s fury is poured out, full strength, into the chalice of His reckoning, and in His fierce anger He shall surely cause all in the earth to drink from it!"}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"I have indeed drawn the line and set the standard; I have indeed placed it in the midst of all people, says The Lord. And no one shall by any means pass over after the number has been fulfilled, when the first election is established. For in the days of Noah, there were many mockers and many who pushed out the lip, jeering and laughing, until the day Noah entered the ark and the door was shut. So shall it be with this wicked generation. The door shall be shut, and many shall be left standing outside, without a covering, with no shelter to protect them from the hard rains which are about to descend. For lo, I tell you a mystery which shall soon be made known: Those who come out before the time, who obey My voice, will pass to one side, and those who refuse to the other; one on this side, and many more to the other. And those who pass over to this side, joining those who remain on this side, shall be plucked up and hidden; yet some shall be replanted and serve. While those who refuse My voice, even to rebel against Me, shall remain on their own part, on the other side of the line which The Lord has drawn, left to endure the plight of their error. By this is the inner court and the outer court measured. And all found on the outer court shall surely die. For they are left outside, with no way in, though they falsely perceive themselves to be on the inside, with their backs set against the walls, placing all their faith in a house doomed to destruction, soon to be torn down. Yet those who come out from among them shall enter the inner court, though they are seen as outcasts and labeled falsely as heretics by their peers. Yet these shall surely live, escaping all these things which I am about to do, which I shall surely bring upon all the inhabitants of the earth. For indeed many are called, yet few are chosen, says The Lord. Even so, amen."}]},{type:"poetry",lines:[[{t:"italic",v:"THEREFORE COME OUT OF HER,"}],[{t:"italic",v:"MY PEOPLE, AND SURRENDER UNTO ME!"}],[{t:"italic",v:"Come out from among them, and be"}],[{t:"italic",v:"Separate from the churches of men!"}],[{t:"italic",v:"Touch no more the unclean thing,"}],[{t:"italic",v:"And I will receive you! Says The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Turn away from My voice no longer,"}],[{t:"italic",v:"To your own hurt, for the time is ending"}],[{t:"italic",v:"And the first of many must be taken;"}],[{t:"italic",v:"They must enter in, and the door must be shut;"}],[{t:"italic",v:"For judgment shall rain down from"}],[{t:"italic",v:"Heaven, filling the entire earth..."}]]},{type:"poetry",lines:[[{t:"italic",v:"COME OUT, THEREFORE,"}],[{t:"italic",v:"ALL YOU WHO HAVE EARS TO HEAR!"}],[{t:"italic",v:"Heed the sound of this Trumpet, and come out!"}],[{t:"italic",v:"For this is indeed the Trumpet Call of God!..."}]]},{type:"closing",text:"Says The Lord of Hosts, your Redeemer."}],footnotes:{1:{type:"scripture",ref:"Jeremiah 5:28"},2:{type:"scripture",ref:"Titus 1:11"},3:{type:"scripture",ref:"Proverbs 13:24 (KJV)"}},nkjv:{"Jeremiah 5:28":"They have grown fat, they are sleek; Yes, they surpass the deeds of the wicked; They do not plead the cause, The cause of the fatherless; Yet they prosper, And the right of the needy they do not defend.","Titus 1:11":"whose mouths must be stopped, who subvert whole households, teaching things which they ought not, for the sake of dishonest gain.","Proverbs 13:24 (KJV)":"He that spareth his rod hateth his son: but he that loveth him chasteneth him betimes."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-calling-you-out-part-two-come-out-of-the-churches-of-men-and-i-will-receive-you-says-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=xAKon-fj-Tc&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=76",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"The True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#Section_2_-_The_True_Bride"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"I Am Calling You Out",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Woe to the Churches of Men",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Churches_of_Men"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men"},{label:"Woe to Those Who Come Against God's Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding the Catholic Church",url:"https://answersonlygodcangive.com/Regarding_the_Catholic_Church"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"False Doctrines Within the Churches of Men (Index)",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven#Heaven"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding the Days of Noah",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah"}],num:65,prevLetter:{id:"i-am-calling-you-out-part-1",title:"I Am Calling You Out! (Part 1)"},nextLetter:{id:"the-last-trumpet-before-the-time",title:"The Last Trumpet Before The Time"}},{id:"the-last-trumpet-before-the-time",title:"The Last Trumpet Before The Time",date:"10/21/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"The trumpet I am blowing is revealed to the wise and enters into the heart of the humble, causing the penitent to shudder and the rebellious to burn with contempt. It is a trumpet of old, yet remains the trumpet of this time also. For My servant is soon entering his seventh year, and My Word and this Trumpet soon after. Lo, it is the seventh, and shall be blown for seven without ceasing, even as this seven sounds continuously before the time. Behold, is it not also that which I have revealed which remains holy in My eyes, the fulfillment which has been long, followed by three which shall come in rapid succession, the fulfillment thereof short yet everlasting, even as the seventh with an eighth yet to come?"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"I have trumpeted the call to awake, yet who has heard My call? Who has given heed and walked according to the will of The Lord? Wicked and slothful generation, DEAF CHILDREN, you have forsaken Me! For you have filled this world with every kind of evil; behold, you have reached new heights in wickedness! Thus I must blot out the kingdoms of men! I must wipe them away and cast them from My sight forever!..."},{t:"italic",v:"Never again shall they arise! Never again shall the nations do evil in My sight! Never again shall they walk proudly, shaking their fists toward Heaven in their self-proclaimed glory! Never again shall they revel in all these perversions and practice all these abominations, seeking always to satisfy their ever-increasing lusts as they pursue evil gain! FOR I AM THE LORD, AND I HAVE SEEN IT!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore I shall speak, and this Trumpet"}],[{t:"italic",v:"Shall sound continually until the time;"}],[{t:"italic",v:"And when it is finished, another shall sound..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And oh what a cry shall be heard,"}],[{t:"italic",v:"Oh what bitter weeping shall fill the streets;"}],[{t:"italic",v:"And like the sound of a plague of locusts"}],[{t:"italic",v:"Devouring every green thing, so shall the"}],[{t:"italic",v:"Sound of gnashing teeth devour the air;"}],[{t:"italic",v:"Behold, it shall break out in every"}],[{t:"italic",v:"Corner with a great noise!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet I shall continue to speak, and in My hot"}],[{t:"italic",v:"Displeasure I shall pronounce judgment upon them!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And whether they will hear, or whether they will forbear,"}],[{t:"italic",v:"The voice of YAHUWAH shall be heard!"}]]},{type:"para",segments:[{t:"text",v:"For I tell you the truth, this Trumpet before you is but the beginning, a whisper from The Almighty, a still small voice spoken in the ear. For the day is coming quickly when I shall speak My name aloud! Behold, I shall open My mouth and into the air I shall speak, and the heavens shall tremble and the earth shall shake violently! For none in the earth know Me, not one sees Me as I truly am. Yet all SHALL know Me! For by My judgments they shall know, and in My Mercy they shall see, says The Holy One, The God of Israel, The God of power and fierce jealousy, The God who has come forth from His sanctuary to punish, The God of Judgment! Behold, The Mighty One of Jacob has spoken in His authority, yet few have given heed, few have bowed down to give Me glory, few have cupped the ear. Therefore I shall speak louder, and the sound of My voice shall increase throughout the earth, and the days shall be turned into darkness before the Great and Terrible Day of The Lord! For in My anger, I shall turn My face against this awful generation, and in the fierceness of My wrath, I shall bring down My hand hard upon all peoples of the earth! And all these tall mountains shall crumble under the weight of My presence, and all these lofty hills shall be bowed down..."},{t:"italic",v:"Behold, the giants shall fall! Says The Lord. They shall be crushed beneath the weight of their fallen riches! Says The Almighty."},{t:"text",v:"Therefore look among the nations, O foolish people, and watch, O most wicked generation, and be utterly astounded, be horribly afraid! For The God of Recompense is risen up, The God of Glory is come out! Behold, I am risen up in My vengeance, I am come out to repay! For I have looked and I have seen; yes, I have beheld your hearts, and I have looked upon all your doings, and I HAVE SEEN IT! For nothing is hidden from My eyes, neither are My ears dull of hearing! Therefore be dismayed, O unfeeling generation, be dismayed, all you who have shown no mercy toward your neighbor, and tremble in fear at the indignation of The Lord! For behold, I shall kindle a fire in your courts that can not be quenched, and it shall rage, until every abomination is consumed and every wicked way perishes from before My face!..."},{t:"italic",v:"Let their faces be blackened with soot! Let the multitudes fall in their weariness! Says The Lord. For who can endure the Day of The Lord?! Who is able to escape the wrath of God when it comes?! Who has the stamina to flee continually, without respite?! Yet those who wait upon The Lord shall renew their strength; they shall mount up with wings like eagles, they shall run and not be weary, they shall walk and not faint, as it is written."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"My people, tears of great sorrow fill My eyes, as flames of fire are shown up behind them! For My face is crimson with fury and My heart burns in the depths of My rage, over that which is before My eyes day and night! PERSECUTION, MURDER and DEATH fills every corner! Behold, sin overtakes the land as a flood bursting forth from the HEARTS OF MEN! My people are slain and disemboweled and paraded through the streets, hung upon the walls as trophies and spoils of war, IN THE NAME OF THE GOD OF ABRAHAM, according to the name by which I am called among them! Yet I am not their God! And though I AM, even God alone, allah is NOT My name! For this allah is no god; he is an idol, the works of men written in a book, a graven image! Oh sons of Ishmael, you have all become sons of perdition, adopted children of satan, from which your religion came forth! Your prophet was deceived by the devil! At no time did he hear My voice, I sent no messenger to him! You are all deceived, acolytes of satan, sons of Cain! Did I not choose Isaac and send Ishmael away? Did I not preserve Isaac from sacrifice and provide the lamb? Was not Abraham\u2019s fear of The Lord perfect among his generations? Yet you do not fear Me, and for My people you have no regard! Is Israel a homeborn slave in your eyes?! Did Jacob steal your possession by treachery?! Or is it you who has rejected your inheritance?! Thus you are as reprobate silver to Me, and Israel shall be treasured among the nations! And He who sits upon the throne of David shall be Lord over you, forever, for on Mount Zion there shall be deliverance and holiness to The Lord! The descendants of Isaac shall possess your possessions, and the house of Jacob shall rule the land, for My Olive Tree shall overshadow all nations! Blessed, therefore, are all those who eat of it and seek shelter beneath its branches. Yet you only conceive violence in your heart against your neighbor, and murderous thoughts against your own brother! Behold, only hate fills your heart, and abhorrence runs through your veins like poison, a wild man without conscience! Thus your iniquity has not ceased, and your transgression is increased beyond measure! For it is written:"},{t:"italic",v:"Your hand shall be against every man, and every man\u2019s hand against you."},{t:"fn",v:"2"},{t:"text",v:"For you are full of pride, and your ego swells like water upon the flood plains of Egypt. Thus the pride of your heart has greatly deceived you. Therefore, I shall leave you desolate in the Day of Recompense! And in the day My witnesses stand up, upon you there shall be no rain, neither the former nor the latter! For I am against you! Says The God of Jacob. I have set My eyes upon you for harm, and not for good! For I shall surely return your reprisal upon your own head, and as you have done, so shall it be done to you! Shall I not cause the land to tremble before Me and sift you from the holy lands, dividing you asunder, allotting you your portion among those appointed to wrath?! For I shall surely slay all your mighty men of battle! Behold, even I shall bring your generation to a sudden end, leaving not one male among you above twenty years of age! For I shall surely turn your land into mourning and leave all your women childless! Yet among the heavy-laden, those who are severely oppressed because of you, I shall have mercy. For from among them I shall bring forth a remnant. For I have seen the hearts of the battered, and I know the minds of the oppressed; I have looked upon those with no hope, of whom you held captive from birth; I know who longs for Me. Behold, even I shall come forth from My place and deliver them, even every captive. For the tears of My people are great because of you, and the women among you weep because you are brutish, O sons of Ishmael! Thus I shall deliver them from your hand, and you shall be sent away, for you have not known Me! Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"O despicable peoples, REPENT, and turn"}],[{t:"italic",v:"Back from this wicked way you have chosen!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet you will not turn, nor will you forsake all these abominations!"}],[{t:"italic",v:"For you do continually plot evil against your brother, and your"}],[{t:"italic",v:"Hands do not cease from shedding innocent blood!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Your works are a foul stench in My nostrils, a detestable lump"}],[{t:"italic",v:"Under the skin, a putrefying sore that refuses to be healed!"}],[{t:"italic",v:"YOU ARE ALL DEAD IN MY EYES!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shall I not repay you for all these things,"}],[{t:"italic",v:"Even double?! Says The Lord God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Shall I not come down and tear you to pieces,"}],[{t:"italic",v:"For what you have done?! Says The God of Israel."}]]},{type:"para",segments:[{t:"text",v:"Shall I not destroy your lands and persecute your people with the sound of My voice, day and night?! Shall I not move swiftly and grind them to powder beneath the feet of The Holy One of Israel?! Shall I not come down and consume and destroy?! Thus it shall come to pass in that day:"},{t:"italic",v:"You shall fall, never to rise again, and it shall be as though you had never been! Declares YAHUWAH, The Only Lord of Hosts."},{t:"text",v:"And NO MORE shall there be any gods before Me! NO MORE shall anything, made by the hands of men, stand proudly before My face!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel:"},{t:"text",v:"My people are slain in every corner! Behold, they murder My messengers and tear My little ones to pieces, without remorse! Beloved, what would you have Me do?! What more could I have done?! I POURED OUT MY LIFE FOR THEM! Yet they refuse to drink! My body was broken for them, yet they refuse to eat! For I tell you the truth, they have utterly forsaken Me, ME, The Fountain of Living Waters! And for what, beloved? For what?! Look at what they do! Look how they greedily lust after every contemptible word and deed, filling their bellies with all this disgusting food, performing every abomination which I commanded they shall not do! They are a vile people, a most deceitful and wicked generation, the likes of which has never been seen! Yet I love them still. Even so, I must not withhold My punishment, and My judgment must be satisfied; evil must be utterly destroyed, it must be consumed from before My face. For if I do not do that which I have purposed in My heart to do, and if that which is stored up in the storehouses of My wrath is not poured out, mankind would surely destroy themselves by their own hand, leaving the garden uninhabitable! Therefore, I am come with a great trumpet blast to awaken the nations, to shake this world to its core..."},{t:"italic",v:"Behold, The Holy One shall shout with a loud command, and the light of this world shall be taken! The whole earth shall be shaken, a mighty earthquake, the Wrath of The Lamb revealed!"}]},{type:"para",segments:[{t:"bold-italic",v:"Now hear the Word of The Lord, those who say they are My people who are not My people; thus says The Lord:"},{t:"text",v:"Behold, My name is forsaken among the generation of My wrath, for My children have forgotten Me days without end! Even My own people, who say falsely that they are My people, do lie, for they are NOT My people! For My ways have become an abhorrence to them, nor will they obey My Commandments, and to My voice they refuse to listen! They are a people of deceits, a people of two faces, who run after every unclean thing! For they say,"},{t:"italic",v:"\u201CAs The Lord lives, we are delivered to do all these things.\u201D"},{t:"text",v:"Yet I shall surely deliver them to wrath! And as I live, says The Lord, they shall not escape the Day of My Anger! For they have polluted My name and desecrated the glory of The Holy One of Israel in the eyes of the people, taking that which is right and good and profaning it, as they continue to put Me to an open shame, to the confusion of many faces! Therefore I am against them! Behold, I have set My face against them, even against all who blaspheme My name and corrupt My Word for their own gain! For they have profaned My holy things, and by their doings have they brought shame upon themselves! Thus I shall continue to rebuke them, for I am against their every word and deed! And when I discipline them, I SHALL NOT SPARE! Behold, I am against you, O churches of men! For My ways have become an abhorrence to you! Yes, you proclaim it by all your filthy traditions, of which I hate, and by every corrupt doctrine you uphold do you set your faces against Me! Behold, by all you say and do is your rebellion put on open display, your uncleanness is clearly seen! Thus YOUR ways have become an abhorrence to ME! Says The Lord. Therefore, I shall surely correct you and bring upon you swift discipline, even recompense for all your evil deeds, in where you have caused My name to be blasphemed among the nations! For with a strong hand and a firm rebuke shall I turn you back from your ways, and recover you from your transgressions!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, with many strong words and"}],[{t:"italic",v:"A stretched out hand shall I abase you!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As a mighty wind breaks off the branches and a"}],[{t:"italic",v:"Swirling wind topples the tall trees, so shall the"}],[{t:"italic",v:"Sound of My voice break you and the strength"}],[{t:"italic",v:"Of My hand humble you in the Day of The Lord!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"With a great thrashing, this way and that,"}],[{t:"italic",v:"Shall you be broken in pieces!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the world shall be turned upside down"}],[{t:"italic",v:"In My fury, and the nations shall fall on their side"}],[{t:"italic",v:"Under the weight of My punishment! Says The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I have surely declared it, and I also shall"}],[{t:"italic",v:"Bring it to pass, even before the eyes of this"}],[{t:"italic",v:"Arrogant and most wicked generation!..."}]]},{type:"closing",text:"FOR I AM THE LORD!"},{type:"para",segments:[{t:"text",v:"For many have played the harlot, many have set themselves up as an authority among men, even to speak as though they were God, proclaiming the will of The Lord with many lofty and vain speeches. Yea, with a great multitude of words they speak as though I had sent them. Yes, they speak in My name, though NOT ONE OF THEM has heard My voice, nor did I send them! Therefore, I have numbered their speeches and remembered their every idle word, which I have accounted against them! Yet My people are not at all ashamed of their offenses, nor will they give heed to My words which I have spoken to this generation, nor are they willing to turn from their sinful ways! For My people do continually transgress, and do always rebel against Me! Thus they are NOT My people! Says The Lord. Behold, in one accord they persecute My prophets and slander My messengers! Lo, they fight against Me, in their own names, saying,"},{t:"italic",v:"\u201CWe shall be justified in our actions, when The Lord comes to punish these messengers and repay these false prophets. For we hate the sound of their voices, and their words torment us without cause.\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"I am indeed come out to punish, I am indeed come down to repay, each one according to their words which they have spoken against Me and My messengers, each one according to their deeds which they have committed against Me and My prophets! For they provoke Me with their words, and by their deeds have they brought My anger to the full! They have forsaken The Fountain of Living Waters and want no more to drink, neither will they swallow! They cast down righteousness to the earth and turn justice to wormwood! For they hate the one who brings The Lord\u2019s Rebuke to the gate, and abhor the one who speaks a true message from God! Lo, they tread upon those who walk uprightly and shun those who obey The Lord\u2019s Commands! Behold, they stone their own brothers and injure their own sisters with their words! Therefore, they shall come to know Me in My bitterness! For I hate all their lavish houses, I detest all their sacred assemblies, nor do I savor their feasts! Their traditions are an abhorrence to Me, and their holidays I despise in My zeal! Thus when I stretch out My hand against them, and lift up My voice against their congregations, they shall fall; even they shall be the first among those who fall! Says The Lord. Tell Me then, by what means shall they rise again? For there shall be no place that is not made desolate, no place which is not consumed by plague and famine! There shall be no open place, for destruction and calamity shall overtake the whole land! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"Behold, what an obscene thing this is before My eyes! What a horrible sound has entered My ears! What a detestable sight is on display, amongst this people who are NOT My people! What an awful spewing is brought forth from this modern generation! MY NAME IS BLASPHEMED BECAUSE OF THEM! In all the world My name is despised and used as a cursing! It is treated like an abomination which offends, a thing to be cast off and forgotten, a name which shall not be mentioned! Behold, even these among the churches of men have endeavored to make The Holy One of Israel in their own image, molding Him by deceitful hands, to their own hurt! -"},{t:"italic",v:"A molded idol, a graven image, which they have given a name to hide their guilt: DESECRATION; even the very name for which they are called: LAWLESSNESS."},{t:"text",v:"For they excuse sin in the name of The Holy One, and forsake My Commandments and My every decree in the name of The Messiah, The Righteous One! They are a polluted people, rejected, until the time be changed! And according to that which their own hearts reveal shall I deal with them, for they testify against themselves! Says The Lord. For they have not known Me, neither do I see of Myself in them. Yes, by their hearts and by their doings they do always testify against themselves! For in their hearts, they say,"},{t:"italic",v:"\u201CLook upon us; see how we have become righteous in our own eyes.\u201D"},{t:"text",v:"Even by all they say and do, they declare,"},{t:"italic",v:"\u201CWe have forsaken The Law of The Father, in the name of The Son; yes, He has made it possible for us to do so. And by His permission do we forsake His every statute and ignore His every decree, that we may pollute the name of The Living God without ceasing.\u201D"},{t:"text",v:"Foolish children, diseased and awful generation, you are all captives, none of you are set free! Lo, you have signed the document of your own sentences, which shall be severe! Behold, you remain on the side of your own judgment, nodding your heads in agreement! Therefore, according to the number of your churches shall be your judgment, and according to the number of your adulteries shall be your punishment, O house of harlots, O daughters of fornication! And according to the words of your own mouths shall be the severity, and according to THIS Word, which you have rejected, shall be the length of your refinement. Behold, I shall not spare the rod, nor shall the strength of My arm be held back in My discipline!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord against every foul tree which bears rotten fruit, enticing My people to eat, that they might stretch out their hand in rebellion against The Lord:"},{t:"text",v:"Behold, you have joined yourselves to another, and in his ways you have chosen to walk; yes, you have all become the children of your father, the devil! Thus all you keep hidden and surmise in the dark shall be put on open display, for the Day shall surely declare it! And all you have built shall crumble, all your works shall burn, and with a great crash shall you be cut down! Says The Lord in His indignation. My beloved children, why do you rend the heart of God?! For you have surely torn the heart of My flesh, by which I have loved you beyond compare! For you have dealt with Me deceitfully, and by treachery you have led My children astray! And for what price? For what gain?!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"YOU HAVE SLANDERED ME! And have brought against My messengers and My servants, the prophets, which I Myself have sent to you, many evil and false accusations; behold, you accuse your brethren day and night! For I have looked upon the fury of your hearts by which you are enslaved, I have beheld your bitter ignorance and all your perverse thoughts and desires, and I have seen your arrogance, how it overflows your pride-ridden hearts! Yes, I have looked upon you, O churches of men, all you \u201CChristians\u201D who fight against Me, going out and coming in, seeking always new ways to stone My prophets and persecute My servants, the elect! I have seen that which dwells within you, and oh what a sight I have seen, what an obscene thing this is before My face! - DEMONS going out and coming in! DEMONS finding sanctuary in the churches of men! Shall I not tear down?! Shall I not repay?! Shall I not destroy every polluted sanctuary and overthrow every city which stands proud against Me?! Lo, My heart is very heavy over all these people called by the name of The Anointed One, yet they do not cease from arousing Me to anger! They are drunken, their own bitter wine has inflamed them! Behold, they are eager to do that which I have said they shall not do; yes, they love to indulge in that which is against Me! For they run to their houses, which are falsely called by My name, to hear every speaker which comes in by treachery, speaking to them in their own names! They run and sit down and cup their ears to listen, that they might hear just one tittle to justify their evil deeds, to soothe their itching ears, so they may continue to dwell gladly in their transgressions, as they seek to coax others into their rebellion! BEHOLD, I AM AGAINST THEM! I am against any man or woman who seeks to uplift their own name, saying,"},{t:"italic",v:"\u201CThe Lord has sent me,\u201D"},{t:"text",v:"and,"},{t:"italic",v:"\u201CIt is The Lord\u2019s will, it is the will of The Lord; hear what The Lord wills for us.\u201D"},{t:"text",v:"I am against all who place stumbling blocks before the feet of My people in My name, twisting My words to perpetuate persecution toward My servants and My messengers! Behold, those who wish ill upon MY bride shall be left in astonishment, left all alone in their turmoil! They shall be bowed down, with their backs bent, crying out,"},{t:"italic",v:"\u201CWhen did I become a harlot? When did I become estranged from my Husband? How is it I am now come into all this punishment? Am I not a queen, having done that which is right? For I have defended the name of The Lord and His Word, and received much gain; look at all these on my part. Yet here I sit in ruin, in a puddle of My own tears... O Lord, why have you forsaken Me? Why does death now stalk me as the prey?\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"My name is YAHUWAH!"}],[{t:"italic",v:"Yet you children in the churches have not known Me;"}],[{t:"italic",v:"Indeed you have forsaken Me, days without end!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My name is JUDGMENT and WRATH!"}],[{t:"italic",v:"Yet you children of disobedience do not fear Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"My name is YAHUSHUA, MERCY and GREAT LOVE!"}],[{t:"italic",v:"Yet you who were to be My bride refuse Me,"}],[{t:"italic",v:"Neither have you kissed Me upon My cheek!"}]]},{type:"para",segments:[{t:"text",v:"And if you are My bride, why have you not given yourself to Me and taken My name, proclaiming you are Mine in joyful expectation? Yet you are ashamed of Me and refuse to look upon My face. For as I am so shall I be, and this is not at all to your liking. For you prefer the face of your molded image, and have fallen in love with your graven images. Thus you are estranged from your God, far removed! Therefore, the face of your Husband is turned from you, for you have not ceased from playing the harlot with many lovers! Even with many tears He has shut the door to you, until the time be changed."}]},{type:"para",segments:[{t:"italic",v:"Return to Me, My children! Come to Me in the Day and cool My tears! For My heart is burdened because of you, My countenance has fallen on your account! Tears run down My cheeks and fall heavily upon the earth, a most bitter lamentation! For I, even I have loved you! Says The Lord. Cry out therefore, and I shall send to you My beacons; behold, by their hand have I called to you many times already. Yes, these are the very same over which your hearts have waxed gross, the very same by which you shall receive these words anew, even the Word of My mouth. For I am not without mercy. And though of your houses I shall make a full end, I shall not make a full end of you. And though I break you, and you lie down in death for My name\u2019s sake, I will not forsake you utterly as the wicked. For they shall go into perpetual darkness, a void of lifeless nothingness, forever. No, I will not leave you to the worms who devour, nor allow your flesh to rot, nor shall any man tread upon your corpses. Behold, I shall gather you to Myself, and you shall wail upon My bosom, with many tears, until your soul runs dry and you are healed. And never again shall you walk in the ways of the world and men, nor in evil, to your own hurt. From Me you shall never again depart, and in MY life you shall walk all of your days, until time has lost all meaning, even forever and ever, singing songs to the praise of My glory. And you shall be My joy, says The Lord who made you, even He who purchased you in My own blood. For as The Son is one with The Father, and The Father with The Son, so shall you be one in Him and Him in you, forever. Thus as it is written, so shall it be: I will dwell in them and walk among them. I will be their God, and they shall be My people."},{t:"fn",v:"3"},{t:"italic",v:"Amen."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore this Trumpet, which is"}],[{t:"italic",v:"Of these seven and is also the seventh,"}],[{t:"italic",v:"Shall be blown loudly until the time..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then all must grow quiet at My command,"}],[{t:"italic",v:"Making way for the next to sound..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"scripture",ref:"Isaiah 40:31"},2:{type:"scripture",ref:"Genesis 16:12"},3:{type:"scripture",ref:"Leviticus 26:12, Jeremiah 32:38, Ezekiel 37:27"}},nkjv:{"Isaiah 40:31":"But those who wait on the LORD Shall renew their strength; They shall mount up with wings like eagles, They shall run and not be weary, They shall walk and not faint.","Genesis 16:12":"He shall be a wild man; His hand shall be against every man, And every man\u2019s hand against him. And he shall dwell in the presence of all his brethren.\u201D","Leviticus 26:12, Jeremiah 32:38, Ezekiel 37:27":"Leviticus 26:12 \u2014 I will walk among you and be your God, and you shall be My people. | Jeremiah 32:38 \u2014 They shall be My people, and I will be their God; | Ezekiel 37:27 \u2014 My tabernacle also shall be with them; indeed I will be their God, and they shall be My people."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-last-trumpet-before-the-time",videoVoiceUrl:"https://www.youtube.com/watch?v=_ZgRhEA9ZR8&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=102",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Voice of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Voice_of_The_Lord"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Woe to Those Who Come Against Israel",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_Israel"},{label:"Regarding the Two Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_Two_Witnesses"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"False Doctrines Within the Churches (Index)",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"Woe to Those Who Come Against God's Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Woe to Those Who Bear False Witness in The Lord\u2019s Name",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Bear_False_Witness_in_The_Lord.E2.80.99s_Name"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#The_True_Bride"},{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:66,prevLetter:{id:"i-am-calling-you-out-part-2-come-out-of-the-churches-of-men-and-i-will-receive-you-says-the-lord",title:"I Am Calling You Out! (Part 2)... Come Out of the Churches of Men and I Will Receive You! Says The Lord"},nextLetter:null}],LETTERS_TIMOTHY_PREFACE={id:"put-all-your-trust-in-the-holy-one",title:"Put All Your Trust in The Holy One",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"poetry",lines:[[{t:"italic",v:"Fear God and put"}],[{t:"italic",v:"All your trust in The Holy One..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the power of The Father is displayed"}],[{t:"italic",v:"Through The Son, for He is the express image"}],[{t:"italic",v:"Of The Holy, The Salvation of God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"He whose hand reaches far and wide,"}],[{t:"italic",v:"Whose strength is almighty, whose wisdom"}],[{t:"italic",v:"Holds all creation in His understanding,"}],[{t:"italic",v:"Whose love endures forever!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"He whose righteousness comes,"}],[{t:"italic",v:"And had been stretched out before us,"}],[{t:"italic",v:"For every eye to see..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The end of which shall be as a flood"}],[{t:"italic",v:"cleansing The sanctuary of His mercy,"}],[{t:"italic",v:"Restoring all things, even to a"}],[{t:"italic",v:"New heavens and a new earth."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/put-all-your-trust-in-the-holy-one",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/put-all-your-trust-in-the-holy?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=TolSnMA4PG8&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=1",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"}],isPreface:!0},LETTERS_TIMOTHY=[{id:"timothy-s-vision-of-yahushua-jesus-standing-upon-the-world",title:"Timothy\u2019s Vision of YahuShua (Jesus) Standing upon the World",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"6/22/05 Timothy\u2019s Vision of YahuShua Standing upon the World"}]},{type:"para",segments:[{t:"text",v:"I saw great suffering of men, women and children, in several countries I did not recognize. I also saw many horrible things being done to Christians in those lands. Then I saw a giant sandaled foot, with its heel on Africa, about to step down on very tall figures. The other sandaled foot was over Israel, but not touching it or stepping down on it. I know the sandaled feet belonged to YahuShua, because I could also see the rest of Him. His height went all the way into the heavens, and He was wearing a white robe."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/timothys-vision-of-yahushua-standing-upon-the-world",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/timothys-vision-of-yahushua?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=Z-0OQtVh5rg&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding Africa",url:"https://answersonlygodcangive.com/Regarding_Africa"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Visions",url:"https://answersonlygodcangive.com/Visions"}],num:1,prevLetter:null,nextLetter:{id:"the-shadow-of-the-almighty",title:"The Shadow of The Almighty"}},{id:"the-shadow-of-the-almighty",title:"The Shadow of The Almighty",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"6/22/05 The Interpretation of the Vision Given to Timothy For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"text",v:"Who can move the foot of The Holy One of Israel, once it has been placed and purposed? Who has the power to fight against God?! For all live under the shadow of The Almighty - whether in judgment, or under the shadow of His healing wings."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, let every high man be bowed down"}],[{t:"italic",v:"And every oppressor be broken in pieces,"}],[{t:"italic",v:"Says The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Let all who stand so tall and lofty,"}],[{t:"italic",v:"With hearts firm and unyielding,"}],[{t:"italic",v:"Be crushed beneath My feet,"}],[{t:"italic",v:"Until only dust and ashes remain,"}],[{t:"italic",v:"Says The Almighty..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet let the penitent receive their reward,"}],[{t:"italic",v:"Let them abide at My feet in peace,"}],[{t:"italic",v:"Until that which is written is completed"}],[{t:"italic",v:"And that which was prophesied comes to pass,"}],[{t:"italic",v:"Says The Holy One of Israel."}]]}],footnotes:{1:{type:"note",text:"Also read: \u201CTimothy\u2019s Vision of YahuShua (Jesus) Standing upon the World\u201D",url:"https://www.thevolumesoftruth.com/Timothys_Vision_of_YahuShua_Standing_upon_the_World",link:{collection:"Letters from Timothy",letterTitle:"Timothy\u2019s Vision of YahuShua (Jesus) Standing upon the World"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-shadow-of-the-almighty",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-shadow-of-the-almighty?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=Z-0OQtVh5rg&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=2",videoMusicUrl:"https://www.youtube.com/watch?v=BN96UpS-FcE&list=PLE8FlkxQPQkOKqEMycTZOwj2BAyqj6HwU&index=1",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding Africa",url:"https://answersonlygodcangive.com/Regarding_Africa"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Visions",url:"https://answersonlygodcangive.com/Visions"}],num:2,prevLetter:{id:"timothy-s-vision-of-yahushua-jesus-standing-upon-the-world",title:"Timothy\u2019s Vision of YahuShua (Jesus) Standing upon the World"},nextLetter:{id:"stealing-from-the-power-of-the-cross",title:"Stealing from the Power of the Cross"}},{id:"stealing-from-the-power-of-the-cross",title:"Stealing from the Power of the Cross",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"7/10/05 Wisdom Given to Timothy For All Those Who Have Ears to Hear Addendum to \u201C The True Baptism \u201D"}]},{type:"para",segments:[{t:"text",v:"Listen, all you who hold baptism in such high regard, even as a measuring stick by which you count others worthy or unworthy, according to your own perverse interpretation of the Scriptures, for here is wisdom:"},{t:"italic",v:"Whosoever God has cleansed is worthy; you shall not call them unworthy."},{t:"fn",v:"1"},{t:"text",v:"For baptism by water was given to men as an outward testimony of one\u2019s commitment to God, in The Messiah\u2019s name, and also for union in fellowship within the body of Messiah. Therefore be wary of any doctrine which steals from the power of the cross, as though the sacrifice of The Messiah was not enough."}]},{type:"poetry",lines:[[{t:"italic",v:"What is earthly, let it stay earthly;"}],[{t:"italic",v:"And what is spiritual, let it stay spiritual..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Hold not to the earthly nor to the"}],[{t:"italic",v:"Understanding of men, nor grab hold"}],[{t:"italic",v:"Of any private interpretation of Scripture;"}],[{t:"italic",v:"Trust not in the doctrines of men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Hold fast to God,"}],[{t:"italic",v:"And place all your trust in The Messiah."}]]}],footnotes:{1:{type:"scripture",ref:"Acts 10:15"}},nkjv:{"Acts 10:15":'And a voice came to him again the second time, "What God has cleansed you must not call common."'},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/stealing-from-the-power-of-the-cross",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/stealing-from-the-power-of-the?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=AbVM4xhJeZU&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=3",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Baptism",url:"https://answersonlygodcangive.com/Regarding_Baptism"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"God Speaks Regarding Those Who Steal From Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Steal_From_Him"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"False Doctrines Within the Churches of Men Regarding - Baptism",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."}],num:3,prevLetter:{id:"the-shadow-of-the-almighty",title:"The Shadow of The Almighty"},nextLetter:{id:"the-origin-of-life",title:"The Origin of Life"}},{id:"the-origin-of-life",title:"The Origin of Life",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"1/18/06 An Exhortation from Timothy For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"text",v:"Sing and offer up praises to The Lord your God, for there is no other! Behold, the earth is filled with His glory; from the vast expanses, to the smallest corner, the earth reveals the craft of His hands! Let all the inhabitants of the earth proclaim the glory of The Lord, therefore! For all creation exalts His holy name, many loud voices singing together in concert, to the glory of His majesty!"}]},{type:"para",segments:[{t:"text",v:"Behold, He shouts to you from on high, His glory assaults you on every side; even within, look, He is there! For in you are all things written, within your very being, delicately etched there by The Right Hand of God. There is no escape from His glory! Apart from His Glory is only darkness and death; apart from Him all things cease to exist. For He alone causes all things to be."}]},{type:"para",segments:[{t:"text",v:"The vastness of His glory is not hidden! It shines forth from the infinitely small to the infinitely large, for God has no end - HE IS The Creator! And YAHUSHUA is your Carpenter,"},{t:"italic",v:"the image of The Invisible God, The Firstborn over all creation. For by Him were all things created, both visible and invisible, in Heaven and on Earth; whether thrones or dominions, or principalities or powers, all things that are and were created were created through Him and for Him. For He is before all things, and in Him do all things consist, as it is written."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"God is The Origin of Life! - The Creator of Heaven and Earth, of all that is known and unknown, YAHUWAH, He who causes to be. Thus YAHUSHUA is the answer you search for, The Very Meaning of Life - The Only Begotten of The Father, God in the flesh, Immanu El, He through whom you were made."}]},{type:"para",segments:[{t:"text",v:"Therefore continue your search, and you shall discover the truth, which is God. Dissect life\u2019s structures; there He is, its writer and fashioner. Look deeper and farther than ever before, and there you will find Him. Calculate and count all things which are before your eyes, yes, search the cosmos, study it, and you will begin to know Him. No matter where you point your lenses, there He is, within the scope of your understanding."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, all discoveries lead to God!"}],[{t:"italic",v:"Though you need not seek, nor discover,"}],[{t:"italic",v:"For the knowledge of God is within you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet only the shedding of the skin"}],[{t:"italic",v:"Of this world and the death of your pride"}],[{t:"italic",v:"Shall open your eyes to The Truth -"}],[{t:"italic",v:"Which is absolute, forever standing"}],[{t:"italic",v:"On a hill, bright and shining,"}],[{t:"italic",v:"Immovable, unbreakable!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Everlasting Stone which has"}],[{t:"italic",v:"Become The Head of the Corner,"}],[{t:"italic",v:"The Great Mountain which"}],[{t:"italic",v:"Fills the whole earth!"}]]}],footnotes:{1:{type:"scripture",ref:"Colossians 1:15-17"}},nkjv:{"Colossians 1:15-17":"15. He is the image of the invisible God, the firstborn over all creation. 16. For by Him all things were created that are in heaven and that are on earth, visible and invisible, whether thrones or dominions or principalities or powers. All things were created through Him and for Him. 17. And He is before all things, and in Him all things consist."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-origin-of-life",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-origin-of-life?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=u5D6jR3N8zI&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"Regarding Science",url:"https://answersonlygodcangive.com/Regarding_Science"}],num:4,prevLetter:{id:"stealing-from-the-power-of-the-cross",title:"Stealing from the Power of the Cross"},nextLetter:{id:"yahushua-hamashiach-is-king",title:"YahuShua HaMashiach Is King"}},{id:"yahushua-hamashiach-is-king",title:"YahuShua HaMashiach Is King",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"2/6/06 Wisdom Given to Timothy For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"text",v:"YahuShua is The Gift; in Him is life. All others lead only to darkness and death, a fleeing away from The True Light, which is YahuShua The Messiah."},{t:"italic",v:"For He is the wonderful new thing born of a virgin, as it is written."},{t:"fn",v:"1"},{t:"text",v:"Behold, He is the fulfillment of all things, The Only Messiah and Lord, fulfilling all written and spoken of Him from the beginning - the very same as God, begotten as The Son, Immanu El. He is also The Word, which is and was and is to come, The Word of God Almighty. For by The Word are you saved, and by this same Word shall the wicked be destroyed. For they have rejected The Author of Life, and want no part with Him through Whom they were made. Thus they have chosen death and not Life - their inheritance lost, their names blotted out. For though He was God in the flesh, He gave Himself up to the smiters, that all nations under God might be saved through Him; He being the foundation and fulfillment of all prophecy, the end of which is The Kingdom. For He is The Kingdom, The Power and The Glory, and by Him alone shall you enter in, sharing in His life and His joy, forever and ever."}]},{type:"para",segments:[{t:"text",v:"Thus as the stars in the heavens are beyond the numbering of men, a glory beyond our understanding, so also is the Glory of The Messiah. For He, being The Only Begotten of The Father, is also the fulfillment of The Word of God and the prophets throughout all generations, the fulfillment of which is also beyond the reason and comprehension of men. Therefore let these things fulfilled in The Son of Man, though mentioned in few, be for a sign to awaken the slumberers. Yet to those of greater understanding, who have been awakened to the knowledge of these things fulfilled in The Son of Man, prophesied, coming to light as a multitude, let it be a wonder. Yet to those who are fully awake, who having received the knowledge and love of the Truth, knowing The Messiah fulfills all in every sense, in all manner, every word written, every word spoken, every action within and without, being altogether The All in All of all things, let it be truth undeniable! - Causing all, both great and small, rich and poor, bond and free, to bow down before Him, calling Him Lord!"}]},{type:"poetry",lines:[[{t:"italic",v:"For this truth is an emblazoned torch,"}],[{t:"italic",v:"A waving banner,"}],[{t:"italic",v:"An ensign to all generations,"}],[{t:"italic",v:"Beyond all question!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For HE IS WHO HE IS,"}],[{t:"italic",v:"And there is none like Him!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YahuShua HaMashiach,"}],[{t:"italic",v:"The Holy One of Israel..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YOUR KING!"}]]},{type:"para",segments:[{t:"italic",v:"Behold, The Messiah had come and is returning; lo, He is coming quickly and shall also appear. Watch therefore, and behold the mighty and awesome power of The Holy One of Israel. For He shall sit upon the throne of His glory, and every knee shall bow. For the will of God shall be done on Earth as in Heaven."}]}],footnotes:{1:{type:"scripture",ref:"Isaiah 9:6; Isaiah 43:19; Isaiah 7:14"}},nkjv:{"Isaiah 9:6; Isaiah 43:19; Isaiah 7:14":"9:6 \u2014 For unto us a Child is born, Unto us a Son is given; And the government will be upon His shoulder. And His name will be called Wonderful, Counselor, Mighty God, Everlasting Father, Prince of Peace. | 43:19 \u2014 Behold, I will do a new thing, Now it shall spring forth; Shall you not know it? I will even make a road in the wilderness And rivers in the desert. | 7:14 \u2014 Therefore the Lord Himself will give you a sign: Behold, the virgin shall conceive and bear a Son, and shall call His name Immanuel."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/yahushua-hamashiach-is-king",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/yahushua-hamashiach-is-king?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=Jq85kkDHdZE&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"}],num:5,prevLetter:{id:"the-origin-of-life",title:"The Origin of Life"},nextLetter:{id:"my-redeemer-lives",title:"My Redeemer Lives"}},{id:"my-redeemer-lives",title:"My Redeemer Lives",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"4/11/06 A Prayer of Timothy For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"text",v:"My God, my God, You are holy! Oh my Redeemer, my beloved Savior, YahuShua, by Your blood am I washed from sin\u2019s raiment, which had clothed me in death. By Your sacrifice You freed me, Your great love has broken my bonds. Behold, a new light has appeared where once there was only darkness, the flame which flickered burns bright once again, for in my heart You have kindled a fire! And Your words, Lord, Your beautiful words, they are truly a lamp for my feet. And by following Your teaching, I have begun to unleaven my life; though by Your sacrifice, You have already freed me from the power of sin. O Lord, YOU are my righteousness! I will obey Your Word! And though I stumble, I will not cease from striving to obey; I want to do what is pleasing in Your sight; help me walk in Your ways. I feel Your hand upon me, O Lord. I offer myself to You, my Lord and my God. Take my life; it\u2019s Yours! You offered Yourself up to suffering and death, on account of what I have done. I deserve my punishment, yet You bore my sins on the tree, even the sins of those I love. I can not approach Your love, but by any and all means, I shall strive to show You my love and my gratitude. I leave my heart open to You; mold it, create in me a pure heart, for I long to see Your face. Renew in me a right spirit, that I may be steadfast for Your purpose and walk in Your ways. You are the love of my life, of which I had forgotten. How wealthy I was in my innocence, how blessed I was in my youth. How could I have departed?! How could I have turned away?! I weep, I cry, because of that place which was left barren inside me, a place the world could never fill, leaving me broken and void - my heart hardened, my countenance bitter. Yet You filled me with wonder and awe, a love I never thought possible - My heart softened, my countenance lifted, my spirit brightened, as Your life rushed in. And Your voice, the beautiful sound of Your voice..."},{t:"italic",v:"Lord, You stir my soul, You light my soul on fire, a love which this world has not known."},{t:"text",v:"Why, O Lord, do You bless me so?! I have sinned greatly in my life; I have broken Your Commandments, and desecrated Your name and this temple You gave me, yet You never forsook me. What have I done to deserve such mercy, such unfathomable joy, such overwhelming love in Your presence? You are my Lord and my God, my life! The sound of Your name, even mentioned in a whisper, brings tears to my eyes. The pronouncement of Your judgment terrifies my soul, yet I welcome it and feel safe. You are so utterly beautiful! I love You. I love You! I can not stand, I fall to my knees, I am so completely unworthy of Your grace, yet by Your grace You saved me - a broken vessel of great dishonor, yet You gathered me up, reviving me, breathing life into me once again, restoring my soul. My God, oh my God, You are The Holy! None compare! No one! Nothing! Lord, I shall wait for You, I will stand firm for You, unyielding in my commitment! I am only a man, yet I know You are with me."}]},{type:"poetry",lines:[[{t:"italic",v:"Lord, I put You to death, You bore my sin in Your own body;"}],[{t:"italic",v:"You were broken and bruised for my transgressions,"}],[{t:"italic",v:"And by Your stripes am I healed..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Before I was born, You knew me and died for me,"}],[{t:"italic",v:"Though I did not ask You."}]]},{type:"para",segments:[{t:"text",v:"Oh my Lord, how many tears must I cry?! How many times can I say, \u201CI love You\u201D?! I shall never cease! With my dying breath, I will proclaim my love for You! And if it is Your will that I not die, I shall sing of my Beloved forever, even forever and ever; I shall trumpet it to every tribe, tongue, people and nation! Give the command and show me the way; fill my heart with Your spirit, O Lord, take control of my mouth! Speak, oh my Lord! Shout, oh my God! Make me a vessel of honor, that I may bring glory to Your name! Lord, lift me up from my wickedness, for I am wretched. Deliver me from this body of death, for my flesh deceives me, I have gone astray. Set Your Truth within me, O Lord; purge my soul! In the name of YahuShua I beseech You; break me by the power of Your words, destroy me with Your love, let me die in Your presence! Lord, cultivate Your Word in me, let the dew of Heaven cover my shame and wash away all I have done. O Lord, set me upright. For I can not raise my head, lest I look upon Your glory. I can not stand, my strength is gone from me. Yet in my weakness, I know Your strength is made perfect; yes, Lord, Your grace is sufficient for me. Light my path, O Lord, for I walk in darkness. I feel the adversary on every side, he bruises me..."},{t:"italic",v:"Help me, O God! In the name of Him crucified, in the name of Him who was hung on the tree, The Greatest of All Loves, be my help and my shield!"},{t:"text",v:"I am but a lost child, Lord. I am consumed with fear and sadness, when I do not hear Your voice. I am swallowed up in sorrow, when I am not in Your presence. For I have heard the voice of The Holy One, I have felt Your hand upon me. I am just a man, so very unclean, yet You embrace me. Woe is me, Lord! Woe is me! Surely my eyes shall go blind, for I have looked upon Your glory, I have beheld Your image! The earth has become pale, an empty wasteland, for I have seen The King! Shut my eyes, Lord, let me never open them again, let me never forget! Stop my ears also, for I have heard Your voice! Yet even now, I hear You comforting me, saying,"},{t:"italic",v:"\u201CWhat The Lord has cleansed is worthy. Call it not unworthy. Rejoice, O son of men, you have been redeemed from the earth as part of the special offering. Again I say, rejoice, and sound the trumpet, for The Redemption draws near.\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"O Lord, how shall I thank You for all You have done?"}],[{t:"italic",v:"I haven\u2019t the words to express my gratitude"}],[{t:"italic",v:"For what You did for me on the cross;"}],[{t:"italic",v:"I am forever indebted to You..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You are my Passover,"}],[{t:"italic",v:"You rescued me from death,"}],[{t:"italic",v:"You restored my soul..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Oh my God, my God,"}],[{t:"italic",v:"In the name of YahuShua my Savior,"}],[{t:"italic",v:"I say, amen, forever amen..."}]]},{type:"poetry",lines:[[{t:"italic",v:"MY REDEEMER LIVES!"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/my-redeemer-lives",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/my-redeemer-lives?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=nOC0lyzaefY&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=6",videoMusicUrl:"https://www.youtube.com/watch?v=FOCZsGf-SSY&list=PLE8FlkxQPQkND8PrAIRI5ghd4pMj21-pF&index=1",relatedTopics:[{label:"Regarding Prayer",url:"https://answersonlygodcangive.com/Regarding_Prayer"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Forgiveness",url:"https://answersonlygodcangive.com/Regarding_Forgiveness"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Patience",url:"https://answersonlygodcangive.com/Regarding_Patience"},{label:"Regarding the Voice of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Voice_of_The_Lord"}],num:6,prevLetter:{id:"yahushua-hamashiach-is-king",title:"YahuShua HaMashiach Is King"},nextLetter:{id:"tithing",title:"Tithing"}},{id:"tithing",title:"Tithing",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"1/26/07 Wisdom Given to Timothy For a Sister in Christ, and For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"text",v:"Abraham gave a tenth of all he had to Melchizedek, king of Salem; and later a portion was also given of the tribes of Israel to the Levites, so they may serve God without hindrance. Yet today the voice of God is not with His people as it was then, for it is written:"},{t:"italic",v:"The heart of this people has waxed gross, their ears are very dull of hearing and their eyes they have shut, lest at any time they should see with their eyes and hear with their ears and understand with their heart, and be fully converted, and I should heal them, says The Lord."},{t:"fn",v:"1"},{t:"text",v:"Therefore give directly to the poor, as your heart leads you, for this is well-pleasing to The Lord. For no servant of God shall profit by monetary means, but shall profit only by that which The Lord gives. And what He gives is true, and in no wise is it of men or mammon."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"Beloved, I delight in that which one gives to another in My name, and by the works of their own hands and feet in all righteousness; this is the tithe in which I delight most. Therefore if one comes to you, saying,"},{t:"italic",v:"\u201CGive me a cup of water,\u201D"},{t:"text",v:"give them a drink in My name."},{t:"fn",v:"2"},{t:"text",v:"And if another comes, saying,"},{t:"italic",v:"\u201CI need clothes, for I am cold and naked,\u201D"},{t:"text",v:"clothe them"},{t:"fn",v:"3"},{t:"text",v:", and give them your coat also."},{t:"fn",v:"4"},{t:"text",v:"And if this same one asks,"},{t:"italic",v:"\u201CWill you walk with me this far?\u201D"},{t:"text",v:"Go with them double."},{t:"fn",v:"5"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore tithe not only of your money"}],[{t:"italic",v:"And material possessions, but also"}],[{t:"italic",v:"Of your strength and your time,"}],[{t:"italic",v:"As one willing to give up"}],[{t:"italic",v:"Their life for My sake..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For this is to truly know Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"This is to walk in Me, in My very footsteps,"}],[{t:"italic",v:"And to love your neighbor as yourself"},{t:"fn",v:"6"},{t:"italic",v:","}],[{t:"italic",v:"Says The Lord YahuShua."}]]}],footnotes:{1:{type:"scripture",ref:"Isaiah 6:10; Matthew 13:15; Acts 28:27"},2:{type:"scripture",ref:"Mark 9:41"},3:{type:"scripture",ref:"Matthew 25:36-40"},4:{type:"scripture",ref:"Matthew 5:40"},5:{type:"scripture",ref:"Matthew 5:41"},6:{type:"scripture",ref:"Matthew 22:39"}},nkjv:{"Isaiah 6:10; Matthew 13:15; Acts 28:27":"Isaiah 6:10 \u2014 \u201CMake the heart of this people dull, And their ears heavy, And shut their eyes; Lest they see with their eyes, And hear with their ears, And understand with their heart, And return and be healed.\u201D | Matthew 13:15 \u2014 For the hearts of this people have grown dull. Their ears are hard of hearing, And their eyes they have closed, Lest they should see with their eyes and hear with their ears, Lest they should understand with their hearts and turn, So that I should heal them.\u2019 | Acts 28:27 \u2014 For the hearts of this people have grown dull. Their ears are hard of hearing, And their eyes they have closed, Lest they should see with their eyes and hear with their ears, Lest they should understand with their hearts and turn, So that I should heal them.\u201D \u2019","Mark 9:41":"For whoever gives you a cup of water to drink in My name, because you belong to Christ, assuredly, I say to you, he will by no means lose his reward.","Matthew 25:36-40":"36. I was naked and you clothed Me; I was sick and you visited Me; I was in prison and you came to Me.\u2019 37. \u201CThen the righteous will answer Him, saying, \u2018Lord, when did we see You hungry and feed You, or thirsty and give You drink? 38. When did we see You a stranger and take You in, or naked and clothe You? 39. Or when did we see You sick, or in prison, and come to You?\u2019 40. And the King will answer and say to them, \u2018Assuredly, I say to you, inasmuch as you did it to one of the least of these My brethren, you did it to Me.\u2019","Matthew 5:40":"If anyone wants to sue you and take away your tunic, let him have your cloak also.","Matthew 5:41":"And whoever compels you to go one mile, go with him two.","Matthew 22:39":"And the second is like it: \u2018You shall love your neighbor as yourself.\u2019"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/tithing",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/tithing?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Tithing",url:"https://answersonlygodcangive.com/Regarding_Tithing"}],num:7,prevLetter:{id:"my-redeemer-lives",title:"My Redeemer Lives"},nextLetter:{id:"remember-the-sabbath-day-to-keep-it-holy",title:"Remember The Sabbath Day, to Keep It Holy"}},{id:"remember-the-sabbath-day-to-keep-it-holy",title:"Remember The Sabbath Day, to Keep It Holy",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"2/15/07 Wisdom Given to Timothy For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"text",v:"If one who loves The Lord dedicates a certain day to The Lord, yet is ignorant regarding the Fourth Commandment, or has been led astray by false teaching in the churches of men, then to The Lord the day is indeed dedicated. For this is acceptable and well-pleasing to The Lord, because of the intent of their heart; to them it will be accounted as righteousness. Yet if another who is not ignorant of the truth, and was not led astray by the churches of men, comes forward and says,"},{t:"italic",v:"\u201CI also dedicate this certain day to The Lord,\u201D"},{t:"text",v:"and it is the correct day, the seventh (Saturday), according to the Fourth Commandment, but does so as a mere outward display to gain honor for themselves, elevating themselves above others, judging those they perceive as less worthy because of their error, to them it shall be accounted as shame. For though they kept the Sabbath outwardly, they did not keep it inwardly, nor to The Lord was it truly dedicated, having not kept the Sabbath at all. Yet the one who remains humble and sincere, though they are in error, will in time see the Truth,"},{t:"italic",v:"and keep the Seventh Day holy as it is written."},{t:"fn",v:"1"},{t:"text",v:"For they had already kept it in their heart. For it is far easier to move someone whose heart is in the right place to the correct day, than to move someone with a wrong heart to a place that is right, if they feel they already abide there."}]},{type:"para",segments:[{t:"text",v:"Yet remember this: All who have been awakened to the Truth must now walk in it..."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"Beloved, walk uprightly in Me, in My very footsteps. Abide in My doctrine, according to the faith and knowledge you have received in Me. Progress toward perfection, with all trust. Keep The Commandments, as you testify to the Truth by your example. Yet no more walk in the ways of this world, nor in the doctrines and traditions of the churches, for they are corrupt; obey not the commandments of men."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, seek and you shall surely find,"}],[{t:"italic",v:"For all you need is written for your"}],[{t:"italic",v:"Edification in the Scriptures of Truth..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And behold, even by these many Letters,"}],[{t:"italic",v:"Which are of the same, have I set"}],[{t:"italic",v:"All these crooked paths straight..."}],[{t:"stanza-break"}],[{t:"italic",v:"Says The Lord."}]]}],footnotes:{1:{type:"scripture",ref:"Exodus 20:8-11"}},nkjv:{"Exodus 20:8-11":"8. \u201CRemember the Sabbath day, to keep it holy. 9. Six days you shall labor and do all your work, 10. but the seventh day is the Sabbath of the LORD your God. In it you shall do no work: you, nor your son, nor your daughter, nor your male servant, nor your female servant, nor your cattle, nor your stranger who is within your gates. 11. For in six days the LORD made the heavens and the earth, the sea, and all that is in them, and rested the seventh day. Therefore the LORD blessed the Sabbath day and hallowed it."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/remember-the-sabbath-day-to-keep-it-holy",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/remember-the-sabbath-day-to?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=YLx2WA-UQvQ&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"About The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],num:8,prevLetter:{id:"tithing",title:"Tithing"},nextLetter:{id:"atonement",title:"Atonement"}},{id:"atonement",title:"Atonement",date:"",from:"",spoken:"",forLine:"",noteLine:"(Regarding The Day of Atonement)",blocks:[{type:"para",segments:[{t:"italic",v:"2010 Wisdom Given to Timothy For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear (Regarding The Day of Atonement)"}]},{type:"para",segments:[{t:"text",v:"Let this day be an offering of abstinence in purity to The Lord, a giving of thanks for your sins atoned for by The Messiah YahuShua; not atonement for your sins, of yourselves, but a free will offering in the name of The Lord your God and Him crucified, rejoicing in the anticipation of The Blessed Hope. And behold, He shall sit upon the throne of His glory and judge the nations. He shall utterly destroy all wickedness from this world, wiping away all that is sin and that which has led His people astray."}]},{type:"poetry",lines:[[{t:"italic",v:"And that which was shut shall be opened,"}],[{t:"italic",v:"And that which was open shall be shut in that Day,"}],[{t:"italic",v:"Says The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/atonement",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/atonement?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=W5M1VWf_sVc&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=6",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"}],num:9,prevLetter:{id:"remember-the-sabbath-day-to-keep-it-holy",title:"Remember The Sabbath Day, to Keep It Holy"},nextLetter:{id:"humble-yourselves-in-the-sight-of-the-king",title:"Humble Yourselves in the Sight of The King"}},{id:"humble-yourselves-in-the-sight-of-the-king",title:"Humble Yourselves in the Sight of The King",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"7/5/10 An Exhortation from Timothy For All Those Who Have Ears to Hear Addendum to \u201C The Alarm of War \u201D"}]},{type:"para",segments:[{t:"text",v:"Behold, The Everlasting had come down to us, Immanu El; yes, God in the flesh, YahuShua, the express image of The Holy, the face of The Invisible God, He through whom all things were brought forth and by whom all things consist. And behold, He shall strike the great image and break apart the nations. For He is The Kingdom, The Power and The Glory! Therefore woe to the inhabitants of the earth, for The Holy One is coming to take His spoil and to pour out judgment. Behold, He shall pour out, until the wrath of God is complete. He shall roar mightily in battle and shake the earth! For the earth trembles at His coming and heaves at His presence. It collapses before the power of His vesture and gives way, breaking apart under His feet. The islands flee away before the power of His might, and the mountains crumble at the backward swipe of His hand. For the footsteps of The Lord shall quake upon the earth, until all in the earth are humbled, until every inhabitant falls down heavily and confesses Him King, The Only Lord of Hosts..."}]},{type:"para",segments:[{t:"italic",v:"Behold the power of God\u2019s right hand! Tremble in fear before the might of His Holy One and shed many tears! For the feet of The Son of Man shall tread heavily upon the earth! He shall tread upon great and mighty nations, and the slain of The Lord shall be great, many ten-thousands cut asunder by the sword of His mouth! Fear The Lord, therefore! Humble yourselves in the sight of The King!"}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/humble-yourselves-in-the-sight-of-the-king",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/humble-yourselves-in-the-sight?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=00cMsoX7bl4&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:10,prevLetter:{id:"atonement",title:"Atonement"},nextLetter:{id:"fear-god-and-put-all-your-trust-in-the-holy-one",title:"Fear God, and Put All Your Trust in The Holy One"}},{id:"fear-god-and-put-all-your-trust-in-the-holy-one",title:"Fear God, and Put All Your Trust in The Holy One",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"12/13/10 An Exhortation from Timothy For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"text",v:"The heart of The Lord is angered by what He has seen and enraged by what He has heard. The heat of His fury shall melt the high places and turn the wicked to ash, scattering them upon the waste places. Behold, the wrath of God burns like the terrible mountain. It builds and is about to burst forth from its hold. It comes forth as roiling clouds and thunder, and with great swiftness it rushes down the slopes, releasing its fury upon all in the path of its destruction. It is great and very dreadful, a suffocating plague covering the cities. For ages it has been silent, building strength. For a multitude of days, its terrible heat has been restrained, its great power hidden beneath the weight of the mountain, ready to break forth in due season, bringing great calamity at the time appointed. For of such is the indignation of The Father, of such is the strength of The Son. For the strength of The Son is manifest in His glory and by the power of His Word spoken in judgment - a sharp double-edged sword unsheathed, striking all nations who gather against Him, piercing blows dividing them asunder, consuming fire from The Almighty upon all His enemies. For the Day of The Lord is here, and is about to come in. Behold, the Great Day is near, and who shall stand? Who shall prevent the hand of The Mashiach from gathering His own? Who can endure the Day of His Anger, or prevent The Holy One from coming in His strength? What army can withstand Him or the power of His sword? For they shall all be as wax before the fire, when the power and brilliance of The Lord is put on open display."}]},{type:"para",segments:[{t:"text",v:"Therefore fear God, and put all your trust in The Holy One. For the power of The Father is displayed through The Son. For He is the express image of The Holy, The Salvation of God - He whose hand reaches far and wide, whose strength is almighty, whose wisdom holds all creation in His understanding, whose love endures forever; He whose righteousness comes and had been stretched out before us, for every eye to see, the end of which shall be as a flood cleansing the sanctuary of His mercy, restoring all things, even to a new heavens and a new earth. Behold, it is time for the power of God to be made known, for the name of The Holy One of Israel to be glorified above the heights of the mountains, to overshadow every hill! It is time for The King to return and gather, to reveal the glory of His might! - Immanu El!"}]},{type:"poetry",lines:[[{t:"italic",v:"Yes YAHUSHUA, The Rock,"}],[{t:"italic",v:"The Stone Everlasting, is coming quickly"}],[{t:"italic",v:"To strike the great image, to break apart"}],[{t:"italic",v:"Every foundation, to spread forth like a flood,"}],[{t:"italic",v:"Until only The Great Mountain remains!"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then shall they know,"}],[{t:"italic",v:"The Father and The Son are one!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the earth shall be full of"}],[{t:"italic",v:"The knowledge of YAHUWAH\u2019s glory,"}],[{t:"italic",v:"As the water covers the depths of the sea!"},{t:"fn",v:"2"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written, so shall it be..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Maranatha!"}]]}],footnotes:{1:{type:"scripture",ref:"Daniel 2"},2:{type:"scripture",ref:"Isaiah 11:9"}},nkjv:{"Daniel 2":"1. Now in the second year of Nebuchadnezzar\u2019s reign, Nebuchadnezzar had dreams; and his spirit was so troubled that his sleep left him. 2. Then the king gave the command to call the magicians, the astrologers, the sorcerers, and the Chaldeans to tell the king his dreams. So they came and stood before the king. 3. And the king said to them, \u201CI have had a dream, and my spirit is anxious to know the dream.\u201D 4. Then the Chaldeans spoke to the king in Aramaic, \u201CO king, live forever! Tell your servants the dream, and we will give the interpretation.\u201D 5. The king answered and said to the Chaldeans, \u201CMy decision is firm: if you do not make known the dream to me, and its interpretation, you shall be cut in pieces, and your houses shall be made an ash heap. 6. However, if you tell the dream and its interpretation, you shall receive from me gifts, rewards, and great honor. Therefore tell me the dream and its interpretation.\u201D 7. They answered again and said, \u201CLet the king tell his servants the dream, and we will give its interpretation.\u201D 8. The king answered and said, \u201CI know for certain that you would gain time, because you see that my decision is firm: 9. if you do not make known the dream to me, there is only one decree for you! For you have agreed to speak lying and corrupt words before me till the time has changed. Therefore tell me the dream, and I shall know that you can give me its interpretation.\u201D 10. The Chaldeans answered the king, and said, \u201CThere is not a man on earth who can tell the king\u2019s matter; therefore no king, lord, or ruler has ever asked such things of any magician, astrologer, or Chaldean. 11. It is a difficult thing that the king requests, and there is no other who can tell it to the king except the gods, whose dwelling is not with flesh.\u201D 12. For this reason the king was angry and very furious, and gave the command to destroy all the wise men of Babylon. 13. So the decree went out, and they began killing the wise men; and they sought Daniel and his companions, to kill them. 14. Then with counsel and wisdom Daniel answered Arioch, the captain of the king\u2019s guard, who had gone out to kill the wise men of Babylon; 15. he answered and said to Arioch the king\u2019s captain, \u201CWhy is the decree from the king so urgent?\u201D Then Arioch made the decision known to Daniel. 16. So Daniel went in and asked the king to give him time, that he might tell the king the interpretation. 17. Then Daniel went to his house, and made the decision known to Hananiah, Mishael, and Azariah, his companions, 18. that they might seek mercies from the God of heaven concerning this secret, so that Daniel and his companions might not perish with the rest of the wise men of Babylon. 19. Then the secret was revealed to Daniel in a night vision. So Daniel blessed the God of heaven. 20. Daniel answered and said:  \u201CBlessed be the name of God forever and ever,  For wisdom and might are His. 21. And He changes the times and the seasons;  He removes kings and raises up kings;  He gives wisdom to the wise And knowledge to those who have understanding. 22.  He reveals deep and secret things;  He knows what is in the darkness, And light dwells with Him. 23. \u201CI thank You and praise You, O God of my fathers; You have given me wisdom and might, And have now made known to me what we asked of You, For You have made known to us the king\u2019s demand.\u201D 24. Therefore Daniel went to Arioch, whom the king had appointed to destroy the wise men of Babylon. He went and said thus to him: \u201CDo not destroy the wise men of Babylon; take me before the king, and I will tell the king the interpretation.\u201D 25. Then Arioch quickly brought Daniel before the king, and said thus to him, \u201CI have found a man of the captives of Judah, who will make known to the king the interpretation.\u201D 26. The king answered and said to Daniel, whose name was Belteshazzar, \u201CAre you able to make known to me the dream which I have seen, and its interpretation?\u201D 27. Daniel answered in the presence of the king, and said, \u201CThe secret which the king has demanded, the wise men, the astrologers, the magicians, and the soothsayers cannot declare to the king. 28. But there is a God in heaven who reveals secrets, and He has made known to King Nebuchadnezzar what will be in the latter days. Your dream, and the visions of your head upon your bed, were these: 29. As for you, O king, thoughts came to your mind while on your bed, about what would come to pass after this; and He who reveals secrets has made known to you what will be. 30. But as for me, this secret has not been revealed to me because I have more wisdom than anyone living, but for our sakes who make known the interpretation to the king, and that you may know the thoughts of your heart. 31. \u201CYou, O king, were watching; and behold, a great image! This great image, whose splendor was excellent, stood before you; and its form was awesome. 32. This image\u2019s head was of fine gold, its chest and arms of silver, its belly and thighs of bronze, 33. its legs of iron, its feet partly of iron and partly of clay. 34. You watched while a stone was cut out without hands, which struck the image on its feet of iron and clay, and broke them in pieces. 35. Then the iron, the clay, the bronze, the silver, and the gold were crushed together, and became like chaff from the summer threshing floors; the wind carried them away so that no trace of them was found. And the stone that struck the image became a great mountain and filled the whole earth. 36. \u201CThis is the dream. Now we will tell the interpretation of it before the king. 37. You, O king, are a king of kings. For the God of heaven has given you a kingdom, power, strength, and glory; 38. and wherever the children of men dwell, or the beasts of the field and the birds of the heaven, He has given them into your hand, and has made you ruler over them all\u2014 you are this head of gold. 39. But after you shall arise another kingdom inferior to yours; then another, a third kingdom of bronze, which shall rule over all the earth. 40. And the fourth kingdom shall be as strong as iron, inasmuch as iron breaks in pieces and shatters everything; and like iron that crushes, that kingdom will break in pieces and crush all the others. 41. Whereas you saw the feet and toes, partly of potter\u2019s clay and partly of iron, the kingdom shall be divided; yet the strength of the iron shall be in it, just as you saw the iron mixed with ceramic clay. 42. And as the toes of the feet were partly of iron and partly of clay, so the kingdom shall be partly strong and partly fragile. 43. As you saw iron mixed with ceramic clay, they will mingle with the seed of men; but they will not adhere to one another, just as iron does not mix with clay. 44. And in the days of these kings the God of heaven will set up a kingdom which shall never be destroyed; and the kingdom shall not be left to other people; it shall break in pieces and consume all these kingdoms, and it shall stand forever. 45. Inasmuch as you saw that the stone was cut out of the mountain without hands, and that it broke in pieces the iron, the bronze, the clay, the silver, and the gold\u2014the great God has made known to the king what will come to pass after this. The dream is certain, and its interpretation is sure.\u201D 46.  Then King Nebuchadnezzar fell on his face, prostrate before Daniel, and commanded that they should present an offering and incense to him. 47. The king answered Daniel, and said, \u201CTruly your God is the God of gods, the Lord of kings, and a revealer of secrets, since you could reveal this secret.\u201D 48. Then the king promoted Daniel and gave him many great gifts; and he made him ruler over the whole province of Babylon, and chief administrator over all the wise men of Babylon. 49. Also Daniel petitioned the king, and he set Shadrach, Meshach, and Abed-Nego over the affairs of the province of Babylon; but Daniel sat in the gate of the king.","Isaiah 11:9":"They shall not hurt nor destroy in all My holy mountain, For the earth shall be full of the knowledge of the LORD As the waters cover the sea."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/fear-god-and-put-all-your-trust-in-the-holy-one",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/fear-god-and-put-all-your?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=iy8nj1XZ1h0&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=8",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:'The Coming of The Lord - "I Am Coming Quickly"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_Am_Coming_Quickly"}],num:11,prevLetter:{id:"humble-yourselves-in-the-sight-of-the-king",title:"Humble Yourselves in the Sight of The King"},nextLetter:{id:"the-unending-fountain",title:"The Unending Fountain"}},{id:"the-unending-fountain",title:"The Unending Fountain",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"6/5/11 A Vision Given to Timothy For All Those Who Have Eyes to See and Ears to Hear"}]},{type:"para",segments:[{t:"italic",v:"[YahuShua]"},{t:"text",v:"Timothy, what do you see?"}]},{type:"para",segments:[{t:"italic",v:"[Timothy]"},{t:"text",v:"I see, Lord! I see! I am in the temple, facing outward toward the entrance. The doors are opening and the brilliance of Your glory is flooding the room. Before me is the altar, and upon it I see a white napkin. It is being folded without hands. There is water being poured out of the air just above it. The water is beautiful and sparkling. It is being poured upon the napkin, but doesn\u2019t seem to be reaching it... Lord, I am thirsty. May I drink from this fountain?"}]},{type:"para",segments:[{t:"italic",v:"[YahuShua]"},{t:"text",v:"You may not yet drink from it. It is reserved for the bride at the time appointed."}]},{type:"para",segments:[{t:"italic",v:"[Timothy]"},{t:"text",v:"Lord, I am very thirsty."}]},{type:"para",segments:[{t:"italic",v:"[YahuShua]"},{t:"text",v:"Take the napkin in your hand. Is it not wet, My son?"}]},{type:"para",segments:[{t:"italic",v:"[Timothy]"},{t:"text",v:"Yes, Lord."}]},{type:"para",segments:[{t:"italic",v:"[YahuShua]"},{t:"text",v:"From it shall you drink. Place it flat in your hand, and bring it to your lips when you thirst. Inhale deeply through your nose, then place the napkin between your lips and drink. Drink deeply, My son, for it is time. Now place it within the pocket of your robe and take it with you, that you may also wring it out on the thirsty; share it with all you meet. For the dampness thereof shall never run dry, no matter the number of times you use it; nor will it wear thin, nor tear, nor can its surface be blemished."}]},{type:"para",segments:[{t:"italic",v:"[Timothy]"},{t:"text",v:"Thank You, Lord."}]},{type:"para",segments:[{t:"italic",v:"[Timothy]"},{t:"text",v:"Lord, I see you in front of me! I see the back of You!... YahuShua!"}]},{type:"para",segments:[{t:"italic",v:"[YahuShua]"},{t:"text",v:"Follow Me."},{t:"fn",v:"1"}]}],footnotes:{1:{type:"note",text:"Note: As He said the words, \u201CFollow Me,\u201D He walked into a bright light. I was moving toward Him, but I was not walking or using my legs. The vision ended, just short of the temple doors. His presence lifted, and His voice became quiet."}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-unending-fountain",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-unending-fountain?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Visions",url:"https://answersonlygodcangive.com/Visions"}],num:12,prevLetter:{id:"fear-god-and-put-all-your-trust-in-the-holy-one",title:"Fear God, and Put All Your Trust in The Holy One"},nextLetter:{id:"the-parable-of-the-great-landowner-and-his-beloved-sheep",title:"The Parable of The Great Landowner and His Beloved Sheep"}},{id:"the-parable-of-the-great-landowner-and-his-beloved-sheep",title:"The Parable of The Great Landowner and His Beloved Sheep",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"7/23/11 A Parable Given to Timothy For All Those Who Have Ears to Hear"}]},{type:"para",segments:[{t:"text",v:"The Kingdom of Heaven is like a landowner who had a large field full of sheep, sheep of every kind and many young lambs. The landowner loved his sheep and treasured his young lambs. Yet in his field, he noticed that many sheep had become ill due to disease, and others had wandered off. Behold, many wolves were there also, stealing his sheep and killing his lambs. Therefore he sent his chief shepherd into the field, to call to his sheep and to every lamb, to gather them together. He was told to wait as long as possible, that every sheep who had wandered off might have a chance to hear the call, and return. The shepherd waited patiently, until all who knew the sound of His voice had gathered to him. Then at the time appointed, the shepherd took them out of the field, setting them in safety, apart from all that offends. Then the landowner came forth from his house, in great anger and haste, and slew every ravaging wolf and burned the field with fire, purging it of all disease."}]},{type:"para",segments:[{t:"italic",v:"Therefore, let those who have ears to hear, hear, and also understand:"},{t:"text",v:"The Chief Shepherd is sent into the field already, and shall also come and finish His work. Lo, He has entered the field and gathers them together. Yet the sheep do not depart, until The Shepherd calls them through the gate. Then will they be gone from this place."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-parable-of-the-great-landowner-and-his-beloved-sheep",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/the-parable-of-the-great?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=HKRxAsjjlsE&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=9",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Parables",url:"https://answersonlygodcangive.com/Parables"}],num:13,prevLetter:{id:"the-unending-fountain",title:"The Unending Fountain"},nextLetter:{id:"one-lord-one-god-one-savior",title:"One Lord, One God, One Savior"}},{id:"one-lord-one-god-one-savior",title:"One Lord, One God, One Savior",date:"",from:"",spoken:"",forLine:"",noteLine:"(Regarding the assertion that calling YAHUWAH or YAHUSHUA \u201CGod\u201D and \u201CLord\u201D is wrong)",blocks:[{type:"para",segments:[{t:"italic",v:"2/25/14 Wisdom Given to Timothy For All Those Who Have Ears to Hear (Regarding the assertion that calling YAHUWAH or YAHUSHUA \u201CGod\u201D and \u201CLord\u201D is wrong)"}]},{type:"para",segments:[{t:"text",v:"There is one God and Father, one Lord who causes to be - YAHUWAH. There is one Savior, The Only Begotten of The Father, by whom all things consist - YAHUSHUA. And they are ONE."}]},{type:"para",segments:[{t:"text",v:"If then, there is only one Lord, one God and one Savior, and in our language He is called \u201CLord\u201D and \u201CGod\u201D, then would not calling anyone or anything else \u201CLord\u201D or \u201CGod\u201D, whether a false god or a man, be blasphemy? Does not The Lord Himself search our hearts and minds, even our innermost thoughts and intentions? Does He not know who we are referring to, when we say \u201CJesus is Lord\u201D? Even throughout the world, believers and unbelievers alike know the name \u201CJesus\u201D"},{t:"fn",v:"1"},{t:"text",v:"(a name given to YahuShua by men) refers to He who was crucified and rose from the dead. And if we say YAHUSHUA is YAHUWAH, is this not also self-evident? Even before the earth was made, there is ONE alone who was and is and has always been THE LORD ABSOLUTE, which by definition demands there can be only one. Thus all others, whether man, false deity or carved image, referred to as \u201CLord\u201D in English or in any other language, are false! - Deceivers! Impostors! Idols! - To call any of these \u201CLord\u201D is blasphemy, even on the highest order!"}]},{type:"poetry",lines:[[{t:"italic",v:"For thus has The Lord spoken:"}]]},{type:"poetry",lines:[[{t:"italic",v:"One God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One Son, The Only Way to The Father..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One Truth, One Word, One Messiah, One Spirit;"}],[{t:"italic",v:"One Food, One Bread and One Drink..."}]]},{type:"poetry",lines:[[{t:"italic",v:"One Body..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Of which I am all,"}],[{t:"italic",v:"The All in All."}]]}],footnotes:{1:{type:"note",text:`\u201CYet understand this: In times past I overlooked the ignorance of the people. Yet now I command all people everywhere to repent in sincerity and in truth.[A] In like manner, I have overlooked the ignorance of those who call The Messiah by another name. Yet now I command all who have ears to hear, to call upon His name as it is, was, and has always been, and not as they presume it to be.[B] Indeed I am calling all tribes, tongues, peoples and nations to embrace Him as He truly is, and not as the churches of men would have Him be, says The Lord.\u201D (From \u201CDeath and Deliverance\u201D)

A. Acts 17:30 \u2014 \u201CTruly, these times of ignorance God overlooked, but now commands all men everywhere to repent,\u201D
B. Zephaniah 3:9 \u2014 \u201CFor then I will restore to the peoples a pure language, That they all may call on the name of the LORD, To serve Him with one accord.\u201D`}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/one-lord-one-god-one-savior",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/one-lord-one-god-one-savior?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Sacred Names",url:"https://answersonlygodcangive.com/Regarding_Sacred_Names"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"}],num:14,prevLetter:{id:"the-parable-of-the-great-landowner-and-his-beloved-sheep",title:"The Parable of The Great Landowner and His Beloved Sheep"},nextLetter:null}],LETTERS_FLOCK_PREFACE={id:"be-my-examples",title:"Be My Examples",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"poetry",lines:[[{t:"italic",v:"Beloved, be My examples..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Order your speech like David,"}],[{t:"italic",v:"And conduct yourselves as Daniel..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Let your speech express your"}],[{t:"italic",v:"Love for Me in every situation,"}],[{t:"italic",v:"And let your conduct reveal My spirit"}],[{t:"italic",v:"In you in open and in secret..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, prepare as though I were"}],[{t:"italic",v:"Coming to take you this very day;"}],[{t:"italic",v:"Walk with Me as though we walk"}],[{t:"italic",v:"Together in the Garden already..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/be-my-examples",videoVoiceUrl:"https://www.youtube.com/watch?v=mxTKg1d70I0&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=1",videoMusicUrl:"https://www.youtube.com/shorts/9MuSAaQ7474",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],isPreface:!0},LETTERS_FLOCK=[{id:"seek-the-light-only",title:"Seek The Light Only",date:"11/14/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy\u2019s Sister, and For All Those Who Have Ears to Hear",noteLine:"(Regarding rebuking demons)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Woe, I say to you; demons are not to be trifled with. There is but One, and One only, to whom complete authority over demons is given - YahuShua The Messiah, He who is called Jesus and Christ. For those who have not truly received of the Spirit are vulnerable to the wiles of the devil. And those who take it upon themselves to cast out demons are in grave danger, and will be easily overpowered by them."},{t:"fn",v:"1"},{t:"text",v:"Yet there are those few who are chosen by God, who may rebuke demons in YahuShua\u2019s name, but only those to whom it is given. And this is not of their own authority, but The Messiah\u2019s authority."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore those who seek to understand the dark"}],[{t:"italic",v:"Will soon find themselves trapped"}],[{t:"italic",v:"In the midst of it, unable to break free..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet those who seek The Light will find it,"}],[{t:"italic",v:"And I will show them The Way;"}],[{t:"italic",v:"In these darkness has no foothold..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Acts 19:13-16"}},nkjv:{"Acts 19:13-16":"13. Then some of the itinerant Jewish exorcists took it upon themselves to call the name of the Lord Jesus over those who had evil spirits, saying, \u201CWe exorcise you by the Jesus whom Paul preaches.\u201D 14. Also there were seven sons of Sceva, a Jewish chief priest, who did so. 15. And the evil spirit answered and said, \u201CJesus I know, and Paul I know; but who are you?\u201D 16. Then the man in whom the evil spirit was leaped on them, overpowered them, and prevailed against them, so that they fled out of that house naked and wounded."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/seek-the-light-only",videoVoiceUrl:"https://www.youtube.com/watch?v=Eld5LewDEdI&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Spiritual Warfare",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Warfare"},{label:"Regarding Demons",url:"https://answersonlygodcangive.com/Regarding_Demons"},{label:"Regarding Demons (Bible)",url:"https://trumpetcallofgodonline.com/index.php5?title=Regarding_Demons"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"}],num:1,prevLetter:null,nextLetter:{id:"adorn-yourself-with-the-word-of-god",title:"Adorn Yourself with The Word of God"}},{id:"adorn-yourself-with-the-word-of-god",title:"Adorn Yourself with The Word of God",date:"11/18/04",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy and His Wife, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Question asked by Timothy, for his wife: Lord, is it OK to wear jewelry with symbols of faith, such as crosses?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Timothy, you shall not adorn yourself with jewelry of any kind, save the band of your union with your wife. Rather, adorn yourself with The Word of God. Yea, put on Messiah and walk in His ways, striving always to bear His likeness. And let your wife adorn herself in like manner. For she is beautiful as she is, as I have made her. Yet to you, Beloved, I say this: You may wear such symbols in remembrance of The Son\u2019s sacrifice, in all humility and love, if they are worn close to the body, in private. For I tell you the truth, a symbol of faith worn in a modest fashion is not a graven image. Therefore have peace, for I know your heart."}]},{type:"para",segments:[{t:"text",v:"Yet woe to those who wear such symbols for the sake of vanity, or as a trophy or sign of their own goodness or beliefs. For by their actions they do always blaspheme, taking the name of The Lord in vain, though they have not opened their mouths to speak. And woe to those who dwell in the limelight, whose showmanship is likened unto a star. Woe to those who adorn themselves with all manner of sparkling ornaments, fine jewelry and expensive apparel, while also bearing symbols of the cross, for theirs is the greater sin. Thus under the guise of pretense and false glory is their true raiment hidden. For they do not know Me, neither do I live in them. For what do all these things have to do with Me? Is it not the humble, penitent man who gives Me glory in all his ways? For he seeks to honor Me, to please Me above all else. He wants no part in the ways of this world, neither does he seek glory for himself. By his actions he shines forth, seeking glory for The One alone who is God."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore let all those who truly know Me"}],[{t:"italic",v:"Proclaim My name first by their ways,"}],[{t:"italic",v:"Then with their mouths..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For honor only spoken of is but wind,"}],[{t:"italic",v:"The veil of the hypocrite who knows not"}],[{t:"italic",v:"Where he is going, having no remorse"}],[{t:"italic",v:"Over where he has been..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/adorn-yourself-with-the-word-of-god",videoVoiceUrl:"https://www.youtube.com/watch?v=FZ3BtaVqSaY&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=3",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Wearing of Jewelry",url:"https://answersonlygodcangive.com/Regarding_the_Wearing_of_Jewelry"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Take No Part",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Take_No_Part"},{label:"Woe to Those Who Walk in Pretense",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Walk_in_Pretense"}],num:2,prevLetter:{id:"seek-the-light-only",title:"Seek The Light Only"},nextLetter:{id:"all-things-were-ordained-from-the-beginning-no-other-name-is-given-by-which-you-must-be-saved",title:"All Things Were Ordained from the Beginning; No Other Name Is Given By Which You Must Be Saved"}},{id:"all-things-were-ordained-from-the-beginning-no-other-name-is-given-by-which-you-must-be-saved",title:"All Things Were Ordained from the Beginning; No Other Name Is Given By Which You Must Be Saved",date:"4/18/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, did dinosaurs exist as science suggests?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Dinosaurs did indeed exist and dwell upon the earth. For they, along with the plants and other animals of their day, were laid to rest as an earthen foundation for those who would come after. For I tell you the truth, all things were in the garden at the beginning, neither destroying nor given to destruction, until the day evil entered in, desecrating that which The Lord God had made. Therefore put your trust in no man, nor put your faith in men of science, for they do greatly err. Trust not their devices, nor give heed to their instruments. For all their lofty assertions are mere theories and hypotheses, retrospect, yet they account them as fact. And that which they put forth as proof is soon disproved in the light of new \u201Cevidence\u201D or understanding, discovery after so-called discovery seen through tainted eyes, to the darkness of many faces. Indeed the knowledge of man is infinitesimal, when compared with the knowledge of God, coming to nothing before the light of My Glory. For only one proof stands forever, lasting from generation to generation - The Word of God. Therefore give heed, all you who know His name, and come to repentance. For the Day of The Lord approaches, and soon the end sign shall appear, and every eye shall see."}]},{type:"para",segments:[{t:"text",v:"What then shall you do, O men of science and learning? Shall you flee to the mountains and hide yourselves in the rocks? Shall you continue to bury your heads in the sand? Your words are wind, your devices dust, and your knowledge of no effect, when confronted with the Glory of God revealed in His Holy One. For He is The Truth Absolute, yes, He who was crucified for your transgressions. Yet you need not flee to the mountains, nor hide yourselves in the caves or among the rocks, but fear The Lord your God, and humble yourselves in the sight of The King. Call on His name, and I, yes I, The One True God, shall grant you a reprieve and restore your life, even unto life everlasting. For it is written:"},{t:"italic",v:"The Lord your God is ready to pardon, gracious and merciful, slow to anger, abundant in kindness, and will not forsake those who repent."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore do not wait,"}],[{t:"italic",v:"But call upon The Salvation of God..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For He is called Jesus and Christ..."}]]},{type:"poetry",lines:[[{t:"italic",v:"His name: YAHUSHUA"},{t:"fn",v:"2"},{t:"italic",v:"HAMASHIACH..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The only name under Heaven"}],[{t:"italic",v:"By which you must be saved."}]]}],footnotes:{1:{type:"scripture",ref:"Nehemiah 9:17"},2:{type:"scripture",ref:"Zechariah 6:9-13"}},nkjv:{"Nehemiah 9:17":"They refused to obey, And they were not mindful of Your wonders That You did among them. But they hardened their necks, And in their rebellion They appointed a leader To return to their bondage. But You are God, Ready to pardon, Gracious and merciful, Slow to anger, Abundant in kindness, And did not forsake them.","Zechariah 6:9-13":`9. The word of the LORD came to me, saying, 10. Take of them of the captivity, even of Heldai, of Toviyah, and of Yedayah; and come the same day, and go into the house of Yoshiyahu the son of Tzefanyah, where they have come from Bavel. 11. Yes, take silver and gold, and make crowns, and set them on the head of Yehoshua the son of Yehotzadak, the Kohen Gadol; 12. and speak to him, saying, 'Thus says the LORD of Hosts, "Behold, the man whose name is the Branch: and he shall grow up out of his place; and he shall build the temple of the LORD; 13. even he shall build the temple of the LORD; and he shall bear the glory, and shall sit and rule on his throne; and he shall be a Kohen on his throne; and the counsel of shalom shall be between them both."' [In Zechariah 6:11, the original Hebrew word for Joshua is Yahushua (\u05D9\u05D4\u05D5\u05E9\u05E2)]`},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/all-things-were-ordained-from-the-beginning-no-other-name-is-given-by-which-you-must-be-saved",videoVoiceUrl:"https://www.youtube.com/watch?v=d_lrgFyY4fc&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=4",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Science",url:"https://answersonlygodcangive.com/Regarding_Science"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the End Sign",url:"https://answersonlygodcangive.com/Regarding_the_End_Sign"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:'The Name of The Lord - "YahuShua"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YahuShua"},{label:"Regarding Dinosaurs",url:"https://answersonlygodcangive.com/Regarding_Dinosaurs"}],num:3,prevLetter:{id:"adorn-yourself-with-the-word-of-god",title:"Adorn Yourself with The Word of God"},nextLetter:{id:"even-to-children-is-the-spirit-given",title:"Even to Children Is The Spirit Given"}},{id:"even-to-children-is-the-spirit-given",title:"Even to Children Is The Spirit Given",date:"4/27/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy and His Wife, and For All Those Who Have Ears to Hear",noteLine:"(Regarding their daughter who is seven)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My spirit has been poured out on all nations, upon every man, woman and child. Who has received it? Who has heard My voice and received of Me, as I truly am? Behold, a child of light has received, and within her heart she has heard. Even at a very young age does she hunger and thirst for righteousness. And so I have placed within her knowledge, and My spirit speaks to her in her dreams."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, even a child does dream dreams"}],[{t:"italic",v:"And prophesy in these last days..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore listen and have understanding,"}],[{t:"italic",v:"For the dreams and visions of the little ones"}],[{t:"italic",v:"Are liken unto pure gold, which has been"}],[{t:"italic",v:"Tried in a furnace seven times..."}]]},{type:"poetry",lines:[[{t:"italic",v:"No impurities found."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/even-to-children-is-the-spirit-given",videoVoiceUrl:"https://www.youtube.com/watch?v=FEKjG7bfcEo&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Spirit",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"},{label:"Regarding the Voice of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Voice_of_The_Lord"}],num:4,prevLetter:{id:"all-things-were-ordained-from-the-beginning-no-other-name-is-given-by-which-you-must-be-saved",title:"All Things Were Ordained from the Beginning; No Other Name Is Given By Which You Must Be Saved"},nextLetter:{id:"in-due-time",title:"In Due Time"}},{id:"in-due-time",title:"In Due Time",date:"5/4/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Timothy, the time is coming and is already here, when My people shall seek you out for nourishment and peace, that you might ease their troubled hearts. And in My name shall you feed them, and I Myself shall grant them peace. I AM THE LORD. Yet others shall also come forth to blaspheme, attempting to spoil that which I have given you. They will utterly fail. Yet in their defeat, some will come to know true repentance and pass from judgment into life."}]},{type:"poetry",lines:[[{t:"italic",v:"For only those in union with The Messiah"}],[{t:"italic",v:"Shall inherit the riches of Eden,"}],[{t:"italic",v:"And only those who fully accept"}],[{t:"italic",v:"His sacrifice shall be restored..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For from the garden did you come forth,"}],[{t:"italic",v:"And to the garden shall you return;"}],[{t:"italic",v:"Yet not in the former manner, but in glory..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Created anew, says The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/in-due-time-2",videoVoiceUrl:"https://www.youtube.com/watch?v=AmkpNrzD4sc&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=6",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:5,prevLetter:{id:"even-to-children-is-the-spirit-given",title:"Even to Children Is The Spirit Given"},nextLetter:{id:"discord",title:"Discord"}},{id:"discord",title:"Discord",date:"7/2/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"Timothy, meet all those with countenances turned against you with love, understanding, patience and truth. For I am with you. Remember it is I they mock, it is My Word they oppose. And on account of their hardened hearts, they refuse to believe and do always stumble over doubt. For they have no understanding; indeed, the ways of The Lord are foreign to them. Thus when confronted with the Truth, they reject it, lest the foundation upon which they stand crack, and the status quo to which they have grown accustomed crumble. Thus you shall walk in My ways, Timothy, that by your example they may in time come to see. For you shall indeed be brought to the forefront, with all eyes fixed upon you. And in the day I send you, I shall dwell in you like a flame of fire; the light of My glory shall rest upon you, and from within you I shall shine bright. Watch and see, therefore. For the wonders of God shall be shown in the heavens above and upon the earth beneath. And behold, even through My servants, the prophets, shall My glory be revealed..."},{t:"italic",v:"Of which you are one, Timothy, one among many, of the number I am sending, says The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/discord",videoVoiceUrl:"https://www.youtube.com/watch?v=ZbrXGKkIs7s&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"}],num:6,prevLetter:{id:"in-due-time",title:"In Due Time"},nextLetter:{id:"all-things-fulfilled-and-restored-in-the-kingdom",title:"All Things Fulfilled and Restored in The Kingdom"}},{id:"all-things-fulfilled-and-restored-in-the-kingdom",title:"All Things Fulfilled and Restored in The Kingdom",date:"8/4/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For His Nephew, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked by Timothy, for his nephew: Lord, will we have our pets with us in the Kingdom?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Hear and have understanding: The power of God is revealed through The Son. For The Son is all in all as The Father; He is in Me, and I in Him - We are One. Beloved one,"},{t:"italic",v:"all things that are and were created were created through Him and for Him. Through Him all things came to be, and nothing in all creation was made apart from Him; in Him do all things consist."},{t:"fn",v:"1"},{t:"text",v:"It is written:"},{t:"italic",v:"No eye has seen, no ear has heard, no one has imagined all the things which I have prepared for those who love Me."},{t:"fn",v:"2"},{t:"italic",v:"Therefore ask, and you shall surely receive."},{t:"fn",v:"3"},{t:"italic",v:"For it shall surely come to pass in that day, before you call I will answer, and while you are yet speaking I will hear."},{t:"fn",v:"4"},{t:"text",v:"For My love is an overflowing fountain, restoring all things, even unto your beloved pets."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, The Restoration is coming, coming quickly!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"All things restored as in the beginning;"}],[{t:"italic",v:"A garden where nothing is destroyed,"}],[{t:"italic",v:"And none are given to destruction;"}],[{t:"italic",v:"No more pain or tears, no more sickness or death..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Only life is, and shall be, forever!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Colossians 1:16-17"},2:{type:"scripture",ref:"1 Corinthians 2:9"},3:{type:"scripture",ref:"Matthew 7:7"},4:{type:"scripture",ref:"Isaiah 65:24"}},nkjv:{"Colossians 1:16-17":"16. For by Him all things were created that are in heaven and that are on earth, visible and invisible, whether thrones or dominions or principalities or powers. All things were created through Him and for Him. 17. And He is before all things, and in Him all things consist.","1 Corinthians 2:9":"But as it is written: \u201CEye has not seen, nor ear heard, Nor have entered into the heart of man The things which God has prepared for those who love Him.\u201D","Matthew 7:7":"\u201CAsk, and it will be given to you; seek, and you will find; knock, and it will be opened to you.","Isaiah 65:24":"\u201CIt shall come to pass That before they call, I will answer; And while they are still speaking, I will hear."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/all-things-fulfilled-and-restored-in-the-kingdom",videoVoiceUrl:"https://www.youtube.com/watch?v=ex4HhTmg2uY&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=8",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:'The Coming of The Lord - "I Am Coming Quickly"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#I_Am_Coming_Quickly"}],num:7,prevLetter:{id:"discord",title:"Discord"},nextLetter:{id:"a-stone-of-stumbling",title:"A Stone of Stumbling"}},{id:"a-stone-of-stumbling",title:"A Stone of Stumbling",date:"8/25/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"It is the penitent man who shall know God, and penitent you must be; die to yourselves daily. Cast off the skin of this world and walk with Me as I am, and not as you would have Me be. Beloved ones, do you long to obey? Then obey. Do you wish to stay clean? Then stay clean. Doubt is your enemy, doubt is a stone of stumbling at your feet. For I tell you the truth, one whose faith has come to completion, having received the full revelation of who I am, will not sin. For only the face of The Holy One is before their eyes. Beloved ones, only One is without sin, The Son of Man. Yet the desire to sin is still within you, and now also The Truth, and so the battle rages. Therefore, beware. For doubt leads to disobedience, and to disobey God is sin, and the penalty of sin is death. Yet I have overcome death, having written your name in the Book of Life from the very foundation of the world. What is left then? Only the death of sin itself, and the passing away of death. Beloved, cast off your sins, depart quickly from temptation, and to the accuser turn a deaf ear. For I tell you the truth, evil has lost its grip on the redeemed..."},{t:"italic",v:"Therefore hear My words, and also do them; give heed to My speech, and embrace all I have given you; drink deeply from this cup, and be created anew, says The Lord your Redeemer."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-stone-of-stumbling",videoVoiceUrl:"https://www.youtube.com/watch?v=S6B5qrOT3EE&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=9",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Doubt",url:"https://answersonlygodcangive.com/Regarding_Doubt"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding_Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"}],num:8,prevLetter:{id:"all-things-fulfilled-and-restored-in-the-kingdom",title:"All Things Fulfilled and Restored in The Kingdom"},nextLetter:{id:"above-reproach",title:"Above Reproach"}},{id:"above-reproach",title:"Above Reproach",date:"10/8/05",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"My son, why do you question Me in this way? To question My servant is to question Me. Therefore listen and have understanding, that My will may be fulfilled in you."}]},{type:"para",segments:[{t:"text",v:"That which you call the Old Testament was indeed written through My servants and prophets of old, and all who were wise gave heed, obeying the writing thereof. Yet even then that which would come to be written in the New Testament already existed, awaiting the day I would send out My apostles and prophets to proclaim the Good News. Was it the Old Testament? No. It was the New Testament, never before seen, heard or published. And now the time has come for Me to send out My apostles and prophets once again, to announce My coming and to set all these crooked paths straight"},{t:"fn",v:"1"},{t:"text",v:"; behold, it is time to blow the Trumpet and prepare My way before Me."},{t:"fn",v:"2"},{t:"text",v:"Does that which My messengers proclaim agree with the Bible? Yes. For the words in these Letters are My words; as are the words in your Bible My words, though they have been greatly misinterpreted and mistranslated by men. Therefore put no difference between them. For to reject any part of My Word is to reject the whole. I tell you the truth, the three books are one, one on-going testament to My glory."},{t:"fn",v:"3"},{t:"text",v:"Thus much of what My servants proclaim, you have already heard. Yet they will also declare that which you have not heard (nor have you understood, because of man\u2019s doctrine in you). Therefore, again I say to you, what My prophets of the end of this age write is indeed new to many, yet remains in perfect agreement with the prophets of old."},{t:"italic",v:"For I do not change"},{t:"fn",v:"4"},{t:"text",v:";"},{t:"italic",v:"I shall surely make My plans known."},{t:"fn",v:"5"}]},{type:"poetry",lines:[[{t:"italic",v:"For My spirit has spoken throughout"}],[{t:"italic",v:"The generations, in its steadfastness and quiet;"}],[{t:"italic",v:"Yet few have ears to hear, few are willing"}],[{t:"italic",v:"To open their hearts and receive My correction..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet now the time has come for those"}],[{t:"italic",v:"Who say they are My people to be tried,"}],[{t:"italic",v:"It is time for their works to be tested;"}],[{t:"italic",v:"For the Word of My mouth shall declare it"},{t:"fn",v:"6"},{t:"italic",v:","}],[{t:"italic",v:"And in the Day of The Lord it shall surely be made plain"},{t:"fn",v:"7"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Every false way exposed, every perverse tradition torn in pieces,"}],[{t:"italic",v:"Every detestable doctrine crushed beneath the weight of the Truth"},{t:"fn",v:"8"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Isaiah 42:16, Isaiah 45:2 (NKJV)"},2:{type:"scripture",ref:"Isaiah 40:3 (NKJV)"},3:{type:"note",text:'Also read: "YaHuWaH Is One; And His Word, One"',url:"https://www.thevolumesoftruth.com/Words_To_Live_By:_Part_One#YAHUWAH_Is_One.3B_And_His_Word.2C_One",link:{collection:"Words To Live By: Part One",letterTitle:"YAHUWAH Is One; And His Word, One"}},4:{type:"scripture",ref:"Malachi 3:6"},5:{type:"scripture",ref:"Amos 3:7"},6:{type:"note",text:'See: "Thus Says The Lord Regarding the Churches of Men"',url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},7:{type:"scripture",ref:"1 Corinthians 3:11-15"},8:{type:"scripture",ref:"Matthew 21:44"}},nkjv:{"Isaiah 42:16, Isaiah 45:2 (NKJV)":"42:16 \u2014 I will bring the blind by a way they did not know; I will lead them in paths they have not known. I will make darkness light before them, And crooked places straight. These things I will do for them, And not forsake them. | 45:2 \u2014 \u2018I will go before you And make the crooked places straight; I will break in pieces the gates of bronze And cut the bars of iron.","Isaiah 40:3 (NKJV)":"The voice of one crying in the wilderness: \u201CPrepare the way of the LORD; Make straight in the desert A highway for our God.","Malachi 3:6":"\u201CFor I am the LORD, I do not change; Therefore you are not consumed, O sons of Jacob.","Amos 3:7":"Surely the Lord GOD does nothing, Unless He reveals His secret to His servants the prophets.","1 Corinthians 3:11-15":"11. For no other foundation can anyone lay than that which is laid, which is Jesus Christ. 12. Now if anyone builds on this foundation with gold, silver, precious stones, wood, hay, straw, 13. each one\u2019s work will become clear; for the Day will declare it, because it will be revealed by fire; and the fire will test each one\u2019s work, of what sort it is. 14. If anyone\u2019s work which he has built on it endures, he will receive a reward. 15. If anyone\u2019s work is burned, he will suffer loss; but he himself will be saved, yet so as through fire.","Matthew 21:44":"And whoever falls on this stone will be broken; but on whomever it falls, it will grind him to powder.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/above-reproach",videoVoiceUrl:"https://www.youtube.com/watch?v=iW3xH8mJlk0&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Setting All These Crooked Paths Straight",url:"https://answersonlygodcangive.com/Main_Page#Setting_All_These_Crooked_Paths_Straight"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:9,prevLetter:{id:"a-stone-of-stumbling",title:"A Stone of Stumbling"},nextLetter:{id:"for-a-testimony-and-as-a-lamentation",title:"For a Testimony and as a Lamentation"}},{id:"for-a-testimony-and-as-a-lamentation",title:"For a Testimony and as a Lamentation",date:"2/24/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His watchman:"},{t:"text",v:"Timothy, hear the voice of The Lord your God and give heed, and obey all I command you. Give unto this strange people a testimony, an example, even in your own body every Sabbath, the seventh day of each week. No, not on the first, nor on the second, but on the seventh you shall take up a fast. You shall partake of no food or drink, save bread without leaven and purified water. This shall be for a testimony to My people, to those who are near and to those who remain afar off. For My watchmen shall eat no earthly bread, nor drink from any man-made fountain. They shall receive only that which comes down from their Father in Heaven."},{t:"italic",v:"Freely you have received, Timothy, freely give."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"For indeed, The Bread of Life was sent,"}],[{t:"italic",v:"And has been broken for all..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Blessed, therefore, are those who eat"}],[{t:"italic",v:"Of The True Bread, and drink continuously"}],[{t:"italic",v:"From The Fountain of Living Waters,"}],[{t:"italic",v:"For they shall inherit everlasting life..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 10:8"}},nkjv:{"Matthew 10:8":"Heal the sick, cleanse the lepers, raise the dead, cast out demons. Freely you have received, freely give."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/for-a-testimony-and-as-a-lamentation",videoVoiceUrl:"https://www.youtube.com/watch?v=9PPJD3Odk1g&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=11",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Fasting",url:"https://answersonlygodcangive.com/Regarding_Fasting"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"}],num:10,prevLetter:{id:"above-reproach",title:"Above Reproach"},nextLetter:{id:"as-you-have-received-so-shall-you-give",title:"As You Have Received, So Shall You Give"}},{id:"as-you-have-received-so-shall-you-give",title:"As You Have Received, So Shall You Give",date:"3/11/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, For All Believing Parents",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"italic",v:"Whoever receives My message receives Me, and I sanctify them. Yet whoever does not receive My message is against Me. And he who does not gather with Me scatters abroad, as it is written."},{t:"fn",v:"1"},{t:"text",v:"Likewise all those I have sanctified must also sanctify their own children, in My name. For they are Mine, and I have given them to you; even as you are The Father\u2019s, and He has given you to Me. Therefore, I ask you, where are you and how is your house? It is in disarray, letting those who abide there chase after the world. Do you not know that this world is condemned, and"},{t:"italic",v:"all who love the world have made themselves enemies of God?"},{t:"fn",v:"2"},{t:"text",v:"All children must obey their parents, and parents, you must cause them to obey. There is no quarrel. Would you say to Me,"},{t:"italic",v:"\u201CYes, Lord, I have heard you, but let me sleep and go my own way, and tomorrow I shall obey\u201D?"},{t:"text",v:"Not so, beloved ones - tomorrow is ending; behold, the sun is already setting upon this age of men."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore now is the accepted time,"}],[{t:"italic",v:"Now is the time of action..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For all those who know The Truth"}],[{t:"italic",v:"Must share the Truth."}]]},{type:"para",segments:[{t:"text",v:"Yet if you withhold, and those in your household continue in sin, assuredly I say to you, they shall fall under judgment and their blood I will require of you. However if you share the Truth with those of your household, and they refuse it, they shall surely suffer wrath, yet you shall be delivered"},{t:"fn",v:"3"},{t:"text",v:"..."},{t:"italic",v:"Yet oh how blessed are those who share the Truth, and those of their household receive it!"}]},{type:"poetry",lines:[[{t:"italic",v:"So again, I ask you, where do you stand?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And these of your household,"}],[{t:"italic",v:"Where are they and where are they going?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I tell you the truth, your work is not finished"}],[{t:"italic",v:"Until all I have given you is returned to Me..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 12:30"},2:{type:"scripture",ref:"James 4:4"},3:{type:"scripture",ref:"Ezekiel 3:18-19"}},nkjv:{"Matthew 12:30":"He who is not with Me is against Me, and he who does not gather with Me scatters abroad.","James 4:4":"Adulterers and adulteresses! Do you not know that friendship with the world is enmity with God? Whoever therefore wants to be a friend of the world makes himself an enemy of God.","Ezekiel 3:18-19":"18. When I say to the wicked, \u2018You shall surely die,\u2019 and you give him no warning, nor speak to warn the wicked from his wicked way, to save his life, that same wicked man shall die in his iniquity; but his blood I will require at your hand. 19. Yet, if you warn the wicked, and he does not turn from his wickedness, nor from his wicked way, he shall die in his iniquity; but you have delivered your soul."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/as-you-have-received-so-shall-you-give",videoVoiceUrl:"https://www.youtube.com/watch?v=fMpdWUSeDJ0&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=12",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Parenting",url:"https://answersonlygodcangive.com/Regarding_Parenting"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:11,prevLetter:{id:"for-a-testimony-and-as-a-lamentation",title:"For a Testimony and as a Lamentation"},nextLetter:{id:"obedience",title:"Obedience"}},{id:"obedience",title:"Obedience",date:"6/28/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord: Lord, how can we convert the sinner from their ways, and bring them the Good News and your warning, if we are to remain separate?"}]},{type:"para",segments:[{t:"text",v:"Beloved ones, did you think you could change the hearts of the afflicted by human power?"},{t:"italic",v:"Human power is of no use at all."},{t:"fn",v:"1"},{t:"text",v:"I soften the hearts of the seekers, pierce the hearts of the insolent, and harden the hearts of the wicked. And what of you, Timothy? Have you saved even one of these thousands who have returned to Me? Did you author all these words? Did you give the newly redeemed understanding? Did you pour out your spirit upon them? Timothy, have peace, I know your heart, yet I will continue to make you an example to the people. Beloved ones, all of Timothy\u2019s apparent success in the conversion of these thousands, and soon to be many ten thousands, is answered in one word:"},{t:"italic",v:"Obedience."},{t:"text",v:"He has obeyed My voice - I gave him the seeds, he planted, you watered, and I brought forth the increase."},{t:"fn",v:"2"},{t:"text",v:"So then how shall you change even one thought or action of those you love, by keeping their company? How shall you teach the blind? What words will the deaf hear? Can you heal the tongues of the dumb? Beloved, I shall teach them. And if they forbear, I will rebuke them, I Myself shall abase them. Therefore, as it is written:"},{t:"italic",v:"Do not be unequally yoked together with unbelievers. For what fellowship does righteousness have with lawlessness? And what communion does light have with darkness? And what accord does The Messiah have with belial? Or what part does a believer have with an unbeliever?"},{t:"fn",v:"3"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, kick not your foot against the stones,"}],[{t:"italic",v:"For you will only limp away, wounded by the effort..."}]]},{type:"poetry",lines:[[{t:"italic",v:"You shall go where I send you..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 6:63 (GNT)"},2:{type:"scripture",ref:"1 Corinthians 3:5-8 (NKJV)"},3:{type:"scripture",ref:"2 Corinthians 6:14-17 (NKJV)"}},nkjv:{"John 6:63 (GNT)":"What gives life is God's Spirit; human power is of no use at all. The words I have spoken to you bring God's life-giving Spirit.","1 Corinthians 3:5-8 (NKJV)":"5. Who then is Paul, and who is Apollos, but ministers through whom you believed, as the Lord gave to each one? 6. I planted, Apollos watered, but God gave the increase. 7. So then neither he who plants is anything, nor he who waters, but God who gives the increase. 8. Now he who plants and he who waters are one, and each one will receive his own reward according to his own labor.","2 Corinthians 6:14-17 (NKJV)":"14. Do not be unequally yoked together with unbelievers. For what fellowship has righteousness with lawlessness? And what communion has light with darkness? 15. And what accord has Christ with Belial? Or what part has a believer with an unbeliever? 16. And what agreement has the temple of God with idols? For you are the temple of the living God. As God has said: \u201CI will dwell in them And walk among them. I will be their God, And they shall be My people.\u201D 17. Therefore \u201CCome out from among them And be separate, says the Lord. Do not touch what is unclean, And I will receive you.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/obedience",videoVoiceUrl:"https://www.youtube.com/watch?v=TdIoFyT8nRk&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:12,prevLetter:{id:"as-you-have-received-so-shall-you-give",title:"As You Have Received, So Shall You Give"},nextLetter:{id:"receive-of-that-which-is-seasoned-with-salt-and-flavored-with-honey",title:"Receive of That Which Is Seasoned with Salt and Flavored with Honey"}},{id:"receive-of-that-which-is-seasoned-with-salt-and-flavored-with-honey",title:"Receive of That Which Is Seasoned with Salt and Flavored with Honey",date:"9/4/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy and His Wife, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved, write these words and receive My blessing, says The Lord."}]},{type:"para",segments:[{t:"text",v:"For I have indeed blessed you and your wife, and will yet bring upon you another blessing, in accordance with My will. For you have willingly eaten of that which is heavily seasoned with salt; even of its bitterness, you have fully accepted. Yet those against Me will not eat, nor will they partake of that which I have offered them. For they want no part with Me as I truly am, nor will they drink from My cup. Therefore you, My beloved servants, are the first of My little flock and have bore much fruit. Thus you will also bear the weight of this burden. And because you are the first, and have stood firm for My name\u2019s sake, you shall also bear the brunt of persecution and slander from those who shall come forth to fight against Me. Indeed, you shall be accused by those of this world of subversion and hate, and labeled as false servants and heretics by those who claim to serve Me yet remain void of the Spirit, a continual hissing brought forth from this most wicked generation."}]},{type:"para",segments:[{t:"text",v:"So then, Timothy, My prophet, and you Beloved, My scribe, trust in My ways and do all I command you: Take now one tenth of an epha of cornmeal, and mix it with water. Season it with salt, add flax, and flavor it also with honey. Bake it into cakes, and eat one cake for each meal, and give thanks. Do this for seven days, as a cleansing and as a testament within your own bodies. For the yoke of bitterness is upon you, and your faith shall be tested, yet what I shall give you will be sweet in your mouth like honey. And once ingested, it shall cause a heaviness, a purging of impurities, to the allaying of every doubt. Also take up a fast from all that is impure and filled with sugar. For this is also a metaphor and a testament against the world. For the things of this world do indeed seem sweet at first, and are presented in a manner which seems nourishing, yet I tell you the truth, they are poison and lead only to death. For the thoughts of man are from below, earthly, fleshly; all his works are evil, a way heavy-laden with sin."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore avoid the things of this world,"}],[{t:"italic",v:"Which I hate, and walk free..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And be separate from those who push out"}],[{t:"italic",v:"The lip, from all who tread the wide path..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come out from among them,"}],[{t:"italic",v:"And receive only that which comes down"}],[{t:"italic",v:"From your Father in Heaven."}]]},{type:"para",segments:[{t:"text",v:"So then, My beloved servants, hear and understand: As you, Timothy, must endure, so in like manner shall your wife endure, yet her time shall be cut short. Therefore to your wife, salt and honey, then The Blessing. And to you, My son, first salt and honey, then great bitterness and great glory before The Blessing comes. In this find wisdom. For all I have spoken shall surely come to pass, during the times and seasons which The Father has set within His own authority. And most assuredly, I say to you, the season is upon you."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore as you do in your body,"}],[{t:"italic",v:"Likewise shall I do in the world and among"}],[{t:"italic",v:"Those who claim to be of My body..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For great want is coming, yet for you, The Blessing..."}]]},{type:"poetry",lines:[[{t:"italic",v:"From whose hand you shall receive an abundance"}],[{t:"italic",v:"And share with those to whom I send you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/receive-of-that-which-is-seasoned-with-salt-and-flavored-with-honey",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Fasting",url:"https://answersonlygodcangive.com/Regarding_Fasting"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"}],num:13,prevLetter:{id:"obedience",title:"Obedience"},nextLetter:{id:"given-to-teach",title:"Given to Teach"}},{id:"given-to-teach",title:"Given to Teach",date:"6/26/07",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"My son, the teacher who has received of Me teaches not only by speaking, but by listening and by example, walking in My ways. And when those with sincere hearts come inquiring of Me, then shall those who I have called to teach do so, according to how I Myself lead them. And to the rest of My disciples, I say this: If you have grown wise in the Word by the reading, and have also received the love of the Truth, you also may help the sincere seeker by sharing that which is written in the Scriptures and Volumes of Truth, according to how My spirit leads you. For I am The Only Master, having never ceased from being your Teacher, and lo, I am with you always, even to the end of this age."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, apart from Me, one can do nothing;"}],[{t:"italic",v:"Human power is of no use at all..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A faithful, humble servant is what I require,"}],[{t:"italic",v:"One who listens to My voice and gives heed"}],[{t:"italic",v:"To My leading, at all times and in every season..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For only those who have ears to hear are given to teach;"}],[{t:"italic",v:"Yet to the rest, it is not given..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/given-to-teach",videoVoiceUrl:"https://www.youtube.com/watch?v=ret1aRYLawQ&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=14",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Spiritual Gifts",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Gifts"}],num:14,prevLetter:{id:"receive-of-that-which-is-seasoned-with-salt-and-flavored-with-honey",title:"Receive of That Which Is Seasoned with Salt and Flavored with Honey"},nextLetter:{id:"the-rod-of-discipline",title:"The Rod of Discipline"}},{id:"the-rod-of-discipline",title:"The Rod of Discipline",date:"3/22/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"When a child comes of age by sin and continues therein, despite the word of their parents or the Word of The Lord written in the Scriptures of Truth, they must be punished. Failing to respond with swift correction and discipline will only encourage further disobedience and sin."}]},{type:"para",segments:[{t:"text",v:"You have heard it said,"},{t:"italic",v:"to spare the rod is to hate your child."},{t:"fn",v:"1"},{t:"text",v:"This Scripture is true. Yet I tell you the truth, the rod is discipline, and not that of physical punishment. O vain and ignorant people, stop perverting the Scriptures of Truth! Humble yourselves, that you may gain wisdom! A child\u2019s disobedience is brought forth from a troubled heart and an unsettled spirit, wrought in ignorance. How then shall a beating correct the heart, or striking them with a rod bring about a right spirit?! Beloved, do not exasperate your children by bringing them into subjection by abuse. Rather take them by the hand, and lead them in the ways of The Lord, with love. For the love of a father is displayed in tenderness and kindness, and is also revealed through the correction and discipline of those he loves. Therefore, as it is written:"},{t:"italic",v:"Let the children first learn and show piety at home, and requite their parents, for this is good and acceptable before God."},{t:"fn",v:"2"}]}],footnotes:{1:{type:"scripture",ref:"Proverbs 13:24"},2:{type:"scripture",ref:"1 Timothy 5:4"}},nkjv:{"Proverbs 13:24":"He who spares his rod hates his son, But he who loves him disciplines him promptly.","1 Timothy 5:4":"But if any widow has children or grandchildren, let them first learn to show piety at home and to repay their parents; for this is good and acceptable before God."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-rod-of-discipline-3",videoVoiceUrl:"https://www.youtube.com/watch?v=Of2clCGYCqE&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=15",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Parenting",url:"https://answersonlygodcangive.com/Regarding_Parenting"}],num:15,prevLetter:{id:"given-to-teach",title:"Given to Teach"},nextLetter:{id:"let-them-eat-silence",title:"Let Them Eat Silence"}},{id:"let-them-eat-silence",title:"Let Them Eat Silence",date:"4/24/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Blow This Trumpet",blocks:[{type:"para",segments:[{t:"text",v:"Yet you ask,"},{t:"italic",v:"\u201CWhat of those who are in agreement, and those who do not fight against you, Lord, even all these who remain on our part?\u201D"},{t:"text",v:"What of yourselves? For whose glory do you write? Is My Word in need of supports to prop it up?"},{t:"italic",v:"For what shall one add to or take away from the Word of The Lord Most High?"},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Therefore, let all My beloved say,"},{t:"italic",v:"\u201CAmen!\u201D"},{t:"fn",v:"2"},{t:"text",v:"Or let them stay silent, abiding in quiet reverence before The Lord. And to the rest, those who cease not from pushing out the lip against The Lord\u2019s anointed, let them flee in terror at the coming of The Lord. Let them seek to hide themselves from the face of Him who sits on the throne. My servants, let them speak against you by the walls, both in open and in secret. For what is it to you? Against whom do they speak? Whose voice is it they withstand? Your own?"},{t:"italic",v:"Rather count it all joy that you have suffered scorn on My account, for great is your reward in Heaven."},{t:"fn",v:"3"},{t:"text",v:"Beloved, trust and obey. For how can one blow the trumpet while talking? And how shall one behold My form, while caught up in all these perverse disputings of the heart and mind, soon brought forth in speech, leading to even more ungodliness? My servants, give no occasion to the adversary, when it is within your power to do so; give the mocker no voice at all. For I tell you, by this you have surely blessed him. For as it is written,"},{t:"italic",v:"a man is defiled by that which is brought forth from his heart and given voice by his mouth."},{t:"fn",v:"4"},{t:"text",v:"Moreover, on the Day of Judgment he will surely give answer for every word he has spoken in his arrogance, to justify his rebellion, all in the name of pride. I AM THE LORD."}]},{type:"para",segments:[{t:"text",v:"Therefore give the scoffer no consideration at all, honor none of their requests. Let them eat silence and abide in their shame. Leave them to their turmoil, that they might consider their ways and repent. Beloved, let them alone."},{t:"italic",v:"Rather pray for your adversaries."},{t:"fn",v:"5"},{t:"text",v:"For they do not fight against you; they contend with Me, says The Lord."}]}],footnotes:{1:{type:"scripture",ref:"Isaiah 40:13"},2:{type:"scripture",ref:"Deuteronomy 27:16-26"},3:{type:"scripture",ref:"Matthew 5:11-12"},4:{type:"scripture",ref:"Mark 7:20-23, Matthew 15:11"},5:{type:"scripture",ref:"Matthew 5:44"}},nkjv:{"Isaiah 40:13":"Who has directed the Spirit of the LORD, Or as His counselor has taught Him?","Deuteronomy 27:16-26":"16. \u2018Cursed is the one who treats his father or his mother with contempt.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 17. \u2018Cursed is the one who moves his neighbor\u2019s landmark.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 18. \u2018Cursed is the one who makes the blind to wander off the road.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 19. \u2018Cursed is the one who perverts the justice due the stranger, the fatherless, and widow.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 20. \u2018Cursed is the one who lies with his father\u2019s wife, because he has uncovered his father\u2019s bed.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 21. \u2018Cursed is the one who lies with any kind of animal.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 22. \u2018Cursed is the one who lies with his sister, the daughter of his father or the daughter of his mother.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 23. \u2018Cursed is the one who lies with his mother-in-law.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 24. \u2018Cursed is the one who attacks his neighbor secretly.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 25. \u2018Cursed is the one who takes a bribe to slay an innocent person.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019 26. \u2018Cursed is the one who does not confirm all the words of this law by observing them.\u2019 \u201CAnd all the people shall say, \u2018Amen!\u2019","Matthew 5:11-12":"11. \u201CBlessed are you when they revile and persecute you, and say all kinds of evil against you falsely for My sake. 12. Rejoice and be exceedingly glad, for great is your reward in heaven, for so they persecuted the prophets who were before you.","Mark 7:20-23, Matthew 15:11":"Mark 7:20-23 \u2014 20. And He said, \u201CWhat comes out of a man, that defiles a man. 21. For from within, out of the heart of men, proceed evil thoughts, adulteries, fornications, murders, 22. thefts, covetousness, wickedness, deceit, lewdness, an evil eye, blasphemy, pride, foolishness. 23. All these evil things come from within and defile a man.\u201D | Matthew 15:11 \u2014 Not what goes into the mouth defiles a man; but what comes out of the mouth, this defiles a man.\u201D","Matthew 5:44":"But I say to you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who spitefully use you and persecute you,"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/let-them-eat-silence",videoVoiceUrl:"https://www.youtube.com/watch?v=qH23Pg32Shs&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=16",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"Regarding Prayer",url:"https://answersonlygodcangive.com/Regarding_Prayer"}],num:16,prevLetter:{id:"the-rod-of-discipline",title:"The Rod of Discipline"},nextLetter:{id:"slothful-servants",title:"Slothful Servants"}},{id:"slothful-servants",title:"Slothful Servants",date:"6/19/08",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"Have I not called to each one of you, saying,"},{t:"italic",v:"\u201CServe Me\u201D?"},{t:"text",v:"Yet you hesitate. Behold, I have spoken to you on many occasions, even placing it upon your hearts, yet you procrastinate, sitting upon your hands, saying within yourselves,"},{t:"italic",v:"\u201CTomorrow I will serve God; later I will pick up the trumpet.\u201D"},{t:"text",v:"Thus you are no watchmen. Yet for this reason, I have called you out. Know you not, that one in league with My watchman has by association become the same? Therefore I spoke to you, saying,"},{t:"italic",v:"\u201CBeloved, come and walk with Me this far.\u201D"},{t:"text",v:"Yet you answered,"},{t:"italic",v:"\u201CHow far?!\u201D"},{t:"text",v:"I have said,"},{t:"italic",v:"\u201CDo this.\u201D"},{t:"text",v:"Yet what have you done? How is it you stand up, yet begrudgingly? Where is your joy in service? Where is the sound of My name put forth in power, with steadfast belief and unwavering trust?"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, serve Me as I have loved you,"}],[{t:"italic",v:"And do so rejoicing as you go,"}],[{t:"italic",v:"For I am with you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And I shall surely provide all you need,"}],[{t:"italic",v:"Even as I have done from the beginning"},{t:"fn",v:"1"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 6:8"}},nkjv:{"Matthew 6:8":"\u201CTherefore do not be like them. For your Father knows the things you have need of before you ask Him."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/slothful-servants",videoVoiceUrl:"https://www.youtube.com/watch?v=aT9K7WS5WBo&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=17",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:17,prevLetter:{id:"let-them-eat-silence",title:"Let Them Eat Silence"},nextLetter:{id:"the-son-of-man-who-is-in-heaven-also-came-from-heaven-and-sits-at-the-right-hand-of-power",title:"The Son of Man Who Is in Heaven Also Came from Heaven, and Sits at the Right Hand of Power"}},{id:"the-son-of-man-who-is-in-heaven-also-came-from-heaven-and-sits-at-the-right-hand-of-power",title:"The Son of Man Who Is in Heaven Also Came from Heaven, and Sits at the Right Hand of Power",date:"2/26/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked regarding John 3:13, where YahuShua said, \u201CNo one has gone up into Heaven; there is only The One who has come down from Heaven, The Son of Man\u201D: Lord, how can this be, when the Bible also says Elijah went up into Heaven in a whirlwind, and Enoch was also taken by God?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord YahuShua:"},{t:"text",v:"I am in The Father, and The Father is in Me; The Father and The Son are One. Therefore no man who has died has ever risen, nor ascended to Heaven, nor sat down at the right hand of Power, save The Son of Man only. Neither has anyone ascended or descended, in the manner of The Holy One. For there is only One who came down from Heaven, who also went up to Heaven, The Messiah. And no man has, nor ever shall, come on the clouds of heaven with power and great glory, as The Son of God. I AM THE LORD."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-son-of-man-who-is-in-heaven-also-came-from-heaven",videoVoiceUrl:"https://www.youtube.com/watch?v=tN_JUUp6o5w&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=18",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Father and The Son are One",url:"https://answersonlygodcangive.com/The_Father_and_The_Son_are_One"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:'The Coming of The Lord - "In Power and Great Glory"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#In_Power_and_Great_Glory"}],num:18,prevLetter:{id:"slothful-servants",title:"Slothful Servants"},nextLetter:{id:"make-your-decision",title:"Make Your Decision"}},{id:"make-your-decision",title:"Make Your Decision",date:"8/18/09",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servant:"},{t:"text",v:"My son, when you have truly made your decision, I Myself shall finish it. Look not to tomorrow, for today is the day. Today is when you must decide, even this very moment - it is time to overcome. Indeed you must be willing to give up your life for My sake, or how shall I send you? For as it is written:"},{t:"italic",v:"Those who do not take up their cross and follow Me are not fit to be My disciples, for they have shown themselves unworthy of Me. And how shall one who loves his father or mother, or son or daughter, more than Me, escape? For they too have shown themselves unworthy of Me."},{t:"fn",v:"1"},{t:"italic",v:"Thus many are called, yet few are chosen."},{t:"fn",v:"2"},{t:"text",v:"Yet understand this: As I have spoken it, so shall it be. For there is a day coming, when I shall come upon My chosen and overshadow My elect, a day when all My faithful ones shall fly away, the day My beloved are made new. And in that day, the prophet\u2019s reward shall be yours also, if you too remain faithful."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore gird up your loins,"}],[{t:"italic",v:"And become the man of God you aspire to be;"}],[{t:"italic",v:"Stand firm for My cause and do not waver;"}],[{t:"italic",v:"Draw very close and receive of Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For indeed My grace is sufficient"}],[{t:"italic",v:"For all those who trust in Me..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Matthew 10:37-38, Luke 21:36"},2:{type:"scripture",ref:"Matthew 22:14 (NKJV)"}},nkjv:{"Matthew 10:37-38, Luke 21:36":"Matthew 10:37-38 \u2014 37. He who loves father or mother more than Me is not worthy of Me. And he who loves son or daughter more than Me is not worthy of Me. 38. And he who does not take his cross and follow after Me is not worthy of Me. | Luke 21:36 \u2014 Watch therefore, and pray always that you may be counted worthy to escape all these things that will come to pass, and to stand before the Son of Man.\u201D","Matthew 22:14 (NKJV)":"\u201CFor many are called, but few are chosen.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/make-your-decision",videoVoiceUrl:"https://www.youtube.com/watch?v=mL2UyjyUv-w&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=19",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:19,prevLetter:{id:"the-son-of-man-who-is-in-heaven-also-came-from-heaven-and-sits-at-the-right-hand-of-power",title:"The Son of Man Who Is in Heaven Also Came from Heaven, and Sits at the Right Hand of Power"},nextLetter:{id:"give-thanks-without-ceasing-and-be-set-apart",title:"Give Thanks Without Ceasing, and Be Set Apart"}},{id:"give-thanks-without-ceasing-and-be-set-apart",title:"Give Thanks Without Ceasing, and Be Set Apart",date:"11/26/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy During an Online Fellowship",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding Thanksgiving)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to those who have chosen not to remain separate:"},{t:"text",v:"Do not deny Me, neither in word or by deed. Do not keep silent, but testify to the glory of who I truly am. Again I say to you, do not deny Me for the sake of others or in an effort to keep the peace, for there is no peace. For I tell you the truth, pretense is unbecoming of a servant of The Lord. For pretense is a false witness, and to conceal a matter is akin to a lie. Therefore regarding those among you who choose to take part in this holiday of men, I say this: Let not one of you sin while doing so. Rather give thanks to The One True God, in the name of The Son. For by Him do all things consist, and through Him were all things made, even all these worlds. Yet wiser still is the one who draws close to Me and sees past this holiday\u2019s veneer, for it is of men and the world. I have no part in it, nor is it in My honor. Be separate from the world therefore, be separate from the unfruitful works of men, as I have called you. Have no fellowship with the unbeliever, nor keep the company of those who push out the lip and make light of My words or persecute My servants. I AM THE LORD."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/give-thanks-without-ceasing-and-be-set-apart",videoVoiceUrl:"https://www.youtube.com/watch?v=-ugiNQAnDhs&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=20",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"}],num:20,prevLetter:{id:"make-your-decision",title:"Make Your Decision"},nextLetter:{id:"devotion",title:"Devotion"}},{id:"devotion",title:"Devotion",date:"3/7/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding the preparation of unleavened bread during The Feast of Unleavened Bread)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"You shall partake only of that which is molded by the hands of a believing bride in each household, doing so with love and great joy in remembrance of Me. For I am He who molded you, and yet molds you still, even as I had unleavened you from the beginning by My sacrifice, remembering you during My Passion. Therefore, take and eat of that which I have provided. Do not go roundabout, nor seek that which is created by the hands of men; accept no replacements. Rather trust in My ways and see with greater eyes, rejoicing in every act of devotion, for I AM HE. Yet for those of you who have no wife, or dwell with a spouse who remains unwilling, you shall prepare the bread with your own hands, and be set apart for these seven days of the feast."}]},{type:"para",segments:[{t:"text",v:"Thus concerning spouses who remain rebellious, I say this: Ask of them nothing, nor partake of anything they offer during My Holy Days. For they have shown themselves unworthy of Me. For though you are two of one flesh by marriage, a division in spirit has occurred. And as it is written:"},{t:"italic",v:"Whatever you bind on earth will be bound in Heaven, and whatever you loose on earth will be loosed in Heaven."},{t:"fn",v:"1"},{t:"text",v:"Thus in the same way, when a division occurs on earth because of Me, so also is there a division in Heaven, says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"For My bride cleaves to Me, she honors Me"}],[{t:"italic",v:"And walks in My ways, and remains faithful..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet any who claim to be My bride, who knowingly"}],[{t:"italic",v:"Commit adultery with the pagan and the heathen,"}],[{t:"italic",v:"While cleaving to the ways of this world"}],[{t:"italic",v:"Or the churches of men, dishonor Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus between us a great gulf has formed..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And so shall it remain, until the day comes"}],[{t:"italic",v:"And is fulfilled, when she cries out, saying,"}],[{t:"italic",v:"\u201CBlessed is He who comes in The Name of The Lord!\u201D"}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 18:18"}},nkjv:{"Matthew 18:18":"\u201CAssuredly, I say to you, whatever you bind on earth will be bound in heaven, and whatever you loose on earth will be loosed in heaven."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/devotion",videoVoiceUrl:"https://www.youtube.com/watch?v=nQjhhK4Yg6A&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=20",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding the True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#Section_2_-_The_True_Bride"}],num:21,prevLetter:{id:"give-thanks-without-ceasing-and-be-set-apart",title:"Give Thanks Without Ceasing, and Be Set Apart"},nextLetter:{id:"witnesses-for-my-name-and-my-glory-trumpeters-of-my-coming",title:"Witnesses for My Name and My Glory, Trumpeters of My Coming"}},{id:"witnesses-for-my-name-and-my-glory-trumpeters-of-my-coming",title:"Witnesses for My Name and My Glory, Trumpeters of My Coming",date:"3/25/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Those in Men\u2019s Fellowship, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord YahuShua:"},{t:"text",v:"My sons, is there not a prophet among you? Do not those who love The Truth heed the Call? And do not My sheep listen to My voice and follow Me? How is it I have been with you this long, and still you fail to discern? Are not My plans made known and My will plainly written in all these Letters, even as the Scriptures of Truth? And yet My prophet stands still, and My servants remain unmoved, chained by fear and self-doubt."}]},{type:"para",segments:[{t:"text",v:"Therefore I ask you, who is a wise and prudent servant? Is he not the one who seeks out My will with prayer and fasting, one who waits upon The Lord in all patience and faith, with all trust? Yet I tell you the truth, you are not My servants only, you are also My friends, sons, some of whom I shall send in the Day. Therefore you shall study My words, to know them, striving each day to walk in them, as you prepare My way before Me. Therefore awaken your hearts and pay attention, be prepared. Be attentive and eager to follow My leading, giving heed to My spirit - hear and so do. Be vigilant, My sons, and always be ready to proclaim My words, at all times and in every season, at every venue. Reprove, rebuke and exhort, convict this generation of its evil ways. Be as adamant stones, immovable, yet also willing to teach, answering all who bring forth sincere questions of faith. I AM THE LORD."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/witnesses-for-my-name-and-my-glory-2",videoVoiceUrl:"https://www.youtube.com/watch?v=e63pMYVymqY&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Discernment",url:"https://answersonlygodcangive.com/Main_Page#Discernment"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Prayer",url:"https://answersonlygodcangive.com/Regarding_Prayer"},{label:"Regarding Fasting",url:"https://answersonlygodcangive.com/Regarding_Fasting"},{label:"Regarding Patience",url:"https://answersonlygodcangive.com/Regarding_Patience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:22,prevLetter:{id:"devotion",title:"Devotion"},nextLetter:{id:"hidden-treasures-in-the-fields-of-the-first-harvest",title:"Hidden Treasures in the Fields of the First Harvest"}},{id:"hidden-treasures-in-the-fields-of-the-first-harvest",title:"Hidden Treasures in the Fields of the First Harvest",date:"3/26/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Those in Men\u2019s Fellowship, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My sons, trust in My ways and look not to your own, says The Lord. For I do indeed have many hidden treasures in this field. Thus I am sending you out to seek the few, that I may bless them by you. It is not the many for which you are sent out this day, but the few."}]},{type:"para",segments:[{t:"text",v:"Therefore, this is what I command you: Go to the college nearby, and go into every open building, seeking a place to display My Word. Be attentive, break not the rules, nor disobey any guideline. For that done which is acceptable shall remain for the next passerby, and that removed due to a violation profits no one."}]},{type:"poetry",lines:[[{t:"italic",v:"So then do as I command you;"}],[{t:"italic",v:"Neither add to, nor take away;"}],[{t:"italic",v:"Be watchful and wide awake."}]]},{type:"para",segments:[{t:"text",v:"For there are many treasures round about, many who seek Me in dry places, many who have yet to be found. You will not find them all this day, neither shall you be led to each one. Rather it is I who shall call them out. I, Myself, shall breach the barrier, which surrounds their hearts; I alone shall cause them to see and take notice; behold, even I shall draw them to this Word, both those who will hear and those who will forbear. Therefore go with joy on your faces, and with eagerness in your hearts, and share My gifts. And when it is accomplished, then you may go and do as you please. Yet understand this: It is not My will that each one you meet leave contented or reveal their gratitude, only that the message be placed in their hands. For I am The Lord, and My Word always convicts."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore let all things be separated,"}],[{t:"italic",v:"Let all choose and make their decision;"}],[{t:"italic",v:"Let the first harvest be separated, bundled and taken,"}],[{t:"italic",v:"And let the rest be left to be purged by fire..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For you, My sons, are sent to divide"}],[{t:"italic",v:"The harvest, not to bring it in..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For again I say to you,"}],[{t:"italic",v:"Many are called, yet few are chosen..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/hidden-treasures-in-the-fields-of-the-first-harvest",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"}],num:23,prevLetter:{id:"witnesses-for-my-name-and-my-glory-trumpeters-of-my-coming",title:"Witnesses for My Name and My Glory, Trumpeters of My Coming"},nextLetter:{id:"a-spectacle-for-my-name-s-sake",title:"A Spectacle For My Name\u2019s Sake"}},{id:"a-spectacle-for-my-name-s-sake",title:"A Spectacle For My Name\u2019s Sake",date:"4/28/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Watchmen, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My sons, go and be to them as a loathsome sore which can not be cast off or healed, an offensive odor in the nostrils of all who hate Me. Yes, go and make of yourselves a spectacle for My name\u2019s sake - stir them up! Serve them the truth absolute and My strong rebuke. Serve them every word of My hot displeasure, and do not relent but continue on, until a great outcry has come forth against you, says The Lord. And when I call you to depart from one place, seek out another, leaving your blessing with those who have given heed, blessing them in My name, even all who have shed tears of repentance upon hearing the Word of The Lord. Yet turn away from those who hate Me, wiping off the dirt from the underside of your shoes as a testament against them."},{t:"italic",v:"You will know them by their fruits,"},{t:"fn",v:"1"},{t:"text",v:"by the darkness of their faces, and by every word which proceeds from their mouths. I AM THE LORD."}]}],footnotes:{1:{type:"scripture",ref:"Matthew 7:16-21"}},nkjv:{"Matthew 7:16-21":"16. You will know them by their fruits. Do men gather grapes from thornbushes or figs from thistles? 17. Even so, every good tree bears good fruit, but a bad tree bears bad fruit. 18. A good tree cannot bear bad fruit, nor can a bad tree bear good fruit. 19. Every tree that does not bear good fruit is cut down and thrown into the fire. 20. Therefore by their fruits you will know them. 21. \u201CNot everyone who says to Me, \u2018Lord, Lord,\u2019 shall enter the kingdom of heaven, but he who does the will of My Father in heaven."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-spectacle-for-my-names-sake",videoVoiceUrl:"https://www.youtube.com/watch?v=0nru1J61--A&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=22",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:24,prevLetter:{id:"hidden-treasures-in-the-fields-of-the-first-harvest",title:"Hidden Treasures in the Fields of the First Harvest"},nextLetter:{id:"go-out-and-trumpet",title:"Go Out and Trumpet"}},{id:"go-out-and-trumpet",title:"Go Out and Trumpet",date:"5/8/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved, the time has come for you to go out and trumpet, to serve My correction to the churches of men, to put My words in the hands of the people. Thus you shall go to every church nearby, to your neighbors and to your countrymen, to all who reside within your reach. And when you approach a church, and see there a sign which says \u201CNo Soliciting,\u201D you shall still go forth. For I AM THE LORD. And when you go into the cities and towns, and to all places where people congregate to buy and sell, and again see a sign which says \u201CNo Soliciting,\u201D you shall not go forth, but you shall remain outside and hand My Word to the passerby. I AM THE LORD."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved ones, it is time for you"}],[{t:"italic",v:"To stand up, to make a stand;"}],[{t:"italic",v:"It is time to spread My words abroad"}],[{t:"italic",v:"And blow this Trumpet..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Or to depart and walk through dry places..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/go-out-and-trumpet",videoVoiceUrl:"https://www.youtube.com/watch?v=0jURewKMOa0&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=23",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:25,prevLetter:{id:"a-spectacle-for-my-name-s-sake",title:"A Spectacle For My Name\u2019s Sake"},nextLetter:{id:"a-trying-of-your-trust-a-testing-of-your-resolve-your-faith-revealed",title:"A Trying of Your Trust, a Testing of Your Resolve... Your Faith Revealed"}},{id:"a-trying-of-your-trust-a-testing-of-your-resolve-your-faith-revealed",title:"A Trying of Your Trust, a Testing of Your Resolve... Your Faith Revealed",date:"5/14/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Little flock, hear My words and give heed to My commands."}]},{type:"para",segments:[{t:"text",v:"In your doings I am well pleased, yet you have not awaited My command. Have I commanded you to keep this feast at such a time as this? Behold, even Timothy ran ahead and did not await My command. Therefore hear the Word of My mouth, for it is I who commands you; yes I, The Lord of Heaven and Earth, YAHUWAH, The One alone who causes to be."}]},{type:"para",segments:[{t:"bold-italic",v:"For thus says The Lord:"},{t:"text",v:"You also must be tried, you also must be tested. For this Pentecost is and shall be, yet is not and shall be no longer. Therefore you shall indeed keep this day, which is set apart, holy. And you shall do so by service, honoring Me by doing that which I command you. For some this shall be a new beginning, and to others a falling away - a testing of your resolve, a trying of your trust, an exercise in obedience according to your faith. Yet remember this: No matter your decision, I know your hearts. And behold, some have fallen away already. Therefore, this is what you shall do on this Pentecost, even a week before the time: You shall go out and warn them from Me. You shall warn those in the churches of men, as many as you are able on this day. Yet the one to whom this Trumpet was given shall not go with you, nor shall he leave his house; neither he nor his wife shall go out. They shall remain separate and pray, making intercession for you and for those held captive in the churches of men. I AM THE LORD. Behold, I have set before you a stone of stumbling, over which many shall fall. I have called you into service, according to your faith. Indeed I have given you much, therefore much shall I require, and only a very few shall remain. And so that which was begun shall be finished - the first of two is ending, and the second is about to begin; even as three are accomplished, one is ending, and three wait upon the horizon, soon to be fulfilled."}]},{type:"para",segments:[{t:"text",v:"Therefore you must ask yourselves, little flock,"},{t:"italic",v:"\u201CWhere have all these seeds been sown? Have they taken root? Or are they choked by the multitude of weeds which have sprung up?\u201D"},{t:"text",v:"Beware, for the birds gather, and wait eagerly to devour all seeds which have fallen by the wayside."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus only that which is first shall bear fruit;"}],[{t:"italic",v:"For that which is foremost bears fruit according"}],[{t:"italic",v:"To the Seed and The One who has sown it..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet that which is put first by men, which is not"}],[{t:"italic",v:"Of the Seed nor of The Sower, must die;"}],[{t:"italic",v:"It must be uprooted and cast into the fire..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-trying-of-your-trust-a-testing-of-your-resolve-your-faith-revealed",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding The Holy Days of God (Pentecost)",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God#Pentecost"},{label:"Regarding_Prayer",url:"https://answersonlygodcangive.com/Regarding_Prayer"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"}],num:26,prevLetter:{id:"go-out-and-trumpet",title:"Go Out and Trumpet"},nextLetter:{id:"stand-fast",title:"Stand Fast"}},{id:"stand-fast",title:"Stand Fast",date:"5/31/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Those in Men\u2019s Fellowship, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Calamities shall increase, reaching far and wide, and many ten thousands shall fall; multitudes shall lie down in death, and all shall fear. Behold, a great wailing shall be heard from one end of the earth to the other, and many will turn against Me. Even amongst all these scattered flocks shall there be many who turn away and mock My promises. And thus that which is written shall be fulfilled. Behold, even some among this little flock shall fall away, saying within themselves,"},{t:"italic",v:"\u201CWhere is the promise of His coming?\u201D"},{t:"fn",v:"1"},{t:"text",v:"Yet you, My sons, don\u2019t"},{t:"italic",v:"you"},{t:"text",v:"fall away - hold fast."}]},{type:"poetry",lines:[[{t:"italic",v:"Set your feet solidly upon The Rock,"}],[{t:"italic",v:"Fix your eyes upon The King,"}],[{t:"italic",v:"Set your shoulders straight"}],[{t:"italic",v:"And stand fast in battle array..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The Holy One is coming down,"}],[{t:"italic",v:"On a day which no one knows,"}],[{t:"italic",v:"And at an hour you do not expect..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore prepare and make ready..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It is time."}]]}],footnotes:{1:{type:"scripture",ref:"2 Peter 3:3-4"}},nkjv:{"2 Peter 3:3-4":"3. knowing this first: that scoffers will come in the last days, walking according to their own lusts, 4. and saying, \u201CWhere is the promise of His coming? For since the fathers fell asleep, all things continue as they were from the beginning of creation.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/stand-fast",videoVoiceUrl:"https://www.youtube.com/watch?v=3HDzeZRUFMU&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"}],num:27,prevLetter:{id:"a-trying-of-your-trust-a-testing-of-your-resolve-your-faith-revealed",title:"A Trying of Your Trust, a Testing of Your Resolve... Your Faith Revealed"},nextLetter:{id:"begin-again-in-me",title:"Begin Again in Me"}},{id:"begin-again-in-me",title:"Begin Again in Me",date:"6/7/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Begin again in Me, says The Lord, for I have not left you. Behold, I am with you, even to the end of this age."}]},{type:"para",segments:[{t:"text",v:"My son, you are forgiven. And in true forgiveness, there is no remembrance of past offenses; behold, even your sins of tomorrow are washed away. Therefore fix your gaze upon Me, focus not on your sin; give temptation no power, and to the accuser turn a deaf ear. Beloved, turn aside and come to Me. Regain the line and together we shall walk, choosing the good and refusing the evil, until you also have forgotten your sin. Behold, it is separated from you as far as the east is from the west. Therefore do not revive your sins, let evil die, and let the man you were pass away."},{t:"italic",v:"For if The Son sets you free, then you are truly free, as it is written."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, come all who struggle and are heavy-laden,"}],[{t:"italic",v:"And I will give you rest..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Take My yoke upon you and learn from Me,"}],[{t:"italic",v:"For I am gentle and lowly in heart,"}],[{t:"italic",v:"And in Me you will find rest for your souls..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My yoke is easy, and My burden light,"},{t:"fn",v:"2"}],[{t:"italic",v:"For all those who trust in Me..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 8:36"},2:{type:"scripture",ref:"Matthew 11:28-30"}},nkjv:{"John 8:36":"Therefore if the Son makes you free, you shall be free indeed.","Matthew 11:28-30":"28. Come to Me, all you who labor and are heavy laden, and I will give you rest. 29. Take My yoke upon you and learn from Me, for I am gentle and lowly in heart, and you will find rest for your souls. 30. For My yoke is easy and My burden is light.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/begin-again-in-me",videoVoiceUrl:"https://www.youtube.com/watch?v=PkZQVKcUVdU&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=26",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Forgiveness",url:"https://answersonlygodcangive.com/Regarding_Forgiveness"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:28,prevLetter:{id:"stand-fast",title:"Stand Fast"},nextLetter:{id:"serve-me-as-i-have-loved-you-says-the-lord",title:"Serve Me as I Have Loved You, Says The Lord"}},{id:"serve-me-as-i-have-loved-you-says-the-lord",title:"Serve Me as I Have Loved You, Says The Lord",date:"6/10/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved ones, there are many sheep in this field, yet most have wandered and gone their own way. Behold, many rage as lions, and others bleat like goats, yet they are no lions nor are they goats. They are ill sheep, living in a pasture which is greatly polluted, the stink thereof bringing forth a thick fog of delusion and fear. Therefore, from this field I have called a select few, to be My examples; not according to their own righteousness, nor by their own strength or intellect, but according to My Word and by My spirit which dwells within them. These have forsaken everything for the sake of their Shepherd. They follow Me wheresoever I go. They listen to My voice and heed the call, and will by no means follow another."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, little flock,"}],[{t:"italic",v:"You also shall strive to be My examples..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved ones, serve Me as I have loved you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And remember, whatsoever you do"}],[{t:"italic",v:"For another, you have done it for Me;"}],[{t:"italic",v:"And whatsoever you do to another,"}],[{t:"italic",v:"Whether in goodness or in malice,"}],[{t:"italic",v:"You have done it also to Me..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/serve-me-as-i-have-loved-you-says-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=SYANyqGydhw&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=26",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:29,prevLetter:{id:"begin-again-in-me",title:"Begin Again in Me"},nextLetter:{id:"offenses-must-come",title:"Offenses Must Come"}},{id:"offenses-must-come",title:"Offenses Must Come",date:"7/4/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"My son, I have called you to trumpet, to proclaim the Truth, to set all these crooked paths straight according to that which I have spoken to this generation; to be that example which also speaks to the truth of who I am, testifying by action according to the Spirit and The Word of Truth, to the bearing of much fruit in The Beloved. Yet by cleverness of words and witty speeches, which are void of the Spirit, have you caused offenses, as though My words were not enough. Indeed offenses shall come, let them come, yet they shall not come by My servant\u2019s words, but by My Word alone. My son, I have called you out. And you shall indeed be as a watchman for My people, that you may aid My servant in the blowing of this Trumpet. Therefore this is the food, with which you shall feed them: My Word, and My Word alone, lest you be exalted in your own name. For by My Word alone shall the sleepers be awakened, and by My Word alone shall the rebellious be warned. Even some shall be brought forward because of this, and they shall blaspheme My words, that the hidden state of their heart may be exposed. I AM THE LORD. Thus My servants shall cause no offense at all, save that which comes by the trumpeting of this Word. And of those who come forward, who are offended in Me because of My words, take nothing to yourself, lest you disavow the promises which must be met, for which you are also called. Again I say to you, let no guile be found in your mouth. Let only the song of The Lamb be upon your lips, as you blow this Trumpet to all within your reach. And when one who claims to know Me comes and asks you for more, feed them from My plate. And when they take offense and seek to cast down My words, warn them from Me, then quickly turn away as you shake the dust off your feet. For they fight not against you, but against Me, says The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/offenses-must-come",videoVoiceUrl:"https://www.youtube.com/watch?v=1_v3Tir9CTk&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=27",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Setting All These Crooked Paths Straight",url:"https://answersonlygodcangive.com/Main_Page#Setting_All_These_Crooked_Paths_Straight"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"The Volumes of Truth (Amos 3:7)",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth#Amos_3:7"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"}],num:30,prevLetter:{id:"serve-me-as-i-have-loved-you-says-the-lord",title:"Serve Me as I Have Loved You, Says The Lord"},nextLetter:{id:"the-fear-of-the-lord",title:"The Fear of The Lord"}},{id:"the-fear-of-the-lord",title:"The Fear of The Lord",date:"8/5/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"It is written,"},{t:"italic",v:"The fear of The Lord is the beginning of wisdom, and knowledge of The Holy One is understanding."},{t:"fn",v:"1"},{t:"text",v:"Therefore all else is vanity, a false way, leading to great vexation of spirit. For I AM THE LORD. From the beginning it was I who had done it; even to the end shall I perform it; and behold, all is fulfilled according to My will."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore to fear The Lord your God"}],[{t:"italic",v:"Is indeed the beginning of wisdom..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For how can one know Me,"}],[{t:"italic",v:"Unless they first acknowledge Me?"}],[{t:"italic",v:"And how can one fear Me, unless they"}],[{t:"italic",v:"Believe, I AM WHO I AM?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"He who causes to be,"}],[{t:"italic",v:"He who called all things into existence,"}],[{t:"italic",v:"The Creator of Heaven and Earth."}]]}],footnotes:{1:{type:"scripture",ref:"Proverbs 9:10"}},nkjv:{"Proverbs 9:10":"\u201CThe fear of the LORD is the beginning of wisdom, And the knowledge of the Holy One is understanding."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-fear-of-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=LXAJjf1dsc0&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=28",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:31,prevLetter:{id:"offenses-must-come",title:"Offenses Must Come"},nextLetter:{id:"to-be-set-apart",title:"To Be Set Apart"}},{id:"to-be-set-apart",title:"To Be Set Apart",date:"9/7/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding the Feast of Trumpets)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"Beloved ones, hear My words. For I have indeed set you apart to do My will. Therefore you shall honor and celebrate this feast in My name. You shall do all I command you, even that which the world and other believers do not yet understand. This night, you shall blow the trumpet as the sun dips below the horizon, doing so with great sorrow in your hearts, because of that which this world has chosen in all their forsaking of Me; even as a lamentation over all this wickedness mankind has wrought in the earth, which shall come to a swift end at the setting of the sun upon this age of men. Then when morning comes, you shall once again sound the trumpet as the sun breaks the horizon, doing so with great joy in your hearts..."},{t:"italic",v:"For My Kingdom comes!"}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/to-be-set-apart",videoVoiceUrl:"https://www.youtube.com/watch?v=hcb2Klosbpw&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"}],num:32,prevLetter:{id:"the-fear-of-the-lord",title:"The Fear of The Lord"},nextLetter:{id:"a-wise-servant-and-the-line",title:"A Wise Servant and the Line"}},{id:"a-wise-servant-and-the-line",title:"A Wise Servant and the Line",date:"10/5/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy During Fellowship",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"A brother in Christ said: I\u2019m being faced with a few dilemmas. A close friend made me the godfather of her son. They are having a birthday celebration for him this Sabbath, then having him christened at a local church. I\u2019ve been praying about this, and feel that it would be okay to go to the birthday, but I\u2019m not sure about the christening. I want to do what is right in The Lord\u2019s sight, having proper reasoning for my decision."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My son, before you have I set many things of great importance, yet I have heard no answer, nor have you offered yourself in place of your lack. And now you ask of obedience, stumbling over those things from which you were to remain separate."},{t:"italic",v:"Therefore, this is what I say to you:"},{t:"text",v:"One who serves Me in truth must show themselves fully worthy, embracing the call of The Lord wholeheartedly, or how shall I send them? I speak not of being made worthy according to My sacrifice, but of giving up your life in this world for My sake, loving Me more than these, bearing your cross after Me."}]},{type:"para",segments:[{t:"text",v:"Behold, I shall speak, and in a loud voice I shall reveal My will through My servant, and he shall write. "},{t:"fn",v:"1"},{t:"text",v:" And the line shall be declared, it shall be set, and no one shall pass over it. I tell you a mystery: Those who heed the call and come out will pass to one side, and those who refuse to the other - one on this side, and many more on the other. And those who pass over to those who remain on this side shall escape. Yet those who continue to reject My voice and rebel against Me shall remain, left to walk through the valley until death comes to claim them. I AM THE LORD."}]},{type:"para",segments:[{t:"italic",v:"[A brother in Christ]"},{t:"text",v:"Amen. I may have been foolish, I am not seeing with greater eyes. Is that birthday on the Sabbath wrong also? I\u2019m so caught up in these small matters. This is not good."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My son, a wise servant who lacks understanding seeks out a prophet of The Lord who is true, that he might receive understanding by the Word of My mouth. Yet wiser still is the man who seeks out the things of God by way of Him who was sent and is about to return, that he might understand by the Word of The Lord spoken already. For any plate left uneaten quickly grows cold, says The Lord."}]}],footnotes:{1:{type:"note",text:'Also read: "I Am Calling You Out! (Part 2)... Come Out of the Churches of Men and I Will Receive You! Says The Lord"',url:"https://www.thevolumesoftruth.com/I_Am_Calling_You_Out_Part_2",link:{collection:"Volume Seven",letterTitle:"I Am Calling You Out! (Part 2)... Come Out of the Churches of Men and I Will Receive You! Says The Lord"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-wise-servant-and-the-line",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"I Am Calling You Out",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Discernment",url:"https://answersonlygodcangive.com/Main_Page#Discernment"}],num:33,prevLetter:{id:"to-be-set-apart",title:"To Be Set Apart"},nextLetter:{id:"fixed",title:"Fixed"}},{id:"fixed",title:"Fixed",date:"10/28/10",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",metaAddendum:"Trees of the Field",metaAddendumLink:{collection:"Volume Five",letterTitle:"Trees of the Field"},blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold these multitudes who call of themselves Christian and Jew, they have misplaced that which I had given them"},{t:"fn",v:"1"},{t:"text",v:", deceiving themselves. For they think within themselves,"},{t:"italic",v:'"I too carry an axe, with which I shall cut down every messenger sent to us,"'},{t:"text",v:"perceiving falsely that they are able to cut them down with ease, as though My servants and the Word they carry were a dry tree, having not weight enough in its roots to remain standing..."},{t:"italic",v:"Behold, the winds shall blow, the earth shall shake, and this same Word"},{t:"fn",v:"2"},{t:"italic",v:"which they endeavored to cut down shall fall hard upon them, and My witnesses shall indeed rule over them. For My Word never returns void! Says The Lord."}]},{type:"para",segments:[{t:"text",v:"Yet of this Word"},{t:"fn",v:"3"},{t:"text",v:"which you have considered, it shall be fulfilled in more ways than one - some of which you have understood according to that which I have given you, and some shall be hidden from your eyes until the day is upon you. I AM THE LORD."}]}],footnotes:{1:{type:"note",text:'See: "Follow Me"',url:"https://www.thevolumesoftruth.com/Follow_Me"},2:{type:"note",text:'See: "The Volumes of Truth Online Edition"',url:"https://www.thevolumesoftruth.com/Main_Page#The_Volumes_of_Truth_Online_Edition"},3:{type:"note",text:'See: "Trees of the Field"',url:"https://www.thevolumesoftruth.com/Trees_of_the_Field"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/fixed",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"}],num:34,prevLetter:{id:"a-wise-servant-and-the-line",title:"A Wise Servant and the Line"},nextLetter:{id:"keeping-the-wolves-at-bay",title:"Keeping the Wolves at Bay"}},{id:"keeping-the-wolves-at-bay",title:"Keeping the Wolves at Bay",date:"11/9/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding those who persecute The Lord\u2019s servants, because of The Volumes of Truth)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Have I not said,"},{t:"italic",v:"\u201CWhatsoever one finds to justify their rejection of My Word, let it be sufficient for them\u201D?"},{t:"text",v:"For what are their accusations to Me? - Wind. Refuse, fit to be thrown out or cast upon the dunghill. Therefore, let them have their self-perceived victory and sit at ease in their rebellion. Let them revel in their hubris, and walk boldly in their wickedness, until death comes to claim them. But let not My servants return evil for evil; rather let them pray. Again I say to you, let them alone. For the wicked do always open their mouths against Me; they cease not from speaking against My servants, with a froward mouth and a lying tongue. They fight against Me without cause, returning evil for good, and hatred for My love. Thus they remain in their sins, their guilt uncovered, as they continue to tread the wide path. For vanity is a rope, and pride builds the gallows; envy leads to hate, and jealousy brings forth evil thoughts. Therefore, I ask you, what part do you have with them? Says The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/keeping-the-wolves-at-bay",videoVoiceUrl:"https://www.youtube.com/watch?v=mem6BGejQNk&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=30",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:35,prevLetter:{id:"fixed",title:"Fixed"},nextLetter:{id:"the-time-has-passed",title:"The Time Has Passed"}},{id:"the-time-has-passed",title:"The Time Has Passed",date:"11/11/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding requests to join online fellowship)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Have I not provided a bounty? Have I not poured out and sent forth the call? Therefore let those who have come out"},{t:"fn",v:"1"},{t:"text",v:"abide in Me until the time, and eat also of this bread. For I shall be with them, yes, even I Myself shall be with them, close at hand, and they shall fellowship with Me in the secret place. They have all they need. Yet as for this table, the door is shut, that it may be for a testimony of that which is coming quickly and of that which I am about to do. Yet let those who reject Me and My Word, even this blessing which I have given to this generation, walk through dry places. For I have left them desolate. And so they must walk, they must tread the path they have chosen, until the time be changed, until they are broken without hand. I AM THE LORD."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, again I say,"}],[{t:"italic",v:"To all those who have ears to hear:"}],[{t:"italic",v:"Seek not the table, but He who sits at it..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "I Am Calling You Out! (Part 2)"',url:"https://www.thevolumesoftruth.com/I_Am_Calling_You_Out!_(Part_2)..._Come_Out_of_the_Churches_of_Men_and_I_Will_Receive_You!_Says_The_Lord"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-time-has-passed",videoVoiceUrl:"https://www.youtube.com/watch?v=vBOfCvLYRKY&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=31",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:36,prevLetter:{id:"keeping-the-wolves-at-bay",title:"Keeping the Wolves at Bay"},nextLetter:{id:"i-know-my-sheep",title:"I Know My Sheep"}},{id:"i-know-my-sheep",title:"I Know My Sheep",date:"12/1/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Sister in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Regarding this quote from the Letters: \u201CTherefore I am coming quickly, and will take from among you those who are ready, those who have treated others as they would be treated, and done to others as they would do unto Me; yes, all those in whom I see of Myself shall be snatched away\u201D... A sister in Christ said, \u201CWhen I read things like this, my stomach goes in knots. I can\u2019t do these things. I try to do unto others as I do unto The Lord, but it has become a burden to me. I can\u2019t do it, so if I can\u2019t do it, why would God leave me behind for not being able to?\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved daughter, how is it you have come this far and now endeavor to paint Me as the one who is to blame for your unwillingness, as the author of your sins, like those in the churches of men?"},{t:"fn",v:"1"},{t:"text",v:"I AM NOT THAT JESUS!"},{t:"fn",v:"2"},{t:"text",v:"Nor is there one in all the earth who is like Me. There are none like Me, beloved, nor has there ever been one whose love surpasses understanding, a love without end. For I had paid the ransom from the beginning, a dowry the likes of which has never been seen, a bride-price from The God of Heaven. Beloved, I stretched out My hands for you; I bore the weight of your sins, I carried your burdens! Therefore is My grace sufficient for you. Yet you must choose to stand up and walk in Me, relying on My strength in your times of weakness, by which My strength and your trust is made perfect. Have I not said,"},{t:"italic",v:"\u201CIn obedience is your love made perfect,\u201D"},{t:"text",v:"and,"},{t:"italic",v:"\u201CWho you choose, not what you choose, is the answer\u201D?"},{t:"text",v:"And when you have chosen Me, is it not also your reasonable service to walk in Me?"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, again I say, choose..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I am The Only Way,"}],[{t:"italic",v:"The Only Truth, The Only Life..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'See: "Regarding Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},2:{type:"note",text:'See: "The Messiah"',url:"https://answersonlygodcangive.com/The_Messiah"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-know-my-sheep",videoVoiceUrl:"https://www.youtube.com/watch?v=WWAR_Ko-vds&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=32",videoMusicUrl:"https://www.youtube.com/watch?v=nSsyYCmSVk4&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=27",relatedTopics:[{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:37,prevLetter:{id:"the-time-has-passed",title:"The Time Has Passed"},nextLetter:{id:"watchmen",title:"Watchmen"}},{id:"watchmen",title:"Watchmen",date:"12/15/10",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Those in Men\u2019s Fellowship, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord YahuShua:"},{t:"text",v:"I have cleansed My well beloved, even every vessel, as many as are willing to receive, as many as are willing to walk in My ways and make their repentance full."},{t:"fn",v:"1"},{t:"text",v:"Yet who among you has truly received? Who among you has made every effort to cast off his old nature and walk free? Who has come to Me naked that he may be clothed in My righteousness, that I might gird him with My strength? My sons, My way is not easy. And those sent to prepare My way before Me shall indeed be persecuted and slandered, hated by all nations because of Me; yes, even by those who say they are My people, yet are not My people, for they refuse to accept Me as I truly am. Yet the power of My strength shall be fulfilled in My servant\u2019s weakness, in accordance with their love and faithfulness, and by their willingness to lay down their life, that they might receive of My life..."},{t:"italic",v:"A man in desperate thirst who refuses every cup from men, yet gladly drinks from Mine; a man whose hunger has brought forth within him a great void, which can not be filled by any earthly bread, a man who strives to live by every word that proceeds from the mouth of God; a man who carries Me within him, bearing the scars of My Passion in his heart, always."}]}],footnotes:{1:{type:"note",text:'See: "Regarding True Repentance"',url:"https://answersonlygodcangive.com/Regarding_True_Repentance"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/watchmen",videoVoiceUrl:"https://www.youtube.com/watch?v=42mcGfNb_ME&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=33",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:38,prevLetter:{id:"i-know-my-sheep",title:"I Know My Sheep"},nextLetter:{id:"trust-comes-by-service-and-sacrifice",title:"Trust Comes by Service and Sacrifice"}},{id:"trust-comes-by-service-and-sacrifice",title:"Trust Comes by Service and Sacrifice",date:"1/3/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Little flock, consider nothing you have done thus far as anything more than your reasonable service."},{t:"fn",v:"1"},{t:"text",v:"Or is your love limited and your compassion conditional? When will you open to Me and be healed? When will your hearts burst inside you, setting you free? Yet because you are dull of hearing, and your hearts remain calloused and hard, I tell you plainly, you live in kings\u2019 houses! And to those of you who yet resist My words, I say this: Are not all your needs met, as though you dwell in the court? What lack have you, save that which remains wanting in your heart?"}]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you the truth..."}]]},{type:"poetry",lines:[[{t:"italic",v:"ALL who forsake the poor"}],[{t:"italic",v:"And the needy, and the fatherless"}],[{t:"italic",v:"And the widow, do not know Me,"}],[{t:"italic",v:"And have no place with Me at My supper,"}],[{t:"italic",v:"Until they become as those they have forsaken..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For by no other means will they"}],[{t:"italic",v:"Learn true compassion."}]]},{type:"para",segments:[{t:"text",v:"Beloved, to drink My blood is to receive of Me, to give up everything is to walk in Me, to suffer is to know Me, and to die for another is to know the depths of My love. Yet I do not ask you to die for another, only that you push through - that you shatter all this stained glass with which you surround yourselves; that you be broken in pieces and truly become My disciples; that you love one another, even all those I send to you..."},{t:"italic",v:"That you surrender your lives and be created anew, trusting in Me to supply all that is needful, trust which comes by service and sacrifice, says The Lord."}]}],footnotes:{1:{type:"note",text:'See: "Reasonable Service"',url:"https://www.thevolumesoftruth.com/Reasonable_Service"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/trust-comes-by-service-and-sacrifice",videoVoiceUrl:"https://www.youtube.com/watch?v=T8ud4z_SqPU&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=34",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"God Speaks Regarding Those Who Forsake the Poor and the Needy",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Forsake_the_Poor_and_the_Needy"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"}],num:39,prevLetter:{id:"watchmen",title:"Watchmen"},nextLetter:{id:"blessed-are-those-who-hunger-and-thirst-for-righteousness",title:"Blessed Are Those Who Hunger and Thirst for Righteousness"}},{id:"blessed-are-those-who-hunger-and-thirst-for-righteousness",title:"Blessed Are Those Who Hunger and Thirst for Righteousness",date:"1/22/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:'This question was asked: What does the following verse in The Letters mean: "One who is awakened can not remain so, unless they receive of Me and also eat of that which I provide"?'},{t:"fn",v:"1"},{t:"italic",v:""}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"One who has truly received of Me has tasted, and within them a great hunger builds. Yet the one who has not truly received does not hunger, nor do they thirst. For these partaking of My food involves effort, in where they quickly grow weary, as they slowly fade back into slumber; their newfound faith dying due to their lack, a need which remained covered, hidden under the guise of pretense, says The Lord."}]}],footnotes:{1:{type:"note",text:'Also read: "Awaken... Partake of The Living Bread"',url:"https://www.thevolumesoftruth.com/Awaken_Partake_of_The_Living_Bread",link:{collection:"Volume Four",letterTitle:"Awaken... Partake of The Living Bread"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/blessed-are-those-who-hunger-and-thirst-for-righteousness",videoVoiceUrl:"https://www.youtube.com/watch?v=cXvnfVetvoc&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=35",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:40,prevLetter:{id:"trust-comes-by-service-and-sacrifice",title:"Trust Comes by Service and Sacrifice"},nextLetter:{id:"the-heart-of-the-matter",title:"The Heart of the Matter"}},{id:"the-heart-of-the-matter",title:"The Heart of the Matter",date:"1/31/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have mourned, yet who has offered to wipe My tears? I was poured out, mocked, beaten and scourged, pierced, yet who has come forward to kiss My wounds? Behold, My own people reject Me! And those who call of themselves Christian have hated both Me and My Word, refusing to walk in My ways, nor will they receive correction! Behold, even now they persecute Me, slandering all those I send - their hearts consumed with envy, their eyes blazing with contempt! Therefore what more shall be done, beloved? What more shall I speak? What more will they hear, if they reject that which has already been given?"}]},{type:"para",segments:[{t:"text",v:"And what of you, beloved? You have indeed entered in, yet who among you has mourned or stopped to consider? For I tell you the truth, you also push out the hand as you refuse to be broken, you also deny Me in favor of your own way. Behold, pretense and hypocrisy abound, yes, even among you, little flock. For each of you look outwardly, as you lean upon the perceived faith and knowledge of others. You accept little and eat even less, refusing accountability. And when you partake of My words, you read them as one afar off, as one who hears yet only slightly, straining to listen only when it suits you, partaking of My Word as one devours a piece of fruit. How then shall I heal you? How then shall you shed the skin of this world and be set free? Little flock, how is it you exalt yourselves above the churches, though your eyes remain dim and your ears dull, seeing and hearing yet only in part? Have you forgotten the line, by which those who have the Word of God in their midst are tried,"},{t:"fn",v:"1"},{t:"text",v:"and the time of testing which was to come and is now here? Beloved ones, the time has passed for the churches of men. Will you also come running at the last moment, only to find the door is shut to you also? The Day of The Lord is here! Yet not one of you trembles, not one has rushed out to warn their neighbor. Even among your beloved, of whom you say you love, you have yet to speak to the heart of the matter. Yet you say,"},{t:"italic",v:"\u201CLook at us! We have seen and heard. Behold, we are the real church, The Lord\u2019s body, a church without walls.\u201D"},{t:"text",v:"Yet I tell you the truth, you have closed yourselves in, rebuilding every wall which I have torn down. Thus I am about to shut the door to this table, little flock; I must bring these banquets to a close. What then shall you do when there is no one left to feed you, no one upon which to lean? Yet there is a fellowship which remains most needful, a private place reserved for My people, a banquet which was prepared from the beginning, given freely to all who hunger and thirst. Yet who among you has truly desired to know it?"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, I seek not a relationship"}],[{t:"italic",v:"Of convenience, nor a kiss on the cheek"}],[{t:"italic",v:"As you swiftly pass Me by..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I seek union..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, I ask you once again,"}],[{t:"italic",v:"Do you really love Me?"}]]}],footnotes:{1:{type:"note",text:'See: "The Measuring Line"',url:"https://www.thevolumesoftruth.com/The_Measuring_Line"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-heart-of-the-matter",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding The True Church",url:"https://answersonlygodcangive.com/Regarding_The_True_Church"}],num:41,prevLetter:{id:"blessed-are-those-who-hunger-and-thirst-for-righteousness",title:"Blessed Are Those Who Hunger and Thirst for Righteousness"},nextLetter:{id:"true-repentance",title:"True Repentance"}},{id:"true-repentance",title:"True Repentance",date:"2/5/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy During Fellowship",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"A brother in Christ said: I don\u2019t think I ever find myself putting others before me. Lord, help me."}]},{type:"para",segments:[{t:"italic",v:"[The Lord replied]"},{t:"text",v:"My son, does not conviction also bring about revelation in those in whom My spirit dwells? And when it is finished, does it not also lead to repentance, producing new and righteous works?... A deep desire to be set free in My love, followed by a sincere unyielding commitment to make your love perfect through obedience;"},{t:"italic",v:"the shedding of the skin of this world, the crucifying of your old man with his sinful ways, the putting on of the new man who is renewed in the knowledge of The Holy One, conforming to the image of Him who created him."},{t:"fn",v:"1"},{t:"text",v:"For this, My son, is true repentance, says The Lord."}]},{type:"para",segments:[{t:"italic",v:"A brother in Christ said: Thank You, Lord, for the correction You have given us. Lord, have we truly repented?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"My son, your question can only be answered by tasting the salt in one\u2019s tears, says The Lord."}]}],footnotes:{1:{type:"scripture",ref:"Colossians 3:9-10"}},nkjv:{"Colossians 3:9-10":"9. Do not lie to one another, since you have put off the old man with his deeds, 10. and have put on the new man who is renewed in knowledge according to the image of Him who created him,"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/true-repentance",videoVoiceUrl:"https://www.youtube.com/watch?v=qq6HyWYzWvY&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=37",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:42,prevLetter:{id:"the-heart-of-the-matter",title:"The Heart of the Matter"},nextLetter:{id:"ears-to-hear",title:"Ears to Hear"}},{id:"ears-to-hear",title:"Ears to Hear",date:"2/11/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding the gift of prophecy)",blocks:[{type:"para",segments:[{t:"text",v:"It is written:"},{t:"italic",v:"There is no prophecy apart from My will, and without My voice there can be no prophesying. And without My spirit, no man may hear, nor shall he behold a vision, nor is he able to understand. Thus he is only a prophet in that self-same moment in which I speak to him and cause him to hear, prophesying only as long as I cause him to speak or to write My words. I AM THE LORD."},{t:"fn",v:"1"}]},{type:"para",segments:[{t:"text",v:"Beloved ones, all My sheep hear My voice. Yet each receives in proportion to their faith and in accordance with My will and purpose. For a willing, humble heart is open to Me, and one who is deeply in love with Me will hear My voice. Yet this is not equal, nor shall every servant hear My voice in the same way. For a prophet hears My voice, while another is moved deep within, while still others may only discern My leading, and this also is according to My will and purpose. Yet do not be at all surprised by this. For the Scriptures testify to the same, and I will surely do according to the counsel of My own will. And that which I do has a perfect work within the hearts of My beloved, coming to fruition in those who remain in My love, those meet for The Master\u2019s use."}]},{type:"para",segments:[{t:"italic",v:"Hear and understand:"},{t:"text",v:"I have spoken to My prophets throughout the generations (for I change not), and each was given that which was required to accomplish My will among the people."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore rejoice, My sons and daughters!"}],[{t:"italic",v:"For The Most High has come down to you;"}],[{t:"italic",v:"And behold, I have caused My servants to hear,"}],[{t:"italic",v:"To receive wisdom by the power of My own spirit..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Lo, by the Word of My mouth shall"}],[{t:"italic",v:"My beloved be blessed, the prideful humbled"}],[{t:"italic",v:"And the haughty abased..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the Word of The Lord never returns void..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"italic",v:"Yet understand this also:"},{t:"text",v:"That which I commanded be written in a book was named according to the one who received it, so all may know to whom I have spoken, lest any lay claim to My words as though they were their own, polluting them, bringing upon themselves quick judgment and great recompense. And so it is to this day; I speak to whomever I choose, and it is noted that this is the one to whom I have spoken - Let not another lay claim! Beloved ones, human power is of no use at all. You are but vessels for My glory. And when one departs from this wisdom and falls away, My Word also grows quiet as My hand is removed. And I shall surely humble them, according to the length of time I dictate as needful. Yet if one turns and does not cease from fighting against Me, the very same shall have their name stricken from My Book. I AM THE LORD."}]}],footnotes:{1:{type:"note",text:'See: "Gnashing Children"',url:"https://www.thevolumesoftruth.com/Gnashing_Children"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/ears-to-hear-3",videoVoiceUrl:"https://www.youtube.com/watch?v=G-6KxfM3p4U&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=37",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the Voice of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Voice_of_The_Lord"},{label:"About The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Spiritual Gifts",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Gifts"}],num:43,prevLetter:{id:"true-repentance",title:"True Repentance"},nextLetter:{id:"kindle-the-flame-of-your-hearts-on-the-sabbath-day",title:"Kindle the Flame of Your Hearts on The Sabbath Day"}},{id:"kindle-the-flame-of-your-hearts-on-the-sabbath-day",title:"Kindle the Flame of Your Hearts on The Sabbath Day",date:"2/18/11",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For a Brother in Christ and For The Lord\u2019s Little Flock",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked during an online fellowship: I have a question about preparing food on the Sabbath. Is this allowed? Exodus 35:3 says: \u201CYou shall kindle no fire throughout your dwellings on the Sabbath day.\u201D We need fire to heat up food. Or is this an ordinance?"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"That which is needful do."},{t:"italic",v:"For the Sabbath was made for man, and not man for the Sabbath, as it is written."},{t:"fn",v:"1"},{t:"text",v:"Therefore prepare your meals as desired, in accordance with the needs of your household. In doing so, you have kindled no fire within your dwelling, nor have you gone out to gather wood."}]},{type:"poetry",lines:[[{t:"italic",v:"Yet the servant who is wise prepares"}],[{t:"italic",v:"For the Sabbath on the sixth day,"}],[{t:"italic",v:"In anticipation of the seventh..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I desire that all My people"}],[{t:"italic",v:"Rest on the Sabbath Day."}]]}],footnotes:{1:{type:"scripture",ref:"Mark 2:27"}},nkjv:{"Mark 2:27":"And He said to them, \u201CThe Sabbath was made for man, and not man for the Sabbath."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/kindle-the-flame-of-your-hearts-on-the-sabbath-day-2",videoVoiceUrl:"https://www.youtube.com/watch?v=Hbntq2SzyRw&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=39",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"}],num:44,prevLetter:{id:"ears-to-hear",title:"Ears to Hear"},nextLetter:{id:"consider",title:"Consider"}},{id:"consider",title:"Consider",date:"3/7/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have brought you up as My own children. I have nourished you with good food, yes, with very fine food and satisfying drink. I have dwelt in the midst of you, and among you I have spoken plainly, revealing the truth of who I am. Behold, I have laid My heart open before your eyes, and into your ears I have spoken. As a harpist playing soft music, beautiful music, plucking each string with delicate fingers, I revealed the song of My heart to you. With precise strokes, in gentle tones of healing, with many notes of unending love and by soothing vibrations of peace, did the sound of My love speak. And I, even I, The Lord of Hosts, did not withhold from you. Yea, even the fierceness of My wrath was not hidden from you; neither did I conceal the weight of My sorrow. My judgments I have declared openly, and into the ears of My prophet did I reveal the full measure of My indignation. And still I am not known among you; I remain hidden from your eyes. Therefore consider the fear of The Lord, and gain wisdom; consider the knowledge of The Lord, that your understanding may be full; partake of the fullness of this tree, and consider the root thereof."}]},{type:"para",segments:[{t:"italic",v:"My children, seek My glory and look to My Righteousness, for The Kingdom of Heaven is at hand! Look into My eyes, open your ears to My voice, for the mouth of The Lord has spoken! Return to the first works; it is time to be consumed in your First Love!"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, see the Word of The Lord,"}],[{t:"italic",v:"Drink deeply from this vine..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Consider My Mercy and the name of Love,"}],[{t:"italic",v:"That you may know Me as I truly am,"}],[{t:"italic",v:"That we may be one..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Consider, for it is time..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/consider",videoVoiceUrl:"https://www.youtube.com/watch?v=Yry9MUy9Jgo&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=39",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],num:45,prevLetter:{id:"kindle-the-flame-of-your-hearts-on-the-sabbath-day",title:"Kindle the Flame of Your Hearts on The Sabbath Day"},nextLetter:{id:"my-words-are-pure",title:"My Words are Pure"}},{id:"my-words-are-pure",title:"My Words are Pure",date:"3/7/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Little flock, I have taken from you My lampstand, and from you this table is removed. For I do always what is right by My children, says The Lord."}]},{type:"para",segments:[{t:"text",v:"Beloved, are you still without knowledge? Are you still without understanding? The humble receive of My gifts, and the pure in heart shall behold My face forever. Yet among you I see some who look elsewhere for fulfillment, running to and fro, seeking here a little and there a little, that you might ease your troubled hearts - This should not be! I see a flock who is always seeking after something new, as though you had itching ears. And when I grew quiet, and removed My mouthpiece from you, you immediately sought after another. Yes, you went out, and behold, another endeavored to speak on My behalf. Yet from the overflow of his heart was the message brought forth; I did not speak to him, nor did I command him to write. Thus you are not yet able to distinguish the voice of The Lord from your own, nor are you able to distinguish the voice of recollection from that which My prophets hear. Therefore, O faithless children, I have indeed stepped back from you, that you might strain to hear, that you might let go of your pride and fall down heavily, that you might break and be humbled, and remember. For I have called to you many times, yet you have not come to Me without condition. I have spoken a multitude of words, yet you retain no knowledge, nor have you given heed. I have served you food and drink from My own table, yet you are never satisfied."}]},{type:"poetry",lines:[[{t:"italic",v:"Yet My words are pure..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A solid foundation beneath the feet"}],[{t:"italic",v:"Of My beloved, a sure way for all who believe..."}]]},{type:"poetry",lines:[[{t:"italic",v:"My words are a strong staff in the hand"}],[{t:"italic",v:"Of all those who do them, and all who place"}],[{t:"italic",v:"Their trust in Me will never falter..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/my-words-are-pure",videoVoiceUrl:"https://www.youtube.com/watch?v=eWCf_44U-F8&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=40",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"}],num:46,prevLetter:{id:"consider",title:"Consider"},nextLetter:{id:"the-way-of-the-lord-is-equal",title:"The Way of The Lord Is Equal"}},{id:"the-way-of-the-lord-is-equal",title:"The Way of The Lord Is Equal",date:"3/15/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Little flock, how is it you say within yourselves the way of The Lord is not equal? How is it you feel as though upon this servant I have poured a bounty, yet you remain desolate? Beloved ones, by whose power were you called forth into existence? To whose joy were you created? By whose favor were you born into this world by way of water and blood? Therefore, again I say to you, who you choose is everything. For I do not withhold My love, yet on account of your flesh you do always step backward. Consider the woman who touched My robes and was made whole. Tell Me, how is it that she received and you do not? Was she so highly favored, that she should receive and you should not? Beloved, come close and walk beside Me, for you are indeed highly favored! And all who grab hold of Me shall surely share in all that is Mine. Little flock, My ways are equal, yet the ways of My people remain unequal. For I have indeed poured out My life for you, yet each one must decide how deeply they drink. Do you not see? My blessings are equal for all who receive of My blessings, and My grace sufficient for all who trust in Me. Thus among those who come to Me, one is not favored over another, nor is My love bestowed by measure. Rather it is you who receive by measure, resisting on account of all these deceitful weights, trust which remains altogether lacking. Therefore do not confuse My love with the calling I have purposed for another, nor compare the gifts of the Spirit with The Blessing. For those I have called to serve shall indeed be given gifts, each in accordance with their faith and My will. And those who receive the greater gifts shall also bear the greater burden, even in the heat of the Day."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, again I say to you,"}],[{t:"italic",v:"The Lord\u2019s ways are indeed equal,"}],[{t:"italic",v:"Yet the ways of men remain unequal..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet those who grab hold of their First Love"}],[{t:"italic",v:"With all their heart, with all their mind,"}],[{t:"italic",v:"With all their strength and with all their soul,"}],[{t:"italic",v:"Shall never go hungry, nor shall they thirst anymore;"}],[{t:"italic",v:"Nor shall the heat of the noonday"}],[{t:"italic",v:"Sun do them any harm..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yea, even all their tears shall be wiped away"}],[{t:"italic",v:"In the house of The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-way-of-the-lord-is-equal",videoVoiceUrl:"https://www.youtube.com/watch?v=RQ8WynhtSpM&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=41",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Spiritual Gifts",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Gifts"}],num:47,prevLetter:{id:"my-words-are-pure",title:"My Words are Pure"},nextLetter:{id:"a-rare-bundle",title:"A Rare Bundle"}},{id:"a-rare-bundle",title:"A Rare Bundle",date:"3/15/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Beloved, you are to be a flock set apart, a rare bundle who has the Word of The Lord in their midst, a blameless people, servants who do what is right and good at all times and in every season, disciples who do not hide what they are doing. Neither shall you break the laws of your land, nor devise schemes to hide from your persecutors. Or do you yet lack faith, unwilling to endure for My name\u2019s sake? Yet I tell you this, the days are evil. And the day is indeed coming quickly, when times and laws shall be changed, and evil shall reign for a short season. And in that day and at that time, you shall not obey the laws of your land, which I hate; nor shall you honor any appointed time or season, which causes you to sin against The Lord your God. I AM THE LORD."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-rare-bundle",videoVoiceUrl:"https://www.youtube.com/watch?v=W48lC0eqgFI&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=42",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:48,prevLetter:{id:"the-way-of-the-lord-is-equal",title:"The Way of The Lord Is Equal"},nextLetter:{id:"cut-off",title:"Cut Off"}},{id:"cut-off",title:"Cut Off",date:"5/8/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Those Who Have Gone Astray, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, I put forth My hand and offered you bread, I opened My mouth and breathed upon you blessings from above, offering you wisdom, with stern and loving counsel. Yet you do not embrace Me, resisting My voice, disobeying My commands, seeking always to go roundabout, though I Myself had spoken to you, saying,"},{t:"italic",v:"\u201CNo more shall My servants go roundabout when they hear no answer; nor shall they go roundabout when My answer is not to their liking. For Timothy is My prophet, he speaks for Me, and by him have I made My plans known.\u201D"}]},{type:"para",segments:[{t:"text",v:"Yet you do not believe. Therefore you are cut off, My hand removed, until the time be changed."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/cut-off-2",videoVoiceUrl:"https://www.youtube.com/watch?v=ul5aIWLHzp8&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=43",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:49,prevLetter:{id:"a-rare-bundle",title:"A Rare Bundle"},nextLetter:{id:"a-right-heart-bridles-the-tongue-and-a-forgiving-heart-absolves-every-hurt-bringing-peace-to-the-mind",title:"A Right Heart Bridles the Tongue; And a Forgiving Heart Absolves Every Hurt, Bringing Peace to the Mind"}},{id:"a-right-heart-bridles-the-tongue-and-a-forgiving-heart-absolves-every-hurt-bringing-peace-to-the-mind",title:"A Right Heart Bridles the Tongue; And a Forgiving Heart Absolves Every Hurt, Bringing Peace to the Mind",date:"8/8/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy and His Wife, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"You have been faithful, and from your mouths you have testified of My glory. Yet I tell you, let judgment be no more upon your lips, and cause unforgiveness to pass from your hearts. When a brother or sister has gone astray, and done that which I said they shall not do, I ask you, what is that to you? Do they not answer to their own master? Judge not another\u2019s servant, but to your own Master be true. Beloved, speak not one word concerning those who have hurt you, not one more word against those who have betrayed you. Forgive them, pray for them, and let them go their way. Beloved, love your enemies and pray for those who betray you, and double for those who fight against you, for they have lifted up their heel against Me. Let resentment pass from your heart, and no more let your tongue cause you to stumble on their account. For each is accountable for their own heart and that which flows from it, even to every idle word."}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, be My examples..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Order your speech like David,"}],[{t:"italic",v:"And conduct yourselves as Daniel..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Let your speech express your"}],[{t:"italic",v:"Love for Me in every situation,"}],[{t:"italic",v:"And let your conduct reveal My spirit"}],[{t:"italic",v:"In you in open and in secret..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, prepare as though I were"}],[{t:"italic",v:"Coming to take you this very day;"}],[{t:"italic",v:"Walk with Me as though we walk"}],[{t:"italic",v:"Together in the Garden already..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-right-heart-bridles-the-tongue-and-a-forgiving-heart-absolves-every-hurt-bringing-peace-to-the-mind",videoVoiceUrl:"https://www.youtube.com/watch?v=gVtw5MdeckU&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=44",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Unforgiveness",url:"https://answersonlygodcangive.com/Regarding_Unforgiveness"},{label:"Regarding Forgiveness",url:"https://answersonlygodcangive.com/Regarding_Forgiveness"},{label:"Regarding Prayer",url:"https://answersonlygodcangive.com/Regarding_Prayer"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Patience",url:"https://answersonlygodcangive.com/Regarding_Patience"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"}],num:50,prevLetter:{id:"cut-off",title:"Cut Off"},nextLetter:{id:"repentance",title:"Repentance"}},{id:"repentance",title:"Repentance",date:"8/13/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"A brother in Christ asked this question: Will you ask The Lord if He is pleased with my wife\u2019s repentance?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"In repentance I am always well pleased. Therefore let the penitent now turn fully to God,"},{t:"italic",v:"and do works meet for repentance."},{t:"fn",v:"1"},{t:"text",v:"Let them no more be as the hypocrite, but let them walk close behind Me, abiding in the shadow of The Almighty."},{t:"italic",v:"And let the wife in her youth learn piety at home, for this is good and acceptable before God."},{t:"fn",v:"2"}]},{type:"poetry",lines:[[{t:"italic",v:"And what more shall I speak than"}],[{t:"italic",v:"That which I have spoken already?..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore believe My words,"}],[{t:"italic",v:"And also do them, says The Lord."}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 3:8"},2:{type:"scripture",ref:"1 Timothy 5:4"}},nkjv:{"Matthew 3:8":"Therefore bear fruits worthy of repentance,","1 Timothy 5:4":"But if any widow has children or grandchildren, let them first learn to show piety at home and to repay their parents; for this is good and acceptable before God."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/repentance",videoVoiceUrl:"https://www.youtube.com/watch?v=0KhyyGJiil0&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=45",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Unforgiveness",url:"https://answersonlygodcangive.com/Regarding_Unforgiveness"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding Being Born Again",url:"https://answersonlygodcangive.com/Regarding_Being_Born_Again"}],num:51,prevLetter:{id:"a-right-heart-bridles-the-tongue-and-a-forgiving-heart-absolves-every-hurt-bringing-peace-to-the-mind",title:"A Right Heart Bridles the Tongue; And a Forgiving Heart Absolves Every Hurt, Bringing Peace to the Mind"},nextLetter:{id:"set-your-house-in-order",title:"Set Your House in Order"}},{id:"set-your-house-in-order",title:"Set Your House in Order",date:"8/13/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"A Brother in Christ asked this question: I know The Lord has said correction is not to come from without, but from within. I also know that He has appointed me as head over this house. So is it my place, as head of the household, to correct the younger brothers and sisters staying here, or is that the responsibility of their parents alone? Or was I just \u201Ccorrecting from without\u201D?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"My son, did I not say to you that it is time to set your house in order? How is it you have not understood My speech? For the outward appearance of a man means little, yet the inward man I know, and this is the house which must first be set in order. For what man is able to manage the affairs of his earthly household, when his spiritual house remains in disarray? And what temple is offered to The Lord without first being cleaned and swept? Yet you I have made, by My own hands were you created, even now you are as clay. Beloved son, you are that temple which is being cleaned and swept. How is it then you yet hold on to those things which are yours no longer? Why do you grasp at that which is being swept away?"}]},{type:"para",segments:[{t:"text",v:"Now concerning the correction and discipline of the younger brothers and sisters in your household, here is wisdom: A daughter can have only one father, and the father\u2019s friend is to share in the father\u2019s concern, because he is a friend and also a brother. Yet the father is the head of his daughter, and the friend is only to lend an ear. And one who shares his household with others shall lead by example, remembering that the host is also a servant, even to every guest, no matter the length of their stay."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, seek to make your house"}],[{t:"italic",v:"A house of God, both within and without."}]]},{type:"poetry",lines:[[{t:"italic",v:"For you are My son, and these"}],[{t:"italic",v:"With you are My sons and daughters."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore let all of you agree together"}],[{t:"italic",v:"And make haste, for the angels of Heaven"}],[{t:"italic",v:"Must soon ascend and descend upon The Son of Man..."}],[{t:"stanza-break"}],[{t:"italic",v:"Says The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/set-your-house-in-order",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Parenting",url:"https://answersonlygodcangive.com/Regarding_Parenting"}],num:52,prevLetter:{id:"repentance",title:"Repentance"},nextLetter:{id:"the-valley-of-discontent",title:"The Valley of Discontent"}},{id:"the-valley-of-discontent",title:"The Valley of Discontent",date:"8/20/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Is there not a prophet among you, that you might seek him out to know My will? And who is a prophet of The Most High God? Who have I declared, and who among this generation have I appointed to speak for Me? Is there not one among you, who I have commanded to write My words in a book? Or have you taken it upon yourselves to stand in his stead?"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Lord, for thus says The Lord:"},{t:"text",v:"Each of you seek your own will. You follow the counsels and dictates of your own hearts, always seeking but never finding, listening but failing to hear. Yet from the beginning I taught you, speaking to you of that which pleases Me, of that which is right and good in My eyes. Beloved ones, I do not stand divided against Myself. Neither shall I break faith with that which I have spoken, neither the former nor the latter. Therefore have your wanton desires come full circle; thus has your selfishness brought you to this place. For you have become as those who say,"},{t:"italic",v:"\u201CDo not prophesy to us right things. Speak only pleasant words. Tell us what we want to hear.\u201D"},{t:"text",v:"Yet The Word of God has spoken; the Scriptures do not lie, and My every Letter is Truth. Behold, I have put forth a great multitude of words to bless you, a great number of loving and stern speeches. I have called this generation to repent, and have given ample warning. And those who cupped their ears heard My voice, and those who received of Me wrote My words in their heart, sincerely seeking to do them, that they might honor Me and bring glory to My name. Yet many in this little flock have given the scoffer occasion to blaspheme, doing those things which I did not command - always running ahead or lagging behind, never content to walk beside Me, unwilling to accept Me as I truly am."}]},{type:"para",segments:[{t:"text",v:"Beloved, awake! For I tell you the truth, ALL have entered in! Yes, you reside in the Day of The Lord, you walk in the Day of Troubles already; and behold, the Great and Terrible Day is close at hand. It is awesome and dreadful, and shall be very terrible, the Day in which all shall be tried, when all things are tested, the Day in which all the works of men shall burn."}]},{type:"closing",text:"For I AM THE LORD, And there is but One Escape..."},{type:"poetry",lines:[[{t:"italic",v:"Whether one lives or dies,"}],[{t:"italic",v:"There is but One Salvation..."}]]},{type:"poetry",lines:[[{t:"italic",v:"No matter the time or the season,"}],[{t:"italic",v:"There is but One..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Declares The Almighty."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-valley-of-discontent",videoVoiceUrl:"https://www.youtube.com/watch?v=2yodiLoS2cg&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=46",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Way, The Truth, The Life",url:"https://answersonlygodcangive.com/The_Way,_The_Truth,_The_Life"}],num:53,prevLetter:{id:"set-your-house-in-order",title:"Set Your House in Order"},nextLetter:{id:"in-one-accord",title:"In One Accord"}},{id:"in-one-accord",title:"In One Accord",date:"10/10/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",noteLine:"(Regarding Men\u2019s Fellowship)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"You shall meet on the Sabbath, at a time which is pleasing to all members, both near and far. The time spent together in My Word shall be kept holy, for I am holy. And where two or three are gathered together in My name, there I am in the midst of them. Therefore I have placed this opportunity before My sons, once again, that they might prepare their hearts and make ready, that they might come together and fellowship with Me in one accord. For I am indeed coming quickly."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the signs of My coming"}],[{t:"italic",v:"Are made plain and are revealed in the"}],[{t:"italic",v:"World everyday, even in every corner,"}],[{t:"italic",v:"Yet that which I am doing is not"}],[{t:"italic",v:"Easily discerned by men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For their hearts are hard, and they"}],[{t:"italic",v:"Remain slow of understanding..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore great trust is required,"}],[{t:"italic",v:"And must be born of real belief,"}],[{t:"italic",v:"Knowing I AM WHO I AM."}]]},{type:"para",segments:[{t:"text",v:"Thus those who say they know Me, yet do not embrace Me as I am, remain daunted. For their trust was not founded upon The Rock, but upon the shifting sands of human expectation and arrogant assumption, which led them into their own private interpretation of My Word, having also forgotten that no prophecy of Scripture is to be interpreted by an individual on his own. For no prophecy or Scripture has ever come about by the power of man\u2019s will. Rather, as it is written:"},{t:"italic",v:"Those chosen by God were given ears to hear His voice, and by the power of His spirit, according to His will, they received a message from God."},{t:"fn",v:"1"},{t:"text",v:"Thus I have allowed this fellowship to continue, that My glory may be revealed among you, that your trust may be established upon true knowledge and the revelation of who I am; not by searching here a little or there a little, that you might somehow confirm your own perverse expectations or arrogant assumptions, that you might somehow find a way to alleviate your troubled hearts, seeking in vain for that peace which is yours already, if you would only believe. My sons, do not come together in fellowship for the sake of regaining something you feel you have lost, or in an effort to heal this breach which you yourselves have created, or so your trust may once again be propped up by the perceived faith or knowledge of another. Rather come together in union, one with the other, in Me, that the glory of who I am may no longer be polluted among you, that My words may no longer be mistreated by you in an effort to fulfill your own selfish desires. Therefore, let My words be read aloud or played in your hearing, whether understanding is quick in coming or hidden from your eyes. Let My words be heard as they are - no more, no less."}]},{type:"poetry",lines:[[{t:"italic",v:"My sons, listen to the sound of My voice!"}],[{t:"italic",v:"Fall in love with Me as at the first,"}],[{t:"italic",v:"Come to Me anew as in the beginning..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, it is time to acquiesce,"}],[{t:"italic",v:"To fully surrender to the truth of who I am..."}]]},{type:"poetry",lines:[[{t:"italic",v:"To be submersed in My spirit,"}],[{t:"italic",v:"To be baptized in My love,"}],[{t:"italic",v:"To seek first The Kingdom of God"}],[{t:"italic",v:"And His Righteousness, which I am!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then shall that which is needful be added to you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"scripture",ref:"2 Peter 1:20-21 (CJB)"}},nkjv:{"2 Peter 1:20-21 (CJB)":"20. First of all, understand this: no prophecy of Scripture is to be interpreted by an individual on his own; 21. for never has a prophecy come as a result of human willing \u2014 on the contrary, people moved by the Ruach HaKodesh spoke a message from God."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/in-one-accord",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"},{label:"Discernment",url:"https://answersonlygodcangive.com/Main_Page#Discernment"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"}],num:54,prevLetter:{id:"the-valley-of-discontent",title:"The Valley of Discontent"},nextLetter:{id:"my-bride-is-chosen",title:"My Bride Is Chosen"}},{id:"my-bride-is-chosen",title:"My Bride Is Chosen",date:"10/27/11",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For The Lord\u2019s Little Flock and for All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His Little flock:"},{t:"text",v:"I am not at all satisfied with what I see. For you tread the line with one foot, and with the other you seek to run back into the world. Beloved, did I not tell you that I would treat this little flock as I treated My people, Israel, in the wilderness? And is there not a prophet among you, even as Moses walked among Israel, repeating My every word to the multitude? Yet do not concern yourselves with their number, nor compare, but consider the message and look upon the example. For the size of a flock matters little. Rather it was the message and the example, which spoke throughout the generations. For the heart of every hearer is precious in My sight, yet those full of complaints shall be rebuked and chastened. Yet the heart of the scoffer is an abomination to The Lord. For I do not change."}]},{type:"para",segments:[{t:"text",v:"Therefore I ask you, who among you has remained faithful? Who among you holds a listening ear, eager to receive My every word? Yea, who among this great multitude called Christian has truly devoted themselves to Me? Little flock, did you think I had not seen it?! Did you think I would stay silent at a time such as this?! Even now I hear you saying within yourselves,"},{t:"italic",v:"\u201CSpeak no more the word of The Lord, lest I feel convicted and further burdened. Cast these cords from me, for the weight of this yoke is too heavy. I no longer wish to stand and bear it, I no longer wish to embrace it. Let me go my own way.\u201D"}]},{type:"para",segments:[{t:"text",v:"Thus as a flower which springs up in a stony place, as a plant which has no depth of earth, so also are you, little flock. For your trust is easily toppled, and your faith withers for lack of water, for you have no root. Behold, many thorns have sprung up, yet you make no effort to break free! Beloved, when will you open to Me? When will you drink from this fountain? When will you pick up your cross and follow after Me? Disobedient children, come out from among them, and be joined unto Me!"}]},{type:"poetry",lines:[[{t:"italic",v:"The time has passed, beloved ones..."}],[{t:"stanza-break"}],[{t:"italic",v:"My bride is chosen."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/my-bride-is-chosen",videoVoiceUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Faith",url:"https://answersonlygodcangive.com/Regarding_Faith"},{label:"I Am Calling You Out",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out"},{label:"The True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#The_True_Bride"}],num:55,prevLetter:{id:"in-one-accord",title:"In One Accord"},nextLetter:{id:"offerings",title:"Offerings"}},{id:"offerings",title:"Offerings",date:"2/27/12",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Little flock, hear now and understand, says The Lord."}]},{type:"para",segments:[{t:"text",v:"For thousands of years My people have brought Me offerings, even from the very beginning. Indeed many gifts have been placed upon My altar, yet not all were accepted..."},{t:"italic",v:"A gift of love is accepted, a gift of worship is well pleasing in My sight, a gift of thanksgiving is a very wise offering indeed."},{t:"text",v:"Yet those who come to leave their gift for their own sake, or for the sake of the onlooker, are not accepted."},{t:"italic",v:"And those who offer a gift, and then remember that a brother or sister has something against them, should leave their gift and go and be reconciled to their brother or sister, and then come and offer their gift, as it is written."},{t:"fn",v:"1"},{t:"text",v:"And those who offer a gift for those in need, with no thought to whom it is truly offered, let them keep their gift and do with it as they please; it is not accepted. And those who give begrudgingly do not know Me. How is it that many of you must be prompted to do a good deed? Has goodness now become a burden to you? Or is the one in the mirror your only concern? Do not be fooled, but remember:"},{t:"italic",v:"It is who you choose that defines what you do."},{t:"fn",v:"2"},{t:"italic",v:"And faith without works is dead, even as works done without faith are dead also. And one who bears their own burdens must also bear the heat of the day. Yet one who lets go, cutting every cord that binds them to this world, walks free, and shall be given eagle\u2019s wings. For idle hands lack bread, and an idle heart lacks trust; their backs are bent down always, their countenances fallen, their eyelids have grown very heavy. Yet love strengthens the spirit and washing another\u2019s feet is good for the soul, renewing the whole of the body."},{t:"text",v:"Little flock, why do you hold on so tightly to that which is passing away, and grasp that which is not your own? Why do you cast off knowledge and depart from trust, choosing rather to embrace your own selfish expectations, which only cause you to stumble? I am very displeased. Yet I remain always The Good Teacher, who continually reminds His students of that which He has taught them before they lose sight of The Goal. I remain also The Faithful Shepherd, who calls to His sheep before they have wandered too far, The Wise and Loving Father who makes the sins of His beloved known early, while they are still able to step easily off the crooked path, says The Lord."}]}],footnotes:{1:{type:"scripture",ref:"Matthew 5:23-24"},2:{type:"note",text:'See: "Choose Me"',url:"https://www.thevolumesoftruth.com/Choose_Me#Choose_Me",link:{collection:"Volume Four",letterTitle:"Choose Me"}}},nkjv:{"Matthew 5:23-24":"23. Therefore if you bring your gift to the altar, and there remember that your brother has something against you, 24. leave your gift there before the altar, and go your way. First be reconciled to your brother, and then come and offer your gift."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/offerings",videoVoiceUrl:"https://www.youtube.com/watch?v=mJiW8kMeaKo&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=48",relatedTopics:[{label:"Regarding Tithing",url:"https://answersonlygodcangive.com/Regarding_Tithing"}],num:56,prevLetter:{id:"my-bride-is-chosen",title:"My Bride Is Chosen"},nextLetter:{id:"a-bitter-cup-a-heavy-burden",title:"A Bitter Cup, a Heavy Burden"}},{id:"a-bitter-cup-a-heavy-burden",title:"A Bitter Cup, a Heavy Burden",date:"5/25/12",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"There are some among this little flock who have taken it upon themselves to speak on My behalf, striving to attain that which they do not understand. Yet they are no mouthpieces, nor have I called them to this office. Yet sons and daughters they remain."}]},{type:"para",segments:[{t:"text",v:"Therefore, this is what I say to them: Draw back your hand from the page, and place your pen back on the table, remove your fingers from the keys, and make no effort to operate within the gift of prophecy. For upon you this gift is not bestowed, nor have I marked you with My signet. Beloved ones, search the Scriptures so you may know; read My Letters, that you may understand. For the cup of The Lord is a heavy burden, a bitter cup filled with tears and sorrow. Therefore, I ask you, are you able to drink it? I tell you the truth, you are not at all able. For you do not know what you seek, nor do you understand. For the weight of this burden is very heavy, a path heavy-laden with suffering and death, great tribulation. For as it is written:"},{t:"italic",v:"My way is not easy. And those sent to prepare My way before Me shall indeed be persecuted and slandered, hated by all nations."},{t:"fn",v:"1"},{t:"text",v:"Thus I ask you once again, are you able to drink of this cup? Are you able to bear the full weight of this burden? Beloved, it is not My will that you do so, says The Lord."}]}],footnotes:{1:{type:"note",text:'See: "Watchmen"',url:"https://www.thevolumesoftruth.com/Watchmen#:~:text=My%20way%20is%20not%20easy.%20And%20those%20sent%20to%20prepare%20My%20way%20before%20Me%20shall%20indeed%20be%20persecuted%20and%20slandered%2C%20hated%20by%20all%20nations%20because%20of%20Me%3B%20yes%2C%20even%20by%20those%20who%20say%20they%20are%20My%20people%2C%20yet%20are%20not%20My%20people%2C%20for%20they%20refuse%20to%20accept%20Me%20as%20I%20truly%20am.",link:{collection:"Letters to The Lord's Little Flock",letterTitle:"Watchmen",excerpt:"My way is not easy. And those sent to prepare My way before Me shall indeed be persecuted and slandered, hated by all nations because of Me; yes, even by those who say they are My people, yet are not My people, for they refuse to accept Me as I truly am."}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-bitter-cup-a-heavy-burden",videoVoiceUrl:"https://www.youtube.com/watch?v=jRQzcUJP5QQ&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=47",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding Spiritual Gifts",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Gifts"}],num:57,prevLetter:{id:"offerings",title:"Offerings"},nextLetter:{id:"the-sabbath-was-made-for-man-and-not-man-for-the-sabbath",title:"The Sabbath Was Made for Man, and Not Man for The Sabbath"}},{id:"the-sabbath-was-made-for-man-and-not-man-for-the-sabbath",title:"The Sabbath Was Made for Man, and Not Man for The Sabbath",date:"1/24/13",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"On the Sabbath, do those things which are pleasing in My sight, that we may be glad together. Come to Me and receive peace, for in Me shall you find rest, says The Lord."}]},{type:"para",segments:[{t:"text",v:"Therefore, My son, give ear to My speech, and let your heart leap with joy in My presence."},{t:"italic",v:"For I made the Sabbath for man, and not man for the Sabbath."},{t:"fn",v:"1"},{t:"text",v:"Yet very few understand its true purpose, nor can any comprehend the full scope of its meaning, until the day they enter in. For the Sabbath is more than rest, and the Commandment"},{t:"fn",v:"2"},{t:"text",v:"more than peace, for a day in The Lord is as a thousand years! Therefore, as I rested on the seventh day, so also shall My people."},{t:"italic",v:"For I had blessed and sanctified the seventh day from the beginning"},{t:"fn",v:"3"},{t:"text",v:", a day set apart and holy, even as those in whom I dwell are set apart and holy."}]},{type:"poetry",lines:[[{t:"text",v:"My son, follow Me, walk in My footsteps,"}],[{t:"text",v:"And you shall surely be blessed."}]]},{type:"poetry",lines:[[{t:"text",v:"For the servant who walks in My ways"}],[{t:"text",v:"Shall know Me, and the disciple who"}],[{t:"text",v:"Rests in Me on the Sabbath Day shall have peace."}]]}],footnotes:{1:{type:"scripture",ref:"Mark 2:27"},2:{type:"scripture",ref:"Exodus 20:8-11"},3:{type:"scripture",ref:"Genesis 2:3"}},nkjv:{"Mark 2:27":"And He said to them, \u201CThe Sabbath was made for man, and not man for the Sabbath.","Exodus 20:8-11":"8. \u201CRemember the Sabbath day, to keep it holy. 9. Six days you shall labor and do all your work, 10. but the seventh day is the Sabbath of the LORD your God. In it you shall do no work: you, nor your son, nor your daughter, nor your male servant, nor your female servant, nor your cattle, nor your stranger who is within your gates. 11. For in six days the LORD made the heavens and the earth, the sea, and all that is in them, and rested the seventh day. Therefore the LORD blessed the Sabbath day and hallowed it.","Genesis 2:3":"Then God blessed the seventh day and sanctified it, because in it He rested from all His work which God had created and made."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-sabbath-was-made-for-man-and-not-man-for-the-sabbath",videoVoiceUrl:"https://www.youtube.com/watch?v=4NRp2XT0LPs&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=50",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],num:58,prevLetter:{id:"a-bitter-cup-a-heavy-burden",title:"A Bitter Cup, a Heavy Burden"},nextLetter:{id:"deplorable",title:"Deplorable"}},{id:"deplorable",title:"Deplorable",date:"12/26/16",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For a Brother in Christ, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"A brother in Christ asked this question: Is this Scripture, \u201CThose who knowingly celebrate Easter and its deplorable traditions hate My resurrection\u201D"},{t:"fn",v:"1"},{t:"italic",v:"equal to saying those who knowingly celebrate Christmas and its deplorable traditions hate His birth?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"My son, is it not implied? Is it not self-evident in the eyes of those who have received understanding? For they are indeed equal. Thus ALL who knowingly celebrate these so-called holidays in the name of The Messiah, whom they call Jesus and Christ, while reveling in all their deplorable traditions, hate both Me and My Word, doing those things which I said they shall not do. Yea, from the beginning I said,"},{t:"italic",v:"\u201CObey My voice, and I will be your God and you shall be My people. And walk in all the ways that I have commanded you, that it may be well with you.\u201D Yet they do not obey nor incline the ear, but walk always in the counsel and stubbornness of their own evil hearts, going backward and not forward, as it is written."},{t:"fn",v:"2"},{t:"text",v:"For they worship another god and have fallen in love with another messiah - an impostor, an idol - of which they continually mold to meet their own perverse desires."},{t:"fn",v:"3"},{t:"italic",v:"Thus there is indeed nothing new under the sun."},{t:"fn",v:"4"},{t:"text",v:"For as it was in the days of old with My people Israel, so it is this day also among those who say they are My people..."},{t:"italic",v:"Yet they are NOT My people! Says The Lord."}]}],footnotes:{1:{type:"note",text:'See: "Join Not in the Error of the People"',url:"https://www.thevolumesoftruth.com/Join_Not_in_the_Error_of_the_People#:~:text=Thus%20says%20The%20Lord%20YahuShua%3A%20Those%20who%20knowingly%20celebrate%20Easter%20and%20its%20deplorable%20traditions%20hate%20My%20resurrection.",link:{collection:"Volume Six",letterTitle:"Join Not in the Error of the People",excerpt:"Those who knowingly celebrate Easter and its deplorable traditions"}},2:{type:"scripture",ref:"Jeremiah 7:23-24 (ESV)"},3:{type:"note",text:'See: "Regarding "Another Messiah""',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},4:{type:"scripture",ref:"Ecclesiastes 1:9 (NKJV)"}},nkjv:{"Jeremiah 7:23-24 (ESV)":"23. But this command I gave them: \u201CObey my voice, and I will be your God, and you shall be my people. And walk in all the way that I command you, that it may be well with you.\u201D 24. But they did not obey or incline their ear, but walked in their own counsels and the stubbornness of their evil hearts, and went backward and not forward.","Ecclesiastes 1:9 (NKJV)":"That which has been is what will be, That which is done is what will be done, And there is nothing new under the sun."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/deplorable",videoVoiceUrl:"https://www.youtube.com/watch?v=azUVDewL79c&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=48",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"The Holidays of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Holidays_of_Men_Are_an_Abomination_to_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Man's Holidays vs. God's Holy Days (comparison)",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men#Man.27s_Holidays_vs._God.27s_Holy_Days_.28comparison.29"}],num:59,prevLetter:{id:"the-sabbath-was-made-for-man-and-not-man-for-the-sabbath",title:"The Sabbath Was Made for Man, and Not Man for The Sabbath"},nextLetter:{id:"self-evident",title:"Self-Evident"}},{id:"self-evident",title:"Self-Evident",date:"11/13/17",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",noteLine:"(Regarding the false flat earth theory)",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Why do my people embrace foolishness? How is it they still have itching ears? For the truth is easily discerned by those who love The Truth. Yet a lie only causes confusion, breeding an air of doubt."}]},{type:"para",segments:[{t:"text",v:"Therefore look to the heavens above, and upon the earth beneath, for the truth of the matter is self-evident. For all these worlds, which I have created, testify to the truth. From the crescent moon to the lunar eclipse, to every planet and star within your view, all testify to the same. Yet even the shadow at the feet of My servants is proof. And what of the departing ship as it dips below the horizon, or the tall towers as they rise from the earth on long approach? Do I need mention the lofty mountains, or the lone island in the midst of the sea? And how is it that those who dwell in Asia walk about in daylight, yet for you it is night? Therefore consider, for these are but a few of many examples, which remain self-evident. I AM THE LORD."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/self-evident",videoVoiceUrl:"https://www.youtube.com/watch?v=1eQUTf1z59I&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=49",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Flat Earth Theory",url:"https://answersonlygodcangive.com/Regarding_the_Flat_Earth_Theory"}],num:60,prevLetter:{id:"deplorable",title:"Deplorable"},nextLetter:{id:"by-order-of-magnitude",title:"By Order of Magnitude"}},{id:"by-order-of-magnitude",title:"By Order of Magnitude",date:"2/14/22",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Beloved ones, I have spoken a multitude of words in your hearing, I have given a shout and poured out My spirit. Behold, I have whispered into the ears of this generation, to every man, woman and child. Yet who gave heed? Who stood up and proclaimed My coming? Who among men stood firm for who I truly am?! Who bowed down and gave Me glory? Who among this great multitude fell on their faces in true repentance? Who among those, who say they are My people, sought to make their repentance full?! Yea, the little children gave heed, the hearts of the little ones skipped a beat; they, alone, embraced My voice. For they remember, and seek to return to the place from whence they came. Yet this foolish and most wicked generation despised Me in their zeal, and refused to give heed, plugging their ears when I called, turning their backs when I drew near! Thus I removed My Spirit from the people and drew back My hand from the multitude, and they were forsaken - That they might stumble, that they might fall, that they might reap all they have sown in their arrogance, suffocating on account of their greed, until they drown in the depths of their vanity, to their own shame."}]},{type:"para",segments:[{t:"text",v:"For I tell you the truth, that which is tipped can not be set upright again, and that which has been set in motion can not be stopped. Lo, even that which was held captive in the depths of silence has been released, behold, it comes forth, increasing by order of magnitude... And can in no wise be put back again, says The Lord."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/by-order-of-magnitude",videoVoiceUrl:"https://www.youtube.com/watch?v=yf8J-2zkJZc&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=50",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding Children\u2019s Inheritance on Earth and in Heaven",url:"https://answersonlygodcangive.com/Regarding_Children%E2%80%99s_Inheritance_on_Earth_and_in_Heaven"},{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"The One Who Stays, Lets",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets"},{label:"Regarding Pollution and Mankind's Exploitation of the Earth",url:"https://answersonlygodcangive.com/Regarding_Pollution_and_Mankind%27s_Exploitation_of_the_Earth"}],num:61,prevLetter:{id:"self-evident",title:"Self-Evident"},nextLetter:null}],LETTERS_REBUKE_PREFACE={id:"a-warning",title:"A Warning",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"poetry",lines:[[{t:"italic",v:"Thus says The Lord"}],[{t:"italic",v:"To everyone who hears or"}],[{t:"italic",v:"Looks upon the words of this Book:"}]]},{type:"poetry",lines:[[{t:"italic",v:"If anyone adds to these words,"}],[{t:"italic",v:"I will add to them the punishments"}],[{t:"italic",v:"Written in this Book."}],[{t:"stanza-break"}],[{t:"italic",v:"And if anyone takes anything"}],[{t:"italic",v:"Away from the words in the Book"}],[{t:"italic",v:"Of this prophecy, I will take away"}],[{t:"italic",v:"Their share in The Tree of Life"}],[{t:"italic",v:"And The Holy City, as it is written."},{t:"fn",v:"1"}]]},{type:"poetry",lines:[[{t:"italic",v:"For as I am so shall I be,"}],[{t:"italic",v:"As I have spoken so I speak,"}],[{t:"italic",v:"And that which was written by"}],[{t:"italic",v:"My prophets of old remains standing,"}],[{t:"italic",v:"Even to this day."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"scripture",ref:"Revelation 22:18-19"}},nkjv:{"Revelation 22:18-19":"18. For I testify to everyone who hears the words of the prophecy of this book: If anyone adds to these things, God will add to him the plagues that are written in this book; 19. and if anyone takes away from the words of the book of this prophecy, God shall take away his part from the Book of Life, from the holy city, and from the things which are written in this book."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-warning",videoVoiceUrl:"https://www.youtube.com/watch?v=UGM0FH9k4NA&list=PL6D1BC949E9840878&index=1",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"}],isPreface:!0},LETTERS_REBUKE=[{id:"the-word-of-the-lord",title:"The Word of The Lord",date:"3/22/12",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Behold, the oaks of Bashan are toppled! The strongest among them are snapped as twigs; the most ancient among them are easily fallen, toppled by the wind! The cedars of Lebanon have no power! Their uprightness is brought down to the ground; they are all bent backward! Behold, their darkness is consumed in the light of day! Every shadow flees away, says The Lord."}]},{type:"para",segments:[{t:"text",v:"For The Lord has come out of His holy temple, and the Word of The Lord blows upon the face of the whole earth! Strong and upright is The Word of The Most Holy, righteousness is found in all His ways; a rock, a mighty mountain is The Lord! Behold, His Word is a tower of strength, a strong wall which stands forever! Its height rises above the tallest mountain, its length can not be skirted, nor is there one in all creation who can break through! No army can stand against the sound of His Trumpet, nor is there a weapon forged which can break down the wall!"}]},{type:"poetry",lines:[[{t:"italic",v:"For as it is written:"}]]},{type:"poetry",lines:[[{t:"italic",v:"The Word of God is living and powerful,"}],[{t:"italic",v:"Sharper than any double-edged sword..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Piercing to where the soul meets the spirit,"}],[{t:"italic",v:"Cutting through to where the joint meets the bone,"}],[{t:"italic",v:"Even to the marrow..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A discerner of the thoughts,"}],[{t:"italic",v:"A judge of the innermost intentions,"}],[{t:"italic",v:"Revealing the heart of every hearer."},{t:"fn",v:"1"}]]}],footnotes:{1:{type:"scripture",ref:"Hebrews 4:12"}},nkjv:{"Hebrews 4:12":"For the word of God is living and powerful, and sharper than any two-edged sword, piercing even to the division of soul and spirit, and of joints and marrow, and is a discerner of the thoughts and intents of the heart."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-word-of-the-lord",videoVoiceUrl:"https://www.youtube.com/watch?v=eYo_k9MlONk&list=PL6D1BC949E9840878&index=2",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"}],num:1,prevLetter:null,nextLetter:{id:"gnashing-children",title:"Gnashing Children"}},{id:"gnashing-children",title:"Gnashing Children",date:"1/10/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"I have spoken, and sent My messengers before My face. Yet this foolish people can in no wise see, nor are they able to hear. They refuse to look past My messengers; they refuse to acknowledge the Word of The Living God! Yet what is the messenger to you, O ignorant and vain peoples? Why do you consider, so carefully, seeking to find fault with those I send? Why do you concern yourselves with those I choose, and why do you judge those through whom I speak? And what is a prophet? Is he not a man, My servant, whom I have chosen and called? And when does My servant become a prophet, and what is the length of time he remains as such? Lo, he is only a prophet in that self-same moment in which I speak to him and cause him to hear, prophesying only as long as I cause him to speak or to write My words. I AM THE LORD. For there is no prophecy apart from My will, and without My voice there can be no prophesying. And without My spirit, no man may hear, nor shall he behold a vision, nor is he able to understand. Apart from The Holy One, there is no knowledge; only vanities and lies, false glory, evil divinations. Seek therefore true knowledge, and you shall also receive understanding! Get wisdom and heal these blinded eyes, unstop the deafness which plagues your ears! Here is wisdom: If I send a message, even two of the same, each to separate houses by way of two different messengers, then what is that to you? Indeed, what are the messengers to The Message? Am I not The Sender? Have I not the power to speak through whomever I choose, and send whomever I choose? Or would you have sin prevent Me?! Lo, shall I speak through donkeys instead, for they have no sin? Shall I send the birds of the air to be My messengers, for they have no sin? Shall the sins of men prevent Me in anywise?! Shall My voice be stopped by any means?!"},{t:"italic",v:"Behold, by the mouth of Caiaphas I did speak and declare My will and the means by which you would be saved, though he had the greater sin!"},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"FOR I AM THE LORD; I DO NOT CHANGE!"}],[{t:"italic",v:"My words declare My glory, My message reveals"}],[{t:"italic",v:"My majesty and the power of My strength!"}]]},{type:"poetry",lines:[[{t:"italic",v:"STOP STARING AT MY MESSENGERS!"}],[{t:"italic",v:"Look past them and see with greater eyes!"}]]},{type:"para",segments:[{t:"text",v:"Therefore, O ignorant and vain peoples, flee from all these arrogant pastors and prideful teachers, blind guides who closely adhere to every form of doctrine and tradition of men, while forsaking Me and My Word! Escape all these chains and come out from among them, and seek to buy new oil from those who sell the pure oil; they will not withhold, for I have sent them; they will gladly pour out. Yea, they have received an abundance of oil from the storehouses by which you may surely relight your lamps, if you so choose to receive them."}]},{type:"para",segments:[{t:"text",v:"Hurry now, darkness has fallen, and soon the fullness of night will come in where no one will be able to work, save those who will be set up as beacons. These are they who shall be both seen and unseen, those who will pass through the multitudes unnoticed, yet clearly set on a hill. I tell you, no man in authority will find them, nor can any device of men track them, nor shall any do them harm. For I shall be with them and in them, and remain always their rearguard, says The Lord. For indeed, many will come, saying,"},{t:"italic",v:"\u201CLet us slay them!\u201D"},{t:"text",v:"Yet I warn you, though many thousands were slain in times past, and a thousand more were sent, in the Day of The Lord\u2019s Anger it shall not be so! For strong is The Lord, and in My prophets I shall surely come to dwell, even as a flame of fire!"},{t:"italic",v:"Behold, each one shall possess the power of the trumpets of Jericho, and they shall surely give a shout!"},{t:"fn",v:"2"},{t:"text",v:"And woe to all who come against them!"}]},{type:"poetry",lines:[[{t:"text",v:"Therefore come forth, all you wicked!"}],[{t:"text",v:"Seek out My witnesses to do them harm,"}],[{t:"italic",v:"If you have no fear of God in your hearts!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Lift up your voices, all you mockers,"}],[{t:"italic",v:"Make yourselves known, all you scoffers,"}],[{t:"italic",v:"All you who remain blinded in your pride"}],[{t:"italic",v:"And deafened by your arrogance!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"COME OUT, ALL YOU GNASHING CHILDREN!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For The Lord your God has prepared a great slaughter!"}]]}],footnotes:{1:{type:"scripture",ref:"John 11:49-50"},2:{type:"scripture",ref:"Joshua 6:1-21"}},nkjv:{"John 11:49-50":"49. And one of them, Caiaphas, being high priest that year, said to them, \u201CYou know nothing at all, 50. nor do you consider that it is expedient for us that one man should die for the people, and not that the whole nation should perish.\u201D","Joshua 6:1-21":"1. Now Jericho was securely shut up because of the children of Israel; none went out, and none came in. 2. And the LORD said to Joshua: \u201CSee! I have given Jericho into your hand, its king, and the mighty men of valor. 3. You shall march around the city, all you men of war; you shall go all around the city once. This you shall do six days. 4. And seven priests shall bear seven trumpets of rams\u2019 horns before the ark. But the seventh day you shall march around the city seven times, and the priests shall blow the trumpets. 5. It shall come to pass, when they make a long blast with the ram\u2019s horn, and when you hear the sound of the trumpet, that all the people shall shout with a great shout; then the wall of the city will fall down flat. And the people shall go up every man straight before him.\u201D 6. Then Joshua the son of Nun called the priests and said to them, \u201CTake up the ark of the covenant, and let seven priests bear seven trumpets of rams\u2019 horns before the ark of the LORD.\u201D 7. And he said to the people, \u201CProceed, and march around the city, and let him who is armed advance before the ark of the LORD.\u201D 8. So it was, when Joshua had spoken to the people, that the seven priests bearing the seven trumpets of rams\u2019 horns before the LORD advanced and blew the trumpets, and the ark of the covenant of the LORD followed them. 9. The armed men went before the priests who blew the trumpets, and the rear guard came after the ark, while the priests continued blowing the trumpets. 10. Now Joshua had commanded the people, saying, \u201CYou shall not shout or make any noise with your voice, nor shall a word proceed out of your mouth, until the day I say to you, \u2018Shout!\u2019 Then you shall shout.\u201D 11. So he had the ark of the LORD circle the city, going around it once. Then they came into the camp and lodged in the camp. 12. And Joshua rose early in the morning, and the priests took up the ark of the LORD. 13. Then seven priests bearing seven trumpets of rams\u2019 horns before the ark of the LORD went on continually and blew with the trumpets. And the armed men went before them. But the rear guard came after the ark of the LORD, while the priests continued blowing the trumpets. 14. And the second day they marched around the city once and returned to the camp. So they did six days. 15. But it came to pass on the seventh day that they rose early, about the dawning of the day, and marched around the city seven times in the same manner. On that day only they marched around the city seven times. 16. And the seventh time it happened, when the priests blew the trumpets, that Joshua said to the people: \u201CShout, for the LORD has given you the city! 17. Now the city shall be doomed by the LORD to destruction, it and all who are in it. Only Rahab the harlot shall live, she and all who are with her in the house, because she hid the messengers that we sent. 18. And you, by all means abstain from the accursed things, lest you become accursed when you take of the accursed things, and make the camp of Israel a curse, and trouble it. 19. But all the silver and gold, and vessels of bronze and iron, are consecrated to the LORD; they shall come into the treasury of the LORD.\u201D 20. So the people shouted when the priests blew the trumpets. And it happened when the people heard the sound of the trumpet, and the people shouted with a great shout, that the wall fell down flat. Then the people went up into the city, every man straight before him, and they took the city. 21. And they utterly destroyed all that was in the city, both man and woman, young and old, ox and sheep and donkey, with the edge of the sword."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/gnashing-children",videoVoiceUrl:"https://www.youtube.com/watch?v=ei0foTLAP3U&list=PL6D1BC949E9840878&index=3",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Spiritual Gifts",url:"https://answersonlygodcangive.com/Regarding_Spiritual_Gifts"}],num:2,prevLetter:{id:"the-word-of-the-lord",title:"The Word of The Lord"},nextLetter:{id:"you-have-entered-in",title:"You Have Entered In"}},{id:"you-have-entered-in",title:"You Have Entered In",date:"1/31/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Who are all these who stand before Me in arrogant accord? What people is this who have despised Me and My Word? Ignorant and sinful people, you have all become as false gods before Me, detestable idols meet only to be broken in pieces! For each one of you, from the least to the greatest, have turned from Me, each to his own way!..."},{t:"italic",v:"You worship yourselves!"},{t:"text",v:"Yes, you uphold every false image and stand firm for the sake of your own detestable doctrines! You revel in your perverse traditions, to your own shame! You flee all accountability and rest comfortably in your sin, bearing a multitude of bitter fruit in unrighteousness!..."},{t:"italic",v:"Lawless people, you have despised both Me and My Law! Therefore it shall weigh heavily upon you, and you shall bear its weight in the Day of The Lord, every jot and every tittle! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore hear the Word of The Living God, for thus says The Lord:"},{t:"text",v:"You have entered in; yes, The Day is here and ALL have entered in! Therefore grab hold of The Holy One of Israel,"},{t:"italic",v:"and pray that you are counted worthy to escape!"},{t:"fn",v:"1"},{t:"text",v:"Fall on your faces and wail loudly, die to yourselves, cry out! Call upon the name of Salvation, and repent! Did I not say to you that all your knowledge was useless,"},{t:"fn",v:"2"},{t:"text",v:"and all your thoughts and imaginings were in vain? For I am The Lord, and I shall surely do according to the counsel of My own will. Yet the scholars cry,"},{t:"italic",v:"\u201CFalse!\u201D"},{t:"text",v:"And those who call of themselves Christian plot in vain against My messengers. And the people of Israel walk proudly, exalting themselves by their own knowledge, though they remain ignorant, for The Truth remains hidden from their eyes"},{t:"fn",v:"3"},{t:"text",v:"..."},{t:"italic",v:"Oh My people, when will you cast yourselves down?! When will you be humbled?! When will you forsake your so-called knowledge and be set free?! I AM THE LORD! YES, I AM HE! There is no knowledge apart from Me, and there can be no understanding save it is given you by Mashiach! HE is your Master!"}]},{type:"para",segments:[{t:"italic",v:"Have you not felt these pangs, O earth?! Have you not recoiled in pain, O heavens?! Has not fear grabbed hold of you, O mighty nations?! Blind and hard peoples, REPENT! For My face is turned against you, My shoulders are set, and My hand is ready to strike! Behold, I shall strike the waters, and they shall rise up against you; from bitterness to the raging of the seas, the waters shall oppress you! I shall strike the mountains, and they shall speak and bring forth a great noise; they shall consume you and bury your cities! I shall strike the heavens, and it shall rain down fire and flooding rain, with a great multitude of hail! Lo, I shall strike the foundations of the earth, and the whole world shall be shaken! Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"FOR I AM THE LORD WHO REIGNS!"}],[{t:"italic",v:"He who stretched out the heavens"}],[{t:"italic",v:"And laid the foundations of the earth!"}],[{t:"italic",v:"YAHUWAH, He who formed it and causes to be!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the whole world is but a footstool beneath My feet,"}],[{t:"italic",v:"A rock in My hand made of limestone, easily broken..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Luke 21:36"},2:{type:"note",text:'See: "your knowledge is useless"',url:"https://www.google.com/search?hl=en&ei=j07cXJSoJuGBk-4P0KiTqA0&q=site%3Athevolumesoftruth.com+%22your+knowledge+is+useless%22&oq=site%3Athevolumesoftruth.com+%22your+knowledge+is+useless%22&gs_l=psy-ab.12...34364.34364..38158...0.0..0.89.89.1......0....2j1..gws-wiz.fVZ9VIsUWzc"},3:{type:"scripture",ref:"2 Corinthians 3:14-16"}},nkjv:{"Luke 21:36":"Watch therefore, and pray always that you may be counted worthy to escape all these things that will come to pass, and to stand before the Son of Man.\u201D","2 Corinthians 3:14-16":"14. But their minds were blinded. For until this day the same veil remains unlifted in the reading of the Old Testament, because the veil is taken away in Christ. 15. But even to this day, when Moses is read, a veil lies on their heart. 16. Nevertheless when one turns to the Lord, the veil is taken away."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/you-have-entered-in",videoVoiceUrl:"https://www.youtube.com/watch?v=4PqGeK5Nlx0&list=PL6D1BC949E9840878&index=4",videoMusicUrl:"https://www.youtube.com/watch?v=7GRSWckHJ1o&list=PLSVchFJ22QYKZW4CHtZ43YBxdHUTgS9rv&index=2",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"}],num:3,prevLetter:{id:"gnashing-children",title:"Gnashing Children"},nextLetter:{id:"blood-pours-down",title:"Blood Pours Down"}},{id:"blood-pours-down",title:"Blood Pours Down",date:"2/14/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Blood pours down, a waterfall of tears flow down! Rivers of tears and blood run through the desolate places, yet no growth is seen; nothing at all sprouts forth from the hard and cracked ground! The sound of the charadrion is not heard, neither do the doves come out of their hiding places in the morning; no song is heard..."},{t:"italic",v:"Blood pours down to cover the mountains! Blood pours down and tears cover the land! Blood and tears fall upon the parched ground, yet only dust and ashes remain."},{t:"text",v:"The earth cries out in the morning, and the people mourn at eventide; from dusk until the dawn, the bodies are piled up in heaps! The whole world loves violence, and over all this murder barely a tear is shed; the voice of weeping and lamentation is rarely heard above a whisper. And the cries of every unborn child is muffled by the sound of their mother\u2019s dying womb, as her heart becomes stone..."},{t:"italic",v:"The light of her eyes darkening; her life, forfeit."},{t:"text",v:"Mankind is covered in wickedness! The breadth of the whole earth is filled with every kind of evil! Every tree is dry and bears bitter fruit! For the heart of man is black, the void within him deep, a widening chasm filled with deep darkness, sheer cliffs on every side!..."},{t:"italic",v:"Every branch withers, no more will leaves appear, dry and dead branches ready to be broken off and cast into the fire."}]},{type:"para",segments:[{t:"text",v:"The heart of The Lord your God is very heavy. The heart of The Lord is enraged, and is very heavy. The sorrow of The Lord is deep and infinite."}]},{type:"para",segments:[{t:"text",v:"My people, let it be known to you, I take no pleasure at all in what I must do, in what must be done - NO PLEASURE AT ALL! Says The Lord. As My hand draws back, blood pours down! As I strike the earth in My anger, My tears run down! As famine spreads forth across the land, My heart is rent inside Me over the hardness of men\u2019s hearts! As My face fills with the heat of My fury, My eyes are set ablaze with fire over that which I see! My tears run down, My blood pours down. As My own servants turn from Me and run, as My own beloved, whom I have called sons and daughters, turn and fight against Me, as My own body betrays Me, My blood pours down, My tears run down."}]},{type:"poetry",lines:[[{t:"italic",v:"As the nations come together and bind"}],[{t:"italic",v:"My hands and My feet, My tears run down..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As they bruise Me and spit in My eyes,"}],[{t:"italic",v:"While mocking Me, My tears run down..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As they pierce My side, My blood and"}],[{t:"italic",v:"Tears run down together!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As My own people drive in the nails still,"}],[{t:"italic",v:"I am risen up from My place with My arms"}],[{t:"italic",v:"Spread apart, waiting to receive them!"}],[{t:"italic",v:"My blood runs down, the tears run down..."}]]},{type:"poetry",lines:[[{t:"italic",v:"OH MY PEOPLE, WHY HAVE"}],[{t:"italic",v:"YOU FORSAKEN ME?!"}]]},{type:"para",segments:[{t:"text",v:"Hard generation! Sleeping children! Even My own fall asleep, unable to watch with Me for one hour; their hearts hardened, unwilling to weep with Me in this last hour. Do you not understand My sorrows, little flock? They refuse to be healed! Therefore, I must destroy them!..."},{t:"italic",v:"My blood runs down, and they refuse it! My tears fall like rain upon the nations, yet they will not lift their head, nor do they hold out their tongue to drink it! Where have all My children gone?! They choose death! THEY CHOOSE DEATH! And at the Last Day, they shall surely receive it; they shall taste of it to the fullest! Therefore do My tears run down; therefore do the rivers run like death through the waste places."},{t:"text",v:"Beloved, they heap up death, only to throw themselves upon the heap! Lo, they have made their covenant with death, and with the grave they are in agreement! They burn candles and make sacrifices to other gods; yea, they bow down to them! Behold, they shall be slaughtered and burned together!..."},{t:"italic",v:"The whole field is diseased, every leaf is blighted and withers, every stalk is rotten even to the roots! It must be purged and burned with fire! Therefore do My tears run down; therefore does My sorrow continue on, forever. The wound is incurable! Therefore My love will weep, and My heart will wail, forever."}]},{type:"para",segments:[{t:"text",v:"Have you not read My words, little flock? Are your ears yet dull in hearing? Yet My words shall not return void. For the beasts of the earth languish, and the creatures of flight fail to soar, for they know what is coming. Lo, I have nourished and brought forth young children to weep in your places, for you were unwilling. And still the mighty stand proud, and the feeble follow close behind in their example, refusing to bow down, covering themselves in pretense while wearing many disguises, until the face they behold in the mirror has become unrecognizable to them."}]},{type:"poetry",lines:[[{t:"italic",v:"THEY DO NOT KNOW ME!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"My blood runs down, yet I do not know them!"}],[{t:"italic",v:"My tears run down, yet My own people remain"}],[{t:"italic",v:"Unclean, hiding always in their deceitful houses!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"From the least to the greatest, I tell you,"}],[{t:"italic",v:"They have surely hated Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore I am come down to take My spoil,"}],[{t:"italic",v:"To purge and to slaughter! Blood and fire!"}],[{t:"italic",v:"Rivers of blood and pillars of smoke!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"This world is condemned,"}],[{t:"italic",v:"And The Father has declared its end!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM COME DOWN!"},{t:"fn",v:"1"},{t:"italic",v:" ..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'Also read: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/blood-pours-down-2",videoVoiceUrl:"https://www.youtube.com/watch?v=tlRcOvInlsM&list=PL6D1BC949E9840878&index=5",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."}],num:4,prevLetter:{id:"you-have-entered-in",title:"You Have Entered In"},nextLetter:{id:"the-glory-of-men-must-die",title:"The Glory of Men Must Die"}},{id:"the-glory-of-men-must-die",title:"The Glory of Men Must Die",date:"2/22/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Did you think My wrath would tarry forever? Did you think My judgment sleeps? Are My eyes closed to all these atrocities committed upon the earth, day and night without ceasing?! Are My ears also stopped from hearing? Lo, I have seen and I have heard!..."},{t:"italic",v:"My face draws near to this earth, My eyes are filled with fire and fury! My forehead wrinkles and is set hard against you, O inhabitants of the earth, for it is time!"},{t:"text",v:"It is time to shake the cities of men by measure, and to bring up wrath from beneath! City by city shall be punished, one here and another there! Behold, it shall come upon them suddenly, and men shall fear, and with great perplexity shall their hearts fail; a great trembling shall now come upon all people!..."},{t:"italic",v:"THE TERROR OF THE LORD IS AT HAND!"},{t:"fn",v:"1"},{t:"text",v:"It shall come in swiftly, and you shall not know from where it shall come! It shall come upon city after city without warning, for I have caused the earth to become angry! Lo, the depths of the earth tremble at My nearness, and soon this planet shall rage!..."},{t:"italic",v:"It shall rage against you, O deceitful generation! It shall devour and consume this generation, scouring from the earth all man has made!"},{t:"text",v:"The Scriptures do not lie! And My prophets speak, yet the people refuse to hear; they will not listen! Even My own people will not believe! Yet their belief is not at all required. For My will is set and can in no wise be turned back. The truth of My Word stands; it speaks throughout the generations and echoes throughout eternity! For I am The Lord, YAHUWAH, I am EL Shaddai, and I shall surely perform all I have spoken! I shall not cease, nor relent, nor shall I be turned back from My purpose!..."},{t:"italic",v:"The kingdoms of men must die, and the evil of men must be destroyed; all must be wiped away!"},{t:"text",v:"Peoples of the earth, you have hated life, you have polluted My garden! Diseased and awful generation, you have destroyed the garden! And so I am come to cleanse, and to wipe away! I am come down, My face is very near! Do you feel the heat of My wrath, O ignorant and vain peoples?! You retain no knowledge at all! Only greed and wickedness, wickedness upon wickedness, passes before your eyes without ceasing, and oh how you love to have it so! DEAD GENERATION, YOUR HEARTS ARE STONE! Day after day you build up wrath, the vessels overflow! Day by day, the bodies are stacked up in heaps! Day by day, the unborn are slaughtered, whole generations of people murdered without cause, multitudes of innocent cast off as refuse! Yet you think Me too harsh, and My punishments too severe, My judgments unfair."}]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD, AND THIS IS MY EARTH!"}],[{t:"italic",v:"THESE ARE MY CHILDREN!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"All you see, from the ground beneath your feet"}],[{t:"italic",v:"To the farthest reaches of the universe, is MINE,"}],[{t:"italic",v:"And I shall do as I please!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I shall do according to the counsel"}],[{t:"italic",v:"Of My own will,"},{t:"fn",v:"2"},{t:"italic",v:"for I am God!"}]]},{type:"para",segments:[{t:"text",v:"Therefore, O peoples of the earth, because you have slaughtered the innocent and murdered your neighbor, lo, you have even made for yourselves laws that all may do their pleasure in unrighteousness and perform evil at their leisure, so then shall I also declare MY Law, and it shall fall hard upon the backs of all nations! Yea, I have put forth the decree and hasten to carry out your sentences, O peoples of the earth! And what is the sentence, you ask?..."},{t:"italic",v:"Look upon the slaughtered innocent! Look upon their torn and broken bodies; behold how they are torn in pieces! See how their blood pours down and their limbs are strewn about! LOOK! Look how they are scraped out of their mother\u2019s womb! Look upon the works of your hands, you evil and most wicked generation! LOOK UPON YOUR WICKEDNESS! LOOK UPON ALL YOU HAVE DONE!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God, Creator of Heaven and Earth:"},{t:"text",v:"Because of this blood which remains on your hands, because of all the multitudes of slain you have piled up in heaps, because of the evil works of your hands in where you have agreed together, to both do and allow them, to make them law, THUS SHALL I IN LIKE MANNER DO UNTO YOU! IN LIKE MANNER SHALL YOU RECEIVE AT MY HAND! Lo, even double shall you receive at My hand, and double again, until there is no place found that is not laid waste, until every land is polluted by the stink of rotting corpses! Both man and beast shall lie down in death together; they shall be as refuse upon the land! I shall tear down your cities and break apart all your dwelling places! I shall tear your leaders in pieces and pour out the blood of your mighty men upon the ground, until it reaches unto the neck!"},{t:"fn",v:"3"},{t:"text",v:"Behold, all mighty and evil men shall be torn in pieces, with their limbs strewn about in the open fields and in the waste places!"},{t:"fn",v:"4"},{t:"text",v:"Behold, the great army, the astonishing company, the assemblage of nations who have come together to fight against The Holy One of Israel,"},{t:"fn",v:"5"},{t:"text",v:"shall be broken in pieces without hand! For strong is The Lord, and sharp is the sword which proceeds from His mouth!"},{t:"fn",v:"6"},{t:"text",v:"Behold I, even I, The Lord of Hosts, shall scrape every last vestige of man and his inventions from the earth at the Last Day! For I am God, and the glory of My strength is revealed in My Holy One!"}]},{type:"poetry",lines:[[{t:"italic",v:"The glory of men must die!"}],[{t:"italic",v:"Declares The Lord of Hosts,"}],[{t:"italic",v:"The Only Creator, The God of Israel..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YES, I AM HE, YAHUWAH!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Hurry now, those who hear!"}],[{t:"italic",v:"Hurry now, those who know Me!"}],[{t:"italic",v:"Hurry and kiss The Son!"},{t:"fn",v:"7"}],[{t:"italic",v:"Hurry now and kiss Me upon My face,"}],[{t:"italic",v:"All you who know My name!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA-YAHUWAH!"}]]}],footnotes:{1:{type:"scripture",ref:"Isaiah 2:19 (NKJV)"},2:{type:"scripture",ref:"Ephesians 1:11 (NKJV)"},3:{type:"scripture",ref:"Revelation 14:20"},4:{type:"scripture",ref:"Revelation 19:17-18"},5:{type:"scripture",ref:"Revelation 19:19"},6:{type:"scripture",ref:"Revelation 19:15"},7:{type:"scripture",ref:"Psalm 2:12 (NKJV)"}},nkjv:{"Isaiah 2:19 (NKJV)":"They shall go into the holes of the rocks, And into the caves of the earth, From the terror of the LORD And the glory of His majesty, When He arises to shake the earth mightily.","Ephesians 1:11 (NKJV)":"In Him also we have obtained an inheritance, being predestined according to the purpose of Him who works all things according to the counsel of His will,","Revelation 14:20":"And the winepress was trampled outside the city, and blood came out of the winepress, up to the horses\u2019 bridles, for one thousand six hundred furlongs.","Revelation 19:17-18":"17. Then I saw an angel standing in the sun; and he cried with a loud voice, saying to all the birds that fly in the midst of heaven, \u201CCome and gather together for the supper of the great God, 18. that you may eat the flesh of kings, the flesh of captains, the flesh of mighty men, the flesh of horses and of those who sit on them, and the flesh of all people, free and slave, both small and great.\u201D","Revelation 19:19":"And I saw the beast, the kings of the earth, and their armies, gathered together to make war against Him who sat on the horse and against His army.","Revelation 19:15":"Now out of His mouth goes a sharp sword, that with it He should strike the nations. And He Himself will rule them with a rod of iron. He Himself treads the winepress of the fierceness and wrath of Almighty God.","Psalm 2:12 (NKJV)":"Kiss the Son, lest He be angry, And you perish in the way, When His wrath is kindled but a little. Blessed are all those who put their trust in Him."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-glory-of-men-must-die",videoVoiceUrl:"https://www.youtube.com/watch?v=wQUHWgyx-Ro&list=PL6D1BC949E9840878&index=6",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to the Peoples of the Earth",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Peoples_of_the_Earth"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:"Regarding Pollution and Mankind's Exploitation of the Earth",url:"https://answersonlygodcangive.com/Regarding_Pollution_and_Mankind%27s_Exploitation_of_the_Earth"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:'The Name of The Lord - "YAHUSHUA-YAHUWAH"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YAHUSHUA-YAHUWAH"}],num:5,prevLetter:{id:"blood-pours-down",title:"Blood Pours Down"},nextLetter:{id:"established",title:"Established"}},{id:"established",title:"Established",date:"3/7/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Why do My people step backward in astonishment? Why are they taken aback by My words spoken to this generation, as though I have now become their enemy? Is it not rather you who have made yourselves enemies of God?! For I tell you the truth, by your many adulteries you have revealed who is first, and by your rebellion you have declared your allegiance! Yet you can only serve one master. Thus you, My people, have made your choice, for you are not My people! Yet those who"},{t:"italic",v:"remain in My love"},{t:"fn",v:"1"},{t:"text",v:"have chosen their need, even of that which is most needful, in where My clay must be remolded fully, until every last vessel of honor is completed and set upright. Yet the vessels of wrath shall never be established; they shall be ground to dust beneath My feet! Behold, even now their life pours out of them! For pride strangles the strongest among them, arrogance eats the flesh of the mighty man, and the proud look of the oppressor shall bring desolations and plagues upon him! For The Lord your God is great in power, and the strength of The Lord is made ready! The Word of The Lord has spoken and shall surely strike through, from the piercing of the heart to the stealing of the breath! For this most wicked generation has surely robbed Me; thus I shall also rob them! Says The Lord. Their lives are forfeit, and shall be required of them in one day! Behold, in a day they did not look for, and at a time they did not expect, their hearts shall be stilled in death and their breath shall flee away! For their foreheads are hardened, and with their mouths they strike at My messengers! As a stonecutter strikes the stone, so do these strike at My witnesses; in the strength of their pride, they strike with the hammer! Yet I shall make their arms heavy, and their mallets shall never find the mark; nor shall their chisel break the surface, and their wedge shall have no place; scoring shall be of no help to them, nor shall their technique yield any result. For My messengers can not be cracked, nor is there one able to break them. From The Rock are they forged, and with a heart like adamant stone have I made them unwavering in My purpose. For the zeal of The Lord of Hosts has established them, and upon their foreheads the name of The Father and The Son is written."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, I shall dash the rebellious in pieces"}],[{t:"italic",v:"Upon the rocks, and send the jackals"}],[{t:"italic",v:"To carry away their carcasses!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For they have trusted in false glory"}],[{t:"italic",v:"And wear shame as a garment,"}],[{t:"italic",v:"Cursing My name without ceasing,"}],[{t:"italic",v:"And against My servants they bring"}],[{t:"italic",v:"Railing accusations of every kind!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet My servants are established still..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"John 15:10 (CEB)"}},nkjv:{"John 15:10 (CEB)":"If you keep my commandments, you will remain in my love, just as I kept my Father's commandments and remain in his love."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/established-3",videoVoiceUrl:"https://www.youtube.com/watch?v=BFPi7_uF214&list=PL6D1BC949E9840878&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"}],num:6,prevLetter:{id:"the-glory-of-men-must-die",title:"The Glory of Men Must Die"},nextLetter:{id:"the-god-of-israel-has-set-his-face-to-pour-out-judgment",title:"The God of Israel Has Set His Face To Pour Out Judgment"}},{id:"the-god-of-israel-has-set-his-face-to-pour-out-judgment",title:"The God of Israel Has Set His Face To Pour Out Judgment",date:"3/15/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Hear the Word of The Lord, for thus says The Lord:"},{t:"text",v:"The pride of man is grievous, and the heart of man grows increasingly wicked; his eyes are darkened, his mind filled with deceits."},{t:"italic",v:"Behold, the whole earth is corrupt and filled with violence! Lo, even My own people fight against Me! Indeed, all flesh have corrupted their way before Me"},{t:"fn",v:"1"},{t:"text",v:"..."}]},{type:"para",segments:[{t:"text",v:"Therefore I shall bring calamity in waves, great destruction upon this generation of evil men, evil men who are set under the authority of evil men, hidden evil in high places! For I am come to stir up the multitudes, and to shake the nations mightily! Behold, I shall grab hold of the Pacific plate, and twist! I shall press down hard, and it shall tip, it shall crack, it shall surely buckle! In that day, the waters shall flow backward! No more shall I cause the ocean to know its place! No more shall I say to the waters, \u201CYou shall proceed no further!\u201D For I shall strike the northernmost parts, until they are no more! I shall reach down to the south, into the great treasuries of ice and snow, and push them into the sea in one day! And the seas shall increase by measure before the eyes of all these multitudes, before the eyes of all those who dwell near the coastline, and before the paled faces of the wealthy, who by greed and evil gain have constructed tall towers and built extravagant houses upon the shore! Therefore, watch! Be awestruck in astonishment, O foolish people who build on the sand!"},{t:"fn",v:"2"},{t:"text",v:"Watch how swiftly calamity overtakes you, how the waters inundate and swallow up the shores, how the land shrinks back at the power of the sea! Says The Lord."},{t:"italic",v:"Behold, I will show wonders in the heavens above and in the earth beneath, blood and fire and pillars of smoke! The sun shall be turned into darkness and the moon into blood, as it is written!"},{t:"fn",v:"3"},{t:"text",v:"Satan\u2019s strongholds shall be swallowed up, and all these vines of wickedness shall be uprooted and cast into the depths of the sea! City by city shall be oppressed and broken down, when I call nature to rise up and fight against you! Then you will know, I AM THE LORD! For the word of the wisest among you shall fail, and the knowledge of the most learned shall be accounted as dung, when calamity upon calamity breaks out in every corner! Says The Lord. Behold, My every burning tear, which you have caused, shall rain down in torrents of flooding rain,"},{t:"italic",v:"with a great multitude of hail mixed with fire and blood!"},{t:"fn",v:"4"},{t:"text",v:"It shall inundate the cities and towns, while still other places shall be left utterly desolate! Behold, the dry and cracked ground shall speak in the hollows of the waste places as a testament against you, O most wicked generation! For My anger is kindled, the heat of My fury has come up into My face,"},{t:"italic",v:"and shall scorch the earth in the day I repay you for all your wickedness!"},{t:"fn",v:"5"},{t:"text",v:"Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore hear My words,"}],[{t:"italic",v:"And heed the sound of this Trumpet!"}],[{t:"italic",v:"For I am God alone; there is none besides Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUWAH, He who causes to be!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA, He by whom all things consist!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yes, He who is and was and is to come, The Almighty!"}]]}],footnotes:{1:{type:"scripture",ref:"Genesis 6:11-12 (NKJV)"},2:{type:"scripture",ref:"Matthew 7:26-27"},3:{type:"scripture",ref:"Joel 2:30-31"},4:{type:"scripture",ref:"Revelation 8:7"},5:{type:"scripture",ref:"Revelation 16:8"}},nkjv:{"Genesis 6:11-12 (NKJV)":"11. The earth also was corrupt before God, and the earth was filled with violence. 12. So God looked upon the earth, and indeed it was corrupt; for all flesh had corrupted their way on the earth.","Matthew 7:26-27":"26. \u201CBut everyone who hears these sayings of Mine, and does not do them, will be like a foolish man who built his house on the sand: 27. and the rain descended, the floods came, and the winds blew and beat on that house; and it fell. And great was its fall.\u201D","Joel 2:30-31":"30. \u201CAnd I will show wonders in the heavens and in the earth: Blood and fire and pillars of smoke. 31. The sun shall be turned into darkness, And the moon into blood, Before the coming of the great and awesome day of the LORD.","Revelation 8:7":"The first angel sounded: And hail and fire followed, mingled with blood, and they were thrown to the earth. And a third of the trees were burned up, and all green grass was burned up.","Revelation 16:8":"Then the fourth angel poured out his bowl on the sun, and power was given to him to scorch men with fire."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-god-of-israel-has-set-his-face-to-pour-out-judgment",videoVoiceUrl:"https://www.youtube.com/watch?v=BcLQOi9mD7E&list=PL6D1BC949E9840878&index=8",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Regarding the Days of Noah",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Nature Shall Rise Up and Fight Against This Generation",url:"https://answersonlygodcangive.com/Nature_Shall_Rise_Up_and_Fight_Against_This_Generation"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:'"He Who Was and Is and Is to Come"',url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#He_Who_Was_and_Is_and_Is_to_Come"}],num:7,prevLetter:{id:"established",title:"Established"},nextLetter:{id:"trust-in-god-alone",title:"Trust in God Alone"}},{id:"trust-in-god-alone",title:"Trust in God Alone",date:"3/15/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Do not put your trust in idols, nor in any man-made image forged of stone or marble, or of wood or brass, gold or of fine metal..."},{t:"italic",v:"There is no life in it!"},{t:"text",v:"For they can not speak or walk; they have no power at all. Yea, men bear them upon their shoulders, for they can not move from their places. They have no strength, they are helpless, worthless images carved in futility and must be borne. Look how easily they are toppled by the wind and broken in pieces, when the earth is shaken but a little. And do not put your trust in any man, though he speaks with a clever tongue, with many enticing words of unity and peace and many great promises. And though others bow down to him and give him glory, you shall not place your trust in any man! For man is but flesh, easily crushed beneath the weight of a single branch falling from a tree. For the whole world is My footstool, and the vastness of the universe is but a garment declaring My glory. And who among men is able to comprehend its scope? Says The Creator of Heaven and Earth, your Maker, yes I, The God of All."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, again I call you to kiss The Son"}],[{t:"italic",v:"And bow before your King!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For He alone is your salvation,"}],[{t:"italic",v:"He alone is your only escape!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"He is The Light, The Only Way, The Only Truth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"There is no life apart from Him;"}],[{t:"italic",v:"Apart from Him is only darkness and death,"}],[{t:"italic",v:"The wide path which leads to destruction..."}]]},{type:"poetry",lines:[[{t:"italic",v:"YAHUSHUA-YAHUWAH"}],[{t:"italic",v:"Is His name, The Mashiach!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Bearer of your cross, The Lover of your soul,"}],[{t:"italic",v:"The Risen One, The Mighty One of Jacob..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Immanu El!"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/trust-in-god-alone-3",videoVoiceUrl:"https://www.youtube.com/watch?v=EQCg301LiBw&list=PL6D1BC949E9840878&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"The Name of The Lord",url:"https://answersonlygodcangive.com/The_Name_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:8,prevLetter:{id:"the-god-of-israel-has-set-his-face-to-pour-out-judgment",title:"The God of Israel Has Set His Face To Pour Out Judgment"},nextLetter:{id:"the-fire-is-kindled",title:"The Fire Is Kindled"}},{id:"the-fire-is-kindled",title:"The Fire Is Kindled",date:"4/22/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The Word of My mouth breaks apart the mountains! Behold, whole ranges of mountains bow down when I pass by! Look how the earth trembles at My nearness and shakes beneath My footsteps!... And still the people say,"},{t:"italic",v:"\u201CThere is no God in Israel.\u201D"}]},{type:"para",segments:[{t:"text",v:"The enemies of The Lord gather and set themselves in battle array; they gather together to destroy My holy mountain! They seek to break apart My covenants and slaughter My people! The cleverest among them devise evil schemes, and the most knowledgeable forge weapons of war. Yet the banner of The Lord is risen up, the might of The Holy One is lifted high! Behold, I am poised in My strength, and My face is set to defend! And when I strike, who shall withstand My assault?! Who shall be left, when the hand of The Almighty is stretched out against them?! For My hand is swifter than an eagle, the strength of My arm has crushed leviathan, and I shall not withhold! My wrath shall burst forth like the terrible mountain! The heat of My countenance shall melt the hills, and the rivers of the valleys shall run dry at My presence! For My eyes are like flames of fire, My tears fall and scorch the earth! Says The Lord..."},{t:"italic",v:"Behold, the whole world is set ablaze at the outward glance of The Almighty in His hot displeasure! - A cleansing fire, a purifying flame, of which none shall quench! THE FIRE IS KINDLED!"},{t:"fn",v:"1"}]}],footnotes:{1:{type:"scripture",ref:"Luke 12:49"}},nkjv:{"Luke 12:49":"\u201CI came to send fire on the earth, and how I wish it were already kindled!"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-fire-is-kindled-3",videoVoiceUrl:"https://www.youtube.com/watch?v=PltZIM1Eykk&list=PL6D1BC949E9840878&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:9,prevLetter:{id:"trust-in-god-alone",title:"Trust in God Alone"},nextLetter:{id:"the-breach",title:"The Breach"}},{id:"the-breach",title:"The Breach",date:"5/6/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel, to the generation of the slaughter:"},{t:"text",v:"I have come down to you, and with brevity I speak to you. With shortness of speech and in a very stern voice, I have proclaimed your error. Is not the will of The Most High written in His Book? Are not My decrees made known, even My Law? Lo, even within you did I place discernment, that you may know right from wrong, that you may choose the good and refuse the evil. Yet what is this before My eyes, day and night?! What is this you have chosen?! Look at what you embrace, O most wicked generation!..."},{t:"italic",v:"You have hated justice, and The Promise is a loathsome sore in your eyes! You rage against My covenants and My people you do hate; My messengers are loathed in all the earth! The cause of the needy and the widow you have not known, and from the fatherless you withdraw your hand! You have forsaken and murdered the innocent; your feet stand in pools of their blood!"}]},{type:"poetry",lines:[[{t:"italic",v:"Your sins gather in strength; night and day"}],[{t:"italic",v:"They increase and testify to your demise!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The stain of death covers you, the pit beckons you!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, a fissure has formed beneath your feet,"}],[{t:"italic",v:"The gap widens quickly!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Lo, in the midst of you a great valley has emerged,"}],[{t:"italic",v:"Deep darkness and death spreads forth in every direction,"}],[{t:"italic",v:"Multitudes of dead and dry bones!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet you refuse to see, neither will you listen!"}],[{t:"italic",v:"For you have grown accustomed"}],[{t:"italic",v:"To the sound of wailing,"}],[{t:"italic",v:"And the silence of death pleases you!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, FALL!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-breach-2",videoVoiceUrl:"https://www.youtube.com/watch?v=dGZukr8Gm4Y&list=PL6D1BC949E9840878&index=11",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"}],num:10,prevLetter:{id:"the-fire-is-kindled",title:"The Fire Is Kindled"},nextLetter:{id:"wrath-and-recompense",title:"Wrath and Recompense"}},{id:"wrath-and-recompense",title:"Wrath and Recompense",date:"5/6/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to the peoples of the earth:"},{t:"text",v:"I have come to breach the wall! I am come to tear down your towers and break apart your cities! I am come to uproot every tree and to pull out all your well-groomed hedges, to stomp upon all these briers and thorns which spread across the land! I am come down to break apart every foundation, to shatter in pieces!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to the churches of men:"},{t:"text",v:"I shall splinter all your wooden houses, and the pieces thereof shall lodge beneath your well-manicured fingers! - Festering, until your sores ooze in the midst of your discoloration! I am come forth to break off the bones, pestilence comes forth to gnaw off your dead fingers, to devour all these dead members!"}]},{type:"poetry",lines:[[{t:"italic",v:"For I am risen up in My anger!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I am come down in My hot displeasure,"}],[{t:"italic",v:"To make the west as Sodom and the east as Gomorrah,"},{t:"fn",v:"1"}],[{t:"italic",v:"To repay the nations for all their wickedness!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"To make an end!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Says YAHUWAH Elohim Tz\u2019va\u2019ot,"}],[{t:"italic",v:"Asher Hayah V\u2019 Hoveh V\u2019 Yavo."}]]}],footnotes:{1:{type:"scripture",ref:"2 Peter 2:6, Jude 1:7"}},nkjv:{"2 Peter 2:6, Jude 1:7":"2 Peter 2:6 \u2014 and turning the cities of Sodom and Gomorrah into ashes, condemned them to destruction, making them an example to those who afterward would live ungodly; | Jude 1:7 \u2014 as Sodom and Gomorrah, and the cities around them in a similar manner to these, having given themselves over to sexual immorality and gone after strange flesh, are set forth as an example, suffering the vengeance of eternal fire."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/wrath-and-recompense-2",videoVoiceUrl:"https://www.youtube.com/watch?v=pVhK2VYVjn8&list=PL6D1BC949E9840878&index=12",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding The True Church",url:"https://answersonlygodcangive.com/Regarding_The_True_Church"}],num:11,prevLetter:{id:"the-breach",title:"The Breach"},nextLetter:{id:"the-generation-of-wrath",title:"The Generation of Wrath"}},{id:"the-generation-of-wrath",title:"The Generation of Wrath",date:"5/27/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord of Hosts, to the generation of wrath:"},{t:"text",v:"You know not the anger of The Lord, nor of My jealousy which burns in the fierceness of My wrath! For the Way of The Lord is not known, and the atrocities committed against the innocent you have hidden from your eyes; you refuse to see! Therefore calamity shall not cease from before your eyes, and destruction shall increase in every corner! Destruction from on high shall increase before you, and the wrath of God shall chase you from behind! The strength of your heart shall give way, and you shall lie down heavily, until death comes to take you and darkness closes in. And still the Way of The Lord is not known. Not one has heard the weeping of The Holy One, no one thirsts. Who has come out to drink? Who has eaten from this Tree? Who, among this lying generation, has opened their mouth in truth?! Who among you sees? Who among you knows? My messengers know, and My prophets have seen; behold, upon their lips I have placed the Word of Truth. And still the Way of The Lord is not known! For the prophets of The Lord are hated, and those who call of themselves Christian persecute and slander My messengers without cause! Behold, My faithful servants are hated by My own people, and in the world they are cast off with rarely a mention! For the Way of The Lord is not known, and the fear of The Lord is forgotten!..."},{t:"italic",v:"This generation has no love for God in their hearts!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord God:"},{t:"text",v:"Behold the generation of My wrath! Look upon this great multitude of wicked and deceived peoples; look deep into this darkness! Take a lantern and search, go from house to house, and see if there is one who remembers The Way! See if there are any who know Me, if there is one who embraces Me as I truly am! And yet the people say,"},{t:"italic",v:"\u201CWhere has all this darkness come from, and for what cause has all this violence come upon us? For what reason is all this devastation come upon us?!\u201D"},{t:"text",v:"Is this not the Day which was spoken of? Says The Lord. Is this not the Day prophesied throughout the generations, even from the beginning, that it should come? Is this not the Day of Clouds and Thick Darkness?! For I tell you the truth, it has come, all have entered in!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the outcry of the prophets has"}],[{t:"italic",v:"Come forth, the Word of The Lord is here!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It comes to pass before your eyes,"}],[{t:"italic",v:"It increases and fills the earth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, hear the Word of The Lord and give heed!"}],[{t:"italic",v:"Hear the Word of The Lord from aforetime, and of this day!"}],[{t:"italic",v:"Hear the Call and the Testimony, and tremble"}],[{t:"italic",v:"In fear at the Proclamation of The Lord!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the decree is sent down;"}],[{t:"italic",v:"Judgment is set and ready to be poured out!"}]]},{type:"para",segments:[{t:"text",v:"Lo, calamity has broken forth already, announcing the coming of The Holy One. His messengers prepare His way before Him, the earth trembles at His nearness. Lo, His hands gather His flock together, and His soft voice calls to His lambs..."},{t:"italic",v:"Behold, the house is broken into, yet who is aware of it?"},{t:"text",v:"Behold, the bundles are tied and set in their places, and still the people mock! And those called Christian say,"},{t:"italic",v:"\u201CAre we not the chosen? Yes, we are the elect of God\u201D.."},{t:"text",v:". Woe, I say to you! Woe to you and all your arrogant houses; you have surely deceived yourselves!"}]},{type:"poetry",lines:[[{t:"italic",v:"Bow down therefore and humble yourselves,"}],[{t:"italic",v:"Heed the call and depart from"}],[{t:"italic",v:"Your filthy houses, and repent!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Forsake all these man-made doctrines and"}],[{t:"italic",v:"Perverse traditions, put away all these pagan holidays!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"STOP POLLUTING MY NAME AND MY GLORY!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Stand apart from those who persecute My messengers"}],[{t:"italic",v:"And mock My promises, and I may yet receive you!"}]]},{type:"para",segments:[{t:"text",v:"Am I not The Lord God who sees, The One who knows? Yet My people hide their faces from Me, and cover their shame in an effort to appear righteous before men. Do I not search the hearts and minds, even to the innermost? Therefore who is it you seek to please, and for what cause do you wear all this fine apparel? For what reason do you wear these masks and cover your heads? For what purpose is this masquerade?! For I tell you the truth, the sluggard is at ease among you, the so-called faithful worship themselves, and the supposed devout follow after men! Am I not The Lord? And if I am The Lord your God, then how is it you seek after vain glories and refuse to accept Me as I am?! For vanity is a rope, and pride builds the gallows. Is not Haman your brother and Cain your close friend? And of their reward you have made yourselves fully worthy! Is not wisdom justified by her children and wickedness the delight of fools? For I tell you the truth, death is at the door and the pit is dug deep, Gei-Hinnom waits patiently and Sheol is made ready, and the wicked shall be cast into it! THE EVIL OF HEART SHALL SURELY DESCEND INTO IT! For death and wickedness are married, and the grave is never full. By evil deeds do the wicked consummate their union, by their every word do they confirm their agreement, until the fire consumes them and darkness hides them away. For the place of the deceased is known, yet those consumed by the fire shall never be found. They shall cease to exist, their names blotted out forever."}]},{type:"para",segments:[{t:"bold-italic",v:"Hear, therefore, the bitter grievance of The Lord:"},{t:"text",v:"The heart of man has grown increasingly wicked; he seeks only to steal, kill and destroy. His ravenous appetite is never abated, and his lusts are never full. For his hunger only increases in the pursuit of evil gain, his thirst deepening with every drop of blood he spills..."},{t:"italic",v:"Therefore he shall surely have his fill! Evil shall reign and wickedness shall overtake him! I shall give him blood to drink, and in the midst of his fullness he shall starve! Behold, I shall oppress the kingdoms of men day and night, and the hand of The Lord shall weigh heavily upon them! And at the height of their transgression, I SHALL TREAD THEM DOWN!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, as grapes in the winepress of the wrath"}],[{t:"italic",v:"Of My fury, I shall tread them down!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The back of the high man shall be bent,"}],[{t:"italic",v:"And the neck of the evil man shall be broken..."}]]},{type:"poetry",lines:[[{t:"italic",v:"ALL thrones, dominions, principalities"}],[{t:"italic",v:"And powers shall be bowed down!..."}]]},{type:"closing",text:"FOR I AM THE ONLY LORD OF HOSTS!"}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-generation-of-wrath-4",videoVoiceUrl:"https://www.youtube.com/watch?v=a-ZnErbsSwQ&list=PL6D1BC949E9840878&index=13",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"False Doctrines Within the Churches of Men Regarding...",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"Woe to Those Who Celebrate Pagan-laced Holidays",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Celebrate_Pagan-laced_Holidays"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding Staying Separate",url:"https://answersonlygodcangive.com/Regarding_Staying_Separate"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"God Speaks Regarding Covetousness",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Covetousness"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Regarding the First Death",url:"https://answersonlygodcangive.com/Regarding_the_First_Death"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"}],num:12,prevLetter:{id:"wrath-and-recompense",title:"Wrath and Recompense"},nextLetter:{id:"spiritual-famine",title:"Spiritual Famine"}},{id:"spiritual-famine",title:"Spiritual Famine",date:"6/6/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"italic",v:"I HAVE SENT FAMINE UPON THE LAND, even as in the day I caused a famine throughout the land of Israel. No, not a famine of bread, nor a thirst for water, but of hearing the words of The Lord."},{t:"fn",v:"1"},{t:"text",v:"As it was then, so it is this day also. From the churches of men and from the devout"},{t:"fn",v:"2"},{t:"text",v:"I have removed My hand, and from My people I have taken back My spirit."},{t:"fn",v:"3"},{t:"text",v:"Lo, one full day has passed since I left them desolate, in severe thirst, with nothing at all to nourish them. I have left them in darkness, with no light to guide them, the still small voice silent."},{t:"fn",v:"4"},{t:"text",v:"And what is this I hear among the churches of men and those devout in Israel, even among those who have recognized Mashiach in Israel? What voice do I hear lifted up to Heaven, crying out for guidance, longing for My presence and the Word of The Lord? What sound from the people has entered into the ears of The Holy One?!"}]},{type:"poetry",lines:[[{t:"italic",v:"I HEAR NOTHING!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Not a word is spoken, no outcry is made!"}],[{t:"italic",v:"No repentance is offered, no plea is lifted up!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"No one thirsts, not one hungers, not one of them"}],[{t:"italic",v:"Seeks The Light or grasps My robe, that I might guide"}],[{t:"italic",v:"Them through this darkness, through this desolate land!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"None listen for My voice!"}]]},{type:"para",segments:[{t:"text",v:"Behold, I have spoken a multitude of words, a great number of speeches, Letter after Letter, Volume after Volume! Yet they will not eat of this bread, for they are already full! Nor will they drink from this cup, for they are drunken! Nor can they lift their heads to look upon this glory, for the weight of their sin remains upon them. They refuse to see, their eyes are blinded! They will not listen, their ears are unclean! They cover their faces and stop their ears! Foolish people, most wicked generation, I do not know you! Fill up then the full measure of your error, according to the perverse doctrines of your fathers! Bear the sin of your heresies, drink from the cup of your blasphemies, to the fullest! Yes, I hear your songs and your spiritual hymns, offered up to God..."},{t:"italic",v:"HE LOOKS NOTHING LIKE ME!"},{t:"fn",v:"5"},{t:"text",v:"I see your uplifted hands, and I hear all these prayers offered up in the name of Christ..."},{t:"italic",v:"HE LOOKS NOTHING LIKE ME!"},{t:"text",v:"Perverse generation, the Day of The Lord is here; yes, I have declared it! In these very Letters and by My servants, I have made it known! Lo, through this man I have spoken it, for he does seek to honor Me..."},{t:"italic",v:"I HAVE BROUGHT GLORY TO MY NAME!"},{t:"text",v:"Yet you have hated both Me and My Word! You have rejected the voice of The Living God, you have loathed the messengers of The Most High! Therefore shall I also reject you, for your ways are loathsome in My sight! I have left you in famine, and now I shall leave you utterly desolate."}]},{type:"para",segments:[{t:"text",v:"For I have called to My lambs; their hearts sing in anticipation. I have called to My sheep; they have embraced My voice. Yea, I have entered in and gathered them together. Behold, the harvest is separated, all is ready, the door is shut. I have but to call out, and the first election shall pass from your sight, and the gate shall be shut. For the door is shut already, the time has passed; no more shall pass through."}]},{type:"poetry",lines:[[{t:"italic",v:"I tell you the truth, you have done this!"}],[{t:"italic",v:"You have decided, your decision is made!"}],[{t:"italic",v:"Yes, YOU have shut the door to ME!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore is it also shut to you..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And it shall not be opened again"}],[{t:"italic",v:"Until you breathe your last, testifying to"}],[{t:"italic",v:"The Name of Glory and Him crucified,"}],[{t:"italic",v:"Until the time I open it anew..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I shall open the gates of the city"}],[{t:"italic",v:"And the dead shall pass through,"}],[{t:"italic",v:"The martyrs of The Lord lifted up to glory!"}]]}],footnotes:{1:{type:"scripture",ref:"Amos 8:11"},2:{type:"note",text:'"Devout" in this context refers to the so-called devout in Israel who reject the Messiahship of YahuShua'},3:{type:"note",text:'See: "My Hand is Removed"',url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets#.22My_Hand_is_Removed.22"},4:{type:"note",text:'See: "I Shall Remove My Hand and My Spirit Shall Be Withdrawn..."',url:"https://www.thevolumesoftruth.com/I_Shall_Remove_My_Hand_and_My_Spirit_Shall_Be_Withdrawn..._And_That_Purposed_from_the_Beginning_Shall_Be_Done,_It_Shall_Be_Accomplished_Swiftly#:~:text=Therefore%20I%20shall,darkness%20be%20thick",link:{collection:"Volume Seven",letterTitle:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly",excerpt:"Therefore I shall indeed remove My hand, and My spirit shall return to Me"}},5:{type:"note",text:'See: "Regarding "Another Messiah""',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"}},nkjv:{"Amos 8:11":"\u201CBehold, the days are coming,\u201D says the Lord GOD, \u201CThat I will send a famine on the land, Not a famine of bread, Nor a thirst for water, But of hearing the words of the LORD."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/spiritual-famine-2",videoVoiceUrl:"https://www.youtube.com/watch?v=unxZmGW8WCw&list=PL6D1BC949E9840878&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"My Hand is Removed",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets#.22My_Hand_is_Removed.22"},{label:"My Spirit is Removed",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets#.22My_Spirit_is_Removed.22"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Regarding The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:13,prevLetter:{id:"the-generation-of-wrath",title:"The Generation of Wrath"},nextLetter:{id:"i-am-lord",title:"I AM LORD"}},{id:"i-am-lord",title:"I AM LORD",date:"6/8/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The love of man has grown cold, and the heart of man has become increasingly wicked. Their hands work evil everyday, and with their feet they run swiftly to commit violence against their neighbor; lo, they make plans and devise evil schemes against their neighbors! They murder the innocent without cause and rob the poor! Behold, they murder and dismember the helpless, and the heartless applaud them! And every night, they love to lie down in their abominations. Therefore, My face is set to consume them from off the land, to destroy them in all the earth! Wrath shall increase, and recompense shall overflow by measure! It shall come down like flooding rain, and the tears shall flow like streams of water in the waste places! The face of wrath is shown up, the heat of vengeance has come forth to kill the inhabitants of the earth!"}]},{type:"poetry",lines:[[{t:"italic",v:"The Lord of Hosts has come out of His temple;"}],[{t:"italic",v:"He has stepped down from His dwelling place"}],[{t:"italic",v:"To look upon the evil works of men, and to repay"}],[{t:"italic",v:"All this wickedness done by their hands..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Lord God of Hosts is come down,"}],[{t:"italic",v:"To make the west as Sodom"}],[{t:"italic",v:"And the east as Gomorrah."},{t:"fn",v:"1"}]]},{type:"para",segments:[{t:"text",v:"The hand of The Lord is raised in battle, the arm of The Lord is stretched out to destroy! The army of The Lord rushes forward to slay His enemies and to deliver every captive! Behold, there shall be a great war declared against The Holy One of Israel, yet He shall strike through, laying their armies waste, slaying every last one of them with the sword of His mouth, consuming them in the brightness of His coming! Even all who raise their fists against Him shall surely perish in that day! For I am God, and I am to be greatly feared! My reverence shall last throughout all generations, even forever! For I am YAH! YAHUWAH is My name!"}]},{type:"para",segments:[{t:"bold-italic",v:"Hear now, the indignation of The Lord God of Israel; hear Me, you disgusting multitude:"},{t:"text",v:"I SHALL CONSUME YOU! As the locust consumes the vine, as the swarm eats up the field and every green thing, so shall I consume the wicked from off the land! I shall consume you utterly, destroying you in all the earth! For the places of the wicked shall never be found!"}]},{type:"poetry",lines:[[{t:"italic",v:"Peoples of the earth,"}],[{t:"italic",v:"I had given you dominion over"}],[{t:"italic",v:"My good earth and over every animal..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Now I give the earth and every"}],[{t:"italic",v:"Animal dominion over you,"}],[{t:"italic",v:"To destroy, to kill and to consume!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"There shall be no hiding place;"}],[{t:"italic",v:"There shall be no place of refuge!"}]]},{type:"para",segments:[{t:"text",v:"If you hide in the depths of the earth, the hand of The Lord shall plunge down to meet you! If you climb high into the mountains, the face of The Almighty in His anger will be there waiting! If you dive into the depths of the sea, I shall call leviathan to open his mouth and swallow you! If you run out into the desert, lo, it shall open up and bury you at My command! And if you fly higher than the eagle, the breath of My nostrils shall bring you down to the earth in a heap!"}]},{type:"poetry",lines:[[{t:"italic",v:"Yet the complaint of the people increases"}],[{t:"italic",v:"Against The Lord, and in their unbelief"}],[{t:"italic",v:"They question, saying, \u201CHow can this be?!\u201D..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, The God of Heaven shall give answer!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM LORD!"}]]}],footnotes:{1:{type:"scripture",ref:"2 Peter 2:6, Jude 1:7"}},nkjv:{"2 Peter 2:6, Jude 1:7":"2 Peter 2:6 \u2014 and turning the cities of Sodom and Gomorrah into ashes, condemned them to destruction, making them an example to those who afterward would live ungodly; | Jude 1:7 \u2014 as Sodom and Gomorrah, and the cities around them in a similar manner to these, having given themselves over to sexual immorality and gone after strange flesh, are set forth as an example, suffering the vengeance of eternal fire."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-lord-2",videoVoiceUrl:"https://www.youtube.com/watch?v=Tby0PiZqnRU&list=PL6D1BC949E9840878&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"The Days of Noah Revived",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah#The_Days_of_Noah_Revived"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:'The Name of The Lord - "YAHUWAH"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#YAHUWAH"}],num:14,prevLetter:{id:"spiritual-famine",title:"Spiritual Famine"},nextLetter:{id:"the-power-and-the-majesty-of-the-lord",title:"The Power and the Majesty of The Lord"}},{id:"the-power-and-the-majesty-of-the-lord",title:"The Power and the Majesty of The Lord",date:"6/11/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold the power and majesty of The Lord; hear and understand! Peoples of the earth, see the Word of The Lord! Behold My words and take warning, receive My words and bow down heavily, speak My name aloud and REPENT! Depart swiftly from your wicked ways, run quickly, and I may yet have mercy upon you! O ignorant and vain peoples, you lack knowledge and all wisdom has departed from you! Have you forgotten it is I, who was and is and is to come, The One who made heaven and earth, The Almighty?! Yes, I AM HE, The Everlasting; from the beginning, it was I who had done it!"},{t:"italic",v:"Are not the depths broken up, when I speak but a single word in My anger? Do not the mountains bow down and the islands flee away at My presence? Are not the mountains torn and the rocks broken in pieces when I pass by? Is it not I who brings forth the earthquake and kindles the fire?"},{t:"fn",v:"1"},{t:"text",v:"Behold, the continents shall break apart when My anger is fully aroused! When I step down, they shall give way! They shall surely crumble and break apart violently, and great shall be the sound of it! Awesome and terrible shall it be in that day, the power and might of The Lord put on open display! For I am come down to execute My Word! And when the feet of Him, called Holy and True, step upon the mountains and stand fast upon the Mount, oh how great and terrible shall it be on that day! Who shall endure His coming?! Who will be able to stand?!"}]},{type:"poetry",lines:[[{t:"italic",v:"Blessed, therefore, are the sons of men who bow down;"}],[{t:"italic",v:"Blessed are all those who fear The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Blessed are those who truly know Me,"}],[{t:"italic",v:"Who give heed to My words, to do them..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Blessed also are all those who say, \u201CYes, Lord\u201D,"}],[{t:"italic",v:"To My every decree and proclamation,"}],[{t:"italic",v:"Seeking always to obey My every command..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For their reward is coming, coming very quickly..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 Kings 19:11-12"}},nkjv:{"1 Kings 19:11-12":"11. Then He said, \u201CGo out, and stand on the mountain before the LORD.\u201D And behold, the LORD passed by, and a great and strong wind tore into the mountains and broke the rocks in pieces before the LORD, but the LORD was not in the wind; and after the wind an earthquake, but the LORD was not in the earthquake; 12. and after the earthquake a fire, but the LORD was not in the fire; and after the fire a still small voice."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-power-and-the-majesty-of-the-lord-2",videoVoiceUrl:"https://www.youtube.com/watch?v=Kb9dBCt9Jj4&list=PL6D1BC949E9840878&index=22",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:15,prevLetter:{id:"i-am-lord",title:"I AM LORD"},nextLetter:{id:"the-days-of-the-martyred-prophets-are-at-an-end",title:"The Days of the Martyred Prophets Are at an End"}},{id:"the-days-of-the-martyred-prophets-are-at-an-end",title:"The Days of the Martyred Prophets Are at an End",date:"6/25/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"italic",v:"The days of the martyred prophets are over, the Day of The Lord is here! The anger of The Almighty is put on open display and the might of The Holy One shall be made fully known! Therefore sing amen to The Holy One of Israel, all you My elect! Bow down and give Me perfect praise, all you My holy ones! Break forth into singing, all you My chosen! Praise your King!"}]},{type:"para",segments:[{t:"text",v:"Peoples of the earth, I am come down and I have searched. I have went from house to house and peered into every temple, that I might behold the ways of man, that I may look upon his works and discern his heart and know his mind. For I am The Lord, and I love judgment."}]},{type:"poetry",lines:[[{t:"italic",v:"Justice shall be poured out and punishment sent down!"}],[{t:"italic",v:"For I am The God of Judgment, The God of Recompense!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, The God of Vengeance is risen up"}],[{t:"italic",v:"In His fierce anger and is come down in"}],[{t:"italic",v:"His overflowing indignation, to repay!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"TO TAKE VENGEANCE ON ALL HIS ENEMIES!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Amen and amen!"}]]},{type:"para",segments:[{t:"text",v:"Let it be done, let it come to pass quickly! With great swiftness let wrath overflow, until evil is swept away and the wickedness of men is wiped clean, until every tower crumbles and every city is consumed with fire, until I have utterly destroyed all the works of man, UNTIL I HAVE BLOTTED OUT THE KINGDOMS OF MEN! Let their temples come down with a great crash, and let every religion be crushed beneath the weight of their idols! Let them pine away in their lies and waste away in their deceptions, UNTIL THEY ARE NO MORE!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, I call to the prophets of every religion!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"To every prophet of the wicked one,"}],[{t:"italic",v:"To every soothsayer and prognosticator,"}],[{t:"italic",v:"To every scoffer and evil man"}],[{t:"italic",v:"Who seek to harm My anointed,"}],[{t:"italic",v:"Even to every person who plots ill will"}],[{t:"italic",v:"In their hearts against My messengers..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come forward and fight against My witnesses!"}],[{t:"italic",v:"COME OUT AND FIGHT AGAINST ME!"}],[{t:"italic",v:"That I may cut you down and purge you"}],[{t:"italic",v:"From your places, that you may be"}],[{t:"italic",v:"No more before My face!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I shall make of you a great slaughter!"}]]},{type:"para",segments:[{t:"text",v:"Yes, come and make plans and devise your evil schemes, and come and strike at My prophets that you might do them harm! For the days of the martyred prophets are at an end; the time of recompense is here! Hurry now, come forward, that I may strike you down where you stand, that I may take your life from you in a moment, that I may litter the streets with your rotting corpses! Says The Lord God. Thus shall the prophets of The Lord be made plain, and the prophets of the wicked one be exposed. For the false prophets shall become rotting corpses in every land, scattered across every nation!"}]},{type:"poetry",lines:[[{t:"italic",v:"Yet the prophets of The Lord"}],[{t:"italic",v:"Shall march free, undaunted!"}],[{t:"italic",v:"Behold, they shall fly,"}],[{t:"italic",v:"They shall be given eagle\u2019s wings!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Lo, the strength of Samson shall be theirs,"}],[{t:"italic",v:"And the power of The Lord"}],[{t:"italic",v:"Shall proceed from their nostrils!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Word of The Lord shall"}],[{t:"italic",v:"Blow mightily in all the earth!"}],[{t:"italic",v:"For I have put My words in their mouths!..."}]]},{type:"closing",text:"Says YAHUSHUA-YAHUWAH."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-days-of-the-martyred-prophets-are-at-an-end-2",videoVoiceUrl:"https://www.youtube.com/watch?v=iNt0NznIyVw&list=PL6D1BC949E9840878&index=23",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"}],num:16,prevLetter:{id:"the-power-and-the-majesty-of-the-lord",title:"The Power and the Majesty of The Lord"},nextLetter:{id:"revoked",title:"REVOKED"}},{id:"revoked",title:"REVOKED",date:"7/2/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"From the beginning I had written to you by the pen of My prophets, even to the showing of great signs and wonders. Behold, I came down in the flesh, and spoke with My people face to face. And in one day the sins of My people were purged, in one moment the pain of death was overcome."},{t:"italic",v:"For I am The Lord."},{t:"text",v:"I have declared the end from the beginning, I have spoken of things to come, many wondrous and terrible things. I have set up great kings, and I have cast them down. I have called forth armies to conquer, and I Myself have conquered great armies. I have humbled whole nations and scattered their peoples, and behold, I have also brought them back again."},{t:"italic",v:"For I am The Lord, and there is no other; there is none like Me."}]},{type:"para",segments:[{t:"text",v:"And thus I speak to you now, little flock, even as I have spoken it to My servant already: All of you have stumbled. Yet some of you have departed, returning to the world and the ways of men..."},{t:"italic",v:"A world which hates Me and blasphemes My name at every turn, a world which pollutes My name without ceasing, a world which loathes its Creator! A world which loves abomination and from righteousness is far removed, a great multitude of dying people who hate LIFE! A world which destroys MY EARTH AND MY CHILDREN, a most wicked generation who MURDERS WITHOUT REMORSE!... A world which even now breathes its last... Beloved, I weep! My heart is rent inside Me!"},{t:"text",v:"And what of your country and people, little flock? What of this mighty nation? Prepare your hearts, beloved, prepare your hearts for death. For the end of all things is at hand. For the Day of The Lord shall declare it; in the Day of The Lord\u2019s Anger, it shall surely be made plain! Therefore, I have commanded My servant that he not celebrate this holiday"},{t:"fn",v:"1"},{t:"text",v:"with his peers, nor with his community, for he must remain separate. For if he were to join them in their celebration, I tell you the truth, it would be death he celebrates and captivity he honors. For this nation\u2019s independence is lost, its freedom REVOKED!"}]},{type:"poetry",lines:[[{t:"italic",v:"Beloved, your nation has come to its end; I give it over!"}],[{t:"italic",v:"No more shall I defend its people"}],[{t:"italic",v:"And protect its borders!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For they have utterly forsaken Me,"}],[{t:"italic",v:"And now must I also forsake them!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore cry bitter tears, little flock,"}],[{t:"italic",v:"And weep, be overcome with sorrow,"}],[{t:"italic",v:"For the end of a nation is a terrible thing..."}]]},{type:"poetry",lines:[[{t:"italic",v:"It is wrought with much betrayal"}],[{t:"italic",v:"And falls with a mighty crash,"}],[{t:"italic",v:"Bringing forth death and great mourning;"}],[{t:"italic",v:"The sound of which shall shake every land"}],[{t:"italic",v:"And every people, and they too shall fall!"}]]},{type:"para",segments:[{t:"text",v:"Yet from ruin they shall arise and band together. And in desperation, they shall make a covenant and sign an agreement. And once again they shall blaspheme the name of The Lord Most High, and walk proudly. Thus upon the heels of desolation shall their final destruction be written, in the blood of the slain."}]},{type:"para",segments:[{t:"italic",v:"Thus I shall send forth My witnesses, 144,000! They shall run as one mighty in battle, breaking through the lines, tearing down the walls, leaping over every barrier! From city to city they shall declare The Lord\u2019s Rebuke, pronouncing My judgment upon the multitudes!"}]},{type:"poetry",lines:[[{t:"italic",v:"And thus shall I bring great calamity"}],[{t:"italic",v:"Upon the cities and high places of men,"}],[{t:"italic",v:"Until My wrath is satisfied"}],[{t:"italic",v:"And My fierce anger has abated..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until the feet of The Holy One of Israel"}],[{t:"italic",v:"Stand upon the Mount, bringing forth"}],[{t:"italic",v:"Judgment unto victory absolute..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"note",text:"The 4th of July - Independence Day (U.S.A.)"}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/revoked-2",videoVoiceUrl:"https://www.youtube.com/watch?v=cQVNwdyJjNI&list=PL6D1BC949E9840878&index=22",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"}],num:17,prevLetter:{id:"the-days-of-the-martyred-prophets-are-at-an-end",title:"The Days of the Martyred Prophets Are at an End"},nextLetter:{id:"abasement",title:"ABASEMENT"}},{id:"abasement",title:"ABASEMENT",date:"7/26/11",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord of Hosts, to all the sons and daughters of this, the last generation of men:"},{t:"text",v:"You have all inherited the error of your fathers, you have altogether become like them! Behold, you have surpassed the sins of ancient Egypt, when I poured out My wrath upon them! Your wickedness has increased beyond every tribe, people and nation, which has dwelt upon the earth!"}]},{type:"poetry",lines:[[{t:"italic",v:"THIS GENERATION IS WICKED"}],[{t:"italic",v:"BEYOND MEASURE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus great wrath is stirred up,"}],[{t:"italic",v:"And My indignation has come to the full!"}],[{t:"italic",v:"My anger is fully aroused and"}],[{t:"italic",v:"Shall surely be poured out..."}]]},{type:"poetry",lines:[[{t:"italic",v:"RECOMPENSE for all nations!"}],[{t:"italic",v:"RECOMPENSE for all these churches of men"}],[{t:"italic",v:"Who have spoken presumptuously in My name!"}],[{t:"italic",v:"RECOMPENSE for all these corrupt workers"}],[{t:"italic",v:"Who have done falsely on My behalf!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I HAVE NOT SENT YOU!"}]]},{type:"para",segments:[{t:"text",v:"And you, O peoples of the earth, I have seen how you perform every form of evil at your leisure! You cease not from reveling in that which I hate! Behold, you murder the innocent, day and night, and plot evil against your neighbor! You stand up for the rights of those who commit abomination, and clap your hands as wickedness is celebrated openly in the streets!..."},{t:"italic",v:"O MOST PERVERSE AND ABOMINABLE GENERATION, SHALL I NOT REPAY?!"},{t:"text",v:"Behold, My body is persecuted in every land, and My bride is murdered at the hands of idolaters! My people are bruised and beaten, My servants slandered and hated without cause! Therefore I am come down to take vengeance, to pour out wrath upon this people for all their wickedness!..."},{t:"italic",v:"I SHALL IMPART RECOMPENSE IN FULL!"},{t:"text",v:"For I am The Lord, He who stretched out the heavens and hung the earth upon nothing. I am He who created all these worlds, He who causes all things to be. I am He who formed man from the dust of the earth and gave him breath, and he became a living soul. Behold, I spoke all life into existence, yes, I am He who called all things into existence, saying,"},{t:"italic",v:"\u201CArise and declare My glory!\u201D"},{t:"text",v:"For all creation obeys the sound of My voice. Yea, the whole universe declares My glory, for I am He who commanded the stars to shine their light and the galaxies to take their form. Behold, My voice reaches across the universe, and reverence is spread out before Me. For I command the hills to bow down and the mountains to be brought low, and it is so. Yea, the whole earth trembles when I pass by, for I am great in power and My glory has no equal! Thus the fear of The Lord goes before Me, and obedience follows after Me, says The Lord. Yet you peoples of the earth have turned from Me, and have rebelled against Me days without end! Thus I call upon the sons of men, even all who dwell upon the earth, to repent, to turn from your wicked ways, to bring forth new works worthy of repentance..."},{t:"italic",v:"Oh that justice would well up like water, and righteousness as an ever-flowing stream."},{t:"fn",v:"1"},{t:"text",v:"Yet you will not listen, you refuse to hear! WAYWARD GENERATION! Yes even you, O churches of men, have run far from Me, seeking always to be loosed from all accountability as you build yourselves up in your own false glory, that you might receive praise and recognition from men!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, in your arrogance you have"}],[{t:"italic",v:"Taken it upon yourselves to preach"}],[{t:"italic",v:"MY Word from the pulpit, polluting it,"}],[{t:"italic",v:"As though My words were subject to you"}],[{t:"italic",v:"And your own private interpretation!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"O most arrogant and deceived generation,"}],[{t:"italic",v:"How long must I suffer you?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"How long shall you attempt to rebuild"}],[{t:"italic",v:"Babylon and raise up Babel?!"}],[{t:"italic",v:"For you have restored Sodom and"}],[{t:"italic",v:"Revived Gomorrah from the dead!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Surely the days of Noah have come in!"}]]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus declares The Lord God:"},{t:"text",v:"As surely as the sun sets and night follows, so shall the light of this world be taken. And as a closing door darkens a room, so shall I leave those who remain to all their darkened temples in which they sought to hide themselves. For I know the thoughts of the mind, and I have heard what their hearts have spoken in secret, saying,"},{t:"italic",v:"\u201CLet us hide from The God of Israel and cast off His Word sent to us. Let us persecute His messengers and cast stones at His prophets, that we may remain at ease in our deceptions. For we shall never be made the fool, nor shall we let any of our words fall to the ground, nor shall we allow any of our works to burn in the Day. Hush now, let us continue in secret, and let us hide the truth from the people concerning our error, lest our congregation depart from us. For we shall continue to wear our pretense as a garment and our false righteousness as a cloak, and we shall wear it well.\u201D"},{t:"text",v:"Therefore, because you have brought forth such a great number of false accusations against My prophets, and have utterly rejected this Word which I have spoken to this generation, and because you have endeavored to cover your intentions by pretense and sway My people with many empty words and lofty speeches, and because you have lulled them to sleep by all your vain practices, so too shall I bring forth charges and declare all your wrongdoings before the people!..."},{t:"italic",v:"Behold, I shall bring forth judgment against you, and My words shall strip you naked! Yes, I shall reveal all your secret parts, and you shall walk naked through the streets in that day, shamefully exposed! In that day, humiliation shall be your only garment and death your only hiding place! Therefore, let repentance come forth from your lips and righteous works flow from your hands, as your feet seek to regain the line!"},{t:"text",v:"Yet you continue to forsake The Living God, as you cast off My every decree in favor of your own way! You continue to corrupt MY Word and profane MY Commandments! Behold, you justify your sins in the name of Grace, and spit upon My glory everyday! Thus you shall surely be made to pass through the fire, for you have made yourselves fully worthy! -"},{t:"italic",v:"Refinement in the Day of The Lord!"}]},{type:"poetry",lines:[[{t:"italic",v:"YOU ARE ALL AS LUKEWARM WATER!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Your churches are as stagnant pools,"}],[{t:"italic",v:"Which sour My stomach!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Your doctrines are foul, an awful smell"}],[{t:"italic",v:"In My nostrils, and your traditions leave"}],[{t:"italic",v:"A bitter taste in My mouth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THUS I MUST SPIT YOU OUT!"}],[{t:"italic",v:"I SHALL SURELY VOMIT"}],[{t:"italic",v:"YOU FROM MY MOUTH!"}]]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"The folly of this people is great, for they have sought to raise themselves above Me! They have no fear of God in their hearts! They mislead the penitent, as they push the sincere of heart far from Me! They hold fast to their own selfish desires, and refuse to let go of even one of their false doctrines! And as a babe clings to its mother\u2019s breast, so also do these people among the churches of men cling to all their perverse traditions, of which I hate! At every turn they hide their faces from Me, as they sink deeper and deeper into the mire of their fornications! Yet I remain faithful, and My Word true, says The Lord..."},{t:"italic",v:"Therefore recompense has risen up, and The Lord\u2019s Rebuke is sent down! And with strong discipline shall I feed them, and with swift judgment shall I fill their cups! For the Day has surely come."},{t:"text",v:"Did you think I had not seen it, O sons and daughters of men? Nothing escapes My sight, nor do My eyes rest when the sun sets beneath the horizon; there is no hiding place from the knowledge of The Lord. And what is man, that he should liken himself to ME?! Or the glory of man, that he should raise himself above Me? Foolish people, Godless generation, you do not know Me at all! Nor do you have any love for the Truth, that you might really know Me! You care not to learn My ways, lest you feel obligated to walk in them! Instead you cast them off, yea you hide them under false pretenses, claiming they have passed away!..."},{t:"italic",v:"Ignorant and deceived generation, vain peoples, that which you have cast off has come to claim you, and you shall not escape, for your own words have ensnared you! Behold, that which you claim has entrapped you, and on account of all this filthy pretense are you held captive!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"CHURCHES OF MEN, AWAKEN FROM YOUR SLUMBER! Your service to Me is in vain! For you have grown very tired, and with heavy-laden eyes have you looked upon My people, closing your eyes to My Word as it really is, as anger builds within your hearts over that which I have sent to you! Behold, with false righteousness you judge others and push out the hand! And with great arrogance you cast My words asunder, as though you were above reproach! Yet I tell you, you have mistaken pride for wisdom, and much learning for understanding. WOE TO YOU! Says The Lord. Woe to the learned! Woe to every high-minded scoffer who is wise in his own eyes! Woe to every arrogant pastor and prideful preacher! YOUR ABASEMENT IS COMING AND SHALL BE VERY SEVERE!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, with a shout and with a mighty"}],[{t:"italic",v:"Trumpet blast, it comes very quickly!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And though your ears do not hear"}],[{t:"italic",v:"And your eyes do not see, that which"}],[{t:"italic",v:"I have declared shall surely come,"}],[{t:"italic",v:"And woe to those who are left!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For in a moment, and on a day you"}],[{t:"italic",v:"Do not expect, your hearts shall be pierced"}],[{t:"italic",v:"And your every false expectation struck through!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For as the scythe cuts through the stalk,"}],[{t:"italic",v:"As the sweeping blow fells many plants at once,"}],[{t:"italic",v:"So shall the sharpness of realization cut to the heart"}],[{t:"italic",v:"Of this people, and in that same moment the"}],[{t:"italic",v:"Loftiness of many shall be brought down..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, multitudes shall fall hard upon the ground!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Declares The Lord."}]]}],footnotes:{1:{type:"scripture",ref:"Amos 5:24 (CJB)"}},nkjv:{"Amos 5:24 (CJB)":"Instead, let justice well up like water, and righteousness like an ever-flowing stream."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/abasement-2",videoVoiceUrl:"https://www.youtube.com/watch?v=v4vj7-yOaFo&list=PL6D1BC949E9840878&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Woe to the Churches of Men",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Churches_of_Men"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Hate",url:"https://answersonlygodcangive.com/God_Speaks_About_Committing_Murder_Within_the_Heart#Hate"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Regarding the Mistranslation and Misinterpretation of the Scriptures",url:"https://answersonlygodcangive.com/Regarding_the_Mistranslation_and_Misinterpretation_of_the_Scriptures"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Regarding the Days of Noah",url:"https://answersonlygodcangive.com/Regarding_the_Days_of_Noah"},{label:"Woe to Those Who Come Against God's Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"Woe to Those Who Walk in Pretense",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Walk_in_Pretense"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"False Doctrines Within the Churches (Index)",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"The Day and Hour of God's Wrath",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown#The_Day_and_Hour_of_God.27s_Wrath"}],num:18,prevLetter:{id:"revoked",title:"REVOKED"},nextLetter:{id:"thus-says-the-god-of-judgment",title:"Thus Says The God of Judgment"}},{id:"thus-says-the-god-of-judgment",title:"Thus Says The God of Judgment",date:"7/27/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel:"},{t:"text",v:"Who are these who betray Me and turn against My servants, who seek to devour My prophets and attack My faithful servants? As a lion, they seek out My servants and attack them as the prey; as a starving lion, they turn on those sent to them! In their fierce hunger, they seek to devour their own, for they are in great famine. Who are all these who have despised Me, whose indignation is risen up against My servants without cause? Behold, each one seeks to devour his own brother and steal from his own Father! They do greatly dishonor their Father and lift up their hand to destroy their brother! They trample upon their neighbor and slander their close friend!"}]},{type:"poetry",lines:[[{t:"italic",v:"In this time of famine their hearts have hardened,"}],[{t:"italic",v:"And in them a heart like a beast has taken form!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yea, they are not alone, wickedness dwells there!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And like a beast in the wilderness who is"}],[{t:"italic",v:"Without inhibition, as one who has no master,"}],[{t:"italic",v:"They lash out without thought or consideration!"}]]},{type:"para",segments:[{t:"text",v:"Behold, they stalk their prey and attack their neighbor without cause! They bear false witness against their neighbor and slander their own brother; they seek justice without cause! Therefore shall MY justice be swift, MY judgment shall fall hard upon them, for I am come out! Behold, I am come down to make of them a great slaughter! For The God of Heaven, The Lord over all the earth, shall punish them! I shall strike this world for its iniquity, severely oppressing every inhabitant in My judgment! The whole world shall be struck in My fierce indignation! Says The Lord. For the wicked gather like locusts, and their sin spreads forth like a swarm, devouring and polluting the land! Therefore their pain shall be great, and their affliction intolerable! And who will be able to endure it?! Behold, their distress shall surpass Egypt as in the days of Moses, when I severely afflicted them! They shall choke in their affliction, they shall gasp for air in their distress, until darkness comes to claim them!"}]},{type:"poetry",lines:[[{t:"italic",v:"For the wicked increase in their iniquity everyday,"}],[{t:"italic",v:"And their sin is always before My face;"}],[{t:"italic",v:"See how they do revel in it, look at how"}],[{t:"italic",v:"They bask in it, to their own destruction!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For they have all become as brute beasts!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"They have made themselves fully worthy,"}],[{t:"italic",v:"Yes, they are worthy and made ready;"}],[{t:"italic",v:"They are prepared for the slaughter!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/thus-says-the-god-of-judgment-2",videoVoiceUrl:"https://www.youtube.com/watch?v=yzJAfkVT08U&list=PL6D1BC949E9840878&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:19,prevLetter:{id:"abasement",title:"ABASEMENT"},nextLetter:{id:"every-idle-word",title:"EVERY IDLE WORD"}},{id:"every-idle-word",title:"EVERY IDLE WORD",date:"8/2/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Who are these who speak dark counsel without knowledge? Who are these who walk about in arrogant accord, with their foreheads wrinkled and their hearts hardened? Who are all these who speak with serpents\u2019 tongues? I do not know them! From them My spirit is far removed! Their houses shall be devastated, for they have brought swift destruction upon their own heads! Yes, I am The Lord who is bringing swift destruction upon the houses of the wicked, even upon every one who has come out to fight against Me! The cleverest among them shall be made the fool, and the most cunning shall be left to their own devices, and who shall deliver them?!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore come out against Me,"}],[{t:"italic",v:"All you mockers! Says The Lord..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For behold, this dying generation ceases not"}],[{t:"italic",v:"From mocking MY Word and those sent to them!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come forward therefore, and secure yourselves"}],[{t:"italic",v:"Among their ranks, that you may share in their reward!"}],[{t:"italic",v:"Be set apart in your unjust cause, set yourselves"}],[{t:"italic",v:"Hard against My will, until it consumes you!"}]]},{type:"para",segments:[{t:"text",v:"Increase your slander and continue in your false witnessing, that I may repay you -"},{t:"italic",v:"Prepare yourselves for death!"},{t:"text",v:"For all those who rebel against Me, and seek harm against My messengers, have made themselves meet for destruction! For I have prepared a fire; behold, it is already kindled! Lo, within the mouths of My witnesses I have placed coals from the altar, and I shall surely increase their flame, until every scoffer is put to shame and everyone who slanders is uncovered and sent away in their nakedness! For the pride of the wicked is a hook by which they catch themselves, and their arrogance is a bridle by which they lead themselves into rebellion against The Lord!"},{t:"italic",v:"Therefore, because you have raged against Me and your tumult has come up into My ears, I will put MY hook in your nose and MY bridle in your lips, and I will turn you back by the way which you came!"},{t:"fn",v:"1"},{t:"text",v:"Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to all those who call of themselves Christian, yet never cease from pushing out the lip against The Lord\u2019s anointed:"},{t:"text",v:"Your error is very grievous! Hold your tongue, lest all I have spoken concerning the scoffer and the wicked come upon you, leaving your houses utterly devastated and your sanctuaries in ruinous heaps! For it shall surely be accounted to you, in accordance with your every idle word!"}]},{type:"poetry",lines:[[{t:"italic",v:"REPENT, THEREFORE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And turn back from this wicked way you have chosen,"}],[{t:"italic",v:"And I may yet have mercy upon you..."}]]},{type:"closing",text:"Says The Lord God."}],footnotes:{1:{type:"scripture",ref:"2 Kings 19:28, Isaiah 37:29 (NKJV)"}},nkjv:{"2 Kings 19:28, Isaiah 37:29 (NKJV)":"2 Kings 19:28 \u2014 Because your rage against Me and your tumult Have come up to My ears, Therefore I will put My hook in your nose And My bridle in your lips, And I will turn you back By the way which you came. | Isaiah 37:29 \u2014 Because your rage against Me and your tumult Have come up to My ears, Therefore I will put My hook in your nose And My bridle in your lips, And I will turn you back By the way which you came.\u201D \u2019"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/every-idle-word-2",videoVoiceUrl:"https://www.youtube.com/watch?v=LUrr_ANL1HI&list=PL6D1BC949E9840878&index=25",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"God Speaks Regarding Those Who Bear False Witness Against His Servants",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_Against_His_Servants"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:20,prevLetter:{id:"thus-says-the-god-of-judgment",title:"Thus Says The God of Judgment"},nextLetter:{id:"the-two-lampstands",title:"The Two Lampstands"}},{id:"the-two-lampstands",title:"The Two Lampstands",date:"8/15/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"I have looked upon all the souls who dwell under Heaven, I have waited upon those who call of themselves by My name, calling to them. Yet only blasphemy is heard, many harsh and unfeeling answers. Therefore let the dead care for the dead, and let the mocker fall in the midst of their calamity; let every scoffer walk in the valley with the desolate. For My anger sleeps no longer, and the fire of The Lord is kindled! For the cities of men have raged against Me, and the city of innocent blood shall be torn in pieces! Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I called to the sea, to the great multitude"}],[{t:"italic",v:"Of waters, and there was no answer!..."}],[{t:"stanza-break"}],[{t:"italic",v:"I shouted to the earth and blew the Trumpet upon"}],[{t:"italic",v:"The four winds of heaven, yet no cry was heard,"}],[{t:"italic",v:"No response was lifted up to Heaven!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Only raised fists were seen, many milling"}],[{t:"italic",v:"About gnashing upon their teeth,"}],[{t:"italic",v:"Lashing out against their neighbor!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"So I turned My face away from them"}],[{t:"italic",v:"And set My back against the sea,"}],[{t:"italic",v:"And the earth, it was forsaken."}]]},{type:"para",segments:[{t:"text",v:"Then was a great cry lifted up, and oh such a sorrowful sound was heard! So I said to My two lampstands,"},{t:"italic",v:"\u201CTake a coal from the fire which surrounds the altar, and eat of it. Consume it fully and go down. For I have made these people as kindling, and this multitude as wood, that they may come and fight against you, that they may be given up to the flame. Open your mouths wide that they may be consumed!\u201D"}]},{type:"para",segments:[{t:"text",v:"For I have prepared an offering, lo it is prepared and waits for its time, says The Lord God of Israel. For indeed I tell you, lo, The Lord your God reveals it to you, Eliyahu and Moshe are about to come down! Says YAHUWAH."}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-two-lampstands-2",videoVoiceUrl:"https://www.youtube.com/watch?v=IivJmYKVPr8&list=PL6D1BC949E9840878&index=28",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Two Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_Two_Witnesses"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"}],num:21,prevLetter:{id:"every-idle-word",title:"EVERY IDLE WORD"},nextLetter:{id:"the-hypocrite-s-portion",title:"The Hypocrite\u2019s Portion"}},{id:"the-hypocrite-s-portion",title:"The Hypocrite\u2019s Portion",date:"8/20/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord against every church of men, against all those who falsely call of themselves by My name:"},{t:"text",v:"I have nourished and brought up children, and they have rebelled against Me; they have altogether forsaken Me for their own way!..."},{t:"italic",v:"Foolish and disobedient children!"},{t:"text",v:"They refuse to listen, for by their own hearts are they led. Yes, they follow the dictates of their own hearts, and give heed to their own self-serving desires; to their own voices they give heed. They listen only to the sound of their own voices!..."},{t:"italic",v:"Therefore, all I have spoken against them shall surely come upon them."}]},{type:"poetry",lines:[[{t:"italic",v:"My children are foolish and have"}],[{t:"italic",v:"Gone astray, with no one to lead them!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"They have released their grasp"}],[{t:"italic",v:"And hold fast to one another;"}],[{t:"italic",v:"They are married to their own expectations!"}],[{t:"italic",v:"They know not how to discern"}],[{t:"italic",v:"Their right hand from their left..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, all I have spoken against them"}],[{t:"italic",v:"Shall surely come upon them."}]]},{type:"para",segments:[{t:"text",v:"I had called them to be blameless in the world and to be at peace, to do justly and love mercy, to walk humbly with their God. Yet they could by no means sit still, nor were they at ease. Rather they have gone out polluting My name and desecrating My words in Scripture! For they have hated both Me and My will, and in their hearts My prophet has altogether become as Micaiah, who was hated by the king for speaking the Truth as he heard from God!"},{t:"fn",v:"1"},{t:"text",v:"..."},{t:"italic",v:"Therefore, all I have spoken against them shall surely come upon them."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, they walk in the valley"}],[{t:"italic",v:"Of their own choosing, and have rejected"}],[{t:"italic",v:"That which I, Myself, had provided for them!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And one who mistreats My gifts shall"}],[{t:"italic",v:"By no means retain them..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And that which is given shall not be owned,"}],[{t:"italic",v:"As though one had received it by their own power;"}],[{t:"italic",v:"Rather it is to be cherished, with thanksgiving..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And one who takes and corrupts My gifts,"}],[{t:"italic",v:"For their own gain, shall be left desolate."}]]},{type:"para",segments:[{t:"text",v:"And who are all these who ignore good and wise counsel, while seeking to assert their own authority? I did not send them, yet they went out. I Myself called to them, yet voices on the wind drew them away. And who are all these who have raised their voices against My servants, while polluting My name and Scripture?! Have you not also departed from your Husband, even as the unbeliever?! Thus those who were to be without blame have given many others cause to blaspheme My name, to disregard My prophet on their account!..."},{t:"italic",v:"This should not be!"},{t:"text",v:"Yet what place do the disobedient have with Me, and what portion do the insolent share in? Have they not made their decisions clear and their unbelief known? Is it not revealed plainly, as though it were worn upon the sleeve?"}]},{type:"poetry",lines:[[{t:"italic",v:"For I tell you, all who disobey My voice,"}],[{t:"italic",v:"In favor of their own way, shall not"}],[{t:"italic",v:"Hear My voice when the shout is made;"}],[{t:"italic",v:"And all who forsake the little ones"}],[{t:"italic",v:"Shall also be forsaken..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet every lamb is Mine..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yes, every lamb shall be gone from this place!"}],[{t:"italic",v:"And who in all the earth is able to prevent Me?"}],[{t:"italic",v:"Who is able to move Me aside?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I shall surely do My own pleasure, I shall surely"}],[{t:"italic",v:"Uphold My every word and complete MY will;"}],[{t:"italic",v:"MY name shall be exalted in all the earth!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 Kings 22:5-18"}},nkjv:{"1 Kings 22:5-18":"5. Also Jehoshaphat said to the king of Israel, \u201CPlease inquire for the word of the LORD today.\u201D 6. Then the king of Israel gathered the prophets together, about four hundred men, and said to them, \u201CShall I go against Ramoth Gilead to fight, or shall I refrain?\u201D So they said, \u201CGo up, for the Lord will deliver it into the hand of the king.\u201D 7. And Jehoshaphat said, \u201CIs there not still a prophet of the LORD here, that we may inquire of Him?\u201D 8. So the king of Israel said to Jehoshaphat, \u201CThere is still one man, Micaiah the son of Imlah, by whom we may inquire of the LORD; but I hate him, because he does not prophesy good concerning me, but evil.\u201D And Jehoshaphat said, \u201CLet not the king say such things!\u201D 9. Then the king of Israel called an officer and said, \u201CBring Micaiah the son of Imlah quickly!\u201D 10. The king of Israel and Jehoshaphat the king of Judah, having put on their robes, sat each on his throne, at a threshing floor at the entrance of the gate of Samaria; and all the prophets prophesied before them. 11. Now Zedekiah the son of Chenaanah had made horns of iron for himself; and he said, \u201CThus says the LORD: \u2018With these you shall gore the Syrians until they are destroyed.\u2019 \u201D 12. And all the prophets prophesied so, saying, \u201CGo up to Ramoth Gilead and prosper, for the LORD will deliver it into the king\u2019s hand.\u201D 13. Then the messenger who had gone to call Micaiah spoke to him, saying, \u201CNow listen, the words of the prophets with one accord encourage the king. Please, let your word be like the word of one of them, and speak encouragement.\u201D 14. And Micaiah said, \u201CAs the LORD lives, whatever the LORD says to me, that I will speak.\u201D 15. Then he came to the king; and the king said to him, \u201CMicaiah, shall we go to war against Ramoth Gilead, or shall we refrain?\u201D And he answered him, \u201CGo and prosper, for the LORD will deliver it into the hand of the king!\u201D 16. So the king said to him, \u201CHow many times shall I make you swear that you tell me nothing but the truth in the name of the LORD?\u201D 17. Then he said, \u201CI saw all Israel scattered on the mountains, as sheep that have no shepherd. And the LORD said, \u2018These have no master. Let each return to his house in peace.\u2019 \u201D 18. And the king of Israel said to Jehoshaphat, \u201CDid I not tell you he would not prophesy good concerning me, but evil?\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-hypocrites-portion-2",videoVoiceUrl:"https://www.youtube.com/watch?v=r_W3RhSd0ZM&list=PL6D1BC949E9840878&index=32",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:22,prevLetter:{id:"the-two-lampstands",title:"The Two Lampstands"},nextLetter:{id:"generation-s-end",title:"Generation\u2019s End"}},{id:"generation-s-end",title:"Generation\u2019s End",date:"9/14/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"Streams of water flow down from the mountains, springs of water burst forth from the rocks, rivers of water overflow their banks, and still the thirst of this people is not quenched. Multitudes of dead and dying peoples fill the streets and the alleyways. No hope is found, no light breaks through the open spaces. The darkness grows and is very thick; many darkened and ill faces wandering about, treading the broad way. The light of life dims as their hearts grow cold. Their countenances are always downcast, for there is no hope in man. Affection is all but lost, compassion is forgotten, and loving one another has no place in man\u2019s designs. For natural affection departs from the hearts of the wicked, and lustful endeavors consume them. Filthiness has made a home, and perversion is praised and celebrated openly in the streets, as the innocent look upon them with wonder."}]},{type:"poetry",lines:[[{t:"italic",v:"You deranged and most wicked generation,"}],[{t:"italic",v:"I have looked upon you, I know all your doings!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"How long will you tempt Me?!"}],[{t:"italic",v:"How long shall you rebuild Sodom"}],[{t:"italic",v:"And make Gomorrah your home?!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"My heart tears inside Me,"}],[{t:"italic",v:"Each and every time I look at you!"}]]},{type:"para",segments:[{t:"text",v:"Israel does not know Me, and those who call of themselves Christian pollute My name and My Word without ceasing!..."},{t:"italic",v:"They are unrelenting!"},{t:"text",v:"I can no more listen to their foul speech, I can no more bear the sight of them! The God of Israel is dead in their eyes, The Salvation of God has no part with them, unless I change and become like them, unless I bow down and give heed to their demands, that I altogether conform to their image! And what more shall I say then? What more shall I do for a people such as this?! They will not listen, they refuse to give heed! They squeeze their eyes shut with all their strength, while clasping their hands over their ears tightly! What is left then? - Only that I gather what little light remains, and every innocent child..."},{t:"italic",v:"I must make room! I must clear My way before Me! I must break this people and destroy all they have made! It must be done, the wrath of God must be poured out, the cleansing fire must rage! - Until every last vestige of man\u2019s invention is gone from the earth, until every last stronghold of evil is broken down and utterly destroyed, until every last hint of sin is cleansed from this place! FOR I AM HOLY, The Only God whose name is One!"}]},{type:"poetry",lines:[[{t:"italic",v:"And though it greatly pains My heart,"}],[{t:"italic",v:"A wound which shall last forever, it must be done..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For if I do not do this, My people shall never have a name;"}],[{t:"italic",v:"They shall never dwell in My holy place, they shall never"}],[{t:"italic",v:"See The Light or know life as it was in the beginning..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until the sanctuary is cleansed, I can not dwell"}],[{t:"italic",v:"With My people, both with them and in them..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Unless I make a full end, there can be no restoration."}]]},{type:"para",segments:[{t:"text",v:"If I do not complete My task, never again shall I walk with My beloved in the garden, never again shall the little children come to Me and gather around..."},{t:"italic",v:"Open your eyes, cast yourselves down! Let your hearts melt before The Holy Fire, embrace My Purifying Flame! My dying children, you are the last generation, the last of these kingdoms of men!"},{t:"text",v:"I love you, yet you choose death! You have forsaken Me and forced My hand! The stink of your perversions fills My nostrils, your murders stain My courts, the broken bodies of the innocent and the blameless are piled up in heaps before My eyes! And still you say within yourselves,"},{t:"italic",v:"\u201CWe have done no wrong, we have provoked no god to anger. There is no judgment to come. We do not retain God in our thoughts, His Law is far from us. We do not know Him, nor do we need Him.\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"O most wicked and loathsome generation,"}],[{t:"italic",v:"I have seen it! I have seen and know!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Living God has come down,"}],[{t:"italic",v:"The Salvation of God is here;"}],[{t:"italic",v:"He has seen and knows!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"He has searched, He has went"}],[{t:"italic",v:"Through the multitudes and looked,"}],[{t:"italic",v:"He has peered deep within..."}]]},{type:"poetry",lines:[[{t:"italic",v:"He has called and pleaded;"}],[{t:"italic",v:"Behold, He has poured Himself out!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And still His life departs from this people!"}]]},{type:"para",segments:[{t:"text",v:"His light is all but gone from their eyes, as they fade into a slumber from which there is no escape, a sleep from which the wicked of heart shall never awake - Death..."},{t:"italic",v:"What a horrible and sad thing this is! What a mournful cry is heard from the mouth of The Holy One of Israel, \u201CMy people! Beloved children! WHY HAVE YOU FORSAKEN ME?!\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"Thus I must finish My Book and close this chapter..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the desolate shall have no name, and this most"}],[{t:"italic",v:"Wicked generation is cut off from their legacy;"}],[{t:"italic",v:"Their wickedness shall not rise up a second time!"}],[{t:"italic",v:"They shall never pass this way again..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A whole generation of dead and dying people,"}],[{t:"italic",v:"A great multitude of peoples who refuse to drink,"}],[{t:"italic",v:"A great and mighty people slain by their own hand..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A whole generation of children who I have loved"}],[{t:"italic",v:"With My whole heart, even unto death..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A whole generation wiped from the face of the earth..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/generations-end-2",videoVoiceUrl:"https://www.youtube.com/watch?v=8zZ7ATZjRpQ&list=PL6D1BC949E9840878&index=33",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Woe to the Peoples of the Earth",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Peoples_of_the_Earth"},{label:"New Heights in Wickedness",url:"https://answersonlygodcangive.com/New_Heights_in_Wickedness"},{label:"Regarding Sodom and Gomorrah Revived",url:"https://answersonlygodcangive.com/Regarding_Sodom_and_Gomorrah_Revived"},{label:"Regarding Israel",url:"https://answersonlygodcangive.com/Regarding_Israel"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord_.28Section_One.29"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Lamentations From The Lord",url:"https://answersonlygodcangive.com/Lamentations_From_The_Lord"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Second Death",url:"https://answersonlygodcangive.com/Regarding_the_Second_Death"}],num:23,prevLetter:{id:"the-hypocrite-s-portion",title:"The Hypocrite\u2019s Portion"},nextLetter:{id:"enemies-of-the-lord-come-forth",title:"Enemies of The Lord, Come Forth"}},{id:"enemies-of-the-lord-come-forth",title:"Enemies of The Lord, Come Forth",date:"9/23/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"ENEMIES OF THE LORD, COME FORTH! Be drawn out, all you detestable birds! Come forth and be drawn out! Come and fight, make a stand, O enemies of The King! Let the ruthless step forward and the evil of heart stand up in their place, and give the order! Come forth, all you mighty men; be gathered together against The Lord and His anointed!"}]},{type:"poetry",lines:[[{t:"italic",v:"Come out to conquer and seek your"}],[{t:"italic",v:"Prize, all you men of false valor!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come out in the name of your god,"}],[{t:"italic",v:"All you wicked men of allah!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Come out in the name of your false"}],[{t:"italic",v:"Prophet, that I may tread you down,"}],[{t:"italic",v:"That I may reach down and make of you"}],[{t:"italic",v:"A great slaughter, that My sword may"}],[{t:"italic",v:"Pierce the heart of your god and cut"}],[{t:"italic",v:"Off the head of your prophet!..."}]]},{type:"closing",text:"FOR I AM THE LORD WHO IS MIGHTY IN BATTLE!"},{type:"para",segments:[{t:"text",v:"Behold, My name shall resound in all the earth when I come out mightily in battle, when I stretch out My hand for slaughter, to take vengeance upon all My enemies! I am come to break apart, to shatter in pieces! Behold, I am come down to kill, to murder the gods of the earth! I shall lop off the head of every idol and strike through the heart of every god, of which YOU have created! Every graven image shall bow down heavily! Every religion of man shall burn!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God of Israel:"},{t:"text",v:"I DECLARE WAR, WAR UPON ALL MY ENEMIES! - Upon every inhabitant, upon all friends of this world! Upon everyone who persecutes My bride or throws stones at My messengers, whether in word or by deed! Upon all who speak in My name, saying,"},{t:"italic",v:"\u201CThus says The Lord\u201D,"},{t:"text",v:"when I have NOT spoken it! And upon ALL who murder the innocent and the blameless; a double portion have I reserved for them! Says The Lord. Behold, the mouth of The Lord has spoken, and shall not repent: I AM COME OUT TO DESTROY! - To pillage the sanctuaries! To break apart and tear down the walls! To make a mockery of every sacred and solemn assembly! To cast out your members and to scatter the devout of every religion, stripping them of all their detestable garments! I shall uncover them, they shall be shamefully exposed, left to flee into the mountains naked! And behold, they shall surely call to the mountains and to the rocks, saying,"},{t:"italic",v:"\u201CFall on us, and hide us from the face of Him who sits on the throne and from the wrath of The Lamb!\u201D"},{t:"text",v:"FOR I AM THE LORD! HOT IS MY ANGER!"}]},{type:"para",segments:[{t:"text",v:"Yet the prophets of The Lord shall stand fast; they can not be shaken. The witnesses of The Lord shall shout and not be moved. Behold, I am sending them with staff in hand, and none shall prevent them by any means."}]},{type:"poetry",lines:[[{t:"italic",v:"My Word shall speak, and judgment"}],[{t:"italic",v:"Shall be declared against the cities of men..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, it shall come down from above,"}],[{t:"italic",v:"And it shall rise up from beneath;"}],[{t:"italic",v:"From places unseen shall judgment"}],[{t:"italic",v:"Come forth to consume and to destroy!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Strike the staff! Says The Most High - STRIKE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Strike the ground and the water!"}],[{t:"italic",v:"Let this multitude be divided!"}],[{t:"italic",v:"Let the waters be turned to blood!"}],[{t:"italic",v:"Let the fear of The Lord be greatly increased!"}]]},{type:"para",segments:[{t:"text",v:"For the enemies of The Lord pursue My people as prey, and the camp of the righteous is surrounded on every side! Yet the enemies of The Lord shall be swallowed up, and the great army shall be consumed! For My Word shall speak, and the power of The Lord shall be called down from Heaven in that day!"}]},{type:"para",segments:[{t:"text",v:"Behold, I have called out My servants, I have searched their hearts; lo, they are ready to be set in their places. My house is set in order, every place is prepared, I am ready to receive My guests. My army is assembled, each man is being moved into position, each man to his appointment. And lo, the sickles are placed in the hands of the reapers, the first harvest is ready..."},{t:"italic",v:"Behold, The Ladder reaches from the earth to Heaven!"},{t:"text",v:"Ears open, the Trumpet is raised, and The Son of Man is eager to open His mouth. Make ready and prepare, for I have declared neither the day nor the hour. Yet the season is made plain, and the days of revelation are upon you. Wait and watch, therefore, for The Son of Man is sent down; My Word does not lie. And though many twist and turn My words to their own advantage, aligning them with their own expectation, to their own hurt, My words do not lie. My every Letter shall come to pass, according to My will..."},{t:"italic",v:"And oh what a cry shall be heard, oh what an uproar shall ensue, and much gnashing of teeth! Yet The Holy One is sent down, and behold, the bride says, \u201CGod is with us!\u201D"}]},{type:"poetry",lines:[[{t:"italic",v:"My Word lies not!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"The Shepherd is sent down and gathers together His sheep;"}],[{t:"italic",v:"He beckons to every lamb, drawing them close..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And in a day you do not expect, and at an hour"}],[{t:"italic",v:"You can not predict, He shall pass through the gate"}],[{t:"italic",v:"And His sheep with Him, and every lamb..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/enemies-of-the-lord-come-forth-2",videoVoiceUrl:"https://www.youtube.com/watch?v=TmHqJsA1UMU&list=PL6D1BC949E9840878&index=30",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"The Volumes of Truth",url:"https://answersonlygodcangive.com/The_Volumes_of_Truth"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"}],num:24,prevLetter:{id:"generation-s-end",title:"Generation\u2019s End"},nextLetter:{id:"shiloh",title:"Shiloh"}},{id:"shiloh",title:"Shiloh",date:"9/23/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"When I gathered the waters together in one place, was it not so? And is it not so, even to this day? When I called for the locusts to come forth into the land of Egypt, to eat up every green thing, did they not obey My voice? Says The Lord. Behold, did not I, even I, form man from the stuff of the earth and breathe into him life? Am I not He who created the heavens and the earth? Shall I not take what is Mine, and do with it as I please? Shall I not discipline My own children, and strike those who rebel against Me?"}]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD!"}],[{t:"italic",v:"And there is no God besides Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet the people kindle fire upon MY altar"}],[{t:"italic",v:"And steal from MY sanctuary;"}],[{t:"italic",v:"They cease not from destroying MY holy things!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For they are desolate and have no knowledge!"}],[{t:"italic",v:"They take not one word into their hearts"}],[{t:"italic",v:"And ignore My every decree!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"They have not known Me,"}],[{t:"italic",v:"Though I have walked among them."}]]},{type:"para",segments:[{t:"text",v:"Behold, they are dying and welcome death, though My life was poured out for them! They will not drink, they no longer wish to eat, that I might sustain them! For their every fountain is polluted, and the bread they serve is filled with rottenness!..."},{t:"italic",v:"Therefore, I shall vomit them from My mouth!"},{t:"text",v:"For the lukewarm have no place at My table, and have no interest in the Truth as it really is; Truth has departed from them! Only pretense remains and is worn proudly. Thus falsehoods rise up, bearing chains of imprisonment; harlotries increase, bringing forth illness, infecting the whole of the body..."},{t:"italic",v:"Therefore shall their fornications eat their flesh as their new wine inflames them! For insolent cords bind the proud, and rebellion is a rope by which the foolish hang themselves, says The Lord."},{t:"text",v:"For I am God over all the earth, and lo, I have indeed drawn back My hand that you may fall. Behold, My spirit is removed, that you may do all this wickedness which dwells within your hearts. For the nations have no favor with God, and the people called by My name do not know Me!..."},{t:"italic",v:"Therefore must I also stretch out My arm, and perform all I have spoken against them! I shall bring every word to pass, of which I have spoken in My anger; every Letter shall be accomplished, that My wrath may be satisfied!"},{t:"text",v:"My people, how long shall you pollute My name?! How long shall you forsake My Sabbaths?! My people forsake My ways and will not hallow My Sabbaths; behold, My Commandments have no place in their hearts! Therefore, the dissident shall never prosper, for My every word is law!..."},{t:"italic",v:"Thus shall I kindle a fire in their courts, and bring upon them a fierce wind; great disaster shall befall them in one day!"}]},{type:"para",segments:[{t:"text",v:"Woe to those who cry,"},{t:"italic",v:"\u201CImmanu El!\u201D,"},{t:"text",v:"then break My Commandments by permission in HIS name; you know nothing of grace, and from you My spirit is far removed! Woe to those who say,"},{t:"italic",v:"\u201CWe are delivered!\u201D,"},{t:"text",v:"then persecute those sent to them; that by which you have judged shall return atop your own heads! Woe to those who love their houses of worship and lift up empty praise in My name, then turn their backs on the Word of My mouth and refuse My correction; you have secured your place in the valley!"}]},{type:"poetry",lines:[[{t:"italic",v:"Woe to those who stop their ears to the"}],[{t:"italic",v:"Voice of God, and follow after men!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yours shall be a bitter place,"}],[{t:"italic",v:"Filled with remorse and many tears;"}],[{t:"italic",v:"Hardship and troubles shall be your daily bread!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Woe to every man who teaches eternal torment"}],[{t:"italic",v:"And preaches everlasting burning..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Woe to all those who embrace wicked"}],[{t:"italic",v:"And bitter doctrine, and hold it"}],[{t:"italic",v:"Over the heads of the ignorant!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I DO NOT KNOW YOU!"}],[{t:"italic",v:"NOR HAVE YOU ANY KNOWLEDGE"}],[{t:"italic",v:"OF WHO I TRULY AM, AT ALL!"}]]},{type:"para",segments:[{t:"text",v:"For your famine is great, your poverty severe, a very desolate people! Offer up no praises to My glory, and make no open supplications; I will not listen to your cause, nor will I hear your prayers; I do not accept your worship! Says The Lord. For dogs lick up vomit, and maggots devour rotting flesh, and do not swine wallow in their own filth? Yet you have wallowed in your uncleanness days without end, licking up doctrine meet for the dogs! Look now, death is near! The Day of Calamity is here and the Great Day is very near, where the flesh of the harlot shall be eaten and all her dead members shall be torn in pieces and strewn about! - Rotting flesh, maggot\u2019s food, meet to be burned in the fire! Yet you say,"},{t:"italic",v:"\u201CThis word is false! For we are fat and very rich; not one of us is desolate. Our every doctrine is well accepted, for we are God\u2019s elect, and our church is the true church and only bride. How dare you say we are filthy and shall be torn in pieces! We will live forever and will never be a widow!\u201D"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"You are a widow already, very poor and desolate, a great number of starving people and very desolate, a perverse people who have made God in their own image."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, because you have eaten"}],[{t:"italic",v:"Up My people and held My children captive,"}],[{t:"italic",v:"So shall you eat the flesh of"}],[{t:"italic",v:"Your own arm in your captivity!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Every house of worship shall be torn down!"}],[{t:"italic",v:"Every community devastated!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even as Shiloh!"},{t:"fn",v:"1"}]]}],footnotes:{1:{type:"scripture",ref:"Jeremiah 7:12-14"}},nkjv:{"Jeremiah 7:12-14":"12. \u201CBut go now to My place which was in Shiloh, where I set My name at the first, and see what I did to it because of the wickedness of My people Israel. 13. And now, because you have done all these works,\u201D says the LORD, \u201Cand I spoke to you, rising up early and speaking, but you did not hear, and I called you, but you did not answer, 14. therefore I will do to the house which is called by My name, in which you trust, and to this place which I gave to you and your fathers, as I have done to Shiloh."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/shiloh-2",videoVoiceUrl:"https://www.youtube.com/watch?v=YDQlxs5RA2Y&list=PL6D1BC949E9840878&index=35",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding Creation",url:"https://answersonlygodcangive.com/Regarding_Creation"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Woe to Those Who Walk in Pretense",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Walk_in_Pretense"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"The One Who Stays, Lets",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"My Spirit is Removed",url:"https://answersonlygodcangive.com/The_One_Who_Stays,_Lets#.22My_Spirit_is_Removed.22"},{label:"Woe to Those Who Come Against God's Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"Woe to the Churches of Men",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Churches_of_Men"},{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:"Regarding Hell and Eternal Torment",url:"https://answersonlygodcangive.com/Regarding_Hell_and_Eternal_Torment"},{label:"False Doctrines Within the Churches (Index)",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding The True Church",url:"https://answersonlygodcangive.com/Regarding_The_True_Church"}],num:25,prevLetter:{id:"enemies-of-the-lord-come-forth",title:"Enemies of The Lord, Come Forth"},nextLetter:{id:"the-cup-of-the-wrath-of-my-fury-is-come-to-the-full",title:"THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL"}},{id:"the-cup-of-the-wrath-of-my-fury-is-come-to-the-full",title:"THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL",date:"10/7/11",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Peoples of the earth, your atrocities have kindled a great fire within Me! I am enraged as I look upon all these murdered innocent! My fury has come up into My face as I look upon all your false gods, O adulterous and perverse generation! Lo, multitudes of idols fill every corner! Both the believer and unbeliever bow down together and serve their gods! ALL nations worship the works of their own hands, for they have placed their own creations and the love of their own ideas above their Creator! False deities abound, while science and corrupt religion rule over them! Mere theories become truth and doctrine, and lawlessness is widely accepted! And behold, the love of money has become their new taskmaster, and materialism their god!"}]},{type:"poetry",lines:[[{t:"italic",v:"Sins of every kind imaginable flow through every land!"}],[{t:"italic",v:"Yea, as a mighty river it flows into every nation,"}],[{t:"italic",v:"Reaching unto new heights in wickedness as the walls"}],[{t:"italic",v:"Are broken down, overtopped by these quickly rising waters!"}],[{t:"italic",v:"The levees are eroded from beneath, they are"}],[{t:"italic",v:"Undermined continually, widening the breach!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, a great flood of sin has ensued,"}],[{t:"italic",v:"A terrible deluge covers the face of the whole earth,"}],[{t:"italic",v:"And still the fear of The Lord is all but forgotten!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THUS THE CUP OF THE WRATH"}],[{t:"italic",v:"OF MY FURY IS COME TO THE FULL!"}]]},{type:"para",segments:[{t:"text",v:"Behold, My Kingdom comes, and My will shall be done on earth as in Heaven. Even as I had purposed it from the beginning, so shall it be done to this generation. For My throne is set high above the highest heavens, and the earth is but a footstool set beneath My feet. FOR I AM THE LORD! YAHUWAH IS MY NAME! Therefore, let the enemies of The Lord be gathered! Let them be gathered together in one place for judgment! Let the hills melt in the heat of My wrath, and the mountains crumble under the weight of My fury!..."},{t:"italic",v:"LET THE WHOLE EARTH BE BOWED DOWN! - Until everything high and lofty is brought down, and every stronghold of man is broken and collapses with a great crash! Until every nation is plowed like a field and every city is left in ruinous heaps! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Cut down the trees and lay the forest bare! Let neither stump nor root be left in it! Break off the branches and destroy every vine! For the vine of man is wickedness, and the stronghold of man a dwelling place of evil. Behold, the pillar of man is a tree of abomination! His every branch bears only diseased fruit, infecting the masses! For his roots plunge ever deeper into darkness, that he might secure his place and gain strength in his rebellion against The Lord! Therefore, I must remove My sheep and gather up every lamb, and destroy all these kingdoms of men!..."},{t:"italic",v:"NO MORE shall My sheep be hurt by all these briers and thorns! NO MORE shall they become entangled! NO MORE shall My lambs be given up to the slaughter, O most wicked generation! NO MORE shall My beloved be made subject to you! For I must call My children home, that they may be with Me where I am."},{t:"text",v:"Yet many refuse My voice, and will not listen to the sound of this Trumpet. For they plug their ears and hide their faces; they ignore My call and loathe My messengers! - Obstinate children who endeavor to grab hold of My robes with one hand, while pushing Me away with the other! For I reach down to them, with both hands I bend down to embrace them, yet they want no part with Me as I truly am! Behold, I have offered them bread from My own table, manna from Heaven has been sent down to them, and how do they repay Me?! - WITH EVIL! Stomping upon My bread, refusing all manna provided them! Yea, they loathe My correction and break My Commandments, DOING SO IN THE NAME OF THE HOLY ONE! Yes, in MY OWN NAME they do these things! By permission they claim they are free to do all these things! By permission, UNDER GRACE, they excuse themselves, that they might do all this evil in My name!"},{t:"italic",v:"LAWLESS PEOPLE, PERVERSE AND DEGENERATE GENERATION! Your so-called faith is a loathsome sore upon the skin, a canker upon the lips of all who sing Me praises in your courts! Thus I declare to you, I NEVER KNEW YOU! Depart from Me, you who practice lawlessness! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Shall you provoke Me to anger?! Shall you forsake The Moral Law, in the name of grace and Him crucified, that you might provoke Me to anger?! I tell you the truth, you know nothing of grace, and the true nature of The Holy One is hidden from your eyes! For your knowledge is useless! Your learned leaders desecrate My name and pollute the minds of My people everyday! And when they heard of My anger, they did not repent, neither were they ashamed, nor did they know how to blush! And when I commanded this Trumpet be blown, did they perk up their ears to listen?! Did they come close to know the heart of the matter?! NO! Instead they mocked and refused to give heed, turning their backs on The Holy One of Israel!"}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, thus declares The Lord to this"}],[{t:"italic",v:"Most foolish and perverse generation:"}]]},{type:"poetry",lines:[[{t:"italic",v:"YOU SHALL NOT BE LIFTED UP,"}],[{t:"italic",v:"NOR SHALL YOU ESCAPE"}],[{t:"italic",v:"THE DAY OF THE LORD!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"DEATH SHALL BE YOUR ONLY RELIEF,"}],[{t:"italic",v:"AND MARTYRDOM YOUR ONLY ESCAPE!..."}]]},{type:"closing",text:"Says The Lord God."},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to all these blind and deaf children, to all these desolate people:"},{t:"text",v:"How is it you refuse My voice and question My ways without ceasing, and have yet to consider your own? Test your hearts! Look upon your motives! Shall you question My ways, though you yet stand in judgment for your own actions, which were brought forth from your own deceitful hearts?! I tell you the truth, the lies thereof have led you astray, and the tablets thereof lack justice! For My cause is not pleaded before the people, and the jury of your peers upholds every evil platform. Therefore their cause shall crush them, and their controversy shall consume them in the Day of Judgment! Says The Lord. Behold, the cause of The Lord is forgotten among you, and the controversy of The Lord is held in secret, My every decree forsaken! Yet the cause of The Lord shall be fulfilled in His messengers, and the controversy of The Lord shall be trumpeted from the rooftops, and the sins of this people shall be exposed! For they have altogether hated Me!"}]},{type:"poetry",lines:[[{t:"italic",v:"For every man is led by the deceits of his flesh,"}],[{t:"italic",v:"He is married to the selfish desires of his own heart,"}],[{t:"italic",v:"As he casts off the written Law of God to his own hurt..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My Commandments are regarded"}],[{t:"italic",v:"As foreign and out of date, and My Law"}],[{t:"italic",v:"Antiquated and obsolete, in the eyes of this"}],[{t:"italic",v:"So-called modern generation of enlightened people..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet I tell you, you are all perverse in My sight,"}],[{t:"italic",v:"A whole generation of arrogant"}],[{t:"italic",v:"And high-minded people!..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"And what of you, O churches of men? What has happened to you?! WHY HAVE YOU ALSO FORSAKEN ME?! How is it you have altogether become like the heathen, with the vanity of the world gleaming in your eyes, with the lusts thereof filling your hearts and minds?! I DO NOT KNOW YOU! Your self-created god is an abomination to Me, and this \u201CJesus\u201D you speak of is foreign to Me, a great desecration of My image, an affront to My name and My glory! My people, look! Look at all these material things you have acquired! Look upon all these idols you serve! You are surrounded on every side, you are boxed in with no escape!..."},{t:"italic",v:"Therefore I am come down to destroy all these detestable things! Therefore I am come to wipe them from the face of the earth! For the multitude of all these idols must I destroy the kingdoms of men!"},{t:"text",v:"O foolish and captive children, I am The Only God, your Creator, your Fashioner, The Maker of all things, The God who formed you by His own hands..."},{t:"italic",v:"I gave you breath!..."},{t:"text",v:"And still you bring unwarranted charges against Me and think My ways unfair! Shall you continue to persecute those sent to you, provoking Me to anger?! I tire of all your accusations, your unending presumptuous ways weary Me! I can no longer bear to look upon all your lies and falsehoods! For your heresies have grown unimpeded, filling your unjust courts, which I hate!..."},{t:"italic",v:"O abominable vine, how long shall you grow contrary to the Way I have established?! How long shall you oppose My Word and pollute My name, by upholding your own way?! I AM THE LORD!"},{t:"text",v:"My children, the judgment of your hearts is unjust and very foolish, for you have sought to draw charges against The Great I AM! Thus these courts in which you seek to weigh Me are unfair, and shall be your undoing! For your weights are deceitful, and your arrogant hearts corrupt! Shall you attempt to persecute The Lord your God?! Oh yes, you have persecuted Me days without end! For you have loathed My messengers and spit upon My servants! You have slandered My bride and lifted up your heel against My elect! Shall I not then bring charges against YOU, even against you, O churches of men?! Shall I not judge your courts, and recompense your deeds upon your own heads?! Shall I not correct My people, and bring upon them swift discipline?! Shall I not rain down judgment and pour out justice upon this wicked generation?!..."},{t:"italic",v:"Lo, the decree has went forth, the sentence has been declared, and behold, I shall institute the punishment without delay! For you have all dealt unjustly with Me! Says The Lord God."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"And do I now also lack justice in your eyes?! Have My ways become unfair in your sight?! Shall you continue to cast off My servants as madmen, because they have forsaken everything to follow Me?! Yet day and night you watch over your precious idols and secure all your cherished possessions, that you might sit at ease upon your thrones of vanity! Your goals are foolishness and your words wind, selfish desires and vain pursuits pleasing only to men, plans and aspirations which shall shortly come to nothing, passing from many of you even before the time. For all these things which you love shall be taken from you, and that which you hold most dear shall be snatched from your arms in one day."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I shall purge your hearts by calamity,"}],[{t:"italic",v:"And empty your minds by astonishment,"}],[{t:"italic",v:"And you shall break on account of all these"}],[{t:"italic",v:"Things coming to pass before your eyes!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"SPIRIT AND BODY"}],[{t:"italic",v:"SHALL BE BROKEN TOGETHER!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For I have come to purify and to take away,"}],[{t:"italic",v:"And to destroy, that the defiant may be broken"}],[{t:"italic",v:"And the high-minded bent backward,"}],[{t:"italic",v:"That the evil of heart may be cast face down"}],[{t:"italic",v:"In the midst of great calamity!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Multitudes of dead bodies strewn about"}],[{t:"italic",v:"In the waste places of every city,"}],[{t:"italic",v:"The streets and alleyways stained red with blood!"}]]},{type:"para",segments:[{t:"text",v:"For the defiant stand proud; they shall be humbled. And the high-minded speak foolishly with their mouths wide open, leading many astray; they shall be severely abased. Yet the evil of heart shall have no place. For they shall be brought down into the silence of death, for this is their due reward. Yet the stench of their rotting corpses shall testify on their behalf, and the sight of their broken bodies shall speak loudly in one accord. And The Lord, alone, shall be exalted in that day! Yet The Lord is not without mercy. Therefore those in whom I see of Myself, in whom I am shown to be foremost, shall escape; and after, those who willingly bow down and call upon My name in truth shall be delivered. Yet My people remain foolish. For they think themselves wise in their own eyes, and in their arrogance they rest upon their own doctrine while embracing every tradition I hate. Look how they love their idols and prize their great statues! They seek renown from among their own, that they might receive praise from men. And oh how they love their churches, and revere this false image in which they have recreated Me. Brood of vipers, congregations of sly and deceitful snakes, all you soothsayers and smooth-talkers who lull My people to sleep and seduce My children to commit fornication with the harlot, with your speech you woo My people to follow you into death! Your counsel brings them down to the pit! You provide My people with security in false hope, and put forth divinations of peace and safety, preaching prosperity in monologues of false praise and fake passion, abusing My name and misusing My Word, twisting it to uphold your own corrupt foundation, all in the name of unrighteous gain!..."},{t:"italic",v:"SHALL I NOT REPAY?! SHALL NOT MY DISCIPLINE BE MOST SEVERE?! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Churches of men, have you taken no thought to My judgments? How is it you have ignored My every admonition, admonitions which you were to ponder on your beds at night and dwell upon while gazing at your reflection in the morning? Lo, I have whispered to you in a still small voice, yet you had no ears to hear. I have written to you by the pen of My prophets, yet you refused to see. I have shouted to you by the mouth of My messengers, yet you would not give heed. Rather you think Me evil, and My speech contemptible! Yet in My love I spoke to you, and in My mercy I have warned you. And behold, many of My servants were pricked in their hearts and have confronted these men in authority. Yes, they have pointed the finger at all these perverse doctrines and are unsettled by all these detestable traditions, for they are the Called Out. Yes, My servants are unsettled and have come out, for I have pricked them in their hearts to the cause of the great division. For I, Myself, have brought this sword."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, let the uproar ensue!"}],[{t:"italic",v:"For the name of God has been polluted and"}],[{t:"italic",v:"The sanctity of My Word corrupted, for evil gain!"}],[{t:"italic",v:"The churches of men are unclean!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore must My people come out from among them,"}],[{t:"italic",v:"That I may break apart all these false foundations,"}],[{t:"italic",v:"That I may bring down all these"}],[{t:"italic",v:"High walls and towering steeples..."}]]},{type:"poetry",lines:[[{t:"italic",v:"FOR THUS DECLARES THE LORD:"}],[{t:"italic",v:"LET THE SPIRES BE TURNED UPSIDE DOWN!"}],[{t:"italic",v:"MAKE WAY FOR THE COMING OF THE LORD!"}],[{t:"italic",v:"LET THE POWER AND GLORY OF THE LORD"}],[{t:"italic",v:"BE SEEN WITHOUT OBSTRUCTION!"}]]},{type:"para",segments:[{t:"text",v:"Behold, a great battle cry is heard! The voices of My watchmen are lifted up against their own people, for the enemy dwells within the gates! My witnesses fight in the name of righteousness, yet those within the gate will not give heed! They refuse to come out of their sanctuaries, they will not depart from their man-made temples! - WICKED AND SLOTHFUL SERVANTS! They know not which master they serve, yet I tell you, they serve satan, and by their rebellion have they declared their allegiance! For they have hated Me and My Sabbaths! And of My Book, they see it only as a lever by which they may move the people to conform to their will, perverting My Word in Scripture! For the love of money they seek always to expand their churches, increasing their storehouses of wealth and building up their riches, by authority IN MY NAME! Shall I not repay?! Shall I not set all these crooked paths straight?! For the heart of this people is corrupt; they remain lost in their own deceptions! THUS THEY HAVE INDEED PROVOKED ME TO ANGER! Therefore, as it is written:"},{t:"italic",v:"I shall make My words in the mouths of My prophets fire, and this people wood, and it shall devour them!"},{t:"fn",v:"1"},{t:"text",v:"For the people treat My words with contempt, and do not cease from crying,"},{t:"italic",v:"\u201CFalse! False!\u201D"},{t:"text",v:"Behold, they liken My prophets to predators, and speak of My messengers as though they were brute beasts risen up from the past, as snakes rearing their heads across the ages. Therefore, My servants shall indeed bite them! As the adder they shall rear their heads and strike! Like the fangs of a venomous snake shall their words pierce and flow into the veins! And with the strength of a brute beast shall My servants pass through the midst of them. And not one shall have strength enough to withstand them or prevent them, by any means. For I am great in power, and nothing in all creation is able to restrain Me! Nor shall any prevent My Word from speaking, when I pour out My fury upon the desolate! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, My own people flee from the Word of My mouth; look how they run from My every proclamation! I can not speak to them, for they do always resist Me, nor do they seek Me in truth! Lo, they fight against Me by their every word and deed! THEY DO NOT KNOW ME! For the sake of pretense, they draw near to Me with their mouths and honor Me with their lips, yet their hearts are far from Me! I AM EXCEEDINGLY REMOVED! They do not think about Me, nor do I dwell in their thoughts; I am purged from their consciences! They have not pondered My Law as David, nor have they mourned like Daniel. They have turned from Me, and the Way of The Lord they have not known, adding to and taking away from My Commandments, ignoring My every decree. Thus I have opened My mouth in correction and raised My voice in strong rebuke. Yet they cast off My words spoken to this generation, and want no part with Me as I truly am. Behold, I have become as a foreigner to them, of a tongue which they do not understand! INDEED, THEY REFUSE TO UNDERSTAND! Yet in My mercy I have spoken to them in their own language, with brevity, using few figures of speech, that they might repent and return to Me, and walk again in the first works while not at all ignoring the latter, that they might heed My voice and come out. Yet they will not give heed, nor will they come out; they will not repent. Indeed they refuse to return, nor will they walk in the Way of The Lord. For when I speak, they think Me too harsh, claiming My words to be overtones of a forgotten past. They refuse My teaching, saying it is too hard and does not fit with their established doctrine. Indeed, they despise My food and will not eat from My plate, and want nothing to do with My table..."},{t:"italic",v:"REGURGITATED FOOD IS THEIR DELIGHT, AND DISEASED DOCTRINE THE ONLY ACCEPTED PLATE! For they have grown accustomed to their own filthy table!"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, their forefathers call out to them"}],[{t:"italic",v:"From the grave; their wicked cause continues!"}],[{t:"italic",v:"In the faces of their descendants it is clearly seen,"}],[{t:"italic",v:"And upon their lips the blasphemy of their"}],[{t:"italic",v:"Forefathers is clearly heard, even to this day!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And so they persecute Me in their deceitful courts,"}],[{t:"italic",v:"And place Me on trial because of My words!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Lo, they deny The Truth and put"}],[{t:"italic",v:"The Author of Life to an open shame!..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"How long shall this perverse and arrogant people weigh Me in the balances with preweighted scales, holding Me up against their own corrupt doctrine, placing Me opposite deceitful weights?! To this day I am treated as a criminal, I am spit upon everyday, BEATEN AND SCOURGED BY MY OWN PEOPLE! How many times shall you crucify Me?! HOW LONG SHALL YOU PIERCE YOUR KING, O CHURCHES OF MEN?! For no man of God is pleasant in their sight, no messenger is accepted unless they deal wickedly, unless they speak to them lies and pleasant things! Unless they prophesy to them deceits, they will not be accepted, nor will they listen! Have I not spoken the Truth to them, that they may know it? Have I not sung to them, that they may learn the melody of My song? Have I not sent many servants to help them, to lead them from their self-imprisonment? For as it is written:"},{t:"italic",v:"I have stretched out My hands all day long to a rebellious people who walk in a way that is not good, according to their own thoughts, a people who continually provoke Me to anger to My face."},{t:"fn",v:"2"},{t:"text",v:"Yet I have sent down both the early and latter rain in due season, to a desolate people who are in dire thirst, that I might cool their tongues, a people who walk through very dry places, seeking always to hide themselves from the heat of the noonday sun."},{t:"fn",v:"4"},{t:"text",v:" Yet they will not drink, nor are they hidden, for their sins remain uncovered."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I poured out My life for them"}],[{t:"italic",v:"In fountains of living waters,"}],[{t:"italic",v:"For My love runs deep..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet they forsake Me still..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, the Great and Dreadful Day"}],[{t:"italic",v:"Of The Lord is declared, the days"}],[{t:"italic",v:"Of martyrdom set, the day in which"}],[{t:"italic",v:"The court of God shall be cleansed..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And the hearts of many shall be remade,"}],[{t:"italic",v:"Established anew in the blood of The Lamb,"}],[{t:"italic",v:"Even the remnant whom The Lord shall call."}]]},{type:"para",segments:[{t:"text",v:"Therefore, again I say to you, test your hearts by the line which is true, by the line which I have given you. No longer tempt The Lord your God, nor claim My ways unfair or My judgments unjust. Am I unfair? Is The Lord your God unjust? Or are your hearts so corrupt, that you can no longer discern your right hand from your left? Are your heads so covered with blackness, that your eyes can no longer penetrate this darkness which surrounds you? For I tell you the truth, you have blocked My way before Me by your traditions, and have covered My righteousness with filthy rags of doctrine! Behold, I am hidden from your eyes! Therefore give answer, O churches of men, where am I found? Do I stand upon your pulpits? Am I seen only in your images of stained glass? Am I bent down and overlain with a cloth, which you call the altar? Am I a god found only in your rituals? Am I a god of religious sacraments to you?..."},{t:"italic",v:"OR AM I GOD, THE GOD?!... He who defends the cause of the fatherless and the orphan! He who commands His people to provide shelter for the homeless and to uphold the cause of the needy, the aged and the widow! Do I not uphold the scales of truth, weighing all in the balances?! Am I not the discerner of the heart and of the mind, He who knows the innermost thoughts and intentions?! Says The Lord."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, the heart of this people is waxed gross! For they say,"},{t:"italic",v:"\u201CThe Lord is our God!\u201D"},{t:"text",v:"Yet they forsake My Sabbaths and take no pleasure in My Commandments, choosing rather to walk in their own way!..."},{t:"italic",v:"I AM NOT THEIR GOD!"},{t:"text",v:"For they desire a god without authority, a god who does not see, lest I look upon them and judge them too harshly. For My ways are not sufficient for them, nor will they abandon their sin. They are unwilling to leave behind all they have built up in their vanity, and return to Me. Thus their arrogance remains uplifted, and their pride securely enthroned beneath them, says The Lord. Therefore, it is no longer sufficient that I send only one prophet or a single witness. For the foreheads of this modern generation are as hard as adamant stone, multitudes of dead and dying people with countenances set hard against The Lord and His anointed. Thus I shall not send just one, nor am I sending thirty or sixty, or even one hundred men to this obstinate people, but 144,000! For the sake of mercy I am sending them, and for a trumpet and alarm against the cities, the special offering who shall not suffer at the hands of men, nor be given up to the slaughter. For The Lord their God shall dwell in them and amongst them, with a portion far greater than the prophet Elijah of old. Therefore, woe to all who refuse My messengers and shut their ears to My prophets! Woe to all the inhabitants of the earth, who walk contrary to the Way I have set before them! For who can escape the righteous anger of God?! Who can sidestep the Way of The Lord?! For My fire is unquenchable, consuming wrath from The Almighty! For The God of Recompense is come down, and all shall know Me!..."},{t:"italic",v:"The Glory of The Invisible God revealed, the might of The Holy One put on open display!"},{t:"text",v:"Behold, the wicked and evil of heart shall perish at My own hand, the ungodly and the defiled shall be destroyed together; they shall be consumed! For all those who refuse Me shall die in their uncleanness! All those who willingly forsake Me shall be cast into eternal darkness, into the void of lifeless nothingness, forever! For these did not seek out My Salvation which came down in the flesh, they wanted no part with Him who was sent; they refused to accept Me as I truly am."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, My own blood was poured out for them,"}],[{t:"italic",v:"Yet they continued to curse My name!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I offered them new garments, robes of white,"}],[{t:"italic",v:"As white as snow, yet they pushed out the hand"}],[{t:"italic",v:"And stiffened their necks, and did not cease"}],[{t:"italic",v:"From lifting up their heel against Me!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore My sword shall be fully unsheathed,"}],[{t:"italic",v:"And My robe soaked with blood, when I lift up"}],[{t:"italic",v:"My voice against them and strike them"}],[{t:"italic",v:"With the sword of My mouth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For behold, it is written before Me:"}],[{t:"italic",v:"I will not be silent, but will surely repay,"}],[{t:"italic",v:"Recompense in full even into their bosom,"}],[{t:"italic",v:"Their iniquities and the iniquities of their"}],[{t:"italic",v:"Forefathers together! Says The Lord"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, REPENT!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For the mouth of YAHUWAH has spoken!"}]]}],footnotes:{1:{type:"scripture",ref:"Jeremiah 5:14"},2:{type:"scripture",ref:"Isaiah 65:2-3"},3:{type:"scripture",ref:"Isaiah 65:6-7"},4:{type:"note",text:'Also read: "I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"',url:"https://www.thevolumesoftruth.com/I_Shall_Remove_My_Hand_and_My_Spirit_Shall_Be_Withdrawn..._And_That_Purposed_from_the_Beginning_Shall_Be_Done,_It_Shall_Be_Accomplished_Swiftly",link:{collection:"Volume Seven",letterTitle:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"}}},nkjv:{"Jeremiah 5:14":"Therefore thus says the LORD God of hosts: \u201CBecause you speak this word, Behold, I will make My words in your mouth fire, And this people wood, And it shall devour them.","Isaiah 65:2-3":"2. I have stretched out My hands all day long to a rebellious people, Who walk in a way that is not good, According to their own thoughts; 3. A people who provoke Me to anger continually to My face; Who sacrifice in gardens, And burn incense on altars of brick;","Isaiah 65:6-7":"6. \u201CBehold, it is written before Me: I will not keep silence, but will repay\u2014 Even repay into their bosom\u2014 7. Your iniquities and the iniquities of your fathers together,\u201D Says the LORD, \u201CWho have burned incense on the mountains And blasphemed Me on the hills; Therefore I will measure their former work into their bosom.\u201D"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/the-cup-of-the-wrath-of-my-fury-is-come-to-the-full",videoVoiceUrl:"https://www.youtube.com/watch?v=NCYImxBCfW4&list=PL6D1BC949E9840878&index=30",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"Regarding Science",url:"https://answersonlygodcangive.com/Regarding_Science"},{label:"God Speaks About Materialism",url:"https://answersonlygodcangive.com/God_Speaks_About_Materialism"},{label:"Regarding Sin",url:"https://answersonlygodcangive.com/Regarding_Sin"},{label:"Regarding What is an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Come Out of the Churches of Men",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_of_the_Churches_of_Men_-_Section_One"},{label:"Regarding Scoffers",url:"https://answersonlygodcangive.com/Regarding_Scoffers"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"Regarding Adding to or Taking Away From The Word of God",url:"https://answersonlygodcangive.com/Regarding_Adding_to_or_Taking_Away_From_The_Word_of_God"},{label:"False Doctrines Within the Churches of Men Regarding...",url:"https://answersonlygodcangive.com/False_Doctrines_Within_the_Churches_of_Men_Regarding..."},{label:"Regarding Prophets (True)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(True)"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"}],num:26,prevLetter:{id:"shiloh",title:"Shiloh"},nextLetter:{id:"far-removed",title:"Far Removed"}},{id:"far-removed",title:"Far Removed",date:"2/15/12",from:"From The Lord, Our God and Savior",spoken:"",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, to all those who dwell within these detestable walls; to all these who stand inside these undesirable gates, hear the Word of The Lord:"},{t:"text",v:"Shall you trust in the works of your own hands, O sons of men? How long shall you be wise in your own eyes? For that which you have erected shall be your undoing, and that which you uphold shall surely collapse upon your own heads. For I have seen it! Says The Lord. Yes, I have looked upon you, O perverse and most deceitful generation! I have seen the rebellion within your hearts and how your minds betray you, even each one his neighbor and every one his own close friend! Behold, I have peered deep into each temple, and upon every place of worship have My eyes been set. Thus I open My mouth to speak, and with a loud voice I declare your transgressions before the people."}]},{type:"poetry",lines:[[{t:"italic",v:"Lo, I detest the sight of you, O churches of men,"}],[{t:"italic",v:"And in bitterness I have spit you from My mouth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, blasphemy is heard from every pulpit,"}],[{t:"italic",v:"And perversion is laid upon every altar!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"CHURCHES OF MEN, YOUR HOUSES"}],[{t:"italic",v:"ARE COVERED IN THE FILTH OF"}],[{t:"italic",v:"THE PAGAN AND DRIP WITH THE"}],[{t:"italic",v:"POLLUTED BLOOD OF THE HEATHEN!"}]]},{type:"para",segments:[{t:"text",v:"For by your harlotries have you set the stage for the deceiver, while each one of you claps the hands and offers up praises to your soothsayers!..."},{t:"italic",v:"False prophets and teachers whose words seem oh so wise in your eyes, whose voices are smooth, soothing your itching ears... Prepared speeches, soft songs, lulling you to sleep as you rest comfortably in your padded chairs, slowly fading into all this darkness in which you are so easily ensnared, thick darkness from which you will not escape, says The Lord."},{t:"text",v:"For you have surely polluted My name and desecrated My Commandments, putting The Holy One to an open shame, crucifying Him again and again in your hearts! Behold, He has altogether become as one dead in your eyes!..."},{t:"italic",v:"Yet I tell you the truth, I AM COME!"},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, I am risen up out of My place, and I have"}],[{t:"italic",v:"Come forth to punish the inhabitants of the earth,"}],[{t:"italic",v:"To pour out judgment upon all those who"}],[{t:"italic",v:"Cease not from doing evil in My sight!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I HAVE COME FORTH TO DELIVER"}],[{t:"italic",v:"JUSTICE IN ALL THE EARTH,"}],[{t:"italic",v:"RECOMPENSE FOR ALL NATIONS!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, this generation is dead"}],[{t:"italic",v:"In My eyes, I see no life in them!"}],[{t:"italic",v:"For from this people I am far removed!..."}]]},{type:"closing",text:"Says The Lord."},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to the churches of men:"},{t:"text",v:"Your cups are full of spoiled wine, yet oh how you love to sip from them. I hear you say,"},{t:"italic",v:"\u201CThe body of Christ\u201D"},{t:"text",v:"as you take and eat, yet not one of you truly receives of Him. Indeed, you stand in the midst of pools of water, immersing yourselves, yet you remain unclean. For I do not know you! Says The Lord. Therefore depart from Me, all you workers of lawlessness, all you hard-hearted people who reject Me and My words and push out the hand against My rebuke! Depart from Me, all you blind guides who have failed to recognize Me! DEPART! For with you I am sorely displeased! Says The Lord God."}]},{type:"poetry",lines:[[{t:"italic",v:"For you have allowed the pagan to enter in"}],[{t:"italic",v:"And take his throne upon the altar, as the"}],[{t:"italic",v:"Congregation gives ear to the deceiver,"}],[{t:"italic",v:"Welcoming his every word!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the churches of men have fallen!..."}],[{t:"italic",v:"They are fallen!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even every one of them has forsaken Me!"}],[{t:"italic",v:"All have went backward, and not forward!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Each one refuses to obey, nor will they"}],[{t:"italic",v:"Incline the ear, but follow the counsels and"}],[{t:"italic",v:"Dictates of their own evil hearts!"}]]},{type:"para",segments:[{t:"text",v:"Lo, with open palms they greedily receive false testimony, as they give ear to every false prophet and teacher who comes to them speaking lies and pleasant things, saying,"},{t:"italic",v:"\u201CPeace, peace\u201D..."},{t:"text",v:"Yet there is no peace!"}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord to this insolent people who dwell amongst the churches of men:"},{t:"text",v:"You are dead, though you yet live. How long shall you commit adultery against your God?! How long shall you break My Commandments and ignore My every decree, one after another, then come and stand before Me, saying,"},{t:"italic",v:"\u201CWe are delivered to do all these things\u201D?..."},{t:"text",v:"You are not delivered! Indeed, there is nothing new under the sun, for to this day My people say,"},{t:"italic",v:"\u201CThis is the temple of The Lord, the temple of The Lord, the temple of The Lord. Our God dwells here, and His spirit has come to rest upon us. Therefore we will honor Him with our rituals, and open our mouths in praise. For we are the true bride; yes, WE are His chosen people.\u201D"},{t:"text",v:"Woe, I say to you, for you are all rebellious houses! - A most prideful and wayward generation, a multitude of deceived peoples! Your worship is in vain, it is not accepted! I take no pleasure at all in your offerings, for that which you offer up in My name is unclean!..."},{t:"italic",v:"Behold, all your rituals are like polluted fountains, yet you love to drink! Yea, your every tradition is like refuse spread out before My face, yet you revel in it! For you have not known Me, nor do you recognize My voice."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus you did not come out at My calling,"}],[{t:"italic",v:"Nor are you able to pass through the gate..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For one who truly desires Me seeks Me out;"}],[{t:"italic",v:"And one who is in love with Me obeys My"}],[{t:"italic",v:"Commands and gives heed to My every decree..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet you prefer the voice of a hired man,"}],[{t:"italic",v:"Having altogether forgotten the voice of your Shepherd."}]]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"Again I tell you, I HAVE SEEN IT! And as I live, says The Lord, so also do I declare it through the pen of My prophets; lo, I have sworn it in the heat of My wrath, and will also do it! Behold! I have purposed destruction upon all your abominable temples! I have declared calamity for all your grand houses, until all these riches are consumed!..."},{t:"italic",v:"Every building which stands so high and lofty, every whitewashed wall which conceals abomination, every upright pillar, every established column, all must come down, all must be broken in pieces! - Until only dust and ashes remain, until the foot of the high man can find no level ground upon which to stand and rest, until the hand of the proud finds no place to lean upon in his weariness."},{t:"text",v:"For only then will they be separate, only then will they come out from among them, says The Lord. For I alone am The Kingdom, The Power and The Glory, forever and ever. Amen..."},{t:"italic",v:"Therefore, let My name resound! Let it go forth to break off the branches and level the forests! Let it stir up the hurricane and devastate the coastlands! Let it bring forth the whirlwind against those far inland! Let the lightning strike down every wall and set every city on fire, in the name of The Lord!"},{t:"text",v:"Behold, the ground beneath your feet is unsteady, O mighty nations! Feel it tremble at the presence of The Lord, and watch in astonishment how it shrinks back at The Lord\u2019s rebuke! For I shall thrust the rocks upward and pull apart the mountains! Blood and fire and pillars of smoke! Therefore see The Word of The Lord, O peoples of the earth! Listen to the sound of My voice, and repent! Give Me glory! For there is a worship in which I am well pleased, yet you have not known it. Indeed, there is a praise in which I delight, yet from you I have not heard it. For you honor Me with your lips, yet your hearts remain far from Me."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, I have spit you"}],[{t:"italic",v:"From My mouth, O churches of men!"}],[{t:"italic",v:"I have vomited you out, O peoples of the earth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until I have pursued My enemies and"}],[{t:"italic",v:"Wounded them, until I have destroyed them,"}],[{t:"italic",v:"That they should no more stand..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until truth brings forth conviction"}],[{t:"italic",v:"And humility is born of sincere repentance,"}],[{t:"italic",v:"Until My people are broken without hand,"}],[{t:"italic",v:"Until the whole world has fallen under My feet..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until the hearts of My beloved cry out My name in truth"}],[{t:"italic",v:"And no more pollute My name in their unjust cause..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Until My people are once again made whole..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"note",text:'Also read: "I AM COME"',url:"https://www.thevolumesoftruth.com/I_AM_COME",link:{collection:"Volume Five",letterTitle:"I AM COME"}}},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/far-removed",videoVoiceUrl:"https://www.youtube.com/watch?v=S4KeVCgnVZc&list=PL6D1BC949E9840878&index=49",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"God Speaks Regarding Those Who Bear False Witness in His Name",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Bear_False_Witness_in_His_Name"},{label:"Regarding Prophets (False)",url:"https://answersonlygodcangive.com/Regarding_Prophets_(False)"},{label:"Polluting the Name of The Lord",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain#Polluting_the_Name_of_The_Lord_.28Section_One.29"},{label:"Regarding The Ten Commandments",url:"https://answersonlygodcangive.com/Regarding_The_Ten_Commandments"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding Baptism",url:"https://answersonlygodcangive.com/Regarding_Baptism"},{label:"God Speaks Regarding Adultery Committed Against Him",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Adultery_Committed_Against_Him"},{label:"The True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#The_True_Bride"},{label:"Regarding Pride",url:"https://answersonlygodcangive.com/Regarding_Pride"},{label:"Come Out From Among Them",url:"https://answersonlygodcangive.com/I_Am_Calling_You_Out#Come_Out_From_Among_Them_-_Section_One"},{label:"THERE IS NO OTHER",url:"https://answersonlygodcangive.com/THERE_IS_NO_OTHER"},{label:"Regarding the Voice of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Voice_of_The_Lord"},{label:"Regarding True Repentance",url:"https://answersonlygodcangive.com/Regarding_True_Repentance"}],num:27,prevLetter:{id:"the-cup-of-the-wrath-of-my-fury-is-come-to-the-full",title:"THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL"},nextLetter:{id:"a-new-and-terrible-thing",title:"A New and Terrible Thing"}},{id:"a-new-and-terrible-thing",title:"A New and Terrible Thing",date:"12/5/11",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"Behold, I have come down; yes, I am here! I have come down to dwell in My chosen and to deliver My elect, even every lamb! For I am The Lord, and My jealousy has come to the full! I shall no more tolerate all this injustice and murder, all these abominations, all this wickedness! I shall no more endure all this persecution, even by My own people who pollute My name day and night, without ceasing! For I shall stand upon the earth in My fierce anger, and repay! And I shall defend My elect and protect the weak and the needy, and the cause of the widow shall be fulfilled in her deliverance!..."},{t:"italic",v:"For I am Lord and God, The Deliverer! Yes, I AM HE!"},{t:"text",v:"Behold! Look! For The Lord your God shall do a new thing, a new and terrible thing, an astonishment, a great wonder, the likes of which this world has never seen! The faces of the multitudes shall pale, the hearts of many shall fail them for fear! Many shall collapse, gathering blackness, on account of that which is coming to pass before their eyes! - The mighty and awesome power of The Lord your God put on open display! For who can stand against His coming?! Who will not fall down at the sound of His voice?!"}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"It is time! My hand shall reach down; lo, it shall plunge into the earth! It shall pass through every tomb and every mausoleum, through every grave! Behold, My hand shall pass through the dust and sift the sands of the desert. Even unto the depths of the sea, My hand shall grab hold, and the whole earth shall give up its dead -"},{t:"italic",v:"Every child of God, every servant of The Most High, every sheep beloved of The Shepherd."},{t:"text",v:"Then shall I turn to the multitudes and pass through; behold, I shall pass through and steal them away! -"},{t:"italic",v:"Babes from every womb, children from every corner, and My elect from every nation!"}]},{type:"poetry",lines:[[{t:"italic",v:"The world shall be left utterly desolate and in tears;"}],[{t:"italic",v:"Heavy sorrows shall overtake every land!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, an outcry shall rise up"}],[{t:"italic",v:"Such as has never been heard!"}],[{t:"italic",v:"Much weeping and lamentation, anger and many"}],[{t:"italic",v:"Raised fists, a great gnashing of teeth!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yes, among every tribe, people and nation,"}],[{t:"italic",v:"A great noise shall be heard!"}],[{t:"italic",v:"For three full days it shall not subside,"}],[{t:"italic",v:"And for three full nights it shall not lessen..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus shall their first reward be given,"}],[{t:"italic",v:"For they have shown themselves fully worthy;"}],[{t:"italic",v:"Then shall they know, I AM THE LORD!"}]]},{type:"poetry",lines:[[{t:"italic",v:"And thus shall the Great and Terrible"}],[{t:"italic",v:"Day of The Lord begin!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, the wrath of The Lamb!"}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/a-new-and-terrible-thing",videoVoiceUrl:"https://www.youtube.com/watch?v=D8RlevS_N9Y&list=PL6D1BC949E9840878&index=49",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:'Regarding the Gathering Up ("Rapture")',url:"https://answersonlygodcangive.com/Regarding_the_Gathering_Up_(Rapture)"},{label:"Regarding the Birth Pangs",url:"https://answersonlygodcangive.com/Regarding_the_Birth_Pangs"}],num:28,prevLetter:{id:"far-removed",title:"Far Removed"},nextLetter:{id:"judgment-and-woe",title:"Judgment and Woe"}},{id:"judgment-and-woe",title:"Judgment and Woe",date:"2/12/22",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Behold, the time has come; the time has come for Me to open My mouth, once again. Yet not as in the former manner, nor as at the first; but in fiery anger, in devastating monologues of fierce rebuke, unrelenting diatribes of judgment and woe, setting a whole generation ablaze!... There shall be wailing and gnashing of teeth. Yea, I shall speak through the Sent, and they shall pronounce My judgment! - Upon all the cities of men, upon the waste places, upon the towns and villages! Upon every religion of man, upon every idol, upon every false image of the Gentiles, upon every god of every land, upon everything high and lifted up! Upon all who reject Messiah; yes, even upon those who have marred His image before the people shall My discipline be most severe! -"},{t:"italic",v:"Until the glory of man is turned backward, and the pride of man is bowed down, and the arrogance of man is utterly humiliated, as it is written."},{t:"fn",v:"1"},{t:"text",v:"And behold I, yes I, The Only Lord of Hosts, shall heed the voice of a man in that day. And woe to all who come against them!"}]},{type:"para",segments:[{t:"text",v:"Behold, in an unheard word I shall whisper to the foundations of the earth, and they shall quiver, they shall begin to shake. Yea, I shall increase the sound of My voice, and the continents shall bend to My will. They shall crack and move about in their places, as one bound struggling to break free, as one overcome with panic desperate to flee. For the countenance of The Holy One has changed; His demeanor is set to defend, to avenge and pour out judgment, to shake the earth violently!..."}]},{type:"para",segments:[{t:"text",v:"Behold! The Wrath of The Lamb!..."}]},{type:"para",segments:[{t:"text",v:"THE LION!"}]}],footnotes:{1:{type:"scripture",ref:"Isaiah 2:11,17"}},nkjv:{"Isaiah 2:11,17":"2:11 \u2014 The lofty looks of man shall be humbled, The haughtiness of men shall be bowed down, And the LORD alone shall be exalted in that day. | 2:17 \u2014 The loftiness of man shall be bowed down, And the haughtiness of men shall be brought low; The LORD alone will be exalted in that day,"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/judgment-and-woe",videoVoiceUrl:"https://www.youtube.com/watch?v=G70FSwFw9mI&list=PL6D1BC949E9840878&index=45",videoMusicUrl:"https://www.youtube.com/watch?v=DuBPE9FrkfA&list=PLSVchFJ22QYKZW4CHtZ43YBxdHUTgS9rv&index=1",relatedTopics:[{label:"I Am The Lord, I Do Not Change",url:"https://answersonlygodcangive.com/I_Am_The_Lord,_I_Do_Not_Change"},{label:"Regarding the 144,000 Witnesses",url:"https://answersonlygodcangive.com/Regarding_the_144,000_Witnesses"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Religions of Men Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_Religions_of_Men_Are_an_Abomination_to_The_Lord"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"The gods of the Gentiles Are an Abomination to The Lord",url:"https://answersonlygodcangive.com/Regarding_What_is_an_Abomination_to_The_Lord#The_gods_of_the_Gentiles_Are_an_Abomination_to_The_Lord"},{label:"Woe to the Nay-sayers and Mockers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_the_Nay-sayers_and_Mockers"},{label:'Regarding "Another Messiah"',url:"https://answersonlygodcangive.com/Regarding_Another_Messiah"},{label:"The Pride of Man Shall Be Bowed Down",url:"https://answersonlygodcangive.com/Regarding_Pride#The_Pride_of_Man_Shall_Be_Bowed_Down"},{label:"Woe to Those Who Come Against God's Messengers",url:"https://answersonlygodcangive.com/Woe_to_Those_Who...#Woe_to_Those_Who_Come_Against_God.27s_Messengers"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],num:29,prevLetter:{id:"a-new-and-terrible-thing",title:"A New and Terrible Thing"},nextLetter:{id:"overthrow",title:"Overthrow"}},{id:"overthrow",title:"Overthrow",date:"6/27/22",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"I shall devastate every coastland and pour out judgment on every city where satan dwells, upon every state that continues in the slaughter of the innocent! Behold, I shall pour out double! Yes double, even double again, upon all who murder My precious gifts, as it is written!"},{t:"fn",v:"1"},{t:"text",v:"And those who reject My Word spoken to this generation shall by no means be spared! Yet upon those places which have put a stop to the slaughter of the unborn, I shall stay My hand, yet only slightly. They shall not receive double. They shall receive only that which is due them, according to that which I see, and in accordance with their every idle word. For though the slaughter of the innocent is very grievous, over which My indignation burns hot, it remains but one of many sins, yea, a great multitude of transgressions by which this generation has provoked Me to anger."}]},{type:"poetry",lines:[[{t:"italic",v:"Thus I shall rain down judgment from heaven"}],[{t:"italic",v:"Upon every tribe, tongue, people and nation"},{t:"fn",v:"2"},{t:"italic",v:","}],[{t:"italic",v:"And bring up horrible calamity from beneath"},{t:"fn",v:"3"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And such as are for death, to death;"}],[{t:"italic",v:"And such as are for the sword, to the sword;"}],[{t:"italic",v:"And such as are for the famine, to the famine;"}],[{t:"italic",v:"And such as are for the captivity, to the captivity,"}],[{t:"italic",v:"As it is written"},{t:"fn",v:"4"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{1:{type:"note",text:'See: "The Innocent Are Mine"',url:"https://www.thevolumesoftruth.com/The_Innocent_Are_Mine#:~:text=And%20yes%20double%2C%20even%20double%20again%2C%20upon%20all%20who%20murder%20My%20precious%20gifts!%20Declares%20The%20Lord.",link:{collection:"Volume Four",letterTitle:"The Innocent Are Mine",excerpt:"And yes double, even double again, upon all who murder My precious gifts! Declares The Lord."}},2:{type:"note",text:'See: "The Last Trump"',url:"https://www.thevolumesoftruth.com/The_Last_Trump#:~:text=Behold%2C%20judgment%20shall%20rain%20down%20from%20Heaven%20upon%20every%20tribe%2C%20tongue%20and%20people%20%2D%20RECOMPENSE%20FOR%20ALL%20NATIONS!",link:{collection:"Volume Three",letterTitle:"The Last Trump",excerpt:"Behold, judgment shall rain down from Heaven upon every tribe, tongue and people - RECOMPENSE FOR ALL NATIONS!"}},3:{type:"note",text:'See: "As It Was in the Days of Noah, So Shall the Coming of The Son of Man Be"',url:"https://www.thevolumesoftruth.com/As_It_Was_in_the_Days_of_Noah,_So_Shall_the_Coming_of_The_Son_of_Man_Be#:~:text=And%20upon%20the%20earth%20shall%20I%20rain%20down%20judgment%2C%0AAnd%20bring%20up%20horrible%20calamity%20from%20beneath%3B",link:{collection:"Volume Five",letterTitle:"As It Was in the Days of Noah, So Shall the Coming of The Son of Man Be",excerpt:"And upon the earth shall I rain down judgment"}},4:{type:"scripture",ref:"Jeremiah 15:2"}},nkjv:{"Jeremiah 15:2":"And it shall be, if they say to you, \u2018Where should we go?\u2019 then you shall tell them, \u2018Thus says the LORD: \u201CSuch as are for death, to death; And such as are for the sword, to the sword; And such as are for the famine, to the famine; And such as are for the captivity, to the captivity.\u201D \u2019"},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/overthrow",videoVoiceUrl:"https://www.youtube.com/watch?v=alSVZcbKZzA&list=PL6D1BC949E9840878&index=45",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"Regarding the United States",url:"https://answersonlygodcangive.com/Regarding_the_United_States"},{label:"Thus Says The Lord Regarding Abortion",url:"https://answersonlygodcangive.com/Thus_Says_The_Lord_Regarding_Abortion"},{label:"Woe to Those Who...",url:"https://answersonlygodcangive.com/Woe_to_Those_Who..."}],num:30,prevLetter:{id:"judgment-and-woe",title:"Judgment and Woe"},nextLetter:null}],WTLB_ONE=[{id:"introduction",num:1,title:"Introduction",paragraphs:[{align:"center",text:`**WORDS TO LIVE BY...**



_**More Words of Wisdom**_

_**From The Lord, Our God and Savior**_




For all those who have dedicated

Themselves to Me by means of The Truth,

Those who have recognized My words

And also do them...



Those who came to Me empty

That I might fill them up,

That they might be truly dedicated to Me...



Even as I had dedicated Myself to them also,

That we may become one...



Set apart in My glory, for My glory,

To the joy of their Father in Heaven...


Says The Lord YahuShua.`},{align:"justify",text:"Behold, My words shall never pass away. For as I am, so also is My Word. For it proceeds from Me, being manifest by He Who Is True, also being called The Word... Living... Always feeding His flock The Word, which is written for their nourishment, which is to be received through that part of Himself which is also in Me, says The Lord God. ~ [From \u201CThe Word of My Mouth\u201D ~ Volume 7]"},{align:"center",text:`It is written:



\u201CMan shall not live by bread alone,

But by every word that proceeds

From the mouth of God.\u201D



{{ref:Matthew 4:4}}`}]},{id:"come-love-awaits-you",num:2,title:"Come, Love Awaits You",paragraphs:[{align:"center",text:"Come, all those who know not My ways; I will show you."},{align:"center",text:`Come, all those who have been abandoned;

I will comfort you and give you shelter.`},{align:"center",text:`Come, all those who are crippled;

Let us run and leap for joy together!`},{align:"center",text:`Come, all those faithless;

I shall fill your cup, and watch how it overflows!`},{align:"center",text:`Come, all murderers;

Watch Me raise you, and all who sleep, from the grave.`},{align:"center",text:`Come, all you who blaspheme, I will give you a new voice;

Bring with you all those who are blind and deaf,

For they too shall see and hear!`},{align:"center",text:`Indeed, come all those who have sinned against Me, take My hand!

I will lead you to the waters where I shall wash you,

And where your new clothes hang upon the tree

Which grows next to the stream.`},{align:"center",text:`Come one, come all! Ask, and it shall be given you!

For all things are possible with God

And made manifest through The Son...



Says The Lord YahuShua.`}]},{id:"crowning-glory",num:3,title:"Crowning Glory",paragraphs:[{align:"center",text:"The love of God is His crowning glory..."},{align:"center",text:`And that love is revealed in the glory of The Son,

By which His beloved are also crowned.`}]},{id:"the-spirit-of-truth-brings-conviction",num:4,title:"The Spirit of Truth Brings Conviction",paragraphs:[{align:"justify",text:"This question was asked of The Lord, regarding {{ref:Luke 15:11-32}} Lord, have I become hard like the older son? Have I put my hand to tasks, and forgotten to build up compassion for those who have gone astray? Is this story meant to convict me, Lord?"},{align:"center",text:"[The Lord answered]"},{align:"center",text:`If your heart is convicted,

Then has it not also given answer

To your prayer already,

Revealing the Spirit which dwells

Within you, of what sort it is?`},{align:"center",text:`For only the Spirit of Truth will bring forth

Conviction unto righteousness,

Bearing much fruit in The Beloved...



Says The Lord.`}]},{id:"the-first-stitch",num:5,title:"The First Stitch",paragraphs:[{align:"center",text:`The first stitch, to mend any rent,

Are the words \u201CI\u2019m sorry\u201D...



Says The Lord.`}]},{id:"yahuwah-is-one-and-his-word-one",num:6,title:"YAHUWAH Is One; And His Word, One",paragraphs:[{align:"justify",text:"The Old Testament is The Father revealing Himself, while pointing to The Son. The New Testament is The Son revealing Himself while pointing to The Father, also fulfilling the Messianic prophecies of the Old Testament in Himself. The Letters are The Father and The Son revealing themselves as One, even as the Word of God is one, with The Letters being the culmination of the whole - not separate, but one."},{align:"center",text:`Therefore, to reject any part of

The Lord\u2019s Word is to reject the whole.`},{align:"center",text:"The three books are one..."},{align:"center",text:"One on-going testament to God\u2019s glory."}]},{id:"removing-the-veil",num:7,title:"Removing The Veil",paragraphs:[{align:"justify",text:`_Thus says The Lord:_ Those who receive of Me begin to see with eyes wide open, with the deafness of their ears healing quickly.

Yet those who have not received rely upon the spirit of men to discern, and stumble greatly; rejecting My Word spoken to this generation, while at the same time polluting My Word from aforetime; firmly securing the veil which remains atop their heads, covering their faces in an attempt to hide their shame.`},{align:"center",text:`Therefore, I have spoken it and shall

Say it again before this perverse

And most wicked generation,

Though they can in no wise bear to hear it...`},{align:"center",text:"I AM COME! THE TIME IS HERE!"},{align:"center",text:`And behold I, The Lord your God,

Will do nothing until I have revealed

My plans to My servants, the prophets,

And this I have done.`}]},{id:"serving-others-in-love",num:8,title:"Serving Others in Love",paragraphs:[{align:"center",text:`Beloved, by serving others in love,

Putting their needs before your own...`},{align:"center",text:`By sacrificing yourself,

Your desires, your wants, your will,

Your body, even your very life...`},{align:"center",text:`Will you learn what it truly means

To wash each other\u2019s feet,

Says The Lord.`}]},{id:"prayers-of-the-sincere-in-heart",num:9,title:"Prayers of the Sincere in Heart",paragraphs:[{align:"justify",text:"Prayer request: Please pray that pride won\u2019t become an issue for me, because I just wanna walk with YahuShua only."},{align:"center",text:"[The Lord answered]"},{align:"center",text:`In your request is wisdom;

For those of a sincere heart,

Whose prayer is to flee from pride,

Have received of their request

Already in the asking...`},{align:"center",text:`Whereby they have also begun

To build up a hedge about themselves,

Because of their intent...



Says The Lord.`}]},{id:"touching-the-heart-of-god",num:10,title:"Touching the Heart of God",paragraphs:[{align:"center",text:`The hard of heart have no knowledge;

Even all revelation is hidden from their eyes.`},{align:"center",text:`Yet one who shares in My cup,

Weeping heavily upon My chest,

Has touched the heart of God.`},{align:"center",text:`For sincere tears open the door to My fullness,

Yet a hard heart is a locked door...



Says The Lord.`}]},{id:"matters-of-the-heart",num:11,title:"Matters of the Heart",paragraphs:[{align:"center",text:`The wailing of the penitent

Brings forth healing;

Yet the words of the wicked

Cause only pain.



Love flows outward from

The hearts of the righteous;

Yet the love of the wicked

Grows cold, as hate enters in.`}]},{id:"what-is-pure",num:12,title:"What Is Pure?",paragraphs:[{align:"center",text:`Giving thanks to God

In My name is pure worship,

Yet the wicked man

Demands honor for himself.`},{align:"center",text:`The heart of a child is pure,

Yet the heart of the mature is corrupt...



Says The Lord YahuShua.`}]},{id:"the-spirit-of-unity",num:13,title:"The Spirit of Unity",paragraphs:[{align:"justify",text:`The spirit of unity is in Me, walking in My footsteps, doing unto others as you would have them do unto you; remembering that all you do to others, whether good or bad, you have done also to Me.

Have I not spoken to this already, in the Gospel of My servant, John? For I said to love one another, and to wash each other\u2019s feet, and that you can do nothing apart from Me.`},{align:"center",text:`Therefore be one in Me,

Even as I long to be one with you,

Even as The Father and I are One,

That our love may be made perfect in One...`},{align:"center",text:`You in Me, I in you,

To the joy of The Father...



Says The Lord YahuShua.`}]},{id:"a-wise-guide",num:14,title:"A Wise Guide",paragraphs:[{align:"center",text:`One who endeavors to teach My flock,

Using the Word of My own mouth,

Must grow very wise in the hearing

And must be wide awake in the Spirit...`},{align:"center",text:"Discerning, says The Lord."}]},{id:"the-true-jew",num:15,title:"The True Jew",paragraphs:[{align:"justify",text:`This question was asked: What is the definition of a true Jew?



[The Lord answered] The definition of a true Jew is this: YahuShua. Therefore, all those in whom I dwell are Jews indeed. For they are true, even as I am true... _Let none, therefore, bring even one railing accusation against MY olive tree! Says The Lord._`}]},{id:"finishing-the-race",num:16,title:"Finishing the Race",paragraphs:[{align:"center",text:`It is the man who endures through the pain,

And perseveres through every obstacle,

Who finishes the race.`},{align:"center",text:`Yet the man who surrenders all to The Lord

Will fly with eagle\u2019s wings.`}]},{id:"dual-paths",num:17,title:"Dual Paths",paragraphs:[{align:"center",text:`Let those who do wickedly

Walk in the way they have chosen,

Until their foot becomes ensnared.`},{align:"center",text:`And let those who are Mine seek

Righteousness apart from the wicked,

Until they are lifted up,

High upon healing wings!...



Says The Lord.`}]},{id:"leading-others-in-righteousness",num:18,title:"Leading Others in Righteousness",paragraphs:[{align:"center",text:"Can any man lead while wielding a whip?"},{align:"center",text:"Yet The Lord is above all."}]},{id:"grace-to-the-humble",num:19,title:"Grace to the Humble",paragraphs:[{align:"center",text:`Behold, The Lord raises His voice

Within the hearts of the elect!

Yet His silence bears witness

Against those who refuse to hear.



Pride is a veil held fast

Over the heads of the arrogant;

It shall cover them in the day of darkness.

Yet the way of the elect is a crown of glory,

And grace covers them.`}]},{id:"i-know-my-own",num:20,title:"I Know My Own",paragraphs:[{align:"justify",text:`Those who are Mine receive of Me. For I know My own, and they seek Me; My bride is chosen. Yet those who reject Me and My Word have not known Me, nor will they receive; My spirit is far removed.

Those who set themselves apart from Me, whether by word or deed or by pretense, their hearts are revealed; these shall be left to walk through very dry places. Yet those who seek Me in truth shall be drawn in quickly, whether they are near or far, for I know My own. And those who are married unto Me shall surely enter in.

Therefore, judge no more by human standards, discern by right standards, according to My love and the knowledge you have received in Me.`},{align:"center",text:`For I AM THE LORD, whose will is set

And can in no wise be turned back;

Even from the beginning,

It was decided and accomplished.`},{align:"center",text:"For I AM..."},{align:"center",text:`And My bride has always been

Predestined in The Beloved,

Says The Lord.`}]},{id:"strength-in-weakness",num:21,title:"Strength in Weakness",paragraphs:[{align:"center",text:`A man\u2019s strength is revealed

In confronting his greatest weakness,

Yet a man\u2019s greatest strength

Becomes his enemy

When pride enters in.`},{align:"center",text:`Yet My strength is made perfect

In My servant\u2019s weakness...



Says The Lord.`}]},{id:"stop-lying-to-your-children",num:22,title:"Stop Lying to Your Children",paragraphs:[{align:"justify",text:"(Regarding Santa, the Easter Bunny, the Tooth Fairy and the like)"},{align:"justify",text:"No lie is of the Truth. Yet the little ones are of The Truth, and remain with Me and in Me. Even now I call to them, for My lambs know My voice. And that which came from Me must soon return to Me."},{align:"justify",text:"Therefore, be separate from the ways of this world, and order your conduct according to The Word of Truth. And no more speak lies to your children, for this is sin."},{align:"center",text:`Rather feed them with The Bread

Which came down from Heaven,

The Bread which I am,

The Way, The Truth, The Life;

For this alone is pleasing to God.`},{align:"center",text:`Anything to the contrary

Is of the world and the evil one,

No matter its disguise...



Says The Lord YahuShua.`}]},{id:"all-i-have-is-yours",num:23,title:"All I Have Is Yours...",paragraphs:[{align:"center",text:`For in knowing Me you possess all things...



Says The Lord.`}]},{id:"the-only-fountain-of-knowledge",num:24,title:"The Only Fountain of Knowledge",paragraphs:[{align:"justify",text:`That which is revealed to one may not yet be revealed to another. And those who have seen, have seen, yet most have only understood dimly. Therefore trust is required, and comes before understanding, for understanding can only come from Me. For I am The Only Fountain, The Only Knowledge in which is life.

Beloved, when one loses sight of Me or turns away, understanding darkens. Yet one who keeps Me in front of them, coming to Me at all times and in every season, in them understanding brightens and they will have peace. For they abide in Me, and rest in the knowing that all things are held within My understanding, and are given and received according to the good pleasure of My will.`},{align:"center",text:`And indeed, this is sufficient for them.


For they had first sought after

The Kingdom of God and His righteousness,

By which much revelation was added to them,

According to the Spirit which I have

Poured out for them...



Says The Lord YahuShua.`}]},{id:"mature-faith",num:25,title:"Mature Faith",paragraphs:[{align:"center",text:`Blessed are those who answer, \u201CYes, Lord,\u201D

For their faith is revealed.`},{align:"center",text:`Blessed are those who pray, \u201CYour will be done, Lord,\u201D

For they have great trust.`},{align:"center",text:`Blessed are those who say, \u201CAmen, Lord,\u201D

At all times and in every season,

For they have understood.`},{align:"center",text:`Blessed are those who know, I AM WHO I AM;

They shall have peace...



Says The Lord.`}]},{id:"blessed-is-the-name-of-the-lord",num:26,title:"Blessed Is The Name of The Lord",paragraphs:[{align:"center",text:`By My name is your heart sealed;

For in My name is the Spirit given,

The Spirit which also testifies of My name.`},{align:"center",text:`By My name are you established in life,

As a bride prepared for her husband.`},{align:"center",text:`Therefore, everyone who refuses

To take My name shall not see life,

For there is but One Way into life...`},{align:"center",text:"I am The Way, says The Lord YahuShua."}]},{id:"sabbath-peace",num:27,title:"Sabbath Peace",paragraphs:[{align:"center",text:`On the Sabbath,

Let no unclean thing come from your mouth;

Let only praise and beauty come forth.`},{align:"center",text:`Let My grace be your covering,

Let gentleness and humility be your companion.`},{align:"center",text:`And soon you will wear a crown of glory

Atop your head,
says The Lord YahuShua.`}]},{id:"two-robes",num:28,title:"Two Robes",paragraphs:[{align:"justify",text:"Can one wear two robes without constraint? Or can one place one robe over another, and it not tear? Is it wise to put on one robe, while wearing another already? And shall one attempt to wear a robe of white, to conceal a soiled one beneath? Will they not both become unclean?"},{align:"center",text:`Therefore, take off the one

Which is soiled and cast it away!

That the other may be worn properly

And without constraint...`},{align:"center",text:`Lest it tear, revealing your shame...



Says The Lord YahuShua.`}]},{id:"healing-by-faith",num:29,title:"Healing by Faith",paragraphs:[{align:"justify",text:"Faith is believing I AM WHO I AM, and that I am able to perform it. Faith can by no means be attained, nor can one grab hold of it by human means."},{align:"justify",text:`For there are works done without faith, which are dead; and a faith which has works, which is also dead. Yet your faith came by My works, which enabled you to believe I AM WHO I AM. And all good works, which come forth from you, are My works also.

Therefore if one is to be healed in accordance with My will, that same one must surrender to Me and My will, making no effort to increase their faith by human power as a means to a desired end.`},{align:"center",text:"Rather they acquiesce..."},{align:"center",text:`Knowing that all things will be done

In their proper time and season,

According to the love

Of their Father in Heaven...`},{align:"center",text:"Doubting nothing..."},{align:"center",text:"Says The Lord."}]},{id:"revelation-is-greater-than-knowledge",num:30,title:"Revelation Is Greater Than Knowledge",paragraphs:[{align:"justify",text:"While praying about those who have discounted The Lord\u2019s words in The Volumes of Truth, those who think they have attained such great knowledge, The Lord spoke and said..."},{align:"center",text:`The knowledge they possess is earthly,

But I am Heavenly!`},{align:"center",text:`What they have received is from below,

But I am from above!`},{align:"center",text:`All they know is passing away,

Yet I abide forever!`},{align:"center",text:`They dwell in the darkness, even now,

And remain void of understanding,

Yet I AM HE who dwells

In the unapproachable light!...



Says The Lord YahuShua.`}]},{id:"the-companion-of-fools",num:31,title:"The Companion of Fools",paragraphs:[{align:"center",text:"Unrighteous jealousy is the companion of fools."},{align:"center",text:`For those who envy also grab hold of jealousy,

Walking hand in hand with covetousness.`}]},{id:"deliverance",num:32,title:"Deliverance",paragraphs:[{align:"center",text:`Blessed are those who run to Me,

For they shall be blessed in My presence.`},{align:"center",text:`Even more blessed are those

Who run to Me, then obey My Word,

For their blessing is complete

And they are at peace...`},{align:"center",text:"Deliverance they shall surely know, says The Lord."}]},{id:"trust-obey-and-love",num:33,title:"Trust, Obey and Love",paragraphs:[{align:"center",text:`Trust with abandonment,

Obey without expectation,

And love without condition.`},{align:"center",text:`For in this shall you truly know Me,

With your faith progressing

Quickly toward perfection...



Says The Lord.`}]},{id:"who-you-are",num:34,title:"Who You Are",paragraphs:[{align:"center",text:`Who you are at home reveals

The person you remain.`},{align:"center",text:`Therefore, do not be as the hypocrite

Who has two faces, for I see all your doings,

I know your heart.`},{align:"center",text:`For by a man\u2019s actions is his heart revealed,

And by his mouth is he defined before others...



Says The Lord YahuShua.`}]},{id:"who-you-choose",num:35,title:"Who You Choose",paragraphs:[{align:"center",text:"Here is wisdom:"},{align:"center",text:`Who you choose, not what

You choose, is the answer;

For who you choose defines what you do.`},{align:"center",text:`And whosoever chooses another,

And not Me in truth, has chosen themselves,

And has done according to their own will...



Says The Lord YahuShua.`}]},{id:"embracing-the-gift",num:36,title:"Embracing The Gift",paragraphs:[{align:"center",text:`The Holy Days are the

Stepping stones to Heaven...`},{align:"center",text:`In understanding their meaning shall you

Progress quickly along the path I have laid...`},{align:"center",text:`And when I have fulfilled them to the last

The journey shall be complete,

For those who have accepted and received...



Says The Lord YahuShua.`}]},{id:"notoriety",num:37,title:"Notoriety",paragraphs:[{align:"center",text:`Notoriety is a stumbling block at the

Feet of the prideful, and fame puffs up;

Pride goes before a fall, and fame is short-lived;

Lo, a famous man is honored

More in his death than in his life.`},{align:"center",text:`Yet what does it profit?

For the meek shall inherit the earth.`}]},{id:"forbidden-fruit",num:38,title:"Forbidden Fruit",paragraphs:[{align:"center",text:`If the love of money is the root of all kinds of evil,

Then pride is the tree and notoriety its branches;

Death shall be the reward

Of all those who eat from it...`},{align:"center",text:`Yea darkness is reserved for all those

Who take shelter in its shade.`}]},{id:"evident",num:39,title:"Evident",paragraphs:[{align:"center",text:`If wisdom is justified by her children,

Then the folly of fools is evident

And the way of the wicked is death.`},{align:"center",text:`Yet the humility of the meek shall hide them

In the Day of The Lord\u2019s Anger.`}]},{id:"the-meek-and-the-foolish",num:40,title:"The Meek and the Foolish",paragraphs:[{align:"center",text:`The wise are quiet and know when to speak,

And the humble are barely noticed.`},{align:"center",text:`Yet the prideful announce themselves as with a trumpet,

And the plight of the slothful is made plain by their complaint.`}]},{id:"walking-in-the-word",num:41,title:"Walking in The Word",paragraphs:[{align:"center",text:`Rejoice in the wisdom of The Lord,

And find joy in His correction.`},{align:"center",text:`For only those who have received

Of the Spirit of Truth are able to see,

And only those who love The Truth

Are able to hear.`},{align:"center",text:`Yet only those who embrace

The Messiah fully, who also write

His words upon their hearts, will do them;

And peace, the kind of which only The Lord

Can give, shall be their companion.`}]},{id:"narrow-is-the-way",num:42,title:"Narrow Is The Way",paragraphs:[{align:"justify",text:`Very narrow is the way, yet look how easily a little child passes through...


Men and women of this world, you stand too tall, your girth is too wide. Lose this height therefore and bow down, for you are puffed up; as fatted cattle you have become meet for the slaughter. Therefore, refuse all this rotten food fed to the masses, and eat no more from the filthy plates served in the churches of men. Rather partake of the food I give you, and be satisfied. For I tell you the truth, until you decrease in the world\u2019s eyes, and are humbled in your own, you shall by no means pass through. For the first harvest shall be lowly, of the lowly, says The Lord.`}]},{id:"due-reward",num:43,title:"Due Reward",paragraphs:[{align:"justify",text:"The high man stands proud, and the man of low degree is tread down! The eyes of The Lord have seen it, the ears of The Lord have heard it! Therefore shall the error of the proud be exposed, and the look of the lofty be brought low! For the span of My holy mountain is great, filling the breadth of the whole earth; the weight of the stone, infinite! And woe to those who are crushed beneath it! Says The Lord of Hosts."},{align:"center",text:`Yet the man of low degree shall arise,

And the humble sleeper shall awake from his slumber.`},{align:"center",text:`They together shall inherit the land,

They together shall live in the top of The Mountain!`},{align:"center",text:`And the broken shall receive healing atop The Stone...



Says The Lord.`}]},{id:"wonderful",num:44,title:"Wonderful",paragraphs:[{align:"justify",text:`The power of The Lord is without end! His love covers His creation like a blanket, and the light of His glory reaches beyond the stars of heaven! His majesty is beyond comprehension; it transcends space and time! The Everlasting is His name!

The express image of The Holy is revealed, He is known of His own! His glory shines from the east even unto the west, The Sh\u2019khinah of The Father\u2019s only Son!

WONDERFUL is His name! WONDERFUL are His ways! He wears TRUTH as a garment, and GLORY is His vesture, and LOVE is His crowning glory! All life proceeds from Him; He holds all things together by the Word of His power!`},{align:"center",text:`His way is from everlasting,

And with His mouth He testifies

To the Truth, always!`},{align:"center",text:`Therefore, let us testify also;

The Father and The Son are One! ONE!...



YAHUSHUA-YAHUWAH!`}]},{id:"glad-service",num:45,title:"Glad Service",paragraphs:[{align:"center",text:`A right heart brings forth glad service,

And a joyful giver reaps what he sows;

Life in abundance shall be his reward.`},{align:"center",text:`Yet the heart of the wicked seeks his own way;

And he too shall reap according

To that which he has sown,

Welcoming death when it comes.`}]},{id:"building-the-gallows",num:46,title:"Building the Gallows",paragraphs:[{align:"center",text:`Vanity is a rope, and pride builds the gallows;

Envy leads to hate, and jealousy

Brings forth evil thoughts.`},{align:"center",text:`Therefore, beware of the thoughts of your heart,

Lest you follow in Haman\u2019s error {{nav:esther:7}}

And walk in the way of Cain, {{ref:1 John 3:12}} \xB7 {{ref:Genesis 4:8}}

To your own demise, says The Lord.`}]},{id:"walking-together-in-the-father-s-joy",num:47,title:"Walking Together in The Father\u2019s Joy",paragraphs:[{align:"justify",text:`Blessed is the man who gives out of the abundance of his heart. For one such as this gives, knowing in his heart that all he has is Mine and all I have is his, given and received according to the knowledge of My will for those who believe. For this man knows what it is to be My servant. He is bound by nothing, a man who walks free in all the earth, blessing the name of The Lord his God with enduring trust.

Therefore those who give out of obligation know not the joy of The Lord, nor of the freedom which comes by service, helping others in My name.`},{align:"center",text:`Yet the servant whose heart leaps with joy

At the thought of washing the feet of the poor,

Who also eagerly seeks out the afflicted,

To give them comfort, knows that whatsoever

They do for another they have also done for Me.`},{align:"center",text:"For these know Me, and I live in them."},{align:"center",text:`And together we shall walk,

Choosing the good and refusing the evil,

Until we walk together anew in My kingdom...



Says The Lord.`}]},{id:"reconciliation-in-marriage",num:48,title:"Reconciliation in Marriage",paragraphs:[{align:"center",text:`An unyielding heart sows discord in marriage,

And stubbornness shuts the door to reconciliation.`},{align:"center",text:`Yet the one who is first to say,

\u201CI\u2019m sorry\u201D is wise, defusing any argument;

And the one who is quick to forgive

Heals the breach.`}]},{id:"surrender",num:49,title:"Surrender",paragraphs:[{align:"center",text:`The unbroken remain proud,

And fools speak assertions

Without knowledge; they are bound.`},{align:"center",text:`Yet the one who holds their tongue is wise,

And the one who surrenders all

Shall gain The Victory.`}]},{id:"ears-to-hear",num:50,title:"Ears to Hear",paragraphs:[{align:"justify",text:`A willing, humble heart is open to Me, and one who is deeply in love with Me will hear My voice. Yet this is not equal, nor shall every servant hear My voice in the same way.

Hear and understand: I have spoken to My prophets throughout the generations (for I change not), and each was given that which was required to accomplish My will among the people. Therefore rejoice, My sons and daughters, for The Most High has come down to you! And behold, I have caused My servants to hear, to receive wisdom by the power of My own spirit!`},{align:"center",text:`Lo, by the Word of My mouth
shall My beloved be blessed,

The prideful humbled and the haughty abased.`},{align:"center",text:`For the Word of The Lord never returns void...



Says The Lord.`}]},{id:"a-waving-banner",num:51,title:"A Waving Banner",paragraphs:[{align:"justify",text:"To the unbeliever, My Word, no matter its color or brilliance, shall be as gray clouds on a dark and dreary day. And to those pricked in their hearts, it shall be to them as an after image which ceases not from before their eyes, as a flash of lightning remains in the eyes of the one who beheld it even after they have shut their eyes to it."},{align:"center",text:`Yet to the believer My words are cause

For celebration, a time to stop and pay attention,

For the mouth of The Living God has spoken!`},{align:"center",text:`Both the color and brilliance they recognize,

For their eyes are wide open.`},{align:"center",text:`For them, The Source and The Author is clear,

For they see with the heart and not with the mind...



Says The Lord.`}]},{id:"believing-without-seeing",num:52,title:"Believing without Seeing",paragraphs:[{align:"justify",text:"Look not outwardly for that which can only be discerned from within, and search not in the world for that which is not of this world, for I have already come... _I dwell within the hearts of men! And My spirit testifies on My behalf!_"},{align:"center",text:`Therefore, let the hungry come to Me and eat!

Let the thirsty rush to My side and drink!`},{align:"center",text:`And let those who seek Me turn not their heads;

Let them be still and listen for My voice...



Says The Lord, Your Life.`}]},{id:"freedom",num:53,title:"Freedom",paragraphs:[{align:"center",text:`Demand nothing of Me,

And I shall give you everything.`},{align:"center",text:`Demand everything of yourself, and I will

Take it from you, and you shall be set free...



Says The Lord YahuShua.`}]},{id:"treading-water",num:54,title:"Treading Water",paragraphs:[{align:"justify",text:"The servant who doubts is like a man who is tossed about on the waves of the sea. He is useless, spending all of his time trying to stay afloat, consumed with keeping his head above water."},{align:"center",text:`Yet the man whose trust does not waver

Fears not the boisterous winds,

Nor do the billowing waves trouble him.`},{align:"center",text:`For he takes My hand, and together
We shall walk, upon the water...



Says The Lord YahuShua.`}]},{id:"bearing-fruit-in-due-season",num:55,title:"Bearing Fruit in Due Season",paragraphs:[{align:"justify",text:"Though men speak evil of you and others depart before the time, while still others question your sanity, I tell you, My words shall bear much fruit in due season. Yet the wicked will not understand, and the lukewarm will forsake them, and the worldly will seek to bind them and place them in a corner."},{align:"center",text:`Yet those who are wise will understand,

And in them shall a flame arise,

In them shall My words be written;

Behold, they shall bear fruit

In accordance with My likeness!`},{align:"center",text:`For they were bound to Me from

The beginning, and did not waver...



Says The Lord your Redeemer.`}]},{id:"the-devoted-servant",num:56,title:"The Devoted Servant",paragraphs:[{align:"center",text:`What is the least thing done in service toward Me,
Compared with that which My servant

Wishes to do most for himself?



Yet the servant who is truly devoted

To Me puts no difference between them;

In his eyes they are one and the same;

In his heart the former fulfills the latter.



For have I not said,
\u201CA right heart brings forth glad service\u201D?...



Says The Lord.`}]},{id:"impaired-vision",num:57,title:"Impaired Vision",paragraphs:[{align:"justify",text:"I saw a star fall from Heaven, while the sons of men laughed. For they have no vision, neither are they able to see beyond that which is in front of them. And even this they deny, for they love deception and the truth is not at all convenient."},{align:"center",text:`Yet the sons of God hold their tongues,

And open not their mouths.`},{align:"center",text:`As tears run down their faces,

They look upon creation with new eyes

And restored vision, embracing The Promise,

Abiding in The Hope of Salvation...



Says The Lord.`}]},{id:"the-holy-flame",num:58,title:"The Holy Flame",paragraphs:[{align:"justify",text:`Hear and seek to understand: The Word of God is fire, each word a burning flame in the midst of an immense fire. The countenance of The Lord is a fire, and a flame within a fire. The glory of The Lord is perfect, a pure light, a flame within a flame, a fire engulfing all creation!

YAHUWAH is One, and His name, One; His name is in Him and is Him. YAHUWAH is His name, and His name is One with Him. They are not separate, but one, even as The Father and The Son are One - a flame within a flame, within an immense fire.

YAHUWAH has no beginning and no end, even as His name. Therefore nothing is outside YAHUWAH, for His being is infinite. And those who pass outside creation enter into His eternal glory, or are burned up in His devouring fire, in His everlasting flame.

Therefore no one may come to The Father except through The Son, YAHUSHUA, The Purifying Flame. For only The Holy Flame may dwell within The Fire, for YAH is holy. And all those void of The Flame will consume away; they shall cease to exist. For ALL must pass through the fire, ALL are subject to the power of The Flame - the wicked purged, and the penitent purified.`}]},{id:"more",num:59,title:"More",paragraphs:[{align:"center",text:`I have seen the sun rise upon the mountains of Israel, I have seen the light of the moon illuminate the valleys of Judah, I have even seen the stars fall from the heavens! Yet never have I seen a wonder such as this, never have I beheld such a wondrous thing!

I have seen a brilliant light, a perfect likeness! Behold, I have stepped into the fire! Yet instead of burning, I received understanding; and in place of my wounds, I received healing in this flame!

What a wondrous and beautiful place! Such overwhelming, pure love in the light of His glory, consuming me where I stand, strengthening me as I fall down, my tears flowing as my life departs from me! Yet I do not die. Rather the presence of The Lord of Hosts rises up in me!

Is this Heaven? Yes! It is The Kingdom! For before me is the likeness of a Man, bright and shining! He is beckoning me! I see the holes in His hands and in His feet, as I am pulled toward His open arms!`},{align:"center",text:`I am losing myself,

Yet I feel as though I am being born!

I was dead, and now I am alive again,

The man I was passing away as His life rushes in!`},{align:"center",text:`And what more can I say?

What more shall I ask of Him?...`},{align:"center",text:"Only this: MORE!"}]},{id:"the-selfless-servant",num:60,title:"The Selfless Servant",paragraphs:[{align:"justify",text:`The selfless servant shall be filled and put to use in all the earth, dwelling always in the inner courts of My love, where grace and truth flow as a river which never runs dry, partaking of My glory, bearing fruit in kind. For he who dwells in the secret place of The Most High abides in the shadow of The Almighty, and from this servant nothing is withheld.

Lo, within him are written The Commandments of God, and engraven upon his heart is the name of love and pure righteousness. In his mind\u2019s eye he sees the holy sacrifice, the salvation of many. With his lips he sings the song of The Lamb, and with his mouth he testifies to the glory of The Lord, without ceasing.


For great is YAHUWAH his God, and holy is The One who is poured out! For the mouths of the pure in heart are open, and He shall surely fill them up, even as a welcomed rain in the height of summer, says The Lord.`}]},{id:"made-whole",num:61,title:"Made Whole",paragraphs:[{align:"center",text:"This is wisdom: I AM HE!"},{align:"center",text:`And this is understanding:

I abide forever! All healing is in Me!`},{align:"center",text:`Therefore everyone who comes to Me is made whole,

And everyone who lives in Me shall abide forever...



Says The Lord.`}]},{id:"eternal-fire",num:62,title:"Eternal Fire",paragraphs:[{align:"center",text:`The Lord our God has kindled a fire;

His heart is set ablaze over His beloved!



Thus all who willingly pass through

The Flame shall be purified,

Refined and restored in the image

In which He created them.`},{align:"center",text:`Yet the wicked shall never be established;

Their places shall be removed,

Burned up, utterly consumed!`},{align:"center",text:`For The Lord our God is a consuming fire,

The Purifying Flame!`}]},{id:"the-sower-and-the-reaper",num:63,title:"The Sower and The Reaper",paragraphs:[{align:"justify",text:"Such troubled children, always divided. None have learned to walk, not one truly knows Me. Yea, darkness is overhead, and many have fallen back to sleep. In the height of summer they withered, under the heat of the noonday sun they became faint and fell down. And now the time of the harvest is here, relief is very near, yet who opens their eyes to look upon Me?"},{align:"center",text:"Who stands up and bears their burden gladly?..."},{align:"center",text:`That all might eat and rejoice in their labors,

That all might rejoice and give thanks together

For the bounty which I have provided...`},{align:"center",text:`Looking to the day when the plowman overtakes the reaper,

And the treader of grapes Him who sows seed... {{ref:Amos 9:13}}



Says The Lord.`}]},{id:"the-salvation-day",num:64,title:"The Salvation Day",paragraphs:[{align:"center",text:"The Salvation Day of Men is four-fold:"},{align:"center",text:`It was ordained before the foundation

Of the world, fulfilled at My birth,

Finished at My death on the cross,

And solidified eternally upon My resurrection...



Says The Lord YahuShua.`}]},{id:"the-truth-endures-forever",num:65,title:"The Truth Endures Forever",paragraphs:[{align:"center",text:`The power of a lie is only as strong as those who believe it;

Yet The Truth will set you free.`},{align:"center",text:`All lies are born of the evil one and shall perish;

Yet The Truth endures forever.`}]},{id:"anathema",num:66,title:"Anathema",paragraphs:[{align:"justify",text:"_Thus says The Lord:_ As it is written, My people are destroyed for lack of knowledge! And because they have rejected knowledge, I must also reject them! {{ref:Hosea 4:6}}_... In all their forsaking of Me are they taken away! On account of their pride they reject Me, and in their arrogance do they hold fast to their own way, treading the wide path! Therefore are the walls of Jerusalem broken down! Thus is the vineyard of The Lord tread down! Behold, the vats overflow, every vessel is tipped, all new wine evaporates in the fire! And still, My people are not saved!_"}]},{id:"the-redeemer",num:67,title:"The Redeemer",paragraphs:[{align:"center",text:`Behold, I had come,

The Son who was completely blameless,

To bear the guilt of all The Father\u2019s children...`},{align:"center",text:`The Just for the unjust;

The Innocent for the guilty;

The Son of Man for the sons of men...



Says The Lord YahuShua.`}]},{id:"letting-go",num:68,title:"Letting Go",paragraphs:[{align:"center",text:"Here is wisdom:"},{align:"center",text:`For one to depart this world

They must first depart in spirit,

Willingly forsaking their life in this world,

Fully embracing Mine...`},{align:"center",text:`Coming to Me free,

Without any form of malice

In their heart toward another...`},{align:"center",text:"Then shall they be taken, says The Lord."}]},{id:"true-fellowship",num:69,title:"True Fellowship",paragraphs:[{align:"center",text:`True fellowship comes not by words

Spoken amongst a group of united people.`},{align:"center",text:`Rather it starts with the heart,

And is found in the stillness of My spirit,

Where My peace mends the broken

And My gentle caress gladdens the heart.`},{align:"center",text:`For all those found at the feet of The Lord

Are covered with grace,

And those who abide in My love

Are indeed of one accord...



Says The Lord.`}]},{id:"walk-humbly-with-your-god",num:70,title:"Walk Humbly with Your God",paragraphs:[{align:"justify",text:"Hear and understand: The moment pride enters a man, and the moment he stands in front of Me to look elsewhere, is the same moment My hand is removed. For I have shown you, My servants, what is good and that which I require: _That you should do justly, love mercy, and walk humbly with your God. {{ref:Micah 6:8}}_"},{align:"center",text:`Yet how can one behold My face while

Looking elsewhere, seeking glory for themselves?`},{align:"center",text:`And how can one who has stepped

In front of Me walk in My footsteps?`},{align:"center",text:`Beloved, how shall one who runs away from Me,

To tread another path, take My hand?...



Says The Lord.`}]},{id:"faith",num:71,title:"Faith",paragraphs:[{align:"justify",text:"When My servant no longer seeks to see with his eyes, nor hear with his ears, the fulfillment of those things written, then he will know his faith is near to completion, says The Lord. For one who must see with his eyes lacks trust, and one who has itching ears lacks understanding."},{align:"center",text:`Yet the servant who truly believes is no longer
Bound by the need for confirmation;

He seeks not after signs, nor does

He sit idle waiting for the news.`},{align:"center",text:`For his trust is complete, his understanding full,

And he is at peace, walking in the ways of The Lord.`}]},{id:"walking-free",num:72,title:"Walking Free",paragraphs:[{align:"center",text:`One who bears their own burdens

Must also bear the heat of the day.`},{align:"center",text:`Yet one who lets go, cutting every cord that

Binds them to this world, walks free,

And shall be given eagle\u2019s wings...



Says The Lord.`}]},{id:"antidote",num:73,title:"Antidote",paragraphs:[{align:"center",text:`Judging another man\u2019s servant poisons the heart

And corrupts every good intention.`},{align:"center",text:`Yet judging one\u2019s own judgment,

Taking every thought captive,

Renders this poison neutral and of no effect...


Righteous discernment according to

That which the Spirit reveals, says The Lord.`}]},{id:"idle-hands",num:74,title:"Idle Hands",paragraphs:[{align:"center",text:`Idle hands lack bread, and an idle heart lacks trust;

Their backs are bent down always, their countenances fallen,

Their eyelids have grown very heavy.`},{align:"center",text:`Yet love strengthens the spirit, and washing another\u2019s feet

Is good for the soul, renewing the whole of the body...



Says The Lord.`}]},{id:"i-remain-always",num:75,title:"I Remain Always",paragraphs:[{align:"center",text:`I remain always The Good Teacher,

Who continually reminds His students

Of that which He has taught them

Before they lose sight of The Goal.`},{align:"center",text:`I remain also The Faithful Shepherd,

Who calls to His sheep before they

Have wandered too far...`},{align:"center",text:`The Wise and Loving Father,

Who makes the sins of His beloved

Known early, while they are still able

To step easily off the crooked path...



Says The Lord YahuShua.`}]},{id:"elect-and-precious",num:76,title:"Elect and Precious",paragraphs:[{align:"center",text:`You are more than the filth that covers you,

More than the sin that fills you,

Much more than the choices you make;

For I see your beauty, I know your heart

And the love which you have for Me.



Behold, I know you as you are and will be, with Me where I am.



You are not that which you choose in a moment of weakness;

You are that which I have created, and will become

That which I restore, and will remain always

A beautiful, finished work, elect and precious,

My everlasting treasure, even as I shall be yours also.



For I know My own, says The Lord.`}]},{id:"grace-and-the-moral-law",num:77,title:"Grace AND The Moral Law",paragraphs:[{align:"justify",text:`Hear and understand: Salvation can in no wise depart from you, once received. Therefore, seek to please The Father AND keep The Law.

For how can one who walks in Me by grace also walk in that which had condemned them? Shall My people reach toward Heaven with their hands, while their feet continue to tread the wide path which leads to destruction? And how shall one who loves Me take My hand and walk beside Me, with one foot on the good ground and the other in the grave?

Therefore knowledge must increase, and sin decrease, to enter The Kingdom of Heaven. For one who is under grace bears fruit of the same; and The One who kept The Law of The Father revealed that grace by works.`},{align:"center",text:"So then, Grace is first and everlasting."},{align:"center",text:`Then comes works, the first works done in faith,

Even the first fruits bore in your lives...`},{align:"center",text:`Which is to love The Father and one another,

By keeping The Law, says The Lord.`}]},{id:"a-desirable-union",num:78,title:"A Desirable Union",paragraphs:[{align:"justify",text:`_Thus says The Lord to those who seek Him:_ Do you abide in Me? Have you received of that which I offer? For until one has stilled their heart and quieted the thoughts of their mind, they shall by no means hear that which the Spirit speaks. How then shall they walk in My will, if they are unable to discern?

Yet everyone who looks for Me, with all their heart and with all their soul, shall surely find Me! And everyone who seeks My will, in all trust, shall know it! And in the secret place of My presence shall we break bread together, set apart from the many plots of the evil one, away from the noise of this world.`},{align:"center",text:`For this is where quiet understanding abounds

And the will of The Lord is made plain...`},{align:"center",text:`Where the broken receive peace and every

Sin is absolved in My healing embrace;

Where the heart of every son rests

Securely in the hands of his Father,

And where the hearts of My daughters are

Restored and shine anew in My likeness...`},{align:"center",text:`A desirable union, fulfilling every desire

Of the heart in My love, says The Lord.`}]},{id:"consider-my-love",num:79,title:"Consider My Love",paragraphs:[{align:"center",text:`Behold My hands and My feet, and consider My love;

For the scars of My passion remain,

A holy, everlasting covenant

Written in the blood of The Lamb.`},{align:"center",text:`Taste and see, beloved, drink!

Until that which is veiled is veiled no longer,

Until the void within your heart is filled.`},{align:"center",text:`For My love was written in every stripe I endured for you,

Poured out in every drop of blood I shed for you,

Revealed when you pierced My hands and My feet.`},{align:"center",text:"Beloved, I am married unto you!..."},{align:"center",text:`A union sealed forever in the blood we share...



Says The Lord YahuShua.`}]},{id:"a-man-of-god",num:80,title:"A Man of God",paragraphs:[{align:"center",text:`A man of God is humble and quiet

Until called upon to speak,

A man of low degree who treads softly

Until called upon to act...`},{align:"center",text:`A lowly man who is completely in love with Me,

Who does not his own will nor seek his own way...`},{align:"center",text:`A man who waits upon The Lord,

And hesitates not when the command

Comes down from the mouth of The Lord his God...`},{align:"center",text:`A man after My own heart, My servant, My friend...



Says The Lord.`}]},{id:"the-reward",num:81,title:"The Reward",paragraphs:[{align:"justify",text:"He who trusts in The Lord shall receive healing wings and soar high above the storm! At the call of The Most High, he shall ascend the heights of the heavens with The Lord beside him! Yea, Beauty shall be his dwelling place, and in the sanctuary of God\u2019s mercy shall he worship He who sits on the throne! In one accord and with one spirit shall all praise The God of Jacob, sharing in the depths of Mashiach, as love flows from one heart to another! For YAHUWAH is God alone, He who laid the foundations of the earth, The One who is and was and is to come, The Almighty! YAHUSHUA-YAHUWAH!"},{align:"center",text:"Blessed, therefore, are all those who escape!"},{align:"center",text:`For they have called upon the name

Of The Lord, in sincerity and in truth,

And have given up everything to follow Him.`},{align:"center",text:"Indeed, they have received their reward."}]},{id:"love-has-saved-them",num:82,title:"Love Has Saved Them",paragraphs:[{align:"center",text:`Those who were full shall be left empty,

So they may be truly filled up, and those

Who were thought of as first shall be last.`},{align:"center",text:`Yet those who were forsaken as last

Shall be first partakers of The Glory.




And those without knowledge shall be given

Great knowledge, for Love has saved them.`},{align:"center",text:`Yet those who had attained great knowledge

Shall be brought down to shame, so they too

May be glorified in My presence,

For Love has saved them...



Says The Lord.`}]},{id:"offering-a-gift",num:83,title:"Offering a Gift",paragraphs:[{align:"center",text:`A gift demanded is no gift at all;

And anyone forced to receive a gift

Never truly receives it.`},{align:"center",text:`Thus when offering a gift,

One does not demand its acceptance,

Lest the gift be polluted and a division occur,

Causing both to depart offended...



Says The Lord.`}]},{id:"accepting-the-gift",num:84,title:"Accepting The Gift",paragraphs:[{align:"center",text:`What is life without love?

And what is love without the

Free will to choose love?`},{align:"center",text:`I tell you the truth,

A gift commanded is no gift at all!`},{align:"center",text:`Yet a gift accepted is where you

Shall find life, love and salvation...



Says The Lord.`}]},{id:"who-do-you-serve",num:85,title:"Who Do You Serve?",paragraphs:[{align:"center",text:"No servant is greater than his master..."},{align:"center",text:`How he serves others shows the master he serves;

How he serves his master reveals the master within him;

And what the master suffers will his servant suffer also,

For he serves in his name.




No one can serve two masters...`},{align:"center",text:`Either he will hate the one and love the other,

Or he will be devoted to the one and despise the other {{ref:Matthew 6:24}}...



Says The Lord.`}]},{id:"embracing-the-call-of-the-lord",num:86,title:"Embracing the Call of The Lord",paragraphs:[{align:"justify",text:`There is no greater love than to lay down your life for another, and blessed is the one who embraces the calling of The Lord wholeheartedly. For a servant such as this lays down his life each day, bearing his cross after Me. Upon waking he kneels down at the feet of The Lord, with an open heart and open hands. And in this servant My soul delights.

For the servants of The Most High uphold My cause. And as My love is poured out, it fills the hearts of the penitent, even as My stern correction and harsh discipline comes swiftly upon the defiant. For My ways are not human ways. For I do what is right by My children, doing that which is most needful for each one, that they may come to Me in their due season. I AM THE LORD.`}]},{id:"blowing-the-trumpet",num:87,title:"Blowing The Trumpet",paragraphs:[{align:"center",text:`My servants, to warn your brothers and sisters,

Even to your neighbors and countrymen,

Whether they will hear or whether

They will forbear, is LOVE.`},{align:"center",text:`For only an evil man would fail to warn his fellows,

When he had knowledge of coming calamity.`},{align:"center",text:`And only a wicked man meet for death would save himself,

While forsaking those nearby to the sword...



Says The Lord.`}]},{id:"a-pillar-of-strength",num:88,title:"A Pillar of Strength",paragraphs:[{align:"justify",text:"My forgiveness runs far and wide, entering deep into the hearts of those who come to Me in sincere repentance. Yet many of My sheep believe themselves to be above reproach, and in this do they greatly err. Therefore let all My beloved grow wise in Me, and learn also to walk in My ways. For I am a pillar of strength to those of low degree! I uphold the powerless and steady the weary, as I renew the hearts of My elect!"},{align:"center",text:`Behold, I fill all those who come to Me empty with

Spirit and grace, as they walk with Me into everlasting life!

Indeed, they shall experience life in abundance, forevermore!...`},{align:"center",text:`Life of such a kind, which is only found in Me and I am...



Says The Lord.`}]},{id:"without-condition",num:89,title:"Without Condition",paragraphs:[{align:"center",text:"Learn the lesson of obedience in The Lord."},{align:"center",text:`For obedience is far greater than

Witnessing a prophecy come to pass,

And much greater than receiving healing

By a miracle, for obedience is born of love.`},{align:"center",text:`For those who have no trust seek after signs,

And those who remain in unbelief wait for miracles.`},{align:"center",text:`Yet only those who love Me, without condition,

Will remain faithful, and only those who truly

Know Me will endure in times of trouble...



Says The Lord.`}]},{id:"rejoicing-over-my-sons-and-daughters",num:90,title:"Rejoicing Over My Sons and Daughters",paragraphs:[{align:"justify",text:`My glory is revealed in the lives of all My children, no matter what path they had chosen, no matter how they have tread. I know My own, and I know when each will come to Me and how each shall come to walk in Me. And by this I am glorified, even as each shall also share in My glory.

For to one, it is as the son who remained faithful to his father, and never lost his inheritance, but kept it close his whole life. Yet to the other, it is as the prodigal son {{ref:Luke 15:11-32}} who went out and wasted his inheritance in the world, yet was met with much rejoicing when he returned home. For the one who was faithful remained in his father\u2019s love, and was rejoiced over his whole life; and the other returned to his father\u2019s love, and was met with much rejoicing. Yet both shall dwell in the house of their Father together, from that day onward, sharing equally in all he had laid up in store for them, forever.`},{align:"center",text:`Thus by one I am glorified in their walk,

And by another in their return.



I AM THE LORD.`}]},{id:"pure-love",num:91,title:"Pure Love",paragraphs:[{align:"justify",text:`The love of man is born from the desires of the flesh and comes forth from a place of longing, to fill a void which remains empty; affections built upon conditions and unrealistic expectations, learned in a world without natural affection - corrupt.

Yet My love is a light which shines in a dark place, warmth which brings peace and healing to those whose hearts have grown cold; a cup overflowing, never-ending, affection in its purest form - unconditional.`},{align:"justify",text:"Therefore come to Me, beloved, that our hearts may be satisfied! For all those who sincerely long for Me shall surely receive of Me, and all those who obey My voice shall surely walk beside Me, and all those who love Me, above all else, shall know the depths of My Mercy. For I shall take them, and they shall dwell with Me, where I am, in The Kingdom of My joy, forever... Says The Lord."}]},{id:"trust-in-the-holy-one",num:92,title:"Trust in The Holy One",paragraphs:[{align:"justify",text:"The presence of The Almighty is a consuming fire, a purifying flame. The cloud of The Almighty is a covering for all who put their trust in Him. The Sanctuary of His peace is in His Holy One, and none shall fear who abide in Him. And though the terror of The Lord comes upon all nations, it shall not approach the penitent, nor shall the trembling of the humble continue without comfort. For The Lord God has a Holy One, and in Him is the loving mercy of God revealed. In His bosom are healing tears and laughter, joy beyond compare, the fullness of love, life without end."},{align:"center",text:`Behold, The Lord has come down to look upon

The rage of the nations, to search the hearts of men...



The Mighty One has come down to gather His own,

To take from among them the penitent,

Everyone of a contrite heart and humble spirit...


Those who do justly and love mercy,

Whose eyes long to look upon their King...


Those whose hands reach out for His healing touch,

Whose fingers know His wounds,

Whose lips have tasted of the divine gift,

Drinking from His cup, always.`}]},{id:"choose-me",num:93,title:"Choose Me",paragraphs:[{align:"center",text:"Behold, The Gift is given already!"},{align:"center",text:`Therefore, all those who come to Me, who love Me

With all their heart, with all their mind, with all their soul

And with all their strength, shall be blessed indeed!`},{align:"center",text:`For is it not written:

"Wisdom is justified by her children"? {{ref:Luke 7:35}}`},{align:"center",text:`Therefore, here is wisdom: CHOOSE ME!...



Says The Lord.`}]},{id:"trust-in-me",num:94,title:"Trust in Me",paragraphs:[{align:"center",text:"I am The First! Behold, I am also The Last!"},{align:"center",text:`Blessed therefore are all those who bow down before Me;

For in them shall the vision be made complete

And The Word established, even as it was

At the first and shall also be at the last.`},{align:"center",text:`Trust in Me therefore, for I AM HE!...



Says The Lord.`}]},{id:"breaking-through-the-barriers",num:95,title:"Breaking Through the Barriers",paragraphs:[{align:"center",text:`_Thus says The Lord:_ When tears well up, let them burst forth as a flood overflowing the dam; let them break through the barriers!


Yet understand this: Let not your tears turn to anger when shed over hurt, nor let resentment come forth, lest you strengthen the dam and build up the barriers, leading to rebellion against The Lord as you hold unforgiveness in your heart. Beloved, let your tears flow when the Spirit convicts you! Let them cleanse your eyes so you may see, as your heart is set free! And no more resist the cleansing of The Lord.`}]},{id:"whose-robes-do-you-wear",num:96,title:"Whose Robes Do You Wear?",paragraphs:[{align:"center",text:`Pay attention to the robes you wear,

And those which you seek to put on.`},{align:"center",text:`Rather be willing to come to The Lord naked,

That He may clothe you with that

Which He has prepared for you.`}]},{id:"treat-everyday-as-the-sabbath",num:97,title:"Treat Everyday as The Sabbath",paragraphs:[{align:"center",text:`Why do you depart from the Sabbath at sundown

And return to the ways of the world, welcoming in again

That which you shut the door to on the Sabbath?`},{align:"center",text:`Rather treat everyday as the Sabbath, and you will do well...



Says The Lord YahuShua.`}]},{id:"the-sound-of-my-love",num:98,title:"The Sound of My Love",paragraphs:[{align:"center",text:`I have laid My heart open before your eyes,

And into your ears I have spoken.`},{align:"center",text:`As a harpist playing soft music, beautiful music,

Plucking each string with delicate fingers,

I revealed the song of My heart to you.`},{align:"center",text:`With precise strokes, in gentle tones of healing,

With many notes of unending love

And by soothing vibrations of peace,

Did the sound of My love speak.`},{align:"center",text:`And I, even I, The Lord of Hosts, did not withhold from you...



Says The Lord YahuShua.`}]},{id:"eternity-with-the-lord",num:99,title:"Eternity with The Lord",paragraphs:[{align:"justify",text:`Who are these I have made? And what man have I brought forth from the dust of the earth, that I might share My glory with him? There are none worthy; not one formed from the dust of the earth who knows Me; not one who is righteous, no, not one. All lie down in death, all return to the dust of the earth.


_Yet I came down to you in the image in which I formed you, so you might receive of Me and have life, that you might share in My wisdom and find healing, great peace in My love... Exchanging your life for Mine...

That you might roam free in My creation, close to Me, at My side always, until your first days are called ancient and your latter days laughter... Years beyond number...

Thousands of years passing as the setting of the sun, millions of days passing by as a breeze caressing the face of the forever young... Each one remembered as yesterday, says The Lord YahuShua._`}]},{id:"drink-deeply-from-this-vine",num:100,title:"Drink Deeply from This Vine",paragraphs:[{align:"justify",text:"My children, seek My glory and look to My Righteousness, for The Kingdom of Heaven is at hand! Look into My eyes, open your ears to My voice, for the mouth of The Lord has spoken! Return to the first works; it is time to be consumed in your First Love!"},{align:"center",text:`Beloved, see the Word of The Lord,

Drink deeply from this vine!`},{align:"center",text:`Consider My Mercy and the name of Love,

That you may know Me as I truly am,

That we may be one!`},{align:"center",text:"Consider, for it is time, says The Lord."}]},{id:"a-sure-way",num:101,title:"A Sure Way",paragraphs:[{align:"center",text:`My words are pure,

A solid foundation beneath the feet

Of My beloved, a sure way for all who believe.`},{align:"center",text:`My words are a strong staff in the hand

Of all those who do them, and all who place

Their trust in Me will never falter...



Says The Lord.`}]},{id:"envy",num:102,title:"Envy",paragraphs:[{align:"justify",text:"Envy is a double-ended sword. One end is covetousness, piercing the heart of those who envy; the other is pride, piercing the heart of those being envied. Behold, envy is also a snare. For those who envy are held captive by covetousness, and those who are envied are easily ensnared by pride."},{align:"center",text:`Therefore repent, and place

All your trust in The Messiah.`},{align:"center",text:`Make Him your focus,

Your only desire, and He will keep

Your foot from being taken.`},{align:"center",text:"Indeed, He will preserve your life."}]},{id:"the-feasts-of-the-lord",num:103,title:"The Feasts of The Lord",paragraphs:[{align:"justify",text:"In these Seven is wisdom and understanding, the very mind of God. For the Holy Days are revelation, revealing hidden things kept secret since the world began - signposts of things to come, a foretaste of The Kingdom, a glimpse into the Glory of God even as the Scriptures, unfolding and coming to light as the will of God is manifest, says The Lord."},{align:"center",text:`Behold, four are fulfilled:

Salvation assured, sin and death overcome, the Spirit given.



Three are coming quickly:

Sin destroyed, evil bound, My seat taken, Judgment...



A new day, even one thousand years...



Then a short season, Consummation...



An everlasting day in The Lord!`}]},{id:"beyond-question",num:104,title:"Beyond Question",paragraphs:[{align:"justify",text:`The Lord is eternal; HE IS! He never ends! His love, His mercy, His justice, His majesty, His glory, His sorrow, all that He is endures forever!

Likewise His creation has no end, no boundaries! There are no limits to contain it, for it is as He is! HE IS THE CREATOR! - Everlasting, eternal, The Alpha and Omega, The Beginning and The End, The First and The Last by whom all things exist and have their being, through whom all living things have life!

Kiss The Son, therefore! Bow down heavily and give Him glory! Let the knowledge of who He is fill your heart with wonder and awe, with great reverence and worship! Give Him thanks and praise! For Holy is The Lord God Almighty, His ways past finding out! For who can understand the knowledge of The Lord contained within creation, or know the depths of His wisdom?! Yet His Glory surrounds us on every side, testifying to His majesty beyond question! Indeed, we are without excuse!`},{align:"center",text:`Behold, even the whole of creation shouts,

\u201CYAHUSHUA is YAHUWAH!\u201D`},{align:"center",text:`For it is He by whom all things consist,

It is He who causes to be!

For The Lord our God is One!`}]},{id:"the-song-of-the-lamb",num:105,title:"The Song of The Lamb",paragraphs:[{align:"justify",text:"Eat of Me, partake of My words, and be filled! Breathe Me in, that the song of The Lamb may dwell within you! For it is the knowledge of My love, the revelation of who I truly am! - A song, a chorus, soon to be a symphony, a great outpouring of revelation to the praise of My glory!"},{align:"center",text:`Beloved, it is also the music we share,

Sweet melodies of grace and peace

Playing softly within your heart,

Each string plucked gently and surely...`},{align:"center",text:`The sound of My love revealed

In you and through you...`},{align:"center",text:`My spirit, My breath,

My life given and received,

Bearing much fruit in The Beloved...



Says The Lord YahuShua.`}]},{id:"a-sure-foundation",num:106,title:"A Sure Foundation",paragraphs:[{align:"center",text:`Old houses stand upon old foundations,

And new houses upon new foundations;

A new house cannot be built atop another,

Nor does one build a new house

Upon an old foundation.`},{align:"center",text:`No, the old house must be torn down

And the old foundation removed,

Making room for the new foundation

To be poured, that the new house

May rest securely upon it...`},{align:"center",text:`Behold the house!

A house with a sure foundation, a house able

To withstand even the strongest of storms...



Says The Lord.`}]},{id:"integrity",num:107,title:"Integrity",paragraphs:[{align:"center",text:`Obedience is more than trust,

And trust much more than obedience.`},{align:"center",text:`For obedience by itself

Bears bitter fruit in the end,

And trust left alone becomes a lie...



Says The Lord.`}]},{id:"remembering-the-ascension-looking-to-the-blessed-hope",num:108,title:"Remembering the Ascension, Looking to the Blessed Hope",paragraphs:[{align:"justify",text:"That which was bitter shall be made sweet, and that which brought tears of sadness shall be turned to great rejoicing. For indeed The Bridegroom was taken from them, and has been a long time in coming. Yet those who have waited with all eagerness shall have their hope realized, and those who watched with steadfast trust shall not be put to shame; neither shall those who have fallen asleep be disappointed."},{align:"center",text:`For the Bride shall have her heart\u2019s desire,

And My prophets their due reward.`},{align:"center",text:`For all those who belong to Me have tasted,

And behold, My prophets have surely seen...



Says The Lord.`}]},{id:"the-justice-of-god",num:109,title:"The Justice of God",paragraphs:[{align:"justify",text:`The justice of God rests atop the mountain, and comes forth with a great noise! The retribution of The Lord rains down upon the mountains and gathers strength! It rushes down the steep places, catching many unawares! It gathers together and rages through the valleys, leaping over the banks, breaking down the walls, destroying every barrier! A terrible deluge!

Behold, the trees are fallen and torn from their places, their branches broken and mangled, their roots laid bare! Unrecognizable!`},{align:"center",text:`Thus is the wrath of God,

Thus is the Day of The Lord\u2019s Anger:`},{align:"center",text:`Destruction in a moment, a tearing down,

A wiping away, a great threshing,

A carrying away of all that offends!...`},{align:"center",text:`Until all that is hidden is exposed,

And that which is high and lofty

Is brought low...`},{align:"center",text:`Until every fruitful hill is made barren,

And every lush valley is stripped

And bares neither leaf nor fruit\u2026`},{align:"center",text:"Darkness, thick clouds and darkness..."},{align:"center",text:"The shadow of death."}]},{id:"providence",num:110,title:"Providence",paragraphs:[{align:"justify",text:`My people are a strange and peculiar people. Indeed, they are accounted by the multitude as those who are of unsound mind. Yet My servants are men of action, men with strong trust, men of clout in The Lord; men who are unwavering in My purpose who also care for those given them, willing to go wheresoever I send them, unafraid to do whatever is needful.

Yet the plight of the slothful shall be filled with troubles, as the sun sets upon their need. For in their listlessness they were unaware and did not seek after My will, to know it, nor have they risen up to walk in that which I have spoken already. Thus providence is drawn back, until the sluggard has no place.


Have I not spoken to these things already, in many Letters? Have I not revealed My will and that in which I am most pleased, by My many words? And still My people draw back from My voice and My servants sit idle and fold the hands, closing their eyes to their need while forsaking those placed under their care, both those near to them and those afar off, says The Lord.`}]},{id:"the-true-church",num:111,title:"The True Church",paragraphs:[{align:"center",text:`I am The Church - Its walls, its pews,

Its pulpit, its altar, its very foundation.`},{align:"center",text:`When sitting in My church, you can behold Heaven;

There is no ceiling to keep you from enlightenment.`},{align:"center",text:`And if I am your sanctuary, your four walls of faith,

Your resting place of worship, The Word and the Spirit,

The Stone upon which all must be broken,

The Very Cornerstone of Life,

Then Heaven is open before the eyes of all

Who dwell in Me and become My body...



Says The Lord YahuShua.`}]},{id:"charity",num:112,title:"Charity",paragraphs:[{align:"justify",text:"Comfort the sick, lift up the downtrodden, and visit those in prison; clothe the naked, shelter the homeless, and above all feed the hungry; do so in My name. For in Me shall all find comfort, exaltation, companionship, warm coverings and sanctuary from the storm; even food and drink for their soul shall they receive in Me. For all these things are the very definition and purpose of love."},{align:"center",text:"Thus as I am, so also were you created..."},{align:"center",text:"Understand Love."},{align:"center",text:`For in My love were you created,

To receive and to give;

And in the giving does one also receive.`},{align:"center",text:`Therefore, love one another

As I have loved you,

Says The Lord your Redeemer.`}]},{id:"without-hesitation",num:113,title:"Without Hesitation",paragraphs:[{align:"center",text:`Blessed are My servants who seek to

Obey My commands without hesitation,

For their trust is apparent;

Blessed are those who seek to please Me,

For in them am I well pleased.`},{align:"center",text:`For no man can step forward without trust,

And one who is void of belief is

Consumed by doubt and fear.

And I have already told you that pride blinds

The eyes and arrogance stops the ears.`},{align:"center",text:`Therefore let My servants step

Forward without hesitation, and ask,

That their blessing may be compounded

And their belief increased!...



Says The Lord.`}]},{id:"steadfast-faith",num:114,title:"Steadfast Faith",paragraphs:[{align:"center",text:`Blessed is the wise and faithful servant,

Who gives no thought to how they are

Perceived in the eyes of others.`},{align:"center",text:`For they obey My voice,

And are not dismayed by the looks

Of those who judge without knowledge.`},{align:"center",text:`Indeed, they seek only to please their Master,

Having no need of the approval of others...



Says The Lord.`}]},{id:"perseverance",num:115,title:"Perseverance",paragraphs:[{align:"center",text:`There can be no birth apart from travail,

For birth is always accompanied

By much travail.`},{align:"center",text:`Yet oh how blessed are those

Who persevere with their hearts

Fixed upon the goal, enduring the pain,

For they shall surely receive their reward...



Says The Lord.`}]},{id:"one-body",num:116,title:"One Body",paragraphs:[{align:"center",text:"This is the way of The Lord..."},{align:"center",text:`That one in need in My body

Be supported by their brothers and sisters,

With all members becoming one...`},{align:"center",text:"One body, in Me..."},{align:"center",text:`That he who is able to walk in Me

Dwell alongside those who are weak,

For they are in need of strengthening...`},{align:"center",text:"Lo, you shall all wash each other\u2019s feet!..."},{align:"center",text:`Even as I do likewise

Through you and amongst you,

To the praise of My glory...



Says The Lord YahuShua.`}]},{id:"devotion",num:117,title:"Devotion",paragraphs:[{align:"center",text:`Of My servants I require obedience, with all trust,

Pure service in The Lord...`},{align:"center",text:`An eager servant willing to obey without hesitation,

Even when they lack understanding;

A humble servant who remains in My love,

A disciple who has breathed Me in...`},{align:"center",text:`A devoted son or daughter who loves Me more than these...



Says The Lord.`}]},{id:"unrestrained",num:118,title:"Unrestrained",paragraphs:[{align:"justify",text:`Consider this, says The Lord; ponder it and also receive it: By good works you will not find Me, yet good works are found in Me. And by My works shall you begin to know Me, for My works shall be done in you.


Yet understand this also: Where human power is, pride follows close behind. Yet one who surrenders to The Lord will be given eagle\u2019s wings. Yea nothing shall be impossible for them, for I shall be with them and in them, says The Lord.

In that day, wheresoever I am will My servants be also, and wheresoever I go My servants will follow. And whatsoever I decree will be done in an instant, and those who are chosen will go for Me without hesitation, and that which I speak in this place will be heard in another. And no more shall My servants be restrained, by any means! Declares The Lord. For it is I, The King of Glory, who has spoken it.`}]},{id:"blurred-vision",num:119,title:"Blurred Vision",paragraphs:[{align:"justify",text:`One who answers a matter in the name of The Lord, while being ignorant or unsure, is foolish. And one who judges a matter without knowledge leans upon pride, wearing pretense as a garment.

Thus the one who steps in front of Me shall surely stumble, and the one who seats himself upon My throne shall be cast down. For pride does indeed come before the fall, and those who judge without knowledge shall be made to sit upon the ground. I AM THE LORD.`}]},{id:"responsibility",num:120,title:"Responsibility",paragraphs:[{align:"center",text:`One who does not take responsibility

For their wrong-doings can by

No means place them at My feet;

And until one faces their hurts,

By no means can I heal them.`},{align:"center",text:`For the placing of blame turns the shoulder,

And reluctancy hinders the heart.`},{align:"center",text:`Yet perfect love casts out fear,

And the one who truly knows Me trusts

In My ways and embraces My correction...



Says The Lord.`}]},{id:"the-broken-and-the-proud",num:121,title:"The Broken and the Proud",paragraphs:[{align:"justify",text:`The broken sinner who repents, I know. Yet the prideful man who considers himself righteous, I do not know. Indeed, he shall be found a liar in the Day of Reckoning. For there is none righteous, no not one, save The Son of Man only.


Therefore I ask you, shall the broken sinner be justified in his need, in his fervent desire? He shall indeed be justified in My sight! For I shall clothe him with righteousness and cover him with grace. In his times of weakness My strength shall sustain him, and in My love shall he be made whole. Behold, by My life is he healed!

Yet the proud resist Me, and the arrogant want no part with Me as I truly am. For they have clothed themselves with the glory of men, a quickly fading flower. Their comfort is in their riches, and their solace is in their accomplishments, which shall leave them soiled and bruised in the day of their calamity, says The Lord.`}]},{id:"the-love-of-the-truth",num:122,title:"The Love of The Truth",paragraphs:[{align:"center",text:`Truth is self-evident in the eyes

Of all those who love The Truth.`},{align:"center",text:`Indeed, it resounds within the ears of all those

Who have received of The Truth,

In whom My spirit dwells...



Says The Lord.`}]},{id:"uncovered",num:123,title:"Uncovered",paragraphs:[{align:"justify",text:`Truth is evident in My eyes, and a lie is never hidden. Therefore, let no one place their unrighteous cause upon the backs of the children, when a wrong is accounted only to the one who performed it. Neither let the disobedience of the one be covered over by the needs of the many. For I have seen it; lo, all is known to Me.

Therefore let My people be tested, let them be refined in the fire, that the quality of their trust and the endurance of their belief may be revealed, says The Holy One of Israel.`}]},{id:"the-holy-place",num:124,title:"The Holy Place",paragraphs:[{align:"center",text:`Beloved, there is a language of which

You know nothing about, says The Lord...



A language which is pure and beautiful,

A language in need of no words at all;

A language which you shall soon come to know,

A language which I have revealed

To My servant already...



A language of overwhelming love, pure and undefiled,

Bringing forth much understanding;

A language of power and great glory,

In which all My servants shall come to stand...



The unspoken Word of God received in the presence

Of The Almighty, The Holiest of Holies,

Revealing the essence of who I am...



Union in The Spirit of God...



A place beyond time and space, beyond the knowledge

Contained within creation, surpassing all boundaries,

A place even angels long to know...



The place where I am and have always been seated,

Where you shall be also...



A place without time, The Eternal,

The Bosom of The Father, of which I AM...



Says The Lord YahuShua.`}]},{id:"a-return-to-the-garden",num:125,title:"A Return to the Garden",paragraphs:[{align:"justify",text:"_Thus says The Lord:_ Behold, The Morning Star is risen, the universe is filled with His glory! And that glory shall abide with men, even in them and among them. I shall be a Father unto them, and they shall be My beloved children, forever! Lo, a return to innocence, paradise lost is paradise found, a return to the garden, the universe your playground."},{align:"center",text:"Thus as I have spoken, so shall it be done:"},{align:"center",text:`The mystery of God revealed,

The counting of days no more...`},{align:"center",text:`Forever young in the presence

Of your Shepherd, your Redeemer,

Your Father, your Brother,

Your Most Beloved Friend,

The Fulfillment of all things

For which your hearts have groaned...`},{align:"center",text:"I AM THE MEANING OF LIFE!..."},{align:"center",text:`And all who live in Me, and I in them,

WILL LIVE FOREVER!`}]},{id:"reformation",num:126,title:"Reformation",paragraphs:[{align:"justify",text:"Why does the heathen rage and shake his fist toward Heaven? Behold, he shall fall with none to catch him, and great shall be his fall! Yet the one who reaches for Me shall be lifted up, and the one who extends the hand shall know My dwelling place."},{align:"center",text:"For as it is written:"},{align:"center",text:`Whoever has, to him more will be given,

And he shall have an abundance...`},{align:"center",text:`But whoever does not have,

Even what he has shall be taken away, {{ref:Matthew 13:12}}

Until the Time of Reformation is complete...



Says The Lord.`}]},{id:"the-kingdom",num:127,title:"The Kingdom",paragraphs:[{align:"center",text:"The Kingdom of God is a garden..."},{align:"center",text:`Set apart from the many schemes of the adversary,

A place of rest free of briers and thorns...`},{align:"center",text:"A Sabbath..."},{align:"center",text:`A holy place which shall never pass away,

Where no one lies down in death,

Nor shall any be made to slumber...`},{align:"center",text:`My people shall never be covered over again,

For the old order of things has passed away!

Behold, all things have become new!...



Says The Lord.`}]},{id:"the-word-of-truth",num:128,title:"The Word of Truth",paragraphs:[{align:"justify",text:"My Word is truth! And that which requires understanding shall be given to those of a contrite heart and a humble spirit. For those who love Me obey My Commandments, and those who remember My Sabbaths honor Me and shall know Wisdom. Therefore consider these things carefully."},{align:"center",text:`For I have indeed prepared
a place for those who seek Me,

For those who long to know Me as I truly am...`},{align:"center",text:`A place for all those accepted in The Beloved,

In whom My spirit dwells...`},{align:"center",text:`The Kingdom without end...



Says The Lord.`}]},{id:"faith-without-works-is-dead",num:129,title:"Faith Without Works Is Dead",paragraphs:[{align:"center",text:`Let all those who truly know Me

Proclaim My name first by their ways,

Then with their mouths...`},{align:"center",text:`For honor only spoken of is but wind,

The veil of the hypocrite who knows not

Where he is going, having no remorse

Over where he has been...



Says The Lord.`}]},{id:"faith-and-works",num:130,title:"Faith AND Works",paragraphs:[{align:"center",text:`What is faith without works?

Nothing, a lie spoken in vain.



And what of works without faith?

Vanity, a false good covering a heart

Which has turned from The Truth...



Says The Lord.`}]},{id:"just",num:131,title:"Just",paragraphs:[{align:"center",text:`The justice of God is beyond question,

Standing forever in its permanency,

Unwavering for all time...



Righteous.`}]},{id:"god-is-sovereign",num:132,title:"God Is Sovereign",paragraphs:[{align:"center",text:"God is sovereign, His judgment stands."},{align:"center",text:`Therefore, let the penitent be rewarded equally

To their forgiveness, which is equal.`},{align:"center",text:`And let all evil unrepented be punished in accordance

With evil\u2019s deeds, the final penalty of which

Has remained equal even to this day.`},{align:"center",text:"The Lord does not change."}]},{id:"intentions",num:133,title:"Intentions",paragraphs:[{align:"center",text:`Where there are righteous works, there are also those

Who seek to spoil them for the sake of pride and envy.

And where there is pure knowledge, there are also

Those who defile it among women.



Yet the ignorance of the meek is no cause for offense,

Nor shall the error of the humble bring forth rebuke.



For I know the heart and look upon the innermost intentions...



Says The Lord.`}]},{id:"forgive",num:134,title:"Forgive",paragraphs:[{align:"center",text:`Blessed are those who do not return

Evil for evil, or reviling for reviling,

But rather pray for their enemies.`},{align:"center",text:`Blessed are those who hold no ill-will

In their heart toward another.`},{align:"center",text:`Indeed, blessed are all those who

Forgive everyone who has sinned against them.`},{align:"center",text:`For great shall be their reward in Heaven...



Says The Lord.`}]},{id:"a-heavy-stone",num:135,title:"A Heavy Stone",paragraphs:[{align:"center",text:`Those who refuse My correction are foolish,

And must walk through dry places.`},{align:"center",text:`And those who refuse to repent have

Secured their place in the valley of death.`},{align:"center",text:`For the pride of man is a heavy stone,

Which increases by weight each day

It remains unbroken...



Says The Lord.`}]},{id:"insolent-cords",num:136,title:"Insolent Cords",paragraphs:[{align:"center",text:`Insolent cords bind the proud,

And rebellion is a rope by which

The foolish hang themselves...



Says The Lord.`}]},{id:"the-word-of-god",num:137,title:"The Word of God",paragraphs:[{align:"justify",text:"The Lord your God is a consuming fire, My every word a purifying flame! The presence of The Lord is an oppressive storm, which abases the proud and causes the high-minded to flee! And that which I have spoken to this generation, is it not a sword with which I shall strike to the heart of this people?! For I shall surely set all these crooked paths straight, and burn away the dross!"},{align:"center",text:`Yet for those who trust in Me and in whom My spirit dwells,

My words are like a strong tower set in the midst of battle,

Which can in no wise be broken down!...



A great trumpet blowing upon the hill outside the city,

Which echoes throughout the waste places!

A waving banner for this generation, a bright light,

A beacon, shining in the midst of this present darkness!...



A rod of justice for the oppressed and the persecuted,

A loosening of the chains placed upon My people,

The breaking apart of every shackle!...



Freedom for those who love Me,

Deliverance for those who understand,

Strength for the weak, grace to the humble,

Manna to nourish the penitent...



Says The Lord.`}]},{id:"my-witnesses-and-my-word",num:138,title:"My Witnesses and My Word",paragraphs:[{align:"justify",text:"_Thus says The Lord:_ My words shall be as fire in the mouths of My witnesses, singeing the ears of every hearer! My words shall carry the full weight of My spirit and be very heavy!"},{align:"center",text:"Behold, I shall cause My words to have weight and power!..."},{align:"center",text:`Weight as a man feels when struggling against the power of the sea,

The waves pushing him backward, toppling him, throwing him down,

Until he has no more breath left in him...`},{align:"center",text:`As the wind knocked out of a man

When he has been struck hard upon the chest,

Leaving him in stunned silence, unable to speak,

For all his thoughts have departed from him...`},{align:"center",text:`FOR I SHALL CAUSE MY STRENGTH TO DWELL

IN MY WORDS LIKE THE ROARING OF THE SEA!`}]},{id:"pride",num:139,title:"Pride",paragraphs:[{align:"center",text:`Only those who know they are sick

Seek out The Physician.`},{align:"center",text:`Yet those who perceive themselves as well

Will in no wise come to Me, keeping Me at bay;

They remain seated firmly in the darkness

Of their own understanding,

Resting upon their laurels by which

They have highly esteemed themselves...



Says The Lord.`}]},{id:"stained-glass",num:140,title:"Stained Glass",paragraphs:[{align:"center",text:`One who peers through stained glass can not behold

His own image, nor is he able to see those inside clearly;

For he sees only an outline, a blur of color obscuring his vision.



And those on the inside who peer outward remain blinded,

Able to perceive only a shadow of what truly is,

Holding up the hand against the brightness,

For fear of the noonday sun which is about to come in.



Thus they prefer the light filtered and the brilliance masked,

By means of all this painted glass.



What then shall a people such as this do when night has fallen?...



Says The Lord.`}]},{id:"the-humble-penitent-man",num:141,title:"The Humble, Penitent Man",paragraphs:[{align:"center",text:`It is the humble, penitent man

Who gives Me glory in all his ways;

For he seeks to honor Me,

To please Me above all else.`},{align:"center",text:`He wants no part in the ways of this world,

Neither does he seek glory for himself;

By his actions he shines forth,

Seeking glory for The One alone who is God.`},{align:"center",text:`Thus the man who places Me foremost,

In all things, shall also be first

When The Glory comes...



Says The Lord.`}]},{id:"the-king-eternal",num:142,title:"The King Eternal",paragraphs:[{align:"justify",text:`Behold, the footsteps of The Lord shake the earth! The footsteps of The Lord shall tread the winepress of the wrath of His fury! The presence of The Lord shall break apart the tall mountains; His power shall bring down every mountain, every high place shall be brought low! For the presence of The Lord is strong and mighty, and the anger of The Lord is hot and burns in the heat of His jealousy! Who can turn back The Lord\u2019s anger, once it is kindled? Who can prevent The Most High from performing His will?! Whose glory is like The Lord\u2019s?!

Who comes as The King above all kings wearing the raiment of God, whose majesty is beyond compare?! Who is able to stand in the day of His wrath, or survive the power of His sword which proceeds from His mouth, the day He strikes through the heart of all people and lays His enemies waste, the day every adversary is consumed in the brightness of His coming?! For He is mighty in battle and His justice is swift, His victory absolute!`},{align:"center",text:"Who is The King of Glory?!"},{align:"center",text:`YahuShua HaMashiach, HE is The King of Glory!

His power is infinite, His love never-ending!`},{align:"center",text:`HE is The King Everlasting,

The King of Righteousness!`},{align:"center",text:`His grace is shed abroad to

Every contrite and humble spirit;

His forgiveness is pure, ever-flowing

Into the hearts of the penitent,

Restoring them to righteousness and life!`},{align:"center",text:`Yes, He is The One and Only King Eternal!

There is no other, there is none like Him!`}]},{id:"in-union-with-the-messiah",num:143,title:"In Union With The Messiah",paragraphs:[{align:"justify",text:`Beloved, there is a day coming when you shall enter My presence and never leave it, a day when you shall behold My face, says The Lord. And wheresoever your heart leads you, there will I be also, with you always where you are. Whether you journey to the heights of the mountains, or to the farthest reaches of creation, there I am, with you where you are. Beloved, all creation is Mine, and all I have is yours. For you are Mine, even as I am yours also... _Together, forever._


For the glory you have seen, and that which you have imagined, has until now been measured in a human way. Yet the glory of The Lord is of such a kind! Glory which has always been, glory with no beginning and no end, having neither height, nor depth, nor length, nor width. For My glory is life and that love we share, a gift of understanding which comes by knowledge of The Holy; glory which can not yet be fully realized, nor are there words sufficient to open your understanding... _Fulfillment, which only comes by union._`}]},{id:"my-love-endures-forever",num:144,title:"My Love Endures Forever",paragraphs:[{align:"center",text:`Long after the glory of men has passed away, with the height

Of their kingdoms turned to dust, My love endures!



Long after the stars you behold in the heavens

Have ceased from shining, My love endures!



Deeper and wider than space and time, My love endures!



Even before creation, My love endures; and after, My love remains.



For I shall be your God, and you shall be My people,

As long as My love endures...



Says The Lord.`}]},{id:"i-am-god",num:145,title:"I AM GOD",paragraphs:[{align:"justify",text:`I am He who formed the earth and all you see in the heavens, He who set the foundations and called creation forth by the Word of His power and the vastness of His knowledge, causing all things to be!

I made the matrix, and set all things in order; I am He who formed it! I know all the hidden parts; even the most minute detail, by which all things are made, is known to Me! Behold, I see the inward parts; from the innermost depths to that which can not be seen by man, all is known to Me!

Before Me is the whole of creation at all times! No distance is far from Me, no measure is too great for Me, and no weight is too heavy. That which is beyond your comprehension is known to Me each morning, and every evening I behold the whole of creation and consider. For I am The Lord. YAHUWAH is My name.`}]},{id:"the-volumes-of-truth",num:146,title:"The Volumes of Truth",paragraphs:[{align:"justify",text:`_Thus says The Lord:_ Beloved, this Word, even every Volume to every Letter, is the Word of My glory, which I have put forth once again - A testament of My love and sacrifice, the announcement of My coming, a proclamation of truth, revelation of who I really am! The Trumpet Call of God, so all those called and chosen may hear and come to Me in their proper time and season.

Behold, it is also a strong correction for all those who have taken to themselves MY name and MY Word, to pollute it, a plumb line for this wicked generation! For this Word is a waving banner, an ensign to all nations! - A trumpet of alarm and war, the sound of recompense and judgment, which shall soon fall upon every nation!`},{align:"center",text:`For I AM WHO I AM!

The Only Begotten of The Father!

The One True God and Savior!

The Mashiach!...`},{align:"center",text:"YAHUSHUA-YAHUWAH!"}]},{id:"keep-watch",num:147,title:"Keep Watch",paragraphs:[{align:"justify",text:`_Thus declares The Lord:_ All your setting of dates shall come to nothing, and all your precise predictions shall fail, for I may take them before or after. For I am God.

Behold, the first election is made, the time of bundling passed. Thick clouds have risen in the west, the hard rains have come, and who in all the earth is able to prevent it as it draws near, or hinder it when it arrives? Lo, a mighty wind blows in the east, yet who is aware of it until it has overtaken them?

Therefore keep watch, for you know not the time of The Lord\u2019s coming. Whether it be in the first, or in the second, or in the third watch of the night, you know not the time of His return. You know not the day or the hour, says The Lord.`}]},{id:"awaken",num:148,title:"AWAKEN",paragraphs:[{align:"justify",text:`The mountains tremble and the hills quiver, the oxen grumble in their stalls and the lambs leap about in their places. FOR I AM COME.

Do you hear the sound of My heart pounding within My chest, the thunder rumbling as the storm approaches? Look how the lightning flashes upon the southern skies, see how the clouds roil on the western horizon. Behold, the northern lands are anxious, the isles of the east are unsettled and the deserts burn with hatred. FOR I AM COME.

Behold, the trumpet is blown in the four corners, the warning broadcast in all the earth, and still you sleep! AWAKEN! I AM COME! Says The Lord.`}]},{id:"a-psalm-of-david",num:149,title:"A Psalm of David",paragraphs:[{align:"center",text:`YahuShua is my shepherd; I shall not want.

He makes me lie down in green pastures,

He leads me beside still waters, He restores my soul.

He leads me in paths of righteousness, for His name\u2019s sake.

Yea, though I walk through the valley of the shadow

Of death, I will fear no evil, for You are with me;

Your rod and Your staff, they comfort me.

You prepare a table before me in the presence

Of my enemies, you anoint my head with oil,

My cup runs over.

Surely goodness and mercy shall follow me

All the days of my life, and I will dwell

In the house of YAHUWAH, forever.`}]}],WTLB_TWO=[{id:"introduction",num:1,title:"Introduction",paragraphs:[{align:"center",text:`**WORDS TO LIVE BY**

**PART TWO**`},{align:"center",text:`_More Words of Wisdom

From The Lord, Our God and Savior_





For all those who have dedicated

Themselves to Me by means of The Truth,

Those who have recognized My words

And also do them...`},{align:"center",text:`Those who came to Me empty

That I might fill them up,

That they might be truly dedicated to Me...`},{align:"center",text:`Even as I had dedicated Myself to them also,

That we may become one...`},{align:"center",text:`Set apart in My glory, for My glory,

To the joy of their Father in Heaven...`},{align:"center",text:`Says The Lord YahuShua.





Grow wise in Me, and live according to My Word,

Even according to all these Letters I have given you,

By which I have set all these crooked paths straight.

For My every word is Scripture, My every Letter truth.`},{align:"center",text:`For it is written:

_Man shall not live by bread alone,

But by every word that proceeds

From the mouth of God {{ref:Matthew 4:4}}..._`},{align:"center",text:"Says The Lord."}]},{id:"i-am-the-lord-s",num:2,title:"I Am The Lord's",paragraphs:[{align:"center",text:"**A Prayer Against Temptation**"},{align:"center",text:`I am The Lord\u2019s!

And I will no more give myself to diverse lusts,

To the cares and deceits of my flesh and this world.`},{align:"center",text:`I am The Lord's!

My heart, it is The Lord\u2019s; My mind, it is The Lord\u2019s;

My will, it is The Lord\u2019s; My flesh, it is The Lord\u2019s;

The whole of my body, even all I am, I give to The Lord.`},{align:"center",text:`I am The Lord\u2019s!

Yea, I pour out my life before The Lord,

Even as He poured out His; let me receive it!

In the name of My Love, I call out

In YahuShua\u2019s name, I ask to receive it!`},{align:"center",text:`YahuShua, My Life and My Righteousness,

I want Your life!`},{align:"center",text:`My Lord and my God, I am yours!

Do with me as You please, according to

The good pleasure of Your will...`},{align:"center",text:"I give myself away..."},{align:"center",text:"Amen."}]},{id:"the-bridegroom-approaches",num:3,title:"The Bridegroom Approaches",paragraphs:[{align:"justify",text:`Thus says The Lord: I AM COME!\u2026



From the farthest reaches of creation tothe deepest depths of the earth, below the foundations, from beyond time and space shall the sound of My voice come forth! IT SHALL RESOUND LOUDLY! I SHALL BE HEARD!

Even within the hearts of men shall My voice burst forth, rushing through their veins, causing each of their members to tingle, a great and wonderful shudder within their spirits to the purging of their souls!



For I sit higher than the tallest mountain, I am set high above the highest heavens, set apart and holy, set apart in power and great glory!



Behold, before the beginning was My glory declared, and from the ends of time was My majesty set amongst the stars! Before the earth was made, I wore the universe as a garment!

Who is like Me?! Declares The Alpha. Who holds all existence together by the Word of His power and by the vastness of His knowledge? Says The Omega.
Answer, young children, answer if you know. Speak My name aloud; withhold not! SHOUT, MY SONS AND DAUGHTERS! Let your hearts burst forth with praise! Let every beat resound within your chests, to the praise of My glory!

Bless the name of pure, unending love! Bless the name of mercy and grace, the name of righteousness! Bless the name of Him who bore your sins upon the tree! KISS THE SON! Says YAHUWAH, The Holy! Kiss Him upon His feet, kiss Him upon His hands, put your hand in His side\u2013TASTE and see! Come close, and kiss My wounds which I received, yes, each one you gave Me. Kiss Me, and be separated no longer; partake of His fullness and receive of Me!



Awaken your hearts! Rouse from your slumber! YOUR KING COMES TO YOU! He is just, HE is your salvation! His garment is righteousness! Have you grasped it? Hurry, lay hold on Him!

He is My heart, says The Father. Press your ear against My chest, and listen to the sound of My love, every beat of My mercy. Feel the embrace of My arms, strong and gentle\u2013I AM YOUR FATHER! Your heart\u2019s one embrace!



My children, have you heard? Have you truly considered? THE DESIRE OF AGES IS COME! Therefore sing, sing for Me!...



THE BRIDEGROOM APPROACHES!`}]},{id:"the-only-way",num:4,title:"The Only Way",paragraphs:[{align:"justify",text:"Beloved children, I say this once again, so you may be saved: Come out! _Come out from among them and be separate! Says The Lord. And no more touch what is unclean, and I will receive you! {{ref:2 Corinthians 6:17}}_"},{align:"center",text:"For there is but One Way!..."},{align:"center",text:`YahuShua HaMashiach,

Yes, He who is called Jesus The Christ,

HE is The Only Way!...`},{align:"center",text:`Therefore follow close behind Him,

In His very footsteps,

And you shall surely live and not die...`},{align:"center",text:`Says The Lord whose dominion is everlasting

And whose authority is absolute,

The Only Lord God of Hosts, The I AM.`}]},{id:"wake-up",num:5,title:"Wake Up",paragraphs:[{align:"center",text:`Wake up and pay attention!

Awaken out of this sleep, be shaken out

Of this slumber, and call upon My name!...`},{align:"center",text:`Seek out My will that you may know it;

Heed the sound of this Trumpet and prepare!...`},{align:"center",text:`For My Kingdom comes, and My will

Shall be done on earth as in Heaven...`},{align:"center",text:"Says The Lord God."}]},{id:"hold-fast",num:6,title:"Hold Fast",paragraphs:[{align:"center",text:`Beloved, prepare your hearts

And do not abandon hope...`},{align:"center",text:`Though much death draws near and

The pain of death increases in every corner,

Though heavy sorrows overtake the land

And tears fill your eyes, hold fast...`},{align:"center",text:"Embrace Me fully and do not waver..."},{align:"center",text:"Says The Lord YahuShua."}]},{id:"splendor",num:7,title:"Splendor",paragraphs:[{align:"center",text:`I created autumn so all may
Partake of My brushstrokes,

And know I am God, and give Me glory...`},{align:"center",text:`For My splendor is written

In the leaves of the trees;

It is carried upon the wind,

As it moves through the tall grasses;

It soars high above on the wings of eagles,

Yet remains as near as the fragile flower at your feet...`},{align:"center",text:`Behold, everywhere you look,

The hand of God is clearly seen...`},{align:"center",text:"Says The Lord."}]},{id:"in-the-image-of-god",num:8,title:"In The Image of God",paragraphs:[{align:"justify",text:"All have sinned and fall short of the Glory of God; there is none righteous, no, not one. And for this reason YahuShua The Messiah was sent to die for all men; thereby freeing mankind from the chains which held him captive, loosing him from the bonds which bound him to the punishment of sin, which is death."},{align:"center",text:`So then as The Messiah was

Crucified and died, and is risen,

So too must you crucify your life of old...`},{align:"center",text:`Who you were must perish,

Along with your sinful ways,

Then shall you truly be born again...`},{align:"center",text:"Revived and restored in The Image of God..."},{align:"center",text:"Says The Lord."}]},{id:"life-is",num:9,title:"LIFE IS",paragraphs:[{align:"center",text:`Blessed be the name of The One

Who is, and was, and is forevermore,

The Fosterer and Protector of those

Tossed away in bitter ignorance...`},{align:"center",text:"For LIFE IS, before its very conception..."},{align:"center",text:"Says The Lord."}]},{id:"a-gemstone",num:10,title:"A Gemstone",paragraphs:[{align:"center",text:`Like a gemstone shining in the midst of all

This darkness, easily found by the eyes of God,

So shall you be in the day you surrender your life,

The day you give up this fight and return to Me...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"no-walls",num:11,title:"No Walls",paragraphs:[{align:"center",text:`No church named of men

Is the true church - not one...`},{align:"center",text:`Rather each member individually,

Who believes in The Messiah and obeys

His voice, in whom His spirit dwells,

Make up the True Church of His body...`},{align:"center",text:"No walls, only spirit and truth..."},{align:"center",text:"Says The Lord."}]},{id:"marriage",num:12,title:"Marriage",paragraphs:[{align:"center",text:`I gave unto man woman,

From his side did I form her,

And he who was one became two;

And behold, the two became one again in marriage...`},{align:"center",text:"Two of one flesh, man and woman {{ref:Genesis 2:21-24}}..."},{align:"center",text:"And I saw that it was very good..."},{align:"center",text:"Says The Lord."}]},{id:"bitter",num:13,title:"Bitter",paragraphs:[{align:"center",text:`If you dispense the food of God to the hungry,

While using your own salt to salt that which

Has salt in itself, will not the food you offer

Lose its flavor and become bitter in the mouths

Of those who came looking to be fed?...`},{align:"center",text:"Says The Lord."}]},{id:"gone-from-this-place",num:14,title:"Gone From This Place",paragraphs:[{align:"center",text:`The Thief shall enter the house

And steal away all who are not tied down,

Fastened, or shackled to the house...`},{align:"center",text:`And all those in whom He sees of Himself

Shall surely be gone from this place!...`},{align:"center",text:"Says The Lord."}]},{id:"a-modest-answer",num:15,title:"A Modest Answer",paragraphs:[{align:"center",text:`Saying \u201CI don\u2019t know\u201D is truthful,

Humble, a modest answer...`},{align:"center",text:`Yet assertions without knowledge are akin

To a lie, the seeds of pride and vanity...`},{align:"center",text:"Says The Lord."}]},{id:"sanctuary",num:16,title:"Sanctuary",paragraphs:[{align:"center",text:`Come out from among them,

And take refuge in Me...`},{align:"center",text:`For I am your only shelter,

Your only sanctuary from the storm...`},{align:"center",text:"Says The Holy One of Israel."}]},{id:"bless-those-who-curse-you",num:17,title:"Bless Those Who Curse You",paragraphs:[{align:"justify",text:"My children, struggle not against the principles of another, nor rebuke them with your own words, nor correct them by your own understanding. Let go of your personal notions of right and wrong, and strive to love others in spite of yourselves, and have compassion for those with whom you disagree."},{align:"center",text:`Do not judge them,

Nor shun them in your heart...`},{align:"center",text:`_Rather love those who speak against you,_

Because you obey My Word...`},{align:"center",text:`_Bless those who curse you,_

_And pray for those who mistreat you,_

_As it is written {{ref:Matthew 5:44}}..._`},{align:"center",text:"Says The Lord."}]},{id:"the-only-faithful-and-true-witness",num:18,title:"The Only Faithful and True Witness",paragraphs:[{align:"center",text:`I have written it on tablets of stone

And within the heart of man, and within

The pages of My Book it is made plain;

Thus they are without excuse...`},{align:"center",text:"For I am God alone, The Righteous One..."},{align:"center",text:`I alone am holy, just and good;

I alone have divided right from wrong;

I alone have established

The Law and define what is sin;

Behold, I expose the darkness and bring

All hidden things into the light...`},{align:"center",text:`For I alone sit as Judge,

The Only Faithful and True Witness...`},{align:"center",text:"Says The Lord."}]},{id:"created-anew",num:19,title:"Created Anew",paragraphs:[{align:"center",text:"Trust in Me, and you shall be set free..."},{align:"center",text:`For it is the humble,

Penitent man who shall see God;

Behold, he shall look upon My face,

As I restore him in My image...`},{align:"center",text:`For I am the image of The Invisible God,

The perfect reflection of The Father,

The face of The Majesty from on high,

Immanu El...`},{align:"center",text:`Therefore open your heart to Me,

And I shall create you anew...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"humble-and-penitent",num:20,title:"Humble and Penitent",paragraphs:[{align:"center",text:`All upon the earth who have gained maturity

Have become so very poor and desolate...`},{align:"center",text:`For once you were wealthy,

Rich beyond words, for then you knew

The Kingdom of Heaven as a child;

Yet now you are grown, your light

Quickly fading, as the ways of this

World pull you down to the pit...`},{align:"center",text:`Therefore return to Me, humble and penitent;

Come to Me as a child...`},{align:"center",text:"For by no other means shall you pass through {{ref:Matthew 18:3-4}}..."},{align:"center",text:"Says The Lord."}]},{id:"the-pure-of-heart",num:21,title:"The Pure of Heart",paragraphs:[{align:"center",text:"What is a child\u2019s inheritance on earth and in Heaven, if the years of their life be few in number and they remain in their innocence? Assuredly, I say to you, they will inherit The Kingdom of Heaven, for The Father holds the pure of heart in the palm of His right hand. For like the firefly which alights upon the tall grass, so are these little ones, precious lights shining among men."},{align:"center",text:`And though the little ones may suffer

At the hands of men in this world,

I tell you the truth, all arrive at

The Father\u2019s house in a moment,

In the twinkling of an eye...`},{align:"center",text:`Where healing is complete

And every tear is wiped away,

The ways of the world and men forgotten...`},{align:"center",text:`Only love abides, as they look upon

The face of their Father forever...`},{align:"center",text:"Says The Lord."}]},{id:"rest",num:22,title:"Rest",paragraphs:[{align:"center",text:`Many things shall be put to rest in

The Lord\u2019s Day, even death and the grave;

Destruction shall have no place,

And evil shall be far removed...`},{align:"center",text:`_For as it is written:_

_They shall not hurt nor destroy in all_

_My Holy Mountain, for the earth shall be_

_Full of the knowledge of The Lord_

_As the waters cover the sea {{ref:Isaiah 11:9}}..._`},{align:"center",text:`Therefore, beloved ones, pray always

That you are counted worthy to

Enter My rest, that you may abide

In the presence of The Lord, forever...`},{align:"center",text:"Says The Lord."}]},{id:"your-only-salvation",num:23,title:"Your Only Salvation",paragraphs:[{align:"center",text:`O most foolish and deceived generation,

Can anyone cut out their own heart and live?...`},{align:"center",text:`And who is able to walk alone in darkness,

Without a light to guide them?

Who shall uphold them when they stumble

Or catch them when they fall?

Who will bind up their wounds?...`},{align:"center",text:`O ignorant and confused generation,

Deceived peoples, The Stone which you seek

To cast off is LIFE, your only salvation!...`},{align:"center",text:"Says The Lord."}]},{id:"your-help-and-your-shield",num:24,title:"Your Help and Your Shield",paragraphs:[{align:"center",text:"The Mashiach is your help and your shield..."},{align:"center",text:`YahuShua, whom you call Jesus and Christ,

Is The Rock of your Salvation,

The One who is and was and is to come;

For The Father and The Son are One...`},{align:"center",text:`Therefore embrace Me in My Mercy,

And receive of Me in My Great Love...`},{align:"center",text:"Says The Lord God."}]},{id:"the-lord-s-table",num:25,title:"The Lord\u2019s Table",paragraphs:[{align:"center",text:"The Lord\u2019s table is a bounty..."},{align:"center",text:`And those who eat from My plate are

Always full, and those who drink from

My cup shall never go thirsty...`},{align:"center",text:`For My cup overflows,

Bearing fruit in every part of your life,

Bringing forth love and understanding...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"the-sign-of-the-son-of-man",num:26,title:"The Sign of The Son of Man",paragraphs:[{align:"center",text:`The heavens shall be divided,

And divided again, the glory thereof

Stretching from the earth to heaven,

And the clouds shall be rolled back like a scroll...`},{align:"center",text:`Behold the brilliance, O earth!

Be bowed down and weep, O sons of men!

For The One whom you pierced is about to appear! {{ref:Zechariah 12:10}}...`},{align:"center",text:`Let every eye be opened therefore,

Let all in the earth see, until the fullness

Of the revelation is made complete...`},{align:"center",text:`Thus that which was the beginning and the end

Shall also be the end which brings forth

The new beginning...`},{align:"center",text:"Says The Lord."}]},{id:"soiled",num:27,title:"Soiled",paragraphs:[{align:"center",text:`The water of the earth can only cleanse

That which is soiled on the skin;

By no means can it cleanse

That which is soiled in the spirit...`},{align:"center",text:"This is reserved for the blood of The Lamb..."},{align:"center",text:"Says The Lord."}]},{id:"against-god",num:28,title:"Against God",paragraphs:[{align:"center",text:`That which is unnatural is universally known,

Though the men and women of this world deny it;

And that which is against God shall be purged by fire...`},{align:"center",text:`Even all that offends shall be destroyed

And come to a swift end...`},{align:"center",text:"Says The Lord."}]},{id:"walk-with-me",num:29,title:"Walk With Me",paragraphs:[{align:"center",text:`My Word is for all who truly seek Me

And long to know My ways,

Even to walk in them...`},{align:"center",text:`Thus My Word can only be accepted

And understood by those who have

Received the love of the Truth,

For they abide in Me and

My spirit resides within them...`},{align:"center",text:`For how can one who stands

Apart from Me know Me?

And how can one who teaches his

Own way walk with Me in Mine?...`},{align:"center",text:"Says The Lord."}]},{id:"the-water-of-siloam",num:30,title:"The Water of Siloam",paragraphs:[{align:"justify",text:`Men do not have understanding of the Scriptures in themselves. Rather it is a gift from God, received through the Holy Spirit, given to those who have placed all their trust in The Holy One, embracing Me as I truly am. Or have you never read this Scripture: _The fear of The Lord is the beginning of wisdom, and the knowledge of The Holy One is understanding? {{ref:Proverbs 9:10}}_

Therefore to those who have received is all revealed, and to those who have not received is all shut away. Shall the darkness understand the light? For only those of The Light, bathed in His glory, shall see - the rest left blinded.`},{align:"center",text:`For until one calls on the name of

The Messiah, in sincerity and in truth,

By no means shall they receive...`},{align:"center",text:`_For He is The One who had placed_

_The mud upon their eyes to heal them..._`},{align:"center",text:`_Behold, He is also The Water of Siloam_

_Which was sent to wash them,_

_That they might now see {{ref:John 9:6-7}}..._`},{align:"center",text:"Says The Lord."}]},{id:"the-perfect-reflection",num:31,title:"The Perfect Reflection",paragraphs:[{align:"justify",text:`Apart from Me, there is no wisdom! Apart from The Holy One, there is no life! Apart from The Vine, there are no branches!

Behold, the leaves wither and the fruit has been cast down, for the people have no favor with God. Thus every dry branch must be broken off and cast into the fire, all corrupt fruit must be left and tread down.

For the temple of God has lost its form; its comeliness has departed, every chamber is empty. For the heart of man is void, his countenance unyielding. Thus the pride of man has become a chasm, both deep and wide.`},{align:"center",text:`Therefore repent, and receive of Me

As I am, and not as you would have Me be,

That you may be truly born again.`},{align:"center",text:`For I am the perfect reflection of The Father,

The image of The Invisible God...`},{align:"center",text:`I died, behold, I am risen,

And by My life are you saved;

That you might become the perfect

Reflection of Me, The One alone

In whom is everlasting life...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"my-body-my-bride",num:32,title:"My Body, My Bride",paragraphs:[{align:"center",text:`My church has no walls,

And is called by no other name except

The name The Father has given Me...`},{align:"center",text:`Its members are of one mind

And one spirit, of one love,

One flock with one Shepherd...`},{align:"center",text:`A people set apart who keep

The Commandments of The Father

And remain faithful to The Son,

Striving always to walk in My ways...`},{align:"center",text:`For those who truly know Me

Dwell in Me, and I in them;

For they are Mine, even as I am theirs also...`},{align:"center",text:"My body, My bride..."},{align:"center",text:"Says The Lord YahuShua."}]},{id:"the-remnant",num:33,title:"The Remnant",paragraphs:[{align:"center",text:`I am He who searches the hearts

And minds, I know My own;

I know whose love is steadfast,

Whose faith is unmoving...`},{align:"center",text:`And this is the True Church

My people long for, the remnant

Which now is and is yet to come...`},{align:"center",text:`For it is not found outwardly in the world,

But inwardly, in the temple of God...`},{align:"center",text:"I AM THE LORD."}]},{id:"the-truth",num:34,title:"The Truth",paragraphs:[{align:"center",text:`The Scriptures are not malleable;

The Commandments do not change!...`},{align:"center",text:`For The Truth is absolute,

Forever standing on a hill,

Bright and shining,

Immovable, unbreakable!...`},{align:"center",text:`The Everlasting Stone which has

Become The Head of the Corner {{ref:Matthew 21:42}},

The Great Mountain which fills the whole earth {{ref:Daniel 2:35}}...`},{align:"center",text:"Says The Lord."}]},{id:"absolute",num:35,title:"Absolute",paragraphs:[{align:"center",text:"The Word stands forever..."},{align:"center",text:`Immovable and everlasting,

Unchangeable, having complete

Authority over all things,

The light and the dark,

The righteous and the wicked...`},{align:"center",text:`Indeed, the whole universe is

Set within the confines of His will,

Giving heed to Him who created it,

Forever and ever...`},{align:"center",text:"Says The Lord."}]},{id:"twin-daggers",num:36,title:"Twin Daggers",paragraphs:[{align:"center",text:`My words are fire, singeing the forehead

Of the arrogant, setting the countenance

Of the prideful ablaze, twin daggers

Piercing the heart of every hearer...`},{align:"center",text:`Therefore hear the Word of The Lord,

And heed the call...`},{align:"center",text:`For it is a call to repentance, a shout

And a witness, a proclamation of Truth...`},{align:"center",text:`A trumpet of alarm and war, a declaration

Of judgment, a strong rebuke...`},{align:"center",text:"Says The Lord."}]},{id:"abolished",num:37,title:"Abolished",paragraphs:[{align:"center",text:`The reign of evil shall be abolished,

The wicked stricken and the evil of heart

Blotted out, extinguished in the

Lake of My burning heart...`},{align:"center",text:`For My heart is set ablaze in My anger,

And My countenance burns like a raging fire;

My sadness is infinite, the weight of

Unending sorrow covers Me...`},{align:"center",text:`For as I live, says The Lord, I take no

Pleasure in the destruction of the wicked...`},{align:"center",text:`But call all in the earth to repent,

To turn from their evil ways

And return to Me...`},{align:"center",text:"Says The Lord."}]},{id:"every-heart-laid-bare",num:38,title:"Every Heart Laid Bare",paragraphs:[{align:"justify",text:`One Commandment broken are all Commandments broken. One sin committed in The Messiah\u2019s name are all sins accounted to you. One sin repented in His name, all are forgiven you. For I know your thoughts, My children, even your innermost intentions, and I know whether or not you are fully converted in your hearts.

And though you may lie to yourselves, and bear false witness in the sight of many witnesses, nothing is hidden from the eyes of God - every lie exposed, every heart laid bare, in the Day I rise up and judge the earth.`},{align:"center",text:`Come to Me, therefore, in sincerity and in truth;

Humble yourselves in The Messiah\u2019s name...`},{align:"center",text:`For He is The True Light, utterly void of darkness,

The Only Way to follow, The Truth Absolute;

By Him alone shall you walk into everlasting life...`},{align:"center",text:`For only those who walk in Him shall find Me,

And only those in union with Him shall know Me...`},{align:"center",text:"Says The Lord."}]},{id:"the-only-true-religion",num:39,title:"The Only True Religion",paragraphs:[{align:"center",text:"I am The Way, The Truth, and The Life..."},{align:"center",text:`And this is pure, undefiled love,

The only means by which The Law

Of The Father may be fulfilled:

You shall love The Lord your God

With all your heart, with all your mind,

With all your soul and with all your strength;

And yes, beloved, you shall love

Your neighbor as yourself...`},{align:"center",text:`For this is to walk in Me, this is to abide in Me,

The only true religion in which is life...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"true-faith",num:40,title:"True Faith",paragraphs:[{align:"center",text:`True faith has a name,

And true religion yields fruit of the same...`},{align:"center",text:`A Bride who obeys the voice of her

Husband and walks in His ways,

A people worthy to be called by His name...`},{align:"center",text:"Says The Lord."}]},{id:"regain-the-line",num:41,title:"Regain the Line",paragraphs:[{align:"center",text:"Beloved, turn aside and come to Me."},{align:"center",text:`Regain the line and together we shall walk,

Choosing the good and refusing the evil,

Until you also have forgotten your sin.`},{align:"center",text:`Behold, it is separated from you

As far as the east is from the west...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"worthless-images",num:42,title:"Worthless Images",paragraphs:[{align:"justify",text:`Do not put your trust in idols, nor in any man-made image forged of stone or marble, or of wood or brass, gold or of fine metal; there is no life in it! For they can not speak or walk; they have no power at all.

Yea, men bear them upon their shoulders, for they can not move from their places. They have no strength, they are helpless, worthless images carved in futility and must be borne.`},{align:"center",text:`Look how easily they are toppled

By the wind and broken in pieces,

When the earth is shaken but a little...`},{align:"center",text:"Says The Lord."}]},{id:"impotent-leaders",num:43,title:"Impotent Leaders",paragraphs:[{align:"center",text:`Do not put your trust in any man,

Though he speaks with a clever tongue,

With many enticing words of unity

And peace, and many great promises...`},{align:"center",text:`And though others bow down to him

And give him glory, you shall not

Place your trust in any man...`},{align:"center",text:"For man is but flesh..."},{align:"center",text:`Easily crushed beneath the weight

Of a single branch falling from a tree...`},{align:"center",text:"Says The Lord."}]},{id:"the-prince-of-peace",num:44,title:"The Prince of Peace",paragraphs:[{align:"center",text:`YahuShua HaMashiach

Is The Fulfillment of all things,

The Truth and Understanding you seek,

The Meaning of Life...`},{align:"center",text:`HE is The Bread which came down

From Heaven to feed those who hunger,

The Fountain of Living Waters for those

Who thirst, The Prince of Peace...`},{align:"center",text:`The ONLY Way, The ONLY Truth,

The ONLY Life...`},{align:"center",text:"Says The Lord God."}]},{id:"the-goal",num:45,title:"The Goal",paragraphs:[{align:"center",text:`The spirit of The Law is shown

In The Messiah\u2019s vesture, He being the

Same One who taught you The Law anew,

By His example and by His every word and deed...`},{align:"center",text:`For The Law is fulfilled in The Messiah;

Indeed, He is the goal at which the Torah aims {{ref:Romans 10:4}}...`},{align:"center",text:"Says The Lord God."}]},{id:"life-without-end",num:46,title:"Life Without End",paragraphs:[{align:"center",text:"My mercy endures forever..."},{align:"center",text:`And those who receive of My Mercy

Shall likewise endure, forever...`},{align:"center",text:"Says The Lord."}]},{id:"cherished",num:47,title:"Cherished",paragraphs:[{align:"center",text:"The works of men are evil, even from their youth..."},{align:"center",text:`Thus the little children shall be

My inheritance, and the babes My jewels...`},{align:"center",text:`For the innocent come forth as lights shining

Out of darkness, gifts born from the womb;

They are precious; to be cherished

Is every child in their youth...`},{align:"center",text:`For the innocent are of more value

Than gold and silver, prized

Above precious stones...`},{align:"center",text:"Says The Lord."}]},{id:"one",num:48,title:"ONE",paragraphs:[{align:"justify",text:`Give heed to My words and understand. For as I had spoken to My friends in times past, so now do I also speak to you. For the time has come and is coming and is already here, when all signs and wonders shall be made manifest, when all prophecy shall be fulfilled.
Rejoice, for your redemption draws near! And though the time of great sorrows has come in, hold fast, for these days shall be shortened... _No more pain, no more tears, no more death, all sorrows passing away, rebirth, a time of refreshing which shall never end._`},{align:"center",text:"Therefore, remember My words and have peace:"},{align:"center",text:`One God...



One Son, The Only Way to The Father...`},{align:"center",text:`One Truth, One Word, One Messiah, One Spirit;

One Food, One Bread and One Drink...`},{align:"center",text:"One Body..."},{align:"center",text:`Of which I am all,

The All in All...`},{align:"center",text:"Says The Lord."}]},{id:"take-your-fill",num:49,title:"Take Your Fill",paragraphs:[{align:"center",text:`Come and drink fully of that which is sweet;

Come and drink also of that which you perceive

To be bitter and very hard to swallow...`},{align:"center",text:"Ingest it fully..."},{align:"center",text:`For it too shall become sweet

When understanding comes...`},{align:"center",text:"Says The Lord."}]},{id:"more-than-the-asking",num:50,title:"More Than the Asking",paragraphs:[{align:"center",text:"Repentance is more than the asking..."},{align:"center",text:`It must come from a deep desire to be

Set free in My love, followed by a sincere

Unyielding commitment to make your

Love perfect through obedience...`},{align:"center",text:`The shedding of the skin

Of this world, the crucifying

Of your old man with his sinful ways...`},{align:"center",text:`The putting on of the new man

Who is renewed in the knowledge

Of The Holy One, conforming to the

Image of Him who created him {{ref:Colossians 3:9-10}}...`},{align:"center",text:"Says The Lord."}]},{id:"lead-by-example",num:51,title:"Lead by Example",paragraphs:[{align:"center",text:`Strive to walk as I walked, and they will see,

For every veil is lifted in Me...`},{align:"center",text:`Be steadfast and forthcoming;

Make honesty your companion

And integrity your close friend...`},{align:"center",text:`Lead by example, with quiet boldness

And steadfast trust, and they will begin to see...`},{align:"center",text:"Says The Lord."}]},{id:"a-shining-example",num:52,title:"A Shining Example",paragraphs:[{align:"center",text:`To abide in the doctrine of The Messiah

Is not mere proclamation or belief...`},{align:"center",text:`To abide in His doctrine is to LIVE by His words,

A shining example of righteousness,

Striving always to make your love

Perfect through obedience...`},{align:"center",text:`That those close to you, even to the passerby,

May see your good works and glorify

Your Father in Heaven...`},{align:"center",text:`_For it is written:

One does not live on bread and

Water alone, but by every word that

Comes from the mouth of God {{ref:Matthew 4:4}}..._`},{align:"center",text:`So then do not just give voice and preach,

But ABIDE in the doctrine of The Messiah...`},{align:"center",text:"By example shall you lead them..."},{align:"center",text:"Says The Lord."}]},{id:"let-the-law-be-written-in-your-heart",num:53,title:"Let The Law Be Written in Your Heart",paragraphs:[{align:"center",text:`I am the fulfillment of The Law,

The very goal at which the Torah aims...`},{align:"center",text:`Thus all those who embrace Me

Are freed from the curse of The Law,

But by no means are they now free

To forsake The Law...`},{align:"center",text:"Rather let The Law be written in your heart..."},{align:"center",text:`For now you are under grace,

And by the power of My own spirit

Are you now able to keep The Law...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"first-partakers",num:54,title:"First Partakers",paragraphs:[{align:"center",text:"God is just in everything..."},{align:"center",text:`And if The Father\u2019s justice is not partial,

Then it shall surely come to pass in these

Latter days, that those who have

Placed themselves first shall be last...`},{align:"center",text:`And those who were seen as last

Shall be first partakers of The Glory...`},{align:"center",text:"Says The Lord."}]},{id:"be-born-again",num:55,title:"Be Born Again",paragraphs:[{align:"center",text:"Repent in sincerity and in truth..."},{align:"center",text:`Return to your First Love,

Walk in the first works;

Embrace The Word of God anew,

Bringing forth works worthy of repentance...`},{align:"center",text:"That you may truly be born again..."},{align:"center",text:"Says The Lord."}]},{id:"a-continual-washing",num:56,title:"A Continual Washing",paragraphs:[{align:"justify",text:`I tell you a mystery: It has been appointed to those who are born twice to die once, but by no means shall they die a second time. Yet those who do not come to Me in repentance shall be born once and die twice. Yet there are some among this generation who shall never taste death, having already passed from judgment into life.

Thus to My chosen elect, there is a death of the body unto resurrection. Yet for those still living at My return, there is a death of another kind - _the crucifying of your old man with his sinful ways, the putting on of the new man who is renewed in the knowledge of the Truth, restored in the image of Him who created him. {{ref:Colossians 3:9-10}}_

Thus when one is born into this world, the child and the mother suffer the pangs of childbirth, until the birth is complete. In the same way, those born of the Spirit shall suffer travail. For they are not yet separated from their flesh or this world, in which they continually stumble.`},{align:"center",text:`So then, being born again is the process

By which you are restored in the image of God,

A continual washing, until you come into glory...`},{align:"center",text:"Says The Lord."}]},{id:"reborn",num:57,title:"Reborn",paragraphs:[{align:"center",text:`As a babe is born naked and wrapped in soft linens,

So also shall My people be reborn -

Naked, void of the things of this world,

Clothed in fine linens of white...`},{align:"center",text:`_Behold, the corruptible has put on incorruption,

And the mortal, immortality, as it is written {{ref:1 Corinthians 15:54}}..._`},{align:"center",text:"Says The Lord."}]},{id:"the-perfect-lamb",num:58,title:"The Perfect Lamb",paragraphs:[{align:"center",text:`I carried the weight of the world\u2019s sin to the cross,

And crucified sin through My suffering -

The penalty of sin abolished as I fell asleep,

The Victory established for all time upon My rising...`},{align:"center",text:`For I am and will always be The Perfect Lamb,

Without spot or blemish, given up for many...`},{align:"center",text:"The Restoration of All Things..."},{align:"center",text:"Says The Lord YahuShua."}]},{id:"one-source",num:59,title:"One Source",paragraphs:[{align:"center",text:"That which glorifies Me can have only one source..."},{align:"center",text:`And that which denies My sacrifice, as though it

Were not enough, steals from My glory,

And this also has one source...`},{align:"center",text:"Says The Lord."}]},{id:"i-shall-not-lose-one",num:60,title:"I Shall Not Lose One",paragraphs:[{align:"center",text:"I forgive all who return to Me..."},{align:"center",text:`Even the one in ninety-nine who goes astray;

Even the one among twelve who betrays Me...`},{align:"center",text:"For I am The Lord..."},{align:"center",text:`And of all those The Father

Has given Me, I shall not lose one...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"fear-not",num:61,title:"Fear Not",paragraphs:[{align:"justify",text:"Beloved, I know when each will come to Me, I know every trial and tribulation. Therefore, call on My name in this time of darkness, in this time of great calamity and fear. Hold fast through all these tears, endure in these times of trouble."},{align:"center",text:`Fear not, for I have overcome the world;

I hold the keys of death and Sheol,

And The Book of Life is held

Securely in My right hand...`},{align:"center",text:`No one can steal you from My love;

No one can pluck you from My hand;

No one can break off what I have grafted in...`},{align:"center",text:`For I know you as you are and as you will be,

With Me where I am...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"true-wisdom",num:62,title:"True Wisdom",paragraphs:[{align:"justify",text:`True wisdom is not of man, nor is it found in the earth, but from above - heavenly, holy. For that created was created according to the wisdom of Him who created it and by whom all things consist, knowing their form from the beginning.
_Therefore the fear of The Lord is indeed the beginning of wisdom, and the knowledge of The Holy One is understanding, as it is written. {{ref:Proverbs 9:10}}_ For apart from Me there is no knowledge, apart from Me all understanding passes away. For I AM HE, The Only Fountain from which flows all wisdom and knowledge, The Source of all things.`},{align:"center",text:`So then all who receive of Me grow wise,

Receiving of that which is pure,

Learning to walk in that which is eternal...`},{align:"center",text:`As one being led along a mountain stream

Of living waters, filled with a fervent

Desire to seek out its source...`},{align:"center",text:`Drinking from it along the way,

Gaining strength in weakness,

Leaving all behind in their holy pursuit...`},{align:"center",text:"Says The Lord."}]},{id:"the-only-truth",num:63,title:"The Only Truth",paragraphs:[{align:"center",text:"I AM..."},{align:"center",text:"And you are in life because of Me..."},{align:"center",text:`And all that is, even all these worlds

To every star you see in the heavens,

Was made according to the wisdom

Of The Father, brought forth and established

Through The Son, by whom all things consist...`},{align:"center",text:`For I AM, and have always been,

The Way and The Life, The Salvation of God,

The Only Truth from which all understanding flows...`},{align:"center",text:"YAHUSHUA-YAHUWAH."}]},{id:"faithful",num:64,title:"Faithful",paragraphs:[{align:"center",text:`One who truly loves Me speaks about Me,

And remains faithful at all times and in every season;

And one who places Me above all else has shown their

Loved ones who is first, and what faithfulness truly is...`},{align:"center",text:`For there is no true love apart from Me;

Nor can one remain faithful unless

They have received of Me...`},{align:"center",text:`Therefore to speak of Me in the

Company of others is to love them...`},{align:"center",text:`And to deny Me in the company of others

Is to hate them, whereby you have also

Revealed that your comfort is of more

Importance than The Truth, and keeping

The peace more important than their lives...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"patience-and-faith",num:65,title:"Patience and Faith",paragraphs:[{align:"justify",text:"What is the knowledge of man? Is it not a stone of stumbling? And the pride of man, a rock of offense? How then shall the blind see or the deaf hear, unless I heal them? Or how shall one grab hold of the line, unless it is first placed within their reach?"},{align:"center",text:"Yet My servants are wise..."},{align:"center",text:`They fear The Lord, and wait upon Me

With all patience and faith, doubting nothing,

Humble servants who study My Word, knowing

I am The Author and The Finisher thereof...`},{align:"center",text:"When they wake and when they lie down, I am there..."},{align:"center",text:"I am their life, and they are My joy..."},{align:"center",text:"Says The Lord."}]},{id:"impasse",num:66,title:"Impasse",paragraphs:[{align:"justify",text:`When My servants come to an impasse in My Word, according to their own understanding, what is their reaction? They continue on, without hindrance or doubt.

For their relationship with The Author is intimate, their trust without reservation. Thus they remain at peace, and wait upon The Lord for the light of understanding, knowing in their heart every word is true, ready to receive the spirit of the Word, stumbling not over its letter.

And until My people are established firmly upon this premise, they will remain daunted, striving to see but never fully understanding, straining to hear but remaining dull of hearing.`},{align:"center",text:`Thus for My wise and faithful servants,

All barriers are removed...`},{align:"center",text:`For their peace is in the knowing,

I AM WHO I AM, though they yet

Stand at the beginning, unable to see the end...`},{align:"center",text:`An heir of all I will reveal to them

When the fullness of time has come in...`},{align:"center",text:"Says The Lord."}]},{id:"be-joined-unto-me",num:67,title:"Be Joined Unto Me",paragraphs:[{align:"center",text:`I have called My people out, that they might

Come out from among them and be separate...`},{align:"center",text:`A people set apart for My name,

A people who keep The Commandments

And cease not from testifying to My glory,

A people of pure and undefiled faith...`},{align:"center",text:"A people joined unto ME..."},{align:"center",text:"Says The Lord YahuShua."}]},{id:"the-watchmen",num:68,title:"The Watchmen",paragraphs:[{align:"center",text:"Consider the squirrel and its ways..."},{align:"center",text:`Does it not live among the trees,

Running up and down with ease,

Leaping from branch to branch with skill and grace,

Perfectly designed for its abode and purpose?...`},{align:"center",text:"So shall My watchmen be in the Day of The Lord..."},{align:"center",text:`Prepared, according to their task;

Established, according to the Word of My mouth;

Filled, according to their service;

Remade, according to My purpose...`},{align:"center",text:"I AM THE LORD."}]},{id:"a-wise-and-faithful-servant",num:69,title:"A Wise and Faithful Servant",paragraphs:[{align:"center",text:"Who is a wise and faithful servant?..."},{align:"center",text:`Is he not one who receives the blessings

Of his Father without constraint, one who

Embraces My speech, whether soft or hard,

Even of that which I have spoken to another?...`},{align:"center",text:"A servant such as this is wise indeed..."},{align:"center",text:`_For he knows that every good gift

And every perfect gift is from above,

And comes down from The Father of Lights,

With whom there is no variation or

Shadow of turning, as it is written {{ref:James 1:17}}..._`},{align:"center",text:"Says The Lord."}]},{id:"mindfulness",num:70,title:"Mindfulness",paragraphs:[{align:"justify",text:"What is a son who is mindful of his father\u2019s ways, who pays close attention to his every word? Or a servant, who seeks only to serve his master? Or a faithful bride, who seeks always to please her husband in all her ways, whether he is near or far, in her presence or soon returning?"},{align:"center",text:`Beloved ones, be mindful of

These things and grow in wisdom,

Abide in trust and do not waver;

Be at peace...`},{align:"center",text:`For I am indeed coming quickly,

And My reward is with Me...`},{align:"center",text:"Says The Lord."}]},{id:"fixed-upon-the-goal",num:71,title:"Fixed Upon The Goal",paragraphs:[{align:"center",text:`Those who I have called out of a place

Shall in no wise return to it,

Nor shall they look back...`},{align:"center",text:`They shall continue on toward safety,

With their eyes fixed upon The Goal,

Walking always in line with the Spirit...`},{align:"center",text:`Praying without ceasing,

Giving heed to My leading,

Listening for My voice...`},{align:"center",text:"Says The Lord."}]},{id:"renewed",num:72,title:"Renewed",paragraphs:[{align:"center",text:`Only those who seek that which is first,

Who fill themselves up with that which

Is most needful, will finish the day

With strength enough to face tomorrow...`},{align:"center",text:`Therefore seek Me out at every opportunity,

Whether for a moment or for the hour,

That you may be renewed in My presence...`},{align:"center",text:`Looking always to The Blessed Hope,

Having tasted of it while in waiting...`},{align:"center",text:"Says The Lord."}]},{id:"history-has-an-end",num:73,title:"History Has an End",paragraphs:[{align:"center",text:"I AM COME..."},{align:"center",text:`The One who was has come;

The One who is, is come;

The One who is to come is coming

Quickly to fulfill and complete...`},{align:"center",text:"HISTORY HAS AN END!..."},{align:"center",text:`And His name is The Great I AM,

The Holy One of Israel!...`},{align:"center",text:"YAHUSHUA-YAHUWAH!..."},{align:"center",text:"Immanu El!"}]},{id:"i-am-enough",num:74,title:"I Am Enough",paragraphs:[{align:"center",text:`Beloved ones, you worry, yet I AM HE;

You weep, yet I AM HE;

You stumble, yet I AM HE;

Your hearts tear and break over

All these sorrows, yet I AM HE...`},{align:"center",text:`You struggle and are in turmoil,

You feel lost, yet I AM HE;

You grasp at the wind and have

No understanding, yet I AM HE...`},{align:"center",text:`You are persecuted by those

You love, yet I AM HE;

The world hates you, yet I AM HE;

Everything you have is passing away, yet I AM HE;

Death comes to take you into darkness, yet I AM HE!...`},{align:"center",text:`Do you not understand?! I AM ENOUGH!

The One who sees, The One who knows!

No matter the time or the season,

In every moment of your life, I AM HE!...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"choose",num:75,title:"Choose",paragraphs:[{align:"center",text:`Beloved, it is time to choose,

To make your decision...`},{align:"center",text:`It is time to bring your

Heart forward, and be healed,

To make your repentance full...`},{align:"center",text:`It is time to fall into Me unreservedly;

Or to depart, and walk through dry places...`},{align:"center",text:"Says The Lord."}]},{id:"gifts-of-the-spirit",num:76,title:"Gifts of the Spirit",paragraphs:[{align:"center",text:`I call My servants out from among them,

I appoint every office, and I Myself

Number their steps before them...`},{align:"center",text:`For My gifts are given through the Spirit,

And must also be received in Me...`},{align:"center",text:`They are in no wise open to claim,

Nor shall anyone on earth assign them...`},{align:"center",text:`For only those in union with

The Messiah are able to walk in them...`},{align:"center",text:"Says The Lord."}]},{id:"in-due-season",num:77,title:"In Due Season",paragraphs:[{align:"justify",text:`I have a great vineyard, with many grapes. I have provided both the early and latter rain and tended every vine, pruning them with sure hands and delicate fingers. Yet many wither, while others fail to produce, and still others are slow to ripen.

I have waited patiently and tended My vineyard, doing all that was necessary to produce a fair crop, and now it is time for harvest. Yet I tell you plainly, it shall be a very lowly crop, a very small harvest, for few have ripened to maturity. Thus they must be left to ripen in their season.`},{align:"center",text:`And though the winds shall be harsh

And the rains rare, behold, even all

Manner of plagues shall come,

I must not gather them

Until their due season...`},{align:"center",text:"Says The Lord."}]},{id:"lukewarm",num:78,title:"Lukewarm",paragraphs:[{align:"center",text:`One who treads the path, going up

And down, stepping on and off at

Their convenience, treads not the path,

But is like one who treads water...`},{align:"center",text:`By no means shall they be able

To keep their head above water,

Nor shall their strength deliver

Them in the Day of Troubles...`},{align:"center",text:"Says The Lord."}]},{id:"revived",num:79,title:"Revived",paragraphs:[{align:"center",text:`Behold, the day and hour is close at hand,

Yea it is very near, when the dead in Messiah

Shall arise and the sleepers shall awake,

When the rotting corpses are revived

And the dust gathers together once again...`},{align:"center",text:`From one end of the earth to the other,

Even from the deepest depths, shall My

People rise up and give Me glory...`},{align:"center",text:`Therefore let the children of Israel prepare,

Let everyone joined to Messiah step forward

And claim their inheritance...`},{align:"center",text:"For I have but to call out your name..."},{align:"center",text:"Says The Holy One of Israel."}]},{id:"the-gathering-up",num:80,title:"The Gathering Up",paragraphs:[{align:"center",text:`Behold, the Glory of God breaks through

The clouds, a mighty trumpet blast

Sounds in all the earth!...`},{align:"center",text:`From the heights of the mountains

To the deepest depths, life bursts forth

In the bodies of the dead!...`},{align:"center",text:`Behold, a loud voice is heard from Heaven:

_\u201CEARTH, GIVE UP YOUR DEAD!_

_BRIDE OF THE BLESSED,_

_COME UP HERE!\u201D..._`},{align:"center",text:"Says The Lord."}]},{id:"in-the-arms-of-the-king",num:81,title:"In the Arms of The King",paragraphs:[{align:"justify",text:"There is a place..."},{align:"justify",text:`A place beyond space and time, where eternity dwells and life has no end, where light takes its form and goodness is revealed, where the eyes of the redeemed may look upon the Glory of God and see His face, where Heaven meets the earth and The Eternal dwells with men...

A place where Everlasting Love can be embraced and healing flows like a gentle stream, a place where time has no meaning and the stars flee away, where the brightness is excellent and the warmth thereof very soothing...

A place where joy comes by knowledge with pure understanding, where fulfillment comes by a strong embrace, and love\u2019s completion is met with great satisfaction through many tears flowing down the cheeks of the forever young; a place where understanding bursts forth in realization, revelation beyond words!...`},{align:"center",text:`A place where the hearts of the chosen are revealed,

Behold, they are uncovered, revealing their true form;

The image in which I created them, restored...`},{align:"center",text:"A simple quiet place, set apart..."},{align:"center",text:"In the arms of The King."}]},{id:"the-creator",num:82,title:"The Creator",paragraphs:[{align:"center",text:`When I consider, all creation is before Me;

From the most minute detail to the greatest,

Nothing is hidden from My eyes...`},{align:"center",text:`Behold, the whole universe abides

Within My understanding...`},{align:"center",text:`For I am LORD and GOD,

Creator of Heaven and Earth.`}]},{id:"the-true-bride",num:83,title:"The True Bride",paragraphs:[{align:"center",text:"The Bride is chosen..."},{align:"center",text:`My blood runs through her veins,

My image is shown upon her face...`},{align:"center",text:`Behold, the light of My coming is reflected

In her eyes, for I have captured her gaze,

And she will by no means look away

Or seek after another...`},{align:"center",text:"Says The Lord."}]},{id:"heed-my-words",num:84,title:"Heed My Words",paragraphs:[{align:"justify",text:"Beloved ones, wait upon Me, with all trust and fear; stand steadfast and be patient. Accept My words, as I have spoken them and as they are written. Do not add to My words, nor take from them; neither form for yourselves any private interpretation. Only give heed to My words and also do them, and prepare."},{align:"center",text:`For My words are indeed that light which

Shines in a dark place, a lamp and a beacon,

Preparing My way before Me...`},{align:"center",text:`Until the new day dawns and

The Morning Star rises, filling the hearts

Of My chosen as they enter in...`},{align:"center",text:"Says The Lord."}]},{id:"followers-of-the-way",num:85,title:"Followers of The Way",paragraphs:[{align:"center",text:`When those who call of

Themselves Christian, ask you,

_\u201CTo which church do you belong?\u201D..._`},{align:"center",text:`You shall answer them:

_\u201CI belong to no church named of men._

_I belong to The Lord, YahuShua HaMashiach,_

_Whom you call Jesus and Christ._

_And together with all those who_

_Remain in His love {{ref:John 15:10}} and obey His voice {{ref:John 3:36}}_

_Is The Church in which I dwell\u201D..._`},{align:"center",text:"Says The Lord."}]},{id:"true-baptism",num:86,title:"True Baptism",paragraphs:[{align:"center",text:`Let My beloved first be baptized

In spirit and in truth, filled

With the knowledge of The Holy,

Nourished by the Word of Truth...`},{align:"center",text:`Let them come to Me in sincere

Repentance, and receive forgiveness

Of sins in The Messiah\u2019s name...`},{align:"center",text:`All burdens lifted, immersed

And purified in the Spirit of God...`},{align:"center",text:`For The Holy One of Israel is

He who baptizes with the Holy Spirit

And with fire, and He knows His own...`},{align:"center",text:"Says The Lord."}]},{id:"the-beginning-of-wisdom",num:87,title:"The Beginning of Wisdom",paragraphs:[{align:"justify",text:`Come together and reason, O sons of men. Look upon the works of My hands, and see with new eyes and restored vision, that you may behold the Truth.

For all the works of man are here for but a moment, then quickly pass away. And that which remains, shall it not become fuel for the fire in the Day of The Lord\u2019s Anger? And the knowledge of man, is it not foolishness in My eyes, coming to nothing before the light of My Glory?`},{align:"center",text:`Therefore fear The Lord your God,

And accept the truth of who I am...`},{align:"center",text:`_For the fear of The Lord is the beginning_

_Of wisdom, and the knowledge_

_Of The Holy One is understanding {{ref:Proverbs 9:10}}..._`},{align:"center",text:"For I am God alone."}]},{id:"remember-the-sabbath",num:88,title:"Remember the Sabbath",paragraphs:[{align:"justify",text:`Those who remember the Sabbath honor Me, and those who rest on the Sabbath rest in Me, as they look to the Day. For I had set the seventh day apart, and sanctified it, from the beginning. {{ref:Genesis 2:3}} Thus it has been a sign between Me and My people, even to this day, and so shall it remain forever.

For as I spoke to the children of Israel, saying, _\u201CSurely My Sabbaths you shall keep, for it is a sign between Me and you throughout your generations, that you may know that I am The Lord who sanctifies you,\u201D{{ref:Exodus 31:13}}_ so also do I speak to you, even to all who are grafted in.`},{align:"center",text:`For those who obey My Commandments

Remain in My love {{ref:John 15:10}}, and those who remember

My Sabbaths keep My company,

For The Holy One of Israel

Dwells in the midst of them...`},{align:"center",text:`For I long for My children to be with Me

Where I am, I am eager to return them

To the Garden, that we may once again

Walk together in the cool of the day.`},{align:"justify",text:`Therefore remember the Sabbath, and I shall remember you. Bless the Sabbath, and I shall bless you. Love one another, as I have loved you.

Put away your works, look not to the cares of this world, and let go of your worries on the Sabbath day; spare yourselves the weight of all these troubles for just one day.`},{align:"center",text:`Let all your thoughts dwell upon

Your God and Savior, and consider;

Yea, let your mind be filled with wonder

And awe over the works of My hands...`},{align:"center",text:`For even The Lord your God,

Creator of Heaven and Earth,

Rested on the seventh day {{ref:Genesis 2:3}}...`},{align:"center",text:"Says The Lord."}]},{id:"prepare-and-watch",num:89,title:"Prepare and Watch",paragraphs:[{align:"justify",text:`I am indeed coming down to shake the heavens and the earth, to move all from its place; to bring forth that which was hidden and to reveal that which was misplaced; to open that which was shut and to shut that which was opened.

Therefore prepare, My people, for the time has come; yes, today is the day of salvation! Go forth, beloved ones, and set all these crooked paths straight; regain the line, prepare and watch. For the leaves of the fig tree are upon its branches; summer is near! {{ref:Matthew 24:32-34}}`},{align:"center",text:"Again I say, watch!..."},{align:"center",text:`For The One who ascended

Is about to descend...`},{align:"center",text:`_And lo, I am come, in the Volume_

_Of the Book it is written of Me,_

_To accomplish The Father\u2019s will {{ref:Psalm 40:7-8}} \xB7 {{ref:Hebrews 10:7}}..._`},{align:"center",text:"Says The Lord."}]},{id:"the-first-harvest",num:90,title:"The First Harvest",paragraphs:[{align:"center",text:`It is written, _all shall lie down in death {{ref:Ecclesiastes 9:2-3}}..._



Yet there is a people who shall not sleep,

Nor shall they lie down in death -
A people who shall be awake at My coming,

A people who have received of the divine gift,

A people who know Me and in whom I am known,

For I see of Myself within them.`},{align:"center",text:`They shall be lifted up, not preceding

Those who have fallen asleep in Messiah;

This is the first harvest and resurrection.`},{align:"center",text:`For there is but One Way, One Truth, and One Life;

From the beginning, there is but One...`},{align:"center",text:"I AM HE..."},{align:"center",text:"Says The Lord YahuShua."}]},{id:"to-all-those-who-call-of-themselves-christian",num:91,title:"To All Those Who Call of Themselves Christian",paragraphs:[{align:"center",text:`Listen closely

And take My words to heart,

All you who call of yourselves Christian:

I ask you, do you really love Me?...`},{align:"center",text:"Then follow Me..."},{align:"center",text:`Beloved ones, listen closely

And take My words to heart,

All you who call of yourselves Christian:

Do you really love Me?...`},{align:"center",text:"Then obey My Word! Follow Me!..."},{align:"center",text:`Beloved, listen closely

And take My words to heart,

All you who call of yourselves Christian:

Do you really love Me?!...`},{align:"center",text:`Then heed My voice and come out!

FOLLOW ME!...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"bear-fruit",num:92,title:"Bear Fruit",paragraphs:[{align:"justify",text:"Beloved, bear fruit after the kind I have given you, in open and in secret. For what profit is there in sharing with another that which they believe they already have? And how shall one who pushes out the hand receive a gift?"},{align:"center",text:`Therefore, turn aside from those who

Push out the hand and wag the head...`},{align:"center",text:"Rather seek out the poor, that I may feed them..."},{align:"center",text:`Fill the bowls of the hungry, and place

The cup in the hands of the thirsty;

Give them your portion...`},{align:"center",text:`For My bounty is plentiful,

Given freely to all who hunger

And thirst for righteousness...`},{align:"center",text:"Says The Lord."}]},{id:"the-spirit-of-god",num:93,title:"The Spirit of God",paragraphs:[{align:"justify",text:"Beloved ones, pray to your Father in Heaven, in The Son\u2019s name, and through the Spirit we shall be one. For all My servants move, speak and hear Me through My spirit, and only through The Son shall My children come to know Me as I truly am... _And oh how blessed are those who know Him, for they love Him and obey His voice, having truly received of Him, even of His spirit, the Spirit of God._"},{align:"center",text:`Indeed holy, holy, holy

Is The Lord God Almighty...`},{align:"center",text:`One God, invisible and visible,

The Father and The Son;

And the Spirit called Holy,

Because I am holy...`},{align:"center",text:"Says The Lord."}]},{id:"it-is-time",num:94,title:"It Is Time",paragraphs:[{align:"justify",text:"Behold, the time has come for My name to resound in all the earth, for all who dwell upon the earth to be humbled, to be broken without hand. Indeed, now is the time for all who have ears to hear, to hear and give heed; and for those who refuse, to forbear and rebel against Me."},{align:"center",text:`It is time for My servants to stand up,

To receive My words and also do them;

It is time to blow the trumpet, to sound the alarm...`},{align:"center",text:`It is time for My spirit to be poured out,

For the hand of The Almighty to stir up

The multitudes, for The Word of God

To separate and divide the people...`},{align:"center",text:`It is time for My watchmen to proclaim

The acceptable year of The Lord and the

Day of Vengeance of The Lord their God...`},{align:"center",text:`For the ears of the first election are open,

And within My prophets I have placed

My voice, once again; I have surely

Put My words in their mouths...`},{align:"center",text:"For I am The Lord, and I do not change."}]},{id:"the-spirit-of-the-word",num:95,title:"The Spirit of the Word",paragraphs:[{align:"justify",text:"Do not judge according to human standards, nor by that which is put forth by men as doctrine, for they are greatly misled. _Rather study to show yourself approved unto God, a workman that need not be ashamed, rightly dividing the Word of Truth. {{ref:2 Timothy 2:15}}_ For discernment with fear is righteousness."},{align:"center",text:`Therefore, beloved, remember:

The spirit of the Word, and not the letter,

Is the way, the truth and the life...`},{align:"center",text:`For The Messiah is indeed coming quickly,

To baptize all in fire and glory...`},{align:"center",text:"Those of a wicked heart, in fire..."},{align:"center",text:`And those of the Spirit,

In glory, forever and ever!...`},{align:"center",text:"Says The Lord."}]},{id:"inheritance",num:96,title:"Inheritance",paragraphs:[{align:"center",text:`Behold, My people are afflicted,

And My faithful ones are persecuted,

Imprisoned and put to death!

My little ones are brought to harm,

And the innocent are murdered in droves,

CAST OFF AS REFUSE!...`},{align:"center",text:`Therefore the afflicted shall be

Given wealth beyond imagining,

And the meek shall inherit the earth;

The little ones shall be taken,

And the innocent shall return home...`},{align:"center",text:`And they shall be My sons and daughters,

Forever, life without end...`},{align:"center",text:"Says The Lord."}]},{id:"restoration",num:97,title:"Restoration",paragraphs:[{align:"center",text:"I AM THE RESURRECTION AND THE LIFE!..."},{align:"center",text:`And all who believe in Me shall not die, but live,

For I shall raise them up at the Last Day!...`},{align:"center",text:`No more tears, no more death, no more pain,

For the old order of things has passed away;

All things restored in glory, the glory of everlasting life!...`},{align:"center",text:"I AM RISEN! YOUR REDEEMER LIVES!..."},{align:"center",text:"Says The Holy One of Israel."}]},{id:"call-upon-the-name",num:98,title:"Call Upon The Name",paragraphs:[{align:"justify",text:"The wicked shall surely fall by the word of their own mouth, and by their works shall they stumble into the pit; behold, by their every word and deed have they condemned themselves to death."},{align:"center",text:`Yet if these same ones turn from their

Iniquity, and call upon Me in the name

Of The Messiah, they shall live and not die;

They shall surely be delivered!...`},{align:"center",text:`For they have called upon The Name,

The only name under Heaven

By which you must be saved...`},{align:"center",text:"For He is called Jesus and Christ..."},{align:"center",text:`His name: YAHUSHUA HAMASHIACH,

Both Lord and Savior of men...`},{align:"center",text:"Says YAHUWAH."}]},{id:"all-shall-be-fulfilled",num:99,title:"All Shall Be Fulfilled",paragraphs:[{align:"justify",text:`As I have commanded it, so shall it be done. As I have spoken it, so shall it come to pass. As I have purposed it, so shall it be accomplished. For My glory, all shall be fulfilled.

Thus that which I have spoken by My prophets shall surely be. And though they stumble, they shall by no means fall, for they do continually humble themselves before Me.`},{align:"center",text:`Therefore, blessed is the man who comes

To Me ashamed of his trespasses, whose heart

Is full of grief on account of his sins,

For I am faithful to forgive his sins...`},{align:"center",text:`Indeed I shall lift him up,

And set his feet upon hallowed ground...`},{align:"center",text:"Says The Lord."}]},{id:"daily-bread",num:100,title:"Daily Bread",paragraphs:[{align:"justify",text:`Understand the Word of My mouth and that which is set before you, even upon each of your plates: I have bore you, even twice have you come forth - First by water and blood in the flesh, and a second time in the Spirit, yea even a third time when you shall come into glory.

And behold, that which is first sown in your hearts is The Living Word. And that which grows from Me bears fruit, according to the food and drink I provide, the written Word. Therefore both are necessary, yet one must be first.`},{align:"center",text:`Yet understand this:

One who is awakened can not remain so,

Unless they receive of Me and also

Eat of that which I provide...`},{align:"center",text:`Therefore abide in Me,

And partake daily of My supper...`},{align:"center",text:"Says The Lord."}]},{id:"true-knowledge",num:101,title:"True Knowledge",paragraphs:[{align:"justify",text:`Who among you has committed no murder, whether in heart or in action? Who among you has committed no adultery, whether in heart or in action? Who among you, O peoples of the earth, has committed no sin?!

Behold, all have fallen short of the Glory of God, all have failed utterly in their attempts to gain righteousness; even the works of the most righteous among you are but filthy rags before Me. And for this reason did I come into the world, manifest in the flesh, to bear the full weight of the sin of this world - Immanu El.`},{align:"center",text:`Therefore get wisdom, get understanding,

And seek My face in sincerity and in truth...`},{align:"center",text:`Humble yourselves,

That you may receive true knowledge,

That you may come to know Me as I truly am...`},{align:"center",text:"Says The Lord."}]},{id:"one-fold",num:102,title:"One Fold",paragraphs:[{align:"justify",text:`Where does a shepherd spend his time, and which of his sheep require the most attention? Therefore pray in like manner. For indeed the ill of the flock require the most attention, and the one in ninety-nine who has gone astray shall by no means be forsaken.

And though there are many who stand inside locked gates, while you stand outside, do you not remain all of one fold? And when I have freed them, will you not all rejoice together? Therefore treat them as such, and pray for them, even double, and it shall be well with you. For those who arrive last shall be embraced by those who had arrived first.`},{align:"center",text:`Therefore let your heart remember,

As you look to the day...`},{align:"center",text:"Says The Lord."}]},{id:"mercy",num:103,title:"Mercy",paragraphs:[{align:"justify",text:"Hear and understand the loving mercies of God fulfilled in Me, even of those bitter tears which I have shed over all these who deny Me, over all these who betray Me by all they say and do: Beloved, in My anger I have indeed cast them out, appointing others to run in their stead. Yet I tell you the truth, though they now abide as one sitting along the wayside, they are in no wise broken off. For our bond is love, and any bond forged in My love can never be broken."},{align:"center",text:`Behold, even amongst My flock

Have I received many kisses

After the kind of My son, Judas...`},{align:"center",text:`Yet I tell you the truth, I have

Never lost one who is Mine;

I am in love with My own...`},{align:"center",text:`And though their thoughts betray

Them, having given heed to many lies

And deceptions from within and without,

I know My own, and I will never turn

Away anyone who returns to Me...`},{align:"center",text:"Says The Lord."}]},{id:"peace",num:104,title:"Peace",paragraphs:[{align:"justify",text:`My sons and daughters, from the beginning, I AM WHO I AM and shall be. Even to the end, I AM HE. From everlasting to everlasting, I AM. In this shall you find rest and know peace, says The Lord.

Therefore no longer bind yourselves to what you see, nor concern yourselves with the things of this world and its evil ways. Free yourselves by the knowledge I have given you, by the understanding that I AM WHO I AM, freedom in the knowing I AM HE.`},{align:"center",text:`Beloved ones, I have defeated the world,

I have overcome your sins;

Death is put to death because of Me...`},{align:"center",text:"Behold, I am risen, death is turned backward..."},{align:"center",text:"Only life is and shall be..."},{align:"center",text:"Says The Lord."}]},{id:"refuge",num:105,title:"Refuge",paragraphs:[{align:"center",text:`Beloved, there is but One Refuge,

Only One Way to be found...`},{align:"center",text:`In Mashiach ONLY shall you find

Refuge from all these troubles;

Through Him ONLY have I opened The Way...`},{align:"center",text:`Therefore, My people, call upon the name

Of The Lord in your darkest hour!...`},{align:"center",text:`For it is time for the name of mercy

And pure righteousness to be glorified!

It is time for God\u2019s Salvation to be revealed

To the first election, for the supplications

Of His people to be fulfilled to the fullest!...`},{align:"center",text:"LET THEM BE DELIVERED!..."},{align:"center",text:"Says The Lord."}]},{id:"the-power-of-my-love",num:106,title:"The Power of My Love",paragraphs:[{align:"justify",text:"How long shall the multitudes swear by things made, and place their trust in the works of man?! For the desolate know not the things of God, nor is darkness able to understand; yea, the wicked gnash upon their teeth, the whole body convulses in the wake of mourning, for there is no rest."},{align:"center",text:`Yet My hand caresses the cheeks of the hopeless,

As we watch the dawning of the day together...`},{align:"center",text:`For the strength of My arm uplifts the downtrodden,

My strong embrace heals the sorrowful,

Every beat of My heart revives the dead,

And the sound of My voice frees every captive...`},{align:"center",text:"Behold, the power of My love hides them away!..."},{align:"center",text:"Says The Lord."}]},{id:"the-will-of-god",num:107,title:"The Will of God",paragraphs:[{align:"center",text:`Nothing, nothing in all creation,

Can usurp the will of The Most High God!

Nor shall any run out ahead of Me...`},{align:"center",text:"MY will shall be done on earth as it is in Heaven..."},{align:"center",text:`For it is purposed and can not be moved,

Having been written in everlasting stone

From the very foundation of the world...`},{align:"center",text:"I AM THE LORD."}]},{id:"made-for-the-son",num:108,title:"Made For The Son",paragraphs:[{align:"center",text:`You are and were created in fragile flesh,

Beautifully crafted by the hand of your Father,

Having been made alive in The Son...`},{align:"center",text:`In His image you are and were created,

In love I created you, placing you

In the garden to My own joy...`},{align:"center",text:"My own beloved who have received of My breath..."},{align:"center",text:"Created by The Father, made for The Son..."},{align:"center",text:"Says The Lord."}]},{id:"across-all-boundaries",num:109,title:"Across All Boundaries",paragraphs:[{align:"center",text:`That atoned for by My blood

Is far-reaching, even across all boundaries,

Life and death, time and space...`},{align:"center",text:`For even those before Me were after Me,

And knew The Father, who knowing Him

Knew and saw the time of My coming,

Having repented before The Father

In His name, which is also My name,

The name We shared before the world was made...`},{align:"center",text:`Thus by the heart is one judged,

Of which I know, for nothing is hidden before Me;

I made you and know you, having always known you;

Even those who will yet come to Me, I see and know...`},{align:"center",text:`For I see you as you are and will be,

With Me where I am...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"the-way-is-provided",num:110,title:"The Way Is Provided",paragraphs:[{align:"center",text:`Come now and share in My joy,

Abide in My love, enter into My rest...`},{align:"center",text:`For The Way is provided, The Lamb sacrificed,

My own beating heart stilled in death,

My own blood poured out

So you may return to Me...`},{align:"center",text:`The curtain is torn; the way is open!

Approach and draw near to Me; hear Me calling!...`},{align:"center",text:`For The Ladder of Heaven is joined to earth,

Glorified and named above all names!...`},{align:"center",text:"Says The Lord."}]},{id:"the-tame-of-my-flock",num:111,title:"The Tame of My Flock",paragraphs:[{align:"justify",text:`All who truly receive of Me know Me, and I live in them. And if I live in them, then in no wise will these turn away. For one who abides in My love shall never leave it.

For they have tasted of the divine gift and have looked upon My glory. They will not depart from Me, but rest securely at My right hand. These are My sheep, the tame of My flock. They call out and I do hear them, even as I had called to them and they did hear.`},{align:"center",text:`All My sheep hear My voice

And know the sound of My voice,

And seek to follow Me wheresoever I lead them...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"for-my-own-name-s-sake",num:112,title:"For My Own Name\u2019s Sake",paragraphs:[{align:"center",text:`Behold, My own people go the way

Of the ungodly, following after those void

Of the Spirit, married to this world!...`},{align:"center",text:`Yet I shall save them out of all their troubles;

For My own name\u2019s sake will I do it...`},{align:"center",text:`For the sake of Judah, I shall cover them;

For the sake of Jacob, I shall hold them in safety;

And for the sake of David, My servant, I shall

Shelter them under the shadow of My wings...`},{align:"center",text:"Says The Lord."}]},{id:"keeping-the-law",num:113,title:"Keeping The Law",paragraphs:[{align:"center",text:`Say no more, _\u201CGrace versus The Law.\u201D_

Say rather, _\u201CGrace AND The Law\u201D_...`},{align:"center",text:`For Grace is the fulfillment of The Law;

And where there is an absence of grace,

There is lawlessness...`},{align:"center",text:`Therefore, keeping The Law

Is a reflection of My own spirit in you...`},{align:"center",text:`And oh how blessed are those who have

Received of Grace, and seek to please The Father

By obeying His Law, and teach men so...`},{align:"center",text:"Grace AND The Law..."},{align:"center",text:"Says The Lord."}]},{id:"nothing-is-hidden-before-me",num:114,title:"Nothing Is Hidden Before Me",paragraphs:[{align:"justify",text:"Nothing exists outside of Me, says The Lord; neither does anything continue outside My will. For even the evil of this present world is set within the confines of My will. For evil acts and brings forth of its own, yet is unaware that nothing is hidden before Me; neither has anything come to pass, nor will be, that I have not already beheld. And this, O arrogant and deceived generation, is why I said, _\u201CAll was written and completed, even before the foundation of the world.\u201D_"},{align:"center",text:`For I am God, THE GOD!

The God of Abraham, The God of Isaac,
The God of Jacob, The God of all!...`},{align:"center",text:`Even of all that is known and unknown,

The Creator of all things...`},{align:"center",text:`The Everlasting, who is from

Everlasting to everlasting...`},{align:"center",text:"I AM."}]},{id:"not-by-human-means",num:115,title:"Not By Human Means",paragraphs:[{align:"center",text:`What I have prepared can not be seen

With the eyes, nor can it be attained

By human means or mere proclamation...`},{align:"center",text:`Yet within the hearts of My own

It is clearly seen, and upon the lips

Of My bride the testimony is clearly heard...`},{align:"center",text:`For that which has entered into the hearts

Of the chosen shall soon be realized,

And that which has entered into the hearts

Of the wicked shall return upon their own heads...`},{align:"center",text:"For hate brings forth suffering and violence..."},{align:"center",text:`Yet the love of The Messiah brings salvation,

Escape under the shadow of His healing wings!...`},{align:"center",text:"Says The Lord."}]},{id:"according-to-the-number",num:116,title:"According to the Number",paragraphs:[{align:"center",text:"I am The Lord..."},{align:"center",text:`And though I bruise, I will surely heal;

And though I pour out strong judgment,

I will also show mercy...`},{align:"center",text:`For all appointed to captivity shall go into captivity,

Yet I will deliver them, even all who call on the

Name of The Lord in that day...`},{align:"center",text:`And though many will be brought low,

Even down to the depths of darkness and despair,

Behold, from the depths I shall raise

Them up, even high above the heavens;

Even from the ashes shall I bring them forth,

And they shall give Me perfect praise in the

Tabernacle of My glory!...`},{align:"center",text:`And so it is fulfilled, and shall also come to pass:

The first shall be last, and the last

Shall be first partakers of the glory;

Yet all will be saved according

To the number The Lord shall call...`},{align:"center",text:"Says The Lord."}]},{id:"the-bride",num:117,title:"The Bride",paragraphs:[{align:"center",text:`The true bride is chosen;

She has been called out and shall be lifted up!...`},{align:"center",text:`Behold, I will come for her and she will be taken,

Caught up to My Father\u2019s house for one week

In The Lord, and we shall be together forever...`},{align:"center",text:"All tears wiped away..."},{align:"center",text:`Even every tear she shed on the behalf of others;

Every tear she shed for the afflicted and the unborn;

Every tear she shed over all this evil,

On account of all this oppression and death...`},{align:"center",text:`Even every tear she shed in repentance,

In seeking after her Bridegroom...`},{align:"center",text:"Says The Lord."}]},{id:"reverence",num:118,title:"Reverence",paragraphs:[{align:"justify",text:"Peoples of the earth, do you know Me? Do you really know who I am? I am Elohim. YAHUSHUA-YAHUWAH is My name, both God and Savior. For in The Son does the fullness of The Father dwell..."},{align:"justify",text:"Yet I ask you, who among the nations fears Me? Who among this modern generation, among all these multitudes of perverse and vile people, revere My name? Who, among this great multitude, trembles in fear at the coming of The Lord?! And who among the mighty shall be able to stand, when the wrath of God is revealed from Heaven?!"},{align:"center",text:`Therefore repent, and establish My way before Me,

Says The Lord God, and I shall also establish you...`},{align:"center",text:`For I am The Lord, and I shall

Establish justice in all the earth.`}]},{id:"indwelt",num:119,title:"Indwelt",paragraphs:[{align:"center",text:`Who has given heed to the voice

Of The Lord their God?

Who has come out to meet Me?...`},{align:"center",text:`Behold, the lowly have come out,

The poor in spirit have come forth,

The broken have sought Me and

The faithful uphold My cause...`},{align:"center",text:`Yes, these who carry The Messiah

Within them have come forward to

Partake of My supper, and do follow

The Lamb wheresoever He leads them...`},{align:"center",text:`And behold, the day is near when He shall

Call out to His beloved, and all those who

Have ears to hear will be lifted up;

They shall surely be gone from this place!...`},{align:"center",text:"Says The Lord."}]},{id:"blessed-be-the-name",num:120,title:"Blessed Be The Name",paragraphs:[{align:"center",text:`Behold, My name alone stands throughout

The generations, a perpetual covering for My people,

A secure place of shelter for all those who seek My face,

A tower of strength for all who take refuge in Me...



From everlasting, I AM, and to everlasting shall I be,

The same and unchanging, even as My name...`},{align:"center",text:"For I AM WHO I AM..."},{align:"center",text:`YAHUWAH, The One who causes to be;

YAHUSHUA, He by whom all things

Consist and have life...`},{align:"center",text:`Thus My name is one, even as

The Father and The Son are one,

A just God and a Savior - ONE...`},{align:"center",text:"Says The Lord."}]},{id:"the-holy-days",num:121,title:"The Holy Days",paragraphs:[{align:"center",text:`The significance of The Holy Days is found

In their meaning and revealed by their order...`},{align:"center",text:`Even as all find their fulfillment in The Messiah

And their completion in the coming of The Lord...`},{align:"center",text:"Says The Lord."}]},{id:"set-apart",num:122,title:"Set Apart",paragraphs:[{align:"center",text:`Beloved, stand apart from

This world in word and by deed;

Take your every thought captive

That you may be fully set apart...`},{align:"center",text:`Reveal your love for Me by all you say

And do; put your love on open display!...`},{align:"center",text:`Rest in Me on the Sabbath Day

And receive My blessing;

Honor My Holy Days and remember,

That you may also understand;

Hold fast to The Holy Covenant,

And no longer depart from

The Word of My Commandment...`},{align:"center",text:"Says The Lord."}]},{id:"beloved-awake",num:123,title:"Beloved, Awake",paragraphs:[{align:"center",text:`Beloved, awake! Awake from your slumber!

Awaken your hearts to The Majesty on High!

Embrace the full revelation of

WHO I AM, of all I have done!...`},{align:"center",text:`For the Word of The Lord

Flows like water, My love runs pure...`},{align:"center",text:`Therefore embrace My words and receive

Of My love, that you may be filled with My spirit,

To the bearing of much fruit in The Beloved...`},{align:"center",text:"Says The Lord."}]},{id:"penitent",num:124,title:"Penitent",paragraphs:[{align:"center",text:`It is the penitent man who shall know God,

And penitent you must be; die to yourselves daily...`},{align:"center",text:`Cast off the skin of this world and walk with

Me as I am, and not as you would have Me be...`},{align:"center",text:`Beloved, cast off your sins, depart quickly from

Temptation, and to the accuser turn a deaf ear;

For I tell you the truth, evil has lost

Its grip on the redeemed...`},{align:"center",text:`Therefore hear My words, and also do them;

Give heed to My speech, and embrace

All I have given you...`},{align:"center",text:`Drink deeply from this cup,

And be created anew...`},{align:"center",text:"Says The Lord your Redeemer."}]},{id:"the-god-of-justice",num:125,title:"The God of Justice",paragraphs:[{align:"center",text:"I am The Lord..."},{align:"center",text:`I know what is most needful,

I alone do what is right...`},{align:"center",text:`And though I afflict, I will also heal;

And though I strike the people in My wrath,

I will also bind up their wounds...`},{align:"center",text:`Behold, I shall bring the kingdoms

Of men to utter ruin, and make

The face of the earth a desolation;

For I AM HE who shall create new heavens

And a new earth, in which justice shall

Run down like water and righteousness

Like an ever-flowing stream...`},{align:"center",text:`For as I have spoken, so I speak;

As I am, so shall I be...`},{align:"center",text:`Says The King of Power and Glory,

The Only Lord of Hosts, The Holy One of Israel.`}]},{id:"spare-the-rod",num:126,title:"Spare the Rod",paragraphs:[{align:"justify",text:`You have heard it said, to spare the rod is to hate your child. This Scripture is true. Yet I tell you the truth, the rod is discipline, and not that of physical punishment.

O vain and ignorant people, stop perverting the Scriptures of Truth! Humble yourselves, that you may gain wisdom. A child\u2019s disobedience is brought forth from a troubled heart and an unsettled spirit, wrought in ignorance. How then shall a beating correct the heart, or striking them with a rod bring about a right spirit?`},{align:"center",text:`Beloved, do not exasperate your children

By bringing them into subjection by abuse...`},{align:"center",text:`Rather take them by the hand, and lead

Them in the ways of The Lord, with love...`},{align:"center",text:`For the love of a father is displayed in

Tenderness and kindness, and is also

Revealed through the correction and

Discipline of those he loves...`},{align:"center",text:"Says The Lord."}]},{id:"the-seed-and-the-sower",num:127,title:"The Seed and The Sower",paragraphs:[{align:"justify",text:"Beloved, you must ask yourselves, \u201CWhere have all these seeds been sown? Have they taken root? Or are they choked by the multitude of weeds which have sprung up?\u201D Beware, for the birds gather, and wait eagerly to devour all seeds which have fallen by the wayside."},{align:"center",text:`Thus only that which is first shall bear fruit;

For that which is foremost bears fruit

According to the Seed and

The One who has sown it...`},{align:"center",text:`Yet that which is put first by men, which is

Not of the Seed nor of The Sower, must die;

It must be uprooted and cast into the fire...`},{align:"center",text:"Says The Lord."}]},{id:"true-forgiveness",num:128,title:"True Forgiveness",paragraphs:[{align:"justify",text:"Begin again in Me, says The Lord, for I have not left you. Behold, I am with you, even to the end of this age."},{align:"justify",text:"Beloved, you are forgiven. And in true forgiveness, there is no remembrance of past offenses; behold, even your sins of tomorrow are washed away. Therefore fix your gaze upon Me, focus not on your sin; give temptation no power, and to the accuser turn a deaf ear."},{align:"center",text:`Indeed, come all who struggle and are

Heavy-laden, and I will give you rest...`},{align:"center",text:`Take My yoke upon you and learn from Me,

For I am gentle and lowly in heart,

And in Me you will find rest for your souls...`},{align:"center",text:`For My yoke is easy, and My burden light, {{ref:Matthew 11:28-30}}

For all those who trust in Me...`},{align:"center",text:"Says The Lord."}]},{id:"the-fear-of-the-lord",num:129,title:"The Fear of The Lord",paragraphs:[{align:"justify",text:`It is written: _The fear of The Lord is the beginning of wisdom, and knowledge of The Holy One is understanding. {{ref:Proverbs 9:10}}_

Therefore all else is vanity, a false way, leading to great vexation of spirit. For I AM THE LORD. From the beginning it was I who had done it; even to the end shall I perform it; and behold, all is fulfilled according to My will.`},{align:"center",text:`Therefore to fear The Lord your God

Is indeed the beginning of wisdom...`},{align:"center",text:`For how can one know Me,

Unless they first acknowledge Me?

And how can one fear Me, unless they

Believe, I AM WHO I AM?...`},{align:"center",text:`He who causes to be,

He who called all things into existence,

The Creator of Heaven and Earth...`},{align:"center",text:"Says The Lord."}]},{id:"the-living-bread",num:130,title:"The Living Bread",paragraphs:[{align:"justify",text:`Have I not provided a bounty? Have I not poured out and sent forth the call? Therefore let those who have come out abide in Me until the time, and eat also of this bread. For I shall be with them, yes, even I Myself shall be with them, close at hand, and they shall fellowship with Me in the secret place. They have all they need.

Yet let those who reject Me and My Word, even this blessing which I have given to this generation, walk through dry places. For I have left them desolate. And so they must walk, they must tread the path they have chosen, until the time be changed, until they are broken without hand. I AM THE LORD.`},{align:"center",text:`Therefore, again I say,

To all those who have ears to hear:

Seek not the table, but He who sits at it...`},{align:"center",text:"Says The Lord."}]},{id:"walk-in-me",num:131,title:"Walk In Me",paragraphs:[{align:"justify",text:`There are none like Me, beloved, nor has there ever been one whose love surpasses understanding, a love without end. For I had paid the ransom from the beginning, a dowry the likes of which has never been seen, a bride-price from The God of Heaven.

Beloved, I stretched out My hands for you; I bore the weight of your sins, I carried your burdens! Therefore is My grace sufficient for you. Yet you must choose to stand up and walk in Me, relying on My strength in your times of weakness, by which My strength and your trust is made perfect.

Have I not said, _\u201CIn obedience is your love made perfect,\u201D_ and, _\u201CWho you choose, not what you choose, is the answer\u201D?_ And when you have chosen Me, is it not also your reasonable service to walk in Me?`},{align:"center",text:"Therefore, again I say, choose..."},{align:"center",text:`For I am The Only Way,

The Only Truth, The Only Life...`},{align:"center",text:"Says The Lord."}]},{id:"service-and-sacrifice",num:132,title:"Service and Sacrifice",paragraphs:[{align:"justify",text:"I tell you the truth, ALL who forsake the poor and the needy, and the fatherless and the widow, do not know Me, and have no place with Me at My supper, until they become as those they have forsaken. For by no other means will they learn true compassion."},{align:"center",text:`Beloved, to drink My blood is

To receive of Me...`},{align:"center",text:"To give up everything is to walk in Me..."},{align:"center",text:"To suffer is to know Me..."},{align:"center",text:`And to die for another is to know

The depths of My love.`},{align:"justify",text:"Yet I do not ask you to die for another, only that you push through - that you shatter all this stained glass with which you surround yourselves; that you be broken in pieces and truly become My disciples; that you love one another, even all those I send to you; that you surrender your lives and be created anew, trusting in Me to supply all that is needful... _Trust which comes by service and sacrifice, says The Lord._"}]},{id:"according-to-my-will-and-purpose",num:133,title:"According to My Will and Purpose",paragraphs:[{align:"justify",text:`Beloved ones, all My sheep hear My voice. Yet each receives in proportion to their faith and in accordance with My will and purpose. For a willing, humble heart is open to Me, and one who is deeply in love with Me will hear My voice. Yet this is not equal, nor shall every servant hear My voice in the same way.

For a prophet hears My voice, while another is moved deep within, while still others may only discern My leading, and this also is according to My will and purpose.`},{align:"center",text:`And that which I do has a perfect work

Within the hearts of My beloved, coming to

Fruition in those who remain in My love...`},{align:"center",text:"Those meet for The Master\u2019s use..."},{align:"center",text:"Says The Lord."}]},{id:"in-open-and-in-secret",num:134,title:"In Open and In Secret",paragraphs:[{align:"justify",text:"Beloved, speak not one word concerning those who have hurt you, not one more word against those who have betrayed you. Forgive them, pray for them, and let them go their way. Beloved, love your enemies and pray for those who betray you, and double for those who fight against you, for they have lifted up their heel against Me. Let resentment pass from your heart, and no more let your tongue cause you to stumble on their account. For each is accountable for their own heart and that which flows from it, even to every idle word."},{align:"center",text:"Beloved, be My examples..."},{align:"center",text:`Order your speech like David,

And conduct yourselves as Daniel...`},{align:"center",text:`Let your speech express your love for Me

In every situation, and let your conduct reveal

My spirit in you, in open and in secret...`},{align:"center",text:`Beloved, prepare as though I were

Coming to take you this very day;

Walk with Me as though we walk

Together in the Garden already...`},{align:"center",text:"Says The Lord."}]},{id:"doers-of-the-word",num:135,title:"Doers of the Word",paragraphs:[{align:"center",text:"In repentance I am always well pleased..."},{align:"center",text:`Therefore let the penitent now turn fully to God,

And do works meet for repentance...`},{align:"center",text:`Let them no more be as the hypocrite,

But let them walk close behind Me,

Abiding in the shadow of The Almighty...`},{align:"center",text:`And what more shall I speak than

That which I have spoken already?...`},{align:"center",text:"Therefore believe My words, and also do them..."},{align:"center",text:"Says The Lord."}]},{id:"a-true-disciple",num:136,title:"A True Disciple",paragraphs:[{align:"center",text:`The power of My strength shall be

Fulfilled in My servant\u2019s weakness,

In accordance with their love and faithfulness,

And by their willingness to lay down their life,

That they might receive of My life...`},{align:"center",text:`A man in desperate thirst who refuses every cup

From men, yet gladly drinks from Mine...`},{align:"center",text:`A man whose hunger has brought forth

Within him a great void, which can not

Be filled by any earthly bread...`},{align:"center",text:`A man who strives to live by every word

That proceeds from the mouth of God...`},{align:"center",text:`A man who carries Me within him, bearing the

Scars of My Passion in his heart, always...`},{align:"center",text:"Says The Lord."}]},{id:"serve-me-as-i-have-loved-you",num:137,title:"Serve Me As I Have Loved You",paragraphs:[{align:"justify",text:"From this field I have called a select few, to be My examples; not according to their own righteousness, nor by their own strength or intellect, but according to My Word and by My spirit which dwells within them. These have forsaken everything for the sake of their Shepherd. They follow Me wheresoever I go. They listen to My voice and heed the call, and will by no means follow another."},{align:"center",text:"Therefore, you also shall strive to be My examples..."},{align:"center",text:"Beloved ones, serve Me as I have loved you..."},{align:"center",text:`And remember, whatsoever you do

For another, you have done it for Me;

And whatsoever you do to another,

Whether in goodness or in malice,

You have done it also to Me...`},{align:"center",text:"Says The Lord."}]},{id:"the-narrow-way",num:138,title:"The Narrow Way",paragraphs:[{align:"justify",text:`I have indeed bestowed upon this generation a multitude of gifts, a great number of words, words of warning and unsurpassed wisdom, words of exaltation and correction, calling all in the earth to repent.

Lo, I have expounded many words of unending love, with great passion, revealing My Mercy which endures forever. Behold, I have proclaimed the way of salvation, time and time again, and He whose name is The Salvation of God! Yes, I have blown the trumpet and called forth My watchmen, I have struck the gates and rattled the doors, I have shaken the foundations of the earth! And still the people hold fast, clutching the pillars and shoring up the doors against Me!`},{align:"center",text:`Yet from the beginning I established the line,

A narrow way which I had placed in the

Midst of My people, Israel...`},{align:"center",text:`And in My mercy, I revealed The Way

In which My people should walk...`},{align:"center",text:`Behold, even now I have placed a

Plumb line in the midst of all people,

Setting all these crooked paths straight...`},{align:"center",text:"For I am The Lord, and I do not change."}]},{id:"the-perfect-sacrifice",num:139,title:"The Perfect Sacrifice",paragraphs:[{align:"center",text:`Behold, I had come to you as a man,

Clothed in the flesh, humble, My glory set aside;

God become man, Immanu El...`},{align:"center",text:`Living as all have lived in the body,

Yet not as man lives in the spirit;

For I am clean, having no sin in My body,

Nor in My spirit, having obeyed every

Command of The Father - blameless...`},{align:"center",text:`The Lamb of God without spot or blemish,

Sent to die for the sins of the world,

Bearing the full weight of

Transgression in My own body...`},{align:"center",text:`The perfect sacrifice, acceptable to God,

Whereby all men are reconciled to The Father,

If they so choose to receive of The Free Gift

And walk in My ways...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"the-victory",num:140,title:"The Victory",paragraphs:[{align:"center",text:`All those who repent in My name, with

Sincere remorse in their hearts, are saved...`},{align:"center",text:`For I am The One who makes it

Possible for them to do so...`},{align:"center",text:`And though some have fallen asleep in death,

And others are slain, even by their own hand,

I ask you, shall death have the last word?...`},{align:"center",text:`BY NO MEANS!

For I shall raise them up at the Last Day!...`},{align:"center",text:`For I have granted them the victory, even as

I am The Victory, being The Firstfruits from death...`},{align:"center",text:`Even as those given Me shall likewise be first

When the shout is made...`},{align:"center",text:"Says The Lord."}]},{id:"search-not-in-the-world",num:141,title:"Search Not in the World",paragraphs:[{align:"justify",text:"My grace descends upon all who repent in sincerity and in truth, and My spirit dwells within those who keep The Commandments and testify to My glory. Therefore, receive of Me; then will that which you seek become clear. For your heart\u2019s true desire can not be found in the world... _Seek God!_"},{align:"center",text:`Again I say to you, search not in the world,

For there you will not find Me;

Nor seek Me in the churches of men,

For there you will not find Me...`},{align:"center",text:`For I tell you the truth,

The Kingdom of God is within you...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"ingress",num:142,title:"Ingress",paragraphs:[{align:"justify",text:`Beloved ones, give your attention to those things I have set before you, obey all My commands, and consider that which I require of you... _Trust in Me._

Run not ahead, nor lag behind, but grow wise in My ways. Keep your eyes fixed upon Me, and be keenly aware of My goings out and comings in... _Follow Me._`},{align:"center",text:"Yet remember this..."},{align:"center",text:`The state of your heart

Dictates how much you receive,

And your obedience decides the ingress...`},{align:"center",text:`Your willingness sets the pace, and the strength

Of your grip will keep you from falling...`},{align:"center",text:"Says The Lord."}]},{id:"the-commandments",num:143,title:"The Commandments",paragraphs:[{align:"center",text:`In My love, I laid for you an everlasting

Foundation upon which you were to stand...`},{align:"center",text:`And in My mercy I constructed high walls,

Made with the finest stone, to protect you,

Even from yourselves...`},{align:"center",text:`Engraven stones,

Touched by the finger of God...`},{align:"center",text:"Says The Lord."}]},{id:"my-spirit-dwells-in-my-own",num:144,title:"My Spirit Dwells in My Own",paragraphs:[{align:"justify",text:"Beloved ones, I tell you the truth, the people of this world do not know Me. Therefore I have come close, to unstop the ears of all who long to hear My voice and obey it; I have drawn near, to open the eyes of all who desire to look upon My face and partake of My glory; and behold, I have poured out My spirit to restore the hearts of the penitent, to breathe new life into all those who embrace My words and seek to remain in My love."},{align:"center",text:`For I am come, and have come already;

And behold, I shall also return

And reveal My glory...`},{align:"center",text:`I have not departed from My people,

For My spirit dwells in My own...`},{align:"center",text:"Yet all must be broken..."},{align:"center",text:`Some broken before the time,

And many more after...`},{align:"center",text:"Says The Lord."}]},{id:"restored",num:145,title:"Restored",paragraphs:[{align:"center",text:"Once you were lost, yet now you are found..."},{align:"center",text:`Once you were naked, yet now you are clothed

In fine linens of white, your filthy rags cast off forever...`},{align:"center",text:`Once you were hungry and very thirsty, starving

In a world of empty promises, lies and vain deceits,

Yet now you are nourished with The Word of Truth...`},{align:"center",text:`Once you were sick, mortally ill,

Yet now you are healed in Me, now you are

Restored because of Me - My body, My bride...`},{align:"center",text:`My precious flower, My pleasant plant, of which

I shall pluck from the earth at the time appointed,

Replanted in the Garden at dawn on the new day...`},{align:"center",text:`Therefore come forth, all My people,

And flourish in the light of The Lord,

And bear much fruit in The Beloved!...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"a-spear-and-a-sword",num:146,title:"A Spear and a Sword",paragraphs:[{align:"center",text:`My every Letter is a spear with which I

Shall pierce the heart of this people...`},{align:"center",text:`Every Volume a sword by which I

Shall divide them asunder...`},{align:"center",text:"A rod and a staff for those who believe..."},{align:"center",text:"I AM THE LORD."}]},{id:"contentions",num:147,title:"Contentions",paragraphs:[{align:"center",text:`Answer not the obstinate, nor strive

With those who reject My words...`},{align:"center",text:`Give no occasion to the adversary,

Nor give the mocker a voice;

Give the scoffer no consideration at all;

Let them eat silence...`},{align:"center",text:"Rather pray for your adversaries..."},{align:"center",text:`For they do not fight against you,

They contend with Me...`},{align:"center",text:"Says The Lord."}]},{id:"labor-of-love",num:148,title:"Labor of Love",paragraphs:[{align:"justify",text:`Beloved ones, treat those of My body as you wish to be treated. Consider not what tomorrow may bring, nor dwell on that which has passed; embrace them as they are in this moment. For the one who stands in front of you is the person they are today. For who they were yesterday has passed away, and the person they will become tomorrow is not yet revealed. For you know not what tomorrow will bring, nor do you truly know that which has passed. You know neither the heart nor the mind, nor are you able to search the thoughts or look upon the innermost intentions.

Therefore, treat all My beloved as you would treat Me. Embrace your brothers and sisters in Messiah as you would embrace Me, walking with Me as I am and not as you would have Me be. For it is written: _According to the judgment with which you judge shall you be judged, and with the measure you use shall it be measured back to you._`},{align:"center",text:`Yet the servant who walks with Me

Moment by moment, treating their

Brother or sister as they wish to be treated,

Shall walk free, unhindered...`},{align:"center",text:`Their every reasonable service

Becoming a labor of love...`},{align:"center",text:"Says The Lord."}]},{id:"do-not-judge",num:149,title:"Do Not Judge",paragraphs:[{align:"justify",text:"It is written: _Do not speak evil of one another. For whoever speaks evil of a brother, or judges a brother, speaks evil of The Law and judges The Law. But if you judge The Law, you are not a doer of what The Law says, but a judge. {{ref:James 4:11}}_"},{align:"center",text:`In the same way, one who speaks evil

Of My messenger and judges My prophet

Speaks evil of Me and judges the Word...`},{align:"center",text:`And one who judges the Word will

By no means obey it, but have set

Themselves up as an authority, a judge,

Held captive by their own evil thoughts.`},{align:"justify",text:"Again, one who refuses My messenger can by no means receive My message, and one who judges him has blinded themselves to the Truth. For there is none righteous, no, not one. Yet The One who sent the message is true. Thus the one who delivers My Word must also be its recipient, or how shall I send him? And all those who judge can do nothing and shall receive nothing; even that which they have shall be taken away, says The Lord."}]},{id:"spiritual-warriors",num:150,title:"Spiritual Warriors",paragraphs:[{align:"justify",text:`What is man? He is but flesh, his power of no use at all. And in his pride he seeks glory for himself, a false valor. And so he continually turns to his own devices, deceiving himself, thinking he stands though he has fallen.

Foolhardy, he rushes into battle where he suffers injury after injury, ignoring his wounds, wounds which remain unhealed, infecting the whole of the body. Yet he continues on in his arrogance, his pride driving him forward, unable to see that he is cast down, saying within himself, \u201CLook at my accomplishments, look upon all I have done!\u201D And all the while satan laughs, saying, _\u201CBehold my acolytes; see how these men of battle have become like me.\u201D_`},{align:"center",text:"Sons and daughters of men, you are no warriors..."},{align:"center",text:`You are casualties, spoils of a war

Which was won from the foundation

Of the world, of which I was also slain...`},{align:"center",text:"For I alone bear the scars of battle..."},{align:"center",text:`Lo, I bear them in My hands and My feet,

Upon My back and in My side, wounds which I

Received in the house of My friends...`},{align:"center",text:"Says The Lord."}]},{id:"an-ensign-to-all-nations",num:151,title:"An Ensign to All Nations",paragraphs:[{align:"center",text:`Let the Trumpet be blown loudly!

Let the call to repentance go out

And the announcement be made!...`},{align:"center",text:`For I have lifted up an ensign to all nations,

I have set up a standard for this sleeping generation...`},{align:"center",text:"A bright and shining lamppost for My people..."},{align:"center",text:`A light, the glory of which shall not be diminished,

But shall only increase by measure...`},{align:"center",text:"Says The Lord."}]},{id:"pure-works",num:152,title:"Pure Works",paragraphs:[{align:"justify",text:`Beloved ones, worship Me as I am and not as you would have Me be! Obey MY voice! Depart from every form of evil and tear down every whitewashed wall of abomination!

Again, I say, be separate and come out from among them, and repent! Return to Me, in spirit and in truth, and in the day I stretch out My hand against the inhabitants of the earth, you shall surely be gone from this place.

My beloved servants, share your gifts: Lift up the poor and help the needy, give drink to the thirsty and feed the hungry, share My love and wash each other\u2019s feet. Yet no longer be a friend of this world, and no more walk in the ways of the churches of men, for they have not known Me.`},{align:"center",text:"Be set apart! Rejoice and give thanks!..."},{align:"center",text:`Honor The Messiah in spirit and in truth,

And walk closely in His example;

Testify of Him, from His birth to His passion;

Glorify His name in all the earth!...`},{align:"center",text:"For HE is the true gift..."},{align:"center",text:"Says The Lord."}]},{id:"escape",num:153,title:"Escape",paragraphs:[{align:"center",text:`Embrace My words, obey that which I have

Spoken to this generation, and you shall surely

Escape all these things which I am about to do.`},{align:"center",text:`For as it was in the days of Lot, when I brought

Him out of the city, so likewise shall I deliver

My people in the Day of Wrath.`},{align:"center",text:`For those in whom The Messiah

Dwells must be taken out of the way;

Then shall I judge the earth and strike the nations.`},{align:"center",text:"For I do not change..."},{align:"center",text:"Says The Lord."}]},{id:"the-wrath-of-god",num:154,title:"The Wrath of God",paragraphs:[{align:"center",text:`Beloved ones, come to Me, and I shall give you rest;

Be drawn to Me, that I may lift you up.`},{align:"center",text:`For I tell you the truth, My wrath is coming;

Behold, My anger is aroused, My fierce

Jealousy burns like a raging fire

And is about to come to the full.`},{align:"center",text:"Yet do not waver, but understand."},{align:"center",text:`For My wrath is required, and the foundation

Of My anger rests solidly upon My jealousy,

By which My unending sorrow is also revealed.`},{align:"center",text:`For My wrath is born of sorrow,

And My anger bursts forth as a husband

Jealous over his bride, My fury as a father

Protecting his children, as one mighty

In battle breaking through the lines...`},{align:"center",text:"Says The Lord."}]},{id:"a-dry-tree",num:155,title:"A Dry Tree",paragraphs:[{align:"center",text:"What is a dry tree to he who holds the axe?"},{align:"center",text:`Yet when the winds pass through and catch

The man sleeping, is he not easily

Crushed by the weight of the tree?`},{align:"center",text:`Indeed, what is this forest full of tall trees

Before Me, standing so tall with roots deeply

Embedded in the world, blocking always the warmth

Of the sun at eventide, casting long shadows

Under which the wicked flock?`},{align:"center",text:"Are they not soon left cold, standing in darkness?"},{align:"center",text:`Are they not as those who seek shelter under a tree

When the rains descend and the thunder crashes,

Who meet a quick end when lightning strikes?...`},{align:"center",text:"Says The Lord."}]},{id:"the-plight-of-the-ungodly",num:156,title:"The Plight of the Ungodly",paragraphs:[{align:"center",text:`The words of scoffers come forth

From a hard and troubled heart,

From a place void of understanding.`},{align:"center",text:`Their words are like chaff, their every lofty

Assertion dust, carried away by the wind.`},{align:"center",text:`As a ship tossed about by rough seas,

So is the plight of the ungodly;

In a dark sea of confusion, they attempt

To sail against every wind of doctrine

Which opposes them.`},{align:"center",text:"Yet all their toil is in vain..."},{align:"center",text:`For I am The Only Truth!
I am God alone!`}]},{id:"indomitable",num:157,title:"Indomitable",paragraphs:[{align:"center",text:`Behold, all I have spoken

Is established and shall be;

My Word yields to no man.`},{align:"center",text:`For My words are poured out like rain,

And My voice shakes the house like thunder,

My every word a hailstone released from

The treasury of hail, which I have

Reserved for the Time of Trouble.`},{align:"center",text:`Behold, My wrath is a consuming fire,

A mighty earthquake, encompassing

The breadth of the whole earth!...`},{align:"center",text:"Says The Lord."}]},{id:"the-weeping-willow",num:158,title:"The Weeping Willow",paragraphs:[{align:"center",text:`What is the high branch of the palm tree

To that of the weeping willow?

For they know not each other\u2019s place.`},{align:"center",text:`Each bears seed after its own kind,

Yet the ground beneath remains unyielding.

And without the rain, the leaf fades

And the seed flees back into the dust

Of the ground, unable to rise again.`},{align:"center",text:`Therefore are they cut down as the cedars;

They are broken and they are toppled when

Calamity comes to claim them, washed away.`},{align:"center",text:`And who will mourn their passing or

Search out their seed, that they might

Be revived in another place?...`},{align:"center",text:"Says The Lord."}]},{id:"cast-down",num:159,title:"Cast Down",paragraphs:[{align:"justify",text:`Is My Word in need of confirmation by those who say they know Me, yet do not really know Me? Is the Word of My mouth subject to men, whose understanding remains altogether lacking, whose knowledge is corrupt and whose power is of no use at all?

Shall My words be made subject to the approval of any self- appointed apostle, prophet or teacher? Shall flesh usurp the things of God? Can mortal man ascend above the throne of The Eternal? Shall the created rule over The Creator, or the corrupt sit as judge over The Holy? Shall any attempt to occupy My throne and not be cast down?!`},{align:"center",text:`Thus the highly esteemed shall be abandoned,

And the self-appointed severely abased...`},{align:"center",text:`Left to walk through the valley in the

Great and Terrible Day of The Lord,

Until death comes to claim them...`},{align:"center",text:"Declares The Lord."}]},{id:"the-doctrines-of-men",num:160,title:"The Doctrines of Men",paragraphs:[{align:"center",text:`The doctrines of men are a

Loathsome spot on every garment

Worn in the name of truth!...`},{align:"center",text:`A detestable wrinkle within

The tapestry of My glory!...`},{align:"center",text:`A horrible interwoven thread by

Which those who call of themselves

Christian pollute My name and mar

My image before the people...`},{align:"center",text:"Says The Lord."}]},{id:"my-hand-is-removed",num:161,title:"My Hand Is Removed",paragraphs:[{align:"center",text:`The penitent wait and

Bow down in thanksgiving.`},{align:"center",text:`Yet the arrogant and false righteous

Stand up proudly, declaring their

Deliverance, a deliverance which has

Already passed and shall not come.`},{align:"center",text:`For My hand is removed

And My spirit taken.`},{align:"center",text:`For only those in whom I see of Myself

Shall escape, and only those caught

In My embrace shall fly away...`},{align:"center",text:"Says The Lord."}]},{id:"i-am-god-of-the-living",num:162,title:"I Am God of the Living",paragraphs:[{align:"justify",text:"There is a people who sleep and a flesh which has no life in it, there are many who have been lost to the depths, a great multitude who have returned to the dust of the earth and can not be found. Yet The Lord God knows their names and their dwelling places; not one has passed from My sight, not one has been given up to the void."},{align:"center",text:`Behold, the day and hour is close at hand,

Yea it is very near, when the dead in Messiah

Shall arise and the sleepers shall awake,

When the rotting corpses are revived

And the dust gathers together once again...`},{align:"center",text:`From one end of the earth to the other,

Even from the deepest depths, shall My people

Rise up and give Me glory!...`},{align:"center",text:`Therefore let the children of Israel prepare,

Let everyone joined to Messiah step forward

And claim their inheritance...`},{align:"center",text:`For I have but to call out your name!....



For I am God of the living,

The One alone worthy of all praise...`},{align:"center",text:"Says The Holy One of Israel."}]},{id:"the-indignation-of-the-lord",num:163,title:"The Indignation of The Lord",paragraphs:[{align:"center",text:`My anger is kindled and

Burns in the heat of My wrath;

My indignation has come to the full

And must be poured out!...`},{align:"center",text:`Like a dark storm building upon

The horizon brings foreboding,

As a great torrent inundates a city and

Running waters quickly overtake a town...`},{align:"center",text:`Like fierce waves beat back the shore

Or a raging sea capsizes a ship,

As the power of the great whirlwind

Causes widespread devastation...`},{align:"center",text:"So shall the indignation of The Lord be!..."},{align:"center",text:"Says The Lord."}]},{id:"a-broadsword",num:164,title:"A Broadsword",paragraphs:[{align:"center",text:`The name of The Lord of Hosts is a broadsword,

And My every word a freshly sharpened blade!

For in My name is great power, and at the sound

Of My name all darkness flees away!`},{align:"center",text:`For as a razor removes the stubble,

And fervent heat burns away the dross,

So shall My name purge the waste places

And cleanse the polluted cities...`},{align:"center",text:`Until all these squawking birds are brought

Down into silence and every tall tower

Is toppled and left in ruins!...`},{align:"center",text:`Until Babel is utterly destroyed and every

Last vestige of man\u2019s invention is wiped

From the face of the earth!...`},{align:"center",text:"Says The Lord God."}]},{id:"signs",num:165,title:"Signs",paragraphs:[{align:"center",text:`Many great signs have been given

To this generation, yet all have went

Greatly ignored by the multitude;

Yet those who are Mine have clearly seen.`},{align:"center",text:`Yet understand this,

These signs are but the first of many,

And shall continue, increasing by measure

Until the time be fulfilled...`},{align:"center",text:`Then shall The Son of Man appear,

Clothed in the brightness of His glory,

A brilliance which has no equal;

Even the blind shall see!...`},{align:"center",text:"Says The Lord."}]},{id:"in-my-footsteps",num:166,title:"In My Footsteps",paragraphs:[{align:"justify",text:`Beloved, I delight in that which one gives to another in My name, and by the works of their own hands and feet in all righteousness. This is the tithe in which I delight most.

Therefore if one comes to you, saying, _\u201CGive me a cup of water,\u201D_ give them a drink in My name. And if another comes, saying, _\u201CI need a shirt, for I am naked and cold,\u201D_ give them your shirt and your coat also. And if this same one asks, _\u201CWill you walk with me this far?\u201D_ Go with them double.`},{align:"center",text:`Therefore, tithe not only

Of your money and material possessions,

But also of your strength and your time,

As one willing to give up their life for My sake.`},{align:"center",text:`For this is to truly know Me,

This is to walk in Me, in My very footsteps,

And to love your neighbor as yourself...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"the-way-of-the-upright",num:167,title:"The Way of the Upright",paragraphs:[{align:"center",text:`Those who have received eyes to see,

See the way ahead clearly and

Without obstruction, and follow it.`},{align:"center",text:`And those who have received ears to hear,

Hear the Truth and obey it...`},{align:"center",text:"Says The Lord."}]},{id:"a-welcomed-rain",num:168,title:"A Welcomed Rain",paragraphs:[{align:"justify",text:`Beloved, I have poured out My spirit on all flesh, even as I was poured out for you from the beginning. Yet no one comes to drink, not one is willing to receive of Me as I truly am. Therefore I shall indeed remove My hand, and My spirit shall return to Me. Behold, from every individual who refuses to give heed to My voice and embrace My correction has it departed already.

Yet let all those who remain in My love understand and have peace. For though My spirit departs from the multitudes and the ensuing darkness be thick, though wickedness overflows and every man of pride who being wise in his own eyes is left confounded, I shall not make a total end.`},{align:"center",text:`For My hand shall remain with the faithful,

And My strength shall be revealed in My anointed.`},{align:"center",text:`Behold, My spirit shall well up within

The hearts of the penitent and come upon

My chosen as a welcomed rain, and they shall

Be greatly increased, shining ever brighter,

Even amidst thick clouds and darkness...`},{align:"center",text:"Says The Lord."}]},{id:"prepare-the-way-of-the-lord",num:169,title:"Prepare the Way of The Lord",paragraphs:[{align:"center",text:`Prepare in the desert the way of The Lord!

Make a straight path in these

Dry and parched lands,

For The Holy One of Israel!`},{align:"center",text:`Let every valley be exalted,

And every mountain and hill brought low!

Let the crooked places be made straight,

And the rough places smooth!`},{align:"center",text:`For The Glory of The Lord shall be

Revealed from Heaven, and all

People shall behold it together!...`},{align:"center",text:"Declares The Lord."}]},{id:"the-joy-of-the-lord",num:170,title:"The Joy of The Lord",paragraphs:[{align:"justify",text:"Beloved, come and be filled with the joy of The Lord, which never fades, nor does it slumber, nor will it ever pass away; a flood of joy flowing into the innermost parts of your being, cascading through your spirit, reaching deep into that hidden place known only to The Lord; a place crafted by My own fingertips, delicately fashioned so those of the flesh may know Me, unlocked and opened by the trusting in and the knowledge of The Greatest of All Loves..."},{align:"justify",text:"A love which surpasses time and space, life and death, a place of perfect peace, yea inside pure and undefiled love; love of such a kind, cleansing every part seen and unseen, known and unknown; the love of such power and majesty, even that which has been corrupted is restored in the image of God... From grace to Grace, from light to The Light..."},{align:"justify",text:"My glory shown in you and through you, bright and shining, a flame brought forth from My own glory, shared with My beloved forever; a flame which can never be put out, nor can it flicker, nor shall it be covered over again! For where I am there is no darkness at all! Says The Lord YahuShua."}]},{id:"a-trumpet-and-alarm",num:171,title:"A Trumpet and Alarm",paragraphs:[{align:"center",text:`Let all who behold My words look upon

Them as an ensign, as a waving banner brought

Forth and set up for this wayward generation,

Even as a trumpet and alarm blowing

Continually upon the wall...`},{align:"center",text:`Let its sound rush through the streets of the cities!

Let its noise be carried into the wilderness,

Even to the outermost isles!`},{align:"center",text:`And let all those who have ears to hear listen,

And be silent before their God, and pray.`},{align:"center",text:`Indeed, let all in the earth partake of My Word

And be brought into deep and profound silence,

And consider...`},{align:"center",text:"Says The Lord."}]},{id:"the-stone",num:172,title:"The Stone",paragraphs:[{align:"center",text:`I shall increase the sound of

My voice seven times, even as Jericho,

Until all things break and all are broken...`},{align:"center",text:`Many broken unto death, ground to dust

Beneath The Stone which shall be placed in Zion,

For The Stone shall become a great mountain

Filling the whole earth...`},{align:"center",text:`While still others, My hidden treasure,

My battered and bruised sheep,

The wild of My flock, are broken and

Come to rest solidly atop this same Stone,

The Rock of My Enduring Promise...`},{align:"center",text:"Says The Lord."}]},{id:"the-lord-your-righteousness",num:173,title:"The Lord Your Righteousness",paragraphs:[{align:"justify",text:`The Lord your God has a Holy One. He is The Head of the body, The True Sanctuary, The Only Life Without End! Behold, He is a strong tower, a fortified city in the day of battle, an all-encompassing fire, The Mighty and Strong One whose rod is made of iron, The Law-Giver... The Source of Life by which all things consist, your Carpenter and Redeemer, The Salvation of God!

Therefore wait upon The Lord with meekness and fear, with unwavering trust; wait for Him! For He is The Fountain of Living Waters for all who thirst, a fruitful vine for the hungry, a wealth of riches for all those who come to Me empty.`},{align:"center",text:`Therefore, beloved, give Him glory!

Lift up your voices with everlasting praise!

Bring thanksgiving to the altar,

And offer up your hearts before Him!`},{align:"center",text:`Shout His name to the heavens,

For He is The Lord your Righteousness!...`},{align:"center",text:"YAHUSHUA HAMASHIACH!..."},{align:"center",text:"IMMANU EL!"}]},{id:"the-voice-of-the-lord",num:174,title:"The Voice of The Lord",paragraphs:[{align:"center",text:`And what of My voice, you ask? Its sound? Its tone? Its passion?

This is what I say to you: Listen, and you shall also know...`},{align:"center",text:`How does water taste to the man

Lost in the desert, dying of thirst?`},{align:"center",text:"How does food taste to the starving?"},{align:"center",text:"How does love feel to the desolate?"},{align:"center",text:`How does the warmth of a fire feel

To those coming in from the cold?`},{align:"center",text:`How does the caress of your

Beloved feel after many days apart?`},{align:"center",text:"How does a father look upon his newborn child?"},{align:"center",text:`How can one describe the sound

Of love which surpasses knowledge,

The sound of what My love is?`},{align:"center",text:"Can you hold the infinite in your hand?!"},{align:"center",text:`Beloved, this is what My voice

Sounds like to those who love Me:`},{align:"center",text:"A still small voice."},{align:"center",text:`And to the rest:

The sound of rushing waters,

Lightnings and thunderings of fury and fiery anger,

With deep and infinite sorrow, bitter anguish!`},{align:"center",text:"Love."},{align:"center",text:"The Voice of Truth."}]},{id:"the-volumes",num:175,title:"The Volumes",paragraphs:[{align:"justify",text:"My Word in The Volumes of Truth is the rod by which the translations of men are to be tested, a light which shines upon the doctrines of men to expose them, revealing them to be blasphemies and heresies before God, all of which shall burn up in the Day, when the fire comes to test the quality of each man\u2019s work."},{align:"center",text:`Therefore, if one professing faith be wise,

He shall humble himself before Me,

Calling upon the name of The Holy One

For knowledge, in where all understanding

Flows to the truly contrite and penitent,

Flowing in pure testimony, free from corruption.`},{align:"center",text:`And by this only shall one be wise in the reading,

Comparing that which was given with that

Which is put forth once again, discerning

The Source and The Author to be the same...`},{align:"center",text:`One Word, One Book,

One on-going Testament to My glory;

By no means shall it be divided into three!...`},{align:"center",text:"Says The Lord."}]},{id:"the-tabernacle-of-my-mercy",num:176,title:"The Tabernacle of My Mercy",paragraphs:[{align:"center",text:`Behold, I shall come in an instant!

In a moment, I shall reach down and take My spoil!`},{align:"center",text:`Therefore, let the remnant of Israel be found

Waiting with eager hands, and let those grafted

Into My olive tree bear summer fruit!`},{align:"center",text:`Let the sprigs sprout quickly,

And let not the seedlings be withered;

Let not the noonday sun wilt or scorch

Any of My pleasant plants.`},{align:"center",text:`Be moved from your places,

Oh My people, and be hidden!

Be exalted, oh My beautiful ones,

And find sanctuary in the tabernacle of My mercy!`},{align:"center",text:`Be sheltered from all this burning heat,

Until the indignation passes by

And The Majesty comes! {{ref:Isaiah 26:20-21}}...`},{align:"center",text:"Says The Lord."}]},{id:"the-only-judge",num:177,title:"The Only Judge",paragraphs:[{align:"justify",text:"Nothing coming from the mouth of those who scoff and shoot out the lip against The Lord\u2019s anointed, whether they be a friend or an enemy, a spouse or a relative, a neighbor or a stranger, a scholar or a teacher, a pastor or a self-appointed prophet or preacher, shall be accounted as true. Neither shall any weight be given to their arguments; it is wind. For I alone sit as judge, says The Lord."}]},{id:"brought-low",num:178,title:"Brought Low",paragraphs:[{align:"center",text:`As the scythe cuts through the stalk,

As the sweeping blow fells many plants at once,

So shall the sharpness of realization cut to the heart

Of this people, and in that same moment the

Loftiness of many shall be brought down...`},{align:"center",text:"Declares The Lord."}]},{id:"the-author-and-the-finisher",num:179,title:"The Author and The Finisher",paragraphs:[{align:"center",text:`If you embrace the Scriptures of Truth,

Yet reject My Word in these Volumes,

You deny the Word of The Lord.`},{align:"center",text:`And if you embrace My Letters,

Yet reject the Bible,

You deny the Word of The Lord.`},{align:"center",text:"For I am The Author and Finisher thereof..."},{align:"center",text:"Says The Lord."}]},{id:"solace",num:180,title:"Solace",paragraphs:[{align:"center",text:"I shall not make a total end..."},{align:"center",text:`For I shall clothe all who come to Me

In sincere repentance with fine robes.`},{align:"center",text:`I shall feed the poor in spirit,

Wipe the tears of the remorseful,

And uphold the broken.`},{align:"center",text:`I shall shelter the penitent and give grace

To the humble, and the pure in heart

Shall behold My face.`},{align:"center",text:`Indeed, all who wash My feet

With their tears shall be comforted

For one week in the house of The Lord...`},{align:"center",text:"Says The Holy One of Israel."}]},{id:"the-almighty",num:181,title:"The Almighty",paragraphs:[{align:"center",text:"I AM THE LORD..."},{align:"center",text:`He who sets up kingdoms and brings them to ruin!

He who set the foundations of the earth

And covered them with beauty!

He who also set the stars in their places

And caused the galaxies to take their form!

He to whom all creation bows down!...`},{align:"center",text:`He whose power is limitless and by whose wisdom

All things were brought forth,

Whose authority is absolute,

The God who reigns in Israel!...`},{align:"center",text:`He who was and is and is to come,

The Almighty!`}]},{id:"refinement",num:182,title:"Refinement",paragraphs:[{align:"center",text:`The lake of My burning heart is a consuming fire,

And in the heat of My jealousy I shall purify

My people seven times, until only that

Which bears My likeness remains...`},{align:"center",text:`The refined lifted up, the wicked consumed,

Destruction of every kind of evil!...`},{align:"center",text:`For I am The Lord who was and is,

Even from the beginning,

And to the end and forever after I remain...`},{align:"center",text:"Says The Lord."}]},{id:"the-planting-of-the-lord",num:183,title:"The Planting of The Lord",paragraphs:[{align:"center",text:`Pretense is not at all becoming of a servant

Of The Lord; neither is the world a garment

Which My elect shall wear.`},{align:"center",text:`Beloved, strip yourselves naked;

Cast off these filthy robes!

Wash yourselves, make yourselves clean!

Turn away from this world, and come to Me!`},{align:"center",text:`Lay yourselves upon the altar and

Become a living sacrifice to The Lord,

The planting of The Lord, My pleasant plants

Set in the midst of My vineyard,

My beautiful ones grafted in...`},{align:"center",text:"Says The Lord."}]},{id:"a-unique-and-lovely-song",num:184,title:"A Unique and Lovely Song",paragraphs:[{align:"justify",text:"Here is wisdom: The prayers of My children are indeed precious in My sight, a unique and lovely song entering My ears. For every song sung in My name, whether in open or in secret, in sorrow or in joy, is received up to Heaven as a memorial before The Holy One of Israel, even as incense before the altar. For that which has come up before Me is a blessing, which is then received back again, a wonderful recompense for fervent prayer on another\u2019s behalf."},{align:"center",text:`Thus that prayed due to a troubled heart

Comes back again, to heal not the heart

Of the one on whose behalf the prayer was offered,

But to mend that which is torn in the

Heart of the one who offered it...`},{align:"center",text:`Whether it be from anger to forgiveness,

Or from anguish to peace,

Or from tears of sadness to tears

Of hope and joyful expectation...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"a-prophet",num:185,title:"A Prophet",paragraphs:[{align:"center",text:"What is a prophet?..."},{align:"center",text:`Is he not a man, My servant,

Whom I have chosen and called?

And when does My servant become a prophet?

And what is the length of time he remains as such?`},{align:"center",text:`Lo, he is only a prophet in that self-same moment

In which I speak to him and cause him to hear,

Prophesying only as long as I cause him

To speak or to write My words.`},{align:"center",text:`For there is no prophecy apart from My will,

And without My voice there can be no prophesying;

And without My spirit, no man may hear,

Nor shall he behold a vision,

Nor is he able to understand.`},{align:"center",text:`Apart from The Holy One,

There is no knowledge...`},{align:"center",text:"I AM THE LORD."}]},{id:"no-equal",num:186,title:"No Equal",paragraphs:[{align:"justify",text:"I am The Lord, He who stretched out the heavens and hung the earth upon nothing. I am He who created all these worlds, He who causes all things to be. I am He who formed man from the dust of the earth and gave him breath, and he became a living soul. Behold, I spoke all life into existence, yes, I am He who called all things into existence, saying, _\u201CArise and declare My glory!\u201D_ For all creation obeys the sound of My voice."},{align:"center",text:`Yea, the whole universe declares My glory!

For I am He who commanded the stars to shine

Their light and the galaxies to take their form.`},{align:"center",text:`Behold, My voice reaches across the universe,

And reverence is spread out before Me;

For I command the hills to bow down and the

Mountains to be brought low, and it is so;

Yea, the whole earth trembles when I pass by!`},{align:"center",text:"For I am great in power and My glory has no equal!"},{align:"center",text:`Thus the fear of The Lord goes before Me,

And obedience follows after Me...`},{align:"center",text:"Says The Lord."}]},{id:"maranatha",num:187,title:"Maranatha",paragraphs:[{align:"justify",text:"Fear God and put all your trust in The Holy One. For the power of The Father is displayed through The Son, for He is the express image of The Holy, The Salvation of God... _He whose hand reaches far and wide, whose strength is almighty, whose wisdom holds all creation in His understanding, whose love endures forever! He whose righteousness comes, and had been stretched out before us, for every eye to see! The end of which shall be as a flood cleansing the sanctuary of His mercy, restoring all things, even to a new heavens and a new earth._"},{align:"center",text:`Behold, it is time for the power

Of God to be made known, for the name

Of The Holy One of Israel to be glorified

Above the heights of the mountains,

To overshadow every hill!...`},{align:"center",text:`It is time for The King to return and gather,

To reveal the glory of His might!...`},{align:"center",text:"Immanu El!"}]},{id:"trust-in-god-alone",num:188,title:"Trust In God Alone",paragraphs:[{align:"center",text:`What is earthly, let it stay earthly;

And what is spiritual, let it stay spiritual.`},{align:"center",text:`Hold not to the earthly nor to the

Understanding of men, nor grab hold

Of any private interpretation of Scripture;

Trust not in the doctrines of men.`},{align:"center",text:`Hold fast to God,

And place all your trust in The Messiah.`}]},{id:"open-your-eyes-to-the-truth",num:189,title:"Open Your Eyes to The Truth",paragraphs:[{align:"justify",text:"Search, and you shall discover the truth, which is God. Dissect life\u2019s structures; there He is, its writer and fashioner. Look deeper and farther than ever before, and there you will find Him. Calculate and count all things which are before your eyes, yes, search the cosmos, study it, and you will begin to know Him. No matter where you point your lenses, there He is, within the scope of your understanding."},{align:"center",text:`Behold, all discoveries lead to God!

Though you need not seek, nor discover,

For the knowledge of God is within you.`},{align:"center",text:`Yet only the shedding of the skin

Of this world and the death of your pride

Shall open your eyes to The Truth -

Which is absolute, forever standing

On a hill, bright and shining,

Immovable, unbreakable!...`},{align:"center",text:`The Everlasting Stone which has

Become The Head of the Corner,

The Great Mountain which

Fills the whole earth!`}]},{id:"seek-the-light",num:190,title:"Seek The Light",paragraphs:[{align:"center",text:`Those who seek to understand the dark

Will soon find themselves trapped

In the midst of it, unable to break free.`},{align:"center",text:`Yet those who seek The Light will find it,

And I will show them The Way;

In these darkness has no foothold...`},{align:"center",text:"Says The Lord."}]},{id:"the-redeemed",num:191,title:"The Redeemed",paragraphs:[{align:"center",text:`Beloved, cast off your sins,

Depart quickly from temptation,

And to the accuser turn a deaf ear.`},{align:"center",text:`For I tell you the truth, evil has lost

Its grip on the redeemed...`},{align:"center",text:"Says The Lord YahuShua."}]},{id:"the-riches-of-eden",num:192,title:"The Riches of Eden",paragraphs:[{align:"center",text:`Only those in union with The Messiah

Shall inherit the riches of Eden,

And only those who fully accept

His sacrifice shall be restored.`},{align:"center",text:`For from the garden did you come forth,

And to the garden shall you return;

Yet not in the former manner, but in glory...`},{align:"center",text:"Created anew..."},{align:"center",text:"Says The Lord."}]},{id:"a-right-heart",num:193,title:"A Right Heart",paragraphs:[{align:"center",text:`A right heart bridles the tongue;

And a forgiving heart absolves every hurt,

Bringing peace to the mind...`},{align:"center",text:"Says The Lord."}]},{id:"the-restoration",num:194,title:"The Restoration",paragraphs:[{align:"center",text:"Behold, The Restoration is coming, coming quickly!..."},{align:"center",text:`All things restored as in the beginning;

A garden where nothing is destroyed,

And none are given to destruction;

No more pain or tears, no more sickness or death...`},{align:"center",text:"Only life is, and shall be, forever!..."},{align:"center",text:"Says The Lord."}]},{id:"unchanging",num:195,title:"Unchanging",paragraphs:[{align:"center",text:`As I have spoken, so I speak;

As I am, so shall I be and have always been...`},{align:"center",text:`For I am The Lord,

And I DO NOT CHANGE.`}]},{id:"the-time-of-testing",num:196,title:"The Time of Testing",paragraphs:[{align:"center",text:`My spirit has spoken throughout

The generations, in its steadfastness and quiet;

Yet few have ears to hear, few are willing

To open their hearts and receive My correction.`},{align:"center",text:`Yet now the time has come for those

Who say they are My people to be tried,

It is time for their works to be tested.`},{align:"center",text:`For the Word of My mouth shall declare it,

And in the Day of The Lord

It shall surely be made plain...`},{align:"center",text:`Every false way exposed,

Every perverse tradition torn in pieces,

Every detestable doctrine crushed

Beneath the weight of the Truth...`},{align:"center",text:"Says The Lord."}]},{id:"all-tears-wiped-away",num:197,title:"All Tears Wiped Away",paragraphs:[{align:"center",text:`Those who grab hold of their First Love

With all their heart, with all their mind,

With all their strength and with all their soul,

Shall never go hungry, nor shall they thirst anymore;

Nor shall the heat of the noonday

Sun do them any harm...`},{align:"center",text:`Yea, even all their tears shall be wiped away

In the house of The Lord...`},{align:"center",text:"Says The Lord."}]},{id:"tipping-point",num:198,title:"Tipping Point",paragraphs:[{align:"justify",text:"I tell you the truth, that which is tipped can not be set upright again, and that which has been set in motion can not be stopped. Lo, even that which was held captive in the depths of silence has been released. Behold, it comes forth, increasing by order of magnitude, and can in no wise be put back again... Says The Lord."}]},{id:"one-salvation",num:199,title:"One Salvation",paragraphs:[{align:"justify",text:"I have put forth a great multitude of words to bless you, a great number of loving and stern speeches. I have called this generation to repent, and have given ample warning. And those who cupped their ears heard My voice, and those who received of Me wrote My words in their heart, sincerely seeking to do them, that they might honor Me and bring glory to My name."},{align:"center",text:`For I AM THE LORD,

And there is but One Escape...`},{align:"center",text:`Whether one lives or dies,

There is but One Salvation...`},{align:"center",text:`No matter the time or the season,

There is but One...`},{align:"center",text:"Declares The Almighty."}]},{id:"trust",num:200,title:"Trust",paragraphs:[{align:"center",text:`Behold, the signs of My coming

Are made plain and are revealed in the

World everyday, even in every corner.`},{align:"center",text:`Yet that which I am doing is not

Easily discerned by men;

For their hearts are hard, and they

Remain slow of understanding.`},{align:"center",text:`Therefore great trust is required,

And must be born of real belief,

Knowing I AM WHO I AM...`},{align:"center",text:"Says The Lord."}]},{id:"acquiesce",num:201,title:"Acquiesce",paragraphs:[{align:"center",text:`Listen to the sound of My voice,

Fall in love with Me as at the first,

Come to Me anew as in the beginning;

Beloved, it is time to acquiesce,

To fully surrender to the truth of who I am!...`},{align:"center",text:`To be submersed in My spirit,

To be baptized in My love,

To seek first The Kingdom of God

And His Righteousness, which I am...`},{align:"center",text:"Then shall that which is needful be added to you..."},{align:"center",text:"I AM THE LORD."}]},{id:"the-lord-s-day",num:202,title:"The Lord\u2019s Day",paragraphs:[{align:"justify",text:`Behold, The Son of Righteousness shall rise up with healing in His wings, and you, My precious beloved, shall go out leaping like calves released from the stall! The King, Himself, shall cultivate the ground in that day, with streams of living waters breaking out behind Him! Behold, new life shall fill every corner, and the desolate places shall be restored! Whole forests shall burst forth from the ground, with every kind of tree and flowering plant, every kind of grass and fern reappearing, and every living creature leaping up from the dust of the earth, once again!

Behold, The Lord\u2019s peace shall be there! And nothing under the sun shall destroy, nor shall anything be given to destruction, in all My holy mountain! For there shall be no predator, nor shall any prey be found, neither shall the strong slay the weak. For as it is written: _The wolf and the lamb shall feed together, the lion shall eat straw like the ox, and dust shall be the serpent\u2019s food. {{ref:Isaiah 65:25}}_ All shall dwell in safety, with every living creature dwelling at peace with its neighbor.

Behold, in that day everlasting righteousness shall reign in all the earth! For The King shall stand up, and all creation shall bow down! And He shall look upon the joy of His heart with gladness, and the blessing shall be fulfilled: _He shall bless them and keep them, and make His face to shine upon them; He shall be gracious to them, and lift up His countenance upon them, and grant them peace. {{ref:Numbers 6:24-26}}_

And thus shall My name be placed upon the children of Israel, even upon all who have been grafted in, and they shall be blessed. Yea, they shall be exceedingly glad, dwelling in the presence of The Lord, forever!

Behold, the multitudes shall break forth into singing! For The Glory of The Lord shall be alive in their hearts, the seal of The Living God shall be upon their foreheads, the Way of The Lord shall dwell in their limbs, and unending praise shall be upon their lips! All their doings shall bear fruit in righteousness, for The Law shall be written there, even in their innermost parts! And behold, The King of Peace shall overflow, and His people shall be satisfied and have rest, our joy complete.`},{align:"center",text:`Therefore, blessed are all those who seek

Forgiveness in YahuShua HaMashiach,

And also receive.`},{align:"center",text:`For in His name shall all find freedom,

Solace under the shadow of His healing wings...`},{align:"center",text:"Life without end..."},{align:"center",text:"Says The Lord God."}]},{id:"bound-by-the-word",num:203,title:"Bound by The Word",paragraphs:[{align:"center",text:`And so The Word was sent,

And came into the world

To seek and to save the lost.`},{align:"center",text:`And behold, He is coming again to deliver His own,

All those who believe and live by The Word;

And to destroy those who fight against The Word,

For they too are bound by The Word.`},{align:"center",text:`For The Word stands forever, immovable and everlasting,

Unchangeable, having complete authority over all things,

The light and the dark, the righteous and the wicked.`},{align:"center",text:`Indeed, the whole universe

Is set within the confines of His will,

Giving heed to Him who created it...`},{align:"center",text:`Forever and ever...

Amen.`}]}],WTLB_SCRIPTURES={"Matthew 4:4":"But He answered and said, \u201CIt is written: \u2018Man shall not live by bread alone, but by every word that proceeds from the mouth of God.\u2019\u201D","Luke 15:11-32":"11. Then He said: \u201CA certain man had two sons. 12. And the younger of them said to his father, \u2018Father, give me the portion of goods that falls to me.\u2019 So he divided to them his livelihood. 13. And not many days after, the younger son gathered all together, journeyed to a far country, and there wasted his possessions with prodigal living. 14. But when he had spent all, there arose a severe famine in that land, and he began to be in want. 15. Then he went and joined himself to a citizen of that country, and he sent him into his fields to feed swine. 16. And he would gladly have filled his stomach with the pods that the swine ate, and no one gave him anything. 17. \u201CBut when he came to himself, he said, \u2018How many of my father\u2019s hired servants have bread enough and to spare, and I perish with hunger! 18. I will arise and go to my father, and will say to him, \u201CFather, I have sinned against heaven and before you, 19. and I am no longer worthy to be called your son. Make me like one of your hired servants.\u201D \u2019 20. \u201CAnd he arose and came to his father. But when he was still a great way off, his father saw him and had compassion, and ran and fell on his neck and kissed him. 21. And the son said to him, \u2018Father, I have sinned against heaven and in your sight, and am no longer worthy to be called your son.\u2019 22. \u201CBut the father said to his servants, \u2018Bring out the best robe and put it on him, and put a ring on his hand and sandals on his feet. 23. And bring the fatted calf here and kill it, and let us eat and be merry; 24. for this my son was dead and is alive again; he was lost and is found.\u2019 And they began to be merry. 25. \u201CNow his older son was in the field. And as he came and drew near to the house, he heard music and dancing. 26. So he called one of the servants and asked what these things meant. 27. And he said to him, \u2018Your brother has come, and because he has received him safe and sound, your father has killed the fatted calf.\u2019 28. \u201CBut he was angry and would not go in. Therefore his father came out and pleaded with him. 29. So he answered and said to his father, \u2018Lo, these many years I have been serving you; I never transgressed your commandment at any time; and yet you never gave me a young goat, that I might make merry with my friends. 30. But as soon as this son of yours came, who has devoured your livelihood with harlots, you killed the fatted calf for him.\u2019 31. \u201CAnd he said to him, \u2018Son, you are always with me, and all that I have is yours. 32. It was right that we should make merry and be glad, for your brother was dead and is alive again, and was lost and is found.\u2019 \u201D","Hosea 4:6":"My people are destroyed for lack of knowledge. Because you have rejected knowledge, I also will reject you from being priest for Me; Because you have forgotten the law of your God, I also will forget your children.","Micah 6:8":"He has shown you, O man, what is good; And what does the LORD require of you But to do justly, To love mercy, And to walk humbly with your God?","Matthew 6:24":'"No one can serve two masters. For either he will hate the one and love the other, or else he will be loyal to the one and despise the other. You cannot serve God and mammon."',"Luke 7:35":"But wisdom is justified by all her children.\u201D","Matthew 13:12":"For whoever has, to him more will be given, and he will have abundance; but whoever does not have, even what he has will be taken away from him.","2 Corinthians 6:17":"Therefore \u201CCome out from among them And be separate, says the Lord. Do not touch what is unclean, And I will receive you.\u201D","Genesis 2:21-24":"21. And the LORD God caused a deep sleep to fall on Adam, and he slept; and He took one of his ribs, and closed up the flesh in its place. 22. Then the rib which the LORD God had taken from man He made into a woman, and He brought her to the man. 23. And Adam said: \u201CThis is now bone of my bones And flesh of my flesh; She shall be called Woman, Because she was taken out of Man.\u201D 24. Therefore a man shall leave his father and mother and be joined to his wife, and they shall become one flesh.","Matthew 5:44":"But I say to you, love your enemies, bless those who curse you, do good to those who hate you, and pray for those who spitefully use you and persecute you,","Matthew 18:3-4":'3. and said, "Assuredly, I say to you, unless you are converted and become as little children, you will by no means enter the Kingdom of Heaven. 4. Therefore whoever humbles himself as this little child is the greatest in the Kingdom of Heaven.',"Isaiah 11:9":"They shall not hurt nor destroy in all My holy mountain, For the earth shall be full of the knowledge of the LORD As the waters cover the sea.","Zechariah 12:10":"\u201CAnd I will pour on the house of David and on the inhabitants of Jerusalem the Spirit of grace and supplication; then they will look on Me whom they pierced. Yes, they will mourn for Him as one mourns for his only son, and grieve for Him as one grieves for a firstborn.","Proverbs 9:10":"\u201CThe fear of the LORD is the beginning of wisdom, And the knowledge of the Holy One is understanding.","John 9:6-7":"6. When He had said these things, He spat on the ground and made clay with the saliva; and He anointed the eyes of the blind man with the clay. 7. And He said to him, \u201CGo, wash in the pool of Siloam\u201D (which is translated, Sent). So he went and washed, and came back seeing.","Matthew 21:42":`YahuShua said to them, "Have you never read in the Scriptures: 'The stone which the builders rejected has become the chief cornerstone. This was The Lord's doing, and it is marvelous in our eyes'?`,"Daniel 2:35":"Then the iron, the clay, the bronze, the silver, and the gold were crushed together, and became like chaff from the summer threshing floors; the wind carried them away so that no trace of them was found. And the stone that struck the image became a great mountain and filled the whole earth.","Romans 10:4":"For Christ is the end of the law for righteousness to everyone who believes.","Colossians 3:9-10":"9. Do not lie to one another, since you have put off the old man with his deeds, 10. and have put on the new man who is renewed in knowledge according to the image of Him who created him,","1 Corinthians 15:54":"So when this corruptible has put on incorruption, and this mortal has put on immortality, then shall be brought to pass the saying that is written: \u201CDeath is swallowed up in victory.\u201D","James 1:17":"Every good gift and every perfect gift is from above, and comes down from the Father of lights, with whom there is no variation or shadow of turning.","John 15:10":"If you keep My commandments, you will abide in My love, just as I have kept My Father\u2019s commandments and abide in His love.","John 3:36":"He who believes in the Son has everlasting life; and he who does not believe the Son shall not see life, but the wrath of God abides on him.\u201D","Genesis 2:3":"Then God blessed the seventh day and sanctified it, because in it He rested from all His work which God had created and made.","Exodus 31:13":"\u201CSpeak also to the children of Israel, saying: \u2018Surely My Sabbaths you shall keep, for it is a sign between Me and you throughout your generations, that you may know that I am the LORD who sanctifies you.","Matthew 24:32-34":'32. "Now learn this parable from the fig tree: When its branch has already become tender and puts forth leaves, you know that summer is near. 33. So you also, when you see all these things, know that it is near, at the doors! 34. Assuredly, I say to you, this generation will by no means pass away till all these things take place.',"Ecclesiastes 9:2-3":"2. All things come alike to all: One event happens to the righteous and the wicked; To the good, the clean, and the unclean; To him who sacrifices and him who does not sacrifice. As is the good, so is the sinner; He who takes an oath as he who fears an oath. 3. This is an evil in all that is done under the sun: that one thing happens to all. Truly the hearts of the sons of men are full of evil; madness is in their hearts while they live, and after that they go to the dead.","2 Timothy 2:15":"Be diligent to present yourself approved to God, a worker who does not need to be ashamed, rightly dividing the word of truth.","Matthew 11:28-30":'28. "Come to Me, all you who labor and are heavy-laden, and I will give you rest. 29. Take My yoke upon you and learn from Me, for I am gentle and lowly in heart, and in Me you will find rest for your souls. 30. For My yoke is easy and My burden is light."',"James 4:11":"Do not speak evil of one another, brethren. He who speaks evil of a brother and judges his brother, speaks evil of the law and judges the law. But if you judge the law, you are not a doer of the law but a judge.","Isaiah 26:20-21":"20. Come, my people, enter your chambers, And shut your doors behind you; Hide yourself, as it were, for a little moment, Until the indignation is past. 21. For behold, the LORD comes out of His place To punish the inhabitants of the earth for their iniquity; The earth will also disclose her blood, And will no more cover her slain.","Isaiah 65:25":"The wolf and the lamb shall feed together, The lion shall eat straw like the ox, And dust shall be the serpent\u2019s food. They shall not hurt nor destroy in all My holy mountain,\u201D Says the LORD.","Numbers 6:24-26":"24. \u201CThe LORD bless you and keep you; 25. The LORD make His face shine upon you, And be gracious to you; 26. The LORD lift up His countenance upon you, And give you peace.\u201D \u2019","Amos 9:13":"\u201CBehold, the days are coming,\u201D says the LORD, \u201CWhen the plowman shall overtake the reaper, And the treader of grapes him who sows seed; The mountains shall drip with sweet wine, And all the hills shall flow with it.","Psalm 40:7-8":"7. Then I said, \u201CBehold, I come; In the scroll of the book it is written of me. 8. I delight to do Your will, O my God, And Your law is within my heart.\u201D","Hebrews 10:7":"Then I said, \u2018Behold, I have come\u2014 In the volume of the book it is written of Me\u2014 To do Your will, O God.\u2019 \u201D","1 John 3:12":"not as Cain who was of the wicked one and murdered his brother. And why did he murder him? Because his works were evil and his brother\u2019s righteous.","Genesis 4:8":"Now Cain talked with Abel his brother; and it came to pass, when they were in the field, that Cain rose up against Abel his brother and killed him.","Isaiah 40:13; Romans 11:34":"Isaiah 40:13 \u2014 Who has directed the Spirit of the Lord, Or as His counselor has taught Him? | Romans 11:34 \u2014 For who has known the mind of the Lord? Or who has become His counselor?","1 Corinthians 2:16":"For 'who has known the mind of the Lord that he may instruct Him?' But we have the mind of Christ."},THE_BLESSED=[{id:"introduction",num:1,title:"Introduction",paragraphs:[{align:"center",text:`_**The Blessed **



**More Declarations of Blessedness**

**From The Lord, Our God and Savior**

**(Excerpts from The Volumes of Truth)**



Everything which comes from the mouth

Of The Lord your God is a blessing for all!...



A song for all those

Who have ears to hear!



A vision to all who have

Eyes to see My splendor,

Painted by The Word of My glory!



An overflowing fountain inside those

Whose hearts are open to Me!...



Says The Lord.





It is written:



\u201CMan shall not live by bread alone,

But by every word that proceeds

From the mouth of God.\u201D{{ref:Matthew 4:4}}_`}]},{id:"blessed-are-those-who-seek-me",num:2,title:"Blessed Are Those Who Seek Me",paragraphs:[{align:"center",text:`_Blessed are all those with_

_Their heads raised toward Heaven, _

_Who do continually look up _

_In anticipation of My coming... _



_They shall surely be gone from this place!_



\u2020



_Blessed are the wise who wait and watch, _

_And see these things come to pass _

_During their generation..._



_Blessed are the faithful,_

_For they shall be lifted up. _



\u2020



_Blessed is the one who finds his way to Me, _

_Without the hindrances of men. _



\u2020



_Blessed are those who diligently _

_Seek after God, for they will surely find Me..._



_But know this, I am also He who _

_Corrects and disciplines those He loves. _



\u2020



_Blessed is the man who comes to Me _

_Ashamed of his trespasses, whose heart _

_Is full of grief on account of his sins,_

_For I am faithful to forgive his sins..._



_Indeed I shall lift him up, _

_And set his feet upon hallowed ground._`}]},{id:"blessed-are-those-who-believe-in-me",num:3,title:"Blessed Are Those Who Believe in Me",paragraphs:[{align:"center",text:`_Blessed are those who never lost the pearl,_

_But held it close their whole life._



\u2020



_I am not a god of force, for that which I give _

_Must be received with gladness..._



_And oh how blessed are those _

_Who have truly received,_

_For a multitude of joy awaits them... _



_Soon lifted up, high upon healing wings!_



\u2020



_Blessed are those who believe without seeing;_

_They have received their reward._



\u2020



_Blessed are those who put their trust _

_In God and abide in His Son..._



_For they shall receive _

_Blessing upon blessing, grace upon grace, _

_And wisdom with all trust._



\u2020



_Blessed are those who believe in Me..._



_Even more blessed are those who _

_Embrace Me fully and walk in My ways,_

_For they shall fly away._



\u2020



Beloved, I have saved you already,

Having sent The Lamb of God

Slain from the foundation of the world;

He was come into the world,

And you would not receive Him...



_Blessed are those who have received Him; _

_Grace covers them. _



Behold, He is coming again,

And He have I poured out on every nation,

Yet you are offended in Him...



_Blessed are the thirsty, _

_Who have drunk deeply from His cup;_

_They are filled with His glory. _





Behold, He shall call out, He shall surely gather,

Yet you will neither see nor hear Him...



_Blessed are those who have _

_Eyes to see and ears to hear;_

_For they shall surely be gone from this place._



\u2020



_As there is only One Way _

_And only One Truth and only One Life, _

_There can be only One Wisdom also... _



_Blessed are all those who choose Him._



\u2020



_Blessed are the feet of those_

_Who bring the Gospel of The Messiah_

_To the hungry and thirsty... _



_Even more blessed are those _

_Who eat and drink_

_Of that which is offered them._



\u2020



_Blessed are the pure in heart, _

_For they shall surely behold My face._



\u2020



_Blessed are those who watch _

_And wait eagerly for My coming..._



_Blessed are their eyes, _

_Though they have yet to see,_

_For they have understood... _



_Blessed are their feet also, _

_For they walk along the highway _

_Called Holy, and do not tarry..._



_Lo, they follow close behind Me, _

_Going wheresoever I lead them... _



_Behold, they have passed_

_From judgment into life,_

_And I have provided The Way._



\u2020



_YahuShua is The Gift, _

_Whom you call Christ and Jesus... _



_Blessed are those who know and accept Him._



\u2020



_There is only one name under Heaven,_

_By which you must be saved... _



_And oh how blessed are those _

_Who put their trust in Him._`}]},{id:"blessed-are-those-who-receive-of-me",num:4,title:"Blessed Are Those Who Receive of Me",paragraphs:[{align:"center",text:`_Blessed are the meek, _

_For they shall inherit the Kingdom on Earth. _



\u2020



_Blessed are those who _

_Bless the name of The Lord,_

_And happy are those who have His name_

_Perpetually on their lips..._



_Life without end to all those _

_Who call upon the name of The Lord,_

_Forever striving to walk in His ways _

_And keep His Commandments..._



_Fully partaking of the fruit of the Spirit._



\u2020



_Blessed are those who have tasted and seen, _

_For they have received of The Divine Gift..._



_The Lord Himself shall be _

_Their inheritance, forever._



\u2020



_All My servants move, speak and hear Me _

_Through My spirit, and only through _

_The Son shall My children come _

_To know Me as I truly am... _



_And oh how blessed _

_Are those who know Him..._



_For they love Him and obey His voice, _

_Having truly received of Him, _

_Even of His spirit, the Spirit of God._



\u2020



_Blessed is the man who sincerely repents,_

_And also departs from the ways of his flesh..._



_And happy is the man who loves The Lord _

_With all his heart, with all his soul, _

_With all his mind and with all his strength..._



_For he knows The Kingdom of Heaven already, _

_And shall soon enter in. _



\u2020



_Blessed are those who eat of The True Bread, _

_And drink continuously from _

_The Fountain of Living Waters..._



_They shall inherit everlasting life._



\u2020



_Blessed are all those _

_In whom I see of Myself..._



_For these have already passed _

_From judgment into life, _

_Seated forever at My right hand._



\u2020



_Blessed is the man whose name _

_Is written in The Book of Life..._



_For he shall inherit everlasting life, _

_And his name shall endure forever._



\u2020



_Blessed are those who have the Spirit of God, _

_For God dwells within them._



\u2020



_Blessed be the name of The Lord..._



_Blessed are all those who _

_Receive of His blessings..._



_Even more blessed are those who are blessed_

_In The Blessing I had sent to them..._



_For they are baptized in the Spirit of Truth _

_And sprinkled with The Blood of Sprinkling,_

_By which I have blessed all nations, _

_As many as are willing to receive._



\u2020



_Blessed are those who embrace Me,_

_For they shall share in My goodness, _

_Even of all that I own!_`}]},{id:"blessed-are-those-who-worship-me",num:5,title:"Blessed Are Those Who Worship Me",paragraphs:[{align:"center",text:`_Blessed are all those who raise their voices _

_To Heaven and give Me perfect praise;_

_Blessed are those who offer up thanksgiving, _

_Without ceasing, in My Holy name..._



_I shall be their God, _

_And they shall be My people._



_Yet even more blessed are those _

_Who bow down and kiss the feet of My Son; _

_Their sins are forgiven them..._



_For those who embrace The Son of God _

_Have touched The Kingdom of Heaven..._



_Everlasting life is their reward,_

_Dwelling in union with _

_The Messiah, forever._



\u2020



_Blessed are those who worship with gratitude, _

_Giving thanks for the birth of My Son..._



_Even more blessed are those who _

_Worship and give thanks_

_For His death and resurrection._



\u2020



_Blessed is he who reveres My name _

_And gives Me perfect praise..._



_For I am coming quickly!_



\u2020



_I am The First! _

_Behold, I am also The Last!... _



_Blessed therefore are all those _

_Who bow down before Me; _

_For in them shall the vision be made _

_Complete and The Word established, _

_Even as it was at the first _

_And shall also be at the last..._



_Trust in Me therefore, for I AM HE!_`}]},{id:"blessed-are-those-who-walk-in-my-ways",num:6,title:"Blessed Are Those Who Walk in My Ways",paragraphs:[{align:"center",text:`_Blessed are the sons of men who bow down,_

_Blessed are all those who fear The Lord... _



_Blessed are those who truly know Me, _

_Who give heed to My words, to do them..._



_Blessed also are all those who say, \u201CYes, Lord\u201D, _

_To My every decree and proclamation, _

_Seeking always to obey My every command... _



_For their reward is coming, _

_Coming very quickly. _



\u2020



_Blessed are those who _

_Accept The Blessing from God_

_And walk in His ways._



\u2020



_Blessed are those given and received in marriage,

Who keep My Commandments..._



_For they shall experience love, _

_Compassion, understanding, _

_Much joy and earthly fulfillment._



\u2020



_Blessed are those who run to Me, _

_For they shall be blessed in My presence..._



_Even more blessed are those _

_Who run to Me, then obey My Word, _

_For their blessing is complete _

_And they are at peace..._



_Deliverance they shall surely know._



\u2020



_Blessed is he who fears The Lord _

_And finds delight in His Commands..._



_Blessed are all those who do what _

_They have heard, for these live by faith,_

_And by their example shall many _

_Be led to Salvation. _



\u2020



_Those who follow My voice _

_Shall be blessed in it._



\u2020



_Blessed are those who fear The Lord _

_Rather than men, taking much _

_Delight in God\u2019s Commands._



\u2020



_Blessed are those who answer, \u201CYes, Lord\u201D,_

_For their faith is revealed..._



_Blessed are those who pray, _

_\u201CYour will be done, Lord\u201D, _

_For they have great trust..._



_Blessed are those who say, \u201CAmen, Lord\u201D,_

_At all times and in every season, _

_For they have understood... _



_Blessed are those who know, _

_I AM WHO I AM;_

_They shall have peace._



\u2020



_Oh how blessed are those _

_Who have received of Grace,_

_And seek to please The Father _

_By obeying His Law, and teach men so... _



_Grace AND The Law._



\u2020



_Blessed are all those who take _

_Pleasure in My Sabbaths, _

_Who also delight in doing what is right _

_And good on My Holy Days..._



_They shall be renewed _

_In the presence of The Lord._



\u2020



_Blessed are My servants who seek to obey _

_My commands without hesitation, _

_For their trust is apparent... _



_Blessed are those who seek to please Me, _

_For in them am I well pleased._



\u2020



_Blessed are those who come out _

_At the sound of My voice,_

_For I shall surely gather them together..._



_Indeed, blessed are all those _

_Who obey My voice and heed _

_The word of My Commandment,_

_For they shall be first partakers of The Glory. _



\u2020



_It is written: _

_\u201CWho can know the mind of God?\u201D{{ref:Isaiah 40:13; Romans 11:34}}..._



_Yet I have given you the mind of Mashiach {{ref:1 Corinthians 2:16}}..._



_Therefore, blessed are all those_

_Who strive always to walk in His ways._



\u2020



_Blessed are all those who receive _

_This Word, and obey it..._



_They shall be set apart. _



\u2020



_Blessed are those who diligently _

_Seek to please The Lord their God_

_And keep His Commandments..._



_They will be lifted up._



\u2020



_Blessed are those who _

_Take part in the first harvest..._



_They shall be first partakers of The Glory._



\u2020



_Blessed are those who _

_Come out from among them..._



_Blessed are those who _

_Obey God rather than men..._



_Blessed are all those who place _

_Their trust in The Son of God,_

_Striving always to walk in His ways_

_And keep His Commandments..._



_They shall surely _

_Be taken out of this place._



\u2020



_For there is but One Sanctuary _

_In which My people are to take refuge,_

_One Shelter from the heat of the Day..._



_Blessed, therefore, are all those who embrace Him fully _

_And strive always to walk in His ways..._



_They shall be hidden under the shadow _

_Of His healing wings, high and lifted up..._



_Says The Lord._`}]},{id:"blessed-are-those-who-overcome",num:7,title:"Blessed Are Those Who Overcome",paragraphs:[{align:"center",text:`_Blessed are those who overcome _

_For My name\u2019s sake..._



_To these is there a place of great honor,_

_Where they shall be placed upon the mantle_

_Of The Lord, in His house, forever._



\u2020



_Blessed are all those who lose their life_

_In this world, for My sake; _

_They have their reward..._



_Yet woe to those who hold fast _

_To their life in this world, _

_For all they have is passing away._



\u2020



_Blessed are all those who patiently endure _

_For My name\u2019s sake..._



_They fulfill the promises._



\u2020



_Blessed is the one who embraces _

_The calling of The Lord wholeheartedly..._



_For a servant such as this lays down his life _

_Each day, bearing his cross after Me..._



_Upon waking he kneels down _

_At the feet of The Lord, _

_With an open heart and open hands..._





_And in this servant My soul delights._



\u2020



_Blessed are those who crucify their lives of old, _

_And present themselves as a _

_Living sacrifice unto God..._



_For their prayers have been received _

_Up to Heaven, for a memorial _

_Before The Holy One of Israel._



\u2020



_There can be no birth apart from travail, _

_For birth is always accompanied _

_By much travail... _



_Yet oh how blessed are those _

_Who persevere with their hearts _

_Fixed upon the goal, enduring the pain,_

_For they shall surely receive their reward._



\u2020



_Blessed is the wise and faithful servant, _

_Who gives no thought to how they are _

_Perceived in the eyes of others; _

_For they obey My voice, and are not _

_Dismayed by the looks of those _

_Who judge without knowledge..._



_Indeed, they seek only to please their Master, _

_Having no need of the approval of others._



\u2020



_Blessed are those who do not return _

_Evil for evil, or reviling for reviling, _

_But rather pray for their enemies..._



_Blessed are those who hold no ill-will _

_In their heart toward another..._



_Indeed, blessed are all those who forgive _

_Everyone who has sinned against them,_

_For great shall be their reward in Heaven._`}]},{id:"blessed-are-those-who-serve-me-as-i-have-loved-them",num:8,title:"Blessed Are Those Who Serve Me as I Have Loved Them",paragraphs:[{align:"center",text:`_Give, and you will also receive..._



_Yet even more blessed is the one who gives, _

_Expecting nothing in return; _

_For this is to walk in Me, in My very footsteps._



\u2020



_Blessed are those who call upon _

_The name of The Messiah_

_In sincerity and in truth,_

_For the Spirit of God dwells within them... _



_Blessed are those who seek refuge in Him, _

_For they shall find it..._



_Blessed are all those who love _

_And obey The Son, _

_For they shall be delivered._



\u2020



_Blessed is that servant of Mine _

_Who seeks out the poor, _

_Whose heart is eager to help the needy, _

_For they know My ways and seek to please Me... _



_Blessed also is My servant who gives_

_Out of the abundance they have received, _

_For they walk in My ways..._



_Yet most blessed is My servant _

_Who gives from their lack,_

_For they do justly, love mercy, _

_And walk humbly with their God..._



_Indeed, they have understood._



\u2020



_Blessed is My servant who gives _

_Out of the abundance of their heart..._



_A joyful giver,_

_Who knows that all they have is Mine _

_And all I have is theirs._



\u2020



_Blessed are those who wait eagerly for My coming,_

_Blessed are all those who keep watch,_

_For I shall bless them with a multitude of _

_Blessings, a great fulfilling of My spirit in them!..._



_Lo, they shall stand up and march _

_Across these desolate lands!... _



_They shall stand up! Says The Lord of Hosts..._



_And I shall bless them _

_And bring glory to My name!_



\u2020



_Blessed are the feet of those I am sending, _

_For they have received a message from God._



\u2020



_The King shall stand up, _

_And all creation shall bow down!..._



_And He shall look upon _

_The joy of His heart with gladness, _

_And the blessing shall be fulfilled... _



_For He shall bless them and keep them, _

_And make His face to shine upon them; _

_He shall be gracious to them, _

_And lift up His countenance upon them, _

_And grant them peace {{ref:Numbers 6:24-26}}... _



_And thus shall My name be placed _

_Upon the children of Israel, _

_Even upon all who have been grafted in, _

_And they shall be blessed!..._



_Yea, they shall be exceedingly glad, _

_Dwelling in the presence _

_Of The Lord, forever!_



_Therefore, blessed are all those

Who seek forgiveness in

YahuShua HaMashiach, _

_And also receive..._



_For in His name shall all find freedom,_

_Solace under the shadow _

_Of His healing wings!..._



_Life without end!..._



_Says The Lord God._`}]}],THE_BLESSED_SCRIPTURES={"Matthew 4:4":"But He answered and said, \u201CIt is written, \u2018Man shall not live by bread alone, but by every word that proceeds from the mouth of God.\u2019 \u201D","Isaiah 40:13; Romans 11:34":"Isaiah 40:13 \u2014 Who has directed the Spirit of the LORD, Or as His counselor has taught Him? | Romans 11:34 \u2014 \u201CFor who has known the mind of the LORD? Or who has become His counselor?\u201D","1 Corinthians 2:16":"For \u201Cwho has known the mind of the LORD that he may instruct Him?\u201D But we have the mind of Christ.","Numbers 6:24-26":"24. \u201CThe LORD bless you and keep you; 25. The LORD make His face shine upon you, And be gracious to you; 26. The LORD lift up His countenance upon you, And give you peace.\u201D \u2019"},HOLY_DAYS=[{id:"the-holy-days",num:1,title:"The Holy Days",type:"wtlb",sourceLabel:"Words To Live By: Part Two",paragraphs:[{align:"center",text:`The significance of The Holy Days is found

In their meaning and revealed by their order...`},{align:"center",text:`Even as all find their fulfillment in The Messiah

And their completion in the coming of The Lord...`},{align:"center",text:"Says The Lord."}],nextEntry:{id:"embracing-the-gift",title:"Embracing The Gift"},scriptures:{}},{id:"embracing-the-gift",num:2,title:"Embracing The Gift",type:"wtlb",sourceLabel:"Words To Live By: Part One",paragraphs:[{align:"center",text:`The Holy Days are the

Stepping stones to Heaven...`},{align:"center",text:`In understanding their meaning shall you

Progress quickly along the path I have laid...`},{align:"center",text:`And when I have fulfilled them to the last

The journey shall be complete,

For those who have accepted and received...



Says The Lord YahuShua.`}],prevEntry:{id:"the-holy-days",title:"The Holy Days"},nextEntry:{id:"the-salvation-day",title:"The Salvation Day"},scriptures:{}},{id:"the-salvation-day",num:3,title:"The Salvation Day",type:"wtlb",sourceLabel:"Words To Live By: Part One",paragraphs:[{align:"center",text:"The Salvation Day of Men is four-fold:"},{align:"center",text:`It was ordained before the foundation

Of the world, fulfilled at My birth,

Finished at My death on the cross,

And solidified eternally upon My resurrection...



Says The Lord YahuShua.`}],prevEntry:{id:"embracing-the-gift",title:"Embracing The Gift"},nextEntry:{id:"consider-my-love",title:"Consider My Love"},scriptures:{}},{id:"consider-my-love",num:4,title:"Consider My Love",type:"wtlb",sourceLabel:"Words To Live By: Part One",paragraphs:[{align:"center",text:`Behold My hands and My feet, and consider My love;

For the scars of My passion remain,

A holy, everlasting covenant

Written in the blood of The Lamb.`},{align:"center",text:`Taste and see, beloved, drink!

Until that which is veiled is veiled no longer,

Until the void within your heart is filled.`},{align:"center",text:`For My love was written in every stripe I endured for you,

Poured out in every drop of blood I shed for you,

Revealed when you pierced My hands and My feet.`},{align:"center",text:"Beloved, I am married unto you!..."},{align:"center",text:`A union sealed forever in the blood we share...



Says The Lord YahuShua.`}],prevEntry:{id:"the-salvation-day",title:"The Salvation Day"},nextEntry:{id:"walking-in-the-footsteps-of-the-messiahs-passion",title:"Walking in the Footsteps of The Messiah\u2019s Passion"},scriptures:{}},{id:"walking-in-the-footsteps-of-the-messiahs-passion",num:5,title:"Walking in the Footsteps of The Messiah\u2019s Passion",type:"letter",sourceLabel:"Volume Four",date:"2/10/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to those who believe, to those who have ears to hear, eyes to see, and a heart which longs to know Me as I truly am:"},{t:"text",v:"Three are fulfilled, one is, and three are to come, coming quickly. Of the three fulfilled, you shall remember and honor them according to how I command you. The dates and times, the new moons and seasons, are not the focus; rather, YahuShua is the focus. For the significance of these Holy Days is found in their meaning and revealed by their order, even as all find their fulfillment in The Messiah and their completion in the coming of The Lord. Thus you shall not keep My Holy Days as the world, nor as those held captive in the churches of men, nor shall you follow the futile traditions of the Jews. For those who deny The Son deny The Father also; their worship is in vain. For the Jews reject The Son of Salvation, and the churches of men pollute His name and corrupt His image without ceasing. For they do always follow the dictates of their own hearts, and in their stubbornness they hold fast to religion, embracing the commandments of men, walking in every perverse doctrine and tradition thereof, which I hate! Therefore you shall set yourselves apart from them, and do all I command you: You shall honor the Passover a week before the time, beginning Tuesday at sundown. You shall walk in the footsteps of Messiah, and remember, blessing His name and giving thanks according to each day He fulfilled in His Passion. Four holy convocations, plus one, shall be kept."}]},{type:"poetry",lines:[[{t:"italic",v:"As The Messiah kept The Passover,"}],[{t:"italic",v:"So shall you in like manner keep The Passover..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As He was afflicted, you shall fast..."}]]},{type:"poetry",lines:[[{t:"italic",v:"As He slept in the tomb, you shall mourn..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And as He rose from the grave,"}],[{t:"italic",v:"You shall rejoice and sing praises..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, you shall complete the week with joy and feasting..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then later shall you remember The Bridegroom being taken from you,"}],[{t:"italic",v:"And rejoice in the Blessed Hope of His soon return."}]]},{type:"para",segments:[{t:"text",v:"In this way will you begin to partake of the hidden manna, and your hearts shall be glad, causing you to see with greater eyes; your understanding of the Glory brightening as you enter into a more profound knowledge of the salvation of God, which is accomplished and fulfilled in The Son of Man. For the Holy Days are revelation, revealing hidden things kept secret since the world began - signposts of things to come, a foretaste of The Kingdom, a glimpse into the Glory of God even as the Scriptures, unfolding and coming to light as the will of God is manifest."}]},{type:"para",segments:[{t:"text",v:"And though you are counted as last partakers by the Jews, and scorned by those who dwell in the churches of men, I tell you, you shall be first partakers. For I have set you apart as an example, and by these things shall you bear witness of My comings and goings. For I am The Lord, and I shall surely follow the counsel of My own will. For I do not receive counsel from men, nor shall I follow the line which they have stretched out for Me, that I might adhere to their rules or meet their expectations; rather I do that which is right and good in My own eyes. Therefore those who diligently seek to know The Father must abide in The Son, and obey His voice - living testaments to those without knowledge, an ensign to all nations, soon taken up, first partakers of the Glory."}]},{type:"poetry",lines:[[{t:"italic",v:"Indeed, many who are counted as first will be last,"}],[{t:"italic",v:"And many who are counted as last shall be first..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For those mocked and persecuted"}],[{t:"italic",v:"For My name\u2019s sake must be first..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Even as those who are mocked and persecuted"}],[{t:"italic",v:"Because of this Word shall be first also..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE LORD."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/walking-in-the-footsteps-of-the-messiahs-passion",videoVoiceUrl:"https://www.youtube.com/watch?v=4McEeRHG1wc&list=PLE8FlkxQPQkMkjV_V68yjBNVY-LTyD5Xy&index=20",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord#The_Coming_of_The_Lord"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"}],prevEntry:{id:"consider-my-love",title:"Consider My Love"},nextEntry:{id:"do-this-in-remembrance-of-me",title:"Do This in Remembrance of Me"}},{id:"do-this-in-remembrance-of-me",num:6,title:"Do This in Remembrance of Me",type:"letter",sourceLabel:"Volume Two",date:"4/25/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For Timothy, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Listen and have understanding, for thus says The Lord your Redeemer:"},{t:"text",v:"Only those who truly believe keep the Passover. To them it is a memorial, a time of reflection and the giving of thanks, a Sabbath."}]},{type:"para",segments:[{t:"text",v:"Therefore, Timothy, do not your own pleasure on the Holy Days or on the Sabbath."},{t:"fn",v:"1"},{t:"text",v:"Rather do that which pleases The Lord your God. Keep the feasts holy, and cause your life to follow suit; unleaven your heart. Discern what is most needful, and when in doubt, ask. And concerning the rites and ceremonial symbols of the feasts, consider their meaning and rejoice in their fulfillment, for it is accomplished. Do not agonize over the details, nor stumble over the letter. And concerning that which you partake of for the body, it is of little consequence. Rather feast upon that which sustains your soul. Remember Me and My Passion, as I have shown you; offer up thanksgiving, and consider your salvation and The Loving Mercy of God. For the intent of one\u2019s heart speaks volumes more than the offering put forth by their hands. Yet I tell you the truth, many will there be who enter The Kingdom of Heaven, who did not keep the feasts of The Lord. And many will there be left standing outside the gates, who kept the feasts of The Lord. For those without the gate retain their sin, for they hold fast to malice and have not yet departed from wickedness."},{t:"fn",v:"2"},{t:"text",v:"Yet the hearts of the first election are filled with compassion and a sincere desire to walk in My ways, having called upon My name in sincerity and in truth, as they bring forth new works meet for repentance."},{t:"fn",v:"3"},{t:"text",v:"For where there are righteous works, there are also those who seek to spoil them for the sake of pride and envy. And where there is pure knowledge, there are also those who defile it among women."},{t:"fn",v:"4"},{t:"text",v:"Take heed, therefore, and remember My teaching:"},{t:"italic",v:"Beware of the leaven of the Pharisees and the Sadducees."},{t:"fn",v:"5"},{t:"text",v:"For their like still exists today; only their names and vesture have changed."}]},{type:"poetry",lines:[[{t:"italic",v:"Yet the ignorance of the meek is no cause for offense,"}],[{t:"italic",v:"Nor shall the error of the humble bring forth rebuke;"}],[{t:"italic",v:"For I know the heart and look upon the innermost intentions"},{t:"fn",v:"6"},{t:"italic",v:"..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore keep the feast, not with the old leaven,"}],[{t:"italic",v:"Nor with the leaven of malice and wickedness,"}],[{t:"italic",v:"But with the unleavened bread of sincerity and truth,"}],[{t:"italic",v:"As it is written in accordance with the New Covenant"},{t:"fn",v:"7"},{t:"italic",v:"..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"Isaiah 58:13"},2:{type:"scripture",ref:"Revelation 22:15"},3:{type:"scripture",ref:"Matthew 3:8"},4:{type:"note",text:"\u201CWomen\u201D in this context refers to the churches of men"},5:{type:"scripture",ref:"Matthew 16:6"},6:{type:"scripture",ref:"Jeremiah 17:10"},7:{type:"scripture",ref:"1 Corinthians 5:7-8"}},nkjv:{"Isaiah 58:13":"\u201CIf you turn away your foot from the Sabbath, From doing your pleasure on My holy day, And call the Sabbath a delight, The holy day of the LORD honorable, And shall honor Him, not doing your own ways, Nor finding your own pleasure, Nor speaking your own words,","Revelation 22:15":"But outside are dogs and sorcerers and sexually immoral and murderers and idolaters, and whoever loves and practices a lie.","Matthew 3:8":"Therefore bear fruits worthy of repentance,","Matthew 16:6":"Then Jesus said to them, \u201CTake heed and beware of the leaven of the Pharisees and the Sadducees.\u201D","Jeremiah 17:10":"I, the LORD, search the heart, I test the mind, Even to give every man according to his ways, According to the fruit of his doings.","1 Corinthians 5:7-8":"7. Therefore purge out the old leaven, that you may be a new lump, since you truly are unleavened. For indeed Christ, our Passover, was sacrificed for us. 8. Therefore let us keep the feast, not with old leaven, nor with the leaven of malice and wickedness, but with the unleavened bread of sincerity and truth."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/do-this-in-remembrance-of-me",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/do-this-in-remembrance-of-me?in=the-volumes-of-truth/sets/volume-two",videoVoiceUrl:"https://www.youtube.com/watch?v=_k7yeHHdvYc&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=7",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],prevEntry:{id:"walking-in-the-footsteps-of-the-messiahs-passion",title:"Walking in the Footsteps of The Messiah\u2019s Passion"},nextEntry:{id:"i-am-the-passover-and-the-lamb-the-new-covenant-with-men",title:"I Am The Passover and The Lamb, The New Covenant with Men"}},{id:"i-am-the-passover-and-the-lamb-the-new-covenant-with-men",num:7,title:"I Am The Passover and The Lamb, The New Covenant with Men",type:"letter",sourceLabel:"Volume Two",date:"4/18/05",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Messiah who is called Christ, The Holy One of Israel:"},{t:"text",v:"I am The Lamb of God without spot or blemish, the blood which was shed and placed upon the doorposts,"},{t:"fn",v:"1"},{t:"text",v:"delivering My people from the power of sin,"},{t:"fn",v:"2"},{t:"text",v:"which is death."},{t:"fn",v:"3"},{t:"text",v:"I am The Passover."},{t:"fn",v:"4"},{t:"text",v:"For as it is written in The Law, all things must be purified with blood, and without the shedding of blood there can be no remission."},{t:"fn",v:"5"},{t:"text",v:"Thus no one goes to The Father, unless they receive of Me. Unless they eat My flesh and drink My blood, they have no life in them. For whosoever eats My flesh and drinks My blood has everlasting life, and I will raise them up at the Last Day. For My flesh is food indeed, and My blood is drink indeed. Thus all who eat My flesh and drink My blood live in Me, and I in them. I am The Living Bread which came down from Heaven! If anyone eats this bread, he will live forever! And the bread that I gave was My flesh, which was given for the life of the world. This I have already told you."},{t:"fn",v:"6"},{t:"text",v:"Therefore keep the Passover in remembrance of Me and My Passion, according to The New Covenant."},{t:"fn",v:"7"},{t:"text",v:"For it is accomplished, and was sealed forevermore upon My resurrection. For The Lamb was slain, My people redeemed in all the earth; and behold, I am risen, crowned with glory and honor, forever and ever."},{t:"fn",v:"8"},{t:"text",v:"Amen."}]},{type:"para",segments:[{t:"text",v:"Therefore, again I say to you, celebrate Passover, yet not as in the days of Moses; nor as the unbelieving in Israel, upon whom the veil remains, for they have yet to look upon Me."},{t:"fn",v:"9"},{t:"text",v:"For the Passover was a signpost, a shadow of glorious things to come."},{t:"fn",v:"10"},{t:"text",v:"Read the writing thereof and have understanding, take its meaning to heart."},{t:"fn",v:"11"},{t:"text",v:"For the Holy Days are revelation, the Plan of the Ages revealed."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore rejoice, My people, for your Redeemer lives!"}],[{t:"italic",v:"Death has passed over you!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Therefore eat, drink, and give thanks"}],[{t:"italic",v:"In remembrance of Me, and I shall also"}],[{t:"italic",v:"Remember you in the day I gather My own..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then shall you truly know Me,"}],[{t:"italic",v:"Just as I have always known you,"}],[{t:"italic",v:"Even from the foundation of the world..."}]]},{type:"closing-fn",segments:[{t:"italic",v:"Says He who is, and was, and is to come,"},{t:"fn",v:"12"},{t:"italic",v:"YahuShua, The Salvation of God."}]}],footnotes:{1:{type:"scripture",ref:"Exodus 12:1-27"},2:{type:"scripture",ref:"John 1:29"},3:{type:"scripture",ref:"Romans 6:23"},4:{type:"scripture",ref:"1 Corinthians 5:7"},5:{type:"scripture",ref:"Hebrews 9:22"},6:{type:"scripture",ref:"John 6:48-58"},7:{type:"scripture",ref:"Luke 22:14-20"},8:{type:"scripture",ref:"Hebrews 2:9"},9:{type:"scripture",ref:"Zechariah 12:10"},10:{type:"scripture",ref:"Colossians 2:16-17"},11:{type:"scripture",ref:"Hebrews 10:1-19"},12:{type:"scripture",ref:"Revelation 1:4, Revelation 1:8, Revelation 11:17"}},nkjv:{"Exodus 12:1-27":"1. Now the LORD spoke to Moses and Aaron in the land of Egypt, saying, 2. \u201CThis month shall be your beginning of months; it shall be the first month of the year to you. 3. Speak to all the congregation of Israel, saying: \u2018On the tenth of this month every man shall take for himself a lamb, according to the house of his father, a lamb for a household. 4. And if the household is too small for the lamb, let him and his neighbor next to his house take it according to the number of the persons; according to each man\u2019s need you shall make your count for the lamb. 5. Your lamb shall be without blemish, a male of the first year. You may take it from the sheep or from the goats. 6. Now you shall keep it until the fourteenth day of the same month. Then the whole assembly of the congregation of Israel shall kill it at twilight. 7. And they shall take some of the blood and put it on the two doorposts and on the lintel of the houses where they eat it. 8. Then they shall eat the flesh on that night; roasted in fire, with unleavened bread and with bitter herbs they shall eat it. 9. Do not eat it raw, nor boiled at all with water, but roasted in fire\u2014its head with its legs and its entrails. 10. You shall let none of it remain until morning, and what remains of it until morning you shall burn with fire. 11. And thus you shall eat it: with a belt on your waist, your sandals on your feet, and your staff in your hand. So you shall eat it in haste. It is the LORD\u2019s Passover. 12. \u2018For I will pass through the land of Egypt on that night, and will strike all the firstborn in the land of Egypt, both man and beast; and against all the gods of Egypt I will execute judgment: I am the LORD. 13. Now the blood shall be a sign for you on the houses where you are. And when I see the blood, I will pass over you; and the plague shall not be on you to destroy you when I strike the land of Egypt. 14. \u2018So this day shall be to you a memorial; and you shall keep it as a feast to the LORD throughout your generations. You shall keep it as a feast by an everlasting ordinance. 15. Seven days you shall eat unleavened bread. On the first day you shall remove leaven from your houses. For whoever eats leavened bread from the first day until the seventh day, that person shall be cut off from Israel. 16. On the first day there shall be a holy convocation, and on the seventh day there shall be a holy convocation for you. No manner of work shall be done on them; but that which everyone must eat\u2014that only may be prepared by you. 17. So you shall observe the Feast of Unleavened Bread, for on this same day I will have brought your armies out of the land of Egypt. Therefore you shall observe this day throughout your generations as an everlasting ordinance. 18. In the first month, on the fourteenth day of the month at evening, you shall eat unleavened bread, until the twenty-first day of the month at evening. 19. For seven days no leaven shall be found in your houses, since whoever eats what is leavened, that same person shall be cut off from the congregation of Israel, whether he is a stranger or a native of the land. 20. You shall eat nothing leavened; in all your dwellings you shall eat unleavened bread.\u2019 \u201D 21. Then Moses called for all the elders of Israel and said to them, \u201CPick out and take lambs for yourselves according to your families, and kill the Passover lamb. 22. And you shall take a bunch of hyssop, dip it in the blood that is in the basin, and strike the lintel and the two doorposts with the blood that is in the basin. And none of you shall go out of the door of his house until morning. 23. For the LORD will pass through to strike the Egyptians; and when He sees the blood on the lintel and on the two doorposts, the LORD will pass over the door and not allow the destroyer to come into your houses to strike you. 24. And you shall observe this thing as an ordinance for you and your sons forever. 25. It will come to pass when you come to the land which the LORD will give you, just as He promised, that you shall keep this service. 26. And it shall be, when your children say to you, \u2018What do you mean by this service?\u2019 27. that you shall say, \u2018It is the Passover sacrifice of the LORD, who passed over the houses of the children of Israel in Egypt when He struck the Egyptians and delivered our households.\u2019 \u201D So the people bowed their heads and worshiped.","John 1:29":"The next day John saw Jesus coming toward him, and said, \u201CBehold! The Lamb of God who takes away the sin of the world!","Romans 6:23":"For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord.","1 Corinthians 5:7":"Therefore purge out the old leaven, that you may be a new lump, since you truly are unleavened. For indeed Christ, our Passover, was sacrificed for us.","Hebrews 9:22":"And according to the law almost all things are purified with blood, and without shedding of blood there is no remission.","John 6:48-58":"48. I am the bread of life. 49. Your fathers ate the manna in the wilderness, and are dead. 50. This is the bread which comes down from heaven, that one may eat of it and not die. 51. I am the living bread which came down from heaven. If anyone eats of this bread, he will live forever; and the bread that I shall give is My flesh, which I shall give for the life of the world.\u201D 52. The Jews therefore quarreled among themselves, saying, \u201CHow can this Man give us His flesh to eat?\u201D 53. Then Jesus said to them, \u201CMost assuredly, I say to you, unless you eat the flesh of the Son of Man and drink His blood, you have no life in you. 54. Whoever eats My flesh and drinks My blood has eternal life, and I will raise him up at the last day. 55. For My flesh is food indeed, and My blood is drink indeed. 56. He who eats My flesh and drinks My blood abides in Me, and I in him. 57. As the living Father sent Me, and I live because of the Father, so he who feeds on Me will live because of Me. 58. This is the bread which came down from heaven\u2014not as your fathers ate the manna, and are dead. He who eats this bread will live forever.\u201D","Luke 22:14-20":"14. When the hour had come, He sat down, and the twelve apostles with Him. 15. Then He said to them, \u201CWith fervent desire I have desired to eat this Passover with you before I suffer; 16. for I say to you, I will no longer eat of it until it is fulfilled in the kingdom of God.\u201D 17. Then He took the cup, and gave thanks, and said, \u201CTake this and divide it among yourselves; 18. for I say to you, I will not drink of the fruit of the vine until the kingdom of God comes.\u201D 19. And He took bread, gave thanks and broke it, and gave it to them, saying, \u201CThis is My body which is given for you; do this in remembrance of Me.\u201D 20. Likewise He also took the cup after supper, saying, \u201CThis cup is the new covenant in My blood, which is shed for you.","Hebrews 2:9":"But we see Jesus, who was made a little lower than the angels, for the suffering of death crowned with glory and honor, that He, by the grace of God, might taste death for everyone.","Zechariah 12:10":"\u201CAnd I will pour on the house of David and on the inhabitants of Jerusalem the Spirit of grace and supplication; then they will look on Me whom they pierced. Yes, they will mourn for Him as one mourns for his only son, and grieve for Him as one grieves for a firstborn.","Colossians 2:16-17":"16. So let no one judge you in food or in drink, or regarding a festival or a new moon or sabbaths, 17. which are a shadow of things to come, but the substance is of Christ.","Hebrews 10:1-19":"1. For the law, having a shadow of the good things to come, and not the very image of the things, can never with these same sacrifices, which they offer continually year by year, make those who approach perfect. 2. For then would they not have ceased to be offered? For the worshipers, once purified, would have had no more consciousness of sins. 3. But in those sacrifices there is a reminder of sins every year. 4. For it is not possible that the blood of bulls and goats could take away sins. 5. Therefore, when He came into the world, He said: \u201CSacrifice and offering You did not desire, But a body You have prepared for Me. 6. In burnt offerings and sacrifices for sin You had no pleasure. 7. Then I said, \u2018Behold, I have come\u2014 In the volume of the book it is written of Me\u2014 To do Your will, O God.\u2019 \u201D 8. Previously saying, \u201CSacrifice and offering, burnt offerings, and offerings for sin You did not desire, nor had pleasure in them\u201D (which are offered according to the law), 9. then He said, \u201CBehold, I have come to do Your will, O God.\u201D He takes away the first that He may establish the second. 10. By that will we have been sanctified through the offering of the body of Jesus Christ once for all. 11. And every priest stands ministering daily and offering repeatedly the same sacrifices, which can never take away sins. 12. But this Man, after He had offered one sacrifice for sins forever, sat down at the right hand of God, 13. from that time waiting till His enemies are made His footstool. 14. For by one offering He has perfected forever those who are being sanctified. 15. But the Holy Spirit also witnesses to us; for after He had said before, 16. \u201CThis is the covenant that I will make with them after those days, says the LORD: I will put My laws into their hearts, and in their minds I will write them,\u201D 17. then He adds, \u201CTheir sins and their lawless deeds I will remember no more.\u201D 18. Now where there is remission of these, there is no longer an offering for sin. 19. Therefore, brethren, having boldness to enter the Holiest by the blood of Jesus,","Revelation 1:4, Revelation 1:8, Revelation 11:17":"Revelation 1:4 \u2014 John, to the seven churches which are in Asia: Grace to you and peace from Him who is and who was and who is to come, and from the seven Spirits who are before His throne, | Revelation 1:8 \u2014 \u201CI am the Alpha and the Omega, the Beginning and the End,\u201D says the Lord, \u201Cwho is and who was and who is to come, the Almighty.\u201D | Revelation 11:17 \u2014 saying: \u201CWe give You thanks, O Lord God Almighty, The One who is and who was and who is to come, Because You have taken Your great power and reigned."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-the-passover-and-the-lamb-the-new-covenant-with-men-2",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/i-am-the-passover-and-the-lamb?in=the-volumes-of-truth/sets/volume-two",videoVoiceUrl:"https://www.youtube.com/watch?v=SQNOSo5XNLw&list=PLE8FlkxQPQkM99Siv2xPqHtuLS9gEQ6FA&index=4",videoMusicUrl:"https://www.youtube.com/watch?v=IB6TJi3Q92Y&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=18",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding the First and Second Resurrection",url:"https://answersonlygodcangive.com/Regarding_the_First_and_Second_Resurrection"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"}],prevEntry:{id:"do-this-in-remembrance-of-me",title:"Do This in Remembrance of Me"},nextEntry:{id:"keep-the-passover",title:"Keep The Passover"}},{id:"keep-the-passover",num:8,title:"Keep The Passover",type:"letter",sourceLabel:"Volume Three",date:"3/20/07",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord:"},{t:"text",v:"My children, keep the Passover. Keep it according to the New Covenant, in faith and love, and remember. Yet you who call of yourselves Christian do always dishonor Me. Behold, you pollute the glory of My sacrifice with filthy traditions and desecrate My resurrection with pagan practices, forsaking those things which you were to keep holy and remember, nor will you incline the ear. Churches of men, know you not that in these Seven (the Holy Days) is wisdom and understanding, the very mind of God?! Yet you choose vanities on top of vanities, embracing corrupt doctrine and pagan-laced tradition, placing your stamp of approval on them. For you are a most perverse and adulterous generation. Churches of men, I am not of this world, yet you are of this world. Thus only those who obey My voice trust in Me, and only those who embrace Me as I truly am are set apart. For I live in them and they follow Me. You claim you trust in Me and that I live in you, yet not one of you obeys My voice; indeed, you ignore My example and refuse to walk in My ways. For if I truly lived in you, then you would do as I did. Beloved, follow Me! Keep the Passover, honor the Holy Days, and remember the Sabbath. Only then will you begin to see, only then will you understand. For the Holy Days are revelation, every Sabbath a blessing, a sign between Me and you that you may know I am The Lord who sanctifies you."}]},{type:"poetry",lines:[[{t:"italic",v:"And behold, four are fulfilled:"}],[{t:"italic",v:"Salvation assured, sin and death overcome, the Spirit given..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Three are coming quickly:"}],[{t:"italic",v:"Sin destroyed, evil bound, My seat taken, Judgment..."}]]},{type:"poetry",lines:[[{t:"italic",v:"A new day, even one thousand years..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Then a short season, consummation..."}]]},{type:"poetry",lines:[[{t:"italic",v:"An everlasting day in The Lord!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Amen, and amen."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/keep-the-passover-2",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/keep-the-passover?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=UHSdSNJvX58&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=38",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding the Holidays of Men",url:"https://answersonlygodcangive.com/Regarding_the_Holidays_of_Men"},{label:"God Speaks About Idolatry",url:"https://answersonlygodcangive.com/God_Speaks_About_Idolatry"},{label:"God Speaks Regarding Those Who Take His Name in Vain",url:"https://answersonlygodcangive.com/God_Speaks_Regarding_Those_Who_Take_His_Name_in_Vain"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"Regarding Obedience",url:"https://answersonlygodcangive.com/Regarding_Obedience"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],prevEntry:{id:"i-am-the-passover-and-the-lamb-the-new-covenant-with-men",title:"I Am The Passover and The Lamb, The New Covenant with Men"},nextEntry:{id:"unleavened",title:"Unleavened"}},{id:"unleavened",num:9,title:"Unleavened",type:"letter",sourceLabel:"Volume Three",date:"4/19/06",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord, The Risen One, your Redeemer:"},{t:"text",v:"I had come to you as a man, clothed in the flesh, humble; My glory set aside, God become man, Immanu El... Living as all have lived in the body, yet not as man lives in the spirit; for I am clean, having no sin in My body, nor in My spirit, having obeyed every command of The Father - blameless."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Behold The Lamb of God without spot or blemish, sent to die for the sins of the world, bearing the full weight of transgression in His own body; the perfect sacrifice, acceptable to God, whereby all men are reconciled to The Father if they so choose to receive of The Free Gift, becoming once again My sons and daughters, free to enter the Garden and My love, from which they shall never again depart."}]},{type:"para",segments:[{t:"bold-italic",v:"Thus says The Risen Lamb:"},{t:"text",v:"Therefore, as I have unleavened all men by My sacrifice, in the same way must those who live in Me crucify their lives daily, bearing their cross after Me. For the first six days of the feast shall be for a physical representation of My command to you:"},{t:"italic",v:"You are forgiven, now go out and sin no more."},{t:"text",v:"Be then separate from the ways of this world and the churches of men, and be for Me a strange and peculiar people who remain in My love, even as I kept The Father\u2019s commands and remain in His love. And the seventh day, it is the consummation of the six gone before, a holy convocation, the cleansing completed, a rest from all works against temptation and the many snares of the evil one. For I am coming quickly, and I shall make a complete end of all iniquity, of all things which lead My people into sin. For I had come at the first to unleaven all men, to heal the hearts of all who receive of Me, to bring peace to the minds of all who believe in Me, to set the captives free - I am The Passover! And now I am returning to make a complete end of all leaven which fills this world; behold, in a week and in the Day shall I accomplish it. Then rest, peace, one thousand years. So then, My children, even all who gather together in My name, have understanding of the Plan of the Ages. In the sixth day, the leaven of sin entered the Garden; and on the seventh, God rested, and blessed the seventh day and sanctified it. Thus here is wisdom:"},{t:"italic",v:"Six days, creation; the seventh, rest, holy. Six days since Adam; the seventh, rest, holy. Six days shall you labor; the seventh, rest, holy. Six days shall you feast; the seventh, rest, holy."}]},{type:"poetry",lines:[[{t:"italic",v:"Therefore, eat and drink in remembrance of Me;"}],[{t:"italic",v:"Be filled with the glory of The Lord!"}],[{t:"italic",v:"For I died; behold, I am risen!..."}]]},{type:"closing",text:"Says The Amen, The Firstborn from the dead, YahuShua HaMashiach, Lord and Savior of men."}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/unleavened",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/unleavened?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=z2pjy0bgeYI&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=21",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding the Day of The Lord",url:"https://answersonlygodcangive.com/Regarding_the_Day_of_The_Lord"},{label:"The Coming of The Lord",url:"https://answersonlygodcangive.com/The_Coming_of_The_Lord"},{label:"Regarding the Day and Hour Unknown",url:"https://answersonlygodcangive.com/Regarding_the_Day_and_Hour_Unknown"},{label:"God Speaks About The Sabbath",url:"https://answersonlygodcangive.com/God_Speaks_About_The_Sabbath"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],prevEntry:{id:"keep-the-passover",title:"Keep The Passover"},nextEntry:{id:"devotion",title:"Devotion"}},{id:"devotion",num:10,title:"Devotion",type:"letter",sourceLabel:"Letters to The Lord's Little Flock",date:"3/7/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"You shall partake only of that which is molded by the hands of a believing bride in each household, doing so with love and great joy in remembrance of Me. For I am He who molded you, and yet molds you still, even as I had unleavened you from the beginning by My sacrifice, remembering you during My Passion. Therefore, take and eat of that which I have provided. Do not go roundabout, nor seek that which is created by the hands of men; accept no replacements. Rather trust in My ways and see with greater eyes, rejoicing in every act of devotion, for I AM HE. Yet for those of you who have no wife, or dwell with a spouse who remains unwilling, you shall prepare the bread with your own hands, and be set apart for these seven days of the feast."}]},{type:"para",segments:[{t:"text",v:"Thus concerning spouses who remain rebellious, I say this: Ask of them nothing, nor partake of anything they offer during My Holy Days. For they have shown themselves unworthy of Me. For though you are two of one flesh by marriage, a division in spirit has occurred. And as it is written:"},{t:"italic",v:"Whatever you bind on earth will be bound in Heaven, and whatever you loose on earth will be loosed in Heaven."},{t:"fn",v:"1"},{t:"text",v:"Thus in the same way, when a division occurs on earth because of Me, so also is there a division in Heaven, says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"For My bride cleaves to Me, she honors Me"}],[{t:"italic",v:"And walks in My ways, and remains faithful..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet any who claim to be My bride, who knowingly"}],[{t:"italic",v:"Commit adultery with the pagan and the heathen,"}],[{t:"italic",v:"While cleaving to the ways of this world"}],[{t:"italic",v:"Or the churches of men, dishonor Me..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Thus between us a great gulf has formed..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And so shall it remain, until the day comes"}],[{t:"italic",v:"And is fulfilled, when she cries out, saying,"}],[{t:"italic",v:"\u201CBlessed is He who comes in The Name of The Lord!\u201D"}]]}],footnotes:{1:{type:"scripture",ref:"Matthew 18:18"}},nkjv:{"Matthew 18:18":"\u201CAssuredly, I say to you, whatever you bind on earth will be bound in heaven, and whatever you loose on earth will be loosed in heaven."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/devotion",videoVoiceUrl:"https://www.youtube.com/watch?v=nQjhhK4Yg6A&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=20",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding the True Bride",url:"https://answersonlygodcangive.com/Regarding_The_True_Church#Section_2_-_The_True_Bride"}],prevEntry:{id:"unleavened",title:"Unleavened"},nextEntry:{id:"i-am-risen",title:"I AM RISEN"}},{id:"i-am-risen",num:11,title:"I AM RISEN",type:"letter",sourceLabel:"Volume Three",date:"4/21/06",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Everlasting who would be man, Immanu El:"},{t:"italic",v:"I was born into the world of the virgin, the chosen vessel by which the salvation of man would come; Growing, Living as all men, yet remaining unspotted from the world, blameless..."}]},{type:"para",segments:[{t:"italic",v:"Born to die, suffering as no man could endure, the healing of many in the blood of sprinkling, Death; My spirit committed to The Father, all things accomplished, the cup of The Father consumed..."}]},{type:"para",segments:[{t:"italic",v:"The grain of wheat, The Holy Seed, has fallen and died, planted in the heart of the earth for three days and three nights. For I gave My life as a ransom for many, even unto death. I have the power to lay down My life, and behold, I have the power to take it up again."}]},{type:"poetry",lines:[[{t:"italic",v:"I AM THE RESURRECTION AND THE LIFE!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And all who believe in Me shall not die, but live,"}],[{t:"italic",v:"For I shall raise them up at the Last Day!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"No more tears, no more death, no more pain,"}],[{t:"italic",v:"For the old order of things has passed away;"}],[{t:"italic",v:"All things restored in glory, the glory of everlasting life!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"I AM RISEN! YOUR REDEEMER LIVES!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Says The Holy One of Israel."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-am-risen",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/i-am-risen?in=the-volumes-of-truth/sets/volume-three",videoVoiceUrl:"https://www.youtube.com/watch?v=na0m8NsQkps&list=PLE8FlkxQPQkOki3y3XQqS8Nx49EwLuRld&index=22",videoMusicUrl:"https://www.youtube.com/watch?v=ZlQABsbo7sc&list=PLSVchFJ22QYLFnEgsgioj_Lej_q1CzyfH&index=21",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:'The Name of The Lord - "Immanu El"',url:"https://answersonlygodcangive.com/The_Name_of_The_Lord#Immanu_El"},{label:"The Messiah",url:"https://answersonlygodcangive.com/The_Messiah"},{label:"Regarding The Crucifixion",url:"https://answersonlygodcangive.com/Regarding_The_Crucifixion"},{label:"Regarding The Resurrection",url:"https://answersonlygodcangive.com/Regarding_The_Resurrection"},{label:"Regarding Salvation",url:"https://answersonlygodcangive.com/Regarding_Salvation"},{label:"Regarding The Kingdom and Heaven",url:"https://answersonlygodcangive.com/Regarding_The_Kingdom_and_Heaven"}],prevEntry:{id:"devotion",title:"Devotion"},nextEntry:{id:"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly",title:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"}},{id:"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly",num:12,title:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly",type:"letter",sourceLabel:"Volume Seven",date:"5/19/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"italic",v:"This question was asked of The Lord, for a sister in Christ: Lord, is this really the last Pentecost?"}]},{type:"para",segments:[{t:"italic",v:"[The Lord answered]"},{t:"text",v:"Beloved, I have poured out My spirit on all flesh, even as I was poured out for you from the beginning. Yet no one comes to drink, not one is willing to receive of Me as I truly am. I have brought forth the rains in their due season, both the former and the latter, and still the crop wanes and bears only bitter fruit. Behold, the voice of The Lord your God has spoken, yet few have ears to hear, few are willing to open their heart and truly listen. I tell you the truth, before Me stands a very proud people, multitudes of foolish children who can not discern their right hand from their left. Their knowledge is corrupt; all their thoughts and musings only serve to uphold their vile nature. For they do not retain God in their thoughts, and from The Holy they are far removed."}]},{type:"para",segments:[{t:"bold-italic",v:"Therefore, thus says The Lord:"},{t:"text",v:"The churches of men are perverse, their ways corrupt, a wholly ignorant and vain people, multitudes of deceived children, a people who were to prepare My way before Me! Yet they have chosen another way, twisting and segregating the Scriptures, both adding to and taking away, that they may continue to uphold their own corrupt doctrines and filthy traditions, which I hate! Therefore, woe to those who dwell in the churches of men! Woe to all who walk in their ways! HYPOCRITES! And of the hypocrite\u2019s portion they shall surely receive, unless they repent and return to Me wholly and in truth! Says The Lord. For I tell you the truth, behold, I declare it to you plainly, if I were to come down and speak in the former manner, every one of these churches of men would bar My way before Me; even every one of them would cast Me out and seek to have Me arrested! Yet I have indeed passed through the midst of them, and though they have not seen Me, as I live, says The Lord, they have surely rejected Me!"}]},{type:"poetry",lines:[[{t:"italic",v:"I have poured out My spirit, yet they refuse to drink!"}],[{t:"italic",v:"I have spoken to them, yet they shut their ears to My voice!"}],[{t:"italic",v:"I have sent My messengers to them, yet they cast them out"}],[{t:"italic",v:"With great anger and violence, persecuting and slandering them!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Behold, even the least of these, My servants, have been"}],[{t:"italic",v:"Mistreated by these so-called people of faith!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THEY HAVE SURELY HATED ME!"}]]},{type:"para",segments:[{t:"text",v:"It is written:"},{t:"italic",v:"The heart of this people has waxed gross, their ears are very dull of hearing and their eyes they have shut, lest at any time they should see with their eyes and hear with their ears and understand with their heart, and be fully converted, and I should heal them."},{t:"fn",v:"1"},{t:"text",v:"Yet they have not returned to Me, nor will they repent. How then shall I heal them? For only those who know they are sick seek out The Physician. Yet those who perceive themselves as well will in no wise come to Me. Indeed they remain seated firmly in the darkness of their own understanding, resting upon their laurels by which they highly esteem themselves, as they for a pretense worship another messiah. For one who peers through stained glass can not behold his own image, nor is he able to see those inside clearly. For he sees only an outline, a blur of color obscuring his vision. And those on the inside who peer outward remain blinded, able to perceive only a shadow of what truly is, holding up the hand against the brightness, for fear of the noonday sun which is about to come in."},{t:"fn",v:"2"},{t:"text",v:" Thus they prefer the light filtered and the brilliance masked, by means of all this painted glass. What then shall a people such as this do when night has fallen? Thus the churches of men do always take the name of The Lord in vain, by all they say and do. From the least even unto the greatest, they pollute My name, even to the continual blaspheming of the Spirit. Therefore I shall indeed remove My hand, and My spirit shall return to Me. Behold, from every individual who refuses to give heed to My voice and embrace My correction has it departed already. Yet let all those who remain in My love understand and have peace. For though My spirit departs from the multitudes and the ensuing darkness be thick, though wickedness overflows and every man of pride who being wise in his own eyes is left confounded, I shall not make a total end. For My hand shall remain with the faithful, and My strength shall be revealed in My anointed. Behold, My spirit shall well up within the hearts of the penitent and come upon My chosen as a welcomed rain, and they shall be greatly increased, shining ever brighter, even amidst thick clouds and darkness."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold The Lord\u2019s purpose, for it shall surely"}],[{t:"italic",v:"Be accomplished, it shall surely be done:"}]]},{type:"poetry",lines:[[{t:"italic",v:"From My left hand, judgment shall be poured out"}],[{t:"italic",v:"Upon the desolate, the high-minded and the hypocrite..."}]]},{type:"poetry",lines:[[{t:"italic",v:"Yet under the shadow of My right hand,"}],[{t:"italic",v:"The humble shall be hidden..."}]]},{type:"closing",text:"For I am The Lord, and I do not change."}],footnotes:{1:{type:"scripture",ref:"Matthew 13:15 (KJV)"},2:{type:"note",text:'See: "THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL"',url:"https://www.thevolumesoftruth.com/THE_CUP_OF_THE_WRATH_OF_MY_FURY_IS_COME_TO_THE_FULL",link:{collection:"A Testament Against The World: The Lord's Rebuke",letterTitle:"THE CUP OF THE WRATH OF MY FURY IS COME TO THE FULL"}}},nkjv:{"Matthew 13:15 (KJV)":`For this people\u2019s heart is waxed gross, and
their ears are dull of hearing, and their eyes they have closed; lest at any time they should see with
their eyes, and hear with
their ears, and should understand with
their
 heart, and should be converted, and I should heal them.`},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly",videoVoiceUrl:"https://www.youtube.com/watch?v=PUowi1iW1iA&list=PLE8FlkxQPQkP4Ljrix_obl1uYSx1VNyqE&index=49",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding the Churches of Men",url:"https://answersonlygodcangive.com/Regarding_the_Churches_of_Men"},{label:"*Even More Related Topics",url:"https://answersonlygodcangive.com/index.php?search=%225%2F19%2F10%22&title=Special%3ASearch&go=Go"}],prevEntry:{id:"i-am-risen",title:"I AM RISEN"},nextEntry:{id:"pentecost",title:"Pentecost"}},{id:"pentecost",num:13,title:"Pentecost",type:"letter",sourceLabel:"Volume Six",date:"6/6/11",from:"From YahuShua HaMashiach, Our Lord and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"text",v:"Little flock, hear and understand the will and discipline of The Lord Most High. For I tell you the truth, Pentecost has been fulfilled; behold, it has passed them by unawares. Yet for some it remains, and shall also continue until the time. For many are called, yet few are chosen. Therefore have compassion and pray for them, beloved. For in the same way, you also looked to the time and waited for My words, yet they did not come. And some of you took it upon yourselves to run ahead, impatient, lacking trust, while still others waited patiently; yet all were unaware of My will, save one."}]},{type:"para",segments:[{t:"text",v:"Beloved, here is wisdom: The penitent wait and bow down in thanksgiving. Yet the arrogant and false righteous stand up proudly, declaring their deliverance, a deliverance which has already passed and shall not come. For My hand is removed and My spirit taken. For only those in whom I see of Myself shall escape, and only those caught in My embrace shall fly away. Thus as you were made to wait, so shall these within the churches of men wait. For they wait for a sound they no longer recognize, for a call to which they have shut their ears, for a shout from Him whom they have not known, a voice they have altogether rejected. For how can one who rejects My voice heed the call? And how can one who turns away from Me, embrace Me when the shout is made? For they have surely joined themselves to another, they embrace another messiah, a false christ, who looks nothing like Me. Therefore they shall surely pass through the fire, for by no other means shall they be saved."},{t:"fn",v:"1"}]},{type:"poetry",lines:[[{t:"italic",v:"This then is what I command you, little flock:"}],[{t:"italic",v:"Have compassion, and pray for your brothers and sisters"}],[{t:"italic",v:"In the churches of men and for the unbelieving of Israel;"}],[{t:"italic",v:"For they must endure much for the sake of My name..."}]]},{type:"poetry",lines:[[{t:"italic",v:"And though the day has passed, lo it has ceased"}],[{t:"italic",v:"For many, it has not altogether passed away..."}]]},{type:"poetry",lines:[[{t:"italic",v:"For My spirit remains with the first election,"}],[{t:"italic",v:"And shall be restored to the penitent after..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{1:{type:"scripture",ref:"1 Corinthians 3:11 (HNV)"}},nkjv:{"1 Corinthians 3:11 (HNV)":"For no one can lay any other foundation than that which has been laid, which is Yeshua the Messiah."},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/pentecost-3",videoVoiceUrl:"https://www.youtube.com/watch?v=QRVuknMEXRg&list=PLE8FlkxQPQkPq8VQsKdAQxdkiIuP0i4Fb&index=10",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"},{label:"Regarding The Holy Spirit",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Spirit"}],prevEntry:{id:"i-shall-remove-my-hand-and-my-spirit-shall-be-withdrawn-and-that-purposed-from-the-beginning-shall-be-done-it-shall-be-accomplished-swiftly",title:"I Shall Remove My Hand and My Spirit Shall Be Withdrawn... And That Purposed from the Beginning Shall Be Done, It Shall Be Accomplished Swiftly"},nextEntry:{id:"to-be-set-apart",title:"To Be Set Apart"}},{id:"to-be-set-apart",num:14,title:"To Be Set Apart",type:"letter",sourceLabel:"Letters to The Lord's Little Flock",date:"9/7/10",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord to His servants:"},{t:"text",v:"Beloved ones, hear My words. For I have indeed set you apart to do My will. Therefore you shall honor and celebrate this feast in My name. You shall do all I command you, even that which the world and other believers do not yet understand. This night, you shall blow the trumpet as the sun dips below the horizon, doing so with great sorrow in your hearts, because of that which this world has chosen in all their forsaking of Me; even as a lamentation over all this wickedness mankind has wrought in the earth, which shall come to a swift end at the setting of the sun upon this age of men. Then when morning comes, you shall once again sound the trumpet as the sun breaks the horizon, doing so with great joy in your hearts..."},{t:"italic",v:"For My Kingdom comes!"}]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/to-be-set-apart",videoVoiceUrl:"https://www.youtube.com/watch?v=hcb2Klosbpw&list=PLE8FlkxQPQkMIFKwAICFtCCIxuaoHNJSh&index=29",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"}],prevEntry:{id:"pentecost",title:"Pentecost"},nextEntry:{id:"atonement",title:"Atonement"}},{id:"atonement",num:15,title:"Atonement",type:"letter",sourceLabel:"Letters from Timothy",date:"",from:"",spoken:"",forLine:"",blocks:[{type:"para",segments:[{t:"italic",v:"2010 Wisdom Given to Timothy For The Lord\u2019s Little Flock, and For All Those Who Have Ears to Hear (Regarding The Day of Atonement)"}]},{type:"para",segments:[{t:"text",v:"Let this day be an offering of abstinence in purity to The Lord, a giving of thanks for your sins atoned for by The Messiah YahuShua; not atonement for your sins, of yourselves, but a free will offering in the name of The Lord your God and Him crucified, rejoicing in the anticipation of The Blessed Hope. And behold, He shall sit upon the throne of His glory and judge the nations. He shall utterly destroy all wickedness from this world, wiping away all that is sin and that which has led His people astray."}]},{type:"poetry",lines:[[{t:"italic",v:"And that which was shut shall be opened,"}],[{t:"italic",v:"And that which was open shall be shut in that Day,"}],[{t:"italic",v:"Says The Lord."}]]}],footnotes:{},nkjv:{},audioUrl:"https://thevolumesoftruth.bandcamp.com/track/atonement",soundcloudUrl:"https://soundcloud.com/the-volumes-of-truth/atonement?in=the-volumes-of-truth/sets/letters-from-timothy",videoVoiceUrl:"https://www.youtube.com/watch?v=W5M1VWf_sVc&list=PLE8FlkxQPQkO1p9OJVb6bB-BEqydSy3r2&index=6",videoMusicUrl:"https://www.youtube.com/user/trumpetcallofgod",relatedTopics:[{label:"Regarding The Holy Days of God",url:"https://answersonlygodcangive.com/Regarding_The_Holy_Days_of_God"}],prevEntry:{id:"to-be-set-apart",title:"To Be Set Apart"},nextEntry:{id:"the-feasts-of-the-lord",title:"The Feasts of The Lord"}},{id:"the-feasts-of-the-lord",num:16,title:"The Feasts of The Lord",type:"wtlb",sourceLabel:"Words To Live By: Part One",paragraphs:[{align:"justify",text:"In these Seven is wisdom and understanding, the very mind of God. For the Holy Days are revelation, revealing hidden things kept secret since the world began - signposts of things to come, a foretaste of The Kingdom, a glimpse into the Glory of God even as the Scriptures, unfolding and coming to light as the will of God is manifest, says The Lord."},{align:"center",text:`Behold, four are fulfilled:

Salvation assured, sin and death overcome, the Spirit given.



Three are coming quickly:

Sin destroyed, evil bound, My seat taken, Judgment...



A new day, even one thousand years...



Then a short season, Consummation...



An everlasting day in The Lord!`}],prevEntry:{id:"atonement",title:"Atonement"},scriptures:{}}],HOLY_DAYS_META={audioPlaylist:"https://thevolumesoftruth.bandcamp.com/album/the-holy-days",videoPlaylist:"https://www.youtube.com/playlist?list=PLSVchFJ22QYKKfZ5cAnLm_TxWABElLw7Z"},HIDDEN_MANNA=[{id:"woe-to-dallas",title:"Woe to Dallas",date:"3/31/09",from:"From The Lord, Our God and Savior",spoken:"The Word of The Lord Spoken to Timothy",forLine:"For All Those Who Have Ears to Hear",blocks:[{type:"para",segments:[{t:"bold-italic",v:"Thus says The Lord God:"},{t:"text",v:"Woe to Dallas! Woe to the City of Innocent Blood! Woe to the nation not desired!..."}]},{type:"para",segments:[{t:"text",v:"Day by day, the bodies are piled up in heaps! Day by day, the unborn are slaughtered in droves, because of you! Whole generations of people murdered without cause! Multitudes of innocent cast off as refuse, BECAUSE OF YOU! Fill up then, the measure of the sin of your fathers! Yes, add to your iniquity, that I may also add to you all that which I have purposed in My heart to do! Behold, I shall greatly trouble you, causing nature to rise up and fight against you! I shall leave your people desolate and bring you to utter ruin! Says The Lord."}]},{type:"poetry",lines:[[{t:"italic",v:"Behold, all shall fall and crumble"}],[{t:"italic",v:"Before The Lord, in His anger!"}],[{t:"italic",v:"It shall be shaken down, it shall no more stand!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"All shall crumble under the weight of My fury,"}],[{t:"italic",v:"For all your forsaking of Me, and for all this blood"}],[{t:"italic",v:"Which remains on your hands!..."}]]},{type:"poetry",lines:[[{t:"italic",v:"THE BLOOD OF THE INNOCENT!..."}]]},{type:"closing",text:"Says The Lord."}],footnotes:{},nkjv:{},num:1}];
